INSERT INTO core.text(id, content)
VALUES ('51143fa1-3c63-4898-843b-c9fc88fa23f4',
        'Tarbitakse liiga palju ja ei mõelda, kui palju sellest raisku läheb. See tõttu raisatakse ka palju resursse, mida oleks saanud mujal kasutada. Kui säästma hakkata saaksime end läbi säästmise ka mõnevõrra rikkamaks teha.\nEestis tekib ühe kodumajapidamise kohta aastas keskmiselt 61 kg toidujäätmeid, millest toidu kadu on 26 kg. Ostetakse toitu aga ei jõuda seda ära süüa ja osa toidust  rikneb. Aga kui tarbida vähem ja mõistlikumalt, väheneks raha summa, mis toidule kulub. Samuti läheks vähem ressursse põllumajandusele, sest nõudlus toidu järele väheneb.\nTeine valdkond, millele palju materjale kulub on riided. Ei mõelda nii palju rõiva kvaliteedile kui selle hinnale ja minnakse kaasa sooduskampaaniatega. Ostetakse riideid, mis on küll odavad aga mitte kaua kestvad. See tõttu tekib palju jäätmeid, mida on võimalik näha taaskasutuspoodide ladudes meeletute rõivaste hunnikuna. Võiks ennem analüüsida rõiva kvaliteeti ja siis vaadata, kas rõiva eest küsitav hind on õiglane ning taskukohane. Nii saab vähendada jäätmeid ja säästa ka oma raha ja ressursse, mis riidetööstusesse kulub. \nPraegu kulub palju raha ja teisi ressursse toidu tootmisele ja mõtetule tarbimisele. See on lahendatav kui keskkonna sõbralikumalt tarbima hakata – tuleb mõelda, kas ja kui palju sul midagi vaja on. Sama moodi ka rõivaste ostmisega, tuleb rohkem analüüsida kvaliteeti. Siis on võimalik vähendada jäätmeid ja suurendada ka natuke oma rahakotti, sest lõpuks kulub vähem raha toidule ja riietele.');
