INSERT INTO core.text(id, content)
VALUES ('7a6cc317-10c3-4951-874a-39dddc136d0c',
        'Inimeste tarbimisharjumused on ühiskonnas tuntud probleem, kus inimesed raiskavad palju ressursse ning viskavad suuretes kogustes neid ära. Tuntumad kategooriad on toidu- ja riiete raiskamine. Mida teha, et ressursse hoida?\nOsa inimesi ostavad endale riided, mis on moes ning kui see riie moest välja läheb, siis  seda riidet enam kanda ei soovita ja visatakse see riie ära või viiakse see taaskasutusse. Inimesed peaksid ostma kvaliteetset riiet ning kandma seda kaua, kui ebakvaliteetset riiet ning selle peale paari kasutust ära viskama. Nagu inimesed ütlevad „kvaliteet üle kvantiteedi“. Moedisainer Eve Hanson ütles: „Ma näen taaskasutuspoodide laos vabatahtlikuks käies seda rõivaste kogust, mis tekib iganädalaselt juurde. Need on meeletud hunnikud ja see on väga õpetlik. Ma arvan, et peaks hakkama noortele tegema ekskursioone taaskasutuspoodide lattu, et näidata, milline raiskamine tegelikult toimub.“ saates „Vikerhommik“. Inimesed peavad endale ostma rohkem kvaliteetset riiet, mida nad kannavad mitmeid kordi, mitte suurtes kogustes Hiinas valmistatud riideid, mida nad kannavad paar korda ja viskavad minema. \nRessurss, mida veel raisatakse on toit. Inimesed arvavad, et väikse koguse toidu ära viskamine ei tee suurt halba, aga kui mitmed inimesed väikestes kogustes toitu ära viskavad, tekib sellest juba üpris suur kogus toitu. „Kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 21 kg“ kirjutati tarbitoitutargalt.ee/toidukaost/ lehel. Bioloogilisi toiduaineid saab ka näiteks kompostida. Ülejääke saab kasutada järgmises toidukorras või tuleb osta selline toidukogus, mida inimene teab, et ta suudab ära tarbida. \nInimesed raiskavad või viskavad ära väga palju ressursse, kuid seda saab muuta, kui järgida soovitusi, mis spetsialistid on andnud. Nii saab vältida riiete ja toidu raiskamist ning tarbimisharjumust parandada.');
