INSERT INTO core.text(id, content)
VALUES ('f9f6549e-2b09-4318-8f75-5575c927e16a',
        'Ressurside raiskamine ja mitte kasutamine on suur probleem ühiskonnas. Toite visatakse ära põhjusega, et süüa praegu rohkem ei taha, taaskasutatuid asju ei kasutata, selle pärast et taaskasutatute riiete kvaliteet võib olla halvem, ning esemeid, mida saab veel kasutada visatakse sammuti minema, kuna ei vajata praegu. Need on inimestel havlvad tarbimisharjumused.\nMoedisainer Eve Hanson on öelnud, et eelistada võiks kodumaiseid oma lähedal toodetuid asju ning pigem vähem kui rohkem. Mina nõustun nende viimaste sõnadega mida Eve Hanson on öelnud. Pigem vähem kui rohkem väide kehtib nii söögi, kütuse, riietega kui ka muude ressursidega. Kui mul oleks liiga palju riideid, siis enamus riideid seisaks mul kappis ja koguks tolmu. Selle asemel võiks mul olla kappis kindlad riided, mida ma tean et ma kannan. \nSammuti on inimesi, kes on samaajal näljas kui söödavaid toite visatakse toidujäätmetena prügikasti. Eestis visatatkse kokku kuuskümmend üks kilogrammi toidujäätmeid ära aastas, millest nelikümmend kaks protsenti ehk kakskümmend kuus kilogrammi moodustub toidukaud toiduainetest ja söödavast toidust. Selle toidusummaga saaks päästa nälgivaid inimesi ja ka loomi näljast. Ma olen õppinud enda vanematelt, et kui ei soovita süüa, siis vähemalt annetada see teistele, kes on näljas.\nInimeste tarbinisharjumus pole väga hea, aga see ei tähenda, et kõikide inimeste tarbimisharjumus on halb. On inimesi, kes teevad kõike, et taaskasutada ja aidata teisi. See väike asi, et säästa ressursse teistele on jubagi väga tähtis ja hea harjumus tarbimisel.');
