INSERT INTO core.text(id, content)
VALUES ('ffd58c90-c3c7-45f4-9224-e279ca20a5d1',
        'Ületarbimine on suur probleem mitte ainult Eestis kui ka teistes arenenud riikides. Inimesed viskavad toitu ära, ostavad riideid kiirmoe poodidest ning toodavad mõttetuid asju, aga peab juba arusaama, et see ainult kahjustab loodust. \nKiirmoe poode tekib ainult juurde ja inimesed ostavad sealt riideid, aga kahjuks kõik ei saa aru sellest, et parem on osta ühe kvaliteetse asja kõrgema hinnaga, mitte ühe riideeseme, mis on toodetud Hiinas ja kuu pärast seda enam kanda ei saa, aga vähemalt see on odav. Mina isiklikult ostan kvaliteetseid riideesemeid, sest niimoodi ma ei ületarbi ja ei rikku loodust. Minu arvates on parem osta kallima, aga kvaliteetse riietuse, sest kui selle eest hästi hoolitseda, siis see võib kõlbada kandmiseks veel väga kauaks. \nToiduraiskamine on teemaks praegu peaaegu igas Eesti peres, kuna väga raske on arvestada sellega, kui palju toitu peab tegema, et kõigil peres saaksid kõhud täis ja samas ei viskaks pärast prügikasti toidujääke. Meie peres ema alati käsib süüa kõik lõpuni ära , mis on taldrikusse pandud, aga kui ei jaksa, siis võib alati koerale anda. Meil ei ole kombeks toidujääke prügkasti visata. Paljudes Aafrika riikides inimesed nälguvad ja toidu raiskamine on nende suhtes inetu. Eesti inimese kohta aastas tekib 26 kg toidujäätmeid, see on väga suur arv. Eestlased ise rikuvad ilusat Eestimaa loodust. \nInimestele peab silmad avama sellele, mis praegu Maal toimub. Enamus inimesi arvavad, et kõik ressursid on lõpmatud ja selle pärast ei lõppegi ületarbimine. Inimesed ise rikkuvad loodust ja tapavad loomi oma tegevustega ja lõpuks süüdistavad nad selles kedagi teist.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('ffd58c90-c3c7-45f4-9224-e279ca20a5d1', 'title', 'Liigne ületarbimine');
