INSERT INTO core.text(id, content)
VALUES ('969050e2-7787-48b5-ac35-28c56b9ad3c1',
        'Liigne tarbimine põhjustab probleeme keskkonnale ning mõjub halvasti ka inimese rahakotile. Tihti ostavad inimesed asju mõtlemata ning ei suuda neid hiljem ära tarbida. Odavalt ostetud rõivad, mis on valmistatud mittekvaliteetsetest materjalidest ei kesta enamasti kaua ning lõpetavad peagi prügimäel.\nToidu raiskamine on minu arvates väga suur probleem. Osa inimesi ostavad poest liiga palju toiduaineid, mida nad ise ära ei jõua ega suuda tarbida. Selline käitumine mõjub, aga halvasti loodusressurssidele. Tutvudes tekstiga „Toidukaost“ sain teada, et kodusesmajapidamises tekib iga Eesti inimese arvelt aastas ligikaudu 61 kg toidujäätmeid, millest 26kg on tarbimata jäänud toit. Olen ka isiklikult puutunud kokku toiduraiskamisega. Paar aastat tagasi einestasin perega restoranis ning märkasin, et enamus kliendid jätavad pool toidust alles. Otsustasin teenindajalt pärida, kui palju toitu keskmiselt õhtu lõpuks minema visatakse ning sain vastuseks, et umbes kaks kuni kolm prügikoti täit. Võin enda kogemuste põhjal öelda, et toidu raiskamine on suur murekoht.\nKiirmood mõjub halvasti nii inimese rahakotile kui ka keskkonnale. Tänapäeval muutub mood väga kiiresti ning kauplused peavad pidevalt kaupa vahetama, et käia kaasas uute trendidega. Sellepärast on mitmed brändid nagu Zara ja Shein hakanud odavate vahenditega tootma trendikaid riideid, mida poest väga odavalt endale soetada saab. Kahjuks on materjalid enamasti ebakvaliteetsed ning lagunevad kiiresti. Selle tulemusena kulutab inimene lõpuks  rohkem raha kui ostes kvaliteetsem, kuid kallim riideese. Minu kogemus kiirmoega on olnud pigem negatiivne. Septembris ostsin ma endale Zarast kampsuni, kuid juba oktoobris oli kudum topiline ning pidin sellest loobuma. Suur hulk ebakvaliteetsetest riietest lõpetab prügimäel. Seega ei mõju kiirmood keskkonnale hästi, vaid põhjustab prügimägede suurenemist.\nToidu raiskamine on suur murekoht, sest raiskab ressursse nagu vett ja tööjõudu. Kiirmood mõjub keskkonnale halvasti, sest on tihti ebakvaliteetne. Liigne tootmine on probleem, mis mõjutab meie kliimat ja keskkonda. Mina arvan, et inimesed peaksid enda tarbimist rohkem jälgima ning enne ostu sooritamist põhjalikumalt mõtlema.');
