INSERT INTO core.text(id, content)
VALUES ('6b8404dc-0d1d-4bdb-8d33-32b9c4fa9e16',
        'Tänapäeva ühiskonda võib nimetada tarbijaühiskonnaks, mis on orienteerunud kaupade müümisele ja tarbimisele. Ühiskonnas, kus uus kaup on pidevalt kättesaadav ei osata seda väärtustada ning see toobki meid küsimuseni, millised on tänapäeva inimese tarbimisharjumused?\nInimesed raiskavad suurtes kogustes toitu. Veebilehel tarbitoitutargalt.ee kirjutatakse, et kodumajapidamises raisatakse aastas iga eestlase kohta 26kg toitu. Inimesed ei hooli, et viskavad nii palju toitu ära, sest neil on alati võimalik lihtsalt juurde osta. Olen märganud sellist käitumist ka enda sõprades, kes võtavad sööklas terve taldrikutäie toitu, kuid lõpuks viskavad selle ühel või tesiel põhjusel lihtsalt prügisse. Inimesed ei väärtust oma toidu olemasolu ja on kergekäelised toitu ära viskama.\nTänapäeval ollakse aina rohkem mõjutatud moe trendidest ja eelistatakse kiirmoodi. Enamus inimestel on harjumus vähemalt kord päevas vaadata sotsiaalmeediat, kus on pidevalt uusi trende, see mõjutab ka inimeste ostuharjumusi. Inimesed tahavad jätta mulje, et neil on rohkem raha kui tegelikult ja jägivad igat trendi. Selle saavutamiseks pöördutakse kiirmoe poole. Tunnen mitu inimest, kes on enamus oma riideid ostnud odavalt Shein´ist, mõtlemata, kas see on üldse eetiline. Kiirmoe brändid kasutavad odavat tööjõudu ja ei ole keskkonnasõbralikud. Enamus kiirmoe riietest jõuavad lühikese ajaga prügimäele, sest need lihtsalt ei ole pikaajaliselt kantavad. Kiirmood on saanud tänapäeval normiks.\nTänapäeva inimeste tarbimisharjumused ei ole keskkonnasäästlikud. Suur osa eestlaste toidust läheb raisku, sest seda ei väärtustata. Riiete ostmisel vaadatakse eelkõige hinda ja ei hoolita sellest kuidas riided tehtud on või mis neist tulevikus saab.  Inimeste tarbimisharjumused ei ole jätkusuutlikud ning neid peaks muutma.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('6b8404dc-0d1d-4bdb-8d33-32b9c4fa9e16', 'title', 'Millised on tänapäeva inimese tarbimisharjumused?');
