INSERT INTO core.text(id, content)
VALUES ('057b86b8-4463-44d0-b546-32863c9e814c',
        'Tänapäeva maailmas, igapäeva elus, tarbitakse tonnide kaupa riideid, toite, jalanõusid ja väikeseid vidinaid. See on muutunud tavaliseks, et ühel tänapäeva inimesel on üle kümne paari päikeseprille. Aga kuidas see mõjutab keskkonda ja mis on tegelikult mõttetu üleliigsetarbimise tagajärjed?\nInimesi peaks juba noorest peast harima liigseületarbimise eest, sest see mõjutab nii inimesi kui ka maailma ise. Nüüdisaja noored tellivad liiga suurtes kogustes riideid Hiina ebakvaliteetsetest poodidest nagu „Sheinist“ või „Aliexpressist“, aga nad ei saa aru, et tegelikult on need väga kahjulikud poed. Mina ise olen kahjuks ka tellinud varem „Sheinist“, kuid kui ma need riided kätte sain, lagunesid need ühepesuga kokku ning panin tähele, et paaril särgil ja kampsunil oli silt seljataga, kus oli peale kirjutatud „Please help“ ning sain kohe aru, et tegemist ei ole mingi tavalise poega ja hakkasin kohe uurima. Need riided on valmistatud Hiinas ning enamikuks nende valmistamiseks on kasutatud lapstööjõudu. Seda peaks suurtele, aga ka kindlasti noortele rõhutama, et mitte osta või siis ületarbida riideid sellistest poodidest, sest see rikub ka teiste elusid.\nMida rohkem noored tellivad ebakvaliteetseid riided või esemeid, seda rohkem rikub see keskkonda. Kui noored ostavad tonnide kaupa odavaid riideid kuskilt Hiina poest, siis selleks peavad need kohale Eestisse ka jõudma. Kui noored ja ka suured ei ostaks nii palju ja nii kaugelt ebakvaliteetseid riideid, mis lähevad kohe katki või on ühepesuga rikutud, siis ei peaks nii palju kargolennukuid minutis lendama ning see oleks juba tohutu suur samm parema keskkonna poole.\nIga kui viimne inimene siin maal mõjutab maailma keskkonda, aga ka üksteise elu mingil moel, kuid kahjuks ei ole paljud inimesed piisvalt haritud ja ei tea, mis tagajärjed tegelikult selliste kehvade esemete ostmisega tulenevad ning sellepärast peaksid ka koolid, vanemad, kes on kursis selle teemaga, lasteiaiad ja töökohad proovima inimesi rohkem mõjutada ja aidata.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('057b86b8-4463-44d0-b546-32863c9e814c', 'title', 'Ületarbimine tänapäeva elus');
