INSERT INTO core.text(id, content)
VALUES ('76f3c029-7e98-4e08-ae2f-4910b79a6c51',
        'Palju inimesi raiskab materjale rohkem, kui võiks. Ostetakse rohkem toitu ja riideid, kui tarbida suudetakse. Riideid kantakse vaid paar korda, enne uute ostmist. Selline elustiil on probleemne, sest nii läheb tohutult raisku materjale ja ressursse.\nToiduraiskamise põhijaks on kehtivuse kuupäevad. Inimestel, kellel pole probleeme rahaga, ostavad rohkem toitu, kui nad suudavad ära süüa. Selle tagajärjel visatakse ära halvaks läinud söök. Raisatakse enda raha ning ressursse nagu vesi, energia ja ka toit ise. Mina arvan et seda tegelikult on võimalik kergelt lahendada. Poes käies enda söögikordade planeerimne on hea viis osta täpselt nii palju toitu, kui tarbida suudab. Praegu käiakse poes, ostes kõike, mida ihaldatakse. Selle tagajärjeks ongi suur kogus toitu mida ei tarbita enne kehtivuse kuupäeva möödumist.\nPaljud noored kannavad kiirmoodi. Kiirmood on täpselt nagu kõlab, kiire ning vahetub pidevalt. Noored on alati moega kaasas ning ostavad riideid uue trendi tekkimisel. Selle tõttu on raiskamise kogus üüratult suur. Noortele on peale pandud surve moega kaasas käija kiusamise teel. Minu arvates peaksime me vähendama kiusamist ja lubama inimestel kanda mida nad soovivad kanda. Mina arvan ka, et enamus noori ei saa aru, palju riideid nad niisama raisku lasevad. Noortele peaks koolis rääkima sellistest probleemidest.\nInimeste tarbimisharjumused toiduraiskamise ja riiete tarbimisel ei ole positiivsed. Tarbitakse rohkem, kui võiks ja saaks. Riideid võiksime osta vaid siis, kui eelmiseid enam kasutada ei ole võimalik ning toitu ostes tuleb mõelda oma tarbimiskogusele.');
