INSERT INTO core.text(id, content)
VALUES ('e24ec7a7-7dcd-4c04-bd3e-04c544726ae5',
        'Nüüdisaja inimeste tarbimisharjumised on muutunud aastate jooksul halvemaks. Ostetakse, kas liiga palju kiirmoe riideid, mida kantakse ainult paar korda kuna kuu aja pärast pole need enam moes. Samasugune proobleem on ka toidu tarbimisega. Inimesed ostavad endale liiga palju toitu, mida nad ei jõua ära süüa.\nPaljud inimesed ostavad endale igapäevaselt liiga palju kiirmoe riideid, mida nad kannavd ainult paar korda, sest kuu aja pärast pole need enam moes. Selline tarbimiskasutus on keskkonnale väga halb kuna enamus riietest satub prügimääle ja teine pool taaskasutuskeskustesse. Need riided on tavaliselt ostetud Shein’ist, mis tulevad Hiina tehastest, kus kasutatakse lapstööjõudu ja on valmistatud naftast, mis võib nahka ärritada. Sellised riided on halvema poolsest materjalist ja seetõttu lähevad ka kiiremini katki, kui kvaliteetne materjal.\nTänapäeval on halvenemas ka toidu tarbimiskasutus. Inimesed ostavad endale liiga palju toitu, mida nad ei jõua ära süüa või jõuab kätte parim enne kuupäev. Inimesed arvavad, et kui ainult üks nendest viskab toitu ära, siis ei juhtu midagi, mis on vale. Eestis viskab üks inimene ära keskmiselt 61 kilogrammi toitu. Sellepärast raisataks nii oma raha kui ka energiat ja vett. Toidu kasvatamise kiirendamiseks kasutatakse erinevaid väetisi ja kemikaale, mis mõjuvad keskkonnale halvasti. Kemikaalid ja väetised satuvad põhjavette, mis omakorda jõuab meieni põhjavee kaudu.\nTänapäeva inimeste tarbimisharjumused on halvenemas. Ostetakse endale kiirmoe tõttu liiga palju ebavajalike riideid, mis on tehtud naftast ja halvast materjalist, mis võivad ajada naha sügelema. Ka toidu ostmise kogus on ühe inimese kohta liiga suur, mida ei jõuta ära tarbida ja vistatakse seepärast minema.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('e24ec7a7-7dcd-4c04-bd3e-04c544726ae5', 'title', 'Inimeste tarbimisharjumused');
