INSERT INTO core.text(id, content)
VALUES ('a7a43d1c-c465-4a8d-92df-d4feab8886b3',
        'Tänapäaeval on tarbimine osa igapäeva elust. Ilma tarbimiseta on ühiskonnas keeruline toime tulla. Inimesed vajavad toitu, riideid ning igapäeva esemeid, et hakkama saada, kuid alati ei keskenduta kvaliteedile ning tarbivad liigselt.\nPaljud inimesed on harjunud ostma iga nädal toitu ja eluks vajalikke tooteid, et toime tulla, kuid inimesed kipuvad ostma alati odavamat ning seda suuremates kogustes, mis ei ole alati hea otsus. Allahinnatud toit on tihti ületanud kuupäeva ning selle ostmine pole mõtekas, sest toit pole söödav. Suur kogus ebakvaliteetset prügi ning plastikut, milles pakendatakse tihti tooteid, reostavad loodust, sest nad ei lagune looduses. Kvaliteetsemad ettevõtted ning firmad loovad tihti keskkonnasäästlikumaid biolaugunevaid pakendeid, et luua rohkem usaldusväärsem mulje. Tark tarbija tarbib vähem ja kvaliteetsemalt, et säästa keskkonda ning vähendada enda prügi teket. \nOdavad või alahinnatud tooted on tihti odavad just sellepärast, et neid ostetakse vähem või nad on odavalt toodetud. Sooduskampaaniad ja kõik mis moes on, mõjutab inimest rohkem ja kiiremini tarbima ning hiljem on toode kulunud ja kõlbmatu. Ebakvaliteetsed tooted võivad küll tükk aega toimida, kuid nad on üldiselt loodud üles ütlema, et tarbija ostaks toodet uuesti. Selle asemel, et uut toodet osta võiks taaskasutada tuttavate ja sugulaste vanu asju nagu riided ja beebi tooted.\nToodete lai kättesaadavus ja hea hind tekitavad tarbijale tunde, et on mõtet kohe osta, kuid tegelikult peaks mõtlema toote kvaliteedile ning selle mõjudele. Tarbija peaks rohkem mõtlema, kas see toode on päriselt vajalik ja taaskasutatav.');
