INSERT INTO core.text(id, content)
VALUES ('34ef6a6b-ec50-4d88-b396-72ce87cc4d4a',
        'Tänapäeva ühiskonnas on inimestel harjumus tarbida rohkem, kui tegelikult vaja on. See põhjustab suurt kauba raiskamist ja ületootmist- ning tarbimist. Eriti palju raisatakse toitu ja riideid.\nToidu raiskamine on väga suur probleem. Poodidest ostetakse liiga palju toiduaineid, mis lõpuks aeguvad ja visatakse ära. Samuti visatakse minema toit, mis pole küll kõige värskem, aga on täiesti söödav. Toitu võetakse iseenesestmõistetavana ja arvatakse, et see ei saa kunagi otsa. Ka minu peres on olnud sama probleem, kus ostetakse liiga palju toitu ja kõike ei sööda ära, enne kui toiduained aeguvad. Nii raisatakse väga palju maad, tööjõudu, vett ja energiat. Tuleb mõelda läbi, millist toitu ja kui palju osta, et toidukadu vähendada.\nRiiete raiskamine on samuti suur probleem, inimesed ostavad  kiirmoe tõttu odavaid riideid Hiina veebipoodidest ja eelistavad kvaliteedile kvantiteeti. Hiinast tellitud riideid kantakse tihti vaid mõned korrad, enne kui need ära visatakse. Ka mina olen Hiinast riideid tellinud ning neid vaid mõned korrad kandnud. Olen aru saanud, et see on täiesti mõttetu, sest riided pole hea kvaliteediga. Tuleb eelistada kvaliteetseid riideid ning käia rohkem näiteks taaskasutuspoodides, kust saab tihti leida korralike, odavaid ja ilusaid riideid.\nInimeste tarbimisharjumusi peab muutma. On oluline, et inimesed mõtleksid läbi, mida ja kui palju tarbida, eriti riiete ja toidu osas. Nii saab kaupade raiskamist, ületarbimist ja tootmist vähendada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('34ef6a6b-ec50-4d88-b396-72ce87cc4d4a', 'title', 'Inimeste tarbimisharjumused');
