INSERT INTO core.text(id, content)
VALUES ('721f4100-ef15-4b87-8a71-7d21d7ef34b1',
        'Inimesed tarbivad, nagu neid ei huvitaks homne. Massiliselt visatakse ära toitu ja riideid, selle asemel, et vähem tarbida ja taaskasutada. Iga toit või riideese mis ära visatakse on raisku läinud: töö, materjal, raha jne. Kas tarbimist saaks kuidagi vähendada ja kuidas?\nInimestele tundub, et toit ei saa kunagi otsa ja seda võib lõputult tarbida. Paljud inimesed tarbivad liiga palju ja nad isegi ei tea seda. Eestis tekib inimese kohta aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu on 26 kg. Minu peres proovitakse tarbida ära kõik toidud, mis ostetakse, et vähendada toidu raiskamist. Rahvast tuleks rohkem harida sellel teemal ja juba koolis õpetada, kuidas vähendada oma ökoloogilist jalajälge.\nInimesed eelistavad kvantiteeti üle kvaliteedi. Tänapäeval on väga populaarne tellida internetist riideid ilma, et oleks neid kunagi oma silmaga näinud. Enamasti tulevad need riided Hiinast ja on väga odavad. Mõned inimesed on aga nutikad ja kasutavad teise ringi riideid, et nendele uus elu anda. Viimasel ajal on see saanud populaarseks noorte seas. Mina käin pidevalt sõpradega Humanas ja Taaskasutuskeskuses, et sealt ägedaid riideid osta. Hiina riiete asemel peaks tarbima kodumaist ja kvaliteetset toodangut.\nInimeste tarbimisharjumused on halvad. Palju toitu ja riideid visatakse ära ilma, et mõistetakse kui suurt kahju see loob. Oma ökoliigilise jalajälje vähendamiseks tuleks eelistada kvaliteetseid tooteid ja vältida ületarbimist.');
