INSERT INTO core.text(id, content)
VALUES ('59f13ab9-8b77-4837-a3d0-f53300708a15',
        'Inimeste tarbimisharjumused on väga erinevad. Osad ostavad ainult asju mis neil  vajalikud on. Mõned, aga ei mõtle oma oste ära ja viskavad minema asju, mida nad ei kasuta. \nOn inimesi kes arvava, et toit mis nad ära viskad, või riided mis nad ostsid Hiinast on midagi väga väikest meie looduse jaoks. Sellise mõtlemisega inimesi on maalmas väga palju.Tavainimesi võiks koolitada ja rääkida neile kui halb on osta Hiinast riideid, rääkida sellest, et toidu viskamise jaoks saavad nad kasutada kompostikaste. Kui neile meeldivad ilusad riided, aga neil pole nenede jaoks raha, ei pea kohe Hiinast tellima sarnaseid, vaid võib koguda raha nenede peale. \nÕnneks on neid kes oskavad planeerida oma oste, ei viska oma toitu ära ja ei osta riideid Hiina tehastest. Sellise kirjelduse alla sobib minu vanaema. Ta alati planeerib oma oste hoolikalt. Ta käib poes nimekirjaga, selleks, et kogemata mitte osta midagi mida tal vaja ei ole. Ta ei osta asju mis on tehtud naftast, vaid pigem midagi hea kvaliteediga kuigi see on kallim. \nInimestel on erinevad tarbimis harjumused, aga kõik peavad aru saama, et midagi pole piiramatu. Tavainimesed peavad oskama planeerida oma oste ja aru sama, et toidu ära viskamine ei ole loodusele hea. Meil on ainult üks planeet, kui me niimodi jätkame on meie lastel ja lapselastel halb siin elada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('59f13ab9-8b77-4837-a3d0-f53300708a15', 'title', 'Inimeste tarbimisharjumised');
