INSERT INTO core.text(id, content)
VALUES ('3a0391c3-4f11-46bd-96f5-11eb756bea50',
        'Tänapäeval keskendutakse vähem sellele, kust tooted tulevad. Ostetakse ebavajalikku ja asjad visatakse mõtlemata ära. Kahjulikud tarbimisharjumused põhjustavad keskkonnaprobleeme, kuid tark tarbimine saab luua parema ühiskonna.\nÜletarbimine on aina kasvav probleem. Tooteid ostetakse suures koguses madala hinna eest ja ei mõelda, mida see endaga kaasa toob. Ka mina olen Aasia internetipoodidest nagu Temu ja Shein tellinud, kuid saadud kaup ei ole kvaliteetne ning proovin edaspidi neid poode vältida. Tellisin sealt soodsa hinna pärast. Nüüd aga tean, et sedasi ostlemine pole jätkusuutlik ning parem on osta natuke kallim kvaliteetsem toode, mis ei lagune pärast paari kasutuskorda. \nSamuti on probleemiks raiskamine. Riideid ja toitu visatakse kerge käega minema. Eestis tekib iga inimese kohta aastas umbes 61kg toidujääkmeid, millest peaaegu pool on toidukadu. Harjumus toitu raisata tuleneb mõtteviisist, et toit on alati poes olemas ja ei saa kunagi otsa. Selline arusaam toob aga kaasa keskonnaprobleemid, sest saagi kasvatamiseks kasutatakse tihti kemikaale ja väetiseid, mis satuvad loodusesse. Inimesed peaksid olema teadlikumad, kuidas toit nendeni jõuab ja kuhu see pärast ära viskamist läheb.\nSaab olla ka tark tarbija. Osta ainult nii palju, kui on vaja ja eelistada kodumaiseid poode või taaskasutust. Minu pere külastab tihti Uuskasutuskeskust ja eelistame poes käies Eestis valmistatud toitu. Sellises keskonnas kasvamine on muutnud mind teadlikumaks ja valin kvaliteedi üle kvantiteedi. Head harjumused vähendavad tarbimist ja raiskamist.\nTänapäeva ühiskonnas on ületarbimine normaalseks muutunud ja sellest ei olda teadlik. Raisatakse palju ning ei mõelda tagajärgedele. Nii see aga olla ei tohiks. Tarbides tuleb olla teadlik ja tark, et vähendada keskkonnaprobleeme ja rahakulu.');
