INSERT INTO core.text(id, content)
VALUES ('821ba135-fc40-42bb-8791-606be92f90e5',
        'Kogu aeg uudistes räägitakse, kuidas rahvas peaks taaskasutama ja hoidma oma tarbimisharjumustel silma peal. Kas inimesed tarbivad liiga palju? Liigtarbimist võib põhjustada nii toiduraiskamine kui ka riiete äraviskamine.\nInimesed tarbivad palju, kuna raiskavad sööki. Visatakse ära suurtes kogustes toitu, kuna see on riknenud, ületanud kasutustähtaja või jäänud söömata. Kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt kuuskümmend üks kilogrammi toidujäätmeid, millest kakskümmend kuus kilogrammi moodustab toidukadu. Selline liigtarbimine teeb nii elanikkonnale kui ka keskkonnale kahju, kuna toidu ostmiseks raisatakse raha ja kulutatakse ressursse, nagu vesi, tööjõud, maa ja energia. Saagikuse tõstmiseks kasutatakse ka väetisi ja kemikaale. Rahvas liigtarbib, kuna visatakse ära olulisel määral palju sööki.\nPeale toiduraiskamise ostab elanikkond rohkesti riideid. Soetatakse endale rõivaid, mida kõiki isegi ei kanta, ja tellitakse Hiina veebipoodidest ebakvaliteetseid riideesemeid. Noored ostavad, näiteks Shein-ist, endale halvakvaliteedilisi või nii viletsatsi tehtud riietusesemeid, mis ei ole kõlblikud selga panemiseks. Inimesed peaksid eelistama kvaliteeti kvantiteedile. Tarbitakse palju, kuna märkimisväärne kogus rõivaesemeid jäetakse kandmata või visatakse ära, seda tõestab ka see, et taaskasutuspoodidesse tuuakse iga nädal palju riideid juurde.\nToiduraiskamine ja suur kogus riideid vanarõivapoodides – need faktorid näitavad, kui palju inimesed reaalsuses tarbivad. Liigtarbimist saab parandada, siis kui ostetakse õiges koguses sööki, mis ära ka süüakse, ja kauakestvaid rõivaid. Rahvas peab jälgima enda tarbimisharjumusi.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('821ba135-fc40-42bb-8791-606be92f90e5', 'title', 'Kas inimesed tarbivad liiga palju?');
