INSERT INTO core.text(id, content)
VALUES ('858495f6-73c1-4f2d-90d3-1abaab3e07a6',
        'Mina käin väga tihti taaskasutuspoodides endale riideid vaatamas. Arvan, et see on üks suurimaid investeeringuid, mida mina saan teha. Samuti käib see ka toidu kohta. Minu pere ostab ainult toitu, mis kõigele meeldib ehk kõigil oleks isu oma taldrikud tühjaks süüa ja ülejäägid keelega likvideerida.\nMinu ringkonnast ei mõista paljud, mis kulda võib inimene leida taaskasutuspoodides. Olen tihti üles noppinud rõivaid, mis on kaubamärgiga, ja mis järelturul müüks 5 korda kallimalt või enamgi. Minu vaates on nii uuskasutuskeskused kui ka taaskasutuspoed inimese üks suurimaid investeeringuid. Tänapäeval tehakse ka sellest äri, näiteks minu ema. Ta käib uuskasutuskeskustes, otsib üles väärt rõivad ja esemed, ostab need, ning siis müüb need hiljem maha kõrgema hinnaga. Arvan, et see on väga nutikas.\nSamuti ka väga suur kajastatud teema minu peres on toidujäägid. See kõnetab mind, sest ka meie olime kunagi toidu maha viskajad. Nüüdseks oleme leidnud endale kõige efektiivsema viisi, kuidas toitu säästa. Iga nädala pühapäeval paneme kokku uue nädala menüü ehk lepime kokku, mis poest vaja on. Me ostame tavaliselt toitu, mis on kõigile meelepärane, et ei tekiks probleemi, et kellelegi miski ei maitseks või muud. See on teinud suurt mõju minu perele. \nOlen jõudnud oma kogemustega arvamusele, et suurimaid kohti, kus inimesed elus säästa saavad on riided ja toit. Tuleb kasutada neid võimalusi õigesti ja näha nendes väärtust. Mina ei suudaks oma elu enam teistpidi näha, kus ma ei mõtleks hindadele või ülejääkidele.');
