INSERT INTO core.text(id, content)
VALUES ('a6be1482-59b3-4e26-b4ca-b40d81adb88a',
        'Peresid on rikkamaid kui ka vaesemaid, osad tarbivad rohkem osad vähem. Üheks suureks ühiskonnaprobleemiks on ületarbimine. Sellel on palju põhjuseid, kuid üks suurim on see, et inimesed ei mõtle oma oste läbi.\nMina arvan, et inimesed raiskavad tänapäeval liiga palju toitu seda ära visates. Viimasel ajal olen tähele pannud, et inimesed ei märka seda isegi. Eriti suured raiskajad on lapsed ja teismelised. Lapsed lähevad näteks poodi ja tahavd osta sealt osta kommi. Letil nägid nad eriti värvilist kommipakki ja see paistab neile maitsev väja ning nad otsustavad selle ära osta. Pärast maksmist avavad nad kommipaki ja tuleb välja, et see isegi ei maitse neile ning nad viskavad selle lihtsalt ära. Kuid lapsed pole ainukesed raiskajad. Kahjuks leiame ka tänapäeval täiskasvanud inimesi, kes seda teevad. Olen päris kindel, et inimesed ostavad asju mis neile isegi ei meeldi pakendile vaadates.\nTarbitakse ka palju riideid, mida hiljem kantakse vaid paar korda. Seda teevad enamasti teismelised. Riiete üleostmine reostab kindlasti keskkonda, kuna neid toodetakse naftast. Olen isegi ostnud endale odava särgi, mis näeb hea välja. Kannan seda särki paar päeva, kuid see kulub ära paari päevaga ning siis läheb see tavaliselt äraviskamisele. Inimesed peaksid ostma vähem riideid ja tarbima nii palju kui neil vaja. Lisaks tuleks osta naftast toodetud särkide asemel puuvillast särki, kuna see kestab kauem ja pole keskkonnale nii kahjulik. Ära kasutatud riided tuleks annetada või viia taaskasutuskeskusesse.\nInimesed tarbivad liiga palju ja seda alateadvuses. Selle probleemiga tuleks kindlasti tegeleda ning teavitada inimesi rohkem mõistlikust tarbimisest.');
