INSERT INTO core.text(id, content)
VALUES ('86831bac-1fe5-4bd6-bf01-5e1c55921059',
        'Mida aeg edasi, seda suuremaks probleemiks muutub maailmas toidukadu. See mure ei ole kaua eksisteerinud ning inimesed ei ole veel sellest väga teadlikud. Mida saaks teha, et toidukadu vähendada ja mis see üldse on?\nToidukadu on nähtus, millega palju inimesi ei arvesta. See ilmneb selles, et sööki visatakse ära. Olgu see siis selle pärast, et see läheb riknema või jääb toitu söögist üle. Keskmiselt tekib iga eestlase kohta aastas kuuskümmend üks kilogrammi toidujäätmeid. Mina ise olen ka toidu raiskaja. Kui ma söön sööki mingi kastmega, siis enamasti ma viskan kastme ära, isegi siis, kui seal on lihatükid, sest see ei olnud põhiroog. Minu pere ja ka teised võiksid rohkem arvestada toidukaoga.\nToidukadu on võimalik vähendada, kui rahvas sellest teadlikum on. Tuleb toitu säästlikumalt tarbida ning ei tohi seda liiga palju osta. Peab arvestama oma pere suurusega. Viimasel aastal on minu pere ka rohkem hakanud arvestama toidukuluga. Minu ema, kes ostab enamasti külmkapi täis, on hakanud viimasel aastal rohkem arvestama meie pere suurusega ning nüüd on meil vähem toitu, mis riknema läheb. Ta on ka rohkem rõhutanud mind, et ma ei viskaks toitu ära. Toitu on lihtne säästa, kui tean, kui palju ma niimoodi keskkonda mõjutan.\nToidukadu on nähtus, kui toitu visatakse ära, sest see jääb lihtsalt üle. Väga lihtne oleks sellest hoiduda, kui inimesed oleksid teadlikud tõsiasjast, kui palju toidu raiskamine keskkonnale liiga teeb.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('86831bac-1fe5-4bd6-bf01-5e1c55921059', 'title', 'Mis on toidukadu ja kuidas sellest hoiduda?');
INSERT INTO core.text_property(text_id, property_name, property_value)
