INSERT INTO core.text(id, content)
VALUES ('6e294288-ea1b-40f8-b042-c530509e10f2',
        'Inimesed tarbivad ja ostavad mõttetult palju asju kokku, mida polegi neil endil vaja. See põhjustab maailmas ületarbimist suurtes kogustes. Üks suur küsimus on maailmas kuidas saaks ületarbmist vältida.\nÜks hea soovitus on mõelda enne ostmist läbi, et kas mul on ikkagi seda nüüd päriselt vaja või nägin seda kellelgi ja nüüd tahan seda sama asja ka endale osta. Tuleks osta kohe kõrge kvaliteediga riideid, mööblit, nõusi jne. Mina vaatan, et riideid oleksid kõrge puuvilja sisaldusega või 100% puuvillast. Pigem eelistada kodumaiseid tooteid mitte Hiina tooteid, mis lagunevad kiiresti.\nKogu aeg tulevad peale uued trendid ja vanad muutuvad veidraks, siis tormavad inimesed uusi trendikaid rõivaid, mööblit ja majakujndust ostma. Minu vanemad lähevad maja kujundamis trendidega kaasa, ükspäev nägid mu vanemad internetis diivanit ja järgmine päev tulen koju näen, et meil uus diivan kodus. See raiskab inimeste enda raha ja palju ressursse: maad, vett, tööjõudu ja energiat.\nKiirmood on tänapäeval väga populaarne näiteks shein, h&amp;m, new yorker ja paljud muud riidepoed. Veel kasutatakse kiirmoes palju lapstööjõudu, lapsed töötavad mitmeid tunde päevas riideid valmistades ja nende palk on väga väike. Mina ja mu sõbrad ostame ka kiirmoe rõivaid vahepeal. Kiirmoe poodides on soodukad, millega inimesed kaasa lähevad.\nEnne ostu peaks läbi mõtlema milleks ma seda kasutaks ja kas on ikka seda vaja. Ei pea kogu aeg kiirmoe trendidega kaasa minema, mis sureb umbes 2 nädalaga välja. Peaks rohkem kvaliteetseid rõivaid ostma, mille väga suur % on puuvili mitte polüester. Kui inimesed oleksid tagasihoidlikumad oma ostutega väheneks ületarbimine suures koguses.');
