INSERT INTO core.text(id, content)
VALUES ('fd4a282f-56ff-40ed-8867-7b93d642acec',
        'Tänapäeva ühiskonnas on tihti enesestmõistetav, et ostetud jalanõusid või jopesid saab kanda ainult ühe aasta ning, et eelmisel päeval kasutustähtaja kaotanud toit tuleb ära visata, sest see ei ole enam kõlblik. Avalikkus ei mõtle jäätmete kogusele, mis iga aasta tekib. Seisame seetõttu küsimuse ees, kas ja kuidas saame vähendada tarbimist tänapäeva kiirmoe maailmas?\nInimesed, kelle igapäeva osaks on osutunud kauplustes aja veetmine ja uute kaupade muretsemine, ei mõtiskle järgnevate põlvede elu üle. Millises maailmas peab rahvas elama näiteks saja aasta pärast ning kas loodusest on midagi alles, kui massiline tarbimine jätkub. Suvel ostis minu trennikaaslane endale spordijalatsid, mida ta kandis ühe ainsa korra. Järgimsel korral uhkeldas ta uute jalavarjude üle öeldes, et eelmised läksid katki ning on moest väljas. Kauba soetamisel peab jälgima eelkõige kvaliteeti, vastandliku suhtumisega ei jää planeedist juba praeguse põlvkonna elu jooksul midagi järele.\nToit ei ole lõputu vara ja saab ühel hetkel otsa. Noored ostavad toitu proovimiseks või naljakete sotsiialmeedia videote tegemiseks, peale mida lõpetab söök prügikastis. Samuti tekitab tähtaja ületanud toidukraam, mida on võimalik veel tarbida paljudes vastikust. Kui minu kodus piima kasutusaeg lõppeb, teen selle ära viskamise asemel pannkooke, kuid minu sõbrad sageli nii ei arva, mille tõttu koguneb neil liialt palju toidujäätmeid.\nTarbimine ületab piire ja tekitab keskonnale probleeme. Olukorra parandamiseks peaksid kõik inimesed oma oste läbi mõtlema, ja jõudma järelduseni kas toote soetamine on väärt raha ja jäätmeid, mis sellega kaasnevad. Mõõdukas tarbimine tagab kõigile puhta elukeskkonna ja pika elu.');
