INSERT INTO core.text(id, content)
VALUES ('1d4fe799-79ed-41b9-abb0-56aaf250ae00',
        'Liigne tarbimine on tekitamas suuri probleeme. Sellega kaasneb toidu raiskamine, liigne riiete ost kiirmoe brändidest, mida kantakse vaid paar korda ja ebakvaliteetse toodangu ostmine, erinevatelt Hiina veebilehekülgedelt. Sellega tekibki küsimus, Kuidas me saaksime vähendada tarbimist?\nToidu kogus, mida mina igakuiselt ära viskan on üsna väike. Sinna kuuluvad mõned üksikud kiiresti riknevad toidud, mida minu pere ei jõua õigeaegselt ära süüa. Kõige sagedasem ära visatav toit minu perekonnas on sai. Seda sellepärast, et seda müüakse väga suurtes pakkides, kuid mina ja minu vanemad seda nii palju ei tarbi, seega võib juhtuda, et paar viimast saiaviilu lähevad prügikasti. Toidu raiskamist saaks parandada väiksemalt pakendatud toodanguga.\nSmamamoodi on ka kiirmoe toodetega, mida ostetakse ja visatakse ära samakiiresti. Mudugi olen ka mina üheks kiirmoe toodete omajaks ja soetajaks ning seda on ka minu õbrannad. Sagedasti leian ma oma tee ebakvaliteetsete riietega poodi, siis kui mul on tuju lihtsalt osta midagi, kuid tegelikult sedasorti emotsiooniostude tegemine on keskkonnale kahjulik. Riiete ostu puhul oleks mõistlik minna, kas taaskasutuskeskusesse või üldse lahti mõtestada, kas vajan uut riideeset, sellise mõtteviisga saaks säästa loodust ja hoida enda raha kokku.\nPopulaarseks on muutunud ka erinevatelt Hiina veebilehtedelt tellimine, nagu näiteks: Aliexpressist, Sheinist või Temust. Võrgulehed kust saab tellida riideid ja muud pudipadi vaid paari euroga, ei tohiks pidada kvaliteetseks ega heaks keskkonnale ja ümbrusele. Olukorra parandamiseks peaksid inmesed tunnistama kas nad tahavd seda produkti, sest neil on seda vaja või soovivad nad seda hea hinna pärast.\nMa saan enda oste mõjutada, end keelata või peatada enne nende soetamist, kuid et meie ühiskonnas tekkiks muutus, peavad kõik olema kokkuhoidlikumad ja säästlikumad. Üldpildis on minu tutvusrindkonnas tarbimisega hästi ja seda tehakse mõõdukalt.');
