INSERT INTO core.text(id, content)
VALUES ('48d04a1e-ecb1-4810-927a-4f1210ee8a30',
        'Inimesed peaksid rohkem hakkama mõtlema tarbimisele, mida nad tarbivad ja kui palju. Toitu võetakse iseenesestmõistetavana. On inimesi, kes raiskavad ja neid, kes hoiavad maailma ja soovivad seda paremaks muuta, mõtlevad ette oma ostud, küsivad endalt, kas mul on seda ikka vaja osta, või kui söön, panen taldrikusse nii palju sööki, kui palju ma ise jaksan ära süüa.\nInimesi on tõesti mitmesugused, kes raiskab toitu, sest ta saab seda endale lubada ja mõtlev inimene. Väiksemaid koguseid toitu ära viskavad inimesed arvavad, et sellega nad suurt kahju ei tee, aga kui igas kodus visatakse pidevalt natuke ja natuke, siis see teeb kokku suure kahju. Kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg. Toidukadu ehk raisatud toit , mis mingil põhjusel (riknenud või kasutustähtaja ületanud toit) jääb tarbimata, visatakse toidujäätmena ära. Sellega suurendatakse tohutuid muid resursse: maad, vett, energiat ja tööjõudu. Lisaks tekitab toidu tootmine tõsise keskkonnakoormuse, sest saagikuse tõstmiseks kasutatakse väetisi ja erinevaid kemikaale. \nTuleb mõelda targalt. Moedisainer Eve Hansoni arvates on oluline, et igaüks vaataks üle oma isiklikud tarbimisharjumused ning eelistaks kvaliteeti kvantiteedile. Noortele tuleb teha ekskursioone taaskasutuspoodide lattu, ma arvan, et noored ise ei teagi , kui palju ressursse läheb, et sellist odavat ja mõttetut jama toota.\nInimesed peavad vaatama kriitilise pilguga, mis nad ostavad ja kui palju, näiteks toidu raiskamist ei saa vähendada üleöö. See on paljustki kinni inimeste harjumustes.');
