INSERT INTO core.text(id, content)
VALUES ('45df3ea4-eca8-4296-b29b-cdecfe2ce208',
        'Inimeste tarbimisharjumused, nagu toidu ja riiete raiskamine, on probleem. Praegune seis on, et inimesed raiskavad palju toitu ja riideid, aga kuidas saaks seda probleemi lahendada?\nInimesed ei tarbi toitu mõõdukalt, vaid ostavad näiteks toidu ja lasevad sellel halvaks minna. Mul vahest juhtub nii, et poes on näiteks kartulisalat allahinnatud, sest selle tarbimisaja lõpp on lähedal. Aga siis juhtub nii, et unustan selle täielikult ära. On inimesi, kes raiskavad toitu, sest nad saavad seda endale lubada. Minu arvates saab seda muuta nii, et koik ostavad endale seda toitu mis nad vajavad, mitte rohkem.\nSama asi on riietega. Tean inimesi kes viskavad riided ära ja ostavad endale uued, kuid saaks lihtsalt viia taaskasutusse. Mina arvasin alguses, et taaskasutus on mõttetu. Arvasin, et viiakse sinna vanad haisvad riided, aga kui esimest korda käisin, sain kohe aru, et nii ei olnud. Sain endale seal lahedad riideesemed ja kannan neid siiani. Käin seal tihti oma klassivennaga, siis kui on näiteks Humanas 1-5 euro päevad. Kui veel inimesi oleks nagu mina ja mu klassivend, oleks tarbimistase madalam.\nInimeste tarbimisharjumused on kehvad. Ostetakse toitu mida ei sööda ja riideid mida ei kasutata. Inimesed arvavad, et nende panus selle muutmisele ei tee suurt erinevust, aga kui kõik prooviksid, siis saaksime ühe sammu lähemale selle probleemi lahendamisele.');
