INSERT INTO core.text(id, content)
VALUES ('0e1727e3-63dd-4714-b1ee-820b9240b983',
        'Tänapäevases maailmas on lisaks globaalsele kliimamuutustele suur probleem tarbimisega. Aina suuremaks ja jõukamaks saavad suured töösturriigid, nagu Hiina, kes saavad oma jõukuse just massitootmise tõttu, müües tooteid küll odavama hinna eest, aga suurtes kogustes. Sellest saab eeldada, et tänapäeva inimesed ihkavad kvantiteeti üle kvaliteeti. Mingi osa inimesi saab aru, et on probleem tarbimisharjumustega, aga ikka tekib küsimus: „Miks on tarbimisharjumuste teema probleemne ja kuidas neid harjumusi sel juhul parandada?“\nOtse välja öeldes on inimestel halvad tarbimisharjumused. See on üldteatud fakt, mille peale paljud tavainimesed tihti ei mõtle. See probleem on viimase paari aastakümmnega muutunud viraalsemaks, aga siiski ei mõelda selle peale piisavalt palju. Ka mina ise ei mõtle sellest eriti, kuid ometigi olen sellest teadlik. Tänapäeval on inimesed harjunud, et kõik on lihtsasti kätte saadav, olgu see toit, riided või muu selline, mille jaoks alles pooleteist sajandi eest olid ka materjalid toote või koostisosad toidu valmistamiseks raskesti omandatavad. Kuna kõik vajalik on olemas ja kergesti saadav, ei mõelda enam üle, mis on tarvilik ja mis mitte, millest tulenebki jutualune probleem.\nPaljudel probleemidel on olemas lihtsad lahendused, sedasi on ka selle teema kohta. Kui tarbitakse vähem, tuleb ka juurde osta vähem. See ei tähenda, seda, et kui kõike toitu ära ei tarbita, peab nüüd kohe ostma ainult müslibatoone ja toituma neist terve päeva või lihtsalt näljutad end hommikust õhtuni hoides tagasi oma tarbimist. Tarbimise vähendamine tähendab seda, et ostetakse niipalju, kui ära tarbitakse. Eelneval päeval tehtud pudrust ülejäägid süüakse järgmisel söögikorral või päeval ära, ilma, et need jäägid ära visataks.\nTarbimisprobleemid on tänapäeval viraalsed, kuid igapäevaselt siiski vähe räägitud. Keskendutakse sellele, mida ei omata, väärtustades omatavate toodete rohkust üle toote kvaliteedi, mõtlemata ka vajadustele, mida on vaja ja mida mitte. Lihtsaim lahendus vähesema tarbimise jaoks vähendada juurde saamist, kasutades ära kõik, mis on olemas vajaliku eseme või toidu tegemiseks, ilma midagi juurde ostmata või ära viskamata.');
