INSERT INTO core.text(id, content)
VALUES ('c85d6378-74e7-4734-a65f-25b231986382',
        'Inimeste tarbimisharjumused kujundavad meie maailma. Mida rohkem tarbitakse, seda suuremad on muutused, mida lohakamalt tarbitakse, seda halvemad on muutused.\nÜhiskonnas saab tarbida rohkem see, kes on jõukam. Kui inimene teenib hästi, saab ta rohkem süüa, riideid ja asju osta. See viitab ka suuremale tarbimisele. Kui tarbitakse suurelt, siis kasvab ka majandus, sest toodetakse rohkem. Keskkonda see aga kahjustab, sest kui toodetakse rohkem, tekib rohkem kahjulikke aineid, mis satuvad loodusesse. Suurelt tarbimisel on mitmeid häid ja halbu külgi, kuid see, kas inimene saab suurelt tarbida, sõltub tema ressurssidest.\nKui inimene tarbib lohakalt, siis kahjustab see keskkonda ja koormab teda ennast ning ühiskonda. Lohakalt tarbimine on see, kui tarbitakse odavat kaupa, mida toodetakse suurtes kogustes. Inimesed ostavad kauba, kasutavad seda lühikest aega ning seejärel viskavad kauba ära ja ostavad uue sarnase asemele. See kahjustab keskkonda, sest tootmine suureneb. Ka mõjutab see inimese rahakotti, kui ta ostab iga natukese aja tagant uusi asju. Lisaks koormab ka lohakas tarbimine ühiskonda, sest tootmine suureneb ja seega on tööd rohkem. Eriti mõjutab see riike, kus kasutatakse odavat tööjõudu. Lohakalt tarbimine võib olla küll lühemas vaates kasulik, kuid suures pildis ei too see maailmale kasu.\nTarbimisharjumused tuleb kujundada vastavalt oma ressurssidele ja teadmistele, sest nii saab mõjutada tarbimise mõju ühis- ja keskkonnale.');
