INSERT INTO core.text(id, content)
VALUES ('a295c580-35b8-4ada-bc56-41c146c8df2f',
        'On teada, et meie koduplaneet Maa on reostumas. Seda põhjustavad paljud erinevad faktorid, näiteks kõiksugused kahjulikud heitegaasid, kütuseautode liigne kasutus, ületootmine tehastes ja üleliigne tarbimine. See kõik on väga kahjulik nii mereelule, maismaaökosüsteemi kvaliteedile ja ka inimestele. Aga kuidas ikkagi vähendada saastumist?\nLiigne tarbimine on üks suuri probleeme maismaaökosüsteemi kvaliteedis. Ma olen teadlik, et minu sõbrad tellivad internetist suurtes kogustes Hiina kraami, mis toodetakse väga odavalt ja ebaeetilistes töötamistingimustes. See mõjutab juba meie elamistingimusi ja õhukvaliteeti, sest riided, mis nad tellivad peavad olema siia transporditud lennuki või laevaga. Liigset kokkuostmist tuleb esile ka toite hankides. Mul endalgi kajastub see, et kui me läheme perega poodi, siis me ostame kokku kraami, mida me tegelikuses ei vaja ja mis istub külmkapi taga nurgas, oodates oma aega, millal ta rikneb. See on ehe näide ületarbimisest.\nKindlasti on selleks paremaid viise, kuidas mitte raisata toitu. Ennem poodi minemist peaks tegema poenimekirja asjadest, mida sa tegelikult kodus vajaksid ja kasutaksid, see säästaks rohkem toitu räästumisest. Üleliigsete riiete tellimise asemel võiks eelistada taaskasutuskeskusest ostetud riideid, sest nii säästab rohkem meie planeeti. Mina olen ikka käinud ennem internetist tellimist vaatamas taaskasutatud riideid selle asemel, et osta mingit pahna kokku Hiinast. Juba see väike, justkui tühine tegevus hoiab veidikene õhu puhtamana.\nOma koduplaneeti peab hoidma, et järgmised põlved saaksid ka nautida meie loodust, imelist mereelu ja värsket õhku. See kõik ei juhtu kindlasti ülepäeva, see võtab aastaid aega, aga oluline on alustada väikeste sammude haaval.');
