INSERT INTO core.text(id, content)
VALUES ('678a9f4b-d428-4b37-b4d5-c8ef031976c0',
        'Iga päevaga muutub suuremaks inimeste vajadus midagi uut osta. Inimesed raiskavad tihti oma raha ebavajalikele esemetele ning hiljem viskavad need minema. Seda tehakse mitmel viisil.\nVäga populaarseks on muutunud internetist riiete tellimine. Eriti palju riideid tellitakse Hiina kiirmoepoodidest nagu Shein, Aliexpress ja Temu, sest Hiinas toodetud rõivad on odavad ning valikuvõimalus on suur. Need riided on tehtud sünteetilisest materjalist või naftast ja nende eluiga ning kasutusaeg on tihti lühike, sest need pole kvaliteetsed ja seetõttu satuvad taaskasutuspoodidesse või prügimäele. Selline eluviis pole jätkusuutlik sest see saastab kiiresti maakera ja muudab inimeste eluolu halvemaks.\nToidujäätmete kogus suureneb iga päevaga. Inimesed arvavad, et toitu on lõpmatu kogus, kuid see ei vasta tõele. Lisaks toidu vähenemisele kliimasoojenemise ja loomadele ebasobilike elutingimuste tõttu on ka suureks probleemiks toidukadu ehk raisatud toit. Tihti toiduained aeguvad ja peaaegu alati jääb söömisel toitu üle. Selle toidu kogus võib tunduda väike, kuid pika aja jooksul koguneb seda sööki väga palju. Seetõttu raiskavad inimesed teadmata oma raha ning palju teisi ressursse: energiat, vett ja tööjõudu. Toidu kulutuse vähendamiseks tuleb teha mõistlikke valikuid toiduaineid ostes, toitu tehes ja säilitamisel.\nKeskonnaprobleeme on palju ja nendest hoidumine võib olla keeruline, kuid praeguse olukorra halvenemise vältimiseks peaks iga inimene panustama ja tegema tarkasid otsuseid riideid, toiduaineid ja muud ostes.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('678a9f4b-d428-4b37-b4d5-c8ef031976c0', 'title', 'Kuidas mõjutab inimeste teadmatu saastamine tulevikku Maal?');
INSERT INTO core.text_property(text_id, property_name, property_value)
