INSERT INTO core.text(id, content)
VALUES ('015391df-5c6a-4adb-af02-99185e44fe3f',
        'Mõned inimesed on harjunud tarbima rohketes kogustes. Nad ei ole aga teadlikud, et see tegevus saastab keskkonda. Millised mõjud on liigsel tarbimisel keskkonnale ning mis on selle tegevuse põhjuseks?\nPaljud inimesed ostavad endale koju suures koguses toitu. Poest tulevad nad tagasi kolme suure kotiga, mis on täis söögi valmistamiseks vajalikke aineid. Need jäävad aga enamusel ülejääkideks, mistõttu visatakse toit prügikasti. Mõned inimesed ei ole teadlikud, et see tegu võib keskkonda halvasti mõjutada. Veebileheküljel „Tarbi, toitu targalt“ on kirjutatud, et liigne toidu tootmine toob endaga kaasa tõsise keskkonnakoormuse, sest saagikuse tõstmiseks kasutatakse väetisi ja erinevaid kemikaale. Inimesed ei ole teadlikud, et liigse toidutarbimisega saastatakse keskkonda. \nPaljud inimesed ostavad endale kokku rohkes koguses riideid, kuid pärast esimest rõiva kandmist viiakse see taaskasutuskeskusesse. Minu sõbranna pere tellib iga nädalavahetus Hiina veebipoest nimega Shein uusi pükse ja pluuse, sest nad tahavad, et neil oleks iga nädal uued riided. Nad viivad rõivad pärast esimest kandmist uuskasutuskeskusesse, sest materjal on ebamugav. Anu Välba ütles saates „Vikerhommik“, et paljud Hiina poodide riided koosnevad naftast ja neid ei saa tihti rohkem kui üks kord kanda. Inimesed peaksid oma riiete ostmist läbi mõtlema ja ostma kvaliteetsemaid rõivaid, mida nad saaksid rohkem kui nädala kanda.\nInimesed on harjunud tarbima suurtes kogustes. Nad ostavad endale koju toitu, mida pere ei suuda ära tarbida. Paljud aga ei ole teadlikud, et liigne toidukraami ostmine mõjutab keskkonda halvasti. Mõned aga ostavad endale liiga palju riideid, sest tahavad, et nende riidekapis olevad rõivad oleksid iga nädal uued.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('015391df-5c6a-4adb-af02-99185e44fe3f', 'title', 'Inimesed on harjunud tarbima suuri koguseid');
