INSERT INTO core.text(id, content)
VALUES ('7fb436bf-2268-437a-9767-75480b5d461b',
        'Toidu ja riiete raiskamine on ühed põhilistest probleemidest tänapäeval. Nad põhjustavad paljude ressursside raiskamist: raha, maa, vesi, energia ja tööjõud. \nToidu raiskamise vähendamiseks on palju erinevaid võimalusi. Näiteks, kui söömisel on toitu üle jäänud, siis tuleb algusest peale panna väiksema portsu, sest juurde saab alati võtta. Inimesed, kes saavad endale toidu raiskamist lubada, peaksid mõtlema keskkonna peale, sest toidu tootmine tekitab tõsise keskkonnakoormuse. Kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 26 kg. Kahjuks aga ei saa toidu raiskamist vähendada üleöö, sest see on paljuski kinni inimeste harjumustes. \nRiiete raiskamine ja ületootmine põhjustavad Hiina kaubamajades töötavate inimeste tööülekoormust. Paljud noored tellivad endale riideid Hiina veebipoodidest ning lähevad kaasa sooduskampaaniatega. Eve Hansoni arvates võiks eelistada kodumaiseid asju ning pigem vähem kui rohkem, sest eelistada tuleks kvaliteeti kvantiteedile. Taaskasutuspoodides tekib iganädalaselt riideid juurde, mis näitab, milline raiskamine tegelikult toimub. Sinna viiakse üldiselt korralikke riideid, aga ka selliseid, mis koosnevad naftast ning neid ei taheta kanda rohkem kui üks kord. Väga paljud sellised riided on pärit suurtest Hiina kaubamajadest. \nJärelduseks võib öelda, et toidu ja riiete raiskamise vähendamiseks tuleks oma isiklikud tarbimisharjumused üle vaadata.');
