INSERT INTO core.text(id, content)
VALUES ('16694000-04dd-405e-9f8f-b21b374b9368',
        'Iga päev raisatakse maailmas tohutu suurtes kogustes toitu ja toiduaineid mida saaks vältida. Toidu raiskamine on suur probleem ja sellega peab tegelema.\nMaailimas raisatakse igapäev suurtes kogustes toitu, mis on suurprobleem juba selle pärast, et toidu tegemiseks kasutatakse ressursse nagu maad, vett, energit ja tööjõudu. Nende ressursside raiskamine teeb halba kliimale ja meie rahakotile.\nToidu raiskamist saab vältida mitmel moel. Näiteks saab annetada ülejäänud toorained varjupaikadele ja muudele sellistele kohtadele. Teiseks saaks toitu üldse vähem osta, kui sa tead, et sa seda kõike ära ei tarbi. Toidu annetamine aitaks väga varjupaikasid kes siis peaksid vähem raha kulutama inimsete toitmisele.\nToidu ületootmine tekitab suure koormuse planeedile, sest selle tootmiseks kasutatakse palju kemikaale ja väetisi, mis reostavad meie planeeti. Toidu ületootmise vähendamiseks saaks igainimene jälgida enda toidukoguseid ja vajadusel annetada ülejäänud toidu. \nOn palju inimesi, kes arvavad, et nende toidu ära viskamine ei muuda midagi, isegi kui see on väikestes kogustes. Kui iga inimene hakkaks niimodi mõtlema oleks toidu raiskamise kogus palju suurem.\nToidu säästmine ei päästa mitte ainult meie planeeti vaid ka meie rahakotti.');
INSERT INTO core.text_property(text_id, property_name, property_value)
