INSERT INTO core.text(id, content)
VALUES ('55d5948a-3757-474e-8093-304443dd1040',
        'Meie modernses maailmas tarbitakse palju, isegi liiga palju. Inimesed tarbivad päirs palju asju, näiteks sööki, vett, riideid, tehnikat jne. Ega selles midagi valet ei ole, et inimesed asju tarbivad, aga seda peaks tegema säästlikult.\nMa tooks esimesena välja toidu. Me raiskame toitu väga palju ja see on probleem, sest me kulutame päris palju ressurse, et seda kasvatada. Meil siin Euroopas on päris lihtne toitu raisata, sest meie jaoks ei ole toit enam väärtuslik, sest seda saab lihtsalt poest osta. Mujal maailmas nagu Aafirkas on toidu kätte saamine palju raskem ja paljud nälgivad seal. \nRiided on ka asjad, mida me liiga palju tarbime. Ma ei saa aru, miks inimestel on nii palju riideid vaja. Paljud ostavad endale hullult riideid, aga kannavad neid väga vähe. Minul endal ei ole palju riideid ja vihkan käia riidepoodides, sest see on minu jaoks igav. Mul vanemad ja vanavanemad alati tahavad minuga riideid ostama minna. Muidugi, kui riided hakkavad väikseks minema, siis võiks küll uued osta, aga pole vaja koguaeg neid osta.\nTehnika tooted võtavad väga palju ressurse, et teha, aga inimesed raiskavad neid palju. Ma ei saa aru miks on inimesel vaja endale uus Iphone osta, kui nende vana töötab veel täiesti hästi. Minu praeguse telefoni sain 8.klassi ja mul pole veel pikka aega plaani, et uus osta. Minu eelmine telefon oli mul olnud juba 4.klassist. Minu mõtte on alati olnud, et kui veel töötab, siis kasuta seda nii kaua, kui veel töötab.\nMeie tarbimine on liiga suur ja seda tuleb vähendada. Minu arust see ei ole nii raske, aga paljud inimesed on lihtsalt sellega harjunud ja neil on raske sellest välja tulla. Loodedavasti inimesed hakkavad säästlikumalt tarbima.');
INSERT INTO core.text_property(text_id, property_name, property_value)
