INSERT INTO core.text(id, content)
VALUES ('8aa84e00-5d4f-4310-9aad-173b27cb25d4',
        'Paljud inimesed raiskavad toitu, mida ei sööda või ostavad riideid, mida ei kanda. Enamus nendest asjadest visatakse ära prügikasti, kust need hiljem viiakse prügimägedesse ning sellega tuleneb küsimus: Miks paljud inimesed raiskavad ja mida saaksid nad teha, et seda alandada?\nEnamus toitust, mida inimene ära viskab on, kas ülejäänud- või pahaks läinud toit. Vahel tahab keegi proovida midagi uut kokata ning toidus on näiteks toitaine, mida nad pole varem proovinud, aga tuleb välja, et neile ei maitse see toiduaine ja nad viskavad selle ära või jätavad kappi istuma, kus see läheb pahaks. Veel raisatakse toitu, kuna seda saab endale lubada, ostetakse nii palju toitu, et nad ei suuda seda ära süüa. Seega peaks rahvas vaatama, et kas ta sööb seda toitu ja et ei ostaks nii palju toitu korraga.\nInimestel pole vaja nii palju riideid, eriti riideid mida nad kannavad vaid ükskord elus ja enam mitte kunagi uuesti. Kui inimesel on põhjus riideid ära visata näiteks kui riideesemele on tekkinud plekk, mis ei tule ära või on läinud nii katki, et korda ei saa teha. Seega peab inimene mõtlema hoolega, et kas ta kannab seda riiet.\nInimene peaks küsima rohkem endalt kas ta kasutaks seda asja või ei?');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('8aa84e00-5d4f-4310-9aad-173b27cb25d4', 'title', '‘’Liigne raiskamine,,');
