INSERT INTO core.text(id, content)
VALUES ('2fa827fb-3cba-4f5a-a9a2-9cc11d7dff74',
        'Meie maailmas on palju inimesi, kes tarbivad erinevaid produkte. Kõik inimesed on erinevad ja tarbivad produkte, kuidas erinevad inimesed on harjunud. Nüüd tekib küsimus, millised on inimeste tarbimisharjumused?\n            Inimesed on maailma kõige suuremad tarbijad. Üks halvemaid tarbimisharjumustest on see, et inimesed ostavad kaupa, mida nendel pole tegelikult vaja. Selle tarbimisharjumusga kaasneb näiteks reostus, sest inimesed viskavad lõpuks ära selle toote, mida nendel pole vaja. Ainus asi, mis hea on selle tarbimisharjumuse kohta, et riik saab raha käibemaksu eest, mis võimendab riiki edasi areneda. Teist tüüpi tarbimisharjumus on raha säästmine tarbimisel. Need inimesed on rahatargad, sest nad oskavad paremini raha säästa kui teised tarbijad. Kaks head eelist tarbijale on, et säästab raha kui tarbib midagi, ja et isik ei tarbi üleliigset kaupa endale, mille ta lõpuks ära viskaks. Mõned inimesed tarbivad asju, mis toovad rõõmu isikule, või mis keeravad tähelepanu teisele poole mingist asjast, mis tekitab stressi. Ned inimesed tarbivad narkotikume. Kui inimene on harjunud tarbima narkotikume igapäevaselt ja ei saa funktsioneerida normaalselt siis on isikul tekkinud sõltuvus. Loomlikult see on kohutav asi, mis võib isiku elu ära rikkuda. Sõltuvus võib tekkida iga asja vastu, mida saab tarbida, näiteks sõltuvus võib tekkida ka magustoidu vastu.\n           Kokkuvõtteks tahan öelda, et kõik inimesed on erinevad ja nende tarbimisharjumused on ka. Mõned harjumused on head aga mõned mitte, nii et iga inimene peab enne tarbimist mõtlema, kas on tegelt vaja seda toodet, ja millised tagajärjed on.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('2fa827fb-3cba-4f5a-a9a2-9cc11d7dff74', 'title', 'Inimeste tarbimisharjumused');
