INSERT INTO core.text(id, content)
VALUES ('fb2e99c6-4d2f-4006-8eb6-cf49fb87e18e',
        'Toit on väga oluline osa meie igapaeva elust ilma milleta me ei saaks elada. Toit peaks olema koigile kättesaadav ning seda peaks jätkuma igale inimesele võrdselt. Kuid kas toitu jätkub ikka igaühele vordselt?\nKahjuks ei jätku on inimesi kes töötavad väga mitmeid tunde, et saada natukene süüa. Vaadates teisi siis on maailm ebavordne nende jaoks, aga ma arvan, et seda on vaga raske muuta, sest kui me vähendame enda toidu tarbimist siis väheneb ka meie toidu tootjate palk, mille tõttu  võivad nad hoopis halvemat elu elada.\nMa arvan, et see oleks tõesti parem kui me õpiksime sorteerima toitu ja sellest õigesti lahti saama, aga kahjuks ei ole see võimalik. Maailmas on umb 8 miljardit inimest keda on võimatu koiki kontrollida, kuid saab rakendada seadused erinevate kemikaalide vastu, et natuke midagi päästa. Kui siia mängu tuua minu enda arvamus siis arvan mina, et jah me peaksime proovima säästlikult toituda, aga samas me peaksime ka aitama neid kes tõeliselt vajavad seda abi. Ma arvan et koik riigid peaksid ühinduma, et luua keskkond kus iga inimene on võrdne mimg keegi ei pea muretsema toidu pärast kui me saavutaks sellise maailma siis suudame ka saavutada stabiilsuse ning suudame hoida meie maad ning toota nii palju toitu kui kellegil vaja on.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('fb2e99c6-4d2f-4006-8eb6-cf49fb87e18e', 'title', 'Toidukadu');
