INSERT INTO core.text(id, content)
VALUES ('e210c2fd-77c4-48f8-8100-981f3b0dd269',
        'Tänapäeva elus on suur probleem toidu kadu ja toidu raiskamine. Näiteks me viskame ära oma elus nii palju toitu ja raiskame enamus mille me oleme kokku ostnud.\nKui mina ja mu vanemad käime poes, me alati ostame kõike mis vaja on puuviljad,juurviljad ja muud toiduained mida me sööme. Aga palju kordi juhtub seda et neid toiduaineid jääb üle, kui me neid söögis ära ei kasuta. Ja siis need lähevad tihti hallitama või kana läheb pahaks. Kõige rohkem läevad meie kodus raisku puuviljad, juurviljad ja natuke liha, kuna mõnes retseptis on ainult natukene neid toiduained vaja näiteks ingverit  ja siis meil ei ole pärast midagi nende ülejääkidega teha.\nMina arvan et seda probleemi võiks ennetada niimoodi et inimesed ei osta liiga suurtes kogustes toiduained, vaid ostavad täpselt niipalju kui neil seda vaja läheb. Näiteks pakkide asemel võiks osta lahtiselt paprikaid või võtta väiksem kurk, kui sa tead et sa ei söö seda suurt ära. Või siis kui niimoodi ei saa, võiksid inimesed selle toidu viia kuhugi toidupanka peale seda kui nad ise selle ära kasutanud on, kuna siis see ei lähe raisku ja keegi kasutab selle ikagi ära.\nKokkuvõteks ma tõesti loodan et see probleem saab tulevikus lahendatud, niimoodi nagu ma olen välja toonud kuna toit on tähtis igale elusolendile ja seda ei tohiks aastas tõesti niipalju raisata.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('e210c2fd-77c4-48f8-8100-981f3b0dd269', 'title', 'Toidu kadu');
