INSERT INTO core.text(id, content)
VALUES ('a5a5eec7-d6d9-4970-9ad0-59d45c30a554',
        'Inimestel pole parimad tarbimisharjumused. Seda näeme eriti riiete- ja toidutööstluses, kus inimesed ei tee kohusetunlikke otsuseid neid ostes.\nInimesed ei tarbi riideid kohusetunlikult. Tänapäeval on tavaline see, et moodide ja trendidega püsitakse kaasas. Seetõttu, kui uued riided letile saabuvad, juhtub nähtus, kus uued riided leivad endale kapis koha ja vanad lähevad, kas prügilasse või taaskasutusse. Lisaks riiete puhul jälgitakse pigem kvantiteeti kui kvaliteeti, mille tõttu kulub palju ressursse asja nimel, mis ei peavastu pikalt. Näteks, Prantsusmaal toimunud olümpiamängud, kus oli võimalik igasugu riideid osta, mis näitas inimese kaasaelamist ja sõltuvalt riidest, mis riig poolt inimene oli. Aga nüüd, kui olümpimängud on läbi saanud siis pole enam nende riietega midagi peale hakata. Inimesed peaksid valima ostuks endale riideid, mida nad näevad ennast kasutamas pikka aega ja tihti ning vältima trendidega kaasas käimist.\nInimesed ei tee läbimõeldud ja kohusetundlikke otsuseid poest toitu ostes. Tihti peale on ikka nii, et toit jääb külmkapis vanaks või mõnel muul põhjusel on vaja sellest vabaneda ilma selle tarvitamata. Näiteks, kui inimene teab, et ta ei joo palju piima ega söö palju saia, pole tal mõtet osta 2l piima pakki ja 1kg saia, lihtsalt selleks, et nendel oleks võimalus rikneda. Toidu ostjad peavad hakkama tegema läbimõeldud oste, kus nad arvestavad oma toitumisharjumustega, et saak liikset raisku vältida.\nInimesed peavad hakkama paremini jälgima oma ostude tegemist nii riiete kui ka toidu ostmises. Jälgides tuleb hakata tegema rohkem kohustundlikke ja läbimõeldud otsuseid, mis aitab Maal olevaid ressurssevähem tarvitada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('a5a5eec7-d6d9-4970-9ad0-59d45c30a554', 'title', 'Inimeste tarbimisharjumused');
