INSERT INTO core.text(id, content)
VALUES ('ac16b0d1-acf3-4574-9a64-ab0e8d77f206',
        'Maailma üheks levinumatest probleemidest on liigne toidu tarbimine, kuna paljud inimesed ostavad rohkem toitu kui tarbida jõutakse. Riiete liigne tootmine on samuti üks suurtest probleemidest mida saaks parandada.\nToidu liigne tarbimine on suur probleem mida saaks muuta, kui nt minna poodi nii et sa mõtled ja otsustad ära enne mida sa poest ostad ja ostad seda mõõdukalt, et jõuaksid ära tarbida ning annad ka teistele võimaluse seda toitu osta ja tarbida millega säästad samuti ka loodust ning maavara säästmist. Paljud inimesed ei saagi lubada endale kunagi sellistes kogustes toitu tarbida, kui nt sina igapäevaselt tarbid.\nRiiete liigne tootmine mis on suureks probleemiks nt nagu kiirmood mis tuleb hetkeliseks ja kaob päris kiirelt ja sina ostad neid kiirmoe tooteid kasutad neid mõnda aega ja siis viskad minema mis ei ole ilmselgelt mõistlik otsus kuna sellega tekib palju prahti ja ka materjali kadu. Palju mõistlikum oleks lihtsalt osta riideid aga mitte suures koguses ,kuna enamusel meist on tegelikult kodus rohkem riideid , kui vaja on . Pigem kanda need lõpuni kui osta kohe uued esimesel võimalusel. \n Maailmas on palju muresi mis on suured ja rasked. Me saaks kõik teha midagi mis aitaks maailmale kaasa ja ei reostaks seda nii hullult tuleb lihtsalt mõelda oma ostud ja käigud läbi ning teha neid mõistuse piires');
INSERT INTO core.text_property(text_id, property_name, property_value)
