INSERT INTO core.text(id, content)
VALUES ('296747c3-dd87-4cdc-bc03-7f3294ca284d',
        'Meie maailmas see on väga suur probleem et me viskame väga palju toitu ara. Sest inimesed raiskavad enda aaega, raha,jõudu. Maailmas 100 prosentist viskavad ara 42 prisenti toidu ära, see on peagu pool ja see on vaga palju.Paljud inmesed naiteks panevad endale liiga palju toitu ja pärast  ei söö seda ära ja viskavad prügikasti.\n                Naiteks kui sull on mingi kodu loom ja sa ei söönud lõpuni liha siis võib naiteks talle anda, saa pead aru saama kui palju sa suudad ära süja,teha süja vaiksemattes kogudes, parem saa teed teist korda kui viskad ära toitu. Tähtis ka on, et ei ostaks vaga palju toitumis läheb kiiresti halvaks, naiteks: piima, saia, puuvilju ja nii. a arvan need 42 prosnti toidu mis viskavad see on selle pärast ,sest nad lahevadhalveaks.  Ma nagin mõni kord ,et kui inimesed käivad piknukul siis viskavad erinevad kurkid, tomatit ringi.\n                  Minu jaoks see on vägaaru saamatu kuidas inimesed loobivad toitu ringi, ostavad väga palju ja ei söö ära seda. Inimesed ise raisakad toidu pale enda raha ja viskavad seda ära, moned ostavad ja isegi ei proovi seda jätavad külmkappi seisma ja koik.');
INSERT INTO core.text_property(text_id, property_name, property_value)
