INSERT INTO core.text(id, content)
VALUES ('f11f93d0-44e7-4374-9ede-f878952037d1',
        'Inimesed tihtipeale ei mõtle selle peale kust nad oma asju ostavad või miks need üldse vajalikud on. Kas inimestel on vaja saasta kokku osta?\nPaljud inimesed on harjunud ostama palju sööki kokku, ilma mõtlemata miks neil seda üldse vaja on. Erinevad soodushinnad mõjutavad inimeste mõtlemist ja julgustavad inimestel neid osta. Sageli pole ise inimestel neid tooteid vaja. Nad viskavad need söögitooted ära või jäävad need neile kuhugi kappi seisma. Kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid. Toidu tegemiseks kulub suur hulga ressursse ning visates kasutamata toitu ära, on selle toidu tegemiseks tagavara raisatud ilma asjata. Inimesed peaksid ainult vajalikke asju ostama, asju mida nad teavad, et nad kasutavad.\nInimsed tellivad ka igasuguseid riideid soodsalt, kusagilt Hiinast, mõtlemata kui halb nende kvliteet päriselt on. Need riided võivad näha head piltidel, aga tegelikult on need tehtud kiiresti ja soodsatest materialidest. Tihti kipuvad need rõivad ruttu minema ja need visatakse kohe ära. Selliste riiete ostmine ja ära viskamine on mõttetu. Tuleks valida kvaliteet kvantiteedile. Sellised ära visatud riided liiguvad taaskasutuspoodides, kus lõpuks on neid liiga palju. Tuleb osta riideid mis on heast kvaliteedist.\nInimesed ostavad igasuguseid asju omale kokku, aga päriselt peaksid nad ainult ostama asju mis neil on vaja ja mida nad kasutaksid.');
INSERT INTO core.text_property(text_id, property_name, property_value)
