INSERT INTO core.text(id, content)
VALUES ('fc92f4df-7ff5-45d7-954b-96a6bfab0a58',
        'Paljud inimesed on harjunud sellega, et toidujääke, kasutatud riideid ja muid jäänuseid saab lihtsalt minema visata. See on aga raiskamine ning seal on palju asju, mida saab jäänuste või kasutatud asjadega teha.\n Üks peamine probleem ongi toidujäägid, mis ära visatakse. Meile tundub, et see väike kogus toitu, mis peale söömist üle jääb, ei tee midagi kui ära viskame. Selline mõtlemine toob toidukadu aastas tavalise inimese kohta keskmiselt 26 kg. Toidu raiskamine on maailmale üldiselt halb, sest toitu ei ole maailas lõpmatult ning selline raiskamine on halb ka rahakotile. Sellise luksuse ülalpidamiseks läheb aga tohutult ressursse ning lõpuks tekitab selline raiskamine ka keskonnakoormuse, kuna kasutatakse rohkelt väetisi saagikuse tõstmiseks.\n Riiete ostmine ja nende kohene ära viskamine on ka muutunud tavaliseks. Inimesed ostavad Hiina veebipoodidest endale mõne riideeseme ning peale mõnda aega kandmist on riie juba räbalaks minemas. Need riided lähevad kas mõnda taaskasutuskeskusesse või otse prügikasti. Samas visatakse ära väga kvaliteetseid riideid ning ka need satuvad taaskasutuskeskustesse. \n Tarbimisharjumused on meie elus muutunud liiga raiskavaks, aga neid harjumusi saab väga kergelt ja koheselt parandada. Toidujääkide minema viskamise asemel saab neid kasutada loomade toitmiseks ja komposti jaoks ning riideid,  mida sa enam ei taha või ei kasuta, on võimalik viia taaskasutuskeskustesse või kasutada mõnel nutikamal otstarbel.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('fc92f4df-7ff5-45d7-954b-96a6bfab0a58', 'title', 'Inimeste tarbimisharjumused');
