INSERT INTO core.text(id, content)
VALUES ('bb88bfd4-f4a4-4cd1-b537-83209d7d569a',
        'Ülemaailmseks probleemiks on see, et inimesed raiskavad toitu, viskavad ära riideid mööblit ja palju muud. Inimesed ei taipa, et see kõik on ohuks inimkonnale.\nKõik ostavad poest nii palju toiduaineid ja ei mõtle sellele, kui palju nad suudavad ära tarbida. Inimesed arvavad, et kui osta koju palju toitu, ei pea nad nii tihti poes käima, tegelikult võiksid inimesed teha omale näiteks nädalase toitumiskava ja selle järgi osta koju kõik vajalik, et ei tekiks sellist olukorda, et peaks midagi ära viskama. Tihtipeale toiduained aeguvad ja inimesed viskavad ära toitu mis paar päeva tagasi oleks olnud täitsa kõlblik. Külmkapp ei pea alati olema paksult toitu täis, seal peaksid olema just need asjad, mida keegi suudab toidu aegumiseni ära tarbida.\nŠoppamine on teine probleem maailmas, eriti noorte seas. Ostetakse omale nii palju riideid kokku ja mõne aja pärast kantakse kapist ainult mõnda asja. Noorte seas on väga populaarne tellida kusagilt internetist omale riideid, näiteks Sheinist või siis tellida kalleid brändi riideid. Minu arvates kalleid brändi riideid pole mõtet omale kokku osta, need riided jäävad nagunii väikseks ja siis tundub nagu oleksid raha lihtsalt tuulde lastud. Hiinast toodetud riided on küll väga ilusad ja lahedate mustrite või piltidega, tihtipeale Eestist selliseid ei leia, aga Hiina riided sisaldavad aineid või mürke, mis teevad riiete kandmise ebamugavaks. Selle probleemi lahendamiseks on võimalus šoppamas käia taaskasutus poodides, sealt leiab odavaid ja huvitavaid riideid. Iga nädal tuleb taaskasutus poodidesse uut kaupa ning need poed on üle koormatud. Inimesed võiksid rohkem käia taaskasutus keskustes ja vähem tellida omale riideid Hiinast.\nInimesed võiksid rohkem mõelda oma tarbimisharjumuste peale, säästa raha ja raisata vähem asju. Nende probleemide lahendamiseks on palju alternatiive, mis teevad elu isegi lihtsamaks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
