INSERT INTO core.text(id, content)
VALUES ('567acdd1-7ef6-459a-bdda-9635ec6ae158',
        'Paljud on harjunud suurte koguste riiete, toidu ja kõige muuga, kuid mõned ei saa sellest isegi unistada. Miks me siis raiskame seda nii palju? Miks me oma võimalusi ära kasutame? Milleks meil seda nii palju vaja on osta?\nTavaliselt ostetakse midagi, kui seda on vaja. Näiteks sa ostad süüa, sest sul on seda vaja elamiseks ja oma keha toitmiseks, riideid me ostame, sest me ei saa olla paljad. Milleks me siis seda ületarvitame, kui näiteks Aafrikas on nii palju lapsi kellele need asjad päriselt ka vajalikud on. Kui on raha üle, proovige see saata kuhugi kogumisfondidese, näiteks nende samade Aafrika laste jaoks. Neile oleks kasu sellest 10 eurost palju rohkem, kui sulle selle mõttetu asja peale, mida sul 2 nädala pärast pole vaja.\nPaljud ületarvitavad asjade ostmist, sest see toob hea tunde. Kõigile meeldib see tunne, kui sul on uus asi ja sa tahad sellega nii palju asju kanda ning juba unistad, kuidas sa selles kuhugi välja lähed, aga see on ainult momentaarne. Üks moment on sul hea olla, sest su organism töötab välja sellise aine nagu dopamiin, see on organismis leiduv hormoon, mis annab mõnutunnnet. Mõne aja pärast sa pole enam nii õnnelik selle 5 eurose topi pärast, mis sa ostsid kuskilt hiinast ning mõtled, miks sa selle üldse ostsid.\nAsju osta on vaja siis ,kui on vajadus, mitte siis kui tuli tuju. Dopamiin on hea asi, aga tekitab sõltuvust, mille pärast sa koguaeg tahad midagi juurde osta. Olge säästlikumad ning koguge raha või annetage see nendele, kellele seda on vaja rohkem kui teil.');
