INSERT INTO core.text(id, content)
VALUES ('357a1ea5-7a27-4548-97d1-fa39a85fc2ee',
        'Riided on vajalikud asjad meie igapäeva elus, kuna tänapäeval ei ole inimesed alasti nagu kiviajal. Riided ei tule ka niisama, nende jaoks on raha vaja ja vahest moe inimestel on rohkem vaja, aga seal on ka moodus kuidas odavamalt saada.\nTänapäeval on mitmeid interneti poode kust saab väga odavalt erinevaid riideid ja asju, näiteks nagu köögitarbeid ja laste mänguasju. Kõige rohkem ostetakse sealt riideid kõigest paari raha ühiku eest, kas siis euro või mõne muu. Tavaliselt need interneti poed asuvad Hiinas või mõnes muus siukses kohas. Seal tehtsakse ainult kvandideeti eest neid riideid, mitte kvaliteedi.\nKvandideediga tuleb ka kaasa kehv riide materjal, kuigi müüjaid seda ei huvita. Neid samu riideid pärast leiab ka taasukasutuskeskusdest või mõnest sangaarist, natuke kallimana ja veel halvemana. Osadel interneti poodidel on ka kuulujutud, et kasutatakse lapstööjõudu seal, kuna see on Hiina aga inimesi see ei huvita. Inimesi ei huvita ka enam riietuse kvalideet raha eest, sest mida rohkem siukse hinna eest osta neid riideid seda kehvemaks läheb su vaatepilt ka päriselt kvalideetsedest riiedest. \nMoeteadlased oskavad väga hästi sellest räägita ja oskan ka mina, et kui sulle meeldib kapi täis riideid, äkki peaksid hoopis ise alustama nende riiete tegemist. Ise riiete tegemine läheb odavamalt ja saad hea kvalideedi eest ka neid.');
