INSERT INTO core.text(id, content)
VALUES ('d6a4c392-b4b8-4428-8359-771acf428072',
        'Öeldakse, et iga inimene tarbib erinevalt kuid täpselt nii ongi. Mõned inimesed on rohkem haritud ja teadlikumad mis on kahjulik ja mis ei ole. Tänapäeval on suurem probleem ka kiirmood ja  koguaeg tuleb kaupa peale, see on väga kahjulik ja saasturikas meie planeedile ja läheduses olevale keskkonnale. Koguaeg püütakse seda parandada ja, et üha parem oleks teiseringi poes käimine, mis on palju jätkusuutlikum ja odavam. Minul on väga kehvad tarbimisharjumused aga ainult riietega ja koguaeg nagu tahaks juurde osta asju. See ei ole sugugi hea harjumus ja peaksin seda kindlasti muutma ja rohkem taaskasutatuid riideid ostma. Olen tähele pannud küll, et teise ringi ooted ja riided koguvad ainult populaarsust. Mina alati puhastan ja sorteerin ena asju mida mul müüki oleks panna, mis väikseks jäänud või ei sobi enam. Mu pere samuti tarbib tegelikult väga hästi ja ei kuhja koju mõtetuid asju mis tegelikult on prügi. Siiski arvan, et see tarbimine tulebki sellest kui suur su silmaring on ja milliste inimestega sa suhtled, muidugi tuleb see kõik ka sotsiaalmeediast, et ma peaksin justkui millegi kohe soetama mida reklaamitakse või mis justkui populaarne on kuid nii pole kõik on selleks, et mingil viisil raha saada inimestelt ning, et ettevõttel või firmal oleks hea sissetulek pidevalt.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('d6a4c392-b4b8-4428-8359-771acf428072', 'title', 'Inimeste tarbimisharjumused');
