INSERT INTO core.text(id, content)
VALUES ('eef044d3-955c-43c4-b6d8-411f85a1394b',
        'Meil kõigil on tarbimisharjumused. Arvatakse, et toit ei saa kunagi otsa. Samuti on riided meeletult palju üle.\nMeile kõigile meeldib süüa. Seepärast käivad inimesed kord nädalas vähemalt ühe korra toitu ostmas. Toitu ostes, arvame, et sööme kõik selle ära. Kuigi siiski jääb söök seisma või tähtaeg oli varasem kui arvati. Tegelikult ei peaks toitu ära viskama tähtaja pärast, vaid peaks vaatama, kas toit veel kõlbab. Eestis visatakse keskmiselt aastas ära 61 kg toidujäätmeid. Toidu ülejäämisel läheb raisku vesi, energia ja tööjõud. \nTeiseks probleemiks on riiete ülejäämine. Inimesed ostavad endale aeg-ajalt uusi riideid. Vanad riided visatakse lihtsalt ära. Mõned annavad või proovivad ära müüa, aga teised arvavad, et see nõuab liiga palju vaeva. Eve Hansoni arvates on oluline, et me eelistaks kvaliteeti kvantiteedi üle. Inimesed ei tohiks osta riided, et neid ühe korra kanda ja siis ära visata. Samuti oleks parem mitte osta odavalt Hiina veebipoodidest või sooduskampaania õnge minna.\nInimesed võiksid osta pigem vähem, kui rohkem ja raisata. See hoiaks tööjõudu kokku ja hoiaks maailma puhtamana. Harjumusi ei saa muuta ühe päevaga, vaid peab ise vaevanägema ja vaikselt paremuse poole liikuma.');
