INSERT INTO core.text(id, content)
VALUES ('e8df38a0-6b53-4f4d-8866-fbf0769d141c',
        'Väga paljudel inimestel on erinevad tarbimisharjumused ning enamus harjumustega kaasnevad ka negatiivsed küljed, mis võivad tekitada probleeme. Väga suur osa asjade tarbimise juures ning igasuguste harjumuste juures on asjade raiskamine, ostmine liiga palju asju kuigi pole vaja, ära viskamine ja muu sarnane.\nPõhiline ning ühtlasi ka kõige suurem probleem harjumuste juures on erinevad harjumused toiduga. Tihtipeale visatakse toitu ära, kui enam seda ei taha või kui toit on halvaks läinud. Toidujäätmeid tekib ühe inimese kohta aastas umbes 26kg, mis on üpriski palju. Inimesed arvavad, et see on normaalne toitu ära visata ning see on kujunenud tarbimisharjumuseks, kuid tegelikult on tegu väga suure hulga toidu raiskamisega. \nVeidi väiksem probleem on riiete ära viskamine ja nende raisamine. Sageli viskavad inimesed oma riided ära, kui need on näiteks väikseks jäänud või kuskilt veidi katki läinud. Ka see on lihsalt juba kujunenud harjumuseks. Mille üle inimesed ei mõtle on, et neid väikseks jäänud riideid saaks ju kasutada keegi teine või saaks selle väikse augu riietuses ära parandada. \nErinevate harjumuste kõrvaldamiseks võiks läbi mõelda kas ja kuidas on see kahjulik meie ühiskonnale ning mida teha, et halbadest tarbimisharjumustest lahti saada. Kõik korralikumad toidujäägid saab ka võib olla kuhugi annetada, kus neist midagi muud valmistatakse. Väikseks jäänud riided saab viia taaskasutuspoodi- või kasti, kust keegi teine saab endale uued riided. On olemas igasuguseid võimalusi.\nTarbimisharjumuste parandamiseks peavad inimesed ennast kokku võtma ning tahtma muuta meie ühiskonda paremaks, muutes oma harjumusi. Peavad õppima taaskasutama ning rohkem mõtlema mida nende ära viskamis harjumused võivad teha ühiskonnale. Kõik peaksid õppima mõistlikult asju tarbima.');
INSERT INTO core.text_property(text_id, property_name, property_value)
