INSERT INTO core.text(id, content)
VALUES ('aaa240b1-46d5-48da-9994-597388d1f0e7',
        'Maailmas raisatakse palju toitu, mis on loodusele ja inimestele halb. Paljud inimesed viskavad toidu ära mida nad enam ei söö või mis on üle jäänud. Enamus inimesi arvavad, et see ei tee kellegile halba, aga maailmas on inimesi kes ei saagi iga päev süüa.\nMe saaksime seda parandada sellega, et toiduained mida me ei kasuta kuskile annetada, nii on suur võimalus, et see toit ei lähe raisku ja jõuab kasutusele ning headesse kätesse. Toidu raiskamine ja ära viskamine teeb ka meie loodusele väga suurt kahju. Näiteks toiduaineid mida põlldudel kasvatatakse, neid tuleb veega kasta, kaitsta keemiliste ainetega mis teeb loodusele halba. Tööstusdes kus töödeldakse toiduaineid seal kasutatakse kas elektrit või kütust.\nKui me toiduaineid raiskame siis me põhimõttselt raiskame ka palju teisi asju nagu näiteks vesi,vääetised, elekter või kütus ja inimeste tööjõudu. Ja kui me neid koguaeg järjest raiskame siis mõni hetk pole meil võibolla neid asju enam saadaval mis mõjutab iga inimese elu. Ja tänu sellele võib inimkond välja surra.\nToidu raiskamine on maailmas suur probleem mis mõjutab iga inimese elu. Iga inimene peaks proovima toidu raiskamist vähendada, sest meil ei pruugi kunagi selliseid toidu saamis võimalusi enam olla. Kui iga inimene suudaks seda vähendada oleks keskonna seisund palju parem.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('aaa240b1-46d5-48da-9994-597388d1f0e7', 'title', 'Toidu raiskamine');
