INSERT INTO core.text(id, content)
VALUES ('3fb8ea0c-a26c-4ed9-b1fa-18b077b3a1a4',
        'Mäletan vaheaja lõppu, mil olin vanavanemate juures maal. Vanaisa hakkas puid tegema ja seetõttu otsustas vanaema kutsuda abiväge. Ilmselt oli memmel hirm eelmisest korrast, kui peale puudetegu oli ta kaks päeva jalutu – tervis läbi mis läbi. Vanaisalgi oli mõnda aega toss väljas. Niisiis kutsusgi vanaema appi tuttavad, vanad sõbrad ja sugulased.\nMoodsate elektriautodega seoses leiab üpris sageli aset vestlus, et kas tõesti on võimalik päästa maailm, kui jätta fosiilkütused minevikku. Minu peres on nüüd kaks elektriautot, mistõttu on mul hea võrdlusmoment. Esimene asi, mille alati taolisest vestlustes väja toon, on müravaba liiklemine. Tavaliste autode müra on niigi härirv, kuid selletõttu hukkuvad või saavad viga jalakäiad, kes kõrvaklappidega end olmemürast ära lõikavad. Elektrisõidukil puuduvad samuti heitgaasid. „Heitgaase pole, müra pole, aga mida see ikka suurespildis muudab,“ saan üpris tihti vastuseks.\n„Tarbitoitutargalt.ee“ veebisaidil ühe artikli autor arvab, et iga väike tegu mõjutab ühis- ja keskkonda suures pildis vägagi. Piim läheb külmkapis halvaks, see visatakse ära ja juba unustatud. Kuid just kodumajapidamised moodustavad pea poole kogu raistaud toidust. Kerkib esile probleem: inimestel puudub ülevaade, mida ja kuidas nad oma valikutega mõjutavad. \nÕnneks soovib teadlikkust tõsta nii riik, kui tema enda kodanikud, et luua parem homne. Kurba pilti, kus kvantiteet ületab kvaliteeti, kogeb ka moedisainer Eve Hanson. Eve leiab, et lahendus oleks korraldada ekskursioone taaskasutuspoodide ladudesse – nii saavad noored selge pildi, milline on olukord päriselt. Loodetatavasti saavd nad sealt võtta kaasa mõtteid, millega muuta enda tarbmist ja elustiili. \nFüüsilise tööga end ülekoormanud vanaema tunneb veel mitu päeva, et tegi endale liiga. Kuid sõites sisepõlemismootoriga autoga, visates ära halvaks läinud toidu või ostes odavat hiinakapua, on palju raskem mõista, kuidas see mõjutab keskkonda. Teadlikkust saab kasvatada vaid haridusega. Võib küll tüütu ja närvesööv õppida eesti keelt ja kirjutada täna seda kirjandit, kuid näitkes kirjandi alustekst oli just see, mis pani mind täna mõtlema, kuidas enda tarbimisharjumusi veelgi muuta. Loodan, et see pani mõtlema ka teisi klassikaaslasi, sest igaühe panus loeb – sõprade abiga saime puudki maha lõigatud ning vanaema tundis end järgmisel päeval hästi.');
