INSERT INTO core.text(id, content)
VALUES ('f885573d-ddf4-4dea-a7e9-e0e547287812',
        'Iga päev on inimestel vajadus ja tahmine midagi osta. Kas tegu on just vajaliku ja läbimõeldud ostuga? Asjade saadavuses pole enam küsimust.\nJärjest rohkem arendatakse ja rajatakse internetipoode ja keskkondi, kus ostelda. Enam ei pea vaeva nägema ja palju aega kulutama, et midagi osta. Kõik on palju lihtsam kui vanasti. Internetis osteldes on tooted kohati ka odavamad, kuna ei ole vaka palgata müüjat, kes poodi üleval peaks. Vanasti kui kaupade kättesaadavus oli kesine, ei teinud keegi mõtlematuid oste, sest poeskäiku oli olaneeritud vähemalt nädalajagu. Osteti ainult vajalikku kraami: toitu, matejali millest kehakatet teha ja majatarbeid. Lisaks arvestati rahaga ja selle järgi otsustati asjade tarvidus. \nNüüdisajal näeme, et asjade soetamise tõsidus on kardinaalselt muutunud. Eesti kodudes jääb iga aasta umbes 61 kg toitu üle. Poelettidel on alatasa uus kraam, mis annab ostelejale ideid juurde ning sunnib ostma. Riidepoed teevad oma kaubale lõpmatult palju reklaami, mida me iga päev tarbime ning näeme. Kogu aeg tuleb uut informatsiooni toodete kohta. Olgu siis tegu riiete, toidu või muu müüdavaga. \nOstlemisest on saanud ajaveetmise viis ja hobi ning see võib kohati ka elukutsena esineda. Ühiskondlikult arvatakse, et see on midagi mis paneb silma paistma. Loomulikult on sellest teadlikud ka poed ja tootjad, kes on tänu sellisele liikumisele läinud üle kvantiteedi eelistamisele kvaliteedile. Kvaliteedist ei hoolita, sest kollektsioone uuendatakse pidevalt ning järjekindlalt. \nKahjuks on praeguse ajastu tarbimine paigast ära, kuna inimesed on sattunud surnud ringi, kust on väga rske kõrvale astuda. Ahvatlused tulevad uksest ja aknast sisse ja käivad suult suule. Toodangut suurendatakse, sest nõudlus kasvab ja vastupidi. Arvamus, et väikesed muutused pole olulised, viib meid ühiskonnana üha sügavamale mõtlematu tarbimise auku.');
