INSERT INTO core.text(id, content)
VALUES ('d8ad2eaf-f1ca-4073-a20c-bf65e355efdb',
        'Toitu raisatakse ühes aastas väga palju. Isegi väike toidu ära viskamine tekitab maale kahju. Miks visatakse üldse nii palju toitu ära?\nNagu juba öeldud sai, et väikse toidu ära viskamine tekitab maale palju kahju. Tegelikult mõjutab toidu ära viskamine enda raha, vett, energiat ja tööjõudu. Toitu visatakse ära, sest mõned inimesed lihtsalt saavad lubada endale seda, toit läheb üle säilitusaja, või inimestele lihtsalt ei maitsa söök mida nad endale teevad. Uue toidu tootmine tekitab keskkonnakoormuse, sest põldudele pritsitakse erinevaid kemikaale ja väetist, et saak kiiremini kasvaks ja maitseks paremini. Mida peaksid inimesed tegema, et mitte raisata nii palju toitu?\nMuidugi ei saa inimesed kõike kohe muuta, vaid see on pikaajaline protsess. Et ültse midagi muuta võiksid inimesed poes vaadata, mida nad endale järgmisteks päevadeks tahavad. Kindlasti vaadata toidu kuupäaeva, et sa teaks kaua saab säilitada seda. Kui võtta midagi mille säilitusaeg hakkab lõppema, siis teha see kindlasti kohe ära, sest muidu võib selle ära unustada ja siis tuleb jälle toitu ära visata. Tuleb jälgida, mida ostad poest, sest sellega säästad raha ning ei lähe nii palju toitu raisku. Kui kõik inimesed seda jälgiksid teeksid nad maailma paremaks.\nKokkuvõttes peaksid inimesed hoolima meie planeedist ja mitte tootma nii suurt toidukadu. Kindlasti ei ole võimalik toitu üldse raisata, aga siiski tuleb toidu ära viskamise eest rohkem hoolt kanda.');
