INSERT INTO core.text(id, content)
VALUES ('7aec2cf1-736d-43c0-ace1-6871fa26d6cc',
        'Inimestel on palju erinevad harjumisi ja suur osa nendest on halvad nii keskkonnale kui ka neile. Kõige tavalisemad olukorrad on seotud toidu raiskamisega ja suures koguses riideesemete ostmine. Miks on siiski oluline, et inimesed vähendaksid oma halbu harjumisi ja suunaksid ennast paremate otsusteni?\nSuur osa rahvast ostab toitu kokku, kuna nad arvavad, et terve nädala jooksul ei pea rohkem poes käima ja toit säilib. Mõned ostavad ka toitu kokku sellepärast, et see on allahinnatud ja hiljem see enam pole. Teades, et neile isegi ei maitse see või ei kasuta seda õigeks ajaks ära ning lihtsalt seisab edasi nädalaid kapis, kuni toit visatakse ära. See raiskab raha ja resursse. Säästlikum oleks osta toitu, mida sa päriselt kasutad ära mitte ainult sellepärast, et see on allahinnatud. Toit, mis hakkab halvaks minema, sellest on võimalik valmistada mingeid muid toite või viia komposti, et ei läheks raisku.\nOlukord on sama riietega. Hiinapoodidest kiputakse tellima suures koguses riideid või muid mõtetuid asju, mida hiljem ei kasutata ja visatakse seejärel ära. Sellistest poodidest saadavad riided on halva kvaliteediga ning selle tõttu need ongi odavad, et panna inimesi neid suurtes koguses ostma arvates, et need on head riided. Trendid mõjutavad inimesi ostma praegu moes asju, et käia kaasas kuigi nad ei mõtle läbi, kas nad kannaksid seda riiet ka 5 aasta pärast või ainult praegu ning siis visatakse ära, sest see on katki läinud või lihtsalt enam ei meeldi. Moedisainer Eve Hanson on öelnud „ Eelistada võiks kodumaised oma lähedal toodetud asju ning pigem vähem kui rohkem“ Mitte kellegil pole vajalik osta suures koguses riided, see on raha raisk ja keskkonnale halvasti mõjuv\nSiiski võiksid olla inimesed teadlikud, kui suur mõju on keskkonnale toidu raiskamine ja riiete äraviskamine. Sellepärast peabki järgnevalt inimesi teavitama ja hoitama, mis võib saada maailmast, kui nad ei suuna end heade otsuste juurde, et ühiskonnal oleks parem ja ka neil teades, et nad teevad õigeid otsuseid.');
