INSERT INTO core.text(id, content)
VALUES ('e6586ac2-e0b7-4e2d-b8e7-54e79c40f52b',
        'Tänapäaeval on Inimesed jäänud palju mugavamaks kui vanadel aegadel.Kui vanasti ei olnud asju nii kergelt saada, siis on maailm teinud selle palju kergemaks argipäaeval. Sellest on tulnud suur harjumus üle ostmisega.\nKui minna poodi, võiks sul olla nimekiri, mille juurde sa ostmisega ka jääd.Et sa ei pöördu ebavajalikke asju ostma.Olen ise näinud palju kuidas poodide pakkendid nin soodustused võivad inimesi petta.Tulemusel ostavad inimesed väga suure ebavajalikku koguse toitu, mida nad ise enne tähtkuupäeva ära ei tarbi. .Nagu alustekstis oli välja toodud:“Kodumajapidamises tekkib iga Eesti inimese kohta aastas keskmiselt 61kg toidujäätmeid, millest toidukadu moodustab 42%  ehk 26kg.“Selle harjumuse väljaharjutamiseks soovitaksin ma osta nädala kauba ette, ning planeerida oma toidu tarbimine nädalas.Sellist lahendust on ka meie pere proovinud, ning toidu ära viskamine on meil kordades vähenenud.\nSuureks harjumuseks tänapäaeval on ka riiete üle ostmine. Inimesed lähevad Hiina odavate hindadega alla, ning tellivad suures koguses riideid, mida ei kanta väga kaua halva kvalideedi või mõe edasi mineku pärast. Välismaalt ostmine suurendab transpordi vajalikkuse mis on keskkonnale halb saastuse pärast. Selle probleemi lahenduseks ütles Eve Hanson:“Eelistada võiks kodumaiseid omalähedal asju ning pigem vähem, kui rohkem.“Riideid mida inimene enam ei kasuta andakse ära taaskasutusse. Tänu sellele jääb suure koguse riideid üle ja neid peab hakkama hävitama kuna ei osteta ära. \nArvan, et neid probleeme on võimalik lahendada, kui rohkem arv inimesi prooviks. Igast asjast on võimalik välja harjutada, kuna need on algselt sisseharjutatud. Meie põlvkonna käes on meile tulevik, ning ei oleks väga kohane kui meie planeet ülekoormatakse selle tõttu ,et inimesed ei suutnud oma ebavajalikest harjumusdest end peatada.');
