INSERT INTO core.text(id, content)
VALUES ('6f219e07-6a81-4de0-b85f-d37928b9a8a5',
        'Teada on, et toiduainete ja riiete materjalide raiskamine on tänapäeval üpris normaliseeritud. Annetamise asemel põletatakse riideid mida enam ei kanta ja visatakse ära ‘üleliigsed’ toidud ja toiduained. See harjumus võib tekitada mitte ainult meie maailmale liiga, aga ka vähem-rikastele inimestele antud asjadest puudust. Selline konstantne raiskamine võib lõppeda sellega, et varsti ei olegi vilja ega piisavalt toitained järgi, mida toota.\nKiir-moe riided mida Hiinast tellitakse, ei ole kvaliteetsed ning on täis kemikaale ja allergia-tekitavaid materjale. On olemas taaskasutuspoed kus leidub üha paremaid riided, selle mõttega, et need on kvaliteetsemad nii hinna kui ka materjali poolest. Tuhandeid riideid ja rõivaid läheb igapäev ainuklt rohkem raisku, kuna inimesed eelistavad midagi uut ja säravat selle asemel, et säästa nii raha kui ka rõiva materjale ostes taaskasutatud kaupa. \nToiduga seoses on sama moodi kiir-toit, mida inimesed eelistavad päris roa üle. Aastas kulub Eesti kodanikul umbes 61kg toidujäätmeid, mis moodustab 42% toidukadu. Paljud inimesed viskavad ära toitu ainult paar päeva pärast kapist seimist ja aina ostavaid tooteid juurde, mis lõpuks lõppeb liigtarbimises ja liiasel toiduraiskamisel. \nMeile tundub, et inimestel on vaja õppida rohkem säästlikult elama, kuna kõik meie toidu- ja riide kauba tootmine sõltub meist endast. Mida rohkem inimesed raiskavad, seda vähem materjale on meil alles.');
