INSERT INTO core.text(id, content)
VALUES ('ece17fd8-49d1-4754-80f7-e31279a1a467',
        'Toidukadu kui toidu raiskamine on üks tänapäeva suurematest suuresti sõnastamata probleemidest. Isegi inimesed kes väga ei raiska toitu, kas ei mõtle selle peale, või ei arva, et see probleem on. Aga see ei ole sugugi tõene ja kirjandi raames kirjeldan seda probleemi oma seisukohalt.\nKõige kergemini sõnastatav, ja juba alus nimetatud, näide on nii öelda oma käe läbi raiskamine, mis ongi see kui inimene ise raiskab toitu, visates ära ülejäägi või lausa toidu enda. Alustekstis toodi juba välja kuidas tavalises majapidamises visatakse aastas ära 61 kilogrammi toidujäätmeid! Ja kuigi see on juba võrreldav keskmise inimese kaaluga, ei ole arvestatud ka seda kui keegi käib sõbra või perekonna liikme juures külas, ning nagu mina enda elust näiteks toon, koolis. Koolides ei ole antud toit otseselt lapse enda oma ja on isegi eraldi prügikastid igas kooli sööklas olemas, selleks et laps saaks enda toidu sinna ära visata. Ja muidugi, laps seda teebki.\nKuigi inimesed raiskavad oma toitu juba oma käe läbi,  on ka üks faktor mille kohta inimesed teemaga seoses eriti ei mõtle ja isegi kirjandi alustekstis ei ole seda mainitud. Antud faktoriks on restoranid ja kiirtoidukohad. Nimetatud ja laadsetes kohtades, eriti kiirtoidukohtades, on suureks probleemiks toidu ülejääk. Teema arenduse ja parema seletamis võimaluse jaoks toon põhinäiteks kiirtoidu. Kiirtoidu üks tähtsamaid, kui mitte kõige tähtsam osa on kättesaadavus ja selle alla kuuluv kiirus, nagu nimes välja toodud. Sellel eesmärgil on põhilised toiduained juba enne ostmist valmistatud ja müügivalmiks tehtud, aga kui mõndasid toite ei osteta, nagu võib ettearvata, visatakse see ära. Inimesed ei mõtle selle peale, ja üsna tõenaoliselt ei näe ka seda. Filmides aga, kuigi need ei pruugi olla eriti potentsed näited, on seda näidatud ning kõige rohkem sõõrikutega, kus on näha, kuidas lihtsalt visatakse neid prügikoti suuruste kilekottidega suurtes kogustes prügikasti. Inimesed selle peale aga ei mõtle, ja ei arva, et see neile kuidagi probleem on. \nSellisel viisil raiskamist mina endale ei luba, ja kuigi ei aita see kahjuks olukorda, ei käi mina ka kiirtoidukohtades einetamas. Kuigi minu enda tegevused üksinda selle vastu ei aita, võiks ka teised mõelda sellele probleemile ja teha samme selle peatamiseks, mitte ainult ennast kontrollides, vaid ka teisi jälgides.');
