INSERT INTO core.text(id, content)
VALUES ('22962fe0-3ffd-4c96-852c-8449efe037f1',
        'Inimesed raiskavad üpriski palju toitu ja häid riideid. Taaskasutuspoed on ebappopulaarsed, ning tihtipeale eelistavad inimesed tellida oma riided välismaalt. Probleeme on nende teemade kohta palju, aga tuleb ka teemale peale vaadata tarbijate perspektiivis.\nToidu raiskamine on tõesti suur ja tähtis teema. Selle kõige põhjuseks võib täitsa vabalt olla: liiga suure koguse söögi tegemine, külmkapi täiesti täis ostmine, ja eelmiste päeavade ülejääkide ära viskamine. Lisaks kõigele kulutavad toitu ka ettevõtted, restoranides ülejäänud toit visatakse ära, samamoodi ka näiteks kohvikutes. \nToidu rohket raiskamist saab vältida. Näiteks tuleb jälgida söögi kogust selle tegemisel, et ei jääks liiga palju üle. Kui aga jääb üle, saab selle alati järgmise päeava lõunaks süüa ja ka näiteks liha saab järgmise päeva õhtusöögi siise lisada. Kui toitu on külmkapis rohkem kui seda süüa suudetakse, siis läheb osa sellest ilmselgelt halvaks, seejärel tuleks meil jälgida, et ku palju me toitu tarbime ja selle järeldusel osta seda nii palju kui meil seda vaja on, lisaks on alati parem osta liiga vähe, kui liiga palju, sest siis saab alati seda juurde osta.\nRiiete raiskamine on ka tähtis teema. Selle vältimiseks saab näiteks anda oma vanu riideid oma nooremale või väiksemale pereliikmele või sõbrale. Lisaks võiks vähemalt vaadata ja proovida, et äkki on taaskasutuspoodides häid riideid hea hinnaga. Mõned taaskasutuspoed teevad ka 1 euro päevi, kus on enamus tooted ainult 1 euro. Nagu ka Hanson ütles, et tuleks eelistada kohalikke poode üle hiina kaubanduskeskuste.\nRiiete ja toidu kulutamisele loogiliselt mõeldes kunagi lõppu ei saa, kuid seda saab suuresti vähendada. Toidu säästmine on ka raha säästmine, ja kõik mida selleks teha on vaja on jälgida koguseid. Täpselt samamoodi on ka riiete säästmisega, see sääastab ka raha. Riideid saab odavamalt taaskasutuspoodidest ja seal võib alati olla kalleid brändi tooteid väga odava hinnaga.');
