INSERT INTO core.text(id, content)
VALUES ('8fdc43ba-4032-4f9c-b63b-5d704316543c',
        'Inimesed võivad mõelda, kui natukene toitu ära visatakse või kasutamata riided viia taaskasutuskeskustesse, ei ole see raiskamine. Kas inimesed teavad, kui palju tegelikult raisatakse ning kas nad muudaksid siis oma tarbimisharjumusi?\nToidu ja riiete raiskamine on tänapäeval suur teema. Ei saada aru. kui palju tegelikult aastas toitu või riideid ära visatakse. Paljud inimesed kuulevad sellest, saavad aru ning tegutsevad. Näiteks loetakse internetist, raamatutest, ajalehtedest, kuuldakse raadiost või tuttavatelt. Minu pere on hakanud ostma vähem toitu ja riideid. Kui toitu üle jääb või läheb halvaks, viskame komposti. Komposti kasutame taimede väetamiseks. Riideid ostame siis kui tõesti vaja. Mina ostan suurema osa oma riietest taaskasutuskeskustest. Teades, et Eestis tekib aastas iga inimese kohta umbes 61 kg toidujäätmeid, hakkaksid nad oma toidutarbimisharjumuste üle mõtlema.\nIkka veel on olemas kiirmood. Koguaeg valmistatakse uusi ja ,,moodsamaid“ riideid ning neid ostetakse iga kord. Uute riiete kiirem ja mahukam valmistamine tähendab kvaliteedi langemist. Need lähevad kiiresti katki. Pärast katki minemist viskavad paljud riided ära, kuigi oleks võimalik parandada. Näiteks kui minul või mu vendadel riided rebenevad või tulevad augud, parandame meie ise või ema need ära.\nÜletarbimine on suur probleem tänapäeva ühiskonnas. Seda oleks võimalik vähendada, kui inimesed oleksid sellest teadlikumad. Riiete parandamine ning paraja portsu söögi võtmine on väga olulised oskused, mida igal inimesel vaja on.');
INSERT INTO core.text_property(text_id, property_name, property_value)
