INSERT INTO core.text(id, content)
VALUES ('af7920cd-d370-45d7-ba5e-c4df263ed8aa',
        'Inimeste tarbimisharjumused reostavad kohutavalt palju keskkonda. Looduse heaolu mõjutab otseselt elu Maa peal. Mina usun, et rahvas soovib parimat planeedile, kuid on liiga laisad, ei tea kui tõsine olukord päriselt on või ei huvi ta see neid nii kaua kui saavad rikkaks.\nInimesed ei taha oma mugavustsoonist välja tulla. Kui elu on lihtne miks peaks keegi soovima seda muuta. niimoodi mõtleb ilmselt enamus rahvast. Meie, kui inimkond, ei keskendu tuleviku peale, vaid oleme kinni olevikus ja selle võlus. Praegu on elu lihtne, toit on laual, kui tahta saab reisida ja kool on laiadaselt tasuta. Kahjuks pole ajaloo jooksul midagi head sündinud sellest, kui mugavustsoonis istuda. Kõik impeeriumid tekkisid tänu sellele, et keegi otsustas parema elu poole pürgida. Inimesed ei soovi oma praegust olukorda muuta, ning ei mõtle selle peale mis võib tulevikus juhtuda ja selle pärast ei taha nad oma tarbimidharjumisi muuta.\nRahvas ei tea kui tõsine seis päriselt on. Tsiteerides Eve Hansoni „Ma arvan, et peaks hakkama noortele tegema ekskursioone taaskasutuspoodide lattu, et näidata, milline raiskamine tegelikult toiumub“. Kui inimesed oleks teadlikud kui kehv situatsioon praegu on ei peaks sellisid väljasõite tegema ja sellega tegeletaks rohkem. Tõsi on aga see, et tõde vaigitakse maha, et rohkem raha teenida. Rahvas ei saa olla probleemi vastu, kui nad ei tea, et mure eksisteerib. Eraisikud pole informeeritud olukorra tõsidusest ja seepärast ei muuda oma tarbimisharjumisi.\nInimesi ei huvita keskkond nii kaua, kui see toob neile rohkem kasu kui kahju. Rikkurid on tihti nii eraldatud ühiskonnast, et nad ei mõtle selle peale kas planeet jääb ellu või ei, neid huvitab kuiads rohkem raha teenida. Miljardärid on piisavalt suure rahakotiga, et lõpetada kliima probleemid, kuid nad ei hooli sellest, vaid nuputavad välja odavamaid viise kuidas midagi müüa. See viib rohkema mõtetutte asjade tootmiseni ja ostmiseni ja tarbimisharjumiste suuremaks toitmiseni. Inimesed ei hooli tagajärgedest teistele nii kaua kui nende elu paremaks muutub ja seetõttu ei muuda oma harjumusi.\nRahvas soovib tegelikult head, aga on liig laisad, vähe informeeritud või omakasupüüdlikud, et muutuda. Suurem osa inimestest oleks valmis natuke mugavust loovutama, kui nad teaksid mis tegelikult toimub. Kõik tahavad ellu jääda eriti kui selleks on vaja ainult vahetada oma tarbimisharjumisi.');
