INSERT INTO core.text(id, content)
VALUES ('f6fc0598-4808-4278-9edf-a360eb9fc221',
        'Juba ammusest ajast on olnud inimestel probleem ületarbimisega. See suureneb iga päevaga rohkelt ja enamik ühiskonnast ei saa aru, kui tähtsad on nende tarbimisharjused loodusele ja neile endile. Pean tunnistama, et minagi peaksin vähem poes käima.\nLoodus on saanud palju kahju inimeste käitumise ja hoolituse pärast. Nagu artikliski oli ette toodud, raiskab iga isik suurtes kogustes toitu iga aasta. 61 kg ei tundu nagu suur kogus, aga mõeldes selle peale, et Eestis elab üle 1.3 miljoni inimese on see hunnik, mis tekib, hiiglaslik. Taimse toidu kasvatamiseks on vaja põlde, mida tuleb mürgiste väetistega kasta. Liha ja piimatoodete saamiseks tapetakse ja piinatakse suurtes kogustes loomi. Kui vähendaks inimeste tarbimist ja arendaks teadlikkust, kahaneks toidujäätmete arv. \nInimkond on harjunud ostma kõike, mida korragi soovivad, selle peale korralikult mõtlemata. Kõik, kes kasutavad sotsiaalmeediat, on näinud kedagi kunagi näitamas oma poeskäigu saake. Tulevad ette suurte kastide riietega ja räägivad, kuidas vaatajal on kõiki neid samu asju vaja. Tegelikult teavad suunamudijad väga hästi, et kannavad ostetuid asju paar korda, siis viskavad prügikasti või heal juhul viivad taaskasutuspoodi. Sellega on tekkinud paljudel noortel ja ka vanematel tunne, et peavad raha raiskama ja poest jälle uue moetrendi riietusi ja ehteid ostma. Oleks kasulikum võtta sõber kaasa, minna taaskasutuspoodi ja leida endale midagi, mis näitab, milline su iseloom on.\nLoodus ja inimkond on saanud palju kahjustada meie enda otsuste pärast. Peaks vähendama tarbimist ja õpetama koolides, töökohtades jne., mis on üleliigse ostmise kahjud. Sotsiaalmeedia õpetab kahjuks tihti vastupidist. Poes käies tuleb olla teadlikum ja mõelda, mida on tõsiselt vaja.');
