INSERT INTO core.text(id, content)
VALUES ('9c40a641-3349-4e55-abfc-63b107c581b2',
        'Eestis ja ka mujal maailmas on toidu ja riiete ületarbinime ja raiskamine suur probleem. Millest tuleneb toidu ja riiete raiskamine?\nToidu ja rõivaste raiskamine on, kui ostetakse rohkem kui vaja ja osa ostetud kaubast läheb otse või varsti prügikasti, seda korralikult tarbimata. Toodete ületarbimine võib tulla sellest, et ülehindame oma vajadust neile. Võime arvata, et pildid riietest näevad internetis väga head välja ja olla mõjutatud arvama, et suisa vajame neid. Tänapäeval on ka reklaam erksavärvilisem ja sooduskampaaniad pöörasemad kui kunagi varem, kuigi näiteks riiete kvaliteet võib olla küsitav. Sellele viitab ka moedisainer Eve Hanson: „Sinna viiakse korralikke riideid, aga ka selliseid, mis mingil kaunil reklaamfotol näevad ilusad välja, aga tegelikult koosnevad naftast ja sa ei taha seda rohkem kui üks kord kanda, sest kehal on halb olla selles.“ Reklaam, populaarsus ja odavad hinnad veenavad inimesi, eriti noori, ostma riideid kasvõi Hiinast. Kahjuks tuleb odav hind alati millegi arvelt.\nToidu raiskamine tuleb ilmselt samuti mingil määral reklaami mõjust ja vajaduse ülehindamisest, kuid sellel on ka teisi põhjuseid. Näiteks minu kodus läheb meil samuti toitu rasku, kuigi me ei vaata eriti reklaame. Enamasti läheb minu kodus toit rasku, sest unustame selle külmkapi tagumisse ossa ja avastame selle alles siis, kui toit on juba halvaks läinud. Toitu on raske teha sellises koguses, et seda ei jääks veidi üle. Pärast on sellist jääki liiga vähe, et seda tervele perele soojendama hakata ja nii see unarusse jääbki.\nEelnevatest näidetest võib teha järelduse, et riiete ületarbimise põhjused on reklaamist mõjutatud olemine ja vajaduse ülehindamine ning toidu raisku minemise põhjuseks võib olla lisaks samadele põhjustele ka toidu unustamine.');
