INSERT INTO core.text(id, content)
VALUES ('2ee4a84d-f438-494c-8f12-530d251c3e5a',
        'Inimesed on kõik väga erinevad,mõned tarbivad asju ühtemoodi teised teistmoodi. Kuidas ja mida nad siis tarbivad?\nIga inimene tarbib midagi,kas need on siis riided,toit või muud sellist. Inimesed ja nende tarbimisharjumused on kõik väga erinevad,aeg-ajalt võivad need isegi muutuda. Nagu näiteks toidu tarbimisharjumused. Minu vanaema oli alati selline,kui piim oli ühe päeva kauem seisnud kui peaks, siis viskas ta selle kohe ära. Aga nüüd ta enam seda ei tee.Alati kui piim on ühe päeva kauem seisnud kui peaks,siis koguaeg on ta teinud sellest häid ja maitsvaid pannkooke.\nKuigi,sa ei tarbi ainult toitu,vaid riideid ka.Igale inimestele meeldivad ilusad ja odavad riided, mida nad kanda saavad.Kas peaks ostma kallimaid,ehk kvaliteetsemaid riideid? \nNagu alustekstis oli toodud,et inimesed ei ostaks hiinast oma riideid,vaid eelistaks riideid mille kvaliteet oleks hea.Me teame,et hiina riiete kvaliteet pole just kui kõige parem.Need on tehtud odavast materjalist,mis ei kesta kaua ja reostab rohkem loodust.Kui aga ostaksid kvaliteetsemaid riideid,mis on tehtud kauakestvamast materjalist,siis väldid kiiret ära viskamist ja saad neid riidedi teistele edasi anda. Olen kuulnud veel sellistest harjumustest, et kantakse uusi jalanõusi, ja pärast ühte päeva  visatakse need kohe ära, seda teevad kuulsad ja rikkad räpparid.\nMina arvan et inimeste tarbimisharjumused on alati muutuvad.Pole vaja osta endale sodi kokku,vaid osta hea ja kvaliteetne riie,mis kestab kaua ja ei lähe kohe katki.Inimesed peaks aru saama,et nende tarbimisharjumused võivad väga palju loodust mõjutada.Inimesed peaksid asju mõistlikult tarbima.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('2ee4a84d-f438-494c-8f12-530d251c3e5a', 'title', 'Tarbimisharjumused');
