INSERT INTO core.text(id, content)
VALUES ('b1ea9079-6dbb-4cd5-b0dc-9442bbd25d53',
        'Tänapäeval on suureks probleemiks osutunud toidu ja riiete raiskamine. Inimesed viskavad ära asju, mida on veel võimalik kasutada või tarbida ning see on saanud neile harjumuseks. Kas selle vastu tuleks midagi ette võtta? \nInimesed raiskavad toitu liiga palju. Keskmiselt tekib ühe eestlase kohta 61 kg toidujäätmeid aastas, mida on kindlasti palju. Lisaks toidu raiskamisele, raiskab inimene ka oma raha. Et seda probleemi lahendada, tuleks kõigile meelde tuletada, kui vedanud neil üldse on, et saavad poest osta kvaliteetset toitu. Mõnes vaesemas riigis sellist luksust pole ja sellega on meil vedanud. Kui kõik mõtleksid selle peale siis äkki suudaks inimesed toidu raiskamist vähendada. Toidu raiskamine kindlasti ei kao kuhugi, aga kindlasti väheneks, kui sellega midagi ette võtta.\nLisaks toidu raiskamisele on ka veel riiete raiskamine, kus inimesed viskavad ära riideid, mida on veel võimalik kasutada. Inimesed tellivad väga suure osa oma riietest kusagilt välismaalt. Selle peale ütleb Eve Hanson: „Eelistada võiks kodumaiseid oma lähedal toodetud asju ning pigem vähem kui rohkem,“ kes on moedisainer ja tunneb seda teemat hästi. Tema arvates peaks hakkama noortele tegema ekskursioone taaskasutuspoodide lattu, et näidata, kui palju riideid raisatakse. See oleks väga hea viis kuidas seda raiskamist vähendada.\nRiiete ja toidu raiskamine on väga rumal. Esiteks kaotab inimene raha, teiseks on see loodusele kahjulik ning kolmandaks lähevad raisku muud ressursid näiteks nagu tööjõud ja energia. Sellel raiskamisel on veel palju halbi külgi, aga need on just kõige tähtsamad. Kokkuvõtteks tuleks toitu ja riideid vähem raisata, sest see on inimesele endale kui ka loodusele kasulikum.');
INSERT INTO core.text_property(text_id, property_name, property_value)
