INSERT INTO core.text(id, content)
VALUES ('7d7e5c48-8a20-4361-9192-9b492647a8c6',
        'Tänapaeval on palju inimesi, kes raiskavad lihtsalt toitu. Arvatakse, et toit tuleb meile iseenesest, aga tegelikult on vaeva näinud väga paljud inimesed. Seda ei osata hinnata. Miks raisatakse toitu tänapäeval nii palju?\n Ma olen märganud, et ka mina raiskan ikkagi mingil määral toitu. Näiteks mulle meeldivad meeldivad igasugused puu- ja köögiviljad. Kui neid on kodus siis mul kipub algul meelest ära, et neid võiks süüa või pole kuskile toidu sisse panna. Siis avastan, et neil on juba plekid peal ja natuke hallitus kohti ka tekkimas ning siis tuleb need ära visata. Õnneks on meil kanad,siis saavad nemad vähemalt süüa. Tegelikult võiksin neid kiiremini ära süüa, sest nende korjamiseks ja Eeestisse toomiseks on palju vaeva nähtud.\n  Lugesin ühte lõiku internetist toidukaosest seal oli kirjas sellest, et võtame toitu liiga enesestmõistetavana. Arvame, et toit ei saa kunagi otsa, aga tegelikult ei ole see nii. Iga inimese väike samm aitab väga palju kaasa. Peaksime ka väärtustama seda, et tuhanded inimesed on vaeva näinud nende kasvatamisega, kui ka hooldamise ja transpordi eest. Me oleme liiga enesekesksed ja arvame, et see on ju lihtsalt toit ja seda on kõigil. Asjad pole hoopis nii. Mitte kõigil pole toitu ja veel vähem, et seda saaks raisata.\nToidu raiskamine on tulnud sellest, et me arvame see tuleb meile lihtsalt. Peaksime väärtustama seda, sest selleks on vaeva nähtud, et meie saaks värsket ja puhast toitu nautida.Iga ühe väike samm aitab palju.');
