INSERT INTO core.text(id, content)
VALUES ('0f7cff13-21ec-4475-8706-76378a88fea9',
        'Paljud inimesed ei hooli toidust üldse teevad mis tahavad sellega viskavad ära kui läheb halvaks või lihtsalt ei taha seda ,sest nad saavad endale seda lubada ,sest neil raha on millega seda juurde endale osta,aga nad võiksid teistele selle anda kellel pole raha et endale ise osta süüa.\n    Inimesed on väga palju raha saanud endale et viskavad kõik toitu vahendid ära kui neile need ei meeldi, aga nad võiksid kõik viia kuhugile asutusse kus jagatakse teiste inimeste vahele laiali kõik see toit, et teised inimesed saaksid midagi süüa või veel edasi jagada et saaksid kõik midagi head süüa. Ma ise olen ka teistele inimestele jaganud enda toitu kui näen et neil kõht väga tühi sest inimesi peab aitama.\n    Inimesed võiks hoolida oma külast oma linnast et ei tohi visata toitu aineid ära ega pügi maha, sest tekib 26 kg raisku läinud toitu mida oleks saanud teisele jagada laiali. Ma olen ise näinud kuidas keegi prügi maha viskab olen talle õelnud palun korista ära ja viska üigesse kohta see.\n    Inimesed võiks enda looduse eest ja enda küla või linna eest ärge visake toitu või prügi maha viige see õigesse asutusse kus tegeletakse sellega õigesti kas jagatakse laiali või viitakse õigesse kohta.');
