INSERT INTO core.text(id, content)
VALUES ('412ffbf4-bda2-454a-8ef9-29b1e1a32482',
        'Inimesed tarbivad toitu igapäevaselt ja ostavad seda pidevalt juurde kuid ei söö kõike ära. Tänapäeval on ka väga trendikas käia iga päev eri riietega, pärast paari kandmist aga visatakse need ära. \nTänapäeval on võimalus valida oma toitu ja paljudel ka võimalik pirtsutada, minu isa ütleb alati sellepeale, et tema vanaema poleks sellist käitumist kunagi lubanud. Palju toitu läheb raisku, eriti jõukamatel inimestel, kui meil oleks kratid nagu Andrus Kivirähki raamatus „Rehepapp“ siis ilmselt saadaksime kratid omale toitu varastama. Parem ikka kui see, et see lihtsalt raisku läheb. Kogu selle toidu tootmine ja hiljem lagundamine, suurendab tohutult meie jalajälge. Olen näinud telekast, et sellega ikka tegeletakse, näiteks on olemas toidupangad ja organisatsioonid, mis viivad toidu neile kellel on seda päriselt vaja.\nMood muutub iga päev, sellega kaasneb uute riiete tootmine, nende ostmine ja lõpuks vanade ära viskamine. Ostetakse rohkem kiirmoodi mis normaliseerib ka lapstööjõudu. Isiklikult ei osta ma kõiki oma riideid kaubanduskeskustest vaid käin kaltsukates, seal näen aga palju kiirmoodi mis tõestab fakti, et inimesed kannavad oma riideid vaid paar korda. \nInimesed võiksid osta toitu kogustes, mille nad suudavad ise ära süüa ja kui jääbki üle siis anda neile kellel on seda päriselt vaja. Riideid võiks inimesed võtta kui tarbeeset mitte seda mis neid omaarust paremaks inimeseks teeb.');
