INSERT INTO core.text(id, content)
VALUES ('fcfeeade-8bbe-4a93-8ecc-67255dcb98e1',
        '\nTänapäeval on väga palju raiskamist inimeste poolt. Suures koguses läheb toitu ja riiideid raisku. Miks inimesed ostavad rohkem kui kasutada suudavad? Riided mis on inimestel üle jäänud viiakse tavaliselt taaskasutusse, aga toit lihtsalt visatakse ära.\nTänapäeval on riiete ja toidu raiskamine palju suurem probleem kui see kunagi oli. Suuremosa riideid tänapäeval tulevad hiinast ja ei ole väga tervislikust materjalist tehtud kui kunagi. Eestis tehakse ka riideid, aga nende kogus on nii väike et hiina ületab ikka. Aga miks visatakse toit ära kui üle jäänud toidu saaks anda kuhugi loomadele söödaks, siis oleksid inimesed ja loomad õnnelikud kuna inimesed saavad oma jääkidest lahti ja loomad saavad maitsvat toitu. Ja riided lähevad tavaliselt taaskasutusse aga paljud ikka hävitatakse ära kuna ülejäänud riideid on lihtsalt liiga palju et nendega pole midagi teha. „taaskasutusse viiakse korralikke riideid,  aga ka selliseid , mis näevad ilusad välja, aga tegelikult koosnevad naftast ja sa ei taha seda rohkem kui üks kord kanda, sest kehal on halb olla selle sees.“selgitas Hanson.\nÜleliigsele toidule võiks ka olla taaskasutuskeskus, need toidud mis veel kõlbavad süüa lähevad abivajajatele. Need asjad mis ei kõlba lähevad aga kas komposti või loomadele söödaks. Suur kogus toidust ja riietest lõpetab ikka prügimäel. Aga See toit ja need riided arvatavasti lihtsalt põletatakse seal prügimäel ära. Täna peaks olema igalpool olemas riiete taaskasutuskastid. \nKasutatud ja üleliigsed riided võiks minna taaskasutusse või abivajajatele. Toiduga samamoodi kas abivajajatele või loomadele söödaks muul võimalusel kompostiks. Osta võiks kvaliteetseid riideid kallimalt mitte rohkemas koguses hiina riideid soodsamalt. riideid võiks rohkem taaskasutada,  mitte hävitada.');
