INSERT INTO core.text(id, content)
VALUES ('c2e6c89b-e74a-498a-8c7e-0e1bff2ed8b0',
        'Oleme kõik harjunud ostma endale hulgaliselt asju, mida me isegi vahel ei kasuta ja mis jäävad kappi seisma.\nToitudega on kõige hullem, paljud toidud lähevad halvaks, kuna me pole jõudnud neid kasutada. Ostame poest palju maitseaineid ja siis need lähevad kuskile seisma pikaks ajaks ja ostame uue, sest unustasime, et üldse ostsime selle. Sellega raiskame väga palju raha. Toidu ostmisega peaks inimene hakkama piirduma, näiteks ostad kuu alguses terve kuu toidu varud ära või käid iga nädal poest ostmas endale toitu. Inimestel läheks nii vähem toitu raisku ja vähem koormust sellega, et pead enda külmkapi või kapi puhtaks tegema, sest toit läks halvaks.\nRiideid on ka inimesel kapis palju ja mõndasid inimene isegi ei kanna. Paljud neist on väikseks jäänud ja ei taha neid ära visata, siis peaks inimene need ära andma, sest kunagi ei tea keda sa aitad sellega. On ka perekondi kes ei saa lubada enda lapsele uusi riideid või neil pole üldse sellist võimalust.\nSellega arvan mina, et inimene peaks enda raha kulutamist vähendama ja peaks vähem ostma poest toitu kui hakkab nii juhtuma, et toit läheb halvaks või üldse ära ei kasutada, riideid tuleb ka iga paari kuu tagant vähendada, sest iga korraga sa kasvad ja kõik ei mahu siis enam selga.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('c2e6c89b-e74a-498a-8c7e-0e1bff2ed8b0', 'title', 'Inimeste tarbimine');
