INSERT INTO core.text(id, content)
VALUES ('544db326-a109-4348-ac19-81914e0680a2',
        'Ma arvan,et inimesed võiksid ikkagi kontrollida oma toite ja mida nad ültse ostavad sealt poest.Paljud poed panevad aegunud toitse -50% tavaliselt aga see pole normaale.Raha kokku hoidmine ka.\nMa usun,et poodides võiks keelata ära alla hinnatud tooted mis on -50% v mingi muu % ka.Paljud rahvasd raiskavad ka toitu kuigi,tegelikult võiksid nad sellest midagi muud teha sellest toidust.Ülejääkidest saab teha väga palju erinevaid toite kuigi tegelikult oleneb mis see toit loomulikult on.Rahvas võiks osta oma nädala toidu nii,et nad mõtlevad enne ära mida nad nädala sees süüa teevad ja ainult ostaksgi neid,kuna ss neil on poole kergem,mitte raisata toitu mida nad ei kasuta.Me võiks teha rahvale koolitusi mis on tasuta kus sellkitakse,Kuidas mitte raisata toitu ja kuidas hoida kokku.Harjumusi võiks ka muuta kuna paljud tooted võivad olla halvaks minnud kuigi sa ei saa sellest aru ja pärast söödad inimestele sisse.Sa peaksid jälgima hakkama toitu,et milline see poes on,et saaksid enda harjumusi muuta nii.Ka paljudele meeldib halvaks läinud titu süüa aga see ei ole hea tegelikult kuna see teeb tervisele väga halba.Rahvas võiks hakkata mõtlema,et kui lihtne neil on kui nad vaatavad oma toite ja ei raiskaks neid.neil jääks poole rohkem raha alles ka.\nMa arvan vähemalt,et rahvas võiks ennats kokku võtta ja hakkata jälgima midanad kodus ültse söövad ja kuidas nad vallivad oma toitusi.Inimesed peavad olema hoolikamad.Ma arvan seda ka,et me võiks raha hakkata koguma,et ei osta seda mida pole sellel nädalal vaja osta.');
