INSERT INTO core.text(id, content)
VALUES ('479976e2-a4cc-442a-b847-90650f3c04ca',
        'Sageli ei pane inimesed tähele, kui palju jäätmeid nende igapäevane eluviis tekitab. Mõni eeldab, et toidu ja riiete ära viskamine ei mõjuta suures pildis maailma varusid ja seisu. Tegelikuses, kui paljud nii mõtlevad, tekib massiline raiskamine mis mõjutab siiski inimkonda tervikuna. Seetõttu peab olema kriitiline ka enda tarbimisharjumuste vastu. Sellest tekib küsimus, et mida saaksin mina teha, et vältida majapidamises raiskamist? Mis on lihtsaim viis taaskasutuseks?\nNii mõnigi inimene viskab ära tähtaja ületanud või söömisest üle jäänud toidu. Lisaks meie enda rahale, koormab see keskkonda meie ümber. Selline eluviis kahjustab meie maad, raiskab vett ja energiat ning tööjõudu. Toidujäätmed võivad tunduda kogu prügi hulgas vaid väikese osana. Tegelikuses toodab Eestis iga inimene aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg, kirjutab tarbitoitutargalt.ee.\nLisaks toidu raiskamisele on ka aktuaalseks teemaks riided ja nende taaskasutus. Viimasel ajal on ka inimeste seas tekkinud nii-nimetatud kiirmood, mil inimesed ostavad ja viskavad ära riideid kiiremini kui varem. Moedisainer Eve Hanson sõnas raadios „Vikerhommik“ intervjuu käigus, et ei tohiks osta riideid, mis on imporditud Hiinast justnimelt põhimõtte pärast. Eve Hanson arvab, et tähtsam on siiski kvaliteet üle kvantiteedi. Parem on osta kodumaiseid tooteid, toetades ka sellega kohaliku toodangut. Lisaks sõnas Hanson, et taaskasutuspoodides tekib riideid aina juurde, kuid paljud neist rõivastest ei ole kvaliteetsed. Pigem nii, et neid on võimalik kanda vaid mõni kord, kuna nende koostis on kahjulik.\nArvestades kõike mainitut, olen ma leidnud, et parim viis taaskasutuseks on korduvkasutus. Toidu ära viskamise asemel soovitan sobilikud toiduained anda mõnele lemmikloomale maiuspalana. Lisaks sellele, on säästlik valmistada komposti, mida saab omakorda kasutada väetisena. Kuigi riiete taaskasutus võib osutada keeruliseks, on üpris hea ajaviide õmblemine. Lisaks uuele oskusele, saad kasutada vanu riideesemeid et valmistada uusi riideid, tekke, kotte ja paljut muud. Eestis võeti vastu ka riide taaskasutuseks kastid, kuhu saab viia vanu riideesemeid ja olla kindel, et need ei satu mõnda prügihunnikusse.');
