INSERT INTO core.text(id, content)
VALUES ('3acaf7cf-043e-46cc-a1c1-1d152ca1c560',
        'Tänapäeva üheks suuremaks probleemiks on saanud liigne tarvitamine. Inimesed ostavad palju rohkem, kui neil tegelikult eluks vaja on. Inimesed ei mõtle sellele, et toidu ja riiete liigse tarbimisega raiskavad nad tohutus hulgas vett ja energiat.\nIgal inimesel on eluks iga päev toitu vaja. Tänapäeval ostavad inimesed seda aga kordades rohkem, kui jõuavad tarbida. Minu vanemad rääkisid mulle lapsest saati, et toitu tuleb võtta niipalju, et jaksaksid pärast ära süüa. Lõunamaadel reisides, jälgisin õudusega, kuidas mõned pered toitu raiskasid. Nad jätsid enda järel suured toidukuhad lauale. See jättis jubeda mulje ja näitas, kuidas rikkamad inimesed ei väärtusta toitu. Sellest näen, et inimesed, kes leiba vaevaga teenivad, hindavad igat levatükki rohkem.\nTeine ületarbimise koht on kindlasti riided. Poed teevad ilusaid reklaame, mis kutsuvad inimesi tooteid juurde ostma. Iga hooaeg tekivad juurde uued trendid, milledega iga tänapäeva inimene kaasa tahab minna. Siit tulebki raiskamine. Selle asemel, et vanad ja kvaliteetsed riided kanda, ostab ta iga hooaeg uued riided, mida ta trendi lõppedes ära viskab. \nMina isiklikult proovin olla loodussõbralik tarbija. Ostan uued rõivad peamiselt taaskasutuspoodidest. Kui vanad riided veel korras on, siis annan ära tuttavatele. Moedisainer Eve Hanson ütles väga targa lause, et pigem osta vähem, kui rohkem. Omalt poolt lisan, et pigem vähem kvaliteetsemaid tooteid, kui rohkem madala kvaliteediga riideid. \nLiigne tarbimine on tänapäevaühiskonnas nii tavaliseks muutunud, et inimesed ei näegi selles ,murekohta. Kuigi seda probleemi ei saa vähendada üleöö, ei tohi seda tähelepanuta jätta. Sellest tuleb inimestele rääkida ja näidata nende raiskamise tagajärgi.');
