INSERT INTO core.text(id, content)
VALUES ('59f15a58-153b-48be-bb33-6131d92beb26',
        'Inimesed harjusid elada hästi. Kui mingi riie enam ei meeldi, viskavad nad selle ära. Paljud inimesed ei hooli ka toidust. Nad mõtlevad, et kui nendel on raha, võivad visata ära mida iganes, kuid see on vale.\nVäga palu inimesi raiskab toitu. Kodumajapidamises on iga inimese kohta umbes 26 kg toidukadu. Inimesed mõtlevad, et kui nad viskavad väikese koguse toidu ära, midagi ei juhtu, aga nad unustavad, kuidas see toit oli valmistatud. Teised inimesed palju töötavad, et toit olekss kvalieteetne, aga me ei hooli sellest.\nKõik inimesed peavad üle vaatama oma tarbimismeetodeid. Inimesed tellivad Hiinast endale riietusi, sest seal on need odavamad, kui poes, aga kvalieteet mängib ka rolli. Paljud Hiina riided on halva kvalieteediga. Pärast esimest korda kandmist inimesed ei taha enam neid riideid kanda.\nVaadates enda peale, ei saa öelda, et ma midagi ei raiska. Mõnikord meil läheb mingi toit halvaks, kas kuupäev on möödas või unustati panna toit külmikusse. Kui selline situatsioon juhtub, viime me selle toidu toidujäätmetesse. Meie aia taga on paar toidujäätme konteinorit, kuhu me pärast toidu panemise paneme peale lehed, et putukad saaksid selle toidu ära lagundada.\nMa tahaks lõpetada sellega, et kõik vaataksid enda peale, palju nad midagi raiskavad. Maailmas on väga palju inimesi, kellel pole sellist elamuskvalieteeti nagu meil.');
