INSERT INTO core.text(id, content)
VALUES ('29e2089e-69bd-4960-b696-afd95a0229ce',
        'Iga aasta tekib igal eestlasel keskmiselt 61kg toidujäätmeid ning kapipõhja jääb hunnik riideid, mida enam selga ei sobi panna. Kas siis materjali või nendest väljakasvamise pärast. Seepärast kulub ka rohkem raha, kuna toitu lihtsalt läheb raisku ja riideid mida selga panna jääb aina vähemaks. Tihti ei tulda ka selle peale, et toitu saab vähem raisata ning riideid saab annetada või siis maha müüa.\nPeaaegu pool äravisatavatest toidujäätmetest on toidukadu ehk raisatud toit või toiduaine. See kogus on nii suur, sest kohe kui pakendil olev kuupäev on ületatud eeldatakse, et toit on halvaks läinud ja visatakse kohe minema. Tavaliselt jääb ka toidukordadest toitu üle, kas siis sellepärast, et on liiga suur kogus tehtud või siis eine nässu läinud. Selleks, et toitu säästa tuleks poes käia nii, et oled etteplaneerinud mis sa ostad. Toidukordade ülejäägid saab alles jätta ning järgmisel päeval, või siis samapäeva õhtul soojaks teha ning süüa.\nKiirmood on viimaste aastatega väga suureks probleemiks saanud. See on odav ning kergesti kättesaadav. See on ka loodusele väga ohurikas, kuna kiirmoe riiete tootmise peamine koostisosa on nafta. See on kehal ning sinul endal ebamugav sellepärast, et keha ei ole harjunud sellega. Paljud kiirmoe riided visatakse tavaliselt ära, harval juhul jõuavad need taaskasutuspoodidesse. Tihti näevad need reklaamfotol ilusad välja, kuid riiete kohalejõudmisel mõtled, et kas sulle toodi ikka õige pakk.\nRiiete taaskasutamine ja kaltsukates käimine on üks minu lemmiktegevusi. See aitab natukene minu poolt vähendada riiete raiskamist, säästab raha ning vahepeal leiab taaskasutuspoodidest üli lahedaid riideid. Toitu ma üritan teha alati täpselt nii, et kõik saaksid söödud aga, et väga palju üle ei jääks. Isegi kui üle jääb panen selle külmkappi ja kui kõht juhuslikult tühjaks läheb, saan soojaks teha ning saan aega säästa. \nTaaskasutamine on hea viis kuidas mittevajalikest asjadest lahti saada, natuke kappi tühjendada ning enda poolt natuke loodust aidata. Võibolla sa arvad, et nende väikeste asjadega ei muutu maailm kohe. Sul on õigus, aga see ongi pikk protsess ning iga väike samm aitab.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('29e2089e-69bd-4960-b696-afd95a0229ce', 'title', 'Taaskasutamine');
