INSERT INTO core.text(id, content)
VALUES ('9e89bfef-a878-43b0-9665-894fb463fce5',
        'Inimestel on harjumus hunnikutes ära visata igasuhuseid asju. Lademetes ostetakse kaupa, mis hiljem sekunditega ära visatakse. Rõivaste tootmine ja hävitamine ei toimu linnulennul, kuid nende kergekäeliselt ära viskamine küll. Iga aastaga muutub heidetud asjade arv suuremaks. \nOn olemas e-poode, kus saab tellida odava hinnaga riideid. Hiinas on palju selliseid firmasid, kus praakkaup on odava hinnaga. Tihti peale ostavad sellisest kohast esemeid noored, sest neil palju raha pole. Mimu meelest tuleks neid koolitada. ,,Ei telliks veebipoodidest juba põhimõtte pärast asju, ei läheks kaasa sooduskampaaniatega,“ lausus moedisainer Eve Hanson. Minu arvamus kattub Hansoni sõnadega. Ma ei näe mõttet osta asju, millel on odav hind, kui mul seda vaja pole. Kindlasti ei telli ka mina riideid kohtadest, kus nende tootmine pole eetiline. Olen küll näinud internetis videoid, kus näidatakse, mida osteti. Paari videot olen vaadanud karp lahti, sest see kui palju ebavajalikke tooteid ostetakse on hullumeelne. \nInimesed ei mõista, et ükshetk saab toit otsa. Olen ise tüdruk, kellel väike isu ning paljud asjad ei maitse. Lapsest saadik olen toitu valinud ja palju ka ära visanud. See on tulnud mu emalt, sest käbi ei kukku kännust kaugele. Mida rohkem lugenud olen,  mõistan, et pean muutma oma harjumusi. Iga aastaga olen end parandanud ja oma portsionite kogused muutnud. Osade inimeste jaoks on toit kiiresti kättesaadav, lihtsalt mine poodi ja osta. Mõnede jaoks on toit väärtus, mida kergelt kätte ei saa. Tuleb näha vaeva, et leib lauale jõuaks. Olen väga tänulik oma vanematele, et võimaldavad mulle elu, kus ma ei pea õhtusöögi pärast jahti pidama.\nInimesed võiks rohkem mõelda, enne kui midagi ostavad. Tegelikkuses pole inimesel palju vaja. Kõigile tuleks marjaks ära paar koolitust, kus räägitakse tarbimisharjumustest. Igaüks võiks vähendada oma tarbimiskoguseid.');
