INSERT INTO core.text(id, content)
VALUES ('9d1244eb-a8e4-4b1d-9f3b-b056401df6fb',
        'Tänapäeval toodetakse palju rohkem toitu, võrreldes mitu sada aastat tagasi. Palju toitu on hea, aga kuna see on meil kõikjal, on meil tekkinud erinevad harjumused. Need harjumused saavad olla nii head kui ka halvad.\nÜks halvim harjumus, mis inimestel on, on toidu ära viskamine. Nad kas ei söö toitu enne ära, kui see halvaks läheb või nad võtavad liiga palju süüa ja ei lõpeta seda ära. Selline tegevus on halb, kuna see raiskab toitu, energiat ja raha. Mul kodus sellist harjumust õnneks pole. Kui meil jääb toitu alles, paneme me selle külmkappi ja ennem toitu juurde ei tee, kui see on söödud. Vahel ikka teeme, aga mitte palju.\nTeine halb harjumus on, et inimesed ei tee enam endale süüa. Mõned inimesed ei viitsi enam ise süüa teha, seega nad lähevad restorani või ostavad poest valmis tehtud toite. Restoranid kogu aeg halvad ei ole, aga kiirtoidu restoranid on. Kiirtoit on väga rasvane ja väga ebatervislik, kuna see võib tekitada tervise probleeme, näiteks teeb tüsemaks ja võib  lühendada eluiga. Poest valmis tehtud toite on ka halb süüa, kuna see võib tekitada tervise probleeme. Me perega sööme aeg-ajalt kiirtoitu. Me sööme tavaliselt ainult siis, kui lähme linna, aga seda ei juhtu tihti.\nInimestel on ka häid harjumusi. Tavaliselt on head harjumused tekkinud just nendel inimestel, kes mõistavad, et see on suur probleem, aga kahjuks pole neid palju. Üks neist harjumustest on kogu toidu ära söömise. See harjumus on õnneks enamustel minu pereliikmetel, aga kahjuks mitte igal. Teised head harjumused on, näiteks ise toidu tegemine ja õige toidu valik. Head harjumused on peamiselt need, mis aitavad keskkonda ja aitavad hoida inimeste tervist.\nTarbimisharjumusi on nii häid kui ka halbe. Kahjuks on halbe harjumusi just rohkem ja see arv on kasvamas. Halvad harjumused rikuvad meie keskkonda ja meie tervist, aga head teevad hoopis vastupidi. Me perega proovime õnneks vältida halbe harjumusi ja me loodame, et teised teevad sama.');
