INSERT INTO core.text(id, content)
VALUES ('fdf68fab-f542-480d-b041-500bebeb051f',
        'Eestis on suur probleem tarbimise üle. Inimesed arvavad, et nad saavad endale kogu aeg süüa juurde hankida kui tahavad, ning see viib selleni, et kohe kui miski ei sobi viskavad vana toidu ära. Seda juhtub igas peres väga palju mõndades, aga rohkem ja teistes, aga vähem. Sellega me raiskame oma rahast väga palju ja ressursse. \nMa tahaksin tagasi tulla teema juurde toidu raiskamine. Seda olen ma ka ise teinud kuna toit on kas liiga kaua seisnud või läks halvaks, ning sellega tuleb ettevaatlik olla kohe kui tead, et lähed reisile mõneks päevaks siis süüa mitte palju teha, sest muidu jääb toit seisma ja läheb ära viskamisele. kodupidamises tekib iga inimese kohta 61kg toidujäätmeid, millest toidukadu on 42% ehk 26kg. Seda on küll raske teha aga inimeste võiks olla usku.\nSiin ma langeks uuesti ressursside kadu üle. Ressursse läheb vaja kõigeks nt toidu tegemine, masinate ehitamine, kuumendamiseks, elektriks. Toidu valmistades sa kasutad võib-olla pliiti või ahju, aga nende jaoks on elektrit vaja, niiet kui sa toitu raiskad siis sa ka raiskad elektrit või puitu, ning seda ei ole lõppmatus.\nInimesed on liiga harjunud raiskame ilma, et nad ise saaksid sellest aru ja jätkavad sellega siiamaani. Seda on keeruline järsku vähendada, aga on tehtav. Ressursse läheb liiga palju inimestel raisku kas kogemata või meelega.');
