INSERT INTO core.text(id, content)
VALUES ('434b62ff-69d6-4c41-92f0-f3638761db2c',
        'Kogu maailmaas on üks suur probleem. Palju inimesi raiskavad toitu ja riideid. Näiteks praegu on sellega suur probleem. Palju inimesi ei tea, et nad raiskavad toidu ja riideid. Me oleme veel noored, peame õpetama inimest, et nad ei raiskaks. \nInimesed ostavad rideid Hiinast. Riietus Hiinas ei ole kvaliteetne ja ei ole hea vaid halb,sest on tehtud naftast. Meil on palju poodi, kus on kvaliteetne riietus. Riietus Hiinast maksab vähe, fotodel näeb välja hästi vaid elus on üldse teine. See materjal üldse ei ole hea, ei ole mugav kandma. \nIgal inimesel on umbes 61 kg toidujäätmeid,nendest on 26 kg toidukadu. Palju inimesi raiskavad toidu. Võib-olla nad ei tea, et raiskavad. Mõned teavad vaid ei taha sellega midagi teha. Meie peame rohkem rääkida toidust ja raiskumisest. Peame näitama inimetele, kui suur see probleem tegelikkuses on. Ära raiska toitu, sest palju inimestel pole toitu. Iga kord kui tahad prügikasti ära visata, mõtle selle peale, et on inimesed,kes tahavad süüa aga ei saa.\nToidu raiskamine ei lahenda, kui me ei tee mitte midagi.Peame kuidagi õpetama inimest. Loodame, et see probleem läheneb.Oleks väga tore,kui kõik inimesed saaksid mitte raiskata toitu ja teada, kus ja, kuidas valida riideid');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('434b62ff-69d6-4c41-92f0-f3638761db2c', 'title', 'Toitu ja asju raiskamine');
