INSERT INTO core.text(id, content)
VALUES ('e41bdbc3-7cdf-42a3-997d-6c0ed2fb94e5',
        'Viimastel aegadel on inimesed hakanud aina rohkem tooteid ostma. Tänu sellele hakatakse ka rohkem asju tootma. Iga tootja tahab teenida kuhjaga raha. Paljudel tehastel on eesmärk toodete kogus ja mitte toodete kvaliteet. Sellega kaasneb aina rohkem uute asjade ost. Süüdistada ei saa ka ainult tehaseid. Meie ise oleme ka osa probleemist.\nPoodides on müügil tuhandeid erinevaid rõivaid. Igale inmesele on antud hiiglaslik valik riideid mida kanda, kuid valik on nii suur, et kõiki riideid ei saagi ära müüa. Tänu e-poodidele saab ka tellida riideid ilma neid selga panematta, millega võib taganeda riieta ära viskamine. Lisaks on inimestel soov riietuda stiilselt. Lihtsalt kanda midagi mugavat ei ole piisav, vaid tuleb osta midaki millega torkad teistele silma. Olen ise näinud kuidas internetis inimesed jälgivad moetrende ja ostavad tihti uusi riideid, kui vanad kappi ununevad.\nKahjuks ületarbimine ei peatu ainult riietega. Toidu kättesaadavus ja soodne hind paneb inimesi ostma nagu toidaks tervet küla. Sellise suure tarbimisega läheb palju toitu raisku. Andmed ütlevad: „Kodumajapidamises tekib iga Eesti inimese kohta keskmiselt 61kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg.“ Toit on muutund ka inimvajadusest hoopis meelelahutuseks. Me ostame aina rohkem rämpstoitu ilma vajalike vitamiinida ja mineraalidetta, kuna see on tehtud nii maitsvaks.\nInimesed ostavad aina rohkem ja see on probleem. Meil pole nii palju asju vaja, mistõttu suur osa nendest läheb raisku. Riideid toodetakse liiga palju ja suur osa neist halva materjaliga, mida kantakse ainult paar korda. Toit ei ole enam ainult vajadus, vaid ka meelelahutus. Selle raiskamine tuleb lõpetada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
