INSERT INTO core.text(id, content)
VALUES ('aea3bb6d-1bc4-4d71-ba61-facfa7bbe034',
        'Tänapäeval on inimeste tarbimisharjumused kehvad. Ostetakse igaksjuhuks rohkem asju, kuid pooled visatakse minema. Taaskasutamist on juba ammu reklaamitud, aga palju pole muutunud. Tundub, et inimesed ei taha harjuda taaskasutamisega.\nToidupoes käimine on üpris keeruline. Alati tekib poes isu toidu üle, mida sul tegelikult vaja pole. Nii ostetaksegi toitu, mis lõpuks prügikastis lõpetab. Iga Eesti inimese kohta tekib aastas keskmiselt 61 kg tõidujäätmeid ning sellest pool ongi toidukadu. Ka mina olen üks neist, kes arvab, et üksinda ei saa ma midagi muuta. See mõte on vaid peas. Kui mina hakkan enda toidutarbimist hoolikamalt jälgima, siis tegelikult hakkavad muutuma ka numbrid. \nRiideid ostetakse meeletutes kogustes ja igalt poolt. Noorte seas on levinud Hiina veebipoodidest riiete ostmine, sest sealt saab odavalt ja kiirelt. Ei mõelda nii tootmisprotsessi ega ka kvaliteedi peale. Hiina veebipoodides on riiete kvaliteet väga halb. Peale paari kuud kandmist viiakse riided Second hand poodidesse ning ostetakse Hiinast uued – see on raiskamine. Samuti ostetakse riideid kallilt tavapoodidest. Üks teksapaar maksab 50 eurot, samas kui läbi taaskasutuse saaks poole odavamalt. \nMinu enda tarbimisharjumused pole ka kiita. Mulle väga meeldib riideid osta, kuid mitte taaskasutuspoodidest. See ei ole mulle külge jäänud. Tihti pole ka kaltsukates neid riideid, mida mina otsin. Tavapoes on lihtne – peaaegu kõik on olemas, mine lihtsalt kohale ja vali välja. Soodukatega poodlemine on eriti kerge, sest siis on kõik ilusad riided odavad. \nToitu ja riideid raisatakse palju, nende arvelt ka raha. Toidupoes ostetakse palju sööki, kuid osa sellest visatakse ära. Riideid soetatakse ikka rohkem tavapoodidest kui kaltsukatest. Rahvas pole harjunud taaskasutama.');
