INSERT INTO core.text(id, content)
VALUES ('ec88d495-f382-406e-b8c7-15f3884c7ac6',
        'Tarbmisharjumused on suur teema. Inimesed raiskavad toitu, riideid ja muid taaskasutavaid asju. Suureks probleemiks on saanud see just sellel sajandil kui inimesi on pea 8 miljardit. Probleem seisneb selles ,et inimesed lähevad aina laisemaks ja ei viitsi eraldi sorteerida.\nMinu arust väga hea lahendus on taaskasutuspood. Riiete taaskasutuspoes võib leida väga moodsaid pluuse või jalanõusi. Olen käinud mitmes taaskasutuspoes näiteks Humana. Humanas on stiili valik lõppmatu. Kui oleks selline programm kes viiks ja tutvustaks lastele taaskasutusvõimalusi, ja paneks lapsi mõistma miks see nii suur probleem on. Saaksime tulevikus kindlasti säästa rohkem maailma.\nTaaskasutusvõimalusi on mitmeid. Saaksime säästa toitu kui teeme seda õiges koguses. Olen saanud näha palju välismaa kultuuri ja Eestis toiduraiskamine on päris suur. Ei pea alati toitu ära viskama võid lihtsalt karpi panna ja söögi külmkappi panna. Suurtes restorandies võiksid olla ka reeglid toidu raiskamise kohta. Eestis hea elu toiduga aga teisel pool maailmat pole see päris nii. Kui kõik tuleksime kõik kokku saaksime raiskamist vähendada. \nKõige suurem probleem maal on magevesi. Joodavat vett on niigi vähe ja selle raiskamine eriti suur. Kui pesed hambaid siis ära  jäta kraani käima. Võid ju lihtsalt kraani kinni panna. Seni kaua kui me ei oska mereveest joogivett teha peaksime hoidma vett nagu kulda. \nRaiskamine ja enda maale kahju tegemine on suur. Lahendusi väga palju. Kui iga inimene natuke panustaks oleksime igapäev aina puhtamad. Vanad riided taaskasutuspoodi. Sööme kõik toidu ära, mitte ei viska lihtsalt prügikasti. Säästame joodavat vett ,sest seda pole palju alles.');
