INSERT INTO core.text(id, content)
VALUES ('7e9f9294-7b8b-49f6-8cc8-25aae116d2d2',
        'Toidu raiskamine ja üleliigne riiete ostmine on maailmas aina kasvav probleem. Paljud inimesed isegi ei mõtle selle peale, kui halvasti toidu ära viskamine ja ebavajalike riiete ostmine meie keskkonnale mõjub. Lisaks sellele raisatakse suurel hulgal maailma ressursse.\nMuidugi on maailmas inimesi, kes arvavad, et toidu raiskamine on normaalne ning nende jaoks ka igapäevane tegevus. Rahvas ei mõtle piisavalt riikide peale, kus on söögist puudus ja nende peale, kes peavad pikka aega nälgima kuna kõigile süüa ei jagu. Inimesed ostavad liiga palju süüa ning, kui hiljem pakendilt loevad, et toit on kasutustähtaja ületanud, visatakse ülejäänud toit prügikasti. Sellega raisatakse nii raha, kui ka tootmiseks vajalikku energiat, maavarasid ja tööjõudu.\nOsa probleemist on ka riiete liigne ostmine. Näiteks, kui kõnnitakse mööda riidepoest ja nähakse midagi ilusat, siis mõeldakse kohe, et seda on vaja, isegi siis, kui kodus on riideid juba piisavalt. On ka inimesi, kes ostavad halva kvaliteediga asja, kannavad neid paar korda ja siis viskavad ära. Maailmas ei teata probleemi tõsidust ning see on ka põhjuseks, miks probleem on kasvavas järgus.\nMa ei saa väita, et pole kunagi ise toitu ära visanud. Olen seda kindlasti teinud, kuid mõistan, kui suur probleem sellega on ning üritan toitu mitte ära visata. See kehtib ka kooli sööklas, võtan nii palju toitu, kui ise ära söön ja ei jäta toitu järgi. Riideid ostan ainult siis, kui mul neid tõesti vaja on või siis, kui midagi on väikseks jäänud. \nTarbimisharjumuste muutumine ei saa toimuda üleöö, see on aeganõudev protsess, milles peab osalema terve maailm. Isiklikult teen kõik, et mitte olla osa probleemist.');
