INSERT INTO core.text(id, content)
VALUES ('8a4604aa-fd6e-4ec7-8560-b3e7d5e37c33',
        'Raiskamine, üks inimkonna vigu, mida on raske parandada. Kõik, mida ostakse jõuab prügikasti ja seejärel prügimäele.\nIga inimene vaiab toitu, et elada. Osad raiskavad toitu meeletult ja isegi ei pane seda tähele. Eestlane teeb keskmiselt 61 kg prügi ja 41% sellest on toidujäätmed. See pole lihtsalt kekkonna mure, vaid ka ostija mure. Kui ostija raiskab toitu, raiskab ta ka oma raha. On tähtis, et inimkond õppiks toitu hoidma ja ei raiskaks seda.\nRaha kokku hoidmine on tähtis oskus, mida peaks iga inimene teadma. Inimesed kullutavad raha kogu aeg mõttetutele tootetele: ostes Hiina vebipoodidest või keemikaalidega täidetud toite. Need võivad küll odavamad olla, aga kvaliteet on küsitav. Hind ja kvaliteet on võrdselt tähtsad, kuigi suurem osa keskendub hinnale. On tähtis õpida ostma vajalike tooteid, mitte kullutada ebavajalikkele asjadele.\nMa isiklikult arvan, et hoian asju kokku. Ma söön eilsest tehtud sööki, väldin vebipoode ja kuulutan raha hästi. Kuid see võib paikneda minu ükskõiksusest nendele asjadele. Mind ei huvita need vebipoed, ma saan poodi minna ja sealt midagi osta. Olen kaotanud huvi rämpstoidule, kuid ei suuda lõppetada kui keegi pakkub mulle. Ma ei osta endale riideid, neid ostavad mu vanemad, aga need võivad olla vebipoodidest. Räägin küll, et ei tee sellised asju, kuid ollen ikka osa sellest.\nRaikamine on vältimatu, sellest saab võitu alles, siis kui kõik seda teevad. Inimene tahab, kas raiskamist vähendada või ültse pole sellest huvitatud. Kokkuvõtteks on see kõigi ülesanne.');
