INSERT INTO core.text(id, content)
VALUES ('79f113e6-c9f4-4b8e-b593-9fb88ea91f00',
        'Inimesed on harjunud ära viskama toitu ning korralikus seisukohas riideid, kuid mida nad ei tea, on see, mis mõju selline tegevus meie maailmale avaldab.\nEnamikel on halvaks harjumuseks toiduraiskamine. Aastas tekib meie omaenda riigis, Eestis, keskmiselt 26 kg toidukadu. See on väga suur kogus. Kahjuks ei saa inimesed aru, et sellega teevad nad liiga nii enda rahakotile kui ka meie keskkonnale. Minu peres tuleb harva ette toidu ära viskamist: kasutame kõik ära, mis endale koju kokku ostame.  \nTarbimisega kaasneb ka prügi. Eriti palju tekib plastikut, mis ei lagune ise. Suur viga, mida inimesed teevad, on mitte prügisorteerimine. Just tänu sellele võib sattuda plastikut ka meie keskkonda e loodusesse. Vahepeal tuleb internetis ette videoid suurtest prügimägedest veekogudes ning kuidas loomad nende sees elama peavad. Usun, et mitte keegi ei tahaks elada prügis. Miks me siis loomadele nii teeme? See on iga inimese enda mõtlemiskoht.\nPalju tuleb ka ette juhtumeid, kus inimesed ei hooli enda korralikudest riietest. Odavadelt veebilehtedelt ostetakse endale ebakvaliteetseid riideid ning hiljem lihtsalt visatakse need ära. Alati, kui enda kappi koristan, tulevad päevavalgele riided, mida ma pole pikka aega kandud. Siit tulebki mängu üks suurim tarbimisprobleemide lahendusviis: taaskasutus. Korralikud riided, mida mõni inimene veel kanda saaks, viin ma riidekonteinerisse ning ka teiseringipoodidesse.\nOn veel ka lootust. Saame enda muutmisega muuta ka maailma. Halbadele tarbimisharjumustele ei ole küll lihtne järgi anda. See ei käi kiiresti, vaid on hoopiski pikaajaline protsess, mille käigus inimene õpib mõistma, mis on hea, mis ebakasulik. Arvan, et koos saame hakkama ning liigume edaspidi ainult paremuse poole.');
INSERT INTO core.text_property(text_id, property_name, property_value)
