INSERT INTO core.text(id, content)
VALUES ('e31273c9-bfc4-42c9-99fc-52a452660c4a',
        'Inimesed arvavad et toitu raiskamine sest arvavad et poest ei sa kunagi toit otsa.On inimesi kes raiskavad toitu väga palju.Nad saavad seda endale lubada.On inimesi kes raiskavad vähem toitu kuid sellega suurt pilti ei näe.Inimesed ei sa sellest aru et see võib kahjustada maad,vett,energiat ja tööjõudu.Tähtis on veel see et igaüks vaataks oma tarbimisharjumused üle.Nad ei läheks kaasa odava Hiina asja juurde.\nkodumajapidamises läheb toidu raiskamine kesmiselt suuremaks.Ning sa raiskad sellega enda raha millest inimesed ei sa aru.Riideid tuleb hunnikus kaltsukatese sest inimesed kannavad Hiina kaupa.See ajab naha sügelema ja on seljas rõve kanda seda.Inimesed ostavad Hiina kauplustest mis on odav ja tehtud naftast millest keegi aru ei sa.\nMinu endal on väga halb vaatata inimesi kes tõstavad endale toitu aga ei söö ära seda kõike.Inimesed võiksid tõsta endale nii palju toitu kui jaksavad ära süüa.Kui meil kodus jääb alles midag siis anname koerale.Riideid ma ostan ise ka vahes Hiina kohast.Mida ma ei kanna tavaliselt kas need lähevad mu väiksemale õele või konteinerisse.\nInimeste toidu raiskamine on väga suureks läinud.Inimesed ei oska seda hinnata nagu kunagi.Ostavad riideid odavast poest sest vaatavad selle lehe pildi pealt väga ilus aga tuleb üldse mingi tene asi.');
