INSERT INTO core.text(id, content)
VALUES ('25304b88-6d2a-4c24-9210-f2cf32b2f75e',
        'Iga inimene peab sööma, jooma, riideid ja muid asju tarbima, et ellu jääda. Tänapäeal toimub juba pikka aega ebvajalike asjade ostmine. Mis on põhjuseks, miks me raiskame ning kogu aeg asju juurde soetame? Minu arust kõik algab sellest, kuidas me suhtume oma ümbrusesse.\nMul pole vahel sooja ega külma sellest, kui midagi katki läheb või ei sobi. Alati on võimalik osta poest asendus ja vana asi ära visata. Mina näiteks ostan kehva kvaliteediga asju, sest need on nii palju odavamad võrreldes kallimate variantidega. Kallimad varijandid kestavad küll kauem, aga iga natukese aja tagant soetada uut ja põnevat odavamalt on sama lihtne.\nMul on jäänud mulje, et firmad meelega teevad asju nõrgemaks. Näiteks ma sain kõige esimese telefoni oma vanemalt vennalt, kes sai selle telefoni omakorda vanemalt õelt. See telefon kestis 9 aastat ja ekraanil ikka veel ei ole ühtkit mõra, aga jäi aeglaseks võrreldes teiste mobiilseatmetega. Minu uus telefon seevastu saab alles 3 aastaseks ning ekraanil on mitu mõra plus sügavat kriimud. Ma juba praegust otsin uut telefoni. Mõlemad telefonid pärinevad samast firmast.\nSuur kogus tooteid meie ümber, mida saab lihtsalt välja vahetada. Firmad, mis teevad sihilikult tooteid nõrgemaks, et rohkem neid müüa. Need on vaid osad põhjused minu arust, miks me ülearu tarbime.');
