INSERT INTO core.text(id, content)
VALUES ('7c3dddc4-fce1-45c6-8aa9-b1aaf5d8d351',
        'Tänapäeval inimesed ei saa aru, kui palju nad tegelikult raiskavad. Tihti ostetakse kõige odavamat kaupa, teadmata kaua nad seda kasutada saavad.  See raisksb tohutult meie resursse.\nRiided on üks asi, mida ületarvitatakse. Viimaste aastatega on Hiinast tellitud rõivad populaarseks muutunud. Üheks põhjuseks on nende hind. Need on nii odavad, et inimesed tellivad neid kuhjade viisi. Sageli on need riided halva kvaliteediga ja lähevad kiiresti katki. \nToit on üks tähtsamaid osasi elu juures, inimesed ostavad seda igaks juhuks alati rohkem kui vaja. Seda jääb tihti üle või läheb enne halvaks, kui seda tarbida jõutakse. Toit visatakse ära prügikasti, aga igalpool ei ole nii, osades kohtades on toidust puudust.\nMina väärustan toote kvaliteeti. Riide ese võib rohkem maksta, aga see kestab kauem ja ma kannan seda tihedamini. Kui ostan 40 eurose kampsuni ja kannan seda sada korda, siis tuleb see odavam, kui osta 10 eurone kampsun ja kanda seda viisteist korda. Samamoodi on toiduga, kui toit maitseb hästi ja on kasulik mulle, siis söön kõik ära.\nInimesed teglikult ise ei teagi, et see on halb planeedile ja neile. Neid peaks harima sellel teemal rohkem ja siis saaksid nad aru, miks need odavad tooted halvad on.');
