INSERT INTO core.text(id, content)
VALUES ('ba5d9552-a634-494a-bb36-8997e321c0af',
        'On oluline, et igaüks vaataks üle oma tarbimisharjumused nong eelistaks kvaliteeti kvantiteedi üle. Mõistlikum oleks eelistada pigem kodumaiseid tarbimisharjumusi kui kasutada välismaadelt toodud esemeid. Probleem seisneb selles, et paljud riided koosnevad naftast ja on tihtipeale ebamugav. \nNagu kauplustes on näha, siis kõik rõivad ja riided tulevad enamasti riikidest, mis ei ole üleüldsegi turvalised, nagu näiteks Hiina – sealt tulevad rõivad, mis sisaldavad naftat. Neid ei tasu üldsegi kanda, kuna see võib tekitada inimestele väga halba tingimust inimesele endale ja nahale. Riideid valin ainult järgmistel aspektidel: hind, mugavus, materjal ja vastupidavus. Kui need valikud mulle sobivad, lisan selle endale ostukorvi ja jätkan oma ostlemist.\nTaaskasutuskaupluste laos on vabatahtlikus käies meeletu suur rõivaste kogu ja see on puhas koledus. Mina arvan, et taaskasutus on palju mõistlikum kui kulutada raha modernsete brändide peale. Aegajalt mõtlen: ‘’Milleks mul on vaja kasutada raha tekstiili peale, mis on hullult üle 150€? See on paras kurbus, et ma lasen rahal lennata minema asjade peale, mida mul üldsegi vaja ei lähe.’’ Seetõttu olengi parem riidepoodide, näiteks Sinsay, H&amp;M poolt, sest nendes poodides on palju paremaid ja avaramaid valikuid kui moepoodides. Kõige enam ma kahtlen seda, et kuidas suudab tekstiil nii kallis olla. \nOlen kindel, et riide materjal ja mugavus on veelgi olulisem. Mina tellin endale parem riideid kauplustest, kust saab palju parema hinnaga ja mugavusega esemeid. Taaskasutuspoodides on laos omavolilises käies mõttetult suur rõivaste kogu ja sellega kaasneb kaasa kohutavalt halb jama. Minu arvates on kvaliteet ja kvantiteet parem kui osta riideid, mis on moodsad ja ülehinnatud.');
