INSERT INTO core.text(id, content)
VALUES ('7ea0df6b-b3a8-4402-bb9f-9995ab80a86c',
        'Paljud inimesed viskavad üleliikset toitu prügikasti. Need touidud on kas riknenud või kasutustähtaja ületanud. paljud toiduained on söömis kõlpmatud ja inimesed viskavad need prügikasti. Me ei raiska oma raha vaid ka teisi ressursse maad, vett energiat. Inimesed kes on harjunud toitu ära viskama need vskavadki ära.\nInimesed kes viskavad toitu prügikasti. Kui sa viskad toitu ära siis see teeb keskkonnale väga palju kahju. Sa peaksid vaadama neid toodeid mis säilivad kauem kui üks päev. Visatakse palju riideid ja ka teisi asju minema. \nKui sa ei tarbi neid toodeid mida sa ostad siis ära osta neepalju asju mida sul tegelikult vaja ei lähe. Kui sa võtad nii vähese säilivus ajaga toodeid siis võta neid toodeid mis säilivad rohkem.\nOn inimesi, kes raiskavad toitu, sest nad saavad seda endale lubada. Mina tarbin neid toodeid mis on pikka säilivus ajaga, sest need lihtsalt säilivad kauem, kui need millel on lühike säilivus aeg.\nMina ütleks toitu raiskamise kohta seda, et kui sa ostad palju asju siis vaada kui kaua see säilib. Kui sa ostad neid toodeid mis ei säili kauem kui kaks päeva siis ära neid toodeid võta. Minu arvates on parem võta neid toodeid mis on pikaajalise säilivusega tooded.  Kui sa lähed poodi toodeid ostma siis kontrolli kui pikk on säilivus aeg sellel toodel mida sa ostad. Paljud kelle jääb toitu üle see viskab selle prügikasti.   Minu arvades on see väga halb, sest see mida sa ostad millel säilivus aeg lõpeb paari päeva pärast ära.');
