INSERT INTO core.text(id, content)
VALUES ('4f864bc7-47ce-4072-8f39-957f2803bdd8',
        'Toit on meie kõigi igapäeva loomulik osa, Tänapäeva võimaluste ja tehnoloogia juures on toit saanud kõigile kättesaadavaks, kuid sellega kaasnevad ka teatud probleemid. Inimesed on muutunud niivõrd laisaks, et toidukoguste jälgimine on väljunud täielikult kontrolli alt. \nEesti kodanik viskab aastas ära keskmiselt 61 kg toidujäätmeid, see fakt on paljusid muretsema pannud ning usinalt otsitakse lahendusi toiduraiskamise vastu. Üks ilmselt kõige loogilisem ja populaarsem idee kuidas enda toiduraiskamis hulka vähendada on enda toidukoguste jälgimine. See tähendab, et inimene jälgib, kui palju ta keskmiselt ühes kuus toitu tarbib ning teeb poes vaid selle teadmise järgi vajalike oste.\nTeine levinud lahendus on toidu annetamine. Inimesed saavad viia oma ülejäänud toidu spetsiaalsetesse kogumispunktidesse või toidukapidesse. Kogumispunktid annavad inimeste annetatud toidu edasi neile, kes ei suuda endale nii hästi toitu muretseda. Toidukappide eesmärk on sama, kuid nende erinevus seisneb selles, et inimesed saavad ise minna ja sealt endale meelepärast võtta.\nRaiskamisele ei kuulu ainult toit, vaid ka riided. Inimesed viskavad täiesti ilmapõhjusetta ära uusi ja korralike riideid. Riiete raiskamise vastu aitavad taaskasutuspoed, mis on kokkukogunud kõik minema visatud vähegi korralikumad riided ning müüvad neid mõistliku hinnaga. Ka mina olen vahel taaskasutuspoodides käinud ja võin öelda, et iga kord olen päris üllatunud, kuna seal olevad riided on väga kõrge kvaliteediga.\nRaiskamine on pidev probleem ning see ainult kasvab. Õnneks tuleb pidevalt uusi ja nutikamaid lahendusi. Loodame, et ei lähe enam kaua, kui raiskamine on minevik ning sellepärast ei pea enam meie koduplaneet kannatama.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('4f864bc7-47ce-4072-8f39-957f2803bdd8', 'title', 'Tarbimisharjumused');
