INSERT INTO core.text(id, content)
VALUES ('ff8feaf9-ca24-46f9-b762-4ac3d792dad7',
        'Inimesed söövad rohkem kui tahavad, ära viskavad ja litsalt kuidagi suvakalt ja ebasäilitavasti raiskavad toitu. Peaaegu iga inimene mõtleb, et meil on nii palju toitu, et seda võib võtta igas kohas kus tahad ja see ei saa otsa, aga ei.\nMõned rikkad raiskavad toitu lihtsalt selle pärast, et tahahavad näidata kui vahvad nad on ja saavad üks kõik mis. Sellised inimesed väga palju viskavad ära, sest kui söök ei ole natuke selline kuidas nad endale mõtlesid siis kohe see lendab prügikasti. Ei saa öelda, et kõik niimoodi teevad aga enamus kellel on palju raha näitavad seda üks kõik nagu tahavad ja kuidas ma varem ütlesin isegi läbi toitu. Kuskilt saab neist aru, naad saavad osta ja raisata kuidas ise tahavad, sest on võimalus.\nAga muidugi mitte ainult rikkad inemesed viksavad ära toidu. Iga Eesti inimese kohta tekib aastas umbes 61 kg toidujäätmeid, millest toidukadu on 42% ehk 26 kg ikka sellele on mõnikord põhjus aga mitte sellises kogus.\nKui hästi mõelda võib saada aru, et toidu raiskamist ei saa ruttu vähendada, sest see on juba inimestel nii harjutud. Võib olla kui see teema saab populaarseks inimesed hakkavad sellest rohhkem aru saama ja teha selleks, et kõik stabiliseeriks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
