INSERT INTO core.text(id, content)
VALUES ('bd7eb490-0c7a-45cc-9a84-7d3a58fd4d83',
        'Aluseks võiks öelda, et on olemas kaks probleeme. Esimene on toitu raiskamine ja teine on riietust raiskamine.\nInimesed ei saa aru, et nad raiskavad palju riietusi ja toite. Näiteks iga Eesti inimese kohta tekib aastas 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg. Ma ise näen, et minu vanemad ja sõbrad raiskavad väga palju toite, mis võiks kasutada oma tarbimiseks. Inimesed raiskavad toitu, sest nad saavad seda endale lubada. Võib olla nendel on palju raha või nad lihtsalt on rumalad. Pigem teine variant, sest nad raiskavad mitte ainult toitu, vaid ka maad, vett, energiat ja inimeste tööjõudu. Lisaks kemikaale ja väetisi tõttu, mõjutab toitu raiskamine keskkonnale. Et vältida toitu raiskamist, inimesed peavad iseendast harjutada.\nRiietusega situatsioon on ka väga halb, Moedisainer Eve Hanson ütleb „Ma näen taaskasutuspoodide laos vabatahtlikuks käies seda rõivaste kogust, mis tekib iganädalaselt juurde“. See tähendab, et inimesed raiskavad liiga palju riietusi. Inimesed raiskavad oma Hiina kaubamajandest riietust, sest tegelikult riietud koosnevad naftast, ja keegi ei taha seda kanda. Moedisaineri Eve Hansoni arvates, noored peaved sõida taaskasutuspoodidesse, et saada aru, milline raiskamine toimub. \nKokkuvõtteks võiks öelda, et nii toitu raiskamine kui ka riietust raiskamine on väga halb. Inimesed peavad iseendast harjutada, et seda vältida.');
