INSERT INTO core.text(id, content)
VALUES ('dae2d418-8d47-4bcb-955e-7bdd630bbbf3',
        '20. sajandi algus tähendab teaduse ja kultuuri kiirareng. Progress muutus elu lihtsamaks ning see tõi inimeste hooletut suhtumist ellu kaasa. Inimene muutus tarbijaks, eriti eurooplane, kuid palju inimesi kannatavad toidu, vee või riiete puudumise pärast. Kuidas seda vähendada?\n          Toodatakse liigseid kaupa, seetõttu inimesed viskavad ära ligikaudu 40% toidust, mida nad ostavad. Näiteks talurahvas, kes korjab banaane Brasiilias või teistel soojadel maadel, ei saa normaalset palka. Seega on lõpmatult oluline hinnata toitu, mda ostja omandab poes.\n          Tänapäevased moesuunad on suunatud tarbijale ja toodab mittekvaliteetseid riideid. Vaene kontoritöötaja ostab teksapükse, mis järgmisel kuul lähevad katki. Niimodi inimene kulub palju raha, ainult selleks et osta igakuu teksasid, kuid samal ajal viieaastane laps Indias töötab igapäev ilma söögita, selleks et värvida t-särgi, mida tulevikus kantakse vaevalt kask korda.\n          Hiina elanikud konstrueerivad autosid jamobiiltelefoone ja majasid väga kiiresti, kuid nende kvalitee soovib paremat. Hea tehtud arvuti kodus võiks teenida kaua, kuid omanik on sundinud teda vahetama tihti. Selle tõttu toodetakse liiga palju loodusele kuhjulikuid detaile. \n          Kokkuvõtteks võin ütelda, et iga töötaja on teeninud õigsust palka ära oma raske töö eest. On tarvis säilitada materjaleid töötlemiseks, sel juhul vaene laps Indias ei ole enam selline, loodus on kaitstud ja terve inimkond on õnnelikum.');
