INSERT INTO core.text(id, content)
VALUES ('3303821a-e2dd-4197-93de-07860fd4f15c',
        'Meie tänases elus tundub, et probleeme söögiga meil ei ole. Iga päev me saame hea ja värsket toitu, sööme seda ja ei mõtle sellest, mis toimub kui see toit rikneb ja me visatame seda ära. Eesti inimese kohta aastas keskmiselt tekib 61 kg toiduained, kuid 42% sellest visatatakse ära. Probleem on ka riides, mida noored kannavad.\nMiks see on paha? Tähtis on see, et kui inimesed ei tarbi kõik toitained, siis me kaotame oma maad, vett, energiat ja tööjõudu. Inimesed, kes võivad osta palju toitu ja pärast viskavad seda ära ei mõtle sellest, et on inimesed, kes ei saa palju süüa. Probleemi lahenduseks me peame osta vähem toitu ja süüa kõik seda ära.\nÜks meie tänasest probleemidest on seotud riietusega. Praegu noored ostavad palju asju Hiinast, kuid ei tea, millised probleemid sellega toovad. Taaskasutuspoodis tekib iganädalaselt juurde hunnikud korralike riide. On ka sellised, mis näevad hästi välja, kuid tegelikult koosnevad naftast. Moedisainer Eve Hanson arvab, et peab tegema noortele ekskursiooni taaskasutuspoodide lattu, et nad nägit, mis tegelikuld toimub riietega. \nPraegu on palju probleemi toiduga, mida lihtsalt visatatakse ära. Suur hunnik head asju viitakse taaskasutuspoodidesse. Lahenduseid nendele proobleemidele on palju, inimesed lihtsalt peavad mõistlikult osta asju.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('3303821a-e2dd-4197-93de-07860fd4f15c', 'title', 'Suur tuoidukadu ja taaskasutuspoed.');
