INSERT INTO core.text(id, content)
VALUES ('641184f4-3483-4105-9d1f-356b90fec528',
        'Peame hoolikalt jälgima oma tarbimisharjumusi. Inimestele meeldib osta, eriti löövad nende silmad särama, kui tegu on sooduskampaaniatega. Kuid selletõttu ostavad inimsed ka asju, mis kasutusse ei lähegi. Kuidas me saame seda vältida?\nKõige rohkem raisatakse toitu. Iga Eesti inimese kohta tekib aastas keskmiselt 61 kg toidujäätmeid, millest 26 kg ehk 42% moodustab toidukadu. Tegelikult peaks iga inimene, perekond, jälgima oma tarbimisharjumusi, mitte ostma nii palju, et seda keegi hiljem ära ei söö. Oluline osa on plaani tegemine enne poodi minekut. Kui seda ei tee, hakkavad su otsuseid mõjutama mitte sinu vajadused, vaid sooduskampaaniad. Nii ostadki liiga palju. On soovitatav osta tooteid, mis ei lähe kiiresti halvaks, muidu tihti ei jõuta need ära süüa. Oluline on ka jälgida kvaliteeti ning valida kallimaid tooteid kvantiteeti asemel.\nInimesed raiskavad ka väga palju riideid. Näiteks ostavad moodsa riideeseme, kuid ei kannagi seda, sest kehale ei ole see mugav. Tegelikult on oluline osta riideid, mida päriselt kanda kavatsed ning peale kasutamist anda neile uut elu. Näiteks annetada vaesematele inimestele või taasakasutada. Nii saame vältida riiete raiskamist.\nPeame õppima, kuidas raiskamist vähendada. Looma plaane, ostma vähem, vaatamata soodustustele ning taaskasutama riideid. Nagu soovitab moedisainer Hanson, peame kõik vaatama üle oma isiklikud tarbimisharjumused ning eelistama kvaliteeti kvantiteedile.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('641184f4-3483-4105-9d1f-356b90fec528', 'title', 'Meie tarbimisharjumused');
