INSERT INTO core.text(id, content)
VALUES ('0e351e30-ba44-4802-a6d7-8d1d55abb95e',
        'Meie ajal, meil pole mingid murud, kas lõppeb toit või ei. Me tarbime, raiskame, inimesed ei väärtustavad seda, mis nendel on. Toitu viskavad nii palu, et võiks selle toiduga päästa tuhandeid, kümne tuhandeid või rohkem inimesi. Me ei tähtsustame toitu. Miks nii toimud ja kas võime me midagi teha?\nMiks nii toimub?- Tehnoloogiat meie ajal on väga arendatud, inimesed tegid suured talud, kus kasvatavad loomaid, taimed. Oleme unustanud, kuidas on näljutama. Inimesed unustasid, ja järele jäätnud tähtsustamine. Toit kadus oma tähtsus, ainult Eestis üheks inimeseks kuulub 61 kg raisatud toidu. Me raiskame maa ressurssid, kui raiskame toidu, raiskame ka maad, energiat ja tööjõudu. Väga vähe, kes teab sellest probleemist ja on informeeritud, kui palju me raiskame. \nKas võime midagi teha?- Võime. Peab alustama iseennast. Viskame toit, raiskame toiduained, peab seda lõppetama. Vaja leida tähtsus ja saama aru, kuidas raiskamine mõjutab maa peale. Võiks ülejääk anda abitarvitajale, nt kodutu, pensionärile, lastekodulapsele. Võiks ka ei osta nii palju, et oleks ülejääk. Lahenduse varianti on palju, sõltub inimeste sooviga lahendada ja päästa maa.\nKui palju on raisatud toidu, sõltub inimestest. Probleemi lahendamine algab iseennast, ja kui sa miite midagi ei tee, siis on meil probleemid raiskamisega. Inimesed järele jäätnud toitu täthsus. Selleks, et lahendada probleeme, peame alustada tähtsustama toit.');
INSERT INTO core.text_property(text_id, property_name, property_value)
