INSERT INTO core.text(id, content)
VALUES ('b191a581-a360-4bc2-9890-a3258208df65',
        'Inimesed raiskavad palju erinevaid asju: toitu, riideid, pabereid jms. Kas on üldse võimalik teha nii, et inimesed kasutaksid kõik, mida nad ostavad, ja mitte viskaksid seda prügikasti, kui pole seda enam vaja?\nIga aasta, tavaline Eesti inimene tekib keskmiselt 61kg toidujäätmeid, millest 26kg visatakse ära. Me raiskame mitte ainult oma raha, vaid ka maad, vett, energiat ja tööjõudu, ärge unustage ka sellest, et toitu tootmise ajal kasutatakse erinevaid väetisi ja kemikaale. Toidu raiskamine on suur probleem, mida pole võimalik ühe nädalaga likvideerida, aga võib juba praegu hakata proovida raisata vähem toitu. Minu pere on juba harjunud sellega, et võib kasutada ülejäänud toitu teiste asjade jaoks, näiteks, koera toitmiseks.\nRiietuse raiskamine on ka tõsi asi. Inimesed toovad oma vanad riideid taaskasutuspoodidesse, ja üldse ei tea, kuidas nad võiksid seda ise taaskasutada. Moedisainer Eve Hanson arvab, et noortele võib teha ekskursioone taaskasutuspoodidesse selleks, et näidata, kui palju riietust inimesed ära viivad, kui need pole enam tarvis. Minu arvates, võib vanad riideid kasutada selleks, et pesta põrandaid.\nAsjate raiskamine on tõsine teema, mida õpetajad koolides peavad arenema noorte seas. Selleks, et toitu mitte raisata, võib osta vähem või muul viisil seda kasutada, sama lugu on riietustega. Kui me vähendame asjade raiskamine, siis maailm saab muuta ainult paremaks.');
