INSERT INTO core.text(id, content)
VALUES ('2993966b-da41-459a-945d-4eb39af6520a',
        'Probleem on sellest, et inimesed viskavad ära toitu, mis on veel tarbimiseks tegelik ja nad mõtlevad, et toitu on veel ja see ei saa otsa. On inimeseid, kes raiskavad toitu sest nad saavad endale veel rohkem neid raiskata. Ka raisatud toit on toiduaine  mis mingil põhjusel , näiteks söömisel jäänud toit jääb tarbimata ja visatakse toidujäätmena ära. Seega sellest me raiskame tohutult muid ressursse: maad, vett, energiat, ja tööjõudu. Ning lisaks tekitab toidu tootmine keskkonnakoormuse, sest tõstmiseks kasutatakse väetisi ja erinevaid kemikaale. Aga toidu raiskamist ei saa vähendada üleöö, sest see on paljuski kinni inimeste harjumustes. Põhiseisukohtaks võib öelda, et inimesed, kes elavad Eestis, tekib neil kohta aastas keskmiselt 61 kg toidujäätmeid , millest toidukadu moodustab 26 kg ehk 46%. Oma näide põhjal , kui ma olin kodus ja sõin pool taldriku riisi ja pool kana , siis viskamisel mul jäi pool taldrikku riisi , sest ega ma armastan süüa riisi aga mitte nii palju. Teises kirjandis on probleem , et Hiinast tellitud veebipoodist võib tulla mitte kvaliteetne pakk ja peaks noortele näidata , milline raiskamine toimub. Näideks mõnikord viiakse korraliku riideid aga selliseid mis reklaamfotol näevad ilusasti tegelikult koosnevad koledast materjalist. Sellised rõivad on pärit suurtest kuulsatest Hiina kaubamajadest. Kokkuvötteks on see , et inimesed ei suuda ise kontrollida.');
