INSERT INTO core.text(id, content)
VALUES ('c389a6f2-21b9-45c1-88a2-83ac8aac2786',
        'Inimesed raiskavad toitu mõtetega, et see midagi ei mõjuta, aga küll mõjutab! Inimesed ostavad toitu mida pärast ei kasuta ja toit läheb prügi toidujäätmena ära. See aga ei mõjuta ainult inimese raha, aga ka maakonda. Mõjutab selliseid ressurse nagu: maad, vett, energiat ja tööjõudu. \nIga Eesti inimese kohta aastas tekib keskelt üle 61 kg toitujäätmeid. On kohustuslik, et inimesed saaksid aru kuidas toitu õigesti raisata, et polnud nii palju toidujäätmeid. Muidu toidu raiskamist ei saa vähendada üleöö, sest see on plajudel inimestel juba kinni harjunud, aga kui me näiteks noori õppetlasime kuidas tegelikult toimub raiskamine, kas saame ju minge muutmist. \nNoortel on populaarne asju Hiina veebipoestes osta, just sellest noort võib õppetlema ja teha ekskursioone taaskasutuspoodide lattu, et näidata kuidas ja milline raiskamine tegelikult toimub ja mis see teeb. Mitte kõik asjad, riided nt, mis näevad reklaamfotol hästi välja on head, sest tõeliselt koosnevad nad naftast ja sa ei saa rohkem kui üks kord neid riideid kanda, sest kehale see teeb lihtsalt halb. \nSaime teada, et on väga oluline jälgida toitu raiskamisest, püüda toitu korralikult osta ja kasutada, et ei läks toit lihtsalt prügi, sest just see mõjutab kõige rohkem maakondade ressurse. Noortele aga õppetleda kuidas raiskamine toimub, et mitte kõike mida hästi välja näeb veebipoedest osta.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('c389a6f2-21b9-45c1-88a2-83ac8aac2786', 'title', 'Inimeste toidu raiskamine');
