INSERT INTO core.text(id, content)
VALUES ('2f5d5d8e-fb38-4108-9036-ba2b79c1e629',
        'Tänapaeval iga üks oma kodus ei näe, kui palju ta või tema peres toitu maha viisatakse. Eestis keskmine inimene iga aasta tekkib umbes 61 kg toidujäätmestes ja keskmiselt 26 kg on raisatud toit. See toit jääb tarbimata ning raiskab palju energiat, et selleks said lihtsalt prügi, mille koht on prügikastis. Seda võib ka muuta, näiteks minna poodi koos lehtega, kus on kirjutatud mis on täpselt vaja ja mitte osta toode liiga suure pakki. Veel on ka parem minna poodi, kui sul on kõht täis. See aitab mitte võtta rohkem, kui inimene elab üksinda või lihtsalt saab süüa. Peab see aitama, et nii palju toitu ei läksid prügikasti niisama.\nPaljud inimesed soovivad rohkem osta riideid veebipoodidest, mis on tehtud riigides nägu: Hiina, India, Vietnam, Tai, Laos jms. Selle poodi asja hind on palju väiksem, kui tavasistes poodidest õues ja kellegile on see väga hea pakkumine, aga kuid see riideid tehakse naftast, plastikust ja muud materjalidest, mis on nahale võib olla ohtlik ning see materiaal, millest koosneb see asi on liiga lihtne ja ei kanda seda rohkem kui üks kuu. Selles on vaja rohkem vaadata riigile, miks nende elanikud ei saa osta endale hea, uut ja oma poodidest riideid.');
INSERT INTO core.text_property(text_id, property_name, property_value)
