INSERT INTO core.text(id, content)
VALUES ('a762a086-b89c-42e5-824a-9cc3430b21d0',
        'Tänapäeva üheks suurimaks keskkonna probleemiks on inimeste halvad tarbimisharjumused. Inimesed tarbivad ostavad palju sööki, aga nädala lõppuks midagi ikka lendab prügikasti, olgu see riknenud-, kasutustähtajast ületanud- või ülejäänud- toit. Paljud arvavad, et kui nemad natuke sööki prügisse viskavad ei muutu väga midagi, aga see ei ole nii tegelikuses. Paljud Hiinas toodetud riided on kehva kvaliteediga ja tehtud naftast, need riided kiiresti rikkuvad, selle pärast neid visatakse ära.\nToidu raiskamisega me kaotame mitte ainult omaenda raha, vaid raiskame ka tohutult palju muid ressursse: maad, energiat, vett ja tööjõudu. Toidu tootmine tekkitab tõsise keskkonnakoormuse, kuna tootmise ajal kasutatakse väetisi ja erinevaid kemikaale, mis annavad võimaluse rohkem saaki lühema aja perioodil kätte saada. Need kemikaadid on loodusele kahjulikud.\nKuidas ütles Eve Hanson „Ei telliks Hiinast põhimõtte pärast asju, ei läheks kaasa sooduskampaaniad“ ja „Eelistada võiks kodumaiseid oma lähedal toodetud asju ning pigem vähem kui rohkem“ see tähendab, et tuleks asju kodumaist tellida ja kindlasti mitte Hiinast, kuna siis lükate selliste asjade tootimist edasi.\nKokkuvõttes on paljudel inimestel ikka tarbimisharjumustega probleemid, ostavad palju ja raiskavad palju, aga on veel aega seda parandada, selleks on vaja seda teemat edasi lükata. See on aeglane protsess, mis vajab kannatlikust, kui lõppuks sellega hakkama saame, oleme kõik õnnelikumad.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('a762a086-b89c-42e5-824a-9cc3430b21d0', 'title', 'Tarbimisharjumused');
