INSERT INTO core.text(id, content)
VALUES ('b55f0472-0df3-4a36-9b39-0ab6305b8e4f',
        'Tänane teema minu kirjandist on toidu raskamine, toidu raiskamine on probleem üle maailma kui rääkima eestist siis statistika näitab, et keskmiselt iga eestlane jätab umbes 61 kg toidujäätmist millest toidukadu moodustab 42 protsenti ehk 26 kg.Kui rääkima sellest probleemist nagu toidukadu ehk raisatud toit või toiduaine siis tuleb kurb statistika, et näiteks banaani koor oli läinud natuke mustaks paljud inimesed viskavad teda ära aga sees banaan nagu oli ilus ja magus siukene ja jäänud.Väga populaarne on ka muid resursse raiskamine siukest nagu maad, vett, tööjõudu ja energiat paljud inimesed näiteks kui lähevad ruumist välja ei kustutavad tuli või ei lülitavad lampi, on ka populaarne kui näiteks pesed hambad ja ei paned vett kinni.\nKui rääkida siukest probleemist nagu riete raiskamine praegu on ikka see probleem läinud populaarsemaks et varem inemnesed kui nendele mingi asi ei sobinud lihtsalt viskasid prügikasti ja nii edasi praegu ma arvan rohkem kui pool panevad kasutatud riided riidekonteenerisi ja paljud inemesed hakkasid ostma mitte täielikke uute asju vaid juba natuke kasutatud asju taaskasututes poodidest suikse nimedega nagu Humana, Uuskasutuskeskus, Kilomax ja nii edasi.Minu jaoks ma saan öelda niimodi et mitte üks ekskursioon taaskasutuspoodi lattu ei mängi lapse jaoks suurt rolli pigem on parem variant lihtsalt rääkida lapstega sellest prooblemist ja küsida mida nad sellest arvavad.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('b55f0472-0df3-4a36-9b39-0ab6305b8e4f', 'title', 'TOIDU RAISKAMINE');
