INSERT INTO core.text(id, content)
VALUES ('fd777bdc-5dac-43fe-9a0d-a468ad51682b',
        'Selles peatükkis meil rääkivad, et toitu on veel ja väga palju ja see ei saa otsa. On inimesed, kes raiskavad toitu ja nendel on ükskõik sest nad teevad endale lubu. Minu jaoks see ei ole täitsa hea, ma ei saa lihtsalt visata toitu. Eestis iga inimese kohta tekib 61 kg toidujäätmeid ja toidukaudu 42% ehk 26 kg. Eestis väga palju inimesi lihtsalt ei tarbi ja mitte sorteerivad toitu ja toidupakendeid , sellel põhjusel eestis toit jääb tarbimata ja visatakse toidujäätmena ära. Veel üks problem selles,et seetõttu me raiska meie raha,maad, vett, töjõudu ja energiat. See on väga olulised ressurssid, sest lihtsalt inimesed ei tarbi toitu. Peate teadma, et üleöö ei saa toidu raiskamist vähendada. See on palju inimeste harjumustes.\nOlen nõus selles, et noortele peaks tegema ekskursioone taaskasutuspodide lattu. Moedisaineri Hansoni on oluline,et igaüks ehk mitte ainult noored vaatasid üle oma tarbimisharjumused nin eelistaksid kvaliteeti kvantiteedile. On arvamus,et võib ju eelistada kodumaiseid läheadal toodetud asju. Pigem vähem kui rohkem.\nHanson väga tahtis teha noortele ekskursoiine taaskasutuspoodide lattu selleks et, näidata neile milline raiskamine tegelikult toimub. Primeeriks ta tahab viia sinna korralike riideid, vaid ka sellised mis kauinil reklaamfotol näevad ilusasti välja aga tegelikult koosnevad naftast ja sa ei taha rohkem selle riideid kandma kunagi.');
INSERT INTO core.text_property(text_id, property_name, property_value)
