INSERT INTO core.text(id, content)
VALUES ('11b7c473-ec66-4367-922f-b51319c657dd',
        'Tänapäeva ühiskonnas on tarbimine muutunud elu lahutamatuks osaks,kuid sageli ei mõtle inimesed oma harjumuste tagajärgedele. Toidu raiskamine ja kiirmoe on kaks suurt probleemi,mis mõjutavad nii keskkonda kui ka majandust.\nesiteks on toidu raiskamine tõsine probleem. Paljud inimesed arvavad,et väikesed toidukogused,mis prügikasti visatakse,ei avalda suurt mõju,kuid tegelikult koguneb see suurteks arvudeks. Nagu aluseks olev tekst mainib,tekib Eesti keskmiselt 61kg toidujäätmeid inimese kohya aastas,millest märkimisväärne osa on toidukadu.See tähendab,et suut hulk ressurse,nagu vesi,energia ja tööjäud, läheb raisku.\nTeiseks on kiirmoe ületarbimine suur probleem. Moedisainer Eve Hansoni sõnul peaksid noored eelistama kvaliteetseid ja vastupidavaid rõivaid kvantiteedile. Kiitmood julgustab inimese pidevalt uusi riideid ostma,mis põhjustab tohutut keskkonnakoormust ja ebavajalikku raiskamist.\nKokkuvõttes on inimese tarbimisharjutused sageli hoolimatud ning põhjustavad nii majanduslikke kui ka ökoloogisi probleeme.Selleks,et olukorda parandada peaksid inimesed muutma oma käitumist teadlikumaks-ostma ainult vajalikke tooteid ning eelistama kvaliteeti kvantiteedile. Väikeste sammudega saab kaasa aidata suurtele muutusele. Teadlik tarbimine aitab vähendada raiskamist ja kekkonnakahju. Väikseim toidukadu ja vastupidavamad rõivad säästavad ressursse. Harjumuste muutmine on oluline jätkusuutliku tuleviku jaoks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('11b7c473-ec66-4367-922f-b51319c657dd', 'title', 'Inimeste tarbimisharjumused ja nende mõju');
