INSERT INTO core.text(id, content)
VALUES ('9ede60dc-d8da-4a3f-86d2-80ab73fb1b2b',
        'Kõik me sööme toitu ja mõni toit me ka viskame ära, sest see toit on riknenud või kasutustähtaja ületanud.Ja iga nimene ka mõtleb, et kui ta üksi ja mõnikord niimoodi teeb siis suurt pilti see pisike toidujäätme ei mõjuta.Kuidas kõik teavad, et Aafrikas paljud lapsed ei saa süüa, sest lihtsalt pole sööki aga tavalised inimesd lihtsal viskavad näiteks bannani, sest ta sai natuke pruunikam kui oli poes.Paljud inimesed võivad küsida“Mis siis teha kui toit on juba mittesöödav?“\n Et mitte visata palju toitu prügikasti peab aru saama kui sa ostad poes, kui palju see toode saab sinu külmkappis olla ja kui kiiresti sa saad seda süüa,et toit ei läks prügikasti.\n Kui sa näed,et toidu kasutustähtaeg hakkab ületada ja sa ei taha seda süüa võid minna õues ja proovida anda seda toit kellelegi kes ei saa süüa nägu sina kolm korda päevas.Näiteks võid anda seda sööki inimestele kellel pole kodut või kui see on mingi lihatoode siis võid anda ilma koduta kassidele või koeradele.Aga pead kõige pealt vaadata,et toit polnud väga riknenud.\nPaljud inimesed ei saa aru, et toit saab mõne aega pärast lõppema ja seda ei tohi palju raiskama,sest see on väga ohtlik.');
