INSERT INTO core.text(id, content)
VALUES ('d1bd743e-0dbd-47e5-8826-ed6fa971e8e2',
        'Inimesed tarbivad iga päev väga palju ning enamik inimesi ei mõista, et nad võivad liigselt tarbida ning reostada loodust. See peab muutuma, aga miks on inimestel sellised tarbimisharjumused?\nTänapäeval toodetakse enamik toitaineid pakendites ning need pakendid ei ole loodusele kõige sobilikumad. Inimesed ostavad poest näiteks kotitäis puu- või juurvilju ja siis pärast on see sama kilekott tee kõrval maas. See ei sobi loodusele üldse ning see on väga suur probleem inimeste tarbimisharjumustes. Inimestel on see harjumus sellepärast, et nad päriselt ei tea, kui palju see reostab loodust ning see peaks kiiresti muutuma. Probleemi lahendamiseks saaks teha niimoodi, et kui inimesed näevad kõndides kilekotte või muud pakendeid ja prahti maas, siis nad võtavad selle ülesse ning viskavad prügikasti. See aitaks meie loodust väga ning arendaks inimeste tarbimisharjumusi.\nLiigne tarbimine on ka väga suur probleem tarbimisharjumuste suhtes ning tuleks koheselt muuta. Tihti jääb suur kogus toidujäätmeid inimestel alles, kui nad söövad ning see toit visatakse lihtsalt minema. See on raiskamine ning see pole üldse sobilik viis, mida toidujäätmetega teha. Liigse tarbimise probleemi saaks lahendada niimoodi, et kui jääb toitu üle, siis selle saaks jätta alles ning hiljem ära süüa või anda see kellelegi teisele, kes tahaks selle ära süüa. Toidu valmistamiseks kulub väga palju aega ja raha ning liigse tarbimise probleemi lahendamisega muutuksid inimeste tarbimisharjumused veelgi paremaks.\nInimestel on halvad tarbimisharjumused, kuna nad ei mõista, mis väärtus on sellel, mida nad tarbivad ning kuidas nad reostavad loodust. Seda saab küll muuta, kui inimesed korjaksid prügi ülesse ning toidujäätmed säästaks ja hiljem ära sööks. See aitaks loodust ning arendaks inimeste tarbimisharjumusi.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('d1bd743e-0dbd-47e5-8826-ed6fa971e8e2', 'title', 'Inimeste tarbimisharjumused');
