INSERT INTO core.text(id, content)
VALUES ('885449c9-d9c0-4712-9ca6-574288c1a5f8',
        'Inimeste tarbimisharjumused muutuvad aina suuremaks, aga tarbimisjäätmed seetõttu ka. Iga aasta tekib meeletul hulgal toidujäätmeid ja muid tarbimisjäätmeid, mida ära ei tarbita. Aga miks tekib siis tohutult toidujäätmeid? Miks me tellime Hiina veebipoodidest riideid või lahedaid tooteid, mida me hiljem ei kasuta halva kvaliteedi tõttu ning kuidas me saaksime tarbimisharjumust parandada?\nToidujäätmeid tekib igal aastal väga suures koguses, keskmiselt 61 kg ühe inimesekohta. See näitab, et me raiskame toitu liiga palju. Paljud inimesed arvavad, et see on normaalne, sest nad saavad endale seda lubada, kuid ei mõelda sellele, millised keskkonnaprobleemid see endaga kaasa toob. Toidu mittetarbimine raiskab nii meie raha kui ka teisi ressursse. Toitu ei tohiks osta korraga nii suurtes kogustes, kui seda ei suudeta ära tarbida, kuid seda ei saa muuta äkitselt, sest see on paljudel inimestel harjumuses.\nHiinast tellitakse üsna palju riideid ja teisi huvitavaid tooteid, mida peetakse vajalikuks või tellitakse lihtsalt selleks, et tellida midagi lahedat, mis on soodsam kui Eestis. Tihti on need tooted väga kehva kvaliteediga või riided halvast materjalist ja visatakse siis prügikasti. Nii tekib jälle suures koguses tarbimisjäätmeid. \nMe kõik peaksime rohkem mõtlema keskkonna heaolule. Ei tohiks nii suurel hulgal toitu ära visata ning tuleks osta tooteid mis on hea kvaliteediga meie kodumaalt mitte tellida Hiinast halva kvaliteediga palju erinevaid tooteid, mis lähevad kõik prügikasti ja tekitab suure koguse tarbimisjäätmeid. See parandaks meie halba tootmisharjumust ja vähendaks keskkonnaprobleeme.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('885449c9-d9c0-4712-9ca6-574288c1a5f8', 'title', 'Miks tekivad tarbimisjäätmed?');
