INSERT INTO core.text(id, content)
VALUES ('db85a5a2-9e6e-46c9-b04d-e0b1d7123c26',
        'Inimesed on igapäevaselt harjunud tarbima. Paljud inimesed tarbivad aga väga raiskavalt ja hooletult. Paljud inimesed võiksid hoolikamalt tarbida ja üldse oma tarbimist vähendada, kuid nad ise tunnevad, et nende tarbimine ei mõjuta ümbritsevat maailma nii palju, kui mõni muu. Miks on siis sellised tarbimistavad tekkinud?\n    Me oleme harjunud sööma toitu suurtemates kogustes, kui varem. Paljud inimesed pärast suuremat söögikorda, näiteks pärast lõunasööki, on harjunud võtma mingi snäki või lihtsalt veel peale sööma. Selle snäki ajal aga saab mitmetel kõht täis ja nad ei taha enam lõpuni süüa. Selline tegevus raiskab rohkelt söögivara ja me kõik võiksime natuke sellise asja peale mõelda.\n     Paljud ostavad pigem odavamalt ja rohkem, kui kallimalt ja vähem. Selline mõtteviis on kahjulik, sest ostetakse kuskilt Hiinast omale odavaid särke, mis neile endale ka ei meeldi. Paljud ostavad odavaid riideid lühiajaliseks kasutamiseks, et need siis pärast näiteks taaskasutuskeskusesse viia. Miks osta odav ja ebamugav riideese, kui sa saaksid natukese suurema raha eest endale kvaliteetse riideeseme, millega pikka aega käia?\n      Probleemid inimeste tarbimisharjumistel on söögi raiskamine, mida paljud enda elus isegi tähele ei pane, ja odavate riiete ostmine, mille kaudu ei osteta riideid eestist ja sellekäigus koormatakse taaskusutuskeskuseid. Need paar näidet võiks anda inimestele märku, et midagi on meie igapäevaelus vaja muuta.');
INSERT INTO core.text_property(text_id, property_name, property_value)
