INSERT INTO core.text(id, content)
VALUES ('be8f5ba9-56de-46c5-9837-2820a205c5f4',
        'Inimeste tarbimisharjumused muutuvad järjest kahjulikumaks keskkonnale. Paljud mõtlevad, et kui nad natukene ära viskavad ei juhtu midagi, aga kui suur enamus niimondi mõtleb, siis lõpuks on raiskamist palju. Mida üldse raisatakse ja kas seda oleks võimalik kuidagi vähendada?\nToitu raisadakse suurtes kogustes. Tarbitoitutargalt.ee artiklist võib välja lugeda, et keskmiselt tekib Eesti inimese kohta 61 kg toidujäätmeid ja 26 kg toidukadu, mis on päris palju. Toidu raiskamist saaks, aga vähendada, kui näiteks hakata jälle kodus osasid toiduaineid kasvatama. Tegelikult pole meil ka tarvis maiustusi ja snäkke poest osta ja vahest osa neist ära visata, kui meil on võimalused neid ise kodus teha täpselt nii palju kui me ära sööme.\nTarbitakse ka tohututes kogustes riideid. Lihtne on osta odavatest kiirmoe poodidest palju riideid ja neid paar korda kanda, kuigi võiks osta paar kvaliteetsemat riide eset ja nendega kordades kauem käia. Suur mõju tegur on ka sotsiaalmeedial ja ühiskonnal, kuna mida suurem on  riidekapp, seda parem on, näiteks mõnda asja üle kolme korra kandes saab juba inimestelt tihti halvustavaid pilke.\nInimesed tarbivad kohutavates kogustes, kuigi seda oleks võimalik väga lihtsalt vähendada, aga paljud isegi ei saa aru, et tarbitakse liigselt ja see teglikult on probleem. Inimesed võiksid rohkem tähelepanu pöörata, sellele mida ja kui palju raisadakse ja kuidas oleks seda võimalik vähendada.');
