INSERT INTO core.text(id, content)
VALUES ('d3c74085-4e55-4879-8386-801cf15f518c',
        'Inimesed tarbivad igapäevaelus erinevaid tooteid.Inimestel on harjumuseks tarbida toitaineid ja erinevaid kemikaale sisaldavaid aineid.Inimesed peavad tarbima igapäevaelus toitaineid ja teatud tooteid veel mis laseb neil elus püsida.Selle järel tekibki küsimus kas tarbimine on kallis?\nToitained on inimeste igapäevaelu üks osa,iga inimene peab tarbima toitu,et ellu jääda.Võrreldes 10 aastat tagasi oli tarbimine palju odavam kui nüüd 2025 aastal.Selle aja jooksul on maailm läbinäinud mitmeid kriise.Maailmas on palju inimesi kelle palk ei lase tarbida samu tooteid mida nad said tarbida 10 aastat tagasi kuna maailmas on eluhind tõusnud.Nagu inimesed ise öelnud:“Elu pole odav!“.\n10 aasta jooksul on turule toodud erinevate kemikaalidega sisaldatud tooteid,näiteks e-sigarett ja muud tervist kahjustavad ained.Nagu vanasõna ütleb:“Elu pole prügi,et seda ära visata“.Inimesed kes neid kemikaale tarbivad ei pruugi ise tähele panna kui kiiresti nende teenitud palk kulub tervist rikkuvale ja sõltuvust tekitavale kemikaalile.Inimesed ei pööra tähelepanu sellele millega nad enda tervist rikuvad, kui ka mitu korda hakkab nende väljaminek tõusma ja raha kulub vähem oma riiete ja söögitarvete peale.\nKokkuvõtteks on aastate jooksul inimeste tarbimisharjumused hakanud erinema kuna tooted on kalliks läinud,turule on toodud aineid mis kahjustavad tervist ja suurendab osaliselt inimeste väljaminekut.Inimesed on hakanud kulutama raha asjadele mis pole neile kasulikud ja rikuvad  tervist.');
