INSERT INTO core.text(id, content)
VALUES ('418683a4-5653-42a0-99a5-0e0bd29cffa3',
        'Inimeste tarbimisharjumused ei ole olnud kõige paremad aastate jooksul ja seda tuleks inimestele pidevalt öelda, et toit ja rõivad ei tule iseenesest ja selleks kulub palju ressursse. Mida tuleks teha, et inimesed ei raiskaks, ega viskaks toitu lihtsalt ära, vaid teeks midagi uut sellest ja arvestaks kuludega?\nKui inimesed jätkavad toidu minema viskamist ja liiga suurtes kogustes söögi tegemist, siis meil ei ole varsti tooraineid, millest toitu valmistada ja see tuleks meile kõigile  suureks probleemiks. Tekkida võibki tooraine puudus ja, kui ei jõuta sama kiiresti kasvatada kui tarbida, siis lõpuks halvimal juhul tekib meil näljahäda ja inimesed hakkavad ükshaaval surema. Selle asemel, et toitu ära visata saab näiteks vanaks läinud banaanist teha banaanileiba ja siis ei lähe toit raisku ja nii ei teki ka suur keskkonnakoormus.\nInimesed tarbivad ja ostavad  liiga palju kvaliteetseid rõivaid ja see ei ole kõige parem asi mida teha kuna iganädal tekib aina taaskasutusladuesse rõivaid juurde. Seal on rõivaid, mis on täiesti kasutuskõlblikud aga inimene ei kanna neid, vaid viibki sinna kvaliteetsemaid asemele. Inimsed võiks aru saada ja ise näha, kui palju tekib ja on rõivaid iganädalaselt taaskasutusladudes, et nad saaksid oma käitumist ja olukorda muuta. See tooks kaasa taaskasutusladudesse vähemuse ja inimesed õpivad kandma taaskasututud rõivaid kvaliteetsemate asemel.\nInimesed tarbivad liiga palju ja ei oska midagi peale hakata selle kõigega ning seejärel tekibki suur tarbimisharjumus. Inimesed pole mõelnud sellele kui palju ressursse ja, kui palju keskkonnakoormust see tekitab.');
INSERT INTO core.text_property(text_id, property_name, property_value)
