INSERT INTO core.text(id, content)
VALUES ('3491f6e7-1dae-4d25-8144-9c69a9f8ba46',
        'Maailmas on tohutult palju raiskamist. Raisatakse raha, ostes midagi, mida pole vaja. Raisadakse ressursse, mille abil on kõik valmistatud. On inimesi, kes raiskavad kuna neil on raha, aga on ka inimesi, kes arvavad et nad sellega palju kahju ei tee.             Toidu raiskamine on probleem. Inimesed tihti ostavad endale liiga palju toitu ja ei kasuta seda kõike piisavalt kiirelt ära. Alles hiljem kui see toit enam kõlblik pole, panevad inimesed seda tähele. Kuna toit enam ei kõlba süüa visatakse see ära. Iga inimene raiskab ära keskmiselt 61kg toitu ja toiduaineid.                                                        Peaksime ostma seda, mida meil vaja on. Raiskame liialt raha toidule, riietele, nutiseadmetele, mis meile võibolla ei meeldi või siis me hoopis ei vaja seda, ega ka kasuta. Oleks vaja rohkem mõelda oma ostutele. Inimesed, kellel on palju raha raiskavad mõttetult kuna neil on see võimalus. Aga tegelikult me kaotame sellega lihtsalt raha ja ressursse. Kasulikum oleks osta oma enda riigis toodetud asju, et toetada enda riiki ja inimesi.                                                                                                            Toitu ostetakse liiga palju ja seda ei suudeta õigeks ajaks ära tarbida, ning kõik , mida ära ei tarbitud läheb lihtsalt raisku. Inimesed raiskavad keskmiselt 61kg toitu ja toiduaineid. Rikkad inimesed ei mõtle oma ostudele piisavalt, kuna neil on palju raha. Peaksime rohkem mõtlema oma ostudele ning pigem ostma enda riigist, et toetada meie riiki.');
