INSERT INTO core.text(id, content)
VALUES ('86c90320-5423-4331-a3f7-6604bbc589a5',
        'Terves maailmas visatakse ära palju riideid ning kedagi ei huvita kuhu see läheb või jääb.\nRiiete ära viskamine on väga suur probleem, ning taaskasutamist ei saa vahepeal teha, näiteks, kui mu soki sisse tuleb suur auk, siis ma viskan selle ära, aga kui see on väike, siis ma saan selle kokku õmmelda. Sokkide või särkide ära viskamine on väga tavaline, kuid neid on võimalik ka ära parandada. Nagu Moedisainer Eve Hanson ütles, „Ma arvan, et peaks hakkama tegema noortele ekskursioone taaskasutuspoodide lattu, et näidata milline raiskamine toimub“\nHiinast ostetakse päris palju riideid, mis on, kas halva kvaliteediga või lihtsalt liiga väike/suur. Hiinast saab kõike soodsamalt, aga samal ajal need riided, mida sealt ostetakse ei ole nii head kui piltidel või lihtsalt ebamugavad, niiet inimesed viskavad need ära vöi viivad taaskasutusse, kus mitte keegi neid ei osta, sest need on ebamugavad. Eve Hanson ütles, et „taaskasutuspoodides on korralikke riiedeid, aga ka sellised, mis näevad ilusad välja, aga tegelikult koosnevad naftast.“\nKui osta riideid, tuleks neid osta, kas poest või mõnest populaarsest/usaldatud neti poest, sest siis on teada, et see riide toode on kvaliteetne ning ei lähe katki. Hiinast ostes on vaja meelde jätta, et see hakkab olema halva kvaliteediga, ning see visatakse päris kiiresti, kas prügikasti või viiakse taaskasutuspoodi, kus neid keegi ei osta.\nRiiete ära viskamine ei ole üldsegi hea, ning paljud ostavad Hiinast rämpsu, mis on nende kehale kas halb või väga ebameeldiv kanda. Taaskasutuskeskustes on nii palju Hiina rämpsu, mis näeb hea välja aga on väga ebamugav niiet keegi ei osta neid.');
