INSERT INTO core.text(id, content)
VALUES ('8cfa0fb5-c2a2-410b-86c4-84ffda2b2476',
        'Tänapäeva maailmas tarbitakse väga palju. Esemed, mis on väikseks jäänud, katki või üle aja läinud, kulunud või lihtslt ei meeldi enam, visatakse kõik minema. Sellega tekitatame suuretes kogustes prügi ning reostame oma elukeskkonda.\nIganädalaselt tekib taaskasutuspoodidesse juurde meeletud riide hunnikud. Ostetakse riideid, mis visatakse juba mõne päeva pärast minema. Üheks põhjuseks on kvaliteet. Suur osa riideid tellitakse välismaalt, sest need näevad pildil head välja. Hiljem kui riideid selga proovitakse, selgub, et nende kvaliteet pole hea ning neid on ebamugav kanda. Enne tellimist peaks kindlaks tegema, kas see pood, kust tellitakse, on usaldusväärne ja riided hea kvaliteediga\nSuured allahindlused püüavad inimesi lõksu. Paljud jooksevad kiiruga poodi, kohe kui kuulevad allahindlustest. Ostetakse riideid ja erinevaid seadmeid, mida ei ole vaja. Hiljem koju jõudes, avastatakse, et need tooted isegi ei meeldi või pole neid kuhugi panna. Kõik need ebavajalikud asjad visatakse minema. Sellise tegevusega raisatakse raha ning tekitatakse juurde uut prügi. Enne ostmist tuleks hoolikalt kaaluda, kas peaks sellele ostule raha kulutama.\nIga ostu puhul, peab hoolikalt mõtlema, kas see ost on ikka vajalik. Välismaalt tellitakse kokku suurtes kogustes riideid, kosmeetikat ja teisi huvitavaid vidinaid. HIljem avastatakse, et neil on kehv kvaliteet või on need katkised. Samuti ajavad inimeste pead segadusse suured allahindlused. Sellistel hetkedel ostetakse asju, mida pole vaja. Kõige selle tõttu toodetakse palju prügi ning raisatakse raha ja ressursse.');
