INSERT INTO core.text(id, content)
VALUES ('eefc12bc-92fc-407c-9491-083ce1cf8341',
        'Mida peaks muutma, et asi läheks paremaks?\nMa olen näinud palju inimesi kes lihtsalt viskavad riideid ja toitu ära. Riideid visetakse ära kuna need on väiksed ja kulunud. Toitu visaatakse ära kuna seda sai võetud liiga palju. Tihtipeale ei mõelda selle peale, et riideid saab annetada ja toidu portse vähendada ja kui ikka on kõht tühi saab alati juurde võtta. Minu seisukoht siin kohal on selline, et kõik inimesed on võimelised enda toidu koguseid kontrollima ja riideid on võimalik taaskasutada ja neid ei pea kohe ära viskama, kui need on katki, vaid need saab korda teha ja uuesti kasutada.\nMinu pere teeb ika aasta 2 suurpuhastus päeva, kus käime üle kõigi riided ja kui miski on väike sulle siis läheb see sinust nooremale. Süües midagi arvestame kõik sellega kui palju me toitu võtame, et ikka kõik söödud saaks ja kui  potti tühjaks ei saa peale teist päeva peale selle valmistamist läheb see koertele. Minu pere kasvatab ka väga palju asju ise näiteks sibulad, tomatid, kurk, kõrvits, arbuus, tšili ja teisi ning ostame koju vaid seda mida ära sööme. \nInimesi on erinevaid ja leiame asjadele erinevaid lahendusi, kuid olukord on ikka samas seisus. riiteid visatakse ikka hästi palju ära ja toitu raisatakse ikka hästi palju, nii et mis saab edasi, mis saab meie tulevikust kui me nii jätkame. kas meie tolevikus on siis ikka pisavalt resurse et toitu kasvatada või peame leidma uusi asju millest toitu valmistada.\nKõik kes me siin maal elame saame teha midagi selleks, et see mailm paraneks.');
