INSERT INTO core.text(id, content)
VALUES ('15605e7b-f552-4ddf-82fe-640c93473bcc',
        'Kõikidel inimestel on tarbimisharjumised erinevad. Mõned inimesed raiskavad palju toitu ja toitained, mõned inimesed ei raiska üldse toitu ja toitaineid. Miks raiskavad mõned inimesed palju toitu ja mõned inimesed mitte?\nMõned inimesed raiskavad toitu ja toitaineid, sellepärast, et neil on palju raha ja nad ei hooli sellest, mida nad rahaga teevad. Rikkad inimesed ostavad palju toitu ja toitained, aga nad ei mõtle, sellele et vaestel inimestel pole raha ja nad ei saa nii palju toitu osta. Vaesemad inimesed hoiavad toidu ja muude söökide pealt raha kokku ja ei osta nii palju süüa, kui rikkad. Rikkad peaks annetama vaesematele inimestele raha, et nad saaks endale süüa osta.\nVaesematele inimstele peaks raha juurde annetama, et nad saaks osta endale süüa ja vaja minevaid tooteid. Rikkamad inimesed peaks austama vaesemaid inimesi ja neid aitama, mitte vaatama, nende olukorda, nende välimust ja neile halba mitte teha. Enamus inimesed ei tea mida nad rahaga peale hakkavad, kui neil raha liiga palju on.  Inimestel kellel raha pole on halb poes vaadata, kui rikkad süüa ostavad, kuna nad ei saa nii palju süüa osta, kui rikkad inimesed. Nendel inimestel kellel raha pole ja kellel pole võimalik seda kusgilt saada, siis peaksid teised inimesed tegema neile annetusi.\nVaesematele inimestele peaks tegema erinevaid annetusi, et saada neile raha koguda. Inimesed kellel on palju raha, annetage oma rahast, neile kellel pole raha. Kõikidel inimestel pole nii palju raha,kui mõndadel inimestel. Peame toetama neid inimesi väga, kellel on rasked ajad ja raha pole. Aitame neid inimesi!');
INSERT INTO core.text_property(text_id, property_name, property_value)
