INSERT INTO core.text(id, content)
VALUES ('233d243e-b792-417c-8905-0e7d99703598',
        'Tänapäeval on palju inimesi, kes raiskavad materjale. Suuremateks teemadeks on toit ja toiduained ning riiete raiskamine. Aga miks on tekkinud aina suurem raiskamisharjumus? \nRääkides nüüd toidu ja toiduainete raiskamisharjumusest, siis tarbi toitu targalt artiklis arutati toidu kadumise üle. Paljud arvavad, et toidukadu tuleb sellest, et enamus inimesed saavad seda endale lubada. Nii see ei ole. Enamik toidukadu tuleb sellest, et inimesed ostavad toitu ja toiduaineid aga ei kasuta neid ära enne tähtaega. See tekitab 42% toidukadu ehk 26 kg toitu visatakse ära. Meie maailmas on riike milles on probleeme näljasusega, miks me teeme nii? See toidukadu oli ainult Eesti kohta aga mõtleme, mis toidukadu on suurtemates riikides. \nTeine raiskamisharjumus on riietega. Riideid antakse aina rohkem ära mis moodustab suure raiskamise. Taaskasutuskeskused on saanud aina populaarsemaks kuna inimesed toovad sinna massiliselt riideid, mis on tellitud Hiinast või mujalt suurelt maalt, mis teeb masstoodangut. Oma kogemusest väidan, et Hiinast tulevad riided on mugavad aga need lähevad kiiresti katki, mis raiskab nii minu raha kui ka materjale. \nRaiskamisharjumus on tõsine teema ja arvan, et see võiks olla rohkem aktuaalsem. Võiks rääkida rohkem lastele, kuidas säästa noorest east alates. Sellega me teeks oma tuleviku ja enda laste tuleviku paremaks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('233d243e-b792-417c-8905-0e7d99703598', 'title', 'Miks on tekkinud aina suurem raiskamisharjumus?');
