INSERT INTO core.text(id, content)
VALUES ('5c29ebbf-d0cf-40a5-ac0d-3be03165bc78',
        'Toidu raiskamine on tänapäeval väga suur probleem. Toitu leidub väga palju igal pool. Kui kõndida tänaval, tunned toidu lõhna ja näed erinevaid restorane ja poode ning väikeseid asutusi, mis pakuvad toitu. Tänaval leidub palju toitu ning toidujäätmeid prügikastides ja maas vedelemas. \nRestoranide prügikastides võib leida suurtes kogustes toidujäätmeid. Need on kõik alles jäänud ja ära visatud toit, mida inimesed kas pole jõudnud süüa või ei meeldinud mingi asi toidu juures vms. Sellega raiskavad inimesed oma raha, mis on raskelt teenitud ning ka toiduaineid ja toitu, mis on tulnud igalt poolt maailmast lennukitega, laevadega jms ning reostavad iseenda ümbrust. Toidu hinnad tõusevad ning aina enam tekkib inimesi, kes ei saa lubada endale kuskil väljas söömist või paljude toitude ja toiduainete ostmist. Need inimesed sageli väärtustavad enda ümbrust ja toitu rohkem ja ei reosta nii palju kui inimesed, kes saavad endale rohkemat lubada. \nÜhiskonnaprobleeme on palju kuid üheks tähtsaimaks on riided, mida visatakse liiga kergelt ära ning ostetakse üleliia juurde. On rajatud taaskasutuspoed ja erinevad kohad, kuhu saab oma vanu asju viia või ümbertöödelda, kuid inimesed soovivad ikka uhiuusi ja uhkeid asju ning riideid aina ostetakse ja neid aina koguneb. Paljud inimesed ostavad ka riideid ainult soodustuste tõttu ning ei kanna pooli riideid mida kokku ostetakse. \nMe peame muutma oma harjumusi, õppima väärustama seda, mis toimub meie ümber, mõtlema rohkem tuleviku ja ühiskonna peale ning õpetama ka tulevasi põlvi seda kõike tegema, sest reostust on väga palju ning see mõjutab meid, meie ümbrust ja meie tulevikku. Kui iga inimene panustaks natukenegi reostuse vähendamisele, saaksime paremini  vähendada keskonnaprobleemide teket.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('5c29ebbf-d0cf-40a5-ac0d-3be03165bc78', 'title', 'Prügi meie ümber');
