INSERT INTO core.text(id, content)
VALUES ('7ec822e6-662a-4f4b-826d-5fce07798790',
        'Inimesed kõik tarbivad maailmas toodetuid asju. Olgu need riided, toit, tehnoloogia ja kõik muu mida tootjad pakkuvad. Eestis on suur probleem, et inimesed ei oska õieti tarbida. Kõik läheb raisku või visatakse julmalt minema. Millised on meie inimeste halvad ja hooletud tarbimisharjumused? \nKõige tuntum inimeste halb tarbimisharjumus on see kui ostetakse rohkem kui tegelikult vaja on. See tähendab, et kui kirjutatakse kodus valmis poe ostunimekiri, siis poes vaadatakse ja ostetakse asju mis seal kirjas pole. Põhiliselt juhtub see toidupoodides, näiteks ostetakse magusaid asju, koogid, šokolaad, joogid ja kommid. Selletõttu kulub inimestel liiga palju raha mõttetute asjade peale. Ja kuu lõpuks jääb raha väheks. Lisaks võib juhtuda, et toidud mida ostetakse lähevad raisku. Neid ei tarbita või need lähevad vanaks. Näiteks Eestis kulub iga inimese kohta aastas keskmiselt 61 kg toidujäätmeid. See tähendab, et Eesti inimesed ostavad rohkem kui vaja. \nEesti inimesed ostavad väga palju riideid ja esemeid välismaalt eriti Hiinast. See tuleb sellest, et Hiinas on kõik riided ja esemed väga odavad. Hiina veebipoed kasutavad sooduskampaania taktikat ja see paneb kõiki inimesi asju ostma. Selle asemel, et välismaalt tellida võiksid inimesed osta kodumaiseid tooteid. See tooks kasu riigi majandusele ja aitaks vältida üldist raiskamist eriti riiete osas. \nEesti inimeste tarbimisharjumused on hooletud ja halvad. Nad ostavad rohkem asju kui vaja ja selle tõttu kulub palju raha neil endil ja tekkib palju raiskunud toitu. Lisaks tellivad inimesed asju rohkem välismaalt ja sattuvad sooduskampaania trikkide õnge. Selle asemel võiksid nad osta kodumaiseid tooteid.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('7ec822e6-662a-4f4b-826d-5fce07798790', 'title', 'Hooletu tarbimine');
