INSERT INTO core.text(id, content)
VALUES ('4808e934-a2e4-4de4-9768-cb2708721025',
        'Paljud inimesed arvavad, et nad ei raiska üldse toitu ega riideid, aga tegelikkuses me kõik oleme seda teinud. Me kõik oleme ära visanud toidu, mis oli veel kõlblik süüa ja riideid, mille oleksime saanud kellelegi edasi anda või taaskasutuspoodi viia.\nInimesed kipuvad liiga palju toitu ära viskama. Näiteks kui teeme perele süüa ja arvame, et tegime piisavalt, et mitu päeva saaks seda süüa, aga tegelikult sööme ainult ühe päeva seda ja järgmine päev viskame todujäätmetena ära, sest mitte keegi ei tahtud seda enam süüa. Või kui inimene elab üksi ja ei oska enda jaoks parajat kogust süüa valmistada ja paneb ülejäänud toidu külmkappi, et hiljem ära süüa. See söök võib seal külmkapis mitu päeva seista või nii kaua, et inimene on selle hoopis ära unustnud ja söök läheb halvaks. Lõpude lõpuks peab ta selle söögi jälle ära viskama.\nIga kord kui ma oma riidekappi koristanud tuleb mul suur hunnik riideid, mida ma enam kanda ei soovi või mis mulle väikseks on jäänud. Tavaliselt olen ma need riided oma sugulastele andnud ja nad vaatavad üle, milliseid endale tahavad jätta, aga suurem osa nendest riietest on ikka raisku ja prügikasti läinud. Viimasel ajal olen hakanud neid riideid taaskasutuspoodidesse viima ja olen aru saanud, et selle väikse teoga aitan palju inimesi, kellel on probleeme rahaga või midagi sarnast. Tavaliselt leian ka endale midagi nendest poodidest kui piisavalt hoolikalt vaatan ja otsin.\nPeame ka mõtlema inimestele, kellel pole seda privileegi, et nad saaksid iga päev puhtaid riideid kanda ja korralikku toitu süüa. Mina arvan, et kõige parem viis kuidas sööki ja riideid kokkuhoida on osta ja valmistada asju, milles sa oled kindel, et kasutad ära ega viska nii sama ära.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('4808e934-a2e4-4de4-9768-cb2708721025', 'title', 'Inimeste tarbimisharjumused');
