INSERT INTO core.text(id, content)
VALUES ('876c0d0b-4211-4a56-9ade-743fae1ed3ff',
        'Juba pikka aega on aktuaalseks teemaks olnud inimeste tarbimisharjumused, kuidas need mõjutavad meid ja meie ümbrust. Mis on peamised probleemid tarbimisega  ja kuidas saaks neid lahendada?\nKõige rohkem räägitakse toidukaost ning kiirmoest. Inimesed viskavad igapäevaselt ära tohutus koguses toitu. See koormab maaressursse kui ka inimressursse. Selline teguviis on inimestel justkui loomulik harjumus ning seetõttu on raske elustiili muuta. Nii on ka kiirmoega. Hiinas lapstööjõuga odavalt toodetud produktid jõuavad igasse maailmanurka massilistes kogustes. Tooted on suures osas ebakvaliteetsed, kuid inimesed on nõus sellest mööda vaatama odavate hindate ja mugavuse tõttu. Veel üha märgatumaks probleemiks on majanduslikult kindlustatud inimeste massiline ületarbimine ehk on vajadus omada nii palju, kui võimalik, ilma tegelikult tooteid kasutamata.\nInimeste mugavus on meile endile ning keskonnale kujunenud murekohaks. Miks aga peaks see meid huvitama? Kõik tarbimisviisid nõuavad mingil moel loodusressursse. Ületarbimine, raiskamine- see kõik reostab loodust, koormab ökosüsteemi ja aitab kaasa suurel määral kliimasoojenemisele. Tulevikuplaanides võib see hoopiski tähendada mugavuse kadumist. \nMida me saaksime muuta? Populaarseks on muutunud rohepöörde ideed, mida üha enam rakendatakse ülemaailmselt. Vahetatakse välja looduses mitte-lagunevad materjalid lagunevate vastu, kasutatakse taaskasutust, ei raisata vett, elektrit ning sõidetakse ühistranspordiga. Kui neid elustiiliviise hakkaks kasutama rohkem inimesi, suudaks see olulisel määral muuta ühiskonna mõtteviisi ning kaitsta loodust.\nPeamisteks tarbimisprobleemideks on ületarbimine, raiskamine ning odavuse eelistamine, mis koormab ühiskonda ja loodust. Lahenduseks oleks rohepööre, kui inimesed mõistaksid olukorra tõsidust ja rohepöörde ideed massiliselt leviksid.');
