INSERT INTO core.text(id, content)
VALUES ('6e527801-f948-4229-bd5c-afde6caa1be0',
        'Inimeste harjumused tulenevad kõige rohkem ise endist. See tähendab, et kui nad teevad korra seda, siis nad proovivad seda näiteks uuesti teha. Minu tarbimisharjumus on näiteks valetamine, et mul on tarbeks valetada, kui ma proovin millestki kergelt lahti saada. Millest tulenevad need harjumused üleüldse?\nMina, kui vähese valetajana olen proovinud saada asjadest kergelt lahti, aga see ei tööta nii. Kuna kui ma seda korra proovisin, siis ma mõtlesin, et äkki ma saaksin uuesti sellega hakkama, et saaksin kergelt pääseda millestki. See nii väga ei töödanud, kuna kõik valed tulevad kergelt välja ja inimesed kellega sa suhtled ei saa sind siis enam väga usaldada.\nValetamise võib põhjustada näiteks kellegi eeskujust, või kui sulle endale on nii tehtud. Kui vaid inimesed teaksid, kui jube see tegelikult on. Kuigi mu enda tarbeks peaksin ma ka seda teadma, aga millegi pärast valetan ma ikkagi. Seda on küll lihtnen teha, kuid sellest on raske pääseda.\nKui inimesed sooviksid sellest tõsiselt lahti saada siis nad ei teeks enam niimoodi, vaid õpivad oma vigadest ja proovivad ennast parandada. Seda asja saab ka vaadata sellisel vaate pildil, kui sa võtad näiteks selle toidu raiskamine või toiduga liialdamine. Seda kõike saab parandada, kui inimene vaid sooviks seda isa teha. \nMe teame nüüd, et ei ole vaja tegelikult ültse valetada ja raisata toitu, kuna see kõik võib tuua halba. Et asjadest tõesti lahti saada, tuleb seda püüela teha, mitte lihtsalt edasi teha nii nagu tarbeks. Kunagi pole ilus valetada, kuna kõik tuleb sulle kunagi tagasi.');
