INSERT INTO core.text(id, content)
VALUES ('298e5cbe-9506-42fb-9952-fa7aca3ce193',
        'Meie kui tarbijad, ei pruugi aru saadagi kui palju me tegelikult tarbime toitu ja vajalikke resurrse. Kui me ei tarbiks piisavalt maailmas, siis oleks palju ülejääke ja kui me tarbiks liiga palju siis saaksid vajalikud ressursid väga kiiresti otsa, nii nagu praegu on.\nInimesed ei märkagi, kui palju nad tegelikult raiskavad toitu ja reostavad oma ainukest planeeti, enamik inimesi arvab, et kunagi me nagunii liigume teisele planeedile, kuid  kas seal teisel planeedil on üldse ellujäämis näiteid? Seal ei pruugi olla isegi vett või õhku mida on vaja, et ellu jääda.\nEve Hanson selgitab Vikerhommikus nii: „Ma näen taaskasutuspoodide laos vabatahtlikuks käies seda rõivaste kogust, mis tekib iganädalaselt juurde. Sinna viiakse korralikke riideid, aga ka selliseid, mis mingil kaunil reklaamfotol näevad ilusad välja, aga tegelikult koosnevad naftast.“ Ehtne näide, et ma kasutame valesid resursse valede asjade peal. Meie riigis on nafta puudus ja selle hind on vägagi kõrge, kuid seda kasutatakse hoopis riiete tegemisel.\nMinu järeldus inimeste tarbimisharjumustele on see, et pooled inimesed maailmas ei pruugigi aru saada, mida nad tegelikult meie ainukesele maailmale teevad ja nad avastavad seda liiga hilja. Inimesed kasutavad väga palju resursse valedel asjadel. Kui oleks vaja näiteks naftat juurde, kasutavad inimesed seda hoopis riiete tegemise peal, et seda inimene ainult ühekorra kannaks ja selle eest palju raha maksaks. Nende asjade peale kulub meeletu raha, mida oleks vaja teistel inimestel, kes ei tee elus nii hästi kui teised teevad.');
