INSERT INTO core.text(id, content)
VALUES ('dbca8e0f-2ef7-464e-96a9-23e4148d3da4',
        'Igapäevaselt viskab vähemalt üks inimene maailmas toitu või toiduaineid prügikasti, kuna see on kas ületanud kasutustähtaja, rikenenud, söömisel ülejäänud või midagi sellist sellega juhtunud. Millised on inimestel tarbimisharjumused?\nOn olemas inimesi kes raiskavad toitu, sest nad saavad seda endale lubada. Iga Eesti inimese kohta sattub aastas keskmiselt 61 kg toidujäätmeid prügikasti, millest 42% ehk 26 kg on toidukadu, mis mingil põhjusel jääb tarbimata või lihtsalt visatakse ära.\nToit ja toiduained pole ainukesed tooted mis visatakse ära, sealhulgas on ka riided. Viimaste aastatega on saanud populaarseks e-poed, näiteks Shein ja Temu, kust inimesed ostavad endale riideid ja igat teist kraami, kuna need on odavad. Seda nimetatakse fast fashion-iks. Fast fashion on kui poed toodavad riideid väga kiiresti, et neid odavalt müüa ja meelitada inimesi neilt ostma. Sellised tootajad tihti kohtlevad oma töötajaid vääralt ning kasutavaid lapsi tööjõuks, üks nendest on näiteks Shein.  Kui riideid enam ei kasutata, sattuvad nad prügimäele, kus nad rikuvad keskkonda, kuna paljud neist riietest ei ole võimelised lagunema. Et seda vähendada, andakse riideid taaskasutuspoodidesse, kus riided ja teised tooted võivad endale uue elu saada.\nAastas raisatakse palju tooteid, näiteks toitu, toiduaneid ja riideid. Nende prügimäele sattumise ennetamiseks on töödeldud välja erineivaid võimalusi, näiteks riiete annetamine taaskasutuspoodidesse.');
