INSERT INTO core.text(id, content)
VALUES ('34a40859-3f1c-41b9-9c7d-a9a6c38a3758',
        'Mis põhjustel inimesed viskavad nii palju toitu ära? Millised on inimeste tarbimisharjumused? Miks on poodides parim enne korvid?\nInimesed viskavad toitu ära, sest nad ostavad mõne uue toote prooviks ja neile näiteks ei maitse see, siis nad viskavadki ära. Kui näiteks mõnel tootel on kuupäev mitu päeva üle, siis on see riknenud või halvaks läinud, seda ei soovitata süüa ja sellega pole muud teha kui, et tuleb ära visata. \nInimesed on erinevad ja selle tõttu on neil ka erinevad tarbimisharjumused. On inimesi, kes ostavad toitu endale nii, et nad jõuavad ära tarbida. Kui osta vähem, siis selletõttu me ei raiska enda raha ega ei viska toitu jäätmetena ära. On selliseid inimesi, kes ostavad toitu endale nii,et külmkapp täis ja ei jõua seda ära tarbida. Elad näiteks üksinda ja ostad sellise suure koguse ette ja maksad suure summa, et ei peaks nädala sees nii palju poes käima, aga lõpuks ta ei jõua seda toitu ära tarbida. Kui on tema ostetud kaubal kuupäev läbi ja ta pole jõudnud seda ära tarbida peab ta selle minema viskama. Sellega seoses ta kaotab enda raha ja toote omaniku ressursse.\nPoodides on ka vahepeal parim enne tooteid korvis, mida ei ole neilt ära ostetud. Seal korvis on erinevaid tooteid, millel hakkab kuupäev lähenema, aga seda on võimalik veel tarbida. Kuupäeva tõttu nad panevad ka väiksema hinna sellepärast, et inimesed ostaksid seda tootet, et mitte minema visata.\nTuleb osata toitu osta nii, et sa ei raiskaks oma raha ilmaasjata ja ei peaks toitu lihtsalt ära viskama.');
