INSERT INTO core.text(id, content)
VALUES ('ce45aed3-58f3-449b-aad3-32c927206399',
        'Inimesed raiskavad liiga palju toitu, kuna neil on piisavalt raha ja nad saavad seda endale lubada. Kui inimesed toitu ära viskavad siis ei raiska nad vaid oma raha, kuid ka muid ressursse: maad, vett, energiat, tööjõudu ja aega.\nIga Eesti inimese kohta tekib aastas keskmiselt 61kg toidujäätmeid, millest toidukadu on 42% ehk 26kg. Toidukadu on toit, mis on ületanud kasutustähtaja, mida keegi pole tahtnud ning siis on see lihtsalt ära visatud või komposti pandud. Minu peres on nii väga harva, kuid kui on siis näiteks mõne uue tootega, mis tuleb välja, et ei maitse kellelegi ning siis see jääb kas külmkappi või kuskile mujale kuni kasutustähtaja ületamiseni. Me võiks selle toidu anda kellelegi kellele see maitseb. Seda võib ka juhtuda siis, kui näiteks piim on allahindlusega, siis inimesed ostavad seda väga palju ja lihtsalt ei jõua kõike enne kasutustähtaja ületamist ära juua. Pole mõtet liiga palju osta, alati saab ju juurde.\nMa ei mõista miks inimesed ostavad toitu, nad ei tarbi seda ära ning lihtsalt viskavad selle minema. Inimesed näevad palju vaeva, et endale toitu osta, nad käivad tööl, saavad palka, ostavad toitu ja viskavad selle ära. Mina näen toidu ära viskamist nagu raha ja vaeva raiskamist. Seepärast mulle meeldibgi osta asju millel pole põhjust ära viskamiseks. Näiteks mänguasjad, videomängud ja riided. Kõik need saab teistele maha müüa või tasuta ära anda. Toiduga nii ei ole, ma ei tea ühtegi inimest kes tahaks halvaks läinud toitu, eriti veel raha eest, kuid toidujääke tahavad mõned inimesed küll.\nInimesed raiskavad päris palju toitu ehk siis ostetakse liiga palju. Nad raiskavad oma aja ja tööjõu lihtsalt ära. Me peaks vähem toitu ära viskama ja andma selle neile kes seda vajavad.');
