INSERT INTO core.text(id, content)
VALUES ('e3c6dcc8-b78b-4903-acb4-c71737a18da6',
        'Inimesed peavad elamiseks tarbima toitu. Toitu on lõpuks nii palju tekkinud, et inimesed ei jõua seda kõike ära tarbida ja viskavad enda toidu ära. Peale toidu ära viskamise, mida see veel mõjutab?\n  Toidu tegemine võtab palju ressursse ja aega. Veiseliha saamiseks, tuleb kasvatada, toita veist kuni ta on suureks kasvand ja siis saab teda lihaks teha ja ära süüa, aga kui tarbija ei söö seda liha, siis läheb kõik need aastad, mis veise kasvatamiseks läks, raisku.\n  Toitu tuleb ka tuua tootmis kohast, pakkimis kohta, turule ja hiljem tarbija võtab selle endaga kaasa. Selle aeg, mis toidu lauale toomisega kulub, tekitab palju CO2 ehk süsihappegaasi, mis reostab õhku ja keskkonda meie kõigi ümber ja reostab veel rohkem, kui inimesed selle toidu ka ära viskavad.\n  Lahendusi leidub paljudele asjadele. Toidu tootmist võiks vähendada ja inimesi tuleks põhjalikumalt harida, et nad mõistaks võtta süüa nii palju, kui nad ise seda jaksavad tarbida. Kõik toit, mis üle jääb tuleks teha kompostiks või ilusti ära sorteerida ja anda loomadele, et seda saaks taaskasutada.\n  Kõik elusolendid, peavad tarbima toitu, aga toidu tegemine ja lauale toomine võtab palju ressursse ja aega. Toidu kohale toomine tekitab palju reostust keskkonnale ja õhule meie kõigi ümber. Keskkonna heaks, peaksime põhjalikumalt mõtlema mida me sööme, kui palju me sööme ja mida teha toiduga mis meil üle jääb.');
