INSERT INTO core.text(id, content)
VALUES ('2bea137b-3c74-4ca4-bd11-b363b1ffaaff',
        'Toiduraiskamine on väga suur probleem noorte seas, sest noored ostavad või võtavad üleliia toitu. Noored inimesed ei mõista toidu probleemidest ega nälgimisest mujal maailmas. Kas toiduraiskamine on ültse suur teema Eestis?                                          Tekstist sain teada, et iga Eestlane raiskab 26kg toitu aastas, mis moodustab 42%. Mina ise prvoovin võimalikult vähe raisata toitu kuid vahel suudan mina ka päris palju toitu raisku lasta. Kui ma toitu raisku lasen siis ma mõtlen alati nendele aafrika lastele ja täiskasvanutele kes surevad nälga. Eesti riigis ostavad noorukid alati üleliia toitu poodidest või võtavad kooli sööklatest väga suured portsionid mille nad ära viskavad. Ma alati näen kui palju toitu on söögivahetundidel raisku lastud. See toidukogus, mis seal raisku lastud on suudaks ära toita aafrikast ühe või isegi kaks pere. Noorukid veel ei saa aru kui suur on toidu raiskamis probleem. Keegi ei mõtle resursidesse mida toidu peale kulutatakse nt: vesi, tööjõud, maavarad jne. Eve Hanson tõi ka päris häid ideid välja näiteks see, et võtaksid kvaliteedi enne kvantiteedi ja see, et Hiina veebipoodidest ei ole mõtet asju osta, aga ikkagi inimesed eelistavad Hiina poode üle Eesti veebipoodide, sest asjad on seal sootsamad.                                                                       Lõpetuseks tahan ma öelda, et jah Eestis on toiduraiskamine suur probleem. Ma proovin ise ka nüüd palju vähem toitu raisku lasta ja ostlen nii, et võtan kvaliteedi enne kvantiteedi.');
