INSERT INTO core.text(id, content)
VALUES ('9f8cca16-ce0b-4d16-8f77-82fc9c011a39',
        'Kõik inimesed tarbivad igapäevaselt kõiki võimalikke asiu. Aga me kasutame kasutame enamus asiu ilma mõtlematta, mis nende esemetega edasi saab või, mida nendega edasi tehakse. Aga mida mina tarbin, kasutan või taaskasutan ja mis on minu tarbimisharjumused.\nMinu üheks igapäevaseks kõige enimaks tarbimisharjumuseks on söömine, seda ma teen palju, ning meie peres süüakse palju, aga selle tõttu visatakse palju toitu ära. Kunagi kui meil veel koer oli läksid enamus ülejääke kõigepealt talle, siis kui koer ei jõudnud kõike ära süüa, siis alles viskasime toidu ära. Aga toidu äraviskamiseks on meil suur kompostikast kuhu me saame kogu oma toidujäätmed visata.\nMinu järgmiseks igapäevaseks tarbimisharjumuseks on riietekasutus. Ma kanna iga päev riideid, aga viskan neid ära väga harva, täpsemalt siis kui need enam kasutuskõlblikud pole. Ma kasutan ka väga erinevaid ja mitmesuguseid riideid, näiteks mu emale meeldib käija taaskasutus poodides ja ta tihtipeale leiab nendest poodidest mulle väga kvaliteetseid riideid, aga samas mul on ka väga palju riideid mis on uhiuuena poeletilt koju toodud. \nMa kasutan ka väga palju ühistransporti. Ma sõidan iga päev bussiga mitmeid kümneid kilomeetreid teise linna, et trenni minna. Ma teen seda põhiliselt sellepärast, et saada trennis käija, aga ka sellepärast, et mu vanemad ei peaks ainult minu pärast kümneid kilomeetreid sõitma ja seetõttu keskonda reostama.\nMinu peamisteks tarbimisharjumusteks on riietekasutus, toidusöömine ja ühistransport- need on tegevused ja harjumused mida iga päev teen ning ma õpin juurde kuidas saaks, midagi, kellegi või millegi jaoks paremaks teha.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('9f8cca16-ce0b-4d16-8f77-82fc9c011a39', 'title', 'Minu tarbimisharjumused');
