INSERT INTO core.text(id, content)
VALUES ('3fbfdb6c-b02e-411a-87e1-2f889527e3ab',
        'toidukaost on see kui toitu kasutatakse väga palju ja inimesed ei säästa toitu.kõige suurem probleem ongi praegu toidukaost ja sellega peab tegelema.\nMa arvan, et toidukaost on jube, inimesed raiskavad rohkem toitu kui neil seda raha piisavalt on , sest me kõik raiskame tegelikuses vett,maad, ja ka energiat kuigi terve maailma inimesi võiksid säästa isegi kui on piisavalt raha. Inimestel pole tulevikus enam vett,toitu,maad,energiat ja tööjõudu.\nKui inimesed kellel on elu uhke ja peenem need just raiskavad rohkem tooteidja teistele ei jää midagi, lõppeb see eilu surmaga kiiremini ja inimkond sureb välja. Ma nõustun selle inimesega kes kirjutas selle jutu , sest see on tõsine probleem, kuna loomad ka surevad välja. Kui loomad surevad välja, siis hakatakse kemikaalidega toite tegema väga palju mis toob jällegi ohtu meie inimkonnale, kuna keegi ei kärelikult ei tea mis mürke j aained on sinna sisse pannud.\ninimesed peavad säästma toitu isegi kui kellegil on rohkem raha võiksid anda inimestele toitu kellel pole seda võimalust osta.\nMaailm on nii suur ja inimesi on ka nii palju siin maa peal, et toitu lähebki sellepärast ka rohkem kui tegelikuses peaks.\nLoomi peab toitma ja sellest edasi läheb inimeste poole kes ostavad tohutult kaupa süüa. Inimestel on hirm et loomad surevad välja ja ostavad liiga palju süüa hirmust juba.\n\nMoedisainer: noortele peaks tegema eksursioone taaskasutusoodide lattu\nPraegune probleem maailmas on ka selline et inimesed viskavad minema oma riideid prügikasti , sest inimesed ei mõtle selle peale et neid anda toidukasse kus inimesed käivad riideid ja kõiki asju võtmas et midagi saaks kanda.\nRiideid on tohutult maailmas ja internetis kus saad osta igasuguseid asju ja kallite hindadega, aga lõppude lõpuks visatakse need riided ikka minema. Miks? Sest inimesed ei taha seda enam kanda ja viskavad minema, kuigi tegelikuses saab anda ka riideid ära inimestele kellel oleks vaja neid rohkem.\nÕpilasi tõesti võiks viia eksursioonile ja vaatada kui palju on ära visatud riideid, need Hiina tooteid tellitakse ka väga palju mis on halb, sest riideid tehtakse halvast materjalist ja inimestele ei sobi ja viskavad minema nagu mingi praht oleks see. Inimesed võiksid rohkem vaatada oma riideid ja kui ei meeldi siis peaks viima toidukaupa , sest järgmised inimesed saavad taaskasutada riideid koguaeg. Inimesed meisterdavad endale igasuguseid riideid koguaeg aga mõned kes rikkamad on ja neile ei meeldi mingi riie, nad viskavad minema. Kui mulle näiteks midagi selga ei lähe või ei meeldi siis annan küll toidukaupa, sest ma tean et teistel inimestel on neid riideid rohkem vaja kui mul.');
