INSERT INTO core.text(id, content)
VALUES ('398d58cf-c615-4fab-8416-4892eca54e49',
        'Söögiraiskamine on üks neist asjadest mida enamus inimesi teevad igapäevaselt. Kahjuks on ka inimesi kes saaks meie raisatud toidust palju kasu, kuna nad ise ei suuda endale koguaeg seda lubada. Kuid on ka neid kes ostavad enda külmiku täis toitu ja ei söö seda kõike õigeks ajaks ära mis tegelikult on lihtsalt raiskamine.\n Meie seas on neid, kes ei saa igapäev endale toitu lubada kuna neil lihtsalt puudub raha selle jaoks. Näiteks vaesemates riikides on palju peresi kes ei saa tihti enda kõhtu täis kuna neil puudub söök. Sellepärast on tehtud toidupanku, aga kurb tõde on see, et paljud ei julge sealt võtta toitu kunad nad häbenevad oma olukorda või nad lihtsalt ei ela mõnele piisavalt lähedal. Toit mida me ei söö või hakkab halvaks minema oleks tohutult suur kasu neile.\n Maailmas on ka inimesi kellel on elus rohkem vedanud ja saavad lubada endale toiduaineid ning toitu aga enamus neist ei hinda seda. Näiteks on inimesi kes ostavad enda külmiku toitu täis ning ei tarbi seda kõike ära või ei anneta ja sellepärast jääb see toit tarbimata. Toidu raiskamisega ei raiska me ainult toitu, kuid ka ressurse nagu maad, vett, energiat ja tööjõudu mida oli vaja selle toidu kasvatamisel ja tegemisel.\n Ma arvan, et meie ühiskond peaks juba piisavalt arenenud olema, et me võiks teada kuidas toitu kasutada niimoodi, et see raisku ei läheks. Me võiks toiduaineid ja toitu kasutada mõistlikult nõnda, et me ei peaks seda ära viskama ja isegi kui jääb midagi üle mida me ei kasuta siis me võiks selle annetada inimestele kes sellest leiab abi ning vajavad seda, kuna fakt on see, et me kõik pole sündinud siia ilma nii õnnelikuna, et me saaks igapäevaselt süüa.');
