INSERT INTO core.text(id, content)
VALUES ('f7313608-b9af-480d-a65e-493058b02b06',
        'Kindlasti oled näinud, kuidas inimesed toitu heast peast ära viskavad, kuna neil raha palju. Siis on inimesed, kes ostavad endale asju, mida neil tegelikkult vaja ei lähe. Sina oled ka kindlasti neid asju teinud.\nKodumajapidamises tekib iga Eesti inimese kohta keskmiselt 61 kg toidujäätmeid. See on väga palju ühe inimese kohta. Inimesed raiskavad toitu ja nende tarbimisharjumused on halvad. Kui sa viskad ära toitu, sa ei raiska ainult enda raha, vaid ka raiskad tohutult ka muid ressursse: maad, vett, energiat, tööjõudu, jne. Kuidas toidujäätmeid siis vähendada ja inimeste tarbimisharjumusi paremaks teha?\nMina arvan, et tuleks koolides õppetada, kuidas tarbimisühiskonnas korralikult olla. Moedisainer Eve Hanson ütleb: „Ei telliks Hiina veebipoodidest juba põhimõtte pärast asju, et läheks kaasa sooduskampaaniatega.“ Ta ütles veel, et eelistada tuleks kodumaiseid Eesti tooteid. Eve Hanson ka arvab, et peaks hakkama noortele tegema ekskursioone taaskasutuspoodide lattu, et näidata noortele, milline raiskamine tegelikkult ühiskonnas toimub.\nJärelduseks ma arvan, et inimesed peavad õppima, kuidas looduslikke ressursse hoida, kuidas loodust hoida, kuidas tarbimisühiskonnas õigesti käituda ja elada ja kuidas halbadest tarbimisharjumustest lahti saada. Mitte osta asju. mida vaja pole. Mitte osta halva kvaliteediga ja odavaid asju (nt naftast koosnevad riided). Mitte raisata toitu.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('f7313608-b9af-480d-a65e-493058b02b06', 'title',
        'Inimeste tarbimisharjumused ja kuidas inimesed toitu raiskavad');
