INSERT INTO core.text(id, content)
VALUES ('553359e9-37eb-4615-bf4e-97f5e563f7df',
        'Probleemiks on et inimesed raiskavad toitu ja viskavad ära kõik toidu isegi kui seda on väiksemas koguses. Isegi inimesed on hariunud toitu ära viskama sellega kaasneb keskonnakoormus.Inimesed on minu arvates hakkanud palju raha kulutama igal pool ostes asju mis on soodus igas reklaamis või netti poes on pandud et hea toode aga tegelt pole sest need on tehtuud naftast.\n Minu arust on toidu ära viskamine halb kui just pole läinud üle aja või halvaks,aga kui toit on hea siis ei ole mõttet ära visata kuna sa ei tea kunagi kuna sul seda vaja läheb minu meelest inimesed viskavad toidu maha kuna naad on harjunud seda tegema aga se on keskonnale kahjulik, sest loomad võivad sealt midagi sööma hakkata ja võib olla seal kile või muud asju ja loomale se hästi ei mõju. Inimesed viskavad toidust vähemalt 30% ära kuigi ma saan aru et ei sa jätta seda maha üleöö, aga palun hoiame loodust ja viskame kõik ülejäägi ilusti prügikasti ja ei viska kuhugi maha ega metsa.\n Mina arvan et ei ole mõttet tellida kuskilt hiinast asju kuna se läheb nii kalliks ja ei tule alati õige asi mis sina tahad siis kannad seda riiet paar nädalat ja siis need lähevad kas kuhugi kappi taha või taaskasutuspoodi kus on riideid virnade viisi ja inimesed ei mõista et hiina poes on müügil halvad riided vähemalt minu arvates sest need ei ole nii mugavad kui arvad ja on halb kvaliteet ja tehakse riided naftast ja inimese nahk ei taha seda kanda ja peale selle ei taha enam inimene seda kanda ja viskab kas minema või viib taaskasutuspoodi kus on veel sama suguseid riideid virnade viisi. Minu arvates peaks tegema inimestele ühe tiiru nendes poodides sest siis näevad inimesed kui palju on uusi riideid on inimesed raisanud. \n Kõige selle tulemusena arvan mina et inimesed raiskavad palju raha ja asju kuna naad ostavad ja viskavad kohe ära ja ei hooli mis seal on või mitte naad võiks anda siis juba tasuta inimestele kes seda vajavad mitte ära visata ja müüki panna.');
