INSERT INTO core.text(id, content)
VALUES ('13ad0d09-8aa2-48a3-b016-ed26f289ff1f',
        'Kõik me tarbime ükskõik kas oled rikas, vaene , laps või täiskasvanu. Probleem tekib kui me tarbime üle või raiskame. Kõik me oleme midagi ära visanud ja mõelnud „ see ei muuda midagi“, aga muudab ju küll. kui mõelda kui palju asju ja vaeva on nähtud, et seda eset teha.Kui kõik me visakme ühe asja ära, siis lõpuks see pole enam üks asi. Inimesed tarbivad päris palju valesti ja halvasti , aga kuidas saaks siis paremini ? \nVäga tihti ma näen tik tokis, instagramis või facebookis, et on mingi uus meigitoode, moodne riietus või litsalt popolaarne asi. Sellised reklaamid ju panevad seda asja tahtma. Eriti ,siis kui see tuleb tuntud inimese  poolt. Paljud inimesed lähevadki selle õnge, et see nii uus ja lahe ja, et mul ka seda vaja, sest sellel tuntud  sisuloojal on see.Isegi mul on praegu nii, et tahaks väga seda uut meigitoodet, sest üks tik toki sisulooja  tegi sellest videio. Just selliste asjade ohvriks ei tasu langeda sest paljudele makstakse selle eest, et nad seda tutvustaks inimestele. See ei pruugi isegi hea olla ja võib sul lihstalt seisma jääda ja lõupuks sa viskad selle lihtsalt ära. Võiks ju enne mõelda ja kaaluda ja kas sa vajad seda, sest niikuinii tuleb uus see huulepulk või särk mida sa ka tahaskid, aga ei vaja .lõpuks sul koguneb neid asju liiga palju.\nMeil oleks vaja kas või koolis tunde, kus õpetatkse õigesti tarbima ja mitte üle tarbima.Kui kõik oleksid teadlikud mida nad põhujstavad asjade ära viskamise või hiinast odavata asjade tellimisega muudaks ju paljude meelt. tõesti paljusi, siis ka ei huvitaks, aga kui juba mõndasi huvitaks aitaks see kaasa. Need kõik riided mida hiinast tellitakse ( kiirmood) lõpetab lõpuks prügimäel sest mingi aeg enam pole need moes.kui keegi väidab, et ta „ vajab seda „ siis kas tõesti ? vajalik on see siis kui sa ei saa ilma  selleta elada, aga ilma selle ühe huulepulkata sa saad elada kui sul juba on mitu tükki .Palju parem oleks kui ei läheks kiirmeoga kaasa ja ostaks taaskasutuskeskusest riided või ostksid sellisied mida saaksid  mitu aastat kasutada. Kõik me saame ju panustada, et meie maailm oleks parem ja  ilusam koht.\nMa arvan , et me saaksime kõik paremini tarbida ja teisigi panema  seda tegema. Sisuloojad saaksid ju ka kõiki valgustada sellel teemal, sest  paljud ostavad asju just sellepärast, et nemad neid tutvustavad. Koolis oleks ka hea juba noorest peast õppida kuidas tarbida targalt ja see aitaks isegi raha sääasta.');
