INSERT INTO core.text(id, content)
VALUES ('a551fb0d-0813-4385-867d-80cf937ffd6f',
        'Peaaegu igale inimesele meeldib asju tarbida, aga kas olete mõelnud, et kui palju me igasuguseid maavarasid kulutame selle tootmise ja tarbimisega? Enamus tooteid ja riideid on toodetud Hiinas, kus võidakse väärkohelda inimesi väikese palgaga, ebaturvaliste töökeskkondadega, lapstööjõuga ja muu sellisega. Paljud inimesed ostavad asju Hiina poodidest meelelahutuse pärast, mitte et neil oleks neid tooteid või riideid vaja.\nEnamus riietest on tehtud naftast. Nafta on taastumatu maavara, mis võib reostada meie planeeti nafta põletamisel tekkivate gaasidega. Hiinas toodetud riided on parasjagu odavad, et neid saaks palju toota ja inimesed saaksid neid suure hulgaga osta. Aga see tähendab, et selle riideeseme kvaliteet ei saa ka väga suurepärane olla ja seetõttu ostetakse ja toodetakse neid üha rohkem. Minu arvates võiks toota kvaliteetsemaid riided, isegi kui need maksaksid mõnevõrra rohkem kui üüratult odavad riided. „Ei telliks Hiina veebipoodidest juba põhimõtte pärast asju, ei läheks kaasa sooduskampaaniatega“ arvas Moedisainer Eve Hanson.\nHiinas töötavad ulmeliselt palju inimesi tehastes ja üldiselt tootmisega seotud töödes. On olnud uuringuid Hiina tehastesse, et mis nendes tehastes toimub, kas järgitakse inimesteõigusid, üldist ohutust tehase sees, ja teisi asju. Enamus tehaseid ei pea kinni inimõigustes ja võtavad tööle haigeid, puudetega inimesi ja isegi lapsi. Minu arvates peaksid kõik inimesed olema võrdsed, saama õiglast palka, hoiduma inimõigustesse, ja muid asju.\nMinu arvates inimesed võiksid osta kvaliteetsemaid tooteid ja riideid, et ei oleks nii palju tootmist ja ei kuluks riided nii kiiresti. Samamoodi võiks toota kvaliteetsemat toodangut, isegi kui see võib olla kallim tarbijale kui ka tootjale. Et inimõigusi ei rikutaks, võiks osta asju sinule tuntud poodidest, kus ei rikuta inimõigusi ja oleks „Fair Trade“ märgiga tähistatud produkt.');
