INSERT INTO core.text(id, content)
VALUES ('ec7169bd-e87f-46ae-8ac7-17295e5b7de8',
        'Inimesed viskavaad ühes aastas väga palju toitu ära. Toitu on palju ja on inimesi kes saavad seda lubada endale rohkem kui teised.Toidu ära viskamine raiskab paljusi ressursse ja tekitab keskkonnakoormuse.\nIga inimene võiks vaadata mida ta ära viskab või siis võiksid inimesed prpgi sorteerida.Inimesed on harjunud toitu ära viskama ja nad ei saaks kohe toidu raiskamist vähendada ja prügi sorteerida ,sest nad on harjunud prügi ära viskama.Mõned inimesed arvavad et kui nad vähem toitu ära viskavad siis see ei mõjuta väga midagi.Tegeikult mõjutab see väga palju vahet pole palju sa prügi või toitu ära viskad.\nKui inimeseed viskavad prügi loodusesse siis metsloomad saavad kahjustad akui nad söövad näiteks plastikut.Klaaasist pudeleid ja purke ei tohiks kuskile niisama visata,sestklaasikillud on ohtlikud keegi võib näiteks need endale jalga astuda.Prügi võiks sorteerida nii et klasid ühte kohta papp teise kohta ja paper ja plastik ka nii.\nInimesed võiksid hakkada prügi sorteerima ja toitu ka.Näiteks igal inimesel võiks olla endal kodus kust ta saab prügi sorteerida,komposti saaks kuskile panna ja pudeleid ja purke ka kuskile.Et keskkonnal oleks parem ja loomad ei saaks viga ja et inimestel oleks endal ka parem.');
