INSERT INTO core.text(id, content)
VALUES ('8bd94c00-57c8-4b7c-999a-869bc217baf7',
        'Inimeste tarbimisharjumused on erinevad, kuid väga palju inimesi ei hinda riideid, toitu ning teisi eluks vajalike asju nii nagu peaks. Eriti palju visatakse ära toitu, mis on tegelikult veel söödav. Toidu raiskamisel on mitmeid miinuseid ning halbu pooli. Miks on toidu raiskamine kahjulik?\nRaha raiskamine. Inimesel on vaja süüa, et elus püsida, kuid kui toit visatakse ära enne, kui seda on veel võimalik tarbida, siis ei ole see mitte ainult toidu raiskamine, vaid ka raha raiskamine. Inimeste sissetulekud on erinevad ning on inimesi, kes saavad endale lubada toidu raiskamist, kuid see ei tähenda, et seda peaks tegema. toidu raiskamisel on peale raha ka teisi miinuseid.\nTööjõu ja ressursside raiskamine. Toidu tegemisse läheb palju aega ja ressursse. Inimesed kes tarbivad toitu mida valmistatakse, ei näe kui palju on toidu valmistaja toidu tegemisse kulutanud aega ning raha. Peale tööjõu, läheb toidu valmistamisesse ka teisi ressursse: maad, vett, energiat. Parema toidu saagikuse saavutamiseks kasutatakse toidu kasvatamiseks ka väetist, mis tekitab keskkonnale suurt koormust. Söödava toidu ära viskamisel läheb raisku ka kõik see vaev ja ressurssid, mis on kasutatud toidu valmistamisel.\nToidu raiskamine on kahjulik nii keskkonnale ning raisku läheb ka raha, tööjõud, ressurssid ja sellel on ka palju teisi miinuseid. Toidu raiskamine on inimestel juba harjumus, kuid mina pingestan inimesi rohkem jälgima mida nad ära viskavad ning veenduda kas see on ikka täiesti söömis kõlbetu, enne kui nad selle prügikasti viskavad. Toidu raiskamisel läheb raisku palju rohkem kui ainult see toit, mis ära vistakse.');
