INSERT INTO core.text(id, content)
VALUES ('bdc20ecc-c266-4291-8c79-3ec0278d66f0',
        'Inimeste tarbimisharjumusi on enamsti kohutav vaadata. Kõik nad viskavad ära perfektseid riideid, kõlblikuid toiduaineid ja palju muud. Paljud inimesed ei tea kuidas tegelikult vähendada oma raiskamist, nii et kuidas siis saaks vähendada rasikamist?\nTuleks teha inimestele populaarsetes foorumites ja sotsiaalmeediaplatvormidel selgust, et kui palju inimesed tegelikult raiskavad ja kuidas seda vähendada. Minu soovitus oleks näiteks, et keegi räägiks uudistes või kuskil mujal inimestele igaaastasest raiskamisest ja kuidas see meid kõiki mõjutab. Kõik me peaksime aru saama, et tegelikult on raiskamine väga tähtis asi mida me kõik peaksime oma eludes kontrollima.\nTeiseks viisiks et raiskamist ära hoida oleks taaskasutus. Taaskasutus on imelihtne. Mida mina personaalselt teeksin oleks see, et ma ei lähe ostma poodi endale uusi riideid, vaid ma kasutan neid riideid mis mul kodus on, seni kaua kuni need on realselt ribadeks kantud. Teine näide oleks, et toiduülejaagid panna näiteks kompostrisse et teha nendest komposti, mida saab kasutada jälle uute toiduainete kasvatamiseks.\nToidukao vähendamiseks, võiks kasvatada ise oma toiduaineid, oma toitu kasvatates tead et see ei ole täis mürke ja kui tuleb liiga palju toiduaineid siis saab alati kellegile anda või müüa. Kui aga sa ei taha oma toiduaineid ise kasvatada siis tuleb osta poest või turult, aga osta normaalses koguses, niipalju kui sa päriselt ka ära sööd, sellega vähendad toidu raiskamist.\nKuigi inimesed teavad, et raiskamine toimub igalpool, isegi nende kodus, siiski ei tee nad midagi selle ärahoidmiseks. Raiskamise vähendamiseks tuleb inimestele rääkida raiskamisest ja selle vähendamisest, õppida taaskasutama ja kasvatada omaenda toiduaineid.');
INSERT INTO core.text_property(text_id, property_name, property_value)
