INSERT INTO core.text(id, content)
VALUES ('0a40a4af-0ab1-49dc-8a02-328dee93aba9',
        'Paljud inimesed raiskavad asju mis neile tegelikkult vajalikkud on, ning ei hinda mis neil olemas on. Näiteks mina olen õnnelik kõige üle mis ma saan mitte, kui mingi asi ei meeldi viskan ära. Miks inimesed ei hooli riietest, ega toidust?\nPaljud inimesed ei tee seda meelega, et raisata asju mis vajalikud on näiteks aegunud toitu ei saa süüa ja väikseks jäänud riideid ei saa kanda just kui sull ei ole väiksemaid sugulasi või pereliikmeid. Aga mõned teevad seda meelega, et reostada keskkonda, ostavad kaugetest maadest riideid mis mõne ajaga lähevad katki või kui neile lihtsalt ei maitse midagi viskavad ära kui seda saaks mõne teise asja peale kasutada näiteks väetiseks või anda lemmikloomadele vms. Parem oleks kui lihtsalt osta riideid oma kodumaalt ja vaadata toiduainete kuupäevasi mis kehtiksid kauem.\nKõik peaksid mõistma kust tulevad toit või riided sest, kui inimesed raiskavad neid asju, tööstusted lihtsalt raiskavad materjale, et neid valmis ültse teha ja põllumajandus sammuti. Igal inimesel Eestis keskmiselt tekkib  61kg toidujäätmeid, ning hunnikute viisi riideid mida nad lihtsalt minema viskavad. Peaks mõtlema selle peale kuidas hoida keskkonda korras mitte lõbu pärast asju ära viskama. Mina hoolin kõigest mis meie ümber on ja tarvitan toitu ja riideid õigesti et midagi raisku ei läheks.\nLoodan et inimesed tulevikus mõistavad kuidas käia ümber toiduga ja kuidas hoida enda riideid ning peaksid mõtlema rohkem kuidas hoida keskkonda korras et kõike saaks kasutada kui vähegi võimalik.');
