INSERT INTO core.text(id, content)
VALUES ('bce1387b-aa3e-44f9-b24b-7916ad96591e',
        'Inimesed on harjunud ära viskama riideid ja toitu, mida nad enam ei tarbi mõtlemata tootmisele kulunud ressurssidele ja rahalistele kuludele. Toitu ära visates ei mõelda sellele, et raisatakse enda rahale lisaks veel maad, vett, energiat ja tööjõudu ning toidu tootmine tekitab ka tõsise keskkonnakoormuse, mida tekitab ka uute riiete ja rõivaste tootmine. Kuidas saaks inimene tarbida targemalt ja vähendada keskkonnakoormust?\nTarbides toiduaineid, mille tootmiseks ja kasvatamiseks on kasutatud väetisi ja erinevaid kemikaale, võivad süües sattuda need kemikaalid ka inimese organismi ning põldudelt loodusesse vihmaveega või taimi kastes. Väetises sisalduvate toitainete loodusesse sattumine võib viia erinevate veekogude kinnikasvamiseni, mille tagajärjel võivad kaotada mitmed loomad oma elupaigad ja loomaliike võib vähemaks jääda seega tarbides toiduaineid, mille kasvatamiseks pole kasutatud väetisi ja erinevaid kemikaale vähendatakse keskkonnakoormust ja need on ka inimesele ohutumad. Toitu tuleks osta täpselt nii palju, kui suudetakse ära tarbida, et vältida toidu ära viskamist kui ka raha ja toidu tootmisele kulunud ressursside raiskamist.\nKvaliteetsemaid riideid või taaskasutatud riideid ostes on pikas perspektiivis suurem rahaline kokkuhoid ja kvaliteetsemad riided kestavad kauem kui ebakvaliteetsed. Ebakvaliteetsed riided või nt Hiina veebipoodidest ostetud riided tavaliselt ei kesta nii kaua, vaid hakkad narmendama või mõnel muul moel kaotavad kiirelt oma välimuse, mistõttu hakkavad inimesed ostma uusi riideid juurde ning vanad visatakse kõrvale. Nii raisatakse kokku rohkem raha kui ostes kvaliteetne ja kauakestev riideese ja ka keskkonnakoormus on suurem ning raisatakse rohkem ressursse, mis on kulunud riideeseme või rõiva tootmiseks. Riiete ja rõivaste tootmisel paiskub tehastest atmosfääri suures koguses toksilisi gaase, mis lõhuvad Maa osoonikihti ja sademetena tagasi maapinnale langedes ka reostavad keskkonda, millega kaasnevad erinevad probleemid. \nKokku võttes tarbides vastavalt vajadusele täpses koguses toiduaineid ja ostes taaskasutatud või kvaliteetsemaid riideid,  hoiame loodust, vähendame keskkonnakoormust, säästame raha ja ka tootmiseks kuluvaid ressursse.');
