INSERT INTO core.text(id, content)
VALUES ('5b4f6adc-b45e-4bc0-8b44-66a8c9ebbf2c',
        'Inimeste tarbimis harjumused on erinevad. Mõni kasulikum kui teine. Mõnda tarbimisharjumust tehes või kasutades arvatakse küll, et ega see mingit suur mõju ei tekita, aga just need kahjustavad kõige rohkem. Millised on siis inimeste peamised tarbimisharjumused?\nEsiteks on inimesi kes ostavad Hiinast „ odavaid“ kaupu, lootes et on ka kvaliteetne. aga kvaliteedil ka kavlikteedil on vahe. Hiina  kaup on massi toodang ja sel juhul ei pöörata suurt tähelepanu kvaliteedile. Plus massi toodang reostab keskonda suurel määral. Lisaks on tarne aeg ka meeletult pikk. Inimesed tellivad igaltpoolt asju mida vaja pole, põhimõttega „Aga see on odav juu!“.Minu soovitus on ärge oske Hiinast ainult odavuse ja raha laristamise pärast. Minu iskliku näitena, on minu enda ema Hiina kauba fänn ja ostis suhtliselt thiti Hiinast, aga nüüd on vähemaks jäänud, ehkki pole enam üldse.\nIgapäevane poes käik on ka väga halb tarbimisharjumus.Rohkem läheb raha ja suurem võimalus, et prügikasti läheb toitu, mis on lihtsalt halvaks läinud selle ajaga või „ma ei söö/taha seda enam“. Eriti ulme on tühja kõhuga poes käik. Sel juhul läheb veel rohkem toitu raisku ja raha. Minu soovitus on teha nädala menüü, ja käia korra nädalas poes ja osta ainult seda mida vaja. Mina olen isiklikut oma emale mitu korda üritanud selgeks teha, et nädala plaan ja kord nädalas poes käik tuleb odavam ja ei lähe nii palju toitu raisku.\nKuigi inimeste tarbimis harjumused on erinevad, reostavad need keskkonda kuidagi moodi ikka. Nii et mõtle kas vajad ja kui palju vajad midagi, enne kui ostad. Ja kui teate kedagi nende tarbimisharjumustega siis antke nõu neile kuidas kasulikustada neid harjumusi.');
