INSERT INTO core.text(id, content)
VALUES ('2f4d7345-3c42-49af-bcd8-5099998073ef',
        'Inimeste tarbimisharjumused on kullukad ja ebavajalikud, see tõttu raisadakse palju ressurse. Raisatud tooteid on palju erinevaid. Tekkib küsimus, miks ja mida raiskavad inimesed oma harjumuste pärast.\nInimesed tihti peale raiskavad palju toitu. Selline harjumus tekkib tihti toiduga, mida see inimene ei taha süüa või on tal üle, selle pärast jääb aasta peale palju toitu kasutamata. Harjumusest võiks saada lathi nii, kui tekkib üle jääv toit võiks selle kellegile anda või kasutada mujal. Võimalusel ka mitte osta liialt toitu, mida ära ei jõua süüa. Selliste mõtteviisidega saaks kasutada toitu ilma seda raiskamata. \nTeine enim raiskamine on inimestel riided. Neid on inimestel palju ja enamused on kappis ilma kasutamata. Võimalusel saaks ära anda riideid, mida ei kasutata. Riideid võib taaskasutada, kui on riie katki või selliselt ei kasuta seda riiet. Neid on palju võimalusi muuta millekski, mida kasutadakse ja kantakse. Selle põhimõttega vähendaks raiskamist ja saaks riideid saata ringlusesse, mitte ei jätaks neid kappi vedelema.\nInimeste tarbimisharjumused on küllaltki ebavajalikud ja mõttetud, kuid neid saab koos oma mõttevisi ja käitumisega muuta paremaks. Riideid võib saata ringlusesse ja kasutuselle, toitu võib ära anda või olla mõistlikum kogustes. Tarbimisharjumusi on võimalik muuta paremaks ja mitte raisata tooteid, nagu riideid ja toitu.');
