INSERT INTO core.text(id, content)
VALUES ('330dce87-625a-4240-9b0c-4df4ff90c451',
        'Inimeste tarbimisharjumused on erinevad, aga ka raiskamine on igalühel erinev. Poes tundub, et meil on vaja näiteks riideid, aga hiljem jääb seisma ja ei leia kasutust. Kõige suurem probleem on selles, et hästi palju on emotsiooni oste ja tahetakse moega kaasas käia. Ostetakse uusi riideid, aga mood tihti muutub ja tuleb uus, mille jaoks minnakse jälle poodi. Miks me ostame riideid just poest, kui me saaksime taaskasutusest ja miks kodumaise toodangu asemel eelistama Hiina veebipoodidest tellida?\nSelle põhjus on väga lihtne. Esiteks taaskasutuspoodides maksavad riided sama palju, kui tavalises riide poes, kust me saame riided uuena ja pole keegi kandnud. Paljud riided, mida ei kanta ja ei leia kasutust, viiakse taaskasutusse, et kellegi vana rõivas oleks teise inimese uus. Hanson seletas, et kui tema käib vabatahtlikuna taaskasutuspoodide laos, siis rõivaid tekib iganädalaselt juurde ja need on meeletud hunnikud, aga väga õpetlik. Ta arvab, et noortele peaks hakkama tegema ekskursioone taaskasutuspoodide lattu, et näidata, milline raiskamine tegelikult toimub. Mina ostan taaskasutatud riideid pigem, kui uusi.\nTeiseks inimesed ostavad väga palju riideid ka interneti teel, näiteks Hiina veebipoodidest, kus on uued riided odavamad, kui taaskasutustes. Hanson väitis, et inimesed võiksid eelistada kodumaiseid oma lähedal toodetud asju ning pigem vähem kui rohkem, mitte tellida Hiina veebipoodidest asju just põhimõtte pärast ja ei läheks kaasa sooduskampaaniatega. Tean ka inimesi, kes tellivad sellepärast, et pakki on põnev oodata.\nMina olen Hansoniga nõus, et võiks noortele näidata, mis tegelikult toimub taaskasutuspoodide ladudes ja äkki on mõni noor, kes hakkab selle peale mõtlema. Ostab vähem riideid ja kasutab vanu riideid kuni on väikseks jäänud  või poest uue riide ostmise asemel läheb taaskastuspoodi ostma. Olen nõus sellega, et mõttetuid asju pole vaja tellida Hiina veebipoodidest, kui on mõnda kindlat asja vaja, siis pigem osta kodumaiseid oma lähedal toodetud asju.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('330dce87-625a-4240-9b0c-4df4ff90c451', 'title', 'Miks meil on vaja üleliigseid asju?');
