INSERT INTO core.text(id, content)
VALUES ('3449b98c-6d01-49bb-8b7c-e3a91f18f6b4',
        'Kõik inimesed tarbivad erinevalt, kuid raiskavad sama palju. inimesed ostavad toitu rohkem, kui jõuavad ära tarvita. Riietega on samamoodi ostetakse kokku palju riideid, kuid neid kõiki ei kasutada ja samamoodi on ka teiste toodetega ja need viiakse taaskasutuspoodidesse. Enne tuleb mõelda, kas sul on tõesti neid asju vaja, mida sa kokku ostad. \nToidu visatakse ära mitmetel põhjustel ja need on järgnevad: toit on riknenud, kasutustähtaja ületanud või söömisel ülejäänud, nagu tekstis mainitud. Et toidu ära viskamist vältida tuleb jälgida toidu kuupäeva ja arvestada palju sa jõuad tarbida. „Suurem osa riideid jõuavad taaskasutuspoodidesse, kuid riided on terved korralikud ning sinna viiakse ka selliseid riideid, mis mingil kaunil reklaamfotol näevad ilusad välja ja koosnevad naftast ja sa ei taha seda rohkem kanda, sest kehal on halb olla selles,“ selgitas Hanson.\nEnne toote ostmist tuleb vaadata, mis materjalist on see riie tehtud, et vältida riideeseme ära viskamist või taaskasutuspoodidesse sattumist. Eelistada võiks kodumaiseid tooteid. „Riideid mis koosnevad naftast leidub põhiliselt Hiina kaubamajadest,“ selgitas Hanson. Minu arvates tuleks vältida riiete ja muude  tarbeesemete ostmist Hiinast ja osta rohkem kodumaiseid kaupu. Toidu raiskamise teemadest oleks vaia kindlasti rohkem rääkida, kuna toidu tootmisele ei kulu ainult raha vaid ka palju maavarasid ja  osad maavarad on piiratud.');
INSERT INTO core.text_property(text_id, property_name, property_value)
