INSERT INTO core.text(id, content)
VALUES ('c4baec31-68cc-4796-bab8-2f39205a5210',
        'Me elame tarbijaühiskonnas, kus igapäevane elu ja sotsiaalne hierarhia on ehitatud tarbimisele. Kas meil on aga kõike, mida ostame vaja? Mis saab asjadest, mida ei ole?\nPeame iseenesest mõistetavaks, minna poodi ja osta kõike, mida hing ihaldab. Käia ajaviiteks ringi ja riiulitelt krahmata mõni trendikas särk või seelik, isegi kui meil neid kapis juba kümneid istub. Ainsaks takistuseks on raha, aga sellega aitavad Hiina veebipoed, kust saab odavalt ja kiirelt oma digitaalse korvi täita kõiksugu kraamiga. \nSarnane on lugu ka toidu ja teenustega. Minnakse poodi ostma kartulit ja piima, aga tullakse tagasi kolme toidukotitäie kraamiga. Ei teagi, kas süüdistada inimese tarbimis himu ja tühja kõhtu, mis aju eest otsuseid teeb, või meisterlikult koostatud pakendeid ja reklaame, mis ostlema kutsuvad. \nMiks on tarbimine probleem? Lõppude lõpuks, keda huvitab, mis sul seal kapis seisab? Lihtne, see on raiskamine. Keskmisel Eesti inimesel tekib 61kg toidujäätmeid, millest 42% on kadu. Rääkimata veel kõigist prügisse visatud pakenditest või kogumispunkti viidud kiirmoe riietest. Hea veel seegi, kui need asjad kuhugile kogumispunkti jõuavad, suur osa neist satub loodusesse, reostades seda.\nTarbimine on inimese jaoks sama naturaalne kui hingamine. Sellega kaasnevate tagajärgede peale ei mõelda, või neid ei peeta oluliseks. Me lähme kergesti kaasa trendidega ja oleme mõjutatud reklaamidest.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('c4baec31-68cc-4796-bab8-2f39205a5210', 'title', 'Tarbimine kui naturaalne tegevus');
