INSERT INTO core.text(id, content)
VALUES ('035de72f-06c1-4ea9-8214-85091947d869',
        'Inimesed tarbivad väga palju ühe aasta jooksul nii riideid, toitu ja palju muid asju. Nad ei mõtle sellele, et see on suur raiskamine, aastas keskmiselt on 42% toidukaubast ära visatud. Mina nõustun sellega, mis moedisainer E. Hanson ütles, et noori peaks sellisel teemal rohkem harima ja ma ütleks, et mitte ainult noori, vaid ka täiskasvanuid.\nSee riiete ära viskama ehk materjaalne kadu tekib kõige rohkem kiirmoe pärast. Hetkel on nii palju erinevaid moode käimas, et inimesed aind tellivad uusi riideid, unustavad vanad ära ja lõpuks viskavad minema. E. Hanson mainis ka eelnevalt „ma näen taaskasutuspoodide laos vabatahtlikuks käies seda rõivaste kogust, mis tekib iganädalaselt juurde.“  see näitab, kui palju ebavajalike riideid inimesed endale ostavad.\nJärgmine asi, mis on probleemiks on toidu ära viskamine. Ilmselt See tekib sellest, et poes käiakse ilma nimekirjata ja inimesed ostavad kõike, mis neid sellel momendil isutab. Hiljem jõuavad koju, isu pole enam ja viskavad ära. Näen juba enda ja lähedaste pealt ära, et see toidu ära viskama on liiga „normaalne,“ kuid tegelikul on see tohutu raha raiskamine. \nÜhesõnaga ma arvan, et E. Hasonil on väga head mõtted ja me kõik peaksime rohkem vaatama, mida koju kokku ostame, kui palju ostame ja kui suure osa me sellest tegelikult ära kasutame, nii noored kui ka täiskasvanud.');
