INSERT INTO core.text(id, content)
VALUES ('3b2c1688-6ceb-4dcf-adee-ec776283c29f',
        'Tänapäeva maailmas toimub meeletul viisil ületarbimist. Selline inimeste eluviis on halb loodusele ja seal elavatele loomadele, sest nende elupaigad võetakse üle. Kui nii edasi liikuda, muutuvad keskkonna probleemid aina suuremaks. Neile tuleb leida lahendus.\nNäiteks tekib majapidamistes suur toidukadu. Visatakse ära toit, mis oleks täitnud mõne teise inimese kõhu. See kõik algab juba poes käies, jõukam inimene paneb korvi asju täis, mõtlemata, kas see kaup ka kodus ära tarbitakse. Selline tegevus toob kaasa peale toidukao ka muid probleeme. Tuleb töötada, et see kaup saaks poelettidele ja ka pärast prügikonteineritesse, mis ületarbimise tõttu võtab meeletult tööjõudu, maad ja muid ressursse. Selle ära hoidmiseks tulekski alustada probleemi juurest. Arvan, et toidupoodides peaks olema süsteem, mis vähendab liigse kraami kaasa haaramist. Kas siis teha limiit rahale, mida poes kasutatakse , näiteks ühe ostu kohta ei saa ostleja kasutada rohkem kui 50 eurot või näiteks ei saa ostleja võtta üle limiidi kaupa. Lihtsaim viis oleks küll oma toidu raiskamise harjumust vähendada, kuid seda ei tee piisavalt inimesi.\nLiigne tarbimine toimub ka moemaailmas. Tänapäeval on paljudel harjumus osta odavaid riideid, neid kord või kaks kanda ja siis ära visata. Jällegi oleks seda võimalik peatada. Ostlejad peaksid hindama kvaliteeti ja mite kaasas käime kiirmoega. Err „Vikerhommikus“ on moedisainer Eve Hanson öelnud, et taaskasutuspoe ladudes peaks toimuma ekskursioonid, et näidata, milline raiskamine toimub. Olen Hansoniga täiesti nõus, selline kogemus avaks paljude inimeste silmad ja vähendaks tarbimist. Teiseks on tekkinud ka internetipoed, mis teevad mõtlematute ostude sooritamise veelgi lihtsamaks. Nende kasutust tuleks piirata.\nArvan, et selliseid, laiskusest ja harjumustest tekkinud, probleeme on tegelikult võimalik lahendada ja enamus inimesi suudaks tarbida mõistlikult. Ületarbimisega võitlemist tuleks teha efektiivsemalt ning avada rohkemate inimeste silmaring ja mõelda ka tuleviku peale.');
