INSERT INTO core.text(id, content)
VALUES ('c06fba88-7376-4c29-a789-285c2d86450e',
        'Viimastel aastatel on olnud suurteks probleemideks keskkonna reostamisega seotud probleemid. Näiteks on inimesed hakanud ostma tooteid rohkem kiirmoepoodidest, milleks on praegu populaarseks osutunud erinevad hiina veebipoed, sest inimesed arvavad, et sealt on tooteid „soodsam“ osta. Teiseks suureks probleemiks on ületootmine, mis on põhjustatud ületarbimisest. Inimesed ostavad ja valmistavad üleliija toitu, mis läheb pärast raisku ilma, et nad teaksid mis võib olla selle kõige tagajärg. \nÜheks ülemaailmeks probleemiks, sealhulgas Eestis, on suureks probleemiks tulnud toidu ületarbimine ja tootmine. Artiklis Tarbitoitutargalt.ee/toiudukaost/ on mainitud järgmiselt: „On inimesi, kes raiskavad toitu, sest nad saavad seda endale lubada. Samas arvavad ka väiksemaid koguseid toitu ära viskavad inimesed, et sellega nad suurt pilti ei mõjuta.“ Minu ettepanekul peaksid inimesed mõtlema endale vajalikud kogused ja kindlad asjad välja, enne kui nad lähevad ebavajalikke tooteid ostma. See ei oma tähtsust, kes võib endale vähem lubada või kes rohkem. Tähtis on see, kuidas ja kui säästlikult sa oskad oma ressursse kasutada. Enda kogemusest ei saa ma iseennastki selles olukorras kaitsta, sest ma raiskan ka üsna palju toitu sellepärast, et ma olen toidu tegemisel liialdanud. Olen võimalikul palju proovinud seda parandada ja loodan, et ka teisedki on selle peale mõelnud. \nPaljud noored on sattunud uue trendi hukka, milleks on hiina kiirmoepoodidest oma riiete ostmine. „Vikerhommik“ intervjuus lausus Anu Välba järgmiselt: „Eelistada võiks kodumaiseid oma lähedal toodetud asju ning pigem vähem kui rohkem.“  Kahjuks ei saa paljud noored aru sellest, kui kahjulik ja mittesäästlik on hiina veebipoodidest toodetud. See on selle tõttu, et noored on ka väga palju mõjutatud sotsiaal meediast. Enda vaatepildist võin ma öelda, et olen ka hiina veebipoodide ohvriks sattunud aga ma ei kasuta seda enam nii palju, sest olen ise ka aru saanud kui kahjulikud nende tooted tegelt on. Olen Anu öeldud lausega: „Ma arvan, et peaks hakkama noortele tegema ekskursioone taaskasutuspoodide lattu, et näidata milline raiskamine tegelikult toimub.“ nõus, sest paljud noored ei pruugi kahjust aru saada enne kui nad seda ise näevad. Olen hakanud viimastel aegadel ka ise taaskasutuspoodides käima. Leian, et see on keskkonnasäästlikum, lõbusam ja ka soodne tegevus. \nKokkuvõtteks võib öelda, et keskkonna reostus ja ületootmine ja tarbimine pole väga kahjuks paranenud nagu peaks. Seda kõike saab ainult parandada inimese enda tegudega. Inimesed võiksid mõelda oma ostude tagajärgedele ja mõelda välja erinevaid viise, kuidas olla säästlikum. See pole hea ainult ka keskkonnale, vaid ka sinule endale ja ka su rahakotile, mida sa saaksid kasutada enda ning perega ajaveetmiseks näiteks kinos. Hoiame ennast ja oma keskkonda.');
INSERT INTO core.text_property(text_id, property_name, property_value)
