INSERT INTO core.text(id, content)
VALUES ('0e87494f-7841-4151-bc7f-a39452cc7969',
        'Ma arvan et pole palju neid kes ei nõustuks, et tänapäeval on edukates riikides enamustel tekkinud selline tunne, et igasugused masiivselt toodatud tooted nagu toit, riided ning tehnika on iseenesestmõistetav. kuid hoolimatta sellest kas me sellele mõtleme või mitte on ilmselge, et paljudele riikidele oleks selline elamine lausa luksus.\nSelline elamine on juba meie ühiskonda nii sisse imbunud, et me isegi ei mõtle sellele kui palju vedanud meil on, et me ei pea enam muretsema sellest kust oma järgmist einet saada või ööt veeta. Ma arvan et see on kindlasti imeline, sest see tähendab et me ei pea enam elama lihtsalt selleks et ellu jääda vaid saame elu rohkem nautida. \nSellest hoolimata on sellisel luksuslikul elamisel ka halb külg. Masiivne tootmine tekitab üüratult keskonna kahju. Nii palju kui me ka seda ka ei naudiks, igapäevane tarbimine on väga kahjulik eluviis. Sellest kuidas seda probleemi lahendada ma kahjuks kirjutada ei oska. Siiski üldiselt võin ma öelda,  et me peaks elama nii et me keskonda ei  reostaks, kuid seda viisil mis oeks siiski nauditav, sest päris vaesuses me ilmselt elada ei tahaks, eriti kui on juba teada kui hea elu saaks olla.\nKokkuvõtteks arvan, et kõige parem lahendus oleks leida viis, kuidas saaks elada sarnases luksuses nagu me juba elame anult et keskonnasäästlikumalt. Kuid elleks peame me leiama viise kuidas suurfirmad saaksid toota keskonnasäästlikumalt keskonnasääslikumaid asju.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('0e87494f-7841-4151-bc7f-a39452cc7969', 'title', 'Kuidas ma suhtun inimeste tarbimisharjumuse?');
