INSERT INTO core.text(id, content)
VALUES ('05a490b5-d4bf-4a36-b3f6-de16a23021c9',
        'Kõik me käime loomaaedades vaatama erinevaid loomi ja mõnikord tahame isegi neid toita. Me näeme loomi loomaaias väga nunnuna ja huvitavana, kuid vahel ei märka kui raskelt nad seal elavad. \nIga päev käivad inimesed vaatama loomi andes raha sisenemisel. Naeravad, pildistavad nagu oleksid loomad mänguasjad. Miks inimesed ei märka, et loomad elavad väikestes  puurides, kus on vähe kohta kus kõndida ja kui must seal on. Loomad surevad sellestes tingimustes ära.\nVõtame näiteks meie Tallinna loomaaia valget karu. Alustame sellega, et valged karud peavad elama kohtades kus on palju vaba ruumi, maas on lumi ja õhutemperatuur peab olema vähemalt -10 kraadi. Tallinna loomaaias elab karu väikses puuris, kus on vähe ruumi ja kus on suur bassein väga tume rohelise veega. Bassein on must ja keegi seda ei korista. Karu on koguaeg mustas vees, kuna tal on palav. Ja elab ta seal üksi. Selle peale on väga valus vaadata.\nSee tarbimisharjumus käia loomaaias ning jätta märkamatu loomade olukorda, pole kõige parem mõte. Me anname raha selleks, et vaadata haigete loomade peale. „Miks inimestele see meeldib?“- see küsimus on paljude inimeste peas. Me saame neid aidata toetades loomaaeda rahaliselt, näiteks alustada projekti ja hakata raha koguma. Nii me saame säilitada paljude loomade elusid.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('05a490b5-d4bf-4a36-b3f6-de16a23021c9', 'title', 'Loomade vaesus loomaaedades');
