INSERT INTO core.text(id, content)
VALUES ('b17f5c0a-28da-4c7a-b179-58196c3bc2d0',
        'Tänapäeval inimestel on väga palju igasuguseid harjumusi, mis ei ole alati head ja mis võivad meie maailma kahjustada.\nPaljudel inimestel on selline harjumus, et kui mingi toit muutub halvaks või lihtsalt selle toidu kuupäev on juba möödunud, siis nad tavaliselt lihtsalt viskavad seda ära ja isegi ei mõtle selle peale, et see võib meie maailma kuidagi kahjustada. Paljud inimesed ei saa aru, et kui mõnel toidul möödus selle kuupäev, ei tähenda, et see toit on juba halb ja seda peab ära viskama. Sammuti paljud inimesed ei saa aru ka seda, et nad ei raiska ainult enda raha, vaid nad raiskavad ka teisi ressursse, mis on näiteks maa, vesi, energia ja tööjõud.\nSelleks, et lahendada sellist probleemi, on Tallinnas olemas näiteks Toidupank, mis aitab toitu hoida. Toidupoodides alati on toit mille kuupäev on juba möödunud ja arusaadav, et poodid ei tohi sellist toitu müüa, selleks ongi tehtud Toidupank, mis võtab sellist toitu endale, kontrollib seda ja seejärel jagab seda inimestele kellel on näiteks rahalised probleemid ja kes ei saa endale toitu osta.\nMa arvan, et kõik inimesed peavad oskama toitu hoidma, selleks et mitte raiskama meie maailma ressursse. Sammuti mulle väga meeldib, et Tallinnas oli leidud selline lahendus nagu Toidupank ja ma arvan, et see aitab mitte ainult toitu hoida, vaid see aitab ka inimesi kellel on mingit probleemid.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('b17f5c0a-28da-4c7a-b179-58196c3bc2d0', 'title', 'Inimeste tarbimisharjumused');
