INSERT INTO core.text(id, content)
VALUES ('6069a4de-86dd-402a-87af-b5242698b246',
        'Palju inimesi maalimas viskavad toidu prügikasti, sest nad arvavad ,et toidul pole väärtust ja seda on palju maailmas. Inimesd ei hooli meie planeedist ja seda tuleb lahendada.Kuidas saab seda takistada?\nInimeste seas paljud viskavad toitu prügikasti.  See on väga populaarne koolides läbi maailma. Tavaliselt õpilased teevad seda ,sest nendele ei meeldinud toit. Õpilastele meeldib kui toit on ilusti valmistatud ja lõhnab hästi.\nÕpilastele peaks tegema ekskurioone, kus igaüks vaataks mida ta tarbib ning eelistaks kvaliteetset toitu oma kodulinnas. Õpilased armastavad käia poes mis on kooli kõrval ja sealt osta endale snäkke ja jooke. Nad ostavad ebatervislikku toitu ja sellest võib õpilasel olla kõhuvalud jms. See tekkib ,sest toidus on kemikaale mis tapab meie organismi.\nSee jutt käib ka riiete kohta. Riideid on samapalju kui toitu ja isegi rohkem.Sinna viiakse riideid mis on kulunud või väga vanad.Aga tegelikult võib neid riideid taaskasutada ja teha uusi riideid.Õpilastele tuleb teha ekskursioone taaskasutuspoodide lattu,  et näidata, milline raiskamine tegelikult toimub.\nInimestele tuleb näidata kui oluline on loodus meie elus ,selleks tuleb neile teha ekskursioone ja  ettepanekuid.Inimesed kes hoolivad loodusest on kangelsed ja nendelt tuleb võtta eeskuju. Ma usun ,et iga inimese südames on midagi head.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('6069a4de-86dd-402a-87af-b5242698b246', 'title', 'Maa on meie kodu');
