INSERT INTO core.text(id, content)
VALUES ('ede00d19-1836-42a3-bd1e-c9cc0540b323',
        'Tänapäeval on suureks probleemiks inimeste kehvad tarbimisharjumused, mis pole kahjuks jätkusuutlikud. Me ei saa aru inimestena, kui suurt kahju tekitame iseendale ja meie loodusele, sest ei mõtle sellest, kuidas erinevad tooted, mida tarbime, meieni jõuavad. Ma usun, et seda probleemi saab kindlasti lahendada, aga lihtsalt mitte üleöö ning sellest peavad kõik osa võtma, et see töötaks.\nÜks inimeste halvimaid harjumusi on riiete liigne ostmine, kui selleks pole tegelikult vajadust. Jõukamad inimesed ostavad hunnikutes kalleid riideid ja kannavad neid ainult üks kord, kui tegelikult võiks osta pigem riideid ning neid annetada inimestele, kes neid endale soetada ei jaksa ja sinna, kus on vajadus. Või ostavad inimesed hoopis riideid kiirmoepoodidest, kus kvaliteet jätab soovida – need rõivad ei kesta ning tarbija peab tihedamini väsinud riided uutega asendama. Arvan, et inimesed, kellel on võimalik, peaksid maksma pigem kvaliteedi eest, sest need säilivad kauem ja nii hoiame loodust.\nTeine suur tegur, mis meid kindlasti suurelt mõjutab on toidu raiskamine. Võtame toidu olemasolu enesestmõistetavana ja ei mõtle, kuidas meie tegevused mõjutavad keskkonda. Me ei raiska sellega vaid omaenda raha, vaid ka muid ressursse. Olen ise täheldanud, et inimesed tihti ei planeeri ette, mida on tegelikult vaja osta ning poes käies ostavad tooteid, mis hiljem kodus lihtsalt rikknevad või ostetakse lihtsalt liiga suurtes kogustes mingeid tooraineid. On ka inimesi, kes viskavad ära toiduiane, mille parim enne on läbi, ajades selle sassi märgistusega „kõlblik kuni“,  kui tegelikult saab seda veel täiesti ohutult tarbida. Arvan, et inimesed saaksid toiduraiskamist vähendada, kui nad planeeriksid enne poes käiku ostunimekirja läbi ning jägiksid ka toodete peal olevaid märgistusi.\nMa usun, et saame muuta enda tarbimisharjumusi, peame selleks teadvustama ka teisi, sest kui koos tegutseme, siis asi sujub. Peame jälgima, et tarbiksime mõõdukas koguses ja kvaliteetseid tooteid, eelistades omaenda riigi produkte. Me peame mõtlema ka teistest ning tulevikust, mitte ainult iseendast, sest ainult nii see toimiks.');
