INSERT INTO core.text(id, content)
VALUES ('bdbebb8e-62f0-4a50-8c43-255c49f1198f',
        'Igapäevaselt meie või meie ümber olevad inimesed viskavad toitu ära, kulutavad raha asjade peale mida vaja pole, riiete äraviskamine. Meie ühiskond ei pane tähele seda kui palju me raiskame eluvajalikke asju, mida vajaksid väga paljud teised. \nMinu jaoks võiksid inimesed hakata mõtlema sellele, kuhu raha läheb ja kas läheb väärtuslikku kohta. Milleks on vaja osta 10 õuna kui suudad nädalaga ainult ära süüa 5 ja juba siis on need halvaks läinud ning tuleb ära visata. Täpselt sama ka riietega, milleks osta uus pluus kui sul on sarnaseid juba 3 tükki ja uut kannad paar korda. See ongi minu jaoks suur ja mõttetu raiskamine mida paratamatult me kõik teeme.\nAlustekstis nimega „Toidukaost“ on toodud välja, et mõni inimene raiskab, sest tal lihtsalt on see võimalus. Minu jaoks on see loll ja lapsik mõte, inimene kellel on seda raha saaks toetada inimesi kellel on toiduhäda, rahaprobleemid ja mida iganes veel.\nUuringud ja statistika näitab, et Eesti majapidamises läheb toidujäänusteks 61kg toitu, seda on ulme mõelda. Sellest 61kg-st kõigest 42% on toidukadu. Ka meie majapidamises on toitu, mis jääb järgi küll aga me seda ei viska ära. Meil on 2 suurt koera, kes tihtipeale söövad heameelega meie toitu.\nMa saan aru, et toidu ära viskamine on lihtne hea viis selle lahendamiseks, aga enne toidutegemist või tegelikult ükskõik kuhu see raha läheb, tuleb mõelda kas see on ikka seda väärt.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('bdbebb8e-62f0-4a50-8c43-255c49f1198f', 'title', 'Inimese toidutarbimisharjumused');
