INSERT INTO core.text(id, content)
VALUES ('7ad49c1f-de79-430c-977b-0bab493faa02',
        'Inimesed tarbivad väga palju erinevaid asju. Näiteks kütust, elektrit, toitu, sigarette ja riideid. Sellega kaasneb ka palju kahju tegelikult, aga inimesed ei mõtle sellele.\nToit on küll tähtis ja vajalik, aga näiteks eestlased raiskavad tihti seda ja ei tarbi mõistlikult. Nad ostavad toitu liiga palju ja see läheb kõik riknema. Lisaks enamasti käib toiduga kaasas pakend, mille eest ei kanta hoolt, pakend leiab tihti vale tee loodusesse. Inimesed peaksid sellega arvestama, et see on kahjulik. Seda tuleks muuta, sest kõik mida inimesed teevad, nad teevad seda endale, mitte kellelegi teisele.\nPaljud inimesed suitsetavad ja seda tehes nad tarbivad mürgist suitsu. Suits on inimestele kahjulik ja võib tekitada vähki. Inimesed suitsetavad ja viskavad oma tehtud sigaretid maha, väga harva leiavad need tee õigesse kohta. Vahest võib see sigaret veel põleda ja tekitada looduses põlenguid. See tekitab reostust.\nEnamus inimesi vähemalt Eestis sõidab autodega, seda tehes auto tihti tarbib kütust. See on kahjulik, sest see saastab õhku. Inimesed ei mõtle selle peale. Nad võiksid kõik omada vähem autosid ja omavahel neid jagada.\nElekter on veel tähtis osa inimeste elust. Tänapäeval enamus inimesi ei oska ilma selleta elada ja seetõttu nad tarbivad seda palju. Nad raiskavad seda palju, sest tihti nad ei märka, et mõni seade kasutab koguaeg elektrit. Lähevad reisile jätavad näiteks külmkapi tööle, aga see tegelikult tarbib koguaeg elektrit. Inimesed peaksid jälgima seda, sest siis säästavad nad raha ja elektrit.\nPaljud inimesed kannavad riideid ja nad tarbivad neid, seda tehes. Tihti nad ostavad neid liiga palju kokku ja siis ei kasuta neid. Siis tootjad toodavad riideid palju. Poleks vaja, nii palju enam toota, sest tegelikult on riideid liiga palju, mida inimesed saaks tarbida. Näiteks tippsportlastel on tihti palju riideid ja nemad annetavad neid, et teised saaksid ka riideid tarbida.\nKokkuvõtteks inimesed tarbivad väga palju erinevaid asju. Inimesed peaksid rohkem sellele mõtlema ja tegema paremaid otsuseid, et keskkond püsiks puhtana. Nad tõesti tarbivad palju ja võiksid anda neile, kellel on vähe. Mitte neile kellel on liiga palju.');
INSERT INTO core.text_property(text_id, property_name, property_value)
