INSERT INTO core.text(id, content)
VALUES ('a5283a87-b6f0-4dd7-af27-bc2fec49cce1',
        'Inimesed ei pääse enam tänapäeva maailmas tarbimise käest – see on viis, kuidas hankida omale eluks vajalikke ressursse. Tihti tekib aga inimestel tarbimisvajadus, mis tähendab, et inimene ostab endale rohkem ja ka mõttetuid asju, mida ta tegelikult ei suuda ära tarbida või mida tal tegelikult elus vaja pole.\nPõhjuseid, miks inimestel tarbimisvajadus kui sõltuvus tekib, on palju. Üheks peamiseks põhjuseks on soodsad hinnad ja sooduspakkumised. Inimene ei mõtle enam internetis e-poodeldes, kas tal ikka on seda toodet vaja ning kas see on  ka kvaliteetne. Kahjuks mõtleb inimene hoopis vastupidiselt. Head näited sellest on Hiina e-poed, kus on väga odavad hinnad, kuid mitte nii kvaliteetsed tooted. \nJärgmine põhjus on massiline ostmine. Pööraselt palju tuleb maailmas ette seda, et inimene läheb poodi ühe kindla toote järele, kuid tuleb tagasi kärutäie asjadega ning sellest 25% ta hiljem ära ei tarbi. Inimene arvab alati endast liiga palju ning selle tulemusena ostab ta ka endale liiga palju, näiteks toitu. Peale selle on inimesed üksteise peale kadedad ja pahatahtlikud, mis viib muidugi selleni, et inimene ostab endale mingit toodet võimalikult palju, et keegi teine saaks vähem. Tunnen seda ka omalt poolt.\nNeid põhjuseid on veel mitukümmend, kuid minu arvates on need kaks peamist. Lisaks on ka nendest tarbimisharjumustest väga raske jagu saada, seepärast  meenutabki tarbimine mulle sõltuvust. Õnneks luuakse igapäevaselt ideid, kuidas maailma paremaks muuta ning tarbimist vähendada. Praeguseks on kasutusele võetud näiteks taaraautomaadid, taaskasutuskeskused jne.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('a5283a87-b6f0-4dd7-af27-bc2fec49cce1', 'title', 'Tarbimisvajadus kui sõltuvus');
