INSERT INTO core.text(id, content)
VALUES ('25321ae1-750e-4cdd-8384-13382eb3f534',
        'Toiduharjumus on suur probleem maailmas aga ka minu kodus. Paljud inimesed ei saa sellest ise aru kuid palju uuringud näitavad tõsist murekohta. Näiteks paljud lapsed ei söö igat toitu mida neile pakkutakse seega juba saab tähele panna kui ohtralt toitu selle pealt tühja läheb.\nMina ütlen ausalt, et minu kodus on päris suur toiduraiskamine igapäevaselt. Tavaliselt kui keegi on süüa teinud ja ma pole koju ei jõudnud siis ma isegiei söö õhtusööki. See polr kuigi hea sulle endale ja maailmale. Esiteks sa kahjustad eda tervist mitte söömisega ja teiseks maailma kuna see söök peab kuskile ikka jõudma. Palju inimesed on pirtsagad mingite toitude suhtes nii ka mina. Seega üritavad neid toite inimesed vältida. \nSuurroll ka toidu raiskamises on söögi kohtadel. Üks päev käib hunnik inimesi järgmine kord minimaalselt. seega restoranid ja kohvikud ei tea täpselt palju süüa teha. Olen ka väga paljudes poodides ja söögikohtades näinud kuidas müüakse eelmise päeva tooteid ja need on ka tavalislt mingi soodustusega, et inimesed neid ostaks. See on just sellepärast, et toit raisku ei läheks.\nPaljud inimesed arvatavasti ei tea kui suur probleem tegelt toidu raiskamine on. Mina arvan, et sellest võiks rohkem rääkida. Sellest ainult ei piisa iga inimene peab sellele kaasa aitama.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('25321ae1-750e-4cdd-8384-13382eb3f534', 'title', 'Tarbimisharjumused kui probleem');
