INSERT INTO core.text(id, content)
VALUES ('dd050fba-249b-44be-a619-a96567a5e0bb',
        'Inimeste tarbimisharjumused on väga erinevad. On inimesi, kes püüavad tooteid tarbida mõõdukalt, aga kahjuks osa rahvast ostab asju mõtlematult. Inimesed ei oska isegi arvata, kuidas  liigtarbimine meie elu mõjutab.\nToidu raiskamine on viimasel ajal väga tihe nähtus. Seda võib näha peaaegu igas Eesti koolis, kui paljud õpilased võtavad endale liiga palju toitu, millest tihti mingi osa lõpetab prügikastis. Samuti ostavad inimesed poodides üleliia palju toiduaineid, mida kõike lõpuni tarbida nad ei jõua. Et mingitki kahju vältida, müüvad enamus toidupoed odavamalt tooteid, mille tarbimisaeg hakkab lähenema.  Kindlasti on veel palju viise, kuidas toidu liigtarbimist vähendada ja neid peaks rohkem ka inimestele tutvustama.\nVäga suureks probleemiks on ka kiirmood ja riiete liiga suures ja mõtetus koguses kokkuostmine. Paljud riiete maaletoojad teevad oma tooteid kvaliteetselt, mis tähendab ka kallimat hinda. Mõni osa rahvast saab seda endale lubada. Kahjuks ostavad väga paljud endale riideid ikkagi kiirmoe poodidest, mida nad kannavad ainult paar korda ja siis hiljem need halva kvaliteedi ja väljanägemise pärast ära viskavad. Need tooted on tehtud enamasti  kas polüestrist või millestki muust, mis on kehale kandes ebameeldiv. Kindlasti on mõtekam teha väljaminekud ja osta endale riideid, mida sa saad kanda veel kuid, kui mitte aastaid. Õnneks pole inimesed unustanud taaskasutuspoode, kust võib tegelikult leida väga korralikke ja kantavaid riideid.\nKahjuks on ületarbimisel ka omad tagajärjed. Inimesed võivad mõelda, et raisku läinud toiduained ja paar korda kantud ja siis hiljem ära visatud T-särk ei mõjuta midagi, aga see ei ole nii. Kõige rohkem saab kannatada meie loodus. Kasutatakse erinevaid kemikaale, mis reostavad meie loodust väga suures koguses. Samuti suured tehased koormavad meie loodust väga, mida on kurb pealt vaadata.\nÜletarbimine on meie praeguses maailmas suur probleem ja sellele tuleb leida mõistlikuid lahendusi. Paljud inimesed ei hooli liigtarbimise mõjust meie loodusele ja keskkonnale. Loodan väga, et tulevikus olukord muutub.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('dd050fba-249b-44be-a619-a96567a5e0bb', 'title', 'Kas peaksime oma tarbimisharjumusi muutma?');
