INSERT INTO core.text(id, content)
VALUES ('00cdecf8-ed37-43c4-ab41-39fd01695f44',
        'Inimeste tarbimisharjumused on erinevad. Osad tarbivad asju rohkem ja osad vähem mis on elus normaalne. Aga enamik inimesi tarbib nii väikestes kogustes, et see võib kahjustada füüsilist- ja mentaalset tervist. Kuid ka on inimesi kes tarbivad ilegaalseid asju mis kahjustab tervist veelgi rohkem. Miks tarbimisharjumused erinevad on?\nInimesed tarbivad asju enda kehakaalu, suuruse ja isu järgi. Osa sealhulgas tarbib vähe kuna kas neil on rahalised probleemid või nad on sõltuvuses mingi teatud ainega nt alkohol, narkootilised ained, rohud jne. Inimesi ei saa sundida sööma mida nad ei taha, sest äkki neil on alergjad millest keegi ei tea või paneb see neid ooksele. Vägisi söötes võib inimene kaodata söögi isu või veelgi enamat. Narkootiliste ainete ületõmbamise või tegemise riski faktorid on suured. Võib kaodata enda elu, organid, hääle, silma nägemise. Võib tekkida ka kõrvalised toimed nt delusioon, hajutised, vaimud, sisemine verejooks, aju kahjustus, aju välja lülitused, hapniku puudused, teadvuse kadu, juuste kadu, liigeste või kehaosade amputeerimine, kasvaja protsendi suurenemine, suurenenud vähi tekke, naha peal mädanikud jne.\nKõik on erinevad ja võivad teha oma asju, mida naad harrastavad. Mina ei saa keelata asju mida teised inimesed teevad. Teised ise valivad kas nad söövad või ei söö, kas nad tarvitavad ilekaalseid aineid või mitte. elu on erinev ei saa keerelda ainult ühe inimeseümber.');
