INSERT INTO core.text(id, content)
VALUES ('3d546486-0c56-43e3-99ad-4facd6682599',
        'See kirjand räägib tänapäeva ühest suurimast probleemist: tarbimisharjumusest. Ma kirjutan kirjandis kust see alguse saab, miks see on kahjulik keskkonnale ja kuidas seda parandada või vältida.\nEnamus tarbmisharjumusest saab alguse Hiinast: seal on hiiglaslikud tööstused, mis toodavad tohutult tooteid. Paljud tooted tehakse mõttega kvantiteet kvaliteedile, mis tekkitab tihti tooteid, mida kasutatakse ainult üks kord, läheb katki ja visatakse ära, või kasutatake korra ja visatakse ära, sest seda oli ebamugav kasutada. Lisaks on veel tooteid, mis ongi ainult korra kasutamiseks, näiteks plastnoad, plastkahvlid, plastlusikad jne. Selline tootmine ei ole jätkusuutlik, ressursisäästlik ega keskkonnasõbralik.\nTarbimisharjumused on probleemiks, sest see ei ole keskkonnasõbralik ja kui sedasi jätkata saavad maailma ressursid lõpuks otsa, tekkib kasvuhoonegaase (nt süsihappegaas ehk süsinikdioksiid), mis aitavad kaasa kliimasoojenemisele.\nSeda saab vältida kui näiteks tarbida kodumaiseid, keskkonnasäästlikuimaid tooteid, see vähendab ressurside kasutmist nii tootmiseks kui ka transportimiseks muidu kasutatud ressurse. See võib tuua rohkem töökohti, sest igas riigis oleksid oma tehased ja vabrikud, see küll kulutab rohkem ressurse ehitamisele kui praegune süsteem, aga pikkas mõttes on see keskkonnasäästlikum. Teine viis on seda parandada, näiteks panna igale vabrikule maailmas teatud kvaliteedi piiri, keelustada keskkonnale kahjulikud tooted, mis on ühekordsed.\nKui tahame tarbimisharjumustega kaasnevate probleemidest jagu saada peame hindama enda igapäevast elu: kui palju me tarbime, mida me tarbime, kuidas me saaks seda vähendada ja kuidas säästa keskkonda.');
INSERT INTO core.text_property(text_id, property_name, property_value)
