INSERT INTO core.text(id, content)
VALUES ('8f7f1850-8fea-4d70-8ff6-3a88ebfb1f4e',
        'Inimene on nii huviav olend, et on võimeline tarbima vähem, rohkem või just nii palju, kui tal parasjagu vaja on. On inimesi, kes arvavad et neil on vaja tarbida enda kogusest rohkem, kuid päeva lõpuks viskavad nad oma jäägid minema.\nKõige rohkem mida inimesed tarbivad on muidug toit. Ilma toiduta inimene ei saaks elada. Kõige hullem on toidukadu. Mõned inimesed nagu oli mainitud tarbivad suuremaid kogusi kui neil endal on vaja ning seetõtu tekib toidukadu. Muidugi toidukadu sõltub ka sellest, mitu inimest elab peres. \nTeine kõige suurem mure tarbimises on riided. Inimene võib osta endale uusi riideid nii igapäev kui ka iga kuu või enam. On inimesei kes ei suuda ühte särki kanda ka nädal ning viskavad selle kohe peale nädalat kasutamist minema, kuid on ka selliseid kes ei viska kohe riideid minema vaid kannavad oma riideid nii kaua kui võimalik. Nagu Eve Hanson ütles: „ Ei telliks Hiina veebipoodidest juba põhimõtte pärast asju, ei läheks kaasa sooduskampaaniatega, vaid eelistada võiks kodumaiseid oma lähedal toodetud asju ning pigem vähem kui rohkem.“\nOn ka muid tarbimisi, mida inimene tarbib, näiteks mõni inimene tarbib ainult oma igapäevases elus poevett ning ei joo üldse kraanivett. See on jaburaimaid tarbimisi, millest olen kuulnud. Poevee tarbimine on vähem soodsam inimese rahakotile kui kraanivesi.\nTarbimine on üks olulisemaid asju, mida tuleb läbi mõelda väga hoolikalt, mida ja kui palju tuleb osta, et ei jääks ülejääki mis lõppude lõpuks läheb prügimäele.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('8f7f1850-8fea-4d70-8ff6-3a88ebfb1f4e', 'title', 'Inimene kui tarbija');
