INSERT INTO core.text(id, content)
VALUES ('b98b3d43-6c04-49d1-a932-c4a95a02bc85',
        'Maailmas raiskavad inimesed palju riideid ja toitu. Suur osa selles sõltub inimeste tarbimisharjumustest. Inimesed ei pruugi just tähelepanna aga keskmiselt tekkib iga Eesti inimese kohta 61kg toidu jäätmeid.\nNagu ennem mainitud, inimesed kulutavad palju asju mida saaks veel kasutada, näiteks riided mida ostetaks ja kantakse ühe korra ja siis visatakse ära. Üks suurim üle jääk toidus ja riietes juhtub siis kui osta palju soodushinnaga. Kuid inimese pilgu alt vaatades näeb see välja hea  pakkuminsena, et saada palju asju odavama hinnaga. Aga kahjuks pole see loodusele nii hea kui inimsele, sest kogu see protsess, et riided ja toit meie juurde jõuaksid on loodus kahjulik.\nSelle vähendamiseks tulesk selgeks teha inimestel, et nad ostaksid ainult seda mida neil vaja läheks ja mida nad kasutaksid. Mis on päris keeruline, sest kõik inimesed ei saa sellest aru ja ikka ostav palju riideid ja toitu mis nad lõppude lõppuks ära viskavad. \nKõik need toidutd ja riided mis rikkamad inimesed ära viskavad võiksid ju minna taaskasutusele või annetustele kui need on veel heas korras. Sest kõik inimesed ei saa lubada endala samu asju.\nSellist suurt raiskamist mis toimub praegu on raske koheselt lõppetada, sest inimesed ei saa aru kui suur mure see meie loodusele on, kuigi ma arvan, et sellis raiskamise kogust saab vähendada vaikselt, kui inmesed saavad aru palju nad raisakavad riidedi, toitu ja kui kahjulik see on meie loodusele.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('b98b3d43-6c04-49d1-a932-c4a95a02bc85', 'title', 'Inimeste jõledad raiskamise kombed');
INSERT INTO core.text_property(text_id, property_name, property_value)
