INSERT INTO core.text(id, content)
VALUES ('eb55c8e2-6dba-4bcf-92bf-d6e9c85df01c',
        'Paljude inimeste jaoks on toidu raiskamine tavaline osa päevast. Selleks võib olla palju põhjuseid miks nad seda just täpselt teevad. Aga peamine mõtteviis on neil selline, et toitu on veel ja see ei saa otsa.\nOn palju inimesi maailmas, kellel on privileeg toitu igapäevaselt halvaks lasta või lihtsalt ära visata. Sellistel inimestel on ka üldiselt lihtne mõtteviis, nad ei muretse ega mõtle meie maailma probleemidest. Peamine, et sul oleks raha selleks, et toitu jätkuvalt osta vaatamata sellele, et toidu puudus ja toiduainete kogus aina väheneb iga mööduva aastaga.\nToidukadu ehk raisatud toit jääb tarbimata ja visatakse toidujäätmena ära. Sellepärast ei raiska me ainult omaenda raha, vaid ka kohutavalt palju muid ressursse nagu maad, vett, energiat ja tööjõudu. \nMoedisainer Eve Hanson tõi väga meeldejääva näite just noortele, kuidas tuleks olla targem ja mitte tellida Hiina veebipoodidest, isegi kui hinnad on üllatavalt odavad. Pigem võiksid inimesed eelistada kodumaiseid oma lähedal toodetud asju ning alati vähem kui rohkem. Näide minu elust on kui sõber avastas populaarse Hiina veebipoe ja soovis sealt tellida, rääkisin talle põhjustest, miks sealt ei tuleks kunagi tellida ega usaldada oma isiklike andmetega.\nElus tuleb alati olla kõigeks valmis, isegi toidu vähenemiseks. Viis kuidas seda ennetada on tegelikult lihtne ja sellega saab hakama iga inimene kes vähegi hoolib meie planeedi tulevikust. Osta poest vähem toitu korraga, jälgida kasutustähtaega ja mõelda enne toidu ära viskamist kas ikka on vaja ja miks. Sellise mõtteviisiga on meil võimaik hoida enda planeeti, lähedasi ja iseennast.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('eb55c8e2-6dba-4bcf-92bf-d6e9c85df01c', 'title', 'Toidu raiskamine ohud ja miks just vältida Hiina veebipoode');
INSERT INTO core.text_property(text_id, property_name, property_value)
