INSERT INTO core.text(id, content)
VALUES ('403adf75-7c1c-4ccd-aa60-8bbad7b0ea66',
        'Inimesed tarbivad tänapäeval palju, kuid peaaegu pool sellest, mis ostetakse visatakse tarbimata ära. Võib tunduda, et toitu ja riideid on maailmas sedavõrd palju, et need ei saa kunagi otsa, kuid tõttöelda nii see pole.\nÜheks suurimaks probleemiks on toidukadu. Inimesed ostavad kokku rohkem, kui nad tarbida jõuavad. Kõige selle kauba peale kulub väga palju raha, eriti kulukaks läheb see siis, kui enamus ostetud toidust ära visata. Näiteks tekib iga Eesti inimeste kohta aastas 62kg toidujäätmeid, millest 42% ehk 26kg moodustab toidukadu. Tuleks mõelda ühiskonna ja enda peale, ning olla säästlikum ja teadlikum, mida ja kui palju osta, et selle jõuaks enne riknemist ära tarbida.\nMida aeg edasi, seda populaarsemaks muutub just riiete taaskasutus. Paljud on mõistnud, et ei ole vaja osta poest ebakvaliteetseid, kalleid riidekaupu. Asjatu on osta kokku riideid ja need mõni kuu hiljem ära visata. Enda jaoks on avastatud kaltsukad, kirbuturud ja uuskasutuskeskused, kust saab kvaliteetseid teise ringi tooteid palju seda odavamalt. Näiteks arvab moedisainer Eve Hanson, et tuleks teha kooliekskursioone taaskasutuspoodide lattu ja näitada noortele milline raiskamine tegelikult toimub.\nMida rohkem ja hooletumalt tarbime, seda meeletumaks võib muutuda kogus, mille ära viskame. Tuleks hoiduda emotsiooniostudest ja muust säärasest, mis on maailmale kahjutoov ja mittevajalik. Tarbime targalt ja kohusetruult!');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('403adf75-7c1c-4ccd-aa60-8bbad7b0ea66', 'title', 'Inimeste tarbimisharjumused');
