INSERT INTO core.text(id, content)
VALUES ('32833d8a-704b-41f1-8410-16dacdca5167',
        'Inimeste tarbimisharjumused on erinevad. Tänapäeval on saanud väga aktuaalseks teemaks taaskasutamine ning tänu sellele on mitmed inimesed hakanud pöörama rohkem tähelepanu ka kokkuhoijule. Kahjuks on aga ka selliseid inimesi, kes sellele üldse tähelepanu ei pööra. \nPikka aega on olnud maailmas üheks suuremaks probleemiks toidu raskamine. Inimesed, kes elavad arenenumates riikides on harjunud mõtlema, et toit on igas olukorras kättesaadav ning ei saa kunagi otsa. Olgu need siis koolilõunat söövad lapsed või restorani külastavad kliendid. Inimesed ei mõtle tihti sellele, et nende järelejäänud ning ära visatud toit oleks võinud aidata paljusid teisi, sest selliseid riike, kus nälg vaevab inimesi igapäevaselt on maailmas rohkem kui paar. On uuritud, et iga Eesti elaniku kohta tekib aastas keskmiselt 61 kilogrammi toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kilogrammi. Kindlasti võivad paljud nõustuda, et seda on rohkem kui küll.\nKahjuks ei piirdu inimeste raskamine ainult toiduga. Isegi ainult ühe söögikorra valmistamiseks kulub ka tohutult teisi ressursse, näiteks nagu vett, energiat ja tööjõudu. Ning ka need kaod ei käi ainult toidu valmistamise juurde. Palju on ka teisi tooteid, mida inimesed ei oska tihti hinnata. Sinna alla kuuluvad näiteks igapäevased isiklikud asjad: riided, jalanõud, ehted, köögitarvikud ja palju muud. Moedisainer Eve Hanson olla öelnud, et oluline on inimeste eelistus kvaliteedi, mitte kvantiteedi üle. Ei telliks Hiinast odavaid asju ega viskaks neid pärast väikest aega kasutamist minema. Tänu taaskasutuse laienemisele on paljud inimesed hakanud eelistama ka taaskasutuskaupluseid. Olen ka ise tähele pannud, et tihti võib seal leida palju kvaliteetsemaid ning huvitavamaid esemeid.\nKõik inimesed ei saagi sellistel teemadel ühel meelel olla. Meie tarbimisharjumused on erinevad ning samuti meie mõtteviis. Maailm vajab rohkem selliseid, kes võtaks taldrikule järgmine kord natuke vähem toitu või eelistaksid odava Hiina kauba üle midagi kvaliteetsemat. Siiski ei saa teised niisama pealt vaadata, kui tahame tarbimiskadu vähendada on vaja meie kõigi panust.');
