INSERT INTO core.text(id, content)
VALUES ('8fcd083a-3eff-4023-8f97-7dee958e1826',
        'Tänapäeval inimesed ei pruugi mõista kui palju nad tarbivad ja kui suur osa sellest tarbimisest läheb ka raisku või üldse ei kasutata. Toidu tarbivus on maailma suurim tarbimine ja ka sellega kaasneb suuri probleeme igal pool maailmas.\nSest ka tihti peale inimesed ei tarbi kogu oma toitu ära mille nad ära viskavad kuna on ülejäägid,halvaks läinud või kehtivus kuupäeva ületanud. On ka neid kas tarbivad liigagi palju toitu millega kaasneb tihti peale ka üle tarbivus ja liigne saaste.\nToidu tegemine võtab aga tohutult maad kasvatuseks, vett , energiat ja tööjõudu, et oleks üldse võimalik nii palju toitu teha, aga inimesed ilmselt ei mõista kui palju nad raiskavad ja see toob kaasa üsnagi palju probleeme ühiskonnale kuna suured kogused tarbimata toitu läheb raisku  mis on oma korda ka ressurside raiskamine. Nt USA’s või Indias on need tarbimata toodete numbrid vägagi suured ja millega raisatakse palju maad ja ressurse mis lihtsalt raisku lähevad.\nToidu mitte tarbimine pole ka ainus suur kriis üle tarbivuses on olemas ka rõivaste üle tarbimine mis on sama moodi üsnagi probleemne ühiskonnale kuna inimesed, kas viskavad ära oma vanad rõivaid või ostavad liiga palju rõivaid.\nRõivaid tihti peale visatakse (nt USA’s) ära kui enam ei meeldi või on natuke katki aga mõned viivad ka taaskasutupoodide lattu oma vanu riideid või annetavad neid neile, kes ise ei saa omale lubada rõivaid (nt vaesetematele riikidele või inimestele) nii palju kui vaja või üldse mitte ühtegi rõivast.\nSellist muutust aga ei saa üle öö muuta aga saab proovida leida lahendusi kuidas seda parandada või muuta nii, et oleks parem kõigile ja väheneks ületarbivus üle maailma ja seda on aega mööda vähendatud, kuigi üle tarbivus on siiani tänapäevani suurim probleem , siiani otsitakse ikkagi paremat lahendust, et saaks paremaks  luua üle tarbimist kõige suhtes igal pool maailmas.');
