INSERT INTO core.text(id, content)
VALUES ('def145d4-b628-4441-a7df-2dfb5edd27ef',
        'Kas olete mõelnud kunagi sellele, mis saab puuvilja osakonnas olevatest banaanidest, külmkapis olevast piimast või lihaletis olevast lihast, kui seda ei suudeta ära müüa? Väga vist ei ole, kuid sellele on lihtne vastus. See visatakse kõik ära, isegi kui tegu on veel täiesti korraliku banaaniga. Seda sama väidet võib kasutada ka riietega. Neid ostetatakse liiga palju ja siis antakse ära, kuna neid ei kanta enam. See kõik on aga üks suur ja meeletu raiskamine. Kuid kuidas see kõik üldse alguse saab? \nInimesed tarbivad igapäevaselt aina rohkem ja rohkem kõike. Sellele ei ole lõpuks mingisugust piiri, kuna see kõik on normaliseeritud. Enamasti on nendeks riided ja igasugused pudi-padi asjad. Järjest meelsamini reklaamivad mitmed poeketid, eesotsas SHEIN ja  H&amp;M oma tooteid, mida on võimalik osta suures koguses, aga odavama hinna eest. Inimesed ei mõtle ostlemisel sellele, et tegelikult ei ole vaja neil ühte ja seda sama särki mitmes eri värvivalikus või täpselt samasuguseid pükste, sest need olid soodsama hinnaga. Tuleb mõelda targalt ja teha ratsionaalseid otsuseid. Nt osta kvaliteetsem ja kallim särk, mis kestab kaua. \nRiiete ülekullastumist saab võrrelda ka toidu raiskamisega. Toidu raiskamine tekib tihtipeale just sellepärast, kuna arvatakse, et see ei too mingit kahju. See kõik on, aga puhas laim. On inimesi, kes raiskavad toitu, sest nad saavad seda endale lubada. Toidu raiskamisega kaasnevad erinevate ressursside vähenemused. Nt on välja toodud tarbitoitutargalt.ee kodulehel, et Eesti inimese kohta tekib aastas keskmiselt 61kg toidujäätmeid, millest toidukadu moodustub vaid 42% ehk 26kg. Seda kõike on aga meeletult palju. Selle parandamiseks on soovitav osta vähem toitu, et vajadusel oleks raisatud kulu väiksem või võtta kuskil söömisel väiksem portsion sööki. \nPaarikümne aasta pärast võime me elada sõna otseses mõttes prügimäel, kui sellele probleemile ei suudeta lahendust leida. Selle asemel, et reklaamida uusi tooteid ja toidu ära viskamist, oleks mõttekas populariseerida hoopis taaskasutust ja enne tähtaega ületavate toodete ostmist. \nSeega võib öelda, et inimesed ei ole alati oma valikutes ratsionaalsed ja kipuvad tegema valesid otsuseid, mis omakorda toob üldisele kooslusele kaasa suurt kahju. Enamasti on selleks massiline riiete kokkuost või suur toidu raiskamine. Selle peale ei mõelda enne kui selleks on liiga hilja. Tegutseda tuleb varakult ja kiiresti, et see probleem ei suureneks.');
