INSERT INTO core.text(id, content)
VALUES ('037ea3ee-ac04-4eff-931c-8f372e051886',
        'Tööstuslik revolutsioon muutis maailma ja inimeste igapäevaelu drastiliselt. Tootmine, igas kategoorias, muutus palju lihtsamaks ning kiiremaks. See võib tunduda nagu suurepärane muutus, kuid see tõi endaga kaasa ka tõsise probleemi – masstootmine.\nMasstootmine on samalaadsete toodete pidev valmistamine suurtes kogustes. Justnimelt seetõttu, et tooteid valmistatkse kiirelt suurtes kogustes, et need ruttu turule saata, langeb toodete kvaliteet ekstreemselt. Kuna toodete kvaliteet on madal, on ka nende hinnad madalad ja seetõttu neid ka nii massiliselt tarbitakse. Tarbijad mõtlevad, et mis mõtet on kulutada suur summa raha ühe toote peale kui saab sama või isegi madalama hinna eest mitu toodet, vahet pole et kvaliteet on kergelt madalam!\nInimesed ei mõista kui kahjulik suures koguses odavatest Hiina veebipoodidest ja muudest samasugustest kohtadest tarbimine on nii tarbijale ise kui  ka keskkonnale. Enamus Hiinas masstoodetud riided on kiirmood. See tähendab, et toode on järgmise kuu või isegi nädalaga juba moest maha jäädud ning ostja viskab toote ära kui need just enne ära laguneda ei jõua. Masstarbimine tekitab tohutult ülejääke ning reostab loodust mikroplastidega.\nSuures koguses masstoodangu toodete tarbimine ei ole eetiline. Inimesed arvavad, et nad ise ei mõjuta suurt pilti ja ei tee paremaid tarbimisvalikuid, kuid iga valik loeb. Võiks eelistada kodumaiseid oma lähedal toodetud asju ning pigem vähem kui rohkem, sest kui makstakse kallima kuid kõrge kvaliteediga eseme eest mis ei lagune peale ühte kandmist, kulutatakse pikaaja jooksul palju vähem raha.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('037ea3ee-ac04-4eff-931c-8f372e051886', 'title', 'Masstootmise negatiivne mõju ühiskonnale');
