INSERT INTO core.text(id, content)
VALUES ('b18007de-dda2-421d-aeda-938ffb360dd4',
        'Iga päeva elus on näha , seda mis on juhtunud sellest ,et inimesed tarbivad üle ja kasutavad liialt, asju mida  ei lähe nii palju vaja kui arvatakse, sellega tuleb ületarbimine\nnäiteks kui oli koroona aeg siis inimesed ostsid kõik poed tühjaks ,kuigi neil polnud vaja kõike seda mida nad ostsid, tegelikult paljud moe disainerid ei ületarbi\npaljud kasutavad ärä kõik materjalid mis on, teevad nendest kaunistusi või siis, õmblevad need  kokku ja teevad sellest suurema riide eseme aga mõned suured brandid kasutavad tavaliselt liiga palju materjale näiteks, võlts nahk pool võlts nahk ja siis päris nahk need on need asjad millega neil pole pärast midagi teha näiteks versace , dior jne kes kasutavad nahka et teha käekotte. paljud äppid mis on põhjustanud meile ületarbimist on shein , aliexpress, alibaba ja muud kohad, kust saab inimene riideid tellida\nselle nimi on kiirmood . inglise keeles; „ fast fashion“ see ei meeldi, paljudele inimestele selle pärast, et need riided on tavaliselt , tehtud kemikaalidega mis on inimestele halvad,\n hiina massiline riiete ületarbimine , on pool põhjusest miks meil on kliima soojenemine kuna kõik need tööstused ja mürgilised kaasid, mis tuleb kui nad panevad peale , logosi rikkub meie maad , aga samas ei saa sellega midagi teha kuna need inimesed töötavad selleks \net oma perele toitu lauale panna, isegi kui ületarbimine on halb asi, need inimesed ei tee seda tööd vabatahtlikult,\nKoroona ajal ületarbmine oli kindlasti, meie üks suurimaid probleemidest kuna  inimesed ostsid nii palju plastikku, mida nad ei jõudnud ära visata sest , et keegi ei julgenud väljas olla ,moe brandide ületarbimine on ka samas , hull asi sama kui ka koroona, kanga ja materjalide ületarbimine tegi meie maaila ökojäljele , halba  aga need pole sama hullud asjad kui paljud teised mured , mis meil ültse kogumaailmas on.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('b18007de-dda2-421d-aeda-938ffb360dd4', 'title', '„ Plastikku üle tarbimine ja kiirmood“');
