INSERT INTO core.text(id, content)
VALUES ('44a7cf87-cbac-4602-b0bf-d71f48e2da3f',
        'Inimesed kipuvad igapäevaselt raiskama toitu. Mõned inimesed arvavad, et see on normaalne visata toitu ära ja, et see ei mõjuta kedagi.\nVäikse koguse toidu ära viskamine on meie ressursside raiskamine. Me ei raiska ainult oma raha, vaid ka palju vett, maad, energiat ja tööjõudu. Keskmises Eesti kodupidamises visatakse oma 61kg toidust ära 26kg, see tähendab, et keskmiselt viskab kodumajapidaja ära 42% oma toidust. See tuleb siis riknenud või söömisel ülejaanud toitudest. Veel on toiduraiskamine suur koormus keskkonnale, sest toidu saamiseks kasutatakse väetisi ja erinevaid kemikaale, et 42% saagist visata lihtsalt ära ei ole õige. Lisaks mida kiiremini toitu inimestel kulub seda kiiremini ja rohkem tuleb keskkonda koormata.\nTihtipeale säilivad kallimad riided kauem ja paremini kui odavad ja ei tee kahju keskkonnale. Hiinast riided koosnevad sageli naftast ja nende juurde tootmine on nafta raiskamine ning nende kandmine teeb kehale halba. Pigem osta kodumaiseid tooteid, sest siis aitame ka rahaliselt oma rahvast ja saame ka kvaliteedi poolt paremaid tooteid.\nOn oluline, et igaüks vaataks üle oma tarbimisharjumused ja eelistaks kvaliteeti kvantiteedile. See tähendab, et pigem maksta mingi riideosa või söögi eest rohkem ja saada kvaliteetsem toode mis kestab kauem või saad seda rohkem kasutada kui iga nädal uus odav osta.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('44a7cf87-cbac-4602-b0bf-d71f48e2da3f', 'title', 'Inimeste igapäevane raiskamine');
