INSERT INTO core.text(id, content)
VALUES ('aeb4db74-fc23-4188-9d39-a89043a028a5',
        'Inimeste tarbimisharjumused võivad olla väga erinevad, mõni oskab teadlikult tarbida mõni, aga ei oska. Tarbimise vähendamine võib tunduda raske, kuid see tuleb kasuks! Tarbimise piiramiseks on olemas ka nippe. Muutus maailmale oleks kui kingitus inimeste poolt.\nKuidas saab teadlikult tarbida? Teadlik tarbimine on oluline meile kõigile, meie maailmale. Teadlik tarbimine mõjutab meie igapäevaelu, et maailma päästa tuleks raisata vähem. Tuleks vähem veebipoodidest tellida, käia uuskasutuskeskustes, enda kogemusest saan öelda, et uuskasutuskeskustest leiab palju lahedaid riideid kaasaarvatud firma riideid. Teha vähem emotsioonioste, mitte minna sooduskampaaniatega kaasa ning mõelda, mis saab tulevikust, kui tarbitakse ja raisatakse üleliia.\nTööstused toodavad liiga palju tooteid ja see toob palju halba maailmale. Nad toodavad rohkem kui inimesed ostavad ning tööstustes võivad olla inimtööjõud suured. Heaks näiteks saan tuua Hiina veebipoe Sheini, kus töötavad inimesed kaua ja toodetakse kaupa rohkem kui ostetakse. Ehk parem oleks, kui seda ei pooldata kuna inimesed teevad palju tööd väikese palga eest ja kaup läheb raisku, mille eest saaks palju rohkemat teha.\nKuidas teadlik ja mitte teadlik tarbimine maailma mõjutab? Kui kõik inimesed oskaksid mõistlikult tarbida poleks kliimasoojenemist ega ka inimeste ära kasutamist suur tööstustes. Mõni inimene ei oskagi tähelepanna, et ta tarbib üleliia, selleks tuleb jägida oma oste.\nTeadlik tarbimine mõjutab meid kõiki. On olemas viise, kuidas mõistlikult tarbida- ja mitte tarbida. Teame, et suur tööstusted toodavad rohkem, kui ära kasutatakse ning teame, et see on maailma kahjustamas. Loodetavasti hakkavad inimesed rohkem uuskasutuskeskustes käima ja jälgima, et nad vähendaksid tarbimist.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('aeb4db74-fc23-4188-9d39-a89043a028a5', 'title', 'Teadlik tarbimine');
