INSERT INTO core.text(id, content)
VALUES ('c54acd9b-32c2-46b8-adcd-5a61aba523d3',
        'Tänapäeval on toiduraiskamine muutumas aina suuremaks teemaks ja mitte keegi ei võta sellega midagi ette. Inimesed aina rohkem ja rohkem viskavad toitu ara, mängivad sellega, et internetis vaatamisi saada ja teevad veel igasugu lollusi. On ka normaalseid inimesi kes sööki soetades seda ka söövad.\nSelle asjaga tuleks midagi ette võtta, näiteks kõik need kes midagi postitavad kus mängivad toiduga saavad mingit moodi karistada. Või siis saaks nii teha, et kõik saavad nädala koguse toiduvarud kätte ja sellest rohkem ei saa. Saaks piirata seda kõike aga küsimus on selles kuidas. Väiksematele tuleb näidata mis juhtub kui jätkub see raiskamine ja mida see teeb nendega kes ültse süüa ei saa. Tuleb õpetada, et ei viska nii sama toitu ära ja ei mängi sellega ega tee toidu mingeid lollusi internetis. Tuleb õpetada tuleviku generatsioonile kuidas tuleb käituda sellega mis meile on antud. \nOn ka inimesi kes ei raiska toitu ja näitavad oma lastele, et see ei ole okei kuidas inimesed käituvad toidu ja kui raskelt see tegelt tuleb. Aga ka neid võiks rohkem olla.\nEt ültse seda raiskamist kuidagi vähendada peaks natukene ka tootmist vähendama. Nii palju asju tehakse tööstustes valmis ja need lihtsalt jäetakse seisma kuniks visatakse ära kui keegi justkui seda ära ei osta.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('c54acd9b-32c2-46b8-adcd-5a61aba523d3', 'title', 'Inimeste toiduraiskamine');
