INSERT INTO core.text(id, content)
VALUES ('475f1497-ad47-4006-89c5-c41676b82348',
        'Inimestel on palju ja erinevaid tarbimisharjumusi ning nad kõik erinevad. Harjumused võivad olla nii positiivsed kui ka negatiivsed, kuid tänapäevaelus kaldub see rohkem halvema poole.\nPeamine rutiin inimeste elus on toidu tarvitamine. Sellega kaasneb, aga üks probleem, sest tekivad suured toidukaod, sest ei mõisteta, et toiduaineid on vaja hoida, sest nad ei ole lõpmatud. Keskmiselt ühe eestlase kohta tekib aastas 61 kg toidujäätmeid. Seega peamiseks ja kõige hirmsamaks inimeste tarbimisharjumustest on toidu ületarbimine.\nVeel üheks tarbimisvajaduseks on internet ja elektroonikaseadmed. Inimesed kasutavad seda igapäevaselt ja tihti, sest seal on võimalus teha kõike. Nad saavad sealt tellida endale nii toitu kui ka riideid ning isegi lennupileteid. See mängib inimeste elus suurt rolli ning ilma selleta oleks palju raskem.\nInimeste veel üheks tarbimisharjumuseks on liigne riiete ost. Tavaliselt tahetakse saada  odavamat ning rohkem kui kvaliteetsemat ja kodumaist. See viib, aga prooblemile, sest tekib hiiglaslik kogus rõivaid taaskasutuspoodides. Näiteks moedisaineri Eve Hansoni sõnul peaks noortele tegema ekskursioone taaskasutuspoodide lattu, et nad näeksid, kui suures koguses visatakse riideid ära, ning sellega lõpetada ära riiete liigset ostmist.\nInimesed võtavad enda harjumisi, mis neil on, iseenesestmõistetavatena, kuid see teeb maailmale liiga. Tarbitakse liiga palju toiduaineid, interneti kasutus on suur ja ostetakse palju ebavajalike asju, mis rikub looduse tasakaalu.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('475f1497-ad47-4006-89c5-c41676b82348', 'title', 'Inimeste tarbimisharjumused');
