INSERT INTO core.text(id, content)
VALUES ('4d702093-8506-4dff-bd4c-84f7704f0a69',
        'Tänapäeva tarbimisharjumused on absurdsed. Inimesed ei kohtle enam toitu ega igapäeva tarbeid austusega, sest arenenud riikide ja too inimeste jaoks nii kergelt kätte saadav ja iseendast mõistetav, et see on alati ja igavesti olemas.\nToidu mured ja nälg ei ole maailmas midagi uut, kuid tihti inimesed kipuvad unustama, et ülejäänud maailmas need probleemid kestavad siiani. Isegi kui neil on kõik oma vajadused vastatud, ei tähenda, et mujal maades sama oleks. Keskmine Eesti kodanik viskab aastas minema 61kg kasutamata toidujäätmeid, millest 42%, ehk 26kg raisatud toitu. Seetoimub väikestes kogustes ja hetkes mõeldakse, et suures pildis see ei muuda midagi, kuid tegelikult iga inimene mängib rolli toidusäästmises.\nSuureks probleemiks on ka Hiina madala kvaliteedi ja hinnaga tooted. Inimesed ostavad Hiinast madala hinnaga produkte, mis on halva kvaliteediga ja tihti ka ostja tervisele ja heaolule halb. Moedisainer Eve Hansoni arvates, peaks inimesed pigem eelistama kohalike tooteid ja ettevõteid. Need on küll kallimad, kuid ka kvaliteetsemad, mis tähendab, et tooted kestavd kauem ja lõpuks saad oma raha eest rohkem, kui oleks Hiinast ostnud. \nKõik need probleemid saab lahendada ainult, siis kui me kõik koos töötame parema tuleviku jaoks. Me peame õppima kuidas toitu säästa ja jääke ära kasutada. Jätkusuutlike ja kestvate tarbete ostmine tuleb, nii kliendile, kui ka kogu maailmale kasuks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('4d702093-8506-4dff-bd4c-84f7704f0a69', 'title', 'Tarbimisharjumused');
