INSERT INTO core.text(id, content)
VALUES ('197c6a0d-e817-4204-a6c0-fca8572a1f7f',
        'Inimeste tarbimisharjumused on tänapäeval läinud vägagi ükskõikseks. Inimised ei saa aru, et maailmas hakkavad ressursid otsa saama vaikselt ning keegi ei mõtle tegelikult sellele, kuidas seda vältida.\nTänapäeval on igasugune toidu ära viskamine ja riiete ära andmine väga aktuaalne. Uudistes räägitaks kuidas toidu raisk tõuseb ja kuidas  see meie ühiskonda mõjutab. Internetis ja ajalehtedes on ka palju infot inimestele, kes tõesti soovivad ühiskonnale ja maailmale head teha nagu prügi sorteerimine ja vanade riiete viimine uuskasutuskeskustesse.\nLahendus sellele kõigel võiks olla see, et inimsed võiksid hakata rajama selliseid hooneid/ehitisi, kus saaks viia näiteks riideid ja toitu vaestele täiesti tasuta, et ei viida vanu riideid taaskasutuspoodide lattu, kus pandakse riietele veel hind külge, et vaesed veel rohkem omadega põhja viia. Selline lahendus muudaks meie ühiskonda vägagi, siis ei peaks nägema inimesi tänavatel näljas ja räbalates riietes, eriti talvel kui veel külma aeg on ja näeme, kuidas mõni kodutu kõnnib dressipluusi väel ringi, sest tal pole raha talvejope jaoks. Sellega kaoks igasugune näljahäda maailmas ja haigeks jäämine.\nSee teema tuleks tegelt veelgi aktuaalsemaks teha, et inimesed hakkaksid seda rohkem märkama, sest kui me ei tegutse kiirelt, jääme me oma toiduvarudest ja igasugustest muudest ressursidest kiiresti ilma, sest maailm on ainult meie kätes.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('197c6a0d-e817-4204-a6c0-fca8572a1f7f', 'title', '„Kuidas muuta ühiskond paremaks“');
INSERT INTO core.text_property(text_id, property_name, property_value)
