INSERT INTO core.text(id, content)
VALUES ('6b6b244a-b5c2-40a7-a073-011e55d8d6ba',
        'Inimeste arusaam raiskamisest on erinev. Osad eeldavad, et väike kogus ära viskamist ei mõjuta kedagi, aga see pole tegelikult tõsi.\nVäike raiskamine loeb, sest kui inimene kasvõi natuke ära viskab on see kogus tegelikult väga suur. Samuti peaks eelistama kvaliteeti, et mitte kogu aeg olla olukorras, kus peab uusi asju ostma või midagi välja vahetama. Paljud ei saa endale isegi natuke lubada samas, kui teised tihti raiskavad. Kõik asjad ja toit võiks hoopis minna inimestele, kes seda päriselt vajavad. Rohkem tuleks rajada taaskasutuskeskuseid igas valdkonnas ning kauplused võiksid aeguva toidu tasuta inimestele jagada, sest mis sellega ikka teha on, kui ära visata. \nMeil pole maailmas toitu piiramatult ja me peaks väärtustama kõike, mis meil valikus on, sest meie toidu saamiseks on läinud palju ressursse ja tunde tööd. Kõik meie toidu transportimine ning tööjõud ja muidugi meie endi loodus. Loodust pole meil lõpmata ja, kui me looduse ära kurname oleme ise pärast hädas. Toitu peaks jagama võrdselt ja vältima selle raiskamist isegi, kui meil on raske oma harjumusi muuta peame proovima. \nMe ei peaks oma vara raiskama, vaid selle eest hoolt kandma, et seda jätkuks kõigile ka tuleviku põlvkondadele. Hoidma alles loodust ja selle eest hoolitsema ning hoidma vee ja maa puhtana, et me ei peaks sööma ega jooma reostunud toitu ja vett.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('6b6b244a-b5c2-40a7-a073-011e55d8d6ba', 'title', 'Mõtetu raiskamine');
