INSERT INTO core.text(id, content)
VALUES ('ecf22002-8372-4aa8-a53c-979b7f8853af',
        'Inimesed toodavad ning ostavad tooteid liiga palju, kui tarbiad jõuavad neid tarbida. Enamus inimesi ostavad liiga palju toitu mida nad ei jõua õige aegselt ära tarbida ning see järel läheb see raisku. Kaks peamist valdkonda kus esineb selline probleem on toit ja rõiva tööstused.\nToidu raiskamine on üks kõige levinumaid probleeme. Seda põhjustab see, et inimesed ostavad liiga palju toitu, kui nad jaksavad ära tarbida. Kuid inimesed ei ole nõus ka vähem toitu ostam. Iga aasta viskavad inimesed ära tonnides toitu, seda nii, et seda pole puutudud. Aga inimesed ei saa aru sellest, et kui viskme toitu siis praktiliselt viskame ära raha.\nRõiva tööstused toodavad iga hooaeg uusi disaine, et need rõivad oleksid moes ja, et tööstustel tuleks kasumit. Inimesed aga ei mõtle sellele, et kui nad ostavad iga hooaeg endale uue karderoobi täie riideid siis, mis juhtub nende vanade riietega.  Need riided mida inimesed enam ei kanna lähevad prügimäele ja tõenäoliselt ei saa neid enam taaskasutada. Inimesed on harjunud ostma endale uusi riideid ainult poodidest, kus on need rõivad täiesti uued, aga võb olla oleks aeg hakata soetama enda riideid rohkme taaskasutus poodidest. \nInimesed suudava vähendada enda tarbimisharjumusi, kui nad seda ainult tahavad.  Selle asemel, et osta kokku hulgi toidu kraami, mida tõenäoliselt ei jõua õige aegselt ära tarbida. Võiksid inimesed osta vähem toitu ning vajadusel minna poodi ja vajalike asju juurde osta. Selle asemel, et enda kasutatudrõivad ära vistata vii need pigem taaskasutuskeskusesse, kust keegi teine saab neid riideid uuesti kanda.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('ecf22002-8372-4aa8-a53c-979b7f8853af', 'title', 'Inimeste tarbimisharjumused');
