INSERT INTO core.text(id, content)
VALUES ('063dcef2-b93d-4953-b164-a843eec4da6d',
        'Inimesed kui elusolenditena tarbivad väga palju, võrreldes loomadega. Inimesed raiskavad liiga palju ressursse, sest arvatakse, et maailmas on mahukalt kasulikke asju mida kasutada ja, siis ära visata. Inimesed on lohakad ja tahavad uusi asja iga kord kasutada kuni hakkab muutuma igavaks.\nKõige suurim kadu on toit ning inimesed arvavad, et süüa saab nii palju kui tahta. Üks Eesti inimene viskab ära umbes 26kg aastas, sest see toit on läinud halvaks, defektiga või ainult jääb üle ja ei taha seda süüa. Prügi kastid on hakanud haisema õudsa toidu roisu pärast, sest inimesed viskavad nii palju toiduaineid ära. Vähemalt on olemas erinevaid asukohti kus anda enda vananenud toitu ära, et keegi teine leiaks sellele võimaluse.\nToit ei ole ainus asi mida inimesed raiskavad. Inimesed tarbivad ka palju energiat, maad vett ja riidesemeid. Paljud inimesed arvavad, et kui annavad enda katkised riided ära kolmandatele riikidele, siis nad teevad head ja aitavad vaesemad inimesi, aga hoopis teevad vastupidi. Paljud rikenenud riided näiteks Suurbritannialt, Prantsusmaalt, Ameerikalt ja Venemaalt mis lähevad kolmandatele riikidele ei ole hea, sest neid riideid ei saa kasutada ning ainult täidavad nende jäätmejaame ja tänavaid riietega. Mõned moedisainerid on hakkanud kasutama riiete jääkmeid enda töödes, et olla silmapaistev ja maad säästa riidesemete põletamist.\nInimesed raiskavad liiga palju vahendeid mida võiks tarbida keegi teine, aga ka annavad ära asju mida ei saa isegi kasutada ning teevad tänavaid räpasemaks ja ebameeldivamaks. Praegusel ajal hakatakse jäätmeid rohkem vähendama ja proovitakse olla rohkem jätkusuutlikum, et inimesed ei peaks kehvasti elama.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('063dcef2-b93d-4953-b164-a843eec4da6d', 'title', 'Inimesed ei oska tarbida limiidis');
