INSERT INTO core.text(id, content)
VALUES ('ce1c3a74-f89b-4927-8dff-2d5da13d240e',
        'Tänapäeval toiduraisk on täiesti tavaline tegemine, kuid nimesed ei kujuta ettegi, kui tõsiselt nad hävitavad loodust. Moedisaineri Eve Hansoni arvates võiks eelistada kvaliteeti kvantiteedile. \nKõigepealt esitaksin küsimuse, mis on toidukadu? Toidukadu on toit või toitaine, mis jääb tarbimata ja visatakse toidujäätmena ära. Raisatud toidu vältimiseks võib osta nii palju, et sa ise ära sööksid. Rumalatele inimestele tundub, et ei juhtu midagi, kui viskame toidu ära, aga tegelikult on vaja kaevada natuke sügavamale, et näha tulemusi. Toidukaduga kaasneb küllaltki palju faktoreid, näiteks : maa, vesi, energia ja tööjõud. Selle vältimiseks peavad inimesed muuta harjumusi.\nMoedisainer Eve Hansoni arvates on oluline, et igaüks vaataks üle oma isiklikud tarbimisharjumused. Tema arvates ei  peaks tellima asju Hiinast, vaid võiks eelistada kodumaiseid oma lähedal toodetud asju ning pigem vähem kui rohkem. „Jalutades taaskasutuspoodides panen tähele, et iganädalaselt nad tekkivad juurde. Arvan, et noortele peaks tegema ekskursioone lattu, et näidata, milline raiskamine toimub“ sõnastab Eve.\nToidukadu on kahjulik keskkonnale ning loodusele. Inimesed rikkuvad maailma ning ei teagi sellest. Taaskasutuspoodides on hunnik rõivasid, mis tuleb iganädalaselt juurde. Sinna viiakse korralike riideid. mis näevad reklaamfotol väga ilusad välja, kuid on tehtud naftast ning kehal on selles halb olla.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('ce1c3a74-f89b-4927-8dff-2d5da13d240e', 'title',
        'Toidukadu mõju ja noorte ekskursioonid taaskasutuspoodide lattu');
