INSERT INTO core.text(id, content)
VALUES ('e81c122c-9c3e-40e7-b362-78c51954ac28',
        'Inimeste tarbimisharjumused on väga erinevad, kuigi enamus neist on kas toidu raiskamine või tervete riiete ära viskamine. Inimesed ei mõtle oma tegude üle ja lihtsalt raiskavad maavara ja inimressurse. Me peame midagi muutma, et inimesed vähem raiskaksid väga lihtsalt taaskasutatavaid asju, aga muutused ei juhtu üleöö.\nToidu raisakmist on palju. Eestis iga inimese kohta tekib 61 kg toidujäätmeid millest 26 kg on lihtsalt toidukadu. Toidukadu on raisatud toit või toiduaine mis mingil põhjusel jääb tarbimatta ja visatakse lihtsalt ära. See ära visatud toit ei tähenda lihtsalt halvaks läinud saiapätsi või hallitama läinud juustuviil, vaid ka kõiki ressursse: vesi, raha, maa, trantsport ja tööjõud. Selle kõige vältimiseks on üks lihtne lahendus. Osta korraga vähem toitu. See väldib olukorda, kus sul on külmkapp silmini täis ning iga kord kui tahetakse midagi süüa, siis jäetakse eelmise toidukorra jäägid külmkappi seisma ja tehakse uute toiduainetega roog valmis.\nVisatakse ära ka palju täiesti korralikus seisus riideid lihtsalt sellepärast, et nad on liiga vanad või kasutatud. Kuna tuleb pidaevalt peale erinevad moodid ja stiilid ostetakse üleliia riideid mida kantekse natukene aega ja siis visatakse ära. Selle vältimiseks võime samamoodi lihtsal vähem riideid osa. See säästab raha, maa ressursse ja vähendab prügi mis tekkib ostetud riietest mõne aasta pärast. Samamoodi võiks ka lastele teha väljasõite taaskasutuspoodidesse, et nad näeksid kui palju tegelikult riideid raisatakse. Ja kui isegi on mõned riided nii vanad, et nendega ei saa väljas käia, siis pestakse riided ära ja viiakse taaskasutuskeskusesse.\nMa usun, et on olemas veel palju võimalusi vähendada toitu ja riidete raisakmist, aga me lihtsalt ei pööra tähelepanu nendele asjadele, sest keda huvitab homme. Toitu saab hoida lihtsalt selle vähem ostmisega ning riideid saab säästa sellega, et sa mõtled kas sa ikka tahad seda särki kanda või pigem mitte.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('e81c122c-9c3e-40e7-b362-78c51954ac28', 'title', 'Kuidas vältida raisakmist');
