INSERT INTO core.text(id, content)
VALUES ('8a3d6249-99bf-4765-ab8a-e987fb7f8ca6',
        'Maailmas on inimesi palju, kes raiskavad väga palju toitu ja riideid. Miks me raiskame toitu niipalju? Kas on mõistlik osta pigem kvaliteetsemaid või odavamaid asju? Kas taaskasutuspoed on hea või halb variant?   \nInimesed raiskavad palju toitu. Näiteks Eestis on inimese kohta aastas keskmiselt 61kg toidujäätmeid, mis on väga suur arv ühe inimese kohta. Ameerikas on  inimese kohta aastas keskmiselt 95kg toidujäätmeid. \nTaaskasutuspoed on hea variant. Sinna on võimalik viia oma vanad riided mis enam ei leia kasutust ja see vähendab riiete raisku minemist. Laura viis kõik oma vanad joped, jalanõud, särgid ja püksid taaskusutuspoodi Tallinna, sest ta ei tahtnud neid ära visata ning teadis, et kellegil võib neid tulevikus vaja minna. \nMõistlikum on osta kvaliteetsemaid asju, sest need peavad keskmiselt kauem vastu, kui odavamad asjad. Ralph ostab kõik riided ja jalanõud Ralph Laureni poest, sest ta teab, et see firma teeb kvaliteetseid asju, mis peavad kaua vastu. \nMaailm võiks rohkem kursis olla sellega, kui palju me raiskame toitu ning viskame korralikke riideid ära. 1. lõigu järeldus: Inimesed ei pane tähele, kui palju toitu nad tegelikult ära viskavad aastas, eriti ameeriklased. 2. lõigu järeldus: Taaskasutuspoodide loomine oli väga hea mõte, sest see aitab vähendada riiete ära viskamist. 3. lõigu järeldus: Mõistlikum on osta kvaliteetsemaid asju, sest see on kasulikum tulevikus.  Me võiksime rohkem keskenduda oma toidu tarbimisele ja riiete ostmisele. Niimoodi oleks meil vähem toidu ja riiete raiskamist.');
