INSERT INTO core.text(id, content)
VALUES ('f23d0c50-ad06-4172-82d8-d1b53e5f3312',
        'Tarbimisharjumus on väga suur probleeem.Tarbimisharjumus on peaaegu igal inimesesel,sest kõigil inimestel on peaaegu sõltuvus.Sõltuvus on väga suur probleem.\n Sõltuvus on väga halb asi.Sõltuvus tähendab,et teil on mingi asja vastu sõltuvus näiteks  nicotin,magusa isu ja alkoholi tarbimine võib ka olla.Tarbimisharjumus on  alati olnud väga suur probleem,sest inimesed ei oska korralike toite süüa.Noored söövad pigem alati midagi rämpsu ja magusat.See on väga halb asi,sest inimesed ei toitu hästi.\n  Iga inimene teab ise kuidas toituda.Teiste inimeste eest ei saa kunagi ise otsustada.Näiteks minul on toidugraafik.Toidugraafik on väga tähtis asi.Toidugraafik annab sulle palju parema päeva,sest kirjutad igpäev endale söögi valmis ja saa saad ilusti toituda siis.Teil pole mingit probleemi,kui mõtlete mida täna süüa teha siis tuleb teil kohe meelde,et te tegite endale toidugraafiku ja sealt vaatad.Toidugraafik on mind väga palju aidanud.Toidugraafikuga võid saada väga kiiresti vormi,kui ilusti toitud.\nInimesed kahjuks ei saa aru sellest,et kui te ilusti ei toitu,siis võib väga halvasti juhtuda.Inimesed on väga palju ära surnud vaid sellepärast,et nad ei toitu hästi.Iga inimene, peab enda tervise eest hoolt kandma.Loodan,et inimesed saavad aru,et toitumine on väga tähtisasi ja peab selle eest hoolt kandma.');
INSERT INTO core.text_property(text_id, property_name, property_value)
