INSERT INTO core.text(id, content)
VALUES ('140462cf-9254-431c-a501-6c24bfd5782f',
        'Inimesed tarbivad palju, aga sellega nad ka raiskavad palju, ega see mingi saladus ei ole. Raisatakse mitmeid kilogramme toitu, visatakse väga normaalsed ja kantavad riided minema ja muudki. See on selline jube rakse asi millest on veelgi raskem lahti saada. Aga miks siis?\nToidust rääkides tuleb ka rääkida mida inimene on harjunud sööma, mis väga sõltub sellest kust nad pärit on, nende isiklikud harjumused ja nii edasi. Paljud virisevad toidu üle, nagu ma isegi. Aga selle virisemisega tuleb ka kaasa see, et kui kellelgi on toit ees mis neile ei meeldi ja ei maitse, on hea võimalus, et nad lihtsalt viskavad selle minema. Toitu visatakse ka tonnide kaupa ära, sest tihti need toidud lihtsalt ei kõlba enam ja aegumis kuupäev on tulnud. Toitu visatakse ära mõtetult palju ja seda tuleb kontrollida.\nÜks viis oleks see, et inimesed lihtsalt ei võtta toitu kui nad juba teavad, et see neile ei meeldi. Ma arvan et see juba likvideeriks selle söödava toidu kaotsi minemist kordades. Toitu saab ka annetada, mis liigub edasi peredele kus on finantsilised raskused, vaesus jne. Maailmas just vaesetes piirkondades, nagu suuremosa Aafrikas, suures osas Aasias, Lõuna-Ameerikas on sadu miljoneid inimesi vaesuses. Toidu raiskamise asemel saaksid inimesed töötata, et maailma vaestesse osadesse jõuaks toitu.\nRaiskamine ja kasutusharjumused inimestes viib mind ka järgmise teemani. Riided. Igaüks tahab, et tal oleks midagi tervet ja hea kvaliteediga kanda. Aga ka just seda riiete raiskamist on ka liiga palju. Inimesed ostavad endale ilmatumalt suure koguse riideid, isegi kui neil pole otseselt vaja neid. Laristatakse sadu eurosid uute riiete peale. Lastakse lendu nii palju raha, mida saaks muude tähtsamate asjade peale kulutada. Kuigi see sõltub ka inimesest endast. Riideid ka visatakse minema suurtes kogustes. Tihti inimesele lihtsalt ei meeldi enam mingi riide ese, või on need riided katki. Sellega läheb raisku nii palju riideid mis oleksid nii vajalikud miljonitele. \nMinu üks lemmikuid asju mis on just riiete raiskamise ära hoidmine on taaskasutus. Inimesed viivad oma riideid teatud kohtadesse, et keegi teine saaks neid kasutada. Ja kõik need poed mis müüvad taaskasutatud asju on suhteliselt odavad ka. Jah ei pruugi leida mida sa alati tahad aga vahepeal võib. Riiete taaskasutamine piirab nende raisku minemist. Ma ise käin tihti kirbukates ja teistes taaskasutatud esemete poodides, sest kunagi ei tea mis kulla võib sealt leida. Riideid saab ka otse annetada maadesse kus ongi probleem sellega, et ei ole korralike riideid millega inimene saab elada.\nInimesed tarbivad palju, meil on vaja tarbida. Aga tihti tarbitakse ka valesti. Seal on nii palju viise maailmas kuidas vältida seda ning neid võimalusi tuleb ka kasutada. See, kas inimene seda üldse teeb on ta enda teha. Aga sellepärast tulebki harida rahvast sellel teemal ning kuidas vältida raiskamist ja muuta oma tarbimisharjumusi.');
