INSERT INTO core.text(id, content)
VALUES ('87872ea0-9746-44e7-b2fd-1c233b6112e5',
        'Tarbimisharjumused on midagi, mis on kõigil olemas. Kes raiskab liiga palju toitu ja kes riideid. Mõned on oma tarbimisharjumustega targemad kui jällegi teised. Kes hoolib rohkem ja kes vähem? Kuidas neid eristada, kui kõik annavad endast igapäev parima?\nMillegi tekkeks ja harjumuseks on tarvis raha. Sealt edasi kujunevad välja võimalused, mida ja kui palju võimaldab keegi endale ostma. Kas on tarvis käija mitmes poes, kuna nägid, et mandariinid on odavamad ühes poes aga piim teises. Või on võimalus minna käed taskus esimesse ettejuhtuvasse poodi?\nMida rohkem raha inimesel on, seda halvemad tarmisharjumused tavaliselt välja kujunevad. Kui raha on palju ning muretsema ei pea, käib asjade ostmine väga kergekäeliselt. Võetakse ühte, teist ja kolmandat ilma, et vaataks hinda ega säilivus kuupäeva. Pikkade tööpäevade lõpus minnakse välja restoraani sööma ja külmkapp ongi unustatud. Kuid alati saab ju vana asja välja visata ning uue osta- mõtlevad enamus rikkurid. Kuid täpselt sellepärast on ka nende tarbimisharjumused väga halvad ja raiskavad. Mingit hoolivust ennast ümbritsevast neil ei ole, vähestel on.\nNendel vähemusse jäänutel, tavaliselt finantsiliselt kõige parem ei ole. Käijaksegi mitmes poes, kuna võimalused on kitsamad. Alati vaadatakse mida ja kui palju ostetakse, et jumala eest midagi ära viskama ei peaks. Raisata ei ole nende jaoks midagi. Kuna tavaliselt on just nemad, kes näevad ennast ümbritsevat ning hoolivad sellest. Mis peaks tegelikult iga inimese mõtteviis olema, kuid see ei saa kunagi juhtuma.\nKõigile antakse valik, kas hoolida või mitte hoolida. Kuid võimaluste pealt, kujuneb see valik iseenesest välja ja sellele ei pöörata erilist tähelepanu. Tuleb leida see kulgne kesktee, kus ennast otseselt ei piirata vaid tehakse õigeid valikuid. Õigeid valikuid nii endale, kui ennast ümbritsevale. Hoolida endast, teistest ning ümbritsevast.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('87872ea0-9746-44e7-b2fd-1c233b6112e5', 'title', 'Hoolida või mitte hoolida?');
