INSERT INTO core.text(id, content)
VALUES ('0770beb2-dce6-4c79-8cb9-317a7b69bac8',
        'Mõnedel riikidel puudub puhas vesi, puhas vesi on kasulik riigile et nende rahvas saak juua ja et puhas olla, ilma selle puhta veeta ei saa inimesed puhtad olla ega tervislikud olla ja kui nad tervislikud ega puhtad pole siis nad ei saa väga hästi elada ega areneda riigina.\nMinu Järeldus on see et miks me ei tee ühelegile nendele riigile vee puhastus jaama, et nad saaksid lõpuks ameti puhast ja tervisliku vett, kõll see hakkaks palju maksma, siis see oleks väärt seda, kuna me saaksime võibolla kiiremini areneda inimolentitena ja saaksime rohkem töötajaid meie ühiskonda. Ma usun ka seda et kui neil oleks turvaline tervis, siis nad saaksid ehitada enda asju ise ja mitte meie abiga, Kui me annaksime neile midagi sellist ka, siis nad rautselt tuleksid ga meie juurde appi kui meil seda vaja on. Ma usun ja loodan ga et kui me tegelikult teeksime seda siis see riik võiks tulla Nato liitu ja mitte minna venemaa juurde appi.\nSee tegelikult sõltub mis riike me aitame kuna paljud riigid on teise Nato riikidega vaenlased ja me ei saaks neid aitata, kuna nad rautselt läheksid siis Venemaa juurde liitu, aga äkki on seal võimalus et nad aitavad tegelikult meid ja mitte vaenlasi, see on väga väike võimalus aga see on võimalus.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('0770beb2-dce6-4c79-8cb9-317a7b69bac8', 'title', 'vee puhasuse puudus mõnedes riikides');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('0770beb2-dce6-4c79-8cb9-317a7b69bac8', 'failinimi', 'id_pHgVvt');
