INSERT INTO core.text(id, content)
VALUES ('7c4b66cc-01af-4929-910a-2c998d775995',
        'Hiljuti olen sattunud väga paljude inimeste kodudesse, kus ma pole varem käinud. Kõik on väga erineva karakteriga – moderne, nõukogudeaegne, avar, hubane. Need kõik väljendavad sealsete elanike maitset, rahalist seisu ning tarbimisharjumusi.\nKellegi koju sisenedes on tavaliselt esimese asjana tunda selle kodu lõhna. Õhus võib tunda koera, vana maja,  värskelt värvitud seinade, toidu või täiesti lõhnatut lõhna.  Need loovad kodule esmamulje.\nKui on tunda vana maja lõhna, siis tavaliselt elab majas keegi vanem inimene, kes ei hooli tänapäeva mugavustest, vaid tunneb rõõmu nendest, mis tal juba olemas on – pere, lapsepõlvesõbrad, lapselapsed ja koduloomad.\nKogu maailm võiks olla nagu see vanem inimene – tunda rõõmu asjade üle, mis tegelikult loevad. \nPraeguses ühiksonnas on kõigil vaja endale koguaeg kõige uuemat ja paremat. Olgu selleks siis auto, kõige värksem Iphone’ i mudel, sotsiaalmeeidas ringlevad trendikad, kuid ebakvaliteetsed riided, mida kõik näivat kandmas ning muu kraam, mis tegelikult meie elu ei rikasta. \nUute asjade ostmine ei ole halb, kui näiteks telefon on olnud juba kuus aastat kasutuses ning lõpuks lakkas töötamast või kui kümneaastane auto  lõpuks tee peal seisma jäi.\nKui oma vara kasutada seni, kuni seda enam ei saa, siis on selle täiustamine hea mõte. Nõustun modedisaineri Eve Hansoni arvamusega, et on oluline, et igaüks vaataks üle oma isiklikud tarbimisharjumised ning eelistaks kvaliteeti kvantiteedile. Koguaeg kõige uuemat ostes teeme kahju nii endale, kui ka kogu maailmale.');
