INSERT INTO core.text(id, content)
VALUES ('00486ba5-bd48-4853-be65-588c8ebdd13e',
        'Tänases maailmas aina rohkem visatakse toitu , riideid ja plastik pakendeid minema ning midagi tuleb ettevõtta. kodudes vistakse iga päev ära toitu , kas siis kui toit ei kõlba või kui on kasutustähtajast üle läinud. Toidu raiskamine tähendab ka mõtetut raha rasikamist ja seeb ka aina rohkem probleeme. Toidust rääkides ei vista ainult toiti vaid ka plastikut ja riideid mida saaks taskustada aga kui inimene ei viska pakentut õigesse kohta siis sei ei jõagi taaskustusse ja saab seda kaotunuks pidada. Riideid vistakse väga palju, kuid neist saaks teha uuemaid riideid.\nKuidas saaksid inimesed vähendada raiskamist ? Peredele tuleks hakata reklaamima raiskamise kohta ja kui palju kahju see tegelikult tekitab. Lastele tuleks lasteaedades ja koolides rääkida, et toidu raiskamine on halb ja kui lapsed on riiedest väljakasvanud siis tuleks need riided taaskasutusse viia mitte ära visata , näiteks saab laste väikestest riiedest anda või teha teistele lastele riideid.\nToit on väga väärtuslik ning seda tuleb hoida. Kuidas saaksime siis ikka ärahoida toidu raisku minemist ja kaotamist üleültse.  Inimestel ei tekki kohe aimu et kui palju nad tegelikult ära viskavad ja kui kahjulik see saab olla. Inimestel on viise kuidas raisata võimalikult vähe ja näiteks head viisid oleksid kui inimese teeks endale nimekirja kõikidest asjadest mis on vaja ja milles on kindlad,  et toit ei lähe raisku. Veel saab teha ka et kõik mis on kõlblik aga mingitel põhjustel pole vaja siis anna seda kellel on vaja.\nÜmber maailma on raiskamist väga palju ja erinevatel viisidel ja selle ärahoidmiseks peavad kõik panustama ja arusaama kui kahjulik on tegelikult raiskamine ja millagi kui on aeg kus raisku minevaid materjale on vähenenud siis paranevad ka palju rohkeim asju kui arvata võib.');
