INSERT INTO core.text(id, content)
VALUES ('863ca147-7ad6-46ac-bfd9-4cb7308b7f7d',
        'Üks suuri probleeme on toidu ja riiete raiskamine. Miks on toidu raiskamine halb? Miks paljud inimesed raiskavad toitu? Miks eelistada kvaliteeti üle kvantiteedi? Miks näidata inimestele milline raiskamine tegelikult toimub? Kuidas vähendada toidu ja riiete raiskamist? Küsimusi on palju, aga nii ka vastuseid.\nMaailmas on toidu raiskamine üks suur probleem, kuna on inimesi, kes raiskavad toitu, sest nad saavad seda endale lubada. Selle asemel, et toit ära visata võiksid inimesed annetada toitu nendele, kes ei suuda endale lubada toitu ehk siis kodutud või rahaliste probleemidega inimesed. Toidu annetamine aitaks ühiskonda omajagu. Loomulikult ei tasu annetada riknenud toitu, sest see ei ole inimsele hea. Lisaks raha kulutamisele, kahjustatakse loodust, vett ja nii edasi. Eve Hanson arvab, et on oluline kui igaüks eelistaks kvaliteeti üle kvantiteedi. Paljud inimesed nõustuvad Eve öelduga, et kvaliteet on parem kui kvantiteet. Eve rääkis taaskasutuspoodidest, nimelt käib Eve vabatahtlikult taaskasutuspoodides ja Ta näeb seda rõivaste kogust , mis tekib iganädalaselt juurde. Tore on teada, et inimesed viivad kasutatud riiedeid taaskasutuspoodidesse, aga kurb on see, et need riided on peaaegu uhiuued või halvast materjalist. Ekskursioonid noortele taaskasutuspoodidesse näitaks, milline raiskamine tegelikult toimub. Eve mainis ka seda, et paljud riided, mis on toodud taaskasutuspoodidesse on pärit nendest suurtest kuulsatest Hiina kaubamajadest.\nToidu ja riiete raiskamine on ja jääb alati üheks probleemiks, aga kui inimesed töötavad selle nimel, et seda vähendada oleks kõik hästi. Üks võimalusi toidu vähendamiseks oleks annetamine. Toidu annetamine inimestele, kellel ei ole seda raha, et endale lubada toitu. Toidu raiskamine tekitab keskkonnakoormuse. Paljud inimesed ei mõtle sellele mida teha toiduga kui nad seda ei taha vaid viskavad toidu minema. Maailmas on raiskamine väga tõsine ja kui igaüks näeks kui kahjulik see on võtaksid inimesed ennast kokku ja ei raiskaks nii palju. Kvaliteet on parem kui kvantiteet, sest see kvaliteet kestab kauem ja see on parem kehale kui ka endale.');
