INSERT INTO core.text(id, content)
VALUES ('c6221daf-a41e-479a-8336-bdc4babddd63',
        'Inimeste tarbimisharjumusi on igasuguseid ning igas kodus on need erinevad. Tihti inimesed isegi ei mõtle, kui palju nende tarbitud kaupadest läheb raisku. Tegelikult ei tea keegi, kui palju tarbekaupa läheb päevas või aastas raisku ainuüksi ühe inimese poolt, aga me kõik teame, et need numbrid on tohutult suured. Suur osa inimkonnast teab, et näiteks toidu ära viskamine või kiirmoe poest riiete ostmine pole hea, aga miks me siis teeme seda edasi?\nKõige lihtsamini läheb raisku toit, et elu Maal saaks toimida peavad inimesed sööma. Me sööme iga päev ning peame toitu ostma kogu aeg juurde. Poes mõjutavad meid suured värvilised sooduskampaaniad ning neid nähes ostame toiduaineid, kogustes mida meil tegelikult vaja pole. Inimese ostukorvi mõjutavad suuresti ka tema isud. Lõpuks jäävad mingid toiduained seisma ning lähevad vanaks ja keegi ei taha seda vanaks läinud toitu süüa ning siis ei jää muud üle, kui riknenud toit jälle ära visata. \nSuureks ülemaailmseks probleemiks on liigne riiete ostmine. Tihti on tegu kiirmoega ning pärast seda jääb rõivaese pimedasse kapinurka seisma. Enamasti pole kiirmoe riided peale paari kasutuskorda enam samas seisus, vaid on halvenenud. Paljud inimesed satuvad elevusse, kui näevad poeaknal allahindlusi. Krabatakse riideid, mida tegelikult vaja pole ning rõivad on kasutud.\nVältimaks riiete seisma jätmist tuleks osta kvaliteetseid rõivaid, mis ei läheks kohe katki ning oleksid loodussõbralikud. Hoidumaks toidu ära viskamisest tuleks hoolikamalt läbi mõelda, missuguseid toiduaineid on vaja ja kui suurtes kogustes. Inimesed peaksid rohkem läbi mõtlema oma tarbimisharjumused ja neid vähendama nii palju, kui võimalik.');
INSERT INTO core.text_property(text_id, property_name, property_value)
