INSERT INTO core.text(id, content)
VALUES ('d0414cab-48ed-4286-b45e-fa984e52a3ae',
        'Me  kõik tarbime midagi, olgu see mingi riietus või hoopis tõit. Oluline on teada, et me neid üle ei tarbi. Kui meil on terve kapp täis riideid ja me kasutame sealt ainult paar eset siis see pole suures osas väga keskonna säästlik. Toitu osta suurtes kogustes koju ja jätta see riknema, on toidu raiskamine mida ei tohiks teha. Aga kas meil on vaja ültse niipalju toitu? Kas me saame seda harjumust kuidagi muuta nii, et see oleks ka tervislik?\nMina arvan, et ei meil pole vaja käija iga päev poes ja osta omale uusi riideid ja kanda neid siis ainult korra. Toiduga sama asi, selle asemel, et käija iga päev ostmas toitu, saaksime käja hoopis nädala algul poes ja hankida vajalik toidu koorem terveks nädalaks. Jah, toit on meie elus vajalik, sealt saame vajalikud toitaineid ja energiat. Aga me ei pea oma külmkapi pilgeni täis laduma, eriti kui seal pole just kõige tervislikumad valikud. Me rikume niimoodi iseenda tervist ja heaolu. Me saame hankida vajaliku toidu, mis on tervislik ja toitev. \nAlati saab harjumusi muuta. Näiteks enne poodi minekut teed omale nimekirja mida vaja on ja paned sinna tervislikud toiduained kirja. Ja selle asemel, et igapäev käja ostamas saad käja nädala alguses. Me ei pea oma kappi pilgeni täis laduma. Me ise teame kui palju sööme, seega me saame ka toidu koguseid täpselt nii palju osta nagu vaja.\nTore on, kui sa oled ära varustatud aga kui sa viskad iga nädal kottide viisi toitu ära siis see pole praktiline. Meil ei ole vaja palju toitu me saame ka vähesemaga hakkama. Me saame igasuguseid harjumusi muuta kui me seda soovime ja kui see on veel meie tervise nimel. Kui sul on indu sees ja tahad oma elu paremaks teha laske aga edasi.');
INSERT INTO core.text_property(text_id, property_name, property_value)
