INSERT INTO core.text(id, content)
VALUES ('d718240b-474d-4738-9c4d-18674ce57cf6',
        'Inimeste tarbimisharjumused on väga erinevad. Mõni inimene tarbib rohkem, kui teised.  Inimesed kes raiskavad toitu, arvavad, et see ei saa kunagi otsa. Nad arvavad seda sellepärast, et nad saavad toitu endale lubada ja ei pea selle jaoks ise midagi tegema. Riideid raiskavad inimesed samamoodi, kas viskavad minema, põletavad või teevad midagi muud nendega.\nMinu arvates võib toitu raisata, aga väga väikses koguses. Mõnele inimesele tõesti mingi toit ei meeldi, siis ma saan aru kui viskad nii mõndagi ära, aga nii suurtes kogustes nagu 26kg on liiga palju. Negatiivne toidu raiskamise juures on see, et see toit võib prügikastidest laiali minna, ehk lindudele ja mõned toidud ei ole lindudele hea. Positiivne on, aga see, et on olemas toidupankad, kuhu saab inimene viia oma toidu muidugi kui see on heas seisukorras. Inimeste aitamine on maailmas tasuta. Maailmas on niigi palju kurjust ja see, kui saa viid mingi oma toidu toidupanka pole ju mingi suur probleem ja ei võta kätt küljest.\nRiiete juurde tulles, siis inimesed viskavad ka riideid minema, kuigi on olemas kaltsukad ja muud kohad kuhu oma riideid viia, et neid saaks edasi müüa või edasi anda. Pole mõtet oma riideid niisama raisku lasta, kui on olemas inimene, kes võibolla tahab seda ise kanda.\nInimesed, kes mõtlesid välja toidupanka ja kaltsukad on südamest väga head inimesed, kuna nemad teevad vaesematele inimestele võimalikuks selle mida need inimesed ise teha ei saaks.');
