INSERT INTO core.text(id, content)
VALUES ('657d279a-a39e-41cd-b0ed-1b69a16e9c4a',
        'Inimeste tarbimisharjumuste probleemid. Arvatakse, et toitu on piiramatult ja seda jagub kõigile, kuigi nii see ei ole. Raisatakse palju toitu ja visatakse niisama ära.\nInimesed söövad igapäevaselt ja mõni raiskab seda rohkem, kui teine tarbib. Euroopas ei ole nii suurt näljahäda, kuid näiteks Aafrikas või Hiinas. Meie arust ei ole see nii hull, kui jääb kaks kartulit üle ja viskame ära, aga kui iga inimene nii teeb siis läheks Eestis juba ainult 2 miljonit kartulit raisku igapäev. Tuleks teha nii palju süüa täpselt, kui sinu peres süüakse ja ülejäägi tuleks jätta järgmiseks korraks, kui kõht tühi on. \nPagaripoodides tehakse hommikul mingi laar sööki valmis, ja mis õhtuks pole ära müüdud visatakse ära, kui nii teha koguaeg siis lõpuks on see väga kahjulik keskonalle, sest inimesed kes kasvatavad seda vilja ja muna teevad seda lihtsalt raiskamise jaoks. Tuleks need tooted, kas panna odavamalt müüki või üldse anda kellegile tasuta ära kellel vaja on. Palju toitu läheb raisku ka suurtes poodides mis ostavad suures koguses tooteid oma lettiedele ja viskavad lihtsalt ära, kui tähtaeg hakkab lähenema. \nTuleks maailmas seda tarmbimist alandada, aga mina ei leidnud sellele vastustus kuidas ja sellega tuleks tegeleda kiiresti, sest muidu meil on varsti toit otsas');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('657d279a-a39e-41cd-b0ed-1b69a16e9c4a', 'title', 'Tarbimisharjumused maailmas');
