INSERT INTO core.text(id, content)
VALUES ('ee5269eb-c230-4e37-876e-da524bbe7943',
        'Minu arvates inimesed tarbivad väga palju erinevaid esemeid. Toitu läheb ka väga palju raisku ning riideesemeid ostetakse ja visatakse hunnikute kaupa ära. Ka Hiina veebipoodidest tellitakse väga palju tooteid. Kodutarbeid, riideesemeid ja nii edasi. \nInimeste tarbimisharjumused on väga kõrged, kuigi ei ole see just kõige parem. Võiksime ikkagi vaadata, mida meil tõesti väga on vaja. Või siis oma vanad esemed taaskasutuspoodidesse viia, et ka teised oleks õnnelikud oma leiu üle. Ka riideesemeid võiks teha rohkem nahasõbralikumatest riietest, sest kui neid naftast teha, siis ei sooviks ka mina neid kanda. \nKa toiduga on raske, ostame kuu aja toidu ette ja siis viskame ära. Mulle ei meeldi ka vahest toitu lõpuni süüa, sest minule lihtsalt ei maitse see, või kõht on nii täis, et enam üldse ei jõua. Seda on tõesti kurb vaadata, et nii palju toitu ära visatakse. Või siis kui visata prügi ära, mis on plastpakendi sees, siis see toit küduneb ära, aga see pakend jääb loodusesse mitme tuhandeks aastaks seisma. \nInimesed viskavad ära väga palju toitu, riideesemeid ning palju muud. See on küll õudne, aga midagi pole teha. Tarbimisharjumused on meil tõesti väga kõrged. Taaskasutuspoode võiks olla minu arvates rohkem, kuhu oma riideid viia. Võiks olla veel ka eraldi toidule mingi koht, et ei peaks seda ära viskama.');
