INSERT INTO core.text(id, content)
VALUES ('a3da808f-7996-48b7-b024-25b4e96ac8d2',
        'Võib öelda, et võrreldes minevikuga on tänapäeval majanduslik õitseng. See ei käi iga riigi kohta, kuid enamik riike maailmas on piisavalt heas majanduslikus seisus, et korraldada ületootmist. Inimeste elutingimused on ajapikku aina soodsamaks muutunud ning sellepärast on võimalik lubada endale peaaegu kõike, mida hing soovib. Seetõttu on inimesed liiale läinud ja hakanud teenuseid üle tarbima, nagu öeldakse veebilehel ‘’tarbitoitutargalt’’: ‘’On inimesed, kes raiskavad toitu, sest nad saavad seda endale lubada’’. Kui suur on ületarbimise kahju?\nÜletarbimine toob endaga kaasa väga palju negatiivseid mõjusid keskkonnale. Toit on üks peamistest asjadest, mida tarbitakse üle. Sellepärast moodustub pidevalt toidujääke, mis visatakse ära. Toidu tegemisele läheb tohutult loodusressursse. Kui raiskame toitu, raiskame loodusvara.\nKeskkond pole ainus asi, mida ületarbimine kahjustab. Ettevõtted, kes korraldavad ületootmist, on peamiselt riikides nagu Hiinas. Hiina on tuntud lapstööjõu kasutamises ning massitoodanguks on vaja massiliselt töötajaid, kellele ei pea palju maksma. Töötajateks sobivad perfektselt lapsed, sest nad on kuulekad ning neile makstakse vähe palka. Ületootmine on toonud ebainimlikke tingimusi mitmele lapsele.\nÜletarbimisel ei ole positiivseid külgi. See on toonud endaga kaasa tohutu suure ületootmiskriisi mitmes riigis. Paljud inimesed ei märka seda, kuni nad rikuvad majanduse täielikult. Maa peal pole lõpmatuseni loodusvarasid, seega peaksime säästma nii palju, kui võimalik.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('a3da808f-7996-48b7-b024-25b4e96ac8d2', 'title', 'Ületarbimine');
