INSERT INTO core.text(id, content)
VALUES ('528066b5-99aa-434c-8474-a0b35fd966d1',
        'Tänapäeval on kõik vajalik lihtsasti kättesaadav ning ei pea muretsema, kas poes on midagi olemas, sest seda saab tellida internetist. Sellega tekib ka palju ületarbimist ja jäätmeid, sest sageli võib ära unustada varemalt ostetud toiduaineid või riideesemeid. Kuidas liigset tarbimist vähendada?\nPraeguses ajas oleme harjunud kättesaadavuse ning mugausega, et puuduva saab lihtsasti juurde osta. Kuid alati ei jää meile meelde, mida on juba ostetud ja millal, nii et on võimalus, et koju satub mitu versiooni samast asjast. Samuti võib ka juhtuda sedasi, et üks versioon esemest meeldib omanikule rohkem ja kehvem variant jääb kappi istuma.\nSelle ennetamiseks on olemas alternatiivid. Näiteks võib viia vähem kasutatud riideesemed taaskasutuskeskusesse ning leida sealt endali uusi esemeid, selle asemel et tellida neid juurde Hiina veebipoodidest. Tekstis ka mainiti, et paljud rõivad taaskasutuspoodide ladudes ongi need, mida on tellitud Hiinast. On ka võimalus ise teha riideid, sest siis on kindel, et disainid ja valmistad täpselt seda, mida ise tahad.\nOn täiesti võimalik vähendada oma tarbimist, et tekiks vähem jäätmeid. Inimene peab lihtsalt pöörama tähelepanu on tarbimisele ja märkama, mida on liiga palju. Kui probleemiks on liigne riiete ost internetist, on alati võimalus ringi vaadata erinevates taaskasutuspoodides. Kui probleemiks on liigsed toidujäätmed, siis on üheks lahenduseks teha nädalaks toiduplaan ja osta ainult seda, mis vaja. Kuigi inimestel on palju ületarbimist, on seda võimalik vähendada, kui tõeliselt sellele keskenduda.');
INSERT INTO core.text_property(text_id, property_name, property_value)
