INSERT INTO core.text(id, content)
VALUES ('247f34b3-294b-4950-a3f6-8c1615333e8d',
        'Tänapäeval on väga tavaline, et igal teisel perel on kodus ülemäära asju, mida tegelikult igapäeva elus ei pruugigi vaja olla. Ostetakse kokku igasuguseid riideid mida nähakse, köögimasinaid, et kiiremini toit valmis saaks, meigitooteid, toitu. Kõik see on neile endile ja ka loodusele kahjulik.\nKui liigselt osta riideid, mida tegelikult vaja pole, tekitab see kahju nii inimeste rahakottidele kui ka keskkonnale, kui äsja ostetud särk visatakse peale kahte kandmist nurka. Looduses riided ei kõdune. Heal juhul töödeldakse need ümber ja taaskaskutatakse, kuid vahel isegi see ei tööta. Kui särkidel või pükstel on kas trukid või lukud, ei saa neid täielikult ümbertöödelda. Toitu ei saa aga peaaegu üldse ümbertöödelda, sest ega keegi ei tule inimeste prügikastidesse viimset supitilka välja kraapima. Toidu raiskamine on põhiliselt kahju jällegi rahakotile, kust üldsegi saadi see raha millega toit osteti ja mis nüüd prügikasti on visatud. Arvestade sellega, et iga inimene viskab keskmiselt ära 26kg toitu aastas, võib kujutada ette, et sellest rahast tunneb rahakott ikka puudust . Muidugi, vähendab see ka vahetevahel empaatiavõimet, sest kõikidel inimestel ikkagi toitu ei jätku.\nKui tellida odavatest veebipoodidest, tihti Hiinast, ebakvaliteetseid riideid, ei kahjusta sa sellega ainult keskkonda, vaid paned ka sealtöötavad inimesed ebamugavasse positsiooni. Mitmeid artikleid on tehtud sellest, kuidas Hiina veebipoodide ladudes töötavad tihti alaealised ja suurem osa ajast ka ebainimlikes tingimustes. Sellepärast on lihtsam ja targem osta riideid ja muud kaupa oma endi kodumaalt, nagu on maininud Hanson. Üle sotsiaalmeedia on ka postitatud, kuidas särgisiltidel on kirjutatud teisest keelest tõlgitud abisõnu nagu „Appi!“ ja „Aidake meid!“. On need võltsitud või mitte, kõheda tunde tekitavad ikkagi.\nVäga lihtne on muuta oma tarbimisharjumusi. Igas riikis on mitmeid kohalikke firmasi või brände, kes võibolla ei tee riideid just kindlates stiilides, aga teevad korralikke riideid inimlikus keskkonnas ja tingimustes. Toitu on tark osta piisavalt, et saaks ilusti kõhu täis, aga et ei jääks palju üle äraviskamisele. Alati on ka võimalik külmutada, soojendada, pakkuda kellegile teisele ka ülejääke.');
