INSERT INTO core.text(id, content)
VALUES ('c57e0833-07da-4b11-937d-07450209bfbe',
        'Ületarbimine on tõsine probleem, mis on igapäevaelus normaliseeritud. Sooduskampaaniad, trendid, tänavareklaamid- kõik need tegurid soodustavad seda. Sellele vaatamata, olen arvamusel, et trendid on muutnud inimesed kohusetundlikkumaks ja teadlikkumaks nende tarbimisharjumuste suhtes. \nTänapäeval aktuaalne teema on ületarbimise kritiseerimine ja sellele lahenduste otsimine. Paljud suunamudijad on välja mõelnud erinevaid trende, et inimesi targalt ületarbimise vähendamisse kaasata. Nende trendide hulgas on ka ülalpool mainitud taaskasutuspoodide populariseerimine. Varem nadi muljega teiseringipoed on saanud uue menuka maine. \nSamuti on trendid enamasti suunatud noorte inimeste poole, kelle maailmavaated ja harjumused on alles välja kujunemas. Nooresteast ületarbimise kahjulikke tegurite teadmine võib suuresti muuta inimese mõtteviisi ja soodustab keskkonnasäästlikke otsuste tegemist. Selles suunas liikudes saab ümberpöörata vanu tarbimisega seotud müüte, mis dikteerivad inimeste ulatuslikku sisseostmist.\nÜletarbimine on suur probleem, mis ei kao lähiajal, kuid arvestades väikseid edusamme, mida oleme praeguseks ajaks teinud, liigume aina lähedamale probleemi  likvideerimiseks. Noored inimesed on meie tulevik ning peame neid vastavalt ette valmistama.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('c57e0833-07da-4b11-937d-07450209bfbe', 'title', 'Noored kui ühiskonna tulevik');
