INSERT INTO core.text(id, content)
VALUES ('9996ecb4-e53e-4b25-9657-63ac864bd950',
        'Iga väiksemagi plekiga õun või kõrbenud nurgaga sai jäävad ootama, kui ükskord keegi neid ära sööks. Õmblusest lahti hargnenud jakk loodab, et teda ära parandatakse või selga pannakse. Muidugi seda ei juhtu, sest ebatäiuslikud toidud ja riided lõpetavad oma teekonna prügikastis. Mind paneb mõtlema, kas kõige ära viskamine on tõesti muutunud inimeste harjumuseks?\nMida rohkem toitu ära visatakse, seda suurem nõudlus tekib uute söögikraamide järele. Hinnad kasvavad meeletu kiirusega ning pered, kelle sissetulek pole väga suur, ei jaksa enam soetada kvaliteetseid söögipalu. Hinnatõusudega süüdistatakse valitsust, kuid tõelised süüdlased on ostjad ise. Tahetakse hinnalangust, kuid tegelikult piisab vaid oma toitude ära söömisest.\nInimesed on hullud odavuse järele. Iga allahindlusega rõivas justkui lendab meie ostukorvi mõtlemata. Kahjuks paljud inimesed ei mõista kõige lihtsamat juhust: mida odavam on rõivaese, seda ebakvaliteetsem see ka on. Halvasti valmistatud riided ei kesta kaua: tekivad augud ning kangas võib lihtsasti katki rebeneda. Selle asemel, et neid parandada, ostetakse uusi riided ning vanad visatakse ära. Vahepeal on palju odavam need ära parandada, kui uusi osta.\nOstmine ja ära viskamine on muutunud inimestel katkematuks tsükliks, mida on meie arvates raske murda. Tegelikult piisab vaid söögipala ära söömisest või riideeseme ära parandamisest. Need aitavad säästa raha ning tegelikult ka aega, sest pole vajadust uusi osta. Alati tuleb meeles pidada, et igal väikesel teol on suured tagajärjed.');
