INSERT INTO core.text(id, content)
VALUES ('d7421482-09f2-483a-8d44-b57a2859d971',
        'Üle pooltel maailma inimestel on privileege jalaga segada. Olgu nendeks katus peakohal, puhas vesi, ligipääs arstiabile või riided. Vaid vähesed oskavad oma olukorra õnne väärtustada ja säästa, samal ajal, kui teises maakera otsas elatakse rängas vaesuses.  Ressursse tarbitakse ja raisatakse liigselt, ning see tuleb peatada.\nIga Eesti inimene viskab aastas ära keskmiselt 26 kilogrammi toitu. Kui mõelda terve maailma toidujäätmete kogusele, tekib küsimus, miks kannatavad paljud ikka veel nälga, kui toitu on nii palju? Tegelikkuses pole toitu rohkelt, vaid suurem osa söögist jõuab jõukamate kätte.  Me raiskame toitu, raha ja ressursse. Neist ühtegi pole lõputult.\nRõivaid kanti juba ammusest ajast, kuid ajapikku on inimesed erinevatele riideesemetele tähenduse külge lisanud. Riided pole enam vaid kehakate, vaid staatus, mida kehal kannad. Soov meeldida tekitab otseselt ületarbimist. Näiteks võidakse tänapäeval moodsama riietusega meest paremini kohelda. See tekitab ka suurt raiskamist ja hiljem massilist kahju meie planeedile.\nTuntud lugu mehest, kellele kingiti uhke mantel ja kes hiljem oma ülejäänud mööbli ka mantlivääriliseks uuendas, on väga aktuaalne tänapäeval. Enamikul inimestel on nii mõnigi kasutu või ununenud asi eesmärgitult kapis lebamas. Iga eseme valmistamiseks kasutame resursse, mida enamasti piiramatult ei leidu. Liigne ostmine võib tunduda kahjutu, kuid ükski lõbu ei kesta igavesti.\nPean rõhutama, et toidu, riiete ja esemete valmistamiseks vajaminevaid ressursse pole lõputult. Neid tuleb säästa ja kasutada mõõdukalt. Lihtsa inimesena, ei pruugi me suuta seda mõista, kuid kõigi panus on oluline ja igaühe teguviis tähtis. Vastastikuse heaolu nimel, hoiame kokku toitu  ja ärme osta liigselt asju!');
