INSERT INTO core.text(id, content)
VALUES ('7253165f-2bc5-4d71-b88b-491caf6b4a23',
        'Pole vale öelda, et inimeste tarbimisharjumused on viimase paarikümne aasta jooksul muutunud. Kui eelmine generatsioon kasvas üles teadmisega, et toitu ja riideid on vähe ning neid peab säästma ja hoidma, siis kaasajal on toit ja riided iseenesest mõistetavad.\nIga aasta viskab keskmine Eesti inimene ära ligikaudu 61 kg toitujäätmeid. Sellega ei raiska me vaid enda raha vaid ka kogu planeedi ressursse. Toiduraiskamine on probleemiks üle kogu maailma ja tihti ei pane inimesed seda tähele, kui palju nad tegelikult ära viskavad. Mõndades teistes riikides ja kultuurides on toitu palju vähem ja neil on toidu vastu ka austust. \nTrendid vahetuvad kiiresti, eeskätt moetrendid. Iga kuu või isegi nädal tekkib uus sensatsioon, riideese mida kõik järsku vajavad. Kui mõni riideese niimoodi populaarseks muutub hakkavad kiirmoekauplused seda hulgitootma. Sellest tekib ületootmine ja nii ka ületarbimine. Sageli on see vajadus uusi riideid omada seotud ühtekuuluvustundega. Selle vähendamiseks arvan, et on vaja reklaamida oma isikliku stiili leidmist. Moedisainer Eve Handon, kes käib taaskasutuskeskuste ladudes abis räägib, et inimestele peaks tegema ekskursiooni ladudesse, et neile näidata, milline olukord on.\nÜkspäev saavad maailmast ressurssid otsa ja inimkond peab seda endale teadvustama, ning lahendust otsima. Ületootmine ja ületarbimine ainult ohustab meie tulevaste põlvede keskkonda ja neil saab tänu meie tegudele raske olema. Praegune raiskamiskultuur viib meid ainult allamäge.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('7253165f-2bc5-4d71-b88b-491caf6b4a23', 'title', 'Raiskamiskultuur');
