INSERT INTO core.text(id, content)
VALUES ('268784ca-4c6e-4669-b193-3cdb6274fd0b',
        'Inimkond on aastasadu töötanud helgema ning kindlustatud tuleviku nimel. Nüüd, kus eluks vajalikud vahendid nagu toit ja riided tunduvad meile kättesaadavamad kui iial varem, kimbutab rahvastikku uus mure – ületarbimine. Täheldan isegi, et asjade ostmisega piiri pidamine nõuab ranget distsipliini. Kuid meie kergekäelise ostmis- ja äraviskamiskultuuri juurte mõistmiseks peab heitma pilgu nii möödunud aegadesse kui ka tänapäeva meediamaailma.\nKunagise inimese rahuldamatu nõudlikkus motiveeris teda rühkima parema eluni. Too innukus on säilinud ka nüüdisaegses rahvas, kellest paljud esivanematest veel kaunimalt elada soovivad. Seda mõttelaadi toetavad hiljutised edasiarendused, näiteks kiirmoodi müüvad veebipoed, on teinud meeldivate asjade saamise lihtsamaks. Nagu näitab ka ajalugu, kipub inimkond kiinduma uudsetesse edendustesse ning seetõttu tarbime nüüd tihtipeale riideid ja toitu vaid südame lusti tarvis, mitte hädavajalikkusest tingitult.\nSuurt rolli pidurdamatus tarbimiskultuuris mängib kindlasti ka sotsiaalmeedia. Nähes kellegi seljas uut moodsat kleiti või jalanõusid, tekib endaski soov kiirelt nii trendikat riideeset omada. Nagu tõi välja ka moedisainer Eve Hanson, satuvad sellised impulsiivsed ostud, mis reklaamfotol tohutult ilusad välja näevad, tihtipeale lõpuks taaskasutuspoodide riidehunnikutesse – või hullemal juhul lihtsalt prügimäele. Nõnda vaid kulutame ressursse ja reostame maakera, kui silmailu nimel kiirtarbimist peatada ei suuda.\nEndale uute asjade lubamine on mõistagi tore, inimlik tung, mis tuleneb suuresti meie naturaalsest loomusest ja tootmisele ehitatud ühiskonnast. Siiski põletab tarbimiskultuur liialt läbi maa loodusvahendeid ning ei suuda iialgi täita seda isiklikku tühjust, mida paljud trendikate esemete või toiduhunnikutega unustada püüavad. Sellegipoolest võib näha, kuidas inimkond astub tasapisi ka õigeid samme liigse ostmise ja äraviskamise vähendamiseks, mis tõotaks meile tõepoolest helgemat tulevikku.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('268784ca-4c6e-4669-b193-3cdb6274fd0b', 'title', 'Kiirtarbimine südame lusti tarvis');
