INSERT INTO core.text(id, content)
VALUES ('3037262f-33c1-4ba3-ba57-0ed2cfe97615',
        'Tänapäeva inimkonda ähvardab suur probleem, milleks on meie ebamõistlik tarbimine. Viimasel ajal on hakatud ka sellele murele tähelepanu osutama sotsiaalmeedias, televisioonis, kuid jääb mulje, et inimesed ei mõista siiski olukorra tõsidust ning pole veel pühendunud oma harjumuste muutmisele.\nIlma sellele isegi mõtlemata raiskavad inimesed igapäevaselt tohutult kaupa. Lastele ostetakse eineid, millega tulevad kaasa tarbetud mänguasjad, meie seast käivad kiiresti läbi moetrendid, toidupoodides lähevad raisku puuviljad ja juurviljad pealmise defektiga. Kõige selle keskel ei seisata keegi, et mõelda, kas nende ostudel on tagajärgi looduses ning selline käitumine toob endaga kaasa tohutult loodusreostust. Mõnes mõttes võib öelda, et valime hetkelised mõnud üle kestva heaolu.\nLisaks ületarbimisele ei mõtle tavainimene ka palju toote kvaliteedile. Paljud ei näe vaeva uurides rohkem toote hinnangute või varasemate ostjate kogemuste kohta. Ostetakse odavaid praaktooteid, mis on hinnalt odavad ning ilusa välimusega, kuid ei vasta kvaliteedistandarditele. Tähelepanuta jääb fakt, et selliste toodete valmistamisel ja transportimisel kasutatakse samuti loodusressursse ning eritatakse tõenäoliselt loodusele kahjulikke gaase. Väga suur ja kahjulik selline tööstusharu on näiteks kiirmood, kuid ühiskonda on juba tugevalt kinnistatud moetrendid, seega võib olla raske käitumist muuta. Siiski on vaja kõiki probleemi kohta rohkem harida ja rõhutada mõistlikku tarbimist. Moedisainer Eve Hansoni meelest peaks viima inimesi juba noorelt taaskasutuspoodide lattu raiskamist vaatama.\nInimkond tervikuna peaks käituma tarbimise suhtes vastutustundlikumalt. On oluline, et kõik hakkaksid enda oste põhjalikumalt läbi mõtlema ja plaanima. Iga inimene peaks enda tarbimist analüüsima ja leidma alasid, kus saaks teha parandusi, sest sedamoodi jätkates elame kõik varsti põlevate prügimägede otsas.');
