INSERT INTO core.text(id, content)
VALUES ('051a1637-1905-42bc-8bc7-93884172bdf5',
        'Elame ajal, mil kõik on kättesaadav ja midagi ei ole võimatu toota. Tarbimine juhib meie igapäevaelu, me teeme tööd, et raha teenida ja seda pärast kulutada. Kuigi meile meeldib elada maailmas, mis on lihtne ja mugav, peame mõtlema ka sellele, kuidas keegi või miski kannatab meie harjumuste tõttu. Üks suurimaid probleeme mis sellest tuleneb on ületarbimine.\nÜletarbimine ei ole ainult tarbja süü. Suured firmad panustavad miljoneid eurosid turundusele, et just nende tooteid ostetaks. Reklaaminduses kasutatakse tihti ära päevakohaseid teemasid ning inimeste psühholoogiat, et veenda inimest ostma asju, mida tal võibolla isegi vaja ei ole. Näiteks suurtes Hiina internetipoodides on pidevad allahindlused, mis meelitavad meid ostma halva kvaliteedi ja ebaeetiliste viisidega toodetud kaupu. Ostjaid manipuleeritakse ka erksates toonides hinnasiltide või soodusreklaamidega, mis suunavad kiiresti tähelepanu tootele. Peaksime ise teadlikumalt ostlema. Inimesed ei mõtle tavaliselt, kuidas neid mõjutatakse, kuid on aeg sellele tähelepanu pöörata.\nSiiski peame ka ise meeles pidama, et meie ostetud asjad ei kao pärast kasutamist kuskile ära. Tihti jõuavad need prügimäele või hoopiski loodusesse. Enamus prügi ei töödelda ümber, seega peame ise mõtlema, kuidas millelegi uus elu anda või seda ise ümber teha. Näiteks saab katki läinud või vanadest riietest õmmelda uusi rõivaid või muid tekstiilesemeid nagu patju, kotte ja pajalappe. Kuigi see ei ole väga populaarne, oleks mõistlik meil õppida ise endale asjade valmistamist. Lisaks tuleks ka toidujäätmete hulka vähendada. Praegu viskab kekmine eestlane ära 61kg toitu ning seetõttu raiskame me väga palju loodusressursse. Kasutuskõlbmatut biolagunevat prügi on tark komposteerida, sellega saab väetada uusi taimi, mida võime oma toiduks kasutada- nii ei pea me ka sõltuma teistest inimestest.\nLiigne tarbimine on tänapäeval suur probleem, kuid see ei ole lootusetu situatsioon. Me peame ennast tagasi hoidma- paljud asjad mida me ostame ei ole tegelikult vajalikud. Lisaks on meil tohutult viise taaskasutamiseks või ümbertöötlemiseks. Arvan, et praegu on puudu vaid tahe ning tegelikult on võimalik tarbimist väga palju vähendada. Kui inimesed kollektiivselt muudavad oma harjumusi, saame me liikuda paremuse poole.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('051a1637-1905-42bc-8bc7-93884172bdf5', 'title', 'Kas inimene suudab vähem tarbida?');
