INSERT INTO core.text(id, content)
VALUES ('110910e0-0ebc-49c7-ac00-ed67d6c0d13c',
        'Järjest enam tuleb ette meie igapäevases elus, et inimesed hangivad endale ühtlugu üha uuemaid ning nüüdisaegsemaid asju. Sageli unustatakse vanemad riided ning tarvikud ära ja asjad muudkui kuhjuvad kodus ning kasutust neile ei suudeta enam leida. Armastatakse maitsvaid roogasid ja peetakse normaalsuseks omada kodus külmkappi, mis on täis toitu, mis sageli oma kõlblikkuse enneaegselt kaotavad.\nEnamus inimestele meeldib käia trendiga kaasas. Just moe tõttu kogume endale majja hunnikutes esemeid, mis ühel kenal päeval meil lihtsalt tuppa vedelema jäävad. Jätame mõtlemata sellele, et miks on meil nii palju neid vaja. Tihti on vanemad rõivad huvitavamadki, kuid millegi pärast kardavad inimesed teistest erineda ning usaldatakse neid, kellel on uhiuued riided seljas.\nInimestele tundub, et toitu on alati veel ja see ei saa kunagi otsa. Reaalsuses aga nii ei ole, sest iga toiduaine valmistamiseks läheb vaja ohtralt toorainet ja tööjõudu. Üldjuhul soetatakse endale rohkem toidukraami, kui seda tegelikult vajatakse. Vahel soovime end poputada näiteks millegi magusaga, kuid me ei mõista, et samal ajal, kui meie naudime, peab keegi selle pärast kannatama. Inimestele meeldib elada mugavat ning muretut elu, kuid tihti unustatakse, et igal asjal on siin elus lõpp, ning nii on ka toidul.\nOlulisim siin ilmas on keskkond, kus elame. Kui sedamoodi isekalt jätkame, pole meil varsti enam kohta, kus elada. Meie halvad tarbimisharjumused mõjutavad maad väga suurel määral ning tähtis on alustada targemat eluviisi, mis hõlmab toidu ning rõivastega hästi ümberkäimist.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('110910e0-0ebc-49c7-ac00-ed67d6c0d13c', 'title', 'Inimeste tarbismisharjumused');
