INSERT INTO core.text(id, content)
VALUES ('c13b66e4-d170-4a59-b886-a38545761cc4',
        'Tänapäeval on väga moes kiirmood, see areneb iga päev ning selle ohvriteks on paljud noored. Igal pool, kuhu vaatad on reklaamid ja populaarsust koguvad erinevad Hiina veebipoed nagu Shein ja Temu, kust saab tooteid osta odava hinnaga, kuid halva kvaliteediga. Sellega kaasnevad kohutavad tarbimisharjumused, mille sees teismelised peavad üles kasvama.\nErinevad internetipoed saavadki kuulsaks, sest nad suudavad toota uusi asju kiiresti. Nendes vabrikutes toimub suur ületootmine, sest nõudluse ja pakkumise suhe pole kooskõlas. Suur osa toodest pole võimalik maha müüa ning need lähevad otse prügimäele. Noored seda osa ei näe, sest sotsiaalmeedias näidatakse ainult häid külgi.\nE-poodidega kaasneb ka üleostmine, sest silmatorkavad erinevad sooduskampaaniad ja reklaamid, millele ei suuda ei öelda. Ostetakse riideid, mida ei kanta, ja esemeid, mida ei kasutata. Riideid, mida ei kanta enam, sest need pole moes, viivad noored kaltsukatesse, kus neid edasi müüakse, aga praegu viiaksegi sinna neid kiirmoe esemeid, mida suudetakse kanda ainult korra või kaks.\nNõustun Eve Hansoniga, tema sõnul tulekski näidata noortele taaskasutuspoodide ladusid, et nad näeksid, kui palju riideid tegelikult raiskub. Arvan, et uuskasutus saaks teismelistelt palju tähelepanu, kui seda romantiseeritakse sotsiaalmeedias, sest seal viibides jääme tahtmata reklaamide ohvriteks. Meedias võiks rohkem kajastada kiirmoe problemaatilisust ja sellega kaasnevaid majanduslikke ja ühiskondlikke probleeme.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('c13b66e4-d170-4a59-b886-a38545761cc4', 'title', 'Kiirmood ja noored');
