INSERT INTO core.text(id, content)
VALUES ('38059940-c5c2-439f-b435-9d7a5e05910e',
        'Tänapäeval on populaarseks muutunud asjade hulgiostmine. Kiires maailmas muutuvad inimeste arvamused pidevalt ja vanad asjad jäetakse kiirelt maha. Kui halb see tegelikult on?\nNüüdisajal, kus inimestel on palju rohkem raha kui varem, ei hoita seda enam nii kõvasti kokku. Seda on näha näiteks sellest, et inimloomad ostavad toitu, söövad seda natuke ja siis viskavad ära. Näiteks mul  juhtub tihti sedasi, et ostan paki mingit asja, millele mul kõva isu on, söön sealt paar tükki ära ja tulemusena läheb ülejäänu halvaks. Tihti arvavab ka rahvas, et kui nad ühe asja ära viskavad, ei muuda see midagi. Tegelikult tekib kokku ikkagi nii palju prügi, et see muutub väga kahjulikuks maailmale.\nPopulaarseks on muutunud ka riiete ost. Kaasaja nutimaailmas on tekkinud mood teha kõike üksteise järgi ning ei mõeldagi enam, kui kahjulik see tegelikult olla võiks. Inimesed näevad oma lemmiku sisulooja seljas mingit särki, ja tellivad selle silmapilk mõnelt Hiina lehelt nagu näiteks SHEIN. Tihti ei mõeldagi, kas ostu on tegelikult vaja või mitte. Lisaks ei arvestata, et sellised kiirmoe poed on väga ebaeetilised kuna nad ei maksa oma töötajatele piisavalt ning tihti palgatakse lapstööjõudu. Samuti visatakse tihti riideese peale üht kasutust ära, kuna suunamudija seda enam ei kanna. Mina ei ole kunagi tellinud endale riideid, katsun neid alati kõigepealt kaltsukatest saada. Arvan, et ei hakka kunagi odavaid ja ebakvaliteetseid riideid ostma.\nArvan, et inimesed peaksid rohkem mõtlema, kuidas oma raha kasutada. Samuti peaksid nad enne igat ostu korralikult järele mõtlema, kas asi on vajalik või mitte. Kui sedasi jätkata, pole meil varsti enam maailma.');
