INSERT INTO core.text(id, content)
VALUES ('c12d91da-1dff-4265-8d18-af58d1c702c6',
        'Ületarbimine on tänapäeva maailmas suur probleem, inimesed söövad liiga palju toitu, ostavad liiga palju riideid ja tellivad asju, mida neil tegelikult vaja pole ning tooteid, mis väga vähe kasutust leiavad. Ületarbimine on halb inimese enda rahakotile, aga ka keskkonnale ja ühiskonnale. Miks seda üldse tehakse, kui tundub, et positiivseid külgi sellel polegi?\nÜletarbimine on tehtud väga lihtsaks. Tänu internetikaubamajadele, kust saab osta väikeseid vidinaid väga soodsa hinnaga, on suureks probleemiks kujunenud emotsiooniostud. Ostmine on tehtud kiireks ja lihtsaks, inimene saab panna endale kärusse kümneid asju ja seejärel paljustki mõtlemata vaid paari vajutusega kaubad ära tellida. Nädala pärast on juba asjad käes, neid kasutatakse korra ja siis tihtipeale jäävad kuhugile sahtlisse istuma.\nSamuti on suureks probleemiks söögi raiskamine. Tavaliselt on prooblem liialt suurte koguste tegemine, peale mida ei suudeta kõike ära süüa. Siis jääb toitu üle ja see visatakse minema uuesti soojendamise asemel. Inimesed ei mõtle piisavalt selle peale, mida ja kui palju nad tegelikult sööma peaks ja süüa jõuavad. \nÜletarbimise põhjuseid võib olla palju, kuid enamjaolt on asi ostude ja otsuste mitte läbimõtlemises. Ei mõelda piisavalt selle peale, kas asju, mida ostetakse on üldse vaja või mitte. Mina arvan et saaksime ületarbimist suuresti vähendada, kui mõtleksime rohkem ja lõpetaksime emotsiooni pealt ostude tegemise.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('c12d91da-1dff-4265-8d18-af58d1c702c6', 'title', 'Ületarbimine');
