INSERT INTO core.text(id, content)
VALUES ('5047d15c-9179-4abc-9d16-bb0999c65ed4',
        '\nMe raiskame rohkem toitu kui me tarbimime.Osad inimsed  lähevad kaasa sooduskampaaniatega ostavad palju ja hiljem viskavad ära. Paljud arvavad ,et   kui nad natuke midagi ära viskavad, siis nad väga midagi ei mõjuta. \nPaljud inimsesed raiskavad toitu sellega ,et lähevad kaasa sooduskampaaniatega ostavad liiga palju ja hiljem peavad ära viskama, kuna nad ei jõua seda ära tarbida, palju tellitakse ka internetist igasuguseid asju mis pärast ei sobi kuna need on halva kvaliteediga  ja hiljem on ebamugavad nad aravavad ,et nad sellega väga midagi ei mõjuta tegelikult on see vale iga aasta tekib  palju toitu ja muid kaupasi  mis on ära visatud  riknemise pärast. See on tegelikult suur probleem mida ei saa vähendada väga kiiresti, üks võiamalus oleks juba lastele teha erinevaid koolitusi toidu raiskamisest.Tänu sellele saaksid lapsed juba varakult selgeks ,et toitu  ei tohiks raisata.\nSooduskampaaniatega ei tohiks kaasa minna, kuna saa ostad liiga palju korraga ei jõua seda ära tarbida ja viskad ära see on tegelikult halb meile kõigile. Ei tohiks arvata ,et kui ma midagi natuke ära viskan siis see pole midagi, kui iga inimene nimodi mõtleks siis me ikka viskame palju ära ja teeme kahju ainult. Kahjuks ei saa toidu raiskamist lõpetada väga kiirelt kuna inimesed on harjunud liigse ostmisega.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('5047d15c-9179-4abc-9d16-bb0999c65ed4', 'title', 'INIMESTE HALVAD TARBIMISHARJUMUSED');
