INSERT INTO core.text(id, content)
VALUES ('213f67ca-fba0-45d4-83c4-609f6982cd0c',
        'On teada, et tänapäeva inimesed tarbivad väga palju. Seda on näha kliimasoojenemisest ja jäätmete hulgast maailmas. Aga tundub, et paljusi, eriti mehi see taaskasutuse ja tarbimise teema absoluutselt ei huvita.\nPlaneedil Maa elab umbkaudu 8 miljardit inimest ja kõik peavad sööma, olema kaetud riietega ja ostma erinevaid tooteid, et elus püsida või lihtsalt teha oma elu mugandada. Väga paljud pered tarbivad ja viskavad ära rohkem asju kui peaks, ehtne näide on toiduraiskamine. Keskmisesse perre tekib 61 kg toidujäätmeid, millest 26 kg moodustab raisatud toit. See on kurb. Inimesed võiksid arvestada toidukogustega mida nad teevad, sest isegi minu peres toimub üüratu raiskamine. Isa teeb terve pannitäie kartuliputru mida me sööme kaks päeva, aga lõpuks läheb ikkagi rohkem kui pool äraviskamisele. Täpselt sama asi kehtib ka riiete kohta. Noored ostavad kiirmoekettidest riideid, ise teadmata millest tema riideese tehtud on ja mis jälje see loodusele jätab, ning viskavad lõpuks ebamugavuse ja kvaliteedi pärast minema, väitis moedisainer Eve Hanson.\nHaridusministeerium võiks teha kohustuslikuks teha näiteks keskkonnaõpe või taaskasutustunni just algklassides, sest tundub, et väiksemad ikkagi ostavad mõttetuid mänguasju, viskavad prügi maha ja viskavad taskurätikuid pakendi sektorisse jne. See tund oleks hea selleks, et nemad saaksid ülevaate meie Maa seisukorrast ja et nemad hakkaksid ka tulevikus sorteerima ja ratsionaalselt mõtlema Eesti ja planeet Maa osas , käima taaskasutuspoodides ja viskama vähem toitu ära, nii oleks vähemalt pealetuleval generatsioonil mingi alus mille järgi opereerida. Muidugi ainult noored ei pea neid asju teadma, keskealised ja neist vanemad võiksid ka teada kuidas sorteerida ja taaskasutada. Keskkonnaministeerium võiks ka asja rohkem tõsisemalt võtta. Näiteks saata kõigile täisealistele juhend või kokkuvõte sellest, et mida, kuidas ja kui palju kasutada. See tõstaks vanemate eriti meeste teadlikust nende tarbimisharjumustest.\nInimesed tarbivad suurtes kogustes toitu ja riideid. Hetkeseisuga tundub, et see väga Eesti kodanikele ja elanikele see suuremat muret ei tekita, ning koolides ja lasteaedades räägitakse sellistest teemadest üsna vähe. Keskkonna- ja Haridusministeerium võiksid teha koostööd ja luua õppekava lastele ja saata laiali juhendeid kõigile täisealistele inimestele kes elavad Eesti Vabariigis, et maailm oleks puhtam ja parem paik kus elada.');
