INSERT INTO core.text(id, content)
VALUES ('e8326697-b3e5-4a6c-b98a-7b2bf86dfbc8',
        'Inimeste tarbimisharjumused on ajaloo kooksul palju muutunud, kuid vaadates üldplaani, tekib pilt, kus inimesed tarbivad kohe, kui selleks raha on. Ühed tarbivad, teised toodavad ning ka tootjad on tarbijad. Sellest tekib meie ühiskonnas pärilik ring, kui lapsepõlves pole vanemad lapselt küsinud „Kas sul on tõesti seda mänguasja vaja?“, ei küsi see inimene seda ka enda käest tulevikus. Asju raisatakse ilma, et mõeldaks, kuidas ja läbi mis protsesside jõudis see asi inimeseni.\nPaljud inimesed ei pruugi mõelda sellele, kui palju nad toitu, riideid ja muid, veel kasutamiskõlblikke asju ära viskavad. Tarbitoitutargalt.ee kodulehel on toodud välja, et Eesti inimese kohta tekib toidujäätmeid keskmiselt 61 kg aastas, millest on raisatud toitu 42% ehk 26 kg. See 26 kg toidukadu moodustub toidust, mis jääb tarbimata ehk on jäänud toidukordadest üle, on riknenud, või lihtsalt visatakse minema. Toit, mis läheb raisku, pole lihtsalt toit, seda toitu kasvatati, taimede peale kulus vett, loomadele kasvatati taimi ja joodeti vett. Taimede kasvatamise jaoks kasutatud põllumaad rikkusid loomade elukeskkondi. Keskmisel inimesel pole täielikku pilti, kust kohast tema toit tuleb ja mis ressursid sinna alla läksid.\nInimesed tarbivad, kuna toodetakse, tootjad toodavad, kuna tarbitakse. Sellisest ringist on raske välja murda, kuna inimestel on selles ringis mugav. Ringist välja saamiseks tuleb jagada tooteid kahte gruppi: vajalikud ja ebavajalikud. Üle kogu maailma tulevad inimesed pidevalt uute ideede peale, mida toota. Tooteid tootes tulevad tarbijad ning teised tootjad, märgates et mingit asja tarbitakse palju, hakkab sellest asjast uut varianti tootma. Selle ringi lõpetamiseks peab ka eraisik oma panuse andma ning vähendama ebavajalike asjade ostmist. Osteldes tuleb meeles pidada küsimust „Kas mul on tõesti seda vaja?“, sest ilma selle küsimuselta lendab igasuguseid mõttetuid asju ostukorvi.\nTarbides kulutame raha ja ressurssi. Kõik asjad ei kesta igavesti ning peame sellega arvestama. Kord saavad ressursid otsa ning kuna inimesed on pidevate uute asjadega harjunud, siis hakkavad tootjad ohverdama rohkem vajalikke ressursse nagu loodus ja madalama klassi inimeste elukvaliteet. Tarbimisringis on alati kaks poolt: „Aga nemad ju toodavad!“ ning „Aga nemad ju tarbivad!“. Võib-olla suudaksime pobleemi lahendada mõeldes „Mina ei pea ju tarbima.“');
