INSERT INTO core.text(id, content)
VALUES ('093158c1-f87d-4c4c-987a-4713ed0d3185',
        'Tänapäeva inimesed on muutunud liiga vabaks oma tarbimisharjumustega. Tihti visatakse ära täiesti kõlblik toit ja väga ilusad kantavad riided. Enamus inimesi ei hoia enam millegi pealt kokku ja ei taha säästa kõlblikke tarbekaupu. Tihtipeale on kuulda, kuidas üks või teine ütleb, et kavatseb hiljem poest uue toidu asemel osta või netist uued riided tellida.\nEriti suur raiskamine toimub tänapäeval toidumaailmas. Kui pool toidust jääb alles, sest sööjal sai kõht täis, siis visatakse see alles jäänud toit lihtsalt ära. Kuigi tegelikkuses saaks seda toitu veel mitu päevagi külmkapis hoida ja seejärel hiljem ära süüa. Ka toidud, mille parim enne on läbi saanud visatakse koheselt minema arvamusega, et need on pahaks läinud. Tarbitoitutargalt.ee veebilehel on välja toodud, et iga Eesti inimese kohta tekib ühe aasta jooksul 61kg raisku läinud toitu või toidujäätmeid. Enamjaolt võiks inimesed kodus ise teha sooja toitu ja võimalikult vähe osta rämpsu. See oleks hea tervisele ja aitaks vähendada toidu raiskamist, sest kodutoit säilib alati kauem.\nTeine suurem probleem tänapäeval on riiete ära viskamine. Paljud ostavad riideid kiirmoetrendide järgi odavatest netipoodidest. Kui need trendid ära lõppevad, siis visatakse ka need riided üsna koheselt prügikasti ja minnakse uue trendi järgi riideid ostma. Näiteks arvab moedisainer Eve Hanson, et riideid peaks ostma kvaliteedi, mitte kvantiteedi järgi. Veel on ka Hanson vägagi suur taaskasutuse fänn. Õnneks ongi üha enam hakatud riideid taaskasutuspoodidesse viima, et need teisele ringile saata. Sellest saab kasu nii ostja, müüa kui ka loodus. Ostja saab odava hinnaga just neid riideid, mida soovib, müüja saab lahti mittevajalikest riietest ja teenib ka ise väikese kasumi sellega ning loodusesse ei satu enam riideprügi.\nInimesed võiksid kõlbliku toidu panna külmkappi ja hiljem lõpuni süüa. Parim enne märgisega tooteid ei peaks kohe ära viskama. Riiete puhul tuleks valita kvaliteet üle kvantiteedi ja vähendada odavatest veebipoodidest ostlemist.');
