INSERT INTO core.text(id, content)
VALUES ('baf864b9-128e-4442-902b-2dd0da8b27b5',
        'Peamisteks probleemideks on inimestel see, et me ei oska säästlikult elada ja ei austa inimesi, tänu kellele meil on olemas toit, kuid asi pole vaid toidus, kuid ka kõikides muudes ressurssides, näiteks vees.\nInimesed peamiselt viskavad nii palju toitu ära selle pärast, et nendele see erilist probleemi ei tekita. Tava inimesed ei ole need, kes peavad kasvatama ome toitu, et need hiljem saata poodidesse, vaid seda kõike teevad talumehed ja naised, kellel on olemas farmid. Üle poole inimestest ei raatsi panna järele jäänud toitu külmikusse, et nad saaksid jätkata hiljem, vaid nad eelistavad ära visata ressursse, mille tegemiseks on vaeva nähtud. Paljud inimesed ka ostavad liiga palju, arvates, et nad jõuavad perega või üksi kõik ära süüa enne kuupäeva kättesaamis, aga see pole enamus peredel ega ka inimestel, kes üksinda elavad, päris tõsi. Hea näide on näiteks toidukaotuse artikklist, kus peaaegu pooled toidud visatakse ära just selle pärast, et inimesed ei suuda kõike ära lõpetada. Ka mina olen näinud, näiteks restoraanides, kuidas inimesed, kes ahnitsevad liiga palju toitu, jätavad selle lauale alles ja hiljem visatakse see ära.\nInimeste harjumuste tõttu oleme harjunud toitu ära viskama ning mitte säästlikult ressursse tarbima. Me kõik oleme endale ilmselt lubanud, et hakkame säästlikkuma elu elama, aga kahjuks väga vähesed peavad oma sõna. Heaks näiteks enda elust peaksin oma õde, kes lubab alati, et lõpetab ahnitsemise, kuid ei pea sellest kinni. Tähtis oleks ikkagi see, et inimesed võtaksid end kokku ning hakkavad elama säästlikumat elu, sest siis poleks nii palju raha raiskamist ja nii palju toidu ära viskamist.\nJärelikult tuleks inimestel hakata austama toitu ning ka talunikke rohkem, sest tänu neile on meil toit laual. Lisaks sellele kõigele tuleb meil ka õppida, kuidas olla säästlikumad parema tuleviku, kui ka enda jaoks.');
