INSERT INTO core.text(id, content)
VALUES ('b35d19ed-db21-4516-a65b-5a84c68274ed',
        'Toiduraiskamine on tänapäeval globaalne probleem, mille suurimaks põhjuseks on see et inimesed ei mõtle kaugemale, nad ei suuda näha suurt perspektiivi. Kui inimesed ei mõtle sellele suuremale pildile on väga lihtne visata toitu ära, tekitada keskkonna probleeme  ning raisata Maa ressursse.\nInimesed ei hooli tänapäeval toidust, nii nagu tehti seda vanasti. Kodumajapidamises tekib iga Eesti inimese kohta aastas 61kg toidujäätmeid, millest 26kg sellest on toidukadu. Inimesele ei ole toit enam nii oluline, kui tekibki toidujääk, visatakse see ära, kui  toiduaine on ületanud oma kehtivuse kuupäeva, visatakse see ära, isegi siis kui see oleks tarbimis kõlblik. Vanaema alati rääkis et vanasti olid inimesed väga õnnelikud kui nad kasvõi natukene midagigi kõlbliku omale hamba alla said. Toiduäraviskamine oli neile kui patt, ennekuulmatu. Mida aeg edasi, seda vähem inimesed mõtlevad, nad harjuvad ära, et toidu raiskamine on okei.\nToidu äraviskamisega raiskame me Maa ressursse ja selle kõrvalt kahjustame ka oma keskkonda. Toitu ära visates ei tule inimesele pähe küsimus Kust see tuleb? Kui palju on vaeva nähtud, et mina saaks seda praegu tarbida? Nad ei mõtle sellele, kui palju kahjustatakse meie keskkonda, selleks et neid toiduaineid toota, mida rohkem toodetakse, seda rohkem läheb ka energiat, seda rohkem peavad tööstused tootma, tekitades keskkonnale suuri kahjustusi.\nToidu ära viskamine on saanud tänapäeva normiks. Inimesed kas ei suuda või ei soovi mõelda kaugemale, mõelda nendele küsimustele, mis tegelikult on olulised. Miks? Kas? Kust? Kas on vaja? Tänu inimkonna mitteteadlikusele rikume me oma keskkonda üha rohkem ja rohkem.');
