INSERT INTO core.text(id, content)
VALUES ('2c1578e2-33a1-4635-9511-57706d6d8e12',
        'Inimesed ostavad või teevad üle liia toitu ja pärast jääb nii palju üle või läheb halvaks ning siis visatakse ülejäänud toit minema. Tegelikult saaks vähem osta ja teha, et ei tekiks nii palju ülejääke ja inimesed säästavad nii rohkem raha ja loodusressursse. Inimesed võiks ka rohekm taaskasutada mitte terveid riideid, mis selga veel lähevad ja kasutuskõlblikke asju mitte  minema visata või nurka panema. Ei pea kohe ostma uusi riideid või asju vaid võib ka veel vanu asju kasutada.\nInimesed ostavad või teevad palju toitu ja väga palju jääb sellest järgi või on see juba riknenud ning see visatakse minema. Toitu visatakse ära ka siis, kui sellel on ka kõlblikuse kuupäev üle läinud, aga tegelikult võib see veel söödav olla, kui see toode on veel kinnine. Tarbitoitutargalt.ee lehel on kirjas, et „kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg“. Sellepärast tulekski toitu kas vähem teha ja osta , sest alati saab juurde teha või juurde osta. Enne toidu ära viskamist proovida ka seda, kas see veel kõlbab ja võtta nii palju toitu kui ära jaksad süüa, et ei peaks seda ära viskama. \nTaaskasutus pole paljude inimeste seas laialt levinud ja nad ostavad koguaeg uusi asju või riideid ja viskavad vanad  ära või lihtsalt jätavad need kuhugi nurka ega vii neid taaskasutusse. Tegelikult võiks need asjad, mis terved ja korralikud on ning mida saab veel kasutada viia taaskasutuskeskusesse, kui neid ise enam ei kasuta. Annetada ka abivajajatele ja kodututele kellel oleks neid asju ja riideid vaja, et nemad ka saaksid tunda, et neid aidatakse. Raadiosaates „Vikerhommik“ räägiti seda, et noortele võiks teha ekskursiooni taaskasutuspoodide lattu, et nemad ka näeksid milline raiskamine on tegelikult inimeste seas ja noored võiks selle peale mõelda ning olla kunagi tulevikus targemad ja kasutada asju kuni lõpuni. Mida kauem asju kasutame ja riideid kanname seda  vähem  tekib asju mida, peaks ära viskama ning sellega tekib vähem jäätmeid. \nKokkuvõtteks võiks inimesed vähem toitu raisata ja taaskasutada rohkem, et hoida loodust ja meie maailma, et uutel põlvkondadel jääks korras maa ja õhk. Kui tahame, et uued põlvkonnad saaks siin veel elada peame enda ümber olevat loodust hoidma, üritada raisata vähem ning taaskasutada rohkem.');
