INSERT INTO core.text(id, content)
VALUES ('64f05770-df8e-4ac8-bb4e-700e5e81f777',
        'Inimested ei tarbi nii palju kui nad kokku ostavad. Kas inimesed ostavad päriselt ka palju toitu või Hiinast odavaid esemeid? \nInimese toidu tarbimis harjumused raiskavad ressursse. Tänapäeval raiskavad nii palju inimesed toitu ja see on muutunud probleemiks. Inimesed viskavad natuke toitu iga päev ära pärast õhtusööki, sest neil on kõht täis ja ei taha enam süüa või toit seisab külmkapis nii kaua, et läheb pahak. Nad ei saa aru kui palju toitu päriselt raisku läheb kui viskad iga päev natuke toitu ära. Nagu ütleb tarbitoitutargalt.ee, et keskmine eestlane viskab ära umbes 61kg toidujäätmeid millest toidukadu moodustab 42% ehk 26 kg ja seejärel läheb raisku paljuid ressursse nagu maad, vett, energiat ja tööjõudu. Me saaksime inimeste toidu tarbimist  Inimesed saaksid seda ära hoida toidu hulga vähendamisega, mis nad enda taldrikule panevad. Inimesed ostavad rohkem toitu kui neil vaja on ja selle pärast viskavad nad toitu ära.\nInimesed eelistavad kvantiteeti kvaliteedi üle. Inimesed vaatavad asjade juures kõige rohkem hinda mitte seda kui kvaliteetne asi on nagu tõi Hanson välja, et „Ei telliks Hiina veebipoodidest juba põhimõtte pärast asju, ei läheks kaasa sooduskampaaniatega“ ja „Eelistada võiks kodumaiseid oma lähedal toodetud asju ning pigem vähem kui rohkem“  Tänapäeval on nii palju sooduskampaaniaid ja kõik tellivad endale Hiinast tooteid, sest need on ondavamad ja siis ei pea oma kodust välja minema. Et seda parandada peaksime ostma süüa lähedusest nagu näiteks kodustest farmides ja ei ostaks liikseid esemeid mida tegelt pole vaja.\nInimesed raiskavad tänapäeval palju toitu, toidujääkide ära viskamisega ja ei saa aru palju see aasta peale päriselt need toidujäägid kaaluvad. Inimesed tellivad Hiinast odavaid esemeid ja lähevad kaasa sooduskampaanjatega, kõik selle pärast, et asjad on sootsamad aga nade ei vaata selle eseme kvaliteeti.');
