INSERT INTO core.text(id, content)
VALUES ('330181c7-46b9-4c58-8dff-5ff4ac1cd46f',
        'See teema on väga suur globaalselt ja ka väga suur oht meile kui inimestele. Inimesed ainult tarbivad ja raiskavad toitu ilma, et nad aru saaks, et isegi toit saab kunagi otsa. See on ka sellest, et meile kui inimestele ei õpetata piisavalt, et kui tähtis toit meile tegelikult on.\nToidu raiskamine on suur teema millele peaksid kõik inimesed tähelepanu põõrama. Paljud inimesed arvavad, et kui nemad natuke toitu ära viskavad ei muuda nad midagi, aga see on puhas vale. On ka inimesi, kes raiskavad rohkem toitu kui keskmine inimene, kuna nad saavad seda endale lubada. Mida rohkem inimesed nii hakkavad mõtlema, seda rohkem hakkavad inimesed toitu ära viskama ja seda raiskama, mis teeb toidukaotuse veel suuremaks. Näiteks näeme tarbitoitutargalt.ee veebilehelt, just kui palju Eesti inimesed toitu ära viskavad. Veebilehel on kirjas, et iga Eesti inimene viskab ära aastas keskmiselt 61 kg toidujäätmeid, millest 42% mis on ka 26 kg moodustab toidukadu. See kõik on meie enda raisatud raha kui ka maa, vee ja energia ressursid mis on kõik raisku läinud. Kõike seda saaks ära hoida kui näiteks saaks tarbimisharjumuste teema koolitunditesse sisse tuua. Siis kuuleksid rohkem inimesi sellise probleemi kohta ning need inimesed hakkaksid sellele rohkem mõtlema.\nMida rohkem inimesed raiskavad toitu ja ei kasuta seda targalt ära, seda suuremaks ja probleemsemaks see teema muutub. Lõpuks hakkab meie toit otsa saama, kuna meil ei ole piisavalt ressurse, et seda teha. Lõpuks hakkavame, meie kui inimesed tundma iseenda vigade maitset.');
INSERT INTO core.text_property(text_id, property_name, property_value)
