INSERT INTO core.text(id, content)
VALUES ('dd3a355d-ecdf-4abf-968f-3f024762b2fc',
        'Inimestel on läbi aegade koguaeg tarbinud ja selle tõttu on läinud paljud kaubad raisku. Toodete, teenuste ja kaupade tarbimine on inimesele väga vajalik. Mõni suudab neid kaupasid säästlikult ära kasutada, kuid paljud pole nii hoolikad. Paljud kulutused tulevadki just toidu raiskamisest ja ebasobilike riiete ostmisest teadmata, millist mõju see keskkonnale avaldab.\nToidu raiskamine toob kaasa suuri keskkonna ja isiklikke probleeme, mida inimesed tavaliselt tähele ei pane. Enamusel on see mõte, et tema raisatud toit ei muuda midagi, kuid ei tea, et tema raisatud toit kaasneb tohtu ressussride raiskamisega. Paljud arvavad, et toidu raiskamine aegamisi ei too mingit probleemi nii iseendale, loodusele ja ümbruskonnale. Selle suhtumisega tulebki probleeme. Võin tuua esile selle, kuidas minu sõbra perekonnal läheb koguaeg toitu raisku ja selle tõttu läheb neil see kuus maksma umbkaudu 25 eurot, mis ei lähe mitte millegi peale. Samuti räägib ka artikkel „Toidukaost“ seda, et „Kodumajapidamises tekib iga Eesti inimese kohta aastas 61kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26kg.“ Sellega saab öelda, et toidu raiskamine läheb nii iseendale kui ka loodusele lõpuks maksma. \nNooremat põlvkonda peaks õpetama, et nad ei raiskaks raha ja aega, ajades taga uusimaid moetrende ja riideid.  Kui noortele juba väiksest peale selgeks teha, et palju riideosi läheb raisku ja palju kõik need kokku maksavad, oleks tulevikus need samad noored teadlikumad sellest, mida nad ostavad. Moedisainer Eva Hanson on rääkinud, et „Ma arvan, et peaks hakkama noortele tegema ekskursioone taaskasutuspoodide lattu, et näidata milline raiskamine tegelikult toimub.“  Selle põhjal võib öelda, et vanemad võiksid noortematele selgeks teha, kuidas mõistlikult käituda riideesemetega. \nKõikide nende punktide põhjal võib kindalt öelda, et inimesed peavad muutma nii oma toitumis ja riiete tarbimis harjumusi. Nii toidu ja riiete raiskamisega kaasnevad suured kulud, nii endale kui ka loodusele. Samuti peaks kaasnema nooremat põlvkonda kasulikule tarbimisele, et tulevikus oleks vähem kaupade raisku ja loodus reostust.');
