INSERT INTO core.text(id, content)
VALUES ('f695fceb-ce87-4d00-879c-ec5aa7fbe05a',
        'Inimestele meeldib palju tarbida aga samas ka palju raisata ja see raiskamise osa on päris halb, sest selle käigus kaob raha ja muud ressurssid nagu näiteks maa, vesi, tööjõud. Energia ei kao, vaid muundub mingisuguseks muuks energiaks, mida saab hiljem kuskil mujal kasutada.\nTänapäevased tarbimisharjumused on väga mitmekesised. Mingi osa inimestest tarbib hästi minimaalselt, teine osa aga liialt palju või ei tarbigi üldse teatuid tooteid. Raiskamisega on samamoodi, mõni raiskab väga minimaalselt, teine aga tohutult palju või ei raiskagi üldse.Tarbitoitutargalt.ee leheküljel on välja toodud, et inimistele tundub et toitu on veel ja see ei saa otsa ning et on inimesi kes raiskavad toitu ja saavad seda endale lubada, samas ka need kes hästi väikse koguse toitu viskavad minema arvavad et nad ei mõjuta sellega midagi. Eestis tekib iga aasta kodumajapidamises inimese kohta keskmiselt 61kg toidujäätmeid ja 42% ehk 26kg on sellest toidukadu. Toidukadu on raisatud toiduaine, mis on mingisuguse põhjuse tõttu raisatud. Olgu selleks kas riknenud, kasutamistähtaja ületanud või lihtsalt järele jäänud toit mida pole süües suudetud ära lõpetada ja visatakse toidujäätmetena ära. Toidu tootmine on ka keskkonnale pisut kahjulik, kuna kasutatakse erinevaid väetisi ja kemikaale et saagikus oleks suur ning see tekitab ka keskkonnakoormusi.\nToidumaailm pole ainus valdkond kus raisatakse asju. Vikerhommiku saates käis külas Eve Hanson, kes rääkis riiete raiskamisest ning, et inimesed eelistavad kvantiteedi asemel kvaliteeti ehk inimene ei telliks kuskil hiina veebipoest endale riideid juba põhimõtte pärast sealt asju ja ei läheks kaasa sooduskampaaniatega. Tema arvates tuleks eelistada kodumaiseid või Eesti lähedal toodetud asju ja et pigem vähe kui rohkem. Taaskasutuspoodidesse koguneb iga nädalaselt tohutult palju riideid ning need seisavad laos ja koguvad tolmu. Hansoni arvates võiks noortele teha ekskursiooni taaskasutuspoodi, kuna see oleks tema arvates õpetlik sest see näitaks noortele, missugune raiskamine tegelikult toimub. Sealt võib korralikke riideid ka leida aga enamus riided on naftast tehtud ehk nö „kiirmoe“ riided ja need on pärit Hiina kaubamajadest.\nTänapäevased tarbimisharjumused on päris mitmekesised, kuna toimub palju tarbimist ja raiskamist ning sellega raisatakse ka raha ja tööjõudu ning ressurssi. Eesti majapidamisest tekib keskmiselt inimese kohta 61kg toidujäätmeid ning sellest 42% ehk 26kg on toidukadu. Eve Hansoni meelest tuleks eelistada kodumaiseid ja meile lähedal toodetuid asju ning pigem vähe kui rohkem. Noored võiks taaskasutuspoodi ekskursioonile minna et natukenegi aru saada riiete raiskamisest. Taaskasutuspoodides on hästi palju kiirmoe riideid, mis on naftast tehtud ja neid tuleb sinna juurde.');
