INSERT INTO core.text(id, content)
VALUES ('d663a7ac-8b21-4e6a-88bc-8ea19dd931a1',
        'Selles kirjandis arutan selle üle, kuidas inimesed saaksid keskkonda toidujäänuste ja riiete ära viskamisega korras hoida. Inimestele meeldib osta asju rohkem kui neil tegelikult neid asju vaja on.\n     Kõige vajalikum asi meie elus on toit, seda läheb igal inimesel elamiseks vaja. Mõned aga ostavad endale koju rohkem toitu kui nad jõuavad seda tarbida ning seetõttu tekib palju toidujäätmeid. Kõigil on kombeks üleliigne toit ära visata, kuid seda toidujääki saab paljudes teistes kohtades ära kasutada. Perekonnad kellel on koduloomad, nemad saavad enda toidujäägid anda loomadele, kui loomi pole saavad viia varjupaikadesse. Kõige mõtekam on osta nädalatoit ja nimekirja alusel, sest siis ei lähe midagi raisku ja jääke ei jää.\n     Inimesed ei saa ringi käia ilma riieteta, seega on ka riiete ära viskamine ja taaskasutuspoodidesse viimine suur probleem. Iganädal saabuvad hunnikud erinevatesse poodidesse ja riided jäävad poes lihtsalt seisma, sest neid on nii palju. Kasulik nii ühiskonna kui ka iseenda jaoks oleks riided ümber teha nii, et endale selga sobiks. Paljudel perekondadel pole võimalust endale riideid osta, inimesed, kes viivad poodidesse riideid võiksid hädasolijatele need tasuta ära anda. Mitte kasutuses olevaid riideid saab pakkuda ka lastekodudele, sest seal pole lastel selliseid võimalusi et, kõike endale lubada.\n    Nendele probleemidele on palju lahendusi, toit ei pea alati prügikastides käima ning riided ei pea koguaeg poodidesse ja prügikasti minema. Kõike saab otstarbekalt ära kasutada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('d663a7ac-8b21-4e6a-88bc-8ea19dd931a1', 'title', 'Toidu ja riiete taaskasutamine');
