INSERT INTO core.text(id, content)
VALUES ('9ddf00df-9869-47de-ad0c-4d5784d6912f',
        'Inimestel on väga halvad tarbimisharjumused, inimesed ostavad endale igasuguseid asju, näiteks riideid. Nad kannavad neid riideid kuni paar korda, ja seejärel jätavad need riided kappi lihtsalt vedelema.\nPraegune eesmärk on inimeste tarbimisharjumusi muuta. Neid harjumusi saab muuta nii, et enne ostmist sa mõtled, et kas sul on seda asja ikka nii väga vaja, ja  kas sa kannad neid riideid nii kaua kui võimalik. Praegu inimesed kahjuks seda kõike läbi ei mõtle, sellest see probleem tulenebki. Inimesed võikisd osta rohkem meie lähedalt ümbrusest asju, kui tellida mingist mõttetust Hiina poest.\nHiina poodidest tellimine on igatpidi halvem. Hiinast tellides nad koguvad veel ka infot inimeste isiklike andmete kohta. Nende toodete transportimine Hiinast siia on juba päris kulukas ja reostav. Alati ei saa ka kindel olla, et kas sa saad just selle toote, mida sa tellisid, kas nad saadavad selle õigesse kohta, ja kas sa selle üldse saad.Kui kaup Hiinast jõuab sulle kohale, ei pruugi see ka tööle hakata. Seejärel inimesed võivad selle toote kuskile vedelema  jätta. Kui sa seda toodet üldse kätte ei saa, siis võivad tekkida igasugused probleemid ja muud arusaamatused.\nEnne asjade ostmist tuleb kõik sügavalt läbi mõelda. Igasuguseid tooteid on palju kindlam osta lähedamalt, kui  näiteks Hiinast. Kohalik on turvalisem.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('9ddf00df-9869-47de-ad0c-4d5784d6912f', 'title', 'Inimeste tarbimisharjumused');
