INSERT INTO core.text(id, content)
VALUES ('49d85078-141d-4187-8cbf-b0e20ddc4f09',
        'Toit on söök, mida inimesed tarbivad, sest see annab meile energiat, et saaks oma päevaga edasi minna. Toite on väga palju erinevaid. Inimesed sageli ei tea kuidas õigesti toituda. Keskendun selles kirjandis toidu raiskamisele ja soetamisele. Kui palju peaksid inimesed toitu tarbima ja kuidas?\nInimesed ostavad liiga palju toitu, mis hiljem lihtsalt raisku läheb. Isegi kui kogused on väiksed, läheb söök raisku. Tihiti poes käies näen, kuidas inimesed ostavad suurtes kogustes tooteid, mida nad ära ei jõua tarbida. Arvan, et inimesed võiksid rohkem mõelda oma ostude üle, mida on vaja, mida mitte, sest see mõjutab ka maad. \nMoedisainer Eve Hanson ütles, et me peaksime eelistama kodumaiseid oma lähedal toodetud asju, mitte tellima kaupa Hiinas veebipoodidest. Sellega ma nõustun, sest oma kodumaal tehtud asjad on esiteks värskemad ja teiseks kvaliteetsemad. Nad ei ole rännanud mitu sada kilomeetrit ja neile pole pandud kemikaale peale. Näiteks olen näinud, et välismaa õunadel on vahest selline kiht peal, mida meie kodumaistel õunadel ei ole.\nKokkuvõtteks on toit oluline asi eluks. Inimesed võiksid sellest rohkem lugu pidada ning vaadata kust nad toitu ostavad ning palju seda tarbivad. Kindlasti tarbida rohkem kodumaist toitu, kui välismaist. Toidu raiskamist ei saa kiiresti lõpetada aga seda saab vähendada.');
