INSERT INTO core.text(id, content)
VALUES ('18bf5242-565c-48e7-9eab-34ccabe25591',
        'Selles kirjandis räägin probleemist, mis mõjutab kogu maailma. Raiskamine toimub igal pool, miks, kuidas, kuipalju. Mida saame teha selleks, et see ära hoida, mida peaksime rohkem või vähem tootma, miks me raiskame ja kuidas see meie elukeskkonda mõjutab?\nSelleks, et raiskamist ära hoida peaks rohkem kodust eeltööd tegema selleks, et me ostaks toitu piisavas koguse ja selle ära sööks ning selle käigus ka raha säästame. Kõige parem viis selle lahenduseks oleks päävikut pidata. Kuigi see kõik võtab aega hoiab see meie planeeti, see väendaks meie väätise kasutust ning laseks muldatel puhata. „Eelistada võiks kodumaiseid oma lähedalt toodetud asju ning pigem vähem kui rohkem.“ Näiteks mina kasvatan oma suguvõsale kartulit ja vanaema hoolitseb köögiviljade eest.\nPoes käies peaks mõtlema, kas meil on vaja selises koguses asju või mitte ja pigem koguda külmkappi asju, mis kestavad, kuiv aineid on ka hea osta, sest need kestavad väga pikka aega. Selleks, et vähentada heitgaaside kogust võiks e-kaublust kasutada, sest üks kaubik reostab vähem, kui kümme autot ning paksuks minemisest saab hoiduda pärast söögiliste jalutus käikudega. Juhul kui pood asub 500 meetri radiuses võiks sinna jalutada.\nKokku võtteks soovin öelda, et käi ja liigu, sest siis tuleb nälg ja kontrolli olemas olevate toodete kuupäeva ning siis valmista endale hommiku-, jõuna- või õhtusöök.');
