INSERT INTO core.text(id, content)
VALUES ('89e06cc8-c840-4910-a7e3-c2ac631d28c3',
        'Inimeste toitumis- ja tarbimisharjumused on üpriski erinevad. Mõned söövad kana koos konidiga ära ja teised viskavad pool söödud banaani ära, aga miks me üldse raiskame toitu.\nPaljud inimesed lihtsalt viskavad hunnikutes toitu ära ja ei mõtle sellele, et seda allesjäänud toitu saaks kasutada ka näiteks järgmises toidukorras. Selle pealt säästaks palju raha. Seda allesjäänud või kasutustähtaja ületanud toidust teha koduloomadele toitu näiteks kassile või koerale. Minu peres me toitu ära otseselt ei viska, aga kui juba ikka hallitab siis läheb viskamisele. Me kasutame ka kasutustähtajast üle läinud toitu, et teha lemmikloomadele süüa või halvaks läinud piimast teeme pannkooke. Meil pole mõtet toitu ära visata, kui sellele kasutust on. Kui ostame suuremas koguses toitu, siis enamasti läheb osa sellest sügavkülmikusse järgmist kasutust ootama.\nKüll aga pered, kellel koduloomi ei ole või pole selliseid loomi, kes allesjäänud toitu sööksid soovitaksin neil kasutada seda ülejäänud toitu oma järgmises toidukorras. Allesjäänud makaroonid, liha, juurviljad jne lisada omletti või mõnda muusse toitu. Halvaks läinud puu- ja juurvilju saaks mitte ära visata vaid panna komposti ja sellest tulnud mulda kasutada pottides, kuhu istutad mõne tomati- või kurgitaime.\nKokkuvõtteks ütlen, et toidu raiskamine on mõtetu. Sellele on nii palju erinevaid kasutusvõimalusi ja kui ei jaksa nii palju toitu süüa, kui tegid, siis tee järgmine kord vähem.');
