INSERT INTO core.text(id, content)
VALUES ('02643d71-cc41-4983-ba10-0d1941a45cc4',
        'Toidu tarbimine ja raiskamine on juba meie maailmas päris tippu hakand tõusma. See on juba natuke nagu sõltuvus, et kui isegi kõht pole tühi inimene ikka läheb ja vaatab kas on midagi võimlik hambaalla saada. Kas oleks kuidagi võimalik sellist asja hakata vähendama.\nSellist asja saakas päris hästi hakata vähendama aga jälle asi on meis iseendas inimestes, et ka me jälle oleme selliseasjaga nõus või mitte. Inimesel kellel on oma kodupidamine tekib umbes 61kg toidujäätmeid millest siis toidukadu on 42% ehk 26kg. Sellepärast ongi niisuur kadu, et kas inimene ei jaksa süüa niipalju ära kui ta endale tõstab ja siis lihtsalt viskabgi ära. See jälle mõjutab ka rahalisi ressurrse veel siis maad, vett, energiat ja tööjõudu. Ongi kui seda hakata vähendama ega see ei lange kohe üleöö see võtab veel tohutult aega ja viitsimist. Sellepärast seda vaikselt proovitaksegi teha, sest teatakse, et läheb päris kaua aega.\nSama on ka kodumasinatega. Tellitakse midagi hiinast ja pärast ei töötagi ja visataksegi lihtsalt minema. Inimesed on nii laisad ka, et ei jaksa isegi neid pärast taaskasutuspoodidesse viia. Isegi selline väike asi aitab juba vägapalju.\nKõkkuvõtteks ütlen siis niipalju, et kui inimesed on ise nõus selliseid asju tegema siis ka nad seda teevad.Hakkavad toidukadu vähendama. Hakkavad vaatama, et nad liigapalju vanu kodumasinaid lihtsalt ära ei viska ja viivad ilust taaskasutuspoodidesse.');
