INSERT INTO core.text(id, content)
VALUES ('082af7fb-48aa-4157-b7af-dd950b8bdca0',
        'Üheks praeguseks probleemiks maailmas on see, et raisatakse palju toitu ja ka riideid. See kõik mõjub loodusele reostavalt ja suurendab meie ökoloogilist jalajälge. Inimesed ei mõista mida tegelikult nad teevad. Nad arvavad, et see on normaalne, kuid tegelt see nii ei ole.\nInimesed käivad poes, ostavad kaupa, kuid mõnikord nad ei pane tähele toiduainete kuupäevasid. See tähendab, et toit võib minna kiiresti pahaks ja nagu ikka tuleb see toit siis kuskile visata. Praeguseks peaks igal majapidamisel olema kompostikast kuhu nad saavad panna oma rikknenud toiudud või nende ülejäägid. Poodides on ka veel parim enne möödas kaubad mis on tava kaupadest odavamad, sest need hakkavad pahaks minema. Kuid mõnikord leiab ka seal täiesti kõlbavaid kaupu.\nRiided mida me enam ei kanna või on väikseks jäänud tuleks viia taaskasutuskeskusesse, et nendest saaks teha uusi asju. Osad inimsed kas viskavad need ära või põletavad. Mis mõjub loodusele reostavalt. Üheks uueks asjaks on Hiinast tellimine. Sealt saab asju tellida väga odavalt, kuid nende kvaliteet ei pruugi olla hea. Vahest juhtub ka nii, et kas need tulevad katkisena või lähevad kiiresti katki. Muidugi odavalt asju saada on hea aga kui neid vaja ei lähe enam siis viskame ka need ära. Millegi pärast me kipume tellima liiga palju asju, mida meil tegelikult vaja ei ole.\nLõpetuseks kuidas siis seda probleemi lahendada. Iga inimene peaks hakkama vaatama kuidas tema saab muuta ennast. See pole kindlasti lihtne muutus, sest see on suht suur elu muudatus. Peaksimee mõtlema kuhu me oma toidud või asjad viime kui meil neid vaja enam ei ole. Püüame olle ikkagi loodussõbralikud.');
INSERT INTO core.text_property(text_id, property_name, property_value)
