INSERT INTO core.text(id, content)
VALUES ('ed9c88cf-0a3d-4c82-beb5-32773075a8fa',
        'Selles kirjandis hakkan ma rääkima inimeste ükskõiksuset ja laiskusest.Tänapäeval inimesed ei pööra väga tähelepanu kui palju nad päriselt toitu tarbivad. Sageli olen mina ka sattunud selle ohvriks.\nToiduraiskamine on suur ja lai teema, mille üle saab arutleda. Toit on vajalik igaühele, mis on tähtis ja tuleb kokku hoida . Mina olen ka palju toitu ära raisanud nagu näiteks ei arvesta kui palju ma restoranis söön, kas tellin suure või väikse portsu. Tellin suure eine ja ei jaksa ära süüa. Selle mure lahendamiseks oleksin võinud ma võtta väiksema toidu portsu ja kõik ära süüa.\nToitu tuleb kokku hoida, sest mingi asi siin maailmas ei kesta igavesti. Toit on vajalik meile ja oluline on see, et see on kvaliteetne. Kui toidu kraam on odav see võib meile halvasti mõjuda, nagu toidu sees on mittevajalikud säilitusaineid. Eve Hanson tõi väja: „Ei telliks Hiina veebipoodidest juba põhimõtte pärast asju, ei läheks kaasa suuduskampaaniatega.“ Kvaliteetsed asjad on kopsaka raha summaga ja võib see meile kasuks olla, see paneb meid mõtlema säästma ja me ei osta seda nii palju ning hoiame toidu kokku.\nKokkuvõteks tahan ma öelda seda, et kui sa käid restoranis, siis mõtle hoolikalt, kas sa sööd kõik ära ning tähtis on toidu kvaliteet, et ei oleks odav kraam vaid tervislik ja kasulik sulle.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('ed9c88cf-0a3d-4c82-beb5-32773075a8fa', 'title', 'Kuidas mulle mõjub inimeste ükskõiksus?');
