INSERT INTO core.text(id, content)
VALUES ('8de256ee-ff78-4988-859b-55789c4703c4',
        'Maailmas läheb iga aasta raisku rohkelt toitu, rõivaid ja muid tarbeesemeid. Mina arvan, et selline asi ei ole mitte mingit moodi õige. Kuidas seda vähendada ja kas selle jaoks on vaja teha suuri muutusi?\nIgapäevaselt viskavad inimesed ära halvaks läinud toitu või riideid, kuhu on tekkinud väikene auk. Kui nüüd selle peale mõelda, siis aastas viskab keskmine inimene ära asju suurtes kogustes. Me isegi ei mõtle, et mida sarnane raiskamine toob kaasa maailmale. Aafrikas peavad paljud lapsed käima ringi katkiste riietega ning neil ei ole võimalik süüa kolm korda päevas. Kui inimkond oleks haritum kõigi tarbimisharjumuste koha pealt, siis arvan ei toimuks liigset kulutamist.\nRaiskamises ei ole ainult süüdi inimesed ise vaid ka ettevõtted, tehased ja ettevõtjad. Mina arvan, et liigset raiskamist oleks võimalik ära hoida õigete koguste valmistamisega, ühesõnaga, et ei toimuks ületootmist. Paljud firmad teevad enda tooteid rohkem, et vältida puudujääki. Vahest mõtlevad aga nemadki üle ja tooteid jääb liiga palju üle. Üle jäänud tooted müüakse tavaliselt soodsamalt maha ja see justkui tõmbab inimesi ostma. \nKokkuvõtteks arvan, et haridusasutused peaksid pisut rohkem õpetama inimesi hoolima meie keskkonnast ja teistest rahvastest. Tavaliselt ongi probleemide aluseks teadmatus, mis paneb inimesed käituma nii nagu nad käituvad. Tarbime teadlikult ning ärme lase kellegil teisel mõjutada enda tarbimisharjumusi.');
