INSERT INTO core.text(id, content)
VALUES ('03edcd70-d250-42e3-be17-5f14c119244d',
        'Mis on inimeste tarbimisharjumused, võivad inimesed küsida? Tarbimisharjumused on harjumused mis inimesed on endale tekitanud, kus me raiskame toitu meeletul kogusel iga aasta. Inimene tavaliselt raiskab aastas 61 kg toitu, kas siis toiduülejäänustena või talle lihtsalt ei meeldi see toit mis talle on ette antud.\nInimeste tarbimisharjumusi me peame muutma, sest need jäänused mida me tekidame on väga halvad meie maale ja se on ka väga inetu inimestele kes ei saa süüa sooja toitu iga päeavaselt. Näiteks oletame, et me viskame ära ühe plaadi toitu, meie ei mõtle selle peale, et kas me nüüd saame tänasepäeva jooksul veel süüa, sest suurem osa ajast on meil külmkapp täiesti täis.\nRääkides söögi saamisest on ka inimesed Aafrikas, kes ei saa toitu iga päevaselt ja ka tänu sellele, et neil ei ole kusgilt toitu saada on Aafrikas väga suured nälga suremis probleemid. Ning on ka inimesed kellest me nii palju ei räägi, kodutud kes peavad kerjama raha ja toidu jaoks, aga meil on ka maailmas inimesi kes aitavad selle vastu, et inimesed ei sureks nälga ja ei peaks lootma prügi peale, et ellu jääda. Inimesed on loonud kohtasi kus kodutud saavad käia süüija võtmas. Ning suured firmad teevad kampaanijaid, et aidata inimesi Aafrikas,viies neile puhast vett ja süüa.\nKokkuvõtteks inimesed ei pruugi aru saada palju nemad tegelt toitu raiskavad ja kui palju se aitaks mõnda inimest kes ei saa iga päev sooja toitu süüa.');
