INSERT INTO core.text(id, content)
VALUES ('af2456da-c584-49d4-99be-753bd73c99c8',
        'Inimestel on läbi aegade tekkinud palju erinevad tarbimisharjumusi. Kõigil inimestel on vaja riideid ja toitu, aga probleem tekib siis, kui neid hakatakse üle tootma. Selles kirjandis proovin leida lahendust asjade meeletule raiskamisele.\nViimase sajandi jooksul on tarbimine muutunud tohutuks, sest inimeste populatsioon on tänu meditsiini ja tehnoloogia arengule niivõrd tõusnud. Kõikjal maailmas on suured vabrikud, mis toodavad näiteks rõivaid, aga kui neid toodetakse liiga palju, siis jäetakse need ladudesse tolmu koguma või visatakse üldse ära. Need rõivad, mis ei satu ladudesse või ei visata ära, ostetakse ära, kuid ka neil on võimalus lihtsalt kappi tolmu koguma jääda või ruumi raiskamise eest minema visatud saada. Sama kehtib ka toiduga, sest enamus toitu, mis saab kokku ostetud, läheb riknema ja visatakse lihtsalt ära. Näiteks tekib aastas keskmiselt iga Eesti inimese kohta 61 kg toidujäätmeid, millest ligi 42% on raisatud toit. Selline tarbimine on suur raha ja ressursside kulu. Selleks, et sellist toidukadu vältida, ei tohi nii palju toitu kokku osta, sest me ei jõua lihtsalt seda kõike ära süüa ja see lähebki raisku. Samamoodi ei tohi kokku osta nii palju riideid, sest neid kõiki ei jõuta kanda ja need võtavad ruumi.\nKokkuvõtteks võib öelda, et toidu ja riiete raiskamine on vale ja seda tuleks vältida, sest see on raha ja ressursside kulu. Selle vältimiseks tuleb kokku osta vähem toitu ja riideid ning vältida emotsionaalset ostlemist.');
INSERT INTO core.text_property(text_id, property_name, property_value)
