INSERT INTO core.text(id, content)
VALUES ('692e4095-863b-4edd-a6b9-9b6d0b6678e9',
        'Inimesed tarbivad igapäevaselt erinevaid tooteid. Näiteks toitu kaupu, hügeenitarbeid, elu lihtsustavaid masinaid ja muid igapäeva eluks vajalikke tooteid. Tooteid aga toodetakse ja tarbitakse ülemäära palju. Mida võib ületootmist soodustada ja kuidas seda peatada?\nInimesed ülemaailma tarbivad ja toodavad asju, mida pole vaja või lihtsalt mitte nii palju. Siin saab tuua näiteks firmad, kes toodavad kõik erineva brändi alt samu tooteid. Kui kõik need mitme tuhanded brändid toodavad peaaegu samasugust toodet tekib üle tootmine, ning neid ei suudeta ära tarbida. Tooraine läheb raisku, see omakorda tekitab ka loodusele kahju. \nSuur loomade tapmine, metsade maha raiumine, lapstööjõu kasutamine ja suurte tehaste tossamine toimub igapäev. Kõik selleks, et tooteid ei ostetaks. Mina arvan, et peaksime hakkama keelustama uute firmade ja brändide loomist. Või peatama suurte tööstuste tegevuse ja jääma kohalike väikefirmade juurde. Kuna oleme siiski juba nii kaugele jõudnud, et ei ole võimalik seda teha, siis inimesena saaks ise vähendada oma looduslikku jalajälge. Kasutada loodusliku ja kohaliku toorainega tooteid ja osta neid vajalikus koguses.\nMitukümmend aastat on ületarbmine ja- tootmine olnud ülemaailmseks probleemiks. Seda kasvavat probleemi pole tõsiselt võetud ja on tagaplaanile jäänud. Proobleemi lahendajateks saame olla meie ise. Ostame kohalikke tooteid, sorteerime prügi ning kasutame meile tehtud tooteid vastutustundlkult.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('692e4095-863b-4edd-a6b9-9b6d0b6678e9', 'title', 'Toodame ja tarbime kohalikult');
INSERT INTO core.text_property(text_id, property_name, property_value)
