INSERT INTO core.text(id, content)
VALUES ('2fedc1ff-7c3f-4c86-96dc-665f5a772641',
        'Riiete ja toidu raiskamine on üks maailma suurimaid ja aktuaalsemaid probleeme. Kas meil on varsti enam piisavalt ressursse, et toota uusi riideid ja ka teisi asju?\nInimesed viskavad tohutudes kogustes toitu ära. See on väga suur probleem, sest toiduainete tootmiseks kasutatakse väga palju ressursse. Näiteks vett, tööjõudu ja maad. Inimesed peaksid rohkem hindama toitu. Igal inimesel pole koguaeg toitu laual. Väga paljud inimesed peavad nälgima, aga inimesed, kes ei hinda toitu nii palju lihtsalt raiskavad. Mina arvan, et inimesed ostavad ka liiga palju välismaist toitu. Selle kvaliteet ei pruugi olla nii hea, kui kodumaine. Inimesed peaksid ostma rohkem kodumaist toitu ja sellega toetama oma riigi majandust.\nPaljud inimesed ostavad koguaeg uusi riideid endale, aga vahepeal tasuks mõelda ka taaskasutamise peale. Näiteks enne, kui lähed poodi uusi riideid ostma võiksid inimesed vaadata kõigepeal uuskasutuskeskustesse. Võibolla on jäänud inimestele tunne, et see on täiesti mõttetu ja ainult vaeste inimeste koht. Kuid tegelikult võib sealt leida väga head ja kasulikku kaupa, palju parema hinna ja kvaliteedi suhtega, kui poes. Inimesed peaksid hakkama ka vältima täielikult emotsioonioste. Emotsiooni pealt ostetud tooted võivad tunduda algselt väga head ja kasulikud, kuida hiljem jäävad lihtsalt kappi seima. Ja see on väga suur raiskamine.\nKokkuvõtteks iga inimene peaks vähendama toodete raiskamist. Me peaksime olema rohkem empaatilisemad teiste inimeste suhtes, kelle majanduslik olukord ei ole nii hea. Tooteid on vaja rohkem hinnata. Tuleks raisata vähem tooteid ja mõelda ressurssidele, mida on kasutatud toodete valmistamisel.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('2fedc1ff-7c3f-4c86-96dc-665f5a772641', 'title', 'Inimesed raiskavad liiga palju toitu ja riideid');
INSERT INTO core.text_property(text_id, property_name, property_value)
