INSERT INTO core.text(id, content)
VALUES ('5fa2c7b2-89dd-487b-89f4-b60bad8976bc',
        'Mina arutlen kirjandit, mis on toit, kuidas me hakkame saame ning, mida edasi teha. Probleemiks on see, et inimesed ei oska hoida raha. See tähendab seda, et ostavad kõiki asju kokku ja pärast lihtsalt viskvad minema, samalajal raiskame ka muid ressursse.\n        Kõige vajalikum on meile toit, me peame sööma igapäev ning ka jälgima ja, kui palju kokku ostame. Võiks toidu osas, jäätmeid vähendada ja seda saab teha ühel põhjusel, hakkad normaalses koguses toitu ostma. Inimesed võiksid ka mõelda looduse peale. Looduses on loomad, kes võivad midagi sisse süüa toitujäätmetest ja siis surevad see on ka paha. Riided, mida on inimesed kasutanud oma seljas ja on saatnud taaskasutuspoodidesse see on ka vastik, kuna kunagi ei tea, missugune inimene on kasutanud seda seljas kandnud.\n             Tekib toidu tootmisel tõsine keskkonnakoormus, mis põhjustab halba, toodab meile siin saagikuse tõstmiseks kasutatakse väetisi erinevaid kemikaale. Riided võivad ilusad välja näha, aga iial ei tea, millega koos on võib vabalt naftaga olla või sügelised. Me kunagi ei tea, kas on need rõivad maast korjatud. Näiteks võin saada, mingisuguse haiguse, mida ma enam ei saa ravida ja toiduga on sama teema ka loomadega, loomad võivad ka mingi toidu pärast haigeks jääda ja levitavad seda niimoodi edasi oma kehalt, kuna inimene ei tea kas on haige või ei.\n               Loodan, et inimesed hakkvad loogiliselt mõtlema peaga et ei reostaks ning ei ostaks kuskilt poest suvalisi riideid, kuna nad ei tea kus pärit on.');
INSERT INTO core.text_property(text_id, property_name, property_value)
