INSERT INTO core.text(id, content)
VALUES ('67aa8095-e0f3-46f9-ac28-42714ac78a8d',
        'Inimeste tarbimisharjumused on erinevad, mis tekitab meie planeedile probleeme. Paljud ei pane tähele, kui palju neil asju üleliia on, mida nad tegelikult ei vaja. See viib selleni, et need üleliigsed asjad visatakse ära millega tegelikult tekitakse palju prügi. Kes on kohusetundlikumad viivad nad selle prügi ettenähtud kohta, kas siis olmejäätmejaama või riided taaskasutuspoodi.\nRiiete hunnikud, mis tekitavd taaskasutuspoodidesse võiks olla õpetlikud noorte arvates Eve Handonile kes oli intervjueeritav (eeter.eer.ee) raadios. Noortel on tänapäeval lihtsam riideid tellida internetist, sest siis ei pea kohale minema ja kõike selga proovima, kaup on ka palju soodsam. Miks osta poest kallima hinna eest kui saaks odavamalt ja rohkem? Tavaliselt tellitakse palju asju korraga, et ei peaks uuesti ootama kuni pakk kohale tuleb, mille pärarast ostekakse kokku ebavajalikke rõivaid.  Kuigi saadakse palju riideid korraga odavamast interneti poest, ei ole kvaliteet sama. Taaskasutuspoodides on näha, kui palju riideid sinna koguneb ja kaubamärki vaadates on näha, et paljud riided kuuluvad just suurtele Hiina poodidele. \nInimesed ostavad rohkem, kui tarbivad. Kõik pered on erinevad ja nende toitumine sammuti, aga vahest võib väike pere süüa palju rohkem, kui nendest suurem. Kindlasti on neid inimesi, kes ostavad kokku poes ettejuhtuvat kaupa, mis näeb hea välja või mida nad parasjagu tahavad süüa. Teised on need, kes lähevad poodi poenimekirjaga ja võib-olla võtavad midagi väikest juurde. Külmkapp saab mõlemal perel täis, aga üks neist viskab palju toitu ära, kuna see läks halvaks, sest ei mõeldud läbi, kas selle ma ikka söön ära, kui isu üle läheb. \nNäeme nüüd, et saaks alati paremini teha ja mõelda korra, kas sul seda ikka vaja on. Võib küll mõelda, et minu üks riie või üks banaan ei muuda midagi, aga ikkagi kui minna taaskasutuspoodi on seal paksult riideid, mis on kõik ära visatud inimeste poolt, kes mõtlesid samamoodi. Kõikide panus loeb ja mida nad endale ostavad, ning mis sellest saab.');
INSERT INTO core.text_property(text_id, property_name, property_value)
