INSERT INTO core.text(id, content)
VALUES ('86e00458-b9de-4972-be7d-b4a8c07a19af',
        '„Aga kust tuleb see, mida me tarbime?“ Kõik, mida me kasutame, tuleb Maalt endalt, sellelt samalt, kus me elame. Liigne looduslike varude raiskamine laastab meie planeeti kohtavalt ning just selle pärast tuleks jälgida, millele sa oma raha, ressursse kulutad.\nEriti palju raisatakse praegusel hetkel toitu, kuid just seda ei saa endale iga inimene lubada. On persoone, kes ei hinda seda, mis neile antud. Samal ajal kui mõni ei saa endale lubada isegi pätsi leiba, viskab teine ära aastas kilode viisi toitu, mis on söömiskõlblik. Tarbitoitutargalt on uurinud, et keskmiselt viskab eestlane ära 61 kg toidujäätmeid, sellest alla poole on toidukadu. \nTänapäevane kiirmood on kohutav. Uued trendid tulevad kiiremini peale, kui eelmised ära kaovad. Tellitakse odavat ning ebakvaliteetset kaupa Aasiast, sest see on käesoleval ajahetkel populaarne. Paari kuu pärast on need plastikust, naftast tooted juba prügikastis või taaskasutuspoe riideilaos. Eve Hanson arvab, et selle asemel tuleks osta midagi kvaliteetsemat ja käia poodlemas teiseringi kauplustes ning eelistada kodumaist kaupa.  \nToidu kasvatamiseks kasutatakse ka erinevaid kemikaale ja väetiseid. Need laostavad keskkonda, veel lisaks ressursside kasutamisele, väga palju. Selleks, et taimi kasvatada on vaja maad, vett ja energiat, kuid see kõik on piiratud. Veebilehelt tarbitoitutargalt.ee võib lugeda, et selline keskkonnakoormus on väga halb.\nÜhiskonnas raisatakse liigselt toitu, riideid ja ressursse. Õnneks on muutus võimalik.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('86e00458-b9de-4972-be7d-b4a8c07a19af', 'title', 'Suur raiskamine ühiskonnas');
