INSERT INTO core.text(id, content)
VALUES ('069e5722-9035-4543-80eb-e45094574e55',
        'Missugused on eestlaste tarbimisharjumused ja miks visatakse toitu ja riideid ära? Kuidas mõjutavad meie tarbimisharjumused keskkonda?\nEestlased teevad liiga palju toitu. Toitu visatakse ära siis, kui seda jääb üle või tähtaeg saabub. Eestlased toodavad liiga palju toitu ja ei jõua seda enam ära süüja, siis visatakse toit ära. Minu klassil toimus kokkandustund, kus me küpsetasime toitu, aga me tegime liiga palju ja osa oli vaja ära visata. Liiga palju süüja teha ei ole hea, sest kui ei jõua ära süüja peab toidu ära viskama. Toitu peaks tegema nii palju, et suudetakse ära süüja.\nLiialt palju toidu kasvatamine tekitab keskonna jaoks probleeme. Vilja kasvatamiseks kastutatakse palju väetisi ja kemikaale. Väetised ja kemikaalid kahjustavad keskonda palju. „tarbitoitutargalt.ee“ loeme, et toidu tootmine tekitab keskkonnale suure koormuse, sest vilja saamiseks kasutatakse kemikaale ja erinevaid väetisi. Toidu kasvatamise ajal peaks mõtlema keskkonna peale. Liialt palju kemikaale ja väetisi ei ole kasulik tarbida.\nKorralikke riideid visatakse ära. Eestlased viskavad riideid ära isegi siis, kui need on veel kasutamis kõlblikud. Enamasti ostetakse palju uusi riideid ja visatake vanad ära ilma mõtlemata. „Vikerhommikus“ räägib Eve Hanson, et iga nädal, kui ta käib taaskasutuspoes vabatahtlikuna töödates, näeb ta, et on ära visatud korralikke riideid. Riideid võiks enna viskamist ära kasutada. Liiga palju riideid ei ole mõtekas korraga osta.\nEestlased toodavad liiga palju ja ei jõua tooteid ära tarbida. Rõivaid ei tohiks liiga palju osta, sest siis ei jõuta kõike riideid kanda ja visatakse neid ära.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('069e5722-9035-4543-80eb-e45094574e55', 'title', 'Eestlaste tarbimisharjumused');
