INSERT INTO core.text(id, content)
VALUES ('d8472045-c109-481a-9b1b-4de4e36ed35b',
        'Inimeste tarbimisharjumused on erinevad, aga uute asjade ostmisel visatakse või antakse ära eelmised toodete, mida enam ei vajata. Praegu raisatakse erinevaid tooteid väga palju arvates, et see ei mõjuta meie ümber olevat ühiskonda.  Koguaeg ostetakse juurde tooteid mõtlemata, mis vanadest asjadest sai. Ühiskond raiskab praegu palju erinevaid tooteid.\nÜhiskond raiskab palju toitu. Kuna osad inimesed saavad toidu raiskamist endale lubada, siis nad arvavad, et see vähene toidu raiskamine ei tee midagi välismaailmale. Nad kulutavad järjest rohkem ja rohkem toitu mõtlemata, mis teevad inimseded, kes ei saa endale toitu osta. Toitu ära visates raiskavad inimsed ka raha, kuna pole toitu lõpuni tarvitanud. Tarbi toitu targalt artikis toidukaost on öeldud, et kodumajapidamises tekib iga Eesti inimsese kohta aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg. Inimsesd ostavad liiga palju toitu, mida nad ära tarvitada ei suuda ja hiljem viskavad selle lihtsalt ära arvates, et see ei mõjuta ühiskonda.\nInimesed ostavad endale mõtlematult riideid. Ühiskond ostab endale veebipoodidest väga palju riideid ja kui need kohale jõuavad, siis avastavad, et toodet ei ole nii mugav kanda, kui nad arvasid. Kuna inimesed ostlevad väga palju veebis, teadmata milline see toode välja näeb, siis annavad inimesed tihti oma asjad ära uuskasutuskeskustele.  Tänapäeva noored ostavad väga palju riideid hiina veebipoedest teadmata, et uuskasutus keskustes on riided juba üle kuhjutud. Inimesed ostavad palju riideid teadmata, kui palju riideid raisku läheb.\nInimesed raiskavad palju erinevaid tooteid oma tarbimisharjumuste tõttu. Eriti raiskab ühiskond toitu ja riideid teadmata, kui palju neid juba raisku läheb ja arvates, et asjade ära viskamine ei mõjuta ühiskonda.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('d8472045-c109-481a-9b1b-4de4e36ed35b', 'title', 'Ühiskonna tarbimisharjumused kujunevad raiskamiseks');
INSERT INTO core.text_property(text_id, property_name, property_value)
