INSERT INTO core.text(id, content)
VALUES ('2d4d237a-30c6-4757-aa95-a345416256c9',
        'Tänapäeva üheks kõige suuremaks keskkonnaprobleemiks on kui palju toitained, raha ja ressursse valede tarbimisharjumustega inimesed raiskavad.\nKui palju toitu läheb tegelikult raisku? Tarbitoitutargalt.ee andmete põhjal tekib aastas iga Eesti inimese kohta 26kg toidukadu ehk tarbimata toitu, mis on väga suur toitainete ja ressursside raiskamine. See kogus on ära visatud, sest inimesed kes saavad endale nii palju toitu lubada on harjunud teisiti toitu tarbima. Seda keskkonnaprobleemi ei saa isegi kahjuks kaotada, sest see on inimeste harjumustes kinni.\nKahjuks pole see ainuke keskkonnaprobleem millele peaks suuremat tähelepanu pöörama: riided. Riided on osa tervest ühiskonna elust – riided peab kandma, pestma ja hooldama. Kui osta õigest kvaliteedist ja materjalist riideid siis see ei tee nii maailmale kui ka inimesele endale kahju. Inimesed, kes on harjunud ostma enda riideid lähtudes rohkem sellele tekstile selle T-särgi peal kui õigest materjalist ja kvaliteedist on kuidagi ikka teinud maailmale ja iseendale kahju. Kuigi vanemad inimesed on suhteliselt juba vanast east ära harjunud heast kvaliteedist riideid ostma siis paljud tänapäeva noored on harjunud ostma rohkem halva kvaliteediga riideid kui hea kvaliteediga riideid. Kui tänapäeva noored näeksid millest need riided tegelikult tehtud on ja kui palju raisatakse neid taaskasutuskeskuste ladudes, siis ma arvan, et nad hakkaksid ostma mõttekamalt.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('2d4d237a-30c6-4757-aa95-a345416256c9', 'title', 'Inimeste tarbimisharjumuste kahju maailmale');
INSERT INTO core.text_property(text_id, property_name, property_value)
