INSERT INTO core.text(id, content)
VALUES ('315a99ce-2004-48d2-944d-fa5a7abea097',
        'Inimesed toodavad väga palju prügi, mis ei ole kasulik keskkonnale. Seetõttu on vaja hakata tarbimist jälgima ja piirama. Inimeste tarbimisharjumusi on vaja parandada.\nToidu raiskamine on suur probleem. Paljud arvavad, et toitu on palju. Söögi äraviskamisel kaob ressurss, mis aitab maailmas teistel elada ning töötada. Tööd on meil vaja sellepärast, et elada mugavalt ning arendada maailma. Seetõttu on vaja panna tähele, kuidas toitu mitte raisku lasta ja vaadata, kuidas tarbimist langetada. Sellega saab kaasa aidata kvaliteetse söögi ostmine. Arukalt tarbimine aitaks meie keskkonda kui ka ühiskonda. Artiklis „Toidukaost“ öeldakse, et toidukadu on keskkonnale kahjulik, sest see toob endaga kaasa rohkem väetiste ja kemikaalide kasutamist taimede peal, et tõsta saagivõimet.\nJäätmete vähendamiseks tuleb keskenduda kvaliteedile. Tänapäeval ostavad paljud inimesed endale asju Hiina poodidest, mis on odav, aga harva hea kvaliteediga. Korralikke riideid ja kraami on vaja osta sellepärast, kuna kõlbmatuid asju tekib aina rohkem ning sellega tekib rohkem prahti. Paljud odavad rõivad on tehtud keskkonnale ohtlikest materjalidest, mis rikuvad loodust peale äraviskamist. Seetõttu on vaja panna tähele, kust tulevad riided ja kas need on korralikust kangast. Taaskasutuspoodides on korras riideid, aga ka niisuguseid, mis on toodetud kehvadest ainetest Hiina ladudes, ütles moedisainer Eve Hanson.\nJäätmeid tekib väga palju ning inimesed peaksid jälgima oma harjumusi. Need harjumused tuleks välja vahetada rohkem keskkonnasäästlikumaks variandiks. Tarbimisharjumusi peab inimestel korrastama.');
