INSERT INTO core.text(id, content)
VALUES ('9ac61881-5aa2-484d-bafe-b85925721d76',
        'Inimesed tarbivad rohkem, kui neil vaja on. Me tarbime liiga palju.\nMeie rahvas raiskab toitu. Me ostame liiga palju toitu, mis tähendab, et me ei suuda seda kõike ära süüa. Selle tulemusena me raiskame oma ressursse. Eesti isiku kohta tekib aastas keskmiselt 61 kg toidujäätmeid. See on meeletu kogus, millest 26 kg on lihtsalt söömata jäänud toit (tarbitoitutargalt.ee).  Inimestena me peaks oma ressursse targalt kasutama ja seda mitte raiskama nagu me praegu seda teeme.\nErinevad isikud igal pool siin maailmas ostavad rohkem asju, kui neil tarvis on. Need asjad võivad olla igasugused masinad ja vidinad, mida inimene arvab, et tal vaja on. Ajaloos oli majanduslik buum, kus inimesed aina ostsid, mis lõppes sellega, et neid asju oli rohkem, kui oli vaja. Kindlasti paljud neist asjadest seisavad kuskil nüüd prügina ja kasutuskõlbmatuna, mis jällegi näitab, et siin planeedil elav rahvas tarbib rohkem, kui peaks.\nEnamus inimestest ostavad endale riideid, kuid paljud neist ka raiskavad neid. Nende raiskamine võib välja näha nii: ostetakse palju riideid ja siis mõne aja pärast lihtsalt visatakse minema ja ostetakse uued isegi siis, kui need riided, mis visati minema, olid heas korras. Eve Hanson rääkis, kuidas ta käib vabatahtlikuna taaskasutuspoodides abis ja peab iga nädal nägema meeletuid hunnikuid vanu riideid, mida keegi enam ei kasuta („Vikerhommik“). See jällegi viitab sellele, kuidas meie rahvale meeldib palju osta ja raisata.\nEnamus inimestest tarbib rohkem kui tegelikult vaja oleks. Me tarbime palju toitu, riideid ja erinevaid muid asju ning paljud meist teevad seda rohkem, kui peaks.');
