INSERT INTO core.text(id, content)
VALUES ('1ab9db18-99c9-44a6-9775-776fe894362d',
        'Inimesed ei mõtle tihtipeale piisavalt enne, kui nad midagi ostavad. Enne ostmist, peaks mõtlema kas on tõesti vaja seda, mis poest koju kaasa võtad.\nInimesed tarbivad liigselt. Tavaliselt ei mõelda selle peale, kui palju prügi kellelgi päevas tekib. Seda peaks aga hoopis tegema, et aru saada kas kõike, mille peale raha läheb on tõesti vaja. Toiduga on nii, tavaliselt jääb alati peale hommiku-, lõuna-, või õhtusööki üle midagi, mida ära süüa ei jäksa. Eestis tekib keskmiselt iga inimese kohta 61kg toidujäätmeid, mis on vägagi palju arvestades, et meie väikses riigis on ainult 1,3 miljonit elanikku. See liigtarbimine on koormuseks lisaks loodusele ka tabrija enda rahakotile, mis maksab selle kulu ära, aga ei teeni sellest midagi.\nLiigtarbimine kahjustab loodust. Kõik see, mis ostetakse läheb üks hetk tagasi loodusesse ühel või teisel viisil. Mõned asjad aga ei ühine loodusega sadu aastaid. Sellisteks asjadeks on palstmass ja muud tooted, mis ei lagune või on tehtud igasugusest keemiast. Suurenenud tarbimine tekitab rohkelt kasvuhoonegaase ja kasutab tihtipeale piiratuid maavarasi, mille kaevandamine on kahjulik loodusele. See kahju jõuab üks päev meile järele ja seda on parem ennetada.\nEnda ja looduse aitamiseks on paljusi viise ja tarbimise vähendamine on üks nendest. Sellepärast peavad inimsesed enda tarbimisharjumusi muutma.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('1ab9db18-99c9-44a6-9775-776fe894362d', 'title', 'Inimesed peavad enda tarbimisharjumusi muutma');
