INSERT INTO core.text(id, content)
VALUES ('8eeb3f07-3310-454a-97a8-8006f087275a',
        'Kuigi probleem algas juba töölisest revolutsioonist ja nafta kasutuse algusest siis on viimasel ajal eriti tulnud esile inimkonna saastamine ja selle tagajärjed. Kurvem veelgi on see, et palju sellest prügist jääb lihtsalt meie silma alt välja vedelema kas siis ookeanide sügavustesse või metsade soppidesse sambla alla, kus aeglaselt see praht siis kopitab läbi sajandite või satub mõne looma makku ja maksa.\nÜks esimesi probleeme on toidu raiskamine. Mis teeb toidu raiskamise probleemi irooniliseks veelgi on see, et on palju riike, kus vaesusest nälgitakse surnuks. Tarbitoitutargalt.ee veebilehel on välja toodud, et aastas võib keskmine Eesti inimene luua 61 kg toidujäätmeid, millest toidukadu on 26 kg ehk 42%. See 26 kg on toidud või toiduained, mis on mingil põhjusel ära visatud näiteks nagu tähtaja ületamine või siis pole jõutud ära süüa. Isegi kui selline toidu raiskamine otseselt saastamist ei tekita, kuna toit laguneb kiiresti looduses, siis selle kavatamine ja transportimine võib lisa kulusid ökosüsteemile lisada. \nSeoses naftaga on tekkinud ka suur probleem – plastmass. Plastmass on väga laialdaselt kasutatav materjal kuna see on väga elastne ning seda saab väga kirevalt ja rikkalikult värvida ning lisaks on ka odav. Plastmassist saab isegi luua varjatsioone nagu läbipaistev plastmass nagu on näha veepudelitel või veelgi elastsem plastmass nagu on esindatud kiirmoe riietel. Kõik see on küll väga kena ja tore, kuid plastmassil on ka tema Achilliuse kand milleks on selle kõdunemine. Plastmass kõduneb üle mitmete tuhandete aastate looduses ning lisaks sellele eritab see ka veel mikroplaste selle aja jooksul, mille efekte teadlased hirmuga uurivad ning on leidnud mikroplaste peaaeu kõigis esindatud loomaliikides, ka inimestes. Jällegi tuleb ostlejatel mõelda oma ostude üle ning pigem panna see väga odav kiirmoe rõivas tagasi nagisse.\nEelmistes lõikudes olen küll riielnud rohkem tarbijatega kui tootjatega, kuid leian, et sama palju süüdi on ületarbimises ka tootjad, kes reklaamivad oma tooteid nii manipuleerivalt kui seadusega lubatud. Ignoreerides kõiki neid tööliste inimõiguste rikkumise hetkel siis Temu, Hiina korporatsioon, on üks kõige populaarsemaid kiirmoe ning muu ebatarvilike vidinate tootjatest. Kuskil 2022. aasta paiku oli Temu reklaame võimatu eirata, sest Temu sponsoreeris ka suunamudijaid ning muid meelelahutusega seotud üritusi. Temu veeilehelt vaadates on näha, et müüdavad riided on kuidagi väga odavad. Need riided on kõik tehtud madala kvaliteediga plastmassist ning meelega kuluvad kiirest ära, et tarbja jätkuvalt ostaks nende tooteid.\nÜletarbimine ei ole just tuhandedte aastate vanune probleem, kuid eriti tänapäevasel ajal on toidu raiskamine ja plastmassi toodang tekitanud meie ökosüsteemile kohutavat kahju.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('8eeb3f07-3310-454a-97a8-8006f087275a', 'title', 'Ületarbimine');
INSERT INTO core.text_property(text_id, property_name, property_value)
