INSERT INTO core.text(id, content)
VALUES ('81a4cae3-2611-48ce-a9f6-bf1a93c51f1f',
        'Kõik me kasutame igapäevaelus midagi liialt. Inimesed raiskavad oma tarbimisharjumustega palju erinevaid ressursse. \nInimesed ostavad liiga palju riideid ning aksessuaare, mida neil pole vaja. Paljud neist ei mõtle sellele, kui palju materjale ja ressursse nad raiskavad. Keegi näeb kas mõnes reklaamis või poeaknal mõnda riideeset, mis talle meeldib, arvab ta, et talle on seda kohe vaja, kuigi tal on juba sarnane ese endal kodus olemas. Kellelgi ei ole vaja kümme paari päikseprille või kaheksa samasugust pluusi. Hea idee on riiete annetamine või taskasutamine.\nSotsiaalmeedia mõjutab inimesi ostma kalleid ja ebavajalikke asju. Tänapäeval on väga populaarne näidata ja soovitada igat asja internetis. Kui keegi näeb, et mõni suunamudija ostis endale kõige uuema ja kallima telefoni, mõtleb ta, et temal on ka seda kohe vaja, kuigi tema vanal telefonil ei olnud midagi viga.\nInimesed kasutavad liialt elektrit igapäevaselt. Paljud neist ei pane tähele, kui palju elektrit nad igapäevaelus kasutavad. Mõnel neist põleb kodus mõni lamp terve päeva, kuigi nad seda ei kasuta. On inimesi, kes jätavad oma nutiseadmeid mitmeks tunniks laadima, kuigi nende aku on juba täis. Iga inimene kasutab igapäev elektrit, aga nad võiksid jälgida palju nad seda kasutavad.\nIga inimene kasutab ja raiskab oma tarbimisharjumustega erinevaid ressursse  igapäevaelus. Paljud neist ei teagi, kui palju materjali nad tegelikult raiskavad.');
INSERT INTO core.text_property(text_id, property_name, property_value)
