INSERT INTO core.text(id, content)
VALUES ('69fd1ea2-56ab-400f-bcf9-233c92aecd3f',
        'Kõikidel inimestel terves maailmas on mingi sugune tarbimisharjumus ning mõned on loodusele ja planeedile kahjulikumad kui teised. Tarbimisharjumus on igal juhul halb ning iga inimene peaks vaeva nägema ,et seda vähendada.\nÜks tarbimisharjmus ,mis on väga kahjulik ning lihtne vältida on toidukadu.Toidu raiskamisega kulutavad inimased raha ,vett ja maad ei millegi jaoks. Toit jäeb külmkappi ,kus see unustatakse või välditakse ,sest seda ei taheta kindlal päeval. Eestis kulutab keskmiselt inimene aastas 26 kg toitu. Toidu raiskamist saab vältida vaadates ,mis hakkab külmkappis pahaks minema.\nToidu raiskamine pole ainuke harjumus ,mis meil on ,sest inimesed käituvad sama moodi ka riietega. Inimesed ostavad odavaid rõivaid ,mida nad kasutavad ühe korra ning unustavad need riidekappi või viskavad ära. Vahel tellitakse riideid välismaalt ,kus tehtakse riideid odavalt ja tuleb välja ,et see pole see sama rõivas mida neile oli reklaamitud. Riided ,mida inimene peaks ostma on sellised ,mis sa kasutad kaua aega ja on kodumaised.\nInimeste tarbimisharjumus on väga kahjulik planeedile ning kallis tarbjale. Paljusid tarbimisharjumusi on lihtne vältida või vähendada paari muudatusega.');
