INSERT INTO core.text(id, content)
VALUES ('abfdb6e6-b9db-4d84-916c-c6beb01dce55',
        'On näha tänapäev, et inimesed on hakanud esemeid raiskama. Head näited võivad olla toidu raiskus, riiete ära viskamine ja metsade maha võtmine. Kas on võimalik parandada inimeste tarbimisharjumusi?\nEsiteks, on üks suurimaid probleeme toidu raiskamine. Inimesed arvavad, et toitu on veel ja ei saagi otsa. Kui raha on, siis inimesi ei huvita toidu raiskamine. Siiski on neid inimesi, kellel pole raha ja toitu. Vaesemad inimesed teeksid kõike, et saaksid oma pere toita. Raiskamise põhjused võivad olla toidu halvenemine, kasutustähtaeg on läbi saanud või üleliigne toit, mis on järele jäänud. Veebilehel „Toidukaost“ räägib sellest, kuidas eestlased raiskavad toidujäätmeid kodupidamises aastas 61kg, millest raisatud toidust moodustab 42% ehk 26kg. Kirjutis veel seletab, et toidu raiskust pole võimalik kaotada ööga, sest see on inimestele juba harjumustes.\nTeiseks prooblemiks võib olla metsade maha võtmine. Neid raiutakse, et saada puitu, millest ehitatakse maju, maavarade otsimiseks või koju kütteks. Mida inimesed aru ei saa, on see ,et raiumine hävitab loodust ja kodupaike elusolenditele.  Loomad ei saa aru, mis juhtus kodukohaga ja peavad uut kohta leidma. Puud on osa metsast, mis aitavad elusorganismidel hingata. Igalpool maailmas raiutakse puid, sest see on vajalik. Ühes dokumentaalis näidati, kuidas Lõuna-Ameerikas raiuti vihmametsa maha, et leida kulda maa-alt ja seal oli näha, kuidas loomad ära pidid minema.\nInimeste tarbimisharjumusi ei ole võimalik kiiresti ära parandada. Raiskamine jätab reostust järele ja hävitab maailma igapäevaga.');
