INSERT INTO core.text(id, content)
VALUES ('a245cbb4-b2a9-4f2c-b70a-29c117a1e28b',
        'Tänapäeval paljud inimesed ületarbivad riideid ja toitu, arvates, et nad ei mõjuta ümber olevat keskonda, aga nende tarbimisomaduste tõtte tekib palju pürgi. Inimene tarbib liiga palju, sellepärast tekib prügi.\nInimene ostab liiga palju toitu, mis hiljem läheb raisku. Paljud inimesed ostavad liialt toitu, kui on kampaaniad, mille tõttu tekib ületarbimine. Ületarbimine ja -ostmine pole hea, sest siis läheb midagi alati raisku. Minu peres ostakse tihti palju toit, kui on mingi kampaania. Tihti see toit lihtsalt läheb raisku, sest me lihtsalt ei söö nii palju. Selle ületarbmise tõttu tekib meil prügi, mis ei oleks tekkinud, kui me poleks ostnud nii palju toitu. Sellepärast peab ostma ainult nii palju toitu, kui on vaja.\nRiiete ületarbimisel ja -ostmisel kandakse ühte asja väha ning visatakse minema. Tänapäeval, kus on riided läinud odavamaks ja on lihtsam neid kättesaada, on tekkinud suur probleem. Inimesed ostavad liiga palju riideid, sest need odavad ja lihtne tellida, mille tõttu kandakse ühte riideeset aina vähem. Ma olen ise näinud internetis ja reaal maailmas, kuidas inimesed ostavad odavaid riideid Hiinast ning kannavad neid ühe korra ning viskad minema. Seda probleeme saab lahendada sellega, et inimene ostab riideid, mis on kvaliteetsed ja peavad kaua vastu.\nInimene arvab, et tema ületarbimine ei mõjuta ümbrust. Inimeste väike või suur ületarbimine alati mõjutab meie ümbrust. Paljud inimesed arvavad, et väike ületarbimine ei ole halb, aga see juba kindlustab sellist mõtteviisi. Ma olen näinud, kuidas inimesed tihti ütlevad, et nende ületarbmine väga ei mõjuta meie ümbrust, mis pole tõsi. Ületarbmise õigustamine on juba halb, sest siis aina rohkem inimesi hakkavad seda tegema, sellepärast peab mõõdukalt ostma asju.\nTänapäeval paljud inimesed ostavad liiga palju toitu ja riideid, millepärast tekib prügi. Selle ületarbimise ja -ostmise lõpetamiseks peab õppetama inimestele, kuidas osta tasakaalus. Tasakaalus ostmisega tekib vähem prügi ja jääke.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('a245cbb4-b2a9-4f2c-b70a-29c117a1e28b', 'title', 'Inimeste ületarbimine ja kasutamata jäätmine');
