INSERT INTO core.text(id, content)
VALUES ('1a028c07-86bf-4a06-94a9-96e662f3c4c5',
        'Kõikidel olenditel on omad harjumused, mida nad igapäevaselt teevad. Tihti ei ole inimestel need just kiiduväärt. Seetõttu tuleks inimestel oma igapäevaseid tarbimisharjumisi muuta. \nIga päev visatakse nii suurtes kui ka väikestes kogustes toitu ära. Seda tehakse, kuna toit või toiduaine on kas üle säilimiskuupäeva läinud, pole kõlblik süüa enam või keegi majapidamises lihtsalt ei tarbi seda. Veebileheküljel TarbiToituTargalt.ee on välja toodud, et aasta jooksul tekib iga Eesti elaniku kohta 61kg toidujäätmeid, millest moodustab raisku läinud toit 26% (26kg). Kõik see raiskamine koormab meie koduplaneeti, kuna me kasutame väga palju ressursse (näiteks vett, maad), et toota ning kui midagi ära visata, on see kõik lihtsalt üks mõttetu töö.\nÜheks halvaks harjumuseks on ka autod. Seda sellepärast, et autod toodavad heitgaase ning kui ülimalt paljud inimesed kasutavad autosid, tekib neid heitgaase kohutavalt palju. Heaks alternatiiviks oleks kasutada midagi tervislikumat, milleks võiks olla näiteks jalgratas. Üheksanda klassi eesti keele töövihikus toodi välja ühes tekstis, et miks oleks hea kasutada autode asemel ratast. Üheks põhjuseks on liikumine, mis ühtlasi ka värskendab mõtlemist. Kõik peaksid aega võtma ja ennast igapäevaselt liigutama.\nInimestel on palju harjumusi, näiteks nagu toidu ära viskamine ning autode kasutus. Tuleks olla leidlik ja leida parem viis midagi teha. Oma halbu harjumusi peaksime me kõik muutma.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('1a028c07-86bf-4a06-94a9-96e662f3c4c5', 'title', 'Inimeste tarbimisharjumused');
