INSERT INTO core.text(id, content)
VALUES ('30e3cbeb-89dc-4275-8b6e-a45b56b93eb9',
        'Iga inimene on tarbija ja sellest ei pääse kuhugi. Tarvitatakse toitu, riideesemied ja kõike muud sellist. Inimesed tarbivad liialt palju ebavajalikku.\nInimeste tarbimiskombed on loodusele kahjulikud. Paljud ei mõtle sellele, kuhu nende välja visatud esemed lõpuks jõuavad.  Ajakirjas Minu Maailm oli artikkel sellest, kuidas ühte ookeanisse on tekkinud suur prügisaar. Saarel oli erinevaid toidupakendeid, riideesemeid ja üleüldist prahti, mis kõik reostas antud ookeani. \nLiiga palju toitu visatakse lihtsalt ära. Tihtipeale ostetakse söögiks asju, mida tegelikult ära ei sööda. Kuna kõigil toitainetel on kehtivus aeg, siis lähevad antud asjad halvaks ja need lihtsalt visatakse välja. Tarbitoitutargalt.ee lehel on juttu toidukaost. Nende kirjutatud artiklis on juttu sellest, et keskmiselt iga inimese kohta läheb väljaviskamisele 26 kg toitu. Ehk siis Eestis läheb väljaviskamisele üle 33 miljoni kilogrammi toitaineid aastas. \nEnda rahalise kasu tarbeks valitakse tihti odavamad ja vähem kvaliteetsed esemed. Seetõttu ei mõelda sellele, kust see ese pärit on ja kes on selle looja. Ka just selle pärast on loodud tuntud Tony šokolaad. Kuna antud firma kakao on pärit Aafrika eri riikidest, on võimalik šokolaaditahvli tükkidest kokku panna just need riigid, kust kakao pärit on. Kuigi nende šokolaad on kallim, kui keskmine šokolaaditahvli hind, kuid siiski Tony šokolaadi taga on sügavam mõte, et inimesed teaksid kust nende toit pärit on.\nÜhiskonnana raiskame liialt palju resursse ilma tagamõtteta. Igaüks peab muutma, oma tarbmisharjumusi mõttega, et meie loodus ja resursid säiliks võimalikult pikaks ajaks.');
