INSERT INTO core.text(id, content)
VALUES ('cd055b0b-faf8-4bd2-ac18-a2abcd7d89f5',
        'Meie ühiskond tarvitab üleliigselt toitu, riideesemeid ja muid kasulikke loodusvarasid. Inimesed tarvitavad rohkem loodusresursse kui kunagi varem. Loodusvarade raiskamine tekitab meie planeedile palju kahju, mida tulevikus on raske lahendada.\nInimesed valmistavad perele või iseendale liialt suures koguses toitu, mis tihti läheb raisku. Poed on tänapäeval täis kaupa ja toit ei ole enam luksus. Poodide areng tekitas inimesele suure valiku toidukaupade vahel. Raske on valida mida poest osta ja sellepärast tihti ostetakse rohkem kui on vaja. Tarbitoitutargalt.ee andmetel tekib iga Eesti inimese kohta aastas 26 kg toidukadu.\nInimesed tarvitavad liialt palju maavarasid: energiat, maad, vett ja muud sellist. Inimesed tarvitavad loodusvarasid rohkem, kui päriselt vaja oleks. Televiisoreid ei panda kinni, jäetakse lampe mis ei ole kasutusel tööle, kasutatakse pesumasinat mis raiskab rohkem vett kui tavaline ja sõidetakse autoga kuigi saaks rongi või bussiga. Selline üleliigne kasutamine tekitab kõigile tulevikus veel suurema probleemi. Eestis on elektri kriis, mida on raske leevendada selgitab ERR.ee\nÜleliigne resursside kulutamine mõjutab meie loodust, loomi ja isegi meid. Elektrit toodetakse erinevates jaamades, mis saastab meie õhku. Palju prügi sattub kaunitesse Eesti metsadesse, mis tapab taimi kui ka loomi. Vette sattub palju prahti ,mis mõjutab selle ökosüsteemi. Delfi.ee andmetel on looduses liialt palju prahti ja õhu kvaliteet halveneb.\nInimesed peavad enda tarbimisharjumused tegema nii loodussäästlikuks kui võimalik. Inimesed kui ka kõik loodus saaksid elada paremas keskkonnas. Õhukvaliteet läheks paremaks ja Eestis jääks järele rohkem loodusresursse.');
