INSERT INTO core.text(id, content)
VALUES ('d53743d9-ef68-4985-9f05-33c04b457bc6',
        'Inimesed raiskavad palju ja ostavad asju, mida nad tegelikult ei vaja. Rohkem peaks mõtlema oma tarbimisharjumuste peale ja ostma seda, mida päriselt vaja läheb.\nOstetakse sageli asju, mis on odavad ja ei pöörata tähelepanu kvaliteedile. Sageli on allahinnatud toiduained oma tähtaja ületanud ja kui inimesed seda ostavad, võivad nad halva üllatusena avastada, et see toit on juba pahaks läinud. Kui poes nähakse, et mõni toode on allahinnatud, siis tahetakse see kohe ära osta aga ei mõelda selle peale, et see asi ei pruugi kaua kesta. Allahinnatuid tooteid ostes, proovitakse oma raha võimalikult palju kokku hoida. Sellised ostud aga, ei pruugi alati kõige säästlikumad olla.\nKa väikeses koguses toidu ära viskamine avaldab suurt mõju. Tihti aga arvavad inimesed, kes seda teevad, et nii see pole. Tarbitoitutargalt.ee andmetel tekib kodupidamises iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg. Need numbrid on ühe inimese kohta hirmutavalt suured ja see peaks meid mõtlema panema, et kas meil tõesti on vaja nii palju raisata. Kahjuks aga ei saa neid probleeme lahendada üleöö.\nTuleks eelistada rohkem kodumaiseid asju. Oma kodumaal tootetud asjad on sageli paremad, kui välismaal tootetud asjad, sest nende tootmisel on kasutatud kodumaiseid vahendeid. Kui välismaalt sisse toodud toiduainetes on tihti kasutatud erinevaid säilistusaineid, et need transportimise käigus halvaks ei lähe. Kodumaistel toodetel aga pole neid nii palju, kuna neid saab kiiremini poodidesse transportida. Seetõttu on need tervislikumad ja isegi odavamad.\nInimesed tarbivad liiga palju ja peaks rohkem mõtlema oma vajaduste üle. See on tõsine probleem keskkonna jaoks ja seda tuleb koheselt lahendama hakata.');
