INSERT INTO core.text(id, content)
VALUES ('9b235f51-bb82-448e-9d35-6a3b102c7ead',
        'Igal inimesel on omad tarbimisharjumused, aga nendest on paljud meie keskkonnale halvad. Neid eluviise tuleb aga muuta. Inimeste harjumusi peab muutma. \nInimesed raiskavad liiga palju toitu. Iga päev sööb iga inimene toitu, aga osad selle asemel, et lõpetada einestamine, viskavad toidu lihtsalt ära. Sellest on tekkinud suur probleem meie keskonnale. Toiu raiskaminest ei kaotata ainult raha, vaid ka maad, energiat, tööjõudu ja veel. Et muuta inimeste viise, kuidas toiduga toime tulla, peaks iga majapidamine, kas komposteerima ülejääke või hoopis annetama toitu, mida ei ole katsutud ega tarbitud, aga see võtab aega. Tarbitoitutargalt.ee lehelt saab teada, et iga Eesti inimese kohta läheb raisku ligi 61 kg toitu, millest 26 kg moodustab toidukadu. Toiduraiskamis probleemi lahendamiseks läheb kaua aega. \nToidu sees on liiga palju ebatervislikke aineid. Tihti peale käivad noored poes, et osta omale mingeid komme ja krõpsu. Paljudes sellistes toodetes on aineid, mis inimkehale ei sobi. Üks peamine aine, mida kasutatakse näiteks kommides, on palmiõli. Mida võiks teha, et parandada olukorda, on, et hakata tootma tervislikumaid komme, mis maitsevad sama hästi, kui enne. Brasiilias võetakse iga aasta liiga palju hektareid vihmametsa maha, et saada palmiõli ja toota ebatervislikke komme. Palmiõlile oleks vaja leida alternatiiv.\nKvantiteet ei ole alati parem kui kvaliteet. Viimasel ajal üle maailma ostetakse mitmeid asju hiina veebipoodidest nagu Temust ja Alibabast. Sealt ostetakse oluliselt palju riideid ka. Need rõivad, mida inimesed ostavad sealt, ei ole tavaliselt kvaliteetsed ning on tehtud ohtlikutest materjalidest nagu näiteks naftast. Pigem võiks inimesed eelistada rohkem kohalikke riideid, mis on toodetud ka kohalikes tehastes. Veel saaks näidata noortele, et mis juhtub rõivastega, mida inimesed enam ei soovi ja näidata kui palju iganädalaselt nendest raisku läeb. Eve Hansoni arvates on oluline, et igaüks vaataks üle oma isiklikud tarbimisharjumused ning eelistaks kvaliteeti kvantiteedile. Kõige tähtsam pole riietes see, et kui soodne see on, vaid kui palju seda kasutatakse.\nPea igal inimesel on oma tarbimis probleem. Õnneks on ka võimalik neil oma viise parandada ja keskkonna jaoks rohkem head teha.');
