INSERT INTO core.text(id, content)
VALUES ('96541393-edf5-46f9-a316-69640c3f97b3',
        'Viimasel ajal on hakatud rohkem tähelepanu pöörama sellel, kui palju inimesed tarbivad. On aru saadud, et inimesed tarbivad asju liiga palju ning tegelikult ei ole neil kõike seda vaja.\nMitmetes riikides raisatakse väga palju toitu. Inimesed ostavad endale liiga palju toitu, kuid ei jõua kõike seda ära süüa ning siis lihtsalt viskavad selle ära. Toitu raiskavad ka paljud Eestlased. Veebilehel Tarbitoitutargalt toodi välja, kuidas aasta peale viskab üks eestlane keskmiselt 26kg toitu ära. Toidu raiskamine kulutab inimeste raha, aga ka ressursse. Toitu raisatakse liiga palju ja see näitab, kuidas inimesed tarbivad liiga palju, kuid ei jõua kõike ära kasutada.\nMitmed inimesed ostavad enda riideid kiirmoe poodidest. Sellised riided on halva kvaliteediga ja seetõttu kantakse neid riideid väga lühikese aja ning siis viskatakse need ära. Maailmas toimub palju sellist asja. Vikerhommiku saataes rääkis Eve Hanson, et paljud riided, mida inimesed ära viskavad jõuavad taaskasutuskeskistesse.  Need riided on sellised, mida inimesed on vähe kandnud, sest nad on nii halvast kvaliteedist. Inimesed ostavad endale riideid, mis on naftast tehtud ja pärast paari kandmist viskavad kohe ära. Ei teada kuhu riided jõuavad vaid lihtsalt ostetakse juurde.\nLiiga palju raiutakse puid maha. Inimestel on kõtteks või ehitamiseks koguaeg puitu vaja, kuid puul võtab aega, et tagasi kasvada. Raiutakse maga rohkem puid, kui tagasi istutatakse ning see on halb. Uhes loodusdokumentaalis toodi välja, kuidas nendes metsades, mis inimeste jaoks maha raiutakse, elavad loomad ning need loomad kaotavad oma elupaiga raie tõttu. Inimesed mõtlevad, et neil on vaja puitu ning raidumise tagajärgedest üldse ei mõtle. \nInimesed tarbivad liigselt erinevaid asju ning raiskavad ressursse. Tarbitakse liigselt toitu, riideid ning puitu ja ei mõelda, kuhu kõik lõpuks jõuab.');
