INSERT INTO core.text(id, content)
VALUES ('dd744ad8-3e83-49b6-8f7a-d17229a12480',
        'Inimesed tarbivad kogu aeg erinevaid asju ja väga suurtes kogustes. Suure tarbimisega tuleb kaasa aga raiskamine ning tihtipeale ei mõelda tagajärgedele, mis sellele järgnevad.\nRaiskamise pärast läheb kaotsi väga palju ressursse. Mingi asja tootmisel kasutati selle jaoks erinevaid varasid alates rahast kuni inimkapitalini. Selle toote ostmisel peab maksma raha ning ka pärast selle ära viskamist toimub pikk protsess, näiteks prügi ümbertöötlemine. Kui visata ära asju, mis on veel täielikult kõlblikud kasutamiseks või söömiseks, siis läheb kaduma rohkem ressursse kui peaks. Veebilehel tarbitoitutargalt.ee on kirjutatud, et keskmiselt tekib kodumajapidamises ühe Eesti inimese kohta aastas 61 kg toidujäätmeid ning sellest on 42% toidukadu ehk 26 kg. See tähendab, et kaduma läheb tonnides toitu, mida oleks võinud veel süüa. \nPaljud inimesed tahavad alati osta kõige uuemaid tooteid. Vana, mis on veel täiesti korralik, vahetatakse välja lihtsalt, et osta kõige hiljutisem. Mitmed inimesed soetavad kohe uusima automudeli või telefoni, kui selleks võimalus on, olenemata sellest, et selleks pole vajadust. Seda tehakse tihti teistele silma jäämise pärast. Sama lugu on ka riietega ning selle teema kohta räägiti saates „Vikerhommik“. Taaskasutuspoodidesse koguneb kogu aeg hunnikutes riideid, mida on vaevalt kantud. Inimesed ostavad riiideid põhimõtte pärast ning lähevad arutult kaasa sooduskampaaniatega. Oluline pole uusimate toodete omamine, vaid keskkonnasõbralik ostmine.\nPaljude inimeste tarbimisharjumused pole keskkonna jaoks jätkusuutlikud. Inimesed raiskavad ja ostavad liialt tihti uusi asju ega mõtle, kuidas see kahju tekitab.');
