INSERT INTO core.text(id, content)
VALUES ('0ea5e2eb-adde-4a88-b05b-157d7aaf6f65',
        'Igaühel on oma tarbimisharjumused. Regulaarselt inimesed viskavad ära nii toitu kui ka riideid, mis põhjustab keskkonda reostumist ja kahju. Tänapäeval see on tõsine probleem, mille üle peame kõik mõtlema.\nArgielus tarvitame tohutult palju toitu mõeldes, et see ei saagi otsa. Tarbitoitutargelt veebis on öeldud, et meie ettekujutus meie panusest on suurem. Ühe pere kohta toidukadu on 26 kg, mis moodustab 42% kogu toidujäätmest. See tähendab, et peaaegu pool meie toidujäätmest jäävad tarvitamata. Inimeste jaoks kahjustab üleliigne viskamine nende raha seisu, sest selle asemel, et proovida toidu targemalt tarvitada, nad ostavad uut toitu ja kuuluvad rohkem raha selle peale. Nii muutub ka keskkond meie ümber.\nInimesed on harjunud sellega, et nad viskavad minema riiet, mis nad enam ei vaja. Kuid tavaliselt need võiks veelgi kasutada. Lisaks nad ostavad midagi odavamad väljaspoolt. Näiteks taaskasutuskeskused pakuvad uuskasutuse. Moedisaineri Eve Hansoni arvates see on hea pakkumine inimeste jaoks, sest seal pakuvad häid riiet, mis on suurepärane keskkonna jaoks. Sellega võib näidata noortele, kuidas uuseti kasutada, mida sa rohkem ei vaja.\nLõpuks, inimesed tarvitavad palju ressursse, mille puudus on keskkonna jaoks on väga ohtlik. On mingeid võimalusi säästada ökosüteemi meie ümber. Kuid see kõik sõltub meie tarbimisharjumustest. Kui me tahame muuta meie ümber, peame muuta meie harjumusi.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('0ea5e2eb-adde-4a88-b05b-157d7aaf6f65', 'title', 'Inimeste tarbimisharjumused');
