INSERT INTO core.text(id, content)
VALUES ('a901a718-3c4b-4e6d-b07a-477196ca40ff',
        'Tänapäeval toidukaotus on väga suur problem ja sellega on vaja midagi teha .Inimised ei savad aru seda, et naad lihtsalt raiskava väga vajalist ainet võib olla ,et naad teevad seda kogemata. Täna päeval inimesed viskavad väga palju toitu ja seda teevad kui ka vaesed inimesed kui ka rikkad. Veel mõned inimesed arvavadet, et taaskasutuspoodid on pahad ja mõttetu ja seal käivad ainult kodutu inimesed \nTarbtoitutargalt.ee öeldakse,et eestlased viskavad umbes 30 kg toidu ja selle põhjal me võime sada , et kui seda väljendada  umbes kümnesk  protsendi me saame onda veel ühele inimesele sööma ja selles võib sõltuma tema elu. Inimesed ei saavad aru , kui sull on toit siis see ei tähenda, et saa võid seda raiskada ja sellega mängida. Näiteks kui sull on või leib ja sa ei taha seda sa võid anda seda teisele inimestele ja võib olla sa võid teda pästa tee agedat asju ja see sulle tuleb tagasi.\n  On veel on väga tõsine teema, et taaskasutuspoodides on väga pahad asjad ja seda pole võimalik kasudada ja Vikerhommik ütleb,et lapsed mõtlevad, et seal on väga paha inimesed seal töö');
