INSERT INTO core.text(id, content)
VALUES ('1f9098ed-288a-4c74-a713-a1b91cfd2bf7',
        'Tänapäeval inimestele on normiks saanud toidu ja raha raiskamine. Inimesed teevad vale valikut, kui näiteks viskavad toidu ära ja ei hooli sellest. Või, kui ostavad mõtlematult riideid, mida nad kandma ei hakka. Mina arvan, et sellist olukorda peaks muutma.\nToitumisharjumused. Inimesed tihti ei arvesta sellega, kui palju nad ühes söögikorras süüa soovivad ja seepärast jääb ühe inimese kohta aasta jooksul päris palju toidujäätmeid. Selline suhtumine toitu mõjutab tohutult ressursse: maad, energiat, vett. Tarbitargalt.ee veebilehel kirjutati, et sellise käitumisega paneme keskkonnale kõva koormuse peale ning lisaks see mõjutab globaalset kliimasoojenemist.\nKas inimesed peavad alati ebavajalikke riideid viskama prügikasti, või on mõni muu lahendus? Moedisaineri Eve Hansoni intervjuu kuulates koondame järeldust, et peame sagedamini taaskasutuspoode külastama ninng sinna ka riideid viima. Mina täiesti nõustun Hansoni seisukohaga, sest taaskasutuspoodid saavad ainsa populaarsemateks ja nende arengut tuleb jätkata. Kui näidata noortele raiskamist, mis maailmas toimub, hakkavad nad järgmise ostu sooritades ülemõtlema, kas nendel on seda riietust tarvis.\nKokkuvõttes, peame vaatama üle oma tarbimisharjumusi. Kombed, mis tegelikult tunduvad meile ebaolulistena, rikkavad riigi- ja üleüldist maailmaarengut. Toidu raiskamine mõjutab kliimasoojenemist, ressursside raiskamist ja kemikaalide eraldumist. Enne uue riie ostmist mõtle, kas sa hakkad seda riiet üldse kandma. Iga väike muutus meie elus on ka väike samm tuleviku heaolu parandamiseks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('1f9098ed-288a-4c74-a713-a1b91cfd2bf7', 'title', 'Inimeste tarbimisharjumused ja nende mõju');
INSERT INTO core.text_property(text_id, property_name, property_value)
