INSERT INTO core.text(id, content)
VALUES ('cee542c8-cf07-463d-9588-0b1fe919a8a5',
        'Üks olulimatest ühiskonna probleemist on inimeste tarbimisharjumused ja seda puutub mitte ainult toitu. Minu meelest me saame parandada oma tarbimisoskusi, kuid seda peavad parandada kõik, mitte üksikud.\nKust te teate, et te oskate õigesti toitu tarbida? Kas te teate, mis see üldse on? Paljud vastaksid, et nad teavad sellest piisavalt, kuid see ei ole nii. Lehelt tarbitoitutargalt.ee/toidukava on öeldud, et kodumajanduspiamises tekib iga Eesti inimese kohta aastas kesmiselt 61 kg toidujäätmeid, millest toidukaudu moodustab 26 kg. Nii me raiskame mitte ainult toitu, vaid muid ressursse ka. Aga kuidas me siis seda harjumust parandame?\nMeie probleemidest peab teatada juba noorest vanuserühmast. Anu Välba intervjuus, allikas „Viruhommik“ ütleb moedisainer järgmisi sõnu: „ Ma näen taaskasutuspoodide laos vabatahtlikuks käies seda rõivaste kogust, mis tekib iganädalaselt juurde. Need on meeletud hunnikud ja see on väga õpetlik. Ma arvan, et peaks hakkama noortele tegema ekskursioone taaaskasutuspoodide lattu, et näidata, milline raiskamine tegelikult toimub.“ Ja ma olen temaga täiesti nõus. Inimeste mõtteviis moodustub noores eas ja me vastutame selle moodustamisest. Meil on võimalus parandada ühiskonna probleeme läbi järgmise põlvkonna ja meie kohus on seda võimalust kasutada. \n Eesti elanikkud peavad aru saama, et kõik sõltub neist. Läbi probleemi tutvumise noorteeast saame parandada elanikke harjumusi aga see on ainult algus probleemi lahendamisest.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('cee542c8-cf07-463d-9588-0b1fe919a8a5', 'title', 'Inimeste tarbimisharjumused');
