INSERT INTO core.text(id, content)
VALUES ('27da4fe6-ceb0-4e2e-9b04-81a314943b04',
        'Tänapäeva keskkonnas on paljudel inimestel mure. Paljud inimesed rikkuvad loodusressursse toitu tarbimise põhjuseks. Nad viskavad toitu, paljud noored ei tunne tervislikud tarbimisharjumuseid. \nTänapaeva keskkonnas on paljudel inimestel tekkib mure, põhjuseks on inimeste toidu harbimisharjumused. Paljud inimesed lihtsalt ei oska ega ei taha hinnata ressursse, mida inimestel on.\nOn oluline, et inimestel peavad olema tervislikud tarbimisharjumused ja nad peavad tundma korraliku aine tarbimise, mis ei kahjusta nende tervist. Osa inimesi, eriti noored kahjustavad ja raiskavad oma toidu. Seejärel toidu viskamine kahjustab loodust, see teeb keskkonnakoormatuse ja see viib elluks paljud muret. Kahjuks, me ei saa automaatselt ära lahendada kõik probleemid, mida toidu viskamine ja looduse kahjustamine  ära toob. See surendab prügi hulka ja negatiivselt mõjutab keskkona tervise.\nProbleemide lahendamiseks me peame arendama terved harjumused. On oluline, et peame õppetama ja näidata noortele, miline toiduressursse  kasutamine ei kahjusta loodust ega  inimeste tervist.');
