INSERT INTO core.text(id, content)
VALUES ('93467903-7054-453c-b2dd-d13566d9904d',
        'Tarbimisharjumused võivad olla erinevad ja see sõltub rohkem enerinevades olukordades. Nagu räägis moedisainer Eve Hanson, on väga oluline, et igaüks vaatas üle oma tarbimisharjumused ning eelistas seda kvaliteri kvaliteedile. On kaks teksti ja nende üks suur probleem sõltub raiskamisega. \nEsimesel tekstil saame teada, et mõned inimesed raiskavad toitu, mõned aga viskavad toitu ära. Inimesed, kes raiskavad toitu, saavad seda endale lubada. Inimised, kes seda ära viskavad, arvavad, et sellega suurt pilti ei mõjuta. Kodumajapidamises tekib iga Eesti inimese kohta aastas keskmisel 61 kg toidujäätmeid, millest toidukaudu moodustab 26 kg. Toidukaudu pärast, mida visatakse toidujäätmena ära, tulevad probleemid nagu raha raiskamisega, see mõjub ka muid tohutult ressursse nagu maad, vett, energiat ja tööjõudu. Aga toidujäätmed võib kasutada teistmoodi, näiteks seda võib kasutada biomaterjalides, et teha uued asjad.\nSama probleem on teistel tekstil. Moedisainer Eve Hanson arvab, et peab noortele tegema ekskursioone taaskasutuspoodide lattu, et näidata, milline raiskamine tegelikult toimub. Eve Hanson selgitas, et sinna viiakse korralike riideid, aga ka selliseid, mis tegelikult koosneb naftast ja kehal on halb olla selleses riietuses ja seda kantakse üks kord. Aga pakkun seda, et Eestis koostakse ka riideid, mis koosneb erinevates biomaterjalides, mille kandmine ei anna diskomforti ja sellest ei tule raiskamine, vaid tuleb kasu.\nKahe teksti põhjal tegin kokkuvõtte. On erinevad inimesed ja nende käitumine on ka erinev. Eestis raiskamisega probleemid tulevad palju, sõltub olukordades ja seda arutleda võib, aga lahendus sõltub meiest.');
