INSERT INTO core.text(id, content)
VALUES ('0bc82311-db43-4805-9138-714430f47497',
        'Tänapäeval, on väga oluline probleem ressurssidega. Meil tundub, et toit ei lõppe mitte kunagi, aga see on väär. Me tarbime väga palju ressusrssi, et toit jõuaks meie lauda, aga pärast, kui ei meeldi lihtsalt viskame seda ära. Aga kas päriselt inimeste toidu tarbimisharjumus on nii suur probleem?\nVeebilehel tarbitoitutargalt.ee on kirjutatud, et Kodumajapidamises tekib Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmed, millest toidukaudu moodustab 42% ehk 26 kg. Arvan, et see on liiga suured arvud Eestile ning peab juba arutlema, et meie toit ja ressursid varsti lõppevat. Peab hakkama mõtlema peaga, mitte kõhuga.\nMoedisainer Eve Hanson ütles “Ma arvan, et peaks hakkama noortele tegema ekskursioone taaskasutuspoodide lattu, et näidata milline raiskamine toimub.“ Ja ma olen temaga nõus. Sest arvan, et tänapäeval kõihe rohkem toidu ja ressursi kasutavad noored, aga nad isegi ei võtta vastu see, et kõik elus lõppeb.Nad ostavad toitu, et seda ilusasti sotsialmeediasse pildistama ja pärast lihtsalt viskavad seda ära. Aga nad ei võtta vastu see, et meie maa aeglasti sureb nende  pärast.\nKokkuvõtteks tahan öelda, et inimesed tahavad lihtsalt tarbida ja võtta, aga anda midagi asemele ei taha. Minu arvates see on kõige suurem inimeste probleem. Inimeste ahnus sunnib tarbida neid rohkem kui vaja, et näidata nende ühskonna staatusi.');
