INSERT INTO core.text(id, content)
VALUES ('4389846a-7000-4d5e-a750-054fef072370',
        'Tänapäeval inimesed ei hoolitse selle eest, mida nad teevad toiduga ja kuidas selle tarbivad. On inimesi, kes raiskavad toidu niisama, kuna see ei teki nedele probleeme. Paljud teised raiskavad ka teisi asju. Inimesed teevad palju osteid Hiina veebipoodides ja ostavad seda, mis üldse pole vajalik. Ja pärast viskavad neid ära.  Inimesed ei mõsta, mis võib juhtuda mõttetu asjade ja ressursside raiskamisega.\nVeebilehel tarbitoitutargalt.ee väitakse, et aastas tekib keskmiselt 61 kg todujääätmeid iga Eesti inimese kohta, milles 42% ehk 26 kg on toit. Selle hulgas suurim osa on lihtsalt visatud toit, mida inimene ei jõudnud ära süüa või ostis mõttetult. Me raiskame selle peale raha ja muud teised ressursse, mis teeb meie elu keerulisem. Aga lisaks toidu raiskamisele toimub ka teste erinevate asjade raiskamine, näiteks riietus.\nMoedisainer Eve Hanson arvab, et tuleks jälgida oma tarbimisharjumuseid ning eelistada asjad hea kvalititeediga. Parem oleks osta kodumaised asju kallima hinnaga,  kui tellida mingis Hiina veebipoodis sooduskampaaniaga. Sellised asjad võivad olla tehtud ükskõik, millisest materjalist ja erineva kvaliteediga. Eve Hanson arvab, et noored peavad tutvustama taaskasutuspoodide lattuga, selleks, et näidata, millised raiskamised toimuvad ja kuidas võiks selle muuda, kui taaskasutada asju uute asju ostmise asemel. \nSelleks, et vähendata raiskamised, parem oleks muuda oma harjumisi, mõistlikum teha ostmiseid ja mõelda nende järgneva kasutamise ja kvaliteeti kohta ning võimalusel kasutada taaskasutuspoodid.');
