INSERT INTO core.text(id, content)
VALUES ('22d677d4-b1bf-47a4-b93d-5051c2e7cc85',
        'Tänapäeval inimesed olid õppinud leituma erinevaid põnevaid asju erinevates sfääridest, et anna ühiskondade uued elatused, unustusi ja . Aga mõnedel inimestel on juba piisavalt pehmed väärtused rõõmu ja nemad alustavad mitte austada see mis neil on. Kaasajagselajal on ka tarbimine muutunud elu lahutamatuks osaks. Toit ja rõivad, mida osate, ei mõjuta ainult meid endid, vaid ka keskkonda tervikuna. Kuigitarbimine on vajalik, toob se kaasa ka probleeme, nagu toiduraiskamine ja ületarbimine.\nToiduraiskamineon tõsine probleem. Eriti viskab inimen aastas ära keskmiselt 61 kg toitu, mis tähendab, et suur hulk ressursse nagu vesi, energia ja tööjõjub,läheb raisku.\nSageli ostetakse rohkem, kui tegelikult vaja, ning halvaks läinud toit visatakse lihtsalt prügikasti. See suurendab prügi hulka ja mõjutab negatiivselt keskkonda.\nSamuti on suur probleem kiirmood. Palud inimesed ostavad odavaid riideid, mis kuluvad kiiresti ja visatakse ära. Moedisainer Eve Hanson on  rõhutanud, et inimesed peaksid eelistama kvaliteeti kvantiteedi asemel ja toetama kvaliteeti kvantiteedi asemel ja toetama kohalikke tootjaid. Taaskasutuspoodidest ostmine aitab vähendada rõivasate riskamist ja hida keskkonda.\nKokkuvõttes peaksid inimesed oma tarbimisharjumusi teadlikumalt kaaluma. Väiksemad ja teadlikumad ostud aitavad vähendada raiskamist ning muuta tarbimist jätkusuutlikumals. Iga üks saab oma valikutega kaasa aidata paremale tuleviku.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('22d677d4-b1bf-47a4-b93d-5051c2e7cc85', 'title', 'Inimeste tarbimisharjumuste elu');
