INSERT INTO core.text(id, content)
VALUES ('1c04dd39-a8cf-43f5-a2a0-6fc62918ff99',
        'Inimeste tarbimisharjumust on väga erinevad ja paljudel kohal ta on erinev kui teisel kohtadel. Inimestel on vaja tulemus nemad terbivad see mida nendele meeldib ja see mis on praegune ajal aktuaalne ja mitte tarbivad see mis ei meeldi või mitte aktuaalne praegusel ajal. \nTarbitoittargalt lehel öeldud see et toidu raiskamist ei saa vähendada üleöö aga mina arvan et toidu raiskamist saab vähendada mitte üleöö vaid kümne või kahekümne protsenti. Selles et vähendada toidu raisakamis on meil vaja lihtsalt vähendada inimesi sest kui on vähem tarbijad see vähem toidu tuleb raiskada rahval mis sööb väga palju. Vaja teha mingit virus või haigus millega võib tappma mõned inimesed et filtrerida rahvas ja toitu tuleb haarama kõigel. Või võib panna reklaami paljudel kohal et kõik ostsid seda tarb ja teisel tarbil tuleb vähem protsent ostumist ja võib olla seda tarbimine läheb alla ja selle tuleb vähem tarbida sest ta ei ole paiguselt aktuaalne toit. Näiteks et meil vaja vähendada protsent paksu inimesi võib panna reklaam parem toitu tarbimist ja burgereid ja kartul fri ja koka kola tuleb mitte aktuaalne ja protsent paksu inimesi peab vähendama ag see kõik sõltub inimeste tahtmist ja kui inimene ei tahab midagi tegema sellest ta ei teeb on ju aga leidub selles inimesed mis kõik ju tahavad ja sellises inimestega lihtne töötama sest nemad kulavad ja teevad mida ütleb pea.');
INSERT INTO core.text_property(text_id, property_name, property_value)
