INSERT INTO core.text(id, content)
VALUES ('3108f02c-68f7-4240-8acb-1e7865d3bc6d',
        'Tänapäeval inimesed arvavad, et toitu võib raisata niipalju, kui on võimalik. Nendele tundub, et toit on kergesti kättesaadav ning see ei saa kunagi otsa. Arvatakse, et kui toitaineid ära visata, ei muuda see suurt pilti maailmas. Kui vaadata õigest vaatenurgast, toidujäätmete ära viskamisel ei raiska me ainult oma raha, vaid ka muid ressursse; maad, vett, energiat, tööjõudu ja nii edasi, üteldakse tarbitoitutargalt.ee veebileheküljel.\nToit on vajalik eluks ressurss, mis võib lõppeda ühel päeval, ning selle tagastamiseks tuleb teha suurt ja rasket tööd. Selleks, et vähendada ebamõistliku toitainete raiskamist, peab olema kindel eesmärk. Näiteks, enne poodi minekut peab mõtlema, mida tuleb osta ja mida on võimalik õigeks ajaks ära süüa.\nEve Hanson arvab, et on oluline see, et inimesed vaataksid üle oma tarbimisharjumused ning eelistaksid kvaliteeti kvaliteedile. Muidugi kõik meie planeedi inimesed ei proovigu sellist mõtteid ellu viia. Oleks hea teha sellist eksperimenti, kus kõik proovivad jälgida oma tarbimisharjumusi. Olgu need riided Hiina veebipoest, või muudest kauplustest. \nInimesed peavad mõistma oma ostu otsust, ning ostma seda, mis sobiks endale. Ei ole vaja osta sellist toitu, mida ära süüa ei saa. Soovitav on jälgida riiete kvaliteeti. Kõik need väiksed tegud aitavad meie maailmale muutuda puhtamaks ja paremaks. Tuleb hoolitseda maailma ja kodumaa eest, niipalju kui on võimalik.');
INSERT INTO core.text_property(text_id, property_name, property_value)
