INSERT INTO core.text(id, content)
VALUES ('965f2fa4-c1f5-489d-b968-f12bd66ef3a3',
        'Paljude inimeste probleem tänapäeval on, et nende tarbimisharjumused ei ole nii head nagu nad võivad mõelda. Nad ei väärtusta toitu, inimeste tööjõudu, raiskavad korralikke riideid, mis võiksid olla kasulikud nendele või teistele vajalikkusega inimestele.\nInimesed jätkavad toitu raiskamist, heate riiete ära viskamist, aga kuidas võiks seda harjumusi peatuda, või vähemalt proovida seda teha? Ja on ka küsimus miks sellised harjumused üldse tekkivad inimeste peas?\n Moedisaineri Eve Hansoni arvates allikast „Vikerhommik“, et igaüks vaataks üle oma tarbimisharjumusi, paremini mõtleks tellimustest enne tellimist ja prooviks teha nii, et sooduskampaaniat ei mõjutaks mõttetu toode -ja raharaiskamist. Mina olen sellega väga nõus, sest tänapäeval on suur hulk veebipoode, kus on kõik mis vaja ja samuti see mis ei ole. Mina ka kohtun selliseid inimesi, kellel on suur soov tellida ilma vajaduse, kui nad näevad sooduskampaaniat või midagi lihtsalt põnevat. \nToiduga probleem on palju raskem, seda ei saa pärast kasutamist ära anda või lihtsalt kellelgile laenata, raisatud toit ei sobi kusagile, vaid prügikasti. Üle terve maailma on palju nälga ja samuti ka mõnedes kohtades on liiga palju toitu ja inimesed lihtsalt harjuvad toitu raskamisest, et toit on ja toitu on palju, nad ei näe seda, mida näevad teised inimesed, kes toitu ei saa.\nMinu arvates inimesed peavad jälgima oma tegevusi, harjumusi ja jälgida ka kohti, kus see mida nad raiskavad on defitsiidis.');
