INSERT INTO core.text(id, content)
VALUES ('7c0f8ea4-207c-4b60-a1af-5302bb8a4295',
        'Tänapäeval inimesed tarbivad palju, nad võivad ostma asju mis neile vaja ei ole nii internetis kui ka toidupoodides ja see on päris suur probleem kuna väga suur osa toidust läheb prügikasti. \nToidukao on päris suur probleem sest väga palju toitu läheb prügikasti ja saab ebamugavaks, et sööma. Toidutargal.ee öeldakse ,et tekib iga Eesti inimene kohta aastas keskmiselt 61 kg toidujäätmeid, et seda arvu vähenema peab toitu ostmis kontroleerima ja ära ostma asju mis sa sööma ei saad.\nTaaskasutuspoodid praegu noored arvavad, et see on paha koht aga see nii ei ole \nsee on väga kasumlik koht kus saad ostma asju mis kandis keegi teine.\nMinu meelest peab toidukao probleemi lahendama ja taaskasutuspoodid on hea koht\nkokkuvõtte');
