INSERT INTO core.text(id, content)
VALUES ('922824ef-9745-4130-bdb3-2e24f7555a3e',
        'Tänapäeval paljud inimesed söövad,paha toitu.Ja kui nad söövad, paha toitu nad savad paksemaks ja nende tervis saab hulemaks ja naad ei tee sporti.paljud inimesed suurivad selle pärast.Ma arvan see on väga suur problem,sest arstid ei tea kuidas see võib ravima.Selle idea ma võtsin tekstist „Toidukaost“, tarbitoitutargalt.ee.\nSeelest on palju probleemi lahendamist, aga ma kirjutan, ainult need mis on efektivsed.Esimene problemi lahendamine on see et,inimesed lähevad ravida.Lähevad haiglase ja seal nendele aitavad , nad savad head toitu ja naad seal teevad trenni.\nTeine problemi lahendamine on see,et noortele peaks teegema ekskursioone taaskasutuspoodide lattu.Ja seal näitada nendele kõiki mis, on paha toit mis, ei ole paha.Võiks ka seles ekskursionil räkida sellest et oleks terveks,ei saada haigust.Ka on vaja nendele rääkima sellest et,ei tohi sööma asia sööki.Asia söök on paha ja võib saada haigust mis, tuli asia poolt,või hiina poolt.Selle ekskursioni plani ma võtsin tekstist „Vikerhommikust“,intervjueerist Anu Välba.\nLõpuks ma tahan teha kokuvõted sellest.Esimeseks,me saime aru et, on vaja teha palju sporti ja ei unustada teha seeda iga päev.Teiseks on vaja sööma tervisliku toitu.Kolmeks ei tohi sööma asia ja hiina toitu.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('922824ef-9745-4130-bdb3-2e24f7555a3e', 'title', 'Tarbimisharjutus inimestel');
