INSERT INTO core.text(id, content)
VALUES ('30792ec1-1cfb-40ed-9275-8bb59b6548f9',
        'Igal inimesel on oma tarbimisharjumused. Ja praegu on suur probleem, et paljud inimesed ei oska õigesti kontrollida oma tarbimisharjumusi. Ma arvan, et iga inimene peab teadma kuidas kontrollida oma tarbimusharjumusi.\nIgapäev inimesed raiskavad tohutult palju toitu. Nad juba ei saa aru, kui palju toitu osta, kui palju nad saavad seda ära süüa. Meile tundub, et toitu on veel ja see kunagi ei lõppe. Näiteks on inimesi, kes raiskavad toitu, sest nad saavad seda endale lubada. Allikas: tarbitoitutargalt.ee/toidukaost. Samas arvavad ka väiksemaid koguseid toitu ära vikavad inimesed, et sellega nad suurt pilti ei mõjuta. Allikas: tarbitoitutargalt.ee/toidukaost/. Mina näiteks veel paar aastat tagasi ei pannud tähele, kas ma söön kõiki, mida olen endale taldrikule pannud.\nPraegusel ajal on moodne tellida igasuguseid riideid mis on odavad, näevad välja kvaliteetsetena ja mis on populaarsed. Aga nad ei ole ju nii head, kui nad väljanäevad. Neid tehakse ebamugavast ja odavast materjalist. Ja pärast, kui inimesed saavad oma riideid kätte, siis nad kurvastavad, sest riided ei näe välja nii ilusana, kuidas oli foto peal. Mulle näiteks ei meeldi tellida riideid internetist, sest ma juba tean, et midagi head internetist ei tule.\nMa võin järeldada, et inimesed peavad hakkama õppima õigesti tarbima igasuguseid asju, muidugi jälgida toidu tarbimist, sest toit muidu saab otsa. Me peame hoidma oma maailma ja mitte kasutada liigset materjali ja ressursse.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('30792ec1-1cfb-40ed-9275-8bb59b6548f9', 'title', 'Inimeste tarbimisharjumused');
