INSERT INTO core.text(id, content)
VALUES ('d64bbe8e-ba6d-4dba-9103-9fdeda12de9d',
        'Suurimateks probleemseteks põhjusteks inimeste tarbimisharjumustes on rohke toidu raiskamine ja liigne rõivaste tootmine. Kuid neid probleeme on võimalik muuta. Minu seisukohalt peaksime nendesse muredesse suhtuma täie tõsisusega, ja vähemasti proovima muuta enda harjumusi, sest kõik algab teist endast.\nKõige keerukamaks probleemiks on toidu kulu. Toit ise on vajalik, aga tihtipeale tarbivad inimesed toitu läbimõtlematult ja viskavad endale mõistmata väga suures koguses toitu minema. Lisaks sellele, et toidu ära viskamisega kaasneb väga suur rahaline kaotus, siis on see ka meie ühiskonnas suureks kaotuseks. Inimesed, kes saavad endale lubada toidu ära viskamist, ilma et see puudutaks neid rahaliselt, peaksid siiski mõtlema, milline kaotus on see tööjõus. Keegi on näinud palju rasket vaeva. Ja selle vältimiseks peaksime lihtsalt natukene rohkem läbimõtlikkumad olema, jälgides mida me ostame, ja kas see mida ostame on üldse vajalik. \nTeiseks suurimaks probleemiks on rõivaste liigne tootmine. Peaksime eelistama eelkõige kvaliteeti. Jah tõepoolest, on tihti just Hiina veebipoodides need kõige soodsamad riided, kuid kui arvestada nende väheke odavamate rõivaste vastupidavust, siis tuleb lõppkokkuvõtes mõistlikum osta meie enda kodumaal toodetud, küll väheke kallimaid aga vastupidavamaid rõivaid. Ja veel keskkonnasõbralikum oleks, kui viiksime riideid rohkem ringlusesse, heaks võimaluseks on näiteks taaskasutuspoed. \nKokkuvõteks, kui jälgida ja teha läbimõtlikemaid otsuseid, säästaksime palju. Säästaksime inimeste rasket vaeva kui ka  rahaliselt oleks kindlasti parem seis ühiskonnas.');
