INSERT INTO core.text(id, content)
VALUES ('0440a5f2-ebb7-4482-80a1-1723e182fd7c',
        'Tänapäeva inimeste tarbimisharjumused tekitavad tõsiseid probleeme meie keskkonnale. Nad ostavad endale igasuguseid asju kuigi need ei ole vajalikud tooted igapäeva eluks. Peale asjade raisatakase ka toitu. Seda ostetakse endale koju liiga palju ja pärast need aeguvad ning lõpetavad prügikastis. Sellised tarbimisharjumused raiskavad meie maad, vett ja energiat. \nInimestele meeldib endale kokku osta riideid hiina veebipoodidest kuna seal on madalamad hinnad ja palju sooduskampaaniaid. Enamus veebipoodides müüakse aga halva kvaliteediga ja materjaliga riideid, mis võivad kiiresti puruneda. Sooduskampaaniatega ostetakse endale palju rohkem tooteid kui tegelikult tarvis ja pärast need lähevad taaskasutuspoodidesse või visatakse ära. Muidugi ostetakse ka kvaliteetsemaid rõivaid aga pärast kodus need ei pruugi nii head välja näha nagu mingil reklaamfotol või neid on ebamugav kanda. \nOn inimesi, kes raiskavad toitu kuna nad saavad seda endale raha suhtes lubada. Samas arvavad ka mõned, kes viskavad väiksemaid koguseid toitu ära, et nad ei mõjuta sellega väga midagi. Kahjuks see nii ei ole. Me raiskame kokku palju rohkem kui arvata suudame. Peres on väikseid lapsi, kes tavaliselt jätavad taldrikule suuri koguseid toitu alles ja pärast visatakse see minema. Tavaliselt nad ei söö kõike ära kuna nad tarvitavad toitu vähem või neile ei maitse see söök, mis on tehtud.\nKokkuvõtteks me tarbime tooteid rohkem kui peaks ja inimesed võiks enda tarbimisharjumusi muuta kuna üle tootmine on meie keskkonnale kahjulik.');
