INSERT INTO core.text(id, content)
VALUES ('b4cc0ac5-5181-49f1-b8c3-fb8b95ee2782',
        'Tänapäeval on inimesed hakanud rohkem osta või kasutama üleliigseid asju, mida tegelikult vaja ei ole. Mis on inimeste tarbimisharjumused ja kas neid oleks vaja piirata või jätta nagu need on?\nPalju populaarsust on kogunud interneti veebipoed, kus müüakse odavalt igasuguseid asju. Näiteks mänguasju, riideid, kosmeetika tooteid, nutitelefoni ümbriseid ja kaitsevahendeid. Praegu sellisteks poodideks on kujunenud Shein ja Temu. Veebipoed kogusid kuulsust koroona pandeemia ajal, kui ei saanud poodides koha peal käia. Seal müüdavate asjade valmistamiseks kasutatakse palju Maa ressursse, mis koormab Maakera ja tekitab palju jääkaineid. Inimesed võiks käia rohkem taaskasutus poodides, osta ja vaadelda seal, mitte teha emotsiooni oste ja raisata raha.  \nRahvas võtavad toitu iseenesestmõistetavana. Arvavad, et see ei saa kunagi otsa ja leidub igal pool. Inimesed ei oska mõelda, kui palju toitu maailmas igapäev raisatakse ja visatakse ära. Sama on ka riiete, jalanõude ja muude vahenditega. Sellega kaasneb tohutult prügi. Lahenduseks võiks inimesed suhtuda tõsiselt prügi sorteerimisse ja kasutada kõik ära mis võimalik.  \nTarbimisharjumuste vähendamiseks võiks olla suunatud rohkem koolitusi ja üritus, mis on suunatud nooremale põlvkonnale. Koolides võiks olla sama teemalisi tunde. See aitaks ära hoida Maakera ülekoormuse ja vähendada ebavajaliku asjade müügi. See paneks noored mõtlema rohkem ühiskonnale ja tulevikule. \nInimesed võiks kontrollida ennast rohkem mida nad ostavad ja mis jälje see loodusele jätab. Noorte harimine ja asjadega kursis hoidmine aitab tarbimisharjumusi vähendada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
