INSERT INTO core.text(id, content)
VALUES ('10c29c5a-0525-4074-877f-2765080232ce',
        'Maailm tänapäeval on tarbijakesksem kui kunagi varem. Peaaegu midagi muud peale tarbimise ei toimu, ning enamus ei märka seda. Kuid kogu selle tarbimisega arenevad inimesel uued harjumused ja tavad, mis on keskkonnale väga kahjulikud.\nPraegu toimuvad asjad nii, et ostleja läheb poodi ja vaatab mida osta ja leiab midagi ilusat. Siis ta ostab selle, ja koju jõudes tekib esimene saaste: pakend. Pakend on mõeldud ostleja pilku püüdma, sest mida ilusam asi on, seda rohkem see müüb. Selle ühe pakendi koostamiseks kulub enamasti palju rohkem ressursse kui arvatakse, eriti siis kui pakend on läikiv või tekstuuriga. Ja see pakend läheb otse prügikasti, ning seal edasi tõenäoliselt põletatakse ära, mis tekitab veelgi rohkem kahju keskkonnale.\nSiis aga on toode ise. Tooted ei pruugi kesta kaua. Me oleme näinud ja kuulnud, kuidas erinevad firmad, näiteks Ameerikas „Tupperware“, kes tegi säilituskarpe, lähevad pankrotti, sest nende toode on nii kvaliteetne ja kauakestev, et see ei tekita vajadust uuesti ja uuesti ostma. Selle vältimiseks, tänapäeva tooted kas lähevad latki, kuigi ostleja pole toodet valesti kasutanud, või vananeb, nagu näiteks tehnika vidinad ei saa enam tarkvara värskendusi. Niimoodi tekib inimesel arvamus, et on normaalne kõiki asju ära visata ja korduvalt uusi osta.\nKokkuvõtteks, pole tänased halvad tarbimisharjumused otseselt tarbija enda süü, vaid hoopis tootja keskendub sellele, mis müüb korduvalt, eirates teisi tagajärgi. Mis lõpuks raisku käheb, tootjat ei mõjuta ja ei sunni neid seda probleemi tõsiselt võtma. Ning pikajaline tarbimine muudab inimese pilgus raiskamise normaalseks, ja inimene samuti ei võta probleemi tõsiselt. Muutus ei ole kunagi lihtne olnud, aga kui asja tõsiselt ei võeta, on muutus võimatu.');
