INSERT INTO core.text(id, content)
VALUES ('524823b7-e832-469f-8295-35ad976e2fcb',
        'Toit on oluline osa inimese elus ja selleks ,et toidu kaotust väheneda peavad inimesed vähendama toidu siise võttu ja selle raiskamist sellepärast ,et inimestele oleks tulevikus toitu üle.\nEssana inimesed peaksid kontrollima ennast sellejaoks ,et nad ei saaks toidu sõltuvuse ja sellega ei sööks ennast paksuks ,selleks võiksid nad laadida üles ühe äppi mis ütleb ,kui palju toitu nad võiksid võtta iga päevaselt ja ,kui palju kilo caloreid selle toidu sees on.\nTeine etapp oleks kontrollida , kui palju saaksid ise süüa , et hiljem üle jääke ei viskaks ära vaid taldrik või kaus oleks tühi ja ei oleks täais ülejääke mis hiljem visatakse sigadele , hobustele ,lehmadele ja teistele loomadele ,kui oled sööklas kui oled kodus siis ka ei võiks ära visata jääke vaid panna külmkappi ja süüa hiljem .\nKui toit on halvaks läind siis poleks mõttet seda ära visata vaid sellega saab mitut asja veel teha kas anda mingisugusele loomale või anda ära looma farmile kus loomad söövad selle ära ja ei jätta ülejääke.\nNende propleemide lahendamiseks on mitmeid viise kuidas neid peadada ja toitu üle jätta nagu erilised rohud mis panevad inimest kas rohkem- või vähem sööma ja paljusi teisi rohte, loomulikult on ka liikutamine viis kuidas enda söögi tahtmist vähendada nagu näiteks minna jooksma, jõusaali ja teha teha einevaid sporte.\nkokkuvõtteks inimene saab kontrollida enda toidu sisse tulekud erinevate viisidega ja tegevustega oleneb ,kui palju inimesed tahavad ennast muuta. Inimene võiks teada kui palju ta suudab süüa ,et hiljemaks ei viskaks ära ja raiskaks toitu ennem võiks anda kotututele mitte lasta toaletist alla või visata prügikasti. Inimene suudab enda sisse ja välja tulekut kontrollida rohtude ja liikutamise abil.');
