INSERT INTO core.text(id, content)
VALUES ('845c7eac-3a9f-48a2-9330-b2d5ef32b120',
        'Inimestel on palju tarbimisharjumusi, üks suurimaid harjumusi on see, et inimesed viskavad peale söömist nii palju sööki minema, ilma, et nad mõtleksid teiste inimeste peale kellel ei ole enda söögilauale midagi panna ja kellele oleks kasvõi sellet väiksest kogusest söögist väga palju abi. Kas inimesed peaksid muutma enda tarbimisharjumusi ja mõtlema rohkem teistele?\n      Inimeste harjumus sööki peale selle tarbimist kohe ära visata ei ole ilus. Võiks viia selle toidu mis jäi kõik üle ja mida ei kavatse paari päeva jooksul ära tarbida näiteks supikööki, kus käivad inimesed kes ei suuda enda toidulauale midagi panna. See oleks kindlasti üks paremaid ideid, kui ei ole muud viisi kuidas seda toitu ära tarbida.\n     Teine viis oleks, et annad tänaval kellegile selle toidu, kui näed, et see inimene on tõesti näljane. Mina isegi olen kunagi oma  vanaisaga paarile toredale inimesele toidupaki andnud, kus oli nii mõndagi head ja paremat sees. See tegi enesetunde nii soojaks, et ei pidanud süüa ära viskama ja keegi teine sai sellest vägagi rõõmu.\n    Inimesed tõesti mõtlevad ainult enda peale ja viskavad söögi ära ilma seda mõtlemata. Seda probleemi peab parandama nii, et inimesed saaksid aru, et sööki ei tohi ära visata ja selle võib alati teistele edasi anda, kui sa ise seda enam tarbida ei soovi. Teistele on sellest väga palju abi ja see teeb paljud inimesed õnnelikuks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('845c7eac-3a9f-48a2-9330-b2d5ef32b120', 'title', 'Inimese tarbimisharjumus');
