INSERT INTO core.text(id, content)
VALUES ('c238f37a-a3c1-401f-869b-8a3bb151526f',
        'Inimesed tänapäeval tarvitavad väga imelike asju nagu aineid, alkoholi ja e-sigarette. Tavaliselt teevad need inimesed selle ainete tarvitamise nende igapäevaseks kombeks ehk nad on harjunud neid aineid võtma iga päev. Nüüd räägime miks nad seda teevad ja kuidas seda vältida.\nEsiteks nagu me rääkisime enne, kui täiskasvanud või lapsed teevad e-sigarette liiga palju siis nad teevad selle suitsetamise oma iga päevaseks eluks, et ennast rahustada või, et välja näha äge teiste ümber. Kuidas seda vältida on väga lihtne lapsele peab õpetama, rääkima või isegi näitama, mida e-sigarettid või muu tarbimis ained võib teha nendele oma elus.\nNagu näiteks keegi pakub sulle arbuusi maitselist e-sigaretti proovimiseks, kas sa võtaksid selle vastu ja prooviksid või mitte, kui sa võtaksid selle vastu siis sulle võib tekkida mulje, et „See oli päris hea, kas võib uuesti proovida?“, ehk sul tekkib harjumus ja sõltuvus seda rohkem proovida. Aga kui keegi on sulle õelnud, et see asi võib sulle vähi või mingi mürgituse anda siis ma väga ei usu, et sa tahaks seda proovida.\nTeiseks on inimesi kes on juba harjunud võtma aineid mida nad ei tohiks nagu näiteks; Heroiin, kokaiin ja alkoholi tarbeid. Kui inimene on juba harjunud neid tavitama, siis seda saab mingil viisil ravida aga sul oleks vaja rohkem distsipliini.\nVõimalus sellele on see, et nad lihtsalt viskavad ära need ained ja proovivad oma eluga edasi elada. Aga suurem osa ajal see ei tööta, sest nende aju juba arvab, et see on vajalik aine tema elus.\nKokkuvõtteks on see, et inimesed kes juba on harjunud ära mingi ainega või muu asjaga, ei saa väga sellest lahkuda. Aga inimesed kes ei ole veel harjunud nagu ainete tarbimisega, siis nendel on see lihtsam, kuna nendele saab selgitada, et sellised asjad ei ole okei tarbida. Vanemad võiksid rohkem õpetada enda lastele kuidas viisakalt käituda või mis juhtub kui tarvitad neid aineid.');
