INSERT INTO core.text(id, content)
VALUES ('ee7643fe-c3dc-474a-84ee-eac80aeb0d93',
        'Toiduraiskamine ja odavate Hiina riiete ostmine on saanud igapäevaseks probleemiks. Inimesed käivad poes ning ostavad omale käru täie toitu mida nad ära ei söö. Sama on Hiina riietega, inimesed näevad sooduskampaaniaid ja ostavad omale asju mida nad ei vaja. Aga miks seda kõike tehakse ja kuidas seda vältida?\nInimeste harjumised näitavad, et nad käivad iga nädal poes ning ostavad hunnikuga toitu ja toiduaineid kokku mida nad tegelikult ära ei söö. Liigse söögi tegemisega ning selle hiljem ära viskamisega tekib iga majapidamise kohta aastas keskmiselt 61 kg toidujäätmeid. Enamasti käiakse tühja kõhu või nimekirjata poes ning ostetakse kõike mis näeb hea välja aga hiljem kodus ei ole need enam nii ahvatlevad. Toiduraiskamine tähendab ka seda et tehased peavad tootma rohkem toitu mis tekitab tõsise keskkonnakoormuse, kasutatakse veel rohkem väetiseid ja mürke.\nKui inimesed näevad netis sooduspakkumisi ja odavaid hindu ilusate riiete juures tekib neil kohe tahtmine neid osta. Kui aga riided kohale jõuavad kantakse neid vaid paar korda ning seejärel viiakse need taaskasutuspoodidesse kus on sellepärast hiiglaslikud riidehunnikud.\nToidu raiskamist saaks vähendada kui inimesed käiks täis kõhu ja nimekirjaga poes, et osta vaid vajalikke asju ning ka kui süüa alles jäänud asjad ära. Hiina riiete osas võiksid inimesed mõelda kas neil päriselt on vaja raista oma raha riiete peale kohe kui näevad sooduspakkumisi.');
