INSERT INTO core.text(id, content)
VALUES ('b9676210-a1ae-4bbc-8c2b-92051789de49',
        'Inimesed raiskavad. See on juba mitmesaja-aastane fakt. Kuid miks see toimub? Kolm põhjust, miks raisatakse nii toitu, riideid kui ka raha on see, et see on neil juba harjumus ja nad usuvad, et ühe inimese panus ei tähenda suures pildis midagi.\nInimesed, kellel pole vaja muretseda mingite asjade puuduse pärast on alati neid samu asju raisanud. Kui kellelgi on piisavalt suur kogus piima, et sellest ei tekiks puudust, pole tal põhjust muretseda, kas piim saab otsa. Seetõttu raiskab ta seda mõtlematult. Tegelikkuses ei kehti selline olukord vaid piima kohta, vaid ka teiste toidutarvete ja ressursside kohta. Paraku on nii paljudes riikides, kus keskmine elatustase on kõrge. Sellistes riikides tihti ei mõelda, kui palju inimesed raiskavad.\nKui inimesed mõtlevad, kas visata kõlblikku toitu ära, mõtlevad nad vahel, et „mida see ühe inimese panus ikka teeb“. Tegelikult teeb see palju, kuid kui piisavalt palju inimesi teistmoodi arvab, siis on peaaegu võimatu nende kollektiivset arvamust muuta. Osad minu enda sõbrad on mulle ka öelnud, et see on põhjus, miks nad raiskavad toitu. Mina olen neile vastu vaielnud öeldes, et isegi see, kui üks inimene hoiab raiskamist kokku, tähendab keskkonnale väga palju. Aga tõsiasi see on, oleks kõige parem kui suurem osa või isegi kõik maailma elanikest peaksid piiri oma raiskamisega.\nKuigi on inimesi, kes on teadlikud oma raiskamisest ja hoiavad seda seetõttu kokku, on neid palju rohkem, kes seda ei tee. Eve Hanson on öelnud: „Ma arvan, et peaks hakkama noortele tegema ekskursioone taaskasutuspoodide lattu, et näidata, milline raiskamine tegelikult toimub.“ On võimalik, et see tõesti ärgitaks noortes ja lastes suuremat tahet mõelda oma raiskamise üle. See on meie ainus planeet, mistõttu me ei saa seda katta prügiga.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('b9676210-a1ae-4bbc-8c2b-92051789de49', 'title', 'Miks inimene raiskab?');
