INSERT INTO core.text(id, content)
VALUES ('df6a3055-13f1-4d42-a7d2-af0a3e10b7c6',
        'Tänapäeval visatakse ära väga palju toiduaineid ja riideid. Sellega me ei kuluta ainult enda , vaid ka teiste firmade ja tööstuste ressursse ja energiat ning see tekitab väga palju keskkonnaprobleeme.\nKõige rohkem toitu ja riideid kulutavad inimesed, kellel on rohkem raha. See on selle pärast, et nemad saavad kallimaid asju endale lubada. Väga paljud rikkad tahavad iga päev endale uusi riideid või muid tarvikuid osta, sest nad ei taha kanda sama riietust kogu aeg. Näiteks, käivad nad luksuslikes moepoodides ja ostavad kõike, mis silma jääb. Kui aga enam ei meeldi mingi asi, siis viskavad nad selle ära ning harva viivad taaskasutuspoodi. Sellest tekib väga suur energia- ja töökulu. \nInimesed, kes on vaesemad, oskavad hinnata rohkem poest saadud asju. Sest nad ei saa selliseid asju endale  kogu aeg lubada. Vahepeal saavad inimesed enda sugulastelt ja tuttavatelt riideid, mida nad enam ei taha või on väikseks jäänud. Tihti käiakse ka uuskasutuspoodides, sest sealt on odavam osta, kui tavapoodidest ning sealt leiab ka palju kvaliteetseid ja põnevaid esemeid ja ehteid ning on üldiselt parem keskkonnale.\nNoori peaks õpetama, kuidas olla taaskasulik ja viima ekskursioonile taaskasutuspoodide lattu, et näidata, milline raiskamine iganädalaselt toimub. Tänapäeval käib tegelikult päris palju inimesi taaskasutuskeskustes, ka mina käin vahepeal seal. Osad inimesed panevad oma vanad riided ka internetti müügile, kuid tavaliselt natuke kõrgema hinnaga kui taaskasutuskeskustesse. \nMe ei peaks riideid nii palju ostma ning ära viskama, vaid viima need taaskasutuskeskustesse või andma tuttavatele. Iga päev visatakse väga suurel hulgal riideid ja toiduaineid prügikasti ja see tekitab väga palju keskonnaprobleeme ja koormusi.');
