INSERT INTO core.text(id, content)
VALUES ('8d3022f6-efcf-4985-9137-1c50c4caaeea',
        'Tänapäeval jääb inimestel palju asju järgi – toidujäätmeid, riideid ja muud kaupa. Me ei väärtusta enam nii väga seda, mis meil on, sest teame, et kusagilt saab nii kui nii midagi vajadusel juurde või asemele. Tegelikult, isegi, kui jääbki miskit järele, oleks ju lithne näiteks viia oma kasutatud riided või esemed taaskasutusse või need kusagile annetada. Kahjuks aga ei tee mitmed sedagi, mis tähendab, et midagi peab muutma – aga kuidas?\nElame ajas, kus on pidev massitoodang ning tarbitakse vähem, kui toodetakse. Kasvõi keskmisel Eesti inimesel koguneb juba 61 kg toidujäätmeid aastas, millest 42% on toidukadu. Seetõttu ei raiska me mitte ainult raha, vaid ka Maa ressursse. Oleme oma halbades harjumustes nii kinni ja vahel ei pruugi isegi teada, et teeme kahju, mille pärast peakski sellele probleemile rohkem tähelepanu tooma.\nNiisiis, millised on mõned võimalused, kuidas vältida toidu raiskamist ja hoida meie elukeskkonda? On näiteks sellised ülilihtsad tegevused, mida saab iga inimene selleks teha: mitte hunnikutes toidukaupa osta, vaid ainult nii palju, kui sul on vaja ja oled kindel, et ära sööd või kui jääbki toitu järgi, aga see on veel kõlblik, siis mitte prügikasti visata, vaid kasvõi mõnele linnule toita – näiteks minu peres, maal olles, pannakse hommikusöögi jäägid varese kaussi, lisaks võiksid ka oma toidujäätmeid sorteerida. Tehes vähemalt neid väikseid asju säästame juba üsna korralikult nii oma raha kui ka keskkonda.\nRääkides moest, on ka selles valdkonnas sarnane probleem – toimub riiete massitoodang ja inimesed ostavad rohkem riideid kokku, kui nad tegelikult kannavad.  On mitmeid veebipoode, kus müüakse odavat kiirmoodi – näiteks SHEIN, Temu ja muud sellelaadsed. Ka mõned kauplustes olevad poed teevad sama. Muuseas ei kahjusta sa sellistest poodidest ostes ainult keskkonda, vaid aitad ka kaasa nende töötajate, kes nendes müüdavaid riideid pidevalt valmistavad, ebainimlikule kohtlemisele – neile makstakse väga väikest palka ning tihti nad peavad töötama kohutavates tingimustes.\nSellega jõuame küsimuseni – aga kuidas saaks keskmine Eesti inimene teha teisiti, kui riidepoed, kus ei toodeta kiirmoodi, on nii kallid? Vastus ei ole tegelikult nii keeruline: eelista kvaliteeti üle kvantiteedi. Kuigi odavad hinnad Hiina veebipoodides võivad olla meelitavad, usu mind, sealt ostetud riided kestavad sul heal juhul pidevalt kandes aastakese. Järelikult osta pigem nendest kallimatest riidepoodidest mõni kvaliteetne riideese, kui kiirmoe poodidest hunnikutes, sest niimoodi hoiad kokku oma raha ning säästad ka keskkonda ja ei aita kaasa inimeste väärkohtlemisele.\nKokkuvõtteks – muuda oma tarbimisharjutusi ning niimoodi hoiad iseennast, Maad ja ka selle inimesi.');
