INSERT INTO core.text(id, content)
VALUES ('066240a8-14d7-4565-904c-88ee3d6d1353',
        'Tänapäeva kapitalistlikus ühiskonnas läheb tihti meelest, et kõik need asjad, mida me ühekordselt kasutame ja mille me siis igavledes prügikasti viskame, liiguvad edasi vaid prügimägedele, et seal siis aastasadu, või isegi aastatuhandeid aeglaselt laguneda, samaaegselt meie loodust ja planeeti hävitades.\nIga aasta tekib ühe Eesti inimese kohta 61kg toidujäätmeid, millest pea pool on toidukadu ehk lihtsalt raisku läinud toit. Tihti ostavad inimesed poodi minnes liiga palju süüa ja ei jõua seda siis piisavalt kiiresti ära kasutada, lastes üleliigsel toidul külmkapis rikneda. Me ei raiska sellise käitumisega ainult oma raha, vaid ka vajalikke ressursse, mida sellel maailmal juba praegu ohtlikult vähe on: vett, maad, energiat ja tööjõudu.\nRiiete valmistamine kulutab väga palju ressursse, eriti tänu kiirmoekettidele, nagu näiteks H&amp;M. Riideid valmistatakse mõeldes pigem kvantiteedile, kui kvaliteedile, mis tähendab, et kulutatakse palju ressursse rõivaste peale, mis ei kesta kaua. See on tootjate poolt läbimõeldud valik. Riiete halb kvaliteet, kiire kulumine ja maitsetuks muutumine sunnib meid aina uusi riideid ostma ja seega ka rohkem raha kulutama. \nInimesed ütlevad, et nende isiklikud harjumused või nende harjumuste muutmine, on laiemas perspektiivis ebaolulised. Muutus aga algab siiski inimesest endast. Soovides seda maailma päästa, või vähemalt veidi kauem elus hoida, peame me kõik enda käitumist ja harjumusi parandama: vähem raiskama, vähem tarbima ning rohkem hoolima oma planedist ja selle elanikest.');
