INSERT INTO core.text(id, content)
VALUES ('714f244e-7f30-4bcb-8d74-560e1e2d8236',
        'Tänapäeva ühiskonnas on mõttetu ja liigne tarbimine muutunud tavaks. Riietest kuni toiduni, raiskavad inimesed liiga palju.\nInimeste tarbimisharjumused on mõne saja aastaga palju muutunud. Vanasti hinnati igat toitu ja riideeset, kui riided läksid katki, tehti nad korda ja kasutati uuesti ja toitu ei jõudnud keegi raisata, kuna raha lihtsalt oli vähem. Tänapäeval tekib iga Eesti inimese kohta keskmiselt 61 kg toidujäätmeid, kuigi puhta toidu osa sellest on väiksem, umbes 26 kg ehk 42%, on see arv väga suur ühe inimese jaoks. Need arvud võtavad ka arvesse ainult kodumajapidamisi ja ei arvesta asustustega, nagu poed või koolid. Tihti näen ma koolis täiesti kõlbliku toitu, mida visatakse ära kuna see ei meeldinud või ei jõutud seda ära süüa.\nInimesed ei tarbi üle ainult toitu, ületarbimine koosneb mitmest erinevast komponendist. Nendest üks suurimaid on riiete raisk. Ei osteta enam riideid vajaduse pärast vaid siis, kui tahetakse. Nähakse sooduskampaaniad ja mõeldakse, et peab ostma muidu jään ma ilma. Eelistatakse kvantiteeti kvaliteedi üle ja ostetakse odavaid riideid Hiinast, milles on ebamugav käia ja lähevad katki kiiresti. Seda probleemi aitavad taaskasutuspoodide olemasolu, kuid see ei muuda riiete kasutavust ja paljud riideesemed lähevad siiski raisku. Tihti näen ma kasutatud riietehunnikuid nii poodides kui ka inimeste kodudes, kus nad seisavad kasutuseta.\nÜletarbimise jaoks on vähe lahendusi. Tuleb harida inimesi selles, kuidas vähem toitu raisata ja riietest rohkem elu välja saada. Pärast seda saab ainult loota, et inimesed on nõus oma harjumusi muutma.');
