INSERT INTO core.text(id, content)
VALUES ('27b93cc5-53f9-435e-8c23-e8cbecebbd9f',
        'Paljudel inimestel on probleem tarbimisega. Inimesed ostavad palju rohkem, kui nad tarbida suudavad. Tänu sellele raiskavad inimesed väga palju toitu ja inimesed, kes tegelikult nälgivad, jäävadki nälgima.\nÜletarbimis probleem pole seotud ainult toiduga, vaid ka riiete, asjade ja palju muuga. Inimesed, kes saavad endale rohkem lubada ei suuda enam asjadega ümberkäia, kuna neil on niigi palju asju ja nad ei saa kõigele korraga tähelepanu panna.\nOn ka probleem, et on inimesi, keda ei huvitagi palju nad raiskavad, kuna neil on hea olla ja neid ei huvita kuidas teised elavad. Inimesed võiksid rohkem sellest probleemist ülemaailma rääkida näiteks koolides, festivalidel, kirikutes ja paljudes teistes kohtades, kuna muidu ei jõuagi inimestele see info, et ületarbimine on väga suur probleem ja niikuinii paljud inimesed ei taha selle jaoks midagi teha, aga see paneks mõnegi inimese rohkem mõtlema selle üle ja see mõte võib juba tervet maailma muuta.\nSellepärast ma arvangi, et ületarbimine on väga suur probleem, sest inimesed ei pööra sellele tähelepanu ja peavad niikuinii lõpuks selle kõige sees hakkama elama, kuna ületarbimine hävitab loodust metsikult ja loodus on meie kõigi ümber. Linnas muutub reostus samamoodi palju hullemaks ja tänu sellele tekib ka rohkem haigusi, mis võivad tulevikus terve ühiskonna ära hävitada.');
