INSERT INTO core.text(id, content)
VALUES ('73879dfb-e20e-4846-84ec-9bd1ae9a2928',
        'Tänapäeval me elame maailmas, kus enamus inimkonnal on võimalik soetada peaaegu kõike, mida hing ihkab. Kättesaadavuse tõttu oleme inimestena hakanud tarbima aina rohkem ja rohkem, kuid sellega kaasnevalt on suurenenud ka jäätmete hulk, mis satub prügimägedele. Mida on aga üldse võimalik teha, et inimestena tarbida keskkonda säästvamalt?\nÜks probleem, mis on hetkel väga kajastatud, on riideesemete raiskamine. Nooremate inimeste juures olen taibanud nendega rääkides ja harjumusi pealt vaadates, et iga uue stiiliga on neil tunne nagu oleks vaja eelmise nädala riided ära visata ja uued osta. Kahjuks on ka enamused kättesaadavad odavad riided tehtud naftast, mis on enamjaol kehva kvaliteediga ja ebamugavad. Kui riided on  halva kvaliteediga, lagunevad need ka  lihtsalt ja tekivad jäätmed. Olles külastanud Lilleküla ringmajanduskeskust sain ka lisaks teada, et Eesti piires riidejäätmetel on kurb lõpp: need viiakse matmisele. Riiete rohelisemaks tarbimiseks on aga mitmeid lahendusi: mitte osta uusi, kui vanad on korras, parandada neid või teha nendest hoopis midagi uut. \nSageli on ka inimestel kiindumus arvata, et toidu on veel ja see ei saa otsa. Sellega kaasnevalt viskame tihti ära ülejäänud või tähtaega ületanud toidu, kuna arvame, et ühe inimese prügi ei mõjuta suurt pilti. Kahjuks on see arvamus kaugel tõest. Tarbi toitu targalt veebilehel öeldud, et kodumajapidamises tekib iga Eesti inimese kohta 61kg toidujäätmeid. Samuti olen ma kooli sööklas märganud, et õpilased võtavad suurema koguse toitu, kui nad suudavad ära süüa ja viskavad järele jäänud toidu minema. Lisaks sellele, et tekib palju jäätmeid, on ka toidu tegemiseks kulutatud palju ressursse, mis on läinud raisku. Toitujäätmeid saab aga väga lihtsalt vähem tekitada: osta nii palju toiduaineid, kui on päriselt vaja, võtta selline portsjon, mille päriselt ära sööd ning vaadata toitude parim enne kuupäevi, et need enne roiskumist ära tarbida.\nHetkeses ühiskonnas tarbivad inimesed nii palju, et tekib väga palju jäätmeid. Siiski  on olemas võimalused, kuidas teha meie tarbimisharjumused keskkonnasäästlikumaks. Riiete puhul kanda neid, mis juba olemas on, neid parandada ja neist luua midagi täiesti uut. Toitu tarbides osta nii palju kui on vaja, mitte võtta liiga suuri koguseid ja vaadata kuupäevi, et õigeaegselt ära kasutada.');
