INSERT INTO core.text(id, content)
VALUES ('e3e548bf-4f1d-4cd8-97ca-189fc30ba5b4',
        'Tutvustan teile täna arutelu miks on vaja hoida mõõdukat piiri oma igapäeva tarbimistel ning mis on nende tagajärjed. Inimesed on tänapäeval päris ükskõiksed kui jutt tuleb igapäeva tarbimistest. See tähendab et kui nad midagi tarbivad igapäev ja ei suuda sellel mõõdukat piiri hoida siis võib nii juhtuda, et talle vaatavad otsa väga rängad tagajarjed. Näiteks kui inimene proovib mingi sugust meelemürki ei pruugi see teha midagi kui ühekorra proovida, kuid ta peab arusaama, et see võib ta viia väga halvale teekonnale ja tavaliselt see teekond saab päris kiirelt läbi. \nKui inimene peaks aru saama, et tagajärjed on karmid siis ta lõpetab selle tegevuse ära. Kuid alati ei ole selline situatsioon kui inimene on kasvõi ühekorra proovinud mingi sugust narkootilist ainet on ta selle tunde omale meelde jätnud ning võimalus, et talle võib see tunne ükspäev meenuda on päris suur. See jäärel hakkab tal selline mõtte peas jooksma et „ah mis see ikka teha võib“  mul on teile vastus olemas see tekitab inimese elust kaose. Kui inimene ei ole mentaalselt tugev on lood halvasti, ta teeks ükskõik mida, et seda tunnet jälle kätte saada, ning need viisid ei ole alati kõige ilusamad. Alguses võivad jallegi olla sellised variandid kus küsitakse oma lähedastelt raha, kuid kui inimesed ta ümber saavad aru mille peale ta seda raha raiskab siis võivad need viisid koledamaks muutuda kuna kellel on soovi oma lähedast pealt vaadata kui ta parasjagu oma elu ära raiskab rääkimata veel seda rahastada.\nKahjuks on meil selliseid inimesi tänapäeval ühiskonnas palju mõnel isegi oma enda perekonnas, ning seda on veel kurvem vaadata kui sa näed mida võib ühekordne kasutus teha keerata inimese elu täielikult tagurpidi. Järelduseks võime öelda, et tuleb oma lähedaste eest hoolitseda vahepeal nendega ka natuke tõsistemadel teemadel arutada ning oma igapeva tarbetel piiri peal hoida.');
