INSERT INTO core.text(id, content)
VALUES ('68d00138-f853-4632-95d3-b700ad77c11f',
        'Inimene tarbib midagi iga päev, iga päev me sööme toitu, kanname rõivaid, kasutame erinevaid hügieenitooteid ja palju muud. Nimekiri asjadest, mida me tarbime, on lõputu. Kas see on hea et me nii palju tarbime? Meil on vaja tarbida iga päev et ellu jääda, aga kust läheb piir, kus me tarbime rohkem, kui meil tegelikult eluks on vajalik?\nTõsi on, et inimesed vajavad toitu et ellu jääda, aga me tihti ei märka seda, et me tarbime toitu ja toiduaineid rohkem, kui meil tegelikult vaja läheb. Toit ja toiduained on muutunud viimase paari sajandi jooksul aina rohkem kättesaadavamaks. Tänapäeval, võib igaüks minna oma lähimasse toidupoodi ning osta sealt just neid toiduaineid, mida tema tahab. Kuna toit ja toiduained on nii kergelt kättesaadavad, ostame me tihti rohkem, kui me ise jõuame ära tarbida, millele kaasneb see, et me peaaegu iga päev viskame toitu või toiduaineid ära. Me viskame toitu ja toiduaineid ära, iga kord kui need kas riknevad, kui nende kasutustähtaeg saab läbi, või kui me lihtsalt ei jaksa rohkem süüa. See liigne toidu ära viskamine tekitab rohkem prügi ning me raiskame ka rohkem ressursse, mida kasutatakse toiduainete kasvatamiseks ja tootmiseks. Toidu liigne ära viskamine on probleem, mis on saanud harjumuseks peaaegu igale inimesele ning millel on keskkonnale halb mõju.\nVeel üks ületarbimise näide on riiete ületarbimine, meil kõigil on riided, mida me iga päev selga paneme. Kahjuks aga ostame me tihti rohkem riideid, kui me ise vajame. Riideid saab tänapäeval internetist ning taaskasutuse poodidest osta väga odava hinnaga, millele kaasneb aga see, et me ostame pigem rohkem riideid, kui kvaliteetseid riideid. Need ebakvaliteetsed riided võivad mõjuvad halvasti nahale ning neid on ebamugav kogu aeg kanda. Riideid visatakse ka väga tihti ära, kui arvatakse et neid ei hakka enam keegi kandma. Riiete ületarbimisele kaasneb ka riiete ületootmine, mis põhjustab materjalide raiskamist ning mõndades illegaalsetes tehastes kasutatakse ka lapstööjõudu. Riiete ületarbimine on tõsine probleem, millest on raske saada lahti, kuna inimesed saavad rahuldust kui nad ostavad riideid mis neile meeldivad.\nÜletarbimine on tänapäeva ühiskonnas üks kõige levinumaid ning tõsisemaid probleeme. Ületarbimine põhjustab ka ületootmist, mis toob tõsist kahju keskkonnale. Inimesed on harjunud sellega, et see pole probleem osta rohkem, kui sa tegelikult vajad ning inimesed on valmis ostma väiksema hinna eest mittekvaliteetsemaid tooteid, kui natukese kõrgema hinna eest vastupidavaid ja kvaliteetseid tooteid. Toidu ja toiduainete ületarbimine ning ära viskamine on kõige levinud ületarbimise viise, igas kodus visatakse meeletult palju toitu ära ning kõik see toit läheb lihtsalt raisku. Inimesed ostavad rohkem toitu, kui nad jõuavad ära tarbida ning sellele kaasneb ka toidu ületootmine. Riiete ületarbimine ja ületootmine on samuti kolossaalne probleem meie tänapäeva ühiskonnas. Paljud inimesed eelistavad kvantiteeti üle kvaliteeti ning sellepärast ostavad inimesed pigem palju odavaid rõivaid, kui vähem aga kvaliteetseid rõivaid. Ületarbimisele tuleks pöörata rohkem tähelepanu ning pole üldse hilja selle probleemiga tegeleda ning vähendada ületarbimist ning ületootmist.');
