INSERT INTO core.text(id, content)
VALUES ('8a8fd51a-432c-457b-a422-16e47dbe8c36',
        'inimesed eelistavad aina rohkem kvantiteeti üle kvaliteedi, seda on näha ka selles, kuidas suured korpuratsioonid toodavad aina rohkem tooteid, mille hinnad on madalad kuid toote kvaliteet on nähtavalt kehvem. Mina arvan, et proobleem on ka selles, kuidas taaskasutus on muutunud moeks.\nHumana on viimasel ajal üks väga populaarne poekett, mille bränd on ehitatud taaskasutusele üles. Tean inimesi organisatsioonist Fridays For Future, kes tegelevad looduskaitsega, nad on rääkinud sellest, kuidas Humana on üks paljudest brändidest, kus kaup, mida ära ei osteta, viiakse prügimäele. Taaskasutuse eesmärk pole enam loodussäästlik, vaid on muutunud suuremaks liikumiseks, inimesed tahavad endale palju asju ja odavalt, mis põhjustab suuri korpuratsioone tootma täpselt seda. Tava inimesele, kes päriselt soovib olla säästlik on aina raskem leida kohti, kust endale tarbeid leida sest, nagu eelnevalt näha, on brände, keda sa ei eeldaks, et nad panustavad reostusesse.\nMinu enda sõbrad on öelnud, et nad ei uuri seda põhjalikult, kuna ei taha jääda internetis moest maha. Samal konverentsil, milles rääkis FFF-i liige taaskasutuse eesmärgist, räägiti ka sellest, et internet on meie tarbeharjumusi väga tugevalt mõjutanud. Me näeme midagi populaarset ja meil on seda vaja, brändid toodavad seda kiirelt ja odavalt, kuni tuleb uus mood ning on vaja uusi asju. \nTarbimisharjumused on tugevalt seotud inimkonna tahtega, moega kaasa liikuda, kuid on selge, et see pole jätkusuutlik ja on oluline seda teadvustada ning sellest rääkida.');
INSERT INTO core.text_property(text_id, property_name, property_value)
