INSERT INTO core.text(id, content)
VALUES ('5972ae4c-2cf3-4656-a9ce-c13427b0122d',
        'Noortel on saanud aina enam harjumuseks ületarbimine. Mida rohkem riideid kapis on seda ägedam ja moekam sa oled. Normaliseeritud on iga kuu uhiuusi riideid osta. Kõik see paneb mind mõtlema, kas on mõtekam osta soodsalt kiirmoe poodidest või investeerida kodumaisetesse riietesse?\nMõnda aega tagasi nägin pidevalt, kuidas sotsiaalmeedias oli populaarseks saanud soodsatest hiina e-poodidest tellitud riiete lahti pakkimis videod ehk haulid. Nendes videodes kajastatakse väga hästi ületarbimist. Inimesed ostavad kilode kaupa riideid, mõtlemata nende riiete materjalile või kuidas need tehtud on. Popp on see kui sul on kappp riideid täis, ning oluline on see, et neid oleks palju, mitte see, et neid saaks pikalt kanda ja oleks kvaliteetsed. Moedisaineri Eve Hansoni sõnul on oluline, et igaüks vaataks üle oma tarbimis harjumused ja eelistaks kvaliteeti kvantiteedile.\nTeiselt küljelt märkan ma ka neid noori, kes tõesti proovivad säästa keskkonda ja jälgida oma tarbimisharjumusi. Noored jälgivaid üha rohkem kodumaiseid disainereid, näiteks nagu Reet Aus, kes põimub oma töödesse taaskasutuse ja näitab noortele, et taaskasutus on moekas ja äge. Taaskasutuspoodidest saab osta sama raha eest riideid,mis on kvaliteetsemad, kui kiirmoe poodidesst, kus riided \nArvan, et mina hakkan tulevikus rohkem mõtlema oma tarbimis harjumusi ja ostlemas taaskasutuspoodides. Aeg-ajalt viskan pilgu peale ka Eesti disaineritele ning räägin kindlasti oma sõpradele nendest.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('5972ae4c-2cf3-4656-a9ce-c13427b0122d', 'title', 'Moedisain: kas valida kvaliteet või kvantiteet?');
