INSERT INTO core.text(id, content)
VALUES ('b28c33e4-615c-417c-a7bf-0ccf0e191ebc',
        'Sellest ajast kui toit hakkas saama rohkem kätte saavamaks, kui kunagi varem hakkati seda rohkem raiskama. Tänapäeval ei ole enam 90% inimestest talupoiad, kes proovivad elu jääda sellega, mis neil on.\nToiduraiskamine tuleb sellest, et me saame endale lubada rohkem toidu kui kunagi varem. Kuna toit on järjest soodsamaks läinud siis oleme hakkanud ostma maitse järgi toitu ja enamus inimesed ei käi igapäev poes, et osta täpset nii palju, kui nad täna tahavad. Ostetakse kuskil üks kord nädalas või rohkem kõik ette. Sellega kaasneb see, et ei teata kui palju nad millal söövad või tuli midagi ette ja söövad kusgil muial, millega jääb see toit kõju mädanema.\nKõik toitujäägid mis üle jäävad ei pea minema põletamisele. Toitujääkidest saab teha väätist, mis oleks kasulik taimedele aga mille jaoks on vaja komposti kasti. Kui sa elad kitsas korteris linnas siis saab leida sõpra kellel pole midagi selle vastu, et sa tood või ta toob jäägid tema komposti kasti kord kuus. Toitujääkidest saab teha väätist, mis oleks kasulik sinule või sinu sõprale.\nKui me tahame toiduraiskamist vähendada siis tuleb alguses plaanida ette, kas on mul on vaja seda või tahan ma seda. Toitujääkidest ei saa kõik ära jätta, ikka tuleb ette. Toidu jääkidest saab teha midagi kasuliku ja mitte lihtalt ära visata.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('b28c33e4-615c-417c-a7bf-0ccf0e191ebc', 'title', 'Toidujääkide vähendamine');
