INSERT INTO core.text(id, content)
VALUES ('1a56721f-3b5b-4f00-b806-87bc66b09323',
        'Tänapäeval tarbivad inimesed väga paljusid asju, aga mitte lõpuni. Tänu sellele on meil maailmas tekkinud suur hulk jäätmeid, mida enam ei saa kasutada. Kõige suuremateks probleemideks nende seas on saanud riiete mitte lõpulik kandmine ja toidu raiskamine. See on probleem, millega peame tegelema kõik koos, see ei kao üleöö.\nToitu visatakse ära kogu aeg, kas kodus, koolis või restoranis. Arvatakse, et see ei mõjuta meie elu, aga pikas perspektiivis mõjutab küllalt. Tulevikus võib sellepärast tekkida toidu hankimisega probleeme, nagu ka kunagi kauges ajaloos. Inimeste jaoks on toiduraiskamine normaalne, kuniks seda saab liiga palju. Sellest järeldades pole ära visatud toitu pole võimalik ümber töötleda, mis teebki sellest suure probleemi.\nRiideid on võimalik taaskasutada, aga seda tehakse vähe. Enamus inimesed kannavad riiet mõned korrad ja viskavad selle ära, millega ei mõelda tagajärgedele. Paljud noored inimesed tellivad oma riided Hiinast, teadmata mis materjalist need tehtud on. Hiinast tellitud tooted on küll odavad, aga halva kvaliteediga, mida on ebamugav kanda.\nKokkuvõtteks muudavad kõige rohkem meie elukeskkonda tarbimisharjumused. See on globaalne probleem, millega ei tegeleta piisavalt. Suurtemateks raiskamis valdkondadest on toit ja tekstiilesemed. Ära visatud toitu pole võimalik ümbertöötleda, aga tekstiilesemeid on võimalik taaskasutada või ümber teha teiseks tooteks. Meie tarbimisharjumused mõjutavad meie tuleviku.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('1a56721f-3b5b-4f00-b806-87bc66b09323', 'title', 'Tarbimisharjumused mõjutavad meie elu keskkonda');
INSERT INTO core.text_property(text_id, property_name, property_value)
