INSERT INTO core.text(id, content)
VALUES ('06bc6b0a-3bbc-425e-a357-3f06876d4c01',
        'Tänapäeval on suur probleem tarbimisharjumuste üle, inimestele meeldib osta uusi asju, kui näevad kuskil reklaame või sooduskampaaniaid. Inimesed ei mõtle emotsioonioste tehes, kas see asi saab hiljem ka kasutust või mitte. Tekib küsimus, miks inimesed raiskavad oma raha asjade peale mida nad hiljem ei kasuta, või viivad taaskasutuskeskusesse korraliku ja kasutamata eseme.\nMa toon enda elust ühe väga hea näite, ma lähen sõpradega linna ja näen sooduskampaaniat või midagi mis mulle meeldib, ning mul kohe vaja seda minna proovima, kui on hea hind siis tavaliselt ma ostan selle ilma mõtlemata kas see saab ka kasutust või jääb kappi seisma. Nii teevad ka palju inimesed tänapäeval, millest tulenebki probleem.\nInimesed raiskavad oma raha enamasti emotsiooniostu pärast, on ka olukordi kus tõesti mõtled, et seda on vaja, aga hiljem jääb ikka seisma. Kui asi on terve ja korralik siis saab mingi lahenduse leida, et asjad niisama seisma ei jääks, näiteks: anneta kuhugi, anna lähedastele, pane müüki, leia mõni teine viis kuidas see asi saaks kasutust. Hanson tõi välja väga hea näite: ‘’Ei telliks Hiina veebipoodidest juba põhimõtte pärast asju, ei läheks kaasa sooduskampaaniatega.’’ Väga palju inimesi kahjuks läheb kaasa Hiina veebipoodide sooduskampaaniate ja reklaamidega, millest tulevadki probleemid tarbimisharjumuste üle. \nMina ise peaksin rohkem mõtlema asja kasutusele enne kui seda ostma hakkan, kui mul tõesti ei ole seda asja vaja, siis pole mõtet raha raisata. Las ostab keegi teine selle asja, kes päriselt hakkab kasutama seda, mitte ei jäta seisma ja ootama hetke millal see viiakse taaskasutuskeskusesse. ’’Eelistada võiks kodumaiseid oma lähedal toodetud asju ning pigem vähem kui rohkem.’’');
