INSERT INTO core.text(id, content)
VALUES ('057a5502-3c95-4a05-b03c-9029e219d451',
        'Sissejuhatus: Inimised kodumajapidamises tekib iga aasta umbes 61 kg toidujäätmeid, Millest toiudkadu moodustab 42% ehk siis 26kg. Toidukadu on siis ikka raisatud toit ja toit mis on läinud üle enda säilimis kuupäeva. Miks inimsed raiskavad toitu?\n Teemaarendus: Inimsed raiskavad toitu sellepärast, et nad arvad, et nad saavad osta koguaeg toitu juurde. On ka inimesi kes saavad endale toitu lubada nii palju, et nad ei oska sellegiga midagi teha. Iga inimese kohta igas kodumajapidamises tekib vähemalt 61kg toidujäätmeid. Mis toidud jäävad tarbimata ja lihtsalt visatatakse toit biojäätmese ära või kui inimesele ei meeldi see toit siis ta viskab terve toidu minema mis tekitab rohkem biojäätmeid kui poolik toit.\nInimsed raiskavad toitu sellepärast, et nad arvad, et toit tuleb lihtsalt kätte ja nad ei pea midagi tegema ja kui nad peaksid siis nad saaksid aru kui raske on tegelt seda kasvatada ja hooldada. Kui me toodame väga palju toiduained ja toitu siis see võib tekkitada keskonnale tõsiseid probleeme. Me ei saa vähenda toidu raiskamist kuna rohkem kui pooled inimsed on kinni oma vanadses harjumustes.\nKokkuvõte: Inimsed raiskavad toitu ja nad tekitavad iga aasta 61kg iga inimese kohta. On ka inimesi kes saavad lubada endale väga palju toitu ja sealt võib minna pool raisku kuna nad lihtsalt ei jõua seda kõike ära süüa. Inimsed raiskavad toitu sellepärast, et nad arvad, et toitu on lihtne kätte saada ja nad veel arvavad, et meil on seda väga palju. Mõned inimesed on kinni oma vanades harjumustes.');
