INSERT INTO core.text(id, content)
VALUES ('de2c3580-9158-4ff0-bfd2-5d0895263ea8',
        'Tänapäeval, on suureks probleemiks raisku läinud kaup. Kõige rohkem tähelepanu, tuleks pöörata aga raisku läinud riiete ja toidu peale. Maailmas on palju inimesi, kes elavad näljas ja ilma korralikude riieteta. Inimesed peavad vähem tootma kaupa mis läheb raisku. \nInimeste tarbimisharjumused on kehvad. Nad toodavad liiga palju kaupa, mis läheb kõik raisku selle asemel, et see jõuaks hädavajalisteni. Hiinas toodetakse mitmeis tehases suures koguses kaupa, mis on küll odav, aga halva kvaliteediga. Mu sugulane on sõltuvuses odavate Hiina toodetega ja nende äppidega, kust kaupa saab tellida. Mu sugulase ema räägib alati kuidas umbes pooltest riietest, mis ta sealt ostab, kannab ta ainult ühekorra.\nKui inimesed kahandaksid mõttetute kaupade tootmist, siis ei läheks niipalju raha, aega ja resursse raisku. Võibolla, aitaks see isegi kliimasoojenemis ja reostus probleemidega. Hiinas on osad linnad, mis on reostust täis ja õhukvaliteet on madal. See on peamine tehaste asukoht, kus nad toodavad odavat kraami. Kui nad vähendaksid tootmist, siis kindlalt läheks õhukvaliteet paremaks ja inimesed oleksid õnnelikumad. Mu isa omab tehast lasnamäel ja ta tootis hulganisti kaupa, mis läks raisku. Ta otsustas, et toodab vähem kaupa, ja ainult seda kaupa mis müüb hästi. Tagajärjeks olid ta laoruumid tühjemad ja ta säästis hulganisti raha selle pealt.\nJärelduseks Inimesed võiksid avada oma silmad ja näha, mis halvad tarbimisharjumused nende maale teevad. Inimesed ise tapavad maad kõige selle raisku läinud kauba, ressurside ja rahaga. Loodetavasti inimesed lõpetavad selle hullu tootmise ja kauba raiskamise ja siis võime isegi loota, et maakeral elu ei kao paarisaja aastapärast.');
