INSERT INTO core.text(id, content)
VALUES ('775a0ba0-0a5c-4bc6-adcd-0ab1dda66067',
        'Inimesed raiskavad liiga palju toitu ja ostavad asju kaugelt mis tekkitab palju reostust.\n Eestis iga inimese kohta tekkib umbes 61kg aastas toidujäätmeid, millest toidukadu moodustab 42% ehk 26kg see on liiga palju minu arvates, inimesed arvavad et kui nad viskavad natukene toitu ära siis see ei tee midagi, aga kui iga üks inimene raiskab veidike toitu siis see on tegelikult väga suur arv.\nInimesed tellivad liiga palju asju hiinast, mis nad viskavad ära veidike aja pärst see on lihtsalt raha raisk kui sa viskad selle ära pärast veidike aja kandmist, või kui inimesed ostavad mingit asja mida nad ei kasuta kunagi või neil polnudgi seda tegelikult vaja.\ninimesed viskavad oma riided ära väga kergesti tänapäeval, sest on kerge osta või tellida uusi riideid, ja riided on soodsamaks ka läinud tänapäeval aga halva kvaliteediga riideid pole mõtet tellida hiinast, sest need on arvatavasti halb kanda, kas ebamugavad või lihtsalt ei sobi, ja siis nad viskavad selle lihtsalt ära või viivad need taaskasutus pooditesse.\nKv\nVähem riideid peaks tellima, sest sa veel ei tea kuidas sulle meeldivad need ja kui ostad toitu, siis peaksid ostma nii palju kui sa ära sõõd pole mõtet raha raisata toidu peale kui sa lihtsalt viskad selle ära.');
