INSERT INTO core.text(id, content)
VALUES ('b90ecd06-80e9-4934-9d24-74ad7c1c6f60',
        'Toiduraiskamine on vägagi globaalne probleem. Seda esineb sageli koolides. Ka mujal maailmas on toiduraiskamine aktiivne probleem. Võetakse liiga palju toitu ja ei sööda ära, ostetakse liiga palju ja enamus rikneb, või tehakse toitu liiga palju ja ei tarbita ära. Toiduraiskamine on halb ja seda tuleks vähendada.\nOn inimesi kelle arvamus ei muutu toiduraiskemisel, nad lihtsalt viskavad toitu ära sest nad saavad seda omale lubada. Või siis ostavad liiga palju ja ei tarbi seda kõike ära. Nad justkui ei pea tähtsaks probleeme mis sellega võib kaasneda. Paljutel peredel on raske toime tulla rahaliselt ning ei suudagi omale süüa osta. \nMe raiskame toitu vahest isegi teadmatult, ostame liiga palju ja ei tarbi kõike ära. Nagu ka koolis on tahtmatu raiskamine. lapsed võtavad liiga palju ja viskavad kõik ära ning hiljem tulijatel pole enam piisavalt toitu. Või tuleb mingi suurem pidustus kus tehakse palju süüa, aga kõike ei sööda ära.\nSellise probleemiga tuleks tegeleda ja olla rohkem vastuvõtvamad kui tahetakse teadvustada seda probleemi meile. selle lahendamiseks on mitmeid viise. Ei pea kohe alustama riigi tasandist, tuleks kõigepealt alustada pere ja kodu tasandist. Teha ostunimekirju kui poodi minna, osta nii palju kui ära söödakse, kui mingi toote kehtivus kuupäev hakkab lähenema, proovi kõigepealt sellega midagi teha. Riigi tasandil on juba võetud ette sellega midagi ja on tehtud toidupangad.');
INSERT INTO core.text_property(text_id, property_name, property_value)
