INSERT INTO core.text(id, content)
VALUES ('380ffc4f-156c-4757-9d04-13afe2a95ea5',
        'Tarbimine on meie maailmas väga suur osa ja kõik inimesed tarbivad erinevaid asju. Kõige lihtsamaks näiteks võib tuua riided ja toidu, Kuid see pole kõik. Neid asju mida tarbitakse on tegelikult palju rohkem kui inimene jõuab üldse ette kujutada. Kuid tarbimine on tegelikult maailmas väga suur probleem. Aga miks see nii on?\nMaailmas on tohultult palju inimesi ja kõikidel on enda kombed ja tavad. Samuti on ka kasvatus igas peres, suguvõsas ja riigis väga erinev. Kuid aga on probleem väga suur kuna kõik inimesed maapeal tarbivad liiga palju. \nEnamus inimesi on harjunud sellega, et kui kõik toit ei saa otsa siis viskavad nad selle toidu ära. Ning ka sellega, et kui näevad kusagil Hiina netipoes midagi väga odavat siis nad kohe ostavad selle ja kui see kohale jõuab siis nad isegi ei kasuta seda regulaarselt vaid kannavad korra ja peale seda jääb see kappi seisma või visatakse ära.\nSelle asemel, et üleliigset toitu ära visata, saab teha erinevaid asju sellega. Kui järgmisel päeval on piisavalt toitu üle, siis saab selle teha soojaks ja süüa uuesti. Või siis saab võtta selle sama toidu ja teha midagi muud huvitavat sellest. Lisaks on võimalik jagada seda toitu inimestega kellele pole toit rahalistel põhjustel nii lihtsasti kätte saadav.\nSelle asemel et osta kusagilt Hiina veebipoest odavat  „fast fashion“-it mis võib olla tohutult halva kvaliteediga ja võib olla väga ebamugav ja mille sa viskad niguinii suht suure tõenäosusega suht kohe ära, saab osta hoopis kusagilt lähedamalt ja natuke kallima hinnaga palju kvaliteetsema riideeseme mis võib kesta kuid ja aastaid. Samal ajal kui hiina kaup kestab paar nädalat või päeva ja juba võib olla sellel auk sees  või õmblused lahti.\nKokkuvõtteks võib õelda, et on olemas palju paremaid valikuid mida saab enda üleliigsete asjadega teha. Ja on olemas palju paremaid kohti kust enda asju soetada. Isegi kui võib olla mingi kvaliteetsem asi kallim kui mingi Hiina asi. On see ikkagi seda hinda väärt ja kestab palju kauem. \nKokkuvõtteks on väga palju teisi valikuid mida sa');
