INSERT INTO core.text(id, content)
VALUES ('58b542d5-4bc1-4967-8e45-526ee18d5813',
        'Mina kui ka teised inimesed, kes tarbivad asju räägiksin ma probleemitest, mis võivad sellga kaasneda. Algatuseks, mis inimesed teevad on ostavad asju külmkappi ja ei vaata teiste asjade kuupäevi ja nii peavad nad üle poole asjade ära viskama, kuna nad kas ei teadnud kaua veel see kestab või  nad lihtsalt ei tahtnud enam seda tarbitada.\nJärgmiseks probleemist mis ma prooviks on sama asi nagu toidu ära viskamine aga teist. Ma mõtlen riiete ära viskamisest ja kuidas me võiks mingit toetust teha teisele inimeste ühiskonnas ja ma loodan, et see aitab neid.\nLisaks me ei raiska neid asju raiskame veel teisi asju peale nende. Näiteks viskame ära vanu riideid, mis meile ei sobi, on juba ära kulunud või see on juba väikseks jäänud ja inimesed lihtsalt viskavad ära või annavad kasutatud riide poedele, mis on nende poolest väga mõistlik ,et nii saavad teised inimesed need lõbuni ära kasutada või saavad soetada enadale soodsamalt kui täista uuelt, kus teistes poodites on.\nKokkuvõtteks ma ütlen, et ma prooviks sama moodi teisi inimesi aitada oma riiedega. Ma loodan, et inimesed saavad tulevikus aru, et toidu raiskamine ei ole hea nendele ja tervele ühiskonnale. Ma loodan, et minust saadakse aru mida ma üritan siin öelda.');
