INSERT INTO core.text(id, content)
VALUES ('c9b1cb0b-999c-4136-84f2-2b962737b116',
        'Raiskamine on üks suur teema ja see ei kehti ainult toituga vaid ka asjatega. Seda on tulnud kohutavalt juurde ja mõned ei sa sellest aru. Inimesed viskavad enda riided ära ilma, et anda neile uuskodu ja raiskavad toitu lastes sellel minna halvaks.\nInimesed on läinud ükskõiksemaks, nii toitu kui ka asjatega. Seda on näha, sest raiskamist on ainult rohkem ja rohkem. Nooremad tellivad ka nüüd Hiina kaubamajadest ,aga selle asemel võiks nad minna taaskasutuspoodidesse aga ei pigem noored ikka tahavad uuemaid asju või siis brändiriideid aga mõeldes tuleviku peale on taaskasutus palju parem, kui uus Calvin Kleini särk. Kui õpetaksime rohkem noortele, miks peab taaskasutadama, siis oleks meil kui ka neil suurem tõenäolisem parema tuleviku jaoks.\nUuringute järgi näitab, et kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid. Seda on liiga palju ja seda tuleks vähendada aga seda ei saa lihtsalt üleöö teha. Tuleks alustada väikselt ja siis oleks juba see arv palju väiksem. Alustame näiteks sellest, et õpetame noortele, kuidas kasutada kõik kodus olevad ostutarbet ära või siis kuidas planeerida oma nädala toitu, et oleks võimalikult vähe toitu raiskamist. See oleks juba hea algus parema tuleviku jaoks.\nInimesed peaksid mõtlema paar sammu ette, sest iga väiksem samm viib meid parema tuleviku poole. Keegi ei soovi endale või enda lastele halba tuleviku. Alustame väikselt, näiteks käia või siis viia oma asjad taaskasutuspoodidesse, planeerida oma toitukorda ja peaks jälgima kasutustähtaega, et kõik võimalik oleks kasutatud.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('c9b1cb0b-999c-4136-84f2-2b962737b116', 'title', 'Raiskamine');
