INSERT INTO core.text(id, content)
VALUES ('717f725b-e361-466f-aa13-3f83d178d642',
        'Tarbimine on maailmas minu arvates käest ara läinud.Inimesed tarbimine on läinud minu meelest üle piiri, ostetakse liiga palju toiduaineid kokku ja siis lihtsalt visatakse need minema kuna nad ei jõua kõike ära tarbida. Liiga paljud inimesed lihtsalt tarbivad ja ei mõtle sellele mis tagajärgi see võib endaga kaasa tuua. Paljud inimesed ei taaskasuta, vaid ostavad tutikaid rõivaid.\nKuna inimesed mõtlevad enamasti ainult enda peale, siis nad lihtsalt tarbivad ja nad ei mõtle sellele, et tegelikult on inimesed vaeva näinud, et toitu hankida. Toidu minema viskamisega ei viska nad minema mitte ainult raha, vaid ka raiskavad ka tohutult erinevaid ressurse: maad, vett, energiat ja tööjõudu. Ühekordne toidu minema viskamine pole nii hull, aga kui seda teha regulaarselt siis moodustub see päris suure hulga toitu aastas. Minuarvates peaksid inimesed üle vaatama enda tarbimisharjumused. Nad peaksid ostma poest niipalju toitu kui nad ära jõuavad tarbida, mitte rohkem. Kui neil ka tekib olukord kus toit hakkab pahaks minema, siis nad peaksid selle esma järjekorras ära tarbima mitte ostma uusi toiduaineid.\nTeine asi on taaskasutus mille peale paljud minu arust ei mõtle. Paljud ostavad muudkui tutikaid asju ja ei mõtle, et selle peale on kulutatud palju lisa ressursse.\nKokkuvõtteks ütleks niipalju, et kui inimesed vaataksid üle oma tarbimisharjumused ja hakkaksid rohkem taaskasutama, siis sellega annaks palju ära teha, oleks puhtam maailm');
