INSERT INTO core.text(id, content)
VALUES ('6a90f8f1-9774-4ee6-ad40-a461836a8f58',
        'Palju inimesi arvab, et maailmas pole toiduraiskamine probleem. Kuid nad eksivad. Ühe inimese kohta juba läheb väga palju toitu minema. Maalimas on inimesi kõvasti rohkem kui üks. Toiduraiskamine pole ainuke probleem. Selline asi mida inimesed ei pane tähele, et see võib probleem olla, on riiete ära viskamine. Kuid muret on seal küll.\nMaal elades ei raisata nii palju toitu kui korteris elades. Maal saab anda loomadele ja viia komposti. Korteris sellist võimalust väga pole. Just korteris elavad inimesed need, kes raiskavad toitu rohkem. Toiduraiskamise põhjuseks on poest ostetud toit ja see on juba halvaks läinud. Või kui toit on jäänud seisma ja selle kuupäev on aegunud. Kõige tüüpilisem põhjus on ikkagi ülejäänud toit. Eesti inimene viskab aasta jooksul toitu ära ligi 61 kg. Kui juba ühe inimese kohta on nii palju, siis terves maailmas on see arv väga palju suurem.\nÜks väike probleem, mis on juba vägagi suureks läinud on riiete ära viskamine. Kui riidele tuleb väike auk sisse, siis visatakse see kohe ära. Ning enamus riided on prügimäel just seetõttu, et see oli lihtsalt emotsiooniost kuskilt Hiina odavast poest ja ei näinud selline välja nagu pildi peal ja see visatakse minema. Tegelikult ei mõelda sellele, et neid saab ära anda tuttavatele, ning viia kaltsukatesse. Seal leiavad riided endale uue kasutuse.\nSeepärast peaksime rohkem tähele panema, mida me ära viskame. Toiduraiskamist saaksime kõik vähendada sellega, et süüa ära enne need toidud, mille kuupäev läheneb ja toit, mis on söömisel üle jäänud, tuleb viia loomadele või komposti. Riiete minema viskamist saame vähemaks võtta sellega, et riided, mis ei sobi, tuleb viia katsukasse ja anda perele ja sõpradele.');
INSERT INTO core.text_property(text_id, property_name, property_value)
