INSERT INTO core.text(id, content)
VALUES ('e5925441-bf36-435d-9a42-3c6963b8ab10',
        'Inimesed arvavad, et naad ei raiska toitu, kuid see on täiesti vale. Ka vähe tarbivad inimesed raiskavad üsna suurtes kogustes toitu. Tuleb alustada pisikestest asjadest, et jõuda parema Eesti poole. Teadvustada meie rahvast toiduraiskamisest. See võtab aega kuid koos jõuame paremasse Eestisse.\nInimesed võiksid olla teadlikumad, kuidas ja kui palju naad tarbivad ja raiskavad toitu. Nimelt kodubidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid. Ühe Eesti pere jaoks pole see just suur asi aga, kui vaatame ühe suure tervikuna kõigi Eesti perede toidujäätmeid on see aga meeletu. Ja me ei pane tähelegi, et mitte ainult sellega ei raiska me ennda raha vaid ka tohutult maa rersursse.\nMinu arvates saaksime selle probleemi lahendada, kui tarbiksime teadlikult. Näiteks ei osta ülemäära toitu käiksime poes näiteks nimekirjaga. Ja ültse teadvustaks rohkem Eesti inimesi toidu raiskamisest. Parem Eesti ei tuleks üle öö kuid tasa pisi harjutades jõuaksime ennda unistuseni. Ka see ei tundu palju kuid, kui seda teeks kogu Eesti, liiguksime koos parema Eesti poole.\nInimesed peaksid tarbima teadlikumalt. Tihti me ei pane tähelegi kui palju me tegelikult tarbime. Kui palju me ültse raiskame raha ja maarersursse. Kindlasti saab vähendada toidu raisku minemist näiteks kasutada poenimekirja ja mitte osta ülemäära toitu. Koos liigume parema Eesti poole.');
INSERT INTO core.text_property(text_id, property_name, property_value)
