INSERT INTO core.text(id, content)
VALUES ('69c2dbb8-5c30-4143-a446-a60d2860e169',
        'Juba mitmeid aastaid on teemaks olnud kliimasoojenemine, mille põhjuseks on mitu erinevat tegurit. Üks suurim ning tavapäraseim tegur on liigtarbimine, millega kaasneb otseloomulikult ka ületootmine. Inimesed ostavad rohkem kui päriselt vaja. Arvatakse, et söögi ning esemete sorteerimine parandab kõik ära, kuid nii see tegelikult ei ole. Olukorra parandamiseks, tuleb asju vaadata teravama pilguga.\nTööstusmaailmas käib päevast päeva pidev sigin-sagin, sest iga minutiga tuleb juurde uusi tellimusi. Ostetakse riideid, toitu, majapidamistarbeid, erinevaid vidinaid meelelahutuseks ja nii edasi. Kõik need asjad on eluks vajalikud, kuid ei suudeta pidada piiri. Toitu valmistades ei mõelda koguste peale, mille tulemuseks võib söök külmkappi seisma jääda ning hallitama minna. Riidekappi uuendades, visatakse täiesti puhtad ja korralikud riided prügikasti, et olla hetkese moega kursis. Ka igasuguste muude esemete lühiajaline kasutamine toob meie armastatud kodumaale parajalt kahju.\nKliimasoojenemine ei mõjuta ainult inimesi, vaid ka loodust meie ümber. Et hõlbustada elu järgnevate põlvkondade jaoks, tuleks kohe tegutsema hakata. Peale prügi sorteerimise peab kontrollida oma tarbimist. Odavalt saadud riiete asemel, osta kallim, korralikuma materjaliga ning püsivam riideese, mida oled valmis kasutama mitu aastat järjest. Vanad riided vii taaskasutuskeskusesse, kus mõni teine inimene võib leida nende seast midagi sobivat. Sööki tuleb osta ainult siis, kui oled kindel, et selle ka ära sööd. Igasugune meelelahutus on lubatud ning isegi vajalik, et meie vaimnetervis tasakaalus oleks, kuid ka sellega võiks mõistlikult tegeleda.\nLiigtarbimine on tänapäeval suureks probleemiks, sest sellega kaasnev reostus mängib tähtsat rolli planeet Maal. Tuleb jälgida ning läbi mõelda oma iga liigutus. Uut tellimust tehes veendu, et see oleks asi, mida päriselt vajad ning kasutaksid. Inimesed on need, kes loodust on hakanud vaevama ning ka seepärast oleme just meie need, kes seda muutma peame. Tuleb lihtsalt mõelda roheliselt.');
