INSERT INTO core.text(id, content)
VALUES ('4cacc0f5-61af-4cae-86cc-be10352af8fc',
        'Inimesed tarbivad tänapäeval liiga palju. Näiteks toit, mitmeid tonne toidujäätmeid läheb raisku, lihtsalt sellepärast, et neid ei sööda ära. Seal hulgas on ka riided, paljud ostavad endale mingi riide esema, kannavad seda paar korda ja siis mõtlevad, et neil pole seda ikka vaja ja lihtsalt viskavad selle ära. Asju ei tohiks sedasi raisata, neid peaks maksimaalselt ära kasutama.\n Võtame näiteks toidu. Inimene võiks võtta endale nii palju sööki, kui ta suudab ära süüa. See pole väga hull, kui võtad natuke liiga palju ja viskad ära, lihtsalt pea meeles järgmine kord, et võta vähem. Toitu saab alati juurde võtta, kui kõht tühjaks jääb. See on loomulik, et mingi osa toidust alles jääb, näiteks banaani- või apelsinikoor. Seda saab kas komposteerida või mingis muus toidus kasutada.\n Tänapäeval visatakse ära ka palju riideid. Kui sul on mingi riideese, millest sa oled välja kasvanud ja see on heas korras, siis seda saab näiteks annetada või kellegile müüa. Kui sul on mingi riideese milles on auk sees, siis seda saaks, kas ise parandada või kellegil teisel lasta parandada. Mõte on see, et riideid peaks võimalikult palju ära kasutama, et neid ei peaks üleliia tootma.\n Riideid ja toitu ei pea ära viskama, vaid neid saab uuel otstarbel ära kasutada. Riideid saab ära anda ja toitu saab komposteerida. Inimesed võiks asju maksimaalselt tarbida, et neid ei peaks üleliia tootma ja ära viskama.');
