INSERT INTO core.text(id, content)
VALUES ('d274eb46-80f1-4960-b378-066e1a6d5736',
        'Inimesed raiskavad iga aasta tohututes kogustes toitu ning riideid. See on  inimestele iseenesestmõistetav aga see ei tohiks nii olla. Inimesed ostavad Hiina e-poodidest kõiksugu asju mille nad hiljem prügikasti viskavad ja sellest saab prügi. sellele kõigele kulub väga palju ressurssi ning see on loodusele kahjulik.\nKui inimesed riideid ostavad, siis nad ei tule selle peale, et see on toodetud naftast. See ei ole keskkonna sõbralik ja, et see ei ole inimsõbralik, see ei meeldi inimesele ja ta viskab selle peale esimest kandmist minema. Kui ta selle prügikasti viskab siis see ei lähe taaskasutusse vaid põletamisse. Aga kui ta selle taaskasutuskonteinerisse paneb siis see läheb ringlusesse.\ninimesed ostavad ka toitu, et saaks süüa aga inimene ei mõtle sellepeale, kui palju ta süüa ostab. Kui inimesed ostavad liiga palju süüa siis ta ei jõua seda kõike ära süüa ja ta viskab selle minema kui ta näeb, et toit on aegunud. \nInimestele meeldib tarbida aga me ei mõtle selle peale, et loodus hävineb sellega. Loodust hävitatakse kui kaevandatakse naftat ja sellest toodetakse tehases riideid ja muid plast tooteid. tehased hävitavad loodust kui need tossavad ja saastavad õhku.\nInimestele meeldib tarbida ja sellest harjumusest ei saa nii kergesti lahti. Inimesed viskavad minema toitu ja riideid suurtes kohustes ning saastavad sellega ka loodust. Inimesed ostavad Hiina e-poodidest palju soodsat kaupa ja nii see majandusring käib.');
