INSERT INTO core.text(id, content)
VALUES ('6fb491f7-b303-4a38-9fea-7660a9213ff7',
        'Inimesed ostavad tihtipeale rohkem kaupa kui neil tegelikult vaja on. Ülejäänud kaup, mida ei suudetud ära tarvitada, visatakse ära. Ületarbimine on meie tänapäevases ühiskonnas tava. Mis probleemid kaasnevad inimeste liigse tarbimisega?\nInimesed ei oska poes käies hinnata, kui palju toitu nende majapidamises vaja läheb. Toit ei püsi igavesti söödavana. Kui toiduaine on ületanud tähtpäeva ei ole see enam söögikõlblik. Toit, mis ei ole enam söödav, visatakse ära. Liigne toidu ostmine raiskab inimese enda raha ja ka resursse, mis olid toidu valmistamiseks vajalikud. Veelgi tekitab inimeste toiduraiskamine keskkonnale rohkem koormust. Liigse tarbimisega kaasneb ka liigne tootmine. Tootmisel kasutatakse väetisi ja ka kemikaale, mis kahjustavad keskkonda. Kaubatootjad on suure koguse tootmisega harjunud, seega peaksid enda toidu raiskamist ja liigset tarbimist vähendama paljud, enne kui see hakkaks kahju vähendama.\nKiirmood on paljudele ahvatlev. Ostetakse odavaid riideid, mida kantakse vaid mõni või üks kord. Rõivaid ostes vaata ka kvaliteeti, mitte vaid hinda. Juhul kui kvaliteetsed riided on sinu jaoks liiga kulukad, osta neid vähem või siis taaskasutuspoodidest. Ostetakse palju riideid, mis on tulnud välismaalt, tehtud halbadest materjalidest ja ei püsi kaua. See viib meeletu resursside raiskamiseni. Taaskasutuspoodidest ei taheta osta riideid, mis on lagunemas või rikutud. Riided mis jäid ostmata, visatakse ära. Kiirmoe tarbmisega kaasneb ka liigne tootmine. Toodetud riided, mis ei püsi, visatakse kiiresti ära. See reostab meie maailma ja raiskab ressursse. Palun mõtle enne kui ostad.\nInimesed ostavad rohkem kui vaja on. Asjad, mis ei kõlba tarbimiseks, visatakse ära. Kauba ära viskamine on keskkonnale kahjulik.Ületarbimisega raisatakse raha ja ka ressursse. Enam ei ole tagasiteed, kahjud on juba väga suured. Inimesed peavad oma käitumist muutma.');
