INSERT INTO core.text(id, content)
VALUES ('c4c26b84-3c9d-4152-bfe6-7e15d834984c',
        'Söök ja riided on inimestele väga tähtsad asjad elus. Keskmises koguses on need vajalikud, kuid nii mõnelgi inimesel on tänu rohkemale rahale ka ülemäära toitu või riideid. Paljud arvavad, et nemad on ainult ühed ainsatest, kes ületarbivad ja mõtlevad, et mis see ikka teha saab. Mida saaks selle juures parandada?\nEsiteks toidust. Enamus inimesi mõtleb, et „toit ei saa ju kunagi otsa“, kuid see ei tähenda, et toitu võib lihtsalt raisata või ära visata. Tihti käiakse tühja kõhuga poes toitu ostmas ning mõeldakse, et tahaks sellel hetkel kõike süüa, ostetakse korv toitu täis ja pool sellest jääb lihtsalt külmkappi seisma. Selle vältimiseks võiks poes mitte käia tühja kõhuga. Kui see pole üldse võimalik, siis enne maksmist või toitu valides, mõtle selle peale, mida sellest toidust teha nii, et midagi seisma ei jääks. Kui kõike ei jõua valmis teha, siis pole seda ka vaja. \n„Miks osta kallimaid riideid poest, kui neid saab tellida palju odavamalt Hiinast“. Väga palju inimesi arvab, et Hiina tooteid on parem ja odavam osta, kuid see pole tõsi. Kuigi Hiinas toodetud riided on kordades odavamad, kui mõned parema poe riided, on nende kvaliteet siiski palju halvem korralikest riietest. Parem osta kallim 70 eurone ja kvaliteetne jope, kui 10 eurone jope Sheinist või muust Hiina poest, sest korraliku firma poolt tehtud ja natuke kallim jope võib kesta ka üle kümne aasta. Selle kõrval Hiinas toodetud odavast materjalist jope võib ära laguneda isegi poole aasta jooksul. Lisaks odavad materjalid lagunedes reostavad maad, sest need enamasti lagunevad väga kaua.\nKokkuvõtteks maailmas ületarbimist on võimalik parandada. Selleks peaks iga inimene andma pisikese panuse. Ka kõige väiksem muudatus on suur, kui kõik natukenegi aitaks. Me ei tohi mõelda ainult enda peale ja lootma, et töö tehakse meie eest ära, vaid peame ise sellega alustama.');
