INSERT INTO core.text(id, content)
VALUES ('740dbd8b-ea91-458a-91fc-3c265cd99eb9',
        'Eestis tõesti raisatakse väga palju toitu ja toiduaineid. Nagu eeslmistes juttudes oli kirjas, et keskimine eestlane raiskab ligi kaudu 61kg toidukaupu iga aasta. Se aga on väga halb sest see tähendab, et eestlased ei oska toitu austada. Toidu raiskamisel on väga palju negatiivseid külgi. Toidu raiskamine on meie planeeile väga halb sest see kasutab väga palju ressursse.\nToitu ei tohiks raisata sest seda toota juba pole kerge. Ja kui me raiskame toitu siis saab poe lettid palju kiiremini tühjaks. Kui poe toidu lettid saavad kiirest otsa siis peab se pood rohkem toitu tellima. Selle asemel, et toitu raisata võiks selle toidu kodututele anda. Toitu ei tohiks veel sellepärast raisata on se, et siis ei saa prügi alad nii kiirest täis. Kui vähem riknenud toit on prügikastis siis ei haise see prügikast nii hullusti. Ja kui ei ole nii palju toidu prügi siis ei peaks nii tihti ostma prügikotte.\nKui toitu vähe raisata siis oleksid toidu hinnad soodsamad sest neid  ei pea nii tihti enam tootma. Isegi kui toidul on parim enne läbi siis saab seda ikka veel tarvitada. Kui näiteks piim on riknenud siis saab teha pankooke selle asemel, et seda piima minema visata. Kui näiteks panaani koored rikknevad saa teha komposti. Inimesed peaks vähem toitu raiskama selle pärast siis ei saa need toidu ained lõplikult otsa. Kõige parem viis kuidas mitte toiduaineid mitte raisata on se, et ära osta nii palju toitu mida sa ei jõua ära süüa ja ära tarvitada.\nKokkuvõtteks saab õelda, et isegi kui neid meetmeid jälgida siis eestlased raiskaksid ikka väga palju. Toidu raiskamisel on väga palju negatiivseid külgu mida saaks vätida. Paljuseid inimesi ei huita kui halb se meie planeedile on kui sa toitu raiskad. Ilma toidu raiskamiseta oleksid paljude toitude hinnad väga palju odavamad sest neid ei peaks nii palju tootma. Meie planeet oleks väga palju puhtam kui me ei vaid ei raiskaks nii palju toiduaineid.');
