INSERT INTO core.text(id, content)
VALUES ('6ba577db-4fba-414e-b65c-9e344a8e7515',
        'Tänapäeva maailmas läheb aina rohkem raisku igasugu asju, millest me ise aru ei saa. Inimesed tarbivad rohkem kui neil tegelikult vaja. Proovitakse leida lahendusi, aga selleks, et need ka päriselt toimiksid tuleb kaasata kõik inimesed. \nSellistel teemadel on raske saada inimeste tähelepanu. Eriti noorte tähelepanu. Noored huvituvad uutest ja uhketest asjadest. Aga kuna taaskasutuse teema tuleb aina rohkem meie maailma ja sellest räägitakse aina rohkem, on hakanud paljud noored ka kaltsukates käima. Mood on muutunud, paljud saavad oma riided, mida otsitakse just kaltsukatest, kuna mujal selliseid enam ei müüda. Olen ka tähele pannud, et hinna vahe kaltsukate ja tavapoodide vahel on suur.\nSama lugu on ka toiduga. Tavaliselt ostetakse toitu rohkem, sest käiakse tühja kõhuga poes. Mille tagajärg on emotsiooniost ja toidu üleküllus kodus. Seda kõike ei suudeta ära tarbida ja see visatakse ära. Aga seda probleemi on väga raske muuta. Inimesed on harjunud sellise eluga ja tavaliselt käiaksegi poes tühja kõhuga peale tööpäeva. Olen käinud tühja kõhuga poes ja tuleb välja, et see pole hea ka sinu rahakottile. \nAsjad on paremuse poole läinud. Aga mitte piisavalt. Kui võrrelda praegust olukorda aastate tagusega, on kindalasti näidud muutunud. Selleks, et need näidud veel paremaks läheks, tuleb jätkata samas vaimus. Seda teemat tuleb inimestele veel rohkem pähe raiuda.');
