INSERT INTO core.text(id, content)
VALUES ('f2aaae3f-a32b-4f9e-95ca-0aad726eceb2',
        'Inimeste tarbimisharjumused on käest ära läinud ja sellega kaasneb palju asjade ära viskamist. Isegi mina olen käinud paljudes taaskasutuspoodides ja need on tavaliselt kuhjaga riideid täis. Rääkimata veel sellest, kui palju inimesi viskab lihtsalt riideid ära, mitte ei vii taaskasutuspoodi. Inimesed võiksid aru saada mida nende tühjad ostud, ära viskamised keskkonnale teevad ja õppima, Kuidas oste õigesti teha, et neid poleks vaja ära viskata.\nMinu meelest on riiete ära viskamine üks halvemaid asju mida inimene teha saab. Kuigi ma mõistan natukene seda tahtmist osta kõik asjad mis silma jäävad, kui raha seda lubab. Aga igasuguste ostudega peab ostu läbimõtlema, küsima endalt, Kas mul läheb seda asja vaja? Kas see on mõistlik ost? Kas ma jään seda kasutama või viskan mõne ajatagant ära? Kuidas võib see mõjutada keskkonda? Kahjuks ma ei saa öelda, et kõik mu ostud on olnud arukad. Mu ema on pidanud palju mu ostetuid riideid taaskasutuspoodi viima.\nToiduainete raiskamine tundub olevat isegi suurem patt. ära viskamine toidu mis on täiesti kõlblik on tundub lihtsalt vale. Selle asemel võiks täpselt välja planeerida, mida sööd ja palju? Toiduained mis säilivad kaua on ka võimalik ära annetada.\nKokkuvõtteks võin öelda, et kõik inimesed raiskavad natukene, aga see oleks väga hea kui saad seda võimalikult palju vähendada. Uute riiete tahtmine on ka täiesti inimlik, aga ennem võiks vaatada palju sul veel on vanu riideid mis on täiesti kõlblikud.');
INSERT INTO core.text_property(text_id, property_name, property_value)
