INSERT INTO core.text(id, content)
VALUES ('d27bd1f4-e20b-4007-869f-ffb60f50d038',
        'Tänapäevases tarbimisühiskonnas on väga palju toidu, rõivaste ja muude kaupade raiskamine täiesti tavaline. Paljud inimesed ei saa aru, kui palju nad tegelikult kulutavad eluks vajalike ressursse. See probleem ei ole ainult mitte Eestis või Euroopas aga ülemaailmne.\nTänaseks on tekkinud paljusi organisatsioone, mis tegelevad tarbimise vähendamisega. Riigivalitsus on hakkanud ka reegleid püstitama, et vähendada tarbimist. Näiteks on paljudes kohtades sorteerimis prügikastid, et saaks prügisorteerida ja tagasi ringlema panna. Toidujääkidega tegelevad erinevad farmid. Näiteks koolide ja restoraanide toidujääkid lähevad kuhugi farmi loomadele söögiks.\nPalju tarbimisega võib kaasneda palju probleeme, mida on raske lahendada. Metsasi võetakse kiiremini maha kui see jõuab tagasi kasvada ja nii hävivad meie ilusad metsad. Näiteks suurimaid ebaseaduslike raiumisi on Amazonase metsades, kus raiutakse väga palju puid maha. Üks suurimaid probleeme on odavad riided, mis lähevad kergesti katki ja mida ei saa taaskasutada ja peab ara põletama, mis toob mürgiseid gaase meie kopsudesse. Näiteks Mu sõber Romet Aleksander Jürimäe tellis Hiinast endale võltsitud Nike Techi pusa endale, mis läks tal nädalaga katki ja ta viskas selle ära.\nKokkuvõtteks saaksid kõik inimesed kokku hoidmisega hakkama, isegi kui alustavad väikestest sammudest nagu kui võtad oma taldikule nii palju kui sa suudad ära süüa. Maailmas on paljusi ettevõteid mis tegelevad: puude istutamisega, prügisorteerimisega, erinevad farmid kus loomad ootavad toitu.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('d27bd1f4-e20b-4007-869f-ffb60f50d038', 'title', 'Tarbimine tänapäevases keskkonnas');
