INSERT INTO core.text(id, content)
VALUES ('d5228fa8-bc0b-4620-99e7-f2864717b1f5',
        'Tänapäeva noortele peaks tegema rohkem tuvust taaskasutuspoodidega, sest seal on palju disaineri riideid millest tänapäeva noored huvitatud on. Noored tarbiksid siis vähem ja saaksid aru eseme väärtusest isegi kui see on juba korra kasutuses olnud. Aga kas noored päriselt hakkaksid käime taaskasutuspoodides ja kas me peaks tegema noortele rohkem ekskursioone taaskasutuspoodide lattu? Sellele leiame täna vastuse.\nTänapäeva noortele meeldivad paljud disaineri riided ja need on tavaliselt päris kallid isegi allahindlusega. Sellepärast olekski taaskasutuspood väga hea võimalus leida endale hea hinna eest disaineri riideid. Nendega on kül üks probleem seal ei leidu tavaliselt täpselt seda mis sa otsid, sest sinna tuuakse asju mis teistel inimestele vaja enam ei ole. Sa võid leida täpselt selle mis sa otsisid aga siis sul lihtsalt vedas. Ma ise olen ka taaskasutuspoest ostnud endale riideid, ostsin endale ühe mantli et pidulikudel üritustel käia väga hästi säilis ja sain paar aastat sellega käidud ja see maksis ka olematu summa.\nAga kas siis me peaks tegema noortele neid ekskursioone nendesse ladudesse?  Ma arvan kül, sest siis nad mõistavad kui palju riideid nad saaksid osta selle rahaga mis nad kulutaksid ühe paari Nike jalanõude peale. Ma ostsin just ühest Eesti taaskasutus laost endale talve joppe disaineri oma. See toodi Ameerikast sinna, selle alghind oli olnud 250 eurot aga seal ma sain selle 50 euroga. Ma säästsin selle ostuga 200 eurot ja sain palju muid asju endale osta. Nende ekskursioonidega näeksid noored ka kui palju tänapäeval tarbitakse ja äkki see paneb nad mõtlema, et nad peaksid ise ka siis vähem tarbima.\nKokkuvõteks noori viia taaskasutuspoodide lattu ekskursioonile on väga hea mõte. See vastab ka meie küsimustele. Me ei saa kül täiesti kindlad olla, et kõik hakkavad taaskasutatud riideid ostma aga mõne võib see kindlalt mõtlema panna ehk tühja see mõte ei läheks.');
