INSERT INTO core.text(id, content)
VALUES ('e688546e-06f9-43ae-b332-7ee39298f564',
        'Inimesed tarbivad toitu ja riideid iga päevaselt. Need on eluks vajalikud, sest neist saab energiat ja sooja. Inimesed, aga raiskavad neid luksusi mis neil olemas on ja viskavad asju minema. Mitte kõigil ei ole selliseid luksusi nagu toit või soojad rõivad.\nTavaliselt visatakse toit minema, siis kui toitu on liiga palju, söök on halvaks läinud või kui toit lihtsalt ei maitse. Minu sõber võttis eelmine nädal sööklas liiga palju süüa mida ta ei jõudnud ära süüa, peamiselt selle pärast, et ta läks juurde võtma ja mõne hetke pärast kell helises. Me pidime tundi kiirustama, aga sõbral oli alles suur hunnik ees. Vahest juhtubki nii, et aega jääb väheseks ja lihtsalt ei suuda toitu ära süüa.\nInimesed kasutavad riideid peamiselt soojuse ja privaatsuse nimel, vahest ka stiili nimel, et lahe välja näha. Inimesed kasvavad enda riietest lõpuks välja, eriti kui nad on veel nooruki eas, aga on ka neid kes ostavad uusi riideid kui vanad rõivad alles parajad. Neid vanu rõivaid pole enam vaja ja need visatakse ära. See on keskkonnale äärmiselt kahjulik. Ära viskamise asemel võiksid inimesed need riided sugulastele või järgmistele põlvkondadele jätta või viia jäätmejaama kus teised inimesed saavad sealt endale riideid.\nNeed inimesed kes toitu aeg-ajalt ära viskavad peaksid enne mõtlema teiste peale. Kuid vahest pole lihtsalt aega söögi korda korralikkult lõpetada. Kui riideid hakatakse ära viskama tuleks enne mõelda taaskasutusele. Raiskamise probleemid ei lõppe aninult ühe inimesest, kõik peaksid planeeti hoidma.');
