INSERT INTO core.text(id, content)
VALUES ('0bbb11b6-19de-40cd-8605-e40e3046fa68',
        'Praegusel ajal on järjest olulisemaks tõusnud inimeste tarbimisharjumused,  mis kajastuvad kõige enam toidukaos. Iga Eesti inimene raiskab aastas umbes 26 kg toitu, mida on selgelt liiga palju. Mis põhjustab toidukadu ja kuidas seda vähendada?\nToidukadu põhjustab põhiliselt inimeste arvamus, et toitu on palju ja seda saab alati juurde osta. Sellise mõtteviisiga kogutaksegi terve külmkapp toitu täis, millest läheb lõpuks mitmed asjad vanaks. Veel on probleemiks toidu hulgi ostmine eriti, kui nähakse suuri allahindlusi.\nToidukao vähendamiseks on mitmeid võimalusi. Esiteks võiks poest osta täpselt niipalju toitu, kui parasjagu vaja. Toitu valmistades peaks arvestama, et kõik saaks lähipäevil söödud. Lisaks on ka väga oluline, kuidas toiduaineid hoiustatakse, sest see võib nende eluiga kõvasti pikendada.\nOlen ise nelja liikmelisest perest ja pean tõdema, et toidujääke tekib vahepeal päris palju. Proovime küll neid vähendada, mis tihtipeale töötab, aga mõnikord on toidujäägid paratamatud. Kõik meie poeskäigud on planeeritud, et ei ostaks üleliigset toitu, mis pärast halvaks läheb. Isegi, kui toidujääke tekib, komposteime me need üldiselt ära.\nToidukadu tekib mitmetel eri põhjustel, aga seda on võimalik vähendada, kui sellele tähelepanu pöörata. Mõnikord on aga see paratamatu ja sellest tuleb aru saada. Toidukadu on väga aktuaalne ja oluline teema, millega tuleb tegeleda.');
INSERT INTO core.text_property(text_id, property_name, property_value)
