INSERT INTO core.text(id, content)
VALUES ('adb42e02-13e3-4d12-9710-3c660d9ac28f',
        'Inimeste tarbimine ja selle harjumused on tänapäeval väga suur osa elust. Kõik, mida ära visatakse on puhas raiskamine ja seda tuleks eirata. Ning inimesi tuleks viia taaskasutuskeskustesse.\nSöögi ja vee raiskamine on väga aktuaalne tänapäeval. Kui inimesed käivad pesus raiskavad mõtetult palju vett, kui toidu kuupäev on üks päev möödas viskavad inimesed toiduaine ära. Kõike seda tuleks hakata vältima, ning mitte kahjustada meie maailma. \nVanu ja väikseks jäänud riideid ei tohiks ära visata. Paljud inimesed vist isegi juba teevad seda, et viivad enda vanad ja väikseks jäänud riided taaskasutuskeskusesse. Seda on loomlikult ainult tore kuulda, sest siis ei lähe raisku riideid ja need kellel vaja odavalt saada riideid, saavad need endale.\nMina ei ole toidu ega riiete raiskaja. Võin isegi öelda, et mulle meeldib viia ja müüa neid riideid, mis on vanad või väikseks jäänud hea hinnaga, siis saan natukene raha endalegi. Mulle ka meeldib küpsetada, nii et kui näen, et midagi hakkab vanaks jääma, teen sellest kohe midagi head. See on hea meie maailmale ja kõigile teistele.\nRaiskamine on üks suur ja maailmat reostav tegevus, mida paljud inimesed üritavad eirata, kuigi on neid, kes ikka seda teevad. Kõik taaskasutamine ja toidu mitte äraviskamine on hea meie enda tulevikule ja järglastele. Loodame, et inimesed saavad sellest halvast kombest lahti.');
INSERT INTO core.text_property(text_id, property_name, property_value)
