INSERT INTO core.text(id, content)
VALUES ('5580b84a-0fca-452c-a5c3-23cb1ccf8c12',
        '\n Tänapäeva üheks suuremaks probleemiks on inimeste tarbimis sõltuvus, mis reostab loodust ja vähendab meie riigi ressursse. Täiskasvanud viskavad suurtes kogustes toitu ära, mitte arvestades tagajärgedega. Selle halva harjumuse peatamiseks, võiksid perekonnad olla säästlikud ja taaskasutada. Mida peaksid inimesed tegema, et tarbida vähem?\n Tänapäeva inimsed raiskavad palju toitu. Täiskasvanud kipuvad tihti suurtes kogustes pala ära viskama, mitte arvestades sellega, et missugust kahju see tekidab meie ühiskonnale. Maailmas on riike, kus toidupuudus on üks suur probleem, ning selle lahendamiseks, võiksid pered annetada ülejäägid toidupangadesse, et vähendada toidupuudust vaesemates linnades. Selle asemel, et kõrvale eine heita, võiksid isikud annetada selle heategevusesse.\n Keskonna hoidmiseks tuleb olla säästlik. Selle asemel, et hoida elektrilambid tööl või käja igapäevaselt vannis, võiksid inimesed olla rohkem jätkusuudlikud. Näiteks minu perekonnas on kaua pesus olemine ja lampide umbkaudne kasutamine keelatud, mis vähendab voolu ja vee tarbimist. Tänu sellele, säilitaksid inimesed rohkem raha ja looduslikke ressursse, mis omakorda päästab ka loodust. \n Taaskasutamine on võti ressursside hoidmisele. Inimesed võiksid viia taaskasutatavad asjad taaskasutusjaama, selle asemel, et visata need tagasi loodusesse või prügikastidesse. Näiteks meie perekonnas eraldatakse pakendid prügist ja viiakse tühjad pudelid lähimasse poodi. Tänu sellele, säästaksid täiskasvanud kilogrammides materjale ning hoiaks meie loodust ohu eest.\n \n Taaskasutamine ja materjalide säästmine võib mõne inimese jaoks olla raske tegevus, kuid selle omandamine võib aidata meie ühiskonda suurtes kogustes. Piisab ka sellest, kui perekonnad hakkaksid vähem vett tarbima, mis hoiaks inimorganismi kõige tähtsamat ressurssi. Jätkusuudlik olemine pole sugugi keeruline, tuleb ainult alustada.');
