INSERT INTO core.text(id, content)
VALUES ('ba62a69b-2390-4566-8d0f-d4f1d166974a',
        'Meie maaressurside raiskamine on probleem, millele tavaliselt inimesed ei mõtle. Selle alla võib lugeda toidujäätmeid, riideid ja plastikust tehtud tooteid, mida saab kasutada ainult ühekorra enne prügikasti viskamist: kilekotid, kahvlid ja noad (plastikust), pakendid. Nende tootmine kahjustab ja reostab meie keskonda. Inimestele peab selgeks tegema, et nende harjumused kahjustavad meie kõigi elusid.\nKeskmiselt viskab ära Eesti kodanik 61kg toidujäätmeid. Sellest 26kg on söömiseks kõlbav toit. Tegelt on terve 61kg kõlbav toit enne nende, kas riknemist või aegumist. Nad ei mõtle selle peale, mitu päeva väärt toitu nad ära viskavad, sest see on nende harjumuses. Mõnede troopiliste puuviljadega läheb raisku ka inimtööjõud, kus inimesi sunnitakse, kas nende vabatahtlikuse vastu või väga madala palga eest töötama.\nInimesed tahavad osta endale soodsaid riideid, mis näevad head välja ja neid otsides leiavad nad Hiina kaubamaja. Hiina kaubamajades toodetakse riideid just kvantiteedi suhtes väga soodsa hinnaga, mis tähendab, et nende riided on tehtud väga odavast materjalist, mis kuluvad paari kuuga ära. Nende tootmine on väga suur raiskamine, sest kuu aega pärast nende tellimist saab neid leida taaskasutuspoodide laost suurtes hunnikutes, kus leidub ka kõik teised samasugustest vabrikutest toodetud riideid. See on üks väga suur näide maaressurside raiskamisest ja millest peaks inimesi uudistes teavitama.\nTänapäevased inimharjumused on väga keskkonda kahjustavad. Nendest peaks inimestele igalpool uudistes ja sotsiaalmeedias teavitama. Peaks alustama ka kampaanijaid Hiina kaubamajade veebilehtede sulgemisele või blokeerimisele, kas Eestis või Euroopa liidus.');
