INSERT INTO core.text(id, content)
VALUES ('67108759-2ac0-47a3-a896-e2b551ffcc8a',
        'Mida rohkem inimkond edasi on arenenud, seda rohkem on tekkinud juurde uusi kaupu ja esemeid. Tihti ostetakse asju liiga palju ja sellest tekib raiskamine ja reostus, mis ei kahjusta ainult meid ennast, vaid ka keskkonda. Kui palju inimesed adekvaatselt oma tarbimisharjumuste peale mõtlevad ja kas liigne tarbimine on kujunemas peatamatuks probleemiks?\nInimesed on järjest vähem hakanud mõtlema oma tarbimisharjumuste peale. Arvatakse, et pole mõtet, kuna kõike on küllaga ja võib isegi jääda mulje, et mitte miski ei saa otsa. Ületarbimine aga on kasvanud suureks probleemiks. Uutest asjadest leitakse rõõmu ja tihti peale ei mõelda, kas neid tooteid tegelikult vaja on. Pidev ostmine on kujunenud ka harjumuseks, kuna elu on muutunud väga mugavaks. Ebavajalikud riided, toit ja kaubad jäävad teatud aja pärast vedelema. Sellega ei raiska me ainult omaenda raha, vaid ka tohutuid ressursse, näiteks vett. Mõtlematu käitumine tekitab prügi ja reostust, mis kahjustavad ka keskkonda.\nÜletarbimise vähendamiseks tuleb ostes teha targemaid valikuid: enne suurtesse ostukauplustesse minekut käia läbi ka taaskasutuspoed, mõelda oma ostud põhjalikumalt läbi ja objektiivselt hinnata, mida tegelikult vaja osta on. Vanu riideid, mida enam vaja ei ole, saab viia taaskasutuspoodidesse, kus nad leiavad uue omaniku ja ei lähe raisku. Väikseid muudatusi tehes ja oma harjumusi muutes, saame kõik oma panuse anda, et reostuse teket vähendada.\nÜletarbimine on suur probleem, millega tuleb tegeleda. Tänapäeva ühiskonnas, kus kõike on tohutult palju saada, ei mõelda eriti selle peale. Igaüks peaks aga tegema targemaid valikuid: taaskasutus, teadlik tarbimine ja vajalikkuse analüüsimine. Tarbimise vähendamiseks saavad kõik oma panuse anda.');
