INSERT INTO core.text(id, content)
VALUES ('b8384144-08f3-4c59-9ed3-2783a76fba3e',
        'Maailmas on palju, kes ei tea, kuidas tuleks õigesti riideid või toitu tarbida. Inimesed viskavad toidu ära, ilma, et mõtleks kui väärtuslik see siiski on. Kuid mis on peamised kohad, kus inimene neid ära viskab?\nKõige tuntum on toidu ära viskamine. Paljudele inimestele tunub, et toitu on veel ja see ei saa kunagi otsa. Siiski on neid inimesi ka, kes ei viska seda nii lihtsalt ära. Kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26kg. Toidu raiskamist ei saa vähendada üleöö. Kahjuks on see inimeste harjumustes palju kinni.\nPalju on ka inimesi, kes ei oska hinnata riideid. Nad tellivad suurtes kogustes, kuulsatest Hiina veebipoodidest endale riideid. Eestis on palju taaskasutuspoode. Sinna tekib iganädal hunnikuid riideid, kuid inimesed ei käi seal. Seepärast tuleks, organiseerida noortele ekskursioone taaskasutuspoodide lattu, et näidata milline raiskamine tegelikult toimub. Kindlasti tuleks õpetada noortele, kuidas ise vanast rõivast, endale ilus top või kleit valmistada. Mina isiklikult, olen valmistanud endale vanast seelikust uue topi, mida saan nüüd uuesti kanda. Mina arvan, et inimesed ei oska rõivaid hinnata ega kanda ning seda tuleks parandada.\nIga inimene on erinev, kuid toidu või riide ära viskamine ei ole kõige parem lahendus. Seda tuleks inimeste juures muuta. Kindlasti ei saa seda üleöö teha. Tuleks alustada vaikselt ja rahulikult.');
