INSERT INTO core.text(id, content)
VALUES ('fac1238f-a252-4e12-80a5-27ef5e23e1b3',
        'Suur osa maailma inimesi ei saa endale lubada uusi riideid, täisväärtuslikke toidukordi, mugavuskaupadest rääkimatagi. Ja siis on inimesed, kes ostavad endale iga päev uusi tooteid ning viskavad need õigepea ära. Samas, on suureks probleemiks ka toidu raiskamine. Kuidas see õudne raiskamine täpsemalt toimub?\nRahvastiku seas on palju ülirikkaid, kellel on väga sageli vaja uusi jalanõusid, rõivaid või autosid osta. Selline käitumine ei tee keskkonnale head, sest see toetab tehaste laienemist. Tööstuste laienemine toob kaasa suuremad heitgaaside kogused, mis hävitavad Maad. Seetõttu peaksid rikkurid veidi järele mõtlema, kuidas nad käituvad.\nKogu kokku ostetud kaup jõuab ajaga tagasi loodusesse, mis on halb. Vanad tooted ja materjal tuleks viia kogumispunktidesse ja saata tagasi ringlusesse. Seejärel saaks valmistada vanast tootest uue või anda korralik kaup vaesematele. Sellist taaskasutust suures osas maailmas kahjuks veel ei toimu. Loodetavasti tulevikus olukord aga paraneb.\nTänapäeval on käimas ka massiivne toiduraiskamine. See toimub väga paljudes paikades: kodudes, koolides, hotellides ja veel mitmetes kohtades. Peamiseks raiskamise põhjuseks on ilmselt see, et ostetakse kokku liiga palju toitu , seda ei jõuta ära süüa ning seejärel see aegub. Samuti võetakse oma taldrikutele nii palju toitu, et pool sellest jääb järele. Ülejäägid lähevad kahjuks sageli prügikasti, mitte ei jätkata sama toidu söömist teine päev. See on väga suur probleem, mis kahjuks aina süveneb.\nInimestel on vaja süüa toitu, omada riideid ja autosid, aga neid ei ole vaja osta liialt palju. Rahvas peab mõtlema, kas neil on tõesti vaja mitut kapitäit riideid või rohkem kui kahte või kolme autot. Just meie vastutame oma planeedi eest ja seepärast peame enda harjumusi analüüsima ja vajadusel neid kohandama.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('fac1238f-a252-4e12-80a5-27ef5e23e1b3', 'title', 'Keskkonda säästma!');
