INSERT INTO core.text(id, content)
VALUES ('7dd1e47b-005d-43cf-b01a-70b68812ff1b',
        'Tänapäeval raiskab suur osa Eesti inimesi toitu, riideid ja muid igapäevaelus kasutatavaid tooteid.Tavalises kodumajapidamises Eestis tekib rohkem kui 60kg jäätmeid ühe inimese kohta aastas.\nToidu või toitaine raiskamine ehk mingil põhjusel jääb see tarbimata ja visatakse jäätmena ära.See võib juhtuda siis kui toit on söömisel ülejäänud või toit kasutustähtaja ületanud.Mul endal on on tihti nii, et pean mingi toitaine ära viskama, kuna sellel on midagi viga aga kui toit vanaks pole läinud siis ma toitu niisama ära ei viska.\nKa riideid ja muid tooteid, mida kasutame peab aeg-ajalt minema viskama.Olgu põhjuseks see, et riideese on katki või mingit kindlat tootet pole enam mõtet  kasutada.Kuid seda võiks proovida teha pigem harva, mitte iga paari päeva tagant.Mina viskan üsna vähe riideid ja teisi tooteid ära, selle asemel otsin viisi, kuidas keegi muu isik saaks minu riietest ja toodetest kasu.\nRaiskamist vältida on tegelikult lihtsam kui mõni inimene arvata võib.Toidu raiskamist saab vältida mitte õhtusöögi ülejääke ära visates,vaid need külmkappi pandes ja homme edasi süües.Riiete ja muude toodete raiskamist saab vältida viies need kaltsukasse või maha internetis maha müües.Ise väldin raiskamist täpselt sama moodi.\nToitu visatakse väga suurtes kogustes ära, isegi kui see süüa kõlbab.Ka riideid ja teisi tooteid visatakse palju ära.Raiskamise asemel võiksime me mõelda võimalusi selleks , kuidas inimesed ei peaks seda tegema.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('7dd1e47b-005d-43cf-b01a-70b68812ff1b', 'title', 'Kuidas vältida raiskamist?');
