INSERT INTO core.text(id, content)
VALUES ('ff1ae15d-c3f6-4d2b-8c40-07f23d6f9bcf',
        'Taaskasutamist on tänapäeval väga palju vähemaks jäänud. Inimesed tahavad koguaeg ainult uut ja paremat ning raiskavad palju. Sammuti ei hooli enamikud ka toidust.\nAastate jooksul on taaskasutamine jäänud inimestel väga tahaplaanile. Paljud arvavad, et taaskasutamine on rõve ja kellegi teise kantud riideid ei ole nad nõus kandma. Ja, et kui inimene kannab odavaid ja kasutatud riideid pole ta lahe. Sellist suhtumist oleks vaja inimestes  muuta, neid harida ja neile selgeks teha, et kõigil pole igasuguseid luksuslikke võimalusi ja kõigile meeldivadki erinevad asjad.\nToidu raiskamine on praegu maailmas ka üks üpris suur probleem. Inimesed arvavad, et meil on palju toitu ning see ei saa kunagi otsa. Toidu järgi jätmisel ja lõpuks selle ära viskamisel inimesed ei mõtle sellele, et mujal maailmas ja ka näiteks naabri juures on toidust suur puudus ja, et nemad oleksid väga õnnelikud ja tänulikud, kui saaksid selle toidu hoopis endale. Inimesi tuleks läbi televisiooni ja interneti informeerida inimesi sellega, mis mujal maailmas toimub ning panna neid mõtlema, kuidas keegi võib end tunda samal ajal, kui nemad toitu raisku lasevad ja kui paljudel on tegelikult maailmas toidupuudus.\nTaaskasutus ja säästmine on maailmast peaaegu, et kadunud. Inimesed teevad kõike enda heaks ning ei mõtle teistele. Et maailma tagasi paremuse poole muuta oleks vaja sellistel teemadel rohkem avalikult rääkida.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('ff1ae15d-c3f6-4d2b-8c40-07f23d6f9bcf', 'title', 'Taaskasutamine ja raiskamine tänapäeval');
