INSERT INTO core.text(id, content)
VALUES ('960ced9d-a951-4cc5-8210-5b914928cac0',
        'Hetkel on maailmas palju probleeme ületarbimisega eriti levinud on see toidu ja riiete osas. Tegelikkuses saab ühiskond seda muuta, muutes enda harjumusi. \nSuuresti on levinud Hiina veebipoed, näiteks viimasel ajal üha rohkem populaarsust kogunud veebi pood Shein, kust on võimalik vaid paarikümmne euro eest soetada endale stiilne garderoob.  Selle stiilse poe taga on tegelikult alamakstud töötajad, ebakvaliteetsed materjalid ja isegi lapstööjõud. Ebakvaliteetne toode on kahjulik nii enda tervisele kui ka  keskkonnale, kuna tihtipeale kasutatakse odavates riidematerjalides naftat. Positiivne ju oleks kui need riided kestaks kaua, kuid tahes-tahtmata kaotavad need oma kasutusaja juba paari kuu möödudes. Just see panebki mõtlema et, kas lihtsam ja parem  poleks osta üks korralikust materjalist ja vastutustundlikust poest üks riideese, mis kestab aastaid? Üks headest variantidest on külastada ka taaskasutuspoode, riideid mis sealt leidub on kohati ägedamadki kui need, mida leiad kuskilt kiirmoe poest. \nLiiklemine autode ja muude mootorsõidukitega liikumine on ka keskkonnale kahjulikum, kui jala või rattaga liiklemine. Kui koht kuhu soovid minna on läheduses on mõistlikum kasutada ühistransporti või iseenda kondimootorit, see on ikka keskonnasõbralikum  kui üksi autoga erinevatesse kohtadesse sõitmine, kui aga autot kasutada siis mõelda läbi äkki saab käia ära  kõik vajalikud kohad ühesõiduga.\nToiduraiskamise küsimus on puhtalt harjumustes. Kui osta poest juba toitu mõttega : ,,See vist aegub ennem ära kui ma jõuan selle lõpuni süüa“, kas siis poleks parem osta väiksem pakk või tarbida targemalt? Tahestahtmata läheb toitu raiskamisse, kuid arvan, et iga inimene saab teha omaltpoolt panuse, et raisatakse vähem. Võimalus on alati süües toitu juurde tõsta, kui ära vista ülejäänud toit. Alati on võimalus mitte osta suurtes kogustes süüa kui mingisugune sooduskampaania on, või kui lähed poodi teades, et täna teed süüa võib ju vabalt vaadata ka ,,Parim enne“ korvi, need toiduained pole halvaks läinud, vaid lihtsalt selle „Parim enne“ aja ületanud, nii saab teha odavamalt süüa samal ajal toitu mitte raisates.\nRaiskamise vähendamisel saab aidata iga inimene, vaadates üle oma harjumused ja olla keskonnateadlik. Mõelda saab läbi palju mida raiskan ja kuidas seda vähendada. Keskonda saab tõesti panustada igaüks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('960ced9d-a951-4cc5-8210-5b914928cac0', 'title', ',,Kuidas aidata keskkonda“');
