INSERT INTO core.text(id, content)
VALUES ('b95303e0-2504-4ef3-a682-d9b691c59e10',
        'Inimene on olend, kes eelistab igasuguseid mugavusi. Tarbitakse asju, mida soovitakse ja alatihti ei mõelda sellele, mis võib olla liigse tarbimise tagajärg. Aga mida tarbib inimene ja millised on tema tarbimisharjumused?\nInimene ei käi toiduga mõistlikult ümber. Ostetakse liigselt toitu ja muud tarbitavat, mida ei suudeta õigeks ajaks tarbida ja visatakse lihtsalt minema. Keskmisel Eesti inimesel tekib aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 26 kg. Inimesed arvavad, et nende liigtarbimine ei mõjuta suurt pilti, kuid nii see kahjuks ei ole. Inimesed peaksid toidu soetamisel mõtlema ka sellele, et nad suudaksid seda ära tarbida.\nEelistatakse uusi asju taaskasutamise asemel. Moedisainer Eve Hanso arvab, et noored peaksid rohkem taaskasutama ja tarbima kodumaist kaupa. Nõustun selle faktiga, sest on oluline, et inimesed toetaksid nii kodumaist kaubandust ning eelistaksid osta vähem ja kvaliteetsemat, kui kuskilt Hiinast odavat ja hulgi. Inimesed peaksid mõtlema, kas tasub osta kaupa, mis jääb lihtsalt kuhugile kappi seisma, tolmu koguma.\nInimesed tarbivad liigselt asju, mida neil pole vaja ning nende tarbimisharjumused on ebasobivad ja liigsed . Tuleks hakata tarbima mõistlikumalt ostes vähem toitu ja välismaist kaupa ning rohkem kodumaist kaupa. Elanikud peaksid hakkama rohkem taaskasutama, et vältida üleliigset tarbimist. Iga inimese panus loeb liigtarbimise vähendamisel.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('b95303e0-2504-4ef3-a682-d9b691c59e10', 'title', 'Inimene tarbijana');
