INSERT INTO core.text(id, content)
VALUES ('8a64ebdd-4956-4372-bde9-a127bc0a9f5e',
        'Taaskasutus on aastatega olulisemaks läinud. Seda heal põhjusel. Kes ei tahaks, kui su maailm põleb? Tuleb välja, et päris paljud. See võib olla ainult kõrgklass aga neil on kõige suurem võim. Kuidas teha selgeks, et meil on ainult üks maailm.\n    Eestlased on loodussõbralike toodete ja materjalidega päris hästi hakkama saanud. Meil on õlekõrtest joogikõrred, hea prügi sorteerimis süsteem ning ühiskondlikud peenrad. Ühistransport on veel alla keskmisse, kuid parem kui mõnes kohas maailmas. Eestis väga ei olegi top 1 protsenti. See on päris väike. Suurem osa neist on vabamüürlased. Tean seda isa kaudu, kes õhtustab nendega ja kuuleb lugusid reisidest. Üks neist on minu vanaisa. Kui peaks rääkima tarbimist ühiskonnast, siis ma tooksin näiteks tema. Mulle rääkitakse palju, kuidas ta oli diivani põlema pannud. Pärast ostsid uued, kuid see ei olnud sama mugav kui poes, ning ostsid veel ühe. Toidu osas ei saa sama öelda. Just hiljuti oli ta peolt tulles palju jääke kaasa saanud, ning kutsus mind ja mu vanemaid õhtust sööma. Mööbliga ta väga osav ei ole, kuid oskab toiduga ümberkäia. \n   Kõige suuremad taaskasutajad on muidugi punkarid, eriti riiete osas. Nende vastandiks on inimesed, kes ostavad ainult disainer riideid. Mul on üks sõber, kes on punkar ning õmbles kaisuka üla osa pükste külge ja see näeb hea välja. Ta käib ka palju kaltsukates ning on saja aastane telefon. Olen tundnud ka inimesi, kes said iga teine nädal uue telefoni, uued riided ning tahtis kogu aeg midagi osta. Tema oleks üks neist, kes korralid riided ära viskab. Ma ise üritan vältida riiete tellimist. See on alati riskantne. Rohkem sobib mulle kaltsukates käimine või kirbu turul. Sealt leiab alati häid asju. Ma mäletan korda, kui käisin õega Humanas ning ta leidis Hugo Boss`i pintsaku. Originaalis oleks see maksnud vähemalt viissada eurot, Humanast sai viiega. \n   Inimesed peaksid enda tegudele rohkem mõtlema ning nende tagajärgedele. Oleksime arengus viiskümmend aastat ees, kui ei käituks hooletult. Ma jään eldale kindlaks ning ütlen, et punkarid on kõige paremad taaskasutajad. Mulle tundub see elementaarne. Hea inimene, hooliks oma inimestest ja maailmast. Ainuke probleem on, et sellised inimesed pole võimul.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('8a64ebdd-4956-4372-bde9-a127bc0a9f5e', 'title', 'Kes on hea taaskasutaja?');
