INSERT INTO core.text(id, content)
VALUES ('4c26ef24-b93f-490b-b4c6-470a74e5c32d',
        'Tihti kuuleme, kuidas räägitakse keskkonnaheaolust ja kuidas me peame loodust säästma ning kaitsma. Paljud inimesed aga, arvavad, et nende panus et mõjuta midagi, see on vale. Kuid mis tegelikult aitaks keskkonda säästa?\nVäga palju raisatakse toitu, sellepärast et seda saadakse endale lubada. Uuringud näitavad, et ühe inimese kohta tekib aastas umbes 61 kg toidujäätmeid. Kui see kogus on juba nii suur, ei mõjuta see enam ainult inimest ise. Toiduraisku saab vähendada näiteks nii, kui ostad ainult toiduaineid mida sa tead, et sa kindlasti ära tarbid ja tõstad taldrikule täpselt nii palju toitu kui ära jõuad süüa. Juba selline väike isiklik panus aitaks hoida mingi koguse toidukadu ära.\nVeel on väga tähtsal kohal riietega seostuvad tarbimisharjumused. Paljud inimesed tellivad riideid Hiina veebipoodidest, sest seal on riided odavad. Kui aga vaadata suuremat pilti, on see keskkonnale väga kahjulik. Riiete suhtes, tuleks valida kvaliteedi üle kvantiteedi. Eelistada tuleks kodumaist kaupa või osta heas korras riideid taaskasutuskeskustest. Kuid kahjuks, on tänapäeval tihti taaskasutuskeskused täis neid samu Hiina kaubamajade riideid, mida keegi on sinna toonud sest need on ebamugavad või ei näinud päriselus välja samasugused nagu reklaampildil.\nTarbimisharjumused on erinevad, kuid tuleks mõista, et iga inimese panus loeb. Koos saame me vähendada toidukadu ja naftast riiete tootmist, tuleb lihtsalt olla teadlik,  mida osta. Loodetavasti elame kunagi ühiskonnas, mille üle saame uhkust tunda ja mida saame kutsuda oma unistuste koduks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('4c26ef24-b93f-490b-b4c6-470a74e5c32d', 'title', 'Inimeste tarbimisharjumused');
