INSERT INTO core.text(id, content)
VALUES ('32e357b7-e92d-4d1d-b319-ac360c60aa84',
        'Üks kõige suuremaid keskkondareostav tegur on toidu ära viskamine. On osa inimesi, kes raiskavad toitu, sest nad saavad seda endale lubada. Riiete ostmine Hinnast on ka üks suur probleem. Miks inimesed reostavad keskkonda?\nKodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg. Kui me toidu ära viskame siis me ei raiska ainult oma raha, vaid ka tohult muid ressursse: maad, vett, energiat ja tööjõudu. Lisaks tekitab toidu tootmine tõsise keskkonnakoormuse, sest saagikuse tõstmiseks kasutatakse väetisi ja erinevaid kemikaale. Inimene raisakab väga palju toitu. Minu pere proovib mõimalikult vähe toitu raisata.\nInimesed ostavad väga palju riideid Hiinast kus tehakes riideid naftast. Taaskasutuspoodises on väga palju riideid kus on riideid ja asju mida inimesed enam ei taha. Sinna viiakse korralikke riideid. Ka mina käin taaskastuspoodides, ma käin koos emaga ja me viime sinna asju mis on mulle või minu vennale väikseks jäänud riideid ja ka mänguasju millega ta  või mina enam ei mängi. Eelistada võiks kodumaiseid oma lähedal toodetuid asju ning pigem vähem kui rohkem.\nMina arvan, et inimesed reostavad keskkonda, sest nad arvavad et neil on vaja väga palju toitu ja väga palju riideid. Kuigi nad viskavad väga palju toitu ja riideid ära.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('32e357b7-e92d-4d1d-b319-ac360c60aa84', 'title', 'Keskkonnareostus');
