INSERT INTO core.text(id, content)
VALUES ('46187459-c9ee-4300-9b0e-d356a0270d43',
        'Inimeste tarbimisharjumused aina halvenevad. Üha rohkem toodetakse kaupa, mida tegelikult kellelgi vaja ei lähe. See algas juba 18. ja 19. sajandil tööstusrevolutsiooniga, läbi mille manufaktuuritootmine asendus massilise vabrikutootmisega. Missugused on tarbimisharjumuste avaldumisvormid, mis meie elu muudavad?\nOdavad veebipoed tuleks ära keelata. Need tekitavad sõltuvust, sest iga väike ost annab väikse koguse dopamiini ja elevust, mille pärast tekib soov uuesti osta. Enamus ajast see asi, kui see üldse kohale jõuab, muutub mõtetuks või igavaks pärast paari kasutamist. Iga ost on ka rahakotile kahjulik, sest aja möödudes kõik summad hakkavad kuhjuma. Ma arvan, et enne ostmist tuleb väga põhjalikult läbi mõelda, kas see on mulle vajalik.\nIgasuguste riiete hulka võiks vähendada. See kogus riideid, mis on võimalik ükskõik kust saada on massiivne. Mitte et see oleks halb, kui on suur valik, aga suurtes kaubanduskeskustes ei pea iga nurga peal olema veel üks riidepood. Enamus neist riietest niikuinii lõpetab kuskil taaskasutuspoes või kapi põhjas. Minu meelest võiks kanda vanu riideid kuniks need selga enam ei mahu, ning siis osta paar uut püksi või särki.\nKõik saavad oma tarbimisharjumusi muuta. Selleks peab end lihtsalt kokku võtma ja mõtlema, mis on väärt seda summat, mis ma maksan. Nii on võimalik päästa oma rahakott ja Maa suurest hävingust.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('46187459-c9ee-4300-9b0e-d356a0270d43', 'title', 'Masstoodanguga seostuvad tarbimisharjumused');
