INSERT INTO core.text(id, content)
VALUES ('6f74fe44-94a0-49b0-bcb4-2043d7c1e354',
        'Tänapäeval on moes kiirmoe tarbimine ja uute huvitavate toitude proovimine. Inimesed tihti ei mõtle, mida see kõik endaga kaasa toob. Mida teeb kõigi moes olevate toodete tarbimine maailmale?\nUute huvitavate toitude proovimine on suur toiduraiskamise allikas. Kui proovitakse uusi moes olevaid toite, siis väga tihti need ei maitse paljudele inimestele ning need on ka väga kallid. Nad proovivad seda poppi toitu , neile ei maitse see ja nad lihtsalt viskavad selle ära. Tihti selliste toitude valmistamine on väga suur enda ressursside ja ka muude ressursside raiskamine: maa, vee, energia ja tööjõu. Jah, moes olevaid toite võib proovida, aga tuleb väga hoolega mõelda, mis töö on sinna taha pandud ja kui tõenäoline on see, et see sulle ei maitse.\nKiirmoe tarbimine on väga suur raiskamine ja kliimasoojenemise esilekutsumine. Need kiirmoe riided koosnevad naftast ja muust halvast, mida inimene lihtsalt pärast esimest kandmist ei taha enam nähagi. Kiirmood ei lase kehal hingata, seda pole mugav kanda ja see ei sobi. Ostes näeb pilti peal ilus välja aga kui kohale jõuab, siis pole värv üldse sama ja see tundub nagu tükk naftat. Selle tarbimist tuleks vähendada ja selle reklaamimist keelata. Tuleb osta pigem lähedal disainitud ja valmistatud rõivaid, mis kestavad kaua ja mida saaks paljude esemetega kombineerida.\nTuleb eirata kiirmoe ja moes olevate toitude reklaame internetis. Kui neid tooteid siiski tarbida, siis mõistlikult ja mõeldes, kas mul on ikka seda vaja ja kui palju ma seda päriselt kasutaks. Kui inimesed ei lõpeta kiirmoe tarbimist, toiduraiskamist, siis pole varsti enam ressursse, millega neid toota ja maailma, kuhu neid tööstusi rajada.');
