INSERT INTO core.text(id, content)
VALUES ('3564087d-5414-4305-9c14-f9e8c179ed3d',
        'Meie ümber on väga palju inimesi, kes vajavad igapäevaselt erinevaid tooteid. Väga arvukalt on inimesi, kes on väga head tarbijad, kõik mida ostetakse saab kasutatud ilma raiskamata. Paraku on ka inimesi, kes ei mõtle selle peale kui palju jääb üle näiteks süüa, erinevaid hügieeni tarbeid ja kuhu need kõik pärast lähevad. \n     Kogu toit, mis meie toidulaual on, ei tule niisama taevast, vaid raske tööga. Toome näiteks Eesti elanikud, kelle kodumajapidamises tekib iga inimese kohta aastas keskmiselt 61 kg toidujäätmeid. Selleks, et seda arvu vähendada tuleb hoolikalt läbi mõelda, mida me ostame, kui palju me seda ostame ja kas see on üldse vajalik ost. \n      Laiaslaastus on Eesti väga hea riik kus elada, sest meil ei ole mitte millestki puudus. Kõik, mida me soovime on enamjaolt poes olemas. Tuleb mõelda läbi iga ostu kui sa hoolid enda keskkonnast, kuna kogu see rämp, mis alles jääb ei kao niisama kuhugi, vaid jõuab kuhugi ookeani, mis kahjustab kogu maakera. \n      Mina isiklikult püüan tarbida võimalikult mõistlikult ilma raiskamata. Muidugi ma jätan ka vahepeal midagi alles aga annan siiski parima, et seda vältida. Poes ostan ma nii vähe kui võimalik ja nii palju, kui vajalik. Proovin olla eeskujuks sellesosas väiksematele.     \n       Lihtsalt öeldes on inimestel nii häid, kui halbu harjumusi. Üks suurtemateks halbadest harjumustest on raiskamine. Tuleb mõelda läbi iga oma ostu poodi minnes, kas see on vajalik jne. Mina annan endast parima, et mitte raisata kas toitu või teisi asju. Soovitan seda teistel ka teha.');
