INSERT INTO core.text(id, content)
VALUES ('183c3ef2-189b-49a8-917d-d9669c7263de',
        'Väga paljud inimesed ei pane tähele, kui palju nad midagi raiskavad. Inimesed arvavad, et kui viskavad väiksemaid toidu koguseid ära siis see ei mõjuta midagi. See on vale. Kõik peaksid olema õnnelikud, et neil on midagi. Miks inimesed siis raiskavad paljusi tarbeid, mitte ainult toitu? \n Minule tundub, et inimestel on harjumus raiskamisega ja toidu ära viskamisega. Need kes tavaliselt toitu ära viskavad saavad seda endale rohkem lubada ehk osadel inimestel on ükskõik sellega.\nNäiteks paljud inimesed viivad taaskasutuspoodi korralikke riideid mis on ilmselgelt veel kantavad või toidukadu ehk raistud toit mis mingil põhjusel jääb tarbimata ja visatakse toidujäädmetena ära. Ma arvan, et raisatud toitu ei võiks kohe ära visata. Seda näiteks võiks kellegile pakkuda või jätta homseks, mis ei oleks raiskamine. Noortel on probleemi sellega, et kui nad proovivad midagi selga ja tundub seljas ebamugav siis saadakse kohe sellest lahti. Paljud inimesed tellivad ka mõttetuid vidinaid Hiina veebipoodidest ning see kõik lihtsalt hakkab koguenma kuni neild vaja nendest lahti saada. \nInimesed kes raiskavad erinevaid tarbeid võiksid tajuda, et see on tõesti suur probleem ja seda peaks seda vähendama. Neil on tavaliseslt sellega ükskõik ja saavad rohkem lubada. Inimestel on harjumused raiskamisega ehk nad suurt pilti ei tee sellest.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('183c3ef2-189b-49a8-917d-d9669c7263de', 'title', 'Inimeste tarbismisharjumus');
