INSERT INTO core.text(id, content)
VALUES ('c63edf54-4cde-4e64-bf9f-3ba560bb7c15',
        'Inimesed tahavad kogu aeg uusi ja paremaid asju. Tänu sellele on paljudel tarbimisharjumused, mis on ohtlikud meie planeedile ja keskkonnale. Kuidas vähendada toiduraiskamist? Miks me peaksime eelistama riiete osas kvantiteeti kvaliteedile?\nToidu raiskamine on ühiskonnas suur probleem. Eestis tekib kodumajapidamises iga inimese koha aastas keskmiselt 61 kilogrammi toidujäätmeid ja sellest 42% ehk 26 kilogrammi on toidukadu ehk raisatud toit. Toidu raiskamine kulutab meie enda raha ja muid ressursse. Selleks, et toidukadu vähendada, peaks ostma poest ainult vajaliku kauba ja vältida selle roiskumist, valmistama esialgu väiksemad toidukogused, hiljem saab toitu juurde teha, kui vaja. \nInimesed ostavad suure osa enda riietest kiirmoepoodidest. Sealne kaup on odav, kuid keskkonnale väga saastav ja ei pruugi olla kõige eetilisem lapstööjõu ja töötajate alamaksustamise pärast. Sellised riided ei ole tihtipeale ka väga kvaliteetsed. Sellepärast tuleks eelistadada kodumaised ja lähedal toodetud asju. Kodumaised riided on küll kallimad, aga kestavad kauem ja on tehtud kvaliteetsetest materjalidest, mis on kehal mugavad ja stiilsed. Veel üks hea variant on käia taaskasutuspoodides. Taaskasutuspoodidesse viiakse meeletul hulgal riided, mille seast võid leida endale sobivaid.\nToidu raiskamine ja kiirmoe ostmine on mõlemad ressursse raiskavad ja saastavad tegevused. Toidu raiskamine on kinni harjumustes, kuid väikeste sammudega saab neid muuta. Kiirmood on odav, kuid kodumaised riided on kvaliteetsemad, mugavamad ja kestavad kauem.');
INSERT INTO core.text_property(text_id, property_name, property_value)
