INSERT INTO core.text(id, content)
VALUES ('1ac7a9cd-f150-48ca-946e-f6dd5db9884a',
        'Inimesed viskavad ainult nädalate jooksul ära hunnikute viis riideid. Kogus, mille saavad taaskasutuspoed selle aja jooksul on üüratult suur. Kas peaks viima noori taaskasutuspoodide lattu ja näitama neile kui palju asju ära vistataksse?\nNoori peaks viiama taasakutuspoodidesse, et nad näeksid ja saaksid aru kui halvad on inimeste ja nende endi tarbimis oskused. Kui noored näeksid, kui palju visataksse ära riideid siis see paneks neid mõtlema, et kui palju nemad tegelikult ära viskavad ja kust nad üldse neid riideid ostavad? Artiklis räägitaksse, et „Eesti noored peaksid alustama oma riiete ostmist kodumaalt, kuna hiinast tellides ei ole materjal enamjaolt kõige parem“. Kuna paljud inimesed ostavad oma riideid hiinast mis põhjustab riiete halva materjali ja väljanägemise pärast veelgi rohkem ära visatuid riideid. Viies inimesi nägema, kuidas tegelikult toimetatakse nende ära antud riietega, mille nad on hiinast paari euroga kokku ostunud näevad nad, et peaksid suunama oma rahad eesti riiete toodangu peale, mis on parema materjaliga ja just sellised mida nad piltide pealt nägid.\nInimesed viskavad hunnikute viisi riideid ära nende halbade omaduste pärast. Nähes kui palju ja kuidas kõik toimub võidkase suunata noori tegema paremaid otsuseid tulevikus, et kust, mida ja kui palju osta.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('1ac7a9cd-f150-48ca-946e-f6dd5db9884a', 'title', 'Halvad tarbimis oskused riiete seas');
