INSERT INTO core.text(id, content)
VALUES ('792c4d3e-48e4-4b52-ac45-32c5559004dc',
        'Aina aktuaalsemaks teemaks muutub tänapäeval toidu ja riiete raiskamine. Ostetakse igasugu asju kokku, mõtlemata sellele, kas neid päriselt ka tarbitakse. Selle tagajärjel tuleb taaskasutuspoodidesse iganädalaselt hulk korralike riideid, mida keegi enam ei vaja. Nii nagu riietega, läheb ka toidu valmistamiseks vaja erinevaid ressursse: energiat, vett, materjale, tööjõudu. Inimesed ei mõtle sellele, et enamus tuleb kellegi heaolu kulult ning raiskavad mõttetult tooteid, mõtlemata sellele kui palju on inimesi, kes nälgivad ja ei suuda endale korralike riideid lubada.\nKelle heaolu kulult see kõik tuleb? Riiete kui ka toidu valmistamiseks on vaja tööjõudu, halvimal juhul valmistatakse tooteid ekstreemselt halbades tingimustes, kasutades lapstööjõudu. Keegi näeb väga palju vaeva, et valmistada neid riideid või tagada toidu toodang, mis hiljem ära visatakse. \nIga aasta läheb ära viskamisele mitukümmend tonni toitu. Vaadates, kui palju on maailmas inimesi nälgimas, saaks selle raisatud toidu eest toita tuhandeid inimesi. Sama ka riietega, ostetakse igasugu riideid kokku, mis hiljem viiakse taaskasutusse või läheb ära viskamisele. Selle asemel saaks paljusi inimesi aidata, kes ei saa omale soojasi, korralike ja puhtaid riideid lubada.\nMaailmas tuleks tõsisemalt ette võtta tarbimisharjumuste probleemid. Inimesed peaksid mõistma, kui palju kahju toodete raiskamine ühiskonnale teeb. Keegi näeb suurt vaeva, et võimaldada toitu ja riideid teistele, samal ajal kui neid massiliselt ära visatakse.');
