INSERT INTO core.text(id, content)
VALUES ('3581eadd-a299-4020-a232-5ebb5de5245d',
        'Raiskamine on teema millele peaks igaüks meist tähelepanud pöörama. Inimesed soovivad endale ainult mugavamat elu ja soodsamaid hindu, selle pärast on paljudel halvad tarbimisharjumused, mis kahjustavad meie loodust ja keskkonda. Kuidas seda vältida?\nPoodidest riiete ostmine on parem kui välismaalt tellimine. Väga paljud on läinud seda mugavuse teed, et istuda kodus ja vaadata internetist endale sobivaid riideid, mis on ka odavamad kui poes kohapeal. See on suur probleem kuna läbi pildi ei ole ese nii sarnane päriseluga. Pole mõtet niisama tellida midagi, et äkki võib ilus olla. Selle peale ei mõelda, et kui toode ei meeldi ja selle ära viskad, peab see lõpuks ka kuhugile jõudma. Sellises tellimise protsessis on ka suured loodust kahjustavad tegurid, üks kõige suurem on transport ühest riigist teise. Riided, mis on ära loobitud jõuavad lõpuks taaskasutuspoodide lattu.\nToit on üks tähtsamaid vajadusi meie elus. Õnnelikudel inimestel on võimalik endale osta kokku palju erinevaid toiduaineid ja valmistada maitsvaid toite. Sellised inimesed inimesed tihti ei mõtle, kuidas see võib maailma mõjutada suuremas pildis, kui nad mõtetult toitu ära viskavad. See raha mis läks selle toidu peale, mida ära visati, oleks võinud minna paremasse kohta, nt teiste aitamisele, kellel ei ole sellist võimalust. See on väga hea, kui kellegil on kodus kompost, et seda toitu kiiresti lagundada, mitte, et see jouaks prügimäele.\nInimestele peaks rohkem õpetama tarbimisharjumustest, et muuta meie loodust puhtamaks ja paremaks. Mugavus meil seda teha ei aita ja tuleb ennem mõelda kui midagi mõtetult teed.');
