INSERT INTO core.text(id, content)
VALUES ('fbd1e516-9ae8-4605-bebd-c471840fa3a1',
        'Tänapäeval kõige levinumaks probleemiks on toidu ja riiete ära viskamine. Suurema osa inimestest ei pane tähele, kui palju nad tegelikkuses toitu raiskavad ja kui palju kahju see päriselt teeb. Kuidas saaksime seda harjumust muuta?\nKõige parem viis selle probleemi lahendamiseks oleks hakata noortele tegema erinevaid ekskursioone taaskasutuskeskustesse. See aitaks lastel paremini aru saada, et milline raiskamine tegelikult toimub. Taaskasutuskeskustesse viiakse väga palju terveid, korralike ja isegi uusi riideid, mida inimesed on ainult üks kord kandnud. Nende põhjuseks võibolla ebamugavus, riided on tehtud materjalist, mis ei ole väga mugavad nahale ja ei suuda seda pikaajaliselt kanda, väljanägemine, riided nägid paremad välja modelli või mannekeeni peal, aga seljas polnud nii ilusad.\nToidu raiskamise probleemi pole nii lihtne lahendada. Toitu raiskame meie kõik, kas siis söögikohtades, kus toit ei pruugi olla kõige parem, või kodus, kui mingi toiduaine halvaks läheb ja pole kõlblik enam söömiseks. Ka mina viskan toitu ära, kui see on söögikõlbmatu või see ei maitse mulle, aga suurema osa ajast ma proovin ikkagi kõik ära süüa. Kuidas seda probleemi vähendada?\nKõige lihtsam viis toidu raiskamist kahandada on alati jälgida pakenditel olevat kuupäeva. Kui kuupäev hakkab lähenema, peaksid toidu kiiremas korras ära sööma. Teiseks proovi tõsta taldrikule piisavalt toitu, mida suudad ära süüa. Alati saab juurde tõsta, kui kõht tühjaks jääb.\nRaiskamine on suur osa meie elust, aga on ka palju erinevaid viise, kuidas kõik koos saaksime seda vähendada. Raiskamine on osa meie elust, mida ei saa üleöö kaotada, aga on võimalus hakata väikeste sammudega parema poole liikuma.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('fbd1e516-9ae8-4605-bebd-c471840fa3a1', 'title', 'Toidu säilitamine ja taaskasutuse tähtsus');
