INSERT INTO core.text(id, content)
VALUES ('791ed8ec-b41d-4a35-b878-a7e55211ad77',
        'Inimesed peavad tarbima asju. Inimesed tarbivad toitu ja vett, et ellu jääda. Nad kasutavad riideid, et enast katta ja soojas hoida, aga vahel nad ostavad asju mida nad ei kasut või ei vaja.\nToitu läheb raisku Eesti inimese kohta umbkaudu 26 kg. See tähendab, et nad ei raiska ainult end raha vaid ka teiste ressursse vaid ka maad, energiat, vett ja toidujõudu. Toit, mis me raiskame oleks võinud minna kellegile teisele, aga me viime selle lihtsalt prügikasti. Inimesed saaksid selle alles jätta ja järgmine päev soojaks teha.\nRiideid ostame me, et soe oleks ja, et meil oleks midagi väljas kanda. Me ostame riideid, sest me tahame hea välja näha. Mingis teatud aja vahemikus hangime endale liiga palju kantavaid esemeid, nagu ehted ja riided, aga me ei kanna neid. Kõik need kantavad asjad mida me ei kanna lähvad raisku ja lõpuks me viskame need lihtsalt minema. Näitaks minul on sahtli täis asju, mida ma pole aastad kandnud. Igal isikul on võimalik need vanad või kasutud riided viia taaskasutuskeskussese.\nInimesed ei raisk ainult riideid ja toitu vaid ka elektroonilisi asju näiteks; röster telefon arvuti jupid. Paljud inimesed ostavad endale uue telefoni, kui ekraan katki läheb või ostavad endale kõige uuemad arvuti jupid. Suurem osa telefonidest ja arvui osadest läheb prügi kasti, kust need lähvad prügimäele.\nInimesed ei peaks ostma endale nii palju asju mida nad ei kasuta. Ilma nende mõtetute ostuteta saaksid nad raha kokku hoida ja and enda ostudega teistele kasu anda. Inimesed võiksid mõelda ennem ostude tegemist.');
