INSERT INTO core.text(id, content)
VALUES ('6292a994-82e1-4505-a6d3-fa900f4326a5',
        'Paljud inimesed raiskavad lihtsalt toitu ja ei mõtle selle peale, mis selle tagajärjed võivad olla. Need kes raiskavad võivad tavaliselt seda endala lubada, aga nii on põhimõtteliselt terve Eesti. On aga palju vaeseid peresi ja inimesi, kes just ei saa raisata vaid püjavad hoida raha kokku, et süüa osta.\nEesti kodumajapidamises tekkib iga elaniku kohta umbes 61 kg toidujäätmeid iga aasta. Selle peale mõeldes 61 kg toidujäätmeid iga Eesti elaniku kohta on väga suur arv millega saaks toita kodutuid ja vaesemaid peresi, kes elavad vaesuses ja kellel ei pruugi olla piisavalt raha, et oma pere kõhtusi täis hoida.\nSelleks et mitte raisata oma toitu mida keegi ei söö saab ka annetada ära näiteks kirikutesse või kodutute varjupaika. Seal võetakse vastu igasugust abi ja saab vähendada üle Eesti toidu raiskamist, kui inimesed annetaksid. See ei oleks kohene muudatus vaid pigem pikaajaline mis muudaks väga paljude elusid. See võib paari aatsa jooksul 61 kg toiduraiskamise tõmmata ala kümnete kg viisi ja aitaks paljusi välja vaesusest.\nInimesed võiksid vaadata palju nad raiskavad ja mõelda, et kas on vaja kohe ära visata või saab ka seda annetda, et teisi välja aidata kes ei ole nii rikkad ja kes vajavad abi.');
