INSERT INTO core.text(id, content)
VALUES ('90517cc1-02e4-49ee-8000-5e7418f817e7',
        'Inimesed raiskavad ja viskavad minema väga suurtes kogustes toidujäätmeid. Seda tehes raiskame ka oma ressursse. Mis probleemid võivad sellega kaasneda ja miks inimesed toitu ära viskavad.\nMõned inimesed saavad endale seda lubada. Mõned inimesed, kes viskavad väiksemates kogustes toitu ära arvavad, et nad ei tekita sellega kahju. Inimene ei tea kui suurtes kogustes raisatakse toitu ja kui palju ressursse sellega raiskame.  Aasta jooksul viskab inimene tegelikult väga palju toitu minema. Eesti inimene viskab aastas minema keskmiselt 61kg toidujäätmeid, 42% sellest ehk 26kg moodustab toidukadu. Toidukadu on toit või toiduaine, mis mingil põhjusel jääb tarbimata ja visatakse ära. See kogus mida inimene ära viskab oleks saanud väga palju ressursse säästa.\nToidu ja toiduainete ära viskamisel raiskame me väga palju olulisi ressursse. Toidujäätmete ära viskamisel ei säästa me ainult raha vaid ka maad, vett, energiat ja tööjõudu. Kui iga inimene ostaks hoolikalt oma toiduaineid ja ei raiskaks nii palju, siis säästaksime kõik olulisi ressursse. Toidu tootmisel kasutatakse väetisi ja erinevaid kemikaale, et saagi kogus tõuseks. Need ained reostavad meie õhku ja ka see omakorda tekitab palju probleeme.\nToitu raisates raiskame ka muid olulisi ressursse, mida saaks panustada vajalikesse asjadesse. Toidu tootmisel kasutatakse väetisi ja kemikaale mis reostavad meie õhku. Õhu reostused tekitavad omakorda kahjusi juurde. Inimesed on harjunud toitu raiskama ja seda ei saa muuta üle öö.');
