INSERT INTO core.text(id, content)
VALUES ('44a80100-7242-4379-88e0-8853188eef5c',
        'Asjade tarbimine on meie igapäeva lahutamatu osa. Erinevaid rõivaid ja tarbeesemeid tellitakse tohutult suurtes kogustes veebipooditest üle terve maailma. Tellimise ja ostmisega on tekkinuid tõsiseid probleeme. Kas selline ületarbmine on vajalik meie planeedile?\nAastate jooksul on hakkanud inimesed rohkem toitu tarbima, sellega on ka kaasnenud toidukadu. Majapidamistes tekib iga Eesti inimese kohta aastas keskmiselt 61kg toitujäätmeid, millest toidukadu on 42% ehk 26kg. Toidu raiskamine on tõsine murekoht, mis ei kuluta ainult meie raha, vaid ka muid ressursse. Toitu ei peaks ära viskama ning seda tuleb tarbida sellises koguses, mis söödakse ära.\nRiiete tellimine on tänapäeval suur osa, kuid sellega tekib ka mitmeid keskkonnaprobleeme. Rõivaste ostmisel saadetakse suur osa riietest tagasi, mis inimesele ei pruugi sobida. Tagasi jõudnud riideid tavaliselt ei taaskasutata ning materjal jääb laokile. Lisaks on suur probleem tulnud sellest, et riietel on kehv kvaliteet ning neid kantakse ainult paar korda. Eelistama peaks kodumaist või meile lähedal toodetud asju ning pigem väiksemas kui suures koguses.\nInimeste jaoks on esemete tarbimine ja ostmine igapäeva harjumus, aga selle kõrvalt ei märgata kaotusi, mida tekitame. Toidukadu ja riiete tellimine on selle suur osa, me kulutame enda raha kui ka muid oluslisi ressursse, mis tekitavad meile suuri keskkonnakoormusi. Tarbimisharjumusi on võimalik muuta, alustades väikeste sammudega.');
INSERT INTO core.text_property(text_id, property_name, property_value)
