INSERT INTO core.text(id, content)
VALUES ('e6f2d1e9-1d38-4241-89f9-6e378214c0e1',
        'Tarbimine on inimese elus suur osa. Me tarbime, kui me sööme, kanname riideid, sõidame autoga, käime pesus jne. Ilma tarbimiseta oleks raske oma elu ette kujutada, sest kõik on sellega juba harjunud ning harjumusi ei ole kerge muuta.\nKuidas toidu raiskamist vähendada? Toit on piiratud resurss, kuid inimese vajadused on piiramatud. See tähendab, et inimesed tahavad elu lõpuni süüa, kuid toitu, mida süüa, ja koht, kus toitu kasvatada, on piiratud. Paljud inimesed viskavad toitu ära, sest nad arvavad, et nemad ei mõjuta suurt pilti. Nad on ju ainult üks inimene? See on vale, sest kui kõik inimesed maa peal niimoodi arvaksid, ei jätkuks meile mitte midagi süüa. On vaja väikeseid muudatusi, et muuta suurt pilti ja kui kõik muudaksid oma toidutarbimist veidi, nt ei viskaks vana sööki ära, kui seda enam süüa ei taha ja ostaks poest tooteid, mille pood oleks muidu ära visanud, oleks see meie planeedile väga suur heategu.\nMiks tarbivad inimesed kiirmoodi? Kiirmood on mood ehk riided, mis tulevad kiirelt turule, on mingi aeg populaarsed, kuid lähevad turult sama kiiresti kui tulid. Kiirmoodi iseloomustab veel soodne hind ja halb kvaliteet. See ei tähenda muidugi, et kõik kiirmoe riided on ühesugused ja halvad, vaid et tavaliselt üritatakse teha kiirmoodi võimalikult soodsalt ja kergelt. Tänu kergele ja soodsale tootmisele on ka saadus ehk kaup soodsam, mis omakorda tekitab inimestes suuremat soovi seda osta. Niimoodi ostetakse palju ebavajalikku kaupa kokku ja kui tuleb uuem ja ägedam kaup peale, visatakse vanad lihtsalt minema.\n Inimesed on mugavad ja ei taha endale asju keerulisemaks teha. Et muuta suurt pilti, on vaja, et kõik inimesed teeksid väikeseid muudatusi. Aitaks toidu ja riiete mitte nii kergekäeliselt ära vsikamine ja keskonnasäästlikum mõtteviis.');
INSERT INTO core.text_property(text_id, property_name, property_value)
