INSERT INTO core.text(id, content)
VALUES ('4fcd3fd8-db9c-4bdf-ac8f-b65dae284e85',
        'Tänapäeva inimesed tarbivad liiga palju. Ostetakse rohkesti asju ja toitu, tihti ilma mõtlemata kas mul tegelikult ka seda vaja on. Ei mõelda, mis kahju ületarbimine meie planeedile teeb.\nInimesed on harjunud, et kõike on saada, näiteks on inimene poes ja näeb, et poes on ilus särk ja ostab selle, sest tema õnneks on see ka allahindlusega. Pärast koju minnes näeb ta, et kuna tal on nüüd nii palju särke ja kaks teist särki enam nii väga talle ei meeldi viib ta täiesti kantavad riided prügikasti. Inimene ostab, tarbib ja viskab ära väga palju asju ja toitu. Hiinast on hea tellida odava hinnaga palju riideid, kuid tegelikkuses ei kanna ta paljusi nendest riietest ja kuna need olid odavad visatakse need minema.\nToiduga on samamoodi inimene läheb poodi ja ostab seda mida ta tahab. Poes on jogurt soodushinnaga ja inimene ostab kohe kaks pakki, ta ei jõua ühte pakki ära juua, sest see on vanaks läinud ja ta viskab selle lihtsalt minema. Pärast teeb ta kodus süüa ja kui toitu üle jääb viskab ta selle minema ilma mõtlemata kui palju kahju see tekitab. Oletame, et on sõõdud ja nüüd peseb ta nõusi ja heliseb uksekell, ta läheb ta seda avama, kuid jätab vee jooksma. Ka see on raiskamine. \nKogu aeg on poes kõike pakkuda ja alati on kuskilt veebilehelt midagi tellida, sellepärast tarbtakse meeletult palju. Planeet ei suuda sellist elustiili enam kaua pakkuda. Vaja on teha muutusi, sest niimoodi edasi minna ei saa.');
