INSERT INTO core.text(id, content)
VALUES ('c86a1432-218a-4a53-bf0d-4204970ce8b6',
        'On teada, et inimesed raiskavad ülemäära riideid ja toitu kui ka teisi igapäevaseid tarbeasju. Inimesed ise ei pruugi teada kui palju nad tegelikult raiskavad. Kui palju inimesed igapäeva elus raiskavad tarbeesemeid?\nMeile võib tunduda, et me ei raiska nii palju, kuid tegelikkuses isegi kord siit kord sealt jäi üle, see lõppute lõpuks on kokku väga palju ja me ei teagi seda. Nagu oli tarbitoitutargalt.ee kirjutatud „Kodumajapidamises tekib iga Eesti inimese kohta keskmiselt 61 kg toidujäätmeid.“ Toidu raiskamine on väga suur probleem ja inimesed peaksid sellega arvestama. Miks inimesed raiskavad?\nInimesed raiskavad kuna nad saavad seda endale lubada. Suur kogus toidu raiskamine tuleb peredest kus on umbes 2-3 last. Laps ei taha või ei jaksa kõik ära süüa mis talle ette pannakse ja viskab ülejaagid ära sama ka täiskasvanutega, et ostis liiga palju ja ei jõua kõike ära süüa. Raiskamine tuleb kodutest kus on vähe rohkem raha ja ostetakse üleliia toitu ja kõike kas ei jõua või ei jaksa ära süüa. Mis toiduraiskamine meie keskkonnale teeb?\nToiduained läbivad palju punkte näiteks kemikaalidega kasvatamine siis masinatega korjamine ja pakendamine ja transport kas lennukite, laevade või rekkatega. Looma lihaga samamoodi transport ja see teeb meie keskkonnale suurt koormust. Kõik see pikk protsess, et toitu raisata. \nMe peaksime hakkama tegelema selle probleemiga, et aidata meie keskkonda. See protsess pole liht ega kiire kuid vajalik tervele inimkonnale. Toitu jäädakse raiskama ja selle vastu pole midagi teha, aga me saame seda arvu vähendada.');
