INSERT INTO core.text(id, content)
VALUES ('84599fce-9123-4bc1-989f-dab959b5f523',
        'Inimestele meeldib osta igasugu asju. Olgu need siis uued riided, nutiseadmed või ilutooted, vahel saab asju lihtsalt liiga palju ning pole ruumi rohkema jaoks. Aga mida teha, et nii ei juhtuks?\nKui elad jõukas peres, on võimalik, et su vanemad tihti ostavad igasugu asju, mida tavaisikud endale lubada ei saa. Tihtipeale pole neil ka seda kõike vaja ning asjad aina kogunevad ja kogunevad, kuni on võimatu midagi täpset leida. Eriti halvad harjumused võivad viia ka sellise olukorrani, kus sagedane ostlemine teeb pere väga vaeseks.\nSa ei pea alati lihtsalt istuma ja vaatama, kuidas teie raha voolab minema. Sul on võimalus rääkida vanematega või teha finantsaudit, et nõu saada. Isegi halvimates olukordades inimesed on end august välja vedanud.\nTähtis on osta asju kasutamiseks, mitte lihtsalt silmailuks – sa pead teadma, milleks sul seda vaja läheb. Näiteks on hea osta paar jalatseid, mis näevad sinu arust head välja ning on igapäevaseks kandmiseks head, kuid mitte paari jalatseid, mille ostsid lihtsalt sellepärast, et need lahedad välja nägid. Oluline on ka vaadata, mida teised inimesed sellest tootest arvavad. Kui arvustused on rohkem negatiivsed, pole vist hea mõte seda endale osta.\nKui tead kedagi, kellel on sama toode, mida sa vaatad, küsi neilt seda prooviks. Enne ostmist toote laenamine sõbralt on hea viis otsustada, kas sa seda tegelikult tahad või ei. Kui oled sõbra toodet piisavalt kasutanud ning see sulle meeldib, võid ostu ära teha.\nVahel võib toode ka liiga kalliks osutuda. Sel juhul võrdle erinevate poodide hindasid, otsi odavamat alternatiivi või otsi kusagilt allahindust. Tähtis on ka teada, kas poel on hea maine, st kas inimesed on nende teenindusega rahul või mitte. Internetist ostes on kasulik tellida poest, mis on sulle lähedal, sest saatmistasud on madalamad.\nRahaga peab alati tark olema, eriti nüüdisel ajal, kui majandus on pidevalt muutumas. Kui arvad, et oled halva rahalise otsuse teinud, ära karda abi küsida ja õpi vigadest. Järgi kindlasti abi inimestelt, kes teavad, millest nad räägivad.');
