INSERT INTO core.text(id, content)
VALUES ('cac45a24-e396-4adf-96a6-355e68344732',
        'Elus oleme kokkusattunud brändiriietega. Need on tavaliselt vastavalt poodides. On inimesi kes pole elus brändiriideid kunagi ostnud. Kõige rohkem on nende seas vanu inimesi, kes kannavad isetehtud rõivaid. Kuigi pole nad uute aegadega kokku puutunud on neil õige elustiil. Brändiriided on kallid, disaini poolest koledad ja vahest ka ebamugavad kandmiseks. \nBrädiriided on populaarseks teinud noored inimesed. Ned, kes ei kanna neid riideid on noorte jaoks igavad ja vaesed.  Noored ajavad oma vanemad allati poodidesse, kus neilt paljapäeva jooksul lihtsalt raha varastatakse. Lastele peab selgeks tegema selle, et brändi- ja tavariiete vahel pole mingit erinevust. Noored ei saa raha kasutusest aru, kuna nad ei käi tööl. Vanemad inimesed saavad aru ja kasutavad raha targasti.\nTavaliselt on brändiriided väga kallid ja ülatuvad 50 eurost kuni 100 või 300 euroni. Kuna need on nii kallid on nendel alati allahinnad. Soodus pakkumised on alati väga head tavapoodides kuid brändipoodides jäävad need kehvaks. Brändipoodides, võivad 300 eurosed jalanõud maksta allahinnaga 200 eurot, vahe on suur kuid hind on ikkagi liiga kallis.\nDisani poolest on need riided mõttetud. Tavalised mustad särgid ja hallid püksid võivad kokku maksta 600 eurot. Rahalises mõttes ,võib üprishea arvuti maksta vähem kui mõni mõttetu riideese. Kuna neid asju on reklaamides hästi turundatud on selles ka palju ostjaid. Ned reklaamid võivad ka vana inimese kallist brändiasja ostma panna.\nRahalises suhtes maksavad brändiriided rohkem ,kui kodus liigtoidu ostmine. Selletõttu jäävad inimesed nälga ja surevad oma lollusest. Brändiriidete kulunemine muudab inimese valiku selle ostmiseks suurelt. Kui riideese kulub 3 kuu pärast kasutamist juba ära, on selle ostmine täiesti mõttetu.\nBrändi riidete populaarsus ei tohiks sind neid ostma panna, need on lihtsalt mõttetult kallid ja tava riietest natuke paremad. Mina soovitaks osta riideid tavapoodides. Pole vahet kas särgil on mingi nimi peal või mitte. Elu tähtsaim mõtte on ellujääda ja majaliselt areneda.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('cac45a24-e396-4adf-96a6-355e68344732', 'title', 'Inimesed peavad vähem brändi riideid ostma');
