INSERT INTO core.text(id, content)
VALUES ('6c86a007-dcac-4874-8b84-32361e085b56',
        'Tarbimine on üks suurimaid osasid inimese igapäeva elus. ilma tarbimiseta ei oskaks elu ette kujutada, sest me tarbime nii süües, juues kui ka riietekandmises. Igal inimesel on enda tarbimisharjumused mida on raske muuta.\nToidu raiskamine on üks suurimaid probleeme. Inimesed tihti arvavad, et toitu on veel ja see ei saa niipea otsa. Sageli visatakse väiksemas koguses toitu ja arvatakse, et see ei mõjuta väga midagi. Tegeligult on see vale, sest iga aasta tekib 61 kg toidujäätmeid iga Eesti inimese kohta, millest raisatud toit moodustab 42% ehk 26 kg.  Sellega sa raiskad enda raha kui ka maad, vett, energiat ja tööjõudu. Toitu raiskamist ei saa muidugi üleöö vähendada, sest see on kinni inimeste harjumustes. Alustada võib väiksemate asjadega näiteks ostad poest neid mis sul on vaja, teed endale normaalses kogustes süüa, et hiljem ei peaks ära viskama.\nRiiete tellimine Hiinast on suur keskkonnaprobleem. Inimesed tellivad välismaalt riideid, et käia tänapäeva moega kaasas ja tavaliselt on sealt tellitud riided odavamad kui kodumaised. Riided mis tellitakse Hiinast koosnevad sageli naftast, mis on meie tervisele kahjulikud  ja on kasutatud lapstööjõudu nende valmimisel. Iganädal viiakse sellised riided taaskasutuspoodidesse, mis jäävad lattu, sest neid ei jõuta ära osta kuna neid on nii palju ja need jäävad keskkonda kahjustama kuna need rõivad sisaldavad kemikaale ja naftat\nInimeste tarbimisharjumused on sageli keskkonnale kahjulikud. Inimesed raiskavad meeletult toitu, mis kahjustab meie endi kui ka planeedi ressursse. Riiete tellimine välismaalt kahjustab nii meie tervist ja keskkonda, sest need sisaldavad igasugust kemikaale. Tarbimisharjumusi on võimalik muuta alustades väiksemate sammudega.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('6c86a007-dcac-4874-8b84-32361e085b56', 'title', 'Inimeste tarbimisharjumused');
