INSERT INTO core.text(id, content)
VALUES ('bb166b71-6cdd-46a3-8c62-558c9cc62f0d',
        'Tänapäeva toodete valik on väga lai. Tavapärastes poodides leidub nii tehnikat, toitu, riideid, koduvahendeid ja veel palju erinevaid tarbetooteid. Inimestel on alates tööstuse arengu algusest tekkinud harjumus tooteid raisata, mille peamiseks põhjuseks on toodete odav hind massilise tootmise tõttu. Millised on tänapäeva inimeste tarbimisharjumused?\nKaupade raiskamise tagajärjed on meile kahjulikud. Toodete raiskamise peamine kahju esineb ökonoomias ja meid ümbritsevas keskkonnas. Ma arvan, et tänapäeval on enamus inimeste harjumus liigsete tarbetoodete ära viskamine, mille tõttu kannatab loodus reostuse tõttu. Meil on vaja puhast keskkonda heaks, odavaks ja tervislikuks eluviisiks.\nInimeste teadlikkus raiskamise kohta on minimaalne. Minu arvates ei õpetata ega teavitata tänapäeval inimesi piisavalt selle kohta, mis kaasneb pideva raiskamisega. Selle üldiseks põhjuseks on puuduvad plakatid ja reklaamid raiskamise kohta, mistõttu ei jüua see informatsioon inimesteni. Teadlikkus toodete raiskamise kohta aitab meil hoiduda keskonna reostusest suurel määral.\nInimeste tarbimisharjumused on tänapäeval sarnased. Tarbete raiskamise täielik olematus on võimatu, kuid meil on võimalik ühiselt koos töötada ning seda hulgaliselt takistada. Meil on ka võimalik leida infot ning ennast harida selle kohta, kuidas mitte liigselt kaupu ära visata. Puhas keskkond on võti meie tulevikku.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('bb166b71-6cdd-46a3-8c62-558c9cc62f0d', 'title', 'Millised on tänapäeva inimeste tarbimisharjumused?');
