INSERT INTO core.text(id, content)
VALUES ('7c09cb26-13b9-423e-8287-7bfdd3caebfa',
        'Tänapäeval on inimestel halb tarbimisharjumus. Miks on see nii ja kuidas seda paremaks saaks teha?\nTävapäeva tarbimisharjumuste tõttu viskavad inimesed ära väga palju toidujääke. Toidu raiskamine on halb harjumus, kuna väga paljud inimesed üle maailma nälgivad. Selle summa todujäägitega mis me ära viskame saaksid paljud toidu vajaduses inimesed söödud.Artikkel „Toidukaost“ on välja toonud et ainult Eestis juba tekib aastas 61 kg toidujäätmeid kodumajapidamise peale millest 42% ehk 26 kg on toidukadu. Eestis toidukadu on väga suur ja oleks vaja seda vähendada.\nPeale toidukadu on ka riietega tarbimisega probleem. Inimesed tellivad välismaalt palju riideid mis on halva kvaliteediga. Suurem osa välismaalt tellitud riiedest tulevad Hiinast. Hiinast tulevad paljud riided mis näevad ilusad välja aga on halva kvaliteediga ja toodetud ainest mis pole su kehale hea. Selliseid riideid ostetakse nende sootsa hinna pärast. Moedisanier Eve Hanson tõi välja häid näiteid miks peaks rohkem kodumaised tooteid kasutama ja taaskastutus poodides käija. Eve Hansoni ütles „Sinna viiakse korralikke riideid, aga ka sellised, mis mingil reklaamfotol näevad ilusad välja, aga tegelikult koosnevad need naftast ja sa ei taha seda orhkem kui üks kord kanda.“ Välismaalt riideid tellides on oht et riided on halvad ja kannad neid üks kord enne kui ära viskad või annad, nii et on mõistlikum osta riideid normaalsest kvaliteedist isegi kui need on natuke kallimad.\nEestis toidukadu on suur osa toidujääkitest iga aasta ja seda võiks vähendada. Mõistlikum on osta heast kvaliteedist riideid isegi kui need on kallimad kui Hiina riided mis on naftast toodetud ja ära viskad peale korra kasutust.');
