INSERT INTO core.text(id, content)
VALUES ('c91e66b5-6d80-48cc-b4aa-54232ebb5aa7',
        'Tänapäeva üks suurimatest keskkonnaprobleemidest on toidu ja riiete raisku minek. Igapäevaelus inimesed ei märka, kui suurt koormust nad tekitavad loodusele ja keskkonnale. Me ei pruugi mõelda sellele iga päev, kuid lõppude lõpuks mõjutavad halvad tarbimisharjumused meid kõiki. Kuidas seda harjumust muuta?\nÜks tuntumatest tarbimisharjumustest on toidukaost. Probleem seisneb selles, et me võtame toitu kui iseenesestmõistetavana. Selle põhimõtte järgi jagunevad inimesed kaheks: need, kes võivad endal lubada raisata toitu ja need, kes arvavad, et väiksest raisku läinud kogusest ei juhtu midagi, kuid ühiseks on neil see, et raiskasvad mõlemad! Tühjusesse läinud toit mõjutab suurel moel loodusresursse ja tööjõudu. Selleks, et parandada keskkonnakoormust on esiteks vaja aega, inimeste soovi muuta meie keskkonda paremaks ning parandada inimeste harjumusi. Seesuguse probleemi lahenduseks on võimalik teha mõõtühikutega sööginõud, mis aitaksid inimestel süüa just see toiduports, mida nad suudavad süüa või siis teha vähem toitu.\nRiiete taaskasutamise probleemi on lahendada raskem. Taaskasutuspoodide lattu on viidud meeletult palju korralikke riideesemeid kui ka neid, mille taaskasutusse sattumise põhjuseks on see, et tellides e-poodidest näeb riie elus täiesti teistsugune või siis koosneb see naftast ja kehal on halb olla selles. Tänapäeva suurim inimeste harjumus, on tellida endale riideid kusagilt Hiinast, kus kvaliteet ei ole kõige parem. Selle asemel, et osta Hiinast ja pärast viia neid taaskasutusse, võiks osta omamaiseid riideesemeid või õmmelda endale sobivaid riideid ise. Riiete mõte on sellest, et nad oleksid kantud kaua ja hea meelega. Niiet sellist probleemi võib lahendada, tehes inimestele ekskursioone taaskasutuspoodide lattu, see oleks nii huvitav kui ka kasulik.\nInimestel on mitmeid tarbimisharjumusi, mis on keskkonnale koormaks ja mida tuleb lahendada enne, kui need muutuvad katastroofiks. Meie kui targad inimolendid peame suutma mõistlikult hoida  meie ümbrust, mitte reostama seda.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('c91e66b5-6d80-48cc-b4aa-54232ebb5aa7', 'title', 'Toidu ja taaskasutamise tarbimisharjumused');
