INSERT INTO core.text(id, content)
VALUES ('f3f7e519-18f7-4072-aa4c-33ad3fc62e21',
        'Tänapäeval on inimestel palju halbu tarbimisharjumusi, sealhulgas toidu ja riiete raiskamine, mille pärast inimesed kaotavad palju rohkem kui võidavad. Inimesed kaotavad nii omaenda raha kui ka muid ressursse, mis tegelikult on meile väga halb. Kuidas saaks teha nii et inimesed märgatavalt vähendaksid riiete ja toidu raiskamist?\nInimestele võib tunduda et see probleem üldse ei puuduta neid, sest et nende arust raiskavad nad väga vähe toitu, samal ajal kui nad tegelikult raiskavad kohe mittukümmend kilogrammi aastas, natukene siit natukene sealt ja ongi juba arutu suur kogus. Inimesed võikisid osta nii palju kui nad suudavad tarbida, kui aga nad ei suuda tarbida seda kogust siis võiksid nad neid ülejääke mis on kõlbavad lisada järgmistesse toidupaladesse.\nRiiete raiskamine on ka üks tohutumaid probleeme, Inimesed tellivad riideid kaugelt, kannavad natukene, siis saavad aru et neile need riided ei meeldi või nendel on halb kvaliteet ja siis viskavad nad need riided ära. Ühes intervjuus ütles moedisainer Eve Hanson järgmist „Eelistada võiks kodumaiseid oma lähedal toodetuid asju ning pigem vähem kui rohkem.“ see lause ütleb meile et me võiks kanda ja osta oma kodumaised tooteid, mida pole vaja oodata ja kohe saab kanda ja saab reklameerida eesti brände ka välismaal, ning seda et pigem osta vähem aga kõrge kvaliteediga tooteid kui palju madala kvaliteediga tooteid.\nMõned inimmesed ikkagi jäävad raiskama toitu ja riideid kuna neil lihtsalt on selline võimalus, neil on piisavalt raha ja ressursse sellejaoks, kuid kui inimesed kellel on piiratud eelarve või kes tahavad meie planeedile teha head ja proovivad seda teha, kasutada riideid kaua, süüa nii palju kui suudavad ja mitte osta seda toitu või neid riideid mida neil ei ole vaja siis inimeste arv kes ei panusta jääb minimaalseks.\nInimesed ostavad palju üleliigsed mis tõttu raiskavad nad meie kõikide resursse, see on meile kõigile halb kuid hulk inimesi ikka ei saa aru kui halb see meile ja meie planeedile on, meie ressurssid pole lõpmatused. Ühiskoos suudaksime raiset väga palju alandada et see protsent mida inimesed lihtsalt raiskavad ei oleks nii kriitiline.');
