INSERT INTO core.text(id, content)
VALUES ('40475bb2-70b5-4738-a287-463746d62280',
        'Üle terve maailma on väga palju tooteid, näiteks toit, riided, transpordivahendid, mugavuskaupad, meelelahutus vahendid ja veel muid, kuid inimesed kipuvad neid ära viskama. Miks siis nii? Kas need on katki läind või ära aegunud? Selle asemel võiksid nad hoopis kasutatud riideid, mobiile, voodeid ja teisi asju ära annetada nendele, kellel seda vaja on.\nKolmanda maailma riikides nagu Nigeeria, Sudaan, Uganda, India on väga suured vaesuse ja toiduvähesuse probleemid. Selle põhjuseks on muidugi see, et seal on liiga suur rahvahulk kasvanud üles ja nad peavad elama vaesuses, kuna tööd ei jätku, ja sellepärast ei saa raha teenida, et toitu või elatist osta. Sellepärast tahavad ka kõik ära joosta kusgile paremasse riiki, kus saaks leida tööd ja saaks elatist ja toitu osta.\nTeistel inimesel aga, kes elavad esimese maailma riikides, on korrapärane riiki rahvahulk. Nagu näiteks Eestis on tasakaalus rahvahulk, seepärast ei esinegi tööpuudust ja saab rahulikult tööl käia ja pappi teenida toidu ja elatise jaoks. Neil jääb ka raha üle, millega nad saavad osta lisaks toidule ka meelelahutus vahendeid ja mugavustooteid. Aga siis, kui uue ostavad, viskavad nad vanad minema. Selle asemel võiks vana ära anda. Isegi kui see on katki, saab sellest juppe ära tõmmata. Isegi Henri Anier annetab oma vanasi asju ära, nii et võtke eeskuju.\nKuidagi ikka, kipuvad esimese maailma riikides olevad inimesed oma asju ära viskama. Aga miks? Kas sellepärast et need on katki või see, et et nendest pole enam kasu? Inimesed võiksid oma kasutuid asju ära annetada. Nagu näiteks väikseks jäänd pluusi võib ära viskamise asemel anda ära kellegile, kellel pole isegi pluusi mida kanda. Need kasutamata jupid keldris, anna need Ugandalastele, nad teevad nendest uue vidina. Seda probleemi saaks lihtsasti lahendada sellega, et inimesed ei viska tooteid ära, vaid annavad midagi ära mis neil on, mida teistel ei ole. Ka seda võib öelda, et pole vaja mingeid mõttetuid asju välismaalt osta, mida sul vaja ei lähe. „Ei telliks hiina veebipoodidest juba põhimõtte pärast asju, ei läheks kaasa sooduskampaaniatega.“ Peaks ostma ainult oma kodulähiseid tooteid, nagu maksima pirukaid ja aura vett.\nSellest rääkides, võiks siis inimesi, kes elavad vähem arenenud riikides aitata, kas siis annetades oma raha või oma kasutatuid asju ära anda. Kuna meie esimese maailma riikides on lihtsam elatist teenida, ei tähenda see seda, et igalpool on nii. Kui aga ära anda kasutuid asju teistele, siis võivad nad seda näha kui kasulikku asjana, ja sellest midagi ehitada. Me peaksime üksteist aitama.');
