INSERT INTO core.text(id, content)
VALUES ('8d08b183-d0ed-42f5-8e56-c35e1f9065a6',
        'Tarbimisharjumused on teema, millele ei pöörata piisavalt tähelepanu. Inimesed on harjunud ära viskama toidujäätmeid, mida ei aita enam süüa ja riideid, mida pole nõus enam kandma. Raiskamine on inimeste harjumustes.\n Esimene tarbimisharjumus on toit. Toitu võetakse iseenesestmõistetavana. Kodumajapidamises tekib iga Eesti inimese kohta keskmiselt 61 kg toidujäätmeid. 42% ehk 26 kg raisatud toidust moodustab toidukadu ehk toit või toiduaine, mis mingil põhjusel jääb kas tarbimata või visatakse ära. Toidukao vähendamiseks on palju erinevaid viise. Näiteks saab ette planeerida eineid. Selle eesmärk on vähendada toidukadu, sest sel moel on täpselt teada, mida poest osta on vaja. Toidu äraviskamisega ei raiska me ainult omaenda raha, vaid ka  hirmpalju  muid ressursse: maad, vett energiat ja tööjõudu. \nMood on midagi, mida paljusi huvitab, aga kõik ei ole teadlikud selle mõjust planeedile. On hakatud eelistama kiirmoodi üle riiete, mis on kvaliteetsed. Kiirmood tuleb peamiselt Hiinast. Väga lihtne on saada ligi Hiina veebipoodidele ja sealt osta odava hinnaga riideid, mida kannatab ainult paar korda kanda, sest peale seda hakkab kehal halb ja ebamugav. Riiete jaoks on olemas ka taaskasutuspoed, mille eesmärk on saata riided uuele ringile. Taaskasutuspoodide ladudes on hullumeelselt palju rõivaid ja neid tuleb iga nädal juurde. Moedisainer Eve  Hanson arvab, et peaks hakkama noortele tegema ekskursioone taaskasutuspoodide lattu, et näidata, milline raiskamine tegelikult toimub.\nMõlemad, nii toit kui ka riided on midagi, milleta elada ei saa, kuid nende raiskamise mõjust ei ole inimesed piisavalt teadlikud. Igaühel soovitatakse üle vaadata oma isiklikud tarbimisharjumused, murekohtadele leida lahendused ja eelistada kvaliteeti üle kvantiteedi.');
