INSERT INTO core.text(id, content)
VALUES ('96838fe3-fe2a-4a39-9566-af36e1be75f4',
        'Inimesed viskavad ära tohutult palju toitu ja riideid mis kõlbavad veel. Aastas tekib eestlastel ligi 61kg toidujäätmeid inimese kohta, arvatavasti riideid veelgi rohkem. Mida ettevõtta?\nInimesed arvavad, et isegi kui nad viskavad pool banaani ära, siis see nende ökoloogilist jalajälge väga palju ei tõsta. Toidu raiskamisega kaasnevad paljud probleemid, (näiteks) paljud ressursid lähevad raisku, nagu raha, vesi, energia ja tööjõud. Minnakse toidupoodi tühja kõhuga ja vaadatakse „Oi see oleks küll maitsev“, ostetakse kokku igast magusat ja snäkke, mida ei jõuta kuupäevaks ära tarbida ja siis visatakse minema, ilma, et isegi vaadatakse või proovitakse kas toit kõlbab ning kas sellel on hallitus peal.\nRiideid ostetakse kiirmoe müüjatelt, mis pole ültse kvaliteetne ja ei ela kaua. Parem oleks osta kvaliteetseid riideid, et nende eluiga suureneks ja ei oleks nii palju ära viskamist. Veelgi parem oleks käija taaskasutus poodides, et vanadele riietele uus elu saaks ja äkki leiad isegi mõne kvaliteetse eseme odavamalt kui uuena ostes. Inimesed eriti noored võiksid käija kaltsukates või taaskasutus poodides ja vaadata, mida sealt leida võib. Praegu on noorte seas populaarsed riided, mida kanti aastas 2000-2010 ja just siukseid riided on leitavad kaltsukatest.\nKokkuvõtteks peaksid inimesed ostma toitu niivõrd palju kui nad jõuavad ära süüa ja tegema endale nädala menüü, kuna see on kõige taskukohasem ja parem nende ökoloogilisele jalajäljele. Riietest rääkides peaks inimene rohkem kaltsukates käima ja parem oleks osta kvaliteetne ese, kui mõni kiirmoe riidetükk.');
