INSERT INTO core.text(id, content)
VALUES ('8c708d0e-1003-407d-a7c8-0671e84dd679',
        'Inimesed on harjunud raha kulutama riiete peale, mis ei kesta kaua. Mõnel inimesel on isegi liiga palju riideid. Suurem osa riideid mis ostetakse on viletsad kiirtrendid, mis visatakse kahe kuu pärast minema. Inimesed ei taha osta kvaliteedseid riideid. Minu emal on palju riideid ja ta peab mõnest lahti saama, sest me oleme vaesed ja mulle ei meeldi, et pool tuba on riietega täis. Isa on mul alkohoolik ja kasutab oma raha suurte koguste alkoholi riiete ostmiseks,\nMõnel inimesel on nii palju riideid, et need ei mahu kõik karderoobi ära ja siis peab mõned ära viskama, seda saaks parandada niimoodi, et vanad riided taaskasutab või annetab teistele. \nInimesed ei taha osta kaua kestvaid riideid, sest kvaliteedsed riideesemed on kallid. Lihtsam on oma raha kulutada mitmele odavamale riideesemele kui ühele kallile jopele või kleidile. Taaskasutuspoodide laos otsides leiad, et korralike riiete hulgas on palju viletsaid riideid.\nInimeste tarbimisharjumuste vähendamiseks peab vähendama vajadust uusi riideid kogu aeg juurde osta. Inimene peaks enne uuete riiete ostmist mõtlema kas tal uusi riideid päriselt vaja on. Garderoobi üle vaatamine jaitab. Riideid peaks korralikult hoidma,et teised põlvkonnad saaksid neid uusesti kasutada ja siis ei pea neid ära viskama. Tänan kuulamast, seda kirju´tas Toomas Hendrik Ilves.');
