INSERT INTO core.text(id, content)
VALUES ('71afe130-dcc0-4ef3-bf29-7d3336652806',
        'Inimesed on aja jooksul hakanud juba olemasolevaoid asju järjest vähem kasutama, kuna lihtsa kättesaadavuse tõttu tekib tihemini soov asendada midagi vanemat uue vastu. Tegelikkuses võib vana tööriist või isegi riideese olla sama hea ning uuendatakse neid mitte vajaduse, vaid osturõõmu pärast.\nRaisatud toit on üks kõige paremini esile tulnud näiteid halbade tarbimisharjumuste kohta. Poodides olev lai valik erinevates värvides ja kujundites tooteid kutsub proovima midagi uut, mõtlemata sellele, mis juba kodus olemas võib olla. Poodidele tähendab tarbijatepoolne toidu äraviskamine muidugi võimalust teenida rohkem kasumit suurema nõudluse läbi, kuid mõju keskkonnale on hoopis vastupidine.\nLisaks toidule läheb raisku suurtes kogustes riideid ja ka palju plastmassi sisaldavaid asju, millest üsna suur osa satub ühel või teisel viisil loodusesse. Toodete üleküllust mõjutavad suuresti välismaised tööstused, kus toote tegemine on märkimisväärselt odavam, kuid kvaliteedi tõttu nõuab see tihemini vahetamist. Tänu sellele suureneb kahju keskkonnale veelgi.\nÕnneks on inimesed ja ka osad tootjad hakanud enda veast vähehaaval aru saama ning on keskendunud loodussõbralikumatele toodetele. Keskkonnasäästlikkusest  on saanud omamoodi uus mood, ehkki kaugeid masstootjaid see ei endiselt ei mõjuta.\nInimeste halvad tarbimisharjumused on avaldanud suurt mõju meie ühis- ja keskkonnale, kuid tänapäeval on säästlikkuse teema järjest aktiivsemaks saanud. On tekkinud ka tarbijaskonnad, mis rõhutavad eranditult keskkonnasäästlikute toodete kasutamist.');
