INSERT INTO core.text(id, content)
VALUES ('aa510b2b-59d1-4b44-9312-91d3539c9491',
        'Toiduraiskamine on suur probleem eestis nägu püstitatud ekspertide poolt nende allikate kohta raiskab keskmine eestlane vähemalt 61kg toitu aastas.Mis ei pruugi alguses olla isegi palju aga kui võtta meie totaalne populatsioon on se ikka väga palju toitu mida me saaks annetada kas või meie kodututele või siis sõduritele kes näiteks võitlevad venemaal või ukrainas.\nEt, seda vähendada võiksime me teha toidu taaskasutus süsteemin nägu Lõuna-Koreas kus on väga ränge taaskasutamis süsteem paika pandud ja se on hea.Sest seal iga kilogramm toitu mis on raisatud pead selle eest raha maksma ja ma arvan kui meil oleks sama süsteem Eestis raiskaksid inimesed vähem toitu ja oleks julgemad et, toiduga rohkem asju teha näiteks saaksid nad teha komposti süsteemi või siis anda se toit sugulastele või tuttavatele kellel on rasked ajad et, saada endale toitu.Ja se ei ole just kõige parem riigile ka kuna raiska vajalikke resursse et, toota toitu mida keegi ei söö.Eesti talunikel on juba präegugi raske aeg et, toota toitu mida me ei söö ja me teeme nende töö jubagi raskemaks kui me rasikame nii palju toitu.\nKokkuvõttes võiksime toetada rohkem enda talunikke ja nende tööd sest ilma nendeta me lihtsalt ei saaks hakkama riigina ja peaksime olema julgemad ja karta raisata toitu sest toit on privileeg mida me peaksime nautia ja mitte raisata sest igakl inimesel pole se privileeg ja me peaks nautima seda seni kaua kui meil on se.');
