INSERT INTO core.text(id, content)
VALUES ('da72a790-99eb-495f-971d-4cfab660e96a',
        'Toidukaotus on üks suuur problem meie elus. Me raiskame liiga palju toitu iga päev nii et mõned riigid ikka veel nälgivad ja me siin raiskame ja viskame minema seda. Meie maailmas ei ole mite missgi lõbmatuseni nii et me peaksime kõike õigesti ära kasutama.\n  Eestis ise iga inimene raiskab umbes 26 kg toitu mis on väga palju. kui me kõik raiskaksime vähem ja näiteks anedaksime seda siis juba toidukadu on vähem. See on tegeld suur problem ülemaa et inimesed lõik raiskavad toitu lihtsalt lõbu pärast. Kui me aitaksime teisi hoppis siis oleks maa parem koht kõikide jaoks. Me võiks aidata Aafrikad et naad jõuaksid meile ka järgi siis naad savad meid ka aitada tulevikus kui seda vaja on. Veel üks suur problem on see et inimesed ostavad asju põhimõtte pärast mida naad kanavad üks või kaks korta ja siis läheb raisku. Me koik võiks kvaliteetsemaid asju osta need on jah kallimad aga päeva lõbus see on seda väärt. Sa raiskad vähem ja aitad maailma. \n  Kokkuvõtteks siis me koik raiskame liiga palju toitu ja nuud asju nagu riideid ikka päev ja lõbuks maal ei ole enam neid asju siis me kõik nälkime ja sureme ära. Vähendame kõik koos raiskamist.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('da72a790-99eb-495f-971d-4cfab660e96a', 'title', 'Inimeste tarbimishar');
