INSERT INTO core.text(id, content)
VALUES ('60978eff-5459-419d-b7f1-a4b1439d8d41',
        'Inimestel on harjumuseks osta liiga palju asju, mida nad ei jõua ära tarbida. Vanu või üleliikseid asju võiks ära viskamise asemel edasi anda näiteks tuttavatele või siis viia taaskasutuskeskusesse. Lisaks tekitab toidu ja riiete mitte lõplikult ära tarbimine kahjut keskkonnale.\nIga päev ostavad inimesed hulgaliselt asju, millest nad vahel pooligi ära ei kasuta. Näiteks mõni inimene näeb poes ilusat särki ja ostab selle aga pärast selgub, et tegelikult see talle ei sobigi. Toiduga on sarnane lugu. Inimesed ostavad palju toitu , aga nad ei jaksa seda ära tarbida ja viskavad selle minema.\nSelle asemel, et riideid ära visata võiks neid kellegile edasi anda. Kuskil on kindlast keegi kellele sobiks see särk, mis sulle ei sobinud. Riiete taaskasutamiseks on olemas erinevad poed, mis võtavad vastu kõik, mis sa neile viid. Toiduga on keerulisem aga kui sul on kodus mõni koduloom näiteks kana võib jäägid ju talle anda.\nInimesed ei tea, mida vanade riietega teha ja lõpuks võivad need jõuda isegi loodusesse. Kuna inimesed ostavad palju toitu peab olema ka keegi, kes seda toitu palju toodab. Paljud toiduained tulevad põllult ja nende kasvatamisks on vaja väetisi ja mürke, mis kahjustavad loodust.\nInimesed võiksid mõõdukamalt tarbida ja osta smapalju kaupa, kui nad jõuavad ära tarbida. Lisakas peaksid nad mõtlema ka rohkem tagajärgedele ja sellele kuidas neid ennetada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
