INSERT INTO core.text(id, content)
VALUES ('c6dea781-c95a-4361-b02f-d414c1d5848e',
        'Inimesed tarbivad praeguses maailmas ülemäära asju. Maailmale on see väga koormav ja see tuleks lõpetada. Peamisteks murekohtadeks on minu arvates toit ja riided. \nToidu raiskamine juhtub mõtlemata, me ei pane tähelegi kui kergelt me seda teeme. Ostame mõne uue toiduaine ja proovime sellega huvitavat praadi teha, aga see ei tule välja, on kohe esimene mõte, kas jätta see külmkappi seisma või see ära visata. Külmkappi jättes muutub see lõpuks vanaks ja läheb äraviskamisele. Sellisel olukorral lohutame ennast, et pole hullu, sest vanaks läinud toitu ei saa süüa. Mina ei tee kunagi endale süüa nii, et peaksin panema selle kuhugi seisma, vaid söön kohe ära. Kõige sellega raiskame raha ja lisaks on see keskkonnale koormav. \nMa ostan riideid tihti ja pean tunnistama, et ka Hiinast. Minu põhjendus sellele, miks ma ostan on lihtne, Eestis on kaup kallis ja kuskilt mujalt tellides hoian raha kokku. Mina küll teen seda säästlikult ja kannan riideid kaua. Õnneks on mõndadesse poodidesse tehtud kogumiskastid, kuhu saab viia vanu riideid, millest tehakse uued riided. Internetist tellides on reaalsus teine, kindlasti tuleks lugeda tagasisidet ja arvestada sellega. Samuti ei tohiks teha emotsioonioste.\nInimesed peaksid rohkem mõtlema oma valikute üle ja sellele, kas nad ikka söövad selle toidu ära, mis nad on ostnud või valmistanud. Riideid tuleks teadlikumalt tellida ja ainult neid, mida sul päriselt vaja läheb.');
