INSERT INTO core.text(id, content)
VALUES ('16ff24a1-0f17-4459-adbf-ece0eb61332c',
        'Inimesed raiskavad raha mõttetutele asjadele ja reostavad maailma mõtlemata. Peamised probleemid on rämpstoidu ostmine ja välja viskamine, riiete massilik tellimine või ostmine  ja mitte kandmine ning ainult uute asjade ostmine.\nRämpstoit on madala toiduväärtusega ebatervislik valmis toit (nt hamburgerid, kartulikrõpsud). Süües rämstoitu me ei pane tähele, kuidas suurema toidu hulgast me viskame ära ja selle toiduga toidame loomi (nt rotte, linde, kodutud kasse ja koeri). Ebatervislik toit koosneb paljudest komponentidest, mis riietest tuleb väga halvasti ära.\nNende riiete asemel, mis ei kõlba kandmiseks me viskame alati ära ja ostame hulgi riideid selle asemele, mida lõppkokkuvõttes keegi ei kanna. Need riided jäävad kappi ja koguvad tolmu ning selle asemel, et vaadata riided üle ja kontrollida, mida kannan või ei kanna, ostame hulgi riideid juurde ja ei pane tähele kuidas mõttetult raiskame raha.\nProbleem riietega koosneb ka selles, et me ei taha vanu ja kasutatud riideid ning pigem ostame alati uusi riideid. Selle asemel, et osta alati uusi riideid võib vaadata ka uuskasutus keskestesse, kus võivad olla väga korralikud asjad. Inimesed ostavad ka uusi aju, et alandada stressi või lihtsalt igavuse pärast ja see on juba suur probleem.\nProbleeme taaskasutusega ja suurte rahade raiskamine on meie maailmas praeguseks hetkeks väga suur ja sellega on vaja midagi teha. Paljud inimesed ei oska kasutada rahasid õigesti.');
