INSERT INTO core.text(id, content)
VALUES ('7b40248f-829f-435b-9eb3-37a85b221342',
        'Tänapäeval masstoodetakse igasuguseid asju ja inimesed ostavad neid, sest miks mitte? Selline suhtumine viib ainult seinani ja olukorra ümberpööramine võtab kaua aega ja palju tööd.\nPraegusel ajal on lihtsam uppuda tarbimishullusesse kui kunagi varem. Meedia on igal pool ja sellega kaasneb pidev reklaamimine. Ükskõik kuhu lähen, ma näen reklaame. Kogu aeg leiutatakse midagi uut, midagi paremat, midagi ilusamat. Mis mul siis üle jääb? Ma pean selle ostma. Ei tahaks ju olla ainus, kellel ei ole seda kõige uuemat telefoni või kõige kuumemaid tosse. Kuid mis saab siis kui need asjad ei ole enam populaarsed või ei paku kellelegi huvi? Need visatakse ära. Ja mida enam on asju mida ära visata, seda rohkem on prügi millega tegeleda.\nKuidas tegeleda kuhjuva prahiga? Rohkem tööjõudu võib töötada ajutiselt aga probleemi lahendamiseks on vaja minna selle alguseni. Siin on kaks valikut: tööstused muutuvad või meie. Realistlikult vaadates on teine variant kordades lihtsam kui esimene. Eve Hansoni arvates peaksime eelistama kvaliteeti kvantiteedile ja mina nõustun sellega. Me peame olema teadlikumad kõige tarbimise suhtes. Vähem toodete ostmine ei tööta omaette, vaid nõuab ka vähem reklaamide vaatamist. See peaks olema tavaline teema, millest rääkida söögilaua taga.\nPaneme tähele oma tarbimist. Kuniks see ei muutu püsivaks teemaks meie ühiskonnas, ei saa miski muutuda paremaks.');
