INSERT INTO core.text(id, content)
VALUES ('e2dd4d36-e596-41a1-95db-240b50ebbf72',
        'Tänapäeval ei tea paljud, kuidas peaks käituma toiduga, riietega ja üldse kõigega, mis neil olemas on. Ostetakse kaupu, mis ei ole ainult kahjulikud loodusele, vaid ka inimestele endale. Riided asendatakse odavamate, suuremas koguses kättesaadavamate ja rohkem moes olevate riietega. Raisatakse olemas olevaid toiduaineid, asendades need parema välimusega, kuid ebatervislike toiduainetega. \nLapsed, noored ja täiskasvanud – kõik tahavad ju mingil moel sulanduda kokku ennast ümbritsevate inimestega. Parim viis kokku sobituda on kanda riideid, mis on moes. Ainuke probleem on selles, et ei teata vahet kvaliteedil ja kvantiteedil. Kokku ostetakse suuri hulki halva kvaliteediga riideid sealt, kus neid odavalt valmistada saab. Lõpuks kantakse neid riideid ainult paar korda ja visatakse minema.\nKoju ostetakse rohkem toitu, kui ära söödakse – sellest tuleneb toiduriknemise ning suurtes kogustes toidujäätmete ära viskamine. Lisaks toidujäätmete äraviskamisele on meie maailmas ka suureks probleemiks vee raiskamine. Need inimesed, kellel on omas kodus normaalse joodavusega vesi, ei ole tänulikud selle olemasolus.\nMaailmas inimesed nälgivad ning on joogijanus, kuid ikka veel raisatakse toitu ja vett. Ostetakse halva kvaliteediga riideid ning pärast paari kandmist vistakse need ära, Nendele probleemidele peab leidma varem või hiljem lõplikud lahendused, kas seda soovitakse või ei. Hea idee riiete raiskamise probleemi lahenduseks on toetada väikeettevõtteid, ostes nende hea kvaliteediga ja kaua püsivaid riideid.');
INSERT INTO core.text_property(text_id, property_name, property_value)
