INSERT INTO core.text(id, content)
VALUES ('38e4cdcd-ebc9-4d2e-a1f6-431dafe54804',
        'Üle aastate on inimeste tarbimisharjumused allamäge läinud. Hiina massitootmise pärast kannatavad paljud Euroopa firmad, sest nende kvaliteetse kauba asemel ostetakse hoopis odavat massitoodangut. Massitoodangu tagajärjel on paljudel inimestel ostusõltuvus tekkinud, sest asju saab lihtsalt nii odavalt kätte.\nSellest ajast saati, kui Aasias massitoodangut Euroopasse müüma hakati on Euroopa kaubandus väga alla käinud. Kuna asjad tunduvad pealevaadates kvaliteetsed ja korrektsed ei näe keegi nende ostmises probleemi. Inimesed aga ei näe, kuidas need asjad, mida nad Aasiast nii odavalt ostavad, toodetud on. Suured tehased, kus töötavad korraga sajad, kui mitte tuhanded töölised. Mina tunnen, et seda muuta peavad inimesed sügavalt mõtlema selle peale, kuidas kogu see kaup toodetud on.\nPaljudel inimestel on viimaste aastate jooksul välja kujunenud ostusõltuvused. Sellele on raske vastu panna, kui internetis olles suured reklaamid ette löövad, kuidas mõni Hiina kaubamaja euroseid kleite müüb, või kuidas saad endale terve komplekti maniküüritehnikat vaid viie euro eest. Ostusõltuvused ei teki ka ainult Aasia massitoodangu pärast. On ka inimesi, kes ei suuda vastu panna Euroopa kaubale. Vastupandamatus kohaliku kauba vastu pole küll nii hull, kui Aasia kauba vastu, aga ostsõltuvuseks jääb see ikka. \nTeades, kui palju me tegelikult selle kõigega loodust kahjustame, tekitab see väga muret. Seda kõike saaks küll muuta, aga see pole ühe inimese teha, vaid sellesse peab panustama terve maailm.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('38e4cdcd-ebc9-4d2e-a1f6-431dafe54804', 'title', 'Inimeste tarbimisharjumused');
