INSERT INTO core.text(id, content)
VALUES ('e79a3c2d-c324-45f4-9f4e-4297536163e7',
        'Maailmas tekib aina rohkem ja rohkem toidu- ja riidejäätmeid. Enamus inimesi arvavad, et toit on lõputu resurss, seega ära viskamisest nad suurt asja ei tee. Sama lugu on ka riietega, inimestele meeldib üldjuhul tellida endale riideid Hiinast ja hulgi.\nToidu ära viskamine on minu arvates õigustatud, sest kui toit on vanaks läinud või mingil muul põhjusel söömiskõlbmatu siis mida peaksid inimesed tegema? Jah, Aafrikas ja mõnes teises riigis on näljahäda, kuid kui keegi ei leia piisavalt head viisi kuidas saaksid tavalised inimesed enda ülejäänud toitu näljahädalistele annetada siis pole see ka nende süü. Pigem on asi just selles, et ei ole leitud head annetus võimalust. \nKindlasti pole probleem seotud sellega, et riideid viiakse liiga suurel määral taaskasutuspoodidesse, sest see on ju tegelikult just hea. Inimesed kellel pole nii head võimalused, et nad saaksid osta uusi riideid, saaksidki osta odava hinnaga ja vähe kantud asju taaskasutuspoodidest. Küsimus olekski pigem see, et miks ostetakse endale riideid ja siis visatakse kohe ära või viiakse second hand poodidesse.\nÜldiselt arvan mina, et toidu ära viskamine on õigustatud, sest inimestele pole antud head võimalust, et seda annetada ning kasutatud riiete taaskasutuspoodidesse viimine on just hea.');
