INSERT INTO core.text(id, content)
VALUES ('d1d23ec8-336a-4738-867d-a75917158cd4',
        'Inimesed kulutavadliiga palju maa- ja loodusvarasid enda teadmata. Mida saaks paremini teha, et meie planeet ja looduks säiliks?\nKõik inimesed tahavad alati loodust säästa, aga ikka ostavad asju mida teglikult vaja ei ole. Need asjad jäävad tavaliselt kappi seisma ja hiljem visatakse need juba ära. Inimesed on hakkanud järjest rohkem ja rohkem mõtlema taaskasutamisele, kuid samalajal tellivad suurem osa inimesi ikka Hiinast odavat ja mitte vajaliku kaupa ainult juurde. Eve Hanso on öelnud „Vikerhommiku“ intervjus, et inimesed ei telliks Hiina veebipoodidest juba põhimõtte pärast asju, ja ei läheks kaasa sooduspakumistega. Sammuti viiakse ka asju taaskasutuspoodidesse, et neid ei peaks kohe ära viskama ja keegi saaks nendega veel midagi teha.\nSuureks probleemiks maailmas on ka toit. On riike kus pole toiduga ja selle nö hankimisega mingit probleemi ja kahjuks leidub ka neid riike kus on toidu kätte saadavus väga suur probleem. Riigid kus pole toidu saadavusega probleemi on jalajälg suurem ja visatakse enda teadmata ära väga suures koguses kõlbliku toitu, mida saaks veel kasutada.\nInimesed peaksid vähem Hiina poodidest asju tellima ja rohkem toetama kohaliku elu. Kuna nii säilib meie planeet ja loodus kauem tervena.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('d1d23ec8-336a-4738-867d-a75917158cd4', 'title', 'Meie planeet ja meie loodus');
