INSERT INTO core.text(id, content)
VALUES ('bb4c614e-be3c-41de-a20e-586bee50830c',
        'Inimeste tarbmisharjumused mõjuvad keskkonnale väga halvasti. Kõik toidu raiskamine ja liigne mitte vajalike asjade ostmine jätab Maale märkimisväärse jälje.\nKõik teavad, et toidu raiskamine pole hea, aga minu arvates ei mõista paljud kui väga see tegelikult mõjutab meid ja meie keskkonda. Nii mõnedki inimesed käivad toidupoodides mõttega, et neil on kõht tühi ja vajavad midagi süüa. Selle käigus nad ostavad kordades rohkem asju kui tegelikult vaja oleks ja lõpuks viskavad need ära. Iga Eesti inimese kohta aastas tekib 61 kg toidujääätmeid ja sellest peeaegu pool on toidukadu. Seda on väga palju, aga enamasti inimesed ei mõista selle tõsidust ja jätkavad oma vanade harjumustega.\nSammuti riiete ostmisega. Väga paljudel juhtub tihti see, et neil tuleb ostlemistuhin peale ja tellivad kokku kõike, mis vähegi silma jääb. Eriti kui need on veel soodsad ka. Ei mõelda kui palju vett ja tööjõudu kulub selleks, et neile meeldiv riideese nende kätte jõuaks. Mina arvan, et tuleks näidata koolides dokumentaale rohkem ja televiisoris sammuti peaks rohkem filme olema liigse tarbimise mõjude kohta.\nTõstes rohkem inimeste teadlikust, kuidas nende tarbimisharjumused mõjutavad Maad ja neid ennast. Näidates ja rääkides liigse ostlemise tõsidusest ja ohtudest, mis võib juhtuda meie keskkonnaga kui see jätkub võib muuta palju.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('bb4c614e-be3c-41de-a20e-586bee50830c', 'title', 'Inimeste harjumuste mõju keskkonnale');
