INSERT INTO core.text(id, content)
VALUES ('8af6d862-d136-41f0-a630-871601ee40ba',
        'Igal inimesel on erinevad kombed, Kõigil on rahaga erinevad suhted, kellel on raha rohkem, kellel vähem. Tarbimisharjumusi mõjutavad erinevad asjad, üks kõige suuremaid mõjutegureid on jõukus. Inimestel puuduvad teadmsed selle kohta, kui palju läheb raisku juba ainult ühe inimese kulult. Nad ei tea, kuhu läheb kõik see raisatud kraam peale nende kasutamist.\nSuhted rahaga mõiutavad ka raiskamist ja selle vähendamist. Kui sul on palju raha siis tõenäolislt sulle ei lähe nii väga korda, kas see mõni asi läheb halvaks ja pead ära viskama või mitte, sest alati saab ju uue osta. Kui sul ei ole nii hea seis rahaliselt siis tõenäolislt sa raiskad vähem, sest sulle läheb korda, kas saa viskad selle tooraine ära või mitte, kuna sa pead raiskama raha mida sul võib olla ei ole, et uus osta. \nInimestel pole õrna aimugi, kuhu läheb nende raisatud kraam peale nende kasutamist või raiskamist. Inimesed ei tea, kui palju ressursse kasutatakse nende igapäevaste vajaduste täitmiseks. Üks asi, mida tundub on see, et toitu on ja seda veel jätkub, ega ta veel nii pea otsa ei saa, aga see pole tõsi. Raisates ei raiska te ainult toitu ja mingeid riideid vaid ka maa ressursse, mida kõiki ei ole lõputult. Kõige parem lahendus oleks noorest saadik jagada informatsiooni kõige selle seostuva kohta, reostuste mis on osaliselt põjustanud raiskamine ning, kuidas saaks seda muuta.\nRaiskamine oleneb erinevatest asjades enamasti on need rahaline seis ja teadmised. Enamus ei tea palju nende raiskamine mõjutab maailma.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('8af6d862-d136-41f0-a630-871601ee40ba', 'title', 'Materjal vs teadmised');
