INSERT INTO core.text(id, content)
VALUES ('52ac4524-e851-4efe-80ce-74f1cd711dee',
        'Tarbimisharjumus on väga lai teema. Sinna alla kuuluvad igasugused asjad mida saab osta. Näiteks riided, toidukaubad jne. Aga mis on üldsegi tarbimisharjumus?\nTavaliselt tarbitakse rohkem kui neil endal vaja on. Ja see on ka suur probleem ka meie maailmale. Kui me ostame rohkem kui me ise ära suudame tarbida, siis see võib põhjustada näiteks kliimasoojenemist. Enamik asju mida me ära ei tarbi, satuvad prügimäele. \nKui inimesed oma tarbimisjarjumusi ei muuda, siis kannatab maailm ja inimesed. Näiteks inimesed ostavad palju toitu aga nad ise seda ära ei söö, siis nad võiksid toidu annetada inimestele, kes ei saa sellist asja endale lubada. Nagu „Toidukaose“ tekstis välja toodi: „Toidu raiskamist ei saa vähendada üleöö.“ See on tõsi, aga kui inimesed lõpuks võtavad kätte ja otsustavad, et me enam toitu ei raiska, ostame nii palju kui ise jõuame ära süüa, siis maailm muutuks. Aga isegi, siis kui selline ime toimuks, mõned inimesed siiski ei läheks sellega kaasa. Kuna kõikidel inimestel on oma arvamus ja see on täiesti normaalne. Aga inimesed võiks mõelda tuleviku peale, meie laste peale. Nemad peavad selles maailmas elama, mille me ise laastasime. \nRiietega on sama moodi. Inimesed ostavad tavaliselt riideid mõttega „ Aga äkki ma kunagi kannan seda. See on ju nii kena, ma ei saa seda ometi selle siia jätta.“ See on üks meie suurtest probleemidest. See idee, et äkki kunagi kannan seda riideeset. Tavaliselt ei tehta nii. Jällegi me ostame rohkem kui me ise suudame tarbida. \nInimesed võivad küll mõelda, et me muudame tarbimisharjumusi, me muutume paremaks. Aga nii see tavaliselt ei ole. Kuna alati on keegi, kes ei muutu. Inimesed on ju isekad. Nad ei mõtle mis tulevikus toimuma hakkab. Inimesed on ju nii egoistlikud, et me mõtleme ainult enda peale. Tarbimisharjumusi on raske muuta, kuna siis sa peaks muutma ka inimest.');
