INSERT INTO core.text(id, content)
VALUES ('b8bc1ee1-1552-443f-b9e9-d84a211f6680',
        'Inimesed raiskavad palju toitu kuna arvavad, et toitu on lõpmatult ning see ei saa kunagi otsa. Kindlasti ei vasta see tõele, maailmas on palju inimesi ja peresi kes nälgivad kuna neil pole süüa ega juua. Samamoodi on riietega enamus inimestest viskavad oma riided ära kui need jäävad neile väikseks või arvavad, et need ei sobi neile, kuid nad saaksid riided või erinevad eluks vajalikud asjad viia kuskile pankadesse mis ongi loodud, et koguda asju mida anda ära inimestele kellel neid võib väga vaja minna. Väga suur osa inimestest ei mõtle teiste peale vaid mõtlevad vaid endale.\nInimesed pidevalt raiskavad toitu arvates, et mingi toit on halb ja lihtsalt viskavad selle minema. Sellise teguviisi peamine probleem on, et maailmas nälgivad tuhanded kui mitte miljonid inimesed kuna neil pole raha, et süüa osta. Paljud teised taaskasutatavad kaubad nt riided jne saab ka taaskasutusse saata, viies need pankadesse, et neid laiali jagada.  \nOn olemas erinevaid kohti kuhu saab viia enda allesjäänud sööki, jooki ning erinevaid riideid jne. Minuarust on need kohad vägagi mõistlikud kuna sealt saavad inimesed endale võtta asju mida nad võibolla endale ise lubada ei saa. \nKokkuvõtteks ütlen, et on olemas väga palju erinevaid viise kuidas aidata teisi inimesi ning kuidas taaskasutada asju, kuid paljud inimesed seda ei tee. Arvan, et kindlasti inimesed peaksid natuke avardama oma silmaringi ning mõtlema teiste aitamise peale. Maailmas on väga palju inimesi kellel oleks seda abi vaja.');
