INSERT INTO core.text(id, content)
VALUES ('6bd789b9-1ff1-4b6c-8f9c-b21ce5af7334',
        'See mida ja kuidas tarbitakse on olnud suureks probleemiks juba aastaid. Raiskav tarbimine on ja jääb veel pikaks ajaks, kuid on olemas asju mida saame muuta, ja kaasa aidata rasikava tarbimise vähendamiseks.\nToitu peetakse iseenesest mõistetavaks, see, et seda on ja selle pärast ei pea muretsema, kuid on riike ja peresid kes peavad. Eestis tekib inimese kohta keskmiselt aastas 61kg toidujäätmeid, võib küll mõelda, et viskame mõne üksiku asja ära, ja see ei muuda midagi, kuid tegelikus on teine, kuna iga inimene võib mõelda, et see natuke ei muuda midagi, tulemusena tekibki selline suur hulk toidujäätmeid.  Selle asemel, et poes käies osta mis silma jääb, tuleks hoolikalt läbi mõelda, kas seda süüakse kodus, ja kas seda tõesti kasutataks. Kui osta lihtsalt niisama kõike mis silma jääb, võib selle tagajärjel toimuda suure hulgaline toidu raiskamine, mis oleks võinud ära jääda seda mitte ostes, kuna mõni inimene või pere kes seda päriselt kasutaks oleks võinud selle osta ja seda kasutada. Et vältida liigse toidu ostmist saab kodus teha nimekirja asjadest mida vaja on, see aitab poes kiiremini käija kui ka vältida liigsete asjade ostmist. Niimoodi säästaks ka maaressursse nagu maad ennast, vett, energiat ja tööjõudu.\nMoe disainer Eve Hansen rääkis, kuidas peaks valima kvaliteedi üle kvantiteedi, mis on väga õige, kuna kvaliteetne asi võib küll olla kallim, kuid kestab kauem. Hiinast tellitud asjad võivad olla odavamad, kuid ei ole sama kvaliteetsed, ja lähevad kiiremini katki. Samas kui sulle meeldib mingi särk, kleit jm odavamast hiina poest on mõistlikum osta see kui mõni kvaliteetne riide ese, mida kannaksid vaid korra, kuna ka see aitab tegelikult säästa ressursse ja raiskamist. Hansen rääkis ka sellest, et tuleks eelistada pigem vähem kui rohkem, ja mõelda läbi mida ja miks sa vajad, kas kannaksid seda vaid korra või rohkem, see aitab hoida resursse, kuna ei pea tootma peale uusi tooteid. Samuti võiks eelistada taaskasutus jaamasid/ keskuseid, mis ühe jaoks vana, see teise jaoks uus, sellistest kohtadest, võib leida palju huvitavaid asju, mida oled otsinud, ja veel odavama hinna kui ka looduse jaoks kasulikumalt. \nTuleb läbi mõelda mida ja miks sa vajad, kas tõesti kasutad ja kannad seda, või oli see hetkeline otsus, poes tundus toiduaine hea, või pluus ilus, ja vajalik, kuid tegelikuses ei kanna seda, ei söö seda. Meie otsustel ja tegudel on tagajärjed, nii loodusele kui ka tulevatele põlvkondadele, kui suudame vähendada raiskamist, on ka neil ilus loodus mida nautida, paksude metsade, ilusate rabade, soodega ja kaunite veekogudega. Seda kõike ei saa teha ühe päeva, ega ühe aastaga, kuid läbi mõeldes enda oste saame aidata kaasa, et meie lastele ja lastelastele jääks selline maailm, nagu meie seda teame.');
