INSERT INTO core.text(id, content)
VALUES ('88b6f219-e067-49fa-8f58-4c4b3b7686ac',
        'Toidukadu on maailmas vägagi suur probleem. Toidukadu on raisatud toiduaine või toit, mille riknemise tähtaeg on läbi saanud või ka söömata jäätud toit ehk toidujäägid. Sellele lisaks on ka rõivaste heas korras hoidmine ja nende kvaliteetne tootmine probleemiks. \nToidujäätmeid tekib iga päev ja igalpool. Neid tekib söömata toidust mida keegi enam nii ahvatlevaks ei pidanud ja otsustas selle ära vista või ka reaalne asi mida ei sööda näiteks kartuli- või banaanikoored. Toidujääk pole ainult toit mis inimesele enam ahvatlust ei pakkunud või mille tähtaeg möödus vaid ka koored, südamikud, seemned jne. Toitu peaks austama ja sööma ära ka eelmisest päevast jäänud jäägid, et olla jätkusuutlikum.\nToidu tootmine ei ole kerge kui võtta arvesse palju läheb ressurrse, aega ja ka see kui  vastutustundlikult inimesed toitu raiskavad. Tootmiseks väheb vaja maad, vett, energiat ja tööjõudu. Toidu transportimine on ka veel oma asi, kuhu läheb tohutult raha ja ressursse. Enne seda kui tavainimesed saavad osta poest süüa ja selle kodus lauale panna tuleb teha hulk eeltööd ja arvutamist.\nRiideid tuleks teha rohkem mugavuse ja kvaliteedi eesmärgil, mitte selle jaoks et riie oleks pealevaadates ilus. Peamine eesmärk ei tohiks olla riiete odav massiline tootmine ja müümine, vaid selleks, et kasumit teenida, unustades rõiva mugavuse, kestvuse ja jätkusuutlikkuse tagaplaanile. Moedisainer Eve Hanson arvab, et kaasa ei peaks minema sooduskampaaniatega, peaks eelistama kodumaiseid tooteid ja neid peaks ka endale lubama pigem vähem kui rohkem. Veel ütleb ta, et taaskasutuspoodidesse viiakse tihedasti korralikke riideid, mis on tehtud naftast või muust möksist. Tema ettepanek on noortele ekskursioonide tegemine taaskasutuspoodide lattudesse.\nSelle peale ma ütleks, et osta ja süüa tuleb kohustustundlikult. Toitu ja riideid on palju, aga neid tuleb osta mõõdukalt. Tuleb panna tähele et kas toode on kvaliteetne või lihtsalt silmapete. Tootmine on väga ressurrsenõudev ja kurnav. Iga inimene saab panustada meie kõigi jätkusuutlikuma ja helgema tuleviku poole, kui on aru saadud kuidas ja miks seda teha tuleb.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('88b6f219-e067-49fa-8f58-4c4b3b7686ac', 'title', 'Toidukadu ja riiete eesmärk');
