INSERT INTO core.text(id, content)
VALUES ('30de6a42-d812-460f-898f-876823f1c69d',
        'Inimesi on harjutatud teadmisega, et ressursse on lõputult palju. See ei ole tõsi ja ei ole kunagi olnud. Kasvatatakse lapsi üles ja öeldakse neile, et kui nad ei jõua enda toitu lõpuni süüa siis visaku see prügikasti. Sotsiaalmeedias aetakse taga kuulsust toidu raiskamisega, kuigu keegi kusagil maksaks hinge hinda selle söögi eest. Poes on alati kõik letid toitu täis ja jääbki arusaam, et toit ei saagi otsa.\nVäikesest saadik on paljusi üles kasvatatud raiskamis harjumustega. Ei jõua süüa enam? Viska siis ära. Ei jõua enda piima ära juua? Kalla see lihtsalt kraanikausist alla. Lapsi keda nii üles kasvatatakse võivadki jööda arusaama, et meil on kõike lõputult ja see ei saa kunagi otsa. Eriti siis kui ollakse rikkamast perest. Raha on palju ja sööki on veel, siis ei saagi kunagi midagi otsa. Minule röögiti lapsena alati, et kõik tuleb ära süüa ja arvan, et tuleks rohkem lastele seda õpetata.\nSotsiaalmeedias on ka palju toidu raiskamist ja kui lapsele anda ligipääs internetile, siis võib ta sealt omandada mõned halvad harjumused. Tihtipeale nähakse videot kus raisatakse toitu ja sellel on väga palju vaatamisi, siis võitaksegi arvata, et nii on äge ja nii peabki tegema. Mina olin ka kunagi selline. Nägin videot kuidas inimene raiskab toitu ja arvasin, et ma olen ka siis lahe kui ostan toitu ja viskan selle peaaegu tervenisti ära. Minasain sellest harjumusest lahti aga kõikidel ei pruugi nii olla.\nPoodides jääb inimestele illusioon, et on kõike lõputult, sest alati kui poodi minnakse siis on kõik letid alati täis. Kuid ei ole näha seda kuidas see toit sinna sai. Mitu looma suri selle lihapiruka jaoks või mitu taime võeti maha selle maitseaine jaoks. Kõikide nende asjade jaoks on vaja tööjõudu ja trantsporti. Kõik toit tuuakse sinna poodi mingi sõidukiga. Kas siis lennuki või rongiga. Nendest tulevad heitegaasid mõjutavad keskkonda.\nToiduraiskamist on olnud palju, nii laste kui ka töiskasvanute seas. Seda on tehtud ja ma arvan, et seda jäädakse ka tegema. Ei saa kontrollida mida keegi ja kui palju ära viskab. Raiskamis harjumusteks on paljusi tegureid, kuidas kedagi üles kasvatati ja kellest keegi võib halba eeskuju võtta.');
