INSERT INTO core.text(id, content)
VALUES ('2def69f8-0d31-4037-9363-d532faa51062',
        'Suur probleem on meil sellega, et inimesed raiskavad suurtes kogustes toitu ja toitaineid. Nad ei saa aru kui suur mõju neil on sellega kui viskavad minema väikseid toidu koguseid näiteks nagu on öeldud textis ´´Kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61kg toidujäätmeid, millest toidukadu moodustab 26kg.´´\nProbleemi alguseks võib ka olla see, et koolid ei vii lapsi õppereisidele taaskasutuspoodide lattu. Kui lapsed saaksid aru kuidas toimib taaskasutamine siis oleks võimalus, et tulevikus ei raiska lapsed nii moodi, nagu präegu täiskasvanud teevad.\nMinu järeldus on ikkagi see, et kui me koolid ja töökohad alustaks taaskasutamise õpetust, kuidas see toimib ja mida saavad lapsed teha selle jaoks ja üldse inimesed siis olen ma kindel, et kõik raiskamis protsendid lähevad alla ja meil lõppeb igasugune ületarbimine ära, sellega võib võtta aastaid aega aga tulevikus oleks see väga hea. \nVõimalik on ka see kui me alustaksime dieeti ehk siis sööme kindlaid toite ja toiduaineid vähem siis oleks see igate pidid kasulik meile, toidu raiskamine läheks kindlasti alla kuna inimesed söövad seda mida nad teavad, et nad tahavad mitte ei osta kokku endale igasuguseid toite mis tunduvad head. Võiksime ka Eestis keelata hiinapoodidest tellimise, siis ei tekiks nii palju asju mida oleks vaja taaskasutada. Asjad ei laguneks peale paari kuud ja kui saame selle probleemiga lahendatud siis saaksime loodust hoida ja säästa.');
