INSERT INTO core.text(id, content)
VALUES ('2e0b5baa-1b8c-440e-afa9-4c3d9a0e7372',
        'Ma arvan, et iga inimene on enda elus näinud olukorda, kus keegi raiskab midagi. Olgu see kas siis toit, riided või muu kaup. Raiskamine on maailmas suur probleem ning sellega tuleks midagi tõsist kiiresti ette võtta.\nMina üritan hoiduda raiskamisest, sest ma saan aru, kui suur probleem see on. Näiteks kui ma teen süüa, siis ma teen nii palju kui ma jaksan ära süüa ning isegi kui seda jääb üle, leian sellele kasuliku otstarbe. Alati on paremaid asju toiduga teha kui seda ära visata, nagu näiteks annetad toidu kuhugi või annad ülejäänud toidu koduloomadele. Samuti saab vanu riideid kasutada otstarbekalt. Näiteks meisterdad vanadest riietest mingi uue ja kasuliku eseme, näiteks uue riideeseme, või annad enda vanad riided kellegile teisele, kes nende üle rõõmu tunneks, nagu mina teen. Iga asjaga, mida sina enam ei soovi, saab kindlasti mida etemat teha, kui see ära visata.\nSäärase raiskamise lõpetamiseks on palju erinevaid viise. Nagu moedisainer Eva Hanson ütles, ei tohiks me tellida hiinast odavalt kaupa, ning et me eelistaksime kodumaist kaupa. Samuti mainis ta, et taaskasutuspoodide ladudesse tuleb iga nädal juurde nii palju riideid, mis on täiesti korralikud ning neid saaks veel kanda. Selle vältimiseks tuleks kanda riideid nii kaua kuni need on veel kasutuskõlblikud ning ei ole katki. Enda toidujäägid võiksid inimesed hoopis kasutada ära otstarbekalt. Neid saab erinevatesse kohtadesse annetada, koduloomadele anda, või kõige lihtsam võimalus, need ise ära tarbida. Samas see, mida inimesed enda riiete ning toiduga teevad, ei ole kellegile teise teha kui nende endi. Seepärast tuleks hakata rohkem tähelepanu tõstma raiskamise kohta. Inimestele peab selgeks tegema, et kui selline raiskamine jätkub, siis ei ole meil enam varsti uusi riideid selga panna, ei ole poest toitu võtta ning ka muu kaup saab ükskord otsa. Eva Hanson arvas, et peaks noortele hakkama tegema ekskursioone taaskasutuspoodide ladudesse, et nad näeksid, mis päriselt Eestis ning mujal maailmas toimub. Ma arvan, et see on hea idee, sest see aitab noorte teadmisi tõsta raiskamise koha pealt.\nMaailmas on raiskamine suureks probleemiks, kuid seda annab veel peatada. Kui inimesed saavad aru, mis valesti on ja varsti saavad materjalid maailmast otsa, siis hakkvad ka nemad üritama raiskamist lõpetada. Kindlasti jätkub maailmas inimesi, kes ei soovi üldse raiskamist lõpetada, ning me ei saa sinna midagi parata.');
