INSERT INTO core.text(id, content)
VALUES ('368449ff-8518-4f34-bbe9-fc37872c13ca',
        'Inimesed tihti ei mõista, kui palju nende tarbimisharjumused meie planeeti mõjutavad. Toitu, vett, riideid ja palju muud kasutavad kõik igapäevaselt, kuid tihti ei mõtle, kas nad teevad seda säästlikult. \nKodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid. Raisates toitu raiskame me ka maad, vett, energiat, tööjõudu ja ka oma raha. Selle vältimiseks on mõistlik osta nii palju, kui suudad ära tarbida. Inimesed, kellel on näiteks sead või kanad annavad neile toidujäätmeid söögiks, see on hea alternatiiv toidu lihtsalt prügikasti viskamisele. Kõik seda muidugi teha ei saa, aga nad saavad prügi sorteerida ning toidujäätmeid komposti panna.\nKa riideid ostetakse suurtes kogustes. Raiskamise vältimiseks on kõige lihtsam mitte osta uusi riideid, kui pole vajadust. Kõige rohkem tarbivad inimesed, kes lähevad iga moega kaasa. Need inimesed ei olegi tihti kõige rikkamad, vaid nad tellivad odavatest välismaa kiirmoe poodidest. Nende poe töötajad töötavad kohutavates tingimustes ja saavad väga vähe palka, kahjuks see aga nende riiete tarbijaid ei huvita. Mina arvan, et kõige parem on tarbida taaskasutatud riideid. Kaltsukates on väga odavad hinnad ja sealt võib leida väga kvaliteetseid riideid. Häid riideid saab ka teistelt inimestelt, kes müüvad või annavad ära oma vanu riideid.\nOn oluline mõista, et säästlikult tarbida ei ole keeruline. Jälgides oma tarbimisharjumusi, proovides leida uusi ja paremaid võimalusi ning raiskamist vähendades saab maailma paremaks muuta.');
