INSERT INTO core.text(id, content)
VALUES ('a0cd5a62-4d48-4e0b-9b6f-272bae190216',
        'Tänapäeval on inimeste tarbimiskogus suur ja sellele ei pöörata piisavalt tähelepanu. Kuidas inimeste tarbimisharjumused mõjutavad meie ümbruskonda? Milliseid asju kõige rohkem tarbitakse? Mis on kõige halvemad tarbimisharjumused inimestel?\nKindlasti on toit üks asi, mida tarbitakse ja raisatakse tänapäeval palju. Osad inimesed arvavad, et seda on veel, aga tegelikult nii ei ole. Visatakse toitu ära, kui see on näiteks ületanud kuupäeva, riknenud või söömisel ülejäänud. See raiskab tohutult meie maad, vett, energiat ja tööjõudu ning mõjutab kliimasoojenemist. Seda saaks vältida näiteks nii, et toidu tegemisel teha kogus, mis saab kindlasti söödud, tarbida toiduained enne ära, kui need pahaks lähevad ja poes oma ostud läbimõelda.\nTeiseks ostetakse riideid väga palju. Põhjuseks on tihti see, et minnakse kaasa sooduskampaaniatega ja tehaske emotsiooni pealt oste ja ei mõelda läbi, kas tegelikult on seda riideeset ikka vaja. Tänapäeval tellitakse palju Hiina veebipoodidest, kus samuti minnakse kaasa odavate hindadega. Trendid vahetuvad kiiresti ning selletõttu ka riided kiirmoepoodides ning need ei leia kasutust. Selle tagakülg on see, et taaskasutuspoodide ladudes on hunnikutes riideid ja see on täielik raiskamine. Inimesed võiksid eelistada pigem kvaliteetsemaid ja kodumaised asju.\nTänapäeva inimeste tarbimisharjumused on läinud ülepiiri ja see mõjutab meie keskkonda ja kindlasti ka kliimasoojenemist. Toidu raiskamine ja emotsiooniostud on koht, kus kõige rohkem asju tarbitakse. Ühiskonnana peaks sellele rohkem tähelepanu pöörama ja midagi ettevõtma enne, kui on liiga hilja.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('a0cd5a62-4d48-4e0b-9b6f-272bae190216', 'title', 'Tarbimisharjumused tänapäeval');
