INSERT INTO core.text(id, content)
VALUES ('806459f0-217b-49f0-a027-55f2ca997d18',
        'Igapäev inimesed teevad kodus endale midagi mida tarbida,aga paljud asjad ei pruugi saada täielikult ära tarbitud, kuna neid asju kas saadakse tehtud liiga palju või kasutatud liiga palju ja selle tõttu ära raisatud. Inimesed tarbivad ja kulutavad väga palju asju, niiet nad ise sellest aru ei saa,paljud tähtsad asjad mis lähevad raisku võib olla elekter, raha, toit ja muud paljud muud asjad, aga selleks et neid minimaalselt kasutada peame me midagi muutma.\nKõik mida me raiskame saaksime hoopis kokku hoida, aga et seda teha peame me ise olema targad ja kokkuhoidlikuma mõtteviisiga, kui inimene teeb toitu võiks ta teha seda niimoodi, et ta teeb seda kas teatud arv inimestele või ainult endale ja mitte teha üks  suur pannitäis mille ta kindlasti pärast ära viskab, sama on ka elektriga peaaegu kõik inimesed kasutavad mõtetult palju elektrit, näiteks: ei kustuda enda majas ära tuld ja kõik asjad mis on elektriga seotud käivad niisama.Aga et see niimoodi ei oleks tuleb hoida asju mis on suure tarbimiskogusega kinni ja enne millegi kasutamist kõik ilusti ja targalt läbi mõelda.\nLõpuks kõik inimesed suudavad tegelikult säästa suure tarbimiskogumiga asju, aga ennem tuleb lihtsalt mõelda hoolikalt asjad läbi ja enda tarbimisharjumused madalamaks muutma.');
