INSERT INTO core.text(id, content)
VALUES ('fd03c032-c543-417d-b657-d13e2bc75620',
        'Eesti kodudes on hakkanud kujunema rohkem toiduraisku kui kunagi varem. Inimesed ostavad hunnikutes toitu ja viskavad suure osa sellest minema. Mida saaksime teha, et hoida planeet maad, kui ka oma rahakotte?\nKuidas on toiduraisk halb planeet maale? Toidu tegemine võttab väga palju ressurse, näiteks banaan mida kasvatadakse välismaal. Seda kasvatadakse soojal maal kus see banaan kasvab ja võttab maalt ressurse näiteks vett, enegriat ja tööjõudu. Siis kui banaan on valmis, lendab see siia lennukiga mis rikkub meie õhukvaliteeti ja energiat. Kui see lõppuks on poe lettile jõudnud, ostab keegi selle ära, viskab selle külmkappi nurka, unustatakse seda sööa ja visatakse minema. Kui selline asi juhtub umbes iga ühe viiendiku asjaga mida poes ostetakse, siis raiskame maa ressurse kui ka enda raha. Meie planeet maad on ainult üks ja  peame seda hoidma.\nKuidas saame hoida meie maad ja säästa raha? Minu perekond teeb näiteks nimekirja kui poodi lähme, asjades mida meil on kindlasti vaja. Kuigi me küll ei pea sellest alati kinni, siis aitab see meil mitte ülekurnata toitu. Kui näiteks jääb toitu üle, siis toidame seda loomadele, muidugi peab kindlasti ennem internetist otsima kas sellele loomale tohib toita seda toitu.\nPeame hakkama hoidma enda maad. Kui oleme säästlikud ja ostame ainult seda mida on vaja, siis sellega järgneb vähem toiduraisku ja paranemist meie maale. Seda planeeti on ainult üks ja me peame hoolitsema selle eest.');
