INSERT INTO core.text(id, content)
VALUES ('2c86240c-9b81-4a72-81d0-a1dd788df98d',
        'Mis on halb tarbimisharjumus. Mis võib juhtuda kui visata palju toitu ära? Miks eelistada kvaliteeti toidu juures, mitte hinda?\nToidu raiskamine on üks suurimaid halbasi toitumisharjumusi. Inimestena oleme harjunud, et toit ei saa otsa, sest poes on seda alati. Seetõttu oleme harjunud, et viskame toidu ära, isegi siis kui sellel pole midagi viga. Näiteks teen süüa ja tõstan taldrikule palju toitu ning ei jaksa seda ära süüa. Mõni viskab toidu ära selmet panna külma ja süüa hiljem. Võib ju arvata, et paar korda pole midagi, aga see on vale. Inimese kohta tekib aastas umbes 26kg toidukadu. Kui me toitu liiga palju raiskame, saab see lõpuks otsa. Raiskame sellega: tootjate ressursse, vett, energiat ja maavara.\nArvame, et vahet pole, kust toit pärit on. Ostame enamasti tööstustest, sest see on odavam, kuid ei mõtle kuidas neid tehti. Taluniku käest saad näiteks marju , millega ta on vaeva näinud ning pole sinna pannud kemikaale, et need kauem säiliks. Kui aga ostad marju, mis on toodud kaugelt maalt, kuid odavamad siis on loogiline, et neid on kemikaalidega pritsitud, sest muidu neid ei saaks transportida.\nToidu raiskamine on halb tarbimisharjumus. Kui palju toitu ära viskame saavad tooted otsa, eelistada tuleks kvaliteeti toidu juures, sest siis me ei söö kemikaale sisse.');
INSERT INTO core.text_property(text_id, property_name, property_value)
