INSERT INTO core.text(id, content)
VALUES ('ecb44f94-f657-4955-880b-c3192132c2c2',
        'Suureks probleemiks üle terve Eesti on toidukadu. Inimesed arvavad, et toidu jääkide ära viskamine ei mõjuta maailma, kuigi neil pole aimugi kui suur raha ja muude ressursside raiskamine see on. Veelgi probleemiks on Hiinast ebakvaliteetsete toodete tellimine.\nEesti kodupidamistes tekib iga inimese kohta keskmiselt aastas 61kg toidujäätmeid, millest raisatud toit on 26kg. Raisatud toidu all mõeldakse tooteid mis on vanaks läinud, jäetud järele ning ära visatud või lihtsalt ära visatud, sest neile ei maitsenud see toode. Selline toidukadu probleem raiskab inimeste enda raha, kuid ka tohutult muid ressursse: maad, vett, energiat ja tööjõudu. Toidutootmine tekitab tõsise keskkonnakoormuse seetõttu, et rohkem saaki kasvatada kasutatakse väetisi ja erinevaid kemikaale. Need kemikalid ja väetised võivad olla ohtlikud loodusele ja seal elavatele loomadele. Toidu raiskamine on kinni paljude inimeste harjumustes, aga seda on võimalik muuta kui õpitakse ostma ainult asju mida sa päriselt tarbid, ja ei lase raisku.\nMoedisaineri, Eva Hansoni arvates on oluline, et igaüks eelistaks kvaliteeti üle kvantiteedi. Hanson arvab et välismaalt ja soodsate hindadega ostmine ei ole hea ning väidab, et kodumaised tooteid võiks eelistada ning pigem vähem kui rohkem. Kvaliteet üle kvantiteedi tähendab seda selles tekstis, et kui sa ostad välismaalt soodsate hindadega, siis need tooted ei ole alati kvaliteetsed, lähevad kergesti katki või rikki. Hiinas näiteks on palju laboreid ja tööjõudu igalpool, kus nad toodavad neid odavaid ebakvaliteetseid tooteid. Suur võimalus on kui sellistest kohtadest tellida siis sa võid riskida lapstööjõu toetamisega. Taaskasutuspoodide lattu viiakse iganädalaselt väga suurtes hulkades rõivaste koguseid ja väga paljud neist on Hiinast ja mujalt kus toodetakse ebakvaliteetseid ja odavaid tooteid. Taaskasutuspoodidesse viiakse Hiinast riideid seetõttu, et need tegelikult võivad koosneda naftast ja neid ei kannatata rohkem kui korra kanda, sest see on ebamugav ja ei ole meeldiv.\nVõib teha järeldusi, et toidu raiskamine on inimestel suureks harjumuseks ja see ei ole keskkonna sõbralik, ning toidu või kasutustähtaja ületanud toidu äraviskamine raiskab su enda raha ja muid ressursse. Veelgi võib teha järelduse, et ei ole mõtet tellida Hiinast, kui seal toodetakse ainult ebakvaliteetseid ja odavaid tooteid, mis on ebamugavad või lähevad kergesti katki. Suur osa nendet toodetest lõpetab taaskasutuspoodides, või tõenäoliselt prügimäel kui see katki läheb. Targem oleks eelistada kodumaiseid tooteid mis on kvaliteetsed.');
