INSERT INTO core.text(id, content)
VALUES ('d05f2278-8602-466b-83a5-28cde22f190e',
        'Meie kui tarbijad oleme teise sõnaga asjade kasutajad näiteks tarbime toitu, kasutame riideid, ostame tehnikat ja muud säärast. Saaksime osta vähem uusi asju ja kasutada rohkem kasutatud asju või vana ära parandada, et säästaks keskkonda ja inimesi kes neid materjale koguvad.\nKoolis peaks noortele juba alguses õpetama, et peaks hakkama kasutama tehnikat või riideid mis on saadetud näiteks taaskasutuskesustesse kus saab vahel ka täiesti uusi riideid või tehnikat ei pea kogu aeg ostma uusi telefone kuna igast telefonis on maavarad mida ei jagu väga palju. Vanad esemed saab viia taaskasutuskeskustesse, kellegile anda või kinkida, et säästa meie loodust ja inimesi. Noortele peaks veel õpetama, kuidas säästa toitaineid, et mitte neil rikneda, kui käid poest osta asjad mis sa tarbid näiteks kahe päevaga ära, et sa ei ostaks asju mis võib jääda külmkappi vedelema. Toit mis jääb järele ja hakkab juba aeg läbi saama tuleks panna toidu kappidesse, et kellel seda vaja saaks selle sealt võtta.\nSellest teemast järeldan, et kõik saaksime hakkama asjade säästmisega ja kasutada kasutatud asju näiteks riideid, tehnikat ja muud vajalikud asjad mis iga päeva elus vaja läheb. Saaksime vähem osta uusi asju ja vanad asjad ära viia kas taaskasutuskesutesse või kellegile anda kellel seda vaja on. Toitu ei tohiks raisat ja vajadusel kellegile anda või panna toidukapidesse.');
