INSERT INTO core.text(id, content)
VALUES ('d3c450fe-76cd-4e85-a3d8-5845ab74e5d7',
        'Mina hakkan rääkima taaskasutusest mis on väga tähtis teema millest räägida, kuna inimesed viskavad või lõhuvad oma riided lihtsalt minema ilma et mõtleskid mis nendega teha saaks.Neid saaks taaskasutada ja taaskasutus keskusesse viia kus saab riideid uueks teha.\nKaks kõige hulemat teemad millest räägitakse on riiede ära viskamine ja riided olema vees.Essa teema millest räägin on riiede ära viskamine.see on väga halb kuna inimesed viskavaid riideid ära aastas päris palju kuigi neid saaks viia kuhugile hea tegevusele. Lastekodus on päris palju lapsi kellel pole palju riideid ja neid saaks sinna viia või, siis panna riideid kottidega heategevus kasti mis on üle Eesti need on põhimõtteliselt kastid kuhu saab riideid viia ja lastekodu viia.Teine teema millest ma räägin on, et riideid on vees ja see on väga halb kuna loomi on vees ja nad võivad arvata et see on toit nende ees mida võib süüa.Kui nad söövad seda toidu, siis loomad võivad ära surra\nMa tahaks öelda et taaskautus on väga hea asi mida teha kuna inimesed saavad omale natukene uuemaid riideid ja lapsed, kes on lastekodus saavad ka omale riideid kellel ei ole nii palju riideid.Taaskasutamine on hea asi mida teha oma elus.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('d3c450fe-76cd-4e85-a3d8-5845ab74e5d7', 'title', 'TAASKASUTUS');
INSERT INTO core.text_property(text_id, property_name, property_value)
