INSERT INTO core.text(id, content)
VALUES ('a3dde468-0f12-4f4d-9384-f9f7b56099ab',
        'Tänapäeval on väga aktuaalne teema taaskasutus. Paljud ostavad asju ja toitu kokku rohkem, kui nad seda tegelikult tarbivad ja viskavad palju ära. Kas on võimalik oma igapäevast toidukadu vähendada? Kuidas taaskasutada oma vanu asju?\nVäga paljud ostavad kokku sööki, millest enamus läheb raisku, selle ennetamiseks saaks oma tarbimist analüüsida ja osta kokku just nii palju, kui seda tegelikult vaja läheb. Enamus toidust on võimalik kasutada kompostina, mis on hea taimede kasvatamiseks. Näiteks kohv ja tee on väga head komposteerimiseks, mis muudaks juba toidukadu üsna palju ja inimese harjumust, et säästa rohkem. Tänapäeval on ka olemas toidukapid, kuhu saab annetada toit mida sa ise tegelikult ei  tarbi.\nRiided ja muud tarbeasjad võivad inimese jaoks olla keerukam. Selle jaoks on olemas taaskasutuspoed, kuhu saab iga inimene viia enda vanu asju mida ta enam ei kanna või kasuta. Olemas on ka riiete äraandmise konteinerid, et teha taaskasutamise lihtsamaks. Aina rohkem on tegelikult näha noori taaskasutamas, sest nemad on meie tulevik. Mõte viia noored taaskasutuspoodide lattu on tark, et näidata kui palju me teglikult asju lihtsalt ära viskame.\nIga inimene saab taaskasutada olles selleks, kas toidu säästmine ja mitte osta rohkem, kui sa tegelikult tarbid või oma vanade asjade viimine taaskasutusse. Mõtekas on noortele õpetada säästmist, et meie planeeti elamiskõlblikuna hoida.');
INSERT INTO core.text_property(text_id, property_name, property_value)
