INSERT INTO core.text(id, content)
VALUES ('d9681911-6f1e-4183-b3fd-1fc6c1dde287',
        'Meie planeedil on väga suureks probleemiks toidu raiskamine ja paljude asjade ületootmine. Sealhulgas ka välismaal toodetud toidu kasvatamine. Kuid kuidas neid probleeme lahendada?\nÜks suurimaid probleeme maailmas on toidu raiskamine. Eestis viskab inimene keskmiselt 61kg toidujäätmeid prügikasti. Sellest 42% on kas rikkenud- või kasutus tähtaja ületanud toit. Selle probleemi vältimiseks on mitu lahendust. Toit mis sul jääb üle, ära viska seda ära vaid anneta neile kellel on seda tarvis. Poes ei ole mõtet üleoste teha. See tähendab, et ära osta liiga palju asju kui sul on jäänud koguaeg neid üle, ning oled need minema visanud. Proovi osta poest tooteid mis on tehtud kas Eestis või selle lähedal, et oleks kindel kuidas neid kasvatatakse. Välismaal on palju probleeme, et toitu laheb vaja palju ja kiiresti, ning tänu sellele nad pritsivad oma tooteid erinevate keemiliste elementidega.\nTeiseks suureks probleemiks on aga ületootmine. Väga paljud suurfirmad toodavad väga palju riideid millest aga suur osa kahjuks ei osteta. Neid mida ei osteta on aga väga palju materjali raiskanud. Suured Hiina firmad teevad aga oma rõivaid väga odavast materjalist mida pole üldse mõnus kanda. Paljud inimesed aga ostavad oma riideid taaskasutus keskustest mis on väga hea mõte, kuna siis sa ei raiska rohkem materjali.\nKokkuvõtteks võtaksin ma, et inimesed peaksid hakkama palju rohkem taaskasutama ja mitte nii palju raiskama, kuna maavarad saavad ka kunagi otsa ja neid ei ole lõpmatuseni.');
