INSERT INTO core.text(id, content)
VALUES ('6c877dc1-7a55-4798-a231-72ad0acec290',
        'Probleem on suur, sest see on täitsa tõsi, et me rüüstame oma enda planeeti sellega kui viskame koguaeg toitu ära millest paljud tunnevad puudust ja ka see, et me ostame liiga palju riideid ja mis hinna eest planeet maale. Minu arvates peaks me kõik taaskasutama ja säästma rohkem.\nMaailma rüüstamine igatepidi on halb ja meie peaks vaatama rohkem iseenda ökoloogilist jalajalge ja tegema nii palju kui võimalik, et meie lastel oleks maailm kus elada ja sei oleks prügimägi, vaid midagi paremat midagi enamat, helgem tulevik.\nMaailma parandamisks peab alati alustama iseendast ehk, kui kasvõi sina sööd iga päaev oma toidu ara ja ei lase saial hallitama minna jne siis oled sina juba teinud sammu parema maailma poole.\nMeie inimesed tarbime nii palju ja terve maailm meie ümber koosneb ja töötab ressurrsidest mis saavad üks hetk otsa kuna me ei saa loodust lihtsalt ära kasutada kuni see välja sureb ega ju, niiet kui me tahame maailma kus elada ja kus jäätist süüa ilusal suve päaeval, siis peaks me väga ettevaatlikud olema mida me maha viskame mida me ära viskame ja mida me ostame kõik selleks, et meie kallis maailm ei sureks meie endi pärast üks päev mina kutsun ülesse „Päästame maailma koos“');
