INSERT INTO core.text(id, content)
VALUES ('2d449f8a-90f2-46ec-bd74-9b0278de197e',
        'Kas inimesed on kunagi mõelnud ja analüüsinud enda tarbimisharjumusi ning mõelnud, mis see võib kaasa tuua? Kas inimesed saavad aru, kui palju me tegelikult tarbime ja raiskame oma asju?\nMe tarbime igapäev midagi ega saagi aru, kui palju me seda tarbime ja mis see võib kaasa tuua. Kas teadsite, et kodumajapidamises tekib iga Eesti inimsese kohta aastas keskmiselt 61kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26kg? Kui korrutada need numbrid Eesti inimeste arvuga, siis saame aru kui palju me teglikult tarbime ning raiskame toitu. Mida rohkem me tarbime asju, seda rohkem kulub meil raha, vett, energiat, maad ja tööjõudu. Et vähem toitu raisata, oleks minul mõned soovitused. Esiteks, tuleks osta minimaalselt toitu ja mõelda, kas me tarbime kõik selle ära? Teiseks, tuleks võtta taldrikule niipalju toitu, kui me ära süüa suudame.\nTarbimisharjumuste alla kuulub ka riiete ostmine, kandmine jne. Paljud inimesed tellivad riideid Hiinast, sest see on odav ja nad eelistavad kvanditeeti kvaliteedile. „Mida rohkem on sul riideid seda ägedam sa oled“, tegelikult ei vasta see tõele. Minu idee on see, et mida kvaliteetsem on riideese, seda kauem sa saad seda kanda ehk vähem raisku laskmist. \nMina arvan seda, et kui me analüüsiksime natukene rohkem oma tarbimisharjumusi ning muudaks neid, siis oleks võimalik vähendada asjade raisku laskmist ning  ressursse nende tootmiseks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('2d449f8a-90f2-46ec-bd74-9b0278de197e', 'title', 'Inimeste tarbimisharjumused');
