INSERT INTO core.text(id, content)
VALUES ('69085d33-31a0-42af-91c9-f6678a388c77',
        'Meie ümber on palju inimesi, kes raiskavad toitu või riideid see on probleem.Esemete raiskamine on juba mõndadele igapäeva elu osa.See on halb riigile ja loomadele ning teistele ka.\nPaljud inimesed raiskavad toitu ja ei näe selles midagi halba.Nad saavad seda enda arust teha sest nad suudavad endale seda lubada.Samas on meie ümber ja ümber maailama inimesi kes on näljas.Meie kui viskame toidu ära mille oleksime saanud süüa homme ei mõtle nii, et teised nälgivad.Ostame midagi ja paneme külmkappi ning see jääbki sinna.Päevade kaupa isegi näadalate pärast kui tuleb meelde,et toode on ikka veel söömata.Siis vaatame tähtaega ja on aegunud siis lihsalt visatakse toode ära.\nMõned inimesed viskavad ära korralike riideid või midagi muud mida oleks saanud mitu korda kasutada.Ostavad ühe riietuse peo jaoks ja kannavad selle peol ära ja viskavad pärast minema,sest nad saavad lubada seda endale.Selle asemel,et uuesti kanda või jätta see mõneks muuks tähtsaks ürituse jaoks.Isegi sõbrale anda kui ise ei soovi seda mitu korda kanda.Hoiab raha kokku ja pole midagi viga sellega kui kannad ühte riietust mitu korda.Me ei kuluta mitte ainult riideid või toitu vaid kõike mida saab raisata,mis on suur probleem meie kõigi jaoks.\nSee on kindel,et me kõik raiskame toitu,riideid või midagi muud see on probleem,millele tuleb leida lahendus tuleb lõpetada toidu üle ostmise.Tuleb osta kõiki asju mõõdukalt ja mõistuse piires.Nii suudaksime lahendada selliesed probleemid.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('69085d33-31a0-42af-91c9-f6678a388c77', 'title', 'Inimeste halvad tarbimisharjumised');
