INSERT INTO core.text(id, content)
VALUES ('076376d4-63bf-4929-8161-01e5a84a51db',
        'Kõik inimesed puutuvad igapäevaselt kokku tarbimisega ning teevad seda erinevalt. Inimesed on harjunud tarbima asju erinevalt. Millised on inimeste tarbimisharjumused?\n   Osa inimesi raiskavad oma toitu, sest nad saavad seda endale lubada. On ka neid, kes söövad terve nädala samat sööki kuni see otsa saab või viskavad ära väikestes kogustes toitu. Toidu ära viskamise asemel võiks selle viia inimestele, kes endale ise ei saa süüa osta. Söögi raiskamist saame me ise reguleerida ja parandada, sest see on kinni meie harjumustes. Lisaks sellele tekitab toidu raiskamine keskkonnaprobleeme, -koormust ja reostust. Toitu ära visates raiskame me nii enda raha kui ka maad, vett, energiat ja tööjõudu. \n   On ka neid inimesi, kes ostavad endale suurtes kogustes riideid, kuid kannavad neid vaid korra ja siis jäävad need seisma või visatakse minema. Rõivaste ära viskamise asemel võiks need viia taaskasutuskauplustesse või riidekonteinerisse. Osad inimesed tellivad internetist tohutult palju riideid ja muid esemeid, sest pildi peal tundus ilus, kuid päriselus võivad need välja näha erinevad ning nad ei taha neid kasutada. On oluline, et inimesed valiksid kvaliteedi üle kvantiteeti, et vähendada suurtes kogustest mõttetute kaupade ostu. \n  Väga suur osa inimestest raiskab toitu ning viskab suures kogustes ülejääke minema. Samal ajal on ka neid, kes ei jäta midagi alles ega viska midagi ära. On ka neid, kes raiskavad riideid, ostes neid palju ning kandes väga vähe.');
