INSERT INTO core.text(id, content)
VALUES ('3bab4da3-0448-4995-b11b-fc8ad69a7e35',
        'Tänapäeva inimeste tarbimisharjumised on suuremad. Inimene arvab, et tal on vaja nii palju asju, mis kõik pärast tegelikult raisku läheb. Mis on tänapäeva inimeste tarbimisharjumised?\nInimeste üks kindlaim tarbimisharjumus on liigne söögi tegemine ning liiga suure toidu koguse tõstmine endale taldrikusse. Näiteks koolilapsed tõstavad endale suure portsu sööki taldrikusse, mis lõpetab pärast solgi ämbris. Arvatakse, et kõht on nii tühi ja toit näeb nii hea välja. Tihti peale tuleb ka välja poole söömise pealt, et toit pole nii maitsev, kui välja nägi. Sama on ka toidu liigne valmistamine nii koolides ja muudes asutustes ning kodudes. Toit suudab, kas vahepeal pahAKS minna või töökohtades ja koolis ei tohiks sama toitu pakuda järgmine päev ega teistele võõrastele anda.\nInimeste teine kõige suurim tarbimisharjumus on osta hunnikus uusi riiideid ning neid toodetakse aina juurde. Näiteks ostetakse riideid kahtleval seisukohal, et kas ikka meeldib ja, kas on vaja. Enamus ikkagist ostavad ära. Koju jõudes pannakse riideese kappi ning paari päeva möödudes suudab inimese meel muutuda ja visatakse ära. Selle asemel võiks taaskasutusse viia, müüa maha või annetada. Võiks ka osta taaskasutuskeskustest. Veel parem oleks, kui inimene taaskasutab seda ja teeb endale sobivaks nii, et ta kannaks seda.\nTänapäeva inimeste tarbimisharjumised on toidu liigne tõstmine taldrikusse, toidu üleliigne tegemine ja ebameeldivate riiete ostmine.');
