INSERT INTO core.text(id, content)
VALUES ('57d7e31c-68f7-4cdb-bf97-0a2290fc7ab3',
        'Paljud inimesed arvavad, et nende tarbimisharjumused mõjutavad ainult neid. Mõned ususvad, et asjade raiskamine on mõtlematu ja kahjustav. Kas inimeste tarbimisharjumused mõjutavad teisi elusolendeid?\n   Inimeste toidu, riiete ja elektroonika raiskamine kahjustab loodust ja loomi. Kui restoranid viskavad prügikasti päevavanuse toidu siis on võimalik, et loomad leiavad selle ja saavad seda söödes mingi haiguse. Paljud restoranid ei kaitse prügikaste kuhu nad toitu viskavad, seega käivad seal igasugused loomad ning ka inimesed. Suuremad kauplused viskavad ära ka riideid ja elektroonikat, mis loodusesse sattudes ei lagune ja võib haavata, lämmutada loomi. Ka tavalised tsiviilisikud viskavad ära toitu, riideid ja elektroonikad, mis loodusesse sattudes seda kahjustab\n   Halvad tarbimisharjumused tähendavad ka seda, et asjad, mis oleksid teistele inimestele kasulikud leiavad ennast prügimäel või looduses. Inimesed ei raiska ainult omaenda raha, vaid ka tohutult muid ressursse: maad, vett, energiat ja tööjõudu. Paljud inimesed kasutavad toidu kaste ja kasutatud riiete poode, et vähendada raisku läinud ressursse. Riiete ning muude asjade annetamine on kasulik ja hea, sest inimesed, kellel pole piisavalt raha toidu või uute riiete jaoks, saavad vajalikke tarebeid oma elu jaoks. Kui kõik inimesed annetaksid riideid, mida nad ei kasuta, väheneks ka loodus reoste tohutult.\n   Halvad tarbimisharjumused võivad kahjustada loodust, loomi ja ka inimesi. Inimesed kes annetavad toitu ja riideid aitavad teisi tohutult. Inimeste tarbimisharjumused mõjutavad teisi elusolendeid palju.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('57d7e31c-68f7-4cdb-bf97-0a2290fc7ab3', 'title',
        'Kas inimeste tarbimisharjumused mõjutavad teisi elusolendeid?');
