INSERT INTO core.text(id, content)
VALUES ('76193444-b626-481f-8c28-9e7d33118cee',
        'Tänapäeva inimeste tarbimisharjumised soovivad parenemist. Nende puudumine võib kahjustada meie keskkonda. inimeste  tarbimisharjumused.\n       Üheks oluliseks prooblemiks tänapäeva inimestel on see, et paljud võtavad endale liigse toidu. Enamik tarbivad toitu iseenesestmõistetavana. Selle tagajärjel enamik toidust läheb halvaks ja seda visatakse prügikasti. Iga Eesti inimese kohta tekib aastas umbes 61 kilogrammi toidujäätmeid, millest toidukadu moodustab umbes 42 protsenti ehk 26 kilogrammi. Selleks, et seda vältida, inimesel tuleb osta endale mõõdukalt toitu ja visata prügikasti ainult seda, mis ei kõlba süüa.\n         Teiseks samuti suureks probleemiks on riiete  liigneostmine, see tähendab, et paljud inimesed, eriti noored, ostavad endale liiga palju riideid, mis tulevikus ei kasuta ja ei kanna. On oluline et igaüks vaataks üle oma tarbimisharjumused ning eelistaks kvaliteeti kvaliteedile. Sellele  tuleb abiks ekskursioonid  taaskasutuspoodide laodel.see aitab mõista, kui palju inimsed osavad riideid, mis pärast ei kanna.\nInimeste tarbimisharjumused in igal ühel erinevad. oluline on mõista, kui tähtis on tarbimisharjumused. need aitavad hoida meie keskkonda puhtana.');
