INSERT INTO core.text(id, content)
VALUES ('6d891424-fec3-4319-810c-466e2e5677ae',
        'Kõik inimesed kui midagi ostavad satuvad need asjad nii kui nii prügikasti. Aga kui kiiresti need asjad satuvad prügikasti sõltub inimesest. Kõikidel inimestel on olemas oma tarbimis harjumused need võivad olla nii head kui ka halvad.\nInimesed on väga erinevad rõivate poolest näiteks: Inimesed ostavad rõivaid ja hoolivad nende eest kuidas tahavad. Mõned inimesed on harjunud, et kui nad ostavad rõivaid kannavad nad neid natukene ja siis viskavad ära või annavad taaskasutusse. Inimesed võivad olla ka sellised, et kannavad rõivaid viimseni ja nad hoolitsevad enda rõivate üle nii hästi, nad lausa õmblevad neid. Mina hoolin väga enda rõivatest ja hoian neid viimseni, ma lasen isegi emal vahepeal neid õmmelda. Ma olen väikesid rõivaid alles hoidnud ka pereliikmetele näiteks vennale või õele.\nInimesed on erinevad ka söögi poolest. Osad inimesed teevad ise süüa aga osad alati muudkui tellivad. Kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt kuuskümmend üks kilogrammi toidujäätmeid, milles toidukadu moodustab nelikümmend kaks protsenti ehk kakskümmend kuus kilogrammi. Ma olen natuke ökonoomne toidu poolest, üldiselt mul ikka jääb toitu alles aga ma annan enda toidujäägid enda koerale.\nMa arvan, et iga inimene saab olla ikka hoolivam ja ökonoomsem oma rõivate ja toidu poolest.');
