INSERT INTO core.text(id, content)
VALUES ('e66cbc9e-aafa-40fb-bd17-6a5c5820d60a',
        'Me kõik oleme harjunud toitu erinevalt kohtlema . Mõni kohtleb seda paremini ja mõni seda halvemini. Millised on inimeste toitumisharjumused?\n    Paljud inimesed taaskasutavad toitu. Nad teevad neist võimalikult palju erinevaid asju. Sellised inimesed kasutavad ülejääke ka oma toitudes uuesti. Toitu taaskasutatakse ka riiete tegemisel.  Nad vaatavad seda ka palju kui palju nad oma taldrikule tõstavad. Neile on ka oluline kui palju nad tavaliselt ära viskavad.\n      Paljud inimesed ei hooli sellest kui palju nad ära viskavad.Sellised inimesed tavaliselt ei vaata kui palju nad poest ostavad ja kas seda kõike läheb vaja. Selle tagajärel viskavad nad rohkem ära kui vaja on. Nad ei mõista sellega kui palju nad raiskavad. Nad ei mõista ka seda kui palju nad mõtetult raha raiskavad. Nad tavaliselt ei sorteeri ka oma prügi, mida peaks enam-vähem kõik pere tegema.\n    Paljud inimesed eelistavad kodumaised tooteid. Kõigile ei pruugi meeldida välimaised tooted. Nende asemel tahavad nad midagi mis on tootetud kodumaal ja on värske. Mõned inimesed tootavad ka toitu ise, näiteks farmerid. Kodumaised tooted on tavaliselt värskemad ja paremad. Kodumaiste toodete ostimisega toetavad nad oma kodumaad. Mõned käivad lausa enda valmistatud asju müümas. \n     Muidugi on teisiki inimesi olemas. Inimeste toitumisharjumused on taaskasutamine, ära viskamine ja kodumaiste toodete ostmine.\nKirke Kuusik 9.B');
INSERT INTO core.text_property(text_id, property_name, property_value)
