INSERT INTO core.text(id, content)
VALUES ('a9b1e9f9-113a-47b4-b70b-a40c73c10331',
        'Mõned ütlevad, et arvuti on inimeste kõige olulisem leiutis, kuid siiski osad inimesed ütlevad, et see on ajaraiskaja. Kas arvuti on tõesti ajaraiskaja või on ta väärtuslik abiline?\nSuurim põhjus, miks arvuti on kasulik, on selle võime kiirendada töötamist ja õppimist. Arvuti annab  inimestele võimaluse otsida igat asja, mida nad soovivad, ainult mõne vajutusega. Arvuti laseb inimestel saada kodakondsus, ID kaart või muu selline dokument. Mõndades kohtades on inimestel võimalik arvutiga isegi uuendada enda dokumente\nÜks suur põhjus mis teeb kompuuteri kasulikuks on mugavus mis see annab. Arvutist saab tellida süüa, maksta makseid, lugeda ajalehte ning isegi osta poest vajalikke esemeid. Samuti annab kompuuter inimestele võimaluse töödata kodust, mida paljud eelistavad üle kontori. Kontoris töötamine tõstab inimeste produktiivsust kuna kodus ei räägi inimesed enda kolleegidega.\nSuurim põhjus, miks arvuti võib ka olla ajaraiskaja on selle külluslik meelelahutus. Raalis võib vaadata filme, mängida videomänge ja isegi suhelda enda tuttavatega. Sellised tegevused on väga kaasahaaravad ning ka samuti aega võtvad. Mõned inimesed võivad tihtipeale üle kümne tunni järjest kasuta arvutit.\nKuigi arvuti võib olla väga aega nõudev on ta siiski väga kasulik mis teeb ta rohkem abiliseks kui ajaraiskajaks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('a9b1e9f9-113a-47b4-b70b-a40c73c10331', 'title', 'Arvuti, abiline või ajaraiskaja?');
INSERT INTO core.text_property(text_id, property_name, property_value)
