INSERT INTO core.text(id, content)
VALUES ('226cde89-86b4-4c80-9f8e-211809d8b642',
        'Ületarbimine on tänapäeval suur probleem. Inimesed raiskavad toitu, ostavad ebavajalikke tooteid ja kõigel sellel on oma tagajärjed. \nToit on eluksvajalik toode mida kõik tarbivad . Seda on nii palju ja on nii odav et inimesed ei mõtlegi kuidas nad seda raiskavad. Halvaks läinud toitu mida keegi pole isegi söönud on palju, oodatakse, kui see halvaks läheb ja visatakse ära, kuigi oleks saanud selle ära anda. Pärast söögikorda ülejäänud toit visatakse ära. Kõik see raisatud toit võttis palju energiat et toota. Toidu tootmine võib kahjustada keskonnda, kui see toit  visatakse ära on see mõttetu looduse kahjustamine.\nElektroonka liigne ostmine on väga kahjulik. Inimesed ostavad koguaeg endale kas uue telefoni, arvuti või muu vidina, neil pole isegi neid asju vaja, aga kuna see on uuem siis nad kohe jooksevad sellele järgi. Millepärast tekib väga palju prügi mida ei ole lihtne taaskasutada. Kõikide metallide ja tükkide välja võtmine ja taaskasutamine võtab palju energiat ja tööd. Nende tootmine on ka keskonnale halb. Kaevandatakse neis kasutatud metalle kohutavates tingimustes. Liigne ostmine erinevatelt veebipoodidest suvalisi tooteid tehtud Hiina tehases.\nÜletarbimine on ikka suur probleem tänu internetile ja odava toidule. See kahjustab keskkonda. Inimesed peavad tulema mõistusele ja tarbima vähem.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('226cde89-86b4-4c80-9f8e-211809d8b642', 'title', 'Ületarbimine');
