INSERT INTO core.text(id, content)
VALUES ('a2af13f7-86b6-4ea2-8df6-6421881051c0',
        'Inimesed tarbivad maailmas palju. On inimesi kes raiskavad toitu ja on inimesi kes säästavad toitu. Sama asi on ka riietega. Osa inimesi viskavad riideid kohe ära, kui on katki ja osa parandavad riideid või teevad midagi uut nendest. Kas inimestel on samasugune tarbimisharjumus?\n   Toit on maailmas suur probleem. Me tarbime igapäev toitu. Paljud meist viskavad söögi ära, sest neile ei meeldi süüa mitu päeva sama toitu. On inimesi, kes suudavad osta endale uusi riideid igapäevaselt aga on ka neid, kes vaevu suudavad osta endale riideid. Me saaksime mitmeid viisi säästa raha. Nagu näiteks annetame vaesematele riideid ja toitu, teeme kogus toitu mis me sööme ära.\n   Inimesed reostavad loodust. Igalpool ookeanis leidub prügi, sest inimesed ei hooli meie loodusest. Loodus on tähtis meile, sest seal elavad loomad, taimed kasvavad ja ka sellepärast, et me ise pidevalt viibime looduses. On loodud organisatsioone, mis tegeleb prügi korjamisega. Seal on vabatahtlikud inimesed, kes hoolivad loodusest palju. Loodus teeb ühe riigi ilusaks ja atraktiivseks.\n   Inimesed reostavad loodust visates prügi maha. Aga ka on organisatsioone, mis tegeleb loodust puhtana hoidmisega. Looduses elab palju erinevaid loomi, kes võivad haruldased ka olla. Me saame annetada Inimestele, kes ei saa ise väga hästi hakkama riideid või toitu.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('a2af13f7-86b6-4ea2-8df6-6421881051c0', 'title', 'Inimeste tarbimisharjumus');
