INSERT INTO core.text(id, content)
VALUES ('63defc09-ca31-4b01-b529-8509f504a550',
        'Tänapäaeva ühiskond on selline, kus saab lubada erinevaid tarbimisharjumusi kõigile. Kes hoolib endast, kes hoolib keskkonnast või hoopis keegi hoolib neist, kes teiste nõuete all kannatavad. Millised on erinevad tarbimisharjumused?\nSuureks probleemiks tänapäeval on toidukadu. Enamik inimesi on harjunud sellega, et toidu olemasolu kohta muretsema ei pea. Poodides on toitu lettide kaupa ning see, et toit otsa peaks saama, pole võimalik. Säärane mõtlemine soodustab toidu raiskamist. Toidu raiskamine ei kahjusta vaid keskkonda, vaid see ka koormab nii tootjaid kui ka töölisi. Kuigi kui ei põhjusta muret söögi teema mitmetes riikides, on selline probleem sagedane suurarengumaades. Toidu olemasolu on privileeg ning seda tuleb väärtustada nii, et ostetud kaup ära tarbitakse\nTänavu noorte riietusharjumused põhinevad mõttel kvantiteet üle kvaliteedi. Tahetakse omada mitmeid eri sorti rõivaid mitte mõeldes sellele, millest need tehtud on ja kus tehtud on. Kiirmoepoed on vägagi populaarsed noorte seas, kuid selliste poodide kohta ei tea, kuidas nende toodetud riideid valmistatakse. Hiinas toodetakse massiliselt väikese hinnaga  riideid, mille kvaliteet võib olla isegi tervisele kahjulik. Parem oleks olla kindel selles, mida kantakse ja milliseid riske kiirmoe tooteid ostes olla võib.\nPaljud tarbimisharjumused tänapäeval on kahjulikud seoses reostusega ning massi tootmisega. Kõik peaksid kasutama oma asju mõtekalt ning mitte soodustama halbu tarbimisharjumusi.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('63defc09-ca31-4b01-b529-8509f504a550', 'title', 'Inimeste tarbimisharjumused');
