INSERT INTO core.text(id, content)
VALUES ('91ac0aed-ae25-4069-b4b5-c98b3e734621',
        'Paljud tänapäeva noored käivad kaasas uute moodide ning trendidega. Trendid tulevad ruttu ning lahkuvad veel rutem. Kui uus video, uute lahedate riietega jõuab sotsiaalmeediasse, on hetke pärast need riided ka igas poes. Millised on noorte tarbimisharjumused?\nEnamus noored näevad reklaami, kus pakutakse soodsa hinnaga trendikaid  riideid ning tellivad need koheselt. Mitte teades kas need on kvaliteetsed ja õiged ning kesneed valmistas. Paljud tellivad välismaa riikidest, kus kasutatakse lapstööjõudu. Kõige populaarsem on Hiina.\nTaaskasutuspoodidesse jõuab väga palju odavaid ning mittekvalitseetseid riideid, mida tellitakse Aasia riikidest. Noored peaksid hindama kvaliteeti üle kvantiteedi. Suur trend sotsiaalmeedias on omada võimalikult palju riideid ja jalatseid. Ületarbimine toimub ka teiste esemetega, näiteks telefoniga. Paljud inimesed ostavad iga aasta uue telefoni kuid nende vana telefon on täiesti töökorras.\nTänapäeval on ka tekkinud häid harjumusi. Paljud inimesed käivad taaskasutuspoodides ning müüvad oma vanu riideid läbi erinevate rakenduste. Riideid müüdakse ka sotsiaalmeedias. Kuulsused saadavad oma austajatele riideid, mida nad on kandnud üritustel või postitustel. Kellegi vana on teise uus. Selline viis ostelda on väga tark, sest leiad uusi riideid mida teistel pole.\nTänapäeva noortel on halbu ning ka häid tarbimisharjumusi.  Jätkusuutlikus ning taaskasutus on kõige paremviis saada endale lahedad ning omapärased riided hea hinnaga. Sellist ostlemist peaksid kõik proovima.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('91ac0aed-ae25-4069-b4b5-c98b3e734621', 'title', 'Noorte tarbimisharjumused');
