INSERT INTO core.text(id, content)
VALUES ('a542cd8e-61cf-4518-b2b6-90874ad82ccc',
        'Paljud inimesed tänapäeval kulutvad suure hulga raha erinevate asjade peale.Mõndade jaoks klutavad nad raha kasulike asjade peale teised kulutavad seda erinevatele mitte vajalikele asjadele.Kas inimesed kulutavad liiga palju raha internetis?\nTänapäeval on internetis kauba ostmine väga tavaline. Mõned inimesed kulutavad liiga palju raha siukeste asjade peale mis ei ole kasulikud iga päeva elus või pole ültse kasu neile. Mina ise olen palju siukseid asju ostnud ja nüüd need istuvad kappides tolmuga. Populaarseks on saanud soodne hiina kaup mis on peagu alati praak ja ei tööta kaua.\nKunagi pole olnud nii kerge raha kulutada kuskil. Peagu kõik mida sa saaksid teha oma toast väljas saad sa teha oma arvutist või isegi oma mobiilseadmest. Peaegu igal söögikohal ja poel on nüüd võimalus midagi osta oma kodust. Isegi hasartmänge saaksid mängida oma enda arvutist. Inimesed võttavad kõik need ekstra hinnad mis tulevad nende ostudega vastu ja kulutavad raha lihtsalt selle pärast, et nad ei peaks väljuma oma kodust.\nInimesed kellel on kas mentaalsed või füüsilised probleemid, nende jaoks on internetipoed head. Siuksed inimesed saavad tellida endale sööki ja igapäeva vajadusi ilma probleemiteta. Sellised asjad võivad ka kalliks minna nendele inimestele, sest nad veedavad pikka aega siukestel lehtedel kus viskab palju erinevaid asju neile ette. Inimestest keda mina tean kes on siuksed ei kuluta liiga palju ja teavad palju raha nad võivad kulutada.\nÜldiselt kulutatakse liiga palju internetis raha. Sellele pole väga suurt head poolt peamiselt on ainult vajadustega inimestele.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('a542cd8e-61cf-4518-b2b6-90874ad82ccc', 'title', 'Inimeste kulutamine internetis.');
