INSERT INTO core.text(id, content)
VALUES ('e08280aa-abcc-4211-b7c3-9fbe3070dc49',
        'Inimeste tarbimisharjumused on erinevad. Millised on minu tarbimisharjumused?\nÜks minu tarbimisharjumustest on poest mõistlikus koguses toidu ostmine. Kui ma käin poes ma ostan nii palju süüa kui ma ära söön, et mitte toitu raisata, lisaks sellele ma võtan ainult neid tooteid, mida mul on tõesti vaja on, et säästa raha.\nSamuti on mul harjumus osta riideid ainult siis kui ma tõesti pean, näiteks siis kui mu riided on mulle väikseks jäänud, katki läinu või  ära määrdunud ning ma ostan riideid ainult taaskasutuspoodidest, et hoida raha kokku kuna riidepoodides on rõivad kallid.\nKõige viimane harjumus mul on erinevatelt veebilehtedelt soodustuste otsimine tooteid ostes kuna nii ma leian endale sobiva soodustuse sellele tootele mida ma tahan osta, lisaks ma käin erinevates veebipoodides ostlemas kõige rohkem siis kui on erinevad kampaaniad ning suured soodustused.\nVäljatoodud väidete põhjal ma saan öelda et minu tarbimisharjumused on poes mõistlikus koguses toidu ostmine, riiete ostmine siis kui ma tõesti pean ning erinevatelt veebilehtedelt soodustuste otsimine tooteid ostes.');
