INSERT INTO core.text(id, content)
VALUES ('cbb800a1-919a-4347-9a15-d555e8876819',
        'Inimesed tarbivad väga palju asju, näiteks riideid. Kuid enamik inimesi viskavad need väja pärast kasutamist. Kuidas on minu peres tarbimis harjumusega?\n Me lõpetame ära kõik toidu taldrikul. Mulle on juba väikesest ajast pähe tambitud, et me ei raiska toitu. Mu isa ja ema ütlevad, et see on raha raisk ja ma nõustun nendega. Seal on olnud haruldased korrad kui toidu raisk oli minu peres hea. Näiteks kui mitte kellegile mu peres toit ei meeldi, siis on meil õigus see välja visata.\n Vanad riided kingime teistele peredele. Minu peres on komme vaadata üle oma riide kappid vähemalt üks kord kahe kuu jooksul. Kui me leiame midagi, mis meile enam ei meeldi siis paneme need ilusasti kottidesse ja viime teistele inimestele. Näiteks, mu emal on üks sõber kellel on ka lapsed ja neile meeldib vahetada oma, ning oma laste riideid teineteisega. Kuid mulle üsna meeldib vaadata nendesse kottidesse, kuna kunagi ei tea millal on võimalusleida mõni haruldane riideese.\nMinu peres on üsna suur energia kulutus. Meie peres on üks väike probleem, me kasutame väga palju energiat. Meie energia makse on varsti läbi katuse ja ei nää välja nagu see hakkaks peatama. Näiteks ainult minu toa pealt oleks vaja umbes 5000 sidrunit, et lihtsalt mu arvutit tööle korralikult saada.\nMinu pere ei raiska toitu, ei viska ära vanu riideid. Kuid samas kulutab mu pere kohutavalt energiat.');
