INSERT INTO core.text(id, content)
VALUES ('a3960999-7b54-4410-8caf-21a65d525d3b',
        'Inimesed tarbivad palju toitu.Toitu on nii palju,et see ei saagi otsa.Paljud inimesed viskavad suurtes kogustes toitu ära.Mis on inimeste tarbimisharjumused?\n    Paljud inimesed tarbivad palju toitu ning ei jaksa seda kõike ära tarbida.On inimesi, kes raiskavad toitu, sest saavad seda endale lubada.See mõjutab palju keskkonda.Toit on meie jaoks iseenesestmõistetav, sest me vajame süüa, et oleks meil energiat ja jõudu. Me ostame palju süüa kokku, aga me ei tarbi seda kõike ära.Majapidamises tekib igal inimesel 61kg toidujäätmeid.Miks me seda toitu ei jõua ära süüa on see, et söök võib pahaks minna ega kõlba enam süüa.Inimesed ei pruugi teadagi, kui palju raha nad toidu peale panevad ja kõik selle pahaks läinud söögi ära viskavad.\n    Ei raiska ainult raha vaid ka teisi asju nt:maad,vett,energiat ja tööjõudu.Liskas tekitab toidu tootmine tõsise keskkonna koormuse, sest saagikuse tõstmiseks kasutatakse väetisi ja erinevaid kemikaale.Mõjutab keskkonda, sest kui viskad toidu kuskile kus loomad siis nad võivad saada sealt mürgituse või haigestuda.Paljudes riikides ei ole süüa nii palju, et seda raisata, sest on vaesemaid riike kui Eesti.Toidu raiskamist ei saa lõpetada üleöö, sest see on kinni inimeste harjumustes.Säästame keskkonda ning ärme raiska toitu.');
INSERT INTO core.text_property(text_id, property_name, property_value)
