INSERT INTO core.text(id, content)
VALUES ('3c153738-f7bd-4ba6-a5d4-733adcbb962e',
        'Tarbimisharjumused on inimese psüühiliselt mõtlematta korduv otsus või tegevus, mis hõmab igat inimest omamoodi. Tarbimisharjumused arenevad üle kogu meie elu. Millised on meie kõige põhilisemad probleemid, mis hõlmavad inimeste tarbimisharjumusi?\nInimesed pidevalt ostavad liiga palju asju. Üks pidev ja tüüpiline viga inimeste tarbimisharjumusted on asjade liigne ost. Inimesed ostavad liigselt asju mida nad ära ei kasuta. Näiteks söögipoes liigne oostmine tähendab kodus toorainete või muude asjade roiskumist, riidepoes suur ostu palavik, mille tõttu kasvab inimene riietest juba välja või riie poleenam moes. Minu kodus on ka selliseid juhtumeid nagu puuviljade roiskumine külmkapis või riiete panek panipaika.\nEnamus kodudes lähevad roisku eelnevate toidukordade jäägid. Enamikes peredes sööb toidujääke ainult isa, ja sellest lihtsalt ei piisa. Kui perenaine teeb päevas 3 kordas kõigile süüa ja iga kord jääb jääke ei jõua keegi neid süüa ja toit läheb litsalt roisku. Minu kodus on ka vahepeal toidujääke, mida keegi ei söö, kui mina või mu isa neid ei taha, millega jäävad tihti jäägid roiskuma.\nInimesed ostavad ka pidevalt asju mida nemad ise ei tarbi ei kanna. Inimesed teevad tihedalt kohapeal olevaid oste ehk impulssoste. Inimesed ostavd nimadi mõtlemata, millega tihti jäävad sellised ostud koju seisma (eseme korral) või lähevad roiskuma (toiduaine korral). Sellised asjad tihadelt visatakse koristuste ajal minema. Minu kodu on ka asju või esemaid mis lihtsalt seisavad seismise pärast.\nInimesi tabavad mitmed elmentaarsed tarbimisharjumusi mõjutavad vead, mille tõttu raiskame me meie planeedi ressursse. Liigsed ostud, jäätmete roiskumine ja impulssostud on meie kõigi ühed põhilised vead, mis hõlmavad meie tarbimisharjumusi. Minu pere on ka neid kõiki probleeme näha, kui vaatad õigest küljest.');
INSERT INTO core.text_property(text_id, property_name, property_value)
