INSERT INTO core.text(id, content)
VALUES ('276e3cb9-0910-4899-a6b0-0ee378361770',
        'Iga Eesti elanik raiskab keskmiselt 26 kg toitu iga aasta, toidukadu ei raiska vaid meie enda rahakotte, aga ka maad, vett, tööjõudu ja energiat. Kuidas peaks õpetama inimest, et ta toitu ei raiskaks?\nInimesed ei raiska toitu pahatahtlikult, vaid see käib neil harjumuse järgi ning nad ei mõtle tagajärgede peale, mis kaasnevad toidu ära viskamisega. Seda peakski õpetama neile, kes on harjunud toidu raiskamisega.\nÜhes „Vikerhommiku“ intervjuus rääkis üks moedisainer, et igaüks võiks valida kvaliteedi kvantiteedi üle, et kui toode ei sobi siis ei pea ära viskama ega maha müüma. Ta soovitas ka seda, et noortele tehtaks ekskursioone taaskasutuspoodidest, et nad näeksid oma silmaga kui palju riideid, mänguasju, tööriistu ja muud sellist ära antakse, sest see ei sobinud oma omanikule.\nEkskursioonid taaskasutuspoodidesse on hea viis vähendada noorte tootekulutamist, aga siis jääb ette probleem: täisealiste tarbimisharjumused. Sest täisealised muidugi koolis ei käi, ei käi nad ka nendel ekskursioonidel ja tihtipeale laste tarbimisharjumused tulevadki oma vanematelt, ehk on selle vältimine mõjukam kui noorte õpetamine. Vanemaid inimesi saab effektiivselt harida kas neti abil või ajalehe abil. Need kes pole harjunud internetti kasutama loevad pigem ajalehte, ning need kes on töenäoliselt loevad netis uudiseid.\nToidukadu on suur probleem ühiskonnas, ning seda täienisti ei saa kustutada. Me saame õpetada inimesi, et nende tarbimisharjumusi vähendada kas ekskursioonide abil, uudiste abil või lihtsalt vanemalt lapsele õpetades, sest noorematel jääb kiiremini mõte meelde.');
