INSERT INTO core.text(id, content)
VALUES ('8d7e81d3-c915-49d6-b042-7fae098cea7e',
        'Inimesed tarbivad liiga palju. Pole vaja osta endale viis täpselt samasugust särki, mis siis, et neil võib tõesti olla vaevumärgatav toonivahe. Liigne tarbimine pole hea nii meie planeedile, keskkonnale ja seega ka meile endile.\nSuurt osa tarbimist mõjutab tööstus. Mida rohkem toodetakse, seda rohkem tahetakse oma toodangut müüa. Inimestele meeldib ikka paremaid ja ilusamaid asju omada, tean seda omast käest. See on minu arvates mõistetav aga asju ei peaks olema nii palju. Piisabki mõnest ilusast ja kallist asjast, neid asju pole vaja hunnikute viisi kodus hoida.\nProbleem millega olen lähedasemalt kokku puutunud on liigne pudi-padi omamine. Minu vanaemal on kas kodus või keldris või suvilas palju jama, osad neist võivad olla koguni üle 20 aasta vanad. Veidi hoian ka ise asju liiga palju alles, tekib tunne, et äkki vajan veel neid või on lihtsalt tore nostalgiline meenutus.\nProbleemi saaks parandada inimeste enda arusaamisega, et äkki neil pole ikka kolme samasuguseid jakke vaja. Minu arust on hea idee taaskasutus, laenata sõbra mütsi, mitte osta iseendale täpselt samasugust, et siis seda üks kord kanda saaks.\nTarbimine on mõistetav aga seda võiks teha normaalses koguses. Kui tööstused vähendaksid tootmist, ei peaks inimesed nii palju ostma, sest nad ei näe ega unista nii paljudest asjadest.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('8d7e81d3-c915-49d6-b042-7fae098cea7e', 'title', 'Tarbimine');
