INSERT INTO core.text(id, content)
VALUES ('ba0d1b4d-d2cc-4dff-90ca-0c69d65b9cf8',
        'Tootete tarbimine ja ära viskamise mõju keskkonnale. Inimeste harjumus tooteid ära visata. Mida saaks teha, et vähendada tootete raiskamist.\n        Toidukaubad on üks asi mida iga inimene ostab ja tarbib. Toidujäätmeid tekib iga aasta ühe inimese kohta keskmiselt 61kg. Toidu raiskamine on suhteliselt suur probleem, sest maailmas läheb aasta jooksul raisku tonnide viisi toitu. Selleasemel, et osta asju mida sa võibolla tahad süüa või selle pakend meeldib sulle osta asju mida sa kindlalt ära kasutad.\n          Riideesemed on üks asi mida kandmatta ei lähe keegi teiste inimest ette, kuid neid visatakse tonnide viisi ära. Inimesed ostavad endale palju riideid mida nad võibolla kasutavad ühe korra ja siis enam seda ei puutu ja see visatakse pärast ära. Väga paljud ei käi ka taaskasutuspoodides, et vaadata sealt korralike riideid mida on võibolla ainult ühe korra kantud. Osad ei käi seal, sest see tundub imelik või vaesetele.\n             Kui me konstanselt viskame asju ära, sest meile need enam ei meeldi või on roiskuma läinud kuna ostsime liiga palju ja ei kasutanud neid ära, siis me mõjutame suhteliselt palju ka keskkonda. Iga asja, olgu see siis toidukaup või riietusese nende tegemine toodab jääkaineid, mis omakorda mõjutavad keskkonda. Toidutootmine võib tekitada erinevaid heitgaase ja kemikaale. Keskkonnale mõjuvaid asju saaks vähendada kui inimesed tarbiksid ainult seda mida vaja.');
INSERT INTO core.text_property(text_id, property_name, property_value)
