INSERT INTO core.text(id, content)
VALUES ('2235b31d-ff90-41e6-8b4f-6042723138a5',
        'Inimesed on väga erinevad. On olemas ininmesi, kes raiskavad palju tarbeid, aga on inimesi, kes teevad vastupidist. Planeet Maa ei kesta igavesti ja kui inimesed raiskamist jätkavad, pole maavaradest ja loodusest varsti midagi järgi. Kas inimesed peavad nii palju tarbima?\nNeid inimesi on vähe, kes arvavad, et tarbete raiskamine on kahjulik. Kahjuks tuleb tõdeda, et nende inimeste arvukus on vähenenud. See, kui me juba näiteks ei viska suurtes kogustes toitu ära, ei osta igapäevaselt uusi asju ja käiksime rohkem taaskasutus poodides on juba samm, hea tarbija poole. Selleks, et nende inimeste arvukust tõsta on vaja näidata uudiseid halvast maailma poolest. Me peame tegema seda selleks, et näidata ja tõdeda neile reaalsust. \nNeid inimesi, kes raiskavad tarbeid on väga palju. Need inimesed ei mõista, et nad tegelikult võtavad iga rasikamisega Maalt elu. Üks suuremaid probleeme on toidu raiskamine. Toidu ära viskamisega, raiskame me tohutult maad, vett, tööjõudu ja energiat. Kindlasti peaksime iga ostetud toidu kuidagi ära tarbima. \nÜks probleem on ka riiete tarbimine. Inimesete suur probleem on internetist tarbete tellimine. Koht, kus inimestele väga meeldib tellida on Hiina veebipoed. Suur asi on, kui me juba ei telliks Hiinast põhimõtte pärast asju ja ei läheks kaasa sooduskampaaniatega. Hea oleks ka see, kui me ei jätaks oma riideid kappi seisma. \nSeda kõike saab muuta, aga selleks peavad inimesed oma harjumustest üle saama ja hakkama mõtlema looduse või maa heaolule. Need, kes on targad tarbijad on sellest harjumusest lahti saanud. Need, kes aga ei saa aru peaksid nägema tegelikkust ja hakkama teisiti tarbima. Inimesed ei pea nii palju tarbima, kui nad praegu tarbivad.');
