INSERT INTO core.text(id, content)
VALUES ('37d58b18-7c69-4bde-834b-7ba30d6a3797',
        'Asjade raiskamine on üks osa elust, ostame kord liiga palju midagi, viskame ära või anname ära. Eks neil igal omad plussid ja miinused, aga miks me lubame endal asju raisata?\nToit, seda on lihtne raisata, läheb hallitama või lihtsalt ei maitse see mida sa ostsid, see muidugi pole hea vabandus, miks oma ostetud toitu, mis sulle kuigi ei maitse, ära visata. Aga kuna meil on nüüd nii palju ressursse, ei pilguta inimesed sellele silmagi, et näha kui kahjulik see tegelt on keskkonnale ja kui see on kahjulik keskkonnale, siis see on ka kahjulik meile.\nRiideid on lihtne osta ja muidugi ka taaskasutada. Probleemiks on see, et inimesed ostavad nii palju ebavajalikke riideid ja mida rohkem sa ostad, seda rohkem firmad toodavad neid asju juurde. Paljud riidetehased kasutavad lapstööjõudu, nagu näiteks Shein, Temu, Alixpress. Ka H&amp;M on saanud süüdistudi, et nad kasutavad lapstööjõudu. Samas on liigne tööstuste töötamine kahjulik osoonkihile, kuna gaasid, mis tulevad on mitte enam kui mürgised.\nKa vett on lihtne raisata, jätad vee jooksma samal ajal, kui pesed hambaid või muud midagi sellist. Me arvame, et magedat vett on lõpmatuseni, aga tegelikult on tervel maakeral kuskil 3% magedat vett. Juba paljud riigid ei saa endale enam lubada puhast kraanist tulevat joogivett, ning on ka riike, kes ei saa endale lubada üldse mingit puhast joogivett.\nMe lubame endal raisata, kuna arvame, et kõik ressursid on lõpmatuseni meile kasutada. Me võtame asju oma heaks ja ei mõtle tulevikule.');
