INSERT INTO core.text(id, content)
VALUES ('589bd9a0-2ae0-4d6a-b67d-1218188ac7ee',
        'Maailmas toodetakse ja  tarbitakse tuhandeid, kui mitte miljoneid toiduesemeid igapäevaselt. Sama käib ka riideesemete kohta, mis tänu kiirmoe populaarsuse tõttu visatakse igapäevaselt minema. Kuigi toiduraiskamisele on viimasel ajal rohkem tähelepanu pööratud on kiirmoodi praktiliselt ignoreeritud.\nPaljud arvavad, et paari hallitama läinud saiakoti või paari halvaks läinud vorstipaki äraviskamise pärast ei ole nad osa probleemist. Kuigi tundub, et natuke äravisates ei tee sa üldse kahju keskonnale, ei ole see täiesti tõsi. Tõsi, sa ei ole nii raiskav kui need kes palju toitu ära viskavad, kuid kui miljardid inimesed natuke toitu ära viskavad kogunevad jääkmed ikka kokku ja toidukadu on suur. Samuti viskavad osad ära toitu mida ostsid, kuid enam ei soovi, mis on sobimatu ja raiskav. Toidukadu ei saa vähendada üleöö, kuid sellega tuleks hakata tegelema varem kui hiljem.\nSamuti on üks suur probleem viimasel ajal populaarsust koguv kiirmood. Kiirmood on sisuliselt riided, mis on loodud vaid lühikeseks ajaks kandimseks ja siis ära viskamiseks – mis on probleem, kuna enamikke nendest riietest ei ola võimalik taaskasutada nende materjalide pärast. Tavaliselt suudab kiirmood inimesed enda poole võita suurte allahindlustega, mis panevad riided odavatena tunduma, kuid kui sa riideid vaid paar korda kanda saad, siis võib see nagunii kallimaks minna.\nKiirmood ja üleliigne toidu tarbimine on tänapäeva ühed suurimad maailma probleemid. Meie saame aidata vähem ja normaalsetes kogustes toitu ostes ja vähem kiirmoe asju tarbides. Loodetavasti suudame tulevikuks enda tarbimisharjumusi muuta ja keskonnale kasulikumad olla.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('589bd9a0-2ae0-4d6a-b67d-1218188ac7ee', 'title', 'Inimeste tarbimisharjumused');
