INSERT INTO core.text(id, content)
VALUES ('e3ce64c9-ed51-47c1-a499-152a7348a704',
        'Eesti pole ainus riik, kus raisatakse toitu, on ka palju teisi riike, aga näiteks: Aafrika riikides võetakse toitu nagu maailmaime. Nemad austavad  toitu, kuid me viskame need ära. Aga miks? \nVõtame näiteks Eesti inimesed, nemad viskavad ära toitu, näiteks kui läheb midagi halvaks, ei taha rohkem süüa seda või ei maitse see. See on Eesti riigile väga suur probleem, peale toidule, mida me ära viskame, viskame me veel ära looduslikke ressursse, näiteks: vett, maad, energiat ja tööjõudu. Peale selle veel viskame me ära ka oma raha, mida inimesed ei tea kui palju tegelikult nad ära viskavad. Inimesed ei arva sellest midagi, aga kui inimesed saaksid teada kui palju nad raha raiskavad, et lõppus ära viskavad, siis nad mõtleksid teisiti, aga on ka inimesi kes viskabki niisama toitu ära. Toidu tootmine on väga suur koormus, sest toidu kasvatamisel kasutatakse väga palju väetisi ja kemikaale, peale kasvatamise tapetakse ka väga suures koguses loomi, näiteks: kana (et saada kanaliha), lehmad (et saada veise liha), sigu (et saada sealiha) ja palju muid loomi.\nMinu arust kuidas sellist asja parandada, peavad inimesed aru saama mida nad selle toidu ära viskamisega teevad ja kui nad saaksidki aru mida nad teevad, peaksid nad annetama seda toitu mida nad ei taha enam vaestematele peredele, aga se ei juhtu üleöö, aga lähistulevikus oleks see suur samm meie toidu kaosele.');
