INSERT INTO core.text(id, content)
VALUES ('801dc72b-3f8e-4845-b6e5-d72ffbb499f0',
        'Tänapäeval läheb palju tooteid raisku, on see siis kvaliteedi või liigse ostmise küsimus. Kahjuks toovad paljud sellised jäätmed keskkonnale suurt kahju.\nKeskmise Eesti inimese aastane toidukadu on 26kg, mis on päris suur kogus. Kuid õnnetuseks me ei märka neid väikseid koguseid, mis me igapäevaselt ära viskame, sest võtame seda iseenesestmõistetavana.\nSelline raiskamine toob kaasa ka suure ressursside kao. Selleks, et toota selline toidukogus, mis tundub inimestele normaalsena, kulub meeletu kogus maad, vett, elektrit ja tööjõudu.\nOma tarbimist on siiski ka võimalik vähendada, vältides impulssoste ning eelistades kohalikke tooteid. Samuti one hea mõte osta allahinnatud toidukaupa, mis sageli muidu ära visatakse. Veel üks hea nipp on eelnevast toidust teha midagi uut teha, näiteks kui eile sai tehtud praekartuleid, võib täna teha kartuliputru.\nKa riiete tarbimisel tekib palju jäätmeid. Suurem osa hetkel müüdavatest riietest keskendub pigem kvantiteedile kui kvaliteedile. Odavam on kasutada tehislikke tooraineid, mis teevad keskkonnale suurt kahju.\nPaljud kiirmoe riided sisaldavad aineid, mis on inimesele äärmiselt kahjulikud, kuid sellele ei pöörata tihti tähelepanu, sest selline tootmisviis on odavam, ja/või ei ole tootmispiirkonnas nii rangeid tootmisreegleid kui mujal. Selliseid riideid müüakse tihti väga odavalt, innustades inimesi ostma. On ka palju muid taktikaid, näiteks redigeeritakse reklaamfotosid nii, et need näeksid välja paremad kui toode ise.\nHalva kvaliteedi tõttu ei meeldi inimestele selliseid riideid kanda ning need jõuavad tihti peale vaid ühte kandimiskorda taaskasutusse. Selline raiskamine ei too kasu ei inimsetele ega loodusele.\nRiiete tootmine on üks saastavamaid tööstusharusid maailmas, millest on hea näide Citarumi jõgi Indoneesias, mis on hetkel maailma saastatuim jõgi. Sealsed inimesed kannatavad paljude haiguste ja mürgistuste käes, mida põhjustanud aineid pole kõiki kindlaks tehtud.\nKokkuvõtteks, peame vähendama oma tootmist ja tarbimist, sest praegune ressursside kadu mõjutab nii meid kui ka meie planeeti äärmiselt negatiivselt. Kui nii edasi läheb, ei pruugi inimkond näha järgmist sajandit.');
