INSERT INTO core.text(id, content)
VALUES ('5e4da2f2-1ab7-42e5-8894-c20848779021',
        'Täna päeva maailmas toodetakse liialt toitu ja inimesed ostavad palju toitu mille järel ei jõuata kõike toitu ära süüa või ära kasutada mingil viisil, raisates raha, maad, vett, energiat ja tööjõudu. toidu tootmisega tekitatakse palju keskonnakoormusi, et saada ja toota paremat ja rohken saaki mille tõttu kasutatakse palju erinevaid kemikaale ja väetiseid. Iga Eesti kodumajapidamises tekib ühe inimese kohta aastas umbes 61 kg toidujäätmeid. Toitu visatakse välja kõige rohkem, sest toit onvanaks läinud või seda ei kasutata.\nInimeaed arvavad et toit ei saa otsa ja et naad eimõjuta midagikui nad viskavad välja ainult väikese osa toidust aga see on ikka toidu raiskamine ja välja viskamine. Need kes saavad seda endale üle liikset toitu lubada raiskavad rohkem, sest ostavad rohkem kui arvavad et suudavad ära tarbida. \nEt toidu raiskamist välyida saaksid inimesed osta nii palju kui suudavad päriselt ära süüa ja sellega midagi teha mitte seda toitu ära visata. Võib poesr vähem osta ja ainult võtta missa tead et sa ära sõõd ja ei lähe raisku, kui sellest ei piisa siis võib pärast alati uuesti poodi minna ja osta juurde ainult seda mis on vaja.\nKokkuvõtte on et kõik saaksid vähem toitu osta või kõik toidu ära tarbida või saaks proovida vähem raisata ja ära visata.');
