INSERT INTO core.text(id, content)
VALUES ('0e5d58c7-6fec-4982-ab36-37725c9bf7e6',
        'Inimesed raiskavad tohutult palju toitu ja riideid. Kuna see aga toimub natukehaaval, siis ei ole selle mõju kohe märgatav. Kui aga vaadata suures perspektiivis, siis on toidu ja riiete raiskamine üsnagi suur probleem. Kuidas saab igaüks aidata kaasa selle raiskamise vähendamisele?\nInimesed ostavad palju toitu, ei suuda seda ära tarvitada ja seetõttu läheb toit riknema ning see visatakse minema. Näiteks, mõni inimene ostab külmkapi toidukraami täis, kuid ei suuda seda ära tarbida ning lõpuks ei jää lihtsalt muud üle, kui see ära visata. Seda saaks parandada kui inimesed ostaksid endale korraga vähem toitu kokku ning kui see otsa saab, siis saab uuesti väiksema koguse poest juurde osta. Muidugi on erandeid, näiteks inimesed, kes elavad tihedamast asustusest kaugemal ja kellel lihtsalt ei ole võimalust mitu korda nädalas poes käia. Küll aga inimesed, kes saavad tihedamini poest käia, võiksid kindlasti mõelda vähem korraga ostmise peale.\nTeine probleem on odavate ja madala kvaliteediga riideesemete ostmine. Neid ostetakse palju kokku, kantkse ja pestakse mõned korrad, ning siis on need juba enda ilme kaotanud ning ei sobi enam kanda. Kui aga inimesed ostaksid kõrgema kvaliteediga riideid, mis kannatavad rohkem pesukordi, siis ei tekiks jõhkrates kogustes odavate ja ilmetute riiete jääke, millest tuleb kuidagi vabaneda. Kvaliteetsed riided püsivad ilusa ja korralikuna lausa aastaid võrreldes riietega, mis tulevad masstoodanguna Hiinast.\nKui inimesed ostaksid korraga vähem toitu ja madala kvaliteediga riideid, oleks väga palju vähem jääke, mis nendest tekivad ja millest tuleb kuidagi lahti saada. See oleks väga kasulik meie loodusele ja ka kogu planeedile ning ökosüsteemile. Esialgu võib tunduda, et see ei muuda midagi, aga mõeldes kui palju see võib muuta aastate jooksul, siis tasub säästlikum elamine ennast kindlasti ära.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('0e5d58c7-6fec-4982-ab36-37725c9bf7e6', 'title', 'Kuidas vähenda raiskamist?');
