INSERT INTO core.text(id, content)
VALUES ('a525b62c-55e7-481f-96ec-0a575d0b134b',
        'Tarbimist on tänapäeval päris palju ja see on kujunenud juba päris suureks probleemiks. Tarbitakse liiga palju toitaineid, millest suur osa ära visatakse ning tarbitakse ka liiga palju mõnuaineid.\nInimesed, kellel on rohkem raha kui kesmisel eestlasel, ostavad koju liiga palju toitu ning suur osa sellest visatakse ära ja toit läheb raisku. Tarbijatel on tunne, et toit ei saa otsa, aga selle asemel, et see ära vista võiks söögi ju anda neile, kellel pole võimalik endale süüa osta. Kui võrdlen ennast J.D Sallingeri teose „Kuristik rukkis“ peategelase Holdeniga, siis näen, et mina tarbin palju rohkem toitu kui tema. Mina tubakatooteid ja alkoholi ei tarbi, aga Holden kasutas neid mõnuaineid igapäevaselt.\nMõnuainete tarbimine tänapäeva ühiskonnas on kujunenud ka päris suureks probleemiks. Kui kõndida ringi ja jälgida inimesi, siis näeb iga viie minuti tagant kedagi, kes tarbib mõnda mõnuainet. Mõnuained on ka lastele väga kergelt kätte saadavad ja selle tagajärjel on ka tarbijaskond palju suurem. Alkoholi ja tubakatoodete tootmine nõuab palju resurssi ja selle tagajärjel toimub ka mingit moodi planeedi reostumine. Inimesed viskavad ka maha suitsu pakke ja alkoholi pudeleid, mis ei ole keskonaale sugugi head.\nTänapäeval on tarbimist liiga palju ja selle tagajärjel läheb raisku väga palju toitu. Tarbimise tagajärjel reostub ka maakera ning tarbimist tuleks kindlasti vähendada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('a525b62c-55e7-481f-96ec-0a575d0b134b', 'title', 'Inimeste tarbimisharjumused');
