INSERT INTO core.text(id, content)
VALUES ('eb862d2a-02b7-41da-a471-96a85fb0adda',
        'Meie peamised halvad tarbimisharjumused on toidu liigne raiskamine ja kiirmoe üleküllus.Inimestele ei ole see veel probleemiks, sest enamik inimestele ei ole see silmnähtav, kui palju kahju see tekitab. Kuidas seda vähendada?\nToidu liigne riaskamine on probleemiks inimeste igapäevaelus. Enamik inimesetele jääb see märkamata, aga see ei tähenda, et see probleeme ei tekitaks. Raiskamise hulk on väga suur, nagu on tekstis öeldud tekib iga aasta ühe Esti inimese kohta 61kg toidujäätmeid, millest toidukadu on 42% ehk 26kg. Toitu raiskavad peamiselt inimesed kes seda endale lubada saavad. Samal ajal,kui meie raiskame suure hulga toitu kannatavad paljud inimesed toidu puuduses.\nSuureks probleemiks on ka kiirmoe üleküllus. Inimsed ostvad rohkem kaupa, kui neil seda tegelikult vaja on. Suurt ostu huvi tekitab ka võimalus odavamalt kaupa tellida erinevatest Hiina e-poodidest. Inimesed soetavad sealt pigem odavamalt riideid, kui ostvad meie oma toodangut. Uusi riideid võiks nt. soetada hoopis teise ringi kauplustest ja enne uute ostmist vanad anda inimestele kes seda vajavad. \nErinevate odavamate kiirmoeprändide kvaliteet on ka kindlasti halvem kui meie oma kohaliku toodangu oma. Kindlasti tuleks eelistada head kvaliteeti sest ka see aitab tarbimist vähendada. Kui ostad ühe kvaliteetse toote saad sa seda kindlasti kauem kanda/kasutada kui odavamat toodet. Tihtipeale on ka odavamate toodete valmistamisel kasutatud nt. naftat mis ei ole meie nahale üldse hea.\nSeda suurt kadu ja üleküllust on võimalik vähendad. Toitu tuleks osta täpselt nii palju,kui suudetakse ära tarbida,et vältida selle riknemist. Mitte soetada ebavajalike tooteid.Mõelda võimalusele soetada tooted teise ringi kauplustest. Võimalusi on palju ja kindlasti leiab iga inimene endale sobiva.');
