INSERT INTO core.text(id, content)
VALUES ('05cbcfa6-ac01-4238-b417-ffa6a65b7158',
        'Tihti peale paljud inimesed viskavad oma toidu ära. Sellepärast, et see on halvaks läinud, või nad enam ei tarbi seda. Sellega kaasneb tohutult suur arv toidujäätmeid. Kuigi mina ei arva, et see on kõik alati meelega.\nPaljud inimesed isegi ei märka, et see mis nad teevad on kuidagi vale. Või nad arvavad, et sellel pole suurt mõju kui nemad seda teevad. „On inimesi, kes raiskavad toitu, sest nad saavad seda endale lubada.“ Need inimesed raiskavad seda toitu, sest nendel on nii lihtne lihtsalt see toiduaine uuesti osta. Nad on sellega harjunud.\n„Toidu raiskamist ei saa vähendada üleöö.“ Sellepärast, et meil inimestel on raske harjumustest loobuda. Ja mõndadel ei tule pähe isegi, kui palju ja kas nad seda üldse teevad. Eriti ka veel noored, kes ei pruugi sellest kõigest veel teadlikud olla. Kuigi nad isegi võiksid ja peaksid olema.\n Kõikides vanustes inimesed võiksid üle vaadata oma tarbimisharjumused. Praegusel ajal tellivad peaaegu igas vanuse klassis inimesed endale Hiinast asju. Põhiliselt sellepärast, et nad on palju sootsamad. Kuigi võiks tegelikult osta kodumaiseid asju.\nSee ei tähenda, et peaks hullult palju asju ka ostma. Ainult asju mida päriselt vaja on. Taaskasutuspoodidega on oht, et sealt võib leida paljusi riideid, mis on pärit Hiinast. Sellega peaks ettevaatlik olema.\nInimesed teevad asju kiiresti. Paljudele ei tule pähe, et midagi on valesti. Peaksime proovima muuta oma harjumisi ja tarbima vähem.');
