INSERT INTO core.text(id, content)
VALUES ('32a3c5fb-139e-4957-b9cf-04589a6bd48f',
        'Paljud inimesed Eestis lihtsalt viskavad minema toitu, riideid ja nii edasi. Millega koosneb ressursside kaudus, nagu näiteks Eesti inimene keskmiselt raiskab 61 kg toitu aastas, millest toidukadu  moodustab 42% ehk 26 kg.\nNende numbritega saaks paljud ilma toituda inimesed süüa aga see kõik toit lihtsalt visatakse välja. Korralikkud riided ja toitud visatakse uksest välja. Paljud lapsed võiksid minna kohtuma taaskasutuspoodide lattu, et näidata, milline raiskamine tegelikult toimub seal.Inimesed ostavad mingeid Hiina asju temust, sheinist ja seal on veel paljusid aga Eestlane tahab ikka ju soodususes asju mitte mingeid 100€ asju vaid 1€-10€ aitab neile küll.\nEelistatakse rohkem kvantiteedile kuid kvaliteetile rohkem selle pärast ostetakse rohekm soodsaid asju mitte mis maksab palju lihtne viis et lihtsalt raha säästa aga paljud näevad ka seda, et see on halb aga ikka ostavad selle pärast, et see kõik on nii soodne nagu 1€ termo pukste eest mõned vaatavad ja ütlevad ‘’ohoo vot ma nägin selliseid eile kaupluses 60€ eest aga siin ma saan selle ju 1€ miks ma peaks sealt ostma ju.’’ selle kvaliteed on halb aga soodne ning inimesed lähevad sellele üle, et mitte raha raisada.\nÜldvaates mõned lihtsalt kannavad paari riietust mida nad on ostnud endale ja siis viskavad selle ära, sest neile see lihtsalt ei meeldinud. Ning paljud toitud mida saaks teistel inimestele anda saaks ju ära anda kellel pole süüa nagu mõnedel.\nRahad lähevad raisku toit ja veel mõttetu rämpsu peale nagu mitte kvaliteetsed riided Hiinast. Aga see tarbe raiskamine on väga suur ja seda peaks õppedama uule generatsionile rohkem, et nad ikka ei raiskaks ja ostaks mõttetuid asju internetist.');
