INSERT INTO core.text(id, content)
VALUES ('8d50d981-a9bc-4ae4-a99e-abae1e4ee8b7',
        '\nToitu raisatakse maailmas igapäevaselt. Visatakse ära asju, mida inimene enam oma elus ei kasuta. Olemas on erinevaid taaskasutuspoode. Tänavatel leidub ka toidukappe ja riidekonteinereid, mida on võimalik kõigil kasutada.\nSuurema osa toidu raiskamise põhjuseks on toidupakendil olev kasutustähtaeg, mis on ületanud kindla tähtaja. Tegelikult, mida inimesed ei tea on see, et kui pakendil olev tähtaeg on möödunud aga pakend ei ole veel avatud, siis on see toit mõni päev ikka veel söödav. \nInimesed tellivad omale tegelikult ebavajalikke asju, kuid nad ise seda ei arva. Vaadatakse hinda, mis on väga odav ja tekib pähe mõte, et ese on väga vajalik. Näiteks, tellitakse asju Temust või Sheinist, kus on hinnad kõik väga soodsad. Tänu sellele hakkab kogunema koju kraami, mis hiljem kõik ära visatakse. Asjad, mis on veel kasutusvõimelised, võiksid jõuda taaskasutuspoodidesse, kus ese leiab omale uue omaniku.\nPaljud ei tea, et toidukapid eksisteerivad, sest need asuvad ainult teatud piirkondades ja keegi ei viitsiks minna kodust kaugele, et oma järele jäänud toitu ära viia, siis visataksegi kõik minema. Riidekonteinereid kasutatase juhul, kui on kodus riideid, mis on jäänud väikseks või lihtsalt riideid, mida enam ei kanta. Mina annan kõik oma väikseks jäänud riided oma nooremale sugulasele, et mitte neid ära visata.\nAlati tuleks oma asjad, mis ei leia enam kasutust, viia kellegile, kes neid kasutab või taaskasutuspoodidesse. Alati enne mõne asja tellimist, tuleks läbi mõelda milleks seda vaja on.');
