INSERT INTO core.text(id, content)
VALUES ('c5cdcbd5-3431-4b40-bace-a46c4a4c32e6',
        'Olemas on palju mehi kui ka naisi kelle harjumuseks on käia igakuu riidepoes ning ka tavapoes et endale midagi osta eriti kui on sooduspakkumised samuti ka internetist tellides igasugust mõtetuid asju mida tegelikult meil vaja ei lähe kuid see on tore ja lõbus kui endale midagi lubada saab, aga kas seda kõike jama on vaja endale ikkagi osta?\nMaailmas on olemas inimesi kes lähevad alati soodupakkumistega kaasa riidepoes,tavapoes ning ka internetist tellides.Uued riided mis lähevad vanade riiete asemel kappi on raiskamine kuna need vanad riided olid ka kunagi uued kuid nüüd lähevad need prügimäele, aga on olemas ka inimesi kes viivad need hooopis riidekondeinerisse mis on palju parem.\nKuid on ka selline pood nagu näiteks kasutatud rõivad mida kutsutakse kaltsukaks kus on riided mis on kasutatud aga täiesti korralikud ja terved tavaliselt käivad seal inimesed kelle jaoks ei ole tähtis palju mingi ese või asi maksab vaid milline see välja näeb ja, et raha säästa. Muidugi ka Hiinast tellides tuleb odavam kui tavapoes, aga alati on nii kui näiteks lappad telefonis Sheini või Temu lehte mis on Hiina tooted siis tulevad ka ette mõningad muud mõtetud asjad mida mul tegelikult vaja ei ole, aga hirmsalt tahaks, et äkki ikka on vaja.\nSee on täiesti normaalne kui me tahame nedale paljusid asju lubada, aga kuskil on ikka ostmis piir, et kõike jama kokku ei ostaks. Mina ise samuti ostan endale igakuu internetist, aga üritan mitte ebavajalike asju osta tuleb lihtsalt alati läbi vaadata kas mul on ikka seda kõike vaja.');
