INSERT INTO core.text(id, content)
VALUES ('3b8aa088-41c4-48a8-a317-38a525ae10ff',
        'Raiskamine on meile kõigile juba praegu ja ka tulevikuks väga suur probleem. Inimesed söövad, ei jaksa enam ja tihtipeale viskavad toidu ära. Ostavad riideid, ei meeldi enam ja viskavad ära. Nii on iga järgmisegi võimaliku asjaga.\nMe kõik käime poes. Tihtilugu ostame seda, mida ise tahame. Kuid enamik inimesi ei mõtle, kas seda on päriselt vaja või mitte. Mul tuleb tunne, lähen poodi ja ostan suure kotitäie riideid, lihtsalt sellepärast, et mul on selline tuju. Seesuguseid poes käike nimetatakse emotsiooniostudeks.\nSelles ei ole midagi halba, kui aeg-ajalt poodi minna ja endale üks ilus pluus osta. Mine tea, äkki ongi meeldiv materjal ja väga mugav. Kuid ka sellega tuleb piiri pidada. Kõik mõtlevad pärast poes käiku, et „Ah vahet ei ole, viin kuhugi kaltsukasse või annan kellelegi, kui ise ei kanna.“\nEve Hanson andis Vikerhommikule intervjuud, kus ta tõi välja, et noortele võiks teha ekskursioone taaskasutuspoodide lattu, et näidata, milline raiskamine seal tegelikult käib. See haakub täpselt meie probleemiga. Taaskasutuspoodides on muidugi ka korralikke riideid, aga väga palju on ka sellist kraami, mis on odavast materjalist, halva kvaliteediga ja keegi ei taha neid kanda.\nKõige selle parandamiseks soovitaksin inimestel vaadata esialgu kodust üle kõik oma asjad enne, kui minna uusi ostma. Mõelda, kas mul on seda ikka vaja ja siis teha oma järeldus. Lõppude lõpuks teeme me oma halbade harjumustega iseendale kõige rohkem kahju.');
