INSERT INTO core.text(id, content)
VALUES ('172d29ad-f8a6-440b-9a8b-f517a8009841',
        'Miks inimesed raiskavad niivõrd palju toitu ja muid asju? Kas inimeste tarbimisharjumusi saab üleöö muuta? Toidu ja riiete raiskamine on probleem kogu Eestis ja kogu maailmas.\nPaljud inimesed ostavad poest korraga näiteks nädala toiduvaru, kuid siis ei suuda seda nädalaga ära süüa. Seetõttu ongi toidu ära viskamis protsent nii suur, koguni 42% aastas inimese kohta. Ma arvan, et ei ole mõtet nädala toiduvaru kokku osta, kui mingi osa sellest läheb halvaks ja see tuleb ära visata. \nInimeste tarbimisharjumused on üsna erinevad. Mõni inimene nähes Facebookis või kuskil mujal mingit reklaami näiteks nõudest, peab ta need kohe ostma, aga teine inimene hakkab mõtlema, kas tal on neid vaja, miks tal on neid vaja ja kui palju ta neid kasutab. Siinkohal ongi inimeste harjumused erinevad ja neid harjumusi ei saa üleöö muuta. \nOsad inimesed tellivad omale Hiinast odavaid riideid, mis on tehtud naftast. Nende riiete kandmine võib põhjustada nahal ärritusi. Pärast paari kandmist viivad nad selle taaskasutuspoodi ja hiljem tellivad Hiinast uue samasuguse särgi ja see protsess kordub mitu korda enne kui neile jõuab kohale, et odavam oleks osta mõni puuvillast särk, mis on veidi kallim, kuid kestab kauem ja ei põhjusta nahal ärritusi.\nInimesed peaksid enne natuke mõtlema, kui nad midagi ostavad, siis saaksime ka toidu ja riiete raiskamist vähendada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('172d29ad-f8a6-440b-9a8b-f517a8009841', 'title', 'Inimeste tarbimisharjumused');
