INSERT INTO core.text(id, content)
VALUES ('fa20eaf6-39d7-44ad-841c-9de3cfd1cff8',
        'Toidu raiskamine on väga suur probleem Eestis ja see kehtib pea igas kodumajapidamises. Sellega kaasnevad kulutused võivad olla suured ja ressursside raiskamine on jõhker.\nToidu raiskamine ei ole mingi naljaasi. Paljud inimesed kes võimaldavad seda tegu teostada on suures osas ebameeldivad inimesed kes ei hooli teistest inimestest. Pea igas kodumajapidamises iga inimene raiskab aastaga keskmiselt 61 kg toidujäätmeid.\nTänapäeval toidu hinnad kasvavad, Inflatsioon tõuseb. See paneb suurema osa inimesi raha peale mõtlema, et kui palju poes raisata raha toidu peale. See toob kaasa ka toidu vähese raiskamise, kuid igal heal asjal on ka miinuseid. Inimesed ostavad vähem süüa, see tähendab neil on vähem raha ehk elutingimused inimestel halvenevad.\nToit ei ilmu poodidesse imeväel, vaid selle toidu peale näevad paljud inimesed vaeva üle kogu maailma, et see toit jõuaks inimeste toidulauale. Selle toidu valmistamiseks kulub palju aega, maad, vett ja tööjõudu. Sellega teenivad paljud teised inimesed raha, et ka nemad saaksid süüa osta. Kuid kui toitu raisata, läheb see terve vaev raisku.\nInimesed peaksin enne poodi minekut välja mõtlema mida nad sealt tahavad ja ostma toitu mõistetavas koguses, et enda raha ja teistega arvestada ja anda endast maailmale parema mulje. Toit ei ole maailmas tasuta ja igavene, sellega tuleb arvestada ja jagada, et kõik inimesed saaksid midagi.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('fa20eaf6-39d7-44ad-841c-9de3cfd1cff8', 'title', 'Toidu raiskamine');
