INSERT INTO core.text(id, content)
VALUES ('e022f679-07b2-4bee-88c4-4e844c0d17a7',
        'Toitu raisatakse maailmas rohkem,kui inimesed seda ise ette kujutavad. Sööki peame austama ja sellest tuleb alati lugu pidada. Ärme viska toitu ära,vaid anname selle teistele abivajavatele inimestele edasi .\nToidu raiskamine on tulnud maailmast vägagi suureks probleemiks.Selle asemel,et toitu ära visata,võiksime selle alati anda inimestele kellel ei lähe hetkel oma elus mingil põhjusel hästi ja nad ei saa endale iga päev korralikku toitu lubada,kuna neil lihtsalt ei ole raha selleks.Nende inimeste all mõtlen ma nt: kodutuid,lastekodu lapsi jms. Samasugune olukord on ka muude esemetega, nimelt mänguasjade ja riietega.Miks visata asju ära,kui neid saab viia abivajavatele inimestele?\nPaljudel inimestel ongi kombeks ja harjumuseks see,et kui neil endal on kõht täis ütlevad nad „Mina rohkem süüa ei taha“ ning seejärel viskavad toidu lihtsalt ära. Kuid kas keegi on kunagi mõelnud sellele,et kuskil maailmas on inimene kes oleks väga õnnelik ja tänulik,et neile toitu või muid eluks vajalikke asju viiakse? Need inimesed kes seda ei tee,on enamasti need,kes on ennast nii täis või need kes on nii hea elu peal,et see lihtsalt ei puutu neisse mis teistest saab.Selleks ongi ju tehtu siia ilma kõiksugused toidukassad ja kohad kus saab riideid viia,või siis internet kuhu saab postitada ning küsida,et kas kellegil oleks riideid vaja?See on kõik taaskasutus.\nIgal inimesel oleks parem elu, kui alati oleks olemas keegi,kes sind saab aidata ja toetada kui endal läheb elu allapoole.Kõigil oleks endal ka palju parem ja soojem tunne kui me aitame või kui me saame teistelt abi.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('e022f679-07b2-4bee-88c4-4e844c0d17a7', 'title', 'Toidu raiskamine ja selle jagamine');
