INSERT INTO core.text(id, content)
VALUES ('d9ff4bfd-2b12-40af-8b15-90845848162f',
        'Miks on toidukaos nii suur ja miks me seda tähele ei pane? Ma arvan, et see on nii suur ja me ei pane seda tähele, kuna see ei tundu tähtis olevat.\nÜks viisidest kuidas toitu raisata on selle ära viskamine. Vahel ma tõstan endale liiga palju toitu ja ei jaksa seda kõike ära süüa. Paljud annavad oma koertele alles jäänud toidu, aga mul koera ei ole, nii et ma viskan alles jäänud ära. Väikestel lastel söövad tihti vanemad alles jäänud toidu ära, kui seal sees pole laps palju sonkinud.\nMa olen ka näinud toidu raiskamist siis, kui keegi katsetab midagi uut süüa teha või proovida, aga see ei tule maitsev välja ja visatakse pärast ära. Reklaamis või pildil võib jääda arvamus, et see eine on jube hea ja tervislik, aga tegelt maitseb väga halvasti ja ei ole tervislik.\nMinu pere raiskab toitu kõige rohkem, kui mingi asi jääb seisma. Seda on eriti kartulisalatiga. Mina ega mu õde ei söö seda, kuna selle tekstuur ei meeldi meile. Mu kasuisa peab selle kõige üksinda ära sööma või viskama alles jäänud, kuna mitte keegi ei jaksa kartulisalatit poolteist nädalat süüa.\nSellepärast arvan mina, et toidukaos on nii suur, kuna sellest ei tee tavainimene välja, kui ta toitu ära viskab.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('d9ff4bfd-2b12-40af-8b15-90845848162f', 'title', 'Toidukaos');
