INSERT INTO core.text(id, content)
VALUES ('0b8d2f57-174a-4055-a24c-b5dbe09bcb49',
        'Paljud neist viskavad toidujäägid ära, aga meie mitte riknenud sööme kiiresti ära enne, kui kuupäev kätte jõuab.\nInimesed viskavad liiga tihti toidujääke ära ega ei söö seda lõpuni, toiduraiskamine ei ole väga viisakas ja see viitab toiduraiskamisele. Täiskasvanud ja lapsed on pidanud selle peale raha kulutama. Kui toit on riknenud või kuupäeva ületanud siis võib toidu ära visata.\nKuid osa minu peres söövad kõik liikmed toidu lõpuni ega ei viska kohe esimest pärast ampsu toitu ära. Kui mina vahepeal ei jaksa enda toitu ära süüa, siis ma ei viska kohe prügikasti vaid panen toidupotti tagasi või siis külmkappi, ning kui minul jälle söögi isu tuleb siis ma soendan ära ja söön edasi. Minu teiste pereliikemetel on teised meetotid kuidas nemad enda toiduga askeldavad. \nKui teised inimesed ei raatsi oma toitu äragi süüa, siis nad viskavad kohe toidujäägid ära. Meie ei viska kohe toite minema isegi kui me ei jaksa ära süüa siis me ikkagi sööme kas lõpuni või paneme külmkappi ja hiljem võiks edasi süüa, et saada kõhtu korralikult täis.');
INSERT INTO core.text_property(text_id, property_name, property_value)
