INSERT INTO core.text(id, content)
VALUES ('cb9982ab-49a6-447d-a432-8021c5398598',
        'Kuidas inimesed raiskavad toitu ja raha riiete peale mida paar korda kantakse. Millega saaks neid harjumusi parandada?\nPaljud pered ostavad suurtes kogustes endale paaari nädalase või kuu toiduvarud. Kui osta suurtes kogustes võib alati midagi raisku minna kuna ostetakse rohkem kui tarbitakse. Inimesed käivad poes ostavad suurtes kogustes kuna siis nad ei pea iga kord kui neil midagi vaja on jälle poodi minema. Sellega tulebki see, et inimesed võtavad mõnikord asju mida nad lõpuks ei tarbi ja siis see läheb raisku.\nToit, aga pole ka ainus asi mis raisku võib minna. Riided sama moodi võivad raisku minna kui ostetakse ja kantakse paar korda ja siis jääb kuhugi kappi põhja seisma. Kui niimooodi kasutada riideid siis see on lihtsalt raha raiskamine. Selle asemel, et raisata riietele mida inimesed kannavad paar korda võiks jätta need ostmata ja kasutada seda mis juba olemas on või kasutada seda raha mõnel muul eesmärgil.\nNeid harjumusi saaks parandada kui hakkata mõtlema kas seda on mul ikka vaja milleks ma seda kasutaksin ja millal mul seda vaja läheks. kui neid küsimusi inimesed hakkaksid endalt küsima siis see säästaks nende raha. Tuleb lihtsalt rahaga ümber käia targalt.\nSellele mõeldes tuleb saada aru oma valikute põhimõtetest ja mõelda järele kas on ikka vaja seda. Iga inimene teeb lõpuks ise oma valikuid olgu need head või halvad.');
