INSERT INTO core.text(id, content)
VALUES ('296f66af-4f37-41b8-bcdb-01a806dcd300',
        'Seda kahte teksti lugedes, sain ma ise aru sellest kui palju toitu raisatakse. Nüüd kui mõelda siis saaks selle toidu annetada neile kellel pole kui mitte midagi, nad oleksid kindlasti väga õnnelikud selle üle. Seepärast, et see meie jaoks prügi on ei tähenda see seda, et see teiste jaoks varandus pole. \nEestlased võiksid nendest kahest probleemi tekitajatest aru saada: Toidu raiskamine ja Hiina veebipoed. Kui nüüd mõelda nende protsentide peale siis mõelge kui palju inimesi saaks sellest söönuks. Mõnikord jah tõesti läheb halvaks, kuid see mis on täiesti söömiskõlblik selle võiks siiski edasi annetada.\nRäägime nüüd ka moeasjadest, me kõik oleme kindlasti Hiina veebipoodidest asju tellinud. Tavaliselt sellistest kohtadest tellivad kas tiinekad või lapsevanemad. Lapsevanemad see tõttu kuna lapsevanemad viibivad tihtipeale Facebook- is, seal tehakse sellistele kohtadele nagu Shein ja Temu tõsiselt palju reklaami. Reklaam muidu iseenesest müüb väga hästi kuid, need ei ole usaldusväärsed veebisaidid. \nMõtleme siin kõik sellele kuidas Eesti oleks parem. Saime selgeks selle, et kindlasti peaks toidu ära viskamist vähendama, kuna see ei ole hea meile ja loodusele. Iga Eesti inimene võiks sellest arusaada. Selle toiduga ju saaks täiesti miskit muud teha vii näiteks toidupanka või vii otse kellelegi kes vajab seda. Riietega on täpselt samamoodi, kui sulle sulle ei meeldi mõni riideese siis ära viska seda ära vaid vii uuskasutuskeskusesse. Seal sa saad oma riietest lähti ja võid isegi väike kopika teenida selle pealt.');
