INSERT INTO core.text(id, content)
VALUES ('cbdfc33b-111d-4062-ba39-f85a3c49ac28',
        'Inimeste tarbimisharjumuste alla läheb kõik, mida me tarbime või kanname. Inimeste tarbimisharjumuse näit on halb, sest me inimsesed raiskame kõike väga palju, mida meil tegelikult vaja ei lähe. \nInimesed tarbivad, raiskavad ja kasutavad asju nii palju, et me ise ei saagi aru, kui palju me tegelikult raiskame. Kindlasti ei ole vaja inimestel süüa ja kanda nii peeneid rõivaid, mis tavaliselt maksavad väga palju. Selle raha kulutamise ja raiskamise asemel võiksime toetada teisi inimesi, kellel tegelikult ka on abi ja tuge vaja. \nInimesed raiskavad just toiduga kõige rohkem, sest tavaliselt ostetakse suur kogus toiduained koju ja kui keegi ei jõua seda ära süüa, siis ikka läheb söök vanaks ja siis visatakse roiskunud toiduained kõik minema. Toiduga ei raiska me ainult enda raha, vaid ka muid ressursse: vett, maad, energiat ja palju veel.\nInimesed veel raiskavad väga palju ka riietega, kuid paljud inimesed taaskasutavad riideid. Müüvad maha, annavad lihtsalt ara kellelegi. See on palju parem viis kui riideid põletada või lihtsalt ära visata. Paljud kuulsused kannavad riideid ainult ühe korra ja viskavad hiljem minema, teised kuulsused aga müüvad maha või annavad lihtsalt ära, mis on palju normaalsem tegu, kui ära viskamine. Ka riietega ei kuluta me ainult enda raha.\nMina arvan, et tõesti meie tarbimisharjumused on suhteliselt halvad, sest ei piisa ainult ühest inimesest, kes ei raiska, vaid on vaja, et mitte keegi ei raiskaks. Raiskamist ei saa vähendada üle öö ja sellepärast peabki hakkama mõtlema, kuidas elada nii, et me ei teeks keskonnale liiga oma harjumustega. Me ei pea kandma ja ostma üüratu raha eest riideid, mille viskame lõpuks  lihtsalt minema ja sööma peaksime nii, et järgi ei jääks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('cbdfc33b-111d-4062-ba39-f85a3c49ac28', 'title', 'Inimeste taribimisharjumused');
