INSERT INTO core.text(id, content)
VALUES ('6a04ce98-4236-488f-b64e-74edb0fcef21',
        'Üks suurimaid ülemaailmseid probleeme on asjade raiskamine. Aga miks seda tehakse ja kuidas seda saaks vähendada? Esmalt arutame mida raisatakse ja miks. \nMe teame, et inimesed ostavad endale pidevalt asju juurde ja juurde. Ja mida nad  vanade asjadega teevad? Suurem osa viskab vanad asjad lihtsalt prügimäele ja ei kontrolli, et äkki saab neid taaskasutada. Minema visatakse ka asju mis on täielikult töökorras selle pärast, et uuem versjoon sellest asjast osta. Kõige rohkem raisatakse toitu ja riideid.\nAga kuidas on võimalik toitu siis raisata? Inimens sööb ju kogu aeg kuidas ta saab toitu raisata? Lihtne. Inimene ei söö toidust järele jäänud jääke ära ja viskab need minema. Nii kulutatakse ja energiat, mis kulus selle toidu valmistamisele. Ja kui toit on pahaks läind siis visatakse see ka minema aga see võib olla ka täiesti puutumatu toit mis lihtsalt külmkappis istus. Aga kuidas siis toidu raiskamist vähendada? Tuleb osta nii palju kui inimene tarbib. Võib isegi vähem osta. Alati saab minna ja juurde osta. Nii viisi sa ei raiska toitu ja ei lase sellel nii sama külmkappis istuda ja keegi teine saab seda osta. Ja kui sa oled toitu liiga palju ostnud saad sa seda viia toidupanka ja sealt viiaks toitu inimestele kes ei saa seda osta.\nJa siis raisatakse ka riideid. Inimesed tahvad alati hästi välja näha ja teistega sarnane olla. Kogu aeg võib mood muutuda ja kui see juhtub siis jäetakse riided mis olid enne moes mis on korras kuhugi kappi tolmu kogu või lihtsalt visatakse minema. See on räige raiskamine, et lihtsalt uued riided mis ei meeldi ära visata. Aga mida siis teha kui sull on riided mis sulle enam ei meeldi? Esmalt tuleks vaadata kas neid saab taaskasutada ja kui saab siis viia taaskasutus punkti, et nendest uusi riideid teha. Kui nendest midagi uut teha ei saa siis saab need viia poodi kus saa saad need müüki panna, et keegi teine neid saaks ära kasutada või saad need annetada kellelegi kellel pole raha, et uusi riideid osta. Riideid on nii lihtne taaskasutada. Kõik võiksid seda teha. \nKokkuvõtteks saab öelda seda et tarbeasjade raiskamist saab vähendada suures koguses ja seda on lihtne teha. Kõik saaksid seda teha.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('6a04ce98-4236-488f-b64e-74edb0fcef21', 'title',
        'Miks raisatakse erinevaid tarbeasjasid ja kuidas seda vähendada?');
INSERT INTO core.text_property(text_id, property_name, property_value)
