INSERT INTO core.text(id, content)
VALUES ('2030fca3-b6d9-4d2e-b06c-3fd354f8bee4',
        'Probleem paikneb selles, et üsna palju noori tarvitavad mõnuaineid, näiteks: alkohol, e-sigaretid, suits, mokatubakas ja paljud muud ained.\nKuid küsimus ei saa õhku jääda ja sellele peab ka vastuse leidma. Nii siis, miks noored neid mõnuaineid tegelikult tarvitavad? Põhjuseid võib olla väga palju ja erinevaid, kõige enam vastatud põhjuseks on see, et see rahustab neid, aga see ongi tegelikult mõnuaine eesmärk, et tekitada sulle sõltuvust maha rahustamisega ja hea olemisega.\nMa arvan et kõik see mõnuainete tarvitamine hakkab peamiselt koolist, kus asub inimese sõprusringkond, sest peamiselt hakkavad sõbrad teistele pakkuma ja kui keegi ei ole kunagi proovinud, hakkavad teised sõbrad peale suruma ja tahavad, et inimene, kes ei ole kordagi teinud prooviks nt. suitsu. Kuna need kes pakuvad on ta sõbrad ja ta ei taha nende kõrval välja näha nagu „nohik“, mida ta tegelikuses ei ole, siis ta kindlalt proovib selle ühe suitsu ära, aga suurel võimalusel jääb sõltuvusse. \nPäris paljud arvavad, et kui sa oled keskkonnas, kus tarvitatakse mõnuaineid ja sa ise ei tarvita, vaid lihtsalt viibid seal, siis see rikub sinu tervist sama palju, kui sa tarvitaks neid ise.\nKuidas saab noortel nii suur huvi olla mõnuainete vastu, kui nad teavad, et see kahjustab tervist ja ei ole inimesele hea. Tegelikuses, kui me vaatame ringi siis ei tundu, et nii paljud noored tarvitaksid midagi, aga kui me teeksime küsitluse, kus vastaja jääb anonüümseks, siis neid noori on kordades rohkem, kui me arvasime.\nMina arvan, et mõnuained ei ole just kõige parem viis oma närvide rahustamiseks. Selle asemel, et midagi tarvitada, saad sa õue värskeõhu kätte jalutama, jooksma või palju muud tegevust minna tegema, et mõtted eemale saada ja maha rahuneda.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('2030fca3-b6d9-4d2e-b06c-3fd354f8bee4', 'title', 'Miks tarbivad noored mõnuaineid?');
