INSERT INTO core.text(id, content)
VALUES ('56e1514e-899b-405e-b177-63cf5a91ab35',
        'Mis on tarbimisharjumus inimestel? Miks inimesed ei saa oma harjumustest lahti? inimestel on enda tarbimisharjumus, et mida ta vajab ja mida mitte aga mõned inimesed ei suuda sellest kinni pidada.\nSuurem osa inimestel on tarbimisharjumus millest nad ei saa lahti. Ühel suurem kui teisel aga see on tekitanud probleeme. inimesed on harjunud ostma liialt asju ja siis hiljem ära viskama, sest neile ei meeldinud see või oli mõtetu asi. See probleem ei kuluta ainult meie enda raha, vaid ka palju ressurse, et neid asju teha. inimesed arvavad, et see väike kogus ei tee midagi. See on täiesti vale jutt! Iga aasta leidakse meeletult raisatud asju mida oleks saanud veel kasutada või ära annetada.\nSee probleem ei ole ainult eestis, vaid see on ka üle maailma üks suurimatest probleemidest. Inimesed lihtsalt ostavad uusi riideid, nutivahendeid ja igasuguseid muud asju kuigi neil pole otseselt vaja. Ostetakse uusi riideid ja pärast ühe päeva kasutamist ei kasuta seda enam kunagi ja selle asemel ostavad uue riietuse. See on täiesti mõtetu raha ja ressursi raiskamine. Seda põhjustab nende harjumus ja nad ei märka, et tegelikult raiskavad väga palju raha. Sest nad on harjunud, et raha tuleb ja raha läheb.\nSiin on palju lahendusi, kuidas neid probleemi lahendada nii, et inimesed saaksid sellest harjumusest lahti. Esiteks inimesed peaksid arvestama mida nad ostavad ja arutlema, kas neil tõesti seda vaja või lihtsalt hiljem ära viskamiseks. Täpselt sama jutt toiduga, et inimesed peaksid ostma teatud koguses toitu, et nad saaksid selle kõik ilusti ära tarbida nii, et ei tekiks harjumust osta palju toitu ja siis hiljem ära visata. Kui juhtub, et kellelgi jääb riideid üle, mida nad ei kasuta või ei taha, saaksid need ära annetada, et raisku ei läheks, sest meil ei ole lõputult ressursse, et neid alati tagasi teha.\nInimesed peavad arvestama ja arutlema mida nad ostavad, et ei tekiks nende elus harjumust sellest, et osta alati liialt asju ja siis ära visata. Peab meeles pidama, et meil ei ole lõputult ressursse.');
