INSERT INTO core.text(id, content)
VALUES ('328fdbf8-64b7-4689-9898-6c93dd170c9c',
        'Toit on see, mida tuleks väärtustada. Maailmas on sadu erinevaid võimalusi, mida toota ja süüa. Mõnel inimesel on komme toitu raisata ehk mitte 100% ära kasutada. See tähendab seda, et inimesed arvavad, et toit ei saa kunagi otsa ning seda tuleb alati igalt poolt juurde.\nIgal inimesel on oma toidueelistus, mida süüa. Mina, kui olen söönuud, siis on mul tulnud mõtteid. näiteks olen mõelnud ümbruskonna inimestest kui ka vaesemate riikide kodanikest. Sest mõnel neist ei ole sellist toidu võimalust nagu mul. Nemad, kui seda toitu näeksid ja maitseksid, oleks see suur kingitus. Toit ongi üks suur kingitus. Ilma selleta me ei saaks elada.Sellepärast olen oma toitu 100% nautinud.\ntoitu saab valmistada nii paljudest asjadest, mis meid ümbritsevad. Ning jääke saab isegi ära kasutada oma looma toitmiseks. Koju lähen vaatan, et kapis pole nagu mitte kui midagi, aga nendest asjadest, mis seal on, annab tegelikult nii palju asju toota.Harjumus on see ,et lähed ikka poodi ja ostad tooteid, mida oled koguaeg söönud. Mõnel inimesel tuleb sellepärast ka rahalised probleemid, kui oled igapäevaselt poest midagi uut ostmas.\nToit on see, mida väärtustada ja anda hea tunde Sinu päevale mitte seda raisates. Inimesele tuleb nii palju kahju, kui Ta seda igapäevaselt kaotab.');
