INSERT INTO core.text(id, content)
VALUES ('c7f56eb6-166f-4289-8cc8-5738020505ae',
        'Toidu raiskamine on tänapäeva ühiskonnas üks suurimaid ja enim kajastatumaid probleeme. Maailmas on meile kõigile teada olevalt palju erinevaid kultuure ja harjumusi. Mõne inimese harjumus on visata toitu ära, kulutada täiesti mõttetult meie ilusaid loodusvarasid ja kasutada  neid ilma neid väärtustamata, kuid mõni inimene peab sellepärast tõsiselt kannatama.\nMeie generatsioon aina uueneb ja kujuneb igapäevaselt, mis on ühest küljest tore. Moesse on tulnud toidusäästmine ja taaskasutus. Teisest küljest on aga hakatud rajama tehaseid ja ka tööstusi, mis mitte kuidagi ei soodusta meie kliimat ega loodust. No jah, see on enesest ju mõistetav, et igal heal küljel on ka alati mingigi pahupool, see lihtsalt on nii. \nTänapäeval võiks inimesed hakata pöörama rohkem tähelepanu oma tarbimisharjumustele. Kui igaüks vaataks üle oma harjumused seosed toidu tarbimise ja ära viskamisega, oma uhke garderoobi ja mõtleks kuidas panustada kas või killukese meie heasse tuleviku ühiskonda siis olen ma päris kindel, et saaksime endale luua oma unistuste ühiskonna. See hõlmab endas toidu kui ka vee väärtustamist, taaskasutust ja meie loodusressursside mõistlikku kastamist. \nMa olen õnnelik, et me liigume selles suunas, et saavutada hea tulevik meie lastele ja lastelastele, aga see võtab aega, väga palju aega. Me ei saa loota teistele. Igaüks peab ka ise panustama sellesse, et meil oleks hea elada ühiskonnas, kus ei ole enam probleemiks toiduraiskamine, nälg, saastunud kliima ja loodus. Meie tulevik on meie endi kätes.');
