INSERT INTO core.text(id, content)
VALUES ('b2c74a1c-73dc-42a6-9733-a229cce82f7c',
        'Tarbimisharjumused on kõikidel erinevad mõned armastavad rämps toitu teistel on just harjumus toituda ainult tervislikult. Arvan, et inimesed on harjunud toituma nii nagu neile on õpetatud lapsest saati. Väga palju sõltub ka inimese geneetikast ja ku kiiresti inimene satub sõltuvusse.\nTavaliselt inimesed ei mõtle tuleviku peale, sest igal pool poodides on toiduaineid parajalt ja piisavalt, et elada rahuliku elu. Inimeste tarbimine sõltub paljul määral ka hindadest. Paljud valivad just odavaid ja praktilisi tooteid mis seisavad kaua ja teevad inimese elu paremaks. Inimestel on harjumus panna endale alguses suure portsu toitu, kuid mõnikord ei ole nad võimelised seda tervenisti ära sööma.\nPaljudes tehastes tehakse tooteid liiga palju, mida tulevikus ei müüda kõike täielikult ära. Kahjuks  lähevad kõik mitte müüdud tooted tavaliselt viskamisele prügikasti. Prügi läheb omakorda hunnikutesse mis hakkab reostama loodust. Paljud mitte müüdud ained lähevad toidubanka kus jagatakse ained inimeste vahel ära.\nPaljud inimesed tarbivad rohkem välis riikide tooteid sest need on odavamad ja praktilisemad. inimesed juhivad tähelepanu ka toote pakendile. Tavaliselt valivad inimesed reklaamist tulnud tooeteid millel on erksad värvid, suurte ja paksude tähtedega kirjutatud sõnad ning laused. Inimesed valivad riideid firma järgi, mis on enim populaarsem.\n Inimesed leiavad lahendusi iga päev, et tooted ei läheks raisku ja säiliks rohkem. Arvan et inimesed tarbivad aineid tasakaalukalt ja õpivad iga päev oma tarbimisharjumusi muutma.');
