INSERT INTO core.text(id, content)
VALUES ('80583672-ae64-479b-8a02-1b2903f6ca1b',
        'Praegusel ajal on suureks probleemiks osutunud inimeste tarbimisharjumused. Inimesed raiskavad loodusressursse, sest ei väärtusta neid tarbimisvahendeid, mis juba antud on.\nToit on üks peamisi asju, mida suurem osa  inimestest ei väärtusta. Olen näinud, kuidas visatakse toitu prügikastidesse, maha või rikutakse mingil muul viisil ära. Muidugi on ka inimesi, kes oskavad hinnata toidu olulisust, aga enamus inimestest ei väärtusta toitu. Paar aastat tagasi ei oleks ma välja teinud sellest, et peame toitu hoolikalt tarbima ja mitte raiskama. Märgates, kui palju inimesi meie ümber hävitavad söömis kõlblikut toitu, visates seda ära või rikkudes.\nRiided on tänapäeval väga olulised esemed, sest tihti peale iseloomustavad need meid. Kuid on ka riietega suur probleem, inimesed ostavad odavamaid riideid kohtadest, kus on kulutatud palju ressursse, et neid toota. Odavad riided on küll head, aga enamus on toodetud naftast. Nafta on maavara, mis ei lähe kokku meie kehaga või täpsemini nahaga. Just need riided on halva kvaliteediga, mis väljendub järgnevatest teguritest: värv kulub kiirelt, tulevad augud, materjal on õhuke ja läbi nähtav. Need tegurid mõjutavad nende riiete tootmist, sest inimesed kipuvad ostma ikkagist odavamaid riideid. Kahjuks olen ka mina inimene, kes pigem ostab odavamaid riideid, sest ma ei saa piisavalt taskuraha.\nInimeste tarbimisharjumused on muutunud aastatega halvemaks, aga on veel lootust parandada neid. Peame alustama juba väikestest lastest ja neile olema eeskujuks ja õpetama neid, et nemad saaksid edasi näidata, et tarbimisharjumusi on võimalik parandada ja ühiskond loodusrikkamaks paigaks muuta.');
INSERT INTO core.text_property(text_id, property_name, property_value)
