INSERT INTO core.text(id, content)
VALUES ('c1ae8e57-b41b-489c-ab44-aecb4220bb24',
        'Paljud inimesed arvavad et toidu on lihdne saada ja naad ei tea kui palju võib minna toidu valmistamisel ja selle kasvadamisel ja miks ostavad inimeset oma riited Hiina poodites.\nHiinapoodites on noorde jaoks odavam sela osta asju ja see tuleb neile kiiresti kohale ja nendel on internetis kiiresti osda ja lihtne.Paljud inimesed arvavad et toidu saad kiiresti valmis ja kui naad enam toidu ei taha siis naad viskavad selle ära peale selle et ära visata võiksid nemad seda anda edasi.\n näide et ma teen endale söögi ja ma ei taha seda enam selle asemel et ära visada oleks võinud teha väiksema söögi koguse teha´´toidukaubad ehk raisatud toit on toit või aine,mis mingil põhjulsel rikenud.´´Inimesed võiksid riidet taaskasutada mitte neid ära visada või kelleki oma tudavates anda et nemad saaksid seda ise edasi kanda või anda pooditese kus müüjakse neid edasi teistele inimestele kes saad neid ise edasi kanda´´.Kui minule on mingid riited suureks või väiksekd jäänud siis ma annan neid riidet endasi oma sõbratele või perele.´´\nüritame räägitda inimestele mida rohkem olla säästlikumad  seda vähem pekasime tarbiima saju ja neid toodma aidama inimesi kellel olek vaja ise asju saada.');
