INSERT INTO core.text(id, content)
VALUES ('ebfbd096-15c4-45ba-9809-c9e5d6e754d1',
        'On palju inimesi, kes raiskavad toitu ja viskavad selle ära selle asemel et anda see kellegile kes seda väga vajab. Inimesed kes teavad, et nad saavad endale midagi lubada, tavaliselt ei tarvita seda kõike ära vaid sellest jääb ülejääke. Samamoodi ka riietega, paljud riided visatakse ära kuigi saab anda inimestele kellel neid oleks hädasti vaja. \nToidu tootmine tekitab tõsise keskkonnakoormuse, sest saagi koguse tõstmiseks kasutatakse erinevaid kemikaale ka väetisi, seega kulutatakse erinevaid ressursse toidu tootmiseks ja ka riiete tegemisel. Paljud riided visatakse ära kuigi neid  saaks anda edasi kellelegi kes neid vajab ja see tekitaks inimeses endas heameelt, kuna ta ise aitab teisi. Näiteks saaks anda ära toitu mida sa tead et ei jõua lõpuni süüa või riideid mida ise enam ei kanna. Noortele ehk uutele põlvkondadele tuleks õpetada rohkem, et mitte ära visata riideid, sest taaskasutuspoodides on paljusid riideid mis on ilusad ka reklaamifotodel, aga neid saab ainult korra elus kanda sest need on tehtud naftast ja kehal on halb ja ebamugav seal sees olla.\nInimesed peaksid rohkem mõtlema teiste peale ennem kui nad midagi ära viskavad. On paljusid inimesi näiteks lapsi, täiskasvanuid ja ka vanemaid inimesi kellel on vaja riideid ja toitu, aga toitu raisatakse ja riided visatakse ära.');
INSERT INTO core.text_property(text_id, property_name, property_value)
