INSERT INTO core.text(id, content)
VALUES ('c224166d-eca0-4023-89d9-7e12db625003',
        'Me inimestena oleme harjunud sellega, et meil on suures hulgas toitu. Raiskame tänapäeval toitu ilma mõtlemata.\nToidu raiskamine on suur probleem kuna nii me ei raiska ainult toitu vaid ka resursi mis selle toidu valmistamiseks läks. Kurb on veel vaadata kuidas visatakse täiesti söödavat toitu niisama ära. Mina olen sellel arvamusel, et siis kui toit on ühel päeval tehtud, siis kõlbab ka järgmisel päeval. Suur tegur toidu raiskamisel on  ka veel ületootmine mis on kahjuks tänapäeval suur probleem.\nVäga inteligentne leiutis mis on nüüd ka Eestise jõudnud on toidukapid. Toidukapidesse panevad poed toite mida enam müüa ei saa, aga süüa veel kõlbavad. Need kapid aitavd neid peresi kelllel võibolla pole nii palju raha et süüa soetada. Minu peres on ka väga tavaline näiteks osta toite millel on parem enne mõõdas näiteks liha.\nTulevikus võiks olla toidu raiskamine täiesti olemata asi, mida ei eksisteeri või on ainult väheses hulgas. Ma aga tean seda et see ei saa toimuda üleöö, et see on aega nõudev protsess. Toidukapid võiksid olla saadaval olla igale linna elanikule üle Eesti.\nMe võiksime vähem toota toitu, nii väheneb ka toidu raiskamine. Peame rohkem hindama seda mis meil on kuna kunagi polnud ültse toit nii kättesaadav kõigile inimsetele.');
