INSERT INTO core.text(id, content)
VALUES ('f7636431-3aad-4e78-9e36-7e57c6907a23',
        'Inimesed raiskavad toitu igapäevaga aina rohkem isegi nii, et nad ei pane seda enam ise tähelegi. Eestis läheb raisku aastas umes 61kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg. See arv võib minna iga aastaga aina suuremaks ning see põhjustab maa, vee energia ja tööjõu ning ka oma raha kaotust. \nPere inimesed ostavad vahest liiga palju toitu ette ja  sellest võib minna enaus riknema ja see kõik vistakse lihtsalt ära. Mina soovitaksin suurtelperedel osta ainult paari päeva toidu ained ette osta nimekirja alusel, sest nii saavad nad kindlad olla, midagi ei lähe enam raisku ja kui peaksgi minema pole see arv nii suur. \nVahest juhtub selliseid raiskamisi ka noortel kes on alles vanemate juurest ära kolinud kuna nad ei oska veel nii hästi arvestada kui palju neil toitu on vaja osta, või ka riideid. Artvatavasti ostavad nad veebipooditest odavaid esemeid ja nende kvaliteet pole nii hea ja peavad need kohe ära viskama. Oleks hea kui osta veidi kallimaid tooteid, et need kauem kestaks ja saaks rohkem kui ainult ühe korra kanda. \nKindlasti paljusi mehi ja naisi või isegi noori ei huvita kogu see keskonnna probleem, aga siiski võiks  mõelda sellel, et võib-olla tulevikus polegi meil metsi ega maid kus kasvavad toidud ja millest saab valmistada riideid.');
