INSERT INTO core.text(id, content)
VALUES ('b3129aeb-c0ba-4a83-8c95-9b32763ea83b',
        'Kas te teade kas peakside enda tarbimisharjumisi muutma? Tarbimisharjumisi saab vähendada, aga see on iga inimese oma teha. Tarbimisharjumisi saab olla erinevaid näiteks, kui raiskad toidu või riideid, kas need lihtsalt ära visades või mitte kasutades. Kuidas saaks tarbimisharjumusi muuta paremuse poole?\nKui osta palju süüa kokku võib minna suur osa ka mitte tarbimiseks ja lihtsalt ära viskamisele. Seda võib juhtuda ka riiedega, kui ostad endale uued riided mida kasutad ühe korra ja läheb pärast kas kuhugi tolmu koguma või ära viskamisele. Kuigi saaks neid riideid kasutada teised kellel kas pole raha, et endale osta või tahavad vähendada oma tarbimisharjumisi. On veel palju teisigi asju, mis võivad lihtsalt minna raisku. Osa ühiskonnast raiskavad asju, sest nad kas ei viitsi neid taaskasutada või lasevad söögil lihtsalt raisku minna. \nAsjade raiskamist saab ka ju ära hoida näiteks annad oma vanad riided taaskasutamisse või enda tuttavale. Kui tahad endale uusi riideid on ka hea mõtte vaatada ringi taaskasutuskeskuses. Söögiga on see, et ei osta liiga palju ostad nii palju kui on vaja mitte ei hakka ostma endale varusi. Oma tarbimist ei saa muuta üleöö ,sest see tähendab, et inimene peab oma harjumisi muutma, mis ei ole kõigile just kõige kergem asi mida teha. Meie ühiskonnas on inimesi, kes proovivad tarbida võimalikult vähe. Kui suudad oma harjumisi muuta ja vähem raisada kas süüa või riideid on see väga hea.\nKui kõik inimesed muudaksid enda tarbimisharjumisi paremuse poole, oleks väiksem ökoloogiline jalajälg. Parem osta vajalikke asju ja vajalikus koguses, et vahendada asjade raiskamist. Tarbimisharjumusi on raske muuta , aga pole võimatu see on sinu enda teha. Kui oled otsustanud enda tarbimisharjumusi muuta ja see õnnestub aita teisi ja anna nõu.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('b3129aeb-c0ba-4a83-8c95-9b32763ea83b', 'title', 'Inimeste tarbimisharjumised');
