INSERT INTO core.text(id, content)
VALUES ('b800fb1b-de2b-46cd-b68d-06b6c85e5864',
        'Toit on inimese igapäevases elus väga tähtis. Tänu toidule me oleme energilised, mõistlikud ja vastupidavad. Toit aitab meil elus püsida, kui ei oleks toitu ei oleks ka meid. Taaskasutamine on ka meie igapäevases elus tähtis, sest sellega me päästame meie enda loodust. Paljud inimesed ei pruugi ennast kasutatavates riietes mugavana tunda, kuigi neid riideid pestakse ja see kaitseb meie keskkonda mitmel viisil.\nInimesed arvavad et toidu ära viskamine on normaalne tegu, kuigi see ei ole. Toit aitab meil olla elus, kui ei oleks toitu ei oleks ka meid. Tänu taaskasutamisele on meie loodus puhtam. Taaskasutamine on üks olulistest asjadest elus mida võiks enda hea südamega teha. Paljud inimesed käivad väheste riietega ringi ja nälgivad, sest neil ei ole võimalust endale neid asju lubada. Inimesed kes viskavad enda toidu alati peale söömist ära võiksid selle anda kellelegi teisele või hoida järgmiseks korraks kui koht on tühi, et see hiljem ära süüa. Sama asi on ka riietega, kui riided jäävad väikseks, kitsaks või ei meeldi enam, siis võiks need riided kellelegi ära anda kellel on neid tõsiselt vaja. Enda riiete ära andmine kellelegi teisele ongi taaskasutamine, mõned inimesed ei hooli nendest kellel ei ole võimalust riideid ega süüa endale osta, vaid nad viskavad enda riided ja toidu ära. \nLühidalt, toidu ja riiete ära viskamine võiks läbi saada, sest mõned inimesed ei saa endale lubada neid asju. Me kõik oleme inimesed ja me võiksime üksteist aidata enda hea südamega. Kui ei kanna enam enda riideid, siis taaskasutuspoed on olemas kuhu saab neid viia, et teised inimesed saaksid neid kanda kellel on neid rohkem vaja kui sul. Toiduga on sama lugu, kui sa tunned kedagi kellel on seda rohkem vaja kui sinu prügikastil, siis sellele inimesele võiks selle viia.');
