INSERT INTO core.text(id, content)
VALUES ('8f68bb2b-003d-4975-8b40-4561c24e8c1d',
        'Iga päevaselt tarbivad inimesed uusi asju ja ei pane tähele, kui palju nad üle tarbivad. Milline oleks maailm, kui me kõik niimoodi jätkame ja ei võta seda teemat tõsiselt? Kas inimesed peaksid rohkem jälgima mida ja kuidas nad tarbivad?\nInimesed on kõik ühed suured tarbijad. Me tahame liiga tihti uusi riideid endale hankida ja tihtipeale läheme me odavat teed kaudu, tellides odavaid riideid. Tavaliselt ei tea paljud tellijad, kust need riided pärit on ja kuidas on need valmistatud. Odavad riided mida tavaliselt tellitakse tulevad Hiinast. Neid riideid tehakse aina juurde ja juurde, tekitades reostust loodusele. Juba ühe t-särgi valmistamiseks läheb mitu kümmend liitrit vett. See on tohutu tarbimine. Selle asemel, et tellida odavaid riideid mis isegi ei pea kaua vastu, minna hoopis taaskasutatud riidepoodidesse ja vaadata, mida nad pakuvad. Minu arvates on taaskasutatud riided veel huvitavamad ja unikaalsed, eriti kui need on heas seisus. \nAga milline oleks maailm umbes kahekümne aasta pärast, kui keegi ei võta tarbimis teemat tõsiselt? Kindlasti mitte heas seisus. Juba praegu on suur probleem paljudes maailma riikides prügi ja reostus. Inimesed on üritanud ja üritavad ikka veel sellega toime tulla ja näidata, et neid huvitab, kuid sellest ei ole ikkagi piisav. Kui mõelda sellele palju kõik inimesed maailmas ühe päevaga tarbivad erinevaid asju, mida nad isegi ei pea tarbima, läheks mõttemeel kurvaks. \nKokkuvõtteks peaksid inimesed iga päevaselt jälgima mida nad tarbivad ja kas nad tõesti vajavad seda kõike. Kuidas saaksime hoida kokku tarbimist ja mida saame muuta oma harjumustes.');
