INSERT INTO core.text(id, content)
VALUES ('ad7d7d36-15a1-4c61-b64c-0f0571de6252',
        'Väga paljud pered raiskavad meeletus koguses toitu. Kuidas seda parandada? Moes olevad kaubad tulevad eelkõige Hiinast. Miks on see probleem? Kas see on mõistlik ja kasulik?\nVäga paljudes kodudes läheb aastas mitmeid kilosid toitu raisku. Selle põhjuseks enamasti on kasutustähtaja ületamine või ülejäänud toit, mis lihtsalt enam kasutust ei leia. Selline käitumine raiskab meie enda raha kui ka muid ressursse maal. Inimesed, kes raiskavad ka väiksemas koguses toitu, mõjutavad tervet maaimapilti. Toidu raiskamist saab kodudes parandada igaüks. Kui kodus tehakse liigne kogus süüa, siis mõistlik oleks süüa seda toitu terve ülejäänud nädal. Kui tegemist on kuupäeva ületanud toiduga, siis saab küpsetada midagi, kus see ei mängi olulist rolli.\nSama probleem on ka moes. Tihtipeale nähtakse internetis ilusaid inspireerivaid fotosi ja pilte, mis paneb aluse odavamate kaupade ostmisele Hiinast. Miks on see nii suur probleem? Kõik tahaksid madala hinnaga moodsaid riideid, kuid see alternatiiv pole mõistlik. Hiinas kasutatakse odavaid ja kehale ebasõbralike materjale. Pildil võib toode ilus välja näha, kuid päris elus kvaliteet ja toode ise pole selline nagu ootasime. Moedisainerid soovitavad poodelda taaskasutuspoodides. Sinna koguneb igapäevaga riideid, millele saaksid inimesed anda uue elu.\nNoored tihti peale ei mõista nende rõivaste arengut. Tegemist on väga kuluka protsessiga, just sellepärast peaksime hakkama mõtlema, kas see on tegelikult ka praktiline?  EI, nende rõivaste tegemiseks kulub jubedalt loodusressurse, kvaliteet pole hea, kehale ebasõbralik. Lõpuks on see meie enda raha raiskamine ja looduse kulutamine.\nKokkuvõteks peaksid noored mõtlema rohkem reaalsuse peale, mitte mida nähtakse pildil. Toidu raiskamine pole kasulik meile ega keskkonnale. Tuleb hakata tegutsema enne, kui on liiga hilja.');
