INSERT INTO core.text(id, content)
VALUES ('0e61da51-93ae-4dc3-b7fb-1b0e7f2ead71',
        'Iga inimene vajab miskit. Iga inimene vajab sööki ja jooki. Iga inimene vajab ka riideid. Aga iga inimene ei söö ega joo kõike mis ta ostnud on ja ka kõiki riideid ei kanna ja see kõik läheb lõpuks raisku.\nToitu toodetakse igapäevaselt rohkem kui seda tarbitakse ja selle toidu kogus mis raisku läheb sellel viisil on tohutu palju suurem kui inimeste kes lihtsalt viskavad peale söömist toitu ära. Toitu mis ei osteta poest õige aegselt või tehased ei saada kuskile müügile ja need lihtsalt neil laos ootavad, võiks viia kuskile kus on vaesem piirkond ja ei ole nii palju raha, et igapäevaselt süüa osta oma perele ja on tänu sellele näljas.\nJoogi tehased mis toodavad karastusjooke ja maitse vett viskavad ära ja hävitavad suure hulga oma tooteid tänu sellele, et neil on suhkru kogus natukene vale või lausa selle pärast, et neil ei läinud piisav kogus vedelikku pudelisse. Tänu kõigile väikestele vigadele tuleb need joogid võtta käibelt ära ja minema visata või hävitada aga need joogid saaks anda ka vaestele kes seda vajavad. See teeks vähem loodusele kahju ja joogid ei läheks niisama raisku.\nRiideid tehakse tohutult mida isegi ei kasutata. Neid riideid hoitakse ladudes lootes, et keegi ostab need ära kuna ei taha anda ka tasuta kellegile kes seda vajab. Sellised riided saaks anda kas kanga tööstustele taas kasutamiseks või kodututele. Reklaami firmad saaksid mingil moel neid riideid kasutada. Neist saaks uusi riideid disainida ja see tooks juba riiete hulga mis jääb üle, alla. On palju riideid mis on kuskil poodides ja ladudes ja keegi ei osta neid, kuna need on liiga kallid, ja tänu sellele on need lihtsalt seismas.\nTeema millest ei räägita väga palju on ka metsa majandus. Tehakse metsa rohkem kui metsa tagasi kasvab. Paljud raie puidud seisavad kuskil tee äärtes mis on juba ära poolkõdunenud ja ei ole enam kõlbulikud kasutamiseks. Sellised puud oleksid saanud veel aasta kümneid kasvada rahulikult ja olla ilusad Eesti loodusele aga ahned metsaomanikud hoolivad rahast ja ei hooli kui palju tegelikult Eesti metsadest läheb raisku tänu nende ahnusele.\nSuure kahju jätab ka sõjategevus. Maailmas on kõige suuremaid avastusi tulnud tänu sõdade pidamisele. Esimesed autod ja lennukid loodi tänu sõjategevusele kus oli vaja transportida inimesi ja relvi ja lausa hävitada vaenlasi. Tänu sõdadele on tehased tootnud palju relvastust ja tehnikat mis hävineb küll sõjas aga jääb maa peale kus see ei mädane ja tekitab loodusele suurelt kahju. Relvi toodetakse liiga palju, kuna kui sa kellegi sõjas teise ilma saadad, sa saad tema käest võtta sõja trofeed ja sellega edasi võidelda. Tankid ja muu tehnika mis on purustatud ja ei ole võimalik taastada saab uuesti ära töödelda, et looda uus tank mis on sama tõhus kui ennem kui mitte parem.\nOn ka tootmisi mis kasutatakse kohe ära ja on vaja aina juurde. Energia tootmine on väga nõutud ja seda tarbitakse iga päev. Autodel on vaja kütust ja majadel elektrit. Elekter ei saa maa peal otsa kunagi, sest see on taastuv energia ja seda saab toota nii suurel hulgal kui ära saab kasutatud. Kütust toodetakse naftast aga nafta on taastumatu energia seega seda ei saa igavesti kasutada. \nKokkuvõtteks toodetakse maailmas asju rohkem kui seda suudab ära tarbida. Inimesed ei ole võimelised ostma ega tarbima kõike mida tehased toodavad. Igal inimesel on oma eelistused ja omad ahvatlused. Toodetakse asju massiliselt igale inimesel ja tänu sellele jääb ka väga palju tooteid üle mis läheb lihtsalt raisku ja hävineb. On inimeste enda kätes massi tootmine peatada ja toota nii palju kui inimesed ise suudavad ära tarbida ja taaskasutada.');
