INSERT INTO core.text(id, content)
VALUES ('b7a68859-fb46-42e8-b70c-142385795279',
        'Paljudele on räägitud, et tuleb tarbida nii, et midagi ei raiskaks. Aga kuidas on lood päriselt? Kas inimesed tarbivad mõistlikult, või tarbitakse liiga palju, et korralikud riided satuvad taaskasutuskeskusesse, või liigse toidu ostmisel tekib toidukadu? Kuidas parandada oma tarbimisharjumusi? Siin kirjandis räägin, kuidas eesti inimene tarbib ja kuidas parandada oma tarbimisharjumusi.\nMinu arvates ei tarbita mõistlikult. Paljudele on räägitud, et tarbida tuleks mõistlikult, mitte palju toitu osta, et toit raisku ei läheks, et osta kodumaist, mitte välismaist. Andmete järgi tekib iga Eesti inimese kohta 26 kilogrammi toidukadu, mis on liiga palju. See ei ole ainult toit, mis raisku läheb, vaid ka vesi, energia ja maa, mida kasutatakse toidu valmistamiseks. Lisaks on palju inimesi hakanud ostma riideid Hiina veebipoodidest, sest need on odavad. Ent need riided on halva kvaliteediga, halvad loodusele ja inimese jaoks halvad, sest mõndades riietes võib olla näiteks naftat, mis kehale ei meeldi.\nKuidas saab parandada oma tarbimisharjumisi? Selleks on mitu võimalust. Esiteks saab osta vähem. Näiteks saab vaadata, mida ei sööda ja seda mitte osta. See säästaks raha ja loodust. Veel saaks näiteks vanad riided ära müüa, või ära anda. Vanad, ent korralikud riided, mis on näiteks liiga väiksed, on kellegi teise jaoks hea suurusega ja see annaks riide elueale mitu aastat juurde. Viimaseks saab osta kodumaiseid riideid. Nendel on palju parem kvaliteet, kui näiteks Hiinast ostetud riietel, sest nende materjal on näiteks puuvili, mitte nafta nagu odavatel välismaa riietel. Lisaks aitab kodumaise toote ostmisel ka tootjat, sest raha läheb otse neile, mitte välismaale.\nKokkuvõtteks peaksid inimesed parandama oma tarbimisharjumusi, sest toidukadu on andmete kohaselt liiga suur. Lisaks peaks ostma vähem Hiina poodidest, sest need on halva kvaliteediga, raiskavad loodust ja on inimese jaoks halvad. Tarbmisharjumusi saab parandada vähem ostmisega, vanade riiete mahamüümise või äraandmisega ja kodumaise toote eelistamist välismaa tootele.');
