INSERT INTO core.text(id, content)
VALUES ('61b8c7cd-d4a3-4565-8875-95b8bd4effa1',
        'Inimeste tarbimisharjumused on üle aastate kasvanud ja muutunud suuremaks probleemiks. Inimesed ostavad endale liiga palju toitu või riideid kokku ja lihtsalt lasevad nendel asjadel raisku minna, Näiteks ostavad endale liiga palju toitu kokku mida nad ei jõua kasutada ära ennem kui need halvaks lähevad, või kui ostad riideesemeid kokku mida sa võib olla kunagi ei kannagi. Sellest ma tahangi arutada, Kuidas me saaksime oma tarbimisharjumusi muuta ja proovida olla kokkuhoidlikumad.\nAga kuidas me siis saaksime hoida toitu kokku, et ei läheks raisku. Esiteks me saame hakkata tegema ostunimekirju kus saame kõik täpselt kirja pana mida see nädal siis umbes tarbime ja kas jõuad need kõik ikka ära tarbida. Kui hakkad midagi juurde ostma mida sa ei ole kirja pannud siis küsi ennem endalt, kas ma ikka jõuan selle ka ära tarbida ennem kui see halvaks läheb. Saame ka hakkata käima poes tihedamalt, et mitte osta endale ühe korraga kõik asjad kokku ja riskida, et midagi jääb üle. Alati on ka poodides lett kus on tänase kuupäevaga toitu mida on vaja tarbida samal päeval kui ostad selle ja kui juhuslikult näed seal midagi mida sa saad kasutada samal päeval siis miks ka mitte saad isegi võib olla säästa mõne euro ka.\nRiietega on sama lugu, kõik võiksid vaatada üle oma riided, jalanõud või ükskõik mis riideesemed ja vaatada kas neil on midagi mida nad enam ei kasuta, ei mahu selga või mis iganes põhjus, lihtsalt vaatada üle oma ülejäänud riided ja nendega midagi peale hakkata. Näiteks saab viia oma vanad riideesemed uuskasutuskeskusesse, et anda neile uus võimalus või teha Nendest riiedest midagi uut endale. Saab ka nii kokkuhoida, et mitte tellida endale kuskilt hiinast mingeid riideid juurde mida sul endale isegi vaja ei ole aga nägid, et jube hea hinnaga on. Muidugi ei saa uuskasutuskeskused lõputult võta riideid vastu sest ükshetk saab ruum otsa nii, et pigem vaata mida sa endale kokkuostad.\njärelduseks saame öelda, et tegelikult kui sa ennem mõtled läbi kui sa midagi ostad  siis juba sellega saab hoida päris palju kokku nii raha kui ka, et oleks võimalikult vähe asju mis läheksid lihtsalt halvaks või raisku.');
