INSERT INTO core.text(id, content)
VALUES ('adae953b-400e-4fa6-9def-4ed711bcbc2b',
        'Tänapäeval tarbivad inimsesed asju liiga palju. Ostetakse liigselt toitu, mis siis ära visatakse või soetatakse ülemäära palju riideid, mida kanda ei jõua. Aga kuidas siis teha nii, et inimesed ei tarbiks enam nii palju? Mina arvan, et selleni jõudmiseks peavad inimesed ise aru saama oma valikute mõjust maailmale.\nInimestele peaks rohkem näitama oma otsuste mõju visuaalselt. Just siis näevadki nad oma silmaga, mida nad on korda saatnud ja kuidas see neid päriselt tulevikus mõjutada võib. Kõige parem on seda teha läbi dokumentaalide ja uuringute inimestele kättesaadavamaks loomise. Iga eestlane loob aastas umbes 61 kg toidujäätmeid, millest 26 kg moodustab toidukagu, ehk raisku läinud toitu. Kui inimesele seda numbrit visualiseerida, näeksid nad realistlikult ja füüsiliselt oma valikute tagajärgi ja hakkaksid selle üle sügavamalt mõtlema.\nAga nende arusaam oma vigadest on üks asi. Peale seda peab neil aitama aru saada, kuidas seda tulevikus vältida. Seega peaks inimestele rohkem rääkima, kuidas paremini kokku hoida. Seda saab teha luues töötube ja avalikke üritusi, kus kõik saavad teadlikumast headest viisidest mitte nii palju tarbida. Samamoodi võiks ka meedia sellistele probleemidele rohkem tähelepanu pöörata ja inimesi rohkem harida, et see planeet kauem kestaks ja me kõik nii pea tehasesuistu ei lämbuks.\nKokkuvõtteks, usun ma, et inimesed hakkaksid vähem tarbima, kui nad oma mõjust paremini aru saaksid ja neid õpetataks seda paremini kontrollima.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('adae953b-400e-4fa6-9def-4ed711bcbc2b', 'title', 'Kuidas saada inimesi vähem liigselt tarbima');
