INSERT INTO core.text(id, content)
VALUES ('3a532ebf-debd-4d06-81a8-9d91cc60bb16',
        'Inimesed leiutavad iga päev midagi uut just sellel eesmärgil, et oma tarbimisvajaldusi rahuldada, raisatakse nii enam asju igapäevaselt ning tarbimisjääk muutub aina suuremaks, kuid kas igapäevane tarbimine seab maailmale mingit ohtu?\nMeie, kui inimeste, vajadus on saada pidevalt uusi asju. Inimestele meeldib käia kõige moodsamate trendide ja brändidega kaasas ning selle pärast tarbitakse palju rõivaid ja tahetakse kogu aeg uusi osta. Trendide kiire muutumise tõttu soovitakse kiiresti osta uusi ja odavaid riideid ning tihti visatakse vanad ära selle asemel, et neid taaskasutada või annetada neile kellel pole võimalik riideid osta. \nSamuti on suureks probleemiks ka inimeste toiduraiskamine. Toidutarbimis veebileht kirjutab: „Võtame toitu iseenesestmõistetatavana, meile tundub, et toitu on veel ja see ei saa otsa.“ Toidu raiskamine on väga suureks probleemiks, mitmed riigid on ilma toiduta ning peavad silmitsi seisma näljahädade ja erinevate haigustega. Kuid mitmetel riikidel on toitu küllalt ning seda raisatakse igapäevaselt. Toidu raiskamine ei kahjusta ainult meie rahakotti vaid ka maad, vett ning energiat. \nMinu arvates on inimeste tarbimisharjumused suur probleem meie planeedile, sest see kahjustab loodust, kasutab energiat ning tekitab prügi. Selle probleemi lahendamine võtab aega ja pikemalt mõtlemist aga minu lahendus oleks annetada võimalikult palju vanu riideid ja toitu neile kellel pole võimalust selliseid asju ise soetada. Peaksime rohkem mõtlema taaskasutusele ja olema loovad selleks, et meie planeet oleks terve ja inimesed sellel tarbimistargad ja õnnelikud.');
INSERT INTO core.text_property(text_id, property_name, property_value)
