INSERT INTO core.text(id, content)
VALUES ('7beccbb9-666e-4c1e-af62-c2972fea44f1',
        'Me kõik elu jooksul ostame endale pluuse, jalanõusid, jopesid, pükse jne. Ostame uusi, et käia trendiga kaasas või sellepärast, et poes oli nii hea soodustus, et lihtsalt ei saanud mitte osta. Aga mida saaksime paremini teha?\nKui ostame endale uued riideesemed siis tihti vanad viskame ära, kuid see pole kõige parem valik. Tohutult suur kogus rõivaid jääb peaaegu et kandmata iga päev, sest toodetakse liiga palju riideid. Aga neid toodetakse just palju, kuna meie, inimesed, ostame koguaeg uusi ja ‘’paremaid’’. Tootmise käigus raisatakse palju vett, maad, energiat ja ka tööjõudu. See pole üldse hea meile praegu ega ka paari aasta pärast, sest üks hetk on seda ületootmist liiga palju.\nMeil ei ole vaja alati osta uusi asju, vaid eelistada tuleks just juba toodetud rõivaid. Selle asemel, et osta koguaeg uusi riideid, saaksime minna taaskasutus poodi ning sukelduda mitmetesse erinevatesse aastatesse, et leida nii kaasaegseid kui ka vanemaid riideid, mis on kestnud siiamaani ja kestaks mitmeid aastaid veel, kui neid ilusti hooldada. Kui kõik annaksid enda vanad riided uuskasutus poodidesse ning käiks sealt ka endale rõivaid ostmas siis me suudaksime väga suure protsendiga vähendada riiete ületootmist. \nKokkuvõtteks me kõik raiskame elujooksul riideid ning toimub palju ületootmist, aga me saaks neid mõlemaid fakte muuta, kui hakkaksime enda rõivad panema teisele ringile ja samal eelistaksime ka ise neid. Kõike saab muuta, kui seda piisavalt soovida ja selle nimel töödata.');
