INSERT INTO core.text(id, content)
VALUES ('92340eea-3d11-4781-b6df-bb9c41f54587',
        'Tänapäeval toodetakse hiinas ja ka mujal tohutult suurtes kogustes riideid mida inimesed kokku ostavad ja siis hiljem ära viskavad. Need riided toodetakse sellistest materjalidest millest on kõige odavam toota ja mis ei ole mugavad.\nInimesed ostavad hiinast riideid suurtes kogustes, sest need on mugavad ja näevad head välja piltidel, kuid kui need kohale jõuavad, siis nad kannavad neid paar korda ja siis viskavad ära. Üheks selle põhjuseks on tänapäeva mood. Moemaailm muutub nii kiiresti ehk siis uued moes olevad riided tulevad koguaeg peale. Kui uued moes olevad riided tulevad peale siis ostetakse need hiinast ja vanad visatakse ära. Kui riide ese on tehtud micro plastikust siis seda ei saa taaskasutada ehk siis see on väga suur reostus ühiskonnale.\nTeiseks põhjuseks on sotsiaalmeedias olevad reklaamid. Inimesed näevad uusi riideid ja ostavad need hiinast, teades, et kui riided neile ei sobi või ei ole mugavad siia nad saavad need ara visata ja uued osta hiinast. See, aga nii ei tohiks olla. Inimesed peaksid eelistama kvaliteeti üle kvantiteedi. See tähendab, et eesmärk ei tohiks olla igapäev uute riietega kooli tulla vaid hoopis kanda riideid mis kestavad kaua, riided mida ei pea pärast paari päeva ära viskama.\nEhk siis ära osta hiinast odavaid halbadest materialidest riideid, vaid osta kvaliteetseid riideid mis kestavad kauem kui paar nädalat ja ära lase moemaailmal ennast hulgaliselt mõjutada.');
