INSERT INTO core.text(id, content)
VALUES ('ba7f96f0-d101-4dc6-ad75-479173ae5d00',
        'Me kõik kui osa ühiskonnast tarbime midagi: toitu, riideid, plastikut. Enamus meist tarbib vähemalt ühte neist asjadest üle olgu see siis toidu raiskamise või odavate riiete ostmise näol. Aga üldse miks me seda teeme?\nAjalugu on näidanud, et kui on mingit resurssi üle, siis kasutab inimkond selle viimse tilgani. Nagu näiteks maa, suur osa sellest mingil hetkel kallati lihtsalt kahju tekitavate kemkaalidega üle (näiteks Ameerikas eriti DDT-ga) ja nüüd oleks meil seda nagu puudu, kuna toiduhinnad aina tõusevad, sest on järjest vähem viljakat ala kus süüa kasvatada. Toidu tarbimisega on üldse keeruline, sest päris suur hulk toodetud toidust läheb lihtsalt äraviskamisele või mahakandmisele ja mõnes osas maailmast on seda liiga vähe. Kui võrrelda arenenud maade toiduraiskamist arenevate maailmaosade nälgadega saaks need isegi ära katta.\nHetkel on meil ka teine suurem pahe, plastik. Tehased toodavad seda hiiglaslikes kogustes, kuid seda jääb ikka aina vähemaks ja vähemaks. See probleem on peamiselt tekitatud sellest, et taaskasutus on jäetud rohkem tavainimeste kui nende samade tehaste kätte. Küsimus tekib kui palju inimesi viitsib kõik oma tekstiilid või muud plastikust valmistatud tooted taaskasutada. See on ka üks põhjuseid miks plastikut nii palju üle toodetakse, sest üks hetk müüakse see tarbijale ja järgmine hetk on see kuskil Siberi metsas, kust keegi seda enam ära tooma ei hakka.\nKokkuvõtteks toodab maailm enamus asju üle ja seda jääki ei taaskasutata ega aidata vaesemaid kogukondi vaid lihtsalt visatakse minema järgmise põlvkonna probleemiks. See on kõige kurvem osa meie ületootlusest ja tarbimisest.');
