INSERT INTO core.text(id, content)
VALUES ('5740cad9-49c2-438a-833d-565900a0d4eb',
        'Enam levinumaid probleeme maailmas on ületarbimine. Murekoht seisneb selles, et inimesed ei mõista, millist reostust nende soovid ja harjumused endaga kaasa toovad. Kuidas tarbivad inimesed üle?\nSotsiaalmeedias levivad igapäevaselt reklaamid kiirmoepoodidele. Enamasti on need suunatud noortele, sest neil ei ole nii palju raha. Kuigi võib tunduda, et etem on osta hunnikute viisi riideid soodsate hindadega, on see keskkonda reostav ja üldises plaanis raha raiskamine. Kiirmoepoed kasutavad odavaid kangaid ja materjale, näiteks naftat. Sellised riided on seljas ebamugavad ja võivad paljudele tekitada isegi ärritusi. Peale paari korda odavate riiete kandmist tekib soov osta veel asju, sest vanad on juba koledad või ei sobi mingil muul põhjusel. Nii ongi taaskasutuspoodides palju riideid, mis pärinevad kiirmoepoodidest.\nPoes käies tuleks alati oma ostukorv üle vaadata. See kehtib nii toiduainetele kui ka tarbeesemetele, nt mänguasjadele, ilutoodetele jne. Poodides ekponeeritakse igasuguseid maiustusi poelettide juures. See on teaduslikult tõestatud, et nii tekib meil suurem kiusatus veel asju osta, kuigi algul seda plaanis ei olnud. Kui koguaeg osta asju üle ei suudeta seda ära tarbida, ja nii tekib väga palju reostust.  Keskonna hoidmiseks tuleks korraldad erinevaid kampaaniaid. Paljudes koolides on selliseid tehtud toiduraiskamise vastu, nt „Tõsta nii palju toitu, kui ära sööd“. On ka olemas toidupanku, kuid need on enamasti sellised, kus annetuseks tuleb süüa osta. Minu arvates oleks hea mõte sinna ka viia poolikuid kuivaine pakke või muid esemeid mida vaja enam ei ole.\nTarbimisharjumusi on raske muuta, kuid ühiskonna hüvanguks peavad kõik pingutama. Tuleb lasta lahti harjumustest osta ülemäära koguses toitu või kanda neid riideid, mis meil juba olemas on ning vanad annetada teistele.  Nii ei hoia me ainult ära keskonnareostust, vaid aitame ka neid, kellel nii palju võimalusi ei ole.');
INSERT INTO core.text_property(text_id, property_name, property_value)
