INSERT INTO core.text(id, content)
VALUES ('4cd1dbf5-18ca-4323-91f4-523486c10d24',
        'Inimesed tarbivad tänapäeval tohutult palju enesestmõistetavaid asju. Need harjumused reostavad ja raiskavad suures koguses meie ressursse, kui ka maad. See tähendab, et lõpuks saavad meie planeedilt lihtsalt ressursid otsa ja me oleme surutud mujale suunduma. Aga kuidas peatada sellist ressurside raiskamist?\nÜks suur probleem on toidu liigses tarbimises ja ära viskamises. Inimesed tarbivad toitu nagu see ei saakski otsa ja tekiks maagiliselt juurde, aga tegelikult pole asjad nii. Kogu meie todu raiskamisega, raiskame ka teisi tähtsaid ressurse: maad, raha, tööjõudu, vett. Inimesed arvavad, et nende vähene raiskamine iga päev ei tee maailma pildis mingit vahet, aga meid on nüüd 8 miljardit ja iga inimene loeb. Eesti keskmises majapidamises tekib umbes 61 kg toidujääke, ehk üle jäänud toitu ja sellest 42% ehk 26 kg moodustab toidukadu, mis on toit mis ei tarbita ja visatakse ära. See teeb maailma perspektiivis väga palju raisatud toitu kokku.\nTeine suur probleem on liigne riiete ost ja niisama ära viskamine. Üleliigne riiete ost on eriti populaarne just noorte seas, sest kuskilt tuleb alati välja uus mood, ning sisse sobitumiseks on vaja just neid riideid. Suur põhjus on ilmselt noorte harimatus selle teema kohta. Ka moedisainer Eve Hanson soovitab võimalikult vähe tellida netist või hiinast riideid ja jääda kodumaisete toodete juurde. Ta ütleb veel, et on parem osta vähem ja kvaliteetsemaid tooteid, kui palju ja kiirelt katki minevaid riideid, sest see säästab keskkonda ja on ka meie kehadele meeldivam.\nSellist ressursside raiskamist on väga raske peatada, sest oleks vaja head plaani ja üle poole maailma nõusolekut, kuid algus oleks inimeste harimine sellel teemal. Inimesi on väga raske panna oma harjumusi murdma.');
