INSERT INTO core.text(id, content)
VALUES ('fd0f856a-9d1d-4ea9-b13a-2cf85d44d6ad',
        'Me kõik tarbime igapäevaselt erinevaid tooteid, näiteks toitu, riideid, hügeenitooteid ja muud, kuid enamus inimesi ei oska hinnata, kui palju ressursse nende valmistamiseks võib kuluda. Seetõttu tuleb olla teadlik selles mida ja kui palju tarbida, et hoida meie planeeti. Kuidas seda teha?\nEnne kui midagi osta, peab mõtlema toote väärtuse peale. Tihti kõnnitakse poes mööda mõnest preždiisikast riideesemest ja nähakse ainult selle hinnasilti või allahindlust, kuid ei vaadata järgi, millest see valmistatud on. Siis visatakse riie ostukorvi, viiakse koju, kantakse seda paar nädalat ning saadakse aru, et see hakkab juba lagunema – prügikast. Kui aga osta kallima hinna eest midagi kvaliteetsemat, võib see teenida oma tarbijat mitmeid aastaid. On võimalik ka lähedaste vahel riideid taaskasutada, kui need hakkavad väikseks jääma.\nTuleb tarbida ökonoomselt ja teada oma vajadusi. Tihti on nii, et olen sõpradega väljas ja vaatan, et kõht hakkab tühjaks minema ning ostan mõnest kiirtoidu restoranist endale midagi hamba vahele. Tund hiljem jõuan koju ja vaatan, et on süüa tehtud, ning toitu on veel palju alles. Siis tekib oht, et pole kedagi, kes seda ära sööks. Tuleb osata teha tööd sellega, mis olemas on. Tihti mõeldakse ka, et riietused hakkavad vanaks jääma – tegelikult saab mõelda välja uusi viise kuidas oma olemasolevaid riideid kombineerida, tuleb lihtsalt olla loominguline.\nKokkuvõtteks võib öelda, et parim viis, kuidas oma tarbimist ökosõbralikuks teha on ettenägelikkus tuleviku suhtes ja võime oma ressursse efektiivselt kasutada.');
