INSERT INTO core.text(id, content)
VALUES ('27d76cd5-6e00-4ac5-9270-db3af349b7a9',
        'Selles kirjandis ma räägin inimeste tarbimisharjumustest ja toon välja enda lahendused, kuidas seda probleemi muuta.\nTarbimisharjumusi on erinevaid, aga põhiline neist on toidu raiskamine. Näiteks, on inimesi, kes raiskavad toitu, sest nad saavad seda endale lubada, aga on ka inimesi, kes viskavad ära väiksemates kogudes toitu ja arvavad, et nad ei muuda midagi seda tehes. Nad eksivad sellega, sest kodumajapidamises tekib keskmiselt iga Eesti inimese kohta 26 kg toidukadu. Toidukadu ehk raisatud toit on toit või toiduaine, mis jääb tarbimata ja visatakse toidujäätmena ära. Teine kõige suurem tarbimisharjumus on korralike riiete ära viskamine, sest koguaeg tuleb uusi riideid, mida inimesed osta tahavad kuigi neil on vanu korralike veel alles.\nLahendusteks tooksin ma välja kohustuslikud õppekäigud/õppetunnid, kus noored saaksid näha oma silmadega, milline see raiskamine tegelikult on. Noored, aga pole ainukesed inimesed, kes seda teadma peaksid. Sellepärast peaks olema ka loenguid või koolitusi  keskeastele ning vanematele inimestele, kes on need peamised toidu äraviskajad. Kolmas variant oleks sellest teemast pikemalt ja põhjalikult rääkimine sotsiaalmeedias või uudistes, mida kõik tänapäeva inimesed jälgivad.\nKokkuvõteks, inimeste tarbimisharjumused on väga suur probleem meie keskkonnas, aga seda probleemi on võimalik lahendada mitte küll üleöö, sest see on paljuski kinni inimeste harjumustes ja tahtes muuta seda.');
