INSERT INTO core.text(id, content)
VALUES ('88c3d488-39ed-4a66-91d5-adbbbf27c274',
        'Tänapäeval on hakanud inimesed aina rohkem asju tarbima ja kõige hullem on see, et nad ei väärtusta enam raha olemasolu. Visatakse toitu mõtetult ära ning ostetakse odavaid asju kokku, mis ei pea kaua vastu ja on halbadest materjalidest tehtud. Kuidas saame meie selle ära lõpetada?\nEsiteks räägime toidu raiskamisest. Inimesed ostavad endale korraga palju toiduaineid kokku ja arvavad, et saavad kõik ennem söödud, kui toit enam ei kõlba. Kahjuks see ei ole nii. Kui osta endale asju kokku, mida füüsiliselt ei jaksa ära süüa, siis pigem oleks mõistlik osta vähem ja kui puudu jääb, siis uuesti natukene juurde osta. Toidu ära viskamine tekitab tõsise keskkonnakoormuse ja aeglaselt hävitab juba maailma. Sellega peab hakkama tegelema, igaüks meist! \nTeiseks tahaksin rääkida riietusesemetest. Paljud noored ostavad riideid odavalt internetist. Eriti Hiina poodidest, nagu näiteks AliExpress või Shein. Võidakse ju mõelda, et see on lihtne viis kuidas endale lihtsalt ja odavalt palju riideid saada, kuid sellele pikemalt mõeldes, kahjustab see samuti maailma. Need riided, mis sealt on ostetud ei ole üldsegi heast materjalist tehtud. Need sisaldavad naftat ja ei ole enam pärast paari korda kandmist sobivad. Minu arvamus on see, et võiks osta kasvõi üks korralik riideese kallima raha eest, aga mitte mitu kõlbmatut riideeset odava raha eest. \nKokkuvõtteks me peame hakkama kõik enda tarbimisharjumusi muutma. See ei ole absoluutselt lihtne, aga seda jätkates hakkab maailm aina hävinema ja seda me ei taha. Kindlasti mõned inimesed juba tegelevad sellega, kuid see pole piisav. Kõik peavad oma parima panuse andma ja niimoodi saame maailmale head teha. Toitained peame hakkama paremini tarbima ja mitte ära viskama ning riideid kasvõi taaskasutuskeskustest ostma ning seda ka üpris odava hinna eest, aga need on tehtud parematest materjalidest ja ei sisalda naftat.');
