INSERT INTO core.text(id, content)
VALUES ('f12286e7-6298-4931-b97e-533faed4f70f',
        'Tänapäeval on inimeste harjumused, ja eriti tarbimisharjumused, väga kahjulikud meie keskkonnale. Me ei mõtle enne kui tegutseme ja selle tagajärjena kahjustame me oma planeeti. Tarbimisprobleemide lahendamiseks ei piisa ainult sellest, et üks inimene teeb absoluutselt kõik mis ta vähegi suuudab, selleks on vaja, et kõik inimesed teeks kasvõi väikese muudatuse oma igapäevases tarbimises.\nMeil ei ole vaja osta kusagilt Hiina lehekülgedelt kõiki asju mida me tahame. Enamasti me kanname neid ainult paar korda, enne kui need kasutuskõlblikuks muutuvad. Hiina tooted ei ole hea kvaliteediga, enamasti tehtud naftast, mida ei ole hea naha peal kanda. Arusaadav on see, et odavad hinnad, kiire kohaletoimetamine ja nii palju erinevaid võimalusi on ahvatlev, aga kui mõelda mis kõik sinna taha läheb, ei ole seda meie paki avamisrõõmu väärt. Kõik kindlasti mõtlevad, et mis see üks tellimus ikka paha teeb. Ei mõelda sellele mis seal Hiinas toimub: kuidas neid asju valmistatakse, kes neid valmistab, kuidas neid pakendatakse ning kuidas need üldse Eestisse jõuavad. Inimesed, kes Hiinas nendes tehastes töötavad, ei saa oma töö eest õiget palka ning CO2 mis pakkide lennutamisest ule maailma tekib on väga suur ja ebavajalik.\nAga kuidas piirata Hiinast tellimist? Enamus kes Hiinast igasuguseid mõtetuid asju tellivad ongi just noored. Nemad veel ei mõtle et nende pakk teeb planeedile kahju ja tulevikus hakkab see ka neid mõjutama, nemad lihtsalt näevad neid odavaid hindu ja trende mis nad sotsiaalmeedias näevad. Sellise probleemi vähendamiseks olekski vaja noortele selgeks teha kui suur kahju tellimisest tegelikult tuleb. Mina nõustun moedisainer Eve Hansoniga, noored tuleks viia taaskasutuskeskustesse ja näidata neile kui palju ületarbimist tegelikult toimub. Oleks mõistlik ka suurtel suunamudijatel noortele rääkida ja neid suunata paremate harjumusteni. Kindlasti see ei lahendaks tervet probleemi, kuid ka meie kõigi väike panus oleks suureks abiks.\nKokkuvõtteks on tänapäevane sostsiaalmeedia meie planeedile suureks kahjuks, noored ei saa aru mis kahju nad tekitavad ja kõigil meil on mingigi harjumus mida me muuta saaks, et meil kõigil oleks siin planeedil hea elada. Tuleb leida võimalusi näitata inimestele mis tegelikult toimub ja kui kahjulik see on. Aga seniks kuni kõik me oma harjumusi ei muuda, erilist paranemist sellel probleemil ei ole.');
