INSERT INTO core.text(id, content)
VALUES ('3dfb75ac-7ee1-457f-8bea-a101cbbfe88f',
        'Tänapäeval on maailma üks suurimaid probleeme ületarbimine. Mure seisneb selles, et suurem osa inimesi isegi ei tea, et ka nemad tarbivad üle ja on osa probleemist. Kuidas saame oma tarbimisharjumusi parandada ja miks peaksime seda tegema?\nOma tarbimisharjumusi pole tegelikult raske parandada, peab lihtsalt natuke rohkem mõtlema ostude üle. Näiteks, kui käija poes, siis tuleb vaatada ennem kassase minekut oma ostukorv üle ja mõelda, kas seda kõike on tõesti vaja?  Kui jõuab juba olukord kohale, kus tead, et ei jaksa toitu ära süüa ennem kui see riknema hakkab, siis tuleks see toidupangale annetada või hoopis pakkuda seda oma naabritele! \nParatamatult avaldab meie tarbimine suurt mõju loodusele. Kliima muutub, loomade elukohad hävivad ja selle tõttu surevad paljud liigid välja või on ohustatud. Lisaks on ka osadel kiirbrändidel, eetilised tavad küsimärgi alla seatud. Näiteks kasutatakse mitmel pool maailmas tootmiseks endiselt lapstööjõudu. Kui jätkata samas tempos, siis võivad olla lõpptulemused katastroofilised kõigile, nii loodusele, loomadele kui ka inimestele.\nJärelikult, on väga väikeste muutustega juba võimalik parandada maailma ja tuleb hakata oma tarbimisharjumuste kallal töötama juba täna, et parandada meie tuleviku. Kui töötada üheskoos, saame inimeste tarbimisharjumusi parandada drastiliselt.');
