INSERT INTO core.text(id, content)
VALUES ('8c31a79d-8d4e-4706-95ef-edf47e975050',
        'Iga inimene tarbib asju, kas siis toitu, riideid, võid muid asju mis nad ostavad. Inimesed võtavad seda kõike juba enesestmõistetavalt ja ei mõtle selle peale, mis juhtub kui see kõik lõpuks otsa saab.\nKõik inimesed tarbivad midagi ja üks kõige suuremaks tarbimis probleemiks on toidu tarbimine. Inimesed ei mõtle selle peale, et maailma rahvastik aina tõuseb ja tarbijaid tuleb aina rohkem ehk toitu läheb aina rohkem. Inimesed ei pea ka lugu toidust. Nad viskavad toitu ära või lasevad sellel halvaks minna seda mitte ära süües. Igaüks võib küll mõelda, et kui ta natuke toitu ära viskab, siis suures pildis see ei muuda midagi, aga see natuke tuleb keskmiselt Eesti inimese peale aastas kokku 61kg toidujäätmeid.\nInimesed ei raiska ainult toitu vaid ka muid tarbekaupu nagu näiteks riideid. Mõned inimesed ostavad endale riideid, kannavad paar korda ja siis viskavad ära mis siis, et need näevad veel korralikud ja kantavad välja. Keegi ei mõtle selle peale, et nende riided võivad küll ilusad välja näha, aga nad tegelikult koosnevad naftast ja selline raiskamine jätab jälje.\nInimesed võtavad asju liiga iseenesest ja ei mõtle kui suure jälje oma tarbimisharjumustega ühiskonnale jätavad. Kõik peaksid oma toidu tarbimist jälgima ja selle raiskamist vältima. Inimesed ei tohiks osta riideid, et paar korda neid kanda ja siis ära vista, sest see jätab suure jälje ühiskonnale.');
INSERT INTO core.text_property(text_id, property_name, property_value)
