INSERT INTO core.text(id, content)
VALUES ('9a061086-4797-4048-8e79-e0dccb2984b8',
        'Mida rohkem läheb aeg edasi, seda rohkem muutuvad inimesed heaoluriikides sõltuvaks pidevast ostmisest ja tarbimisest. Mida see kõik endaga kaasa toob? Kuidas sellest hoiduda?\nTarbimine ja ostmine on meeletult kahjulikud inimkonnale. Juba praegu on näha meeletuid tagajärgi, mis on kõik inimeste süü. Tihti levinud argument liigse tarbimise vastu on see, et see rikkub loodust, kuid minu arvates on võib-olla isegi suurem probleem lapstööjõud. Riikides, mis toodavaid riideid suurtel kogustel on tihti probleeme lapstööjõuga, kohtades nagu Hiina on inimesi, kellele ei maksta õiglast tasu ning tihti töötavad nad liiga kaua. Meie ühiskonnana oleksime pidanud sellistest asjadest edasi liikuma juba sadu-aastaid tagasi. Kõik see ongi  põhjustatud tarbimise pärast, kui keegi neid asju ei ostaks, siis peaksid sellised asutused kiirelt sulgema ja pikkas perspektiivis läheks ka asju vähem raisku.\nMoedisainer arvab, et me peaks hakkama tegema Eesti noortele ekskursioone ladudesse, et nad näeksid palju asju läheb raisku. Minu arvates oleks see hea idee, kuid sellega kaasneks ka mõni probleem. Etteheide sellele oleks, et need ekskursioonid peaksid toimuma ülemaailmselt, mitte ainult Eestis, kuid kuskilt peaks ikkagi alustama ja ma arvan, et vähemalt meie riigile tuleks selline ai kasuks.\nKokkuvõtteks on tarbeühiskond ja sellega kaasnevad asjad inimkonnale suureks probleemiks. Selle peatamiseks on vaja noori sellistel teemadel harida.');
INSERT INTO core.text_property(text_id, property_name, property_value)
