INSERT INTO core.text(id, content)
VALUES ('48b98e59-0b73-41d9-ba0c-095fe51c350c',
        'Kõigil inimestel on oma tavad ja harjumused, millega oleme harjunud ning nende muutmine võib olla keeruline. Siiski on oluline jälgida, kuidas ja mis moodi mõjutavad meie harjumused planeeti. Aga millised faktorid mõjutavad meie planeedi heaolu?Kuidas saaks neid harjumusi muuta ning millega asendada?\nKindlasti on toit vältimatu osa tarbimisharjumustest, kuid siiski on võmalusi, kuidas ka selles osas planeeti säästa ja hoida. Ma usun, et jõukamatel inimestel on toidukulu suurem, sest neil on ressursse mille eest endale seda lubada ning see tõttu on valik suurem. Toidukulu ja raisku minemise juures saaksime aidata üksteist ja seal juures ka planeeti, toidukappide kujul. Sel juhul saaksid aidata inimesed kellel on toitu üle inimesi kes on näljas ning seal juures ei läheks midagi raisku.\nTänapäeval on valik taaskasutuspoodides nii võrd hea, et inimestel ei tohiks olla põhjust miks mitte mingit osa oma riietest sealt osta. Riiete ringlus annab ka kiirmoena toodetud riietele uue võimaluse ning isegi kui riide tootmine on keskkonnale kahjulik, on siiski võetud selle elu east maksimum. Kuid kui ikkagi osta mingi osa riietest uuena siis eelistada looduslikumaid materiale kuna siis on riidel looduses lagunemis võimalus. Samuti oleks mõistlik, eelistada kodumaist käsitööd kuna sel juhul on transpordi kulu ja reostus väiksem võrreldes näiteks hiinast tellitud esemega. Selliseid muudatusi on lihtne teha kuid see säästab nii planeeti kui ka raha.\nMuudatusi harjumustes on keeruline teha, kuid on väiksemad võimalused kuidas planeeti säästa, näiteks eelistades kodumaist. Samuti on võimalus aidata oma ülejäägiga inimesi kes vajavad seda ning anda riideid ringlusesse- need võimalused aitavad anda esemetele, toidule või näiteks riietele maksimaalse kasutuse.');
