INSERT INTO core.text(id, content)
VALUES ('1c319d33-0306-40f0-b0fb-557c75a44ad5',
        'Tänapäeval suureks probleemiks, kuid ka trendiks, on ületarbimine. Sellega seotud on ka toiduraiskamine. Tihti ei mõelda, kui palju see mõjutab ning koormab loodust.  Need on probleemid, mida ei ole võimalik lahendada üleöö ning olenevad palju inimeste enda tahtest ennast parandada.\nToitu on lihtne raisata. Me ei mõtle igapäevaselt sellele, et maailmas on palju inimesi, kes nälgivad ning ei saa igapäevaselt süüa. Enamus inimeste jaoks on toit iseenesest mõistetav osa elust. Nagu ka tekstis mainitud, raiskab keskmine Eesti inimene oma toidujäätmetest 42%. See on tohutu hulk arvestades seda, et 61kg-st moodustab see 26 kg. Mõeldes sellele, kui palju resursse ja raha on läinud nende toodete peale, on seis päris kurb.\nHetkel eelistame kvantiteeti kvaliteedile. Olukord peaks olema vastupidi. Läheme kaasa iga trendiga, mida näeme sotsiaalmeedias. Kõik reklaamid on väga suured mõjutajad. Tihti osteldes ei mõtle me sellele, kas meil üldse on neid uusi asju vaja. Tahame saada kõike soodsalt ning seetõttu suundumegi kiirmoe juurde. Asi millele me aga ei mõtle on see, et taaskasutuspoodides leidub nii palju asju, mis ükshetk kõik raisku lähevad.\nKokkuvõtteks ütlen, et ühiskond peaks uuesti hindama oma tarbimisharjumusi. Kõik raiskamine, mis tänapäeval toimub, toidu kui ka riiete, koormab loodust väga. See raiskab ka meie enda raha ja resursse. Peame võtma aega, et rohkem hoolida');
