INSERT INTO core.text(id, content)
VALUES ('b4e1779c-068e-47de-9b70-ff81b5c3af8c',
        'Tarbimisharjumused on kõigil erinevad. Tarbimine võib jaguneda mitmeks erinevaks osaks, aga põhimõte jääb samaks. Tarbitakse mingisugust toodet ja peale selle kasutamist visatakse see ära või viiakse taaskasutuskeskustesse. Neid teisi inimesi on üllatavalt vähe. Aga kuidas seda muuta?\nKuna väga paljud inimesed tegelikult ei tea kui palju prügi iga Eesti elaniku kohta keskmiselt tekib, on neil raske lihtsalt aru saada, mida nad valesti teevad. Võib mõelda, et mis see üks pooleldi söödud banaan või näiteks parim enne kuupäeva läbinud piim, mis on tegelikult täiesti joodav ikka teevad, kui ära visata, aga reaalsuses seda ei juhtu ainult mõni kord, seda teeb iga inimene kilogrammide viisi. Eespool välja toodud mõtteid peaks kasvõi mingi sotsiaalmeedia kaudu kajastama suuremale rahva hulgale, et kõik selle kohta rohkem teaksid ja enda harjumusi muutma hakkaks.\nSama lugu on ka kahjuks riietega. Probleem seisneb selles, et tellitakse oma riideid kusagilt kaugelt Hiinast. Me oleme kõik seda teinud, see on väga mugav ja kiire lahendus, aga jällegi ei mõelda tagajärgede üle. Ma pean silmas tagajärgi, mis nad ise põhjustavad. Kui saad oma valitud riideeseme kätte, võib see olla liiga väike, vale värvi, ebameeldiv materjal jpm. Esimene mõte ei ole see kellelegi ära anda või viia taaskasutuskeskustesse. Hakatakse otsima tagasimakset, mida enamus kordadest ei saa tegelikult, ja siis visatakse see lihtsalt ära. See on ka asi mille peale paljud ei mõtle või mida nad ei teagi.\nMinu arvates on nende probleemide lahendus kõigi Eesti elanike kätes, aga neid võiks ka õpetada kuidas neid lahendada. Halvad tarbimisharjumused on kahjulikud nii keskkonnale kui ka meile endale.');
