INSERT INTO core.text(id, content)
VALUES ('c92290d2-3c9c-4b81-99fa-b435b0a158a3',
        'Inimestel on palju tarbimisharjumusi. Paljud inimesed hakkavad midagi tegema ja sellest jääb harjumus. Näiteks toidu raiskamine või riiete ära viskamine. On palju asju, mida inimesed teevad, aga ise seda enam ei märka, sest see on neile harjumuseks jäänud. Aga mis on paljud tarbimisharjumused?\nVäga paljudel on harjumus, et võtavad liiga palju toitu ja pärast ei jaksa seda kõike ära süüa, seega nad viskavad toidu ära. Aga tegelikult on palju viise, et toitu mitte raisata. Näiteks saab toidu panna komposti, mis hiljem saab mullaks teha ja seda saab kasutada taimede kasvatamisele. Mina näiteks annan oma järelejäänud toidu koerale. Tegelikult on väga palju võimalusi, et toitu mitte raisata.\nMõndadel inimestel on ka harjumuseks see, et nad viskavad prügi maha ja ei korja seda üles. See on väga kahjulik loomadele ja loodusele. Selline tegevus reostab tõeliselt loodust. Sellist probleemi saab kergesti lahendada. Näiteks inimesed saavad korjata oma prügi ülesse või teised inimesed saavad aidata, et korjata teiste prügi ülesse, mis väga aitaks kaasa looduse hoidmisele.\nInimestel on väga palju tarbimisharjumusi ja neid saab tegelikult kergesti vältida. Erinevaid viise on, et vältida toidu raiskamist või riiete ära viskamist jne. Igal inimesel on mingi oma harjumus, mida nad enam isegi ei märka et nad seda teevad. Seega peaagu igat harjumust saab tegelikult vältida, aga sa pead tõsiselt ise ka tahtma seda.');
INSERT INTO core.text_property(text_id, property_name, property_value)
