INSERT INTO core.text(id, content)
VALUES ('a9f3906a-82f9-4422-96ce-b06e4128187d',
        'On teada et tänapäeva inimesed tarbivad rohkem kuieelmised põlvkonnad.Uute tehnoloogiatega on inimeste tarbimine ja elukvaliteet kasvanud mitmekordselt võrreldes eelmiste sajanditega.Küsimus on selles kas tänapäeva inimeste tarbimisharjumised on jätkusuutlikud või mitte?\nKiir mood on nimi antud moele mis on kiiresti ja odavalt tehtud et tänapäevasele populaarsele meediale müüa.Tavaliselt pole need riided tehtud kvaliteediga ja võivad ära laguneda kiiremini kui tavalised riided.On ka transporti kulud loodusele ja hinnale.Kõige mõtekam oleks piirata oma kulutamist ja osta lähedamalt oma riideid kui võimalik.“Ei telliks Hiina veebipoodidest juba põhimõtte pärast asju,ei läheks kaasa sooduskampaaniatega.Eelistada võiks kodumaiseid oma lähedal toodetud asju ning pigem vähem kui rohkem.“Lisas Eve hanson.\nToidukaos on kui inimesed raiskavad toitu,sest nad saavad seda endale lubada ja saavad alati rohkem osta.Kodumajapidamises tekib iga Eesti inimese kohta keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 42 protsenti ehk 26 kg.Siukene tarbimine ja toidu raiskamine ei ole jätkusuutlik,toidukaost ei raiska me ainult seda toitu,me raiskame ka muid ressurse mis oli vajalik selle toidu saamiseks:maad,vett,energiat ja tööjõudu.\n´Järeldusena ei ole tänapäevase inimese tarbimisharjumused jätkusuutlikud.Me peame liigume ära kiirmoest ja piirama oma ostmist ning raiskama vähem toitu et säästa loodust ja ühiskonda.');
