INSERT INTO core.text(id, content)
VALUES ('fd96e0f8-d73b-4fad-9534-613b14544685',
        'Inimesed tarbivad palju erinevaid asju ja teenuseid, olgu need riided, toit ja nii edasi. Iga aasta räägitakse inimeste tarbimisharjumustest ja selle kahjust. Samuti läheb ka iga aastaga suuremaks asjade äraviskamine, mis on kahjulik loodusele. Selles kirjandi ma püstitan probleemi „Missugused on inimeste tarbimisharjumused?“\nIga päev ostetakse ja raisatakse toitu igas majapidamises. On leitud, et Eestis tekib 61kg toitu, millest 26kg ei tarbitagi. Toidu tegemisega kulutatakse ressursse, nagu vesi maa ja tööjõud. On palju perekondi ja inimesi , kes ei teeni piisavalt, et ennast üleval pidada. Selle pärast ei jätku neil raha toiduks, riieteks, hügieentarveteks ja kõigeks muuks. Õnneks on Eestis ja ülekogu maailma erinevad asutused, kes saavad selliseid peri ja inimesi aidata. Üks nendest on Toidupank, kus inimesed saavad panna pikalt säilivalt toiduaineid, nagu kuivained ja konvervid.  Samas on inimesi ja perekondi, kus suurene toiu äravisakmine on täiesti normaalne. Poes ostetakse liiga palju asju kokku ning selle tõttu ei sööda seda kõike ära. Inimeste tarbimisharjumused toidu suhtes on suur probleem, mida peab vähendama. Kui märkad poes või kodus, et oled liiga palju toitu ostnud ja tead, et sa seda ära ei söö, vii see inimestele, kes oleksid toidu üle väga rõõmsad.\nMina ei tarbi väga palju. See on mõjutatud paljudest asjadest. Esiteks mulle ei anta palju taskuraha, mistõttu ma ei saa osta väga palju ja pean oma rahakulutamist planeerima.Teiseks oma minu riidekapp ääreni täis, seega ei mahuks uued riided kappi ära. See on eriti hea erinevates riidepoodides, kui ma näen lahedat asja, mida tahaks osta, samas teades, et ei saa seda teha. Samuti ei tarbi ega kuluta suuresti minu perekond. Elan koos oma emaga, sellepärast ei ole vaja palju osta. Teeme iga nädal söögiplaani, kus vaatame, mida iga päev sööme. Samuti ei osta me eriti riideid ja muid asju. Nende asjade pärast suudangi oma kulutusi ja tarbimist vähendada.\nUsun, et inimeste tarbimisharjumusi on võimalik vähendada. Selleks peavad inimesed oma harjumustest lahti ütlema ja mõtlema keskkonaasõbralikumalt. Tuleb rohkem hakata mõtlema inimestele enda ümber ning vaadatada, kas sa saaksid midagi nende heaks teha. Usun, et saame palju ära teha, kui paljudel inimestel on samad soovid ja ideed. Sellepärast on võimalik inimeste tarbimisharjumusi vähendada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('fd96e0f8-d73b-4fad-9534-613b14544685', 'title', 'Missugused on inimeste tarbimisharjumused?');
