INSERT INTO core.text(id, content)
VALUES ('8c76348f-acca-42db-819f-8293a2464d62',
        'Tänapäeval on väga suureks probleemiks inimeste tarbimine ja sellega kaasnev raiskamine. Meile on iseenesest mõistetav, et kõik on kättesaadav ja olemas, aga kui see saadaval on ei tähenda, et me peame seda suures koguses koju ostma. \n          Toidu raiskamisest on saanud trend. Väga paljud inimesed viskavad ära heas korras ja söödavat toitu. Marketid ja poed lasevad raisku tuhandeid kilosi toitu iga aasta. Suure raiskamise ja korras toidu ära viskamise pärast on tegutsema hakkanud sellised inimesed, kes käivad suurte keskuste prügikastide juures ja otsivad korralikku toitu mida nad tarbida saavad.\n            Raiskamine ja ületarbimine ei ole probleem ainult toiduga ,vaid ka riietega. Enamus kiir-moe brändid, nagu H&amp;M, ZARA jne, toodavad väga kehva kvaliteediga riideid ,mida saab kanda lühikest aega. Seejärel visatakse need lihtsalt prügikaste ja nad lõpetavad kusagi meres,ookeanis või hoopis mõnel soojal maal suures riide hunnikus.\n            Inimestel tuleb aru saada, et kui me sedasi jätkame, ei ole meie maailmast varsti enam midagi alles. Rahval tuleb hakata kokkuhoidlikumalt elama. Kellelgi ei ole vaja 8+ paari teksasi või 10+ jopet. Me oleme loonud tarbimisühiskonna, mis rikud meie planeeti ja nüüd on meil vaja asju muuta, et tulevased generatsioonid saaksid siin rahulikult elada.\n             Tarbimisharjumused on suur probleem, mis on seotud nii toidu, riiete kui ka igapäevaste asjadega. Selleks, et planeeti säästa ja inimeste elu mitte rikkuda, tuleb meil töötada koos ühise eesmärgi nimel.');
INSERT INTO core.text_property(text_id, property_name, property_value)
