INSERT INTO core.text(id, content)
VALUES ('0f70d3f5-2362-42cd-b442-184366d88617',
        'Tänapäeva ühiskonnas on väga esile kerkinud tarbimisühiskond. Oleme harjunud kättesaadavusega: toidupoodides on võimalik soetada peale kodumaise ka välismaise kõhutäie ja riiete ostmiseks ei pea isegi oma mugavast tugitoolist tõusma, piisab internetikauplustest, kus on kogu kaup vaid klõpsatuse kaugusel.\nKiirmood on rikkunud inimeste tarbimisharjumused. Sotsiaalmeedia on tohutult muutnud inimeste arusaamist moest ja stiilist. Ühest küljest on see hea, sest leidub palju inspiratsiooni, kuid teisest küljest on see kilbile tõstnud üüratu raiskamise.  Ühismeedia kättesaadavus ja suunamudijate suur hulk on teinud ühe trendi pikkuseks vaid mõned nädalad, see tähendab, et võime osta eseme kauplusest ja kanda seda mõni nädal, kuni too ese pole enam moes ja sellise eseme kandmine on sotsiaalvõrgustiku sõnade järgi „piinlik.“ Sellist käitumist soodustavad veelgi enam netikaubamajad. Ainuüksi kuulus internetikaubamaja Shein toodab 6000 uut eset päevas. Enamus nendest esemetest jõuavad varem või hiljem prügimäele. \nToidukadu on tingitud lihtsast kättesaadavusest. Nagu sissejuhatuses mainitud on tänapäeval võimalik hõlpsasti ligi pääseda suure hulgale maitseelamustele: seda linnatänavatel, kus on suur hulk restorane või ka ostukeskustes, kus on kohvikuid ja toidupoode küllaga. Veebilehelt tarbitoitutargalt.ee leiame infot, et kodumajapidamises tekib iga Eesti inimese kohta keskmiselt 61kg toidujäätmeid, millest toidukadu moodustab 42% ehk 61kg. Kui iga inimene muudaks oma rutiini niivõrd palju, et ei laseks end mõjutada massilisest valikust, saaksime toidukadu vähehaaval langetada.\nTarbimisühiskond on tingitud kergest ligipääsust paljudele toodetele. Riiete tootmises väljendub see trendide kiirest muutumisest sotsiaalmeedias ja internetikaupuste olemasoust. Toiduvaldkonnas väljendub see massilises valikus.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('0f70d3f5-2362-42cd-b442-184366d88617', 'title', 'Kuidas on tarbimisühiskond seotud tarbimisharjumustega?');
