INSERT INTO core.text(id, content)
VALUES ('bc9d1754-fe16-4c99-86eb-bfc5795af398',
        'Toit on elusorganismi jaoks üks kõige vajalikumaid osi, kuid me ikka tihti peale rasiskame seda või ei kasuta seda efektiivselt. Miks see nii on? Mina arvan, et selleks on kolm peamist põhjust. Me ostame liiga palju toitu, mida me ära ei tarbi, me viskame ära toiduaineid, mida saaks veel ära kasutada ja me ei viitsi sorteerida.\nEsiteks, me ostame liiga palju toiduaineid, mida me ära ei tarbi. Inimesed poes käies tihti peale ostavad pigem toiduaineid rohkem, kui vähem. Mina arvan, et see võib olla hirmust, et see saab neil kohe otsa. Soodus tooted on ka need mis panevad ostma. Näiteks minul endalgi oli olukord, kus ostsin endale liiga palju ühte uut jooki, mis just oli välja tulnud, lõpuks ei tahtnud ma enam seda jooki, sest mul sai sellest küllalt ja viskasin selle lihtsalt ära. Me ostame toiduaineid liiga palju, meil saab neist üks hetk nii-öelda kopp ette ja me viskame selle lihtsalt ära ehk me kulutame toitu.\nTeiseks, me viskame ära veel kõlblikke ja kasutatavaid toiduaineid. Inimesed tihti peale ei tea, kui palju saab ühest või teisest toiduainest veel midagi teha või kuidas neid lõplikult ära kasutada. Kõige kergem viis, kuidas toiduainet lõppuni ära kasutada on see, kui saame selle lihtsalt näiteks kompostihunnikusse visata, aga kõigega nii ei saa, kuid sellel on lahendus. Meil on sotiaalmeedias igasuguseid rohe sõbralikke ja ökoinimesi, kes teevad õpetusi, kuidas mitte raisata toiduaineid. Me ei kasuta ära toiduainete täielikku potentsiaali, kuid sellele on lahendus.\nKolmandaks, me ei viitsi sorteerida. Sorteerimine aitab toiduained eraldada muust prügist, mis omakorda aitab neid toiduaineid ka taaskasutada näiteks kompostiks. Kui meil Eestis ei oleks neid sorteerimis reegleid, kas siis me sorteerikisme või oleksime laisad. Mina arvan, et pigem oleksime laisad. Näiteks mina ei viitsi väga sorteerida ning mu vanemad vingusid selle üle, kui me Eestis pidime hakkama sorteerima. Me inimestena ei viitsi sorteerida, kuidki me peaksime, sest siis saame taaskasutada ülejäänud toiduaineid.\nKokkuvõtteks osakan öelda, et me inimestena võiksime rohkem vaeva näha ja mõelda ette, mida ja kui palju me ostame, sest muidu me lihtsalt raiskame toitu. Me peaksime rohkem ära kasutama toiduainete täis potentsiaali, õppides seda sotsiaalmeediast. Me peaksime rohkem eraldama toiduaineid muust prügist, et seda saaks taaskasutada.');
