INSERT INTO core.text(id, content)
VALUES ('1f75a067-01db-4d76-a92b-fd5cbdaafa7d',
        'Ülemaailma tellivad täiskasvanud kui ka noored endale hiina poodidest asju, millega nad ju tegelikult isegi ei tee midagi. Nad tellivad suurtes kogustes asju, aga mitte keegi ei saa ise aru, et tegelikult nad isegi ei tea, millest on see tehtud ja, kas need asjad on üldse kasulikud nende jaoks. Lõpuks kui nad sellest aru saavad, et neil pole mitte midagi nende asjadega teha, viivad nad selle kauba taaskasutusse ja teevad seda sama viga otsast peale.\nNii paljud inimesed panevad oma rasket teenitud raha, hiina poodidesse odavate asjade peale, mille nad viskad ära jne. Samas kui kõik inimesed ostaksid odavaid asju hiina poest ja viivad taaskasutusse siis, kes ostab näiteks neid riideid taaskasutusest? Reaalsuses kui me vaatame siis mitte keegi, sest isegi kui me leiaksime taaskasutusest endale korralikud riided, siis oleks nendega ju piinlik ringi käia, sest kui keegi küsib nende riiete kohta, siis tegelikult mitte keegi ei julgeks öelda, kust me need riided tegelikult saime.\nMinu ema näiteks tellib endale igalt pool ülemaailma asju, aga muidugi on need asjad hunnikus kusagil kapi peal, sest tegelikult ta ei tea ju, mida nende asjadega peale hakkata. Ainult mõned üksikud asjad on, mida kasutatakse, aga tõesti need isegi ei pea nii kaua vastu, sest need on nii halvasti tehtud ja lähevad katki. Siis tehakse jälle seda sama viga. Ostad, kasutad, läheb katki, viskad ära ja siis jälle otsast peale ja sellest veast ei õpi mitte keegi. Tegelikkuses on seda kahju vaadata pealt, kui kõnnid kusagilt taaskasutuspoest mööda ja näed, kuidas terve pood on riideid täis ja mõni üksik vananaine vaatab seal ringi.\nMida ma tahan sellega öelda on see, et inimesed võiksid jälgida seda, mida nad tellivad internetist ja, milleks nad seda tegelikult kasutavad. Võiks ju natukenegi oma rasket teenitud raha austada. Mõelda tähtsamatele asjadele, mida reaalselt oleks vaja. Mitte keegi tegelikult ei tea, mis saab vanadest riietest, mida lihtsalt ära ei osteta. Selle pärast võikski juba varakult noortele teha ekskursioone taaskasutuspoodide lattu, et näha kui palju korralikke riideid läheb raisku.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('1f75a067-01db-4d76-a92b-fd5cbdaafa7d', 'title', 'Miks peaks tegema ekskursioone taaskasutuspoodide lattu?');
