INSERT INTO core.text(id, content)
VALUES ('6037cf81-163b-4b50-856e-4014657cca52',
        'Tänapäeval on väga suureks probleemiks raiskamine. Sellest räägitakse enamjaolt halvasti, kuid vaatamata sellele näeme raiskamist enda ümber iga päev. Miks see nii on ning kuidas seda muuta?\nArvan, et paljud inimesed ei mõtle, kust ja kuidas tulevad riided ning toit, mida nad poest mugavalt ostavad. Nad ei arvesta, et nende õhtusöögi jaoks on tapetud mõni veis või nende kleidi eest on õmbleja saanud alaväärset palka. Inimesed ei näe asjade, nagu lihtne õhtusöök või riietus, tegelikku väärtust- seetõttu on nendest samadest asjadest tunduvalt lihtsam ilma negatiivsete emotsioonideta loobuda.\n„Ei telliks Hiina veebipoodidest juba põhimõtte pärast asju,“ on öelnud moedisainer Eve Hanson saates „Vikerhallik“. Kuida seda mõista? Tavaline on osta endale iga kuu halva kvaliteediga teksapüksid, kui osta iga paari aasta tagant ühed kvaliteetsed. Lisaks kehvale kvaliteedile on kiirmood väga odav, mistõttu võimaldavad seda endale peaaegu kõik. Säärased asjaolud loovad meile ühiskonna, kus on normaalne iga kuu oma riidekappi värskendada ja vanad riided lihtsalt ära visata.\nMida inimesed ei tea, on see, kui katki on meie planeet meie halbade tarbimisharjumuste tõttu. Tehastest ning masinatest tulevad heitgaasid mõjutavad meie toitu aga ka meie kõige kallimat vara- meie tervist. Lisaks teevad kiirmoe tehaste töötajad oma tööd väga halbades tingimustes ning saavad selle eest väga madalat palka. Toidu jaoks tapetakse loomi, linde ja kalu. Paljudes riikides koheldakse ka põllutöölisi väga alandavalt. Seda kõike selleks, et inimesed, kes seda ei näe ega kuule, end mugavalt tunneksid.\nSeega arvan, et inimeste halvad tarbimisharjumused on tingitud teadmatusest, kust tooted meieni tegelikult jõuavad. Kui kõik teaksid kõige tegelikku väärtust, oleks maailmas kindlasti kordades vähem raiskamist ning teadlikku tarbimist. Kuni mitte keegi selle heaks midagi ei tee, ei muutu mitte miski paremaks. Kõik algab meist ja meie enda tarbimisharjumustest.');
