INSERT INTO core.text(id, content)
VALUES ('444e25fe-0752-455f-b99c-a61833164eff',
        'Inimene on aegade algusest tahtnud kaunis ja moodne välja näha, sama on lugu ka tänapäeva maailmas. Kuid meie ajal on see soov võtnud hoopis teise ilme, milleks on ületarbimine.  Sotsiaalmeedias näeme suunamudijaid, kes peaaegu iga nädal ostavad vähemalt kümme uut riideeset – mis kohe peale üht kasutust prügikasti näeb. Ka tavakodanikul on selline harjumus külge kasvanud. Kuid selle harjumuse tagajärjel satuvad riided loodusesse ning reostavad maid ja veekogusid.  See, et riideese on ära visatud, ei tähenda et rõiva elu on läbi, vaid nüüd on tema hädaks loodusele. Aga miks see kõik siis niimoodi on? Miks on inimesel vaja kõiki rõivaesemeid raisata?\nVanasti kestsid moetrendid kas kümnendi või isegi mitu aastakümmet, aga tänaseks päevaks on trendide eluiga väga palju lühenenud. Nüüd võib üks trend kesta ainult nädal aega. Kuna inimene on sotsiaalne loom, on tal vaja teistega sarnane olla, seega kui teised inimesed ostavad ühel nädalal endale uue moodsa kampsuni, tahab inimene ka seda endale soetada. „Kõikidel mu sõpradel on see sama kampsun, võiksin ise ka selle osta!“ mõtleb see sama inimene. Aga siis tuleb välja, et järgmiseks nädalaks on kampsun hoopismoest väljas, keegi ei taha sellest isegi kuuldagi. Pole muud teha kui see ära visata, sellega pole midagi enam peale hakata.\nTänapäeval on populaarseks muutunud internetipoed nagu näiteks Temu ja Shein. Tegemist on väga odavate poodidega, kust ostetakse palju rõivaid, eriti just sooduskampaaniate ajal. Siis on just nii-öelda „kõige kuumemad hinnad“ ja tekib vajadus kampaaniaga kaasa minna. Aga nende poodide õmbluskodades käib töö lööklause „kvantiteet üle kvaliteedi“ järgi: Bangladeshis või Hiinas töötavatele õmblejatele ei maksta peaaegu midagi ning töö peab kiire ja tõhus olema. Ei kontrollita, kas tegemist on kvaliteetse tööga, järelikult saab öelda, et peale üht-kaht kasutust tuleb rõivad ära visata. Ka minu pere pole selles probleemis osalemises päris süütu, kuna mu ema näiteks on paar korda tellinud rõivaid Shein`ist.\nRõivaste ületarbimise probleemi on keeruline lahendada, kuna miljonid inimesed osalevad selle jätkamises. Aga igaüks võib anda oma panuse, näiteks pole vaja moetrendidega kaasas käia ja tuleb osta kvaliteetseid riideid, mida tead, et kindlasti kannad. Kõigil on omad põhjused, aga need ei õigusta ületarbimist, eriti just ülaltoodud põhjused.  Tuleb keskkonna eest hoolitseda ja mitte riideid ilma asjata ära visata. Inimene saab ilusasti riietatud olla ka siis, kui ta trende ei järgi ja Hiina veebipoodidest odavaid riideid ei telli.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('444e25fe-0752-455f-b99c-a61833164eff', 'title', 'Miks on vaja riideid raisata!?');
