INSERT INTO core.text(id, content)
VALUES ('4ba99099-4f74-44e6-8e5c-d37b1dccf5c8',
        'Kas oled kunagi kuulnud, et toitu on palju ja see ei saa kunagi otsa. Inimesed raiskavad toitu, sest nad lubavad endale seda, aga nad ka samas arvavad, et väiksemaid koguseid toitu nad ära viskavad, et sellest pole midagi. Aafrikas on elundkondi kellel pole ültse midagi süüia, või on vaesaid perekondi kes saavad vevu süüia osta. Eestis inimesed raiskavad aastas keskmiselt 61 kg toidujäätmeid ja veel ei raiska ainult toitu vaid raiskavad ka oma enda teenitud raha ja veel raiskavad muid ressurse: maad, energiat, vett ja tööjõudu. Inimesed mitte kui ei viska ainult toitujäänuseid ära, vaid nad kas jättavad ostetuid riiteid kappi seisma või viskavad need lihtsalt minema.\n  Koolid peavad hakkama noortele ekskursioone taaskasutuspoodide lattu, et näidata, milline raiskamine toimub, aga ka täiskasvanutele tuleb ka näidata millist raiksamist nad teeva kui nad viskavad toitujäänused ära. Eve Hansoni arvates on väga tähtis, et igaüks vaataks üle oma isiklikud tarbimisharjumused ning eelistaks kvaliteeti kvantiteedile. Inimesed peavad oma riideid mida nad enam ei kanna, hakkama ära  annetama nendele kellel on väga vaja näiteks vasetele, sest nemad ei saa osta ilusaid riiteid või ei saa ültse osta. \n       Kokkuvõtteks võib öelda, et Eesti inimesed raiskavad keskmiselt aastas 61 kg toidujäätmeid ja veel ei raiska nad ainult toidu vaid raiskavad ka ressurse nagu näiteks maad, vett, tööjõudu ja enegriat. Toidu tootmine tektiab tõsise keskkonnakoormuse.\n    Lõpetuseks on see, et Toidu raiskamist ei saa vähendada üleöö. See on paljuski kinni inimeste harjumusest.');
