INSERT INTO core.text(id, content)
VALUES ('15bcba4c-0c1c-494d-8a64-701a7f7e560c',
        'Kui inimeste tarbimisharjumused oleks sellised.Kirjutasin siis on vaja inimestel rohkem teadmisi ja selgust kuidas ja kus kõiki sööke,jooke süüa ja esemeid pana või kasutada.\nMiks inimesed viskavad toitu ära.Kui mõelda inimeste peale, kes ei saagi päevas süüa või saavd kord kuus süüa siis peaksime rohkem arvestama kogustega ja söögi ainetega.Präeguse seisuga jääb „kodu maja pidamises tekinud toidujäätmeid ühe inimese kohta keskiselt 61kg“.Minu kodus on tehtud täpsemaid koguseid ja toit süüakse ära, aga kui jääb alles siis võetakse tööle kaasa ja süüakse mitmeid päevi seda.Kaitseliidus on palju liikmeid, kuid täpset kogust on raske teha selle pärast anetatakse ka toitu inimestele tasuta, et ei peaks raiskama seda suurtes kogustes.\nKui noori viidaks taaskasutuspoodide lattu siis on suurem võimalus, et noored nääksid maailma teistpidi.Mina ise olen käinud ja näinud neid riideid aga ei ole kunagi ostnud, kuigi ei ole riietel midagi viga.Tavaliselt inimesed ei soovi osta taaskasutatuid riideid kuna on kellegi seljas olnud ja ei ole uus, aga tegelikult võiksid inimesed proovida ja uurida äkki saab odavamalt.Kui kunagi oleks nii, et noored viiakse taaskasutuspoodi ja näidatakse kui oluline on riiete ostmine ,kandmine ja puhastamine olulisus kodus ja välismaal.\nNoored tarbivad suurtes kogustes inergiajooke, kuigi ei tea mis nende jookide sees on.Mina ise olen proovinud ja joonud, aga ei tahaks et teised nooremad poisid või tüdrukud hakaksid ka seda jooma kuna, inimesed päriselt ei tea kui palju probleeme on päriselt inergiajookidega. Enamus südamega probleeme on juhtunud just inergiajoogi mõjual.paljudel juhtudel on alaealistega tegu aga täisealised proovivad üksteist proovile panna, või nalja teha ja siis joovad koos alkohooliga ja see annab suurema töö südamele.\nKogusellekirjandi jooksul olen paremini aru saanud kui oluline on elu meile.Kõik esemed,söögid ja joogid meile kui oluline on järeldusi teha ja otsuseid langetada.Loodan, et inmesed muutuvad paremaks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('15bcba4c-0c1c-494d-8a64-701a7f7e560c', 'title', 'Inimeste tarbimisharjumused');
