INSERT INTO core.text(id, content)
VALUES ('f55c5f06-3bc6-4702-9a59-f83c88230a55',
        'Inimesed ostavad poest toitu rohkem, kui neil tegelikult kulub. Me käime poes ja vaatame: „Ohoh, täna on need kotletid soodushinnaga, ma võtan kohe 3 pakki“. Jah, võibolla tegidki ühe pakki kolmapäeva õhtul ära, aga teised 2 pakki leiavad ennast prügikastist, sest need olid aegunud. Miks me siis ikkagi ostame nii palju toitu poest?\nEsiteks näide minu elust. Vaatasin ühel päeval külmkappi ning nägin seal toiduaineid, mida ma polnud õhtusöökides näinud. Esitasin emale küsimuse, et miks me ostame külmkapi asju täis, kui me isegi ei kasuta neid? Ta ei andnudki mulle selget vastust ja ega ma sellest edasi ka väga ei mõelnud. Järgmine päev läksime poodi ja ma tuletasin talle kohe meelde, et täna ostame ainult neid asju, mida me päriselt kasutame ka. Tänu sellele tuli arve väiksem ja külmkapp ei olnud ka enam väga täis.\nTeiseks näide filmist, mis on tõsi ka päriselus. Vaatasin ühte filmi, kus nägin, et tüdrukud arutlesid, et mida nad koolipeole selga panevad. Nad ütlesid, et lähevad kõik koos peale kooli shoppama. Muidugi nad olid rikkad ja ütlesid teistele: „Kas teie siis ei ostagi iga peo jaoks uut kleiti?“, ja et „Me ei kanna kunagi ühte kleiti kaks korda.“ See pani mind kohe mõtlema nende tõsielu saadete kohta, kus näidatakse, et mis seis on vaesetes riikedes, ja et kuidas nad riides käivad.\nMiks me siis ikkagi ostame nii palju toitu poest ja arvame, et iga peo jaoks on vaja uut riietust? Vastus on lihtne, sest me ei ole näinud, mis asi on päris vaesus ja milline on tegelikult olukord vaesetes riikides, kus inimesed võitlevad iga saiatüki eest ning selle eest, et neil midagigi seljas oleks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('f55c5f06-3bc6-4702-9a59-f83c88230a55', 'title',
        'Miks me ostame poest rohkem asju, kui meil tegelikult vaja on?');
