INSERT INTO core.text(id, content)
VALUES ('331f944a-e397-4ece-ad1b-1aca18d54598',
        'Me kõik tarbime erinevaid tooteid, enamus aga tarbib liiga palju. Mis on meie tarbimisharjumused, ja mis kahju me nendega tekitame?\nMida me tarbime ja kui palju? Tarbitoitutargalt veebilehel on öeldud, et kodumajapidamisel tekib iga Eesti inimese kohta keskmiselt 61kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26kg. Selle peale mõeldes, võid arvata, et 61kg toidujäätmeid aasta jooksul ei ole ühe inimese kohta palju, kuid kui arvestad, kui palju inimesi Eestis on, ja kui palju ressursse me kulutame selle toidu tootmiseks, siis taipad, et see kulu on liiga suur.\nMis on ületarbimise kahjud loodusele? Toidu kasvatamiseks on vaja põlde, mille harimiseks peame lõikama maha metsasid, mis segab meie ökosüsteemi: loomadel pole enam pesitsemiskohti, kaovad toitumiskohad ja peidukohad. Põldude harimiseks kasutatakse ka kemikaale ja erinevaid väetisi, mis on loomadele kahjulikud, ja selle tõttu ei saa loomad nende põldude lähistel enam toituda.\nÜletarbimise lõpetamiseks peaksime kõik olema kokkuhoidlikumad ja mõtlema kahjudele, mis me loodusele tekitame: hoiame loodust ja  loomi.\nLõpetuseks tahaksin öelda, et inimesed raiskavad liiga palju, kuid seda saame parandada looduse hoidmisega ja söögi mitte ületarbimisega. Loodust hoides muudame maailma paremaks kohaks meile ja tulevike põlvkondadele.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('331f944a-e397-4ece-ad1b-1aca18d54598', 'title', 'Tarbimisharjumused');
