INSERT INTO core.text(id, content)
VALUES ('417aa893-3154-4ca8-9fa5-206f32e2be04',
        'Inimestel on mitmeid harjumusi, millega kõik peavad kannatama. Harjumused võivad olla igasuguseid, aga nendest halvemad kahjustavad meie elu ja keskkonda, kus elame.\nInimesed võtavad rohkem toitu, kui söövad. See tähendab, et inimesed raiskavad rohkem toitu, kui nad jõuavad süüa. Esiteks meie koolis on toidu ära viskamine suur harjumus, et lapsed võtavad süüa, ja kui neile ei meeldi see, siis nad viskavad selle kohe minema. Teiseks on tarbitoitutargalt.ee sõnanud, et iga eestlase kohta tekib 61 kg toidujäänuseid, millest toidukadu moodustab 42% ehk 21 kg. Seega peaksid inimesed toidu võtma vähestes kogustes ja vähem toitu ära viskama.\nInimeste toidu raiskamise harjumus kahjustab keskkonda. See Tähendab, et mida rohkem inimene tarvitab, seda rohkem peab loodus kannatama. Esiteks toidu valmistamiseks võtab, niigi palju loodusvarasi (puu-, köögi- ja juurviljad). Teiseks me raiskame veel ka energiat ja tööjõudu (masinad ja inimesed) toidu valmimiseks. Järelikult peaksime ka keskkonnale mõtlema, kui me toitu ära viskame.\nInimesed viskavad terveid riideid ära. See tähendab, et riited, mis on korralikud ja kandvad välja. Esiteks on Paides Maksimarketi juures on riiedejäätmehoidla, kus on parajalt riideid alles, mida saaks kanda seljas. Teiseks on Hanson välja toonud, et ta ei telliks Hiinast riideid põhimõtte pärast ja ei läheks kaasa sooduskampaanitega. Ta tahab öelda, et nendest kohtades on riided valmistatud halvast materjalist. Järgmiseks neid riideid, mis jäätmedes vetelevad, saab taaskasutada. Järelikult peaksid inimesed paremast kohast riided ostma ja rohkem taaskasutama neid.\nKokkuvõtteks on see, et inimeste halvad harjumused kahjulikud elu ja keskkonna jaoks. Kui me neid harjumusi eirame, siis hakkavad nende tagajärg meid mõjutama.');
