INSERT INTO core.text(id, content)
VALUES ('4ca3a7f0-e416-4051-8b41-878cab0617f1',
        'Olete te kunagi mõelnud, miks inimesed raiskavad. Igapäevaselt näeme, et keegi raiskab midagi, olgu see toit, riided või muu kasulik asi maale. Paljud inimesed ei märka, et need asjad mida nad tühja käega ära viskavad on mõne jaoks miljoni euro eest. Selles kirjandis proovin selgitada, miks on raiskamine halb.\nPaljudes tööstustes üle maailma raiskavad inimesed oma energiat ja aega tehes meile asju, mida me tahame, aga me ei vaja. Aga inimkond ei näe, et see inimene, kes need asjad meile tegi võis kahjustada enda tervist ja raisata enda aega, kus ta oleks saanud olla enda lähetastega selleks, et me kõik ära viskaks. See ongi probleem, et me tasapisi tapame süütuid inimesi. \nVeel üks proobleem, mida näeme on toidu ära viskamine. Erinevates sööklates on näha, et kilode kaupa toitu visatakse igapäevaselt ära. Inimesed ei mõtle, et toidumaht mida nad ära viskavad, on samaväärne mõne pere kuu mahuga. Inimesed näevad vaeva, et kasvatada toitu ja tuua see poodidesse selleks, et kõik see ära raisata. Inimesed, kes seda toitu ostavad ei mõtle, et toidu ostmine ja raiskamine on sama hea kui raha põletamine. Selle asemel võivad inimesed lihtsalt raha põlema panna ja jätta toitu neile, kes seda tõsiselt vajavad.\nLõpetuseks võib öelda, et raiskamine on jõudnud suurele tasemele ja inimesed surevad ja teevad pidevalt tööd selleks, et see kõik minema visata. Inimesed peaks mõtlema mis tunne on olla näiteks tööline või see kes kasvatab toitu ja näha mis tunne on kui sinu raske vaev lihtsalt ära visatakse.');
