INSERT INTO core.text(id, content)
VALUES ('2ca94988-9ff6-4aab-b58d-fd0d3ef1538b',
        'Tänapäeval on igasugune kaup väga kergesti kättesaadav. Inimesed üldjuhul ei mõtle selle peale, mida kõike nad endale kokku ostavad. Mul tekivad küsimused: „Kas inimene tarbib targalt?“ ja „Millist mõju inimene mõtlematult keskkonnale avaldab?“.\nKiirmood on meie maailma üle võtnud. Sotsiaalmeedias on pidevalt uued stiilid ja trendid, ent kuna inimesed tahavad välja näha nagu nende lemmik suunamudijad, peavad mood ja riided kiiresti arenema, muutuma, olema huvitavad ning kättesaadavad. Tihti käin ma riidepoes ja ei suuda uskuda, kui odavalt riideid müüakse. Aga odavate riiete ostmisel on need rõivad sageli ebakvaliteetsed. Sellest võib tihtipeale tuleneda see, et need riided visatakse minema.\nInimesed ei mõtle selle peale, kuidas nende tegevus võib maailma mõjutada. Tänapäeval on juba kõik teadlikud, kuidas tegelikult kiirmood ja inimese ebausk tarvete teadlikul kasutamisel laastab meie planeeti. Ikkagi on inimesi, kes ei taha arvata, et nende tegevus võib planeedi hävitamisel osa mängida. Näiteks ostab mu ema meile alatihti toitu, mis ta arvab, et mu pereliikmetele meeldida võib, aga lõppude lõpuks satub see toit prügikasti. Selline tegevus on tegelikult väga keskkonda kahjustav.\nMa arvan, et üldjuhul pole inimesel plaani, mida toodetega peale hakata. Seetõttu ostab inimene endale kokku asju nagu toitu ja riideid, mida ta tegelikult ei taha või ei vaja. Võin teha järelduse, et kasulik oleks ennem ostlemist mõelda: „Kus ma seda kannaks?“, „Mida ma sellega teen?“ ja „Kas ma tõesti vajan seda?“.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('2ca94988-9ff6-4aab-b58d-fd0d3ef1538b', 'title', 'Kas inimene tarbib targalt?');
