INSERT INTO core.text(id, content)
VALUES ('99ea413c-a142-4230-be37-1cfc8e70e2d0',
        'Inimeste tarbimisharjumused on väga erinevad, mõned inimesed kasutavad asju lõpuni, teised kasutavad ainult nii kaua kui neil seda vaja läheb.Võiksime kõik mõelda selle peale, et kuidas kasutaks mõni kodutu või mõni mitte nii rahaliselt positiivsel kohal olev inimene seda toodet. Kas ta ostaks särgi ainult ühekorraliseks kasutamiseks, või kas ta sööks ainult pool oma krõpsupakki ära.\nEsiteks, ma kirjutaksin toiduraiskamisest.See on tõsine probleem meie inimkonna juures.Me arvame, et toitu on lõpmatult aga seda tegelikult ei ole.Peaksime alati meeles pidama, et mõnes vaesemas kohas nälgivad inimesed igapäev ja ei ole söönud juba päevi.Sellepärast peaksimegi me mõtlema enda toidukoguste peale ja võtma süüa ainult seda, mida me teame, et me suudame ära süüa.Mitte nimodi, et kaks ampsu ja enam ei suuda edasi süüa, või et ostad midagi enda arust maitsvat, proovid seda ja siis viskad ülejäänud ära, sest see ei maitsenud sulle.Ja näiteks ongi kirjutatud „tarbitoitutargalt.ee“, et kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg.\nTeiseks, ma kirjutan riiete alakasutamisest.See on väga suur probleem, mida iga inimene on vähemalt ühe korra oma elus teinud.Me ostame ühe riideeseme ja vaatame poes või netis, et see näeb päris hea välja aga pärast leiame selles defekti mis meile ei meeldi ja ei kannagi seda riideeset enam kunagi.See on näiteks minuga ka juhtunud.Ostsin ühe tressika mis nägi poes väga normaalne välja aga kui järgmisel päeval sellega kooli tulin oli see väga ebamugav ja ajas mu kaela kogu aeg sügelema.Pärast seda päeva ma seda tressikat enam selga ei pannud.\nKokkuvõtteks, toiduraiskamine on suur probleem, me peaksime arvestama enda toidukogustega ja mitte laskma toidul raisku minna.Riiete alakasutamisega võiksime proovida riideid rohkem kasutada, isegi kui nendel on mõni väike viga, mis meile ei meeld ja mitte minna odavale teele ja osta riideid soodukate pärast.');
INSERT INTO core.text_property(text_id, property_name, property_value)
