INSERT INTO core.text(id, content)
VALUES ('39f527be-970d-4897-9324-0c7d08800c87',
        'Inimesed kipuvad ostma tooteid, mida neil tegelikult vaja pole. Teise sõnaga öeldes toodete ületarbimine. See on raske teema just sellepärast, et firmad üritavad oma tooteid peale suruda ja panna arvama, et sul on neid vaja, kuid tegelikult pole. Internet on täis kampaaniaid, üks parem kui teine. Aga kuidas tarbida vähem? Ja mis tegelikult toimub?\nÜletootmine ja ületarbimine käivad käsikäes. Firmad toodavad palju riideid ja mida rohkem toodetakse seda rohkem on ka neid tooteid, mis lõpetavad looduses. See on tegelikult maailmale suur probleem, sest tööstused, mis toodavad nii suures koguses riideid, reostavad rohkesti loodust. Mina arvan, et inimesed peaks ostma riideid, mida neil tegelikult vaja on ja ei läheks kaasa kampaaniatega ning ei ostaks kõiki uusi trendikaid riideid, mida nende lemmik suunamudija reklaamib. Sellega järeldan, mida vähem inimesed kiirmoodi ostavad, seda vähem toodavad ka tööstused.\nMaailmas on ka toidu ületarbimine suur probleem. Osa maailmast ostab kokku, aga ei tarbi kõike ja osa ei saa üldse. Maailm on nii jaotatud ja ei saa teha väga midagi, et seda jaotust murda. Kuid meie osa maailmast, kus ostetakse kokku ning ei tarbita seda saab muuta. Inimesed peaksid ostma poest just neid toiduaineid, mida nad teavad, et nad kasutavad ja just nii palju kui kulub. Näiteks minu kodus käime korra nädalas poes ja ostame kokku just nädala jagu toitu ning ei lähe ennem järgmist laupäeva poodi. Selline süsteem aitab meil ära tarbida kõik, mis kokku osteti ja vähendab toidu raiskamist.\nTuleks vähendada ka internetipoodidest kiirmoe ostmist. Suured firmad nagu Shein ja AliExpress toodavad igapäevaselt tuhandeid riideesemeid. Netis olen näinud, kuidas inimesed ostavad suurtes kogustes kokku riideid, kannavad paar korda ja siis viivad taaskasutusse. Sellest informeerimiseks käis moedisainer, Eve Hanson, Vikerraadios rääkimas. Tema sõnu kokkuvõttes rääkis ta, et noored tuleks viia ekskursioonile taaskasutuskeskuse lattu vaatama, kuidas igapäevaselt voolab sisse sadu riideesemeid, mida on korra kantud ja enam ei taheta. Enamus tuleb just neilt suurtelt Hiina tootjatelt ning see aitaks avada noorte silmad sellele, mis maailmas toimub.\nMa arvan, et sellest võib järeldada, et maailmas toodetakse liiga palju ja inimesed ostavad kokku kõike, mida reklaamitakse. Seda tuleks vähendada erinvatel viisidel, kas vähem käike poodi või üleüldse vähem ostmine. Inimestel tuleks mõelda ennem ostlemist järgi, kas neil päriselt on seda toodet vaja või mitte. Loodust tuleb hoida ja me saame aidata kaasa vähem tarbides ja vähem raisates.');
