INSERT INTO core.text(id, content)
VALUES ('1788e582-8789-424a-95ff-859f0b1ee910',
        'Meil on maailmas inimesi ,kes raiskavad toitu ehk viskavad ära toitujääkmed ja ei tunne sellest kahju, siis on meil inimesi, kes viskavad väiksemaid koguseid, sest nemad on säästlikud. Mind paneb mõtlema, kui inimesed raiskavad liiga palju toitu, kas siis kunagi enam toitu tulevikuks ei oleks nii palju?\nInimesi on erinevaid: need kes raiskavad ja ei tunne sellest kahju, sest nad saavad lubada seda endale, siis on inimesi, kes viskavad väiksemaid toitu kogusi ära või lausa taaskasutavad, et mitte nii plaju raisada. Tavaliselt inimesed kes raiskavad palju toitu viskavad umbes aastas 60kg toitujääkmeid ära, nad võiksid näiteks taaskasutada toitu ära, et nii palju toitu raiskamist ei oleks. Inimesed, kes raiskavad natukene toitujääkmeid raiskavad kuni 25kg toitujääkmeid aastas, nad taaskasutavad rohkem, aga viskavad ikka palju jääkmeid ära, kui kõik inimesed jätkavad toitu raiskamisega siis kunagi võib toitu vähemaks jääta ja paljud inimesed ei saaks enam toitu osta.\nKui mõelda toitu saamiseks siis põllumehed peavad raiskama väga palju ressursse: maad, vett, energiat ja erinevaid keemikale, et kasvatada toidu inimestele kes raiskavad selle ära. Kui põllumehed ei kasvataks inimestele toitu, siis kuidas see mõjutaks neid, kui palju toitujääkmeid nad siis raiskaksid, kui vähem toitu on. Või tõstaks toitu hindasi kallimaks, et inimesed ei viskaks ära enda toitujääkmed, sest toit on kallim ja väärtuslikum.\nInimesed raiskavad liiga palju toitujääke, ükskõik mis sa teed nad suutavad igal juhul raisata enda toitu, isegi kui tõstaks toitu hinnad kõrgemaks suudavad nad ikka raisata, kui inimesed jätkavad nii, kas siis tulevikus jagub inimestele toitu, kui nii mõelda siis see tundub, et ei jaguks, sest põlde hakkab vähemaks jääma ja inimarv kasvab suuremaks.');
