INSERT INTO core.text(id, content)
VALUES ('eb1d0d72-8f52-42d9-acfc-3034a9cf9948',
        'Väga paljud arvavad, et toit on kõigile kättesaadav, kuid tegelikkuses on see reaalsus hoopis teine. Sadu inimesi nälgib kuna neil pole raha, et toitu osta ja lõpuks paljud ka surevad nälga. Sellele peab lõppu tegema.\nMitmed arvavad, et toidu ära viskamine ei ole mingi probleem aga see ei ole päris nii. Toidu ära viskamine raiskab resursse, tööjõudu, energiat, vett jne. Alustades väikeste sammudega nagu see, saame aidata keskkonda ja säästa oma raha. Poes käies, tuleks mõistlikumalt toiduaineid valida ja kindlasti aitab ka, kui poodi minnes on kõht täis, siis ei osta kokku mõtetuid asju, mis hiljem ära visatakse.\nMõeldes inimestele, kes ei saa lubada endale toitu ning peavad nälgima, peaksime meie, midagi ette võtma. Kahjuks on aga väga palju inimesi, kes hoolivad ainult iseendast ja on liiga uhked, midagi selle nimel tegema. Just sel põhjusel peame tegema kõik teadlikuks, et toit ei ole nii lihtne kätte saada kui arvatakse. Ja võibolla just siis hakkame muutusi nägema. Selline asi ei juhtu kindlasti üleöö aga ühe sammu haaval jõuame sinna.\nMa loodan, et paari aasta pärast on kõik need probleemid märksa väiksemad, kuid see juhtub, vaid siis kui me kõik koos selle nimel vaeva näeme. Ärme ole ükskõiksed, vaid üritame probleemile lahenduse leida. Parema maailma nimel.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('eb1d0d72-8f52-42d9-acfc-3034a9cf9948', 'title', 'Parem maailm');
