INSERT INTO core.text(id, content)
VALUES ('679c0bd7-41a6-469f-89b8-6705ce2775db',
        'Inimesed tarbivad enamus asju selle pärast, et neil oleks mugav ja nende tegevus oleks efektiivsem. Mida nad kasutavad selleks, et inimeste tulemused oleksid paremad?\nTarbimis harjumus, mis see ültse on, see jaguneb kaheks üks on see mida me kasutame ja teine on see mida me oleme harjunud kasutama ehk kokku mida me oleme harjunud kasutama.\nInimesed kasutavad enda tulemuste muutmiseks palju asju, mina kasutan toitu, transporti ja enda aju koos õpimisega.\nToidu puhul on imelik asi see, et kui ostetakse toitu siis vähemalt poolest pool visatakse ära, kuna see on juba halvaks läinud.\nSelline tegevus mõjutab keskonnakoormust kuna kui inimestele toodetakse toitu juurde siis kasutatakse erinevaid kemikaale.\nKõige rohkem me tarbime iga suguseid riideid kuna need on ikka kõik mugavuse pärast ja „vajaduse“ pärast. \nEnamus inimesed kes tahavad endale erinevaid riide esemeid siis kasutatakse ja pannakse kõrvale, kuna ühiskonda tuleb iga päev uusi asju mida tarbida.\nAga inimesed on targemad kui ma arvan, nad viivad asjad taaskasutus keskustesse kust saavad teised inimesed osta endale vajalike asju kuna nende raharesurs ei võimalda kallimaid asju osta.\nKõige suuremad riiete tarbijad on noored, kuna neil on mõttes see et peab käima moega koos, aga ei peaks mõtlema sellele mis on mulle vajalik mitte mis teistele meeldiks.\nErinevate asjade kasutamist tuleks minu arvates ikka enne planeerida kas seda on vaja ja kas saaks kuidagi teisiti nii, et mull oleks parem ja teistel.\nKõik ühes ehk, inimesed on harjunud tarbima asju palju ja mitte vajalikult, selle põhjus on enamasti see, et kõik soovivad kõike ja ei nähta ohtu enda ja teiste suunas (maailma reostamine).\nTuleks valida mida kasutad ja kui palju.\nÕpetada nooremaid asju õigesti tarbima ja kasulikult tarbima asju mitte nii, et tekiksid probleemid.\nÜhis kond vajab rohkem inimeste tarbimisharjumuste vähendamist kuna me uppume on tarbimis harjumuste sisse.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('679c0bd7-41a6-469f-89b8-6705ce2775db', 'title', 'Mis on inimese tarbimisharjumused');
