INSERT INTO core.text(id, content)
VALUES ('086117d6-991f-49b1-b67b-5a22435ce159',
        'Väga oluline teema on inimeste tarbimine ja taaskasutamine. Minu jaoks on kolm kõige olulisemat riiete taaskasutus, toidu raiskamine ja vana mööbli või esemete taaskasutus. Kuidas tarbida ja taaskasutada säästlikult?\nPaljudele inimestele meeldib osta iga nädal või iga kuu uusi riideid. Inimesi kutsub ostma sooduspakkumised või odavad riided. Tegelikult ei ole mõistlik osta endale kokku Hiinas tootetud odavaid ja ebakvaliteetseid riideid. Odavad Hiina riided lähevad kiiresti topiliseks ja ei kesta kaua. Alati ei pea ostma poest uusi riideid. Mõistlik oleks osta mõnest taaskasutus poest või realiseerimiskeskusest. Sealt saab väga odava raha eest korralike ja täiesti kantavaid riideid. Mina ise alati eelistan käia taaskasutus poodides. Seal on suurem valik, raha kulub vähem ja taaskasutan riideid.\nToidu raiskamine on üks olulisemaid probleeme.  Inimesed ostavad kokku toitu, mida nad hiljem ära ei söö. Inimesed peaksid vähem ostma, sest enamus sellest läheb prügikasti. Poes tuleks alati vaadata sooduspakkumise osakonda. Seal on vanaks minevad toiduasjad aga kõlbavad süüa ja on soodushinnaga. Mina ise alati ostan vähemalt ühe toote sealt, sest see aitab tarbida võimalikult palju toitu, seda ei pea minema viskama ja raha kulub vähem.\nVanu asju ja mööblit oleks mõistlik taaskasutada. Inimesed tavaliselt lähevad kallitesse mööblipoodidesse ja kulutavad mööblile väga suure summa. Minu arvates oleks mõistlik vaadata mõnest taaskasutus poest või interneti leheküljelt, kus inimesed ise müüvad oma vanu esemeid. Mina alati eelistan osta asju kellegi käest või taaskasutuspoest. See on hea viis säästa raha ja taaskasutada esemeid.\nMinu jaoks on need kolm teemat väga oluline osa tarbimisel ja taaskasutamisel. Riiete, toidu ja esemete taaskasutus aitab tarbida säästlikult.');
INSERT INTO core.text_property(text_id, property_name, property_value)
