INSERT INTO core.text(id, content)
VALUES ('d503f52a-8020-42fa-95f2-bbc5a243a049',
        'Kui mõelda realistlikult siis maailmas on väga palju toitu raisku läinud sellepärast, et mõned inimesed ei väärtusta seda. Toit on tegelikuses väga tähtis meie igapäeva elus ja seda tuleb süüa vähemalt kolm korda päevas. \nInimesed siin maailmas ei väärtusta seda mis meile pakkutakse.Mõned inimesed rügavad hommikust õhtuni tööl, et nad saaksid minna koju ja teha sooja toidu oma perele aga mõned käivad kallites restoraanides söömas ja nüüd kujuta ette kui palju toitu läheb raisku restoranides ja kui palju läheb kodus.\nIgapäevaselt visatakse hunniku viisi toitu, et minna samal päeval uuesti poodi ja osta kõike mis ette jääb ja lasta neil mädaneda kuskil sahtlis.On mõned kes ostavad kuupäevade järgi ja on mõned kes lihtsalt võtavad aga mida hilisem kuupäev seda parem.\nVäga kurb on mõelda kuidas inimesed arvavad, et see pole suur teema visata toitu ära ja ahnitsevad seda juurde aga selle peale nad ei mõtle, et praegu sellel ajal võib olla üks näljane laps nutmas, sest ta pole mittu päeva söönud.\nSamamoodi vanemad teevad kodus toidu valmis, et mittu päeva saaks süüa ja lapsed ikka eelistavad süüa kuskil burgeri suurt einet ja kokkuvõttes ta ikka viskab selle toidu ära, sest tal sai kõht täis.\nToidu raiskamine raiskab ainult meie enda raha ja  tohutult ressurrse näiteks- maad,vett,energiat ja tööjõudu.Lisaks tekitab toidu tootmine keskonnakoormuse, sest saagikuse suurendamiseks kasutatakse väetist ja erinevaid kemikaale.\nNii, et toiduraiskamine ja ära viskamine toob lisaks meile suuri probleeme kui ka riigile.');
