INSERT INTO core.text(id, content)
VALUES ('f6548305-002b-4c72-bb40-1095e32ebcfb',
        'Iga inimene on erinev, nii ka meie harjumused. Maailmas leidub mitmeid inimesi, kes teevad endast oleneva, et ei toimuks üleliigset tarbimist ega mõttetut raiskamist. Neid on aga vähe, seepärast tekitavad meile probleeme inimesed keda ei huvita, et nad tarbivad liigselt.\nSuure osa liigsest tarbimisest tekitab kiirmood. Inimestel on vajadus omada just seda riideeset, mida toodetakse Hiinas aga see ju neid ei huvita, sest asjad on soodsad ja näevad kenad välja. Need asjad oma madala hinna tõttu lähevad lihtsamalt katki,  topiliseks või kuluvad lihtsalt ära. Peaksime väärtustama rohkem kodumaiseid tootjaid, kelle disaini saab kanda küll suurema hinna eest aga nende riiete vastupidavus on silmnähtavalt suurem, kui Hiinast tellitud riietel. Taaskasutuspoodidest võime leida väga hea hinna ja kvaliteedi suhtega riideid, mis maksaksid uuena poes topelthinda, kui just mitte rohkem, seetõttu peaksime külastama rohkem taaskasutuspoode, et leida omale uusi rõivaid ning ka ise oma vanu riideid sinna viima.\nTeine suur probleem on toiduraiskamine. Peaksime olema tänulikud inimestele, kes siiani kasutavad poenimekirjasi, et aidata vähendada liigset kokkuostu. Säärased inimesed on heade tarbimisharjumustega ning eeskujuks teistele. Inimesed, kes käivad poes igapäevaselt, raiskavad palju, nemad tavaliselt ei söö ära eelneval päeval valmistatud kõlblikku toitu ega kasuta ära eelnevatest päevadest alles jäänud toidu komponente. \nSelleks, et vähendada liigset tarbimist peame vähendama kiirmoe tarbimist ning liigset toidu kokkuostu. Peame võtma eeskuju inimestest, kes nii juba teevad ja mõtlevad.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('f6548305-002b-4c72-bb40-1095e32ebcfb', 'title', 'Millised on inimeste tarbimisharjumused?');
