INSERT INTO core.text(id, content)
VALUES ('4203ee00-55f6-4840-bbb3-0d1d8a9b47d8',
        'Inimestel on komme osta palju toitu, aga ära viskamise mõjule tavaliselt ei mõelda. Väga paljudele meeldib välismaalt riideid ja asju tellida, kuid see ei ole meie keskkonnale üldse hea. Taaskasutuspoodides käimine oleks väga hea idee, riiete õmblemiseks ei kuluks peaaegu üldse enam materjale. Sellega säästaks raha ja keskonda.\nToidu ära viskamisest tavaliselt ei tehta suurt numbrit. Ei mõelda tagajärgedele, mis mõjutavad meie keskkonda. Sellest ma saan aru, kui kellegile ei maitse mõni toit ja ei taheta seetõttu ära süüa ning visatakse ära. Tegelikult peaks saama toidu väärtusest aru, seda ei ole lõpmatuseni. Igal inimesel ei ole isegi võimalik osta täisväärtuslikku toitu igapäev.\nInimesed ostavad riideid endale liiga palju kokku. Enne kui ostama hakkad, peaks läbi mõtlema kas neid on tõesti vaja või tahaks lihtsalt moega kaasas käia. Kaks korda aastas võiks vähemalt teha riidekapis suur puhastuse. Kõik mida enam ei kanna, võiks kas kellegile teisele andma või taaskasutuskeskusesse viia. Niimoodi ei viska me terveid ja kantavaid riideid niisama ära. Usun, et kui inimesed sama moodi jätkavad, nagu praegu, on meil varsti riideuputus.\nKindlasti saame me oma harjumusi muuta, et meil oleks parem elada. Kui keegi ei viskaks prügi maha ja ei ostaks kiirmoe riideid, oleks meil tunduvalt puhtam õhk ja loodus. Selle mõtte nimel võiks ennast kokkuvõtta ja selle jaoks ka päriselt midagi teha. See on meie endi kätes, et elada paremas tulevikus.');
