INSERT INTO core.text(id, content)
VALUES ('c7fea314-c89f-466c-a2e2-fecbded532c4',
        'Looduse ja Maa saastamine on väga levinud probleem. Seda teevad inimesed igas vanuses ja riigis. Muidugi on probleemiks heitgaasid, kliima soojenemine ja muud maailmale destruktiivselt mõjuvad faktorid, kuid paljud mured saavad alguse inimeste endi tarbimisharjumustest. \nTänapäeval on moega kaasas käimine lausa tarvilik. Firmad loovad riideid või esemeid, mis muutuvad moodsaks ja populaarseks ning see partikulaarne firma teenib kasumit. Probleem seisneb selles, et selle toote populaarsust märkavad ka odavamad ja ebakvaliteetsemad moebrändid. Need samad brändid hakkavad tootma taskukohaseid ning madalakvaliteedilisi replikaid esemest, mis oli kunagi ainulaadne. Inimesed pöörduvad odavama toote poole ning ei pööra jätkusuutlikusele tähelepanu. Seda toodet hakatakse massiliselt ostma ja nagu enamus trendid, läheb see varsti moest välja. Seejärel visatakse ese peale mõnda kandmist ära ja saastatakse loodust. Ökonoomilisem varient oleks siiski osta kallim, kuid kvaliteetsem asi ning samuti enne oste kaaluda, kui mõtlematult moega kaasas käia.\nToiduainete tarbimisel muutuvad inimesed aina hooletumaks. Ostetakse toitu ning jäetakse see külmkappi, kuni see on söömiskõlbmatu ning siis visatakse minema. Samuti tehakse süüa just poest ostetud uutest toorainetest ja mitte sellest, mis on kodus juba kaua seisnud. See on raha kui ka loodusressursside raiskamine. Tänapäeval on inflantsiooni tõttu võimalused niigi piiratud, nii et selline teguviis on kahjulik endale ja Maale.\nKeegi ei soovi jätta järeltulijatele maailma, kus valitseb kaos. Praegused probleemid võivad tunduda väikesed, kuid need aina kasvavad. Meie planeedi ja järglaste tulevikku saame ja peame muutma me veel niikaua kui see on meie kätes, jõukohane ja võimalik.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('c7fea314-c89f-466c-a2e2-fecbded532c4', 'title', 'Tarbimine saastab loodust');
