INSERT INTO core.text(id, content)
VALUES ('4850c2b1-9924-48dc-93e4-10bb2d3a4304',
        'Suureks globaalseks probleemiks, esitub ilma küsimuseta toidu raiskamine, kuid kindlasti, peab rohkem tähelepanu suunama ka toidupuudusele. Seda leidub maailma igal küljel, ning selle tõttu sureb inimesi igapäevaselt. Siin ei saa tuua tähtsamale kohale kas ühte või teist probleemi, sest mõlemad probleemid vajavad lahendust. Mõlemad probleemid ohustavad kas Maa tooraineid ja loodusvarasid või populatsiooni ja tööjõudu.\nToidu raiskamist esineb igal pool Maad, igas riigis, igas linnas ning igas kodus. Osa inimestest annab enda osa, et seda vähendada, kuid enamus inimestest isegi ei hooli sellest. Paljud inimesed lihtsalt ei tea kui suurt kahju see Maale toob, kui tõsine see tegelikult on. \nKuna maailma üks suurimaid probleeme on nälg, siis õnneks osa inimesi, mõtleb ka neile, kellel ei ole toidule nii kättesaadavat võimalust. Nälja vähendamiseks, saab kaasa aidata näiteks raha ja toidu annetamises. Seda saab kergelt teha läbi interneti.\nKahjulik pole ainult toidukaost, vaid toidu saaste. See reostab metsasid, ning on ohtlik loomadele. Paljud toidud, sisaldvad nüüd rohkelt kemikaale, selliseid kemikaale, mida inimene ega loom pole tegelikult loodud sööma. Näiteks kõik rämpstoit, mis kahjusab inimese tervist ning ebavajalikus koguses plastik, mille pärast paljud loomad surevad.\nMaad reostab ka riiete üleliigne tootmine ja ostmine. Riideid ostes, peaks rohkem jälgima, kas need meile tegelikult meeldivad, ning kas need kestavad meil kaua. Suurel osal rahvast on äärmuselt palju riideid, mida nad ei kanna. Selle lahendamiseks, saab näiteks müüa need maha teistele, kes neid kannaks või annetada need inimestel kellel neid vaja läheb.\nToidu raiskamise vähendamisest ja prügi sorteerimisest, peab hakkama rohkem inimestele rääkima. Neile peab aru andma, et liigne reostus on Maale ohtlik ja tekitab globaalset soojenemist. Ning kokkuvõttes, mõeldes sellele, kui kerge on aidata neid,  kellel ei ole toidule või riietele kättesaadavust, näeme me, et Maa paremaks muutmine ei olegi nii raske.');
