INSERT INTO core.text(id, content)
VALUES ('b628378c-883c-4f59-abdf-f9a8ce70545e',
        'Kõikjal maailmas läheb alati raisku toitu, riideid ning palju teisi asju. Vahel visatakse neid lihtsalt minema. Inimesed ise ei märka seda, sest arvavad, et kui nad vähe asju minema viskavad, ei muuda see midagi.\nMe peaksime vähem toitu raiskama, sest kõik lõpeb kunagi ja varsti pole midagi järgi. Me ei raiska vaid oma raha, aga ka ressursse. Selleks, et toitu vähem raisata, võiks inimesed tähele panna, kas suudavad selle enne pahaks minemist ära süüa või mitte ja anda toidu edasi kellelegi, kellel seda vaja on. Väga paljudel inimestel üle terve maailma puudub raha või ressursid, et normaalset toitu saada. See on ka üks põhjustest, miks peaks seda paremini hoidma. Paljud on ka harjunud, et toitu saab igalt poolt juurde, seega neid ei huvita raiskamine. Ma arvan, et toitu võiks osta nii palju, kui tead, et jaksad ära süüa.\nRiietega on suhteliselt sama asi. Neid raisatakse ka väga palju. Noored tellivad aina rohkem Hiinast ja mujalt teistest riikidest asju, sest need on seal odavamad. Taaskasutuspoodides on alati hunnikutes riideid. Mõned on korralikud, aga teised samas sellised, mis näevad ilusad välja, aga on naftast tehtud ja paljud sellised ongi Hiinast. Võiks osta pigem vähem riideid, millel on hea kvaliteet ja mis on kodumaised.\nMinu meelest võiks kõike vähem raisata, riideid, toitu, ressursse ja kõike muud. Selleks, et seda teha, peaksid kõik inimesed kaasa aitama. Üksi see ei töötaks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('b628378c-883c-4f59-abdf-f9a8ce70545e', 'title', 'Millised on inimeste tarbimisharjumused?');
