INSERT INTO core.text(id, content)
VALUES ('c76a6c4c-b1a0-40ae-80b1-d1209abb1368',
        'Eesti probleemiks on liigne raisk. Me tellime hiinast ja igaltpoolt mujalt asju mida me tegelikult ei vaja. Paljudes kohtades visatakse iga päev kilode kaupa toitu ära nii restoranides kui ka koolides ja kohvikutes.\nToidu raiskamine on mõndade inimete jaoks loomulik aga on ka inimesi kes ei saa igapäev süüa. Aga mis siis kui me ei raiskaks nii palju toitu ega meie endi ressursse nagu vett, mulda ja ka energiat? Peaksime ümber ennast harjutama ning näiteks, kooliõpilased võtavad ainult nii palju toitu kui nad jaksavad ära süüa, restoranid muudavad roogade suuruseid ehk vähendavad kogust ning kohvikud võiksid õhtu lõpus jagada ülejäänud pirukad või koogid neile kellel ei ole seda võimalust, et ostma tulla.\nMinu arust võiks hakata kodus taaskasutama asju nagu pluuse, pükse ja salle, et vähendada suuri hunnikuid taaskasutuskeskustes. Pluusidest saab uusi padjapüüre teha, teksastest teiste teksaste auke parandada ja sallidest koduloomale uusi mänguasju. Pole mõtet ka riideid koguaeg juurde tellida kui kapp juba täis on. Muidugi isegi mina lähen soodukampaaniatega vahepeal kaasa, aga proovin ikka säästlik ka olla. Kui ma näiteks oma riietest välja kasvan, annan need oma väiksele õele, et ma ei peaks neid lihtsalt ära viskama. \nMinu järeldus on see, et koolid ning restoranid võiksid vähendada ühe taldriku toidu koguseid, et raiskamist oleks vähem ja et eesti oleks puhtam. Võiksime ka lõpetada uute riiete tellimist kui kanname neid ainult paar korda ja siis viskame ära. Kokkuvõttes oleme säästlikumad ja aitame oma enda tulevikku.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('c76a6c4c-b1a0-40ae-80b1-d1209abb1368', 'title', 'Miks me raiskame nii palju?');
