INSERT INTO core.text(id, content)
VALUES ('dbd7b04b-8477-4fc5-8ecd-5b9d217efc33',
        'Ma ise armastan väga loomi. Eriti lemmikloomi, kuna mul on ka endal koduloom. Ma tunnen, et paljud veel ei räägi sellest teemast piisavalt. Sellepärast see teema kõnetabki mind sellest rääkima.\nInimesed ei tohiks kasutada loomi nagu asjadena, kuna nad on täpselt sama elus, kui meie. Neil on kindlasti ka oma pere. Lapsed, kes ootavad oma vanemaid koju. Kahju mõelda, kui nad ei jõuakski koju tagasi. Veel kurvem oleks siis, kui nad võtaks nende beebid ka sinna loomade testimis kohta. \nMa iseenesest ei kujuta ette, kui südametud need inimesed võivad seal olla. Need, kes testivad loomi ja kuulevad neid appi karjeid. Mitte ükski loom pole seda väärt. Loomad on nii armastavad ning abistavad. On ka olemas meditsiiniliselt välja kirjutatud abikoerad, kes tunnevad kohe, kui halb hakkab inimesel. Ja enamustel on kodus endal mingi lemmikloom. Isenesest juba loomale haiget tegemine on väga jube. Ma ei mõista, kuidas selline asi on seadusega lubatud. Ma siiralt armastan tõesti loomi ja täpselt,  sellepärast ma ei saa aru sellest, kuidas inimesed ei võiks mingit asendust leida loomade testimisele.\nKogu selle teema põhimõte ongi, et leida paremaid viise, et testida asju, mis lähevad inimestele. Loomadel on ka enda elu ja pisike pere. Täpselt samamoodi nagu inimestel. Meie ju ei tahaks, et meiega samamoodi tehtaks. Kogu see teema on väga tundlik ning puudutab inimest omamoodi. Ma tahtsin seda seletada omamoodi, kuna siis näevad teised ka võibolla samamoodi nagu mina. Ma tõesti loodan, et tulevikus mõeldakse asendusplaan välja ikkagist.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('dbd7b04b-8477-4fc5-8ecd-5b9d217efc33', 'title', 'Loomade testimine');
