INSERT INTO core.text(id, content)
VALUES ('0363b614-1da0-4307-83c8-2ffc62c714c0',
        'Toidu raiskamine on tänapäeval suur teema. Inimesed ostavad rohkem toiduaineid,kui tegelt vaja on. Miks väga suur hulk inimesi teeb nii?\n Minu pere vahest ostab ka süüa liiga palju, ning kuu lõpus, kui enamus tooded on vanaks lääinud viskavad ära. Mõnikord võib juhtuda ka, et anname teistele pereliikmetele toitu, kuna me oleme jällegi endale liiga palju ostnud ja lihtsalt ära viskamine oleks raiskamine. Mu vanemad on peaaegu iga kuu õelnud, et see kuu ei pane toidu peale nii palju raha. \n Toit läheb koguaeg aina kallimaks. Kui paar aastat tagasi said osta kahe euro eest  krõpse, limonaadi ja kommi, siis nüüd saaks selle raha eest endale ainult kommi. Vahepeal on hea osta hästi palju toitu ja mõelda et nüüd saan mitu kuud süüa neid asju, tegelt see on lihtsalt raha raiskamine, need isud mis sellel ajal kui ostid asju kaovad päris kiiresti ära.\nAlati kui mina viskan toitu ära, siis mõtlen, et väga paljud maailmas ei saa lubada endale nii palju, ning unistavad sellest toidust mida mina praegu söön. Kurb on mõelda selliste asjade peale. Minu arvates võiks kõik toidu mis on alles jäänud annetada inimestele kes ei saa endale lubada head toitu.\n Tuleks enne ostmist läbi mõelda, kas sul on ikka seda vaja. Ma arvan, et kõik suudavad säästlikumalt käituda ja kui juhtub, et ostad liiga palju siis saad kas annetad või annad oma pereliikmetele ei tohiks lihtsalt ära visata. Me saame teha kõike nii, et kõigil oleks hea.');
