INSERT INTO core.text(id, content)
VALUES ('b769e03c-e020-445c-82ae-fa13b64413b1',
        'Inimesed kasutavad igapäevaselt väga palju pakendi olevaid asju ja ei mõtle isegi selle peale kuhu see sattunud on või mis sellega juhtunud on. Enamus asju visatakse loodusesse pärast kasutust ja veelgi hullem on see kui visatakse prügi merre.\nInimesed toodavad iga aasta, kuu, nädal, päev meeletult pakendis olevaid asju või pakendit ise ja kedagi ei huvita kui see prügi lõpetab maas või meres, mõeldakse, et vahet pole, küll keegi selle ülesse korjab. Väga suur osa mereloomadest sureb sellepärast, et enamus prügi on meres. Merelooma jaoks tundub see söögina, aga nemad seda ei tea. Kui on juba liiga hilja ja keegi teda päästa ei suuda, siis tema keha ei saa selle plastikuga hakkama ja loom sureb.\nÕnneks on inimkond selleni jõudnud, et kasutusele võtta paberist asju. Väga suurel määral on hakatud kasutama pabertopse, kõrsi, kiirtoidu söögikohtades kasutatakse vähem pakndit just jookide juures. See toob kaasa jällegi suurt metsade maha võtmist, kuna on vaja puust saada paberit. Paljudes kodudes, kes jaksavad sellel silma peal hoida, sorteerivad enda prügi. Kuhu läheb pakend, paber, olme jäätmed, jne. Olmejäätmete jaoks on olemas kompost, kuhu saab viia enda söögilaualt üleliigseid toite.\nLooduse saaste on väga suur probleem üle maailma, just suurtes riikides, kus inimesi on miljoneid. Osad riigid loovad aina rohkem prügikaste tänavatele, kuhu inimesed saaksid visata oma prügi, et see loodusesse ei jõuaks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('b769e03c-e020-445c-82ae-fa13b64413b1', 'title', 'Looduse saaste maailmas');
