INSERT INTO core.text(id, content)
VALUES ('98a38215-7ac6-4a18-b7e2-6433e80413ff',
        'Maailmas on väga palju inimesi, keda huvitab meie planeet ja selle heaolu.Igaüks tahab, et meil oleks puhas ja vaba riik.Mida teha, et maailm püsiks sellisena nagu ta preagu on , või lausa paremana?\nMinu meelest suurtes ja üle rahvastatud kaubakeskustes on lõbus, kuid seal on hinnad kõrgemad kui Suur Munamägi Eestis.Igal inimesel on riideid, mida nad ei kasuta või mis ei lähe enam selga, aga on veel kandmis kasulikud.Riided tuleks viia taaskasutuspoodi, seal on mõistlikud ja odavad riided, mida on veel võimalik aastaid kanda.Mina eelistan rohkem ka taaskasutuspoode, kuna sealt leiad riideid mida teistel pole.Taaskasutuspoode on ümberringi maailmas igalpool.Aga minu lemmikud on siin Eestis näiteks: Sarapuu kirbukas ja humana.\nToidusorteerimine on maailmas väga suur probleem.Inimesed tarbivad tooteid mis on pakend, aga viskavad selle põrandale.Prügikonteinereid on igas linnas, alevis ja maal.Prügi sorteerimine on väga oluline, kuna me taheme, et meil oleks puhas maailm. Minul kodus on taara, pakend ja bio eraldi. Iga inimene peaks sorteerima oma  prügi.\nMe kõik tahame, et meil maailmas oleks kõik hästi, niiet käime taaskasutuspoodides mitte kaubaduskeskustes, sorteerimeprügi ja palju veel. Kui tahame ilusat elus siis teeme endast kõik, mis me suudame, iga tegu loeb.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('98a38215-7ac6-4a18-b7e2-6433e80413ff', 'title', 'Miks on vaja rääkida inimeste tarbimisharjumistest?');
