INSERT INTO core.text(id, content)
VALUES ('d927e8ca-a7fa-4a7d-8d92-a6e4f5083669',
        'Kõik inimesed tarbivad iga päev midagi ja kohati liiga palju, mis jätab endast maha ka suure jälje. Tänapäeval on väga suureks probleemiks ületarbimine. See võib olla paljuski kinni inimeste harjumustes, aga kuidas tuleks ikkagi selle probleemiga tegeleda?\nToidu raikamine, ületarbimine ja tarbimatta jätmine on väga aktuaalne teema. Inimesed viskavad tohututes kogustes toitu iga päev ära ja seda üle maailma. Veebilehelt tarbitoitutargalt.ee võib lugeda, et kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid. Toidujäätmete ära viskamine on oma enda raha, kuid ka tööjõu, maa ja energia raiskamine. Väga palju toitu läheb ka lihtsalt raisku, enne kui sellega midagi tehakse. See läheb kas enne halvaks või ei jõua mõnel muul põhjusel tarbijani. Mõttetu toidu raisku minemine on kindlasti üks  inimeste harjumustest, kuid ka probleem mis mõjutab keskkonda meie ümber ning millest peaks veel rohkem rääkima.\nSuur ületarbimine toimub ka riidemaailmas. Me kõik kanname ja ostame endale riiedeid, kuid seda tuleks teha arukalt. Riideid toodetakse tohututes kogustes ja väga paljud neist on ebakvaliteetsed ja keskkonnale kahjulikud, mis on odvalt toodetud ja edasi müüdud. Me peaksime kõik eelistama kvaliteeti kvantiteedile ning kui osta uusi riideid, siis valida lähedal toodetud asju. Taaskasutamine on arvatavasti kõige keskkonna säästlikum ühiskonnale ning see on kindlasti palju odavam kui poest uute riiete soetamine.\nIga inimene peaks jälgima oma tabimisharjumusi ning vältima ületarbimist. Nii säästame me keskkonda ja ka iseennast.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('d927e8ca-a7fa-4a7d-8d92-a6e4f5083669', 'title', 'Tarbimisharjumused');
