INSERT INTO core.text(id, content)
VALUES ('24798e85-a35a-470e-9100-2e85031f5f41',
        'Inimesed tekitavad viimastel aastatel väga palju toidujäätmeid, mis on väga halb. Iga kord tekib rohkem jäätmeid, mis pole kasulik meie keskkonnale. Millised on inimeste tarbimisharjumused?\nInimesed ostavad endale liiga suurtes kogustes toitu, mida nad ei jõua ära tarbida. Eesti inimene tekitab aastas keskmiselt 61kg toidujäätmeid, mis on kirjas lehelt tarbitoitutargalt.ee. Liigse toidu ostmine pole kasulik meile juba rahalises perspektiivis. Pole mõtet osta koju nii palju toitu, et seda ära ei sööda ja et selle peab pärast ära viskama. See oleks lihtsalt raha raiskamine. Kui sa toitu ära ei tarbi, siis raiskad sa ka inimeste aega, kes selle valmistasid. Toitu peab poest ostma mõistlikult ja mõeldes, mida oleks koju üldse vaja.\nPaljud on hakanud endale ostma asju Hiina veebipoodidest. Inimesed on hakanud vaatama enne riide hinda, kui kvaliteeti. Moedisainer Eve Hanson väidab, et tema ei telliks Hiina veebipoodidest juba põhimõtte pärast. Tema ei lähe kaasa sooduskampaaniatega, ütlest ta Anu Välbale. Nendeks on suured ettevõtted nagu näiteks: Shein ja Temu. Need on tuntud oma soodsate hindade ja suurte riiete valiku eest. Sellised soodsad hinnad paneb inimest tahtma osta asju, mida tegelikult vaja pole.\nInimesed peavad hakkama muutma enda tarbimisharjumusi. Liigne toidu raiskamine ja asjade ostmine pole kasulik keskkonale. Sellest peavad inimesed aru saama, et enda tarbimisharjumusi tuleb muuta, et ei tekiks liiga palju jäätmeid. Väga palju raha kulub toidu peale, mida ei tarbita ja asjadele, mida pole vaja.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('24798e85-a35a-470e-9100-2e85031f5f41', 'title', 'Inimeste tarbismisharjumused');
