INSERT INTO core.text(id, content)
VALUES ('b08d7fce-3c53-45bd-8b02-c1933699217f',
        'Tänapäeval on suureks probleemiks ületarbimine: toidu raiskamine, ebavajalike esemete ostmine, moega kaasas käimine. Kõik see jätab meie planeedile suure jalajälje. Kuidas saaksime vähendada ületarbimist?\nMassiliselt on kasvanud toidu ületarbimine, me ostame rohkem, kui jõuame tarbida. Me ei mõtle poes enda oste läbi ning ostame kõike, mis riiulitel mõõda minnes silma jääb. Kahjuks on ajas muutunud toiduainete pakendid, mis on tehtud värvilisteks ja silmajäävateks. Tavaliselt inimesed ei söö suuga, vaid silmadega. Lihtne on osta poest valmistoitusid, kuid see on ka pakendatud plastikusse. See tähendab, et inimesi ei huvita enam toidu sees olevad koostisained, vaid eelkõige välimus. Lihtsam on osta valmis toitu, kui totu ise valmistada.\nSuuresti on kasvanud ka meie tarbimine riiete osas. Noored ja ka vanemad ei taha enam kohe ültse tänapäeva ühiskonnast erineda. Ostetakse kõike, mis käib moega kaasas ja on pärit välismaalt. Moedisainer: „noortele peaks tegema ekskursioone taaskasutuspoodide lattu.“ See oleks väga hea viis, kuidas õpilastele näidata meie meeletut ületarbimist riiete kohapealt. See paneks mõtlema: teadlikumale riiete tarbimisele, ostmisele, kasutamisele ja saadavusele. Saaksime väga palju teha selle heaks, et kasutada riideid viimse kandmiseni ja ostaksime neid ausatest kohtadest.\nPeaksime kõik muutma enda mõtteviisi ostude tegemise kohapealt. Teadvustama peab ka seda , et me sööme suuga mitte silmadega ning rõhku panema rohkem toitude valmistamisele. Isetehtud toitudel ei jää järele nii palju pakendit. Riiete kohapealt saaksime vähendada oluliselt nende kohest ära viskamist ja pooldada nende viimse võimaluseni kandmist.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('b08d7fce-3c53-45bd-8b02-c1933699217f', 'title', 'Ületarbimine tänapäeval');
