INSERT INTO core.text(id, content)
VALUES ('51db4da9-fba2-4308-9ed2-2d13c29e2ffb',
        'Iga päevaga muutub aina aktuaalsemaks teemaks inimeste tarbimisharjumused. Peamiselt ületarbimine. Seda ka põhjusega. Raisatakse rohkem kui kunagi varem. Kõik inimesed teavad, et raiskamine ei ole hea ja kõike tuleb võimalikult palju ära kasutada, kuid seda ikkagi tehtakse. Mis seda põhjustab?\nOn teada fakt, et iga Eesti inimese kohta tekib aastas keskmiselt 61 kg toidujäätmeid. Mida paljud ei tea on see, et sellest 61-st kilogrammist peaaegu pool, ehk 26 kg on toidukadu. Raisatud toit. Selle toidu ära viskamise kaudu ei kaota me ainlt raha, vaid ka väga palju muid ressursse. Olen ka enda kodust märganud, et seda toitu mille me oleme minema visanud oleks saanud ära kasutada kui oleks, vaid sellega arvestanud. Toidukadule võib olla väga lihtne lahendus— osta täpselt nii palju toitu, kui on vaja. Ei ole mõtet raisata raha toidule mida nagunii ei söö.\nKahjuks pole toidu liigne ost ja ära viskamine inimeste ainus hukkamõistetav tarbimisharjumine. Hiina päritolu veebipoodie populariseerimine on tekitanud üle maailma liigset tarbimist. Telesaates ,,Vikerhommik’’, intervjueeris Anu Välba moedisainer Eve Hansoni, kus viimane rääkis, et tuleks eelistada kodumaiseid tooteid ja osta neid pigem vähem kui rohkem. Ta mainis ka, et ta on taaskasutuspoodide ladudes vabatahtlikuks käies näinud kui palju tekib iganädalaselt rõivaid. Kahjuks need rõivad, mis viiakse taaskasutuspoodidesse on vaid väike osa võrreldes sellega kui palju riideid lihtsalt ära visataske. Alati on võimalik oma vanadele rõivastele uus elu anda. Tee vanadest riietest midagi uut, anna edasi teistele pereliikmetele või vii taaskasutuskeskusesse. Peaasi et lihtsalt prügikasti ei viska.\nInimeste ületarbimisele võib olla paar lihtsalt lahendust. Kahjuks on tihtipeaele inimesed oma harjumustes kinni. Tuleb võtta esimene samm. Osta nii palju kui vaja, ja veenduda, et sinu jäätmed või kasutatud riided lähevad õigesse kohta.');
