INSERT INTO core.text(id, content)
VALUES ('0a100e71-ee7e-46fa-b2b8-01ddac5d7b0f',
        'Palajudel Eesti inimestel on erinevad tarbimisharjumused. Osadel on see säästlikum variant teistel aga mitte nii säästlik. Et sellest rohkem tead saada peame me algul vaatama mis on inimeste tarbimisharjumused.\nKõigepealt hakkame vaatama, mis on need inimeste säästlikud harjumused. Säästlik saab olla mitut erinevat viisi, noh näiteks inimesed osdavad asju mida nad jõuavad ära süüa enne toidu riknemist. Inimesed kellel on koduloomad nagu kanad ja sead saavad anda enda toidu jäänuseid loomadele söögiks. Ja naad saavad sellest ise ka midagi tagasi nagu liha ja mune. Peale nende on veel võimalusi toidu säästmiseks aga mul pole nii palju aega, et neist kõigist kirjutada.\nTarbitoitutargalt.ee kohaselt tekib iga eesti inimese kohta aastas keskmiselt 61kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26kg. Selline arv iga inimese kohta aastas on ikka väga suur, kui arvutada terve Eesti toidujäätmed, siis me peame korrutama terve Eesti populatsioon korrda 61tuleb välja umbes 78 miljonit kilogrammi. Inimesed peaksid vähem toitu ära viskama  ja rohkem säästlikumalt toiduga käituma. Ma järeldan sellest, et Eesti inimesed on väga lohakad ja peaksid rohkem hakkama mõtlema selle peale kuidas toitu säästa.\nMina olen hakkanud juba säästlikumaks muutuma, kuna mul on kanad kes söövad väga hea meelega minu toidujäätmeid ja vastutasuks saan mina kanadelt umbes 35 muna päevas. Kõik, mis ma poest ostan või, mis mul kodus riknema on hakkanud panen ma kana pangi ja segan teiste asjadega nagu leiva, vee, jahu, keefir ja kõige muuga, mis mul halvaks on läinud ühte kokku, ja viin kanadele ette. Sellest ajast kui ma hakkasin seda tegema on minu kanad hakkanud poole paremini munema ja nende energia tasemed on laes.\nSee oleneb inimesest endast, kas tahakkab säästlikumalt toiduga käituma või laseb lihtsalt toidul raisku minna. Üldiselt öeldes on Eesti inimesed väga ebasäästlikud. Ikkagi kõige lõppuks mina ei saa hakkata inimesi sundima toitu säästma või raiskama aga mina saan anda enda osa nüüd on võimalus inimestel anda nende osa.');
