INSERT INTO core.text(id, content)
VALUES ('f0465f3a-1ef6-4218-ae1e-fc9c0ce76dc5',
        'Ülemaailmselt on paljudes riikides suures koguses nälgivaid inimesi. Kuna enamustel Eestis seda probleemi pole, tundub meile, et toitu on veel ja see ei saa otsa. Samuti eestlaste halva finantsolukorra tõttu kodudes palju ebakvaliteetset kaupa, mille ostes on mõeldud kvantiteedi peale, mitte kvaliteedi. Et vältida nälgivust ja ületootmist maailmas, peame kõik oma rolli mängima toidu ja raha säästmises.\nKõige lihtsam on toitu säästa nii, et lihtsalt mitte midagi ära visata. Kui toit on juba ostetud, miks seda raisata. Kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg. Alati saab toitu mõni muu päev soojaks teha mikrolaineahju teel või ka õhufritüüri abil, mis tähendab, et sa ei viska toitu lihtsalt ära.\nSamuti hea viis, kuidas päästa maailma on osta heast kvaliteedist riideid, mida tead, et kannad korduvalt. Väga paljud inimesed üle maailma ostavad nii riideid, et nad kannavad seda teatud riietuseset vaid korra ja peale kandmist viskavad ära või viivad taaskasutuspoodidesse, mis nüüdseks on täiesti täis Hiinast ostetud kaupa. Selle parandamiseks peaks kandma riietusesemeid rohkem kui ühe korra ja ostma kvaliteetseid riideid.\nKuna toitu pole meile kõigile piisavalt, peame kõik mängima rolli selles, et me toitu ilma asjata ära ei viska. Et meie planeet oleks puhtam, peaks samuti ostma kvaliteetsemaid riideesemeid, mida kanname korduvalt, et ei tekiks ebavajalikku prügi.');
