INSERT INTO core.text(id, content)
VALUES ('baa4883b-a585-4bf1-aff1-989978ef35cc',
        'Maailmas on tekkinud probleem, kus Inimesed on ka hakanud valima pigem kvantiteeti kui kvaliteeti ehk see tähendab rohkem reostust ja rohkem halba enda kehale.Kõik see kaup tuleb hiinast ning pole hea meie keskkonnale, kuid inimesed ei saa nendest probleemidest aru nii kaua kuni nad on näinud seda enda silmaga.\nInimestele on hakanud meeldima Hiina kaup, mis tuleb kohtadest kus kasutatakse laste võimu ja igasuguseid erinevaid kemikaale ,mis on ainult halb meile ning võib tekitada igasuguseid haigusi, kõige hullemas pildis isegi nahavähki. Selle põhjuse pärast on meil vaja, kas kodumaiseid kaupe, mis on hea kvaliteediga ja võime olla kindlad, et ei ole kasutatud ebavajalikke meetodeid riiete tegemiseks ja ka toksilisi aineid.\nEve Hanson väitis, et „Eelistada võiks kodumaiseid oma lähedal toodetud asju ning pigem vähem kui rohkem.“ See on väide millega võiks kõik nõustuda ja mitte tuua kolmandast riigist erinevaid kaupe, mida kannad ühekorra ja jääbki lõpuks kappi seisma. Kui ostad endale kvaliteetsema ja vähe kallima toote, jääb sulle see kohe kindlasti pikemaks ajaks ning sa ei raiska tulevikus raha iga aasta uue Hiina toodetele. Kodumaisetega on ka veel plusse. Sa toetad kohalikke inimesi ja riiki, ei tee enda kehale halba, ei toeta firmasi kes kasutavad lastejõudu, pikaajaga hoiad raha kokku ja on veelgi palju põhjuseid. Üks põhjus miks inimesed ei osta kohalikke asju on see, et need on liiga kallid ning mõtlevad, et hiinast saaks täpselt selle sama asja kolm korda odavamalt. Seda saaks lahendada sellega, et riik teeks palju reklaami selle kohta kuidas hiinast tellimine mõjutab meid ja mis aineid on kasutatud Hiinast toodud riietes ning toetaks  väikseid ettevõtteid rohkem.\nLoodetavasti võtavad inimesed tulevikus midagi ette ja üritavad seda probleemi lahendada võimalikult hästi, et ebavajalikud Hiina tooted ei jõuaks enam Eestisse. Eesti ülesanne on väikseid riide ettevõtteid võimalikult palju toetada, et inimestel tekiks võimalus teha enda firmasi ning ka enda produkti  inimestele edasi müüa.');
