INSERT INTO core.text(id, content)
VALUES ('a0475fad-9b1e-4adb-a390-60fa49704bad',
        'Inimesed raiskavad üha rohkem nii toitu kui riideid. Probleemi aluseks võib ola see, et inimesed ei saa aru, kuidas toit ja riided meie poodidesse jõuavad. Artiklis  tarbitoitutargalt.ee/toidukaost/ kirjutati: “Meile tundub, et toitu on veel ja see ei saa otsa“. Kas see ka päriselt nii on? \nPaljude inimeste lemmik veebipoeks on saanud Temu. Seal veebilehel müüakse Hiinas valmistatud tooteid väga odavalt. Tundub ju super võimalus osta toode mis maksab Eestis paarkümmend eurot, aga Hiinast saad sama toote umbes paari euroga. Kahjuks millelel paljud inimesed ei mõtle on see, et millise teekonna peab see pakk läbima. See tähendab seda, et liiklusvahendid, olgu nendeks laevad, lennukid vms, saastavad keskkonda tohutult. Saates „Vikerhommik“, intervjueeris Anu välba Eve Hansoni. Hanson ütles, et igaljuhul peaks eelistama valiteeti kvantiteedile. \nSamuti on riiete üleküllus meie suur probleem. Ostetakse ainult uusi riideid. mõtlemata kas mul tegelikult oleks ka seda vaja? Jälle tagasitulles ennist mainitud teema juurde, milleks oli Hiina veebipoed. Hiinas tehakse ka järgi väga sarnaseid riide esemeid, olgu selleks Nike, Jordan, Guess jms. Jällegi millele inimesed ei mõtle on see, et kui palju läheb maksma Hiinast enda koduriiki paki kohale toimetamine. Vahepeal on paki kohale toimetamine kallim, kui ese ise. Vaadatakse ainult toote hinda ja ollakse imestunud, et see nii odav on. Ning tellitakse neid hulgi kogustes. Samas saaks osta sama eseme Eestist ja säästa meie keskkonda.\nInimestele on jäänud mulje, et toitu on meil palju ja see ei saa kunagi otsa. Artiklis tarbitoitutargalt.ee/toidukaost/ kirjutati, et inimesel jääb aastas keskmiselt 61 kg toidujäätmeid üle. Mõeldes sellele, et Eesti elab üle ühe milljoni kolmesaja inimese on see ikka väga karm. See on lihtsalt mõtetu energia kadu. Inimesed võiks vaadata enda juurest natukene kaugemale ja mõelda, kui suurt rolli mängin mina selles keskkonnas.\nInimesed elavad hetkel väga heal ajal, nad ei pea mõtlema toidu ja riide vähesusele. Ühiskondlikult võiksime eelistada kodumaiseid tooteid ja neid rohkem tarbida, kui muudest riikidest sisse toodud kaupa. Vahepeal võiks võtta mõne hetke ja mõelda, kuidas saan olla mina kasulik keskkonnale, ja seda veelgi paremaks muuta.');
