INSERT INTO core.text(id, content)
VALUES ('a69e0bcb-7718-40a7-8052-9f3e328b176f',
        'Viimase sajandi jooksul on inimesed tootnud palju jäätmeid ja sellega reostanud loodust kui ka ühiskonnda. Inimesed hakkasid alles 21. sajandi algul aru saama, et jäätmeid on siin maailmas liiga palju ja neid tuleb kuidagi ära likvideerida. Kuidas saab inimene jäätmete mitte tekismisele kaasa aidata?\n     Praegusel kümmnendil on imesed hakkanud looma roboteid, mis koristaksid meie eest ookeane ja maismaad. Kuid inimesed peavad olema ise ka suureks abiliseks maailmakoristamisel, kui tahame, et meie lapsed elaksid heas ja tervislikus ühiskonnas. Inimesed peavad vähendama oma jäätmete tootmist, et järgmised põlvkonnad saaksid maailmas jäätmete vabana elada. Olen näinud videoid, kuidas robotid puhastavad merest jäätmeid ja taaskasutavad neid jäätmeid. Minu koolis on igaaastaselt prügijooks, kus terve koolipere käib mööda linna ringi ja koristab prügi, mis on maha visatud. See toimub ükskord septembris ja teine kord aprillis. Inimesed ei suuda kõiki jäätmeid ära koristada, aga me saame selleks abiksolla.\n     Iga inimene peab vaatama endale otsa ja mõtlema, kas tal on vaja uusi asju või saab ta vanadsi asju veel kasutada. Pragusel hetkel ongi liiga palju mõtetuid jäätmeid, sellepärast et inimesed ostavad uusi asja ja vanasi lihtsalt visatakse ära. Sama hästi saaks neid asju taaskasutada või ära anda neile, kes seda vajavad. Minul olid väga korralikud teksapüksid, mis olid mulle väikeseks jäänud, mõtlesin algul, et viskan need ära, agasiis tuli meelde, et mul on väike sugulane kellele need sobivad. Mänguasjad, millega inimene enam ei mängi neid ei ole mõtet ära visata, vaid anda näiteks lastaeda või kellegile. Jäätmete teke algab igal inimesel endast.\n     Suured tööstused on peamised jäätmete tootjad. Tööstuste olevad tooteid tootetaks nii, et pool materjalist läheb raisku. Teksapükside tööstus, pool riitest läheb lihtsalt ära viskamise, kuid sama hästi saaks sellest luua uusi tooteid, nagu parandaims metrjaal või midagi. See aitaks vähendada jäätmete tootmist. T-särkide tööstus, kus läheb samuti poole riidest äraviskamise. Nendele peab leidma mingi hea lahenduse, et seda riiet võimalikuld vähe ära visata. Tuleb leida lahendusi jäätmete kasutamisel.\n     Jäätmed on praegusel hetkel väga suur osa meie tulevikus suhtes. Loomad, kes surevad ooekanis või metsas jäätmete pärast. See on suur probeemi mis vajab lahendust. Inimesed ei jõua kõiki jäätmeid ära koristada, aga me saame selleks abiksolla. Iga jääde, mis siis maailma tekib algab inimesest. Kui tahame, meie lastele head tuleviku siis peame leidma lahendusi jäätmete taaskasutamisel.');
INSERT INTO core.text_property(text_id, property_name, property_value)
