INSERT INTO core.text(id, content)
VALUES ('a0f51cfc-aeaa-4146-9a31-62c8f3c7da0c',
        'Tänapäeval on palju globaalprobleeme, mis mõjutab inimeste elustiili ja tervist ning mõjutavad loodust ja majandust ülemaailmselt ja halvad tarbimisharjumused on üks nendest teguritest.\nEnne lahenduste läbirääkimist, peab enne ülevaatama, mis on meie halvad tarbimisharjumused ja toit on üks neist. Peamine põhjus on see, et inimesed viskavad toitu minema ja nad sellega suurt pilti ei näe. Keskmine eestlane viskab aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu on sellest 42% ehk 26kg. Nad viskavad toitu minema järgnevatest põhjustest: toit on üle kasutustähtaja, toit ei ole kvaliteetne, toidu ülejäägid jm. Pidama peab meeles seda, et toidu tootmiseks kulub maad, sööta, tööjõudu ja energiat- need on samuti üks globaalprobleemide osasid. Nendest teemadest on detailsemini räägitud tarbitoitutargalt.ee/toidukaost/  veebilehel. Selle probleemi täielik lahendamine ei tule sõrmenipsuga, selle jaoks kulub palju aega ja vaeva. Lahenduseks sobiks kõige paremini inimeste toitumisharjumuste muutmine. Poes šoppamas, mitte osta üleliigselt palju toitu, mida lihtsalt süüa kõike ei suudaks. See lahendaks kahte toidukao peamist probleemi: toidu ülejäägid ja kasutustätaja ületamine.\nTaaskasutuspoodidest peaks asju rohkem ostma, sest sealt kodumasinate ja riiete ostmine vähendab materiaalset kulu, sellest teemast räägiti saates „Vikerhommik“ ja intervjueeriti moedisaineri Eve Hansoni ja tema arvates oli, et igaüks vaataks üle oma isiklikud tarbimisharjumused ning eelistaks kvaliteeti kvantiteedile ning ei telliks Hiina veebipoodidest põhimõtte pärast asju, et läheks kaasa sooduskampaaniatega. Ta veel ütles, et eelistada võiks kodumaiseid asju. On nähtud, et taaskasutuspoodide laos on vanade riiete kogus väga suur, mis tekib iganädalaselt juurde. Eve Hanson veel soovitas, et noortele peaks sinna ekskursioone korraldama, et näidata, milline raiskamine tegeliklut toimub.\nToidu raiskamine ja vanade kodumasinate ning riiete minema viskamine on suur inimkonna ja keskkonna probleem, mis on arenenud juba globaalprobleemiks. Meil on kõik mõtted olemas, kuidas neid probleeme lahendada, aga inimesed ei ole veel piisavalt motiveeritud nendega tegelema. Ühe lausega öeldes, peab inimesi varaselt õpetama väärtuslike maa ressursse säästma.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('a0f51cfc-aeaa-4146-9a31-62c8f3c7da0c', 'title', 'Inimeste halvad tarbimisharjumused ja nende lahendamine');
