INSERT INTO core.text(id, content)
VALUES ('61c4a1d5-965a-4471-ba06-3b3355adeb30',
        'Me kõik oleme midagi raisku lasknud. See võis olla mõni toiduaine, riideese või midagi muud. Raiskamise suurus võib tunduda väike, kuid tegelikult see nii ei ole. Peaksime kõik olema veidi kokkuhoidlikumad ning targemad tarbimise suhtes.\nKui rääkida raiskamisest siis tuleb pähe ilmselt toit. Sellel on lihtne lasta halvaks minna ning paljud inimesed on toidu suhtes väga valivad. Inimesed viskavad seda suurtes kogustes lihtsalt minema. Tarbitoitutargalt.ee artikli sõnul tekitab iga Eesti inimene keskmiselt 61 kg toidujäätmeid millest 26 kg on toidukadu. Räägitakse ka sellest kuidas me ei raiska ainult enda raha, vaid ka tohutult muid ressursse nagu maad, vett, energiat ja tööjõudu. Sellise probleemi lahendamiseks peavad inimesed ise vaeva nägema ja oma harjumusi muutma. Ka rõivaid lastakse kergesti raisku.\nTaaskasutuspoed on kohad kuhu inimesed saavad viia oma riideid mida nad enam ei kanna. Kahjuks viiakse sinna tohutus koguses riideid. Moedisainer Eve Hansoni sõnul viiakse sinna palju korralikke riideid, kui ka riideid mille kvaliteet on kehv. Tema arvab, et inimesed peaksid eelistama kvaliteeti kvantiteedile. Paljud ostavad riideid erinevatest Hiina poodidest odavalt, kuid viskavad need pärast mõnda kandmist minema, sest need on ebamugavad. Isiklikult nõustun Eve Hansoniga ning proovin ise ka hoida eemale odavast jamast. \nInimesed peavad aru saama, et odav ei tähenda alati head. Vahepeal ostetakse kokku toidukraami mida ei suudeta ära süüa või riideid mida ei taheta pärast mõnda kasutust enam selga panna. Peab olema teadlik kas ost on väärt seda ja kas ostetud asja tarbitakse targalt.');
