INSERT INTO core.text(id, content)
VALUES ('5ba9c276-a48f-44b2-8a5e-4ca4a290fa67',
        'Inimesed ostavad asju, mõtlemata kas nad päriselt vajavad seda. See on tekitanud toodete suure ületarbimise ülemaailma mis rikkub keskkonda ja kulutab vajalikke maa ressursse.\nToit on üks suurimaid tegureid inimeste ületarbimises. Toitu ostetakse tohutus koguses, mida pole võimalik ara süüa ja enamus läheb raisku. Kokku aastas raiskub toitu inimese kohta palju rohkem kui arvata võiks. Nagu tarbitoitutargalt.ee kirjutas: ,, Kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg.’’ Seda probleemi on raske lahendada kuna paljud isegi ei märka, et nad nii palju raiskavad, sest see on nende harjumustes kinni ja seda tehtakse ilma mõtlemata. Inimestele peab õpetama ja tegema näiteid sellest kui palju päriselt raisatakse ja mis mõjud sellel on keskkonnale.\nPaljud inimesed ostavad riideid mida nad ei vaja ega taha. Inimesed lähevad poodi ning märkavad head soodukat ja siis tuleb neile surve, et osta midagi, sest see on soodukaga, kuid tegelikult nad ei vaja seda. Suur osa sellest on mood mis muutud pidevalt ja mida inimesed tahavad alati jälgida. Ostetakse moodsad riided mis lähevad paari aastaga moest välja ning visatakse välja. Seda saaks leevendad kui inimesed hakkaksid ostma riide esemeid mis neile meeldivad ja mida nad tahavad kanda, mitte mis teistele meeldib või mis moes on sellel hetkel. \nPaljud inimesed ostavad rohkem kui tegelikult tahavad, see on loomulik, aga see on suur probleem keskkonnale. Ühiskond peaks panema suurema kohustuse ületarbimise kohta õpetamisele ja kuidas seda ennetada.');
