INSERT INTO core.text(id, content)
VALUES ('57507154-86c1-4d4c-965d-291ca23b3926',
        'Viimase 10 – 15 aasta jooksul on inimeste ressurside tarbimine halvenenud. On hakkatud toitu raiskama, lõhkuma asju mida pole vaja, mis tegelikult töötavad jne. Inimesi ei ole õppetatud säästma või tagasi viima asju, kuna mõned vanemad on nii laisad. Seega tarbimine on halvenenud\nMaailmas on inimesi kes raiskavad toitu, sest nad saavad seda endale lubada ja väiksemaid kogusi toitu ära visanud inimesed arvavad et see ei mõjuta maailma pilti. See on väga vale. Kodudes tekkib iga eesti inimese kohta aastas 61kg toidujäätmeid, millest toidukadu moodustab 26kg. Seetõttu ei raisata ainult raha, vaid ka tohutult vett, energiat, maad ja tööjõudu.\nInimesed viskavad paljusi asju ära mis tegelt on kas terved või isegi uued. Ei teata miks , aga see muutub juba keskkonna probleemiks, sest neid asju võidakse kuskile metsa vahele jätta või isegi vette visata. Näitena kui ma kunagi väike olin, siis ma olin ka siuke, kellele ei meeldinud asi, siis lihtsalt viskan minema või jättan seisma selle kuhugi. Aga suureks saades ma sain aru mis vea ma tegin ja enam ei tee siukest asja. Seega see võib muutuda keskkonna probleemiks.\nÜhiskonnas on hakkatud aina rohkem ressurse kaevandama maapõuest ja puude raiumine on halvaks läinud. Seda on hakkatud tegema, kuna tahtmine on suurem, ja saab maju rohkem ehitada kuid see on täiesti mõttetu, kuna meil on hooneid piisavalt ja kõndimine ka on olemas autode asemel. Amazoni vihmamets hakkab väiksemaks jääma metsaraiete pärast, sest on vaja paberit rohkem teha kuigi seda raisatakse rohkem kui toitu. Seega seda tegevust peab vähendama.\n10 – 15 aasta jooksul inimeste tarbimisharjumused on tõesti halvemaks läinud, kuna inimesed ei hooli ültse oma planeedist enam. Neid lihtsalt huvitab see, kuidas sotsiaalmeedias kuulsaks saada toidu raiskamised ja kuna nad saavad endale uue telefoni. Kasulikude asjade ära viskamine võib muutuda probleemiks tulevikus reostuse tõttu. Lõppuks mina proovin vähem toitu raisata ja asju ära anda, mis pole mulle vajalikud enam');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('57507154-86c1-4d4c-965d-291ca23b3926', 'title', 'inimeste tarbimisharjumused');
