INSERT INTO core.text(id, content)
VALUES ('e76c5b61-ec1e-4c0a-84bc-30d3f5267855',
        'Paljudel inimestel tekivad jäägid, nii toidu kui ka muude toodete puhul. Kui palju seda tekib ja kuidas seda vähendada?\nInimesed kellel tekib väiksem kogus jääke mõjutavad ikkagi palju. Tarbitoitutargalt.ee väidab, et on inimesi, kes raiskavad toitu, sest nad saavad seda endale lubada. Leht mainib ka seda, et inimesed kes viskavad ära väiksemaid koguseid mõjutab ka päris palju. kodumajanduses tekib iga Eesti inimese kohta aastas kesmiselt 61kg toidujäätmeid, millest toidukaup moodustab 42% ehk 26 kg. See tähendab, et Inimesed kellel tekib vähem jääke ikkagi mõjutavad palju kuna see lisandub Eesti keskmisele.\nKui tahta vähem jääke tekitada tuleks õigeaegselt tooted ära tarbida. Suur osa toidujäätmeid tekib sellest, et ei jõuta toode enne kasutuskuupäeva ära tarbida. Selle põhjuseks võib olla ka see, et ostetakse liiga palju ning ei ole toodet ära tarbida. Teine põhjus võib olla ka see, et unustatakse, et neil see toode olemas on. See tähendab, et selle lahendamiseks tuleks mõelda rohkem koguste üle ja mitte tooteid kappi riknema unustada. \nParem on osta kodumaiseid riideid. Hanson tõi välja, et ei telliks Hiina veebipoodidest juba põhimõtte pärast asju, ei läheks kaasa sooduskampaaniatega. Hiinast tellides ei pruugi olla kvaliteet kõige parem mistõttu ei kesta ostetud riiided kaua. Hiinast ostes mõjutab see ka loodust kuna keegi peab riided kaugelt Hiinast need Eestisse tooma. Hanson tõi ka välja, et eelistada võiks kodumaiseid oma lähedal toodetud asju ning pigem vähem kui rohkem. See tähendab, et kasulikum on osta kodumaal toodetud tooteid kuna need on kvaliteetsemad ja ei pea nii palju vaeva nägema transpordiga. \nEesti keskmises majapidamises tekib 61kg toidujäätmeid aastas. Toidujäätmete vähendamiseks peaks pöörama rohkem tähelepanu kogustele ja kuupäevadele, ning riideid tuleks osta kohalikumatest kohtadest mitte Hiina veebipoodidest.');
