INSERT INTO core.text(id, content)
VALUES ('993d1c48-58dd-4fdc-bce7-a99dd811a5aa',
        'Ei mõelda üldse kui palju inimesed tegelikult maa ressursse raiskavad, olgu need siis seotud riiete või toiduga. Me võtame peaaegu kõike iseenesestmõistetavana. Kuidas ning mida siis inimesed tarbivad ja ressursse raiskavad?\nInimesed ei mõtle selle peale kui palju nad tegelikult toitu ära viskavad. Me mitte ainult ei raiska sellega oma raha, vaid kulutame ka tohutult palju ressursse milleks on näiteks maa, vesi või energia. Toidu tootmine on kahjulik ka keskkonnale kuna suurema saagi kasvatamiseks kasutatakse väetiseid ja kemikaale, mis omakorda võivad mürgitada põhjavett ning, kui kemikaalid liiguvad edasi teistele taimedele võiad ka loomad haigestuda. Inimesed peaks enne toidu ostmist mõtlema täpselt, kui palju ja mida vaja on, sest toidu raiskamine on suur probleem.\nInimesed peaksid riideid ostes valima kvaliteedi kvaniteedi asemel ning mõtlema täpselt kas on vaja osta riideese, mida tahetakse kanda vaid korra või kaks. Enne riiete ostmist tuleks ikkagi kodus oma garderoob läbi vaadata ja võimalik, et seal leidub midagi mis võib soovitud asju asendada. Võib ka ju käia taaskasutuspoodides, sest kunagi ei või teada mida sealt leida võib. Ka moedisainer Eve Hansoni arvates peaks just eriti noortele tutvustama taaskasutatud poodide ladusid, et nad näeks, kui suur raiskamine tegelikult toimub. Alati tuleb põhjaikult mõelda sele peale, kas ikka on mõtet osta riideese, mis on küll moes, kuid endale väga ei meeldi.\nEnda kohta võin öelda, et toidu raiskamine pole minu jaoks probleem, kuna mõtlen alati läbi mida ja kui palju ma ostan. Ma üritan alati kõike nii lõpuni tarbida, kui vähegi saab. Riietega on mul aga teised lood kuna neid on mul üsna palju. Olen hakanud vähem ostma riideid odavatest Hiina netipoodidest ning käin ka rohkem taaskasutuskauplustes. Sealt võib leida väga huitavaid ja ilusaid riideid. Olen teinud palju edusamme, et vähendada oma toidu raiskamist ning ka hunnikutes riiete ostmist.\nToidu raiskamine on maailmas suur probleem ning sellega peab aktiivselt tegelema muidu ei muutu mitte midagi. Inimeste tarbimine riiete osas on ka väga tõsine probleem, kuna on nii palju odavaid netipoode kust saad osta riideid, kuid need pole hea kvaliteediga ja ei kesta kaua. Igaüks peaks vaatama üle oma tarbimsharjumused ning tõsiselt mõtlema mida ta teha saab, et seda paremaks muuta. Kui kõik tarbivad teadlikult, siis on võimalus, et olukord paraneb.');
