INSERT INTO core.text(id, content)
VALUES ('adff73f9-cce3-4988-bed7-537142f2f54e',
        'Eesti inimestele tundub , et toit ei saa kunagi otsa. On ka inimesi ,kes saavad toidu raiskamist endale lubada. Iga Eesti inimese kohta on keskmiselt 61kg toidujäätmeid. Seega ma uurin selles kirjandis inimeste tarbimisharjumusi.\nToidukadu ehk raisatud toit on toit või toiduaine, mis mingil põhjusel (riknenud või kasutustähtaja ületanud toit, söömisel ülejäänud toit vms). Toit pole ainuke asi mida raiskame ,vaid ka tohutult palju teisi maavarasi: vett, energiat,maad. Me kõik oleme kunagi toitu raiskanud , näiteks kui mina väike olin siis mul oli väke kõht aga suur süda, ning ma viskasin toidujäägid minema või peitsin vanemate eest ära.\nSuur osa inimkonnast viskavad oma rõivaid ära või kaotavad. Taaskasutuse poodidesse viiakse väga suures koguses rõivaid ,ning siis tellivad endale hiina kaubamajadest rõivaid mis on väga suure nafta sisaldusega. Näiteks on õelnud Moedisainer Eve Hanson ,,Ma näen taaskasutuspoodide laos vabatahtlikuks käies seda rõivaste kogust, mis tekib iganädalaselt juurde. Need on meeletud hunnikud ja see on väga õpetlik. Ma arvan, et peaks hakkama noortele ekskursioone taaskasutuspoodide lattu, et näidata, milline raiskamine tegelikult toimub.\nNii , et inimesed ei hukka ainult toitu ,vaid ka riideid. Riided ja toit võrdub tohutud maavara ressurssid. Kahjuks ei saa vähendada üleöö. See on paljuski kinni inimeste harjumustes.');
INSERT INTO core.text_property(text_id, property_name, property_value)
