INSERT INTO core.text(id, content)
VALUES ('cedfb072-991d-40fe-841b-b4ac92522a45',
        'Suureks probleemiks on kodupidamises toidu raiskamine. Seda teeb iga Eesti pere ja see probleem ainult kasvab. Kuidas vähendada toidu raiskamist?\nKõige loogilisem ja efektiivsem viis kuidas toitu mitte raisata on kuupäevade vaatamisega. Enamasti on poodides olevad tooted lähedal kõlblikkuse tähtpäevani ja seda ei panda tähele. Eriti siis, kui on kiire, ei vaadata kuupäevi ja on suur võimalus, et võetud toode on juba halvaks läinud. Seda avastatakse alles siis, kui toode on pakendist lahti tehtud ja on tunda halba aroomi. Keegi ei hakka seda enam sööma, ning lendabki prügikasti. Alati tuleb olla hoolas kuupäevadega, mida värskem seda parem. Veebileht tarbitoitutargalt.ee/toidukaost/ ütleb järgmiselt: „Kodupidamises tekib iga Eesti inimese kohta aastas keskmiselt 61kg toidujäätmeid, millest 42% ehk 26kg on toidukadu.“\nToit mida on unustatud külmkapi taha nurka on samuti hea näide, millega saaks vähendada toiduraiskamist. Hea viis on osta toitu, mis meeldib ja pole mõtet raisata raha toidule mida ei sallita. Oleks hea, kui on plaan, mis toitu kasutatakse lähipäevadel ja mida pole praegu vaja. Isiklikult ei ole oliivi sõber, ma ei raiska raha selle peale, isegi siis kui minu pereliikmetele meeldib. Ma ei saa olla kindel, et see süüakse ära.\nKuupäevade vaatamine ja õigete toodete ostmine aitab drastiliselt vähendada toidujäätmete teket. Inimesed raiskavad toitu rohkem, kui arvavad. Kõik peaksid sellele rohkem tähelepanu pöörama.');
