INSERT INTO core.text(id, content)
VALUES ('c96d2d42-6b61-42e2-87a0-0a1abcdef009',
        'Miks inimesed viskavad suurel määral toitu ära ja Kuidas me saaks parandata ja mida parandata? Seal võib olla palju põhjuseid, miks inimesed viskavad toitu ära ja kuidas see toit ikkagi  prügikasti satub.\nMinu arvates tundub see veits nõme ja seda peaks parandama, sest maailmas on palju inimesi kes on näljas ja pole nii heades elupaikades, kus on söök kohe kätte saadav. Vahel on kuulda kuidas inimesed ei ole rahul enda riikiga ja ütlevad, et „See riik on täielik pommiauk“ jne, kuid minu arvates on meil siin väga hea siin.\nToidu ära viskamist peab vähendama ja selle peab ettevõtma. Minu arvates saaksime seda parandata mitmeid moodi, näiteks igal inimesel päeva limiit, kui palju ta saab osta poest süüa, mis sõltub kui suur ta pere on ja hiljem arvutada välja, kui palju ta toitu ära viskas ja selle pealt trahvi maksta, äkki nii saavad rohkem inimesed aru, kui palju nad toitu viskavad ja mida nad raiskavad. Olen ka enda peres näinud toidu raiskamist, kuid siis ei osanud aravata kui suurt rolli see mängida võib.\nInimesed võivad toitu ära visata mitme põhjuse pärast, nagu näiteks minnakse tühja kõhuga poodi ja siis kõik mis seal on näeb hea välja ja jääb tunne, et tahaks tervet poodi ära osta. Inimesed peaks käima täis kõhuga poes ja siis on vähem sööki, mida ära visata.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('c96d2d42-6b61-42e2-87a0-0a1abcdef009', 'title', 'Miks inimesed viskavad toitu ära?');
INSERT INTO core.text_property(text_id, property_name, property_value)
