INSERT INTO core.text(id, content)
VALUES ('69b90ee5-0d69-4815-8903-afa81daa58d2',
        'Kui ma käin erinevates poodides riideid otsimas, siis ma alati vaatan kui palju mis toode maksab. Tihtipeale ma isegi hakkan mõtlema kus kohast ma saaks valitud asja odavamalt. Kuigi kas me saaks kuidagi inimesi panna rohkem kaltsukates käima?\nErinevad inimesed vaatavad erinevaid riideid teist moodi, mõni vaatab vana kampsunit ja mõtleb kui kole see välja näeb, aga teine leiab selle üsnagi ilusana. Kui ma ise käin taaskasutuspoodides, siis ma enamast ei leia asju, kuna just see topp ei sobi või need püksid on koledad. Inimesed peaks aru saama kui palju meil neid riideid raisku läheb. Ma ise ei saa kõigi eest rääkida, aga olen üsnagi kindel, et inimesed tegelikult käiksid rohkem kaltsukates kui see ei oleks nii allakäinud.\nMa vahel kahetsen, kui olen jälle esitanud tellimuse Hiina, aga kui mul pole raha ja kiirmood on nii lahe on see raske. Tegelikult kui ma jättaks selle kõik maha ja hakkaksin hoopis kaltsukates rohkem käima, ega ma siis nii hullult ei telliksgi. Kõige hullem selle juures on see, kui lihtne on osta internetist riideid mis võimalikult lõppetavad kusagil prügikastis või hoopisgi sinu lähedal kaltsukas.\nMina arvan, et me võiks hakkata rohkem „Promoma“ kaltukaid. See oleks kasulik meile ja ka neile väikestele firmadele hea kes proovivad ise kaasa meie riiete raisule. Muidugi võiks me ka lõppetada need mõttetud hinna kauba tellimise. Meil oleks võibolla natukenegi vähem neid tühjasi riidehunnikuid.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('69b90ee5-0d69-4815-8903-afa81daa58d2', 'title', 'Miks peaks inimesed taaskasutuspoodides käima?');
