INSERT INTO core.text(id, content)
VALUES ('9e30bcff-9217-41be-9699-98089dad5d92',
        'Ühiskonna üks suuremaid probleeme on kliimasoojenemine aga paljud ei pööra tähelepanu toiduraiskamisele. Toidukaost on muutunud suureks probleemiks kuigi paljud ei saa sellest arugi. Selle põhimõttel tekib küsimus. Miks inimesed raiskavad toitu ja mis selle põhjustab?\nPaljud mu tuttavad ütlevad, et toidu ära viskamine ei tee halba ning ei mõjuta meid. Võib tunduda, et see väike kogus mis sageli prügikasti visatakse ei tee halba siis see tegelikult nii ei ole. Tarbitoitutargalt.ee poolt saadud uuringu tulemused näitavad, et iga Eesti inimese kohta tekib aastas keskmiselt 61kg toidujäätmeid ja sellest 26kg moodustab toidukadu. Tuleb pöörata suuremat tähelepanu ning iga inimene peaks üle mõtlema toitu ära visates kas see on ikka vajalik.\nToidu ära viskamine on inimeste harjumuses juba mitme kümneid aastaid. Näiteks mu perekonna liikmetele on see juba tavaline visata ära külmaks või seisma jäänud toit, kuna neil ei ole isu selle vastu enam. Toiduraiskamine tekib ka üld juhtudel sellest, et inimesed saavad lubada endale suures koguses toidu ostmist. Ei mõisteta seda, et ei kaotata ainult raha vaid ka ressursse, millega toodetakse neid toite ja see on meile väga halb.\nVaadates kõiki neid probleeme mis tekivad toidu ära viskamisel ning raiskamisel saan öelda, et iga inimene peaks mõtlema üle kas on ikka vaja suurendada toiduraiskamist. Inimesed peavad hakkama toitu otstarbekalt kasutama ja vähemates kogustes ostma. Harjumusi peab muutma ning toiduraiskamine peab ära lõppema nendele tulenevate probleemide pärast.');
INSERT INTO core.text_property(text_id, property_name, property_value)
