INSERT INTO core.text(id, content)
VALUES ('3cd5f71f-525c-4104-b5d9-e5eeacf0c0d7',
        'Maailmas on erinevaid probleeme. Üks nendest on toidu ja riiete ära viskamine. Aga miks visatakse asju ära?\nToitu visatakse ära sest, toit on halvaks läinud või oma kuupäeva ületanud. Halvaks läinud toitu visatakse enamus korral komposti, et sellest tekiks viljakas muld millega saab taimi istudada. Inimesed ka raiskavad raha, et toitu või toidu lisandeid osta mis on lihtsalt raha kulutamine. Toiduraiskamist on proovitud vähendada aga see ei juhtu kiiresti sest, enamik inimesi maailmas on juba harjujnud sellega, et nad on selle toidu ära viskamisega ära harjunud.\nEnamus riideid tulevad Hiiinast ja neid müüakse soodsalt teistes riikides. Aga asi on selles et, need riided mis Hiinas toodetakse ei ole hea kvaliteediga ning need lähvad lihtsasti katki. Parem on osta riided mis on Eestis tehtud sest Eestis tehtud riided võivad olla parema kvaliteediga kui riided mis on Hiinas tehtud. \nInimesed võiksid vanu ja katkisi riideid taaskasutada uute asjade tegemisks. Näiteks teha teksapüksdest seeliku või kotti. Või kui riidetesse on tulnud augud siis tikkitakse midagi, et seda saaks uuesti ja kauem kasutada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
