INSERT INTO core.text(id, content)
VALUES ('a6e294b4-0918-4040-8dd0-463eb521e288',
        'Inimestena tarbime me igapäeva elus suurtes kogustes toitu sest ilma toiduta organism ei funktsioneeri. Toit on ühiskonnas nii tavaline sest toidupoed on ju põhimõtteliselt igalpool ja toit on kogu aeg kättesaadav, mis tõttu kipuvad inimesed toitu raiskama.\nToit ja toidu raiskamine käivad käsikäes, iga inimene viskab alatihti mingisuguse toiduaine ära. Põhjuseid on mitmeid: inimesed ei ostavad rohkem toitu kui nad tarbivad, ei mõelda ette, toiduaineid ostetakse läheneva kuupäevaga ning unustatakse ära, ostetakse midagi, et proovida kuid see ei pruugi maitselt meeldiv olla ja visatakse ära, saadakse toidust isu täis ja arvatakse, et peaks ära viskama.\nKuidas käituda, et võimalikult vähe toitu ära visata? Poes käies tuleks mõelda ette oma nädala söögid ja söögikorrad, et selle järgi ostetava toidu kogust arvestada. Tuleks ettevaatlik olla uute toiduainete katsetamisega või teha seda mõne lähedasega ehk keegi ikka ära sööb. Tuleks jälgida kuupäevi toodetel mida soovid osta. \nVõiksime iimestena meeles pidada, et toiduainete tegemiseks ja poelettidele saamiseks kuluvad selleks nii tööjõud,elekter ja tehnika,töötajate aeg ja iseenda raha mille pealt võiks kokkuhoida. \nTarbime toitu targalt ja ärme unusta mõelda mida tegelikult kindla aja sees sööme ja kui palju. Säästame ennast kui ka ühiskonda,');
INSERT INTO core.text_property(text_id, property_name, property_value)
