INSERT INTO core.text(id, content)
VALUES ('f85e694b-2500-4ac9-8b38-9fcedd8ffad2',
        'Kaupu tarbitakse väga palju, ning sellepärast on oluline teada, kust osta ja mida jälgida. Miks on halb tellida Hiinast või teistest Aasia riikidest kaupu, mis on valmistatud halbades tingimustes? Mis üldse on need halvad tingimused? Kumb on olulisem, kas kvaliteet või hind?\nTänapäeval on tarbimisharjumused muutunud kvantiteedi põhiseks. Hiinast ostetud odav kaup on muutunud harjumuspäraseks ja inimesed ei ole enam nii kursis ja teadlikud, mis seal tegelikult toimub. Paljudes tööstustes Hiinas ja teistes Aasia riikides, valmistatakse riideid ja teisi tarbeid väga halbades töötingimustes: ületunnid, lapstööjõud, väike palk ja vähesed puhketunnid. Tellides sealt, võib muutuda tööliste sealne elu raskemaks. Et Aasia riikide toodetud kaupade tarbimist vähendada tuleks tutvuda sealsete tööoludega, ning siis vaadata, kas sealt ikka on soov osta.\nTihtilugu hoitakse silm peal hinnal, mitte kvaliteedil. Ostes odavast riidepoest endale riie, mis on odav, aga kestab lühikest aega, ei ole just kõige mõistlikum. Kõige tähtsam on kvaliteet, arvatakse, et mida kallim riie, seda parem kvaliteet, aga see ei pruugi niiviisi olla. Veendudes, et kvaliteet on hea, tuleb vaadata silte kaupadel, nind hind jätta tagaplaanile. \nHiinast või teistest Aasia riikidest on halb tellida kaupu kohast, millest sa tegelikult midagi ei tea. Tooted võivad valmida halbades tingimustes, ning mõjutada tööliste elu veelgi raskemaks. Ületunnid, lapstööjõud, väike palk, ning vähesed puhketunnid, võivad muutuda rängemaks, kui sealt palju tellida. Toodete puhul kõige olulisem on kvaliteet, mitte hind, tutvudes siltide ja infoga toodete küljes, on võimalik tutvuda kvaliteediga.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('f85e694b-2500-4ac9-8b38-9fcedd8ffad2', 'title', 'Kuidas tarbida?');
INSERT INTO core.text_property(text_id, property_name, property_value)
