INSERT INTO core.text(id, content)
VALUES ('b49ea890-d200-40a3-9baf-81ec368c9863',
        'Tänapäeval on maailmas kaks suurt probleemi. Meie inimestena raiskame igapäevaselt väga palju toitu ja materjale. Aga miks me seda teeme ja mis seda võib põhjustada? Toitu ja ressursse ei ole siin maa peal lõpmatuseni ja need võivad millalgil otsa saada. Et seda takistada kõik peavad üritama kaasa aidata ning andma endast maksimumi.\nSuur osa raisatud toidust tuleb koolidest, kuna õpilased võtavad endale rohkem süüa kui nad ise suudavad ära süüa. See põhjustab väga suurtes kogustes toidu raiskamist, kuid lahendus on lihtne. Paljudes koolides on nii ,et õpilased tõstavad endale portse, aga kui  kokka tädid tõstaksid ise, see vähendaks palju toidu ära viskamist. \nPraegusel ajal on vägu populaarne Hiinast tellida endale odavat kaupa mida sa arvad et sul on vaja, kuigi tegelikult ei ole. Inimesed näevad et hinnad on odavad ja tellivad mõtetuid asju. Enne ostmist peab ikka üle mõtlema kas sa päriselt ka vajad midagi sellist või kas see pigem teeb maailmale halba või head. Materjale ei ole ka lõpmatuseni ja kui me neid mõtetute asjadele raiskame siis see pole tark.\nMinu arvates on see raiskamine täiesti ebavajalik ükski asi ei kesta lõpmatuseni, nii et järgmine kord kui midagi tellid osta pigem üks kvaliteetne asi, kui mitut odavat ja mõtetud asja ja enne kui toitu ära viskad ,mõtle selle peale ,et kui koguaeg ära viskaksid kui palju toitu sa tegelikult raiskad.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('b49ea890-d200-40a3-9baf-81ec368c9863', 'title', 'Toidukaost');
INSERT INTO core.text_property(text_id, property_name, property_value)
