INSERT INTO core.text(id, content)
VALUES ('f530fefe-c18a-4742-aa14-8bf88a7652ee',
        'Igapäeva elus me raiskame toitu aga ise aru ei saa, kui suurtes kogustes päriselt meil raisku läheb. Inimesed samuti tellivad odavkaupa Hiinast, kuid nad ei tea kui halvasti need päriselt tehtud on ja kui halvas keskkonnas. Miks meil läheb nii palju toitu alati raisku ilma et me tähele paneks? Miks tellitakse Hiinast odavaid asju?\nMeil läheb toitu raisku igapäevaselt, ja aja jooksul sellest võib saada päris suur kogus. Inimesed võivad juba olla harjunud toidu ära viskamisega, kui nad näiteks rohkem ei jõua. Sellest tunduvalt olematust probleemist võib välja kujuneda väga suur raiskamine. Kuid toidu raiskamist saaks lihtsalt vähendada, pannes endale koguse milles oled kindel, et jõuad ära süüa ja kui tahad, saad võtta veel.\nHiina odavkauba tellimine võib tunduda pealevaadates okei. Samuti need veebi reklaamid võivad tunduda ahvatlevad, kuid kui peale vajutad pead hakkama suuri summasi kulutama mõne tasuta asja jaoks. Probleemiks on see, kuidas need tooted on tehtud ja kui halvasti neid töölisi seal koheldakse. Töötajaid koheldatakse seal nagu tööriistu ning Hiina firmasi huvitab ainult üks, et saada müüdud võimalikult palju tooteid, ilma et nad peaksid toodetele palju kulutama. Sellest tulenevadki need odavad- ja halvast kvaliteedist tooted. \nToiduraiskamist saab vähendada oma koguste kontrollimisega üle aja, ja ongi säästetud raha, toitu ja muid ressurse. Hiina kauba asemel saad maksta natuke rohkem, ja saad juba kvaliteetsemaid tooteid kohalikest poodidest.');
INSERT INTO core.text_property(text_id, property_name, property_value)
