INSERT INTO core.text(id, content)
VALUES ('34ef8793-8472-4d7a-9f32-1f10a91874d4',
        'Toitumine on meie kui inimeste väga tähtis osa, kui seda poleks, ei oleks ka inimesi, siiski kipub inimestele kombeks toitu ära visata. See tekitab küsimuse. Miks inimesed toitu raiskavad? Kuidas saaks vähendada liigset toidu raiskamist?\nInimesed kui segatoidulised vajavad mitmekülgset toitumist ellujäämiseks, kuigi inimestele on jäänud kombeks toitu suures hulgas ära visata, siis üritatakse seda vähendada. Inimestel on mitmeid põhjuseid toidu ära viskamiseks, näiteks inimene võtab suure kuhja süüa ja seetõttu võib minna suur osa toidust ära viskamisele. Teine suur probleem on selles, et inimesed ostavad poest liiga suures koguses sööki, hiljem märkavad, et toit on aegunud ja viskavad suures koguses toitu ära. Näiteks võetakse 2 pakki leiba, 1 pakk kasutatakse supi kõrval söömiseks ära ja teine pakk jääb lihtsalt kappi seisma ning pärast märgatakse, et pakk leiba on aegunud ja see läheb lihtsalt ära viskamisele.\nToidu raiskamist saaks vähendada sedasi, et kui sööd, siis võtad sobiva portsu süüa, mitte liiga palju, vaid kui kõht jääb tühjaks, võtad toitu juurde, kuna ülejäänud toit võib minna ära viskamisele. Selle pealt saab õelda, et kui toitud korrektselt jääb raha rohkem alles ja keskkonna seis jääb positiivseks.\nLõpetuseks võin õelda, et kui sa kasutad oma raha ja mõtlemisvõimet korrektselt jääb keskkonna seis heaks, kui aga ostad asju mida sul vaja pole ja võtad rohkem toitu kui sa süüa jõuad, halveneb ka keskkonna seis.');
