INSERT INTO core.text(id, content)
VALUES ('2ec60df5-65bc-4220-9b8a-7edc7c260cdc',
        'Ühiskonnas, kus kõik on kättesaadav, tundub tarbimine nagu loomulik instinkt. Me kõik soovime uusi asju, aga kas meil neid vaja on, on miski mille peale paljud ei mõtle. Miks tunnevad inimesed suurt ihaldust koguaeg uusi esemeid osta?\nInimene soovib alati midagi rohkemat, et olla õnnelik. Kui inimesel ei ole eluks vajalike ressurse nagu toit ja vesi, ei huvita neid muu, kui nende saamine. Kui põhi ressursid on aga inimesel olemas, siis soovib ta kuuluvus tunnet, kui see on omakord saavutatud, ihaldab inimene asju – oma enda asju. Võib siis õelda, et tarbete ostmine on nagu üks iniminstinktidest, kuid seda pole vaja nii massiliselt teha.\nIInimesed tunnevad, et riiete ostmine pole paha, kui neid uuele ringile saata. Uute moekate riiete ostmine üheks kasutuskorraks on muutunud tänapäeva normiks, peale seda saadetakse riided uuskasutuskeskusesse või annetatakse, et tunda end loodussõbralikuna. Kurb tõde on see, et taaskasutuspoodide laod on ülekoormatud rõivatega ja suurem osa neist lõpetavad ikkagi prügimäel. Inimesed ostavad liiga palju ebavajalike riideid, esemeid ja nende annetamine ei tee muutuse kahjule, mis on juba tehtud.\nTarbimine on liiga normaliseeritud. Inimesed ei tea tõelist mõju, mis ületarbimisel on ja sellepärast ei hoia tagasi nad oma soovi koguag midagi hankida. Inimestel pole tegelikuses nii palju asju vaja ja meie, kui ühiskonna, ületarbimist tuleb suurelt vähendada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('2ec60df5-65bc-4220-9b8a-7edc7c260cdc', 'title', 'Miks inimesed tarbivad');
