INSERT INTO core.text(id, content)
VALUES ('08fae758-f557-47d9-8407-563c418759c0',
        'Tänase maailma põhiprobleem on reostus. Sellega kaasneb ka toidu raiskamine, mis on loodusele kahjulik. Tänases maailmas on toidud mis on kemikaalidega üle pestud ning on loomadele ja taimedele kahjulik. Osadel inimestel pole isegi toitu mida raisata. Ülevates tekstides on räägitud, kuidas toidu raiskamine on hakanud suureks probleemiks ja loodusele väga kahjulik. \nÜks punktidest mis välja toodi, oli kvaliteet üle kvantiteet. Ma osaliselt nõustun, aga mitte täiesti. Minu põhjus on see, et paljud inimesed ei ole rikkad. Mõnedel on üldse vaevalt raha, et läbi saada. Kui mulle oleks antud valik, siis võtaks selles olukorras mina ka kvantiteedi. Inimested pole vahepeal valikut aga kui raha on piisavalt, siis ei tohiks osta odavat toitu mille ära viskad.\nPaljud inimesed arvavad, et toidu raiskamine ei mõjuta maailma. See oli üks punktidest toodud loetevast tekstist millega olen täiesti nõus. Inimesed on elanud ja ära harjunud mugavuses kus toitu on palju ning selle tõttu on rohkem raisklikud.  Selles toidus mis me ära viskame on hästi palju ressursse, näiteks vesi ja energia. Kaotame ka vajaliku tööjõudu, mis oleks paremini kasutad teisted töökohtades kui inimesed lõpetaksid toidu raiskamise.\nKõige tähtsam asi on meie maa. Igapäev seda rikutakse toidu raiskamisega. Mõned on sünnitud ostma odavat ja keemilist toitu, sest nendel lihtsalt pole piisavalt raha. Mõned viskavad toitu, sest arvavad, et see ei ole suur asi.');
INSERT INTO core.text_property(text_id, property_name, property_value)
