INSERT INTO core.text(id, content)
VALUES ('2c609376-21d8-4393-af83-9d17b6db63de',
        'Väga paljud inimesed raiskavad toitu seetõttu, kuna arvatakse et nad jõuavad rohkem süüa kui nad reaalsuses enda makku toitu mahutavad. Samuti ostetakse ka hulgasti toitu või et on tahe soolase või magusa suutäie järgi. Sellega kaasnevad küsimused Miks ja kuidas me toitu raiskame?\nToidukadu tekib enamasti sellest, et inimesed lubavad endale toidupoest liiga palju kaupa, mida neil vaja ei ole, eelkõige palju väikseid suupalasi, mis lõpuks söömata jäävad ja välja viskamisele lähevad. Selle tulemuseks on toiduraiskamine kus aastas seda on otsesõnu 61 kilogrammi iga eestlase kohta kust suur osa sellest on toidu või toitainete mille soovitatud kasutustähtaeg on üleaja ära viskamine. See on meeletu raha, ressursside, energia ja maaala raiskamine.\nKõik raisatud kaubad jõuavad lõppude lõpuks vette, jõgedesse või prügimägedele kus suur osa sellest on pakendatud või tehislike ainetega toodetud mis hoiavad toitu kauem hallitama minemast ja ära kõdunemast. Need toidud ei kao mitte kuhugile ennem paari aastat, samuti rikuvad tooted veekogusi, teevad neid mustemaks ja pakendid jäävad neisse ulpima. Kuidas seda enneteda? Seda saab ennetada sellega, kui kõik inimesed viskaks oma prügi, sealhulgas toidu prügikasti mitte vette või maha kust see võib ka veekogudesse jõuda\nInimesed peaksid poest ostma vähem toitu, mida neil vaja ei lähe või teavad, et see koju jõudes jääb seisma ja äraviskamisele läheb. Samuti ka oma toidukadu jälgima, et neil seda niipalju ei tekkiks ja oma jäätmed prügikasti viskama mitte maha ega veekogudesse.');
