INSERT INTO core.text(id, content)
VALUES ('013a0f35-99b6-41d2-b201-543a4a2ec781',
        'Toit on meie igapäevane liikumis ressurss, ilma toiduta ei saaks me piisavalt energiat, et liikuda või isegi elada! On inimesi kes raiskab toitu ja on neid kes hoiab kokku toidu pealt ehk ei osta seda mida tal tegelikult vaja ei ole.Kuidas saaksime toidu viskamist või raiskamist vähendada?\nToidukadu ehk raisatud toit on toit või toiduaine, mis migil põhjusel on rikenenud või kasutustähtaja ületanud toit.Kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid millest, toidukaupu moodustab 42 % ehk 26 kg. Kuidas hoiduda ära toiduraiskamisest? Tea seda, et sul on võimalusi kuidas või mis olukorras endale toitu osta.Proovi vältida poes käimist tühja kõhuga sest kui lähed tühja kohuga poodi vaatad poe leti peal olevaid asju mis sind isutab, mitte sinu tegelik nälg millegi üle.\nProovi käija poes koos ostu nime kirjaga siis pöörad rohkem tähelepanu just toodetele mida on sul päriselt vaja ja millega saad kõhu täis. Proovi osta toitu mis on kõlblik mitu päeva. Teine probleem on toitude liigne tegemine suurtes kogustes ja hakatakse toitu ära viskama peale mitut päeva.Proovi teha endale ja teistele piisav kogus toitu teatud päevaks. Proovi saada toitainetest terve kogus mis võimalik saada on ehk kui koorid kartulit siis proovi see koorida nii ära, et ei tule liigset kartulit kaasa.\nToiduraiskamist saab vähendada enda koguste jälgimistega ning sellega säästad raha, aega ja toitu. Toiduraiskamist ei saa muuta üle ööga.Peame jälgima miks ja kuidas me ostame toitu ning kas meil on seda vaja?');
