INSERT INTO core.text(id, content)
VALUES ('70397fa0-2ca1-4ba3-afde-baa4b4e9ad90',
        'Meil on kombeks toitu raisata, kuna me arvame, et ee ei saa otsa. Enamik inimesi raiskab toitu, kuna see ei mõjuta nende rahalist hoiakut. See teine enamus raiskab vähem, aga raiskamine on ikka raiskamine.\nToidukadu ei pruugi mõjutada inimese rahakoti paksust, aga see mõjutab vägagi meie keskkonda. Me raiskame oma looduslikke ressursse: maad, vett, energiat ja tööjõudu. Toidu raiskamine tekitab ka tõsist keskkonnakoormust, kuna toidutarbete tegemiseks kasutatakse erinevaid kemikaale ja väetist. Kui meie keskkond laguneb, alles siis hakkab meil olema raskusi, näiteks toidu saamisega, vee saamisega ja meil võib kujuneda ka värske õhu puudus, ja me ei saa enne aru, kui on liiga hilja. \nKui ülejäänud toit visatakse näiteks metsa või kuhugi teeäärde, ei kahjusta see enam ainult meie elu, vaid ka loomade elu. Toidu maha viskamine võib järgneda loomade haigestumiseni, pesade hävinguni ja võib-olla kunigi massilist loomade surmani. Me peame aru saama kuidas me mõjutame oma tegevusega ka seda, mis meie ümber on, mitte ainult kuidas meil hea on.\nNeed inimesed, kellel on raha toidu jaoks ja kes raatsivad seda raisata ei mõtle, kas teistes riikides inimesed elavad ka nii hästi kui nemad. Inimesed on näljas, ja väga vähesed mõtlevad nende peale. Kui toitu jääb üle, siis oleks targem kas enda jaoks säästa seda toitu, või annetada inimestele, kes seda ise osta ei jõua. Uudistes on ka üles toodud igasuguseid vaesus- ja toiduprobleeme, aga sellele reageerivad ja veel vähem tegutsevad väga vähesed inimesed. Selle probleemiga võivad kaasneda igasugused haigused, just väikestele lastele, ja see omakorda võib kaasa tuua väikeste laste või noorte inimeste varast surma. \nToidu säästmine on väga tähtis, et meie elu maal säiluks. Kõik see raiskamine võib kaasa tuua inimkonna hävinemise ja see hävinemine võib alguse saada juba kartulipudru ja pannkookide ära viskamisest, ja meie ei mõtlegi selle peale.');
