INSERT INTO core.text(id, content)
VALUES ('ca8b6605-22f7-4a01-816e-75f869ece78e',
        '\nMiks tahetakse,et lapsed käiksid taaskasutamise poodides?  Miks lapsed viskavad vanu riideid ja pakendeid ära?  Kas lapsed peaksid hoolsamad olema?\n\nMina arvan,et inimesed tahavad,et nende lapsed käiksid taaskasutus poodides sellepärast , sest nad siis saaksid aru kui palju prügi tegelikult on igal pool ja mis  nendega teha saab.\nMina arvan,et lapsed ei saa veel aru kui palju rolli see mängib elus, kui sa viskad väikese asja maha kui palju see looduses halba teeb. Selle asemel tuleks visata prügikasti  prügi, sest miks meil need prügikastid on kui neid ei kasutata.Ja ma arvan et vanu asju tuleks viia taaskasutuspoodidesse, sestkui sul on asjad väikseks jäänud siis targem on need asjad ära viia kui ära visata, sest nagunii on isimesi kes vajavad rohkem, kui meie.\nMina arvan,et lapsed peaksid väga palju rohkem hoolsamad olema kuna mida rohkem me asju ära viskame seda rohkem on ka prügi.Ja seda rohkem jäävad inimesed asjadest ilma mida saaks taaskasutada.\nMinu arvates tuleks kõikides koolides teha üks ekskursioon taaskasutuspoodidesse , et neile räägida kui oluline on asju viia taaskasutuspoodidesse ja miks on üldse siuksed poed välja mõeldud ja mis sellega parandada saaks,et teistel inimestel oleks kergem elada. Tänu nende taaskasutuspoodidele on palju inimesi kes saavad nüüd palju paremini hakkama elus. kuna neil on tänu sellele taaskasutamisepoodides vajalike asju mida kasutada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('ca8b6605-22f7-4a01-816e-75f869ece78e', 'title',
        'Miks peaks noortele tegema eksursioone taaskasutuspoodide lattu');
