INSERT INTO core.text(id, content)
VALUES ('3d7363f0-1b18-48a0-b638-e931f72bce11',
        'Inimesed raiskavad tohutu kogusega toitu ,sest neil on piisavalt raha ja saavad endale lubada. Aga tänu sellele ,raiskavad nad tohutu kogusega toitu, Kuni 42% ehk 26kg toitu raiskavad inimesed igaasta. Inimesed mõtlevad miks me nii palju toitu raiskame, selle peamiseks põhjuseks on ,et me saame endale seda rahaliselt hästi lubada.\nToit on üks kõige vajalikum resurss, mida meie kehad vajavad ,aga ikka viskame seda ära mitmetes tuhandetes tonnides. Kõik inimesed, ei saa aru ,et isegi kui visata ära väikse koguse toitu igapäev lõppude lõpuks ,on see tohutult suur arv mida me raiskame. Asi on kindlasti kaa selles ,et inimesed ei taha süüa sama toitu mitu päeva järjest ,aga ikkagi teevad liiga suure koguse toitu.\nInimesed võiksid kindlasti rohkem mõelda selle peale ,kui palju toitu nad ära viskavad iga aasta, kui nad teaksid kui suur kogus see on ja kui palju see reostab meie loodust ,siis ei raiskaks inimesed nii palju toitu. Toidu ära viskamisel ,ei kaota me ainult raha ,vaid ka teiste inimeste aega ja vajalikke resursse ,ning maavarasid.\nMinu arvates ,et toitu kokku hoida peaks iga inimene panustama õige kogusega toidu mitte raiskamiseks ,toidu raiskamine meil niipea veel ei kao ,aga saaksime paremini kasutada toitu ja hoida meie loodust.');
