INSERT INTO core.text(id, content)
VALUES ('af6ad0b3-58ef-4926-b666-5ea6fc348498',
        'Tänases juttus ma arutlen teiega maailma probleemi toidujäätmete raiskamisega ja taaskasutuspoodide laoga, miks nad halvad on ja kuidas sellest võiks jagu saada, kui inimesed prooviksid neid teha. Sest minu eesmärk on aidata meie keskkonda ja arendada seda niimodi, et see oleks puhtam ja tervislikum\nToidukadu, ehk toidu raiskamine on siis, kui keegi viskab oma toidu ära mis mingil põhjusel, näitkes, kui neil on toit riknenud, kasutustähtaja ületanud, söömisel ülejäänud ja edasi. Kodumajapidamises iga Eesti inimese kohta on aastas ära visatud keskmiselt 61kg toidujäätmeid, millest moodustab toidukadu 42%, ehk 26kg. Niimodi me raiskame oma raha ja ressursse, mis läksid selle toidu tegemisele.\nMinu arust saaksid lahendada seda niimodi, et me võiksime lihtsalt osta vähem toitu nii, et igal isikul oleks vähem põhjuseid neid ära visata kuna tavaliselt on ülejäänud toit see põhiprobleem  ja, kui jääb mingi toit üle siis hoidke see alles ja viige see kodututele.\nTaaskasutuspoodide laod on ka üks asi mis on meie keskkonnale ebasobilik ja ohtlik, eriti Hiinast, kuna nad müüvad riideid, mis esimesel vaatepildil näevad välja ilusad, aga nad on tavaliselt tehtud naftaga, mis on väga halb oma kehapeal kanda 24/7.\nMinu lahendus on see, et lihtsalt ärge tellige midagi Hiina epoodidest, eriti riideid, kuna isegi tava asjad mida tellite sealt, võivad ka olla midagi mida hakkate tihti puudutama.\nKokkuvõttes ma soovitan, et ärge lihtsalt raisake toitu ja viige see neile kellel on seda vaja. Ja taaskasutuspoodidega on nii, et ärge tellige Hiina epoodidest mitte midagi, Uurige ennem, et mis riigist on teie taaskasutuspoe firma.');
