INSERT INTO core.text(id, content)
VALUES ('0e465535-a1bf-47c8-937e-c33de43f9468',
        'Inimesed käivad toidupoes ja ostavad suurtes kogustes koju süüa. Üks osa  kasutatakse ära ja teine osa läheb raisku. Kui toidu kasutustähtaeg on möödunud, hakkab toit teatud ajajooksul riknema ning seejärel visatakse ära. Miks ei võiks koostada ostunimekirja, kuhu kirjutada toidud, mis ära kasutatakse?\nInimesed käivad nädalas üldiselt ühe korra poes ja ostavad koju terve nädala peale toitu. Tarbivad ära tervest ostetud kaupadest ainult poole ja ülejäänud jätavad kappi seisma. Selle asemel, et jätta see kappi seisma võiks panna näiteks lihatooted sügavkülma, et need ei hakkaks riknema külmkapis. Või teha valmis nii-öelda nädala toidumenüü. Igapäev kasutada neid toiduaineid, mis on kavas või menüüs.\nRaistakse raha ja toitu ilma asjata. Toidu peale kulub palju raha, toidu ära viskamine tähendab raha raiskamist asjade peale, mida poleks olnud vaja osta. Enne poodi minemist tasuks vaadata, mida on vaja juurde osta ja mida mitte, sest seda kergem on endal kui ka toidu tootjatel (toidufirmad). Sotsiaalmeedias nägin üht naist valmistamas suurtes kogustes toitu inimestele, kes ise ei pruugi toitu alati osta. Ei raisatud raha ega visatud toitu ära.\nKui minna poodi, siis võiks valmistada ette ostunimekiri, kus on vajalikud toidud, mida kasutatakse nädalajooksul. Toidu ära viskamisel raisatakse raha ja ei mõelda selle peale ega ka nende peale, kes ei saa igakord toidu eest maksta.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('0e465535-a1bf-47c8-937e-c33de43f9468', 'title', 'Toidu ostmine ja tarbimine');
