INSERT INTO core.text(id, content)
VALUES ('840b9083-8faa-45c0-96db-ba90887d1438',
        'Toidukaost on üks suuremaid probleeme meie ühiskonnas ning sellele on vaja rohkem tähelepanu pöörata, kuid siiski tekib küsimus. Miks inimesed raiskavad toitu ja mis neis seda põhjustab?\nTihti inimesed raiskavad toitu, kui minnakse poodi ja ostedakse mingit snäkki või jooki ning saadakse teada, et neile tegelikult ei maitse see, mis nad just omale poest sooritasid. Teisest poolest on inimesi, kes raiskavad toitu kuna nad saavad endale seda lubada ja seetõttu nad ei mõtle, et see mida nad raiskavad pole ainult toit. Näiteks tarbitoitutargalt.ee on kirjas, et me ei raiska ainult omaenda raha, vaid ka muid ressursse: maad, vett, energiat ja tööjõudu. Seal on ka toodud, et tekib iga eestlase kohta aastas keskmiselt 61 kilogrammi toidujäätmeid, millest raisatud toit on 42% ehk 26 kilogrammi sellest. Seejärel võiksid inimesed mõelda, et nad ei raiska ainult toitu, ka muid tegureid ning mõelda kuidas nad saaksid toitu otstarbekalt ära kasutada, et võimalikult vähe raisku läheks toit.\nInimesed võiksid hakkata reguleerima oma toitumist, et vältida toidu ära viskamist. Samas saab ka vaadata, mida sa täpsemalt poest soovid endale poest sooritada ning siis küsida, et kas sul tegelikult läheb seda vaja või sa soetad nii-öelda „igaksjuhuks“.\nMinu arvates toidukaost võiks rohkem rääkida ja seda teemat rohkem ülestuua, et see ei jääks inimestel kahe kõrvavahele, sest see on tõsine probleem. Toidukadu saaks tegelikult kergelt vältida, kuid peab viitsimist olema.');
