INSERT INTO core.text(id, content)
VALUES ('a42ab11d-775b-41ea-9bf8-5dbd9be0dc6f',
        'Inimesed raiskavad toitu sest nad saavad seda endale lubada. Iga Eesti inimesekohta umbes 61kg toitu iga aasta millest moodustab 42% ehk 26kg. Toitu on nii palju raisatud ning tekkib küsimus miks? Miks just mitte annetada toitu inimestele kes päriselt vajavad seda või miks mitte annetada seda toidupanka? Mis võiks teha ,et inimesed lõppetaksid toiduraiskamise kas või natukene?\nToit on maailma üks kõige vajalikuim resurss tänu millele me oleme elus. Isegi kui see on  üks maailma kõige vajalikuim resurse miks inimesed ei anneta toitu selle ära viskamise asemel? Asi võib ka selle olla ,et mitte kõik inimesed teavad annetamisest või näiteks toidupankast aga asi võib olla ka laiskuses. Laiskus võib olla päris suur protsent sellest miks inimesed ei anneta ning sama asi ka selle pärast inimesed ei tea sellest. \nSeetõttu ,et inimesed raiskavad toitu nii palju ei raiska me ainult omaenda raha, vaid ka tohutult muid ressursse: maad, vett, energiat ja tööjõudu. Lisaks sellele tekitab see toidu tootmisele keskkonnakoormuse, sest toidu tootmiseks kasutatakse väetist ja erinevaid kemikaale. Toidu raiskamist pole võimalik vähendada üleöö kuid on võimalik selle kohta midagi teha näiteks: annetada toidupanka ninng süüa toit lõppuni.\nMinu arust ,et säilitada maad üheks heaks kohaks kõigile peaksime me ennast kokku võtma ning annetama toitu inimestele kes vajavad seda ning austama teiste tööjõudu.');
