INSERT INTO core.text(id, content)
VALUES ('402ee452-73ff-42e1-a892-200993c3df6a',
        'Tänapäeval toiduraiskamist on tohutu palju, inimesed lihtsald viskavad toidu ära nagu prügi. Toiduraiskamine on tuntuim probleem, sest toit on see miks me ikka veel elame, ei oleks toitu ei oleks meid. Ma arvan, et kui toit on ebakõlblik siis tuleb ära visata, sest see teeb meile kehale liiga ja me võime ära surra. \n \nMõned inimesed ostavad toitu mida nad ei ole proovinud ja hiljem viskavad minema. Targem oleks ennem proovida ja siis osta kui see sulle maitses mitte osta kohe suures koguses. \nMinu arust toiduraiskamine probleem on vaid nendele kellel pole võimalust osta suures koguses toitu. Rikkamatel ei ole siukest probleemi, sest neil on võimalus osta teist toitu. Tarbitoitutargalt andmetel Eest inemese kohta aastas keskmiselt 61 kg toidujäätmeid millest moodustab 42% ehk 26 kg   t, see on tohutu palju inimese kohta aastas. Ma olen näinud et mu naaber on ära viinud umbes 30 kg toidujäätmeid.\nKokkuvõttes toiduraiskamine ei ole nii hull probleem, sest ebakõlblikud toitu ei tohi süüa, sest see tapab inemese organismi.');
