INSERT INTO core.text(id, content)
VALUES ('1016ebda-7d0f-4513-9967-8d6191541f0e',
        'Minu arust maailma suurimaks probleemiks on toidu raiskamine, sest toidu jaoks kulub igal inimesel raha, töö ja vaev. Samas toit võib maailmas ükskord ka otsa saada, see ongi sellepärast et inimesed raiskavad toitu ja paljud inimesed ei saagi söögiks mitte midagi.\nEestis iga inimese kohta läheb raisku umbes 61kg toitu, siiski kulub sellele palju tööd, sest toitu peab ikkagi kasvatama ning ikkagi kulub selleks ka palju raha. Minu arust kõige rohkem toitu läheb raisku poes, sest paljud inimesed ei osta kõiki toiduaineid ära ja siis selle ajaga toit aegub. Veelgi toiduraiskamine on kõige suuremaks probleemiks ka linnades, sest linnades on poed ja paljud poed viskavad seda aegunud toitu poe tagusesse prügikasti. Sellega kaasneb ka paljusi probleeme, näiteks inimesed kellel pole kodu, söövad seda aegunud toitu ja võivad saada sealt mitmeid erinevaid haigusi. Minu arust on toiduraiskamise probleem kõige väiksem mure maa inimestel, siiski võib maal toiduraiskamine tekitada mitmeid haigusi. Kui oleks toitu vaja kuskile visata siis tuleks see kõige rohkem kasuks maa inimestel, maal on paljudel elanikel mitmeid erinevaid loomi kellele saaks toitu visata, eriti kanadele kes söövad peamiselt kõike.\nKokkuvõteks võib öelda, et see toiduraiskamine on suurimaid probleeme mis olla saab, eriti linnades, samas ka maa inimestel. Kõige rohkem raisatakse toitu linnades, just poodides ja muidugi ka paljudes majapidamistes. Veel ka seda, et Eestis raisatakse toitu ka väga palju, peamiselt igas majas.');
INSERT INTO core.text_property(text_id, property_name, property_value)
