INSERT INTO core.text(id, content)
VALUES ('509c5f17-d525-4eee-b07e-145d8ce3ab8c',
        'Inimesed viskavad aina rohkem toitu ära, kuna seda jääb üle ning sellega pole midagi teha. Inimesed võiksid olla rohkem teadlikumad kuidas toitu tarbida, kuhu seda visata või mida sellega edasi teha. Oleks parem kui nad oleksid mõistlikumad, kuidas nad sellega ümber käivad. Sellese kulub ka meeletult raha mille nad kõik ära viskavad ning ka mõndade loomade elud, keda on halvasti selleks koheldud ja kelle liha sa ära viskad ja mõõdukalt ei tarbi.\nInimesed võiksiod osta piiratud koguses toitu olles teadlikud, et nad seda ka ära kasutavad. Enamus inimesed ostavad hulga toitu isegi kui nad teavad, et nad selle lõpuks ära viskavad, samamoodi on ka poodides ninga ka kovhikutes või restoraanides. Toidud mis jäävad üle, võiksid nad annetada kodutetele või ka laste haiglatesse ja veel midagi sellist.\nKohvikud, restoraanid ja veel sellised toidukohad kus toitu pakutakse, on toidu raiskamine, inimesed aina tellivad ja tellivad, kuid enamus ajast seda kõike ei sööda ära. Alati jääb toitu üle ja see visatakse lihtsald ära, see on toiduraiskamine. Kui ka kohvikutes jääb pirukaid või midagi sellist, visatakse see enamus ajast minema, kuid jällegi seda toitu saaks annetada erinevatesse kohtadesse ning see teeks vägu suurt rõõmu ka teistele kes selle toidu endale saaks.\nToidu raiksamine on väga halb asi, seda saaks annetada teistele. Toitu võiks mõõdukalt kasutada teades, et sa ei viska seda ära ning oled kindel, et sa sööd selle kindlasti ära.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('509c5f17-d525-4eee-b07e-145d8ce3ab8c', 'title', '„Toidukaos“');
