INSERT INTO core.text(id, content)
VALUES ('87afa441-b189-4603-88c8-b1cd0b106995',
        'Paljudel on halbu harjumusi, mõned on halvad neile endale ning mõned loodusele. Kuidas siis seda vältida? MIs võiksid olla sobivad lahendused?\n Tänapäeval toodetakse liigselt mõnu tooteid, näiteks igal inimesel ei ole vaja autot. Muidugi on palju eranded näiteks, kui keegi elab kaugel linnast või kuskil mujal raskesti kätte saadavas kohas siis auto võib tunduda vajalik, aga tavalisele linna elanikule ei ole see vajadus vaid puhas mugavus. Viimasel ajal on sellele mõttele toodud rohkem valgust ja kehtistatud automaks. Minu arvates peaks toetaks rohkem ühis trantsporte, üks buss saab muvavalt 30 inimest riingi sõidutada see on 30 inimest keis ei pea autoga sõitma ja kütust raiskama kui me võtaks praeguse koguse autosi eestis ja jagaks selle 30-nega oleksid linnades, alevikes ja külades värskem õhja, vähem müra ja üldiselt mõnusam keskkond.\n  Tark tarbija olemine ei ole raske.  Paljud elava iga päev kulutades liigselt raha ja ostes asju mis ei ole neile vajalikud. Näiteks minu arust on suhkru joogid ühed kõige hullemad nendest. Paljud inimesed oleksid nagu sõltuvuses nendest ja see on väga normaliseeritud kõigi poolt. Asjad nagu suhkrumaks tunduvad nagu õige lahendus sellele see hoiaks inimesi liigselt eneset kahjustavatest sõltuvustest ja ka toetaks riiki.\nIgal inimesel on õigus omada autosi ja osta poest mis nad ise tahavad, kuid enams sellest on eba vajalik. Kulude suurendamine mõnu ja mugavus toodete terbimisel näib kui hea lahendus nii inimkonnale suures pildis, kui ka loodusele.');
