INSERT INTO core.text(id, content)
VALUES ('e0219368-f146-4b7e-84fb-dddf40a161cb',
        'Inimesed ostvad palju rohkem kui neil tegelikult vaja on ja see tekitab palju ära visatuid asju.Kahjuks visatakse just asju mida mõni veel kasutada saaks.\n                Inimesed tahavad alati trendidega kaasas käia ja näitada teistele ,et nendel on kõige uuemad riided voi suur ja kallis auto.Kuid selline ostmine tekitab proobleeme millega inimesed tegleda ei taha. Näiteks inimesed ei taaskasuta alati oma vanu riideid ja viskavad need lihtsalt ära. Mina arvan et kui osta endale midagi uut siis tuleks vanad asjad kindlasti taaskasutada.Kui on soovi uusi riideid endale soetada siis tuleks ka kindlasti käia taaskasutus keskustes ja erinevates väikestes kaltsukates.Paljud ostavad ka mõne särgi voi jope ,sest seal on mõni logo või brandi nimi peal aga see on ju täiesti mõttetu sest see on lihtsalt kallim ja pole meie planeedile üldse rohkem kasulik\nsuureks prooblemiks on ka toidu ära viskamine või siis selle raiskamine.Inimesed ostavad endale nii palju toitu ,et ei suuda seda enne riknemist ära süüa ja siis lihtsalt viskavad toidu minema.ma arvan ,et inimsesed peaks paremini planeerima mida ja kui palju nad toitu ostavad kui niimoodi ette planeerida ei tohiks tulla proobleme liialdase söögiga külmkappis.Kui osta toitu kuskilt kohvikust või restoranist tuleks ikka mõelda ,et kas ma jäksan selle ära süüa ja ei jäta midagi järele.\nInimesed ostavad liiga palju ja elvad üle oma vajaduste kui me kõik hakkas vahe tarbima ja asju kokku ostma siis saame vähendada ära visatud toidu ja prügi igalpool maailmas.');
