INSERT INTO core.text(id, content)
VALUES ('6f83a074-f9b5-4a81-bedd-32c096da6d85',
        'Tavaliselt on arvatud,et tarbimisharjumusi inimestel aina väheneb,kuid justkui on kõik teistmoodi.Oluline on ka see,mis tarbimisharjumus on inimesele hea ja milline on halb.Millised on inimeste kaks kõige halvemat tarbimisharjumust?\nIgal inimesel on olemas oma erinevad tarbimisharjumused,kuid üks halvematest selles valdkonnas on söök. Söögi ostmine tänapäeval kodudesse on muutunud tõesti väga kalliks,kuid inimestel on harjumus mõnikord see söök ära visata. Mis tõttu,võib toimuda poodides mõnikord ka erinevate toodete puudus,sest neid lihtsalt ei jätku enam. Ära visatud söök ehk biojäätmed,visatakse teise prügi juurde,kuid ka see kahjustab nii loodust,kui ka imetajaid ja muid loomi meie maailmas.\nOn aga veel halbu tarbimisharjumusi,kuid teine nende seast on prügi maha viskamine. See on seotud samamoodi toiduga, kuid kõlab mitu korda hullemini. Ehk,kui tavaliselt viskavad inimesed toidu eraldi konteinerisse,kus ongi kõik biojäätmed,siis kahjuks,on ka neid,kes viskavad lihtsalt selle prügi või toidu maha.Näiteks krõpsupakid,erinevad pudelid ja muud teised pakendid. Kuid inimesed vist ei mõista tavaliselt,kui viskavad prügi maha,et see kahjustab loodust ning kahjustab ka meie merd.Kui sattub praht maha,siis iga korraga muutub loomade ja looduse elu aina hullemaks ja mustemaks. Kuid loomad ja loodus ei tee ju midagi halba,et elada sellist koledat elu siin maailmas.\nInimeste kaks kõige halvemat tarbimisharjumust on toidu ära viskamine ning prügi maha loopimine,sest need teod viivad selleni,et loomade ja looduse elu muutub iga korraga aina halvemaks ning mustemaks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
