INSERT INTO core.text(id, content)
VALUES ('b47c30f3-1b17-41e4-993e-b635a1105a56',
        'Inimesed on väga suured tarbijad. Nad igapäevaselt kasutavad ressursse ja materjale suurtes kogustes, kuid ise seda ei märka. Millised on inimeste tarbimisharjumused ja kuhu kõik läheb?\nRääkides söömisest, läheb väga palju toitu raisku. Inimesed söövad ja joovad igapäevaselt suurtes kogustes ja tihti peale jääb toitu üle või visatakse ära, kuna toit läks halvaks või ei jaksa enam süüa. Kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg. Poodides käies, ostavad inimesed päris tihti massiliselt toitu nende ilusate ja värviliste pakendite pärast, mis enamasti lõppeb väljaviskamisega. Sellele tähelepanu pööramata, raiskavad inimesed igapäevaselt väga palju toitu.\nRiided on olnud juba aastaid suureks probleemiks keskkonna muutustes. Palju on räägitud ja mainitud, et riideid on Maa peal liiga palju. Moedisaineri sõnul on taaskasutuspoodide laos meeletud hunnikud riideid, mida tuleks näidata noortele, et nad mõtleks veidi rohkem riietele, mida kannavad. On olemas Aafrika mandril rohkelt jõgesi, kus ei ole näha maad äärtes, vaid on mitmete meetrite kõrgusesse ulatuvad riietehunnikud, mida enam võimalik ära koristada ei ole. Lisaks on Nigeerias suured turud, kus müüakse riideid, mida on toodud taaskasutuste poodidest, kuid neid on niivõrd palju, et letid on üle uputatud riietega. Inimesed väga palju kasutavad riideid ja kiirmoe tõttu visatakse palju välja.\nInimene on harjunud rohkelt tarbima ja seda kuidagi mõjutada on väga raske. Üks inimene ei ole suuteline aidata keskkonda aga kui kõik hakkaksid kasvõi natuke vähem väljaviskama, oleks meil suur võimalus maailma muuta.');
