INSERT INTO core.text(id, content)
VALUES ('fa294a05-94fa-4ced-b1db-e6dfda011e3a',
        'Inimesed tarbivad igapäevaselt asju, mis võivad kahjustada meie planeeti. See on saanud suureks probleemiks mida on tarvis muuta ja parandada. Mis siis on inimeste tarbimisharjumused?\n   Kõik tarbivad prügi koguaeg aga ei oska sellega ringi käija. Inimesed kasutavad asju, millel on pakendid või muud asjad ümber ja ei mõtle kui selle näiteks maha viskavad, et mis see meie ümbrusele teeb. Sellist vaatepilti on tohutult palju, kus mittevajalikud asjad lihtsalt logelevad maas või on täiesti vales kohas. See on suur kahjustus keskkonnale ja inimeste eludele, kes vähegi hoolivad puhtusest ja keskkonnast.\n   Raha on väga oluline asi elus ja selle kasutamine võiks olla läbimõeldud. Igal inimesel on erivas koguses raha ning kasutavad seda väga erinevalt ja erinevates suurustes. Raiskamine ja mõtetutele asjadele raha panemine on suhteliselt tavaline asi mida inimene teha saab. Raha ei tule lihtsalt ja seda ei saa ka lihtsalt seega, võiks enne läbi mõelda, mida päriselt vaja soetada on ja mida mitte. Hulk rahvast töötab igapäevaselt rasket tööd ja teenivad selle palga vääriliselt ära, kui aga saavad selle kätte, raiskavad  selle sekundiga ära mitte mõeldes, kas see oli ikka õigesti kasutatud. \n   Suur summa inimesi reostavad meie kodukohta halvasti ja süüdimatult rikuvad keskkonda. Lisaks ka raiskavad raha mitte mõeldes, kas on vajadust või mitte. Arvan, et tuleks panna inimesi mõtlema ja arutama, kas nad teevad ikka õigeid otsuseid ja valikuid.');
