INSERT INTO core.text(id, content)
VALUES ('2023220c-b3b9-40a2-a01c-385d3ab48071',
        'Kõigil inimestel on palju tarbimisharjumusi. Need võivad olla kõik täiesti erinevad ja mitmesugused. Mis on inimeste tarbimisharjumused?\n  Kõigil inimestel on toidu tarbimisvajadused. Toitu tarbitakse tohutult suurtes kogustes ning sellest väga suur osa läheb lihtsalt raisku.  Paljud pered arvavad, et kui nad väheses koguses toitu ära viskavad, siis sellest ei juhtu midagi. See ei vasta tõele, sest kui igas peres visatakse toitu nende arust väheses koguses ära, siis juba paari pere peale niiöelda väikeses koguses toidu ära viskamist muutub juba suureks kahjumiks.\n  Paljudel riidedisaineritel on tarbimisharjumused uute riiete valmistamisel kasutada mitte taaskasutatud riidematerjale. Tänapäeval kasutatakse väga palju riiete ja jalanõude valmistamiseks uut riiet ja see on väga halb tarbimisharjumus loodusele. Selle asemel võiksid riide valmistajad kasutada taaskasutatud materjale või teiste riiete ülejääke.\n  Jällegi inimestel suureks tarbimisharjumuseks on näiteks bussiga sõitimise asemel sõita üksi autoga. Selle tagajärjeks on suur looduse reostus mis ei ole inimestele ja ka teistele elusolenditele hea. Inimesed valivad jõuda kooli, tööle või kuhugi üritusele kiiresti autoga, mitte bussi, trammi või rongiga. Autoga sõitmiseks vajab sõiduk kütust ning selle tootmist, mis on üks halvimatest tarbimisharjumustest. See tähendab seda, et selline tarbimisharjumus on väga reostav , millest paljud inimesed võibolla, et aru ei saa.\n  Inimeste tarbimisharjumused on tihti väga halvad ja  loodust reostavad. Mõned inimesed raiskavad palju toitu. Raiskamise alla lähevad veel uute riidematerjalide valmistamise tarbimisharjumused kui ka sõidukiga sõitmiseks kütuse valmistamise tarbimisvajadused.');
