INSERT INTO core.text(id, content)
VALUES ('5095ee63-c784-4f9b-8c5e-f1587a49f8d5',
        'Igapäev raisatakse toitu, mida saaks panna karpi ja süüa homme lõunaks. Igapäev ostetakse tonnide kaupa uusi riideid, mida siis visatakse kappi ja enam kunagi ei kanta. Tänapäeva inimene peaks teadma kõigest, mis maailmas toimub ja hoiduma sellisest raiskamisest, kuid kahjust seda nõu eiratakse. Missugused on inimkonna tarbimisharjumused?\nToidu raiskamine on muutunud igapäevaseks ja ülemaailmseks tegevuseks. Seda tehakse igal pool koguaeg: koolis, kohvikutes, restoranides, oma kohalikus töökohas, kodudes, poodides ja nii edasi. Koolis, võetakse taldrikule hunniku toitu, mida on mitu tundi valmistatud, siis süüakse pool sellest ära ja ülejäänud visatakse ära. kõik see kasulik ja aega võtnud toit, prügikastist alla isegi, kui meile on räägitud kui halb see on ja et me vaataks kui palju me taldrikule võtame. Raiskamise asemel võiksime kuulda võta, mida meile räägitakse ja taldrikule panna täpselt nii palju kui vaja, kui siis vähem ja võta natukene juurde kui tekib soov.\nPeale toidu raiskamise ostame me mõtetult palju riideid. Riideid, mida saaks mitmeid aastaid kanda. Selle asemel need pannakse kappi istuma ja tolmu koguma. Ostetakse et osta, mitte et kanda. Väga palju oste on impulsi ostud, neid tehakse ilma läbi mõtlemata ja lihtsalt tunde järgi. Need ostud lähevadgi  tavaliselt raiskamiseks ja kahetsuseks raha raiskamise eest. Riiete juurde ostmise asemel, võiks annetada oma liigseid riideid taaskasutus marketitele või kui need on juba liiga kasutatud võib neist lõigata lapid, mida kodus kasutada nende riiete ära viskamise asemel.\nElamine mõtekalt ja raiskamis vabalt on meie tulevik. Tarkus selle kohalt on võim olla kokku hoidvam ja loodus kasulikum. Inimeste tarbimisharjumused on halvad, kuid neid saab parandada toodud abinõu ja tahtejõuga. Ära raiska vaid taaskasuta.');
