INSERT INTO core.text(id, content)
VALUES ('a0cdd8a9-39b6-4c54-9172-836185a04c12',
        'Kõik inimesed teavad, et meie planeeti tuleb hoida. Tänapäeva inimeste elud on nii kiired, et ei jõua mõelda kuidas säästlikult asju tarbida. Millised on inimeste tarbimisharjumused?\n   Toitu tarbib igainimene, kuid on inimesi kes raiskavad toitu niisama ilma põhjuseta. Isegi väikeses koguses toidu ära viskamine on halb, sest lõppkokkuvõttes on see ikkagist toidu raiskamine. Toidu ära viskamine pole asi millest mitte hoolid või ükskõikselt suhtuda, sest see ei ole ainult raha raiskamine, vaid ka maa, vee, energia tööjõu raiskamine. Iga aasta tekib  Eesti majapidamises keskmiselt 61kg toidujäätmeid, millest 42% ehk 26kg on toidukadu. Toidukadu ehk raisatud toit on mingil põhjusel riknenud, kuupäeva ületanud või söömisel ülejäänud toit\n    Iga inimene tarbib riided, kuid inimesed ostavad endale meeletus koguses riideid, mis jäävad pärast kasutamata või mida pannakse ainult ükskord selga. Või odavama hinnaga riideid, arvates et maksavad lihtsalt vähem raha ja saavad originaali või samasuguse kvaliteediga riide mis on kallim riie. Et inimesed mõistaks kui palju riideid tegelikult raisatakse peaks tegema ekskursioone taaskasutuspoodide laos. Taaskasutuspodides on väga korralike riideid mida saaks veel edasi kanda, kuid on ka rõivaid mis on reklaamifotol meeletult ilusad aga seljas on ebamugav või ebamugav materjal.\n    Inimesed tarbivad igapäevaselt meeletult toitu ja riideid. Inimeste tarbimisharjumused on pigem halvad, sest meeletult koguses raisatakse toitu ja riideid. Inimesed peaksid rohkem ülevaatama oma tarbimisharjumisi.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('a0cdd8a9-39b6-4c54-9172-836185a04c12', 'title', 'Millised on inimeste tarbimisharjumused?');
