INSERT INTO core.text(id, content)
VALUES ('27483718-3bf0-46f8-a7d2-ffc682b784d8',
        'Tänapäeval on normaliseeritud ületarbimine, ostetakse asju kokku lihtsalt selle pärast, kuna inimene saab endale seda lubada. Selline tarbimine pole jätkusuutlik. Mille raiskuminek on kõige suurem ühiskonnas? \nHetkel ollakse enim mõjutatud trendidest moemaailas, mis toob kaasa endaga inimestes vajaduse ostlemiseks uute riiete jaoks regulaarselt. Tehakse emotsiooni oste, kus pärast paar korda kandmist lõpetavad need riided kuskil kappi põhjas unustatuna. Eriti jubedaks teeb loo see, et kiirmoe rõivad on enamjaolt ostetud ebaeetilistest poodidest, näiteks Shein`ist või Temu`st. Klassiõed alatihti räägivad, et neil pole midagi selga panna, sest rõivikud hakkavad korduma või kuidas nad peavad enda riidekappi sisu aastaaja vahetudes vahetama koguaeg. Eelistatakse kvantiteeti kvaliteedile, peetakse jaburaks korduvkasutatavust ja teise ringi riideid.\nToidu kaost võtetakse väga isenesestmõistetavana, kuna toit ei saa ju otsa. Jäägid visatakse kergekäeliselt prügikasti kui neil paistab olevat väikseimgi tõrge. Inimesed ei tunne end halvasti, sest nad saavad lubada endile iga kell toidupoodi minna ja osta just seda mida tahavad. Mu ema viskab alati hommikupudru jäänused prügikasti kui need pliidile on jäänd seisma, selle asemel et neist veel midagi teha. Arvatakse ,et nende teodel puuduvad tagajärjed. Kahjuks ei mõisteta, et lisaks toidu raiskamisele, laristatakse ka ressursse.\nTavade ümberkujundamine ei toimu äkitselt, kuid meie ühiskonna tarbimisharjumused peavad muutuma. Praegustega pole meil tulevikku.Toidu ja riiete tarbimis muutus peab toimuma esimesena.');
INSERT INTO core.text_property(text_id, property_name, property_value)
