INSERT INTO core.text(id, content)
VALUES ('3ffec111-7654-43a3-8ad7-b0a16b751be1',
        'Enamikele inimestele meeldib mitu korda nädalas poes käia ja endale midagi osta. Mõni ese on nii ilus või lahe, et see lihtsalt tuleb osta, mõtlemata, mida sellega edasi teha. Miks inimesed nii palju riideid ostavad ja mida nende riideesemetega edasi teha?\nKiirmood paneb inimesed ostma rõivaid, mida kantakse vaid mõne korra. Kiirmood tähendab täpselt seda, mida arvata võib: riided, mis on moest vaid lühikest aega.See on suur probleem, sest inimesed tahavad tihti käia riides nagu teised ning iga kord kui riietumisstiil muutub on vaja osta uued rõivad. Ma olen seda ise ka näinud oma tutavate peal, kelle riidekapp on lõhkemiseni täis, aga midagi pole ikkagi kanda ja on ainult juurde vaja. Me elame tarbimisühiskonnas, kus muretsetakse endale aina uuusi ja uusi rõivaid ega saada ka ise aru, et suurt osa neist riideesemetest ei kanta rohkem kui paar korda.\nRiietele uue elu andmiseks tuleb need viia taaskasutuskeskusesse. Loomulikult ei saa kõiki riideid taaskasutada, aga korralikud rõivad, mida enam ei kanta, tuleks üles otsida ja uuele ringile anda, mitte lihtsalt prügisse visata. See on keskkonnasäästlik viis ja toetab vähemate võimalustega inimesi. Moedisainer Eve Hanson on rääkinud, kuidas taaskasutuspoodidesse viiakse meeletutes kogustes riideid ja see peegeldab inimeste tarbimist. Samuti arvab ta, et noortele tuleks teha taaskasutuspoodide ladudesse ekskursioone, et noored teaksid, mis on suure tarbimise tagajärjed. Andes riided uuele ringile saab toetada inimesi, kes ei suuda uusi riideid osta, hoia keskkonda ja anda rõivastele uus võimalus.\nInimeste suurt tarbimist mõjutab tugevalt kiirmood, mis soodustab rõivaesemete ostmist. Kui riideid enam vaja ei ole lõpetab osa prügimäel, kuid targem oleks need viia taaskasutuskeskkusesse, kus neist uuele ringile minnes teistele kasu on.');
