INSERT INTO core.text(id, content)
VALUES ('fad22c2d-0610-4dcc-b598-5c8b1f684a8c',
        'Raha on igal inimesel erinevas summas. Iga inimene kulutab oma raha erinevatel viisidel. Tänapäeval on raha muutunud nii suureks rollimängijaks, et Inimesed ei teagi enam, mis tõeline raha väärtus tegelikult on.\n   Paljud inimesed kasutavad oma sissetulekut ja raha, et saada  moodsamaid ja ägedamaid asju, nende summa peale mõtlemata. Raha väärtus oleks nagu tundmatu. Antakse suures summas raha üle arvestamata, kui palju kulu see neile tegelikult võib tuua.\n  Raha kasutatakse ka headele- ja mõistlikele asjadele nagu headtegevus, hariduse võimalused, toit, kodu, riided, hügieenitarbed, auto või transport jne. Kuid pandakse ka suure summa raha asjade peale nagu hügieenitarbed, menustratsioonitarbed jne. Mis tegelikult võiksid olla odavama ja mõistlikuma hinnaga, et ka väiksema sissetulekuga inimestel oleks võimalik neid tarbida, sest need on igal ühel meist vajalikud.\n   Kõikidel inimestel peab olema võimalus tarbida tooteid mõistliku ja ausa hinna eest. Raha ei peaks mängima elus nii suurt rolli, et me peaks selle pärast terve oma elu muretsema ja põdema. Hinnad peaksid langeda ausale summale. Iga inimene otsustab ise, mis ta oma rahaga ja sissetulekuga peale hakkab aga raha väärtus ei peaks ikkagi nii ränge olema. Inimesed peaksid hakkama arvestama, et kõikidel siin maailmas ei ole piiramatult kulutusi võimalik teha. Kuid ma ei usu, et raha kunagi mõistliku hinna endale saab.');
