INSERT INTO core.text(id, content)
VALUES ('f9494e9c-3779-404a-a3bc-1520725972cf',
        'Minu arvates on toidu ära viskamine päris rumal tegu, kuna miks on vaja osta palju toitu näiteks nädal aega ette ja siis need lähevad halvaks ja keegi ei söö neid ja visatakse ära. Pole vaja osta endale mitmeid kümneid särke kui kunagi ei kanna neid ja siis visatakse ära kuna ei meeldi enam need.\nAlgul võiks osta mõne päeva toit ette ära, mida teadakse ,et kindlasti kasutatakse ja ei lahe raisku ja kui puudu jääb siis saab minna poodi osta ainult seda toodet juurde. Kui mõeldakse ümber ,et ei taheta seda toitu isegi süüa sel päeval või isu kadus ära siis saab selle alles jätta mingiks teiseks päevaks, aga tuleks need ikka ära kasutada enne tähtaega ,kuna liiga palju inimesi viskavad toitu ära ja meil on juba toitu vähe terve eesti peale, ehk me peaksime targemalt ostlema toitu ja vähem ära viskama.\nRiietega sama lugu,Kui teatakse ,et on tõesti vaja mingit riide eset siis tasuks pigem poodi minna osta kvaliteetsem ese ,et ei peaks uusi ostma nii tihti ja need ei läheks katki ka nii kiiresti mida kvaliteetsem riide ese on seda kauem see kestab.\nNii ,et minu aruvates oleks pigem targem tegu osta paari päeva toit ette ära ,et ei peaks midagi ära viskama ja peaks kindlasti osta midagi mida kõik söövad ka mitte ,et keegi viskab ära kuna ei maitse. Riideid tuleb ka pigem osta kvaliteetsemaid ,et kestaks kauem ja ,et ei ostaks hiina poest kuna seal pole need väga hea kvaliteediga ja nendesse tulevad kiiresti augud sisse.');
