INSERT INTO core.text(id, content)
VALUES ('5b32afa7-a5c0-44e1-b141-cb0d7f0373e2',
        'Tänapäevast ühiskonda võib kirjeldada ühe sõnaga: tarbijaühiskond. See on ühiskond, milles inimesed tarbivad rohkem kui nad ise toodavad ja tekitavad palju jäätmeid. Mis on inimeste tarbimisharjused?\nToidu raiskamine on igal pool suur probleem. Olenemata sellest, et kas inimene on tarbijaühiskonnas või mujal, on toidu raiskamine ja selle riknemine on vältimatu probleem. Paljud inimesed viskavad iga päev natukene toitu ära, arvates, et seda tehes nad toitu ei raiskagi. Samuti raiskavad toitu ka inimesed lihtsalt sellepärast, et neil on see võimalus. Viimane, ja peamine põhjus miks toidukadu tarbijaühiskonnas on nii suur, on toidu riknemine. Näiteks, ostavad inimesed endale liiga palju toitu ja viskavad selle tähtaja möödudes lihtsalt ära.\nTarbijaühiskonnas on suur osa riietel ja ülemaailmsel kaubandusel. Inimesed ostavad kokku liiga palju riideid ja asju, mida neil vaja ei ole. Tihti juhtub nii, et ostetakse välismaalt palju riideid ja neid kätte saades tuleb välja, et riiete kvaliteet on halb või siis see, et neid riideid polnud isegi vaja. Selle tõttu jätavad paljud inimesed oma riided kas taaskasutuspoodidesse või prügimägedele. Näiteks, ostetakse palju riideid eriti siis, kui on mingi sooduspakkumine või kampaania.\nInimeste tarbimisharjumustel on mitmeid halbu külgi. Inimesed raiskavad toitu, kas selle riknemise või nende enda harjumuste tõttu. Samuti raisatakse riideid neid liigselt kokku ostes ja ära visates. Meie planeedi elu säilitamiseks peaksime natuke rohkem mõtlema oma tarbimisharjumustele ja neid kontrollima.');
