INSERT INTO core.text(id, content)
VALUES ('6815cce2-ca41-4996-abdf-911bb3163dac',
        'Me kõik tarbime midagi, on see siis toit või riided. Igat tarbimist saaks vähendada, et säästa loodust ja hoida kokku raha. Mis on minu tarbimisharjumused ja kuidas saaksin neid vähendada?\nMa lasen liiga palju toitu raisku. Vahest tõstan endale liiga palju toitu taldrikule ning ei jõua seda ära süüa. Ma saaksin seda probleemi vähendada sellega, et tõstan alguses vähem toitu ja pärast võtan juurde kui on soovi. Näiteks kui ma käin poes ostan külmutuskappi head ja paremat, aga unustan need asjad ära ning need lähevad riknema ja viskan prügikasti. Sellise olukorra vältimiseks saaksin teha nii, näiteks mõelda ette kogu nädala menüü ja osta ainult neid asju, mis menüüsse kuuluvad. Samuti võiksin tõsta ettepoole toidu, mille parim enne on varsti läbi saamas. Ma võiksin olla rohkem hoolsam toidu kompostkasti viimisel. Näiteks kui olen lõpetanud kartuli koorimise, siis ma vahest ei viitsi minna valja et seda ära viia, vaid viskan tavalisse prügikasti ja need lähevad raisku. Ma ei tarbi toitu teadlikult.\nMa ostan riideid liiga kergekäeliselt. Näiteks lähen poodi ja näen mõnd ilusat asja, ostan selle ära, kuid pärast esimest korda tunnen et see pole ikka päris minu stiil ning viskan ära. Seda probleemi saaksin vätida sellega, et enne ostmist mõtlen hoolega. E-poest vaadates tundub riideese ilus ja äge, kuid kohale jõudes ei ole see üldse see mis pildi peal ning ma ei kanna seda. Sellise olukorra vältimiseks võiksin lugeda, mida teised inimesed on tolle riideeseme kohta kirjutanud. Ma soovin moega kaasas käia ning soovin ka sellist pluusi nagu teistel, tolleks hetkeks kui olen saanud sellise pluusi see mulle enam ei meeldi ja see pole enam moes ka. Ma ostan riideid, mida mul tegelikult pole vaja.\nOma toidu ära viskamist saan vähendada, kas vähesema ostmisega või teadlikuma söömisega. Riiete keregekäelist ostmist saan vähendada, teadlikuma ostmisega. Minu tarbimisharjumused ei ole perfektsed, aga on võimalusi kuidas neid muuta.');
