INSERT INTO core.text(id, content)
VALUES ('72dad437-68bd-469c-9109-88b1d03d88df',
        'Arvame, et igapäevane toit on meile iseenesestmõistetav, kuid nii see ei ole. Paljud inimesed viskavad toitu ja muid materjale igapäevaselt ära ning neid see ei häiri, sest nad arvavad, et neid see ei mõjuta mitte kuidagi ega üldse, sest neil on seda raha, et kogaeg sööki osta juurde ning ülejäänu, mis ei meeldi, ära visata. Millised on inimeste tarbimisharjumused?\nÜheks halvimaks tarbimishrajumuseks on kindlasti riided. See valdkond on muidugi rohkem populaarne noorte seas, kuid mõjutab rohkelt ka teisi. Hetkel muutub mood väga kiiresti ning kõik tahavad sellega kursis olla ja vastavaid riideid osta. Näiteks saavad populaarseks uued püksid ja kõik on nendest vaimustuses ning kiirustavad neid ostma. Tõde on aga see, et ilmselt vaid paari nädala pärast on need püksid moest läinud ja on uus stiil ning vanad esemed  visatakse ära. Selline korduv tsükkel põhjustab rohkelt kasutuskõlblike riiete ära viskamist ning nimetatud teemast peaksid inimesed, eriti noored, teadlikumad olema.\nRiietest olulisem valdkond on muidugi toit. Seda raisatakse palju, sest ei mõisteta, kuidas see tegelikult kõikke mõjutab. Näiteks läheb inimene poodi tühja kõhuga, mistõttu tekib isu erinevate toitude järele, mida tegelikult vaja pole. Kuna ostetakse liialt palju kokku, siis hiljem visatakse ülejäänu lihtsalt minema. Selline raiskamine on kohatu ja kõigile halb.\nInimeste tarbimisharjumused ei ole kõige paremad. Toitu ostetakse liialt palju kokku, mis põhjustab toitude massilist ära viskamist. Samuti muutub stiil väga kiiresti ning riiete kokkuost suureneb, aga suureneb ka nende ära viskamine. Oma tarbimisharjumusi peame me kõik parandama, et luua parem ning jätkusuutlikum tulevik.');
