INSERT INTO core.text(id, content)
VALUES ('dec98c1f-75e8-40db-9268-02c0a293d1fa',
        'Tänapäeval, kui kliima soojenemine on ülemaailmne probleem, peaksid inimesed jälgima, mida ja kui palju nad tarbivad. Igapäevaselt visatakse ära toitu, rõivaid ja teisi tarbeesemeid, mida veel tegelikult kasutada saaks. Millised on inimeste tarbimisharjumused?\nEnamus inimestel on kinnisideeks, et toitu on maailmas lõpmata palju ja see ei saa kunagi otsa. Nad ostavad poodidest suurtes kogustes toidumateriale ja jätavad need endale külmkappi seisma, kus need hiljem riknevad ja seejärel ära visatakse. Nad võtavad endale sööklates suuri portsjoneid ja pärast viskavad pool prügikasti, selline tegevus toimub peamiselt koolides. Inimesed raiskavad tohutult palju toitu, aga selline käitumine vale, sest täpselt samamoodi nagu meil pole lõpmata palju maavarasid, pole meil ka lõpmata palju toitu. Selle asemel, et koju suurel hulgal toitu kokku osta, võiks hoopis enda toidukava planeerida ja ainult vajalik kogus toitu osta. \nViimasel ajal on noorte seas suuresti kasvanud populaarsus erinevate Hiina rõivapoodide kohta, noored tellivad endale kilode kaupa odavast materialist riideid, ning hiljem nad avastavad, et need on ebamugavad. Internetis tuleb ette erinevaid reklaame, kus väidetakse, et Hiinast saab tellida kvaliteetseid riideid odava hinnaga, mis võib esmapilgul tunduda väga ahvatlev, aga kui inimesed hiljem oma riided kätte saavad, mõistavad nad, et material on odav polüester, mida on ebamugav kanda. Seejärel nad viskavad riided otse prügikasti või saadavad taaskasutuspoodidesse. Selle asemel võiks hoopis osta kvaliteetseid riideid natuke kallima hinna eest, mis hiljem tasuvad ennast ära, kuna need kestavad kordades kauem kui odavad Hiina rõivad.\nInimestel on harjumuseks visata ära täiesti tarbimiskõlbelisi rõivaid ning toitu. Näiteks tellitakse Hiinast suur kogus riideid ning hiljem avastatakse, et need ei kõlba kuhugi või ostetakse poest suur kogus toitu, mida lõpuks ei suudeta ära süüa ning visatakse prügikasti. Et seda probleemi lahendada, peaksid inimesed jälgima enda ostukoguseid ja arvestama sellega, et nad kõik enda tarbeesemed ka ära tarbida suudaksid.');
