INSERT INTO core.text(id, content)
VALUES ('20285e71-7877-493d-b19d-0f96e66598eb',
        'Inimesed ostavad Igapäev toitu endale, mis on loogiline, aga see et inimesed toitu raiskavad pole ültsegi hea. On inimesed kes töötavad väga rängalt et tänapäeval isegi enda perele toitu lauale panna. Inimesed kes rohkem ostavad on kaasosaline rohkem toidujäätmetele/toidukadule ja need kes jäävad veebipoodies osteldes kvantiteedi otsa kvaliteedi asemel.\nInimesed kes raiskavad toitu on need kellel kõige rohkem seda on, kui nad ükspäini neid ära ei jõua tarbida, jääb külmkapi seisma, aegunud toit visatakse muidugi ära, aga mida rohkem seda on, sellega rohkem tekib toidujäätmeid/toidukadu, et seda vältida tuleks endale selgeks teha et kas sa saad üksinda kõik ära tarbida, ja mitte raisata, lõpuks selle järel teha järeldus osteldes. Mida vähem on toidujäätmeid seda parem on see keskkonnale. Mina ise ostan piisavalt toitu mis ma ka lõpuks ära tarbida jõuan, millega ei tekita palju toidujäätmeid. Hiinast ostetud röivad, esemed jm võivad väga kergesti sinu kodusse kuskile seisma jääda pärast esimest kasutust, kuna sulle lihtsalt ei meeldinud see päriselu tulemus mis sa reklaamist tegelikult nägid, neid esemeid, röivad toodetakse massiliselt, et inimesed neid ostaksid ja siis lõppude lõpuks kuskile kappi seisma jäävad. Sellega tekib aina rohkem raha raiskamist tehes ka tööjõule raiskuseid nende raiska läinud tarbetele taaskasutusse panemisel. Siukseid ebavajalike röivaid, esemeid veebipoodides osteldes tuleb olla tähelepanelik et kas sa hakkad seda igapäev kandma/kasutama, või pigem jääda enda kodumaistele tarbetele, mis kestavad kauem? Ise osteldes olen tähelepanelik, et mida ma lõpuks endale ikkagi ostan, parem on osta kvaliteeti kui kvantiteeti.\nOn igasuguseid inimesi, need kellele enda arust jätkub palju toitu osta ja toidujäätmeid tekitada aga ka neid kes töötavad rängalt, et enda perele toitu lauale panna. Inimesed kes ka ostavad kvaliteedi asemel kvantiteeti, osteldes Hiina veebipoodides endale röivaid, esemeid jm, mis lõpuks on suur raha raiskamine ja raske koormus tööjõule neid taaskasutusse panna.');
