INSERT INTO core.text(id, content)
VALUES ('0a619511-aba9-4390-a419-c7d33e4bf445',
        'Tänapäeavl muutub järjest suuremaks probleemiks mõtteviis et, kui olen ühekorra asja kasutanud, siis on see vana ja äkki stiilist väljas. Kuidas saaks mõjuvalt muuta minu mõtteviisi, et vähendada tarbimist ja asjade ära viskamist.\nMiks tunnevad praeguse ajastu inimesed et neil on koguaeg uusi asju vaja? Maailm on tänapäeval üle läinud peamiselt sotsiaalmeediale kus on võimalik sekunditega näha mida inimesed üle terve maailma teevad ja kuidas elavad. See paneb arvama, et kui nemad kannavad paremaid riideid kui mina, siis ma pean ka kuidagi ennast muutma, et olla nagu kõik teised ja kandma kõiki kõige paremaid riideid ja vahetama stiili, et olla koguaeg nagu teised. Tänu sellele ma hakkangi ostma uusi riideid ja vanu ära viskama\nMiks jääb maailmas inimestel nii palju toitu igapäev järgi? Ma tunnen alatihti, et kõht on söömise ajal saanud liiga täis ja ma ei jaksa rohkem, siis juhtub see, et viskan toitu minema, kuna tunnen et, ma saan igaltpoolt alati toitu juurde ja see väike portsjon mille ma ära viskan ei muuda mitte midagi. See on täiesti vale arvamus miljoneid lapsi ja peresi ei suuda endale igapäevaselt lubada isegi seda kogust toidu, mille olen peale ühte söömingut lihtsalt prügikasti visanud.\nKuidas ma saaksin ise vähendada oma kasutamis harjumusi? Ma saaksin vähem jälgida seda mida teised teevad ja ostavad, siis ei tekiks tunnet et mul on ka seda vaja ja mul tuleb hakata väärtustama kõike mida mu vanemad on suutnud mulle pakkuda ja anda.\nTänapäeava tarbimisühiskonnas tuleb lihtsalt olla mina ise ja mitte lasta teiste otsustel ja valikutel mõjutada mind. Kõikidel on erinevad vajadused ja tahtmised nii et, tähtis ongi see et ma püsin endana.');
