INSERT INTO core.text(id, content)
VALUES ('fd762aaa-59be-4f75-936e-21c0ba64e31c',
        'Inimesed teevad väikeste tegudega maailmale palju kahju nii, et nad isegi sellest aru ei saa. Visatakse ära palju söödavat toitu või ostetakse riideid, mida koheselt ära visata. \nInimesed raiskavad palju toitu. Aastas tekib iga inimese kohta Eestis umbes 61 kg toidujäätmeid, mis on kas riknenud või söömisel ülejäaanud toit. Tavaliselt on palju nii, et koolis võetakse taldrikule rohkem süüa, kui ära söödakse ja visatakse minema. Seejärel, tekib päeva jooksul hulga toidujäätemid, mis tegelikult on söödav järelejäänud toit. Vahepeal ostab ka meie pere midagi liiga palju, mis pärast jääb lihtsalt seisma ja lõpuks rikneb. Sellega raiskame tööjõudu kui ka maa ressursse. Võiksime rohkem vaadata, kuidas vähem raisata.\nNoored tarbivad palju kiirmoodi. Suurem osa ostavad kiirmoe kaupa just sellepärast, et see on odav ja piltidel näeb ilus välja. Mida inimesed arvesse ei võta, on see, et need riided on nii odavad, kuna need tehakse ebakvaliteetselt ning ebasoodsetest materjalidest. Siis visatakse varsti need riided ära, sest mood on juba muutunud või neid riideid on lihtsalt ebamugav kanda. Kiirmoe riiete ära viskamine omakorda tähendab looduse reostust, sest kui see riie, mis on tehtud teadmatutest plastidest satub loodusesse, ei kõdune see seal ära. Odav ei tähenda kasulikku.\nKurb, palju tegelikult toitu ära visatakse või kui tähelepanemata riideid ostetakse.Väheste tegudega saab teha loodusele palju kahju. Sellepärast peaksimegi rohkem vaatama, mida ostame ja ära viskame.');
