INSERT INTO core.text(id, content)
VALUES ('e6cb87fe-59f5-4dd6-8eb4-400edd812a7f',
        'Tarbimisharjumused ehk tarbimisega seotud kombed ja tavad, väljakujunenud tarbimisviisid on tänapäeva ühiskonnas üha sagedasem nähtus. Tarbimisharjumustel on palju erinevaid aspekte millest kõik hõlmavad meie maailma heaolu. Need erinevad tarbimisharjumused võivad olla põhjuseks paljudele keskkonna probleemidele. Seepärast on vaja meil kõigil muuta oma tarbimisharjumusi ja kohe.\nÜks viis kuidas tarbimisharjumusi vähendada on osta vähem toitu. Ostes vähem toitu saab inimene alandada oma toidu tarbimist ning seekaudud kahandada toidujääke, mis tekkiks ostes ebavajalike toite. Minnes poodi ostunimekirjaga on hea viis kuidas seda meetodi rakendada, sest siis ei osteta ajsu mida vaja ei lähe. Samuti saab vähendada toidukadu jälgides vananemis kuupäeva ja hoides alles ülejäänud toit mida saab hiljem tarbida. See viis on odav ja ei nõua palju vaeva.\nTeine viis kuidas tarbimisharjumusi vähendada on osta kvaliteetseid ja mugavaid rõivaid. Korralikud ja kaua kestvad rõivad vähendavad ebakvaliteetsete rõivaste sattumist prügimääle või taaskasutuspoodidesse. Viis kuidas seda teha on mitte minna kaasa sooduskampaaniatega ja vältida riiete ostmist Hiina veebipoodidest. Ostes riideid kohalikkudest poodidest kus valmistatakse hea väärtusega riideid saab ka vähendada riidekadu. Korralikud riided kestavad kaua ja ei nõua asendus niipea. Seepärast on kvaliteetsed rõivad hea valik nii endale kui ka planeedile.\nOlgu see nimekirja järgi ostlemine, trendidega mitte kaasamineminemine, toidu vananemis kuupäeva jälgimine või korralikkude riiete ostmine siis aitad sa sellega meid kõiki. Pole olemas teist maad kus elada ja kui me ei hoolitse enda oma eest siis varsti jääme me sellest ilma. Tarbimisharjumustest loobumine on esimene samm maakera päästmise poole.');
