INSERT INTO core.text(id, content)
VALUES ('ff2cdca9-5cd8-4125-82a4-088e150ae07e',
        'Vajalike ja kahjulike loodusressursse on vaja, et toota meile, kui inimstele riideid ja toitu. Kuid miks see nii halb asi on?\nMe oleme liiga harjunud meie tarbisharjumustega, me ei saa aru kui halb see loodusele on. Kui inimestel on vaja toitu või riideid, siis nad lähevad ja ostavad neid, aga nende tegemine ei ole kõige loodussõbralikum, sest nende tootmine kasutab vajalike loodusressursse. Rõivaste tegemiseks on vaja teha palju tööd ja kasutada loodusele kahjulikke ressursse nagu naftat. Rõivastuse tegemiseks kasutatakse mõndades vabrikutes lapstööjõudu ja nende kaupade importimine on ka loodust reostav. Aga  kuidas ja miks vähendada selle efekti?\nEt võidelda meie tarbimisharjumuste vastu me peame kõik koos töötama. Meil on vaja koos töödata, et me sorteeriksime ja annetaksime riide esemeid nendele kellel neid vaja. Kui me sorteerime neid, siis need viiakse taasakasutuskeskustesse ja taaskasutatakse, et teha vähem riide esemeid. Kuid taaskasutuspoodides on meeletult annetatud riideid, mis on täiesti terved ja neid tekib iga nädalaga juurde. Neid on meeletult palju ja oleks hea näidata noortele milline reostamine toimub, et nad hakkaksid rohkem mõtlema meie planeedile ja enda tulevastele laste üle.\nMeie planeet on meile väga tähtis, ehk me peaksime selle eest korralikult hoolitsema ja selle sooritamiseks me peame koos töötama ja tegema kõike, mis võimalik, et meie järglastel oleks sama hea elada kui meil.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('ff2cdca9-5cd8-4125-82a4-088e150ae07e', 'title', 'Inimeste tarbimisharjumused');
