INSERT INTO core.text(id, content)
VALUES ('e6e9a5db-779a-4c19-a431-c4fb7c816c0a',
        'Viimastel aastatel on noored hakkanud kasutama rohkem Hiinast tellimis võimalusi, miks? Sest sealt saab odavalt asju tellida ja nad tulevad umbes nädalaga kohale. Kui iga noor tellib põhimõtteliselt kõike, mis ette jääb, siis jääb väga palju ülearuseid asju. Teisesõnaga see on reostus.\nSelle tellimise negatiivne pool on veel see, et noored isegi ei tea kui kvaliteetseid asju nad ostavad. Asi võib pildil ju ilus ja korralik välja näha, aga tegelikkuses see nii ei ole. Mina isiklikult ei telli Hiina poodidest midagi, kuna ma ei taha oma raha raisata asjade peale, mida ma saan kanda ainult paar korda. Nii nagu ka moedisainer Eve Hanson „Vikerhommik“-us ütles, et Hiina kaubamajakast ostetakse riideid, mis tegelikult koosnevad naftast ja sa ei saa neid kanda rohkem kui ühe korra, kuna kehal on halb olla selles.\nOlen ka Hansoniga sellel teemal nõus, et peaks noored taaskasutuspoodide laodesse viima, et nad saaksid aru, milline raiskamine tegelikkuses toimub. Võimalik, et mõnda noort see ikka huvitab ja ta muudab oma harjumusi.\nArvan veel, et noored võiksid rohkem taaskasutuspoodides käija. Noored teevad selliste poodide üle nalja ja räägivad, et ei läheks kunagi sinna. Mina isiklikult käin taaskasutuspoodides ja leian sealt alati, midagi huvitavad või midagi, mis mulle meeldib. Pole alati vaja tuttuut asja, kui sa saaksid selle kuskilt Humanast poole odavamalt. Võimalik, et kvaliteet pole sama, mis uuel, aga kui on heas korras, siis käib kah.\nKokkuvõtvalt peaksid noored rohkem hindama kvaliteeti ja vähem reostust. Ei ole alati vajalik tellida kõike, mida sa internetis näed, teadmata selle kvaliteeti ja kui palju see tegelikkuses reostab. On ka paremaid ja vähem reostavamaid võimalusi. Hoiame kokku, kvaliteet on ikkagi kõige olulisem.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('e6e9a5db-779a-4c19-a431-c4fb7c816c0a', 'title', 'Noored taaskasutuspoodidesse!');
