INSERT INTO core.text(id, content)
VALUES ('4eb4e673-1563-40c7-819d-b981b6e25bca',
        'Kõik inimesed armastavad riietuda. Kõigile meeldib osta uusi, ilusaid riideid, kuid ostes uue riide ese, vanad ununevad kapi põhja ning lõpuks visatakse neid lihtsalt ära. Samuti enamus ostavad riideid, mitte kvaliteedi, vaid hinna pärast, kuid madal hind näitab ära, et riide ese on valmistatud mitte kvaliteetsetest materjalidest.  \nLiiga palju riideid. See on üks suurtematest probleemidest tänapäeval. Riideid ei saa ümbertöötada, naftast valmistatud riided eraldavad mikroplasti vette jne. Inimesed teadlikult reostavad meie ümbrust, kuid ise ei ole nõus midagi ettevõtma. Inimesed võiksid eelistada pigem kvaliteetseid riideid, mis ei ole naftast tehtud. Mõtte on selles, et saada naftast valmistatud riietest lahti, et vette ei eralduks aina rohkem mikroplasti. Inimesed võiksid mõista, kui suur see probleem tegelikuses on. Kui minna taaskasutuspoodi, siis võib näha, kui palju kasutatuid ja mitte vajalike riideid tuuakse. Neid tekib iganädalaselt juurde ja see tohutu hulk riideid on meeletu.\nOlen vägagi nõus moedisaineri Eve Hansoni mõttega, et võiks eelistada taaskasutuspoode, kuna sinna tuuakse korralikke ja puhtaid riideid, mida pole piinlik kanda. Kui inimesed ostaksid riideid sealt, siis oleks ka uute riiete tootmist vähem. Samuti, kui inimesed ostaksid uusi riideid, mitte Hiina veebipoodidest, vaid kvaliteetsetest poodidest, poleks vajadust osta koguaeg uusi riideid, ainult sellepärast, et vana riide värv on kulunud või riie venis välja. \nInimesed võiksid reklameerida taaskasutuspoode, võiksid näidata, kui suur hulk riideid seal seisab. Olen nõus Eve Hansoni ettepanekuga, et noortele võiks teha ekskursioone taaskasutuspoodide ladudes, et näidata, milline raiskamine tänapäeval toimub, sest noored võiksid samuti mõelda tänapäeva keskkonna probleemide peale ning selle peale, mida võiks ettevõtta.\nKokkuvõttes inimkond võiks arusaada, et tuleb midagi ettevõtta. Tohutu hulk riideid reostab meie planeeti ja see on tõenäoliselt nukker, et inimkond ei ürita lahendada seda probleemi. Ma loodan, et inimkond võttab kokku ning suudame lõpuks lahendada seda muret.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('4eb4e673-1563-40c7-819d-b981b6e25bca', 'title', 'Taaskasutuspoodidesse!');
