INSERT INTO core.text(id, content)
VALUES ('907e5126-d21a-4238-ada4-00b6106a7bcd',
        'Riideid toodetakse üle maailma igapäev. Riideid toodetakse, kas looduslikest materjalidest või keemiast ja naftast. Loomad ja linnud on hukkunud nende riiete pärast mida toodetakse kahjulikest kemikaalidest. Kuid mitte ainult loomad ja linnud, kui ka inimesed ja meie planeet. Väga ilusad paigad looduses on hävinud ja reostunud sellepärast. Kemikaalsete riiete kvaliteet on väga kehv.\nEt selliseid asju ära hoida, maailm võiks vähem toota riideid mis on tehtud kahjulikest kemikaalidest ja kasutada hoopis looduslikke materjale, nagu näiteks lamba vill, riide taim ja looma nahk. Kui seda kasutaksime oleks kõigile parem kui lindudele,  loomadele, inimestele ja planeet maale. Loomad ja linnud on hukkunud sellepärast kuna see prügi, mis sellest tekib satub kas metsadesse või vetesse, mida loomad sisse söövad. Ja inimeste puhul on see heitgaas mida nad sisse hingavad ja riiete kandmine, mis võib tekitada lööveid või sügelisi. Looduslike materjalide kasutamine oleks isegi ka lihtsam, kuna kahjulike riiete tootmiseks on vaja väga palju vaeva näha. Masinad millega neid saadakse, masinad millega neid toodetakse. Näiteks nafta saamiseks on vaja seda suurt nafta tööstus alust mis vee peal seisab. Kuid looduslike materjalide jaoks on lihtsad tööriistad, et neid saada. Ja pidevalt on looduslikest materjalidest koosnevad riided palju parema kvaliteediga. Näiteks Hiinas, kes on üks suurimaid kemikaalsete asjade tootja on teinud oma riigi õhu ja selle riigi ilusad kohad väga kahjulikuks ja koledaks.\nKokkuvõtteks saan mina öelda, et minu arvates oleks parem looduslikke materjale kasutada, mida saab ilma maailma reostamatta. Looduslike materjalide uuesti kasutama hakkamine muudaks meie maailma väga palju. Linnud, loomad, kalad, inimesed ja planeet maa oleks paremas seisus kui praegu. See hoiaks meie maailma ilu ja oma naturaalset seisu.');
