INSERT INTO core.text(id, content)
VALUES ('5712e45a-6cac-4f69-87fd-8e50d0514d82',
        'Tänapäeva maailmas on väga palju raiskamist, nii toidu kui ka riiete ja tegelikult ka paljude muude asjadega. Paljud inimesed ei saa aru, et hävitame enda planeeti kasutades liigselt Maa ressursse. Olen kindel, et kui sellest teemast rohkem räägitaks, siis inimesed mõtleksid rohkem mida ja kui palju nad tarbivad.\nPalju räägitakse sellest, kuidas taaskasutada asju või vähe tarbida, aga väga harva seletatakse ära, miks on vaja seda teha seega osad inimesed ei võta seda nii tõsiselt ja tarbivad liigsetes kogustes edasi. Hea oleks sellist asja jagada just kaubanduskeskustes, kus inimesed võivad tihti osta asju ,mis neile hetkeks meeldivad, aga tegelikult pole nad läbi mõelnud, kas neil on seda päriselt vaja või ,kas nad saaksid selle asja näiteks hoopis taaskasutuskeskusest. Internet on samuti hea koht selle info jagamiseks, kuna paljud inimesed ostlevad just e-poodides. Väga populaarne on tellida Hiina kaupa, mida toodetakse hullumeelsetes kogustes, kuid olen märkand internetis aina rohkem inimesi nüüdseks rääkimas sellest, et tuleks lõpetada sellistes e-poodides ostelmine. \nTihti ostavad ka inimesed liiga palju süüa koju, poes olles mõtlevad nad, et neil on selle toidu isu, aga koju jõudes söövad paar ampsu ning toit jääb kappi seisma kuni ületab kasutustähtaja. Seega hea võimalus selle vältimiseks oleks, et teha kodus varem poenimekiri valmis asjadest, mida päriselt vaja läheb ja milles sa oled kindel, et ära tarbid. Ka süüa tehes tuleks teha kogus mille tead, et ära sööd enne seda kui enam toit ei kõlba. Süüa võttes tuleks arvestada kui tühi su kõht tegelikult on ja tõsta endale paras portsjon, mille jaksad ära süüa.\nVäga hea koht, kus ei raisata toitu nii palju on toidupank, sinna viiakse toidud mis on ületanud parim enne kuupäeva, kuid tegelikult on kõlblikud veel ning paljusi inimesi aitab see väga, kellel ei ole rahaliselt võimalust osta iga nädalaselt poest süüa.\nKokkuvõtteks tuleks rohkem jagada maailmas seda, kuidas ületarbimine hävitab meie maailma ning, kuidas on palju võimalusi ületarbimise vältimiseks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
