INSERT INTO core.text(id, content)
VALUES ('2cc8e80f-2abf-4fde-b42d-8b47e2d298f3',
        'Väga paljudel inimestel on välja kujunenud erinevad harjumused, mis on tulnud elu jooksul. Eriti noored- nad ei mõtle liialt sellele, kuidas tarbimisharjumused võivad ka väga muret tekitavad olla. Ma arvan, et ületarbimine on suureks probleemiks, millega tuleks mõjukamalt tegeleda. Kuidas hoida ületarbimist ära ja miks ületarbitakse?\nMida rohkem aeg mööda läheb, seda suuremaks ületarbimine läheb. Hiina veebipoed, mis on viimastel aastatel  väga populaarseteks saanud, on pannud inimesed tohutult palju ületarbima. Ilma, et inimesed sellele mõtleks, on just sooduskampaanjad need, mis panevad ostma, mitte riided ise. Moedisainer Eve Hanson väidab murelikult, kuidas riietehunnikud taaskasutuskeskustes on tohutult suured ja kuidas noortele peaks tegema ekskursioone ladudesse, et noorte mõtlemist riiete ületarbimisest muuta ning näha reaalsust, kui palju see keskkonda mõjutab.\nÜletarbimine- kahjuks ei puuduta see ainult odavalt kampaanjatega riiete ostmist, vaid puudutab ka massiivselt toidu raiskamist. Toidu raiskamine tuleneb ka palju liiga suurtes kogustes toidu ostmistel. Mõelda tuleks rohkem, kas need toiduained lähevad kasutusse ja ka kuupäevadele. Kui toiduaine kuupäev aegub või rikneb, on lihtne see lihtsalt prügikasti visata, kuid kui suur raiskamine see tegelikult on. Kuid sellega ei raiska me ainult enda raha, vaid ka meeletult palju teisi ressursse. Kahjuks pole inimeste silmad sellel teemal täielikult avanenud. Toidutootmine- see pole ka nii lihtne ja muretu kui arvatakse ning see tekitab ka tohutult keskkonnakoormust ja probleeme. Paljud inimesed mõtlevad, et kui toidujäägid ära visata, ei mõjuta see väga midagi, kuid kui palju toitu saaks tegelikult nendest toidujääkidest valmistada- ei tule isegi pähegi. Kuid see kõik oleks palju lihtsam,  kui tegutseda ja mõelda keskkonna hoidmise peale rohkem. \nKokkuvõtteks on ületarbimine kõik kinni meie enda otsustes. Selleks, et ületarbimist vähendada tuleb tegutseda, mitte lihtsalt oodata, et see vaibub. Kõige tähtsam punkt- teha paremaid valikuid ja mõelda kui keskkonnasõbralik see on. Kõik see on inimeste harjumustes kinni. Kui iga üks kasvõi midagi teeks, et vähem raisata ja rohkem säästa, jõuaksime me lõpuks paremate tarbimisharjumuste juurde. Ning me näeks, kuidas iga väike samm tegelikult kaasa aitab.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('2cc8e80f-2abf-4fde-b42d-8b47e2d298f3', 'title', 'Tarbimisharjumuste mõju');
