INSERT INTO core.text(id, content)
VALUES ('3e8936ce-0ee4-4c59-b645-75ec91fd4882',
        'Igal inimesel on erinevad tarbimisharjumused. Vahel inimene ei pane tähele, et tal on on mingi tarbimisharjumus on. Kui neile öelda, et neil on mingi tarbimisharjumus nad ütlevad selle peale, et neile lihsalt meeldib seda süüa või juua.\nVõtame näiteks toidu iseenesestmõistetavana, neile tundub, et toitu on veel ja see ei saaa kunagi otsa. Nendel on inimesi kes ei raiska toidu, inimesi, kes raiskavad toidu ja viskavad ära väikese summa toidu. Need inimesed kes ei raiska toidu need saavad endale tavaliselt seda lubada, sest neil pole probleemi, et ära süüa seda või kellegile edasi anda. Need inimesed kes raiskavad toidu tavaliselt teevad valmis, aga keegi ära ei söö või jääb lihsalt istuma ja nad ei pane ise tähele, mis juhtub kui ära visata toidu, sest keskmiselt iga Eesti elanigu kohta tekkib 61 kg toidujäätmeid, millest toidukaudu moodustab 42% ehk 26kg raisatud toidu. Seetõttu ei raiska me ainult omaenda raha, vaid ka tohutult muid ressuresse: maad, vett, energiat ja tööjõudu. See toob veel küsimusele, mida inimesed raiskavad toidu tegemise juures. Nad raiskavad iseenda aega, raha, elektrit või gaasi ja veel vajalike ressuresse, et teha süüa, aga kui nad lihtsalt ära viska läheb see kõik raisku. Lisaks tekkib toidu tootmine tõsise keskkonnakoormuse, sest saagi tõstmiseks kasutatakse väetist ja erinevaid kemikaale. \nAga kui mõelda „Millised harjumused on veel inimestel“. Kas inimestel on veel mingi harjumus toiduga? Kas oleks neil harjumus kasutada liiga palju maitseainet või liiga palju õli panna pannile. Ja võimalik, et on võimalus, et on inimene kes teeb kõike ise ja ei käi poes ostmas endale midagi ja ei raiska riigi ressursse vaid raiskab enda. \nKokkuvõtte oleks see, et selliseid inimesi on liiga palju kes lihsalt raiskavad süüa ja materjali. Neil oleks kergem anda ära see toit mis nad tegid ja mitte ära visata. Ja arvatavasti on küll maailmas inimesi kes lihtsalt raiskavad ressuresse ja on inimesi kes keelduvad ütlemast, et neil on harjumus on seda on kindlat näha, et neil on.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('3e8936ce-0ee4-4c59-b645-75ec91fd4882', 'title', 'Inimeste tarbimisharjumused');
