INSERT INTO core.text(id, content)
VALUES ('2d91d6ac-4329-4c92-a594-a62293ce9890',
        '\nKas meile tundub, et toitu veel palju ja ei saa kunagi otsa? On palju inimesi, kellel on seda raha, mida teistel pole ning seepärast raiskavad nad toitu, kuna saavad seda endale lubada. On inimesi, kes aga seda toitu ei saa endale lubada ning hoiavad seda ja hoiavad seda varuks väga palju.\nIgal inimesel on oma tarbimisharjumused ja võib olla ei pane tähelegi, et see neil on. Inimesed, kes raiskavad toitu ja saavad endale seda lubada oma raha pärast, peaksid ikka toitu hoidma söömiseks, mitte raiskamiseks. Need inimesed mõjutavad suurt pilti väga palju ja toidu raiskamise vähendamine võtaks päris kaua aega. Mõned inimesed vist lihtsalt ei mõista seda, et nad ei raiska ainult oma raha, vaid ka tohutult vajalikke ressursse. Maa, vesi, energia ja tööjõud on väga tähtis ning keskonda see ainult koormab. Toidukadu moodustab 42% ehk 26 kg, mis on juba peaaegu pool sajast protsendist. Keskonnal saagikuse tõstmiseks kasutatakse siiski väetisi ja erinevaid kemikaale ja paljud inimesed raiskavad toitu nii, nagu see poleks suur asi. Juba, et kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid on juba palju. Tõsi, et toitu on palju, kuid kui nii paljud inimesed jätkavad toidu raiskamist, siis ei pruugi toitu nii palju enam olla ja toidusaamiseks on väga palju viise, kuid ka see võtab aega. Inimesi tuleb ka maailmasse juurde ja juurde, mistõttu võib veel toitu vähemaks jääda, kui nad raiskavad seda samamoodi nagu enamus inimesi.\nKokkuvõttes võib saada toit lõpuks otsa, kui seda nii palju raisata, seetõttu peaksid toitu mitte ära viskama. Isegi ka inimesed, kes väiksemaid koguseid toitu ära viskavad, võiks seda mitte teha, ükskõik kui palju nad seda endale lubada ka ei saaks. Inimesed peaksid mõtlema ka selle peale, et toiduks raisatakse tohutult ressursse, mida kindlasti meil vaja läheb ja nende raiskamine oleks halb, kui see pole just ületähtaja ületanud toit või riknenud, aga söömisel ülejäänud toit tuleks pigem ära süüa kohe või hiljem.');
