INSERT INTO core.text(id, content)
VALUES ('6a7435e5-4fba-4222-aeab-318016ed61f6',
        'Paljudel inimestel on erinevaid harjumusi. Kuid suurel osal inimestest on selleks harjumuseks saanud ületarbimine. Ületarbimine on maailmas väga suur ja levinud probleem, seda ei osata ära hoida ega vähendada.\nHiina kaubamajad toodavad metsikutes kogustes kiirmoe rõivaid ja inimesed ostavad neid kuna need on odavad. Kuid alati ei saa lootma jääda vaid odavuse peale, need riided ei kesta kaua ning leiavad kiiresti oma tee prügikasti või taaskasutuskeskustesse. Moedisainer Eve Hanson tõdeb, et riiete hunnikud taaskasutuskeskustes on meeletud ning noortele peaks tegema ekskursioone ladudesse, et avada nende silmi ületarbimise koha pealt.\nKuid ületarbimine ei ole vaid odavate riiete ostmine. Ka toidu tarbimine võib minna üle piiri. Toidukadu maailmas on meeletu. Inimeste arvates on toit asi mis ei saa otsa ja seda tuleb koguaeg juurde. Mõeldakse, et see väike kogus mille sa ära viskad ei põhjusta midagi halba, kuid see on tohutu ressursside raiskamine kui seda teha pidevalt. Näiteks Eesti inimese kohta tekib aastas keskmiselt 61kg toidujäätmeid millest toidukadu moodustab 42% ehk 26kg. See kõik on tarbimata jäänud toit, mis lõpetab prügikastis.\nMaailma raputav probleem ehk ületarbimine on asi millega tegeletakse igapäevaselt. Ületarbimine võib olla nii riiete kokku ostmine, kuid ka toitu tarbitakse üle. Asjade ära viskamine on saanud tavaks ja mõte, et seda kõike saab tagasi osta on normaliseeritud.');
