INSERT INTO core.text(id, content)
VALUES ('3a25e2b0-1951-41db-a81c-12317fcedf38',
        'Maailmas igalpool kipuvad inimesed ostma just Hiina kaubamajadest, sest seal on palju odavam kui mujalt osta. Inimesed ostavad sealt, kannavad päris vähe aega või ei kanna kordagi (sest see ei sobinud talle ja ta viskab selle ära) ning sealt algab ületarbimine. Ületarbimine on probleem, sest kõik need riided lähevad lihtsalt raisku ja enamik neist riietest ei saa ümber töödelda.\nInimesed peaksid hakkama rohkem ostma kvaliteetsemaid riideid ja riideid mida saab ümber töödelda. Parem oleks isegi toetada enda riiki ja osta enda riigi erinevatest kohtadest riideid, mitte tellida ületoodetud kohtadest nt Hiina kaubamajadest. Inimesed võiksid ka käia rohkem taaskasutuspoodides ja neid võiks üldse veel rohkem avada kui neid praegu on.\nKui inimesed hakkavad ostma kusagilt uusi rõivaid, siis võiksid nad ka mõelda selle peale, kas nad tegelikult vajavaid neid riideid, mida nad hakkavad ostma või tellima. See säästaks hulga rohkem raha ja enamik riideid, mida ostetakse ei kanta kordagi, kannadki paar korda ja viskad kohe minema või jäävad lihtsalt kappi tolmu koguma.\nMoedisainer Eve Hanson rääkis „Vikerhommik“ intervjuus, et noortele peaks tegema ekskursioone taaskasutuspoodide lattu, et noored näeksid, mis raiskamine tegelikult toimub. Noored peaksid tõesti rohkem taaskasutusega tegelema, sest nemad ongi just need põhilised ületarbijad.\nNoortele ja üldse kõigile inimestele tuleks rohkem näitada taaskasutuskeskuseid ja võiksid viia oma riideid sinna. Hiinast riiete tellimine võiks ka ära lõpetada ja rohkem ostleda oma riigi poodides ning toetada oma riiki.');
