INSERT INTO core.text(id, content)
VALUES ('dd89370b-3cf0-499c-af18-2a90413a4b15',
        'Ületarbimine on liigse kauba ostmine, mida inimene lihtsalt ei jõua ära tarvitada, olgu see riietus, toidukaup või midagi muud. Suur osa individuaale ei ole suutnud mõista, et osta palju asju halva kvaliteediga pole parem, kui eelistada head kvaliteeti aga osta vähem asju.\nRiideid tellitakse Hiinast, sest et see on odav, kuid kedagi ei hooli kvaliteet ega see, millest see riietus on tehtud, seni kuni inimene riideeseme selga paneb ja saab aru, et läheb paari minutiga seda särki kandes higiseks, või, et see jope ei ole üldse piisavalt soe talve jaoks. Peale seda nad lähevad tagasi nendele Hiina veebilehtedele ja ostavad midagi muud, lootes, et kui asi kohale jõuab, siis on sellel parem kvaliteet, kui eelmisel. Sellisel viisil see tellimine väga raha ei säästa, kui kõik muudkui ostavad ja tellivad. Taoline hulgaline tellimine võtab paju ressursse ja raha, et kogu kaup kohale toimetada. Tellitud asjad tulevad kohale, kas laevade või lennukitega, mis ei ole looduse jaoks just kõige parem.\nSama asi toimub ka toidukaupadega. Inimesed ostavad rohkem toitu, kui nad suudavad ära süüa. Siis läheb kõik see halvaks läinud kraam prügikasti ja see on päris suur raiskamine. Arvestades sellega, et päris mõnigi arvab, et toit ega vesi ei saa kunagi otsa, ei oska nad isegi mõelda selle peale, et kogu selle toidu kasvatamine on suur koormus maa peale, kuna tänapäeval kasutatakse väetisena kemikaale. \nSellest arutlusest võin järeldada, et ületarbimine ei ole hea ei inimestele, nende rahakottidele ega maale, millel me elame. Parem on osta ei vähe ega palju, vaid just piisavalt.');
INSERT INTO core.text_property(text_id, property_name, property_value)
