INSERT INTO core.text(id, content)
VALUES ('b518c2d2-24b6-45b3-88d3-176f5178e978',
        'Probleeiks siin maailmas on liigne tarbimine ja asjade kuhjamine endale, mida meil pole isegi mitte tegelikult vaja. Need harjumused on halvad ning rikuvad ja reostavad meie maailma.\nRaiskamine ei käi vaid riiete ja asjade kohta vaid ka toidu ja toiduainete kohta. See on halb meie ühiskonnale ja see peab muutuma!\n„Tarbitoitutargalt.ee“ lehel räägitakse, et Eesti inimese kohta tekib 61kg toidujäätmeid ja sellest omakorda 26kg on kahjuks toidukadu. Aga miks inimesed raiskavad toitu nii palju tekib küsimus? See on sellepärast kuna on inimesi kes saavad lubada endale seda, aga on ka inimesi kes viskavad toitu vähe haaval minema ja arvavad, et see ei tee nii suurt kahju, mis on täielik vale.\nMinu arust on toidu raiskamine lollus, sest miks sa pead enda taldrikule kuhjama teades, et sa ei jaksa nii palju süüa. Jah olen ka mina toitu ära visanud põhjusega, et see mulle ei meeldinud või ei maitsenud, aga ka see pole mingi vabandus. Selleks, et ei teksiks sellist olukorda kus midagi jälle prügikasti läheks, siis tuleb jälgida Kus kohast? Kelle käaest? ja Mida? sa ostad. Kui sulle tõesti meeldib näiteks teatud firma sink ja see poes otsas on siis ära osta teise firma oma teades, et see lendab väga suure võimalusega prügikasti. \n„Vikerhommik“ intervjuus rääkis Moedisainer Eva Hanson „on oluline, et igaüks vaataks üle oma isiklikud tarbimisharjumused ning ei eelistaks kvaliteeti üle kvantiteedi“. Inimeste tarbimisharjumused on probleemsed ja halvad, aga ma mõistan ka natuke miks inimesed ostavad ja tellivad Hiinast asju. Põhjuseks on meeletud hinna tõusud. Kunagi said poest pusa viieteist kuni kahekümmne euroga, nüüd aga hinnad kahekordistunud. Tellin ka ise vahest Hiinast, aga pigem sellepärast kuna siin pole seda asja leida voi need on über kallid ja väga suur kahju mu rahakotile. Küll aga jah, Hiinast tellimine muutud probleemseks kui tellid üleliia endale asju mida sul pole isegi vaja just sellepärast, et need on odavad. See on sõna otseses mõttes yletarbimine ja ebavajalik.\nKokkuvõteks tarbime me kõik milleski natukene kasvõi halvasti, kas on need riided, asjad või toiduained. Aga seda saab ainult vältides sellega kui jälgime kriitiliselt Mida? ja Kus kohast? me midagi tarbime. Jah vahest on parem kui tellid midagi endale Hiinast kui see ei rüüsta su rahakotti. Aga parem on kui ostame kodumaisemaid asju.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('b518c2d2-24b6-45b3-88d3-176f5178e978', 'title', 'Probleemsed tarbimisharjumused meie ühiskonnas');
INSERT INTO core.text_property(text_id, property_name, property_value)
