INSERT INTO core.text(id, content)
VALUES ('fac3c7c7-6a7f-42db-9e7e-ad1a467fad8e',
        'Inimesed ja peamiselt noored veedavad liiga palju aega nutiseadmetes. Osad noored ei suuda olla isegi 5 minutit ilma katsumata nutiseadet. Inimesed veedavad nii palju aega nutiseadmetes, et nad varsti ei tee enam päriselul ja virtuaalsel maailmal vahet. Minu meelest on see halb, kui kõik läheb üle internetti, kuna internettis on palju pettusi ja valetamist.\n    Mida rohkem aeg mööda läheb, seda rohkem hakab nutiseade meie elusid mõjutama. Noored ja ka vanemad inimesed on lummatud sotsiaalmeediast nii palju, et nad lihtsalt ei suuda enam telefoni käest ära panna ja keskenduda päris maailmale. Noortele meeldib vaadata videosi inimestest, kelle justkui internetti läbi näha kõik perfektne kuigi tegelikkuses ei pruugi olla. Häasti palju näidatakse migeid ilu nippe või nii öelda asju, mis teevad elu paremaks ja inimesed jäävadki seda uskuma, proovivad ja kui välja ei tule siis on pettunud. Inimesed ei mõista, kui ohtlik võib olla internet. Nad ei tea, kui palju veidraid inimesi seal on ja kui palju inimesi, kes üritavad su raha endale saada läbi pettuste. Maailmas väga paljud inimesed üritavad üle minna internettile, aga ei mõtle selle peale, kui palju halbu asju internetis peitub. \n        Minu meelest peaks ootama selle üleminekuga ja peaks mõtlema, kas see on ikka kõige parem mõtte. Vaadata üle, kui turvaline see on ja mõelda kas see oleks just kõige parem.  Rääkida kindlasti lastele ja ka vanematele inimestel, mis pettusi ja ohte seal on ja teha internet võimalikult turvaliseks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('fac3c7c7-6a7f-42db-9e7e-ad1a467fad8e', 'title', 'Nutiseadmete liigne tarbimine ja selle probleemid');
