INSERT INTO core.text(id, content)
VALUES ('a903b2c7-7c79-4763-86de-f29fcbb6e59e', 'Inimeste tarbimisharjumused tänasel päeval on ilmselt juba päris suur probleem. Raisatakse palju toitu ning kiirmoega kaasas käies inimesed tellivad endale kuskilt välismaalt kuhjade viisi odava hinna eest riideid, mis varsti enam kasutust ei leia ja jäävad kapi nurka seisma. Sellega ei mõelda, mis kahju see tegelikult ühiskonnale toob.
Kuna kõik on tänapaeval tegelikult nii kättesaadav, siis ei pea paljud meist lmselt muretsema millal meil järgmine söögikord on ja sellepärast inimesed suudavad rahuliku südamega toitu ära visata. Tihti, kui kuskil on suured allahindlused, sooduskampaaniad, lähevad inimsed ahneks, tehakse mõtlematta sisseoste.\nOlen täiesti nõus, et igaüks peaks üle vaatama oma isiklikud tarbimisharjused. Näiteks toidupoes käies ei mõelda läbi, mida tegelikult vaja on ja ostetakse üleliia suurtes koguses toitu, mida tegelikult ära ei suudeta tarbida. \nTihti on need kuskilt Hiinast odavalt tellitud rõivad nii halva kvaliteediga, et tulebki koguaeg järjest uusi tellida, kuna riided lähevad ruttu koledaks ja lihtsalt ei ole enam kasutuskõlblikud. Selleasemel, et taaskasutuspoodidesse neid meeletuid hunnikuid tekitada võiksid inimesed investeerida kvaliteetsetesse rõivastesse, mis tegelikult ka aastaid kestavad, juba sellega vähendaksime oma tarbimist.\nKui me kõik mõtleks samamoodi, et kui mina enda toiduraiskamist vähendan ja täna seda toitu ära ei viska, enda ostud läbi mõtlen jne ei muuda üksi ma maailmas midagi paremaks. Nii tõesti ei muutugi midagi. Me võiksime rohkem mõelda enda jalajälje peale ning investeerida kvaliteetsetesse kaupadesse. Õpetajad võiksid koolides sellest teemast rohkem rääkida, et noored oleksid rohkem teadlikumad nendest asjadest ja hakkaksid juba varakult enda tarbimisharjumuste üle mõtlema');
