INSERT INTO core.text(id, content)
VALUES ('c7ed4199-ad23-4fd3-89b9-1dca1dd3d788',
        'Arvan, et hiinakaupa hakkatakse üha rohkem tarbima, sest see on odav ja annab samasuguse tulemuse, kui mõni muu asi, mis on kallim. Millele inimesed ei mõtle on see, et millest see koosneb ning, kas päriselt kehal oleks selles või peab kuhugi hiljem ära viskama? On see seda väärt?\nNoored hakkasid suurest Hiina poest suurte rahasummade eest väga palju ettemõtlematuid asju tellima ja nüüd ka vanemad inimesed. See võib ju odav olla, aga kas see ka väärt on seda? Inimesed ei mõtle sellele, et kas nad teevad midagi valesti või ei, sest nad ei tea, et neil on tarbimisharjumused. Kui neid asju järjepidevalt ära visata, hakkab see mõjutama nii meie loodust kui ka muid ressursse: maad, vett, energiat, tööjõudu. Ka loomade keskkond hävineb nendest tarbimisharjumustest üha rohkem ja rohkem. Milleks? Inimesed peaksid natukene rohkem mõtlema ka inimestest, kellel ei ole võimalust mitte ühelegi asjale, ning võiks mõelda kuidas see ära viskamine kuidagi neile kasulik oleks. Oluline oleks aru saada, mis on päriselt õige ja, mis vale.\nInimesed arvavad jah, et on odav, aga see kuidas nad saaksid maailmale kasulikud olla teisiti, sellele nad ei mõtle. Nüüd on juurde tulnud ka väga palju vanemaid inimesi, kes sellele kaasa aitavad. Nendel ei ole aimugi, kuidas see meie keskkonda muutnud on. Võimalusel võiks mõelda ka inimestele, kellel oleks neid võibolla rohkem vaja.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('c7ed4199-ad23-4fd3-89b9-1dca1dd3d788', 'title', 'Hiinakauba tarbimisharjumused');
