INSERT INTO core.text(id, content)
VALUES ('3c00a83a-38ea-4dbc-9a16-f70cdf40a7bd',
        'Oma igapäevaelus tarbivad inimesed kõike. Me tarbime nii toitu kui ka materjale. Aga, kas me oleme mõelnud sellele, kuidas meie tarbimisharjumused mõjutavad meie keskkonda ja selle tulevikku.\nIga väiksemgi samm võib mõjutada meie planeedi tulevikku. Igapäevaelus me nii tarbime kui ka raiskame. Me võtame toitu ja materjale iseenesestmõistetavana, justkui need ei saakski otsa. Tegelikult ei ole see olukord üldse nii roosiline kui see tundub.\nUuringutest selgub, et kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26kg. Toitu visatakse ära erinevatel põhjustel. Kord on toit riknema läinud, kasutustähtaja ületanud, söömisel ülejäänud või pole lihtsalt maitsenud. Nendel põhjuste tulemusel visatakse see toit lihtsalt toidujäätmetena ära.\nTagajärgedena ei raiska me ainult omaenda raha vaid ka muid ressursse: maad, vett, energiat ning tööjõudu. Nii suures koguse toidu tootmine toob kaasa ka keskkonnakoormuse, kuna saagikuse tõstmiseks kasutatakse väetisi ja erinevaid keskkonda kahjustavaid kemikaale.\nKuid toit ei ole ainus tarbmisharjumus. Me tarbime ka materjale, millest valmistatakse meile vajalike rõivaid. Ka neid rõivaid on inimesed hakanud aina rohkem raiskama. Igapäev viivad inimesed taaskasutuskeskustesse riideid. Viiakse nii korralike riideid kui ka naftast koosnevaid, nahale ebamugavaid rõivaid, mis on tõenäoliselt ostetud kuulsatest Hiina kaubamajdest. \nMoedisaineri Eve Hansoni ettepanekut eelistada kvaliteeti kvantiteedile on minu arvates väga arukas ja igati tark mõte. Eelistada võiks kindlasti rohkem kodumaiseid ja lähedalt toodud asju ning pigem vähem kui rohkem. \nSellise käitumise tagajärjel ei oleks rõivaste ja materjalide kadu nii suur ja nende tootmiseks vajalikke ressursse kasutatakse kindlasti vähem. Selle käigus on ka meie elukeskkonna tulevik palju puhtam ja hoitum.\nKindlasti oleks vajalik tarbimisharjumuste teema teadlikust tõsta nii koolides kui ka kodudes, et inimesed saaksid aru, et toidu ja materjalide tootmine polegi nii lihtne ja iseenesestmõistetav kui see tundub.\nKokkuvõtteks iga meie otsus ja samm võib mõjutada meie keskkonna heaolu ja tulevikku. Tarbimisharjumuste parandamine ei muutu kindlasti üleöö kuid vähehaaval on seda võimalik kindlasti muuta.');
INSERT INTO core.text_property(text_id, property_name, property_value)
