INSERT INTO core.text(id, content)
VALUES ('9dba18b6-8200-4b3f-99cb-330a0dc53528',
        'Inimesed üle terve maailma raiskavad toitu ja ressursse. Paljud arvavad, et nende teod ei mõjuta midagi maailmas. Kuid see on vale.\nPaljud inimesed ütlevad ja arvavad, et nende teod ei mõjuta maailam kuid see on tegelikkuses vale, isegi väikseimal teol võib olla suur tagajärg. Inimesed ostavad tihti peale toitu kokku, mida nad ei söö ja mis lähevad riknema ning siis tihti peale visatakse suures koguses toitu prügikasti. Nagu artikklis tarbitoitutargalt.ee/toidukaost/ räägitakse, siis keskmine Eesti inimene kulutab aastas umbes 61 kg toidujäätmied, mis on minu meelest vägagi suur kogus ühe inimese kohta ning ilmselgelt sellest enamus läheb ära viskamisele. Aga kui keskmine eestlane kulutab aastas 61 kg toitu, siis kui suur toidukulu on keskmisel ameeriklasel aastas. Teada on, et ameeriklased raiskavad rohkem toitu kui eestlased nii et ameeriklaste kekmine aastane toidukulu võib olla poole suurem kui on eestlaste oma ning see pole just kõige parem meile ega meie keskkonnale. Kuid peale toidu raiskavad inimesed ka suures koguses riideid. Allikas, kus Anu Välba intervjueeris Eve Hansoni rääkis Hanson, et enamus inimesi tellib Hiina veebipoodidest riideid, mis ei ole hea kuna need on saadud odavamalt kui kodumaisetes poodides nii et inimestel väga pole vahet kui nenede asjadega midagi juhtub, sest nad saavad iga kell selle sama eseme uuesti tellida. Ning kui nad tellivad, siis see vana ese läheb jällegi ära viskamisele. Nagu mina Hansoni juttu järgi aru sain peaksid inimesed käima rohkem taaskasutuspoodides ning ostma sealt riideid mitte tellima neid Hiina odavalt toodeldud rõivaid.\nKokkuvõtteks arvan mina, et inimesed peaksid rohkem tähelepanu pöörama kõigele sellele, mis nende tagajärjel muutub ning sellele, et uus ei ole alati parem. Ning pole vaja osta suures koguses toitu lihtsalt selleks, et sellest enamus ära visata.');
