INSERT INTO core.text(id, content)
VALUES ('9005f101-3c6f-4206-bc42-bb94c834da33',
        'Meie igapäeva elus on suureks probleemiks toidu ja riiete ära viskamine. See ei pruugi meile koheselt silma paista, kuid mõjutab meid hetkepealt. Aga miks see just nii on ja mis me tegema peaksime? \nPoodides käimine tekitab tahet midagi meelepärast osta, olgu selleks kas šokolaad või uued jalatsid. Tuleb aga ette, kui tahaks midagi uut proovida, mis lõppudelõpuks ei meeldi või pole sinu jaoks sobilik ning viskad selle mõttematult minema.\nToidukadu on nii meile endile kui ka muudele ressursidele suureks kaotuseks. Iga Eesti elaniku kohta tekib aastas keskmiselt 61kg toidujäätmeid, mis moodustab toidukadu 42% eks 26kg. Toitu saab taaskasutada mitut moodi nt: vananenud toidud viia metsloomadele, toit mis endale ei maitsend, paku tuttavale jne. Toidu raiskamist ei sa muuta üleöö, see võtab aega ning on kinni inim harjumustes.\nRiide esemed on meile väga olulised esemed, mida vajame pidevalt. Inimene kasvab ja on ilmselge, et riided jäävad väikseks ning peab ostma uusi rõivaid. Tekivad uued stiilid ning vaja jälle uuendada oma garderoobi. Aga see ei tähenda, et peaksime nüüd vanad riided maha heitma. Igaükspeaks vaatama üle oma isiklikud tarbimisharjumused ning eelistaks rohkem kvaliteeti kvantiteedi asemel kasutama.\nÄra vii riideid lihtsalt kaltsukatesse, vaid paku ka oma tutavatele, kes oleksid huvitatud seda kandma. Samuti rõivad ei kesta kaua ja lähevad katki. Mitmest esemest saab teha uue ja veelgi uhkema. Tuleb osta rohkem kodumaiseid riideid ning vältida kuulsaid Hiina kaubamajasid. \nKokkuvõtteks peame mõtlema mida me ostame ja kas me seda ikka kasutame või  vajame. Taaskasutus on oluline aga me ei näe seda enne, kui muudame enda tarbimisharjumisi. Alati leitakse lahendus probleemile aga kas seda just täide viiakse.');
INSERT INTO core.text_property(text_id, property_name, property_value)
