INSERT INTO core.text(id, content)
VALUES ('719b9eca-a093-420e-bfed-782acf9faed0',
        'Poodidesse on tulnud juurde palju uusi tooteid, mida me varem proovinud pole, asjad on muutunud inimestele kättesaadavamaks, kui need kunagi olid ja inimesed ostavad üha aplamalt koju asju, mis ära ei kulu või vaja ei lähe. Miks teevad inimesed nii ja kas saaks teisiti.\nTihti sisened toidupoodi mõttega, et võtad oma piima ja leiva ning lähed ära, peaaegu alati lõppeb see suure kotitäe ebavajalike asjadega, mis sageli üle jäävad. Enamus toitained ei ole kukkunud puu otsast alla, vaid nende tegemiseks on vaja läinud vett, energiat, tööjõudu ja palju muud. Kui ostetud toiduained jäävad pärast järgi, raiskad toitu ning viskad teenitud raha lihtsalt tuulde. \nVõtame toitu iseenesestmõistetavana, arvame, et seda on veel ja saame igal ajal toiduvarusid uuendada. See aga nõuaks väga suurt toiduainete massitoodangut, mille tulemus on väga suur keskkonnakoormus,  kuna saagitõstmiseks kasutatakse erinevaid kemikaale ja väetisi, on mainitud „Tarbitoitutargalt“ artiklis. Omaltpoolt lisaksin ka toidu transpordi, mis reostab samuti tohutult loodust oma heitgaasidega.\nEve Hanson on  „Vikerraadio“ intervjuus toonud välja ka tekstiili raiskamise. Inimesed eelistavad kodumaistele rõivastele odavaid välismaapoodides suurtes kogustes valmistatavaid ebakvaliteetseid tooteid, mille ostjad pärast vähest kandmist ära viskavad. Hanson on taaskasutuspoodide ladudes vabatahtlikult abis käies täheldanud kui suurtes kogustes riided sinna iganädalaselt tuuakse. Ta on märkinud, et need rõivad on tihti korralikud aga kohe on näha, et need on valmistatud materjalist, mida on naha peal väga ebamugav kanda ning ilmselt just sellepärast need sinna toodud ongi. Tean ka omast kogemusest kuidas e-poes pildi peal ilusad riided on kohalejõudes täiesti teistsugused ja siis alles mõistan, et olen lihtsalt oma raha raisanud ja loodust reostanud.\nKokkuvõtteks on ebavajalike asjade kokku ostmine oma raha ja ressursside raiskamine ning looduse reostamine, kui tunned, et tegelikult ma seda toodet ei vaja pole mõtet seda endale üldse muretse. Kui tahame ka saja või kahesaja aasta pärast planeet Maal elada peame seda hoidma ja selle eest hoolitsema, sest loodus saab hakkama ilma meieta aga meie ilma looduseta hakkama ei saa.');
