INSERT INTO core.text(id, content)
VALUES ('dc6799fd-98bf-47c0-82e1-8dd836420469',
        'Tänapäeva üks suurtematest probleemidest on ületarbimine. Iga teine inimene vahetab oma telefoni välja paari aasta tagant. Mõned ostavad isegi endale uusi autosi tihedamine kui sõidavad nendega, tuues põhjuseks et auto vajab liiga palju remonti.\nTaaskasutamine lahendaks maailmas palju probleeme. Õudne on vaadata dokumentaalfilme Hiinas töötavatest noorukitest ja meresulpivatest prügisaartest. Teada on juba ammu, et peaaegu kõik toodankust tuleb Aasiast, mis ei ole hea ega järjesuutliku kvaliteediga. Ostad kasvõi tooli Ikea´st ja märkad et see hakkab peagi kriiksuma, vaatad vanavanaisa nikerdatud kappi seinanurgas mis on juba aastakümneid vastu pidanud ja näed erinevust. Kiirmood on viinud riiete kvaliteedi viimase sajandiga niivõrd madalaks, et polegi muud teha kui asendada on väljaveninud kampsunid uutega. \nArvatakse, et maailmsete ületarbimis probleemide lahendamiseks saab viia kaltsukatesse oma vanu Shein´i riideid, aga fakt on see, et isegi taaskasutuskeskused peavad viskama ära suurtes hunnikutes riideid, kuna pole kuskil neid hoiustada. Toidupoed viskavad kõlbliku toitu prügikastidesse, selleasemel et annetada hädavajavatele peredele seda. On tehtud aga ka palju head probleemi lahendamiseks, vabatahtlikud korjavad randadelt ja järvedest prügi ja on olemas firmad nagu Toidupank.\nMaailm oleks palju parem kui me tarbiksime vähem. Valmistaksime ise asju, selle asemel et osta Hiina odavtööjõu käest kootud sokke. Kasvataksime oma peenramaal porgandeid, ostmata mürke sisaldavaid masstoodangut, mis vähendab suures hulgas tolmendajate tegutsemist.\nMõtle järgmine kord kui ostad. Kas toode läheb sul varsti prügisse või saad seda edasi pärandad järgmistele põlvkondadele.  Austa vana, märka kvaliteeti.');
