INSERT INTO core.text(id, content)
VALUES ('a24e9c17-39e6-4e8a-bff3-f73938846ac2',
        'Inimestena võtame me seda loomulikult, et kui midagi jääb üle, või kui midagi ei meeldi viskame me selle ära. Raisates igapäev mingi osa jääke ei muuda see algpildis ju midagi, kuid kui seda seisu jälgida pikemas perspektiivis toob see endaga kaasa  suuri probleeme.\nPalju on maailmas selliseid peresi, kellel pole piisavalt vahendeid söögiks. Mõni päev ei söö nad midagi, vahel saavad kasutamiseks koguse millega saaks vaid ühe väikse 3-aastase ära toita. Just nemad ärkavad hommikul teadmisega, et kui täna midagi ei hangi võib asi kurvaks kiskuda. Samal ajal on aga edevaid teiselpool maakera, kes viskavad ära suure paki mingit toodet, kust on  heal juhul võetud üks amps, sest neile "ei maitsenud“.\nNoored tellivad alatasa suuri pakke Hiinast mõtlemata, millistes tingimustes need asjad valmistatud on. Noorele ei saabu mitte kunagi 100% puuvillast tehtud särk, mis on pakendatud töörõõmust pakatatavate inimeste poolt. Ei, noorukile saabub riie, mis on valmistatud naftast, mille on suur tõenäosusega kokku pannud mõni lapstööjõuline ja kui ese kohale jõuab, avastab noor, et talle ei meeldi see. Tema jaoks on nüüd ainus loogiline lahendus visata see prügikasti või natuke paremal juhul viia taaskasutusse.\nMe mõtleme oma tarbimisharjumuste peale alles siis, kui sellest räägitakse suursuguselt meedias. Kõik heietavad, kuidas maailmas ei saa enam mõnesaja aasta pärast elada ja kuidas noorte tarbimine on alla igasugust arvestust. Kuid asi millele nad ei mõtle on see, et selline olukord ei juhtu üleöö.\nMaailm on pikaajalises muutumises, tarbimisharjumused on olnud halvad juba viimased paarkümmend aastat. Need täiskasvanud, kes hoiavad kapinurgast kinni, et mitte ümber kukkuda, kui kuulevad palju asju tegelikult raisatakse ei saa aru, et ka nemad on meie maailmaprobleemide põhjuseks.\nTulevik on meie kätes, kui me selle parandamist päevakohaseks teemaks ei võta, on varsti asjad nii halvad, et ei saagi enam midagi muuta.');
INSERT INTO core.text_property(text_id, property_name, property_value)
