INSERT INTO core.text(id, content)
VALUES ('8d99b336-d744-47bb-ba92-16d607674541',
        'Inimesed ei tea tegelikud kui palju nad maailmale ohtu põhjustavad. Me arvame alati, et natukene ära visatud toitu või hunnik riideid meie kapis ei kahjusta maailma. Kuid tegelikkus on vastupidine.\nInimesed ostavad alati endale palju uusi riideid, aga kunagi ei mõelda kust algab nende teekond ja palju nad maailmale kahju toovad. Mõtleme, et tellime odava raha eest endale armsa väikse koti mingist Hiina veebipoest, aga reaalsus on see, et selle taga on palju kemikaale, mis põhustavad maailmale ohtu. Näiteks Aafrika turgudel on kõrged riide hunnikud, mis on jäänud üle suurtest kallite firmade toodangust, mida keegi nüüd ei osta.\nSuured tegurid on ka suunamudijad, kes saava alatasa firmadelt riided, meiki ja muid tooteid. Inimesed näevad neid, ja tahavad ka, nii tekib ühtelugu uusi asju koju juurde, mida sa võib-olla ainult ühe korra kannad. Olen näinud sotsiaalmeedias inimesi, kes teevad enda aasta eesmärgiks mitte ennem uusi tooteid osta kui vanad on ära kulutatud, mis on mõistlik.\nInimesi võiks rohkem suunata taaskasutuskeskustesse šoppama ja rääkida neile, mis probleeme tekitab liigne riiete tootmine maailmale. See kahju mida inimkond tegelikult Maale teeb on suur ja seda ei saa enam tagasi pöörata, aga me saame harjumuseks tuua mitte nii paljude riiete omamist ja suurtes kogustes toidu ära viskamist.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('8d99b336-d744-47bb-ba92-16d607674541', 'title', 'Inimeste tarbimisharjumused');
