INSERT INTO core.text(id, content)
VALUES ('d5b18830-6bb4-4c52-bfed-f20827185cf1',
        'Igapäevaselt tarbime ja raiskame nii, toitu kui ka riideid, mis on veel kasutuskõlblikud ning me ei mõtle selliste harjumuste tagajärgedele.\nTänapäeval on suureks probleemiks kiirmood. Inimesed tahavad alati uusi ning trendikaid riideid mis oma riidekappi mahutada. Kiirmoodi riided tunduvad nii odavad, kuid need on ka odavalt tehtud, mis tähendab, et nende kasutusiga on lühike. Tihti muutuvad need peale pesemist koledaks, topiliseks või hakkavad niidid lahti tulema. Pärast seda visatakse riided ükskõikselt minema ja mindakse ostma uusi.\nÜks suuremaid lahendusi sellele on taaskasutatud riiete poed. Olen ostnud nii, kiirmoodi ja ka kasutatud riideid. Mulle isiklikult meeldivad taaskasutatud riided rohkem, kuna enamus on kvaliteetsetest materjalidest tehtud. Taaskasutuspoodidest  ostes hoian kokku oma raha ja säästan ka keskkonda.\nTeine suurimaid probleeme on toidu raiskamine. Kõikjal raisatakse toitu: kodudes, kohvikutes, poodides jne. Sellele lahendust leida on raske. Kodudes on sageli külmkappi unustatud või söömisel ülejäänud toidud, mis hiljem visatakse minema, kuna ei teata mida sellega muidu peale hakata.\nKompost on üks levinumaid lahendusi toidu raiskamisele. Sinna saab panna kõik köögiviljad, puuviljad ja muu, mis kompostis laguneb. Komposti lagunemisel muutub see väetiseks, mis saab minna uuele ringile toidu kasvatamisel.\nSamuti saab poest osta ökoloogilist toitu, mis on vähem kahjulik keskkonnale. Keskkonnasõbralikke riideid tehakse taaskasutatud materjalidest milles riided ja kangad saavad uue elu.\nInimeste tarbimisharjumused on nende enda teha, kuid parim oleks, kui me kõik prooviksime taaskasutada riideid ja vähendada toidu raiskamist, nii kaitseme looduskeskkonda.');
INSERT INTO core.text_property(text_id, property_name, property_value)
