INSERT INTO core.text(id, content)
VALUES ('e98d9bee-62c0-40e4-8aec-ad767db997ca',
        'Ühiskond kipub arvama, et me saame kõike muudkui osta, siis ära visata või anda, siis uuesti osta. Mida aga tähele ei panda, on tohutu raiskamine ja mõtlematu käitumine. Me ei pane tähele, kui oluline on targalt ja hoolivalt tarbimine.\nToiduainete raiskamine on aina süübivam probleem kogu maailmas. Toitu visatakse ära meeletul kombel, enamasti, kui see on riknenud, üle jäänud või ei ole enam isu süüa. Iga Eesti inimese kohta tekib aastas keskmiselt 61 kg toidujäätmeid- tarbitoitutargalt.ee/toidukaost/. Inimesed arvavad, et toitu on ülearu, igal pool, terve ülejäänud elu.\nRiidemood on tänapäeval väga teemakajaline pea igas maailma nurgas. Sellepärast ostetakse aina rohkem ja rohkem riideid kappi juurde, isegi, kui riiulid on juba pungil ja midagi juurde ei mahu. Sellele järgnevalt tuleb vanemad riided minema saada.\nToitu raisates teeme nii endale kui ka kogu keskkonnale kahju. Nimelt saagikuse tõstmiseks on vaja igasuguseid kemikaale ja transgeneetilisi taimi. Arvestades, kui palju on Maal elanikke, on jube mõelda, kui palju on vaja sellist tootmist.\nVanad riided viiakse enamus ajast taaskasutuspoodi. Sinna koguneb nii vanu kui ka uusi riideid, mis on täiesti kõlblikud ja ilusad igas aspektis. Tohutu raha ja ressursi raiskamine.\nOlgu see söögi või matejalide raiskamine, tarbimisharjumused ei parane nipsust. Ära osta internetis ahvatlevaid riideid, kui sul on juba kõlblikud olemas. Toitu süües või ära visates, mõtle, kas see on sulle ja ühiskonnale okei käitumine. Inimkond peab võtma ennast kätte, edukeerima end tarbevaldkondades ning õigesti suhtuma. Teeme paremini!');
