INSERT INTO core.text(id, content)
VALUES ('e1738221-9faf-422d-b865-506fe5e00ab6',
        'Tänapäeva inimestel on palju tarbimisharjumustega seotud probleeme, millest tihti ise ka aru ei saada. Nende probleemide esiletoomine on üks esimese ja ka kõige tähtsamaid samme teel puhtamale ja säästliku maailma poole.\nKaasaegsete toitumus harjumused põhinevad paljultki toidu küllusest ja kättesaadavusest. Eesti rahval on paremad kombed toiduga, kuna meie lähiminevik pole olnud kerge. Paljudel inimestel on veel tunne, et enne lauast tõusmist peab taldrik tühi olema. Selline mõtteviis aitab vähendada toidukadu, kuid võib põhjustada kõrvalisi probleeme.\nToidukao koguse mõistmiseks on hea hakkata komposteerima. Iga kord kui jääb sööki üle, mis üldiselt sattuks prügikasti, pane see eraldi ning näha kui palju nädala jooksul raisku läheb. Tuleb ka arvestada, et kui enda hunnik tundub pisike, siis tegelikkuses on sarnaseid koguseid sadu tuhandeid üle Eesti. \nTaaskasutuspoed on väga hea ja soodne viis endale soetada riideid, lisaks toetad keskonda, kui ostad kasutatud riideid uute asemel. Kuid tuleb olla ettevaatlik, seal võib ka peituda palju ebakvaliteetseid tooteid, millel on kahtlane päritolu. Oma enda riiete taaskasutuskeskusesse viimine oleks kindlasti väga positiivne, kui need rõivad ei leia kasutust enda garderoobis.\nToidukadu ja nn fast fashion´iga kaasnevad probleemid on vägagi lahendatavad. Tuleb ainult pöörata tähelepanu ja käituda vastavalt. Söögikorrad tuleks läbi mõtelda ning riiete otsingul on mõistlik pöörduda taaskasutuspoodidesse või osta kvaliteet rõivaid, mis kestaksid ja mida ise kannan.');
