INSERT INTO core.text(id, content)
VALUES ('f9b69f76-9244-42d7-b4dd-bc2aa50733b7',
        'Kindlasti on tänapäeval üks suurimaid probleeme toidu raiskamine ja ebakvaliteetsete riiete ostmine ning kandmine.\nTargad räägivad, et Eesti inimesed raiskavad kogu aasta jooksul kuuskümmend üks kilogrammi toidujäätmeid ning sellest kakskümmend kuus kilogrammi on toit. Riietega on sama probleem, kantakse liiga palju ebakvaliteetseid Hiinas tehtud riideid mitte kodumaiseid. Mina usun, et see kõik on tõsi, aga kas tõesti peaks ostma ainult kodumaiseid riideid. Kodumaised riided on kallid, sest need on käsitööliste tehtud. Paljud inimesed ei saa endale lubada kalleid asju, sest ega raha ei kasva puu otsas.\nToitumisharjumused on paljudel seda viisi, et ostetakse korraga palju toitu ja pärast ei suudeta seda kõike ära tarbida ning toit läheb halvaks. Kes see ikka sööb hallitama läinud toitu, see kõik vistakse kohe ära ja sellest tekibki meie suur toitainete raiskamine. Toitaineid tuleks kasutada otstarblikult, kõik halvaks läinud toit, mida inimese suu vastu ei võta on metsloomadele nagu kingitus, sellepärast peaks pakkuma selliseid toitained jahimeestele, nendele tuleb see omakorda kasuks, et viia see söödaplatsile loomade söödaks.\nKõik väikseks jäänud riided tuleks viia taaskasutuskeskustesse, sest kunagi ei või teada, kellel oleks vaja riideid, sellepärast öeldaksegi, et rikka mehe prügi on vaese varandus.\nTaaskasutamine ja asjadega otstarblikult käitumine on meie planeedile üks tätsamaid asju, kui mitte kõige tähtsam. Riided tuleks osta kvaliteetsed, millega on hea olla igal momendil.');
