INSERT INTO core.text(id, content)
VALUES ('9f874777-a6dd-4a75-a00d-8194b8ce1598',
        'Praeguses maailmas on üha rohkem saamas tavaks ületarbimine. Juba väiksest peale tekivad meil oma soovid mingite asjade järele, mis tunduvad lahedad ja ilusad. Tihtipeale, et enda võsukestele heameelt teha vanemad ostavadki kõik need esemed ära. Selline kulutamine, näitab aga väiksele lapsele, et ületarbine on normaalne, mida see ei ole.\nÜheks mugavuseks on saanud igalepoole autodega minemine, isegi siis kui see on kõigest paarikümne minutiline jalutuskäik. Arvatakse, et väike ots ei tee mingit kahju, kuid realsuse toodab ka see väga palju reostust. Autoga sõitmise asemel võiksime rohkem käia jala või sõita rattaga, mis teeb meie tervisele head, sest kõige selle ületarbimise juures me tervist üle eriti ei tarbi.\nTänapäeval on komme käia palju väljas söömas, samas kui külmkapp on riknevat toitu täis. Põhjenduseks on tihti omaenda laiskus. Hiljem avastatakse, et toit on halvaks läinud ja vistakse minema. Ollakse topelt raha raisanud nii toidu kui ka väljaskäimise peale ning muid ressursse.\nPalju tarbime üle iluvaldkonnas. Arvame tihtipeale, et vajame kõige uuemaid riideid, jalanõusi, kotte ja meigiasju. Tihtilugu jäävad need asjad peale paari kuud kapinurka vedelema ja ostame juurde uusi asju, mis on „moekamad“.\nTarbime üle ka teenuseid, käime igasugustes uudsetes trennides ja töötubades, kui samas saaksime omandada neid oskusi ka kodus ja odavamalt.\nIgaüks peaks endale otsa vaatama ja küsima, kas mul päriselt läheb seda vaja? Meie elu ei keerle ainult lahe ja moekas olemise ümber. Uusi riideid saab osta uuskasutuskeskustest või soetada mõni kvaliteetsem ese. Ülejaavat oitu või riideid võib annetada abivajajatele või olla loominguline ja teha neist midagi uut.\nKõige tähtsam on oma valikud hästi läbi mõelda ja natukenegi ületarbimist vähendada, et maailm saaks olla parem paik.');
