INSERT INTO core.text(id, content)
VALUES ('07461354-f460-45f4-b8aa-6ec53c1cba86',
        'On tõde, et me tarbime kõike liiga palju. Kuhjame loodusele kaela suure koorma, mida on võimatu heastada. Moekunstniku Eve Hansoni uurimuses selgub, et rahvas arvab ei mõjuta sellega suurt pilti. Absurdi tipp! Inimesed peavad oma harjumusi muutma. Miks me nii teeme?\nKodanikel ei koida veel, palju nad tegelikult toitu maha viskavad. Targalt toidu tarbimise uuringutest selgub, et inimese kohta tekib keskmiselt 61 kg tarbimata jäänud söögikraami. Mõelda vaid, palju me eestlastena ühtekokku raha ja ressursse tuulde lennutame. Maa-asunikud ei mõista, et toit saab lõpuks otsa. Toiduvaesed piirkonnad, raskustes pered, kodutud – kõigil on vaja midagi hamba alla. Neid ei aita keegi. Jõukas rahvas kraabib toidu enda juurde kokku, seejärel viskavad selle põõsasse. Kus on mõistus?\nMured ei piirdu selles tarbijate ühiskonnas toiduvaradega, vaid ka rõivatööstuses toimub polundra. Murekoorem tuleneb Hiina suurkaubamajade toodetud nigela kvaliteediga riietest, samuti haiglastest kogustest, mida võileivahinna eest maha müüakse. Ka inimeste emotsiooniostud tekitavad hullumaja, kodanikud kannavad särki vaid ühe korra ja seejärel lendab see prügikasti või uuskasutuskeskusesse. Taaskasutustes on üleküllus, iganädalaselt tekivad ladudesse „pilvepiirini“ ülatuvad hunnikud, mis sisadavad endis uueväärseid ja täiesti korralikke asju.\nPeame hakkama ühiskonnana paremaid otsuseid langetama ning loodust paremini hoidma ja mõistma. Riiete ostmine, söögikraami varumine, teistega arvestamine – seda kõike tuleb teha aruga.');
