INSERT INTO core.text(id, content)
VALUES ('4e30b6fe-d656-4b50-a055-e807b88fee99',
        'Tänapäeval on liiga normaliseeritud ületarbimine ja massilistes kogustes halva kvaliteediga asjade tootmine. Inimesed ostavad kaupu nagu saaks need kohe maakeralt otsa ning raiskavad mõtlematult toitu.\nSelle probleemi parandamiseks läheb kaua aega, aga kui me kõik kasvõi natukenegi rohkem pingutaksime, muutuks pilt paremuse poole. Näiteks kui proovida üks nädal osta ainult toitu ja eluks hädavajalikke tooteid ning jätta kõrvale meelelahutus ja šoppamine, siis aitaks see säästa ressursse ja raha.\nSamuti võib meeletus hulgas asjade omamine olla vaimselt koormav, sest on tunne, et ümber on koguaeg mingi segadus. Tegelikult on ebavajalikest esemetest vabanemiseks vaja hakata lihtsalt enda harjumusi vaikselt muutma, mitte teha järske muudatusi.\nKodumajapidamises tekib iga eesti inimese kohta aastas keskmiselt 61kg toidujäätmeid. Seda on väga palju. Kui iga Eesti kodanik hakkaks näiteks ülejäänud juurviljadest ja kontidest keetma puljongit, selle asemel, et need komposti visata, säästaks see raha ja keskkonda. Tundub väike muutus, aga pikas plaanis väga kasulik, kuna ei peaks enam poest seda ostma.\nKvaliteeti tuleks eelistada kvantiteedile, üks põhitõdesid, mida tuleks peamiselt meeles pidada, kui hakata ostma suurte tööstusriikide toodangut. Pigem oodata natukene kauem ja raha kõrvale panna, sest need esemed peavad vastu pikki aastaid ning on ka keskkonnale palju paremad.\nSelleks, et loodus ja õhk meie ümber veel kaua aega puhtana püsiks, peame me kõik rohkem oma tarbimisharjumusi teadvustama ning seejärel üritada neid parandada. Tuleks osta korraga vähem toitu, kuna seda saab alati juurde. Hoiame keskkonda!');
