INSERT INTO core.text(id, content)
VALUES ('c6bae8f8-a135-46b4-9994-2c0207df8ed7',
        'Inimesed kellel on rohkem raha, tõesti saavad lubada endale rohkem asjade raiskamist, aga pikas perspektiivis võib see mõjutada maailma poole rohkem, kui näiteks kümme keskmise palgaga inimest viskaksid toitu minema.\nKahjuks pean tõdema, et ka mul on veidi selline komme, et ostan endale mingist poest riidied ja käin nendega maksimaalselt kaks korda ning järgmisest päevast alates istuvatki need mul lihtsalt sahtlis. Ma ei saa ka ütelda, et seda juhtub pärast igat ostu, sest mõnikord ma käingi ainult paari särgiga, mis ma olen ostnud ega tahagi endale sellel momendil rohkem riideid.\nLapsed, kes elavad peredes ja saavad suuremates kogustes vanematelt taskuraha, vot nemad võivad olla ühed suurimad raiskajad, sest neil ei pruugi olla nii suurt südametunnistust, et tegelt ikkagi sööks selle jäätise ära ja ei viskaks seda põõsa alla isegi, kui see mulle eriti ei maitsenud. Ma ei taha nüüd öelda seda, et iga laps, kelle vanematel on rohkem sissetulekut peab kohe selline olema. Just nendes peredes peaksid isa ja ema oma lapsi viima kohtadesse, kus kõik pole nii lilleline, et nad näeksid kuidas inimesed iga väikese asja pealt kokkuhoiavad.\nJumalaloomad ostavad üldse jube palju pahna kokku näiteks nahatooteid, juuksepalsameid või muud Hiina kaupa ega kasuta seda rohkem kui ühe korra. Nende tegemiseks võidi kasutada väga suurtes kogustes ressursse ja palju energiat, et mingi lihtsurelik saaks seda lihsalt kuskil kapis hoida.\nMõnikord tuleb enne ostu mõtelda, kas need tooted tegelikult ka sinu majapidamises kasutust leiavad ja kas on ikka vaja proovida seda uut jäätise maitset.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('c6bae8f8-a135-46b4-9994-2c0207df8ed7', 'title', 'Kas ikka peab ostma?');
