INSERT INTO core.text(id, content)
VALUES ('3b18f28e-889d-406c-9f89-ffc005a9347b',
        'Tänapäeval valmistatakse rohkem kaupu, kui tegelikult vaja läheb. See on suur probleem, mitte ainult ressursside raiskamise poolest, vaid ületootmine mõjutab ka meie planeeti. Kraami valmistamisel paiskub atmosfääri väga palju saastavaid gaase, mis tekitavad ka kliimasoojenemist. Meie jaoks on muutunud nii tavapäraseks, et meil on igapäevaselt letid pilgeni asju täis. Kuid nende kaupde tootmisprotsess on liiga pikk ja saastav, et inimene need peale esimest kasutamiskorda ära viskaks. Kahjuks paljud inimesed just nii teevad.\nVäga tihti ostetakse poest rohkem asju, kui neil tegelikult vaja on ja see ei kehti ainult riiete kohta. Iga Eesti inimene viskab ära aastas keskmiselt 61kg toidujäätmeid. Peamine põhjus toidukadu tekkimiseks on see, et jälle osteti liiga palju söögikraami ning seda ei ole jõutud ära tarbida. 61 kg on ikka tohutult palju, arvestades, et siiamaani on maailmas kohti, kust näljahäda ei ole kuhugi kadunud.\nPeale toidu raisatakse ka veel riideid. Tänapäeval enamus taskukohasemaid rõivapoode toodavad kiirmoodi. Kui osta nendest kauplustest riideesemeid siis suurel tõenäolsusel on need ebakvaliteetsed. Tihti on kauplustes ka sooduskampaaniad, mis meelitavad ostma isegi siis, kui tegelikult neid asju ei vajata. Pärast koju jõudes saadakse aru, et on liiale mindud või otsustatakse, et paljud tooted neile ei meeldigi ning üritatakse nendest võimalikult kiiresti lahti saada. Odavate ja kehvasti tehtud hilpude asemel, võiks eelistada kodumaiseid ja korralikke riietusesemeid.\nMaailmas toodetakse rohkem kui jõutakse ära tarbida. Peamiselt raisatakse toiduaineid ja riideid. Igaüks meist peaks oma tarbimisharjumusi parema tuleviku nimel vähendama.');
