INSERT INTO core.text(id, content)
VALUES ('590a71e9-3d1e-47d7-8f25-f92485834c7e',
        'Terves maailmas ostedakse palju tooteid ja kaupu, kuid paljud kas viskavad need ära näiteks toidu või ei kanna neid näiteks riided. Kui me vaid teaks kui palju me tegelikult raiskame oma raha ja teiste ressursse siis me nii palju ei ostaks, aga paljudel meist lihtsalt puudub selline ettekujutus.\nMiks inimesed ostavad nii palju tooteid?\nEsiteks nad tellivad Hiina pooditest odavalt tooteid, mida nad pärast ei pruugi kandagi, sest arvati, et kvaliteet on parem või pole piisavalt mugav. Aga kui sa tellid Hiinast ja see on ka odav, siis mida sa arvad? See ei saagi tulla mingi kvaliteetne toode, kuna nad teevad kõige odavamast materjalist neid tooteid. Neid ei huvita, milline kvaliteet on, nad lihtsalt tahavad, et sa ostaksid seda toodet.\nTeiseks inimesed lähevad liiga palju kaasa sooduskampaaniatega. Vaatavad, et tavahind on jube kallis, aga kui on toote ära ostnud sooduskampaaniaga, siis ei meeldi see toode üldse ning viskavad ära.\nMis saab toodetest, mis ostjale ei meeldi?\nKui tegemist on toiduga siis nad lihtsalt viskavad selle ära, mõeldes, et midagi ei juhtu ja toitu tuleb järjest juurde ning suurt pilti nad sellest ei mõjuta, kuid see on vale! Kodumajapidamises Eestis tekib aastas iga inimese arvelt 61 kg toidujäätmeid, millest toidukadu on 42% ehk 26 kg.\nRääkides riietest siis need viiakse taaskasutuspoodidesse. Mida rohkem inimesed tellivad Hiina veebipoodidest seda rohkem viiakse ka riideid taaskasutuskeskustesse ning lõpuks pole sealgi neile enam ruumi. Et seda probleemi natukenegi vähendada, peame me noored viima taaskasutuspoodidesse, selleks et neil oleks natukenegi aimu, mida see Hiinast telimine kaasa toob. Tegelikult on taaskasutuskeskustes ka väga ilusaid riideid ning need on ka korralikud.\nMe ei saa toidu ja riiete raiskamist parandada üleöö, kuna see on paljuski kinni inimeste harjumustes. Kui me ostame palju tooteid ja ei kasuta neid, vaid viskame ära siis raiskame nii enda raha kui ka teiste ressursse nende tegemiseks. Kõik toidud, mis meil üle jäävad võiks ära anda mitte minema visata ja riided nii samuti viia taaskasutuskeskustesse, selleks et keegi kellele see meeldib ära ostaks ja omatarbeks ära kasutaks või lihtsalt ei ostaks nii palju riideid.');
