INSERT INTO core.text(id, content)
VALUES ('83ceceea-e596-4967-9553-2fb6f2d4119d',
        'Inimesed ostavad endale liigselt asju mida nad tegelikult ei tarbi ja ei vaja.Näiteks: söök,riided,aksessuaarid ja muud allahinnatud tooted. Peale seda kui inimesed on tooted ära ost ja paar korda tarvitanud selgub lõpuks, et enam nad ei vaja neid ja viskavad lihtsalt ära.\nInimesed soetavad endale liigselt asju mis nad pärast ära viskavad, aga sellele on juba raisatud väga palju vahendeid mistõttu väheneb  palju maavara. On ka selliseid inimesi kes kahjuks loobivad oma kasutatud asjad lihtsalt loodusesse, mis on kahjulik nii loomadele kui taimedele \nKõik inimesed raiskavad, kuid seda võiks jääda vähemaks ja inimestele peaks rohkem tutvustama taaskasutuskeskusi kuhu nad saavad oma tooted viia, samas on ka väga palju toiduabi kohti kuhu viia endast järele jäänud kõlbliku toidukraami, sest kindlasti leidub inimesi kes saavad sellest surt kasu. \nInimkond peab hakkama lõpuks aru saama, et ei pea ostma kõike seda mis meeldib vaid tuleb mõelda, kas seda päriselt ka vaja läheb. Inimestel võiks olla rohkem julgust ja tahet viia endast üle jäänud asjad sinna kus keegi kes neid rohkem vajab saaks need endale.Üldse peaks inimestele õpetama rohkem head tegema ja äkki siis saavad inimesed aru sellest, et see mida nemad ei vaja ja ära viskavad võivad olla teisele inimesele väga suure väärtusega.');
