INSERT INTO core.text(id, content)
VALUES ('fa56bdc1-e93f-44ee-b293-20b35396cb09',
        'Minu arust inimesed raiskavad toitu, sest nad saavad seda endale lubada. Neil pole kahju sellest, et nad viskavad aastas keskmiselt 61 kg toidujäätmeid, millest toidukaudu moodustab 42% ehk 26 kg. Seetõttu ei raiska nad ainult raha, vaid ka tohultult muid ressursse: maad, vett, energiat ja tööjõudu. Inimesed ei tea kui palju nad tegelt raiskavad toidu päevas, kuus, nädalas või aastas.\nVäga palju inimesi tellivad süüa koju ja käivad ise poes kas auto, bussi või jala. Viimasel ajal on palju inimesi kes tellivad Hiina veebipoodidest endale asju ja unustavad kodumaiseid üldse ära. Sest inimesed arvavad, et hiina veebipoodidest on odavat ja hea kvaliteet aga tegelikult ei ole.\nMoedisaineri Eve Hansoni arvatest on oluline, et igaüks vaataks üle oma isiklikud tarbimisharjumused ning eelistaks kvaliteeti kvantiteedile. „ Ei telliks Hiina veebipoodidest juba põhimõtte pärast asju, ei läheks kaasa sooduskampaaniatega,“ tõi Hanson välja. „ Eelistada võiks kodumaiseid oma lähedal tootetud asju ning pigem vähem kui rohkem.“\nMinu arust ei ole vaja tellida suurt kogust asju endale Hiina veebipoodidest, kuna seal on suur sooduskampaania, odavat asjad ja jõuab kiirelt kohale. Parem on käia kodumaises kohas endale asju ostmas kui tellida Hiinast.\nInimesed raiskavad aastas väga palju toidu, raha ja tohultult muid ressursse. Nad ei tea kui palju nad tegelt toidu raiskavad päevas, nädalas, kuus ja aastas. See on ikka väga suur kogus ühe inimese kohta. Inimesed raiskavad palju raha ka Hiina veebipoodidest, tellivad asju mida neil tegelt vaja ei ole ja mis paari kuu pärast kusagil prügikastis on või kapis nurkas vedeleb.');
