INSERT INTO core.text(id, content)
VALUES ('aa4b0794-e279-4e92-85c8-939da8262e01',
        'Minu arust on mõndade rikkaste inimeste tarbimisharjumused kõige hullemad. Mõned rikkad inimesed arvavad, et nad võivad teha mida nad tahavd, sest nad on rikkad. Tavainimesed oskavad asju hinnata ja õigesti tarbida. \nMõned rikkad inimesed käivad autoga poes, mis on normaalne aga, kui pood on paari saja meetri kaugusel, siis mõttekam oleks jala minna. Kui sa liigud autoga iga päev poodi ja tagasi, siis sa raiskad bensiini, mis on maavara ja see saab üks kord otsa. Minu arust rikkad inimesed käivad iga väikse asja peale poes. Nad ostavad nädala koguse toidu ette ära, ja kui nad on unustanud poest midagi osta, siis nad lähevad autoga sellele poodi eraldi järele. Autoga on muidugi kiirem ja mugavam minna, aga nad võikisd mõelda, kas neil on hetkel tõesti seda vaja või ei. \nOmast kogemusest võin öelda, et tavainimesed liigu palju vähem autoga, kui pood on paari saja meetri kaugusel, nad lähevad sinna jala, nad isegi ei mõtle selle peale, et nad läheksid auoga. Ma saan aru, kui sa elad maal ja pood on ühe või kahe kilomeetri kaugusel, siis sa muidugi lähevad autoga, see on ilmselge, sa ei hakka mõtlema, kas läheks autoga või jala. Kui nad unustavad midagi poest osta, nad ei lähe selle jaoks eraldi tagasi, vaid lähevad, siis kui nad jälle poodi lähevad. \nEve Hanson ütles, et: ,,Ma näen taaskasutuspoodide laos vabatahtlikuks käies seda rõivaste kogust, mis tekib iganädalasel juurde.’’ Ta räägib veel, et noortele tuleb näidta milline raiskamine see on. Ma olen sellega nõus. Seda tuleks näidata just rikkastele lastle, sest minu arust raiskavad nad kõige rohkem riideid. Mina näen seda asja nii, kui neil läheb mingi särk mustaks, siis nad viskavad selle kohe ära. Kui mõni särk või püksid jäävad väikseks, nad viskavad need kohe ära. Muidugi on ka neid rikkaid, kes ei viska riideid ära. Kui särk määrdub ära siis nad üritavad seda puhtaks saada. Kui särk või püksid jäävad väiseks, siis nad annavad need inimestele, kes neid vajab. \nKokkuvõteks võin öelda, et rikkad inimesed ei osaka oma tarbimisharjumusi muuta või isegi ei ürita seda teha. Tavainimesed oskavd oma arbimisharjumusi tasakaalus hoida.');
