INSERT INTO core.text(id, content)
VALUES ('8843f7e2-d807-4880-8e1a-a0d56674b7ba',
        'Mulle tundub, et üle kogu maailma raisatakse liiga palju. Inimesed ise ei saa aru, et nad raiskavad nii palju ja neile peaks näitama, kui ohtrasi kaotsi läheb. \nTarbitoitutargalt.ee leheküljel on kirjutatud, et Eesti inimene tekitab keskmiselt 61 kg toidujäätmeid ja sellest 42% ehk 26 kg on lihtsalt toidukadu. Toidukaduks nimetatakse seda, mis jääb inimese söögist järgi. Minu pakutav lahendus oleks see, et koolis võiks rääkida rohkem sellest, et lapsed saaksid aru, kui tähtis toit tegelikult on. Aafrika riikides on toidupuudus, aga meie siin raiskame mitukümmend kilogrammi toitu aastas.\nRiideid raisatakse ka väga palju, mis tähendab, et inimene ei tea, kui palju loodusressursse on kasutatud mingisuguse eseme tegemiseks ja mul on kahju sellest. Hanso on öelnud, et noortele peaks hakkama tegema ekskursioone taaskasutuspoodide ladudesse. Mina olen selle väitega väga nõus, sest inimene peaks ostma asju, mis talle tõesti meeldivad ja ka kannaks neid kindlasti. Pole mõtet osta asju, mida kanda ei kavatsetagi, sest see on päriselus palju koledam või materjal ei sobi su nahaga, paremal juhul kantakse ainult mõned korrad ja lõpuks need lihtsalt seisavad kuskil kapi taganurgas. \nKokkuvõtteks tahaksin rõhutada tugevalt sellele, et inimestele võiks rohkem teada anda, kui palju neil jäätmeid tekib, sest nad ise ei pane seda peaaegu üldse tähelegi. Tänapäeva ühiskonnas tarbitakse liiga palju ja selle peaks saama kuidagi kontrolli alla, sest loodusressursse ei jagu meile lõputult.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('8843f7e2-d807-4880-8e1a-a0d56674b7ba', 'title', 'Minu arvamus raiskamisest');
