INSERT INTO core.text(id, content)
VALUES ('f144a47f-8365-4716-93c7-afc073675209',
        'Raiskamine on praeguses maailmas üldiselt suur probleem, kuna ei osata otsustada vajalike ja mittevajalike asjade vahel. Miks on vaja kõiki neid asju, kui me lõpuks ned ära viskame? \nVäiksest lapsest saadik ütles ema mulle, et asju ei tohi osta niisama lõbu või tahtmise pärast. Ma usun, et emal oli selle asja juures ka suurem mõtte. Ma mäletan, kui tulin koju suure poekotiga ning ema küsis, millepärast mul kõiki neid riideid vaja oli ning ma vastasin talle, kuna mulle meeldisid ned poes aga lõpuks ned sattusid ikka kappi nurka ilma, et keegi oleks neid kordagi kandnud. Ma ei osanud asju hinnata. Moedisainer Eve Hanson on avaldanud oma arvamust ka, et noortele peaks näitama, milline raisakmine tegelikuses toimub ja ma nõustun temaga, kuna muidu, kes õpetab meile kuidas on õige asju kasutada.\nAastatega olen õppinud aru saama, et tegelikult on mõttekam käia taaskasutuspoodides, kui tavapoodides, sest sealt leiab ilmtingimata ägedamat kaupa ja see on loodusõbralikum. Kuid ostes peab mõtlema ka toote otstarvele, mitte ainult hinnale. Praegu on levinud hiinakaupade ostmine, kuna seal on odavam osta, kuid tegelt toimub seal lapstööjõu kasutamine ning töölistele miinimum palga maksmine. See on minu arvates kõige halvem osa kogu kaubandustööstusest, kus inimesi koheldakse, kui loomi. \nAsju on vaja iga ühel, kuid peab oskama pidada piiri nende kogustes. Asju peaks oskama kasutada mitte neid lihtsalt ilu pärast ostma, raiskamine sõltub kõigist.');
INSERT INTO core.text_property(text_id, property_name, property_value)
