INSERT INTO core.text(id, content)
VALUES ('41c6e759-ebab-4797-b7e0-ddf7ad6ec765',
        'Inimeste tarbimisharjumused on erinevad. Tarbimisharjumusdega tulenevad kaasa erinevad probleemid, näiteks palju prügi või tühist raiskamist. Kõik muidugi oleneb harjumustest. Ühed inimesed tarbivad asju nii, teised inimesed aga teisiti. Üks on kindel, iga inimene tekitab prügi oma tarbimisega. Mina muidugi arvan, et raiskamise oleneb kõige rohkem inimese enda otsustest ja valikudest.\nSee on kindel, et ükskõik kuidas asju tarbitakse, tekib alati mingisugune prügi. Liigsete asjade ostmisel, mida ei suudeta ära tarbida tekib rohkem prügi. Mina arvan, et mida mõistlikumalt tarbida asju, seda vähem tekib rämpsu ja prügi. See aga on meile kõigile parem ja kasulikum loodusele.\nAlati öeldakse, et tarbi targalt. Mida targemalt tarbid, seda kasulikum sulle. Näiteks poest ostes süüa saab palju asjusid külmas hoida, et neid kauem säilitada. Seda kauem püsib toit ise ja jõutakse ära kasutada mitme päeva jooksul. See on hea lahendus, sest siis ei pea nii tihedalt poes käima. Mina olen väga selle mõtte poolt, et käia poes vähe ja tarbida asju targalt.\nMõistlik on ka hinnata enda tarbimisharjumusi. Vahepeal hinnatakse kalli kvalideeti tarbimist, kui saaks ka odavama hinnaga hakkama. Palju tarbitakse kalli hinnaga riideid mis on moes. Kuigi odavamalt saaks riideid osta taaskasutuskaupadest ja tarbida asju mis on üle jäänud ja see ongi targalt tarbimine. Isegi Eve Hanson on öelnud, et ei telliks Hiina veebipoodidest juba põhimõtte pärast asju ning eelistada võiks kodumaised oma lähedal toodetuid asju. Olen igatipidi selle poolt, mina isegi käin tihti taaskasutuspoodides ja tean, et see on mõistlik.\nInimestel ongi erinevad tarbimisharjumused, sest kõik inimesed ongi erinevad. Iga inimene mõtleb omamoodi tarbimisele ja raiskamisele. Alati saab midagi paremaks muuta enda asjade tarbimises või raiskamises, aga siis peab inimene seda tahtma. Mida vähem raisatakse, seda vähe prügi ning tark tarbimine. See toob alati kasu endale meie maailmale.');
