INSERT INTO core.text(id, content)
VALUES ('bdeef1fd-6ba0-4e4e-a1c2-0bae686275cd',
        'Tänapäeval raiskavad inimesed rohkem ressursse, kui nad arvavad. Tarbitakse ja ostetakse asju, mida tegelikult ei lähe vaja. Kõige enam raisatakse toitu ja riideid.\nEva Hanson on öelnud, et  peaks hakkama noortele tegema ekskursioone taaskasutuspoodide lattu, et näidata, milline raiskamine tegelikult toimub. Minule see mõte meeldib. Taaskasutuspoodide laod on täidetud esemetega, mida inimesed on ostnud mõeldes, et tal läheb seda kindlasti vaja, kuid pärast proovib sellest lahti saada. Kui näitaks õpilastele, millises koguses raisatakse esemeid, aitakse see neil kergemini mõista probleemi.\nMina arvan, et veebipoodide eesmärk on mõjutada inimesi. Nad panevad hinnad hästi madalaks, et inimene pööraks sellele tähelepanu. Kellele ei meeldiks madalad hinnad? Eriti tuntud on selles kategoorias Hiina veebipoed, kust leitakse kõik vajalikud asjad sootsate hindadega. Inimesed on hämmastunud ja ostavad kohe ära. See ei panegi neid mõtlema, et miks on hinnad nii madalad? Kas ma üldse vajan seda? Pärast ese ei vasta ootustele ja läheb ära viskamisele. Ma ise olen ostnud Hiina veebipoodidest esemeid, mis minuni jõudes olid juba praagid.\nInimeste harjumusi ei saa muuta paari päevaga. Minu jaoks on harjumuste muutmine väga pikk protsess. Ma ei saa järgmine päev minna üle rangetele reeglitele, sest siis annaksin ma alla peale esimest päeva. Reegleid peaks lisama iga kord, kui tunnen, et olen hakkama saanud eelmiste täitmisega.\nTänapäeval on ressursside raiskamine väga aktuaalne teema. Ostetakse asju, mida tegelikult pole vaja ega tarvis. Raiskamist saaks vähendada reeglitega, aga seda ei tohiks alustada liiga rangelt.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('bdeef1fd-6ba0-4e4e-a1c2-0bae686275cd', 'title', 'Inimeste harjumused viivad ressursside raiskamiseni');
