INSERT INTO core.text(id, content)
VALUES ('a253cd78-d7d3-47bd-90bb-03fc0fd4c854',
        'Inimeste terbimis harjumused on erinevad. Mõned inimesed tarbivad rohgem ja teised vähem aga üks asi on kindel iga inimene tarbib midagi.\nKui jutt tuleb inimeste tarbimisele siis seeb seda vorelta erinevalt näiteks: rahaliselt, kogustena, protsendina, jne. Võreldes mind ja mingit oma sõpra näiteks Karlis siis rahalisest poolest tarbin mna rohkem, koguste poolelt tarbib Karlis ja protsentidest ma ei tea.\nKui me tarbime midagi siis ie tohiks see olla midagi Hiina poest, kus on igasugust sootsad kraami, mis läheb kiirelt katki või laguneb ära peale esimest kasutamist. Eve Hanson arvates on oluline, et igaüks vaataks üle oma isiklikud tarbimisharjumused ning eelistaks kvaliteeti kvantiteedile.\nTarbimise alla läheb veel toit ja selle jäägid. Inimeset ei tohiks imestada, et kellelgi on toitu jääke kodus kuna see on normaalne, et toiturt jäävad jäägid maha või aegunud toit. Kodumajapidamises tekib igal Eesti inimese kohta aastas keskmiselt 61 kg toidujääkmeid, millest toidukadu moodustab 42% ehk 26 kg. Minu toitumis harjumus pole väga suur, kui mõtlen selle peale. Minu toidu plaan on selline, et hommikul harva ja kui ma söön hommikul siis söön banaani või saija. Lõunal söön kooli toitu. Õhtul söön toitu mis isa tegi.\nKokku võteks tahaksin õelda, et inimeset võiks vähem tarbida kuna siis oleks vähem reostust ja oleks puhtam lootus.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('a253cd78-d7d3-47bd-90bb-03fc0fd4c854', 'title', 'Inimeste tarbimis harjumused');
