INSERT INTO core.text(id, content)
VALUES ('881273c1-195c-4449-934d-32a084d1752e',
        'Tänapäeva inimestena oleme harjunud sellega, et kõik vajalik on kättesaadav. Tihti ei hinda me, kui palju on meil vedanud, et saame kõike seda endale lubada. Just sellepärast raiskamegi oma raha sellele mida meil päriselt vaja pole.\nÜks asi mida me ilmselt kõige rohkem raiskame on toit. Kõik inimesed viskavad vahel toitu ära, tavaliselt sellepärast, et see on halvaks läinud. See on arusaadav aeg-ajalt ikka unustame midagi ära kasutada. Võibolla poleks see nii suur probleem, kui paar protsenti toidust läheks raisku, aga veebilehelt tarbitoitutargalt.ee saame teada, et iga Eesti inimese kohta tekib aastas keskmiselt 61 kg toidujäätmeid, millest 42% on toidukadu.\nSee kõik on selle pärast, et ostame rohkem, kui vajame. Ainus võimalus vähendada toiduraiskamist on osta vähem. Kõige lihtsam viis seda teha on ette planeerida. Kui otsustad ette mida soovid süüa ja teed ostunimekirja, ei lahku sa poest asjadega mida ei vaja.\nPeale toidu, raiskame ka oma raha igasugu mõttetute vidinate peale. Näeme poes midagi huvitavat ja mõtleme: „Ohhoo, kui odav! See tuleb kindlasti kunagi kasuks.“ Tavaliselt aga jääb see asi igaveseks kuskile riiuli vahele tolmu koguma.\nMoedisaineri Eva Hanseni arvates on oluline, et igaüks vaataks üle oma isiklikud tarbimisharjumused ning eelistaks kvaliteeti kvantiteedile. Kui tihti ostame me kuskilt Temust või mingist teisest Hiina veebipoest millegi, mis läheb juba paari kasutusega rikki. See ongi lihtsalt raha raiskamine ning palju mõistlikum oleks osta midagi kallimat, aga seejuures kauakestvamat.\nMe elame ühiskonnas, kus ületarbimine on tavalisus. Raiskame oma raha asjadele mida me tegelikult ei vaja ning mis lähvad lihtsalt raisku. Ainus viis liigtarbimist vähendada ongi osta ainult seda mida vajad ja tegelikult kasutad.');
INSERT INTO core.text_property(text_id, property_name, property_value)
