INSERT INTO core.text(id, content)
VALUES ('d9c5429d-6eab-46d8-81b0-f23752c32b28',
        'Ma arvan, et maailmas raisatakse väga palju asju. Inimeste tabimisharjumused on erinevad mõned inimesed tabivad vähem ja mõned rohkem.\nKuid paljud inimesed ise ei saa arugi kui palju nad tarbivad ja asju raiskavad, mõned inimesed saavad omale rohkem asju lubada, ning mõned vähem, kuna selline see elu ongi.\nKodumajapidamises tekib iga Eesti inimese kohta aastas kesmiselt 61 kg toidujäätmeid mis on päris palju, ning millest toidukadu moodustab 42% ehk 26 kg. Enamasti viskavad inimsesed toitu ära, siis kui see on läinud halvaks, söömisel on toit ülejäänud, riknenud vms.\nToidukaduks nimetatakse seda mis jääb inimeste söögist järgi.Minu lahendus oleks selline, et lapsed hakkaksid aru saama kui tähtis tegelikult toit on, kuna nad raiskavad seda palju kui nt Aafrika riikides on inimesed näljas ja toidu puuduses ja meie Eestis raiskame niimoodi toitu see on jube.\nMoedisainer Eva Hanson on räägib, et peaks noortele tegema ekskursiooni taaskasutuspoodide lattu. Minu see mõte meedlib kuna, siis lõpuks noored inimesed näeksid kui oluline toit tegelikult on ja kui palju seda raisatakse iga päavselt .\nMa arvan ka, et veebipoodide eemärk on mõjutada inimesi ja noorukeid odavate hindadega. Tehakse ka pilte mis internetis näevad välja head ja tutikad kuid kui päriselt selle rõiva või toote kätte saad, siis on see täiesti teistsugune kui pildil.\nMa soovikski oma arutlusega öelda inimestele ja lastele, et nad muudaksid oma tarbimisharjumusi, ning ei raiskaks nii palju toitu ja rõivaid.');
