INSERT INTO core.text(id, content)
VALUES ('f36f1fe7-ed5a-44b2-a084-9146a50aa18e',
        'Maailmas on suur probleem, et inimesed raiskavad maailma ressurse. Toitu raisatakse ka Eestis üpris suurtes kogustes ehk pea 61 kg toidujäätmeid aastas. Eelistatakse kiirmoe ja hiina kaupa, mis kõlbab kanda vaid paaril korral.\nKõik algab siiski kodusest kasvatusest. Paljuski mõjutab meie harjumus käitumist meie vanemate käitumine ja see, kuidas meie lapsepõlves on meid kasvatatud. Kui pere on harjunud valmistama kuue inimese söögikoguse ja ise söövad nad ära ainult kolme inimese koguse. Sellist olukorda on ka meie peres olnud, kuid hea viis kuidas toitu säästa on jaotada toit karpidesse ja ongi järgmiseks lõunaks või õhtu söögiks ka toit olemas. Nii säästame me aega ja ei lähe ka toit raisku. \nPaljud noored on hakanud eelistama kiirmoe ja hiina kaupadele taaskasutust. Minu arvates on see väga hea harjumus. Tänu sellele anname me riietele uue võimaluse ja ei telli kuskilt kaugelt endale riideid, mis võivad muutuda kandmis kõlbmatuks juba paari kandmis korraga. Taaskasutuses ei saa sa alati just täpselt sellist eset, nagu soovisid kuid sealt võib leida mõnikord isegi palju huvitavama ja ilusama eseme kui alguses oli plaanis kiirmoest osta. \nTänapäeva noored on üpris teadlikud tarbimisest ja, kuidas seda vähendada. Meie teadlikust tõstetakse igapäevaselt koolis ja ka sotsiaalmeedias reklaamitakse kasutama kodumaist toodanut või teise ringi asju. Mina olen sotsiaalmeediast leidnud väga palju erinevaid nippe ja soovitusi, kuidas säästa toitu ja kuidas olla teadlikum tarbija.\nMeie peres teen tihti süüa mina. Mulle meeldib tihti teha koguste poolest väga täpselt süüa ehk kungi ei jäe midagi üle, ega ka ei tule puudu. Kahjuks, aga on minu ema ei oska välja arvestada, kui palju võiks süüa vaja minna. Ma olen talle palju õpetanud, koguste arvestamist ja toidu säästmist. Mulle meeldib toitu paarils päevaks ette teha. Nii saan säästa aega ja vältida toidu ülejääke. Kui toidujääke siiski tekkib, siis need lähevad loomadele toiduks. Meie vanaemal on kanad, kes meelsasti kõik jäägid ära söövad.\nNoortel sõltub enamasti valik hinnast. Põhjuseks on enamasti see, et noored alles õpivad ja ei teeni veel endale ise raha. Kõige odavamalt saab kauba kätte Hiinast, kuid see ei ole ültse jätkusuutlik kuna väga palju ressursse raisatakse juba kauba transpordile. Enamasti Aasia riikidest tulev kaup on kergesti purunev ja ei ole just alati väga praktiline. Kuikasutame kodumaist toodangut toetame oma riigi majandust ja arvatavasti saame ka kvaliteetsema toote kui see oleks olnud tellides Hiinast. Minu arvates on mõistliku teha ühekordne investeering mingisse kvaliteetsesse tootesse kui see, et tellida seda korduvalt uuesti.\nMinu arvates on noorte teadlikus tarbimisest üsnagi tugev ja tuleks rohkem hakkata teadlikustama meile eelnevaid põlvi. Noored teavad, miks on vaja toitu säästa ja eelistavad taaskasutust kiirmoele ja hiinast tulevale kaubale.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('f36f1fe7-ed5a-44b2-a084-9146a50aa18e', 'title', 'Noorte teadlikus tarbimisest');
