INSERT INTO core.text(id, content)
VALUES ('b0bca24f-d983-47de-8a25-76882bf215da',
        'Tänapäeva maailm on arenenud nii kaugele, et enamusel inimestest on kõik kättesaadav, kas initernetis kliki või linnades autosõidu kaugusel. Internetis ringleb ka igasuguseid sooduskampaaniaid. Need võivad ahvatleda inimesi tegema oste mõeldes kvantiteedile, kvaliteei asemel.\nAsjade kerge kättesaadavus võib tekitada olukordi, kus inimesed ei mõtle oma oste selgelt läbi. Kas ost on päriselt vajalik või tundub see lihtsalt ilus, odav ja vaid paari kliki kaugusel. Pea igal inimesel on kodus olemas internet, kus söödetakse ette reklaame asjadest, mille ostmist võidakse olnud varem kaalutud. Nüüd on sellel aga sooduskampaania,  mis väidetavalt lõpeb juba tänä õhtul. Sellised eklaamid panevad inimese peale rõhu ning ta teebki pikemalt mõtlemata selle ostu ära.\nNeed samad sooduskampaaniad ja Hiina veebipoed ahvatlevad inimest mõtlema pigem kvantiteedile kui kvaliteedile. Neis poodides saab ühe kvaliteetse asja hinna eest rohkem asju, mille kvaliteed pole kuidagi võrreldav. Tänapäeva inimesed ongi hakanud just selle mõttele rõhuma. Ka Vikerraadio interjuus moedisaineri Eve Hansoniga rääkis ta, kuidas taaskasutuspoodide lattu tekib iganädalaselt meeletu hunnik Hiinas toodetud asju, mille kvaliteet pole just kõige parem. \nTänapaeva inimeste ületarbimis probleemi põhjusteks pakuksingi mina välja toodete kerge kättesaadavuse, sooduskampaaniad ja praeguse maailma olukorra Hiina kauplustega, kus rõhutkse kvaliteedi asemel kvantiteedile. Neile kõigile on leitud ka lahendusi, mille rakendamine võtab aga aega, kuna inimesed kipuvad oma harjumustesse kergesi kinni jääma.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('b0bca24f-d983-47de-8a25-76882bf215da', 'title', 'Mis põhjustab tänapäeval ületarbivust?');
