INSERT INTO core.text(id, content)
VALUES ('b530e32f-6c72-4cc6-9e9c-b52891344a3a',
        'Peaaegu kogu maailma nimetataksin mina tarbimisühiskonnaks. Sellist tüüpi ühiskonnaga kaasneb suur probleem: Ületarbimine. Mina arvan, et sellele suurele probleemile on väga kerge lahendus. \nMeie planeet kannatab ületarbimise all. Ületarbimine tähendab, et inimene ostab omale rokem asju kui ta suudab ära tarbida. Toidu ületarbimine on selle juures suur osa. Olen kuulnud, et inimesed arvavad, et toidu ära viskamine ei ole probleem, sest seda tehakse alati juurde, aga selles probleem seisnebki – Toitu hakatakse ületootma ja et toitu toota läheb vaja meeletut ressurssi. Traktorid paiskavad õhku süsihappegaasi ja farmerid hävitavad metsi uue põllumaa jaoks. \nTänapäeval pannakse väga suurt rõhku taaskasutamisele, see tähendab, et inimesi suunatakse oma vanu esemeid viima ringlusesse. Eve Hanson arvab, et inimesed peaksid oma tarbimisharjumusi parandama. Pean temaga nõustuma, see on üks esimesi asju, mida tuleks teha, et jõuda n-ö rohelise planeedini. Muidugi on ka probleemiks inimeste teadmatus, nt ei tea vanemad inimesed, et prügi põletamine või sisepõlemismootoriga autoga sõitmine on keskkonnale väga kahjulik.\nKui ei tarbime mõõdukalt, siis toodetakse ka mõõdukalt. Ületarbimine on väga suur probleem ja, et seda lahendada tuleb alustada iseendast. Nt ei käi autoga tööl vaid sõidan bussi või ronginga ja ostan poest kvaliteetseid riideid selle asemel, et tellin hiinast odavaid naftast toodetud riideid.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('b530e32f-6c72-4cc6-9e9c-b52891344a3a', 'title', 'Edukas ületarbimine');
