INSERT INTO core.text(id, content)
VALUES ('7ab2cdf8-af3d-40eb-b6e9-47557b15bf46',
        'Inimesed toitu iga päevaselt. Toitu raisatakse arusaamata, et see saab meil ka üks päev otsa. Toitu raisates ei mõelda sellele, et kui suurd resursid selle toidu tootmise alla läinud on.\nToidu riknemine on saanud maailmas suureks probleemiks. Igapäevaselt visatakse prügikasti suurtes kogustes toitu. Uuringutes on välja toodud, et igas aastas viskab üks inimene prügikasti ligikaudu 61KG toitu millest  26KG on kas riknenud või lihtsalt üle jäänud toit. Kui mõtleksime poes läbi, et mida ja mis kogustes meil vaja on oleks toidu äraviskamise ja riknemise protsent palju väiksem. Inimesed ostavad pidevalt poest suuremates kogustes toitu kui nad ära tarvitavad ja nii see toit rikneb ning see visatakse lihtsalt ära. \nToidu tootmisele kuluvad suued resursid. toidu tootmiseks on vaja suuri põlde kus kasvatada kas köögivilju või loomadele sööta. Toidu kasvatamiseks on vaja ka puhast vett mida hakkab maalt aina vähemaks jääma. Toidu tootmisega saavad aga paljud inimesed töö ja ettevõtted tulu. Lisaks läheb toidu tootmisele suur energia ehk masinatele on vaja kütuseid. \nKui mõtleksime rohkem läbi mida me poest ostame ja mis kogustes meil toiduaineid vaja oleks siis raiskaksime toitu palju vähem. Toidutootmis resurside pealt saaksime kokku hoida, meil oleks rohkem vett mida juua ja põllumaadele saaksime rajada midagi muud.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('7ab2cdf8-af3d-40eb-b6e9-47557b15bf46', 'title', 'Toiduraiskamine');
