INSERT INTO core.text(id, content)
VALUES ('97a1f017-6d3e-494d-9206-5f87951393b6',
        'Tarbimisharjumuste tekkimine on üks suurtematest probleemidest, mis takistab meie maaima puhtalt töötamast. Inimesed viskavad ära toitu, riideid ja igasuguseid teisi aineid ja materjale, arvates, et teised tegelevad nende sorteerimise või taaskasutamisega. Selline mõtteviis võib olla kõigil. Järelikult ongi probleemiks see, kui vähe inimesi tegelevad nende harjumuste lahti saamisega.\nSuureks harjumuseks üle maailma on kujunenud riiete hulgaline tellimine, mõtlemata selle peale, kas sa üldse kannaks kõiki neid asju. Mis muudab selle halvemaks on see, et tellitakse Hiina veebipoodidest, kus lapsed töötavad mitu tundi päevas vähem kui miinimum palga eest. Parim viis sellise kombe parandamiseks on sügavalt mõtlemine: mõtle, kas sul on vaja viite samasugust särki, mis on erinevat värvi või kuute paari erineva lõikega teksapükse. Nagu Eve Hanson ütles, on oluline panna esiplaanile kvaliteet, mitte kvantiteet. Kõik riided, mis sul telltust kandmata jäid, ei ole mõtet visata prügikasti. Anna need edasi sõbrale või anneta taaskasutuspoodi, et vältida kõikide nende ressursside raiskamist, mida kasutati nende riiete tegemisel.\nTeiseks suuremaks ja kindlasti popuaarsemaks harjumuseks on toidu raiskamine. Nii lihtne on meil toitu ära visata ja suurtes kogustes uuesti osta. Siin tuleb jälle mängu oma enda peale mõtlemine, näiteks : kas oled kindel, et jõuad kõik selle ostetud kraami ära süüa ennem, kui tähtaeg läbi saab. Kas sul on üldse vaja nii palju asju kappi, kui juhtud üksinda elama? Selliste asjade peale tulemine on väga tähtis, kui tahame lõpetada söögikraami ja ka oma raha kulutamist. Ja kui jääbki toitu üle, siis saame kuhja anda enda või naabrite loomadele, maal elades on see eriti lihtne. Linnas on targem mõtiskleda või isegi teha plaan oma nädalase toidu tarbimise suhtes. \nJäreldus on see, et me kõik oleme kunagi midagi raisku lasknud ja seda ei olegi nii lihtne parandada. Paljudel inimestel läheb aastaid enne, kui suudavad oma tavast lahti saada.  Ainus asi, mida sa teha saad, on korralikult mõelda tuleviku peale. Kaalu oma valikuid ja tee õige otsus, sest selline eluviis on meie kõigi jaoks parem.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('97a1f017-6d3e-494d-9206-5f87951393b6', 'title', 'Tarbimisharjumused ja kuidas nendest lahti saada');
