INSERT INTO core.text(id, content)
VALUES ('9011b495-a1bd-44d1-80ad-451561ae7e52',
        'ma näen, et inimesed raiskavad  väga palju toitu ja viskavad selle lihtsalt prügikasti ja komposti kui see on pahaks  või hapuks läinud . See on väga halb asi mida tehakse niimodi  võib seda väga palju saada kui seda väga palju toodetakse ja pannakse plast karpitesse ja hiljem visatakse loodusesse.\nInimesed peavad ise toidu kasvatama ,minu perel on oma aed kus kasvatame ise puu ja juurvilju, marju .Sügisel teeme talveks hoidiseid ja kasutame klaas purke iga aasta keedame vaarikatest ja õuntest moosi, ja teeme kõrvitsasalatit mis on mu lemmik       korjame seeni ja kuppatame neid,paneme need purkidesse. Inimesed peavad vähem loodust rostama jkasutama looduses kõdunevatest asjatest purke, karpe  näiteks puidust  pambusest need on looduses kõdunevad  ja lagunevad kenasti looduses ja ei reosta loodust  ja hoiame loodust puhtana ja korras.\nInimesed peavad kasutama mis kõduneb looduses ega reosta seda ja pambus jäägid tuleb ära põletada.  Puidust karbid on looduses kõdunevad ja neid on üks loodusvaradest.');
