INSERT INTO core.text(id, content)
VALUES ('0d9c9f18-d993-408c-bd5f-e85ebd1c7334',
        'Inimesed meie kodumaal ei tea kui palju nad raiskavad toitu. Kõik inimesed teevad seda samamoodi.\nIgapäevaselt me sööme ja joome, aga kus me saame seda sööki otseloomulikult poest. Paljud kasvatavad muidugi ise endale toitu. Rahvas kes kasvatab ise toitu ta ju ei soovi seda ära visata, aga kui ostad poest siis sul ei ole vahet kui see prügikastis lõpetab. Inimesed ostavad kodudesse endale liiga palju toitu. Nad ei tarbi seda kõike ära ja pool sellest läheb prügikasti. Inimesed kes on rikkad jah neil ei ole vahet kas see läheb prügikasti, aga nad kunagi ei mõtle sellele mida nad selle toidu viskamisega meie oma kodumaale teevad ja mida nad tegelikult reostavad. Inimesed kes on vaesemad nad ostavadki poest endale sellise koguse toitu, et nad söövad selle ära ja see ei lähe neil prügikasti. Me teame, et paljudel ongi sellised harjumused ostavad palju toitu ja pärast viskavad ära aga mis on selle mõte on me keegi ei mõista seda. Inimesed ei mõtle kunagi kuidas see toit sinna poodi tuli ja kuidas see kauba letile sai nad ei tea,  et kõik see teiste inimeste töö läheb lihtsalt pügikasti ja jääb tarbimata.\nKokkuvõtteks võin öelda , et paljud inimesed viskavad igapäevaselt hulgi koguses toitu ära ja nad ei tea kui palju nad sellega reostavad.');
