INSERT INTO core.text(id, content)
VALUES ('d668d4ce-5d35-45f3-b382-0b9e57009ebf',
        'Inimsed arvavad, et toitu on piisavalt ja ei saa otsa. Inimestele meeldib väga toitu raisata.\nInemstele meeldib koguaeg teha ja süüa toitu suures koguses. Me koguaeg raiskame enda raha ja toitu igapäevaselt. Iga nädal inimsed raiskavad paar kilogrammi toitu. Mõnedele isegi meeldib veel rohekem süüa ja raiskavad plaju raha selle peale. Toidu raiskamisest me veel raiskame ka maad, vett ja veel energiat selle tegemiseks. Näiteks ka vanematele inimestele meeldib plaju toitu poest osta ja sellest süüa teha ja enamus ära visata sest nad ei söö nii palju kui mõned muud inimesed. Ka veel rikastele meeldib söögi peale raha raisata, sest nendel on nii palju raha ei huvita kui raiskavad raha söögi peale. Mõned rikkad ei tea ka kus see toit võib tulla ja kuidas tehakse. Toidu peale raiskamine võib tekitada muid probleeme näiteks vaestele kes eriti toitu ise poest ei saa osta ja peaved lahendusi leidma. Parem oleks kui ise saaks näiteks taimi ja loomi kasvatada. Kui me igapäevaselt raiskame raha toidu peale ja viskame ära, siis võiks näiteks mõned liigsed jääkmed anda loomadele söögiks. Söögi tegemise peale läheb tänapäeval päris palju raha ja soovitaks teha iga nädal panna kuskile kirja mida söögiks teha ja kui palju kulutada selle peale. Ja veel mõelda kui suurt kogust osta korraga ja mitte raisata nii palju raha.');
