INSERT INTO core.text(id, content)
VALUES ('5395afaf-3c9a-4c06-b39a-8d1377e3baf7',
        'Miks inimesed viskavad ära palju toitu või miks nad ültse midagi ära viskavad? Miks nad raiskavad raha?                     \n           Poodi minnes ostavad inimesed tavaliselt seda mida vaja või seda mida tahavad. Võibolla ostetakse ka allahinnatuid toodeid hoolimata sellest kas nad seda päriselt ka tarbivad. Nad lihtsalt näevad, et see on allahinnadud ehk odavam ja neil on seda, siis järsku vaja. Võimalik, et paljud ei vaata isegi säilivus kuupäevi toiduainetel ja lihtsalt ostavad selle, sest kollane hinnalipik toiduainetel on nii ahvatlev. Paari päeva pärast avastavad, et ostetud toit on kuupäeva järgi vana ning inimesed lihtsalt viskavad selle toote ära. Kuid nüüd tasuks meelde tuletada, et poes müüdavad toodet on kahe säilivus märgisega. Selle all mõtlen ma kahte tundud lauset: parim enne ja kõlblik kuni aga, mis on nende kahe lause vahe? Parim enne tähendab , et müüdav toode on märkitud kuupäevani oma parimas vormis ja maitsega, peale selle kuuupäeva ületamist on toode ikka veel söödav, kuid mitte kõige parem või värskem. Kõlblik kuni tähendab, et müüdav toode on kõlblik kuni selle kuupäevani mis on märgitud tootele peale. Kindlasti on mõlemas välja toodud väites ka erandeid. Inimesed ei saa neist kahest lihtsast asjast aru.                                                                               Nüüd jõuame raha juurde.Raha on hea asi, kui seda saab aga liiga palju on inimestel kohe vaja seda kulutada üks võimalus selleks on näiteks pood. Nii öelda üleliigne raha on kindlasti hea kulutamiseks poes, saad osta neid toodeid mida igapäev ei osta, ostad rohkem ja kallimaid toodeid, kui sul tegelikult vaja ja sa üldse tarbida suudad.                                                                                                                                         Järelduseks võib öelda, et inimesed ei ole toidu osas teatlikud ja raiskavad raha täiesti mõttetult. Sõnaotseses mõttes nad viskavad omaenda raha lihtsalt prügikasti ilma, et nad sellele ültse mõttlevad.Tahan siin kohal veel öelda, et eelnevalt tekstis välja toodud väited ja seletus on lihtsalt minu arvamus.');
