INSERT INTO core.text(id, content)
VALUES ('1ecf3807-4b13-45e8-97d8-8b2a80f72451',
        'Aastaid on olnud probleem see, kuidas inimesed toitu, riideid ja muid asju tarbivad. Inimesed ostlevad aina rohkem internetipoodides, ostes Hiinast palju asju. Eriti toitlustamisasutustes toimub hull toidu raiskamine. Kui hull see asi siis tegelikult on?\nToitlustamisvaldkonnas on alati olnud küsimus, et kuhu kõik jäägid pannakse. Enamus jagatakse laiali talunikele, kes omavad loomi, et kõik jäägid loomadele toita. Kõik muu, mis puhtalt alles jääb, saavad toitlustajad endale koju võtta. Kahjuks on siiski ka halvem pool. Tavakodanikud ei oma selliseid privileege ja enamus toit, mis üle jääb, visatakse lihtsalt komposti. Tegemist on täieliku toidu raiskamisega, sest selle asemel, et sellest toidust midagi uut valmistada, visatakse see ära, sest tänapäeval tahavad inimesed rohkem uuemaid asju ning vana jäetakse kõrvale.\nRiided on inimestele väga kallid. Nendega saab end väljendada ja see annab ka teistele väikese vaate, milline sinu iseloom on. Kahjuks on ka neid inimesi, kes ei saa nendest küllalt, käivad igapäevaselt uusi riideid soetamas või ostlevad netis ja tellivad uusi rõivaid Hiinast. Hiinast tellides kasutatakse lapstööjõudu, mittelagunevaid materjale nt nafta ja muid tegureid, mis ei ole loodussäästlikud. Taaskasutuskeskused upuvad riietest, mis on ainult ühe korra kantud. Inimesed peaksid rohkem mõtlema sellele, kuhu see kogus riideid pannakse ja ostlema rohkem kohtades, mis ei müü ainult tuttuusi riideid.\nKokkuvõttes peaksid inimesed mõtlema rohkem taaskasutamisele. Toitu saab taaskasutada, kui mõelda, mida vägevat saaks keegi teha oma eilsetest kartulitest, mis üle jäid. Samuti saavad inimesed endale mittesobilikke riideid teistele jagada ja uurida alati enne, kust see toode tegelikult tulnud on, et mitte ära kasutada lapsi ja ka säästa loodust.');
