INSERT INTO core.text(id, content)
VALUES ('46d88fa2-38fb-4bf1-93c0-ac87fb327642',
        'Väga suureks probleemiks on raiskamine. Raisatakse nii toitu, riideid kui ka muud. Inimesed on harjunud viskama ära asju, mis on vanad, koledad, ebamugavad, toite, mis on halvaks läinud, ei jaksa ära süüa või ei maitse, mõtlemata mida see teeb keskkonnale.\nToitu on lihtne ära visata, kuid raske või peaaegu isegi võimatu taaskasutada. Iga Eesti inimese kohta raisatakse aastas ligikaudu 61 kilogrammi toidujäätmeid. Toidu raiskamise vältimiseks, tuleks enne toidu ostmist ja tegemist mõelda, kas ja kui palju on toitu vaja. Mõnel inimesel on kodus koer või kanad kellele saab anda ülejääke ilma,et need raisku läheksid. Samuti Ameerikas või Aafrikas elavad kodutud inimesed, kellele saab anda näiteks soojast toidust ülejäänud toitu. \nRiideid kantakse palju ja neid ostetakse palju. Inimesed võiksid vaadata üle oma tarbimisharjumused, eelistada kvaliteeti ning mitte minna kaasa Hiina soodsate veebipoodide ja sooduskampaaniatega. Riiete puhul on hea, et neid saab lihtsalt taaskasutada. Kui see riideese sulle enam ei sobi, jäi väikseks, tellisid vale suuruse või lihtsalt ei leia kasutust, saab neid taaskasutada. Taaskasutada saab neid viies taaskasutuspoodidesse, müüa maha või anda oma riided tuttavatele, perele sõpradele.\nInimesed on läinud väga mugavaks, ostes toitu ja riideid väga palju, kuna nad saavad seda endale lubada. Enne riiete ostmist uuena, võiksid nad vaadata taaskasutuspoodidesse, kuna see hunnik riideid, mis sinna iganädalaselt laekub, on meeletu. Inimesed ei pea ostma nii palju toitu, et sellest pool nakuinii ära visata. Tuleb hoolida rohkem keskkonnast.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('46d88fa2-38fb-4bf1-93c0-ac87fb327642', 'title', 'Raiskamine ja taaskasutus.');
