INSERT INTO core.text(id, content)
VALUES ('d343326f-7aa7-481a-9de1-0c18a58edd69',
        'Inimesed raiskavad väga palju toitu näiteks, kas jääb tarbimata või lihtsalt visatakse ära toit. Enamustel inimestel on harjumuseks visata toit minema või lastakse aeguda ja siis visatakse minema. Noored ei tohiks minna kaasa sooduskampaaniadega ega telliks hiinast soodsalt asju.\nInimesed võiksid rohkem omale hea koguse toitu osta nii palju, kui neil vaja oleks või nii palju kui nad teavad, et jõuavad ära süüa mitte osta lihtsalt korraga väga palju toitu. Siis ei raiskaks inimesed toidu peale esiteks rohkem raha ja jõuaksid kõik tähtajaks ära süüa. Inimesed, kes saavad endale palju toitu lubada ei tohiks ikkagi raisata seda ega lihtsalt osta vaid peaksid ikkagi ostma nii palju, et nad jõuavad ära süüa. Minu näiteks oleks see, et inimesed võiksid säästa rohkem toitu ja mitte raisata.\nTänapäeval meeldib noortele tellida näiteks hiinast tooteid mis on 10 korda soodsamad kui Eestis. Aga nad ei tea seda, et need võivad olla katkised tooted või siis lihtsalt maksad raha ja ei saagi tootet kätte. Ostetakse riideid taaskasutus poodidest noored võiksid teada, et need on hiinast ja ei ole päris ja on kehale halvad.\nNäiteks oleks siin see, et ei telliks hiinast asju üldsegi ega taaskasutus riiete poodidest ka mitte.\nKokkuvõteks ütleks, et inimesed võiksid hakata ostma vähem toitu või siis nii palju kui nad ise teavad, et jõuavad süüa. Ei raiskaks toitu ei viskaks igalepoole seda laiali, et ei ostetaks toitu nii palju kui nad saavad seda endale lubada. Noored võiksid tänapäeval käia näiteks klassiga kuskil õppel, et mitte osta hiinast taaskasutatud asju mida nad leiavad ja, et ei ostaks kasutatud riiete poest asju.');
