INSERT INTO core.text(id, content)
VALUES ('914cd636-805b-480e-9748-7f9993ded306',
        'Tänapäeval on tavaline osta iga aasta uued saapad, tossud ja jope. Aga kas ka nii peaks olema, ei. Firmad teevad nii, et ma ostaks aastast aastasse uued ja uhked rõivad, et raha teenida, tuues kvaliteeti alla, et me jätkaks. Toidukraami raiskamine tuleneb ka firmade ahnusest, kuna kõiksugused puu-, köögi- ja juurviljad tulevad Eestisse kuskilt kaugelt tuleb need üle käia säilitusainetega, mis hoiavad produkti poes ilusa ja värkena, aga kui koju jõuad, siis riknevad kaubad päevadega.\nRiiete kvaliteet on langemas ja see on ka üks põhjustest miks neid koguaeg juurde ostetakse, et oleks midagi mida kanda. Jah, tõsi, kõik riided ei ole halva kvaliteetiga ja ei ole ebamugavad, aga suurem osa neist on. Põhjus, miks neist nii palju jõuavad taaskasutus poodiesse on lihtne, riided on kas moest väljas, suurus ei ole õige, sest rõivad on tellitud internetist ilma proovimata, või need ei ole mugavad. Kahte neist probleemidest saab lahendada lihtsalt poodi minekuga, aga inimesed on liiga laisad selleks tänapäeval. Kvaliteedi probleem jääb, kui riideese on piisavalt hea kvlaiteediga, siis enamjaolt jäetakse need riided endale kandmiseks, aga kui on halb kvaliteet ja tagstada ei saa, siis vahel viiakse taaskasutus keskusesse, et äkka saab sealt mingi raha tagasi ilma. et töötajad aru saaks kas kvaliteet on halv või mitte.\nKvaliteedi probleemid on järjast hullemad, sest pea kõik firmad tänapäeval eelistavad kvaniteeti üle kvaliteedi, ja meie, lambad kas me oleme ostame halva kvaliteedi järjest asju.\nToidu raiskamine on loomulik, läheme poodi tühja kõhuga, ostame rphkem kui vaja on ja sealt tekib ka raiskamine, kui me ei jõua kõike õige aegselt ära süüa. Et probleemi leevendada, võik olla targem ja kas ettetehtud poe nimekirjaga poodi minna, või kõht enne täis süüa.\nArtikkel räägib, et keskmine eestlane tekitab 61kg toidujäätmeid aastas, millest 26kg on toidukadu, ma ei usu seda, kui midagi on need arvud väiksemad kui tegelikkuses see lugu on. Ma arvan, et päris numbrid hetkese seisuga aastal 2025, märtsis on ligemale sajale kilole ja 40 kilole. Miks ma nii arvan on lihtne, eestlane on suur võrreldes ülejäänud maailmaga ja me sööme palju, see ei pruugi nii välja näha, aga nii see on. \nTänapäeval raisatake raha ja toitu rohkem kui kunagi varem. Riiete kvaliteet on langenud, et kvantiteet tõusels. Firmad on ahned ja panevad meid rohkem riideid ostma ja ka toitu. Eestlane sööb palju ja raiskab ka palju süüa.');
