INSERT INTO core.text(id, content)
VALUES ('4d482d5b-917b-4458-b861-393a6694b687',
        'Tänapäeval on raisatud toitu väga palju. Suur hulk lihtsalt ei tea kuidas vähem toitu raisata ning millist toodangut tuleks poest soetada.\nKui poes on allahindlused ostavad inimesed mõtlematult suurel hulgal toitu kokku. Enamus ei mõtle säilivustähtajale ning sellele, kas on päriselt seda vaja. Üleüldse poes käies ostetakse kokku suur hulk toiduasju, mida tegelikult ära ei tarbita. Toidukraam mille tähtaeg hakkab otsa saama ja mida ise ei soovi tuleks viia toidukappi. See on heategu inimestele ja keskkonnale.Toidu liigse kokku ostmise probleemi saab lahendada sellega, et  enne poodi minekut teed valmis ostunimekirja.Nimekiri aitab sul kindlaks jääda mida on vaja ja kui palju. Kui lähed ilma ostunimekirjata ostad kokku asju mida tegelikult vaja ei ole.Kodumajapidamises tekib iga Eesti inimese kohta aastas kerkmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg. Kui suur osa inimestest käiksid poes ostunimekirjaga saaksime vähendada liigset kokkuostu. Inimesed ostaksid kokku selles koguses toitu nagu nad  ära tarbivad. \nEnamus ostavad kokku kõige odavamad toorained. Väke hulk mõtleb toidu päritolule ja kuidas see keskkonnale mõjub. Toidu saagikuse tõstmiseks kasutatakse väetiseid ja erinevaid kemikaale. Inimesed ei jägi kas toit on mahetoit, Eestist pärit või kusagilt kaugemast riigist. Mahetoit on kallim, kui toit mis pärit kaugemast riigist aga see eest on mahetoit keskkonnale parem. Mahetoidu tootmisel kasutatakse ainult looduslike väetiseid. Mahetoidu tarbimisel teed head endale ja keskkonnale.\nSaaksime vähendada toidu raiskamist ning hoida keskkonda kui tarbiksime targemalt ning käituksime poes käies õigesti.');
