INSERT INTO core.text(id, content)
VALUES ('62644648-9757-44c8-ba4f-9e600c918587',
        'Inimestel on väga palju erinevaid tarbimisharjumusi. Inimesed on erinevad ning see tähendab, et ka harjumused on erinevad. Mina arvan, et see on tähtis teema millest rääkida kuna paljud inimesed ei tea tegelikult, kui palju nad tarbivad või kas need on head või halvad harjumused. Samas on ka inimesi kes ei ole lihtsalt  teadlikud erinevatest varjantidest.\nMoedisaineri Eve Hansoni arvates on oluline, et igaüks vaataks üle oma isiklikud tarbimisharjumused ning eelistaks kvaliteeti kvantiteedile. Mina olen selle lausega nõus. Minu meelest on õige see, et me peaksime eelistama rohkem kodumaiseid tooteid. Mina arvan, et me ei peaks tellima Hiina veebipoodidest tooteid, sest sellega me toetame lapstööjõudu.\nInimesed tarbivad toitu nagu see ei saaks kunagi otsa. Nad ei mõista tegelikult, kui palju nad seda tarbivad ja ära viskavad. Mõned inimesed tõesti saavad endale toidu raiskamist lubada, aga see, et sul on selleks raha ei tähenda, et sa peaksid toitu raiskama. On palju inimesi kellel ei ole toidu jaoks üldse raha ja ei saa seda endale lubada. Ma arvan, et kõik inimesed peaksid endale teadvustama kui palju nad tegelikult raiskavad  ja, et toidu ostmisega ei saa ka liiale minna.\nInimeste harjumused on erinevad. Inimesed ei saa aru kui palju nad tegelikult tarbivad ja toitu raiskavad. Muutused ei saa toimuda, aga üleöö. Selleks, et midagi muutuks peavad inimesed aru saama, et midagi on vaja muuta. Kõik on kinni inimestes endas ja nende mõttemaailmas.');
