INSERT INTO core.text(id, content)
VALUES ('9229aa8f-dc70-41df-ae5b-b7e3814705f7',
        'Oleme jõudnud siiamaani, kus raiskamine on meie maailmas väga suureks probleemiks. Inimesed viskavad palju toitu ära ja arvavad, et see ei mõjuta ühiskonda suurelt. Samuti ostame liigselt hiina kaupa, just riideid.\nInimesed raiskavad liigselt toitu. Samalajal arvates, et see ei muuda meie maailma halvemaks. Visatakse ära ülejäägid ja riknenud toit, kuid neid saaks väga targalt ära kasutada ja raiskamist vähendada. Ülejääkidest saaks moodustada muid maitsvaid toite. Või kui tahetakse ülejääke pigem vältida, siis tuleks poes targalt käiia ja näiteks planeerida terve nädala toit ette. Planeerides saaks osta toidupoest just paras kogus toiduained, vältides ülejääke.\nRaiskamine toimub ka siis, kui ostame ja tellime hiina kaupa ja ostleme muudes kiirmoe poodides. „Noortele peaks tegema ekskursioone taaskasutuspoodide lattu,“ ütles moedisainer Eve Hanson. Taaskasutuspoodides on väga lai valik riideid ja muid põnevaid asju, aga kui jätkame kiirmoe poodides ostlemist, siis kuhjuvad taaskasutuspoed täis ja inimesed üldse ei käi eriti ka nendes ostlemas. Taaskasutuspoodides võime leida väga ainulaadseid ja huvitavaid leide.\nMina leian, et raiskamine on suur probleem meie ühiskonnas ja soovitan soojalt poes targalt käiia ja planeerida toidukordi ette. Samuti soovitan vahest ostelda taaskasutuspoodides, sest sealt leiab enamasti väga ilusaid asju väga taskukohase hinnaga, samalajal raiskamist vältides.');
