INSERT INTO core.text(id, content)
VALUES ('07b8adcd-8334-4a1c-9b08-318a4d0c21c6',
        'Inimeste tarbimisharjumused on väga erinevad. Me kõik tarbime kodudes erinevaid tooteid erinevas mahus ja koguses. Kui asjad kuhjuvad meie majapidamistesse visatakse need minema või viiakse taaskasutuskeskustesse müüki. See kõik viib meid tohutu toidu- kui ka rõivastekaoni.\nPerekonnad on erinevad. Kõik perekonnad ei ole kahe-, ega kolmeliikmelised on ka kaheksaliikmelisi ja enam.  Julgen arvata, et tegelikult paljudes kodudes on toidukadu inimestele silmaga nähtav. Küll on neid perekondi, kes ei oska teha oma perele õiget kogust toitu. Kus tehakse vähe, kus tehakse palju. Kindlasti on ka neid, kes ostavad allahinnatud toitu ja lasevad neil kodus riknema minna, sest ei tarbita toitu ära. Nagu on öeldud tarbitoitutargal.ee veebilehel: „ Kodumajapidamises tekib iga Eesti inimese kohta aastas keskmisel 61kg toidujäätmeid.“ See kogus on tohutu. Meie tarbijatena peaksime hakkama jälgima, mida ja kui palju me ostame ja kasutame, et kaoks ära sellises mahus ületarbimine ja raiskamine. \nSama kehtib kiirmoepoodidega. Hetkel on populaarseks saanud veebipood Shein, kus müüakse Hiinas toodetud tooteid, millel on minu arvates väga puudulik kvaliteet. Toodet ei saa enne ostu proovida ega käega katsuda. Suurim mõjutaja, miks inimesed sealt tooteid ostavad on hind. Üüratult odav hind. Lõpuks jõuavad kõik need riided ja esemed, kas prügikasti või uuskasutuskeskustesse. \nUuskasutuskeskused on kogumas siiski taas populaarsust. Vähe sellest, et inimesed saavad sinna oma riideid müüki viia leiavad nad sealt üha rohkem kuulsate brändide kaupa, kuna teistel on neid kas liiga palju või on nad kappi seisma jäänud.\nTaaskasutamine tänases ühiskonnas on juba hakanud koguma populaarsust. Taaskasutamine ei ole häbi asi, sest sellega aitad sa meie keskkonda puhtana hoida. Toidukadu peaks iga perekond reguleerima. Jälgima koguseid ja tooteid, mida kasutatakse. Keeldu ostmast kiirmoepoodidest rõivaid. Osta rõivad jälgides kvaliteeti. Nii saame koos muuta keskkonna paremaks ja kaotada ära tohutul hulgal toidukad. Oleme targemad ja hoiame enda ümbrust.');
