INSERT INTO core.text(id, content)
VALUES ('276c7c40-9fb2-446a-bccb-a3a34566fb43',
        'Miks ja millepärast inimesed tarbivad rohkem kaupa kui vaja? Mis paneb inimesi tahtma rohkem asju? Millepäarst on meil vaja vähendada tarbimiseharjumust?\nTänapäeva tavalineinimene võib olla peaaegu sama suur tarbija või suurema tarbimisharjusmusega keskaja kuninkast. Tarbimisharjumus võis suure kiiruse saada juba tööstusrevolutsooniajal umbes 18.-19.saj kui hakkadi kasutama aurumasinaid, mis aitas kiirmini töödelda. Sel ajal hakkasid isegi luksus tooted hinnas kiiresti langema, seepärast võis ka näiteks kooli õpetaja endale lubada uhkeid söögi nõusi kui ka mittu paari vaipu või toole. Seetõttu me ei raiska me ainult  omaenda raha, vaid ka tohutult muid ressursse: maas olevaid haruldasi muldmetalle ja maake, tehastes olevad ohtlikud kemikaalid võivad mürgitada vett jne.Inimeste iseloom, et tahab olla parem kui teine võib aitada tarbimisvajatusele.\nTänapeaval on Euroopas tehtud seadused, et kaitsta tööliste elu, kuid Aasias või Aafrikas pole veel reegleid, nt kasutavad lapstööjõudu, et koguda kakao ube terve päev nii väikse hinna eest ja sa saad osta kümneid erinevaid šokolaade sootsalt. Hiinast sootsat elektroonikat ja väga paljud sellised rõivad on pärit  nendest suurtest kuulsatest Hiina kaubamajadest. Sa saaksid osta, nt usaldus väärsetest majandusdest kus antakse õiglase hinnaga töölistele palka.\nTänapäeva suur tarbimisharjumus vajadus võis alata tööstusrevolutsiooni ajal. Inimesi paneb rohkem ostama sootsus ja mõtte, et nad on paremad siis. Sa võiksid  osta usaltusväärtsemaid toitu ja riideid, et teised inimesed saakasid õiglast palka.');
INSERT INTO core.text_property(text_id, property_name, property_value)
