INSERT INTO core.text(id, content)
VALUES ('cd64427e-be81-48b6-b074-72f65330e17a',
        'Toit on kõige tähtsam asi inimese elus. Ilma selleta ei saa ükski organism elada. Kuid söömisega kaasneb ka massiline toidu raiskamine ehk toit jäetakse tarbimata ning visatakse lihtsalt ära.\nToitu raisatakse erinevatel põhjustel, nt kui oled ostnud liiga palju ning ei jõua kõike ära süüa, kasutustähtaja ületanud toit, enam ei maitse, vms. Keskmiselt tekib iga Eesti inimese kohta aastas kümnetes kilodes toidujäätmeid, mis on liiga suur arv ning välismaal võib see arv olla veelgi suurem.\nToidu raiskamine tekitab paljusi keskkonnaprobleeme, juba tootmine on kahjulik kemikaalide ja väetiste pärast. Toiduga (ja muu prügiga) on reostatud palju tänavaid ning loodust, Eestis mitte eriti, aga välismaal, nt Indias ja Suurbritannias. Toidu tootmisel ning transportimisel tekib veel keskkonnaprobleeme- õhu saastamine, heitgaasid, jms. Ookeanitesse, meredesse ja muudesse veekohtadesse võib tulla toiduga palju plasti, kui visata ära pakendiga.\nMinu arvates on nendele probleemidele kerged lahendused, kui ei plaani toitu süüa, või kui on kasutustähtaeg kohe käes ning ei jõua seda süüa, saab annetada toitu neile, kes seda väga vajavad. Oma toitu võib anda ka lemmikloomadele, nt koertele ja kassidele, et sööki täiesti mitte raisku lasta. Toidu annetamine aitab kaasa söögiprobleemidele ning lemmikloomale toidu andmine teeb ta õnnelikuks. Kahjuks läheb muutusteks kaua aega ning paljud inimesed peavad annetama toitu, et oleks neid muudatusi näha.');
