INSERT INTO core.text(id, content)
VALUES ('a7fd3c32-89c4-46a3-b587-ac885e44400e',
        'Probleem on selles et inimesed hulk viskavad minema külblikke asju ja korralike riideid ilma teise valikutta. Nad arvavad et kui nad ühe korra kannavad riiteid või peak väikseks jääma siis viskavad minema ilma teiste mõteteta. Huvitav miks nad ära ei anna või ei taaskasuta neid sama moodi ka toitu panna komposti. ehk siis täna me proovime selgutada ja aru saada miks inimesed viskavad asju ära mis on korralikud. \nProbleem on eesti ja üle maailme sellega et inimesed viskvad minema toitu. Ja selle alla kuulub ka Riided mis inimesed ei kasuta enam ja viskavad minema lihtsalt meil on vaja sellele probleemile lahendus leida.\nJa need kes seda ei usu tuleb saata Kaltsukatesse ja siis nad näevad oma pilguga seda mis toimub eestis. Ma ei mõista kui inimesel jäävad riided väikseks või enam ei sobi siis mikda mitte ära annetada või kellegile anda kes mahuks sinna.See aitaks juba päris palju eesti  rahva riskamist vähendada mingi protsendi võrra ma saan aru kui riided on puru siis vii need lihtsalt taaskasutuskeskusesse seal ikka nendega om midagi teha riideid ei tohi lihtsalt ära loopida ma saa  aru mõned inimesed ei huvita et keegi seda talle räägib ja ikka viskab neid reiidedi minema nagu ei oleks kunagi kuulnud seda juttu mis maailm ja eesti riik räägib. Inimesed võiks ise selle peale mõelda et nagu võiks mitte viisata ja pitgem annetdada neuile kes pärisest neid vajavad. Järeldus on selline et mina arvad et võiks kõigile saata või öelda edasi tuttvatele või kes iganes inimesed neid viskavad et nad pigem annetaks või teeks midagi targemat nendega mitte ei viskaks minema korralike asju ja aitame eesti paremuse poole.\nÜhesõnaga tuleb meil eesti aitamiseks ja päästmiseks öelda inimestele ja tuletada meelde et viia riided kuskile kus neid saab kaustada veel ja inimesed saacvad võtta ja ise kanda kellel vaja mitte ei loobi ära ja pärast akki keegi tahtis täpselt samat asja mis sa just ara viskasid ja nüüd ei ole enam midagi teha ta peab ostma selle poole kallimalt kui ta oleks saanud kaltsukast või kusagilt selle tuleb mõelda ja eestit paremaks muutu ei tohi visata asju ära mis teistel vajaläheb oleme lahked ja korralikud aitame teisi.');
