INSERT INTO core.text(id, content)
VALUES ('1eb7ac5b-d3b8-4e2c-a725-7df3b09ceeb0',
        'Paljud inimesed ei pane tähele, et nende tarbimisharjumustel oleks halb mõju. Enamus inimesi vastupidi arvavad, et kui nemad näiteks palju toitu ei raiska, ei mõjuta nad sellega sugugi ümbritsevat keskkonda, kuid tegelikult see pole nii. Halvad inimeste tarbimisharjumused on praegu suureks probleemiks, mille lahendamine tundub olevat üpris keeruline. Kuidas mõjutab meie tarbimisharjumused ümbritsevat keskkonda?\nÜks suurim inimeste tarbimisharjumus, mis mõjutab meid ümbristevat keskkonda on toidu raiskamine. Inimesed viskavad ära toitu mitmel põhjusel. Üheks põhjuseks on toidu rikenemine. Toit muutub halvaks ja ainus mis inimestel ülejääb on see toit ära visata. Samuti ka siis, kui toit on ületanud kasutustähtaja. Teiseks põhjuseks on toidu mitte lõpuni söömine. Ma arvan, et paljudel on juhtunud nii, et pärast toidu söömist jääb mingi osa toidust taldrikule, mida pärast söömise lõpetamist prügikasti visatakse. Seetõttu ei kuluta me toidu raiskamisele mitte ainult omaenda raha, vaid ka tohutult palju muid tähtsaid resursse: maad, vett, energiat ja ka tööjõudu. Tänu kõigele sellele tekib toidu tootmise ajal tõsine keskkonnakoormus. Seda sorti keskkonnakoormus tekib kuna selleks, et saagikust tõsta kasutatakse erinevaid kemikaale ja mitut sorti väetisi.\nTeiseks suureks probleemiks on halva kvaliteedi, kuid odavate hindadega riiete eelistamine. Kuulus moedisainer Eve Hansoni on öelnud järgmiselt: „ Eelistada võiks kodumaiseid oma lähedal toodetuid asju ning pigem vähem kui rohkem.“ Kui aga külastada mõnda taaskasutuspoodi ja näha seda meeletut kogust riideid, mis iganädal sinna kauplusesse tuuakse, näeb ära selle, kui palju inimeseid tegelikult riideid raiskavad. Selliseid kohti nagu taaskasutuspoode tuleks külastada igaüks. Isegi noori paneks selline koht mõtlema oma tarbimisharjumuste peale ja kui suureks probleemiks see tegelikult on.\nÜks tähtis küsimus millele üritasin vastust leida oli : „Kuidas mõjutab meie tarbimisharjumused ümbritsevat keskkonda?“ Inimesed mõjutavad ümbritsevat keskkonda erinevalt. Üks suur faktor on toidu rasikamine, kuna see tekitab suurt keskkonnakoormust. Samuti raiskavad inimesed peale toidu ja oma raha ka vett, maad, energiat ja tööjõudu. Teiseks mõjutavaks faktoriks on halva kvaliteediga riiete ostmine, mis pärast ühte kasutuskorda ära visatakse. See kõik reostab meie maailma ja mõjub halvasti meid ümbritsevale keskkonnale.');
