INSERT INTO core.text(id, content)
VALUES ('73426d5a-18a3-40b8-a704-48ba22f70607',
        'Tänapäeval Eestis ja ülemaailma on probleeme toit säästmise, loodus säästmise ja tarbimisharjumustega. Tänapäeval inimesed raiskavad toitu, energiat, tööjõudu kui ka maad. See probleem on väga suur ja raske.\nToit on üks enam raisatud toode maailmas.Näiteks kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid millest toidukadu moodustab 42% ehk 26 kg. Toidukadu on toit mis mingitel põhjustel jääb tarbimata näiteks:Söömisel ülejäänud toit, riknenud vms. Teistes riikides võib olla toidukadu veelgi suurem kui Eestis. Inimesed ise ei märka, et naad niipalju toitu raiskavad kuna toidu raiskamine on tänapäva inimistel harjumus.\nTööjõudu raisatakse päris palju näiteks, toidu tooted, riited vms. Riiete raiskamine on eriti suur. Eve Hanson, moedisainer, on öelnud:“Ma näen taaskasutupoodide laos vabatahtlikuks käies seda rõivaste kogust, mis tekib iganädalaselt juurde. Need on meeletud hunnikud ja see on väga õpetlik. Ma arvan, et peaks hakkama noortele tegema ekskursioone taaskasutuspoodide lattu, et näidata, milline raiskamine tegelikult toimub. Sinna viiakse korralikke riideid, aga ka selliseid, mis mingil kaunil reklaamfotol näevad ilusad välja, aga tegelikult koosnevad naftast ja sa ei taha seda rohkem kui üks kord kanda, sest kehal on halb olla selles. Ja väga paljud sellised rõivad on pärit nendest suurtest kuulsatest Hiina kaubamajadest.“ Hiina tooted on ka suur probleem kuna nad on nii tehtud, et naad kiirest läheksid katki, et te osaksite uued riited.\nLooduse reostus on ülemaailmane probleem. Eesti lood on üks parimatest maailmas. Looduse reostus enamasti on tootete pakendus, riited, tööstusjäägid jms. Üks looduse reostuse lahendus on taaskasutavad pakendid ja taaskasutavad tööstus jäägid või tööstusjääkide täielik hävitamine. Enamus inimestel on harjumus, et naad viskavad pakendi või mingid taaskasutamatud tooted metsa. Inimesed ise ei sa aru, et naad reostavad lootust kui ka ohustavad looma elu, sest mõned loomad võivad arvata, et pakent on toit ja söövad pakendi ära millr käigus naad võivad surra. looduse hoid on üks tähtis asi et meil oleks hapniku ja toitu.\nKokkuvõtteks võib öelda, et inimeste harjumuste ja nõuete pärast on inimesed palju raisanud toitu kui ka tööjõudu. Inimeste nõuete pärast on nii palju riiteid ära visatud kuna naad ei meeltinud kellegile või sest naad olid halvast materiaalist tehtud. Looduse hoid on ka väga vajalik kuna ilma selleta meie hapniku tase langeb.');
