INSERT INTO core.text(id, content)
VALUES ('198c3967-41b8-4cc0-907f-d915c739a042',
        'Tänapäeva üheks suurimaks probleemiks on inimeste tarbimisharjumused. Peaaegu igaüks meist tarbib rohkem kui peaks ja ostab tooteid, mis saastavad loodust väga palju, sest need on soodsamad või ilusamad.\nÜks asjadest, mida me tarbime liiga palju on näiteks toit. Kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg. Lisaks sellele viskab suur osa noori poolikuid toidupakke minema, sest sellel hetkel nad ei taha enam süüa/juua ning ei viitsi seda endaga kaasas kanda. Sellest tekib veel üks suur probleem, sest noored reostavad loodust visates need toidupakid igale poole laiali kui prügikasti pole lähedal. Seda kõike saaks vähendada kui tõstaksime teadvust selliste probleemide üle noorte seas ja kodudes.\nTeine suur probleem on igasuguste toodete ostmine internetis. Inimesed näevad toodete reklaame internetis ning ostavad neid isegi siis kui nendel pole seda tõeliselt vaja. See juhtub veel tänu sellele, et paljudes reklaamides on tooted esitatud väga ilusal moel. Nii tekivad inimeste kodudes liigsed riided, mänguasjad, sportimise varustus jne. Näiteks seetõttu viiakse korralikke riideid taaskasutuspoodidesse või visatakse üldsegi ära. Selliseid asju saaks vältida kui inimesed mõtleksid rohkem enne millegi ostmist ning uuriksid, kas veebilehtedel reklameeritu on sama hea kvaliteediga kui reklaamis.\nMe tihtipeale ei mõtle väga palju selle peale, kas tahame või tõesti vajame midagi, mida osta plaanime. Enamik tarbimisprobleeme saaksid olla lahendatud kui inimesed rohkem mõtleksid enne millegi ostmist ja uuriksid toodete kvaliteedi kohta.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('198c3967-41b8-4cc0-907f-d915c739a042', 'title', 'Inimeste tarbimisharjumused');
