INSERT INTO core.text(id, content)
VALUES ('ea64a161-104c-405e-a179-c36ee33ef069',
        'Millised tarbimisharjumused on inimestel? Paljud meist on oma elu jooksul ära visanud toitu ning tellinud internetist uusi rõivaid. Kuidas saad sina kokku hoida?\nTaaskasutus on hea viis hoida kokku nii raha pealt kui ka säästa meie planeeti. Tihtipeale tellivad teismelised iganädalaselt internetist uusi odavaid rõivaid. Koguaeg on selline tunne, nagu oleks vaja veelgi enam riideid, kuigi kapp on pungini täis. Natukese aja pärast viiakse vanad riided prügi- või taaskasutuskasti. Nagu moedisainer on öelnud: „Ma näen taaskasutuspoodide laos vabatahtlikuks käies seda rõivaste kogust, mis tekib iganädalaselt juurde.“ Selle asemel, et rõivaid niisama ära visata või anda, võiksid hoopis pakkuda riideid, mida sa enam ei soovi, sugulastele või sõpradele. Nii saavad nemad taaskasutada sinu rõivaid, selle asemel, et tellida jälle uusi ning pärast taaskasutuspoodi viia. Sellega hoiaksime oma planeeti ning taaskasutuspoodides ei tekiks üleuputus.\nSuureks probleemiks on ka toidu raiskamine. Tihtipeale ei tea inimesed, mida poest osta ning ostavad asju, mille pärast ära viskavad. Poodi minnes tuleks teha poenimekiri. Kui teed endale poenimekirja, siis viidad vähem aega poes ning tead, mida osta. Nimekirja pane kirja toiduained, millest sa kindlalt süüa teed või mille ära tarbid. Nii ei jää midagi külmkappi riknema, mille pead pärast prügikasti viskama. Ostes toiduaineid, mõtle sellele, kui kaua aega ja abivahendeid, mis on kahjulikud maale, läks just selle toiduaine kasvatamisele või valmistamisele. Nagu tarbitoitutargalt.ee kodulehel on öeldud: „Lisaks tekitab toidu tootmine tõsise keskkonnakoormuse, sest saagikuse tõstmiseks kasutatakse väetisi ja erinevaid kemikaale.“ \nTarbimisharjumused on väga erinevad ning ei muutu üleöö. Taaskasutus ja poenimekirja tegemine on kaks head viisi, kuidas parandada oma tarbimisharjumusi ning hoida planeeti.');
