INSERT INTO core.text(id, content)
VALUES ('cb5bd803-8179-4a12-859e-db664b06e513',
        'Toit on üks osa meie iga päeva elust mida me ostame ja sööme iga päev. Inimestel on probleeme liigse toidu ostmisega mille taga järg on toidu raiskamine.\nPaljud poed üritavad inimesi petta ja mõjutada. Poed tihti-peale panevad populaarsemad kaubad poe taha otsa ja mitte nii popuulaarsed ette, mis sunnib kliente nendest mööda kõndima. Inimesed langevad lõksu ja ostavad toote mis silma jääb mille järgi ta tegelikult ei tulnud. Soodused poes tõmbab inimesi ligi. Inimesed thiti peale näevad 50% soodustust ja võtavad selle isegi kui nad tulid mingi muu toote pärast poodi. Väga thiti seda toodet ära ei sööda ja toode läheb prügikasti. Näiteks lähed poodi piima ostma aga näed võid mis on 75% alla. Sa ostad selle, kuna peas mõtled, et see on pea aegu tasuta. Või läheb halavks enne kui sa seda kasutada saad ja nii toit raisku lähebki.\nInimestel on kodus tihti peale varutud suur kogus kuivaineid nt, makaronid, riis ja tatar. Toitu tehes inimene kasutab terve pakki toodet ära. Toitu jääb liiga palju järele ja toode läheb raisku Tarbitoitutargalt.ee/toidkaost/ ütleb et inimene raiskab keskmiselt 61kg toitu aastas. Mis on väga palju.\nKokku võteks kui sa lähed poodi ja näed toodet mis pakkub sulle huvi mõtle peas läbi kas sa päriselt vajad seda. Tee endale piisav kogus süüa mida ei jää järele ja jõuad ära süüa.');
