INSERT INTO core.text(id, content)
VALUES ('9270b3a9-5648-44f3-bf16-5d7fb905841f',
        'Paljud inimesed arvavad, et meil tuleb olema suur toidukaos paari aastapärast. Nad arvavad, et meil saab toit kohe otsa. Aga on ka inimesi, kes arvavad,  et meil ei saa kunagi toit otsa. On ka  inimesi, kes arvavad, et toit pole enam tänapäeval söödav, et inimesed panevad keemilisi aineid meie toidu sisse.\nMina arvan, et tänapäeval üks toidukaose põhjus on toiduraiskamine. Paljud inimesed raiskavad toitu, kuna nad arvavad, et nad võivad seda endale lubada, et toit ei sa kunagi otsa. Seal on palju inimesi, kes arvavad, et kui nad viskavad väikeseid koguseid ära, et see ei mõjuta ültse meie keskonnda. Ja sellega ei raiska me ainult toitu, vaid ka muid ressursse, nt raha, maad ja vett.\nPaljud inimesed arvavad, et tänapäeva toit ei ole enam söödav. Kuna nad arvavad, et inimsed panevad keemilisi aineid meie toidu sisse. Mina nõustun sellega, kuna ma arvan, et tänapäeval panakse toidu sisse liiga palju kemikaale, nt meie puuviljade ja köögiviljade sisse. Inimesed teevad seda, et puuviljad ja köögiviljad suuremad oleks ja, et nad  näeks rohkem isuäratavamad  välja.\nToidukaost võib põhjustada mittu erinavat asja. Aga meie saame seda vältida. Kui me saaks üksteisest rohkem aru ja õppiks enda halvad harjumused maha jätta. Me võiks vähem toitu raisata ja vähem keeimilisi asju meie toidu sisse panna. See aitaks meie keskonnda väga palju.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('9270b3a9-5648-44f3-bf16-5d7fb905841f', 'title', 'Toidukaos');
