INSERT INTO core.text(id, content)
VALUES ('a99b5225-6d0f-42b7-81a8-28ae35a3ff25',
        'Inimesed kasutavad väga palju erinevaid asju. Mõndade asjade tarbimisest võib välja kujuneda harjumus või lausa sõltuvus. Need ei pruugi su tervisele alati head olla. Kuidas mõjutavad erinevad tarbimisharjumused inimese tervist?\nInimestele tekivad harjumused siis, kui nad teevad seda pidevalt ja on sellega juba ära harjunud. Paljudel on halbi harjumusi, näiteks suitsetamine, narkootikumid ja akohooli joomine. Need tegevused kahjustavad inimese tervist. Enamustel suitsetajatel tekib kopsuvähk, mille tagajärjed võivad väga kriitilised olla. Halbu tarbimisharjumusi pole mõtet endale külge harjutada, sest tulevikus need toovad sulle ainult kahju.\nPeale halbade harjumuste on inimestel ka eluks vajalikud tarbimisharjumused. Inimeste üheks eluks vajalikuks harjumuseks on söömine. Süüa on vaja igal inimesel, et saada energiat ja elus püsida. Süües ei pruugi inimene alati kogu oma sööki ära tarbida ja see visatakse minema. Toidu raiskamine ei ole ka hea, sest see tekitab keskonnale aina suuremat koormust. Eestis ühe inimese kohta tekib umbes 61kg toidujäätmeid. Toitumisharjumuste korral tuleb silmas pidada, mitte toitu liialt raisata. Toidu raiskamine ei ole otseselt kahjulik sulle, aga see võib tekitada raskusi keskonnale, kus me kõik elame.\nInimestel on väga palju tarbimisharjumusi. Mõned neist on elus vajalikud ja teised on lihtsalt külge jäänud. Tarbimisel tuleb väga hoolikalt silmas pidada, millised on tagajärjed ja kuidas me nendega toime tuleksime.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('a99b5225-6d0f-42b7-81a8-28ae35a3ff25', 'title', 'Inimeste tarbimisharjumused');
