INSERT INTO core.text(id, content)
VALUES ('9d76fe8f-66d8-45f8-a6d9-d174d43256e8',
        'Inimesed tarbivad meeletus koguses asju mida neil vaja ei lähe. Nad raiskavad toitu ja rõivaid ilma et nad ise aru saaksid, kui suur on tegelik kogus mille nad lihtsalt ära viskavad. Seda raiskamist vähendada ei ole lihtne, see on paljuski kinni inimste harjumustes.\nEestis tekib kodumajapidamises aastas inimese kohta 61kg toidujäätmeid ilma, et nad ise sellest aru saaksid. Toidu ära viskamisel ei raiska me ainult oma raha, vaid ka teisi ressursse. Inimene võib küll mõelda, et see kogus toitu mis nad ära viskavad ei ole nii suur, kuid tegelikult on see kogus suurem kui nad ette kujutavad.\nSama probleem on ka riietega. Inimesed ostavad ja tellivad endale riideid, mis algul tunduvad kenad ja mugavad, kui lõpuks viskavad või annavad need ära, kuna need ei ole nii muguvad kui tundusid või lihtsalt tüdinevad neist ära. Ei ole mõtet tellida endale riideid Hiina kaubamajadest, sest väga paljud riided seal on tehtud naftast ja neid ei ole mugav kanda. Võin kogemusest öelda, et Hiinast tellitud riided ei ole just kõige mugavamad. Selle asemel võiks osta kodumaiseid rõivaid, mida võid kanda kas või aastaid, selle asemel, et koguaeg uued osta ja vanad ära visata.\nInimeste tarbimisharjumusi vaadates on kurb mõelda kui palju toitu ja rõivaid läheb lihtsalt raisku. Need kogused on suured ja neid vähendada pole sugugi kerge, sest oma harjumusi muuta on raske, kuid kas või väike samm jääkide vähendamise poole on midagi.');
