INSERT INTO core.text(id, content)
VALUES ('7496abf0-6d32-46f1-a038-73a565904688',
        'Inimestena me vahel ei väärtusta neid privileege, mis meil on visates toidu ja riideid ära, mida kellegil teisel oleks vaja läinud. Visatakse riideid ära, mida ainult paar korda seljas käinud. Toidu visatakse ära, mis oli veel söögikõlblik.\nKiirmoega me raiskame ressursse, mida kasutakse nende esemete tegemiseks nagu nafta, vesi, energia ja tööjõud. Praegusel ajal on populaarne tellida endale Hiinast uus trendikas riideese, mis peale kohale jõudmist läheb moest ära juba. Moest ära läinud riided tavaliselt visatakse ära nagu prügikasti ja ainult harva jõuab taaskasutuspoodi. Probleemi lahendamiseks saaksime tuua rohkem tähelepanu, kui palju ressursse me raiskame nende riiede jaoks. Parem oleks meie keskkonnale osta kodumaiseid riideid toedades meie ühiskonda.\nKesmine Eesti inimene aastas viskab 61 kg toidujäätmeid, millest 26 kg on toidukadu. Toidukadu tähendab raisatud toit, mis mingil põhjusel visatakse ära. Isegi siis, kui see veel oli söögkõlblik. Selle parandamiseks peaksime me rohkem oma harjumustega tegelema, et mitte nii palju raisata. Me saaksime oma igapäevasi toidu menüüsi niimoodi koostada, et ainult vähesel määral jääb midagi alles või et kogu toit saab söödud\nInimeste tarbimisharjumustes on meil probleem. Oleme ära harjunud luksusega, et me saame mugavalt endale asju soetada. Me ei hinda oma riideid ja toidu nii kõrgelt ja viskame need lihtsalt kasutamata ära. Selle parandamiseks võiksime rohkem valgust tuua sellistele teemadele, et kõigil pole ressursse endale igapäevast toidu muretseda, sest on nii vaesed.');
