INSERT INTO core.text(id, content)
VALUES ('118b028c-a972-42ac-93e0-11c261c86c5b',
        'Paljudel inimestel on tarbimisharjumused, inimesed viskavad ära toidujäägid ja rõivaid. Kuna nad arvavad, et toidujääke võib lihtsalt omal moel ära visata, et mitte midagi ei juhtu toiduga ja siis inimesed ostavad Hiinast rõivaid, mida nad pärast ei kanna ja tekitavad suuri hunnik rõivaid, millega sa raiskad pärast oma raha nende peale.\nToidu viskamine, on suur kohus meie jaoks. Sa vaid ei viska toitu ära, aga samas sa raiskad ära ka oma raha ja maa ressursse. Et vältida toidukaost sa võiksid enda toidujäägid ümber korralda ja neid teha väetiseks või erinevateks kemikaalideks. Toitu visatakse ära paljudel põhjustel. Näiteks kui sulle ei meeldi see toit, siis inimesed tavaliselt viskavad toidujäägid ära või näiteks see on liiga kaua säilinud sul, neid põhjuseid on palju. Toidu säästmiseks on palju viisse ja ideid kuidas mitte toitu raisata.\nInimestel on ka rõivaste tarbimisharjumus, kus nad ostavad igasuguseid rõivaid välismaalt näiteks Hiinast. Iga aasta inimesed ostavad hunnik rõivaid Hiinast, kus nad ühe korra kannavad ja siis tekitavad suuri rõiva hunnikuid. Hunnikutesse visatakse korralike rõivaid samas ka mida sa pole eales kasutanud või ühe korra seljas kandnud ainult. Noortele võiks teha ekskursioone, kus nad näevad, et ei tohiks osta nii palju rõivaid välismaalt ja näha kui palju inimesi tegelikult viskavad rõivad ära. Nii sa saad säästa oma raha ja hoida maa keskkonda puhtana.');
