INSERT INTO core.text(id, content)
VALUES ('1b9ef1a9-32e0-40d9-9f93-941b8d75ea9c',
        'Tänapäeval raisatakse liiga palju raha mõtetult toidu ja riiete peale. See tähendab et seda on lõpuks liiga palju üle ja kõik läheb raisku. Peab oskama rohkem planeerida ja mõelda mida päriselt vaja läheb ja kas need asjad on ka vajalikud et need seisma ei jääks kuskile niisama.\nInimesed on hakanud liiga palju raha riiete ja söögi peale kulutama igapäev poes käies ostetakse üks või kaks uut riide eset juurde kuigi nendel pole tähtsust olemasoluks need riided jäävad niisama kappi seisma otsarbetult. Täpselt sama on ka toiduga poes nähakse midai mis on meelepärane ning see ostetakse kohe ära sest arvatakse et seda on hädasti vaja kuigi tegelikult jääb ka toit niisama seisma seda ei sööda ära mille tagajärjel see läheb vanaks.\nNäiteks inimeste arvates on nii et toitu on liiga palju ja see eie saa kunagi otsa sellepärast nad ka seda juurde ostavad koguaeg.Riietega on nii et minnakse poodi vaadatakse et seda läheb vaja võetakse mitu riiet ja lõpuks seisavad need kapis kuna neid ei kanta.\nKokkuvõtteks võiks vähem riideid osta et need seisma ei jääks ja ka vähem sööki et see raisku ei läheks nii saab ka raha kokku hoida ja ka loodust puhtana hoida.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('1b9ef1a9-32e0-40d9-9f93-941b8d75ea9c', 'title', 'Liigne tarbimine ja raiskamine');
