INSERT INTO core.text(id, content)
VALUES ('e9e01d65-abf5-4eca-9308-9fa07980f94f',
        'Inimsed kes tarbivad jagunevad kahte ossa. Osa tarbib nii, et saaks rahulikult elada, kuid osa raiskab, sest nad saavad seda lubada. Minu meelest on asi läinud üle mõistlikuse piiri.\nToit on vajalik kõigile. Inimesed arvavad, et kui nad viskavad ära väikese koguse toitu ei tee see suurt paha. Vale vastus. Iga Eesti inimese kohta tekib aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu on 26 kg. Toidukadu on raisatud toit, mis mingil põhjusel jääb tarbimata ja lõpuks ära visatakse. Sellega me raiskame tohutult raha. Lisaks tekivad erinevad keskkonnaprobleemid, sest toidu saagikuse tõstmiseks kasutatakse erinevaid väetiseid ja kemikaale.\nTegelikult ei ole asi ainult toidus, vaid näiteks ka riietes ja muus eluks vajalikus. Inimesed peaksid eelistama kvaliteeti kvantiteedile. Minu arvates peaksime vähendama tellimist Hiina veebipoodidest ja toetuma rohkem kodulähedastele meetmetele. Muidugi on võimalus ka kõik oma riided taaskasutada, kuid praguseks on ka see võimalus muutunud ebakindlaks. Praegusi taaskasutuspoode vaadates on tekkinud suur uputus. Sinna viiakse korralikke riideid kuid ka selliseid, mis reklaamfotol näevad välja ilusad, aga tegelikult on tehtud naftast ja on halvad.\nInimeste tarbimisharjumused on suured. Toidu ja riiete minema viskamine toob kaela meile palju probleeme mille lahendust me ei tea. Seda peatada saame ainult ennast kokku võttes ja vaadates üle oma igapäevased harjumused. Asi on hull ja läheb veel hullemaks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('e9e01d65-abf5-4eca-9308-9fa07980f94f', 'title', 'Inimeste tarbimisharjumused on läinud üle piiri');
INSERT INTO core.text_property(text_id, property_name, property_value)
