INSERT INTO core.text(id, content)
VALUES ('7f55b4de-1c68-45b5-9c9d-7b0246c56a4d',
        'Tänapäevases keskkonnas käivad pidevalt meie kõrvust läbi teemad ‘’ taaskasutus’’ või ‘’raiskamine’’. Raiskamine on suur probleem meie keskkonnas, näiteks viskame ära  toitu, riideid või üleüldse asju mida saaks veel kasutada. Seda saab nimetada raiskamiseks.\n       Enamus inimesed arvavad, et see on normaalne kui me toitu ära viskame. Meile tundub, et toitu on veel ja see ei saagi kunagi otsa. Näiteks on inimesi, kes raiskavadki toitu, sest nad saavad seda endale lubada, kuid sellel on ka suur mõju keskkonnale. Iga inimese kohta tekib aastaga kilode viisi toidujäätmeid. See võib kõlada päris süütult, aga ei. See on meie ühiskonnale väga kahjulik. See et me viskame toitu ära sellepärast, et see on rikknenud, söömisel ülejäänud või oma tähtaja ületanud ei raiska me ainult oma raha vaid ka palju muid ressursse. Toidu raiskamine ei saa väheneda üleöö, me peame sellega ise tegelema ja oma harjumustets lahti laskma. \n                Iga inimene võiks ka üle vaadata oma tarbimisharjumused ning eelistada kvaliteeti kvantiteedi asemel. Näiteks ära osta asju mis on odavad, aga halva kvaliteediga. Pigem osta asju mis on küll kallimad, aga peavad kauem vastu ja on keskkonna sõbralikumad. Riideid ja muid tooteid ei soovitada osta Hiina pooditest, Sest need võivad pildil head välja näha, aga kui kohale jõuab võib see välja näha teistsugune ja sisaldada näiteks naftat ning sul pole soovi seda enam kanda, sest see on ebamugav. See toob jällegi lihtsalt juurde raiskamise mõju keskkonnale.\n         Kokkuvõtteks võin öelda, et ära satu ostuohvriks ja eelista kodumaiseid tooteid. Vaata enda sisse ja mõtle, mida sina saaksid teha paremini, et raiskamist oleks keskkonnas vähem.  Anna enda panus keskkonna parandamise jaoks!');
INSERT INTO core.text_property(text_id, property_name, property_value)
