INSERT INTO core.text(id, content)
VALUES ('63b1fe40-ff0b-4363-9374-0b0055b85fd0',
        'Ühiskonnas on olnud juba aastaid probleem liigtarbimine ja inimeste tarbimisharjumused. Tänapäeval on sellele hakatut pöörama märkimisväärselt rohkem tähelepanu, ning kuidas leida keskonna sõbralikemiad alternatiive.\nEsimene suurem probleem on toiudu raiskamine ja ära viskamine. See on suur resursside raiskamine. Suuremosa toidust vistatakse ära kuna need on kas säilivusaja ületanud või toidu tegemisest järele jäänud. Iga aasta tekib ühe Eesti elaniku kohta keskmiselt 61kg toidujäätmeid millest 26kg on toit. Ühiskond ei väärtusta toitu piisavalt, ning ei usu seda, et nende äravisatud säilivusaja ületanud juustu pakk kellelgi liiga teeb. Otseselt juu ei teegi, kuid sellele on suurem mõju ühiskonnale.  lnimesed peavad õppima rohkem oma toidukordasi ja söömisharjumisi planeerima ja ostama seda mida nad ka päriselt tarvitavad ja söövad.\nTeine suurem probleem on riidetööstus ja riiete äraviskamine. Selle probleemi algataja on kindlasti kiirmood. Paljud ostavad oma riided odav atest riidepoiodistest ja on see juures alati viimaste moetrendidega kaasas. Mida see ,aga keskonnale tähendab on see ,et inimesed ainult toodavad ja toodavad ning riideid mida kanntakse umbes aasta lähevad kas taaskasutusse või prügimääele. Moedisainer Eve Hansoni arvates on tähtsam kvaliteet kui kvantiteet. Eve on vabatahtlikuna erinevates taaskasutus riidepoodides näinud mis kogustes tuleb sinna riideid mida on kanntud vähe või on need odavad hiinas toodetud riided.\nKokkuvõtteiks on väga tähtis teada oma tarbimisharjumusi ja need enda jaoks läbi mõelda. Enne igat ostu kaaluda kas see on vajalik ja äkki on sellele keskonnasõbralikemaid alternatiive.');
