INSERT INTO core.text(id, content)
VALUES ('26ecb6d6-5446-4ade-83ba-ec3919f1e88b',
        'Kui me mõtleme liigse tarbimise peale kui lihtsalt veel üks probleem mida lahendad  ei lahenda me seda mitte kunagi. Tänapäeva noorte seas on suur probleem liigse tarbimisega. Kuid tekivad küsimused, et „Miks noored tarbivad liigselt?“ ja „Kust nad seda õpivad?“\nSuur osa noorte elust toimud tänapäeval sotsiaal meedias, kus neile satuvad ette kõik uued ja trendikad asjad, mida nad „kindlasti“ vajad. Hea näide mida tuua on hiljuti trendikad olnud Stanley termos topsid, suure mahutusega kõrrega topsid mida kõik vajasid ja mille üle poodides kakeldi, kuid kohe pärast neid tulid müügile Owala veepudelid. Ilusate disainidega veepudelid, mida oli palju mugavam kaasas kanda, ning kuna kõik hakkasid järsku Owala veepudelit reklaamima, ei tahetud enam Stanley-ist midagi kuulda ja nii jäidki suured mitmekordsed veetopsid riiulile tolmu koguma.\nNoored ei saa ainult mõjutust sotsiaal meediast, vaid ka muidugi oma vanematelt, tänaseks päevaks on suur probleem hiinast tellimisega nii täiskasvanute kui ka noorte seas. On avastatud sellised veebilehed nagu nt Temu, Shein, Wish ja Aliexpress, kust ostetakse endale odava hinna eest kraami kokku, mida pole vaja.  Pärast ostmist, saab ese 1-2 kasutust lähes asi enamasti lihtsalt katki. Küll odava hinna eest saadud, ei tasu see ära kui ostetud asja saad vaid ühe korra kasutada. \nVõttes kokku kõik mida olen eelnevalt rääkinud on liigne tarbimine meeletu probleem tänapäeva elus. Minu arvates saame probleemi vähendada, kui noored leiaksid endale asjad mis neile väga meeldivad ja on kvaliteetsed, ning ei läheks iga trendiga kaasa. Me oleme ise kõik suured probleemid planeedil tekitanud, aga koos saame ka need lahendada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('26ecb6d6-5446-4ade-83ba-ec3919f1e88b', 'title',
        'Lõpetame liigse tarbimise, enne kui me lõpetame elu planeedil maa!');
