INSERT INTO core.text(id, content)
VALUES ('265c7395-c32d-4d7c-9d7a-6fbf9dbf07f2',
        'Paljud inimesed viskavad niisama toitu, riideid ja muid asju ära, seda teevad eriti inimesed, kes saavad seda enadale lubada ja kellel on neid asju palju üle, kuid seda teevad ka tavalised inimesed väiksemates kogustes.\nToidu niisama ära viskamine, kui seda on üle on väga halb, sest seda tehes raiskame oma enda raha ja palju ressursse. Ja sellepärast, et inimesed viskavad aastas nii palju toitu lihtsalt ära, toodetakse toitu rohkem kui vaja, sest tootjad arvavad, et meil on seda tarvis.\nVõib tunduda, et sa viskad nii vähe toitu ära, et vahet ei ole, aga aasta jookul see kogus läheb päris suureks. Keskmine Eesti inimene tekitab aastas keskmiselt 61 kg toidujäätmeid, millest toidu kadu on koguni 26 kg.\nToidu kadus saab vähendada nii, et ostad poest kokku vähem toitu ja teed kodus süüa täpselt nii palju, kui ära sööd ja jälgid, et sööksid toiduained ära ennem, kui need söödamatuks muutuvad.\nToit ei ole ainus jääde, mida inimesed liigapalju mõõttetult ära viskavad, seda sama tehakse ka riietega. Inimesed ostavad suvaliselt Hiina poodidest mõtlemata lihtsast plastikust riidetooteid, mis tegelikult ei näe nii head välja ja ei ole nii hea kvaliteediga, kui veebileht reklaamis. Mõnikord need riided ei ole isegi üldse mugavad. Lõpuks satuvad need riided hunnikutena taaskasutuspoodidesse.\nInimesed viskavad üleliia asju ära, kuigi selle vältimiseks peab lihtsalt natukene harjumusi muutma.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('265c7395-c32d-4d7c-9d7a-6fbf9dbf07f2', 'title', 'Inimeste tarbimisharjumused');
