INSERT INTO core.text(id, content)
VALUES ('79311971-7774-4e08-b1fa-87cd5d4d0d86',
        'Aina rohkem ja rohkem on hakanud kasvama inimeste toidu ja rõivaste raiskamis harjumused. Visatakse minema toiduülejäägid, kasutustähtajast ületanud toit, korralikud rõivad jms. Inimesed ei tea ja mõista kui suur toidukadu protsent tegelikult on. Mida teha?\nInimeste tarbimisharjumuste muutmine pole lihtne, sest see on inimese harjumustes juba sees. Eesti kodumajapidamises tekib iga inimese kohta aastas keskmiselt 61kg toidujäätmeid, millest toidukadu moodustab 26kg. Toidu ära viskamisega ei raiska me ainult omaenda raha, vaid ka tohutult muid ressursse: maad, vett, energiat ja tööjõudu. Arvatakse  ka väiksemaid koguseid toitu ära viskavad inimesed, et sellega nad suurt pilti ei tee, mis on puha vale!\nSama probleem on rõivatega. Visatakse minema väga korralike riideid, aga ka sellised, mis kaunil reklaamfotol näevad ilusad välja, aga tegelikult koosnevad naftast ja ei taha seda rohkem kui üks kord kanda. Oluline on, et igaüks vaataks üle oma isiklikud tarbimisharjumused ning eelistaks kvaliteeti kvantiteedile ja mitte tellida Hiina veebipoodidest juba põhimõtte pärast asju.\nHetkel on ära visataud toidu ja rõivaste kaalukus suur, kuid selle muutmiseks võiks  iga inimene vaadata üle oma tarbimisharjumused ja neid üritada parandada. Tuleb vaadata kust, mida ja mis kogustes midagi osta või tellida, et ülejääk ei oleks suur. Koos saame muuta tarbimisharjumuste probleemid paremaks!');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('79311971-7774-4e08-b1fa-87cd5d4d0d86', 'title', 'Inimeste tarbimisharjumused');
