INSERT INTO core.text(id, content)
VALUES ('10236fc9-f590-47b2-97b2-501fb469aba5',
        'Me kõik teame, kui palju on tarbimist ja raiskamist maailmas. Prügihunnikud on meeletud ja see kõik jõuab lõpuks veekogudesse ja ookeanisse. Miks inimesed seda teevad?\nPaljud inimesed saavad endale lihtsalt lubada toidu raiskamist, samas arvavad ka väiksemaid koguseid toitu ära viskavad inimesed, et nad sellega ei mõjuta eriti midagi. See on vale!  Keskmiselt tekib iga Eesti inimese kodumajapidamises aastas 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg. Iga raisatud toit, mis mingil põhjusel jääb tarbimata ja visatakse toidujäätmena ära. Niimoodi ei raiska sa ainult enda raha, vaid ka elementaarseid ressursse: maad, vett, energiat ja tööjõudu.\nMida me saaksime teha, et seda vähendada?  Me peaksime hakkama sööma sellises koguses toitu, mida me jõuame ära ka süüa, et üleliigne toit raisku ei läheks. Prügisorteerimisele peaksime rohkem tähelepanu pöörama. Ning, kui vähegi võimalik, rohkem oma kasvatatud tooteid sööma.\nMoedisainer Eve Hanson ütleb, et noortele oleks vaja teha ekskursioon taaskasutuspoodide lattu. Mina olen sellega täiesti nõus. Ma isegi olen saanud mitu ilusat riiet kaltsukatest ja olen ka käinud taaskasutuspoodides. Ja kui tekib hetk, kus sa ise enam ei kanna neid riideid või on sulle väikesed, saad ka viia need edasi kaltsukasse ning anda nendele riietele uue elu!\nMa ei näe mõtet osta hirm kallist poest riideid, kui ma kas näid isegi ei kanna või unusta ära, et need mul üldse olemas on. Mida keskkonna sõbralikumad me oleme, seda parem on meile kõigile!');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('10236fc9-f590-47b2-97b2-501fb469aba5', 'title', 'Inimeste tarbimisharjumus');
