INSERT INTO core.text(id, content)
VALUES ('f2db3057-45b9-4e79-8794-70cdf2b05140',
        'Toidu- ja riietekadu on Eestis ja muus maailmas juba väga suur probleem,  mille vastu peaksime midagi tegema.\nOn inimesi, kes raiskavad toitu, sest nad saavad seda endale lubada. Samas arvavad ka, et nemad sellega suurt pilti ei mõjuta. Kodumajapidamises tuleb keskmise Eesti inimese kohta  aastas umbes 61 kg todujäätmeid, millest toidukadu moodustab 42% ehk 26kg. See suur kogus toidujäätmeid on kohutav ressurside nagu, vesi, maa, energia ja tööjõu raiskamine.\nToidu tootmine tekitab ka tõsise keskkonnakoormuse, sest saagikuse tõstmiseks kasutatakse väetisi ja teisi erinevaid kemikaale. On palju inimesi, kes näiteks lähevad restorani, ostavad midagi ja ei lõpeta oma söögi ära, aga kõik see toit visatakse ju ära.\nMoedisainerite arvates on oluline, et igaüks vaataks üle oma isiklikud tarbimisharjumused ning eelistaks kvaliteeti kvantiteedile. See on peamiselt selle pärast, et odavad Hiina tooted, mis on väga odavad ei ole kuigi kvaliteetsed ja enamasti on tehtud naftast, mis ära visates teeb loodusele kahju.\nTaaskasutuspoodide laod on siukseid odavaid rõivaid täis ja enamus inimesi neid osta ka ei taha, sest riie võib ilus välja näha, aga need enamasti ei ole kuigi mugavad ega kesta kuigi kaua. Sellepärast peaksgi ostma midagi kallmiat, aga vähemalt tead, et see kestaks teil aastaid.\nKokkuvõtteks järeldame, et  peaksime kõik vähem toitu ja riiet raiskama, sest see teeb keskkonnale väga palju kahju ja tekkitab taaskasutuspoodides suuri ummistusi.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('f2db3057-45b9-4e79-8794-70cdf2b05140', 'title', 'Toidu- ja Riietekadu');
