INSERT INTO core.text(id, content)
VALUES ('33d8e3e6-03a6-4102-953f-aebb830c23a8',
        'Tänapäeval raisatakse väga palju asju näiteks toitu või riideid. Paljusid asju saaks taaskasutada või müüa maha ning sellest oleks palju rohkem abi. Toodete ära viskamine on juba paljude inimeste harjumustes kinni.\nToitu läheb väga palju raisku ning pinimesed ei näe selles probleemi, sest arvavad et see ei mõjuta midagi. värske toidu ära viskamisega tekib liiga palju riknenud toitu ning sllega raiskad sa ka enda raha ning teisi ressursse näiteks vett või maad. Paljudel inimestel on tekkinud see kombeks et visata ära toitu mis on vell värske, sest neil ei ole isu seda süüa. Todu raiskamise peatamiseks peavad inimesed sellest osa võtma ning vähem raiskama.\nPeale toidu on ka teisi tooteid mida raisatakse palju näiteks riided mida oleks reaalsuses väga lihtne säästa. Riiete põletamise ja ära viskamise  asemel võiksid näiteks anda suguvõsas edasi või jagada neile kellel päriselt vaja on. Katkised rõivad mis ei ole enam kantavad võid annetada või müüa firmadele kes on nõus seda taaskasutama ja sellest mida uut tegema. Pole mõtet osta odavaid riideid hiina veebipoodidest, sest need lähevad kiiresti katki ja teevad olukorda hullemaks.\nKokkuvõtteks võiks me kõik proovida rohkem säästa tooteid ja neid taaskasutada raiskamise asemel, sest see on parem meile ja ka meile maailmale.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('33d8e3e6-03a6-4102-953f-aebb830c23a8', 'title', 'inimeste tarbimisharjumused');
