INSERT INTO core.text(id, content)
VALUES ('fbc8bb2d-6511-4668-82d9-7f333ab0ba4a',
        'Miks raiskavad inimesed nii palju? Eesti inimese kohta tekkib 61 kg toidujäätmeid. aga miks? Sest inimesed arvavad et toitu on veel ja saab juurde osta.\nToidu raiskamine on igas majapidamises suur, kas midagi läks välesti või jäi alles see läheb kõik viskamisele.Mõned teevad selle biojäätmeteks, aga linnas on rohkem kus ära vistakse.Inimesed ei oska hinnata kui palju toidu neil vaja on. Otsavad nii palju kui arvavad ja, siis unustavad külmkappi ja see läheb pahaks.Inimene võiks osata arvada kui palju naad umbes teevad, pigem tee vähem kui rohkem,sest juurde saad alati teha. Samas on ka riietega nii.Kui jääb väikseks vistatakse ära, või lausa põletatakse.Samas viiakse need poodidese kes võttavad vastu. Iga nädal tekkib sinna aina rohken ja rohkem riideid.Inimesed ostavad endale üleliia riideid mida naad võivad kanda ainult ühe korra ja, siis enam ei kanna.inimesed ostavad riideid Hiina poodidest kus on riided tehtud naftast ja seda on halb kanda.Parem osta kvaliitetsem ese mida kannad mittu korda.\nToidu raiskamine on üks suur probleem terves maailmas mida on raske üleööga ära kaotada.samas on ka riide probleemid.Ostavad ühe asja kannavad seda ühe korra ja siis enam ei kanna ja viskavad minema.Inimesed raiskavad nii palju ja naad ei saa sellest aru.');
