INSERT INTO core.text(id, content)
VALUES ('a7f2dcb6-b147-4b88-9ad0-79a09da3f99b',
        'Tänapäeval üheks väga suureks probleemi allikaks on näiteks rasikamine toitu, maad, vett, energiat ja sealhulgas ka raha, riideid. Iga aasta tekib meeletus koguses toidu jääke ja prügi ühe inimese kohta. Sinna prügi hulka kuuluvad ka riided.\nKuna tänapäeval- toodakse ja viiakse igasse riiki toidu kaupa, siis hetkel meil sellest väheks ei jää ning inimesed viskavad rahuga toitu minema, mis ülejäänud. Isegi need inimesed, kes vähem võibolla toitu rasikavad muudavad palju, sest toidu kasvatamiseks ja suurema saagi saamiseks kasutatakse erinevaid väetisi, mis kahjustavad meie maad.Veel üheks suuremaks probleemiks on riiete ära viskamine ja raiskamine. Pidevalt ostavad paljud inimesed ja noored endale koju väga palju riideid, mida ei pruugi isegi rohkem kui üks kord kanda. See tekitab suure koguse terveid vanu riideid, mis viiakse kas taaskasutus organistatsiooni või lihtsalt visatakse ära. Just see on kõige valem tegu.\nNeed kõik tegevused väga kahjulikud paljudes erinevates olukordades. Pikemas perspektiivis võib maade väetamine olla kahjulik nt veele, maale jne. Pidevalt uute riiete ostmine ja vanade ära viskamine tekitab rohkem prügi. Inimesed peaksid õppima toitu ja riideid säästma ning taaskasutama. Tegelikult loeb ikkagi iga inimese samm, sest kui lõpuks iga inimene maailmas hakkab hoolsam oma toidu ja vara suhtes olema, siis väheneb tootmine ja rasikamine iga asja suhtes.');
INSERT INTO core.text_property(text_id, property_name, property_value)
