INSERT INTO core.text(id, content)
VALUES ('f8f8ed58-f7ed-47fb-86b1-82fe88f376b9',
        'Praegu on väga päevakohaseks teemaks inimeste tarbimisharjumused. Kas jälgitakse kui palju ressursse ära visatakse, olgu need toidujäätmed, vanad riided või muu? Kahjuks mitte eriti.\nEnamuste jaoks on toidu ära viskamine enamjaolt igapäevane tegevus. Kui toit jääb üle, läheb halvaks, siis mis ikka sellega teha? Me saame minna poodi ja osta uue. Saame endale seda lubada ja paljud isegi ei mõtle, kui palju toiduaineid niimoodi raisku läheb. Kui aga võtta hetk asja uurimiseks, leiad, et kogused on ilmatu suured.  Me ei saa loomulikult päeva pealt neid arve muuta, aga me saame anda oma panuse, kui jälgime oma toitumisharjumusi ja püüame neid parandada.\nSuureks probleemiks on ka rõivaste liigne ostmine. Vaadatakse kõike hinna järgi. Hind on enamasti madal põhjusega. Riiete kvaliteet ei pruugi olla hea, kauplus ei pruugi olla eetiline. Kuid see on paljude jaoks teisejärguline. Riiete tootmine vastavalt sellisele nõudlusele kahjustab meeletult keskkonda. Nagu alati, saab ka seda probleemi parandada alustades iseendast. Jälgi kus sa ostled, eelista teiseringikaupluseid. \nÜletarbimine on tänapäeva ühiskonnas suur probleem. Võime mõelda, et ega me üksi ikka midagi ei muuda, kuid kõik hakkab just iseenda muutmisest. Jälgi oma tarbimisharjumusi nii söögi, riiete kui ka kõige muu puhul. Kui sina suudad end muuta, näevad ka teised, et see on võimalik. Ja nii püüdleme me koos parema maailma suunas.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('f8f8ed58-f7ed-47fb-86b1-82fe88f376b9', 'title', 'Inimeste tarbimisharjumused');
