INSERT INTO core.text(id, content)
VALUES ('239ac721-7cb6-4745-a454-aa2ac0b29ba4',
        'Inimestel on väga erinevad harjumused asjade kasutuse poolest. Mõned on väga kokkuhoidvad ja üritavad maad päästa, teised aga ei hooli oma tarbimiskasutuse mõjudest üldse. On mitmeid erinevaid valdkondi, kus saab kokku hoida.\nÜks suurimaid muresi tänapäevel ja kogu ajaloos on nälgimine. Kuigi meil ei pruugi seda väga olla, siiski on kolmanda maailma riikides väga suur toidu puudus. Massiline põhjus selleks on raiskamine. Paljud restoranid, poed ja tehased viskavad aastas tonne ning tonne täiesti söödavat söögipoolist ära. Peredes antakse laste poolt ülejäänud toit koerale. Näiteks Maxima asustustes visatakse iga päev kõik mitte müüdud saiakesed ning pirukad minema, kuigi need on veel täiesti söödavad. Söögi valmistamiseks kulub aastas tohutult ressursse – vett, tööjõudu, raha, maad.\nKoht kuhu ka aastas suur osa ressursse läheb, on rõivatööstus. Õnneks on viimase sajandi jooksul aina rohkem hakatud töötama selle poole, et rõivaid taaskasutada. Noori peaks hakkama viima eksursioonidele ladudesse, kus neid vanu rõivaid tehakse jälle uueks. Massiline osa riidetööstusest on ebasäästlik, sest riideid tahakse teha odavalt ja kiirelt. Inimese kehale meeldivad looduslikest ainetest tehtud rõivad palju paremini. Näiteks spordibränd Breath Divinity teeb oma riideid suures protsendis taaskasutatud rõivastest.\nInimkond saab iga aasta aina lähemale keskkonnasõbraliku elu poole, aga selleks peame me ka ise panustama. Ära viska kõlbliku riiet või söögipoolist ära, vaid taaskasuta seda.');
INSERT INTO core.text_property(text_id, property_name, property_value)
