INSERT INTO core.text(id, content)
VALUES ('e76dcbf9-47ae-45a1-9e7a-287cff8dc59d',
        'Väga paljud inimesed tarbivad meeletult asju mida neil tegelikult vaja ei ole aga nad ise ei tea seda. Maailmas on väga palju asju ning on väga raske keelduda millestki maitsvast või neile meeldivast asjast. Inimesed peaks enne ostmist mõtlema mida neil kindlalt vaja on ja mida ei ole, et asjadega liiga hoogu ei minda. Tänu mitte asjade selgelt läbi mõtlemisele on meil väga palju probleeme.\nInimesed ostavad tihtipeale asju mida neil tegelikult vaja ei ole, nad lähevad näiteks toidu poodi ja ostavad sealt endale kõike mida neil tegelikult vaja ei ole ja mille pärast nad tegelikult poodi ei läinud olgu see siis kommid, pirukad, riided või palju muud mis neil silma jääb. Igas poes on erinevad ja ilusamad asjad, mis inimesi mõjutavad ning neil on raske asjadele ei öelda. Kõik inimesed peaksid enne poodi minemist mõtlema selgelt läbi mida neil kindlalt vaja on, et nad liiga hoogu ei läheks ja ei raiskaks liigselt raha. Sellega kaasnevad väga palju probleeme. Inimesed raiskavad väga palju toitu, näiteks võtavad liiga palju süüa ja viskavad ära. See ei raiska ainult meie omaenda raha vaid ka tohutult muid ressursse:  maad, vett, energiat ja tööjõudu. Meil on ka väga palju prügi kuna inimesed viskavad prügi maha.\nMina enne poodi minemist mõtlen enne läbi mida ma ostan, et mitte raha raisata ja tekitada palju prügi. Inimesed võiksid enne poodi minemist mõelda mis neil vaja on ja võtta aind niipalju raha kaasa kui nad on arvestanud.');
