INSERT INTO core.text(id, content)
VALUES ('6f4a6135-eb1e-4bf0-b944-6dc8468b705b',
        'Miks inimesed ostavad liigselt asju, mida nad hiljem ei tarbi? Miks on vaja kõige kallimaid riideid osta, mida ühe korra kanname? Inimesed ostavad palju, aga tarbivad vähe. Kuidas seda parandada?\nOstes endale kõige popimad ja kallimad riided, tekitad suurt kahju ühiskonnale. Me ostame endale riideid (lõpukleidid, ballikleidid, ülikonnad jms), mida me hiljem enam ei kanna ja viskame ära. Selle asemel, et endale riideid kaubanduskeskustest või internetist osta, võiksime me hoopis osta neid taaskasutuspoodidest. Mõnikord ehk sõbral või sugulasel on riideid, mida ta ei kanna ja saad hoopis need endale võtta. Endal riideid üle jäädes saad need viia kaltsukatesse, sealt on kõige parem väga normaalseid riideid osta.\nToitu raisatakse ilmselt veidi rohkem. Endalgi ei ole mõnikord kõige suurem isu enda tehtud toidu järele, kuid ära viskamine ei ole lahendus. Võib-olla on sul mõni naaber, kes heameelega sooviks kartulit ja hakklihakastet süüa või kutsud mõned sõbrad ja sõbrannad külla, et nad ei peaks peale rasket päeva endale koju süüa tegema minema.\nToidu raiskamine ja riiete ära viskamine või põletamine ei ole hea lahendus. Mõtle terve maailma peale ning arvesta ka muude elusolenditega. Kaltsukad on alati avatud ja sõbrad, perekond või naabrid ei ütleks iialgi ei ühele heale kodus tehtud toidule.');
