INSERT INTO core.text(id, content)
VALUES ('9bbebd06-1809-4431-ba5c-68f50259f1a0',
        'Tänapäeval on suureks probleemiks ületarvitamine. Ükskõik, kas see on seoses toidu- või moemaailmaga. Inimesed on harjunud sellega, et saab kohe poest uue pluusi, kampsuni, šokolaaditahvli või ükskõik mida muud osta.\nTihtipeale visatakse toitu ära, sest inimestel on eelnev harjumus ja teadmine, et seda saab kohe juurde. Näiteks, eelneva õhtu õhtusöök, mis on üle jäänud visatakse ära, sest see on „roiskunud“, kuid seda saaks mitu päeva veel süüa või isegi teisteks roogadeks teha. See probleem on jõudnud sinnamaani, et aastas 61 kg toidujäätmetest 42% on täiesti kõlblik toit.\nSarnane probleem on riietega: kiirmoe kauplused toodavad riideid suuresti lähtudes sotsiaalmeedia moetrendidest. Need moetrendid muutuvad praktiliselt üleöö, mis tähendab, et see mis eile võis vägev ja trendikas olla, on täna äraviskamis kõlblik ja totaalselt trendist väljas. Üks suur probleem nii moe- kui ka üldises kaubanduses on see, et tihti ostetakse odavaid asju Hiina veebipoodidest, mille kvaliteet ei ole kõige parem. Selle tõttu satub taaskasutuspoodidesse lausa mägedeviisi „vanu“ riideid. \nMüügimaailmas on välja arenenud arusaam, et on mõttekam osta ja tarvitada kohalikku kaupa kui suurt jaekaupa. Sellest paratamata on inimesed muutunud väga harjunuks meie kaasaaegse maailma tõttu. Suurem osa inimesi- eriti need, kes linnades või linnade lähedal elavad, eksisteerivad teadmisega, et kõike on kohe poest saada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('9bbebd06-1809-4431-ba5c-68f50259f1a0', 'title', 'Ületarvitamine ühiskonnas');
