INSERT INTO core.text(id, content)
VALUES ('29708d9a-f788-4bb7-ba40-9672c020fc5c',
        'Tänapäeval on väga lihtne tarbida rohkem kui me tegelikult vajame. Toitu ostetakse suure varuga, sest „äkki läheb vaja“, ja riideid koguneb kappi nii palju, et osa neist jääbki kandmata. mõnikord me ei mõtle, mis juhtub selle üleliigsega, kuhu see lõpuks jõuab ja kuidas see meie maailma mõjutab.\nToidu raiskamine ja niisama ära viskamine  on üks suurimaid probleeme. Me harva märkame, kui palju toitu tegelikult ära viskame, aegunud piimapakk, halvaks läinud puuviljad või isegi taldrikule jäänud toit. Samas on maailmas palju inimesi, kes nälgivad, on väga vaesed või isegi kodutud, kellel pole piisavalt süüa. Kui me ostaksime täpselt nii palju kui meil vaja on, ei läheks ka nii palju toitu raisku. Sama on ka riiete kohta. Mood muutub kiirelt ja odavaid riideid on lihtne osta, kuid paljud neist ei pea kaua vastu või muutuvad koledaks ja need visatakse varsti ära. Targemad ja kogenumad disainerid soovitavad pigem eelistada kvaliteetseid ja kauakestvaid rõivaid ning kasutada rohkem taaskasutuspoodide võimalusi.\nMeie tarbimisharjumustel on suur mõju keskkonnale ja teistele inimestele, kui me oleksime natuke teadlikumad sellest, mida ja kui palju ostame, saaksime vähendada jäätmeid ning muuta maailma paremaks paigaks. Väikeste muutustega saab iga inimene midagi head korda saata siin rohelisel planeedil.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('29708d9a-f788-4bb7-ba40-9672c020fc5c', 'title', 'Kas me tarbime liiga palju?');
