INSERT INTO core.text(id, content)
VALUES ('6f85a0c7-14b5-4144-8615-1d47911e2735',
        'Inimesed üle maailma tarvitavad palu erinevaid tooteid ja palju sellest jääb üle ja visatakse ära. Probleem on sellest, et üleliia jääb tooteid üle, mis siis visatakse ära. Kaks suurimat probleemi on touduraiskamine ja kanga/riiete üleliigne tarbimine.\nToiduraiskamine on suur probleem. Inimesed arvavad, et kui viskavas näiteks eilse lõuna jäägid ära siis läheb raisku ainult nende raha. kuid tegelikult läheb raisku ka: maad, vett, energiat ja tööjõudu. Toidu raiskamine liikide Elupaiki. Kuna, et kasvatada süüa on vaja maad ja maad saab kui vötad puid maha.\nRiiete üle tarbimine on ka suur probleem. Kui lähed taaskasutus poodidesse ja vaatad mis neil laos on siis on näha kui palju riideid on lihtsalt ära visatud. neid riideid mis on ära antud või ära visatut on tavaliselt ainult korra kantud. Enamus kiirmoe riideid ostetakse Hiina kaubamajadest mis ei ole kvaliteetsed ja on ebamugavad ja kannad ainult korra. Et seda probleemi muuta tuleks pigem eelistada kvaliteeti ja oma kodumaa tooteid ja mitte osta Hiina suurtööstustest kus pooled riided on naftast ja on ebamugavad kanda. \nKokkuvõtteks ütlen, et kui ostad midaki siis tarbi enne ära kui uue ostad. See kehtib nii toidul kui ka riietel. Jpigem osta Kodumaiset toodet ja kaupa kui Hiina kaupa mis ei ole kvaliteetne.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('6f85a0c7-14b5-4144-8615-1d47911e2735', 'title', 'Inimeste ületarbimine');
