INSERT INTO core.text(id, content)
VALUES ('d4ffc580-7915-423a-8b78-40b9d020ab8d',
        'Inimesed ostavad palju tootied, mida neil päriselt vaja pole. See on suureks probleemiks, kuna me näeme ja ostame, mis võib meil kodudes olemas olla. Kauplused on suured ning seal on kõike mida sooviksime osta. Paljud lähevad lihtsalt poodidesse, sest neil on igav ja tahaksid midagi uut osta. Sealt tulevad inimestele halvad tarbimisharjumused.\nTehased toodavad iga aasta hunnikutes tooteid, mis jäävad poolel ajal kasutamata. See mõjutab meie ökosüsteemi, kui igal aastal tuleb tehastest prügi, mida ei ole puudutud ega kasutatud. Meie maal pole ruumi selle prügi jaoks, mistõttu rikkub see hapnikut ja loodust. Prügi on proovitud visata atmosfääri, aga see võib ohtlik olla. Paljud põletavad oma liikset prügi, millest tuleb välja mürgiseid ained, mis võivad olla eluohtlikud.\nEva Hanson arvab on oluline, et igaüks vaataks üle oma isiklikud tarbimisharjumused. Iga aasta tuleb riidepoest välja uusi moode ja rohkem riideesemeid. Selle pärast viskame me kõik meie vanad riided välja, et uued sisse tuua. Kõik need vanad riided lähevad raisku, mis võivad olla veel kvaliteetsed. Paljud vanad riided ja asjad lähevad taaskasutuspoodidesse, kus oleks kõige parem. Meie ühiskond võiks taaskasutuspoodides rohkem käia. Sealt saab ka häid riideid ülga odavamalt.\nEva Hanson ütles „Ma arvan, et peaks hakkama noortele tegema ekskursioone taaskasutuspoodidesse, et näidata, milline raiskamine toimub.“ Ma olen sellega nõus, kuna mõned noored ei sa aru, kui palju me tegelikult raiskame.\nMeie ühiskonnana peaksime vähem raiskama oma raha asjade peale, mida meil päriselt vaja pole. Võiksime me rohkem taaskasutuspoodides käia ning inimesed võiksid rohkem aidata prügi korjamisel.');
INSERT INTO core.text_property(text_id, property_name, property_value)
