INSERT INTO core.text(id, content)
VALUES ('b4b1e831-ec11-47e7-9f1a-0681a494941e',
        'Maailmas on kahjuks väga palju reostamist ja ületarbimist. Selle tõttu on ka tekkinud kliimasoojenemine. See toob kaasa näiteks väga sooja õhu ja lume sulamise talvel, loomade vähenemise väiksete ressurside tõttu ja nii edasi. Meil on kõik maailmas väga lihtsasti kättesaadav, aga kahjuks me ei mõtle, kas meil seda vaja on.\nToidukahu ehk raisatud toit või toiduaine, mis jääb tarbimata ja visatakse toidujäätmena ära. Inimesed ostavad liigseid toiduaineid järgmiste asjade pärast: huvitavad maitsed, ilusad pakendid, head hinnad. Selle tõttu me raiskame oma raha, sellest mitte aru saamata. Ja muidugi see teeb ka meie planeedile liiga.\nMeile inimestele on palju ressurse antud meie planeedi poolt, aga kahjuks me ei väärtusta neid. Kui me juba enda raha raiskame liigsete toodete peale, siis loomulikult mõjutab see ka meie elukonna ressurse. Ja kui me nii edasi jätkame, siis pole ma üldse kindel, et kas meie planeedist jääb midagi järgi. Kõige rohkem näiteks raisatakse näiteks meie ressursidest: maad, vett, energiat ja tööjõudu.\nRessurside raiskamine on juba omajagu vägagi suur probleem. Aasia riikides kasutatakse vägagi palju lapstööjõudu. Enamasti järgmistes kaubamärkides: Shein, Temu ja Aliexpress. See võib ka lisaks ressurside vähenemisele tuua kaasa ka populatsiooni vähenemise.\nKokkuvõtteks meie maailm on nukras seisus, mida me arvatasti ei saa lähiajal muuta. Kõik need ressurside vähenemised, lapstööjõu kasutamised, toiduainete ja riideesemete ületarbimised ja ka kliimasoojenemised. Nende kõige järeldus on maailma reostamine. Aga põhjendus on see, et raha on vaja.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('b4b1e831-ec11-47e7-9f1a-0681a494941e', 'title', 'Maailma reostamine');
