INSERT INTO core.text(id, content)
VALUES ('4fba0ed3-7d98-4a90-9b7f-c8f8bd2fa428',
        'Tänapeval on probleem, et inimesed ostavad ja raiskavad liiga palju asju. See teeb muret, sest maailma koguneb liiga palju mitte vajalikku kaupa, raiskavad palju ja see suurendab mitte vajaliku kauba suurenemist. Mul ise on kahju, et ni tehakse, sest see on loomadele ja loodusele halb ja see näitab, kui palju inimesed maailmast hoolivad.\nInimeste põhi asjad mida raisatakse on toit ja riided, inimesed raiskavad aastas 42% ehk 26kg toitu tarbittoitutargalt.ee/toidukaost/ andmetel. See jääb kasutamata ja visatakse ära. Sellega raiskame raha, maad, vett, energiat ja tööjõudu. Minu peres väiksemad õed ja vend raiskavad tihti toitu, nad ei söö ära seda või tahavad midagi, aga unustavad ära selle toidu ja jääbki söömata. Mu pere proovib osta toitu ni, et kõik saaks söödud ja tarvitatud.\nKa riideid ostatakse ja tellitakse liiga palju ja, siis visatakse ära või viidakse taaskasutuskeskustesse. Inimesed tellivad ja ostavad nii palju, et taaskasutuskeskused on riideid täis ja jäävad ka üle. Inimesed võiksid vähem välismaalt tellida ja jääda kodumaisete riiete ostmisega. Minu peres on piisavalt, ei ole liiga vähe ega palju, kuid me vahest tellime, aga see on ka harva. Kõikides peres võiks ni olla, siis ei tekiks üleliigseid riideid.\nJäreldus on see, et inimesed peaksid vaatama, kui palju asju nad ostavad, et midagi raisku ei läheks. Ni on kõigil parem ja kasulikum elada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('4fba0ed3-7d98-4a90-9b7f-c8f8bd2fa428', 'title', 'Inimeste tarbimisharjumused');
