INSERT INTO core.text(id, content)
VALUES ('5b8e1692-8a7f-4f45-a3c5-32a3b82a6390',
        'Tänapäevl on kauplustes võimalik osta kõike, mida soovid sellist nagu toitu, tööristad ja elektroonika ja veel paljuid asju. Probleeme ka on inimesed peavad rohkem raiskama raha kui tuled poodi, sest poes on nii võrd palju kõike, et sa tahad kõike osta. On ka neid, kes säästavd raha ja ei osta kõike mis näevad.\nInimesed ei arvesta, kui palju nad toitu ära söövad ja ostavad poest neid toiduaineid, mida neil pole vaja. Siis neil jääb see toit alles see hakkab halvaks minema või mõned ei söö kõik töidu ära ja viskavad selle prügikasti. Inimestele tundub, et toitu on palju ja see ei saa kunagi otsa on ka neid, kes raiskavad toitu ehk nad saavad seda endale lubada ja, et  sellega suurt kahju ei mõjuta. Kodumajapidamises tekib iga Eesti inimese kohta aastas umbes 61 kg toidujäätmeid, mille toidukadu moodustab 42% ehk 26 kg toidu kadu, kus inimesed on ära visanud rikenud või kasutustähtaja ületunud toit. Seetõttu ei raiska ainult oma enda raha kuid ka tohutult muid ressursse: vett, energiat ja tööjöudu.\nMiks inimesed nii käituvad? Selle pärast, et meie poedes on palju reklaami ja telekas on seda nii palju inimesed vaatavad selle peale, et uus toode või midagi on allahindlusega. Pärast tuleb välja, et see toit ei meeldi või, siis nad ostavd nii võrd palju toiti, mis ei ole nii tähtis ja viskavadki toidu ära näiteks minu peres ei ole seda ostetakse seda toitu mid aon vaja.\nMinu arvates pekasid inimesed vaatama, kui palju toitu nad ostavad poes, et poleks vaja palju seda ära visata.');
