INSERT INTO core.text(id, content)
VALUES ('40156f4f-13c8-4651-99d0-785d0ef0ebc0',
        'Tänapäeva inimestel on väga suur tarbimisharjumus, mis tähendab, et nad ostavad palju asju, isegi neid, mida neil vaja pole. Kuid siiski, miks see küll nii on?\nEnamasti on see selle pärast, et inimesed ostavad palju silmadega tänu erinevatele pakenditele, mis neid asju ostma paneb.\nKuna tänapäeval on paljudel väga suur tarbimisharjumus ostavad nad palju asju, mida neil vaja ei ole ja lõppkokkuvõttes lähevad need asjad ikkagi raisku, jäevad need lihtsalt seisma või ei lähe kasutusse.\nNende erinevate pakendite tõttu, mis samuti panevad neid asju ostma, mida neil tegelikult vaja ei lähe. Samuti paneb inimesi asju ostma reklaamid, kus kirjeldatakse neid asju nagu midagi uut ja veel paremat. Ja, mis mind ennast kõige rohkem häirib nende asjade juures on see, et inimesed ostavad kõike, mis on allahindluses või soodushinnaga. Näiteks minu perekonnas seda probleemi ei ole, aga tean küll selliseid peresid, kus selline probleem paraku on. Samuti on ka riietega, inimesed ostavad riideid, mida neil tegelikult vaja ei lähe ja, mida nad ilmselgelt mitte kunagi ei kanna samuti ja lõpuks jõuavad need asjad siiski, kas äraviskamisele või müüki.\nNüüd selleks, et seda probleemi ära hoida on vaja inimestel aru saada, et kõik, mida nad reklaamides või allahindlustes näevad ei tasu kohe ostma hakata, kuna need võivad minna raisku või ei lähe üldse kasutusse.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('40156f4f-13c8-4651-99d0-785d0ef0ebc0', 'title', 'Tänapäeva inimeste tarbimisharjumused');
