INSERT INTO core.text(id, content)
VALUES ('e10050de-7307-42a3-a232-fb73317558e2',
        'Inimestele on tänapäeval asjade kättesaadavus tehtud liiga lihtsaks. Palju kaplused, kust saame osta kõike. Asjade lihtne kättesaadavus tekitab asjade ülekülluse, mille tõttu viskame kõik alles- või ülejäävad asjad ära. Mida saaksid kõik inimesed teha, et oleksime säästlikumad?\nToidu ära viskamine on inimeste jaoks elementaarne. Saaksime ülejäägi säilitada külmkapis ja süüa seda siis, kui ei viitsi ise mingil päeval süüa teha. Veel saaksime jälgida, millises koguses toitu teeme, olla teadlik palju ise ära sööme. Alles jäänud toidu või toiduained saaksime viia kohalikku toidukappi või anneteda toidupangale.\nInimesd tellivad tihti uusi riideid Hiinast. Tihti ei mõtle me selle peale, et sealt tellitud odavad asjad ei pruugi olla kvaliteetsed. Nagu ütles Eve Hanson: „on oluline, et igaüks vaataks oma isitlikud tarbimisharjumused ning eelistaks kvaliteeti kvantiteedile,“ ja ma arvan et me kõik võksime sellega nõustuda. Me võikime hiinast tellimise asemel käia taaskasutuskeskustes, sealt võime leida samu või veel paremaid asju.\nKõik see toidukadu ja raiskamine kujutab ohtu meie keskkonnale. Hiinast teise riiki toimetatavd asjad tuuakse kohale suurte kaubalaevadega, millest satuvad meie oma Läänemerre väga palju kahjulikke Kütuseid, mis kahjustab mereloomi. Sama lugu on toidu tootluses, kus väetatakse põlde ja mürgitatakse mis paiskab loodusesse samuti palju kahjulike aineid.\nInimestel on palju viise, kuidas olla säästlikumad. toiduga saab peale hakata nii palju muud kasulikku, kui see ilhtsalt ära visata. hiinast tellitud riietega on sama lugu. me võime leida kvaliteetseid riideid ka oma kodumaalt ja saaksime ise teha väikese panuse ületarbimise ja raiskamise vähendamiseks.');
