INSERT INTO core.text(id, content)
VALUES ('53841851-8e76-48ab-83f6-c949a36aaf8d',
        'Tänapäeval on tekkinud suur probleem toidu raiskamisega, kus inimesed ostavad poes palju üleliigseid toite mida nad lõppuks ära viskavad kuna keegi neid ei söö. Praegu ühe inimese kohta on keskmiselt 26 kg toidujäätmeid ja see on suur katastroof kuna toidu raiskamist ei saa vähendada üleöö.\nInimesed on harjunud osta liigseid toite mda nad lõppuks ära viskavad, kuid inimesed ei saa aru kui tähtis see produkts on. Selleks, et saada ühe leiba peab olema arenenud põllumajandus sektor, et vajalik kogus saaki saada. Seetõttu ei raiska me ainult omaenda raha, vaid ka tohutult muid ressursse nagu näiteks on maa, väetis, küttus tööjõud, masinad ja energiat.\nToidu raiskamise tõttu suureneb keskkonnakoormus kuna mida rohkem inimesed raiskavad seda rohkem on vaja uut toota sellega suureneb küttuse, raskeõlide kasutamine ja ka suurma saakide saamiseks väetised mis ise reostuvad meie keskkonna. Põllud muutuvad halvaks kuna naad ei saa piisavalt puhata, kuna nende peal kasvatatakse iga aasta tohutult kultuure. Lõpuks põlde võib jääda väheks ja inimesed alustavad metsa raiuma, et uusi põlde saada. Lisaks tekitab toidu tootmine tõsise keskkonnakoormuse, sest saagikuse tõstmiseks kasutatakse väetisi ja erinevaid kemikaale.\nToidu raiskamine on tõsine teema mis puudutab meie tuleviku. Selleks, et meie tulevik oleks hea ning positiivne peame me toidu raiskamis teemasse tõsiselt suhtuma ja kõikide võimalustega vähendada toidu raiskamist.');
