INSERT INTO core.text(id, content)
VALUES ('55e1fddf-777d-47b1-9670-e45e2ac006e8',
        'Kallid hinnad on põhjus, miks inimesed on hakanud odavamaid alternatiive otsima. See toob endaga kaasa omamaisete toodete edukuse languse ja teiste riikide kauba populaarsemaks saamise. Kuid kui tõsine probleem see tegelt on?\nViimati on poodides hinnad lõputult tõusnud, ning inimesed, kes teenivad miinimumpalka ei saa enam tavatooteid endale lubada. Välismaast tulnud toidukaubad on aina populaarsemaks läinud ning elektroonikatooteid, väikeste laste mänguasjad ja riideid on hakanud inimesed Hiina veebipoodidest ostma. See tähendab seda, et Hiina on ülemaailmse marketi varsti üle võtmas.\nOdavamad alternatiivid on aina suuremaks probleemiks tänapäeval saanud. Laste mänguasjade tegemiseks on kasutatud ohtlike kemikaale ja materjale. Elektroonikatooted on odavalt ja ebatäpselt tehtud, mis võib põhjustada selle seadme plahvatuse või põlemise. Rõivaste tegijatele makstakse Hiinas väga vähe palka, ning toidukaupadel on inimesed saanud raske toidumürgituse. \nSee on tõsine teema, mis vajab kiiret lahendust. Inimesed saaksid teha taustakontrolli sellest firmast või ettevõttest, kust nad asju ostavad. Kui tegemist on ettevõttega mis toodab kaupu odavate ja ohtlike ainetega, tuleb otsida mõni teine firma. \nKokkuvõtteks, odavamad tooted on hakanud inimestele aina rohkem ja rohkem meeldima, kuid paljud ei tea nende toodete negatiivseid tagajärgu. Kas mõni elektrooniline seade plahvatab, või laps saab mänguasjast mürgituse, võimalusi on kahjuks palju. Seepärast, võiksid inimesed taustakontrolli teha ja olla kindlad, et kas nad ikka soovivad teatud toodet sealt osta, või otsida mõni muu pood, mis müüb sarnast toodet.');
