INSERT INTO core.text(id, content)
VALUES ('69ee96b3-5987-4224-a998-5d85c5d81513',
        'Mida aeg edasi seda ükskõiksemaks muutub osa ühiskonnast ja sellega muutub ka meie keskond. Olenevalt sellest kui paljud proovivad näidata, et soovivad teha ümbritsevat keskonda paremaks just reostavad teadmatult. Ostes suurtes kogustes halva kvalieediga toitu, rõivaid ja muid aksesuaare on võimalus, et viskad minema rõivad mis kiiresti kuluvad ja toit mida ei jõua tarbida. \n   Pragusel hetkel meie maal on plajuid tööstusi ning asutusi mis toodavad suure valikuga kraami mida vahest pole isegi vaja. Kahjuks aga enamus nendest toodetest on halva kvaliteedi ja kiiruga tehtud just selleks, et suurendada sissetulekut. \n   Majanduse ülesehitus on vigane ning seda tuleb parandada harides neid kes ei tea või puudub teadmine. Toidu, kosmeetika, rõivaste, ja muude vidinate harude suuremad asutused kasutavad ära inimesi, reklaamides vahest valeinfot. Tihtipeale on ka trabjad need kes on ükskõiksed ja ei hooli keskonnast.\n  Harimata keskond pole hea keskond ja lõppuks kaevame endale nii sügava augu, et on võimatu välja saada. Kui vaatame probleemi esiplaanilt siis jah tundub nagu ühe inimese panus täiesti kasutu või, et peab nii palju tegema muutuse tekkeks. Päriselt ei pea palju tegema, kõige lihtsam on enne poodi minekut teha nimekiri ainult vajalikest asjadest, mitte osta üleliigselt ninni nänni lihtsalt sellepärast et soodustus on ja sorteerda prügi. \n    Üleültse on meie laiskus ja ahnus tekkitanud sellised probleemid, harimatta inimesed kes ei tea kuidas aidata kaasa või säästa. Peame kõrvale heitma oma mugavusest ja hajumustest praegu, sest muidu pole tuleviku kus saaksime õnnelikult elada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('69ee96b3-5987-4224-a998-5d85c5d81513', 'title', 'Harjumus ja ahnus rikkub heaolu');
