INSERT INTO core.text(id, content)
VALUES ('2203fe82-c734-4804-bee6-7a5045d597bf',
        'Umbes viiskümmend aastat tagasi oli maailm täiesti erinev meie tänapäeva omast,  mitmeid tegurid on kujundanud välja meie praeguse ühiskonna ja eluviisi. Kas tarbimisharjumused on üks nendest? Kas on üldse tarvis õpetada tuleviku põlvkondi tarbimisharjumusdest ja kuidas need võivad meie maailma mõjutada.\nTarbimisharjumused on viimase kahekümne aasta jooksul muutund päris aktuaalseks teemaks paljude eestlaste elus. Selle põhjuseks võib olla uued uuringud raisatud toidu kohta ja kuidas Hiinas pannakse peaaegu igapäev uus tööstus püsti, mis tekitab maailma rohkem heitgaase ja kehva kvaliteediga riideid mis ei ole inimese kehale head. Sellega võime kindlustada, et tarbimisharjumused on üks suur probleem meie tänapäeva maailmas ja see laieneb igapäev halvema poole.\nTarbimisharjumuste pealt vaadates võib tunduda nagu meie maakera on mitmekümne aasta pärast suur prügi väli, aga õnneks me tegeleme selle vastu. Tänapäeval on juba mitmeid liikumisi ökosõbralikuma maailma poole ja seda on hea näha. Eestis on läinud moodi vabrikus töödeldud ja keemilisel viisil valmistatud toodete asemel osta pigem isevalmistatud või kodutehtud tooteid, kuna need ei reosta loodust nii palju kui suured vabrikud.\nNoored on suur osa meie ühiskonna heaolekust ja kuidas see tulevikus hakkama saab. Sellepärast õpetatakse juba varakult noortele taaskasutusest ja toidu raiskamisest ning kuidas see võib mõjutada nende tulevikku. Mõned moedisainerid  nagu näiteks Eve Hanson soovitavad õpetajatel ja klassijuhatajatel külastada õpilastega taaskasutuspoode, et näitada noortele kui palju mõju neil tõesti on maakera tulevikul.\nKokkuvõteks on tarbimisharjumused üks suurimad faktoreid mis võib mõjutada elu kümne- või kahekümne aasta pärast. Noortel on suur roll selles ning võimalus mõjutada seda suurel määral.');
