INSERT INTO core.text(id, content)
VALUES ('3f7bd988-cb70-43a7-be21-7b604fba7271',
        'Me kõik raiskame meeletutes kogudes toitu, isegi siis kui me seda tähele ei pane. Tihtipeale jäetakse pärast söömist taldrikule väike portsjon alles või visatakse toit ära, sest see lihtsalt ei meeldi. Aga kui ma tegelikult teen seda väga harva, siis miks see halb on?\nVaadates üleüldiselt inimesi, jätame me kõik vahepeal toidujäägid taldrikule ja viskame need ära, kui ei jõua enam süüa. See tundub olevalt väike probleem, aga tegelikult on see üks suurimaid toidu raiskamise viise. Kui mõelda, et pool kaheksast miljardist inimestest on korra toitu alles jätnud ja ära visanud, on toidukadu tõesti väga suur. Sellele probleemile oleks väga hea lahendus toidujääkide alles jätmine järgmiseks päevaks. See on juba pool võitu, kui panna alles jäänud makaronid külmkappi ja järgmine päev need ära süüa.\nSuur probleem, mis kaasneb toidukaoga on ka kuupäevade mitte jälgimine. Suhteliselt palju toitu visatakse ära, kuna kuupäev näitab, et toode on mittekõlblik. Aga midagi muud ei saa ju selle halvaks läinud tootega peale hakata. Tegelikult saab küll. Mõndadest halvaks läinud toodetest saab teha uut toitu. Näiteks halvaks läinud keefirist või kohupiimast saab teha pannkooke. Alati tuleb ka kontrollida enne toidu ära viskamist kas toode on päriselt halvaks läinud, sest tihtipeale mittekõlblikkuse kuupäev pole toodetel õige.\n Järgmine kord, kui tuleb tunne peale, et võiks toitu ära visata, soovitaksin ma mõelda, kui palju ressursse läheb kaotsi tänu sellele. Toidu töötlemise peale läheb tarvis palju maad, vett, energiat, tööjõudu ja raha. See väike toidu ära viskamine mõjutab keskkonda väga palju. Tänapäeval on suur mure ületootmine, nii ka toitlustuse vallas ning kui me raiskame toitu, toob see rohkem probleeme keskkonda. \n Samuti pole suurel osal inimestest võimalik saada korrapärast toitu. Paljudes maailma vaesemates piirkondades surevad inimesed nälga, söövad halvaks läinud toitu ja saavad erinevaid haigusi seotud roiskunud toitude ja jookidega. Üks viis kuidas korralikku toitu vajavaid inimesi aidata on annetada kuivtoitu erinevatesse toidu kogumis kohtadesse. Samamoodi aitab kaasa ka lihtsalt oma toidu ära söömine ja selle üle tänulik olemine.\nKokkuvõtteks on toidukadu suurem probleem, kui me arvame. Tänu sellele tekivad suured mured keskkonnas, kuid neid saab vältida väikeste sammudega. Järgmine kord, kui vanemad ütlevad, et paljudel pole seda võimalust korralikku toitu süüa, tuleks neid kuulata ja olla tänulik, et meil on võimalus süüa head toitu.');
