INSERT INTO core.text(id, content)
VALUES ('c071a4ae-710f-419d-8449-6e39b76650cb',
        'Praegune olukord, kus inimesed liigselt raiskavad toitu ja viskavad ära veel kantavaid ja häid asju võtab katastroofi pöördeid. Meie probleemiks on see, et inimesed ei mõtle tuleviku peale ja elavad ühe päevaga.\nEestis kuulub keskmiselt 61 kg toidujäätmeid ühe inimele peale. Selleks, et toota head ja värsket toitu teevad põllumajandusfirmad keskkonnale halba väetiste ja muude kemikalidega. Võib olla on vaja toota rohkem toidu mitteraiskamise propogandat. Meie koolisööklas on kuldne reegel, et võta pigem vähem ja võta pärast juurde, kui võta palju ja pärast viska ära.\nOlukord riietega Eestis on halb, sest inimesed viskavad ära riideid, mis on veel kantavad ja võivad veel olla kantavad mõnda aega. Taaskasutuspoodide laod on täis riideid, mida võib müüa uuesti hea allahindlusega, aga inimesed  ei ole valmis neid osta, sest neid kandis teine inimene. Selle asemel nad tellivad pigem Hiinast uued riided sama, või isegi odavama hinnaga. Probleem on selles, et need riided mis tulevad Hiinast on halva kvaliteediga ja tehtud suurte kahjustustega keskkonnale. Hea variant probleemi lahendamiseks on jällegi propoganda, mis seletaks kõiki keskkonna probleeme, mida toovad inimeste mõtetud tegevused.\nKokkuvõtteks peavad inimesed mõtlema tuleviku peale, mitte elama ühe päevaga, sest teist planeeti mille peal elada meil pole. Hea lahendus on annetusfondid, mis aitaks vaestel peredel, lastekodu lastel ja muudel inimestel, kes vajavad neid riideid saada seda, mida nad vajavad ja poleks nii palju keskkonna probleeme.');
