INSERT INTO core.text(id, content)
VALUES ('3f42cae3-4ca1-432a-b2d3-ad88021687ff',
        'Noortel on tähtis olla stiilikas ja selle olemiseks on vaja moodsaid riideid, mis ei tee  rahakotile liiga.  Hiina veebipoodidest ostetakse riideid odavalt, kuna seal on lai ja soodne valik. Paksude müüride taha jääb riiete tootmine, mida netipoodides näha ei ole. \nInimesi tõmbab netipoele lähemale soodsad hinnad, suur valik ja lühike kohaletoimetamise aeg. Tihti osteldakse veebis seetõttu, et kohapeal poodides pole riideeset, mida soovitakse. Pettumus ostjatele on kvaliteet tootel, toote suurus või  värv, mis ei vasta pildile. Näiteks ostetakse e- poest kleit ja kleidi kättesaamisel on kvaliteet kehva. Sellisel juhul saadetakse kleit tagasi ja ostetakse uus kleit vana asemele. Hügieeni e- poodides pole, kuna sama vana kleit, mis pole läbinud ühtegi puhastust, leiab endale järgmise kandja.\nTeema, mis jääb samuti paksude seinte taha on Hiina internetipoodide rõivaesemete valmimine. Teismeealised ostjad ei mõtle sellele, et töölised võivad olla 10- aastased, kes peavad tootma suurtes kogustes palju esemeid, kus saadakse alampalka ning kus töötingimused ei ole kiitmist väärt. Riided tulevad suurtest tehastest, mis reostab loodust. Loodus reostub alates riiete plastpakenditest ja lõpetades transportide heitgaasidest.\nKokkuvõttes peaks noor ostleja mõtlema, kas riideese on väärt terviseprobleeme tehaste vaese hügieeni ja kvaliteedi tõttu. Moekaid riideid leidub palju taaskasutuspoodides, kus on taskukohased hinnad ja mitmekesine valik. Samuti võiks eelistada kodumaised riideid, teades et tegu pole masstoodangu tehastega.  Ostmine internetipoodidest, lapstööjõu kasutamine ja looduse osaline reostumine  lõppeks, kui ostujõud e- poodides väheneks.');
