INSERT INTO core.text(id, content)
VALUES ('27329229-c0be-4240-84ca-c8046c3bda18',
        'Inimestel on väga raske pidada jälge oma raiskamisega ja vahepeal ei mõtle ka mis sellest kõigest prahist saab või kuhu läheb, kuigi minu arvates on kõige suurem probleem toidukaost. Pooled ei mõista või ei huvita millist kriisi see tegelikult mõndadele riikidele või inimestele võib teha. Kõigil pole võimalust igapäev sööki lauale saada ja elavad palgalt palgale samalajal kui muu pere teeb palju sööki teades et see järgmine päev on prügikastis, samas kui neil on selline võimalus ja ostavad enda raha eest asjad, siis väga midagi teha ei saaks kuigi peaks mõtlema kui kallid on asjad ja pole hea idee kõik lihtsalt ära visata.Pigem saaks panna selle heasse kasutusse näiteks anda kodututele või peredele kes ei saa igapäev sööki lauda lubada. Mõned inimesed kes töötavad kohvikutes või poodides peavad igapäev viskama puhtat ja söödavat toitu ära lihtsalt sest seal oli väikene plekk, mõndasi ei pruugi huvitada aga mõned teised vaid salaja võtavad öösiti prügikastist toitu, sest nad teavad et see on tegelt söödav ja lihtsalt raha raisk, kuigi paljudele poodidele see ei meeldi, vaid on lukustanud prügikastid.\nMina oma perega teen kõike et kokku hoida sööki, võtame normaalse portsu mis me teame, et sööme ära või siis ema teeb täpselt piisavalt sööki kõigile nii et kui keegi tahab, siis saab teise portsu ka veel võtta\nMinu ema ja mind huvitab ka väga taaskasutus, väga paljud viskavad oma riided prügikasti kui ei mahu  või ei meeldi enam, oleks targem sellega midagi kasulikku teha. Näiteks kui mulle midagi ei sobi või ei meeldi enam ma proovin olla  loominguline ja teen sellest midagi uut ja paremat,või siis ema annab või müüb oma sõpradele maha. Me vaevu viime oma vanad riided kaltsukasse, sest selle eest ei saa meie mitte ühtegi senti, ja neid tuleb juba igapäev piisavalt sinna juurde, veelgi hullem on kuskilt hiina e-poest osta asju teades et need riided ega asjad ei kesta üldse kaua, sest väiksed lapsed peavad seal mitukümmend tundi päevas töötama et inimesed saaksid nii odavalt neid osta. siiski on arusaadav kui sa ei saa endale lubada kvaliteetseid riided, aga sellele oleks teisi võimalusi, näiteks lähedki taaskasutuspoodi ja võibolla on võimalus midagi head ja kvaliteetset hea hinnaga saada mida saad kanda nagu uut.\nKokkuvõtteks peaksid inimesed rohkem tähelepanu panema tarbimisele isegi kui neil on võimalust ja ei pea kokku hoidma, kõige parem oleks kui jõukad inimesed saaksid aidata inimesi kellel pole siukest võimalust. Teeks see paljudele elu kergemaks ja paremaks.');
