INSERT INTO core.text(id, content)
VALUES ('6db2601f-9ee5-4c8d-a897-b5228e3a5f4f',
        'Igal inimesel on oma moodi tarbimisharjumused. Kõik ei tarbi ühte moodi. Toitu tarbitakse vähem kui seda ostetakse. Toit on meil maailmas üks tähtsaim osa, ilma selleta me ei saa elada ja sellepärast me peamegi seda mõistlikult tarbima.             \nMinu tarbmisharjusmused on lihtsad. Mina tarbin seda mida minu vanemad koju ostavad. Muidugi ma ei tarbi kõike toitu, mida nad koju toovad. Aga enamus tarbin. Kui ma poes käin ostan ma seda toitu mida ma alati kõik ära tarbin. Ma ei viska kunagi toitu ära mis mulle maitseb. Aga vahel ma viskan seda toitu ära mis mulle ei maitse. Ma olen isegi näinud seda kuidas inimesed kõik toitu ära ei tarbi ja lihtsalt viskavad minema.                 \nInimestel on tarbimisharjumused üksteistest teissugused. Inimesed peaks vaatama mitmeid külgi kui nad poest midagi ostavad. Nad peaks mõtlema sellele, et kas nad tarbivad kõik selle toidu ära mis nad poest ostavad. Kui me võtame Aasia piirkonna siis seal pole enamus inimestel toitu teadud põhjustel. Aga need inimesed kellel on võimalus koguaeg toitu tarbida peaksid nad olema õnnelikud, et neil selline võimalus on. Aga enamus inimesed ei ole, nad lihtsalt ostavad söövad või viskavad toidu ära mida nad enam ei taha tarbida.\nKokkuvõteks tahan ma öelda seda, et iga inimene peaks tarbima asju mõistuse piires. Ei tohi osta poest sellises koguses toitu mida sa ära ei tarbi vaid tuleb osta sellises koguses mida sa kõik ära tarbid.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('6db2601f-9ee5-4c8d-a897-b5228e3a5f4f', 'title', 'Tarbimisharjumused');
