INSERT INTO core.text(id, content)
VALUES ('024a40c2-09dd-4883-8b7a-368f38e0b9c5',
        'Igal inimesel on oma tarbimisharjumused. Olgu need kas söögiga, riietega või internetiga seotud. Aga mis võib juhtuda kui inimeste tarbimisharjumused lähevad liiale? Mida peaks tegema, et sellist probleemi lahendada?\nToiduraiskamine on väga põhjalikult rääkitud teema. Liigne toiduraiskamine toob kaasa raharaiskamise ja ressursside raiskamise. Kui sa ostada või paned oma taldrikule liiga palju sööki, seda ära ei söö, siis omakorda veel jäägid ära viskad, on see toiduraiskamine. Et seda vältida, tuleks vaadata oma kodus läbi mis toiduained sul juba olemas on, teha list asjadest mida sa ostma pead ning sellega poodi minema.\nRiietega on ka sama mure. Ostetakse kokku liiga palju riideid, eriti kui on tegu kiirmoega. Inimesed võivad mõelda, et mida see üks riideese nii palju maailma rikkuda saab. Saab küll palju. Kui korrutada seda ühte riideeset tuhandega või isegi miljoniga, on selle tagajärg suur. Pigem võiksid inimesed mõelda põhjalikult läbi, mida nad tahavad ja mida tegelikult vaja osta on. Ja kui on midagi vaja osta, saab leida midagi parajat kaltsukatest või taaskasutuspoodidest.\nInterneti liigne tarbimine läheb ka tarbimisharjumuste alla. Kas oldakse mitmeid tunde arvuti taga, istuda mugavalt diivanil televiisorit vaadates või oldakse mobiiltelefonides. Kui olla kõigest tund või kaks internetis, pole see just kõige hullem, aga kui olla juba viis või sellest üle, on see tervisele kahulik. Internetist võib tarbida libauudised või manipuleerivaid sõnumeid. Ja kui keegi nende õnge läheb, võib ta seda internetis ise omakorda jagada ning asi läheb veel tõsisemaks. Et seda probleemi lahendada, peaksid inimesed olema internetis vähem ja mõtlema või uurima, kas tegu on päris uudisega. \nKokkuvõttes, on igal inimesel oma tarbimisharjumused, ükskõik millist teemat see võib puudutada. Kõik peaksid oma tegude üle mõtlema ning olema teadlikud, mis see võib kaasa tuua.');
INSERT INTO core.text_property(text_id, property_name, property_value)
