INSERT INTO core.text(id, content)
VALUES ('c9c4a4b7-731b-4550-84fc-c893f5a60b36',
        'Toiduraiskamine on meie eludes muutunud liigagi tavaliseks. Me tihti ei pane seda tähele, kuidas see tegelikult mõjutab meid ja meie keskkonda. Aga miks on toiduraiskamine nii oluline meie ühiskonnas ja mis probleeme võib see endaga kaasa tuua.\nToiduraikamise teema käib meie ühiskonnas läbi igapäevaselt, kuid me ei pööra sellele tähelepanu. Meie saame poest alati osta värsket kraami ning suudame lõpuks visata sama toidu või toiduaine prügikasti. Nagu tarbitoitutargalt on oma lehel toidukaost rääkinud on nad maininud, kuidas inimesed võtavad toitu iseenesestmõis-tetavana. Meile tundub, et toit ei saa otsa kuna saame alati minna poodi ja osta uued. See mõtteviis on kasvanud aastatega. Toiduraiskaime ei tekita probleeme ainult meile vaid samuti meie planeet Maale. Toidukaoga me ei viska ainult meie raha vaid ka Maa ressursse näiteks: vett, mulda ja energiat. \nKui vaadata väljapoole Eestit on toidukao teema olulisem teistes riikides. Lihtne näide on näljahädad. On riike, kus polel luksust nagu meil on peolettidel. On palju inimesi, kes peavad nälgima kuna neil pole piisavalt toidu, kui samal ajal on meil liiga palju, mis lõpetavad prügikastis. Peale näljahädale me kurname oma enda planeeti. Nagu eelnevalt mainitud me kasutame liiga palju Maa ressursse ja koormame teda üle väetiste ja kemikaalidega, mis mõjutab meie keskkonda. \nKokkuvõttes toiduraiskamine on probleem, mida ei saa parandada üleööga. See on pikaajaline protsess, mis nõuab suurt pingutus riikide ja inimeste vahel. Kuna toiduraiskamine on meie suureks harjumuseks peame tegutsema väikeste sammudega, näiteks prügi sorteerimisega. Kui pööraksime natuke rohkem sellele tähelepanu suudaksime vähendada toidukao ja hoida oma planeet Maad.');
INSERT INTO core.text_property(text_id, property_name, property_value)
