INSERT INTO core.text(id, content)
VALUES ('c463c5ec-a82e-431c-9c1b-7d67f21b0f67',
        'Tänapäeva üheks peamiseks probleemiks ühiskonnas on toiduraiskamine. Miks seda tehakse ning kuidas seda ära hoida? Mina näen seda suure probleemina, kuidas ostetakse kokku palju erinevaid toiduaineid, mida lõpuks ära ei tarvitata ja need visatakse prügikasti. Mida teha üle jäänud toiduga ja kuhu see hoopis minna võiks?\nToiduraiskamine ja selle ära viskamine kohe kui kuupäev kukub. Kas tõesti on kõik asjad kohe kõlbmatud ja ei sunni süüa? Ei, tegelikult nii see pole. Kõikidel pakenditel on peal kirjas „Kõlblik kuni ...“ või „Parim enne ...“.Mida need tegelikult tähendavad ja miks need pakenditele pandud on? \n„Kõlblik kuni...“ viitab sellele, et tõepoolest peale kuupäeva võib olla see juba söömiskõlbmatu. Näiteks nagu piim. „Parim enne...“ on pakendil vaid poodidele märkeks pandud, millal nad enam kaupu tavahinnaga müüa ei või, näiteks saiad, leivad. Osades poodides tähendab see koheselt ära viskamist, kuid mitte igas poes. Olen tähele pannud, et mõningates kauplustes  pannakse ka eraldi letti asjad poole hinnaga, mida inimesed saavad sealt ise valida. \nSamas miks ei võiks poed viia ülejäänud toiduaineid toidukappidesse? Olen märganud, et see on üsna populaarseks saanud. Võibolla see kõlab poodidele lisatööna või halb, kuna nemad sellest kasu ei teeni. Tegelikkuses ei saa nad ära viskamisest ka mitte midagi. Kas tõesti on parem vaadata, siis niigi suurt prügimäge kus on pakendatud toit. See on minu silmis puhas reostus. Prügimäele ei minda ju sorama korraliku toidu leidmiseks. \nIga inimene kes kodus kasvõi vähesel määral raiskab toitu, ei tea kui suur kadu see on tervikule. Kui kõik viskavad natukene, teeb see ju kokku ikkagi palju raiskamist. Samas paljud arvavadki, et toit on kergesti kättesaadav ja mingit kahju see ei too. Tegelikkuses me kaotame nii raha kui ka tohutult muid ressursse: maad, vett, energiat ja tööjõudu. Toidu kasvatamisel on kasutusel ka väetised ja kemikaalid. Mis tekitab keskonnaprobleeme ja saastamist. See pole okei, võiksime rohkem mõelda ja teisiti tegutseda. \nKokkuvõtteks tahan panna igale inimesele südamele, et vähendada raiskamist. Ükskõik mis viisil, kuid see on tõsine teema mida tuleb jälgida. Ausalt öeldes, oleme me kõik väga pirtsakaks läinud ja elame niiöelda kalendri järgi. Kuupäev läheneb ja toit leiab automaatselt koha prügikastis. Kõige tobedam on see, et poed ei taha toidupäästjaid oma prügikastidesse ja lukustavad need ära.');
