INSERT INTO core.text(id, content)
VALUES ('2e9feca7-5e30-4895-9e8f-c1cdb91ab2a7',
        'Tänapäeval raiskavad paljud inimesed toitu. Samal ajal on ka palju inimesi kellel pole midagi süüa. See tekitab küsimuse „Kuidas me saaksime üleliigset toitu vähendada ja kuidas me saaksime seda targalt ära kasutada ning kuidas toiduraiskamine keskkonda mõjutab?“\n        Üks tavalisemaid põhjuseid miks meil üleliigset toitu tekib on kuna me ostame rohkem, kui me tarbime. Üks päriselu näide sellet on, kui me läheme poodi ilma ostunimekirjata. Ostunimekiri on tähtis kuna ilma selleta on raske meelespidada mida me tegelikult vajame. Me võime hakkata ostma toiduained mis on sooduses või asju mis tunduvad vajalikud. Ostukorra lõpuks olema kokku ostnud toiduained mida me ei söö või kasuta. Ostunimekiri, aga aitab meil meeles pidada mida osta ja kui palju osta. See hoiab ära üleostmise kui sellest kinni peame.\n Üks teiseks põhjuseks miks me võime raisata toitu on, et me ei vaata säilivus kuupäeva. Nt: Kui me ostame toitu mis ei säili kaua ja me ei söö seda selles ajavahemikus ära. See on üks näide kuidas me võime toituraisata. Me peaksime alati vaatama kuupäeva ja kindlaks tegema, et me selle selles ajavahemikus ära sööme.\n  Miks on toiduraiskamine üldse halb? Sellepärast, et me ei raiska mitte oma raha vaid teisi ressursse nt: vett, maad, energiat ja tööjõudu. Lisaks tekitab toidu tootmine tõsise keskkonnakoormuse, sest saagi kvaliteedi tõstmiseks kasutatakse väätisi ja kemikaale mis mõjuvad halvasti keskkonnale.\nKokkuvõtteks on tähtis poodi minnes koostada ostunimekiri, et me ei ostaks üleliigseid asju. Tähtis on vaadata säilivus kuupäevi , et me ei ostaks toitu mida me selles ajavahemikus mil see on hea ära ei söö. Toiduraiskamine on halb, sest see kurnab keskkonda kuna saagi tootmiseks kasutatakse kemikaale ja väätisi.');
