INSERT INTO core.text(id, content)
VALUES ('e4aa9823-4fef-4760-862b-8abc1d047da1',
        'Meil on harjumus visata toidu ära juhul, kui seda söömisel alles jääb või kuupäev on möödunud. Lisaks on sagedane olukord see, et Hiina veebipoest tellitud rõivad polegi nii kvaliteetsed ning nad samuti sattuvad prügikasti või paremal juhul lattu. Aga, kas me mõistame, kui palju see tegelikult mõjutab meie ümbrust?\nSee samane probleem oli õieti toodud juba aastaid tagasi. Inimesed hakkasid internetis levitama, mida toob kaasa selline väärkasutamine, ainult, et kõik jäid ignorantseks kuni asi muutus palju keerulisemaks. Nende arust kiirmoodi riiete lattu toomine aitab keskkonnale tohutult kaasa, mis pole otseselt vale, kuid hunnik sarnatest riietest ei saagi müüdud, puhtalt nende kvaliteedi tõttu. Pean tunnistama,et ma ka olin kunagi sealhulgas, tellisin kiirmoodi SHEINist või muust Hiina veebipoest. Ent selle asemel,et neid riided ära viskama, andsin ma neile uue elu. Hetkel ma kasutan neid samu riideid miskusuguste projetkide jaoks. Olen õmmelnud mänguasju ja mõned riied said kaunistatud lipsukiesega või ilusa mustriga paelakesega.\nAga kuhu siiski jõuab ära visatud söök? Üldjuhul mitte kuskile, lihtsa ohutuse tõttu. Harvanähtaval olukorral väiksemad firmad või mõned poed võimalusel ometi üritavad, kas annetada toidu puudust kannavatele isikutele või endale jääta. Ainult see on nii haruldane, et väga suurt rolli see elus ei mängi.Ausalt öeldes me kõik oleme mingitd moodi oma kreatiivsuse kaotanud, räägimaata humaansusest. Igaühel on antud nii palju võimalusi. Me saame isegi apelsinikoorest teha maiustuse, aga muidugi kõik suvatsevad edasi.  Samamoodi peame mälus hoidma, et keegi ei sunni sind ostma toodangu mille kuupäev on kohe möödas, kui palju sa ostad ja palju sa oma taldriku söögiga täidad.\nMinu arust me kõik koos peaksime olema veelgi teadlikumad sarnastest muredest ja kuidas neid vältida. Loodan , et kõik kiirmoodi e-poed sulgevad ja inimesed käituksid mõistlikumalt toidu kasutamisel. Sest sellise tempoga viime me ohtu mitte ainult meie planeedi, vaid ka iseennast.');
INSERT INTO core.text_property(text_id, property_name, property_value)
