INSERT INTO core.text(id, content)
VALUES ('fb76d104-19ac-4ed0-970d-85787a147076',
        'Paari viimase aasta jooksul on veebipoodides ostlemine saanud väga populaarseks. Tihti on internetipoodides kaup soodsam ja see paneb soetama rohkem asju kui meil tegelikult vaja on. Inimesed ostavad üldiselt tooteid, mis on valminud Hiinas ja pole eriti kvaliteetsed. Kuid kuidas oleks võimalik neid tarbimisharjumusi muuta?\nAastatega on hakatud tellima oma riideid just erinevatest internetipoodidest, kus kõik asjad on valminud Hiinas ja paljude põhjendus on see, et nendes kohtades on rõivad poole odavamad. Tooted võivad olla küll odavad, kuid kas ka korralikud? Seda harjumust saaks muuta hoopiski taaskasutuspoodides või kirbukates käimisega. Eestis on palju kohti, kuhu inimesed viivad oma vanad asjad ja sealt saab need kätte umbes sama raha eest, kui välismaa veebipoodidest. Tean inimesi, kes viivad iga kuu riideid mida nad enam ei kanna kirbukatesse ja see on ka hea ühiskonnale.\nHiinast ostetakse ka hulgaliselt tehnoloogiat, mille toimimise võimalus on väga madal. Need kas jooksevad lühisesse või ei käivitu, ja kui isegi käivituvad, siis lähevad nad väga kiiresti katki ning jällegi on toodetud mõttetut jama, mis reostab meie loodust. Selle asemel võiks osta tehnoloogiat poodidest, kus sa võid kindel olla, et saad selle hea kvaliteediga. Jah, tõenäoliselt maksab see kordades rohkem, kuid võid olla kindel, et sa ei pea vahetama seda iga paari kuu tagant. Ka mu üks sõpradest ostis kunagi väga odava arvutihiire ja see lakkas töötamast peale paari nädalat, siis ostis ta endale veidi kallima ja see töötas tal poole paremini ja ka kauem.\nKokkuvõtteks tahan öelda, et alati ei pea ostma kõiki asju soodsamalt ja tuleb mõelda ka teistele valikutele mis sul olla võivad. Kallim kaup võib olla palju kvaliteetsem ja parem. Tasub käia ka taaskasutuspoodides, kust võid leida tooteid mida otsid, eriti hea hinnaga. Taaskasutus ei ole häbi asi!');
