INSERT INTO core.text(id, content)
VALUES ('96e4499a-4148-42da-b06f-42b3a751788e',
        'Oleme ise näinud oma kodudes, kuidas meil tekib tarbimisest jäätmed. On arusaadav, kui meil on tekkinud söömisest üleliigne toit või kui meie riidemood läheb ebahuvitavaks või trendist välja. Ikkagi juhtub aeg-ajalt, kuid nüüd muutub see igapäevaselt tõsisemaks. Tekib mitmesuguseid jäätmeid, eriti riided ja toit, mis ei lähe hästi tagasi taaskasutamisse. Vääralt raisatakse toitu, mis saab täita ühe inimese kõhtu, ja riided, mille tootmiseks kasutati väärsat maavara ja mis teine inimene saaks kanda. Ma ise olen näinud, kuidas koolis väiksemad kooliõpilased ei söö oma toitu lõplikult ära, sest see neile ei meeldinud. Arvan, et peaksime leidma lahenduse, kuidas need harjumused lõpetada.\n Meie toitumisharjumused, näiteks kui unustame kasutada toitu enne nende kasutustähtaega möödumist või kui noorem laps ei taha lõplikult ära süüa oma suure portsu, on tulnud tagajärgedega. Statistika põhjal näeme, et iga Eesti inimese kohta aastas tekib keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg. Toidu äraviskamine on enda raha ja teiste ressursside (maa, vesi, energia, tööjõud) raiskamine. Igapäevaselt sureb inimesi nälga ja see on sellel põhjusel, et toitu ei jagu kõigile, sest need inimesed, kellel toitu on, viskavad toidujäätmed ära ja tekitavad toidukadu. Mina ise teen oma taldriku puhtaks supitükkidest või kastmest leivatükiga. See kindlustab, et kõik, mis mu taldriku peale tõsteti on ära söödud ning ei teki toidukadu\n Tekib ka taaskasutuspoodides riiete ja rõivate kuhjad, mida keegi ei soovi kanda. Need niinimetatud rõivad on tulnud Hiina kaubamajadest sooduskampaaniatega. Inimesed ostavad endale odava ilusa riide, kuid mõne aja pärast eelistavad mingit teist rõivat või kehal on halb olla selles rõivas, sest see koosneb naftast, ning viivad selle taaskasutuspoodi, kus need kõik koguvad hunikutesse. Mõned arvavad, et peaks tegema eksursioone taaskasutuspoodide lattu, et näidata, milline raiskamine tegelikult toimub. See võib kaasa aidata sellele, et vähendada meie halbe tarbimisharjumusi ja eelistada kvaliteeti enne kvantiteeti. Mina ei osta palju riideid. Ma saan oma riided vanematelt sugulastelt, kelle riided on jäänud väikseks, aga kui ma ostan riideid, siis ma ostan siit Eestist, oma kodumaa kvaliteediga.\n Peame koos mõtlema oma raha ja tarbimise üle, et me ei raiskaks oma kallist maavara ja kõhutäitvat toitu. Meil ja teistel saaks olla parem igapäevaelu ja tulevik, kui teeme koos targad või targemad ostud ja otsused.');
