INSERT INTO core.text(id, content)
VALUES ('1e04e240-6514-4918-95fd-4b1157917948',
        'Maailmas on olemas inimesi kes raiskavad toitu,toiduaineid,vett ja erinevaid muud söödavaid asju kuigi on olemas inimesed kes kasutavad seda ära, et toit raisku ei läheks ja seda lihtsalt ära ei visataks olen mina vähemalt kuulnud.\nOn inimesi kes raiskavad toitu sest nad saavad seda endale lubada ja on näiteks rikkamad kui mõni seal Pakistanis või kuskil mujal riigis ja selle järgi tuleksgi küsimus, et ,,Miks inimesed raiskavad toitu?``\nMinu arvates on toidu raiskamine halb, sest inimesed kes on natukene kaugemal kui meie ja ei ela nii hästi kui mõni.Inimene peaks ka saama endale õige koguse toitu, et mitte nälgida kasvõi surnuks.Ligikaudu 42% toidust ehk umbes 26kg,vistakse ära Eestis ja inimesed ültse ei mõtle selle peale mida nad teha saaksid selle toiduga.Selle jaoks on olemas ka toidubank võiMõni muu koht kuhu toitu jägada.Sul jääb midagi kodus järgi ja sellel on hea säilivusaeg siis oleks mõistlikum see ära kasutada mitte ära visata.Kasvõi teed mingi toidu, et mitte neid ära visata aga kui kuupäev on säilimisajast väljas siis sul polegi sellega midagi muud teha peale ära viskamise või näiteks sai taha mingit lihatoodet.Isegi selle jaoks on lahendus kui sul on koer või keegi kes sööks seda liha , sest ära vikamine ei ole väga aksepteeritav kui sul on tervelt 1-5 kg liha siis sa kohe esimese mõttega arvad küll, et ,,mul pole selle lihaga midagi teha ,ma viskan selle minema kuhugi metsa alla.`` Aga ei kasvõi anna see oma koerale või kellegile kes seda sööks, et mitte reostada maad või vett toidujäätmetega.\nMina jõutsin järelduseni, et toidu raiskamine on ebakasulik,sest sa ostad selle toidu oma raha eest ja oletame, et järgmine päev sa lihtsalt viskad selle minema.Inimesed vajaksid seda toitu kusgil mitte nii rikkas riigis,et toita ära kõik nälginud inimesed.');
