INSERT INTO core.text(id, content)
VALUES ('2e21774d-d0a6-4801-a582-cff50df4250b',
        'Kõigil inimestel on erinevad tarbimisharjumused, mõnel head, mõnel halvad. Mõni kulutab ja raiskab väga palju ilma, et isegi aru saaks, mis tagajärjed sellel on. seevastu mõni teine oskab säästa ja tarbida nii, et tekiks võimalikult vähe jääke.\n    Inimese toitumisharjumused olenevad mitmest asjast: teda ümbritsev keskond, kodune õpetus, vanus ja maailma trendid. Keskond mõjutab kindlasti kõige rohkem, sest kui inimene läheb kauplusesse, et midagi osta, siis teda huvitavad rohkem need asjad, mis on tol hetkel maailmas populaarsemad või “kasulikumad“ teiste väidetes. Nende harjumuste muutmiseks peab inimene ise midagi ette võtma, keegi teine seda tema eest teha ei saa.\n    Minu vanustel noortel on kõige suuremateks mõju faktoriteks vanemate poolt  saadud õpetused ja sotsiaalmeedia. Tihtipeale tahetakse endale osta seda, mis on trendikas ja kõigile meeldib, eriti riided ja ehted. Mina isiklikult ei lähtu eriti sotsiaalmeedias nähtud asjadest, vaid tarbin mõistlikult, ei osta üleliigseid riideid, mida ma tean, et ma paari kuu või aasta pärast enam ei kannaks, tihtipeale käin riideid ostmas hoopis taaskasutuspoodides. Toitu raiskan ka üsna vähe, kuna meil on kodus taluloomad, kellele saame kõik toidujäägid anda, seega prügikasti jõuab minimaalne kogus toidukraami, kui üldse midagi.\n    Sellest järeldades, inimesed on kõik erinevad ja kõigil on erinevad harjumused, aga selleks, et tekiks vähem jääke ja oleks vähem raiskamist, peaksid inimesed õppima mõistlikumalt tarbima ja arvestama nii teiste inimeste, kui ka kogu planeediga. Iga väiksemgi raiskamine on väike osa sellest, mis meie planeedile kahju teeb, ja see mis on palneedile kahjulik, on ka meile kahjulik.');
INSERT INTO core.text_property(text_id, property_name, property_value)
