INSERT INTO core.text(id, content)
VALUES ('a4a22db2-3f65-47b8-b811-faa45b605c83',
        'Väga paljud inimesed, kes tarbivad toitu võivad seda raisata kui viskavad viimased portsud minema ja mõndadele on see jälle suur piin, kui ta näeb et toit prügikasti lendab. Toidu raiskamist ei saa vältida, kuna väga paljud inimesed raiskavad seda mitmeid kilogramme aastas.\nToidu raiskamisega peavad inimesed tegelema, et seda liiga palju ei tuleks ja see liigapalju loodust ei raiskaks.\nNagu teksid öeldud on siis „aastas tekib keskmiselt 61kg toidujäätmeid majapidamise koha.“ Minul endal on ka halb vaadata kui toit läheb raisku või siis lihtsalt ei sööda, sellepärast tõstangi mina endale umbes sellise koguse mille ma ära soon et midagi raisku ei läheks.\nIsegi sellised inimesed kes rikkad on ei tohiks toitu raisata kuna see ikkagi reostab loodust ja on keskkonnale halb. Väga palju rikkad ja ära hellitatud lapsed raiskavad toitu, sest nad teavad et saavad seda niipalju kui hing ihaldab. Väga paljud inimesed on ka näljas sest neil pole piisavalt raha või resursse et endale toitu osta või valmistada. Isegi välismaal on väga paljud näljas tänu halvale majandusele nt: India. \nKokkuvõtteks võib öelda, et toiduraiskamine on väga halb ja rikub loodust, kuigi väaga paljud teevad seda siiski ja me ei saa kahjuks midagi teha kui nad ei kuula meid, ega tegele soovitatud tegude järgi.');
