INSERT INTO core.text(id, content)
VALUES ('783dbe9a-0b64-4168-ab2c-41094a255916',
        'Minu arvates on inimeste tarbimisharjumused muutunud väga labaseks ja ükskõikseks. Inimesed ei oska hinnata asju mis maksavad vähe ja arvavad, et alati on vaja omale soetada kallimaid variante. Kindlasti on sellist olukorda väga suurel määral mõjutanud ka sotsiaalmeedia. Kuidas ometigi sellist probleemi siis lahendada?\nKindlasti tuleks hakata meil mõtlema rohkem meie asjade taaskasutusele ja toidupoes näiteks ostunimekirjade koostamise peale. Kodumajapidamises  tekib Eesti inimese kohta aastas keskmiselt 61kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26kg. Selline informatsioon võiks olla rohkem maailmas levinud, sest tihtipeale teevad paljud inimesed sellise vea, et käidakse mõtlemata tühja kõhu ja ilma ostu nimekirjata poes ostlemas. Sellisel tegevusel on alati ka tagajärjed, ostetakse omale asju mida sellel hetkel tahetakse ja reaalsuses koju jõudes, jääd sa mõtlema oma tegude järgi ja siis sa alles saad aru, et sul ei olnudgi sellist rämpsu üldse vaja.\nTeine sarnane varjant sellise probleemi vältimiseks oleks näiteks vana kodutehnika ja riiete  müük või äraandmine. Alati on keegi, kellel võib olla sinu vanadest asjadest rohkem rõõmu kui sul iseendal ja oskab neid omamoodi veel taaskasutada. Kahjuks paljud inimesed ei oska meil selliste mõtete peale tulla ja kõik mis on nende jaoks vana visatakse lihtsalt minema, sest see ei oma nende jaoks enam mitte mingisugust väärtust. Mina isiklikult olen ka väga sellise mõtte poolt, et lastele tuleks näidata näidata taaskasutus poode. Selline vaade oleks kindlasti mõtlema panev ja paljud lapsed näeksid omasilmaga suurt raiskamist, mis meie elus igapäevaselt toimub.\nKui sellise teema puhul nüüd kokkuvõte koostada siis ütleksin mina, et jah, see teema on keeruline ja arvatavasti see olukord ei parane veel pikka aega enne, kui keegi sellega midagi ette ei võta. Teema mille mina alguses ette võtaks oleks kindlasti toiduraiskamine, sest mina ei salli toiduga mängimist ja väärtustan väga seda mida ma omale lubada saan. Kindlasti võiksid inimesed ka sotsiaalmeedias oma vanu riideid ära anda või müüa.');
