INSERT INTO core.text(id, content)
VALUES ('2c79b132-73d2-44b0-9037-fd97f26c1da1',
        'Tarbimis harjumused on muutunud aja jooksul ning on tugevalt seotud inimese elu- ja töötingimustega. tänapäeva maailmas on tarbimisharjumused suuresti mõjutatud tehnoloogia aregust turundusest ja globaalsest majandusest. üks olulisemaid muutusid on interti kasutamine, mis on muutnud ostmisprotsessi lihtsamaks ja kiiremaks. \ntoiduharjumused, on inimesi kes hoiavad toiduga kokku, näiteks käivad vähem väljas, ostlevad odavamas toidupoes. Inimesed kes saavad endale rohkem lubada uhkemat toitu ,nagu näiteks saavad osta paremat sööki, saavad käia peenemates restoranides.\nRiiede vali. Inimestel on erinev valik riide osas, nagu öeldakse „ maitse üle ei vaielda.“  Inimesed, kes saavad endale kallimaid riideid lubada. Ja on ka inimesi kes ei saa endale kallid asju lubada oeavad valima omale odavama riide poe, Eesti on selliseid poode palju nagu näiteks Humana, Realiseerimiskesku ja palju veel. Valikud on suured ja uhked, vali millist tahad, värvilist, odavat, kallimat ja palju veel.\nInimeste tarbimisharjumused sõltuvad ka sotsiaalsetest ja kultuurilistest teguritest. Näiteks nooremad inimesed võivad olla rohkem mõjutavad sotsiaalmeediast ja brändidest, samas kui vanemad inimesef võivad eelistada traditsoonilisi kauplusi ja kvaliteedi asemel hinna arvestamist. samuti tähelepanu kkeskkonnamõjudele. Üha rohke ökoloogilist tooteid, püüdes vähenedada oma ökoloogilist jalajälge. \nKokkuvõttes on tarbimisharjumused pidevalt muutumises, olles seotud tehnoloogia turunduse ja ühiskondiike väärtustega. Vajaduses, vaid ka elustiil ja identiteedi osaks.');
INSERT INTO core.text_property(text_id, property_name, property_value)
