INSERT INTO core.text(id, content)
VALUES ('8021a3d0-7b9e-49d9-8076-45467a35f2b4',
        'Meie ühiskonnas on tekkinud uus esimese maailma probleem, ületarbimine. Kuna inimesed on harjunud omama palju ja võimalikult soodsalt on tekkinud ületootmine. Mis kahjuks mõjutab meid kõiki.\nTrendid, trend on midagi mis on ühel hetkel populaarne, seda ainult ajutiselt. Kuid maailmas kus inimesed tahavad sisse sobituda kuhugi gruppi on trend loonud selleks väga mugava võimalus. Trendi puhul on üks miinus, see ei ole absoluutselt individuaalne. Kõik järgivad seda, mis tähendab, et suured brändid saavad toota asju palju ja odavalt. Oleks see siis nii, et inimesed kannavad oma asjad ära ribadeks, aga see pole nii. Liigutakse pidevalt uute moodsate asjadeni mis tõstatab järgmise mure, mis saab neist asjadest mida ei ole ära kasutatud?\nKahjuks arvavad, ühiskonnaliikmed mingil põhjusel, et taaskasutusse enda riiete andmine teeb maailmale head. Sellega jätkub ka trendide ring pidevalt. Suur brändide taga olevad inimesed väidavad, et nende tooted on suuresti taaskasutatud materjalidest. Ometi tekib riideid aina juurde. Theatriumi etendus „Mood“ loob väga hea pildi tegelikusest. Ka väga vaestel inimestel on võimalik käia ringi kallites moemaja rõivastes tänu ületootmisele. Peaksime rohkem tunnustama inimesi nagu Reet Aus kes tõesti annavad uue elu vanale.\nLeian, et peaksime kõik proovima olla teadlikumad ja tajuma vahet uuel huvitaval trendil ja vajadusel.');
