INSERT INTO core.text(id, content)
VALUES ('998770b4-7af3-497e-8a85-2a69b9e76ca9',
        'Inimesed kasutavad palju asju oma elus, kuid suur osa sellest läheb raisku just meie laiskuse või mõttetult ostmise pärast. Suur osa meie toidutarvetest läheb raisku just nendel põhjusel, aga mis need taganttõukajad selleks on?\nInimestel on palju asju, kuid väikse osa neist on asjad mida inimesed tegelikult vajaksid.  Tihti osetakse asju mingi laheda reklaami tõttu, üks suurimaid tooteid just selleks on riided. Palju hangivad omale uusi riideid, kuid kannavad neid ainult paar korda ja siis jätavad need riidekappi kõige pimedamasse nurka. Moedisainer Eve Hanson on toonud päevavalguse sellele, et tihti ostetakse riidideid ainult nende reklaamifotode tõttu ning pärast rõivastuse ostmist tuleb välja, et kehakatted on tegelikult odavad ja väga ebamugavad.\nIga aasta tekkib inimestel umbes 61kg toidujäätmeid, nende hulgas on peaaegu pool just toidukulu. Toidukulu ehk raisatud toit tekkib tihti inimeste tarbimiskäitumise tõttu. Suur põhjus on tühja kõhuga poes käimine. Inimene haarab rohkem toitu kui ta tarbib ja ei söö kõike seda pärast ära. Selle tulemusel läheb toit roiskuma ja tekkib veel toidukulu mis visatakse ära või harva jäetakse kompostrisse kõdunema. Nagu on kirjutatud tarbitoitutargalt.ee veebisaidil, me ei raiska just oma enda raha vaid ka tohutult muid ressursse: maad, vett, toitu ja tööjõudu.\nInimestel on palju halbu harjumusei, kuid see võibolla üks kõige hullematest eluviisidest, mis meil on. Sellega ei kuluta me vaid meie ressursse, aga vähendame oma ellujäämise võimalusi sel planeedil. Inimesed peavad õppima, kuidas rohkem hoida meie planeete ja mitte tekitada jäätmeid mis kahjustavad meie planeeti. Me peaksime olema palju kokkuhoidvamad ja raha mitte raiskama mõttetutele asjadele. See on küll üks väga ebameeldiv harjumus, mida isegi mina teen, aga tuleb ennast kokkuvõtta ja tarbimist vähendada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('998770b4-7af3-497e-8a85-2a69b9e76ca9', 'title', 'Inimeste tarbimiseharjumised');
