INSERT INTO core.text(id, content)
VALUES ('d6f73bc7-5dd1-4116-b3e5-cadfaa59a3d2',
        'Inimesed hindavad enda ja maailma vara nagu kulda. See oleneb isikust, et milline ta on. Kui inimene on rikas ja neid resursse on tal lihtne kätte saada, siis ta ei pruugi neid varasi nii kõrgelt hinnata nagu keegi, kes tunneb puudust sellest ja hindab seda väga kõrgelt. Selline probleem on meie maailma igast otsast muutnud. \nInimesed ei hooli sellest, et mida nad ära viskavad. Kui keegi, kellel on mingit kindlat asja üleliialt või ta lihtsalt ei hooli sellest siis teda ei pruugi väga huvitada, et mis sellega juhtub ja selle järelduseks nad viskavad need ära või jätavad nad maha. Teisest küljest seda vaadates on väga palju isikuid maa peal kellel oleks ülimalt hea meel kui nad need ära visatud asjad endale saaks, näiteks: toit, riided, elektroonikud, aksessuaarid ja väga palju teisi asju. \nMina arvan, et seda probleemi võiks lahendada. Aga kuidas? Inimesed kellel on elu elamise jaoks kõik vajalikud asjad olemas, või neid asju isegi liiga palju siis äkki nad ei tea, et kuidas on vaesuses elada. Ma olen mõelnud selle peale, et mis siis teha kui inimetse rollid vastupidiseks panna, ehk siis rikkamad inimesed peavad natukese aega elama vaesuses ja vaesed inimesed rikkuses. Seda me ei saa sundida kuna me ei kontrolli inimesi ja me ei saa neid enda käsu alla panna. Mina arvan, et rohkemate resurssidega inimesed võiksid väärtustada seda mida neil on. Ja kui läheb ära viskamiseks midagi siis mõelda vaesemate inimeste peale ja siis uuesti mõelda, et kas tasuks ikka ära visata või sellega midagi ette võtta, näiteks ära annetama.\nArvan, et inimesed võiksid väärtustada enda varasi väga palju. Nad peaksid olema uhked mis neil on kuna maailmas on inimesi kes unistaks nendest asjadest. Inimesed peaksid olema rohkem hoolivad teiste suhtes ja aru saama, et kellegil teisel võiks seda asja hädasti vaja olla.');
