INSERT INTO core.text(id, content)
VALUES ('c421c9bc-9a61-40cc-b4d9-768b54e1832a',
        'Viimasel ajal oleme me kõik kuulnud sellest, et meie planeet on hädas. Maavarasid jääb ainult vähemaks ja vähemaks, kliima muutub jne. Mina arvan, et suuresti on nende probleemide põhjuseks noorte ületarbimine.\nPanen tihti tähele, et paljud minuvanused ostavad peaaegu igakuiselt endale riideid juurde, et „trendidega“ järjepeal olla. Need firmad, kust nad tellivad endale riideid, ei tee ainult riideid, mida nagu ütles moedisainer Eve Hanson „Vikerhommikus“, ei saa rohkem kui üks kord kanda, sest need on tehtud naftast ja kehal on halb olla nendes. Peale selle et need riided pole kvaliteetsed, on need tehtud tihti täiskasvanute ja mõnikord isegi laste poolt, kellele vaevu makstakse selle eest. Noori see ei huvita, sest nende jaoks on tähtsam olla trendikas. Seepärast süüdistan ma rohkem suunamudijaid, kes need trendid algatavad.\nMuidugi on olnud alati tavaks, et mingid riided on moes ja mingid pole. See polegi probleem, probleem on see, kui kiiresti need trendid muutuvad ja kui palju survet on noortel nende trendidega kaasa minna. See on sellepärast, et firmad maksavad tohutuid summasid suunamudijatele, et neid trende peale suruda. Ehk siis lõpuks ongi kurja juureks need samad suurfirmad ise.\nTerve see trendide asi ongi lihtsalt üks suur tsükkel, aga kui küsida kes selle tsükli algatas, pole kedagi muud kellele otsa vaadata kui need samad suurfirmad kust need riided tulevad.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('c421c9bc-9a61-40cc-b4d9-768b54e1832a', 'title', 'Kust tuleb noorte ületarbimine?');
