INSERT INTO core.text(id, content)
VALUES ('8cb02e8c-2c7c-4469-a86f-11dc29f35d23',
        'On teada, et inimesed raiskavad palju resursse, riideid, toitu ja muud. Sellega tekibki küsimus, miks inimesed raiskavad oma resursse nii palju?  Mis on põhjuseks, miks suur raiskamine ikka edasi käib? Selles kirjandis vaadatakse nendele küsimustele otsa.\nInimesed raiskavad nii palju resursse, kuna nad ei tea, kuidas kokku hoida ja kõike korralikult lõpuni ära kasutada. Vanavanemad ja vanavanavanemad ikka vahel räägivad, kuidas nad nõukogude ajal kartuli järjekorras seisid mitmeid tunde, et korvikese kartuleid koju tuua. Meie vanavanemad ja vanavanavanemad on kasvanud üles nõukogude okupatsiooni all, kus oli vähe resursse, seega pidid nad kõik mis kätte said ära kasutama. Tänapäeval pole meil olnud suurt resursside puudust, meil on rahu, on vaid inflatsioon, mis segab veidi elamist, kuid see ei too kaasa suurt resursside puudust. Küsimusele miks inimesed nii palju resursse kasutavad on minumeelest vastuseks see, et nad pole üles kasvanud tõeliselt rasketel aegade, nagu meie vanavanemad ja slle tõtu ei oska nad kõie ära kasutada.\nPõhjuseks miks see suur raiskamine ikka edasi käib on minu meelest põhjuseks see, et inimesed pole lihtsalt piisavalt teadlikud sellel teemal. Nagu Eve Hanson ütles „Vikerhommiku“ intervjuus „Ma arvan, et peaks hakkama noortel tegema ekskursioone taaskasutiuspoodide lattu, et näidata, milline raiskamine tegelikult toimub.“ Lahenduseks on see, kui inimestele näidatakse seda suurt raiskamis kogust mitte telekast, vaid kohapeal. Põhuseks see, et kohapeal näeb kõik palju suurem välja, kui mingil teleka ekraanil.\nKokku võtteks ja järelduseks on see, et inimesed raiskavad nii palju, kuna nad ei tea, kuidas kõike korralikult ära kasutada. Neile tuleks õpetada, kuias resursse kokku hoida ja mitte raisata. Inimestele tuleks ka raiskamise kogust näidata, rt ad saaksid sellest kogusest parema pildi.');
INSERT INTO core.text_property(text_id, property_name, property_value)
