INSERT INTO core.text(id, content)
VALUES ('2d8232c4-ca4a-4a06-8f13-a899cfbf8b21',
        'Igal inimesel on oma tarbimisharjumused. Mõned säästavad ja taaskasutavad teised aga kulutavad ja ostavad juurde. Kumb valik on loodussõbralikum ja kumb on parem valik keskmise inimese jaoks.\nInimesed ostavad ja raiskavad liiga palju toitu. Tarbitoitutargalt lehekülje andmetel tekib igas kodumajapidamises inimese kohta keskmiselt 61 kg raisatud või ära visatud toitu aastas. Seda on väga suur hunnik toitu, mida pärast tootmist, transportimist ja distribueerimist ära visata. Suur osa ära visatud toidus on halvaks läinud ehk aegnenud, aga kuidas vältida sellise probleemi tekkimist?Üks võimalus on näiteks süüa toitusid, mille aegumistähtpäev on lähemal, see aitaks vähendada aegnenud toitude ära viskamist ja raiskamist. Teine võimalus oleks viia avamata pakendis toidud, mida ise ei jõua ära süüa, toidupankadesse. See valik võimaldama raisata vähem toitu ja boonuseks aidata inimesi, kellel on toidupuudus.\nTeiseks probleemiks on odavatate riiete massiline tootmine ja üle maailma laiali saatmine. Eve Hanson ütles kord, et paljud odavalt toodetud riided võivad reklaamil välja näha ilusad ja markantsed aga tegelikul on need tehtud naftast ja neid ühest korrast rohkem ei kanta. Selliseid riideid saab osta peaaegu igast poest, sest neid on odav teha, aga raha toovad need palju sisse. Palju lahendusi naftast riiete vastu ei ole, aga siiski on võimalik taaskasutada. On võimalik võtta vanu riideid ja neid ümberkasutada teisteks eesmärkideks, mitte ainult ei pea selle tulemusel suurt osa ära viskama, vaid saab ka odavamal läbi. \nOn palju erinevaid viise, kuidas vähem ära visata ja raha kokku hoida. Taaskasutada vanu riideid ja selle asemel, et osta uusi ja odavaid on alati parem nii looduse kui ka inimese kasuks. Lõputult siiski ei saa taaskasutada ja kunagi tuleb ka uusi osta. Toitu pole ka mõtet raisata, selle tootmisesse on läinud palju ressursse. Parem on looduse ja inimese jaoks osta toitusid ja riideid, mida inimene ise tarbida suudab.');
INSERT INTO core.text_property(text_id, property_name, property_value)
