INSERT INTO core.text(id, content)
VALUES ('ecfb03bb-5466-4d82-b39e-3708291c5bfa',
        'Keskmisele lääne elanikule, kes tegutseb oma elu ja tegevustega, nagu oleks see täiesti tavaline nädalapäev, võib tunduda, et nende tarbimisharjumused on ka tavalised. Kuid kui võrrelda neid samu tarbimisharjusi ühe kolmanda maailma inimese harjumustega, võib tekkida väga suur vahe. Kas see on ebaõiglane? Kas peaks tulema suurem trahv sellele, kes tarbib rohkem? Kas võimsama riigi elanik peaks oma tarbimisharjumusi parandama? Kas see on ignorantne, kui inimene ei mõtle pidevalt selle üle? Või kas praeguses olukorras on kõik väga hea ja õige?\nEesti on, võrreldes mõndade teiste Euroopa riikidega, märkimisväärselt arenenum. Eesti pind on niiske ja vett leidub igas majas. Meil on ressursse. Kui võrdleme seda ühe Aafrika riigiga, siis leiame, et neil on nukramad olukorrad: vett leidub vähe või kaugel küladest, nende haridustase on madal ja nad on vaesed. Teistes riikides on olukord pooleldi ja teistes on ressurssid kasutuseks üldse ainult riigijuhtidele, kes meelega piiravad nende elanike privileege. Elu on inimõigus globgoglabglogabgalob\ng');
INSERT INTO core.text_property(text_id, property_name, property_value)
