INSERT INTO core.text(id, content)
VALUES ('f0dd373e-cf68-4646-b772-3dd96931a84a',
        'Mida edasi läheb aeg, seda mugavamaks muutub rahvas: tarbitakse rohkem toitu, riideid ning muid esemeid. Väga suur osa rahvastikust tarbib rohkem kui neile on vaja, selline ületarbimine tekitab kahju nii keskkonnale kui ka nende enda rahakotile.\nSagedasti ei pane inimesed oma ületarbimist isegi tähele. Visatakse ära toitu, mis on poest ostetud, kuid pole enne kasutustähtaega ära söödud. Kui kõik inimesed samamoodi käituks, siis tekiksid suured biojäätmete ülejäägid, mille mõju avalduks keskkonnale. Iga inimene võiks enda oste, isegi toiduoste põhjalikumalt läbi mõelda ja olla kindel, et ta päriselt selle toiduaine ka ära tarbib. Toitu raisates ei tekita me kahju ainult iseenda rahakotile, vaid raiskame ka erinevaid muid ressursse: põllumaad, vett ja energiat. Tarbitoitutargale.ee veebiartikklis toidukaost on öeldud, et oma tarbimisharjumusi ei suuda inimesed muuta üleöö, vaid see on inimeste enda harjumustes kinni. Inimestele tuleks teadvustada, et toiduraiskamine on suur probleem, millega saavad tegeleda ainult tarbijad ise.\nSuures osas maailmas toodetakse rohkem kui inimesed tarbida suudavad. Tipptootja Hiina toodang jõuab laiali üle maailma. Isegi suur osa Eesti poodide kaubast on pärit Hiinast. Inimesed ostavad Hiina kaupu lihtsal põhjusel: need on odavamad, kui kodumaal toodetud kaup. Tegelikult tuleks mõelda ka meie enda majandusele. Kui suurem osa kaubast ostetakse sisse välismaalt, siis jääb meie enda tootjatele, meie niigi väiksest populatsioonist, ainult väike osa, kes nende kaupu ostaksid. Inimestele peaks rohkem selgitama, miks on kodumaise kauba ostmine meie enda majandusele kasulikum, kui välismaise kauba ostmine.\nKõik tarbijad ehk kõik inimesed peaks enne millegi ostmist olema kindlad, et nad seda päriselt vajavad, olgu see siis toit või mõni muu ese. Ühiskonnale tuleks teadvustada kui suur probleem on tegelikult ületarbimine ning selle probleemi lahendamiseks tuleb kõigil inimestel muuta isenda tarbimisharjumusi. Kodumaise toodangu ostmine võib olla kulukam, kuid see paneb meie enda riigi majanduse kasvama.');
