INSERT INTO core.text(id, content)
VALUES ('74bd8153-5b8e-4b92-ba75-59230f454ccb',
        'Maailmas on suureks probleemiks tarbimisühiskond ja sellest tekkiv prügi. Paljud inimesed tarbivad vägagi palju rohkem, kui neil tegelikult on vaja, ning sellega tekkitavad väga palju saastet.\nMaailmas on meil suur probleem toidu raiskamisega. Eesti inimesed toodavad asstas keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab umbes 42% ehk 26 kg. See toob välja kui suureks on meie tarbimisühiskond muutunud, see toob ka välja kui palju sellest tegelikult on meil vaja. Toidu raiskamnie toob kaasa ka palju muid probleeme. Suurimaks nendest probleemidest esitub prügi milles on toit pakentatud. Suurt osa nendest pakenditest ei saa ka taaskasutada, mis omakorda tähendab, et kas see lõppetab prügimäel või looduses.\nTarbimisühiskond tuleb välja ka riiete või muude asjde ostul, paljud inimesed ostavad asju mida pole võimalik taaskasutada või ümbertöödelda. Hetkse seisuga meil toodetakse vägagi palju rohkem kui tegeliku me suudame ära tarbida, see ei kehti ainult riiete kohhat. Me kui ühiskonnana toodame ka palju rohkem nutivara, autosi, mänguasju, jm. Praegune maailma üks suurimad tootjaid on Hiina, kus jääb ka palju toodetust üle, ning kus see pärast lõppetab prügimägedel või jäätakse lihtsalt kuhugi vedelema. Mõnes suurema Hiina linnas on ka suuri auto kogulaid kuhu viiakse kõik mis on vananenud või mida ei saa enam kasutada. Lõppu pole sellele siimaani näha.\nTootsmisega esineba ka keskonna probleeme. Paljudes maades kus on odav toota ja kust saab toorained, tekkitatakse palju heitgaase. See omakorda suurendab meie kasvuhooneefekti. Maailmas juba on suureks probleemiks kliimasoojenemine ja selle aitab kaas väga palju ka meie tarbimisühiskond.\nHetkse seisuga on meie maailm saanud suureks tarbimisühiskonnaks, kus kõik on väga kätte saadav. Kuna kõik on vägagi kättesaadav, siis osttakse paljugi rohkem osta kui vaja ja kõik vana visatakse ära. Kõik mida pole enam vaja kas lõppetab prügimäel või looduses.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('74bd8153-5b8e-4b92-ba75-59230f454ccb', 'title', 'Tarbimisühiskond ja selle probleemid');
