INSERT INTO core.text(id, content)
VALUES ('7b99ff68-b382-44c5-9c82-20b0c4e5eb36',
        'Kogu maailmas toimub suur asjade ületarbimine ning sellest ei jää puutumata ka väikene Eesti. Keskmine eestlane raiskab aastas umbes 26 kilogrammi toitu, mis on jäänud tarbimata enne säilivusaja ületamist.                                                                           Praegusel ajal käib suur toitainete ületarbimine, ostetakse poest liiga suures koguses toitu, mida ei jõuta ära tarbida enne, kui see riknema hakkab. Sellise tarbimis- harjumusega ei raisata ainult omaenda raha, vaid ka hulganisti muid varusid, näiteks maad, vett, tööjõudu ja energiat. Sellise probleemi üks lahendustest oleks poest osta toitu väiksemates kogustes ja mitte teha ebavajalikke- ning emotsioonioste.           Kõikidel inimestel ei ole varianti osta toitu väiksemas koguses, eriti just maainimestel. Paljudes väikestes külades ja alevikes pole enam toidukaupluseid ja sellepärast peab suur hulk maainimesi käima kodust kaugel linnas poes. Kuna maainimesed pole üldjuhul just liiga jõukad, siis eelistavad nad käia harvem poes ning osta suurem kogus toiduvaru ette ära.                                                                                       Toidu raiskamise probleemi lahendamine ei saa käia äkitselt, sest suur osa eestlastest on harjunud sellise tarbimisega ning sellega, et kõik asjad on tänapäeval kohe kaupluses saadaval. Maailmas on ka kohti, kus on vastupidi ehk, et on toidust suur puudus. Sellised probleemid on pigem vaesemates piirkondades, näiteks India slummides ja erinevates Aafrika riikides, kus iga päev sureb hulk inimesi nälja kätte ära.                                                                                                                             Söögikraami tuleks raisata vähem, sest selle tootmine ei käi niisama hõlpsasti ning enne toidu ostmist tuleks läbi mõelda, kas on ikka kõike seda tarvis osta. Mina arvan, et toidu raiskamine ei ole väga suur probleem, sest need, kes seda praegu osta ei jaksa ja selle puudusesse surevad, ei jaksaks seda teha ka siis, kui teised vähem raiskaksid.');
