INSERT INTO core.text(id, content)
VALUES ('055f71b9-c3d6-4bdc-979a-27eb056915b3',
        'Miks me ei austa ega väärtusta toitu?\nMeid ümbritseb toit mida me kõik igapäevaselt tarbime.Toit on oma väärtuse kaotanud võrreldes ajalooga.Ajalooliselt polnud toit mitte lihtsalt söök ,see oli valuuta ,selle eest sai osta,müüa,vahetada.Teises maailmasõja ajal Leningradi blogaadis ,kui sul oli leiba ,siis sind võiti ära tappa  järgmisel päeval.Minu vanaisa ,oli blogaadis ja ta oli rääkinud:“Inimesed teevad kõike,selleks et tulla toime oma vajadustega ja elu muutus katastroofiliseks õuduseks.“Selline ,oli elu kuuskümmend aastat tagasi.Tänapäeval ei suudaks inimene sellist elu ette nähagi ,sest elu on tunduvalt pehmemaks muutunud.Tänapäeva ühiskonnas ,on iga toit ümbertööteltud ja ebatervislik ligikaudu seitsekümmend protsendi ameerikast on kas kergelt või suuresti  rasvunud räägimata lastest.Vähem tehakse süüa ise ja ei vaatada mida süüakse.Kui lapsevanem on ebatervisliku eluviiisiga on ka laps.Mida ebatervslikum on laps seda suurem risk on haigestuda rasvumise tulenevatesse haigustesse.Haige laps tähendab seda  ,et ta ei saa elata täisväärtusliku elu sellepärast et ta ei saa oma vanustega mängita,joosta ja olla lihtsalt laps.Ta peab varakult olema hingetu ,sest tema süda on nii kurnatud tänu vanematele.Kui laps on varakult  haige suureneb ta risk kroonilistele haigustele ja seda kiiremini satub haiglasse.Haigekassa ravib meie rahate eest rasvunud inimesi ,kellel süda või maks ei tööta tänu valedele harjumustele.Parem on rohkem propageerida tervisliku eluviisi ja mitte leebelt vaid jõuliselt.Alguses püstitatud küsimus „Miks me ei austa ega väärtusta toitu?“  olen jõudnud järeldusele ,et kuidas noort inimest  kodus haritakse mõjutab see tema suhtumist toitu ja toitu kultuuri vastu.Noor peab ennast ka harima toitu kommede,tavade ja kuidas on toitu saatud ,miks see on tähtis.');
