INSERT INTO core.text(id, content)
VALUES ('cd02a266-4c20-4d26-bf71-7e45b4ea436a',
        'Tänapäeval on väga suureks probleemiks inimeste tarbimisharjumused. Tarbimisharjumused on meil globaalseks probleemiks tulnud juba 20. sajandist alates. Me ei saa aru selle probleemi tõsidusest, kui me ise seda kogenud ei ole. Näiteks Aafika mitmetes riigides ei saa toidu nälgimisest paljudki jagu. Seega toitu ära visates tuleb mõelda, mis küll toimub samal ajal teises maailmaotsas.\n     Kui räägida Eestis olevast toidutarbimisest, siis Eestis on vägagi lihtne leib lauale tuua. Eesti poodides on vägagi palju valikut kodumaisetest toodetest kuni välismaa maiustusteni välja. Näiteks Eestis on oma Tere ja Põltsamaa tooted. Eestis on tooted poelettidel olemas. \n      Tehnika ja selle tarbimine on tänapäeval on inimestel erinev. Räägides tehnikast siis selle tarbimine muutub ainult ahnemaks ja mugavaks. Tarbimisharjumused muutuvad ainult inimesele kasulikumaks, et saada seda tehnikat mis teeks ära kodupidamis nõuded näiteks muruniitmine või tolmu korjamine. Tehisintellekt Chat-GPT on muutunud kasumlikuks tarbeallikaks, kus näiteks tava kooliõpilane saab sealtkaudu kõik oma kodused tööd, referaadid, kõned või esitlused soovi peale ära küsida. Selgub, et ühiskond muutub ainult mugavamaks ja ahnemaks ainuüksi sellele, et tehnika tarbimine muutub aina suuremaks. \n    Tarbimine on tore, kui seda endale lubada saab. Antud juhul tootmine suureneb, tarbimine suureneb, ülejääk suureneb ja tehnika tarbimine muutkui areneb. Kui see mõjutab meie tulevikku, kas seda saab kuidagi tasakaalustada või tarbimisharjumusi muuta ja tulevikus seda stabiliseerida.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('cd02a266-4c20-4d26-bf71-7e45b4ea436a', 'title', 'Inimeste tarbimisharjumused');
