INSERT INTO core.text(id, content)
VALUES ('7279d787-faee-41ce-9180-b6d93c77495d',
        'Tarbimisharjumus on probleem terves maailmas. See puudutab igat ühte mingilgi moel. Näiteks toidu ära viskamine. See tekitab paljudes suurt mure ning see on väga tõsine probleem eriti sellistes riikides, kus elu on väga kallis.\nEnamused ei arva väga halba sellest kuna nad mõtlevad, et see on nii väike kogus, mille ära viskab ning ei pea toidu ostmise pärast muretsema, sest raha on selle jaoks piisavalt palju. Reaalsuses teeb see suurt kahju inimesele endale, majandusele jne. Tarbitoitutargalt.ee artikkel „Toidukaost“ ütleb, et ainuüksi Eestis tekib iga inimese kohta keskmiselt 61 kilogrammi toidujäätmeid, millest 26 kilogrammi moodustab rikenenud või kasutustähtaja ületanud toit vms. \nSamuti on väga suureks probleemiks igasuguste riideesemete ebavajalik minema viskamine ja ostmine. Üheks suurimaks raiskajaks on Hiina. Hiinas toodetakse väga palju seda tüüpi riideid, mida ei ole enam hea kanda pärast esimest kandmist või on tehtud nii õhukesest ja halvast materjalist, et laguneb juba esimesel kandmisel. See kogus materjali, mis läheb raisku ülemäärastele riietele on tohutu. Pole täpset arvu, aga kui vaadata ringi, siis märkab seda päris palju. Näiteks taaskasutuskeskused, kus on riideid massiivsetes hunnikutes. See on ülimalt suur kahjum riideeseme omanikule, kes viskas ära oma riideeseme, sest see on otstarbetu raha kasutamine. Suurim kahjum on see ikkagist majandusele, sest nende riiete valmistamiseks läheb palju aega, raha, tööjõudu ja materjali.\nSee kõik on väga suur globaalne probleem. Seda saab lõpetada aint sel juhul, kui hakatakse kasutama targemalt oma raha ning mõtleks, kas seda on ikka vaja. Kui olla kindel, et too asja pole tegelikkuses vaja, siis pole mõtet seda osta kuna see kõik läheks lõpuks lihtsalt raisku.');
