INSERT INTO core.text(id, content)
VALUES ('9e98e881-1964-447b-824f-97ea4431a6c6',
        'Toidukadu on aja jooksul suurenenud. Seda saavad ainult muuta inimesed ise. Toidu raiskamise vähendamine on pikaajaline protsess, see nõuab aega ja kõigi panust.\n     Kui me tahame toidukadu vähendada, peame ise hakkama säästlikumateks. Nt ostetakse toitu nii palju kui korraga ära süüakse. Paljud arvavad, et toitu on veel ja see ei saa otsa. On ka võimalus, et ülejäägid kasutatakse ära kompostina, saadakse kasutada seda ära aiamaadel või põldudel.\n     Tarbitoitutargalt ütles, et kodumajapidamises tekib iga Eesti inimese kohta aastas kesmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26kg. Selle järgi saame eeldada, et meie ühiskond ei ole väga säästlik toidu suhtes. Enamasti tehtakse korraga liiga palju süüa või ostetakse koju liiga palju toiduvarusid, ei jõua seda ära tarbida õigeks ajaks ja seejärel läheb toit pahaks ning visatakse minema. Koguaeg, kui toitu ära visatakse raisatakse omaenda raha, kuid ka tohutult muid ressursse: maad, vett, energiat ja tööjõudu.\n     Kui inimesed hakkaksid vähem toitu minema viskama ja kasutaksid naturaalseid väetisi oma maadel, siis nad säästaksid palju rohkem enda raha ja ressursse. See vähendaks ka erinevate haiguste ja viiruste levikuid ning ümbruskond oleks palju puhtam ja turvalisem. Selleks peavad nad muutma enda suhtumist ja hakkama hoolitsema oma ümbruskonnast. Seda on raske muuta, kuna paljud on harjunud toidujääke minema viskama.');
