INSERT INTO core.text(id, content)
VALUES ('bfcfda0e-b136-42bf-9692-dd4160d2f3f2',
        'Inimesed tarbivad erinevaid asju, nagu toitu, mõnuaineid või ravimeid. Mõned tarbimisharjumused on halvad, ja mõned on head kui tarbid seda normaalses koguses, näiteks kui tarbid oma ravimeid liiga palju, siis see võib sinujaoks halvasti lõppeda, aga kui võtad ravimeid normaalses koguses, siis see teeb sinule head. Toiduga on täpselt sama, kui tarbid seda liiga palju siis muutud ülekaaluliseks ja võivad tekkida terviseprobleemid, aga kui tarbid seda normaalselt oma kehakaalu järgi, siis see teeb sulle head kui on normaalne toit nagu liha, muna või mingisugune köögivili.\nOn ka tarbimisharjumusi mis teevad sulle koguaeg halba milleks on mõnuainete tarbimine, näiteks nikotiini, tubaka või erinevate narkootikumide tarbimine. Nikotiini tarvitavad tänapäeval väga paljud, isegi noored, nad tarvitavad seda tehes mokatubakat või e-sigaretti mis on tehtud väga populaarseks. Ma ise olen ka tänavatel ja koolis näinud kuidas noorad teevad e-sigaretti või mokatubakat ja mina arvan, et selle lõpetamiseks on vaja teha selliste asjade kättesaadavuse raskemaks, näiteks eemaldada need asjad toidupoodidest ja müüa neid ainult teatud kohtades nagu Tallinnas kuskil tänava nurgas väikeses poes.\nLiigne ravimite tarbimine on päris paljude inimeste suur mure, mõned ravimid mida liigselt tarvitatakse on antidepressandid ja mõned inimesed kasutavad ka uinuteid liiga palju. Inimesed kasutavad neid sellepärast, et saada lahti stressist mis tuleb töölt, perest või isegi koolist.  Mina isiklikult pole mitte kellegagi kokku puutunud kes tarvitab enda ravimeid liiga palju, aga olen koguaeg internetis näinud kuidas kellegil on sellega probleeme.\nMa arvan, et kõik tarbimisharjumused pole halvad, vaid on ka häid näiteks sul on harjumus tarbida igapäevaselt 2 porgandit, siis see on väga hea, aga enamus inimesi siiski ei tee seda vaid tarbivad asju kas normaalselt või liiga palju, väga vähesed tarbivad asju paremini kui keskmine inimene, ma olen ise kogenud rohkem inimesi kelle tarbimisharjumused on pigem halvad ja väga vähe inimesi kelle harjumused on head.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('bfcfda0e-b136-42bf-9692-dd4160d2f3f2', 'title', 'Inimeste tarbimisharjumused');
