INSERT INTO core.text(id, content)
VALUES ('cd54c9cf-3848-4ad9-9ffc-8a41f7884354',
        'Maailmas on suur probleem toidu ja rõivaste mitte otstarbekalt kasutamisega, ning sellega kaasneb toidu ning tervete ja korralike riiete raiskamine. Rõivaste vananemine ja nende ära viskamine on loomulik, kuid terveid ja täiesti korralikke riideid ei tohiks koheselt ära visata, ning toidu raiskamise probleem on veelgi olulisem, sest maailmas on väga palju inimesi kellel pole igapäevaselt midagi süüa ja selle tagajärjel nälgivad.\ntoitutargalt.ee interneti lehekülje artikli „Toidu kaost“ põhjal, on palju selliseid inimesi kes raiskavad toitu ning ei mõtle sellepeale kui nad seda suurtes kogustest ära viskavad. Selleks, et inimesed seda ei teeks ei saa midagi teha, kui ainult  sotsiaalmeedia või telekanalite abil sellele tähelepanu pöörata, et toidu ära viskamine ja raiskamine on väga suureks probleemiks.\nSaates „Vikerhommik“ intervjueeris Anu Välba moedisainerit Eve Hansonit ja räägiti taaskasutusest ja taaskasutuspoodide ladude rohkest riiete probleemist. Eve Hansoni sõnul, on oluline, et iga inimene pööraks tähelepanu oma tarbimisharjumustele ning eelistaks kvaliteeti kvantiteedile. Enamustes maailma riikides on probleemiks suurtes kogustes rõivaste kokkuost ning peale kahte kasutus korda ära viskamine sest see riide ese on inimese kehale väga ebamugav kuna see on naftast ja muudest mittelooduslikest materjalidest valmistatud. Riiete rohket ära viskamist ja nende mitte taaskasutamist võiks ja peaks ära hoidma sellega, et osta kodumaiseid ning looduslikest materjalidest valmistatud rõivaid.\nKeskkonnakoormuse vähendamiseks peaksid kõik inimesed ise mõtle mida nad ostavad ning mida nad oma toidu jääkidega ettevõtavad. Kui maailma soovib keskkonna- , toidu- , riiete vähesest taaskasutamise probleemidest või muudest probleemidest vabaneda, siis peaks iga inimene ise oma eluviisi muutma.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('cd54c9cf-3848-4ad9-9ffc-8a41f7884354', 'title', 'Toidu ja rõivaste raiskamise probleem');
