INSERT INTO core.text(id, content)
VALUES ('e0e74c03-9bae-4e51-846f-54f0dd69e4f9',
        'Tänapäeval on väga aktuaalseks teemaks muutunud inimeste tarbimisharjumused. Paljud ei saa isegi aru, kuidas mõjutavad nende tarbimisharjumused loodust, ühiskonda ja inimesi. Mida see põhjustab ning kuidas seda peatada?\nSöögi kergekäeliselt ära viskamine on loodusele kahjulik. Paljudes peredes on ülejääkide ning tähtaja ületanud toidu ära viskamine tavaline nähtus. Selles ei nähta probleemi. Kuid toidu kergekäeliselt prügikasti viskamisel visatakse ära ka maa, energia, tööjõud, tooraine ja vesi, mille abil söök valmistatud on. Selle asemel, et ülejäägid ära visata oleks vajalik poes mõelda selle peale, kas toiduaine saab päriselt ka kasutust, või on oht, et see läheb vanaks ning selle peab ära viskama? Leheküljel toitutargalt.ee tehtud uuringust tuli välja, et kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg. Inimesed võtavad toitu liiga iseenesestmõistetavalt ning ei märka, kui palju seda päriselt raiskavad ning mis mõju sellest maailmale on.\nVäga levinud probleem tänapäeva ühiskonnas on ka kiirmood, mida tarbivad paljud inimesed ilma aru saamata, kui kahjulik see tegelikult on. Näiteks veebipoed ‘’SHEIN’’ ja ‘’Temu’’: sealt saab endale võimatuna tunduva, soodsa hinnaga suure koguse riideid osta. Kuid thihtipeale tuleb ette, et riided mis on kiirmoest tulnud ei ole kvaliteetsed, neid ei saa kanda ning need lähevad otse prügikasti. Selle kohta saab öelda: ,,Sa saad seda, mille eest maksad.’’ Selle asemel, et kiirmoodi kasutada ning sobivatuid riideid ära visata oleks kasulikum riideid osta poodidest, kus sa tead, et jääd riietega rahule ning ei pea neid pärast ära viskama.\nOn oluline, et inimesed pööraksid oma tarbimisharjumustele rohkem tähelepanu. Tarbimisharjumused mõjutavad loodust, sest toidu või riiete ära viskamisega lähevad raisku ka ressursid, mille abil need tehtud on. Enne millegi ostmist on vaja mõelda: ,,Kas toiduaine või riideese saab päriselt kasutust või läheb see lihtsalt raisku?’’');
