INSERT INTO core.text(id, content)
VALUES ('34d3be8b-7500-4708-9f2b-4d47286860af',
        'Tänapäeva kiirelt arenevas maailmas toodetakse paljusid erinevaid tooteid, kuid kõike ei jõuta ära kasutada ja need visatakse ära. See on suureks probleemiks, sest varsti ei ole enam ruumi, kus neid hoiustada saab.\nRiideid tootvad firmad on muutumas keskkonna säästlikumaks paigaldades oma poodidesse kasutatudriiete kogumiskaste. Moe väga kiire muutumisega tekib pidevalt juurde suurtes hulkades riideid, mis kaotavad üsna ruttu oma stiilsuse jäädes siis, kas kappidesse tolmu koguma või sattudes prügikasti. Selle probleemi vähendamiseks on  mõeldud välja erinevaid lahendusviise, näiteks H&amp;M ning nende kogumiskastid, kuhu saavad inimesed viia oma vanu rideid, mida nad enam ei kasuta ja ei raatsi ära visata, sest need on täiesti korralkud. Üha rohkem mõeldakse välja viise, kuidas olla loodussäästlikumad.\nPaljud inimesed ostavad tihtipeale rohkem kui nad tarbida jõuavad, aga on ka neid, kes on oma elustiili muutnud. Soodushinnad või mõningad kampaaniad on vägagi ahvatlevad, sest tänapäeva maailmas, kus tasuta asju pole olemas, on rahvas nõus kõigega, mis aitab neil raha säästa. Tihti ostetakse  rohkelt näiteks toiduaineid, sest neil oli soodushind, aga kuna seda ei jõuta ära süüa jääb see alles või hakkab rikknema ning siis visatakse see ära. Internetis on populaarsust  kogunud zero waste elustiili, mille põhimõtteks on osta täpselt nii palju kui ära kasutakse, ning mitte midagi ei raisata. See elustiil on hea, sest nii raisatakse vähem ja ollakse säästlikumad. Alati ei tohi keskenduda hinnale, vaid hoopis mõelda, kas seda eset on vaja ja kas see kasutatakse täielikult ära.\nKiirmoe, soodustuste ja paljude teiste teguritega kaasnevatele probleemidele on vaikselt saabumas ka lahendused, mis aitavad prügi ja muude jäänuste teket vähendada, kuid nende edukuse määravad inimesed ja nende otsused ise.');
