INSERT INTO core.text(id, content)
VALUES ('15468c32-9f1a-4d2b-9363-13a60b5c4a53',
        'Inimesed raiskavad ja tarbivad väga palju, peamiseks on toit ja riided. Tihti arvatakse, et pole vahet kui palju või kust kohast riideid ostetakse aga tegelikult on küll. Sarnane probleem käib toidu ostmise ja tarbimise kohta. \nInimestele tundub, et toit on igavene ja ei saa otsa. Näiteks, toidu liigne ostmine. On inimesi, kes ostavad poodidest liiga palju toitu ja lõpuks tuleb välja, et ülejäänud toitu ei jõuagi kodus ära süüa ning see visatakse tuimalt minema. Veebilehel „Tarbitoitutargalt.ee“ kirjutatakse, „Me ei raiska ainult omaenda raha, vaid ka tohutult muid ressursse: maad, vett, energiat ja tööjõudu.“ Kui rahvas sellega jätkab siis toidu tootmine muutub suuremaks keskkonna koormuseks.\nLisaks toidule on ka teine murekoht, selleks on riiete ostmine ja kasutamine. Väga suur osa inimestest tellib riideid kahtlastest Hiina veebipoodidest, milleks on „Shein“, „Temu“ jne. „Vikerhommik“, intervjueeris Anu Välba moedisainer Eve Hansoni. „Eelistada võiks kodumaiseid oma lähedal toodetud asju ning pigem vähem kui rohkem.“ Tooted Hiina e-poodides on oluliselt odavamad ning kasutada saab mitmeid soodustusi. Need rõivad koosnevad just kõige rohkem naftast ja on kehvast materjalist. Järeldusena saab öelda, et riided taaskasutuspoodidest või kodumaisetest kauplustest on usaldusväärsemad ja kvaliteetsemad. \nToidu tootmiseks kasutatakse väetisi ja erinevaid kemikaale, mis saastavad meie elukeskkonda ning riiete tellimine umbkaudsetest veebipoodidest kasvatab kiirmoodi. Kokkuvõteks saab välja tuua, et kui need mõlemad jätkuvad on märksa rohkem ühekordset riiete kandmist ning üha rohkem toidujäätmeid, mis aeglustab tuleviku võimalusi nendele lõpp teha.');
