INSERT INTO core.text(id, content)
VALUES ('c31aba94-6620-4505-b558-f089933a12e0',
        'Tänapäeva maailmas on üheks suurimaks probleemiks raiskamine nii toidu kui ka riiete osas. Inimesed on harjunud, et neil on võimalik kätte saada kõike, mida neil tarvis on. Kuid nad ei märka kunagi kui palju kahju see tegelikult teeb ning nad ei mõtle sellele mida kõike see kaasa võib tuua.\nÜheks suurimaks probleemiks tänapäeval on inimeste seas raiskamine nii toidu kui ka riiete suhtes. Inimesed on aastatega harjunud, et neil on kõik vajalik alati saadaval, ning ei pööra raiskamisele eriti tähelepanu. On ka olemas inimesi kes pööravad toidu raiskamisele rohkem tähelepanu kui teised, ning üritavad seda kuidagi vähendada. Igal aastal tekib iga Eesti inimese kohta ligi 61kg toidujäätmeid, millest 26kg on toidukadu ning enamasti koosneb see halvaks läinud ja söömisest ülejäänud toidust. \nRaiskamise alla käivad ka riided. Iga inimene peaks enne riiete ostmist korralikult läbi mõtlema kas tal on neid riideid ikka vaja. Paljud inimesed ostavad endale korraga liiga palju riideid ning kui on neid kandnud vaid paarkorda, siis need kas visatakse ära, põletatakse või viiakse taaskasutuspoodidesse. Suur hulk inimesi tellib ka enda riideid välismaalt, näiteks Hiinast ja muudest suuremate tööstustega riikidest, kust nad loodavad saada head ja kvaliteetset kaupa, kuid tegelikuses saavad nad sealt riideid millest enamus koosneb naftast ning neid on ebamugav kanda ja see on ka põhjuks, miks neid viiakse pärast paari kandmist taaskasutuspoodidesse.\nÜhiskonnad üheks suurimaks probleemiks on raiskamine. Inimesed on harjunud, et neil on kõik olemas, olgu need siis riided või toit. Igal aastal viskab ära iga Eesti inimene keskmiselt pea 61kg toitu. Inimesed ostavad ka liialt endale riideid, mida nad ei kanna rohkem kui vaid paarilkorral ning viskavad need hiljem minema või viivad taaskasutuspoodeidesse, kust keegi teine neid osta saab. Ka internetist tellimisega peab olema ettevaatli, sest sealt ei pruugi alati saada seda kaupa mida olid oodanud.');
