INSERT INTO core.text(id, content)
VALUES ('edcd2357-fc14-4ac6-a303-f398c29602f3',
        'Meie tarbimisharjumused kahjustavad meeledult maailma ja meid endit. Inimesed peaksid hakkama oma emotsioonidele vastu ja mitte tellima asju tujude järgi.\nInimesed tarbivad rohkem, kui möödunud aasta sajanditel ja see on suur probleem meie planeedile. Moedisainer Eve Hanson arvas, et on oluline igalühel vaadata üle oma isiklikud tarbimisharjumused. Tänapäeva mugavas ühiskonnas tellitakse internetist asju tujude või emotsiooni järgi, seda tehes hakkavad asjad aina kuhjuma ja selle tagajärjeks on maja või korter ebavajalikke asju täis. Aastate pärast avastatakse ostetud asi ja visatakse prügikonteinerisse, sest ei leita enam uut kasutust neile. Seda kõike saaks lahendada Hiina e-poodide sulgemisega või iga kuise limiidiga asjade ostus.\nInimesed raiskavad tohutul määral oma toitu. Tarbitoitutargalt veebilehe artikklist saame teada, et ligi 42% toidust läheb kaotsi. Sellisest mitteläbi planeeritud tarbimisest kannatame me kõik, sest planeet ei jaksa kaheksat miljardit inimest ülal pidada. Taimse toidukao saaks anda erinevatele loomadel, kui kadu pole just riknenud, vaid visatud prügikasti. Kui seda teha, saaksime enda harjumused rohkem kontrolli alla ja maailm, kus elame, paraneks.\nToidukao vähendamine on suur ja pikk protsess, mis võib kesta aastaid või sajandeid, ning seda ei saa kaotada üleöö väitis artikkel Tarbitoitutargalt leheküljelt. Söögi tarbimise minimaliseerimine peab algama ülevamalt poolt, ehk valitsusest. Selleks peab tegema kokkuleppe valitsuste vahel, et liimiteerida toidukadu ja hakata liikuma puhtama ja säästlikuma tuleviku suunas. Kuid toidu õige kasutamine võiks alata inimesest endist.\nInimeste tarbimisharjumused on suured ja kahjulikud maailmale. Vähendamine peab algama endist ja valitsused peaksid sellele kaasa aitama, et inimeste tarbimisharjumusi siin mugavas ühiskonnas vähendada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('edcd2357-fc14-4ac6-a303-f398c29602f3', 'title', 'Inimese tarbimisharjumused');
