INSERT INTO core.text(id, content)
VALUES ('317e2808-442e-4ea8-978b-bfb28be4a711',
        'Taaskasutus algab prügi või toiduaine õigest sorteerimisest ja töötlemisest. Tänapäeval on probleemiks maailmas looduse saastumine ja rikkumine prügiga, kuid on olemas firmad ja asutused, kes taaskasutavad jääkaineid enda toodete jaoks ning sellega mõjutatakse noori. \nÜhiskonna suurimaid probleeme on inimeste enda poolt tekkinud loodus kahjumid prügi põhjusel. Telesaates Osoon kirjeldati, kuidas on loomade elud  ookeanis ja maa peal ohus. Ookeanis elusolendid jäävad kile kottidesse kinni, linnud maa peal söövad plasti arvates, et prügi on toit. Tänu inimeste jääkidele peaaegu igast päevast, kannatavad kuskil mujal teised elud.\nMaailmas on asutusi ja firmasi, et sellist olukorda vähendada ning see juhib noorte inimeste tähelepanu rohkem ühiskondlikule murele. Nooremaid inimesi huvitavad riided, välimust muutvad tooted ja näiteks stiilikad saapad. Seetõttu on tehtud poed, kus müüakse odavamalt riideid, mis on toodetud taaskasutuses ja need poed näitavad noortele, mis on taaskasutus ning, millised probleemid maailmas on. Sellega proovitakse tõsta inimeste arvu, kes sorteerivad prügi, põhjusega, et suurt loodus kahjumit vähendada.\nUuema generatsiooni õigele ja paremale teele viimiseks on panustatud paljuid ressursse, et katastroofi võimaluse suurus väheneks. Mõeldakse praegu tulevikule ja tahetakse, et nooremad inimesed mõistaksid kui tõsine asi on prügi õige sorteerimine. Õpetatakse koolis, tehakse koolitusi, kuidas taaskasutada ka bioloogilist jääki enda kodus. Selle kõigega tahetaksegi saavutada paremat tulevikku ja iga päevaga liikuda edasi rohkem arenenud keskkonnas.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('317e2808-442e-4ea8-978b-bfb28be4a711', 'title', 'Inimeste mõju taaskasutusse');
