INSERT INTO core.text(id, content)
VALUES ('3ee0ffd4-846a-4191-82df-d74820ff71d7',
        'Tänaseks on inimesed loonud ühiskonna, kus toodetakse ja müüakse kõike. Kaupa on kõikjalt saada ja see tõttu on ka reostus ja raiskamis probleemid suuremad kui kunagi varem.\nTänaseks on resurside raiskamine väga suur probleem ja kurb tõsi osa on see, et meie inimestena raiskame suhteliselt kõike, mida võimalik. Nagu on kirjas veebilehel tarbitoitutargalt.ee, „ Me ei raiska ainult oma raha, vaid ka tohutult muid ressursse: maad, vett, energiat ja tööjõudu.“ Toidu raiskamises ei saa me süüdistada ainult kodusi, kuna selles mängivad palju suuremat rolli suured poed ja restoraanid. Ma näen tihti internetis, kuidas mõned inimesed käivad ja otsivad endale asju mõne poe prügikastist, naad ei tee seda kuna neil pole raha vaid kuna nad saavad aru, et asjad mida seal ära visatakse on täiesti korralikud. Sa võid arvata, et selline asi toimub vaid Ameerikas kui tegelt tehakse nii ka Eestis ja seda on näidatud isegi telekas. Sellele probleemile oleks lihtne lahendus, aga selleks oleks vaja, et inimesed koos tööd teeks, kahjuks seda tihti ei juhtu, kuna inimesed on enda mugava eluga nii harjunud, et nad ei suuda seda jätta.\nKahjuks kaasneb selle probleemiga ka järgmine probleem, milleks on reostus. Kõikide asjadega mida me tarbime ja kasutame tulevad ka miinused, mis reostavad meie loodust, näiteks kuidas selleks, et poodi jõuaks kaup tuleb enne seda kasvatada, mille käigus me rikkume oma põhjavett ja siis tuleb see ära pakkida ja kohale toimetada, mis omakorda kulutab naftat ja reostab õhku. Ning see on alles algus. Pärast näiteks särgi ostmist kanavad mõned noored seda paar kuud ja siis viskavad selle prügisse, ning lähevad ja ostavad uue. Selle asemel, et särk ära visata võiks naad viia selle taaskasutuspoodi, et selle saaks osta keegi kes seda uuena endale lubada ei saa. Sellest rääkis ka „Vikerhommiku“ intervjus Anu Välba. Reostusest saaksime me koostööd tehes sama moodi lahti. Nagu kui teodorantides olev gaas tekkitas maa osoonis auke, nii et inimesed lõpetasid nende kasutamise. Kuid kahjuks on inimeste mõttemaailm selline, et probleem pole kunagi neis endis ja kui on siis nemad üksinda nii kui nii maailma ei suuda muuta.\nPraegu on maailmas aina suuremaks muutumas reostus ja raiskamine, milles oleme me kõik süüdi. Nende lahendamiseks oleks vaja, et inimesed teeksid koos tööd ja  oleks valmis oma mugavustsoonist välja tulema.');
