INSERT INTO core.text(id, content)
VALUES ('d5b949e1-a51a-4d8f-a3fc-e99d6faf963e',
        'Viimasel sajandikul on inimesed kulutanud ja tarbinud aina rohkem asju. Sinna alla lähevad näitkes toit, riided ja isegi inimeste ära tarbimine. Aga kas sellel on ültse mingit lahendust?\nOn olemas inimesi kes kasutavad ära teisi inimesi, ei lase tal töö kõrvald tava elu elada või siis midagi hullemat veel ja see inimene ei saa ennast kaitsta ka. Inimestel aegajalt vaja vabadust tööst ja kohustustest, et neil oleks aega enda tava elule ka. Inimeste vahel peaks olema võrdsus ja hoolivus mitte, et sind koheldatakse halvasti kui teenid bähem raha või ei teenigi ültse midagi.\nMaailmas on suur probleem riiete kulutamise ja raiskamisega. Inimesed viskavad minema näiteks riideid mis neile ei meeldi enam, et siis lihtsalt sama asi kohe tagasi osta. Selle  asemel saaks kõik ned riided annetada ära või pakkuda kellegile kellel seda riide eset on siis rohkem vaja kui sul. Riide kulutamise probleemist on kerge lahti saada kui vaid inimesed prooviksid. Taaskasutuspoed  või mingi muu asutus kõik ned kohad on kuhu saaks viia oma vanad-uuemad asjad, mida inimene enam ei soovi, ei ole vaja seda kohe ära visata.\nInimesel ise on juba palju harjumusi mis ei pruugi ühiskonnale või kellegile teisele head teha. kuid see ei tähenda et inimesed ei proovi ennast parandada. Kõik riiete kulutamine, toidu ja ära kasutamine ei tee kellegile head aga maailmas on inimesi kes näevadgi vaeva et siukseid asju enam ei juhtuks, ja on inimesi kes isegi ei tee välja nendest probleemidest.');
