INSERT INTO core.text(id, content)
VALUES ('f50d459e-bc65-40c9-afb2-505a4b2cc50a',
        'Igaüks tarbib midagi. Inimesed on harjunud tarbima toitu, et kaua elada. Toit on inimeste kirg, milleta ei saa elada ja oldakse nõus sellenimel tööd tegema, et koht oleks täis. Mis on toit? Toit on elus üks peoriteet, mis aitab kaasa kasvamisele ja mõttemaailmale. Elusloomad nagu näiteks selgrootud, imetajad, sajajalksed ja teised liigid veel, neil on vaja vitamiine. Vitamineraale saab kõige rohkem toidust. Üks poliitik ütles kord, „Kui te jatkade näljutamist, siis sureb see inimkond paarisaja aasta pärast välja.“ Muid võimalusi on ka, kuidas näljutamist ja väljasuremist ära hoida: 1. Hakata kasutama jääkaineid ja kreeme, mis vähese söömis korral aitab kõhtu täis saada, aga minujaoks on see mõtetu raiskamine, sest „mina ja ka enamus inimkonnast ei taha süüa kemikaale ega jääkaineid, mis on laborites igasugustest ainedest kokku segatud ja pole tegelikult kehale hea. Inimestel on vaja vitamiine kehasse, et vaim oleks terve ja keha tugev ja seda kõike saab läbi söögi. Inimkonna esivanemad said teada, kuidas praadida liha, kartuleid saada, kurke ja tomateid kasvatada, aga ikkagi näljutatakse. Üks sõnamees ütles kord, „Toitu jätkub kõigile.“ parem süüa kasulikku toitu mitte, et see ära närtsuks.\nKokkuvõte: Inimesed ei peaks end näljutama. Toit on meie elu üks olulisemaid pioriteete, milleta inimkond ei saa elada. Tänu toidule elame me kauem ja aitab kasvatada imuunsüsteemi.');
