INSERT INTO core.text(id, content)
VALUES ('7f586644-2313-4fb6-b963-2bd2ecb4956a',
        'Iga inimene on oma elus raisanud toitu või viinud ära endale väikseks jäänud riideid. Sellega on suur probleem kuna, kui keegi ei taaskasuta riideid, ostab endale liiga palju toitu ja laseb sellel halvaks minna, siis neid kuhjub kokku liiga palju ning nendega pole midagi teha.\nToidu raiskamise vähendamine on üldiselt kergem, kui võib arvata. Nagu tarbitoitutargalt ütleb, et toidu raiskamist ei saa vähendada üleöö, sest inimese harjumusi on keerukam muuta. Inimene, kes viskab ära liiga palju toitu ja on sellega harjunud ei pruugi aru saada, miks see on halb. Sellepärast peabki neile õpetama ning näitama kuidas on parem toitu säilitada ning liigse toidu mitte ostmist. Kõige rohkem peaks õpetama noori, sest siis nad harjuvad juba varakult kuidas õigesti tarbida toitu. Mina olen ka toitu ära visanud, kui see on halvaks läinud, sest ma ei soovinud seda enam süüa ning mul oli millegi mu isu. Võin öelda, et ma proovin vähem seda teha, sest tegelikult ma tean, et see on halb ning paljud inimesed ei saa seda endale lubada. Toidu ära viskamine tekitab kahju tunde, mille tõttu ei taha ma seda enam teha.\nTaaskasutus on tähtis tegu, mida peaks iga inimene tegema, sest kui riideid ja esemeid kuhjub liiga palju, siis neid kõiki ei jõua ära töödelda ja kõiki pole ka võimalik. Paljud inimesed tahavad osta soodsaid asju ja neid palju, just selliseid leidub tavaliselt Hiina veebipoodidest. Tähtis on see, et inimesed ei ostaks nendest, sest nagu moedisainer Eve Hanson ütles, et need riided koosnevad naftast ja neid ei taha kanda rohkem kui üks kord. Sellele ongi taaskasutamise lahendus. Riiete taaskasutamisel leiab sealt üsna hea kvaliteediga ja soodsa hinnaga riideid. Riiete kuhjumise vähenemist saaks ka vähendada, kui korraldada üritusi just nende jaoks.\nInimestele tuleb kohe näidata kuidas tarbida ja mitte lükkata seda edasi. Inimest on kergem õpetada nooremast east. Taaskasutamine on parem viis endale leida soodsamaid ning kvaliteetseimad riideid. Tarbimisharjumusi saab muuta, kui seda vaid tahta.');
