INSERT INTO core.text(id, content)
VALUES ('3e5c16cb-3546-4d2a-ac88-1768c2231d26',
        'Veebilehel Tarbi toitu targalt on öeldud, et võtame toitu iseenesestmõistetavana, sest meile tundub, et toitu on veel ja see ei saa otsa. Toidu raiskamine on kinni inimeste harjumustes. Aina rohkem inimesi mõjutab tarbeesemete liigne ostmine.\nVäga paljud inimesed raiskavad tohutus koguses toitu. Veebilehe Tarbi toitu targalt sõnul tekib Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 26 kg. Tüüpiline komme on see, kui tõstetakse endale liiga palju toitu ning ei jaksata seda ära süüa ja visatakse jäänused kergekäeliselt minema. Inimesed on harjunud seda tegema, sest nad elavad teadmatuses selle koormusest loodusele. Kui sellist raiskamist jätkata, tekib ühel hetkel olukord, kus toitu on vähe ja ressursse, millega toitu toodetakse, on ka vähe: energia tootmine on veel kulukam, kui enne, tööjõud on toidu vähemusest kurnatud. Toidu raiskamine on väga kulukas tervele majandusele ja inimkonnale ning selle kahjulikkusest tuleks teadlikum olla.\nPopulaarseks on muutunud ka riiete ja muude esemete üleküllus. Me elame materialistlikus ühiskonnas, kus inimestel on vaja kogu aeg osta asju, mida neil tegelikult vaja ei lähe. Ostetakse meeletus koguses riideid ja tarbeesemeid. Sellepärast elavad paljud inimesed pooleldi vaesuses. Iga kord, kui uus palk kätte saadakse, raisatakse see otsemaid kasututele toodetele. Inimestele meeldib sellist ületarbimist ka internetis vaadata ja läbi teiste inimeste sellist eluviisi elada. Jälgitakse erinevaid suunamudijaid, kes postitavad sisu, kus nad näitavad enda uusi riideid, luksuslikke kotte, kingi. Erinevate esemete liigset hulka seostatakse pidevalt luksuse ja rikkusega ning inimestele meeldib sellisena ennast tunda, kuigi nad tegelikult seda ei ole.\nJäänuste ära viskamine on liiga harjumuspärane. Toidujäänuste raiskamine on väga kulukas igale majandusvaldkonnale. Enamik inimesi ei ole teadlikud selle kahjulikkusest tootmisressurssidele. Elame materialistlikus ja rikkusjanulises ühiskonnas. Jälgitakse suunamudijaid, kelle läbi elatakse endale soovitud elu.');
