INSERT INTO core.text(id, content)
VALUES ('af13969f-aa6b-4ca8-b793-9ac8c6639006',
        'Maailmas on palju suuri ja raskeid probleeme millele püütakse leida lahendusi. Üks hullemaid on ületarbimine. Inimkond ei mõista, kuidas see meie tulevikku mõjutab. Mis võib juhtuda kui pole enam ruumi meile, sest oleme ületarbinud.\nInimesed ei mõista, kui suurt kahju me põhjustame ületarbimisega. Arvatakse, et see pole oluline kui palju ja mida me toodame ja ostame. Oleme mõjutatud sotsiaalmeedias nähtust. Aga, mis saab, siis kui meil puudub iseenda jaoks ruum, sest oleme mattunud kõige selle alla? Rakenduses „Tik tok“ ringleb palju videoid just noortest, kes ostavad endale Hiina kaubamajadest asju, mida kasutatakse ühe korra ja visatakse, siis minema. Tulevik on ohus juba praegu ning asi muutub igapäev üha hullemaks. Just noored on need, kes peavad sellest mõtlema ja arusaama, sest nemad on need, kes meie ühiskonda edasi viivad.\nTaaskasutus kohti vaadatakse pilastavalt. Me ei mõtle sellest, et kõik need riided ja mõttetused, mida me ostame lõpetavad oma tee seal. Uhiuute ebavajalike asjade ostmise asemel võiksime osta oma asju rohkem taaskasutus keskustest. See ei mõjutaks mitte ainult tarbimist vaid ka meie enda rahalist seisundi. Kulutatakse sadu eurosid uute riiete peale ning öeldakse kuu lõpus, et raha toidu ja muu vajaliku peale pole.\nTarbimine on puhtalt kinni meie enda sees. Saaksime muuta meie elusid paremaks, kui me teeksime seda vähem. Igale probleemile on lahendus ja kõik need leiame me iseenda vigadest õppimisel ülesse.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('af13969f-aa6b-4ca8-b793-9ac8c6639006', 'title', 'Ületarbimine on maailma tapmine');
