INSERT INTO core.text(id, content)
VALUES ('2084cc4c-7cd1-4845-aeea-4f92b8c9c3c0',
        'Paljud tänapäeva noored ei mõtle kahjule, mis võib järgneda nende riiete tarbimisvajadustele. Riided on meile väga tähtsad aga me tegelikult ei tea mida need esemed võivad mõhjustada maailmale. Loodus mattub prügisse ja loomad, kes peavad selle keskel elama hukuvad. Kas tõesti on moega kaasas käimine tähtis, et selle nimel keegi kannatab?\nPaljud noored eelistavad osta oma riideid kiirmoepoodidest. Sellise käitumisega ei mõelda nad kui palju kahju võib see tekitada. On ka teisi, kes mõtlevad ka säästlikusele. Podcastis „Taskusõbrad“ rääkis Kaisa Roon, kuidas tema ostab oma riideid vanarõivapoodidest, sest see aitab ka raha kokku hoida. Eestisse ja ka mujale maailma on tehtud palju uuskasutuskeskusi, mis aitavad meil maailma parandada. Seal võiksid kõik inimesed käia, et me parandaksime oma ökoloogilistjalajälge.\nLooduses on palju üleliikset riideprügi tänu välismaalt tellimisele. Pea igapäev tellib keegi midagi Hiinast. Nagu ütles ka moedisainer Eve Hanson „ Eelistada võiks kodumaiseid oma lähedal toodetud asju ning pigem vähem kui rohkem.“ Välismaalt tellitakse, sest see on soodne. Kui tuleb välja, et see on mõtetu asi, visatakse see minema. Kõige enam satub selline prügi loodusesse. ERR tehtud loodusaadetes võib mõni kord ka näha olla loomi kes upuvad prügisse. See probleemi on igas riigis, et seda vältida võiks iga inimene ennem mõelda asja tähtsusele kui ta selle tellib.\nOn noori, kes hoolivad ja on ka neid keda ei huvita. Siin maailmas elamiseks on vaja omada suurt silmaringi ja tuleb aru saada, mis kahjustab. Paljusi moekaid asju leiab ka kaltsukatest. Sealt ostes on sootsam ja hoiab rohkem meie maailma, kus elavad ka meie järeltulijad.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('2084cc4c-7cd1-4845-aeea-4f92b8c9c3c0', 'title', 'Noored ja riieded');
