INSERT INTO core.text(id, content)
VALUES ('b06e7860-bec2-4f54-bd9c-bb58f390ddd7',
        'Toiduraiskamine on suur probleem kuna toidu jaoks läheb palju ressursse mis on lihtsalt tühia lennanud kui inimesed selle toidu ära viskavad. Osa inimesi arvab, et nad ei viska väga palju toitu ära, kuid ei tea palju aastas kokku on nad toitu ära visanud mis üllataks neid. Inimesed peaksid rohkem loodust hoidma ja mitte olema nii isekad ja arvama et meie elame üksi siin maal kuid üks inimene on piisavalt palju et reostada maad ja õhku.\nKõik peaksid nägema päris silmaga mis pikk protses käib läbi et saada midagi mille tavaliselt lihtsalt prügikasti viskad ma usun et kui inimesed näeksid seda saasta mis laheb atmosfääri ja prügi mis tekkib siis saaksid inimesed aru et ei ole mõttet raisata nii palju toitu. Mina üritan teha nii palju kui sudan et mitte toitu raisata osataksin poest näiteks suuremates kogustes jogurtit et hoiduda rohkem pakkendite tekkimisest ja sorteeriksin prügi ja viiksin söödava komposti.\nMeie kõik peaksime vähem toitu raiskama ja olema moistlikud mida ostame ja kas ara sööme ja ostma süüa mis ei ole väga palju töödeldud kuna see kahjustab meie planeeti ja reostab õhku mida hingame oleme koik ikkagi siin maal koik koos mitte üksi nii et voiksime seda hoida ja armastada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
