INSERT INTO core.text(id, content)
VALUES ('b062143f-b73f-473a-8406-eecf8f19c8b1',
        'Muidu raisatakse palju toitu, süües jätakse palju järgi. Toidust saadud energiat kulutatakse, ja on oluline, et ka see energia oleks sihipäraselt kasutatud. Ei tohiks väga palju toitu raisata. \nSööma asudes tuleks valida oma kõhule sobivas suuruses portsjon. Vastasel juhul sa jätad palju järgi. Toitu ei ole hea järgi jätta, sest nii nagu väidetakse veebilehe tarbitoitutargalt.ee artiklis „Toidukaost“, et söömisest järgi jäetaud ja muu toidukadu on 26 kg inimese kohta ehk 42% kogu toidujäätmetest. See on väga suur tagajärg ja see tagajärg ei tohiks enam kasvada. See harjumus, et tõsta palju taldrikule, vajab muutmist. Kui endal on keeruline seda muutust teha, tuleb pöörduda toitumisnõustaja poole. Nullist ise alustada on raske ja ei pruugi kaugele jõuda. Võib küll proovida muuta oma toitumist, kuid tavaliselt tuleb puudus teadmistest ning teed ja jätad pooleli. \nTargalt planeeritud ja toitainerikas menüü raiskab toitu vähem. Kui sa saad toidust õiges koguses energiat kätte, ei ole toitu palju vaja. Läbimõeldult toitudes toidukogused vähenevad. Igasugune spordi tegemine kulutab toidust saadud energiat, näiteks jooksmine ja kõndimine. Kui süüa midagi, kus on palju toitaineid, eeldan, et seal on rohkem energiat ja jaksan rohkem joosta ja muud sporti teha. Kui oled söönud toitu, milles on vähem energiat, on kogused tavaliselt suured ja jätad osa järgi. \nTuleks vähendada toidu kogust taldrikul ja mitte liiga palju süüa. Enerigarikas menüü aitab vähendada toidu raiskamist.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('b062143f-b73f-473a-8406-eecf8f19c8b1', 'title', 'Liigne toidu raiskamine');
