INSERT INTO core.text(id, content)
VALUES ('6d24077e-06a8-4b8e-af9d-78e48bab9028',
        'Tänapäeva ühiskond on harjunud ületarbima. Inimesed ostavad kordades rohkem asju kui nad ära tarbida jõuavad. Niisugune teguviis ei ole hea ei rahakotile ega ka loodusele. Veelgi hullem on asjaolu, et taaskasutatud asjadesse suhtutakse kui alternatiivi, mitte paremasse võimalusse.\nPaljud inimesed ostavad omale riideid, mida kannavad vaid korra ning jätavad siis kappi seisma. Tunnen mõnda inimest, kes ostab uut kodutehnikat selleks, et vana, kuid töökorras asi uue ja ilusama vastu vahetada. Kõige rohkem läheb raisku minu meelest toitu. Inimese ostavad suurtes kogustes toitu ning unustavad selle olemasolu. Varsti lähevad asjad riknema ja need tuleb ära visata. Kõkide nende riiete, kodutehnika, toidu ja palju muu tootmine nõuab tohutult energiat, tööjõudu ja toorainet. Varsti ei ole Maal enam piisavalt resursse, et kõike seda tarbimist üleval pidada.\nÜletarbimise üks põhjusi on ületootmine. Tänu ebakvaliteetsele materjalilie toodetakse odavalt ning tehakse igasuguseid sooduskampaaniaid. Värvilised plakatid ja madalad hinnad kutsuvad inimesi ostma asju, mida neil vaja ei ole. Ebakvaliteetne tooraine teeb riiete kandmise ebamugavaks ja vähendab tehnika eluiga – seda ikka selleks, et uut oleks vaja. Inimestele on saanud juba harjumuseks, et mõne aja tagant tuleb uusi riideid osta, kuigi vanad on täiesti kantavad.\nAsju ära visates kahjustame loodust. Prügi ei lagune nii ruttu nagu paljud arvavad. Mina näen lahendust ületootmise vähendamises, selle asemel võiks asju rohkem taaskasutad. Ületootmise vähendamine vähendab ka ületarbimist ning see on just see, mida praegu vaja on.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('6d24077e-06a8-4b8e-af9d-78e48bab9028', 'title', 'Tänapäeva tarbimisharjumused');
