INSERT INTO core.text(id, content)
VALUES ('45398f1a-52b0-4d17-8ebc-1674e969bb72',
        'Eestlased on ületarbimise all kannatanud juba aastakümneid ja tundub, et asi äheb järjest hullemak!!!s. Selles kirjandis seletan lahti, miks see minu arvates nii on ja kuidas saaks seda muuta\n‘’Inimesed on hea elu peale lolliks läinud’’ – Nii ütleb mu isa iga kord, kui uudistes jälle midagi absurdset näeme, ma nõustun temaga, kuigi mina pole kunagi seda ‘’halvemat aega’’ kogenudki. Eestlased ei ole kunagi varem olnud ületarbijad, see pole lihtaslt võimalik olnud: nõukogude ajal, kui toitu ja kõike muud eluks vajalikku sai osta vaid talongidega ei olnud kohe kindlasti nii suurt raiskamist, kui nüüd on. Paljud raiskavad toitu puhtalt sellepärast, et nad saavad seda endale lubada ja see on kurb, sest, vastu levinud arvamust, toit ei ole lõputu vara. Praegu on Eesti poed lookas asjadest, milles veel mõnikümmend aastat tagasi inimesed vaid unistada võisid, seepärast ei ole ka üllatav, et pärast vabaks saamist eestlaste tarbimisharjumused nii drastiliselt muutusid. \nKuidas muuta eestlaste tarbimisharjumusi? Suurt rolli mängib iga inimese panus: ostes vaid seda, mida päriselt vaja on, ümbertöödeldes asju, mida enam ei kasutata ja ära visates ainult neid, mida enam päriselt vaja pole, on suur töö juba tehtud. Pean tunnistama, et ka mulle pole võõras ületarbimine, ikka on vaja kooli uusi riideid ja seadmeid, et ajaga kaasas püsida. Noortel tulebki liigtarbimine ilmselt kõige kergemini, see on ju siiski sotsiaalne surve, et riided peavad olema uued ja trendidega kaasas käima, ka mitu aastat vana telefon on tänapäeval häbiasi. Kõige tähtsam ongi murda stigma selle juures, et taaskasutamine ja ainult vajaliku tarbimine on häbiasi.\nKokkuvõttes arvan ma, et eestlased on oma ületarbimisega liiga kaugele läinud ja seda on vaja muuta läbi inimeste harjumuste ümber treenimisega.');
