INSERT INTO core.text(id, content)
VALUES ('922e2a43-0600-416f-88a0-ac1457de5f76',
        'Inimeste toidu ära viskamine tekitab maailmas kõige suuremat probleemi.Inimesed arvavad, et toitu võib ära visata ja ei saa kuna otsa, aga võib tulla päev kus toitu enam pole, sest inimesed viskavad nii palju sööki ära.\nInimesed tavaliselt võtavad endale suurtes koguses taldriku täis portsu, kuid lõpuks nad ei jõu ära süüa ja peavad ära viskama. Olen märganud, kuidas laevadel juhtub nii oleme, et võetakse suurtes kogustes süüa ja süüakse ainult natukene sealt ära, lõpuks viskavad kogu söögi ära. Mul jääb mulje, et inimesed arvavad kõik söök saab otsa ja neile ei jätku siis peavad kohe suurtes kogustes võtma. Minul tuleb ka muidugi päevi ette kus ma tõesti ei jaksa ära süüa ja pean kahjuks ära viskama, aga seda juhtub paar korda aastas. Tavaliselt võta algul ikka  väikses koguses toitu ja proovin kas mulle maitseb, ja kui maitseb võtan juurde. Inimesed viskavad toitu ära ja ei mõelda selle peale, et nad viskavad oma teenitud raha, ja oma riigi ressursse näiteks vett,  maad, elektrit ja tööjõudu.\nLoomi tapetakse, et inimesed saaksid süüa näitkeks sigu, kanu, kalu ja jne. Mõni loom tapetakse isegi nii sama ära, et kellegile ei maitsenud ja visati prügikasti mis on väga kurb, et mingilt loomalt võetakse sellepärast elu ära, et teda visata prügikasti. Inimesed võiksid  väiksemates kogustes toitu võtta ja mitte ära visata toitu.');
