INSERT INTO core.text(id, content)
VALUES ('5659d81e-c061-4fc5-81bb-4865897cf7e0',
        'Iga inimestel on erinevad arvamused. Aga oluline on see, et kõik nendel on ainult üks teema. Millis arutled inimeste tarbimisharjutused üle?\nEsimene tekst räägib sellest, et maailmas on väga palju inimesi, kes raiskavad toitu, sest nad saavad seda luubada endale. Sellest, inimesed ei raiskavad ainult omaenda raha, vaid ka tohutult meie kodu – maa. Ma väga nõustun sellega. Minu arvamus, inimesed peavad hoida seda, mida meie maa andis meie. Toit on mitte ainult raha, vaid ka loodus. Inimesed tapavad loodus, et nad saavad sellist toitu. Kui ma olin väike, ma ei mõelnud sellest. Ma mõtsin et see on tavaline asi, millest me saame elada. Aga praegu, kui ma olen noor, ma saatsin aru, et kõik mida me teeme on ainult tapimine meie maa, et me saame elada. Ma loodan, et tulevikus, inimesed saavad aru, et see kõik on mitte see, mida me peame teha.\nTeine tekst räägib sellest, et iga inimene peab vaatama üle oma isiklikud tarbimisharjumused. Et inimesed peavad rohkem tarbima ja teha ekskursioonid sellest.  Ma arvan, et see on õige valik, sest et noored saavad vaadata, et tarbimine on väga kasulik. Inimesed ei viiskavad oma rõivad prügikastis, vaid lihtsalt andavad need poodis, kus inimesed saavad  osta need asjad. Ma ise käin taaskasutuspoodide laat, ja ma olen väga õnnelik, et maailmas on inimesed, kes tahavad aidata meie maale.\nMa arvan, et inimesed peavad rohkem hoida meie maa. Nad saavad rohkem tarbida, kui raiskada. Me armastame meie kodu – maa!');
INSERT INTO core.text_property(text_id, property_name, property_value)
