INSERT INTO core.text(id, content)
VALUES ('19c3bd86-9a9a-4c1b-b2f3-e35a85555049',
        'Ületarbimine on tänapäeval suul probleem. Kes enne mõtles ületarbimise kohta? Kus ületarbimine alustab ja kuidas kahjustab? Milline on lahendus?\nEsimene osa tarbimist on küll toit. Inimesed sageli ostavad toite rohkem kui saavad süüa. Selle pärast iga Eesti inimene tekib aastas kuuskümmend kuus kg toidujäätmed. Raistatid toit jaab tarbimata ja inimesed viskavad seda ära. Selle tulemusena toit lihtsalt jõuab prügikastis. Lahendus on osta nii palju toitu kui sa saad süüa ja ei ole vaja osta toitu tuleviku.  Miks on see nii paha? Sest et see müjutab ja kahjustab kõike muut ressursse. Nii finantsid kui ka tööjõudu.\nKa väga suur osa ületarbimisel on riietus. Inimesed viskavad ära riidet mida nad kannaksid üks kord vüi üldse ei kanna millalgi. Maailmas on juba nii palju riie et me saame riietuda kolm põlvkonna enne. Aga inimesed ostavad ja ostavad ja toodavad rohkem kui temale on vaja. Hea lahendus on osta riidet taaskastuspoodil ja viima oma riied mida sa ei kanna rohkem. Niimoodi saame uued riied osta, vanad riied mida sa ei kanna viia poodil ja kegi teine saab seda osta kellele see riie on vaja.\nInimesed tootavad rohkem kui nad saavad tarbima. Selle pärast palju toodangust. jaavad tarbimata.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('19c3bd86-9a9a-4c1b-b2f3-e35a85555049', 'title', 'Ületarbimine');
