INSERT INTO core.text(id, content)
VALUES ('df51ef06-d3ae-4aa5-8bbe-8c464c5775df',
        'Telefon, arvuti, telekas on kõik uueaja leiutised kuna sajandeid tagasi elati ilusti ilma nutiseadmeteta. Kui telefon leiutati tähtsaks kasutuseks, on see nüüd lihtsalt meelelahutuseks.\nNutisõltuvus on sõltuvus kui tarbid ekraani liiga palju ja inimesed seda ise aru ei saagi kui see on liiga palju. Veetes aega telefonis tunneb inimese aju mõnu uue informatsiooni saamisest ja päris elu kus sa ei saa nii kiiresti, nii palju uut infot on järsku igav. Inimene ei viitsi olla enam füüsiliselt aktiivne ja mõned ülesanded mis olid kunagi lihtsad on järsku rasked. Näiteks isegi enda toa koristamine või nõude pesemine on muutunud väljakutseks. Inimene hävitab enda sotsiaalelu kuna ta vaatab tervepäev teiste inimeste paremat elu, kuidas teistel on rohkem raha ja kuidas reisitakse ümber maailma. Samalajal kui veedad terve oma päev voodis, jalga tõstmata. See võib tekitada depresiooni ja pähe tekib sul ainult mõte kui halb su enda elu on.\nSõltuvusest on aga mudugi võimalik üle saada, kuid see ei ole nii lihtne, kui inimesel on tugev sõltuvus oleks tal kindlasti kellegi abi vaja, kas toetav sõber, pereliige kasvõi psühholoog. Näiteks kui suu sõber lihtsalt kirjutab sulle „Kuidas sul läheb?“ võib see juba aidata. Üksinda sõltuvusega toime tulemine võib olla raske ja kui tead, et ei ole üksi on see lihtsam. Mõeldakse, et tahetakse paremaks saada aga alustad sellega homme, kuid kui tahad päriselt parmaks saada siis alusta sellega kohe.\nEhk usun, et telefonide mõttet on kuritarviatud, on tekkinud koguaeg juurde asju mida me tegelt ei vaja ja mis on meile halb. Ekraani võib vaadata, kui oskad seda mõõdukalt tarbida.');
INSERT INTO core.text_property(text_id, property_name, property_value)
