INSERT INTO core.text(id, content)
VALUES ('f30615fd-678d-46f6-8539-0edf6ca2c24d',
        'Maailmas on mitmeid probleeme, kuid üks suurimaid on raiskamine. Asju toodetakse liiga palju ning selle käigus läheb suur osa raisku ja paljud inimesed isegi ei märka seda.\nRaiskamist on võimalik ära hoida mitmel viisil, kuid iga inimene peab sellest aru saama. Riiete puhul ei pea koguaeg tootma uusi riideid, mille jaoks on ka vaja kasutada energiat. Selle asemel saaksid inimesed käia riiete taaskasutuse poodides, kuna seal on odavamad riided, suur valik ja siis saaks raiskamist vähendada. Küll osad inimesed arvavad, et mingi teise inimese poolt juba kantud riiete ostmine võib olla rõve, aga need pestakse ära ja vahepeal võib leida neist poodidest kalli brändi riideid väga odava hinnaga. Hanson rääkis, et iga nädalaga kuhjub meeletus koguses riideid juurde taaskasutus poodidesse. Mina ise käin sõpradega taaskasutus poodides koguaeg kui vabaaega on, kuna ma olen varem leidnud sealt hea brändi riideid paari euroga.\nToidu raiskamine on jube teema ning maailmas on olemas inimesi, kes raiskavad toitu, lihtsalt sellepärast, sest nad saavad. Iga toiduraiskamine peaks olema keelatud, kuna maailmas on riike, kus inimesed saavad vaevu süüa ja juua. Mind on alati õpetatud toitu mitte raiskama ning, et kui toitu peaks järgi jääma saab selle alati panna karpi ja järgmine päev edasi süüa, et toitu mitte raisata. Igal Eesti inimesel tekib aastas ligikaudu 61kg toidujäätmeid, millest 42% ehk 26kg on toidukadu. Toidukadu on see kui toit läheb riknema ja inimene viskab ära selle ning, et ta raiskab toitu,vett,energiat ja oma raha.\nRaiskamine on küll suur probleem, aga see on ajapikku muutunud paremaks,  mis on hea, sest toidu ja riietekadu on maailmas suur probleem olnud juba pikemat aega.');
INSERT INTO core.text_property(text_id, property_name, property_value)
