INSERT INTO core.text(id, content)
VALUES ('1f51cb9e-485f-4967-88c0-979bf47782cd',
        'Kodumajapidamistes tekib iga Eesti inimese kohta aastas suures koguses toidujäätmeid. Seetõttu ei kuluta me ainult enda raha, vaid ka muid ressursse näiteks nagu: vett, energiat, maad ja tööjõudu. Toidu raiskamist ei saa nii kiiresti vähendada kuna see on ülemaailmselt inimestel harjumuseks ja seda tehtakse igapäevaselt. Samuti tekitab toidu tootmine tõsise keskonnakoormuse kuna selleks, et saagikust tõsta, on vaja kasutada väetesi ja erinevaid kemikaale. Inimesed võiksid vaadata üle oma toiduharjumused ja mõelda viise kuidas saaks toidukaost vähendada. Moedisaineri Eve Hanson arvab, et „Eelistada võiks kodumaiseid asju või oma lähedal loodud asju ning pigem vähem kui rohkem“. Tema arvates ei tohiks inimesed Hiina veebipoodidest asju tellida juba põhimõtte pärast ja ei läheks kaasa sooduskampaaniatega. Samuti on  paljudes taaskasutuspoodides rõivaste kogus üüratult suur mis koguneb aina juurde. Inimesed ei saa aru milline raiskamine toimub nende ümber ja nende poolt. igapäev kulutavad inimesed tohutuid summasi riiete peale mis koosnevad kahjulikest kemikaalidest näiteks nagu nahftast. Toidukaos saks väheneda ainult siis kui inimesed märkaksid ja muudaksid oma halbu harjumusi toidujäätmetega ja hakkaksid valima tervislikemaid ja looduse sõbralikke tooteid ja asju. Toidu ära viskamise asemel võiksid inimesed vähendada toidukogust mida nad ostavad enda koju ja kasutada õigel ajal ära lähestikku oleva kasutustähtajaga toitu. Nii paraneks toidukaos ja loodus.');
