INSERT INTO core.text(id, content)
VALUES ('35ae1c46-6084-45b7-93fa-342f802c9d44',
        'Ületarbimine on tänapäeval väga suur probleem. Inimesed välja viskavad nii palju toidu. Näiteks Eestis iga inimese kohta tekib aastas keskmiselt 61 kg toidujäätmeid. Kujutele, kui palju toidujäätmed tekkivad kõiged inimesed koos iga aasta. Kuidas seda piiri panema?\nEsimene probleem võiks olla ülesöömine. Inimesed võttavad nii palju toitu ja ei söö kõik. Näiteks vanemad tihti annadav lastele nii palju toitu. Aga lapsed on väikesed, nendele ei ole valja palju toitu. Või on lihtsalt inimesed, kes ei oska kui palju toitu nad peavad võtta ja võttavad nii palju. Probleemi lahendamine võiks olla arvutama, kui palju toit sa võttad. Näiteks, ma iga kord võttan nii palju ja pean välja viskama toitu. Või ma lihtsalt söön liiga palju.\nTeine probleem võiks olla, et inimesed karjavad nii palju tooded ja nad mädavad. Me võttame nii palju metsas ja ei anda mitte midagi vastu. Ei ole oluline, et tooded, mida me võttame metsast on ökoloogilised. Karjama nii palju tooded ja jätma need, et nad mädavad, on väga halb. Probleemi lahendamine, ma arvan, võiks olla jälgima, kui palju inimesed võttavad metsast.\nKokkuvõtteks võiks öelda, et ületrbimine on tänapaeval väga suur probleem ja et lahendada seda me võime arvutama kui palju me peama tabima iga päev ja jälgima kui palju me võttame metsast.');
INSERT INTO core.text_property(text_id, property_name, property_value)
