INSERT INTO core.text(id, content)
VALUES ('8687cddc-52e6-4fed-ac70-39b0cacf89d0',
        'Meie ühiskonnas on väga suur probleem. Inimesed kasutavad nii palju toitu ja teised muud asjad, mis võib olla auselt ei ole vaja nende jaoks, aga kõik jäätmed pole läks lihtsalt kuskil. See on meie Maale ja meile on väga ohtlik ja ebakasulik.\nMa näitan iga päeva internetis veebilehes kui palju prügi on Maal praegu. Kõik oskavad, et see ei ole hästi ja mõned teised ka teevad sellega midagi, aga see probleem on veel olemas. Inimesed raiskavad prügi keskkonnas ja pärast nad söövad mingid loomatoodet ja oli näited, kui lihas või kalas oli prügi. Minu jaoks see on väga kurb. Inimesed teavad, mis nad teevad, aga loomad ei saa seda kontrollima. Ühiskonnad, mis reguleerivad see küsimusi ja annavad meile mingi lahendus väga aitavad meid. Aga et inimesed tahavad lõppeb prügiga ühiskonnas, kõik peavad sellega töötama.\nInimesed võivad ka lihtsalt ära hoida loodust. Minu elus oli üks kord, kui ma jalutasin sõbradega ja me tegime väike süüa plats järve  kõrval. Ma ei saa aru miks, aga nad hakkavad raiska prügi ja jäätmed järves. Ma ütlesin nendele, etei ea seda teha, aga nad ei kuulavad ja raiskevad seda väga kaua, nii et ma eu saa võta. See oli naeraselt teid. Praegu ma ei tea kus on see prügi. \nKõik peavad hoia loodus lapsepõlvest. Ma arvan, et vanemad peavad õppima selle lapsega ja noorega, sest see ühendama meie Maaga.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('8687cddc-52e6-4fed-ac70-39b0cacf89d0', 'title', 'Raiskamine meie ühiskonnas');
