INSERT INTO core.text(id, content)
VALUES ('e5a43a81-9bcc-45e0-9ca3-a5d6dac7dd94',
        'Tänapäeval on paljudel inimestel suured võimalused ja saavad endale lubada toidu ära viskamist ja uusi rõivaid. Paljud inimesed ei osta kvaliteetseid rõivaid, vaid tellivad need Hiinast väikese summa eest. Pärast lühikest aega kandmist need riided pole enam mugavad, kuna tegu on mitte nahasõbraliku materjaliga.\nRiided on asjad mida meil läheb igapäevaselt vaja. Sellepärast tahetakse osta endale võimalikult palju riideid. Mängus on ka raha, sest paljud inimesed ei saa võimaldada endale osta kvaliteetseid rõivaid. See on jõudnud selleni, et tekitati internetiplatvormid, kust saab väga väikese summa eest endale ilusaid riideid. Rõivaid müüakse seal odavalt, sest need ei ole kvaliteetsed ja kestavad lühikest aega.\nKui viia inimesi taaskasutuspoodide lattu siis võibolla mõni inimene nõustub sellega, et tuleks vähem raisata ja soetada taaskasutatavaid rõivaid. Teises pildis on nii, et mõni inimene ei pane selga teise omaniku rõivaid ja ostabki endale niiõelda ühekordseid riideid näiteks Hiina veebipoodidest.\nHiina veebipoed on üsna kavalad. Näiteks nad meelitavad inimesi ilusate reklaamfotodega asju ostma, mitte teades selle asja tegelikku materjali. Näiteks tellisin pusa mis nägi ilus välja, kui see kohale jõudis siis tundsin pettumust materjali osas.\nToidu raiskamine on inimeste harjumustes. Kui toit läheb halvaks või on üle kasutuskõlbliku aja, läheb see prügikasti. Iga toidu ära viskamine on halb meie keskkonnale. Riiete liigne ära viskamine toob ka keskkonnale koormust. Inimesed võiksid vähem toitu ära visata ja mitte tellida niiõelda ühekordseid riideid.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('e5a43a81-9bcc-45e0-9ca3-a5d6dac7dd94', 'title', 'Inimeste liigne toidu ja riiete raiskamine');
INSERT INTO core.text_property(text_id, property_name, property_value)
