INSERT INTO core.text(id, content)
VALUES ('984ef02a-b94e-487f-b73f-9d97e487faf7',
        'Ületarbimine on maailmas suur probleem, see raiskab tööjõudu ja resursse, ning meie oma raha. Inimesed peaksid õppima mis on kogu toidu- ja riietetööstuse taga ja kuidas olla säästlik tarbija.\n Ületarbimisega kaasneb palju keskkonna probleeme. Keskmises Eesti kodumajapidamises tekib aastas keskmiselt 61kg toidu jäätmeid iga inimese kohta, millest raisku läheb umbes 42% mis on tervelt 26 kg. Lisaks ka toidujäätmetele jõuab meie ilusasse loodusesse erinevaid riide jäätmeid. Näiteks riided mida inimesed on näinud ilusatel reklaamfototel ja seejärel ostnud, tegelikult kannavad nad neid riideid ainult ühe korra ning see järel jäävad need kas kappi seisma või lähevad äraviskamisele.\nPeaks lastele juba varkult õpetama säästlikku tarbimist. Minu arvates võiks hakkata nooremale generatsioonile juba koolides õpetama säästlikku tarbimist mille käigus õpivad nad kuidas säästa raha, ning resursse. Ka moedisainer Eva Hanson saates „Vikerhommik“ tõi välja, et suur hulk meie ostetud riideid jõuavad erinevatesse taaskasutuspoodidesse, ning see on väga õpetlik. Hanson arvab, et oleks kasulik teha noortele ekskursioone nendesse taaskasutuspoodidesse, et nad näeks kui palju riideid tegelikult raisku läheb. Nii saavad noored end paremuse poole muuta.\nÜletarbimine on meie keskkonnale halb, inimesed raiskavad üle 40% oma ostetud toidust mille pealt oleks saanud säästa raha ja resursse. Lisaks peaks minu arvates juba lastele koolis õpetama säästlikku tarbimist. Mis aitaks kaasa puhtamale keskonnale ja säästlikumale ühiskonnale.');
INSERT INTO core.text_property(text_id, property_name, property_value)
