INSERT INTO core.text(id, content)
VALUES ('960a561d-2ced-4892-a92c-98535f9ea007',
        'Tänapäeval on suureks probleemiks ületarbimine. Selle probleemi üks väga suur tegur on kiirmood. Mis on kiirmood ja kuidas saaks seda vähendada?\nKiirmood on erinevad riide suundumused. See tähendab, et lühikest aega on väga populaarsed mingid kindlad riideesemed või mingi kindel riietusstiil. Kui üks riietus suund saab läbi, siis visatakse või annetatakse need riided ära ning ostetakse uued. Selle tagajärjel tekib väga palju prügi ja riiete raisku minemist. Moedisainer, Eve Hanson, püüdleb riiete ületarbimise vähendamise poole ning ei poolda kiirmoega kaasa minemist. „Eelistada võiks kodumaiseid oma lähedal toodetud asju ning pigem vähem kui rohkem“.\nÜheks suureks kiirmoe ja ületarbimise probleemiks on erinevad veebipoed, kust saab tellida väga odavalt Hiinas toodetud riideid ja aksesuaare. Kõige kuulsam ja enim kasutatud veebipood on Shein, mille riideid ja aksesuaare toodavad kohalikud Hiina elanikud väga väikese palga eest. Paljud noored tellivad sealt mõtetult suures koguses riideid, mille nad peale paari kuud ära unustavad, ei kanna neid enam ning, siis tellivad uuesti järgmised riided mis moes on. Mina arvan, et kui sellel veebipoel tegutsemine ära keelata, siis väheneks riiete ületarbimise protsent oluliselt.\nKiirmood ja ületarbimine on omavahel tugevalt seotud ning selleks, et ületarbimist vähendada tuleks Shein veebipoel riiete müümine ning üleüldine tegutsemine ära keelata.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('960a561d-2ced-4892-a92c-98535f9ea007', 'title', 'Ületarbimine ja kiirmood');
