INSERT INTO core.text(id, content)
VALUES ('4fd399c6-f1eb-41b7-8d82-50df1fb06f31',
        'Inimesed tihtipeale kipuvad toitu raiskama, sest nad ostavad midagi ja kui üle jääb, siis muidugi on inimestel esimene mõte, et mida sellega nüüd edasi teha ja kahjuks jõuavad nad selle otsuseni, et see toit ära visata.\nKindlasti on meil maailmas üks suurim probleem ülekaal, sest inimesed ei kontrolli oma taldriku kogust ja ei hoolitse enda eest, mis ei ole üldse hea. On väga palju viise kuidas olla mormaalkaalus, näiteks trenni tegemine, iga päevane liikumine, tervislik- ja normaalkoguses toitumine.\nInimesed ei pane ise ka tähele,  kui palju halba nad teevad sellega, kui nad ostavad asju üle ja siis need pärast ära viskavad, nad raiskavad ilmaasjata oma raha ja nende mõte on, et „ostan lihtsalt uued, pole midagi hullu“. \nTuleks osta mõistlikus koguses toitu, teades et sa selle kõik ka ära kasutad ja ära sööd.\nKui sa ostad riideid, siis tuleks mõelda ka selle peale, et mida sellega pärast peale hakata.\nNäiteks võiks enda vanadest riietest valmistada uus, sest kui viid taaskasutuspoodi mingi riide ja keegi seda ei osta, siis arvatavasti visatakse see pikapeale ära.\nPaljudel noortel on kapid riideid täis, aga nad isegi ei kanna neid, mis tähendab, et see on täielik raharaisk.\nTuleks mõelda rohkem kokkuhoiule ja kui palju sa mida tarbid. On mõistlik mõelda meie loodusele ja inimestele.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('4fd399c6-f1eb-41b7-8d82-50df1fb06f31', 'title', 'Inimeste tarbimisharjumused');
