INSERT INTO core.text(id, content)
VALUES ('9ee02f48-f469-4720-b2d2-7889f643cce0',
        'Mina arvan, et kõik sõltub inimestest, kas nad ise tahavad midagi muuta ja säästa maailma või mitte. Probleem on selles, et paljud ei tea tagajärge ja ei uuri seda aga isegu kui teavad ei usu seda. Paljud ostavad liiga palja toitu, riideid ja muud kraami aga ei söö kõik ära või ei kasuta nii palju nagu see ette nähtud. Paljud isegi ei pane riided selga mida on kunagi ostnud, nad vedelevad niisama kappis ja hiljem neid visatakse ära. See kõik reostabki maailma. minu põhiseisukoht on see, et võiks olla natuke säästlikum.\nÜks suurimatest probleemidest on riiete ostmine ja nende ära viskamine. See reostab palju loodust ja maailma kuna neid ostetakse ja mõneid nendest ei kannagi vaid lihtsalt visatakse ära. Üks probleemi lahendamistest on see, et enne ostmist sa mõtleksid kas on seda vaja, palju sa seda kannad, kuhu sa seda paned ja kas on sul riided millega see sobiks kokku. Kui sul ikkagi juba on riided mida sa ei kanna siis neid oleks mõistlik kas müüa maha näiteks sotsialmeedias või viia taaskasutuskeskusesse.\nTeine on toitu raiskamine ja selles ostmine suurtes kogudes. Paljudel see toit on niisama külmikus ja teda keegi ei söö, ainult ostab juurde. Sellega läheb palju kaduma kuna toit läheb vanaks ja sellega pole enam midagi teha tuleb ta ära visata. Mina arvan, et tooteid mille kasuustähtaig on lühike tuleb osta väiksetes pakkendites või täpselt niipalju kui sul endal vaja. Enne poodiminekut võik sul olla valmis nimikiri ja kui palju sul mida vaja on.\nKolmandaks probleemiks nagu ma arvan on prügi maha loopimine. Eestis seda on vähem kui teistes riikides aga ikkagi on. See ka reostab maailma pärispalju kuna laguneb väga kaua. Probleemiks on ka prügikastide puudus, näiteks kui ma käisin Inglismaal Londoni kesklinnas meie ei leidnud ühtegi prügikasti, selle tõttu ma arvan, et paljud loobivadki prügi maha kuna ei viitsi seda kaasa tassida.\nKokkuvõteks on see, et kõik sõltub inimestest ja nendetarbimisharjumusi on väga raske muutu, kuna teevad nad seda terve elu ja nende jaoks on see mugavam.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('9ee02f48-f469-4720-b2d2-7889f643cce0', 'title', 'Inimeste tarbimisharjumused');
