INSERT INTO core.text(id, content)
VALUES ('c69a0b5f-54f7-4e2c-b404-630c85a66eae',
        'Millised on inimeste tarbimisharjumused?   \n   Palju sõltub inimesest, kas ta tahab maailma kokku hoida või mitte. \n     Üks suurimaks probleemiks on toidu ära viskamine. Inimesed ei saa aru toidu väärtusest ning mõtlevad,et meil on seda lõpmatu kogus. Kes viskavad väikestes kogustes mõtlevad,et see pole palju ja ei tee mingit kahju keskkonnale, aga see pole nii Eestis inimese kohta aastas keskmiselt visatakse 61 kg toidujäätmeid ning sellest 26 kg on toidukadu ehk toit, mida saaks süüa. See on küllaltki kurb, et paljud ei väärtusta toitu. Eriti praeguses majanduskriisi olukorras on toidu tootmine palju raskemaks muutunud ning kuulub palju rohkem ressursse tootmisele.See tähendab,et kui visatakse mitte ära söödud toidu ära nad ainult ei raiska oma raha, vaid ka muid ressursse: maad, vett, energiat ja tööjõudu. \n    Teiseks suureks probleemiks on suurtes kogustes riiete ost eriti Hiina saitidelt ostetud odav naftast tehtud riided. Kahjuks praegune rahaline olukord maailmas teeb niiet inimesed otsivad odavamaid variante. Internetimaailm ja iga aasta uus mood soodustab suurt uute riiete tootmist. Inimesed tahavad ju olla moekd ning ostavad endale usi riideid, aga võiksid selle asemel mina ja otsida taaskasutus poodidest endale riideid. Ma arvan,et sealt vabalt võiks leida midagi huvitavat ning moekat\n     Inimesed peaksid väärtustama seda,mis neil on ning saama aru kui palju ressursse kuulub mingi asja või toidu tootmisele. Minu arvates võiks koolis teha tunde,kus õpetatakse väärtustama ning taaskasutama asju. Seda võiks juba algklassides õppida,siis inimestel jääb see harjumust varasesteast.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('c69a0b5f-54f7-4e2c-b404-630c85a66eae', 'title', 'Inimeste tarbimisharjumused');
