INSERT INTO core.text(id, content)
VALUES ('cf0d6a4e-3542-46d5-810f-f6938f31b638',
        'Inimesed on juba harjunud selleks, et neil on võimalus süüa, jüüa ja saada kõike, mida nad ise tahavad. Aga probleem on selles, et inimesed ei mõtle isegi selle peale, kui palju kuulub selle peale ressursse, kui palju tööd teevad teised inimesed selleks, et me saaksime lihtsalt poes käia.\nInimesed, kes iga päev töötavad selleks, et meie saaksime pärast tööd või kooli endale süüa osta, väsivad väga palju, sest iga leivatükki tegemiseks kuulub väga palju jõudu ja ressursse. Aga, kuidas meie saaksime leida selle probleemi lahendust ? Tegelikult see on väga lihtne, kui inimesed ostaksid endale toitu just sellistes hulkades, mida nad saavad  ära süüa, siis toiduraiskamist oleks palju vähem.\nMiks on parem osta riideid või muid asju enda lähedal, kui mitte Hiina veebipoodidest? Inimesed on juba harjunud vaadata pilte ja näha pildi peal seda, mis neile meeldib. Aga, paljud inimesed tellivad asju ja isegi mõnikord ei vaata, millest on näiteks tehtud üks ilus kampsun ja missugune ta päriselus on. Just selle pärast inimesed viskavad asju nii sama ära, sest nendele ,kas materjal ei sobi või kampsun ei olnud pildiga sarnane. \nMina ise olin kokku puutunud selle kogemusega ja tellisin erinevates veebipoedes endale erinevaid asju, aga mul olnud ka selliseid olukordi, kus ma pidin pärast ümber õmmblema minu tellitud kleit, ja selle tegemiseks ma veel maksin raha. Pärast ma mõtlesin,  kui palju mul kuulus raha kleidi peale, transpordi peale ja veel kui ma andsin seda ümber õmmblemisele, siis ma sain aru sellise hinnaga ma võiksin osta endale kleiti just meie poes.\n Ma saan öelda seda, et kui inimesed hakkaksid päriselt aru saama kui palju nad kahjustavad loodust, siis nad võib-olla teeksid endal elus midagi teismoodi. Parem osta endale väike portsjon, aga teades et sa sööd seda ära ja ei viska. Parem käia poes ja proovida riided iseenda peal, vaid mitte loota et see asi päriselt sobib sulle.');
