INSERT INTO core.text(id, content)
VALUES ('0265d4b5-648d-4f19-b797-a75c263b98c1',
        'Paljude inimeste tarbimisharjumused on väga halvad. Nad on harjunud midagi tegema ja nii nad seda kogu aeg ka teevad. See kõik ei ole hea.\nInimesed ei oska asju kokku hoida. Enamus inimesi arvavad, et vesi ei saa kunagi otsa, aga see ei ole ju tõsi. Paljudes riikides on väaga suur vee puudus ja kui ka teised inimesed ei hoia vett kokku, siis kaob vesi veel rohkematest kohtadest ära. Söögiga on samamoodi. Inimesed viskavad toitu ära, aga mõned inimesed nälgivad. \nTuleb hoolikalt asjade üle mõelda. Peab inimestele selgeks tegema, et kui nad niimodi raiskavad sööki ja jooki, siis varsti on meil kõik otsas see, et mõned arvavad ,et söök ei saa kunagi otsa pole kindalsti tõsi. Kui inimesed ei mõtle enda tegude peale ja arvavad, et see kõik on okei. \nRiided on ka üks suur probleem. Paljud noored tellivad endale riideid kuskilt hiinast jne. Nende riiete materijal võib olla väga väga halb, aga hea hinna eest ja muidugi paljud tellivad. Aga kas päariselus on ka see toode nii hea ja ilus kui pildi peal? Mina seda väga ei usu, kuna iga nädal tuleb taaskasutuspoodidesse uusi riideid, mis täahendabki seda, et inimesed raiskavad mõtetult raha. Nad tellivad midagi, kannavad ühe korra ja kas viskavad minema või viivad taaskassutuskeskusse.\nMa arvan, et inimesed peaksid rohkem rääkima sellistest probleemidest, et inimesed muutuksid ja saaksid aru kõigest. Noortel pole tõepoolest väga aimu sellest.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('0265d4b5-648d-4f19-b797-a75c263b98c1', 'title', 'Inimeste tarbimisharjumused');
