INSERT INTO core.text(id, content)
VALUES ('622a41dc-2d95-4f1c-af91-7dac3036e991',
        'On tekkinud harjumus, et toit on alati poes veel olemas ehk pole vaja selle lõppemise puhul paanikasse sattuda. Iga kord raisatakse raha aga ikkagi midagi tarbijatele ei meeldi.\nKui arvestada sellega, et ülemaailma on praegu nii öeldud kriis, see on suureks probleemiks muutunud. Paljudel on huvi proovida midagi uut ja selles pole midagi, aga kui oled juba proovinud ja ütled, et sulle ei meeldinud, siis pole vaja seda korduvalt muretsema. Täielik ja puhas raha raiskamine. Praegusel ajal on nii palju erinevaid võimalusi taaskasutuses või uuskasutuses, et raha nii teenimine kui ka säästmine on lihtsamaks muutunud.\nGloobalselt vaadates, on maailmas palju selliseid riike kus isegi rahateenimise võimalusi pole. Võib-olla, selline rahvas oleks hea näidis meie jaoks. Hiina omab suure populaarsuse veebipoodide hulgas, sellised saidid nagu „Shein“ ja „Temu“ kasutavad erinevaid võimalusi, et tooted saaksid kiiremini müüdud. Igasugused reklaamid ja propagandad mojutavad inimesi raharaiskata veel rohkem.\nInimesed, kes teenivad päris suure summa saavad vabalt raharaiskata kuidas tahavad. Aga kui jutt käib sellistest kes teenivad vähem kuik keskmine palk siis võiksid olla natuke säästlikumad. Loodame, et varsti puhas raharaiskamine ja selle kuritarvitamine lõpeb, ja et inimesed osaksid oma teiste kuludega arvestada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('622a41dc-2d95-4f1c-af91-7dac3036e991', 'title', 'Keskkonna tarbimisharjumused');
