INSERT INTO core.text(id, content)
VALUES ('f681c1d5-eab9-4299-a87a-43f7d0fbc18f',
        'Inimesed viskavad palju asju aru ja ei mõtle, et see võib olla kahjulik nii endale kui ka maailmale.  See tekitab väga palju probleeme keskkonnale.\nToidu ära viskamisega tekitame liiga palju prügi ja paljud inimesed isegi ei viska seda prügikasti, vaid kuhugi tänavale. Nii seame ohtu loomad, ning  looduse. Osad inimesed sülitavad nätsu kuhugi tänavale ja ei korja seda üles siis linnud, kes seda lähevad nokkima ei saa seda oma kurgust välja ja nad lihtsalt lämbuvad. Ma arvan, et väga hea lahendus on, et sa saad viia riided, mis on sulle väikseks jäänud taaskasutuspoodi. Siis osad ei viska seda nii sama minema ja ei teki üleliigset prügi.\nKui olen käinud kusagil metsas jalutamas olen alati näinud mingit prügi vedelemas ja see läheb iga aastaga aina hullemakas.Kahjuks inimesed ei võta seda üldse tõsiselt kuigi see probleem on juba väga mitu aastat esinenud. Inimesed arvavad, et see väike prügi ei tee midagi, kuid kui iga inimene nii mõtleb siis seda tekkib ikka päris palju. On veel selliseid, kes isegi viskavad jõkke mingeid saaste aineid. \nTahaksi väga loota, et inimesed hakkavad mõistma seda probleemi ja saavad aru, kui tõsine see tegelikult on ja milliseid probleeme see tekitab. Kui inimesesd hakkaksid sellega tegelema siis loodus oleks palju puhtam ja  paljud loomad ei peaks surema inimeste pärast.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('f681c1d5-eab9-4299-a87a-43f7d0fbc18f', 'title', 'Tarbimisharjumused');
