INSERT INTO core.text(id, content)
VALUES ('6dd14d4c-c87b-4d5b-be55-6b8dfaf4e1f1',
        'Inimesed väga palju ületarbivad ja ei ole ökonoomsed riiete ja toidu suhtes.Nad raiskavad oma raha selle peale mida ei söö või ei kanna.\nToidu ja riiete raiskamine maailmas on väga suur probleem, kuigi inimesed ei saa sellest aru.Nad ostavad igasuguseid riideid veebipoodidest,kannavad seda ühekorra ja viskavad ära.Ostavad palju toitu,ei jõues seda ära süüa, sest toidu kehtivus on juba läbi.\nInimesed ostavad palju toitu,ega jõua seda ära süüa.Kui poes on soodustused ,inimesed tormavad toidu järgi,ostavad liiga palju ja pärast imestavad ,et toidu kehtivus on läbi.Nad peaks säästlikum olema,ostma ainult 3-4 päevaks,et jõuda seda ära süüa ja ,et mitte ära visata.Riiete puhul inimesed võiks osta kallima aga kvaliteetset riietust,mitte odavam veebipoest mida kannavad ühekorra.See on raha säästmine ka.Ostes veebipoest palju riiet ,sest : „Praegu on soodustused“ , inimesed ei märka kuidas raiskavad palju raha selle peale mida pärast ei kanna,sest see on kehale ebameeldiv.\nJärelduseks võiks öelda ,et inimesed ei ole ökonoomsed riiete,toidu ja raha puhul aga seda võib muuta.Võib osta toidu 3-4 päevaks,et jõuda seda ära süüa,osta kallimaid kuid kehameeldivaid riiet ja säästa tänu sellele raha.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('6dd14d4c-c87b-4d5b-be55-6b8dfaf4e1f1', 'title', 'Inimesed ei ole ökonoomsed.');
INSERT INTO core.text_property(text_id, property_name, property_value)
