INSERT INTO core.text(id, content)
VALUES ('b00c1ed1-a00a-4b97-ac9e-86f13f4f52c5',
        'Tänapäeval on paljudel inimestel oma harjumused igasuguste asjade kasutamises või omamises. Need võivad tekkida ümbruskonna jälgimises ning omaenda iseärasuste toimimisel. Muidugi on neid võimalik kuidagi parandada või paremaks muuta. Järgnevas osas toon välja minu arusaamad nendest omamoodi harjumustest ja mõtted nende efektiivsemaks muutmise ning parandamiseks.\nToit on oluline osa meie inimkonna heaolust. Ilma toiduta me ei suudaks elu elada ega tervena püsida. Aga teades seda on meil olemas üks probleem ja see on toidu raiskamine. Paljud inimesed ostavad erinevaid toidupooliseid ainult selleks, et see pärast prügikasti satuks. Aga milleks nad siis seda teevad ja kuidas on see harjumus neile kohale jõudnud? Minu arvamus on see, et elu maal on läinud paljudes kordades paremaks just meie keskkonna arenemise ja kasvamisega, et arveme ning tunneme, kuidas toit lihtsalt jääb alatiseks meie käeulatusse. Nii see aga kahjuks pole, sest mida rohkem me toitu raiskame seda rohkem me oma ümbruskonda halvendame. Peame meeles, et on olemas ka vaeseid ja kodutuid, kes ültse endale toitu lubada ei saa ja teeksid kõike, et kasvõi saada pätsi leiba. Niisiis pakun noortele ja ka täiskasvanutele sellest harjumusest rohkem rääkida ja ka soovitada vähem söögimoona osta kui neil on moona äraviskamisprobleem.\nSama lugu on ka rõivastega. Paljud inimesed ostavad oma riided kiirel valimisel ja pärast seda nad lihtsalt ei kasuta neid enam. Põhjus on võibolla moes ning ka kasvamises, sest mida vanemaks sa saad seda rohkem sa muutud. Aga meeles võiks ka pidada teisi inimesi ja neid, kes neid riideid ültse poodi edastavad. Oleks väga hea kui mittekasutatavaid rõivaid müüa maha kellelegi teisele tervena ning mitte visata neid prügikasti lihtsalt sellepärast, et need on moest läinud või sulle need enam ei meeldi. \nÕppetund on selline, et mõtle kas sul on neid asju mida sa ostad tõesti elus vaja või kas sa ikka kasutad/tarvitad neid pärast ostmist. Me võiksime ikka mõelda oma elukeskkonnale rohkem ja panustada selle paremaksmuutmisele. On veel palju muid tarvitamisharjumusi, aga tõin välja väikese osa sellest.');
