INSERT INTO core.text(id, content)
VALUES ('1978a11f-4f20-47e6-a8b5-aeedef41c9f4',
        'Nagu ma aru olen saanud ja  näinud ise ka sööklas , kuidas kõik sööki ära visakavad.Minu arust pole see normaale , et võtad terve taldriku täie süüa ja söövad pool taldrikut tühjaks  ja  hiljem viskavad ülejäänud söögi lihtsalt ära. See on  ebanormaalne , et sa viskad suure koguse ära ja ei mõtle teiste peale  , kes pole süüa veel saanud . Kui sa elad maal ja sul sõidab päevas ainult vähemalt kaks korda  buss ( nagu näiteks: hommikul kell 8.15 ja õhtul 20.35 ) , muidugi sa ei tahaks õhtul umbes 21.50 koju jõuda .\nKui sa süüa tahad rohkem ja alati saad juurde võtta , kui alles jääb .See on rämps , kui sa võtad kohe terve taldriku täis. Hiljem  niigunii viskavad pool sööki ära , kui nad ei jaksa või ei taha seda enam . Kui on midagi head süüa nagu näiteks  makarone ja kana ,  nooremad võtavad suure hunniku endale ja hiljem näen , kuidas nad söögi ära vsikavad.\nKui sul tõesti pole aega või elad linnast väljast ,  sul on mugavam internetist asju vaadata . Isegi , siis kui see on Hiina asjad need on tegelikult jumala head asjad. Kõik ütlevad , et Hiina asjad jumala halvad tegelikult pole . Mõnele inimesele võib-olla ei meeldi kuskilt tellida , sest nad ei tea kuidas need tegelikult välja näevad . Mõni asi võib jah olla halb ,läheb  kohe katki nagu näiteks veepudel . Kõik oleneb mida sa tellid ja materjalist.\nJärelduseks see kõik oleneb inimesest ,kes näiteks ei telliks midagi internetist või kes just tahab tellida. Ja kõik oleneb õpilasest ,  kes süüa ära vsikab , võib-olla nad ei ole veel välja arenend  või neile pole kombeid õpetatud.');
