INSERT INTO core.text(id, content)
VALUES ('0051a590-3e14-4aa0-a9f0-40d0b5863f3a',
        'Inimeste tarbimisharjumused on väga muret tekitavad. Paljud inimesed ostavad aina uusi riideid, kuigi neil täiesti piisab vanadest. Nad raiskavad ka palju toitu. Kõik saaksid midagi teha, et vähendada seda raiskamist.\nMe peaksime rohkem riideid taaskasutama. Tänapäeval ostavad inimesed tihti riideid juurde ainult suurtelt moebrändidelt. Nad vahetavad vanad riided uute vastu ja viskavad vanad ära. Hea viis peatada üleliigsete rõivaste tekkimist on osta kvaliteetsemast riidest toode. Selline toode kestab kauem ja siis sul ei ole põhjust uut osta. Riided, mida sa enam ei kanna, peaks viima taaskasutuspoodi. Iga inimene peaks vähemalt mõnda oma riideeset saama taaskasutusest. Nii me vähendame materjali raiskamist kui ka prügi tekkimist.\nInimesed viskavad liiga palju toitu ära. Tihti unustatakse vaadata mingi toote kasutustähtaega ja lastakse toidul halvaks minna. Me peaksime olema tähelepanelikumad tähtaegade kui ka toidu koguse suhtes. Paljud ostavad aina uut toitu juurde, kuigi kodus seisab täiesti söödav suupoolis. Iga isik peaks sööma ära selle, mis talle on antud või mis ta on ostnud enne, kui ta juurde võtab. Nii me vähendame toidu, tööjõu, vee, energia kui ka raha tuulde viskamist.\nKui me oleme tähelepanelikumad tähtaegade suhtes ja sööme ära kõik antud toidu, siis me vähendame toidu raiskamist. Kui me taaskasutame rohkem riideid ja eelistame kvaliteeti kvantiteedile siis, me vähendame prügi tekkimist ja riiete minema viskamist. Kõik koos paremuse poole proovides, saame säästa loodust, maad kui ka oma raha.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('0051a590-3e14-4aa0-a9f0-40d0b5863f3a', 'title', 'Inimeste tarbimisharjumused on kohutavad');
