INSERT INTO core.text(id, content)
VALUES ('4c231f5a-6c02-43b6-a63f-b704d71cc836',
        'Tänapäeval on inimeste tarbimisharjumused väga absurdne. Kõik on palju raisklikumad kui varasematel aegadel on olnud ning see on suur probleem.\nAlustame näiteks toidust. Kui vanasti olid inimesed sellise mõtteviisiga, et toitu ei tohi raisata ning toidukadu praktiliselt ei olnudki, siis nüüd on toidu ära viskamist tõsiselt palju. Kõike mida ei sööda, visatakse ära, ostetakse ilmatult suures koguses toiduaineid millest enamus istuvad kusagi külmiku nurgas tähtaja lõppemiseni ning siis visatakse minema. Sellega näiteks raiskame me ka oma raha ning muid ressursse.\nVäga suur osa raiskamises on ka riiete osas. Tänapäeval just tellitakse hästi palju riideid välismaalt, enamuselt suurtest Hiina kaubakettidest, näiteks Shein, Temu, Aliexpress ja nii edasi. Töö seal on väga ebahügeeniline ning ei ole absoluutselt inimlik. Enamus nendest riietest mis sealt tellitakse visatakse minema. Pigem tuleks eelistada kodumaist kaupa ning mitte tellida suurtes hunnikutes riideid Hiinast, eriti noortel. \nVäga palju antakse või visatakse neid riideid ära ning need lõpetavad kokkuvõtteks taaskasutuspoodide ladudes. Seal on väga palju riideid mis on täies korras kuid ka selliseid mida keegi elu sees selga ei paneks, kuna need on lihtsalt nii ebamugavad.\nInimeste tarbimisharjumused ei ole küll kõige paremad kuid me peame pürgima paremuse poole, nii endi kui ka oma planeedi heaolu pärast.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('4c231f5a-6c02-43b6-a63f-b704d71cc836', 'title', 'Inimeste tarbimisharjumused');
