INSERT INTO core.text(id, content)
VALUES ('91ad236f-e36f-40bb-9642-1751b877b565',
        'Viimasel ajal on inimesed hakkanud rohkem toitu, riideid ja tehnikat, mis ei ole enam moes, ära viskama. See ei ole loodusele hea ega meile, sest see rikkub nii meie tervist kui ka loodust. Praeguse aja inimesed mõtlevad pigem enda peale, kuidas neil oleks mugavam ja kuidas nad saaksid ilusamini ja kaasaegsem välja näha. Küll aga meil on võimalus seda muuta.\nKõige tavalisem asi, mida oleme näinud tänapäeval väga palju, on toidu ära viskamine. See juhtub ainult selle pärast, sest inimesed minu arust ei mõtle koguse peale ja tahavad võimalikult suure portsu teha, et nad saaksid ennast ära toita, aga nad ei tule selle peale, et hiljem, kui järgi jääb, läheb see kõõik prügisse. Seda saab vältida niimoodi, et sa vaatad, kui palju sa sööd päevas ja selle järgi saad teha järelduse, et kui palju sa pead endale toitu järgmine kord valmistama. Nüüd oleme näinud rohkem ka seda, kuidas kantakse ühte riietust 2 nädalat ja peale seda visatakse ära. Ma ei saa sellest aru, miks sa ostad endale riide ja vähem kui kuuga viskad ära. Me võiksime mõelda ennem läbi, et kui kaua ma kannan seda ja kas ma ikkagi vajan seda. Samas ka tööstused võiksid vanu riideide taastöötada, et nad saaksid uuesti rõivaid kasutada ja et ei rikkusks meie loodust ja neile tuleks see veel odavam.\nMa usun, et me saaksime paremini kaistada loodust ja ennast, kui me mõtleksime rohkem tuleviku peale. Loodan, et me suudame tarbimist vähendada ja mõelda rohkem asjade taaskasutamisele, sest see on üks asjadest, kuidas hoida loodust kauem elus. Lõppude lõpuks oleme meie need, kes saame enda tuleviku paremaks teha.');
