INSERT INTO core.text(id, content)
VALUES ('5661786d-cd55-43e8-873b-592d6bd1d5ca',
        'Paljud inimesed viskavad loodusesse igasugust prügi, näiteks kommipaberid, plekkpurgid, klaaspurke ja plastmassi. Inimesed ei saa aru mida see kõik prügi loodusele teeb eriti loomadele. Nende arvates on loodus prügimägi, kuid tegelikult on loomad need, kes saavad selles kõiges kannatada.\nLoodus saab igapäevaga aina mustemaks ja koledamaks. Inimesed ei tea mida tähendab loodus Eesti riigile ja üldse tervele maailmale. See on asi, ilma milleta maailma poleks. Maailma asemel oleks tühi auk. Inimesed viskavad maha iga päevaga aina rohkem prügi, mida keegi ei korista.\nÕnneks on olemas selline päev nagu Maailmakoristuspäev, kus osalevad kõik inimesed kaasaarvatud koolid kes koristavad loodust. Koolid koristavad enda kooli ümbrust, näiteks Rääma Põhikool koristab kooli ümbrust, mille alla kuulub ka Männipark.\nSiin ma kutsungi kõiki inimesi, palun ärge reostage meie kalli Eestimaa loodust, kui te ei taha elada prügimäel. Kui on maailmakoristuspäev siis palun osalege selles, sest nagu ma ütlesin loodus tähendab palju.\nNeed kes viskavad prügi maha on inimesed, kes ei hooli midagi ega kedagi peale iseenda. Meie planeet, mille nimeks on Maa, on ainus koht universumis kus on elu. palun hoiame selle ainsa koha puhtana, sest meil pole planeet B-d.');
INSERT INTO core.text_property(text_id, property_name, property_value)
