INSERT INTO core.text(id, content)
VALUES ('27f54324-e49e-403e-9821-ecd3ea285f0d',
        'Tänapäeval on suureks probleemiks kasvuhooneefekt, mis toob globaalse soojenemise. Kasvuhooneefekt on gaasidest koosnev kiht, mis neelab planeedi pinnalt pikaajalist kiirgust, mistõttu õhukiht soojeneb.\nViimastel aastatel on väga populaarne veebipoes ostlemine. Veebis maksavad asjad kordades vähem sellepärast, et need ei ole heast kvaliteedist ja teadlaste poolt heaks kiidetud. Internetis on suur valik riided. Inimestel on lihtsam tellida 10 särki, millest jätavad nad alles ainult 2. Kõik teised särgid lähevad prügikasti ja edasi prügimäele, kus neid põletatakse. Põlemisel eralduv CO2 paiskub õhku ja maa soojeneb. Ma hakkasin vähem tellima internetist kuna mul on raske valida endale sobilik suurus.\nHiinas on juba paar aastat olnud populaarne kaamera ees söömine. YouTube-s või Tiktokis postitatakse sellised videosi, kus inimesed söövad suurtes kogustes rämpstoitu. Alguses ei tundu see nii jube, aga kui mõelda tagajärgedele, siis tuleb hirm peale. Videos on näha, et nad söövad toitu, aga nad kunagi ei näita, kuidas nad neelavad alla. See ongi peamine probleem, et nad raiskavad toitu. Nad ei söö ,vaid sülitavad välja ja viskavad prügikasti. Sellepärast on Hiinas suur mure toidu väljaviskamisega.\nMina arvan, et lahendus võiks olla selline: veebipoed hakkavad tegema heast kvaliteedist asju, riiete hinnad tõusevad, inimesed hakkavad rohkem taaskasutama, inimesed hakkavad tervislikult toituma ja tegelema spordiga. \nMida rohkem me taaskasutame seda parem on meil elada meie planeedil.');
