INSERT INTO core.text(id, content)
VALUES ('faf3360b-f227-4179-8504-4a845ee196b9',
        'Inimeste harjumused tarbimises on vägagi mõistetavad ja arusaadavad, kuid nad peaksid mõtlema ka loodusele ja teistele elusolenditele meie planeedil. Eestis ja üldse maailmas on palju toiduraiskajaid inimesi ja ka inimesi kes võivad söögist vaid und näha kui sedagi. Ma arvan, et sellele tuleks rohkem tähelepanu pöörata ja seda paremini kontrolli all hoida. Aga kui mõtlema hakata kas see ikka on nii suur probleem mailmas?\nMinu arust peaksid inimesed rohkem mõistma ning kaaluma mida ja kui palju nad asju osatavad, kui ka seda kuidas nad neid kasutavad, sest kunagi ei või teada kellel võiks samu asju rohkem vaja minna kui inimesel kes neid asju ostab. Mõistagi, et kui inimestel on raha tuleb see kõik koheselt laiaks lüüa ja kõike osta mida hing ihaldab, kuid mõtlema hakates kas see ikka on nii vajalik ja nii oluline sulle kui sa arvad. Ma arvan, et tegelikult sa vajad seda ainult korraks ja kõik, näiteks tellid endale Hiina veebipoest uue, ilusa käekoti ja eputad sellega oma sõprade ees, aga siis läheb see moest välja ning sa kas lihtsalt ei kasuta seda enam või viskad prügikasti. Mitte ei hakka inimesed mõtlema taaskasutusele, mis on väga oluline maailma populatsioonile ja väikerahvastele.\nInimeste tarbimisharjumused on suur probleem ja sellega tuleks koheselt midagi ette võtta. Kasvõi hakata prügi sorteerima, rohkem bussi või jalgrattaga sõitma ning kõike seda selleks, et meie planeet Maa püsima jääks. On inimesi kes ei saagi endale riideid, sööki ega ka vett mitte, kuid nad ka ei reosta seda maailma mis meil on nii palju. Seda teeme meie ise, meie kes me elame heades kliimades, kellel on head töökohad ning vesi kui ka toit igapäevaselt kättesaadav. Mitte need vaesed väikerahvad, kes proovivad nii palju teha, et elus püsida.\nArvan, et kõik inimesed peaksid muutma oma tarbimisharjumusi ning võitlema meie planeedi eest kus me kõik elame. Maailma muutmine poleks raske, kui inimesed vaid viskaks prügi õigesse prügikasti ning transpordiks loodussõbralikumalt, nii saaks meie tarbimisharjumused paraneda ning oleks ka väikerahvastel ja loomadel parem elada. Kõik algab meist endist ,vaid siis kui me seda päriselt tahame.');
