INSERT INTO core.text(id, content)
VALUES ('5eeb59e9-0f0b-4eaa-97c2-8f0ce38cff5c',
        'Toidu ülemäärase raiskamise peamine põhjus on see, et nad saavad aina rohkem toitu osta ja ei huvitu sellest, kui palju toitu jääb alles või mis sellega tehakse, seepärast igal juhul ülejäänud toit visatakse ära. Miks toitu raisatakseja kust seda õpitakse?\n Toitu raisatakse seepärast, sest rikkamatel peredel on palju rohkem raha ja neid ei huvita see toit mis ülejääb, nende jaoks on see ükskõik ja ülejäänud toidu viskavad lihtsalt ära. Paljudel inimestel on juba südamesse kinni jäänud noorena, et toit mis ülejääb see tuleb ära visata.See rikkamatele haiget ei tee, neil on raha et veel toitu osta. Paljud vaesemad inimesed ning kodutud oleksid õnnelikud kui neil mingigi toit oleks laua peal ja näiteks tuua Aafrika kuidas seal on vähem süüa, kui teistes riikides. \nToidu tootmine tekitab ka keskonnas probleeme, näiteks keskkonnakoormuse. Toitu raisates tuleb toitu aina rohkem toota, milleks kasutatakse erinevaid väetisi ja kemikaale, mis tekitab keskonnas probleeme. Toidu tootmisel raiskame tohutult ressursse: maad, vett, energiat ja loomulikult ka tööjõudu.\nToidu raiskamine on suur probleem üle maailmselt ja samuti ka Eestis, sest juba Eestis iga inimese kohta raiskame aastas 61 kg. Toidu raiskamisest tuleks rohkem rääkida, et seda proovida vähemalt vähendada, sest see on suureks probleemiks. Raiskame aina rohkem ise enda raha ja olulisi ressursse. Ma arvan, et mida rohkem seda õpetada, seda rohkem loodetavasti inimesed hakkavad järgima ja seda mõista. Seepärast vaikselt maailmas hakkabki toitu vähem olema ning ei ole enam ressursse ega jõudu, et toota toitu.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('5eeb59e9-0f0b-4eaa-97c2-8f0ce38cff5c', 'title', 'Ülemäärane toidu raiskamine');
