INSERT INTO core.text(id, content)
VALUES ('70323f01-a3fa-482e-bb21-48b309c8e422',
        'Tarbimisharjumused on tänapäeval inimestel halvad. See on jõudnud kohani, kus see on lausa ohtlik. See on ohtlik nii loodusele, inimestele kui ka loomadele. Aga mis tagajärjed sellel on?\nInimesed ostavad liiga palju toitu. Toidu üle ostmine on läinud palju hullemaks. Paljud inimesed tarbivad liiga palju toitu, sest neil on see võimalus. Tänapäeval on olemas tuhandeid erinevaid kauplusi, kus on võimalik osta nii palju, kui süda lubab. See on väga ohtlik meie loodusele ja armsatele loomadele. Kuna aina tapetakse ja tehakse loomakasvatus farme, kus pealmine eesmärk on teenida raha. Ka paljud inimesed raiskavad kalleid tooraineid, mis on kas looduskaitsealal või üldse väga haruldased. Ma ei taha näha kuhu see meie kalli planeedi viib.\nE-poed on muutnud meie elu hullemaks. Ma usun, et kõik inimesed on ostnud kunagi E-poest midagi ‘’vajalikku’’. Ma saan aru, et veebis ostmine on väga mugav ja lihtne. Alati sa näed kas reklaamides midagi ‘’vajalikku’’, aga tegelikult on see puhas rämps, mida sul tegelikult vaja pole. Paljud inimesed osatavad riideid E-poodidest, aga halb asi selle puhul on see, et sa ei tea kas sulle sobib see või mitte. Seega ostetakse paar erinevat suurust riiet ning sellel puhul peavad töötajad tegema rohkem tööd. Pärast see tagasi saadetud riie jõuab nende juurde tagasi, mis visatakse ära. Lõpuks on suured hunnikuid riided laiali. Väga kurb on mõelda, et mõned inimesed ei saa raha ka selle eest.\nMa olen pannud tähele üle tarbimist juba lapsest saati. Ma olen kurb, et see ikka veel nii hull on. Igakord peab mõtlema, et kas ikka on vaja või mitte. Loodan, et läheb paremaks.');
