INSERT INTO core.text(id, content)
VALUES ('894900c6-e7e5-4ba8-aae0-1d6de6f13ba0',
        'Mina arvan, et inimesed on liiga mugavaks läinud. Nad ei mõtle enam oma käitumiste tagajärgedele ja see võib tulevikus kätte maksta. Tänapäeval peaksid inimesed just rohkem haritud olema, kuid olen oma silmaga näinud, et nii päris ei ole. Kui me ei muuda oma käitumist ja ei hakka targemalt tarbima, võib see meie järgmised põlvkonnad hukka mõista.\nToitu võetakse rikkamates riikides iseenesestmõistetavana. Minu kodus pole ka kunagi toiduga muresid olnud, ning ma pole pidanud mõtlema, kas ma täna õhtul saan süüa, või mitte. See ei tähenda, et me ei peaks ennetama toidu raiskamist. Selline käitumine ilmselgelt tekitab keskkonnakoormuse. Inimesed peaksid oma järglaste jaoks käitumist muutma ja tarbima targalt. Selleks, et muutus päriselt toimuda saaks, peaksid vanemad oma harjumusi muutma, et need siis lastele külge jääks. Kõik algab kodust.\nMinu meelest on riiete taaskasutamine moodi läinud. Ma tean palju endavanuseid noori, kes eelistavad osta oma riideid kirbukatest, kaasaarvatud mina. Kindlasti on popiks saanud ka Hiinast riiete tellimine. Sellise käitumise juures, peaks targalt omale asju tellima. Olen kohanud inimesi, kes riided kätte saades need ka kohe ära viskavad, sest neile need ei meeldinud või ei sobinud. Targem oleks riie tagasi saata või sõbrale pakkuda, aga sellega ei viitsita ju tegeleda. Siiski ma arvan, et riiete taaskasutamise poolest pole minu generatsioon hukas. Humana ja kirbukad on uus mood.\nKindlasti on palju asju, mida saaksime keskkonna säästmiseks teha. Tarbida targalt, taaskasutada jne, aga plakatitest ja Facebooki postitustest ei piisa, kui inimesed ise teadlikult käitumist ei muuda. Selliste targalt tarbimisega peaks juba noorelt alustama, et see normiks saaks.');
