INSERT INTO core.text(id, content)
VALUES ('cc3ef482-85d2-4a22-9d49-e13a82171ba7',
        'Minu arvates on kõigil inimestel erinevad tarbimisharjumused. Mõndadel inimestel on halvemad tarbimisharjumused kui teistel. Minu arust on sellega suur probleem,sest tavaliselt visatakse ära riided ja söögid,mis neile ei meeldi. Nad võiks  anda need hoopis  vaesetele ja riided müüa maha. Minu arust ei tee seda peaaegu mitte keegi.\nMina arvan,et inimeste tarbimisharjumused on pigem halvad kui head,sest ma ei ole näinud kedagi,kes annaks oma toitu,mis nad ei söö,vaestele. Nad peaks seda tegema,sest nii nad aitaksid kaasa inimeste mittenälgimisele ja sureks vähem inimesi.\nMeeldimatute riiete mahamüümisega ei näe ma piisavalt inimesi tegelemas.\nNeid on kindlasti rohkem kui inimesi kes jagavad oma toitu vaestega, aga mitte piisavalt.\nRohkem on neid kes lihtsalt ostavad riideid ja siis püüavad neid lihtsalt rohkema hinnaga maha müüa. Ma ei ütleks et see on sama,mis on siis,kui inimesele ei meeldi need riided,mis ta ostis ja tal ei ole võimalik neid enam tagastada,ja siis ta saab need maha müüa natukene kallimalt kui ta need ostis.\nJärelduseks ma ütleks,et paljudel inimestel on väga erinevad tarbimisharjumused,aga paljudel on see halb. Paljud ei teo kuidas õigesti tarbida,sest nad lihtalt  viskavad näiteks  toidu ja riided mis neile ei meeldi, ära prügikasti või kuhugi mõjale kuigi nad saaks palju rohkem rõõmu ja tasu kui nad viiks need kodututele ja vaestele või müüvad maha. Minu arust ei oska õigesti tarbida peaaegu mitte keegi.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('cc3ef482-85d2-4a22-9d49-e13a82171ba7', 'title', 'Inimeste tarbimisharjumused');
