INSERT INTO core.text(id, content)
VALUES ('1f19ec4d-1447-4baf-a026-b03936cacdac',
        'Kas mina peaksin oma tarbimisharjumusi muutma, et säästa keskkonda? Kuidas peaksin ma seda tegema? Kas ma peaksin ostma kasutatud riideid, et aidata vähendada keskkonnakoormust? Just need on olulised küsimused, mida peaks iga inimene enda peas korra läbi mõtlema.\nInimesed raiskavad iga aasta eestis meeletutes kogustes toitu ja mõni inimene arvab, et see kui ta korra toitu raisku laseb, ei mõjuta suuremat pilti üldse. See on täiesti vale arusaam. Kodumajapidamises tekib iga Eesti inimese kohta keskmiselt 61 kg toidujäätmeid, millest üsna suur osa on riknema lastud toiduained. Selleks, et sellist massiivset toidukadu vältida, peaks iga inimene mõtlema, kui palju toitu ta tarbib ja kui suurtes kogustes ta poest toitu ostab. Mina alustaksin sellest, et plaaniksin ette kui palju ma söön ja kas see toit mida ma söön on kergesti riknev. Sealt edasi muudaksin ma oma poodlemisharjumusi ja ostaksin toitu täpsemates kogustes. Kui iga inimene maailmas, kasvõi Eestis seda jälgima hakkaks, oleks see juba keskkonnale suureks abiks.\nAga asi pole ainult toiduraiskamises. Palju on ka inimesi, kes ostavad riideid suurtes kogustes ja odavalt, näiteks kuskilt hiinast, kannavad neid üks või kaks korda ja siis on nende riietega kõik. Tavaliselt lõpetavad need riided prügimäel, kuid vahest jõuavad nad ikkagi ka taaskasutuspoodidesse. Muidugi taaskasutuskeskuste laoruumid pole ka lõputud ja kõik riided sinna ära ei mahu. See panebki mõtlema, mida saaksin mina ise teha, et vähendada koormust keskkonnale mida põhjustab riiete massiline tootmine. Kõige olulisem ja lihtsam asi mida iga inimene teha saab, on vaadata oma riidekappi ja küsida endalt: „Kas mul tõesti on veel riideid vaja“?  Ilmselt paljudel oleks see vastus „ei“. Just sealt algabki keskkonna säästmine ja paremaks muutmine.\nKokkuvõtteks on keskkonnahoid iga inimese enese kätes ja maailma saavad aidata kõik, kes vähegi soovivad.');
INSERT INTO core.text_property(text_id, property_name, property_value)
