INSERT INTO core.text(id, content)
VALUES ('28a279f9-5e39-4c27-8e59-b84173dd06d8',
        'Teame ,et paljud inimesed ei hooli loodusest ega mis sellega juhtub. Järgmised ei hooli mis nende vanadest riietest saab. See ,et meil kliimasoojenemine on selliste inimeste pärast, nad hoolivad ainult endast.\nKui taaskasutuspoode poleks olemas oleks kõik veel rohkem prügi täis. Aga noored inimesed ei käi sellistes poodides. See ei ole nende arvates piisavalt moodne. Olen ise sellistes poodides käinud ja pole ültse halb riide valik. Igale maitsele on midagi. Minu arvates on seal piisavalt moodi kõigile, isegi noortele. Seal on riideid mis mingil kaunil reklaamfotol näevad ilusad välja, aga tegelikult on see ebakvaliteetne ja sul hakkab selles ebamugav pärast ühte kandmist. \nOlen ise pealt näinud kuidas inimesed viskavad toitu ära mis oli veel täiesti söödav, aga oli üks päev üle vananemis kuupäeva. Aga ma saan aru, sest mina ei taha ka toidu mürgitust saada. Kuigi elu on praegu nii hea ei pruugi see tulevikus sama hea olla. Prügi tuleb aina juurde ja juurde. Kui  mõtled selle peale kui palju viskab üks pere keskmiselt toitu ära on numbrid päris suured. Keskmiselt viskab üks pere ära 61kg aastas. Aga on viise seda numbrit vähendada ja ka teisi inimesi aidata. On olemas toidupangad kuhu saad toitu viia mis oleks kõigile hea.\nArvan ,et kunagi saame nende probleemidega paremini hakkama kui praegu. On inimesi keda ei huvita see mis neid ümbritseb. Aga on ka inimesi kes proovivad teiste vigu parandada. Need ke ostavad riideid taaskasutuspoest aitavad maailma. Kuna kui keegi neid riideid ei osta visatakse need lihtsalt ära. Järgime kord mõtle hoolikalt kas sul on ikka uusi riideid vaja, kas see juust on ikka halvaks läinud.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('28a279f9-5e39-4c27-8e59-b84173dd06d8', 'title', 'Kes hoolib, kes ei hooli');
INSERT INTO core.text_property(text_id, property_name, property_value)
