INSERT INTO core.text(id, content)
VALUES ('3702cdfe-9593-4d91-9419-349c6900b591',
        'Iga inimese tabrmimisharjumused on einevad. Harjumused on tingitud lapsepõlve ja kodukeskkonna pärast. Üleliigse raiskamisega tekib probleeme, mida saaks tegelikult vältida ja parandada.\n   Lapsepõlv ja kodukeskkond mängib tarbimisharjumuste üle väga suurt rolli. Tihti on jõukamatel peredel palju rohkem vabadust tarbimisega enda raha pärast ja haridus säästmise väärtuse kohta puudub. Lapsepõlves on tavaliselt neil kõik vajalik olemas, näiteks toit, kodu, hoolivus ja nii edasi.  Lapsed  saavad omadused oma pere järgi, seega vanemate käitumine ja surve on väga oluline. Laps, kes on üleskasvand heas keskkonnas võib asju väärtustada palju rohkem ja tarbida vähem.  Samas inimene, kellele ei antud sellist keskkonda võib tarbida palju rohkem, enda huvide jaoks.    \n   Selline vaatepilt maailmast võib viia üleliigse kasutamiseni ja raiskamiseni. Tänapäeval on see suur probleem, sest sellega kaasneb väga paljusi negatiivseid omadusi. Raha ja ressurside  kulu on väga suur. Samuti rikub see meie majandusliku seisu ja kahjustab meie loodust. Õnneks saab seda kõike vältida. Haridus selle kohta saab seda vähendada ja inimesed võiksid olla rohkem teadlikud enda raiskamise kohta ja vältida üleliigset tarbimist.\n  Iga inimese tarbimisharjumused on erinevad, aga on faktoreid, mis seda mõjutavad. Haridus tarbimise ja raiskamise kohta aitab meie maailma. Raiskamine on palju suurem probleem kui inimesed arvavad ja kõik võiksid seda teada ja ennast harida raiskamisest.');
INSERT INTO core.text_property(text_id, property_name, property_value)
