INSERT INTO core.text(id, content)
VALUES ('559791f7-3680-44be-9a37-fb341dfa70d5',
        'Toitu raisatakse igapäevaselt. Arvatakse, et see ei ole nii suur problem, alati saab juurde osta kui vaja. Nad ei mõista, et toidu ära viskamine kahjustab nii loodust kui ka omaenda rahakotti. Eks see igapäevane toidu ära viskamine on juba harjumuseks saanudki.  Samuti on ka riietega. Kui ei meeldi riie, visatakse see minema.\nInimesed on erinevad. Mõndade jaoks on ära visatud toit ning riided praht. Kuid on ka inimesi, kes teeks toidu ja riiete eest ükskõik mida. Kui riie ei meeldi siis saab alati selle taaskasutusse viia, kuid miks see üldse osta kui ei kavatseta seda kanda.\nPaljud Eesti kodanikud lahkuvad poest teadmisega, et hinnad on kallid ning absurdsed, kuid ikkagi viskavad ära nii viimsegi toidu, mis veidigi teistmoodi maitseb või lõhnab.  Kõik see kokku ostetud toit läheb tavaliselt raisku, sest ei jõutud ära süüa või lihtsalt pole täna selle "isu". See on täiesti arusaadav, et ei taheta süüa nädal aega vana kartulisalatit, kuid selle oleks võinud siis enne kuupäeva langemist ära süüa või kui isu pole, siis miks see üldse osta.\nKokkuvõtteks võime öelda, et toitu ja riideid raisatakse igapäev. Seda võib ju proovida ennetada, kuid lõppude lõpuks jätkame ikka samamoodi nagu ennemgi. Ostame asju, mille arvatavasti juba nädala pärast ära viskame. Enamus ajast ei mõtle me enne ostmist, tunneme, et meil võib seda vaja minna, kuid sisimas teame, et me ei kavatse seda kasutada.');
