INSERT INTO core.text(id, content)
VALUES ('97a6e02c-bff7-42d5-a592-712f07b7d582',
        'Enam rohkem inimesi raiskavad meile vajalike tooteid. See on tulnud väga suureks probleemiks meile. Selles kirjandis proovin selgitada, kuidas lahendada seda probleemi ja mingeid näpunäiteid välja tuua. Toon esile probleemid, mis ka sellega kaasnevad. \nVäga palju olen kuulnud kuidas inimesed tänapäeval raiskavad aina rohkem tooteid mis on meile vajalikud, näiteks toiduaineid ja riide esemeid. See on juba läinud juba ülemäära liiga suureks probleemiks ja meil on vaja midagi teha, et seda probleemi lahendada. Kuna ise olen perekonnas kus asjade sorteerimine on vajalik teema on see ka minu jaoks väga suur teema. Näitaks toidu raiskamine ei tule kõne allagi minu peres. Kui midagi on üle, tuleb see ära süüa mistahes sulle meeldib see või mitte. Seda asja võiks iga pere teha, et me ei raiskaks nii palju toitu. Näiteks on toodud välja, et „Kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61kg toidujäätmeid“. See on ju täielik absurd. Veel toon välja riiete ära viskamise kohta. Miks me teeme nii. Meil ju olemas poodides kohad kuhu saad oma vanad riided viia ja nendest tehakse midagi uut ja põnevat, mida saaks järgime inimene kanda. Riideid saame ju kanda nii kaua, kui lõpuks see ongi katki. Inimesed ei peaks kohe peale esimest kandimst riided minema viskama. Lihtsalt kanna seda 2 nädalat või veel parem rohkem. Nii on meil vähem riiete kulusid. \nMida ma järeldan sellest on see, et meie jaoks on tunne, et kõik asjad siin maailmas on lihtsasti kättesaadvad. Me ei mõtle sellepeale mis tegeliku kahju see meile toob kui me lihtsalt viskame asjad minema. Me peaksime midagi tegema, et lõpuks see asi laheneks. Varsti me küsime, „kus kõik head asjad kadunud on“.');
