INSERT INTO core.text(id, content)
VALUES ('671f2dfe-409f-430c-a13e-af1ec13abb6c',
        'Kui me peaks parandama oma tarbimisharjumusi, et me saaksime kauem ja puhtamalt elada. Kuidas me peaksime neid parandama? Millal me peaksime neid parandama? Ja Kas sellest parandamisest kasu on?\nMeile võib tunduda, et toit ei saa kunagi otsa aga tegelikult on maailma toidukadu väga suur. Enamsati raiskavad toitu need kes saavad endale seda lubada, aga see pole alati nii. Ka need kes arvavad, et väikse toidu koguse ära viskamine ei saa maailmale midagi halba teha, kuid pikema aja jooksul koguneb see kogus päris suureks. Eestis elava inimese kodumajapidamises tekib aastas keskmiselt 61kg toidujäätmeid (inimese kohta), millest toidukadu moodustab 26kg. Muidugi tehakse igapäev toiduaineid juurde, aga seda ka tänu sellele, et kasutatakse erinevaid kemikaale ja väetist mis vähendavad toidu kvaliteeti, kuid suurendab kvantiteedi. Mida vähem on kvaliteetset toitu, seda rohkem võib see meie keha kahjustada.Muidugi ei saa vähendada toidu raiskamist üleöö, kuid on võimalik seda alustada väikeste osadena.\nPeale toidu raisatakse ka riideid. Neid raisatakse enamasti selle pärast, sest kõik ju tahavad endale kogu aeg uusi riideid ja selle pärast tõuseb ka nõudlus tootlusele. Kuna tehakse nii palju riideid peaved tööstused kasutama palju tehaseid ja materjale, mis kahjustavad keskkonda. Lisaks tehakse palju kalleid riideid mida enamus maailmast ei saa endale lubada. Kui minna üks kõik millisesse taaskasutus poodi, siis leiad sealt palju riidei mida keegi ei kanna ja mida inimesed ei märka on see, et sealsed riided ei erine peaaegu ültse uutest poe riietest aga on peaaegu, et 5 korda sootsamad. Sellepärast soovitan minna taaskasutus poodi ning saate anda väikse panuse keskkonna parandamisele.\nToidujäätmed ei kao ilmselt kuhugi, aga meile on antud see võimalus vähendada seda ja elada paremas ja tervislikumas keskkonnas. Rohkem peaks üleskutsuma inimesi ostma taaskasutuspooditest riideid, sest need on odavamad, ning tänu sellele saame teha väikse sammu keskkonnaparandamisele.');
