INSERT INTO core.text(id, content)
VALUES ('5d994b8b-7a09-43f6-93cb-3002df1585ed',
        'Tänapäeval inimesed ostavad riideid Hiinast odavate hindade tõttu. Inimesed ei märka, palju see mõjutab meie keskkonda. Seda kõike on põhjustanud halvad tarbimisharjumused ning seda tuleb muuta.\nViimastel aastatel on populaarseks saanud brändid nagu SHEIN, Temu ja Aliexpress. Need brändid on Hiinast pärit. Nad on saanud ülemaailma tuntuks see tõttu, et seal on odavad hinnad ja palju erinevat kaupa. Odavad hinnad meelitavad inimesi ostma nende kaupa, kuid on ka kohutavaid põhjuseid miks hinnad on seal odavad. Pidevalt kiirmoe brändid kasutavad lapstööjõudu just aasia riikides. Need riigid on Bangladesh ja Hiina. Nende riidevabrikutes töötavad lapsed ning neile makstake 10 senti tunnis oma töö eest. Enamus riided koosnevad sünteetilistest materjalidest mis on odavamad kui looduslikud materjalid. See kõik mõjutab nende töötajate tervist ja keskkonda.\nPraegu on läinud moodi taaskasutuspoodides käimine. Inimesed on hakkanud rohkem käima kaltsukates ning sellest räägitakse juba rohkem kui varem. Kaltsukates poodlemine on parem, kui ostes midagi aasiast. Sellega inimesed ei toeta kiirmoodide brände rahaliselt, ega reosta maailma. Taaskasutuspoodides leidub palju kvaliteetseid ning hästi hoitud rõivaid heade hindade eest.\nInimeste tarbimisharjumused on läinud halvaks heade hindade tõttu. See kõik mõjutab meie tervist ja keskkonda. Praegu on läinud populaarsemaks taaskasutuspoodides asjade ostmine. Seal on odavam ning sõbralikum keskkonnale.');
