INSERT INTO core.text(id, content)
VALUES ('89c7d476-15b5-4344-9cf0-ac4398d6c621',
        'Inimesed raiskavad palju toitu, need kes saavad rohkem lubada toitu, need ka rohkem raiskavad seda. Väiksemates kogustes toitu ära viskavad inimsesed arvavad, et nad seda suur pilti ei mõjuta, kuigu see on puhas vale! Kas kodumajapidamises raisatakse palju toitu ja kas ressursse raisatakse seda tehes?\nÜlemises artikklis on kirjas et kodumajapidamises tekkib iga Eesti inimese kohta aastas keskmiselt 61kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26kg. Seetõttu ei raiska me ainult omaende raha, vaid ka tohutult muid ressursse: maad, vett, energiat ja tööjõudu.\n   Riide osakonnas inimesed eelistavad kvantiteedi üle kvaliteedi sest Hiinast saab odavalt halva kvaliteediga riideid. Kas kvantiteed üle kvaliteedi on halb asi?\nAlumises artikklis on kirjas et riided mis mingil kaunil reklaamfotol näevad ilusad välja, aga tegelikult koosnevad naftast ja sa ei taha seda rohkem kui üks kord anda, sest kehal on halb olla selles. Ja väga paljud selliseid rõivad on pärit nendest suurtest kuulsatest Hiina kaubamajadest.\n   Kokkuvõtteks saime teada et kui inimestel on liiga palju asju siis nad hakkavad ka rohkem raiskama ja inimesi huvitab rohkem hind kui kvaliteet kuna nad saavad rohkem osta neid odavamaid asju, et seda vältida saaks tulevikus siis võiks asjade hindu tõsta et inimesed ei saaks nii palju osta millega kaasneks vähem raiskamist');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('89c7d476-15b5-4344-9cf0-ac4398d6c621', 'title', 'Inimeste tarbimisharjumused');
