INSERT INTO core.text(id, content)
VALUES ('99b4c531-9558-4b8e-a262-26c33c859738',
        'Inimesed tarbivat erinevates koguseka erinevait toodeid. Kes rohkem kes vähem. Aga, siiski kes, tarbip kõike rohkem ja mis vanusegrupis kui, palju on normaalse inimese tarbimine.\nTavaliselt on harjunut normaalne inimene, kellel on kesmine palk tarbima luksus esmeid, näitaks šokolaad, era auto, televiisor ja kõrvaklapid. Aga, kas tekelikuld lähep tava tarbjal ültselt kõiki neid asju vaia? Vastuseks on ei kindlasti mitte: kuna inimene ei vaja luksus esemeid ett, ära elata oma elu vait vajab toitu, veed ja elukohta. Inimesed on erinevat ja kõikitel meie seasd on minki sukused  mugavused nätaks, tarbimis harjumus on ka see et narkumaan tarvitab narkootikume kuit, on ka positivseid küülki tarbimis harjumusel. Mina isiklikult olen harjunud tarbima hommiku kohvi. Mita ma ei peags üldsegi mite tarbima. Kõike tavalisemad tarbimis harjumused on magusa söömine, teleka või nudi eseme vaatamine. Tarbimine on harjumus mita saab mitud moodi kirjeltada net viisid on järknevad, toitu tarbimine, esemete tarbimine, tenuse tarbimine ja ka palju muud. Tavaline inimene tarvitap kõiki neid tenuseid ja esemeid ilma nenteta ju ei sa inimene elada aga, miks inimestel ültsed on tarpimis harjumused? Sest, ikale tarbjale on oma viis tarpimiseks. Tarbimis tenuseid mita tarbip tavaline inimene om järknevat klientitenitus seeta kohtat ikas poes ja palutes kohtates vell aga, miks on inimesed harjunut tarbimje erinevait asiu? Läpi aegate on sanud inimesed ainuld targemaks ja see töõtu on ka elu länud mugavamaks. Üks vanimait tenus mita on harjunut inimene tarbima on prostitutsoon. Mita, on tarbinud meie esivanemad.\nNüüd, kokkuvõteks järeldan ma seta, et inimeste tarbimis harjumused on vajalikud ja et neid on olemas mitmeid viise tarbimiseks.');
