INSERT INTO core.text(id, content)
VALUES ('405c7198-af54-4bf6-8ba1-92963300aeac',
        'inimesed viskavad liiga palju toitu ära. Miks inimesed viskavad toitu ära? Miks ei anta seda toitu neile, kes seda vajavad? Miks ei tarbita toitu kohe ära? Toidu kaos on väga suur probleem.\nToitu kaob meie seast liiga palju iga päev. Inimesed arvavad, et kui toit on oma kõlblikuse kaotanud ,siis see enam ei kõlba ,mis see paar päeva ikka teeb kui see on ajast üle läinud. Toitu saab säilitada külmas, et see säiliks kauem. Paljudel pakendidel on kirjas: „ külmas säilib kauem, temperatuur +2.....+6“ inimesed võiksid järgida neid soovitusi.\nMeie ühiskonnas elavad ka vaeseid inimesei, kes ei saa endale iga päev toitu lubada ehk aitaks neid see, kui meil kellel on toitu ja kes ei suuda seda ära tarbida annaks ülejäänud neile. Näiteks alustekstis on autor öelnud, et me raiskame enda ressursse: maad, vett, energiat ja tööjõudu, mis on tegelikult väga õige, aga mis siis, kui inimene viskab oma toidu loodusesse ja tuleb loom, kellele ei ole mõeldud see toit ja sööb selle endale sisse ja sureb ehk tahaksin sellega öelda ,et me hävitame ka enda keskkonda oma toiduga. Meie ühiskond ja loodus vaikselt hävineb meie iseendi tõttu, kes ei järgi juhiseid nii nagu neid peaks järgima. Paljud ütlevad, et tänapäeval on kõik võimalik, mis siis, kui teeksime sellise rakenduse kus inimene saab teha erinevaid ülesandeid toidu raiskamise kohta ja näitab kui palju inimene viskab toitu iga kuu ära, kui inimene on järginud ennast, et tal on toidu tarbimisega kõik korras saab ta iga kuu tagant mingise väikese auhinna vms.\nInimesed viskavad toitu sellepärast ära, et toit on oma säilivuse kaotanud või neile ei maitse see toit jne. Inimesed pigem ei viitsi nii palju pingutada, et vaesed saaks selle toidu kätte. Inimene ostab toitu juurde ja unustab selle eelmise toidu ära ja hakkab värskemat toitu kohe tarbima.');
