INSERT INTO core.text(id, content)
VALUES ('bc151711-e69e-40da-8f36-321331f6e47f',
        'Vanasti, kui meie vanemad olid veel väikesed, ei saadud peredes endale uusi asju ja vahel ka toitu lubada, sest ei olnud selliseid võimalusi. Asjad olid väärtuslikud ning neid hinnati. Nüüdseks on inimestel väga elementaarne raisata nii toitu kui esemeid, sest uued asjad tulevad järjest juurde. Aga millised on tänapäeva inimeste tarbimisharjumused? Mida saaks paremini teha?\nNüüdisajal on inimestel oluliselt palju võimalusi. Sageli ei tunta tarbimises piire, mistõttu on suures pildis raiskamise kahju päris suur. Ostetakse suures koguses toitu, aga ära ei tarbita, ostetakse kogu aeg uusi asju, visatakse vanad asjad ära. Üldpildis läheb kõik lõppudelõpuks ära viskamisele, ükskõik, kui vana või uus ese on. See jällegi kulutab peale raha ka muid ressursse. Tooraine saadavust, tööjõudu, vahendite kulutamist. Näiteks ostetakse tihtipeale uusi riideid, selle asemel, et taaskasutada või hoopis soetada endale kvaliteetne ese, mida on võimalik kanda pikka aega. Nagu on öelnud moedisainer Eve Hanson, siis tema arvates on oluline, et igaüks vaataks üle oma isiklikud tarbimisharjumused, eelistaks kvaliteeti kvantiteedile.\nKõike saab elus paremini teha, alustades tarbimisharjumuste muutmisest. Probleeme, sealhulgas toidu ja esemete mittesäästlikku tarbimist ei saa lahendada otsekohe. Suur osa tarbimisharjumuse muutmisest on inimese enda käes. Minu näite kohaselt saaksid inimesed enda tahtmisi ja vajadusi suunata – mida neil tegelikult vaja on ja mida mitte. Mitte mõelda, et kui mina ei tarbi säästlikult, siis see ei tee midagi. See mõjutab üldpildis tohutult palju. Isegi väikene hulk.\nKokkuvõtteks saan öelda, et tänapäeva inimeste tarbimisharjumused on väga kulukad, ent ilmatult ressursse raiskavad. Seepärast on keskkonnal suur koormus. Iga inimene saab paremaks tulevikuks, tublimaks tarbimisharjumuste kujundamiseks ise midagi ette võtta, muutes oma sihte ja olekuid, mida neil tõeliselt vaja on.');
INSERT INTO core.text_property(text_id, property_name, property_value)
