INSERT INTO core.text(id, content)
VALUES ('2b9eb80a-93fd-4ffa-9c4a-54e3cf35c16a',
        'Iga koolis ja peres on lapsi, kes viskavad toitu ära. Mõned isegi ei saa aru, kuidas on raske ja kallis on osta ja toota.  Mõned pered ja inimesed ei saa endale isegi selliseid asja lubada. Aga, mis siis võiks teha või muuta, et seda vähendada?\n  Koolides on pidev toiduraiskamine, samamoodi ka kodudes. Suurem osa lapsi panevad endale liiga palju toitu ja päras see kõik on prügikastis äraviskamiseks. Tarbitoitutarga lehelt oli öeldud, et kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid. Astas läheb nii palju toitu raisku, mis moodustab 42%, puhas raha raiskamine. Et mitte nii paju raisata, võiks parem panna suure portsu asemel keskmise. Siis ei ole liiga suurt ega väikest toiduportsu raiskamist.\n  Taaskasutuspoodides on see, et suurem osa inimesi ostab riideid või asju välismaalt. Moedisainer  Eve Hanson oli öelnud, et peaks hakkama noortele tegema ekskursioone taaskasutuspoodide lattu, et näidata milline raiskamine tegelikult toimub. Minu arvates see on hea ettepanek, sest siis noored saavad teada, kuidas kasutatud riietele kingitakse uue elu. Moedisainer oli öeldnud, et mõnedele inimestele ei meeldi see, et riided koosnevad naftast. Aga ka teistes riikides on sellised, mitte ainult meil. \n  Kokkuvõtteks võin öelda, et toiduraiskamine on praegu suur, aga ma arvan , et varsti see läheb väiksemaks. Samamoodi  ka taaskasutuspoodidega, et parem osta meie toodet kui välismaalt.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('2b9eb80a-93fd-4ffa-9c4a-54e3cf35c16a', 'title', 'Toidukaos ja taaskasutuspoed');
