INSERT INTO core.text(id, content)
VALUES ('88158729-3171-44a3-836c-84a9e3c01503',
        'Grete-Liis Saumann\nMaailm on viimase paarikümne aasta jooksul palju arenenud ja sellega on tekkinud suurem valik erinevates valdkondades. Meil on võimalus valida, mida me sööme, mida me kanname ja kuidas ma kanname. Kuid kas inimesed on selle käigus unustanud panna tähele toidu kvaliteeti? Kas enam ei mõelda, mis on kehale hea või kas inimestel lihtsalt  puuduvad teadmised?\nInimesed ei pööra enam tähelepanu sellele, et kust nende toiduained pärinevad või kas nende lemmikriie on Hiinas naftast tehtud või enda kodumaalt ja toetab loodust. Väga paljud tellivad endale riideid tuntud online riietepoodidest, näiteks Shein või Temu, teadmata, kui halvasti need võivad nende kehadele mõjuda või millest tehtud on.\nToidukaost on rääkinud Tarbitoitutagralt ja öelnud, et me võtame toitu isenesestmõistetavana, me oleme harjunud, et see meil on ja unustame seda hinnata. Meil on nii palju võimalusi valida ning tihti ei vali me parimat. Olen märganud, et noored ei ole kursis, mis toiduained sisaldavad vajalikke vitamiine ja millised on loodud lihtsalt selleks, et teha inimest laisaks ja väsinuks. Nägin hiljuti sotsiaalmeedia rakenduses Tiktok videot, kus öeldi toiduvaliku kohta, et kui see toit ei eksisteerinud 100 aastat tagasi, siis arvatavasti ei ole see kõige tervislikum.\nInimesi peaks kindlasti rohkem informeerima kahjudest, mida Hiinast tellitavad riided võivad tekitada, ning arusaama toidu väärtusest. Kui inimesed oleksid kursis tagajärgedest, siis nad kindlasti teeksid ka paremaid valikuid ja mõtleksid eelkõige enda keha ja maailma jätkusuutlikuse peale.\nI');
