INSERT INTO core.text(id, content)
VALUES ('644ce193-aa74-4476-9578-7c248619db8d',
        'Maailmas on palju inimesi kes raiskavad toitu ja viskavad ära riideid, see on suur probleem mis vajab tõsist käsitlemist. Riiete ära viskamisel ja toidu raiskamisel peaks olema keeld. Miks visatakse riideid ära? Mille pärast raisatakse toitu?\nInimesed maailmas ei mõtle toidu raiskamise ega riiete ära viskamise tagajärjele ja ainult mõtlevad sellele, kust trendikamaid riideid osta ning millisel brändil on parema materjaliga riided. Toidu puhul on sama jutt, selle pärast otsitakse kohti kus valmistatakse maitsvat toitu.\nKui riideid mis on terved visatakse ära võivad need sattuda prügimäele. Raisatud toit läheb samat moodi prügimäele kui ka kanalisatsiooni ja see võib tagada ümmistusi. Pered peaksid kinni pidama toidu raiskamisest nii õppiksid lapsed toitu nautima ja mitte raiskama. Aafrikas näiteks nälgivad paljud inimesed sellel põhjusel, et neil pole palju süüa ega puhast joogivett.\nMina näiteks ei raiska toitu ja võtan nii palju kui ma jaksan ära süüa ja kui ma ei suuda kõike süüa annan ma teistele. Kui mul on riideid mis on kitsad annetan ma neid. Mina arvan, et inimesed viskavad toitu ja riideid ära sellel juhul kui toit ja riided on ülekoormuses. Mõnikord pead ära viskama riideid näiteks siis kui riie ei kõlba kandmiseks. Riideid võiks annetada sellel juhul kui need on liiga kitsad või laiad. Nõnda siis ka kui sa neid ei soovi kanda ja soovid teiste inimeste ellu rõõmu tuua. Kõik inimesed ei saa endale lubata riideid ega toitu selle taga on hindade tõusud. Inimesed peaks kinni pidama sellest kõigest siis oleks maailm veel puhtam ja korralikum.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('644ce193-aa74-4476-9578-7c248619db8d', 'title', 'Milleks ära visata ja annetada toitu ja riideid?');
