INSERT INTO core.text(id, content)
VALUES ('e5275c18-5289-4976-ae65-2d61e98b9698',
        'Tänapäeval on väga suur osa tarbimisühiskonnas just loodusressursside kasutamisel. Väga palju kasutatakse looduses maavarasid, mis on ise enesest väga tore, kuid kui me seda piisavalt hinnata ei oska siis varsti ei ole enam mida tarbida. Ei riideid ega toitu ja puhast vett. Aga miks me ültse raiskame oma ressursse?\nIgapäevaselt näen isegi seda kui palju toitu läheb raisku kasvõi koolis. Kuidas õpilased koolis tõstavad suure portsu süüa ja siis viskavad toitu ära. Sama on ka riietega. Ostatekse suurdes kogustes riideid kokku ja siis ei kanta neid ja jäävad lihtsalt kappi seisma. Kui inimesed väärtustaksid rohkem seda, mis neid n-ö toidab ja katab siis loodetavasti ei raiskaks nad ka nii palju loodusressursse: vett, head maad, enerjiat ja ka tööjõudu.\nInimesed sageli ei mõtle sellele kui palju nad sellega mõjutaksid loodust, kui lõpetaksid toidu raiskamise ja ei telliks enam Hiinast asju mis on odavad aga mõtetud. Kui me kõik hakkaksime rohkem mõtlema sellele kuidas me teekisime sellega endale ja loodusele teene siis');
INSERT INTO core.text_property(text_id, property_name, property_value)
