INSERT INTO core.text(id, content)
VALUES ('f869e088-86a4-4050-85ab-9473ba4e1e6a',
        'Inimeste tarbimisharjumus tähendab seda, et rahvas on ära harjunud asjade tarbimisest, mis on nende jaoks okei, aga realsuses ei ole, vaid lihtsalt vara raisk. Mille tarbmisega on inimesed peamiselt harjunud?\nToit – inimesed arvavad, et meil on süüa nii palju, et see otsa ei saagi, aga otsa saab see ükskord niikuinii. Inimolend viskab nii palju liiast toitu aastas minema, mis on sutsuke aegunud või tarbimata jäetud ehk toidukadu. „Toidukadu ehk raisatud toit on toit või toiduaine, mis mingil põhjusel jääb tarbimata ja visatakse toidujäätmena ära.“ (tarbitoitutargalt.ee) Näiteks inimene näeb, et piim on aegunud ühe päeva, siis pole seda mõtet ära visata, kui see pole soojas olnud, vaid ilusti külmakapis või kuskil külmas, see on täitsa kõlbav juua ning pole vaja ära visata ja raisata seda.\nMoedisainid – Maarahvas on tänapäeva moega liiale läinud ja hakanud sellest liiga palju muretsema. Kuna tänapäeva mood on nii populaarseks saanud, ning hind neil on oluliselt kallid, nii siis selle lahendamiseks on Hiina ja Aasia riigid hakanud tegema nendest koopiaid ja alustanud müümist läbi epoodide odavalt, mis on tehtud naftast ja igast mürgistest ainetes. „Väga paljud sellised rõivad on pärit nendest suurtest kuulsatest Hiina kauamajadest.“ (eeter.err.ee) Näiteks nafta on sulle halb ja mis iganes mürgiseid aineid nendel riietel võib olla, saavad ka levida ja kindlasti võib see su kehale halb olla ning mitte tervislik.\nKokkuvõtteks inimesed võiksid rohkem aru saada toidust, ja mitte raisata neid, vaid kasutada targalt, et kui on aegunud ühe päeva, kuskil külmas siis pole seda mõtet ära visata, vaid see on täiesti kõlbav tarbmiseks. Tänapäeva moega võiks võtta rahulikumalt ja mitte tellid Hiinast endale ohtlike ainetega riideid, sest see võib mõjuda su kehale halvasti ja ohtlikult.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('f869e088-86a4-4050-85ab-9473ba4e1e6a', 'title', 'Inimese tarbimisharjumused');
