INSERT INTO core.text(id, content)
VALUES ('003a8f96-8efe-44f2-9366-bcdc525eb8db',
        'Ressursside raiskamine on tänapäeval saanud inimestele tavaliseks kuna kõik on rikkamad ja neid ei huvita see mis raisatud asjadega edasi juhtub. Kuidas saaks taaskasutada rikknenud ja ära visatud asju? \nTänapäeval jääb toidujääke inimestest palju üle erinevatel põhjustel, kas siis sellepärast, et toit on riknenud või siis toit pole enam söömis kõlbulik. Nüüdseks on tulnud eestisse selline seadus, et bio- lagunevad tooted tuleb panna sorteeritud prügikasti või siis piiatud kopostikasti. Paljudel inimestel on kodus metsa alune koht kuhu nad viivad kõik oma toidujäägid kuna nad ei taha maksta eraldi prügiveo eest, mis nende boi- lagunevad jäägid ära viib.\nArtikklis toidukaost kirjutab: „Kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujääkmeid, millest toidukadu moodustab 42% ehk 26 kg“ (tarbitoitutargalt.ee/toidukaost/).  See tähendab seda, et peaaegu pool inimete toidujääkidest on ära visatud toit, mis on lihtsalt raisku läinud. Toit, mis viiakse komposti, saab veel kasutada teist korda. Komposteerunud toidujäägid muutuvad mullaks ja seda mulda saab kasutada näiteks lillepeenarde väetamiseks. Komposteernunud muld on väga viljakas ja niiske, mis  aitab taimedel kiiremine ja lihtsamalt kasvada.\nVanad ja väikseks jäänud riided visatakse tavaliselt ära, aga nendele saab sammuti uue elu anda. Vanad riided saab viia taaskasutuskeskusesse, et neid saaks keegi teine kasutad, kellel pole raha piisavalt, et uued iided osta. Taaskasutuskeskustest võib leida tavaliselt palju erinevaid asju, mis on väga odava hinnaga oma kvaliteedi kohta, alates suusasaabastest kuni riieteni välja. \nTänapäeval koguneb inimestel palju toidujääke, mis visatakse lihtsalt ära. Toidujääke saab komposteerida, millega saab veel omakorda väetada lillepeenraid. Enamus inimesi viskavad oma vanad riided ära, aga oma vanad ja väikseks jäänud riided saab viia taaskasutuskeskusesse kus saab nendele anda teise elu. Taaskasutuskeskus on tavaliselt nendele inimestele, kes ei jõua oma rahakottiga omale uusi riideid osta.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('003a8f96-8efe-44f2-9366-bcdc525eb8db', 'title', 'Ressursside taaskasutamine');
