INSERT INTO core.text(id, content)
VALUES ('63210bec-9dd1-48cd-a775-ac89e8856b9a',
        'Meil maailmas on palju probleeme, on kliimasoojenemine, inimesed on nälgas, liiga lohakad ja palju muud. Aga on ka selliseid muresid, mille peale mõni ei oskaks mõeldagi, nagu näiteks toiduraiskamine ja liigne riiete kokku ost.\nAlustame toidu raiskamisest, inimese teevad seda rohkem kui aru saavad ja selle peale ei saa pahandada väga, minul ise ka läheb toitu vahepeal raisku isegi kui ma ise sellest väga aru ei saa. Kas lasen kogematta mingil asjal kappis või külmkappis pahaks minna kuna unustasin, et selle ostsin või mis iganes.\nJärgmiseks võtame riiete liigne kokku ost.  Eve Hanson on öelnud „Ma näen taaskasutuspoodide laos vabatahtlikuks käies seda rõivaste kogust, mis tekib iganädaliselt juurde.“ (eeter.err.ee). Ja see on täiesti õige, tahetakse seda uskuda või mitte. Minul ema sõbranna omab kaltsukat ehk teise ringi riiete poodi kuhu tuuakse oma vanad riided tasuta ning need müüakse odavamalt maha. Olen näinud kui palju riided sinna viiakse ning palju tal neid veel laos seisab.\nMeie maailmas pole ühtegi probleemi, mida pole võimalik lahendada. Ka nendele kahele probleemile on lahendus olemas, asi on lihtsalt selles, et kas inimesed on võimelised oma harjumusi muutma? Toiuraisule saaks lahenduse näiteks niimodi, et igaüks teeb endale selgeks täpselt kui palju tema majapidamises tegelikult toitu ära süüakse ning ei osta üleliigset toitu. Riietega suhteliselt samamoodi, kui on juba soojad talvejalanõud olemas, siis uusi ei osta ja niimoodi kõikide riietega.\nKokkuvõtteks on meil kõigil negatiivseid harjumusi nagu näitseks teadmata toiduraiskamine ja liigne riiete ost. Aga neid on võimalik lahendada. Selle asemel, et ostetakse rohkem toitu kui majapidamises ära jõudakse süüa ning uute jalanõude ostmine kui on olemas täiesti terved jalanüud jube, tuleks mõelda, et kas mul on tõesti vaja neid?');
INSERT INTO core.text_property(text_id, property_name, property_value)
