INSERT INTO core.text(id, content)
VALUES ('0622af26-8340-4cb8-957d-b164e6d13ea4',
        'Taaskasutamine on palju räägitud teema viimastel aastatel, globaalse soojenemise ja prügimägede tekke tõttu. Inimesed raiskavad väga palju ja kõik reostavad keskonda mingit moodi, kuid viimastel aastatel on asi ainult hullemaks läinud. Miks on hea taaskasutada?\nTaaskasutamine on teema mida kõik oleme kuulnud , sellest räägitakse igal pool. Kõik saavad panustada end nagu näiteks kõik oma toidu ära söömine „Kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26%“(tarbitoitutargalt.ee/toidukaost/). See on väga suur kogus toitu iga inimese kohta ja kõigi panus loeb, et seda kogust vähendad.\nRiideid saab ka taaskasutada näiteks viia oma riided taaskasutus pooidesse või luua ise midagi uut oma vanade riietega või anda oma vanu rõivaid nendele kes neid vajavad, valikuid on palju. Me lihtsalt ei näe neid kui õige aeg käes ja lihtsalt raiskame korralikke rõivaid selle käigus ning kaotame ka suures koguses raha sellepärast. Saame ka ise leida korralikke rõivaid taaskasutus ladudest „Ma näen taaskasutuspoodide laos vabatahtlikuks käies seda rõivaste kogust, mis tekib igapäevaselt juurde. Need on meeletud hunnikud ja see on väga õpetlik,“(„Vikerhommik“, intervjueeris Anu Väiba (eeter.err.ee)). Iga riide osa, mis taaskasutada teeb muudatuse. Kõigi panus loeb.\nTaaskasutamine on teema mis tuleb meile kõigile kasuks ja säästab meile palju toitu ja raha. Isegi kui ise ei soov oma vanu rõivaid alles jätta on alati võimalus neid kellegile anda või viia poodidesse, kes vajavad neid, Ise säästab loodust ja aitad ka teisi. Kõigi panus loeb.');
