INSERT INTO core.text(id, content)
VALUES ('d84ff5b8-024c-4289-9f8f-a11b74a78ad4',
        'Tarbimine on kaupade ja teenuste teel vajaduste rahuldamine. See on maailmas niivõrd suureks probleemiks kasvanud, et seda kutsutakse tarbimisharjumuseks. Millised on tänapäeva rahva tarbimisharjumused? \nInimesed raiskavad liiga palju toitu. „On inimesi, kes raiskavad toitu, sest nad saavad seda endale lubada.“ (tarbitoitutargalt.ee). Ma olen selle lausega nõus. Suurema sissetulekuga isikud ei hooli söögist nii palju, kui inimesed, kes ei ole rahaliselt heas seisukorras. Minu perel on piisavalt raha, et meie külmkapp on kogu aeg toiduained täis ja me vahest laseme sellel halvaks minna, sest isegi siis kui see läheb saame juurde osta. Lapsed, kelle vanemad ei teeni piisavalt raha, ei saa toitu raisata, sest see kogus toitu, mis nad kätte saadavd võib olla nende esimene korralik kõhutäis kogu nädalas. Jõukad inimesed raiskavad, vaesemad kasutavad.\nTänapäeva noored kulutavad raha ebakvaliteetesetele riideesemetele. Tütarlapsed ostavad hästi palju riideid veebipoodisest nagu Shein. Selles tekibgi probleem. Shein on hiina ettevõte. Nende kaup on odav aga samas ebakvaliteetne, kuigi teismelised ei hooli sellest, nad näevad seda odavat hinnasilti ja lisavad selle ostukorvi. Eva Hanson on ütelnud, et tema arvates on oluline, et inimesed hakkaksid eelisatama kvaliteeti kvantiteedile (eeter.err.ee). Ma olen ka Sheinist kaupa ostnud, aga need pole kunagi kvaliteetsed olnud. Nüüd ma pigem kulutan raha kallile esemele, mis on kvaliteetne, mitte viie eurosele kleidile, mis ärritab mu nahka. Hea ja kulukas on alati parem kui odav ja halb.\nPraeguse aja rahva tarbimisharjumused on suhteliselt halvad. Nad ostavad kaupa kokku aga ei tarbi seda kõike ära. Samuti kulutavad nad raha riietele, mis nad hiljem ei kanna. See on meie inimeste praegune ühiskonna probleem, mida tuleks parandada.');
