INSERT INTO core.text(id, content)
VALUES ('8ecd36e1-6ac2-4a6f-953d-32db9c69ec00',
        'Inimesed saavad tarbida mitmeid erinevaid asju isegi neile kahjulike asju. Ühiskond ise ei pane tähele kui palju nad tegelikult tarbivad ja kas see mõjub neile hästi. Mis on siis inimseste tarbimis harjumused? \nToitu minu arvates on iga inimene raisanud. Näiteks sul võib olla kõht täis ja sa ei jaksa enam süüa ning viskad toidu lihtsalt ära. Mõtled, et see pole palju, mida sa raiskad. Tegelikkuses siin artiklis ütleb „ Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26kg.“(tarbitoitutargalt.ee/toidukaost/) Tuleks mõelda kas on toit vaja ära visata?\nInimesed on ka harjunud nikotiini ja alkohooli tabimisega. Isegi kui nad tevad, et see kahjustab neid. Nad ei saa loobuda, sest see aine on sõltuvust tekitav. Heal juhul suudab inimene maha jäta selle, aga enamnused ei suuda seda teha. Nendel oleks vaja tõsist abi ja pingutust, et saada sellest pisikust lahti.\nTarbimine ei pea tähendama, et otseselt sööd või jood. See võib ka olla asjad mida sa ostad. Enne kui sa ostad midagi võiksid mõelda, kas sul seda vaja ikka on. Anu Välba ütles intervjuus „Ma näen taaskasutuspoodide laos vabatahtlikuks käies seda rõivaste kogust, mis tekib iganädalaselt juurde. Need on meeletud hunnikud ja see on väga õpetlik.“ (eeter.err.ee) Nii, et vali hoolikalt mida ostad. \nInimesed kipuvad toitu raiskama, mida nad ära ei söö. sõltuvuses inimesed tarbivad nikotiini ja alkohooli, mis pole neile ültse kasulik. Ostijad ostavad poest kokku kola, mida nad isegi ei kasuta.');
