INSERT INTO core.text(id, content)
VALUES ('b0e192a4-be74-4315-88aa-5d4886b7bd08',
        'Viimase mõne aastakümnega on inimeste tarbimisharjumus mitmekordistunud. Tahetakse aina rohkem uusi asju alustades kodumasinatest ja mänguasjadest lõpetades loomulikult riietega. Peamisteks e-poodideks on saanud just Hiina kaubamärgid mis toodavad meeletutes kogustes kõike ebakvaliteetselt ning hoolimata keskkonnast ja tööjõust. Suur probleem seoses ületarbimise ning raiskamisega on ka toit. Väga tihti visatakse minema toitu mis pole veel kasutustähtajani jõudnudki, aga on sellele nö „liiga lähedal“.\nMa ütleks, et kõige suuremateks Hiina kaubamärkideks on „Shein“ ja „Temu“. Miljonid noored üle terve maailma ostavad enamus oma riietest ning muudest vajalikest vidinatest just sealt. Selleks on ka tegelikult üks väga arusaadav põhjus ja selleks on raha ja selle puudumine. Sealt saab osta riideid vaid mõne euroga, aga see on meeletult ebaeetiline. Enamus suurtest Hiina kaubamärkidest kasutavad lapstööjõudu ning orjatööjõudu. Lastele kes võib-olla pole veel kooligi jõudnud õpetatakse kuidas käsitleda õmblusmasinat ning kuidas selle abil võimalikult kiirest mõni riideese valmis teha. Rääkides eetikast tundub vale mitte sisse tuua ka keskkonna teema. Masstoodang sellisel tasemel reostab ning rikub meie loodust. Väga paljud riided mis on Hiinast pärit on tehtud naftast mille maa seest välja toomine võib tekitada väga suuri kahjusid nii ookeanis kui ka maa peal. Nagu ütles moedisainer Eve Hanson „Ei telliks Hiina veebipoodidest juba põhimõtte pärast asju.“\nToitu raisatakse mõtlematult ning väga palju ja seda tehakse enamasti arusaamatutel põhjustel. Nagu eelnevalt mainisin, siis tihti visatakse minema toitu mis pole veel tähtajani jõudnud. Minu jaoks on see täielik jaburus, sest esiteks jääb arusaamatuks, et miks raisatakse oma raha ning teiseks ei saa ma aru mõttekäigust mis võis sellise teoni viia. Olen isegi näinud kuidas visati minema pannitäis täiesti korralikku sööki puhtalt selle pärast, et see antud roog siiski ei maitsenud. Mina ütleks, et sellisel hetkel peaks toidu kas kellelegi laiali jagama, ära annetama või siis kui muid võimalusi pole ikkagi ära sööma. Kasvõi vägisi. Toidu ära viskamine pole lihtsalt eetiline.\nOn veel palju erinevaid teemasid mida arendada rääkides ületarbimisest, aga need millest mina juttu tegin on peamised. Üldse igat moodi tarbimine pole enamasti kasulik. Igal võimalusel peaks ostma oma tooteid kas kaltsukatest või kodumaisetest poodidest kus tead, et tooted pole tehtud reostades loodust või kasutades lapstööjõudu. E-poodide laod kust omale riideid ning muid eluks vajalikke asju tellida võiksid olla elukohale võimalikult lähedal, et vähendada transpordi kulusid inig kahjusid keskkonnale. Lõpetuseks ütleksin, et igaüks meist võiks natukene rohkem tähelepanu pöörata sellele, kui palju me tarbime. Kui osta oma riided kaltsukatest ja need nö „ribadeks“ kanda ning ära süüa kogu toit mille soetanud oleme oleks kõik juba palju paremini.');
