INSERT INTO core.text(id, content)
VALUES ('62a31946-a6e7-49be-8d8b-02acde96f2bd',
        'Inimeste tarbimisharjumused on oluline teema, millest peame kõik kindlasti rääkima ja arutlema. Minu arust on pealmine probleem see, et inimesed ei hooli oma tervisest ja oma heaolekust ning keskkonnast. Näiteks on teada, et riided tulevad tehastest, mis edundavad odavat tööjõudu ja teevad keskkonnale halba, kuid inimesed ikka ostavad uusi riideid pidevalt. Paljud teised probleemid tekivad tarbimisega ka, küsimus on selles, kuidas seda vältida?\nPealmine probleem ongi see, et me ei pöördu piisavalt tähelepanu keskkonna heaolekule. Minu arust see on just kõige tähtsam, kuna see mõjutab meie enda tuleviku ja ka meie laste tuleviku. Näiteks reostamisega on tõesti suur häda. On teada, et meil on palju plastpakendid vees ning igal pool looduses ja isegi meie veres väikeste mikroplastidena. Globaalne soojenemine on ka väga hea näide. Teadlased arvavad, et meil on ainult umbes 5 aastat, kuni globaalse soojenemise efektid on pöördumatu.\nAga kuidas seda lahendada? Kuid minu arust peaks suurem surve olema suurte firmade peal, kuna nemad teevad rohkem keskkonnale halba, võiks ka iga inimene palju rohkem panustada keskkonnale ja selle heaolekule mitmel moel. Näiteks võiksid inimesed vähem reostada ja ümber töötada asju mida nad ei kasuta enam. Rohkem võiksime kaltsukatest osta, või ka teha vanadest riietest mingi uus ese. Võiksime vähem toitu raisata, kuna näiteks Eestis iga inimese kohta aastas tekib 61 kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg.\nKokkuvõtes on neid probleeme vaja kiiresti lahendada. Vähemalt on minul on väga tähtis, et loodusel ja keskkonnal hea. Koostööga ja hea planeerimisega, saame kõik korda teha ning rajame täiusliku tuleviku meie lastele.');
