INSERT INTO core.text(id, content)
VALUES ('c830a6f5-8489-402d-8e7e-31eb0adf77aa',
        'Inimesed raiskavad toitu keskmiselt väga palju. Mitu neist teevad sellepärast, et nad arvavad, et see on nende jaoks lubatud. On ka lihtsalt neid, kes viskavad ära toitu, et neil oleks rohkem ruumi kodus või külmkapis. Kuna inimesed raiskavad nii palju toitu, on keskmiselt Eesti inimene raiskanud aastas keskmiselt 61kg toidujäätmeid. Ja need toidud on, kas riknenud ehk kuupäevast möödaläinud toidud või on see lihtsalt ülejäänud toit, kes pole jõudnud ära süüa.\nMa ütleks seda, et kõige suurem probleem on see, et inimesed ei oska toitudega hoolitseda. See pole ainult raiskamisega, vaid on ka rahaga. Inimesed ostavad süüa lihtsalt, et seda visata minema. Mõttetu raha raiskamine. See pole ainuke probleem, mis toob sellega kaasa, on ka ressursse, mis on: maad, vett, energiat ja tööjõudu. Seda probleemi saab lahendada. Kui ostad süüa, tee seda targalt. Ära osta liiga palju toitu. Sa muidu ei jõua kõik ära süüa kuni söögiküüpäevani, mis läheb lihtsalt raisku. Teine asi on see, et inimesed võiksid vaadata, kus nad üleüldse ostab kust. Ei ole mõttet osta seda, mida sa ei hakka isega kasutama. Muidu see läheb raisku, mis pole hea.\nOn ka veel lahendusi. Võiks hakkata noortele näitama, kuidas asjad toimuvad ja kuhu nad kõik lähevad. See tuleb väga kasuks noortele, et nad tulevikus seda viga ei teeks. See on ka väga kasulik vanematele inimestele, kes juba teevad seda viga. Kui kõik inimesed oleksid seda teadnud, siis oleks raiskamine palju vähem kui praeguselt. Lihtsalt loodab, et see hullemaks ei lähe tulevikus, kuna aina rohkem inimesi tuleb maailmasse. \nMinu arvamus on see, et inimesed peaksid oskama hoolitseda ja mitte asju kohe ära viskama. See pole üldse hea maailmale. Ja, et inimesed ei viskaks lihtsalt toitu ära. See pole üldse meile hea. Ega ka mingi naftast tehtud asi näiteks: riided.');
