INSERT INTO core.text(id, content)
VALUES ('a9d40a06-7c64-47c1-aaf1-8b76c1e6122f',
        'Paljud inimesed raiskavad toitu kuna naad teevad liiga suuri söögikoguseid. Ma usun, et toidu raiskamine on suureks probleemiks saanud. Aga kuidas vähem sööki raisata?\nMina usun, et põhi probleem on selles kui palju toitaineid ostetakse. Selle all ma mõtlen seda, et kui poest ostetakse suured kogused sööki siis võib ka palju sellest halvaks minna. Nagu näiteks kui inimesed ei viitsi palju poes käia ostavad nad lihtsalt suured koogused, et ei peaks järgmine või ülejärgmine nädal tagasi tulema. Aga nii paljud  toitained muutuvad kas halvaks või vanaks, kui neid mitte kasutada. Näiteks on minu perel ka see probleem kuna me ostame alati väga palju toitu mida me kohe ära ei söö. Niimodi läheb pool meie sööki kiiresti halvaks kuna me seda ei söö. Ma usun, et see probleem on põhiliselt toidu ostmises, ja et kui inimesed neid kontrolliksid ja oleksid nõus rohkem poes käima oleks see probleem lahendatud.\nTeine probleem on liiga suurte söögikoguste tegemine. Ma mõtlen seda, et kui liiga palju sööki tehtakse siis kas söök soojendatakse järgmiseks korraks või söök visatakse lihtsalt ära. Nii visatakse palju sööki ära. Meil on ka see viimati juhtunud. Me pidime õe söögi ära viskama kuna ta ei  jaksanud oma sööki ära süüa.\nKokkuvõteks ütleksin ma, et peaks ostma ainult toitaineid mida läheb päriselt vaja ja sööki tehes peab alati kogust vaatama, et mitte liiga palju teha.');
