INSERT INTO core.text(id, content)
VALUES ('b22c7ff0-91a9-44b7-9db5-b43f666b5ad2',
        'Inimeste tarbimisharjumused on tänapäeval väga erinevad võrreldes sellega, kuidas vanasti oli. Vanasti, kui tahtsid midagi poest süüa või uusi kingapaare osta, siis pidid sa sõrmed ristis hoidma, et midagigi sealt leiaks. Kuid enam pole nii, kuna poode ning kaupa on ülemääraselt palju. Inimesed on hakkanud arvama, et ületarbimine on täiesti igapäevane tegevus. Kas tänapäeva tarbimisharjumustega on kõik täiesti korras või toob see kaasa ka ohte?\nÜks suuremaid probleeme, millega inimesed on nüüd täiesti harjunud, on toidu raiskamine. Meile tundub, et toitu on veel ja ei saagi otsa. Isegi, kui seda veel on, ei tähenda, et me peaksime seda suurtes kogustes ära viskama. Tavalise Eesti inimese kohta tekib aastas keskmiselt 61 kg toidujäätmeid, millest raisatud toit moodustab 26 kg. Seetõttu ei raiska me ainult oma raha, vaid ka ressursse, mida kasutatakse toidu tootmiseks, näiteks maad, vett ja energiat.\nVeel üks tõsine probleem on kiirmood. Paljud inimesed ostavad endale hulk riideid odavatest poodidest nagu H&amp;M või SHEIN. Kui nad riided kätte saavad, kannavad nad neid tavaliselt üks või kaks korda ja siis viskavad ära. Selline tegevus on keskkonnale tõsiselt kahjulik ning tööjõud, mis nendesse riidetesse läheb, on meeletult suur.\nMida me saaksime teha, et ületarbimist vähendada? Kokkuvõttes peaks igaüks oma isiklikud tarbimisharjumused üle vaatama ning tarbimise suhtes olema palju rohkem ettevaatlikumad. Ei tohiks määratult ostukorvi toiduga täita ning igat kleiti, mis poes näed, kohe osta.');
