INSERT INTO core.text(id, content)
VALUES ('a22c425b-12f6-4a23-b183-f85f6217ec03',
        'Inimesed tarbvad liiga suurtes kogustes. Inimestele on harjumuseks saanud, et koguaeg on võimalik asju või riideid juurde osta ja selline mõtteviis toob endaga kaasa tohututes kogustes raiskamist. Selline pidev tarbimine, läheb meie keskkonnale väga kalliks maksma ja midagi tuleb ette võtta.\nEesti keskmine inimene arvab sageli, et tema raisatud toit ei mõjuta suures plaanis midagi, kuid just see et igainimene üldiselt nii mõtleb, mõjutab toidukadu kõige rohkem. Inimesed ostavad poest liigsetes kogustes toitu, mille tagajärjel lõpetab suur osa toidust jällegi prügikastis. Mina arvan, et üks viis kuidas toidukadu vähendada on teadvustada Eesti inimesi piisavalt just sellest, kui palju läheb toitu raisku ja mis on selle tagajärjed.\nKiirmood on üks väga populaarne teema noorte kui ka täiskasvanute seas. Riideid toodetakse kõige hilisemate moetrendide järgi, mille tulemusena tekib väga suur riiete raiskamine. Tohutustes kogudes riideid viiakse taaskasutuskeskustesse, kuid ostetakse ikka uusi riideid kiirmoepoodidest juurde. Selline tegevus pole üldse jätkusuutlik ega looduse sõbralik. Minu arvates on lahendus sellele lihtne. Inimesed peavad ostma riideid, mis on kvaliteetsed ja pikalt kasutuskõlblikud. Tuleb rohem käija taaskasutuskeskustes ja mõelda enne uue riideeseme soetamist põhjalikult läbi, kas seda on tõesti vaja.\nNiisiis, et vähendada toidu-ja riidekadu, peab teadvustama inimesi tagajärgedest, mis sellega kaasnevad ning inimesed peavad tõsiselt oma tarbimis harjumused ülevaatama.');
