INSERT INTO core.text(id, content)
VALUES ('79145d08-e9be-44ab-826c-8b9e234148b6',
        'Ületarbimine on kasvav ülemaailmne probleem. Ostetakse kokku asju, mida ei vajata ning siis visatakse need paari päeva pärast minema. Tõusulainel on kiirmoe brändid, kust saab osta odavalt riideid, mis käivad moega kaasas. Kui need moest välja lähevad vistatakse need lihtsalt ära. Inimesed on jõukamad ja selletõttu vistakse palju toitu ära, kuna saab ju juurde osta. Mina arvan, et selline suhtumine viib ülemaailmse katastroofini, milles oleme me ise suurimad kannatajad.\nKiirmoe brändid nagu Shein, H&amp;M ja ASOS on viimastel aastatel palju kuulsust kogunud just selle pärast, et nad toodavad kiiresti ning odavalt moekaid rõivaid. Kuid nende kvaliteet ei ole kõige parem. Mood on nagu ilm, mis muutub iga päev. Tihtilugu on äsja ostetud riided nädala pärast moest väljas. Need rõivad viiakse taaskasutuskeskusesse ja arvatakse, et tehakse loodusele head. Tegelikult pole see tõsi. Moe disainer Eve Hanson on öelnud: „Ma näen taaskasutuspoodide laos vabatahtlikuks käies seda rõivaste kogust, mis tekib iganädalaselt juurde. Need on meeletud hunnikud.“ Ma arvan, et seda probleemi tuleks rohkem esile tuua ja näidata välismaailmale, et riiete taaskasutusse viimine polegi nii hea kui meile tundub. Ma arvan, et seda probleemi saaks parandada kiirmoe brändide piiramisega. \nKuigi on inflatsioon ja toiduhinnad tõusevad iganädalaselt, ostekase koju asju, mida tegelikult ei sööda ja unustatakse need kappi, et need hiljem ära visata. Näiteks tahetakse proovida mõnda uut retsepti ja ostetakse selleks mõni vähe kasutatav toiduaine. Kuid siis unustatakse see külmkapinurka, kuna selle valmistamine ei ole kiire. See toiduaine läheb kas hallitama või hakkab rikknema ja siis see visatakse lihtsalt ära. Minu kodus juhtub seda sageli. Näiteks paar päeva tagasi ostsime allahindlusega vorstikesi ja unustasime need külmkappi. Täna hommikul viskasime need biojäätmetesse. Ma arvan, et seda probleemi saaks vältida kui minna poodi poenimekirjaga, sellisel juhul on väiksem võimalus osta ebavajalikke asju, mis võivad kappi seisma jääda.\nAlati ei ole vaja kanda kõige moekamaid riided ja osta kõike mida toidupoes näed. Ma arvan, et kõik inimesed peaksid enda tarbimisharjumused üle vaatama ja tegema nende põhjal järeldused.');
INSERT INTO core.text_property(text_id, property_name, property_value)
