INSERT INTO core.text(id, content)
VALUES ('fe68f4fd-da51-4bca-9a87-81a306280184',
        'Inimeste üleliigne tarvitamine ikasuguseid produkte pole ideaalne, see et inimesed on nii harjunud sellega et kui nad tahavad ,siis na viskavad midagi välja ja ei huvida et kas sellesd saab kasutada või ei saa.  \ninimeste tarvitamisega see et peale paar korda riide eseme kandmisd või kui kööki vilijad pole perfektsed, siis selle peaba väja viskama, muidugi ka see et kui me teeme hästi palju toodeid ja sellega reostame mailma kune toodeid on nii palju et sellel pole kuhugi minna nii et se peab loodusese minema, me sellega rikkume loodusd ja ka neid kess looduses elavad, koos sellega et me pidevald lõikame puid et paperit teha või põletus materjali aga kunagi me ei mõdle tulleviku peale vaid miss meile kõige parem  on kui me kasvataks neid puid tagasi et meil oleks kuiskild midagi ikka võtta ja lindudel ja loomadel oleks kuskil olla.\nMeil oleks parem kui see mis me ära tarvitame me seda kasvataks tagasi et meil tulevikus on seta tarvet kasudada, see ka et ei raiska tooted näideks kui puu maha langedad siis kasudad oksa multši kasutatakse et mingeid auge täida ja suuremad puud kasutatakse mööpli jaoks ära ilma selleda et see jääks kuhugi seisma kuni seda kasdutata ei saa. \nMa ütleks seda et kuime targald tarvidame resurse mis meile on andud siis doidu raiskamis protsend võika alla minna');
