INSERT INTO core.text(id, content)
VALUES ('f3bcfc8e-5286-4ea2-8afb-48ce09f91eab',
        'Inimeste tarbimisharjumised halvened igapäevaselt. Minu arust on põhiliseks probleemiks see, et inimesed ei näe mida see keskkonnale teeb, ning usuvad, et nende teod ei mõjuta teiste heaolu. Sellele probleemile on juba ammu proovitud leida lahendusi, kuid ükski neist lahendustest ei ole piisavalt efektiivne või muudab meie elukvaliteedi halvemaks.\nMiks on inimeste tarbimisharjumused halvad? Ma usun, et suurimaks probleemiks on suurtööstuste nõrga ja ebakvaliteetse tööjõu kasutamine. Kuna inimesed hoolivad tihtipeale ainult hinnast ja mitte kvaliteedist, ostavad nad endale riideid ja tooteid, mis ei ole keskkonna sõbralikud ja hiljem äravisates reostavad nad loodust. Suureks probleemiks on kindlasti ka inimeste laiskus ja minimaalne panus taaskasutamisse. Kindlasti on ka üks meie halbadest harjumustest liigne toidu raiskamine, mis tuleb sageli ette näiteks koolides ja peredes, kes pingutavad endale toidu ostmisega üle, ostes liiga suurtes kogustes toitu ja seda hiljem ära visates.\nKuidas parandada inimeste tarbimisharjumusi? Minu arust on inimeste tarbimisharjumused nende endi halbade otsuste taga kinni. Selle muutmiseks saavad inimesed teha nii mõndagi, näiteks osta keskkonnasõbralikumaid riideid ja tarbeid ning samuti ka normaalsetes kogustes toitu. Mis puutub suurtööstuste tootmisesse, ei näe ma probleemile muud lahendust, kui seda, et inimesed peavad lihtsalt halva kvaliteediliste toodete ostmise lõpetama.\nKokkovõttes on inimeste tarbimisharjumuste parandamine nendi enda teha ja nad peavad hakkama aru saama, mida nende halvad otsused meie keskkonnale teevad. See teema pole ültsegi mitte uus, mis paneb mind mõtlema, miks pole sellele juba probleemi leitud. Kokkuvõttes võiksid inimesed hakkata panustama rohkem taaskasutamisse ja mõelda enda otsuste tagajärgedele.');
