INSERT INTO core.text(id, content)
VALUES ('e1137c26-ec61-4c2d-971c-3411e27a16e3',
        'Inimeste tarbimisharjumused on aja jooksul oluliselt mutunud nii maajanduses, tehnoloogia arengust kui ka keskonnamõjudes. Tänapääeva tarbimis kultuur on tugevalt seotud tarbimisühiskonna ja globaalsete trendidega mis soodustavad kiiret ostlemist ja sageli lühtajalist mõtlemist. Tarbimise suurenemine on viinud sellele, et paljusid tooteid ostetakse mitte vajadusest, vaid pigem soovist olles tihti dikteeritud reklaami ja sotsiaalse surve poolt.\nÜks tähtsamaid muutusi tarbimisharjumustes on teadliuse kasv keskkonna mõjude osas. Paljud inimesed on hakkanud tähelepanu pöörama keskkonnasõbralike toodetele ja teenustele näiteks mina poes käies ostan õrrekana munasid ja naturaalset shampooni ja igasuguseid erinevai ökotooteid. sammuti on üha rohkem inimesi hakanud teadlikumalt tarbimist vähendama, olles vähendanud asjade kogumie poolehoidjad ning hindavad kvaliteeti rohkem kui kogust.\nSmmuti on tehnoloogia arengul suur mõju inimeste ostu käiumisele andes inimestele võimaluse osta tooteid ja teenuseid interneti vahendusel, sageli ilma neid füüsiliselt puutumatta. E-kaubandus on muutunud üha populaarsemaks andes tarbijatele mugavuse ja ajasäästu samas kui ostuprotsess muutub üha kiiremaks ja vähem läbimõtlikuks.\nkokkuvõttes on inimeste tarbimisharjuused oluliselt muutunud paremuse suunas ja isegi mina ja mu pere olen hakkanud paremini säästma ja kokku hoidma ostes ökotooteid. Aga ökotoodetel on ka suurem hinnd mis ei sobi igale inimesele.');
