INSERT INTO core.text(id, content)
VALUES ('a33b7087-459d-4ca4-b5aa-9d2e6e5e562e',
        'Tarbimisharjumused, mis inimestel praegu on, reostavad meie planeeti ja ei ole jätkusuutlikud. Inimestel on tekkinud illusioon, et ressursse on meil siin maailmas lõpmatult. See ei ole tõsi. Me peaksime oma tarbimisharjumusi muutma, et meil oleks ka tulevikus siin planeedil hea elada.\nIga Eesti inimese kohta tekib aastas keskmiselt 61 kg toidujäätmeid, millest 26 kg on toidukadu. See on tohutult palju. Toiduraiskamine on tõsine probleem, kuid ka kahjuks väga tavaline nähtus. Kodus näen isegi kuidas vahel satub prügikasti täiesti puutumatu toit, mis lihtasalt unustades on oma kehtivuse kaotanud. Toit ei ole ainus asi mida raiskame. Riided, vesi, elekter- neid kõiki kulub tohutult. See koormab meie planeeti sest, sest me tarbime neid ressursse liiga kiiresti, liiga suurtes kogustes. See koormus meie planeedile tekitab keskonnahäireid näiteks nagu kliimamuutus.\nTarbimisharjumused, mis meil on pole enam elujõulised. Igaüks peaks neid jälgima. Näiteks oled tähelepanelik, et kui toast lahkud, paned tule kustu. Ostad kvaliteetseid riideid mis kestavad, mitte odavaid kiirmoe riideid, mis mõne nädalaga katki. Poodi minnes teed nimekirja, et ei ostaks midagi, mida tegelt ei vaja. Viise oma tarbimisharjumusi muuta on veelgi. Oluline on, et me nendele tähelepanu pööraksime ja teadlikumalt tarbiksime. Siis säästame Maad ja ka ennast. \nTarbimisharjumused mõjutavad meie planeeti ja selle pärast peame neid tähelepanelikult jälgima. Tuleb vältida raiskamist ning tarbida teadlikult. Nii saame siin veel elamist nautida.');
INSERT INTO core.text_property(text_id, property_name, property_value)
