INSERT INTO core.text(id, content)
VALUES ('2af8520c-30ba-4ef0-8683-2bcc0a2fe290',
        'Inimesed kasutavad igapäevaelus palju erinevevaid tarbeid. Näiteks jaapanlased kasutavad väikseid plastkotte, igal võimalusel mis ette tuleb, ole see kas: kommid, snäkid, suupisted, väiksed mänguasjad nad alati panevad iga tarbe eraldi kotti. Mujal maades mina siukest süsteemi pole märganud.\nInimeste tarbimisharjumused seda saab võtta nii positiivselt kui ka negatiivselt, iga harjumus mida üks inimene teha võib, pole alati positiivne ühiskonnale ning ka endale. Näiteks kui sa tarbid rohkelt plasti, siis  oleks kindlasti hea kui sa selle ka õigesse kohta ära paned mitte, et sa viskaksid selle kuhugi suvakasse kohta maha. prügisorteerimis süsteem aitab sellele reostamisele vastu, et ei ole nii palju prügi maas ega ka ei läheks valesse kohta. Kuigi see süsteem ei saa aidata ainult ise reostamisele kaasa, vaid inimsed peavad ise kontrollima oma tegevusi ning jällegi ka oma tarbimisharjumusi. Kõige halvem mis olla saab, on kui keegi ei keela, ega sa ise aru ei saa, et sa teed midagi valesti. Kuidagi peaksid sa endale leidma viisi, kuidas end takistada ning endale piire määrata reostuse ning halva tarbimisharjumuse vastu.\nOn ka häid tarbimisharjumusi, mida saad ära kasutada positiivselt endale kui ka teistele. Kuid alati pole tarbimisharjumusega seotud probleem väljas pool, vaid võibolla ka sinu enda koduaias- või  kodus sees. Olen kuulnud- ja näind olukorde kus toad on täis söögipurusid ja ebavajalikke tooteid on kokku ostetud. Aeades on ehitatud palju lastele mõeldud ehitisi ning liivakaste kus laps saaks oma aega viita. Üks asi on aiaga seoses tarbimisharjumused, kuid teine on oma sisetoas tarbimisharjumused. Näiteks on olnud probleeme kus täielik prügi istub kuskil maja peal ringi ning keegi seda ära koristada ei raatsi. siis tuleksgi endale määrata limiit, kust sa saad endale lihtsamaks teha tarbmisharjumused negatiivsest positiivsele. Näiteks võin veel tuua näiteks ,et on moes lõhnade ostmine ning ka kogumine, noored ostvad endale eriti palju erinevaid lõhni õudsate hindade eest, mida iga vanem kinni maksta ei suudaks. Sellega tulevad ka mängu erinevad Hügeenitarbed nagu: šhampoonid, higipulgad, odekollonid. Neid tarbeid on kindlasti vaja inimestel, et end hästi muljestada, kuid peab olema ka piir, kust sa endale neid tarbeid ei pommitaks üle ning ei raiskaks enda väärtuslikku raha nendele, lõpudelõpuks ei pruugi sa igat tarvet isegi kasutada, vaid lähevad need mõttetult raisku ja loodusesse reostuseks. \nKokkuvõtvalt peaksime me kõik võtma tarbimisharjumusi tõsisemalt ning mitte üldsegi teha välja enda negatiivsetest harjumustest. Peaksime me kõik olema normaal piirides ning mitte ostma enda lemmikuid vidinaid ülemääralikes kogusdes. Oluline on ka panna prügi õigesse kohta, mitte seda maha visata kuskile kuhu see ei käi. Lõpudelõpuks sa ise vastutad enda tegevuste eest ning keegi selles süüdi ei jää.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('2af8520c-30ba-4ef0-8683-2bcc0a2fe290', 'title', 'Inimeste tarbimisharjumuse');
