INSERT INTO core.text(id, content)
VALUES ('93642f4c-5602-4dec-b731-0d66078bed22',
        'Meie tarbimisharjumused on muutunud palju, kuna inimesed tarbivad päevades aina rohkem tarbeid. Inimesed ostavad näiteks endale rohkem tarbeid,kuna see võib olla moekas ja ei pruugi neile üldse kasulik olla. Neid tarbe ostmisi tuleb enamasti sotsiaalmeediast, kuna inimesed näevad, et teistel on midagi lahedat ja siis soovivad endale ka seda osta.\nTarbimised võivad olla ka nii positiivse küljega kui ka mitte kõige parema mõttega. Näiteks posotiivne võib olla see, et mida sa tarbid igapäeva elus näiteks nagu söök, hügeenitarbed ja riideid. Need on meile kasulikud ja vajalikud igapäevases elamises. Minu arvates on söök meil väga oluline, kuna inimesed peavad sööma head ja kasulikku toitu. Sama on ka hügeenitarbetega, kuna igal inimesel peaks olema hambaharju, deodoranti või isegi heal juhul mingit parfüümi. Siis riietega on ka, et iga inimene peaks saama käija normaalsete riietega mitte katkiste ja auguliste riietega.\nnegatiivne võib see olla, et inimesed on kergesti mõjutavad ja neile on lihtne sotsiaalmeedias midagi pähe ajada, et nad ostaks mingeid ebavajalikke tarbeid. Halb asi võib olla see, et inimene ei pruugi saada osta korralikku toitu, nii et nad peavad ostma sooduspakkumistega ja võibolla isegi aegunuid toite.\njäreldusena võin võtta, et inimesed võivad osta sotsiaalmeedia või tuttavate kaudu endale igalt poolt ebavajalikke asju ja et lihtsalt neid omada ja mitte midagi kasulikku teha nendega. Samas võob ka järeldada, et me tarbime ka häid asju nagu hea toit, riideid ja igapäeva asju.');
