INSERT INTO core.text(id, content)
VALUES ('dcfac532-46ad-4d0a-9b54-20e1c7e45651',
        'Inimeste elu muutub pidevalt mugavamaks ning paremaks, kuid ka sellega tekivad omad murekohad. Näiteks üks neist on inimeste tarbimine, mis suureneb tohutult kuna inimestel on rohkem rahalisi vahendeid. Selle halb külg on see, et inimesed ostavad rohkelt, kuid ei suuda tarbida seda kõike ning nii läheb palju asju raisku. \nInimesed ostavad endale palju asju, mida neil tegelikult vaja ei ole ning millest nad kiiruga ära tüdinevad. Näiteks ostavad inimesed väga palju odavat kiirmoodi, mida nad võibolla korra kannavad, aga siis tüdinevad ning viskavad need riided ära. Õnneks on inimesed saanud sellel teemal teadlikumaks ning hakkanud kandma rohkem taaskasutatud riideid, kuid probleem on ikka veel olemas. \nSarnane lugu on ka toiduga, mida enamus inimesed osavad suures koguses, kuid ei jõua ära tarbida enne toidu kõlblikuse lõppu. Näiteks Eestis tekib aastaga inimese kohta kesmiselt 61kg toidujäätmeid, mis on juba päris murettekitav number. sellest 61kg-st on 26kg lihtsalt riknenud toit, mis on jäänud tarbimata. Selle probleemi lahendus oleks see, et inimesed ostaksid väiksemates kogustes toitu ning käiksid lihtsalt tihedamini poes. Muidugi on ületarbimist ka teistes asjades, pesle toidu ja riiete, kuid nende kahega on see kõige probleemsem.\nInimeste tarbimisharjused on läinud tänapäeval priiskavamaks, kuid samas muutuvad inimesed ka teadlikumaks sel teemal. Kokkuvõttes on inimeste tarbismisharjumused praegu murettekitavad ning neid tuleks kindlasti muuta.');
