INSERT INTO core.text(id, content)
VALUES ('14e68f6b-f1b7-421f-bdf9-a6836dd67729',
        'Tänapäeval on inimestel tavaks tarbida tohutul hulgal riideid. Tarbimisprobleemid esinevad ka söögiga. See ilmatu suur raiskamine on keskkonnale tohutult kahjulik.\nToidu tarbimine on loomulik, aga ületarbimine mitte. Paljud inimesed ostavad külmkappi kokku suurel hulgal toiduaineid, mida nad ära tarbida ei jõua ning need muutuvad hallitanud toidujäätmeteks. Iga aasta tekib Eestis inimese kohta keskmiselt 61kg toidujäätmeid, mis on kõik riknema läinud või tarbimata jäänud toidujäätmed. Toidu raiskamist saab ära hoida näiteks kodus nädalamenüü planeerimisega, mida minagi teen, toidukordi planeerides saad osta just täpselt nii palju toitu kui sul kulub.\nHetkel on probleemiks Hiinas tohutul hulgal kiirmoe riiete tootmine. Need riided saadetakse suurte konteineritega tervesse maailma laiali. Esiteks tekidab see tohutult palju riideid prügimägedele ja teiseks reostavad suured laevad, mis kaupa maailmas laiali viivad erinevate õlidega merevett. Selle tõttu, et riideid toodetakse nii palju, satub ka taaskasutuskeskustesse tohutul hulgal Hiinas valmistatud riideid. Kiirmood on eriti populaarne noorte seas, kes tunnevad vajadust igal nädal riideid juurde osta, aga kui neid on juba paar korda kantud ei tekita need enam noortele huvi ja jäävad kapi nurka seisma. Olen ka ise kogenud erinevaid Hiina riidepoodide reklaame ja ahvatlevaid soodsaid hindu, aga kahjuks on ilusa reklaami taga tihti ebainimlikud töötingimused ja odavad materjalid. Keskkonnasäästlikum oleks osta riideid kodumaistelt firmadelt ja eelistada kvaliteeti kvantiteedile.\nJärelduseks võib öelda, et inimkonnal tuleb oma harjumusi muuta. Tuleb vähendada liigselt toidu tarbimist ja kiirmoe ostmist.');
