INSERT INTO core.text(id, content)
VALUES ('80ca6b26-3a14-4786-9081-33bf245c38f6',
        'Tänapäeval raisatakse väga palju. See on kasvav probleem ja sellele tuleks rohkem tähelepanu viia. Raiskamine on halb meie keskkonnale ning kui see sama moodi jätkub, ei lõppe see hästi. Oma harjumuste muutmine ei ole lihtne, kuid kuidas seda siiski teha?\nViimasel ajal on väga kiire mood. Moes olevad riided vahetuvad väga tihti ning tänu sellele osteakse neid väga palju. Kui need aga moest välja lähevad, hüljatakse need ja ostetakse uued. Minu arvates, tuleks poes käies mõelda rohkem sellele, mis mulle meeldib, kui sellele, mis parasjagu moes on. Kui osta riideid, enda maitse järgi, jäävad need palju kauemaks kestma. Riiete tellimine Hiinast ei ole ka kuigi hea mõte. Need võivad küll odavad olla, kuid kvaliteet on halb ning seetõttu tekkib jälle raisku. Kui on soov siiski odavaid riideid saada, on selleks hea keskkonnasõbralik võimalus käia teiseringipoodides. \nToidu raiskamine on ka suur probleem. Toit, mis rikneb või jääb üle, visatakse minema. Selleks, et vähem toitu ära visata, peaks inimene hästi tundma enda toidu harjumusi. Ma pean teadma kui palju ma süüa jaksan, et ma oskaks võtta piisvalt toitu, mis üle ei jääks. Ka liigse toidu ostmine võib probleemiks osutuda. Kui ostetakse rohkem toitu kui süüa jaksatakse, läheb see halvaks ning see tuleb ära visata. Enim on toidu raiskamine kinni inimeste harjumustes ning nende muutmine võtab aega.\nSelleks, et tarbida säästvamalt, tuleb muuta oma harjumusi. Ainult moodi järgides oma rõivaid osta ei ole mõistlik ning toitu ei tohiks osta liiga palju. Tuleks aktiivselt mõelda sellele, et kas see, mida ma teen on hea meie keskonnale. Kui on tahe muuta oma harjumusi, siis on see juba pool võitu!');
