INSERT INTO core.text(id, content)
VALUES ('ac7e3cf7-5184-4723-a10a-9fa7d9c3189e',
        'Inimeste tarbimisharjumused on inimkonnale suureks probleemiks ja see suureneb igapäevaselt. Minu arust on kõige suurem probleem asjade liigne ost. Seetõttu tekkib palju rämpsu, mida lõpuks visatakse välja või jäätakse õue. Eestlased viskavad rämpsu ära aastas ligikaudu 61kg toidujäätmeid, millest toidukadu moodustab 42% ehk 26kg. Selle vähendamiseks on paar plaani, et näidata tänapäeva noortele mis see tõeliselt tähendab ja kui palju see maailmat rikub. Tänapäeva inimestel pole õrnaaimugi kui palju isegi minimaalne reostus mõjutab üldist pilti.\nMiks on inimeste tarbimisharjumused kehvad? Sellepärast, et see reostab meie keskkonda ja hävitab meie loodust. Kõige suuremaks probleemiks on suurtööstuste ületootmisega ja inimeste liigse ostmisega või tarbimisega, mis omakorda tekkitab palju liigset rämpsu. Suurtõõstused tekkitavad liigselt riided ja jalanõud mis on tehtud materjalidest mis üle aastate ei kõdune, ega kao ära ja arvatavasti jäätakse loodusesse. Inimene on üks suur põhjus miks ültse toodetakse nii palju ja sellepärast visatakse ka ebakvaliteetsed esemed ära.\nKuidas vähendada inimeste tarbimisharjumusi? Minu arust kõige suurem probleem ongi see, et inimestel endil ei ole tagasi hoidu ehk peaks alustama ise endast ennem, kui suur tööstusdest. Kõige tähtsam oleks jälgida enda üldist tarbimist kui palju ostad ja kui palju ära viskad. Pärast seda saab juba vähendada üld tootmist ja teha maailmat puhtamaks.\nKokkuvõttes on inimeste tarbimisharjumuste parandamine nendi enda teha ehk inimesed peaksid vähem tarbima. Järeldame, et teeme kõike mida lõikudes on kirjutatud, tänusellele peaks üld tarbimine vähenema ja asjad peaksid paremaks minema. Selliste meetoditega on võimalik hoida keskkonda puhtana.');
INSERT INTO core.text_property(text_id, property_name, property_value)
