INSERT INTO core.text(id, content)
VALUES ('466c95e9-b2f7-4a6b-a2b9-a90b2e4ca64c',
        'Tänapäeval on suureks probleemiks see, et inimesed raiskavad asju nagu näiteks toit ja riided. Minu arvates ei ole see hea, kuigi ka mina olen visanud ära toitu, kui see on näiteks üks päev kuupäeva ületanud.\nEt tarbimisharjumusi muuta peaks rääkima eriti just noortele taaskasutamisest ja kodumaisete toodete tarbimisest. Muidugi tuleks nendest teemadest rääkida ka täiskasvanutele, aga ma arvan, et täiskasvanud on juba veidi targemad ja mõtlevad sellele juba ise. Mulle jäi silma esimesest alustekstist ka lause:“Võtame toitu iseenesestmõistetavana. Meile tundub, et toitu on veel ja see ei saa otsa.“ Ma nõustun selle lausega, sest ka mulle tundub nii igapäeva elus. Ma ei mõtle sellele, et äkki mingil hetkel toitu enam ei ole. Aga tegelikult võiks mõelda, mitte võibolla küll nii, et äkki toitu enam pole, aga nii, et kuidas seda võimalikult vähe raisku lasta ja rohkem hinnata.\nMina saan oma tarbimisharjumuste muutmiseks toidu koha pealt, süüa ära ka näiteks tänase ja isegi paar päeva üle läinud kuupäevaga toidu ja, et mitte näiteks õhtusööki ära visata, saan ma seda süüa järgmisel päeval. Riiete koha pealt, kui mul on riided väikseks jäänud ja nad pole katkised, siis ma viin need koos oma emaga taaskasutuspoodi. Aga ma raiskan võibolla selle pealt, et ma ostan ka pidevalt uusi asju ega käi ise taaskasutuspoodidest ostmas väga tihti. Teises alustekstis oli kirjas, et ei peaks tellima Hiina veebipoodidest asju ja ei peaks minema kaasa sooduskampaaniatega. Ma nõustun ka sellega, sest inimesed ostavad siis odava hinna eest palju asju ja kasutavad neid võibolla ainult üks kord ja siis viskavad ära. Kuigi jällegi ka mina olen läinud sooduskampaaniatega kaasa.\nKokkuvõtteks võiks öelda, et inimesed raiskavad küllaltki palju kaasaarvatud ka mina. Aga on palju erinevaid võimalusi, kuidas oma tarbimisharjumusi ümber muuta.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('466c95e9-b2f7-4a6b-a2b9-a90b2e4ca64c', 'title', 'Kuidas muuta oma tarbimisharjumusi?');
