INSERT INTO core.text(id, content)
VALUES ('7f9e790f-7437-4fa0-b7af-723adc95232c',
        'Lääne maailmas või nii öelda arenenud maailma ületarbimine on kohutav. Inimesed ostvad asju mida kantakse või kasutatakse vaid mõned korrad, kui sedagi. See on hävitav nii loodusele, kust kõik need resurusid tulevad, ning pole eetiline alarahastatud tööjõule, kes neid tooteid kokku panevad.\nArenenud maailmas on tekkinud väga suur probleem ja sellele ei ole lihtsat lahendust. Hiina või mõne muu riigi veebipoed, kust saab osta väga odava hinna eest, näiliselt sama hea kvaliteediga tooteid, nagu Euroopa või USA pooditest. See on pannud inimesi massiliselt ostma asju mida, neil ei ole vaja. Tellitakse suur hulk tooteid kohale mille eest maksti kokku võibolla mõni kümmend eurot ja ilmselt saatmis kulu polnud ning alles kui toode on kohale jõudnud hakkab inimene päriselt mõtlema mida ta tellis või kas tõesti tal seda natukenegi vaja on.\nInimesi tuleks suunata mõtlema natukene kaugemale, kui enda jalge esine ja koputada natukene nende südametunnistuse peale, et nad mõtleks ennem toote tellimist, kas neil on seda vaja ja mis saab sellest, kui neil enam ei ole seda vaja. Võimalus on, et natukene rohkem mõeldes jääb tellimus tegemata resursid kulutama ning kütus mis on vaja selle kohaletoimetamiseks tarbimata. Seda vaid juhul, kui piisavalt inimesi panna seda tegema.\nSäästlikum tarbimine on vajalik jätkusuutliku elu elamiseks maal. Ületarbimisele peaks juhtima tähelepanu riik ning suunama inimesi mõtlema rohkem ennem ostu sooritamist. See on vajalik, et oleks ressursse ka järgmisele põlvkonale.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('7f9e790f-7437-4fa0-b7af-723adc95232c', 'title', '„Ületarbimine“');
