INSERT INTO core.text(id, content)
VALUES ('c9eb0196-c252-436e-b489-55e26e159ae5',
        'Toit ja riided on inimestele igapäevaeluks vajalikud asjad, kuid kahjuks paljud inimesed ei mõista, kui palju kulub ressursse nende toodete tootmisel ning ei märgata, et paljudele on söök ja riided privileeg. Tihti ostavad inimesed suurtes kogustes endale asju kokku, eriti riideid: sellega toetatakse kiirmoodi ning raisatakse ka oma enda raha.\nViimastel aastatel on eriti olnud näha, kui palju inimesed ostavad endale suurtes kogustes, odava hinna eest, halva kvaliteediga riideid. Need riided on tihti toodetud halbade töötingimustega Hiina tehastes, kus töötajate palk on üliväike, kuigi tööaeg on pikk. Sageli ei osteta neid riideid isegi sellepärast, et need inimesele endale meeldiks, vaid kuna hetkel on need moes. Tihti ostavad inimesed endale koju ka liiga palju toitu, mida ei jõuta ära tarbida. Seepärast läheb raisku hulga toiduaineid. Eesti kodumajapidamistes tekib aastas keskmiselt 61 kg toidujäätmeid iga inimese kohta. Kõige sellega läheb raisku rohkelt erinevaid ressursse: energiat, tööjõudu, maad ja vett. \nKokkuvõteks ei märka inimesed enda tarbimisharjumusi ning paljud ostavad endale suurtes kogustes ebavajalikke asju (milleks ei ole ainult rõivad ning söök). Sellega kaasneb tohutult suur ressursside raiskamine. Ka koolis peaks õpilastele rääkima, miks selline tootmine, ostmine ja omamine on halb ning kuidas see mõjutab keskkonda ja inimesi ning mis on teised, paremad variandid.');
