INSERT INTO core.text(id, content)
VALUES ('f034deb9-1470-4252-bfa3-74b1cd981529',
        'Paljud inimesed ostavad kokku asju liiga palju või siis asju mida neil vaja ei lähe. Toitu teevad paljud inimesed rohkem kui nad ära jõuavad süüa. Paljud inimesed kes viskavad ära väikse toidu koguse arvavad, et nad ei mõjuta sellega palju, aga see on vale. Paljud inimesed tellivad ka Hiinast odavalt asju, mis ei pruugi neile meeldida. Paljud annavad need riided teistele või siis viskavad lihtsalt ära. Eesti rahvas võiks osta asju mis on toodetud Eestis ja pigem vähem kui rohkem.\nKodu majapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61 kg , millest toidu kadu moodustab 42% ehk 26 kg. toidukadu ehk raisatud toit on toit või toidu aine, mis mingil põhjusel (riknenud või kasutustähtaja ületanud toit, söömisel ülejäänud toit vms) jääb tarbimata ja visatakse toidu jäätmena ära. Inimesed saaksid toidukao vähendamiseks teha järgmisi asju: käia iga päev või ülepäeva poes ja osta ainult vajalikke asju vajalikus koguses, teha vanast toidus mingi uus nt kartulist teed kartulisalati, mitte teha uut toitu ennem kui vana on otsas või siis halvaks läinud.\nMoemaailmas on ka palju raiskamist, moedisaineri Eve Hansoni aravtes peaksid kõik vaatama oma tarbimisharjumused üle vaatama ning eelistama kvaliteeti üle kvantiteedi. Eve Hanson arvab, et koolid peaksid tegema õpilastele ekskursioone taaskasutuspoodide lattu, et näidata noortele milline raiskamine maailmas toimub. Riideid ostes sa pead mõtlema hoolikalt kas sulle ikka sobib toote mugavus ja välimus. Kõik riided mis sa ostad ei pea olema brändi riided, ostes endale tavalisi riideid saad sa säästa palju raha. Kui sa lähed riideid ostma, siis enne ostu tee endale nimekiri mida sul vaja läheb ja kui palju, sa saad võtta need asjad mis sul vaja on ja on väiksem võimalus langeda reklaamide ohvriks.\nKäies nii toidu- ja riidepoodides mõtle ennem mis sul vaja on, et sa ei ostaks liiga palju asju mida sul hiljem vaja ei lähe ja ära viskad. Kõige parem on osta asju kohalikkudest poodidest, nii sa säästad aega ning saad oma silmaga näha toote kvaliteeti. Tarbimisharjumusi ei saa muuta üleöö, aga inimesed võiksid seda vähendada.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('f034deb9-1470-4252-bfa3-74b1cd981529', 'title', 'Tarbimisharjumused toidu ja moemaailmas');
