INSERT INTO core.text(id, content)
VALUES ('0b6822ae-2fe3-424c-814b-47741e23e0ae',
        'Inimeste tarbimisharjumused on metsikud. Ostetakse toitu, mis hiljem ära visatakse, sest see tundub nii iseenesestmõistetav. Jälgitakse kiirmoodi, mille käigus ostetakse endal metsikus koguses riideid, millega hiljem ei osata midagi teha.\nLähme ajast veidi tagasi ja mõtleme kunagi eksisteerinud inimese peale. See sama inimene kellest me arenenud oleme. Jah, see sama, kellel puudusid jalanõud, kes kasutas ära kogu püütud saagist. Püütud saagist ei raisatud midagi, looma sisemus läks söögiks, kondid koertele ja nahk soojade rõivaste valmistamisele.\nKuhu oleme hetkel jõudnud? Toidu on inimestele nii iseenesestmõistetav, sest seda pole harjutud ise hankima. Minnakse  poodi ja ostetakse mida vaja. Kui toit tundub iseenesestmõistetav, kiputakse seda ka kergekäeliselt ära viskama. Tulemusena tekivad toidujäätmed, mida iga eestlane aastas umbes 61kg tekitab. Sellest 61kg-ist moodustab 26kg touidukadu ehk raisatud toit või toiduaine.\nNing teiseks teemaks on kiirmood, millega enamus inimesed ka kaasa lähevad. Ostetakse kapp täis riideid mida tegelikult ei vajata. Need samad riided, mis hiljem lähevad kas äraandmisele, mahamüümisele või lihtsalt minemaviskamisele. Hetkel olemasolevate riietega saaks riietada mitu järgmist põlvkonda. Olen nõus Eve Hansoni mõttega, et tõesti tuleks noortele teha ringkäke taaskasutuspoodide ladudes, et nad mõistaksid palju tegelikult rõivaid üle jääb.\nKokkuvõtteks tarbitakse toitu liiga palju, sest see tundub inimestele  iseenesestmõistetav. Kuna see on iseenesestmõistetav, kiputakse seda  kergekäelislet ära viskama. Kiirmoe mõjul ostetakse kapp riideid täis, mis lõpuks antakse ära, müüakse maha või visatakse lihtsalt minema.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('0b6822ae-2fe3-424c-814b-47741e23e0ae', 'title', 'Miks nii palju?');
