INSERT INTO core.text(id, content)
VALUES ('0be56cd1-73ee-4c9e-ab35-35730187c420',
        'Inimeste tarbimisharjumused muutuvad halvemaks iga aasta. Inimesed ei tarbi enam asju säästvalt ja kokkuhoidlikult. Raiskamist on veest ja toidust kuni maa ressurssideni välja. Kõik see ei ole mitte kahjulik meie rahakotile, vaid ka loodusele ja maale endale.\nPräegu kaks kõige enim mainitumat probleemi on toidukadu ja veereostamine. Nagu tarbitoitutargalt.ee lehel mainiti, et Eesti inimese kohta tekib aastas toidujäätmete pealt 42% toidukadu ehk raisatud toitu. Inimesed peavad hakkama töötama üheskoos loodusega, kuna peaaegu kõik toidud pakendatakse ja kui ilusti ei käida pakendiga ümber, siis se satub veekogusse või loodusesse. Talunikud saaksid nt ülejäänud maisi, vilja või oma enda ülejäänud toitu viia sigadele sõõtadele. \nVeereostamine tekibki põhiliselt halvasti ümber käidud pakendite pärast. Kui vesi on reostanud, siis tähendab ka see seda, et kõik, mis vees elab on reostanud keskkonnas ja võivad surra selle tagajärjel nt pakendeid süües või kinni jäädes. Ja see plast võib jõuda meie oma endide toidu laudadele tagasi, kuna on juba leitud, et reostanud veedes elavate kalade liha sisaldab mikroplasti.\nKokkuvõtteks võin õelda, et üksinda suurt muutust ei tee, aga kui kõik koos töötada looduse ja endi tuleviku nimel, saab anda parema elu meile endile, loomadele-ja  edastistele põlvkondadele. Kuna ilma toidu ja veeta me ellu ei jää.');
INSERT INTO core.text_property(text_id, property_name, property_value)
