INSERT INTO core.text(id, content)
VALUES ('a81adf8b-d120-44b3-b78d-d3cbf45e229a',
        'Eestis üks suurimaks probleemiks on liigtarbimine ehk inimesed ostavad kokku palju asju näiteks sööki ja riideid mis on peamine mida tarbitakse suures koguses, aga ei jõuta kanda või süüa.\nSööki peamiselt visatakse prügikasti kuna tihtipeale ei jõuta sööki ära süüa või siis lihtsalt toit ei maitsenud. See, et toitu niimoodi ära vistakse on suur probleem Eestis, nagu ka tekstis mainitud visatakse toitu ära aastas keskmiselt 61 kg mis on  palju, aga, et see söök viia näiteks kompostikasti või teha endale see kast selle peale ei tule keegi mis on tõttöelda kurb. Mul endal on kodus kompostikast kuhu ma siis jäägid viin vastavalt vajadusele.\nPaljusid riideid saab taaskasutuspoodidest, aga tihtipeale ei kasutata seda võimalust kuna ollakse harjunud uute riietega ja nüüd kui antakse taaskasutuspoest ostetud riide ese siis mõeldakse „Kui vastik mina küll seda selga ei pane“ ning seetõttu ostetakse uusi ja vanad vistakse minema, selle asemel, et need siis taaskasutuspoodi viia. Tekstis on ka mainitud kuidas ostetakse riideid Hiinakubamajadest ja kuidas need ikkagist lõpetavad taaskastuspoe laos. Olen ise ka tellinud Hiinastveebilehtedel ja selleks on Shein, kust tellin mis on väga populaarne koht kust tellitakse.\nJärelduseks võin ma nii palju öelda, et mitte keegi teine vaid sina ise saad muuta seda, et me ei raiska sööki ega osta koguaeg uhiuusi riideid ja ostadki ainult seda mida sul tõesti vaja läheb.');
