INSERT INTO core.text(id, content)
VALUES ('80046c89-5792-4325-9268-4488c91136ab',
        'Üleüldse kõikidel inimestel, mitte ainult eestlastel on tekinud aastatega märgatavalt suurem probleem enda raha raiskamisega. Meie tarbimisharjumused on aastatega halvemaks läinud.  Põhjuseks võib olla masstoodand mis ei toimu ainult Eestis vaid üle maailmselt.\nPikema aja jooksul on tulnud välja, et meie tarbimisharjumused, kus me kasutame enda raha ja mille peale on aastatega ainult kehvemaks läinud ja kui palju me päriselt raha kulutame asjadele, mida meil tarvis pole. Näiteks ostetaks endale riideid juurde kuigi kodus on kapp täis riietest või tellitakse endale juurde. Minnakse toidupoodi ostma spetsiifilist toitainet ja komistatakse hoopis teiste toitainete otsa mida inimesel ei ole vaja ja kasutatakse enda raha millegile mida tõesti polnud vaja. Ei kasutata kodus ära toitu ja hiljem see enam ei kõlba. See tekitab toidukadu mis on ligikaudu 46% Eestis.\nArvatakse, et ostes endale uusi riideid tuleks eelistada kvaliteeti üle kvantiteetide ja mina nõustun sellega. Riie võib tõesti kallis olla aga sellegi poolest on see taaskasutatud.\nInimestel on suur probleem enda raha raiskamisega, kui neil seda palju on. Ei mõelda just kõige rohkem looduse peale ja mis kõike me endast maha ei jätaks. Võiks hakata rohkem vaatama mida me toidupoest ostame ja kui palju. Viimaseks, terve tuba ei pea olema riietega täidetud. Paarist asjast minu arust juba piisab.');
