INSERT INTO core.text(id, content)
VALUES ('7ab1131a-f3f5-4cdd-8b41-41b57c1e98cf',
        'Tarbimisharjumused on iga inimese isiklikud harjumused. Iga inimene saab oma tarbimist muuta, seda siis paremaks või halvemaks. Inimeste tarbimisharjumused on küll väga erinevad, aga kõik võiksid proovida neid parandada. Tarbimine ei tohiks olla raiskamine, kuid seda tehakse palju.\nTarbimisharjumuste probleem on suur. Suur osa inimestest tegelikult mingil ajajooksul raiskab. See on okei, kui sellest ei saa igapäeva tegevus. Raisatakse riideid, toitu ja muud sellist. Tegelikult inimesed võiksid seda probleemi proovida lahendada. Näiteks vähendaksid tarbimist, ei ostaks igasuguseid asju, mida nad ei kasuta,ei ostaks hiina interneti poodidest jama, vaid ostaks oma kodumaalt mingi kvaliteetsema asja, siis oleks ju endal ka parem tunne. Tarbimisharjumuste probleemi ei ole võimalik lahendada üleöö, aga kui inimesed prooviksid, oleks seda võimalik lahendada pikema aja jooksul.\nInimesed on hakanud liiga palju toitu raiskama. See on küll inimeste enda valik, mida nad oma raha eest teevad, aga see kahjustab ka loodust. Kõik võiksid hakata jälgima oma tarbimist, sest sa teeksid sellega iseendale kasu. \nRiiete osas võiksid hakata kõik jälgima, et mida sul päriselt vaja on, mitte osta igasugust jama kokku Hiinast ja siis ära visata. See on ka raiskamine. Probleemi saaks lahendada sellega, kui ostaksid Hiina jama asemel midagi kvaliteetsemat. Kuna kui ostad midagi kvaliteetsemat, tähendab see ka seda, et see riie püsib kauem. Ehk sa saad seda kauem kanda ja sul on endal ka mugavam.\nKokkuvõtteks võiksid inimesed oma tarbimist jälgida ja mitte raisata nii palju. See teeks meile kõigile endile head. Kõik võiksid toidu raiskamist kui ka riiete raiskamist vähendada. Ja mitte ainult nende kahe raiskamist, vaid ka kõige osas võiksid natuke jälgida oma tarbmimist.');
