INSERT INTO core.text(id, content)
VALUES ('3fad601d-789d-44f1-9b32-2f637982e05f',
        'Elades ajastul, mil tarbimine ja tootmine on esmane, on väga suureks probleemiks raisakmine ja keskkonna saastamine. Kuidas olukorda päästa?\nTänapäeva ühiskond sageli ei mõtle millise töö ja vaevaga on nendeni jõudnud vajatud toode ning selle tõttu on neil tihti kombeks tooteid ära visata, lõhkuda, raisata ja nii edasi. See tuleneb pidevast uuest kaubast, näiteks on kellegi ostetud saapad moest läinud, näokreem on üle kasutustähtaja läinud, sest oli tahe uus ja trendikam osta, vorst on külmkapis hallitama hakanud, sest selle söömiseks polnud isu.\nKosmeetikatoodete üleostmine on ülemaailmne probleem. Olen isegi näiteks poest läbi käies ostnud uue ripsmetuši. Tagajärjeks kuivab eelmine täiesti kasutuskõlblik ripsmetušš lihtsalt ära ning olen oma raha raisanud. See probleem on väga levinud, kuid sel aastal levis internetis trend mitte osta uut toodet enne eelmise lõpunikasutamist. Ma arvan, et sellised ideed säästavad tootmisenergiat, ressursse, tööjõudu ning ka tarbijate endi raha.\nÜheks maailma suurimaks raiskamisprobleemiks on kujunenud toidu raiskamine. Kodus alati õpetatud, et toidu äraviskamine on häbematu, sest selle eest on makstud raha ning maailmas on inimesi, kes ei saagi igapäev süüa. Sellist raiskamist peatada on küll raske, aga väga vajalik.\nEriti Ameerika Ühendriikides on levinud toodete ribadeks kasutamine. On paljusid tõsielusaateid inimestest, kes närivad mitu päeva sama närimiskummi, jagavad terve perega ühte vannivett ja nii edasi. Selline harjumus on väga ebahügieeniline ning pole teiste inimestega lihtsalt arvestav.\nTarbimisharjumused ning nende mõju keskkonnale peaks olema arutatav teema igapäevaselt, et tulevikus oleks probleem kergendatud. Selleks peaks iga inimese vaeva nägema.');
INSERT INTO core.text_property(text_id, property_name, property_value)
