INSERT INTO core.text(id, content)
VALUES ('1c53c9ee-a43b-47d2-9b8a-e186f68cd8e2',
        'Tänapäeval pole ületarbimine ja raiskamine uus asi. Tihtipeale tarbitakse rohkem, kui on vaja ning kui tuleb arusaam, et nende hulkostetul asjal on kasutus võimatu või raske, visatakse need mõtlemata ära. Näiteks hiinast tellitud riided, mille kvaliteet on halb. Selline asi peab lõppema. \nPaljud jõukamad ja keskklassis inimesed on teinud endale normaalsuseks visata ära toitu, mida on rohkem kui üks portsjon. Tavaliselt ei taheta süüa ühte toitu mitu päeva järjest ning otsustatakse teha uus toit ning vana visatakse sõna otseses mõttes prügikasti. Paljud inimesed teevad seda mõtlemata, mis mõju sellel meie ühiskonnale ja planeedile on.  Inimesed mõtlevad, et ei ole hullu kui visatakse nende arust natuke toitu ära, kuid iga Eesti inimese kohta on aastas keskmiselt 61 kg  toidujäätmeid, millest toidukadu moodustab 42% ehk 26 kg.\nAinuüksi pole probleem vaid toidu ületarbimises vaid ka kiirmoe hullusega. Ostetakse riideid ainult moe pärast ja ei mõelda, kas ka peale moodi kannaks ta selliseid asju. Tuleks endalt küsida, kas me ostame endale asju sellepärast, et meil on vaja ja meeldivad need või ostame me asju vaid moe pärast.  Noored, kes moeröögatuste ohvriks satuvad, ei saa ise arugi, milline raiskamine tegelikult toimub ja kui palju nad ise sellele kaasa aitavad. Me peaksime normaliseerima enda jaoks ka taaskasutuspoed, kus võib olla ka parem kvaliteet kui Hiina veebipoodides.\nKokkuvõtteks tuleks inimesi panna mõtlema ka oma maailmale. Inimestele tuleks panna südamele ka meie ühiskond. Pole vaja tellida asju mõtlemata, ning tuleks mõelda sellele, mida tehakse asjadega, kui neid enam vaja pole. On suur võimus, et rohkem mõeldes jääb palju asju tellimata. Lisaks meie rahale, jääb ka alles kütus, mida on vaja transportimiseks. Sellise mõtteviisiga jääb meist maha puhtam maailm ja parem südametunnistus. Peale meid on ka põlvkonnad, kes tänavad meid, kui me rohkem mõtleks.');
