INSERT INTO core.text(id, content)
VALUES ('612e2056-e14e-42f7-9fcd-49f1b65d0d05',
        'Inimeste tarbimisharjumused on väga halvaks läinud kuna raisatakse ülemeelikult iga aasta toitu ja ka on tekkinud probleem selles, et inimesed ostavad väga odavalt tehtud riideid mis ei ole kvaliteetsed ja võivad ka oma enda kehale ohuks olla. \n Inimestele on külge jäänud toiduraskamine mille tagajärjel igas majapidamises ühe inimese kohta tekib 61kg toidujäätmeid. On olemas inimesi kes ostavad endale liiga palju toitu ja pärast ei oska enam sellega midagi teha kui üle jääb, sellises olukorras oleks kõige mõistlikum lihtsalt järgmine kord vähem toitu osta kuna niimodi säästavad omaenda raha kui ka muid tähtsaid resursse nagu näiteks maad, vett, energiat ja ka tööjõudu.\nInimestele on ka külge jäänud odavate riiete tellimine Hiinast kuna kui nähtakse hinda, arvatakse, et see on väge hea pakkumine kuigi see tegelikuses ei ole. Samasuguseid riideid nagu näiteks Ameerikas tehakse Hiinas vähemalt 4korda väiksema kuluga kuna nende tõõjõu palk on niivõrd väike Hiina tehastes ja kasutatakse ka naftat, et neid riideid teha. Pigem telli kuskilt mujalt nagu näiteks Ameerikast kuna seal tehakse kvaltiteetsemalt aga Hiinas kõige tähtsam on see, et neil oleks kvantiteed mitte kvaliteed. \nInimestel oleks vaja enda tarbimisharjumusi parandada.  Esiteks oleks vaja inimestel vähem toitu raisata kuna selle toidu tegemiseks kulub väga palju resursse ning teiseks ei tohi inimesed uksuda seda mida Hiina kaubamajad neile räägivad.');
INSERT INTO core.text_property(text_id, property_name, property_value)
