INSERT INTO core.text(id, content)
VALUES ('d9e3d039-cd1f-4a57-8f7e-140c3ae5bdb0',
        'Inimeste tarbimisharjumused on erinevad. Mõned inimesed on selle seisuga tekkinud probleeme. Tarbimisharjumuste probleemid ei ole ainult üht ega kaht, vaid on väga palju rohkem, kui inimesed olekid arvanud. See on tekkinud sõltuvuse, et inimestel on tehtud keeruliseks sellest lahti saamine.\nToidu raiskamine on üks inimeste tarbimisharjumuste probleemiks. See on probleemiks, sest see rikub keskkonda ja on raisatud suures koguses raha. On olemas vaeseid inimesi, kes elavad tänaval, ei ole raha toidu ega muude tarbede jaoks. Toidu raiskamise tõttu inimesed on muutunud vaesemaks, sest toit maksab palju raha. Kahjuks on olemas ka inimesi, kes raiskavad toitu, sest nad tahaksid olla populaarsed sotsiaalmeedias.\nJärgmiseks tarbimisharjumuseks on liigne rõivade ostmine. Rõivaid võib osta,kui on vajalikud, aga sellest tekib probleem siis, kui ostetakse liiga palju. Osad rõivad maksavad üle saja või isegi tuhande euro, mis olenevad toode firmast ning materjalist, millest riided tehtud on. Paljud noored võivad varastada toodeid või osta raha eest, mis pole nende oma. Kui inimestel on riided majas, mis nendel ei sobi, siis viiakse taaskasutusse. Osad inimesed kasutavad riided, mis võivad tekitada kahju kehale.\nKokkuvõttes on harjumused mõned probleeme tekkinud. Kahjuks need ei ole ainsad harjumused, sest võivad tekkida need tarbimisharjumused, mis on väga survamad ning teevad kahju. See pole ainult inimesed, kes tarbivad vaid neid inimesi, vaid neid inimesi, kes saavad kannatada teiste tarbimisharjumuste tõttu.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('d9e3d039-cd1f-4a57-8f7e-140c3ae5bdb0', 'title', 'Inimeste tarbimusharjumused');
