INSERT INTO core.text(id, content)
VALUES ('373a6944-fdba-4145-842a-1ab9453d938e',
        'Tänapäeval ei leia inimesed enam aega, et mõelda, mis meist päriselt edasi saab, kui jätkame samas vaimus edasi oma keskkonna ja toidu kohtlemisega. Me ostame kokku mõttetult palju sööki, mida me ei jõua ära tarbida isegi siis, kui me väga tahame. Samuti käib jutt ka esemete kohta, mida me kokku ostame, aga kasutust neile tegelikult ei leia.\nMeie põhiprobleemid on liigne toidu kokkuost ja ebavajalike esemete soetamine, millega tahame mugavust saada. Kui toimuvad sünnipäevad või muud üritused, siis ostetakse kokku ladudes toitu, kuid pärast tuleb välja, et seda ei tarbita ära ja see läheb lihtsalt prügikasti, mis tähendab järjekordset ressursside ja toidu raiskamist. Tellime endale Hiinast huvitavaid abilisi, mis peaks meie elu tegema mugavamaks, aga me ei mõtle, kas see oleks meile endile üldse kasulik ja kas meil tõesti on midagi puudu.\nSelleks, et ei tekiks ülaltoodud olukordi, võiksime me rohkem vaeva näha enda vajaduste tundmisega ja enne üritusele toidu kokkuostmist, peaksime tegema kindlaid nimekirju osalejatest ja nende soovidest  või  ülejäänud toidu teistele koju kaasa andma, mitte ära viskama. Enne Hiina abilise tellimist võiksime samuti mõelda, kas tasub raha raisata ja kas mugavus on see ,mis meile kõige paremini mõjub.\nKui mõtleksime enne tegutsemist, looksime endale juba ise mugava keskkonna.');
