INSERT INTO core.text(id, content)
VALUES ('6c8101ad-f0f9-4231-948f-677280e4a136',
        'Tarbimine on inimese igapäevaelu lahutamatu osa. Tarbimisega kaasneb aga suur keskkonna mõju, seda just kasutuskõlblike tarbeesemete ja toidu ära viskamise näol. Selline tarbimine on kinni inimeste harjumustes, kuid see vajab muutust.\nAlates tööstusrevolutsioonist on kasvanud inimeste tarbimine ja tarbimisvajadused. Seda eeskätt võimaluste rohkenemisest, sest kes ei ostaks endale kohe uut asja, kui vana on juba igavaks muutunud. Kahe sajandi jooksul on inimeste tarbimine järjest suurenenud, seoses millega on tõusnud ka tootmine, mis omakorda omab üha suuremat mõju ümbritsevale keskkonnale.\nPõhiliste tarbimisharjumustena võib väja tuua näiteks uute riiete ostmise, kuigi vanad riided on veel kantavad ja heas seisukorras, üldiste tarbeesemete, nagu näiteks mööbli, pidev välja vahetamine ja toidu ostmine suuremas koguses, kui tegelikult tarbitakse. Näiteks tekib iga Eesti inimese kohta aastas keskmiselt 61 kg toidujäätmeid, millest toidukao osakaal on 42% ehk 26 kg. Näitena saab veel tuua taaskasutuspoodides toimuva, kus toodud riiete hunnikud on meeletult suured ning toodud riided täiesti kantavad. Selline käitumine iseloomustab tänapäevast tarbimist väga ilmekalt. \nTarbimisharjumusi tuleb paratamatult muuta, sest need omavad väga suurt negatiivset mõju keskkonnale, eelkõige läbi keskkondlikult tähtsate ressursside hooletu kasutamise. Tuleb liikuda ringmajanduse suunas.\nTarbimine on inimese igapäevaelu osa. See on kujunenud nii kahe sajandi vältel alates tööstusrevolutsioonist. Tarbimise suurenemine on toonud endaga kaasa liigse tarbimise, mille käigus tekib jääk, mis visatakse ära. See aga omab suurt mõju ümbritsevale keskkonnale ja selle ressurssidele. Tarbimisharjumusi tuleb muuta liikudes üldise ringmajanduse suunas.');
