INSERT INTO core.text(id, content)
VALUES ('ad98153e-b197-427c-81c7-3210bca8efbb',
        'Inimeste mugav eluviis on toonud palju head, kui ka halba. Uued riided, poes olev toit ja kõik muu mida inimene vajab või soovib. Ületarbimine on suur probleem üle terve maailma. Kahjuks on kohti maailmas kui paljudel on puudused ja kohti kus palju raisatakse.\nPaljudel inimestel on rahalisi probleeme, mis kahjuks võib jätta inimesi kas koduta või söögita. Kuigi inimesed kodudes, väljas süües ja toidu halvaks laskmisega, raiskavad inimesed mitu kilogrammi toitu aastas. Poodides ostetakse tooteid paju ka pakendi voi värvuse pärast, aga ei mõelda kas mul läheb seda ikka vaja? Tänu sellele on poes hästi värviline ja tooted tehakse nimelt ilusate pakenditega, mis tõmbab inimese tähelepanu.\nKahjuks veel üheks suureks mureks on riiete raiskamine. Eriti veel tänapäeval tellitakse hästi palju riideid, mida pole vaja aga soovitakse. Ning kahjuks tellitakse palju sootsatest firmadest. Söötsad riided on paljudel inimeste rahakottidele lihtsam, aga sootsamad riided ei ole kvaliteetsed ja lähvad kiiremini katki. Suur osa riiete raiskamiseks on noorte riiete trendi kiire muutumine. Tänapäeval on hakkanud noored arvama, et nad peavad olema trendidega kaasas. Kuid trendid, eriti veel riiete trendid, muutuvad koguaeg. Mis toob kaasa rohkem riietele kulutamist ja riiete ära viskamist.\nKokkuvõtteks tahaksin ma öelda, et inimesed peavad läbimõtlema mida neil vaja on, kas nad saavad seda toodet taaskasututada ja mõelda mida halba teeb raiskamine loodusele.');
