INSERT INTO core.text(id, content)
VALUES ('88ee3e3b-2619-4bd5-be01-85a3639e41c7',
        'Tänapäeval on kaupade valik lai ja tooted kõigile lihtsasti kättesaadavad. Enamus meist vaatab enne toote kvaliteedi kontrollimist hoopis selle hinda ja teeb oma ostud selle alusel. Eelistades kvantiteeti kvaliteedile annavad inimesed aluse järjest kasvavatele probleemidele meie ühiskonnas. \nInimestele võib tulla suureks üllatuseks, kuivõrd palju ressursse läheb raisku ka vähese toidu ära viskamise tõttu. Üldiselt mõtleb rahvas vaid pealiskaudsele raiskamisele toiduga, ollakse teadlikud vaid toiduainete raiskamisest. Tegelikult kulutavad inimesed lisaks puhtalt toidule ka kogu maad, vett, energiat ja tööjõudu, mis selle toidu valmistamise või kasvatamise jaoks on vaja läinud. \nRiiete, aksessuaaride ning muude ilu- ja moekaupadega on olukord hullem. Rahva seas on populaarsust võitnud Hiina kaubamärgid, mille eesmärk on toota võimalikult odavaid tooteid, pööramata tähelepanu nende halvale kvaliteedile. Odav kaup tõmbab ligi palju kliente, kuid tihti ei pea tellitud riided vastu üle kahe korra kandmist. Selle tõttu on taaskasutuspoodides hunnikute viisi riideid, millest oleks võinud saada kvaliteet kaup, mis oleks inimesel mitmeks aastaks olemas. \nTõsine probleem ja suur faktor ületarbimises on emotsiooniostud. Emotsiooniostud tehakse mõtlemata ning ostetakse kokku tooteid, mida inimene tegelikult ei vaja. Enamus emotsioonioste läheb raisku, kui inimene saab aru, et tegelikult ei oleks olund mõistlik oma raha kulutada ebavajalikele asjadele. Paarkümmend aastat tagasi ei oleks inimesed sellist probleemi osanud ette oodatagi. \nRahvas peab hakkama rohkem mõtlema oma ostudele ning sellele, kas need on  vajalikud. Inimesi peaks viima taaskasutuskeskustesse ja näitama neile, kui suure probleemi oleme endale tekitanud. Loomulikult ei saa raiskamist täielikult peatada, kuid võimalik on panna inimesed nägema, kuidas nad ise meie keskkonda ja ressursse mõjutavad.');
INSERT INTO core.text_property(text_id, property_name, property_value)
