INSERT INTO core.text(id, content)
VALUES ('71ad19e7-6dca-406f-95ba-f3d72234d786',
        'Tänapäeva elu võib nii mõnegi jaoks iga päevaga aina keerulisemaks ja raskemaks muutuda. Inimesed ei taju enam piire ja ületavad igasugused käitusmisnormid. Kliimasoojenemine ja igasugused muud probleemid jõuavad meie käitumise pärast iga päevaga aina lähedamale. Inimestel on ununenud, kuidas peab vaeva nägema ilusa elu nimel ja kuidas kõik hea ei tule soovides kätte. Miks on meil sellised probleemid ja miks neist nii raske välja saada on\nArvan, et üks suurimatest mõjutusvahenditeks on populaarseks saanud tehisintellekt. See võib pealt vaadates äge olla, kuid keegi ei tea milliseid probleeme see võib tekitada ühiskonnale. Areng on juba nii suur, et töökohad kaovad ja elu muutub aina lihtsamaks. Raha ju ei kuku lihtsalt puu otsast alla, selleks peab iga inimene vaeva nägema. Iga liigutus on väärt kellegi higi ja panust. \nOn inimesi, kes raiskavad toitu, sest nad saavad seda endale lubada. On inimesi, kes peavad istuma näljas, tapma loomi või ohverdama oma elu selleks, et nende lapsed saaksid süüa jne. Need inimesed, kes loobivad ära toitu ja ei hinda selle väärtust on häbematud. Lisaks peale asjade väärtustamise peaks ka mõtlema sellele, et meie oleme need kes hoiavad planeeti veel elus, iga sellise käitumise tagajärg võib lõppeda hukkavalt meile kõigile.\nNii on ka masstootmisega. Tänase päevani ei tea keegi suurte firmade Shein, Temu jne, kuidas nad saavad nii odavalt toota ja edasi müüa kaupa. Muidugi kõik ka teavad, et see saast mis nendelt firmadelt tuleb laguneb kiiresti ära sest nad toodavad oma kaupa naftas või teistest kahtlastest kemikaalidest. See ainult ei saasta loodust vaid on ka inimeste tervisele ohtlik. Mille jaoks on vaja osta odavalt prahti kui saaks kallima eest palju parema kvalitediga toote, mis säästab ka sind, meie planeeti kui ka inimeste tervist.\nKokkuvõtteks nagu Eve Hanson arvas, tuleks kõikidel inimestel vaadata üle oma isiklikud tarbimisharjumused ja eelistada kvaliteeti kvantiteedile. Tuleks vähem kasutada tehisintellekti ja hakata rohkem ise tööd tegema, et ei tekiks ülearust prahi tootmist mis pole kellelegi eluks vajalik. Mõistus võiks koju tulla ja võiks mõelda oma jalajälje peale. Muidugi on ka teisi tegureid mis mõjutavad, aga mina isiklikult arvan, et kõige suuremat rolli mängib see samune tehisintellekt mis on kaotanud ära meie elust ühe osa, mille tagajärge on näha.');
INSERT INTO core.text_property(text_id, property_name, property_value)
