INSERT INTO core.text(id, content)
VALUES ('5ce2912f-12e7-42e3-b5bd-d597cd46f8ad',
        'Toidu raiskamine on levinud probleem,mis mõjutab meie keskkonda. Iga päev inimesed viskavad ära toitu mida tegelikult saaks veel kasutada või kellegile anda. Toiduraiskamine võib tulla sellest et inimene ei mõtle korralikult läbi mida ta osta tahab ja milleks see vajalik on. Näiteks vaatab et toode on ilusa pakendi välimusega ja siis ta ostabki selle, kuigi tegelikult välimus petab toote sisu ära ja tal ei olegi muud teha kui see ära visata. Toiduraiskamine tekitab suurt kahju loodusele, sest toidu tootmiseks kulutatakse palju vett, energiat, ja tööjõudu. Kui toit ära visatakse raisatakse ka kõik need loodusvarad. Samuti tekib prügilates toidujäätmetest gaas, mis kiirendab kliimamuutusi. Selleks et toiduraiskamist vähendada, võiks inimesed teha ostunimekirju ja osta ainult seda, mida neil päriselt vaja on. Samuti aitab toidu säilitamine õiges kohas pikendada selle eluiga. Ülejäänud toitu saab kasutada uutes toitudes või jagada teistele. Mida rohkem inimestele sellest rääkida seda rohkem hakkavad nad aru saama ja mõistma milleks selline käitumine vajalik on.Toiduraiskamine on probleem, mida saaks igaüks oma käitumist muutes vähendada. Kui inimesed oleksid hoolivamad ja mõtleksid rohkem oma valikute peale, väheneks raiskamine oluliselt. Iga väike samm aitab kaasa looduse hoidmisele ja ressursside säästmisele. Väikeste sammudega saab igaüks anda oma panuse, et vähendada raiskamist ja kaitseta keskkonda.');
