INSERT INTO core.text(id, content)
VALUES ('8a0baa93-9d24-4543-b1be-05c8dcbfe054',
        'Inimeste suutlikus toidu ostmisele on liiga suur ja piiramata. See tekitab olukorra, kus ostetakse palju, aga tarbitakse vähe. Toidu tegemisele ja transportimisele, aga kulutatakse meeletus koguses energiat. Kõik need meeletud kilogrammid toitu lähevad siiski raisku.\nSuur osa probleemi põhjuseks on ilmselt ikkagi inimeste peas. Olgu selleks, kas toidu mitte austamine võibolla emotsiooni ostud või hoopis valearvestus. Asi võib olla ka puhtalt harjumustes ja vähestes teadmistes. Kindlasti aitaks selle vastu info levik. Kui koolid võtaks oma programmidesse sisse sellest rohkem rääkimise või, kui raadiotes ja televisioonis räägitaks sellest rohkem ajal, kui on suur tarbjaskond. Muidugi tuleks muuta see inimestele huvitavaks. Teemast rääkimisel tuleks valida alateemasid nii, et see puudutaks inimeste hinge, rääkides võibolla pigem negatiivsetest külgedest näidata rohkesti pilte, teha juttu mis saab tulevikus kui selline raiskamine jätkub jne. Tegelikult on võimalusi palju ja kindlasti hetkel räägitakse sellest ka, aga võibolla mitte piisavalt.\nEsimene lahendus, mis mulle pähe tuli oli tõidu ostmise piiramine. Kui oleks võimalik välja arvestada ja kehtestada mingi piir või kogus millest üle ei tohi inimesed osta siis, kas see aitaks selle tohutu toidukadu vastu? Ma usun, et kui seda väga organiseeritult ja läbimõeldult teha siis see kindlasti aitaks mingil määral. Oletades, et kehtestatakse mingi kindel summa või toidukogus, mille raames on inimesel võimalik käia poes ja osta ikkagi see mida ta soovib, kuid jäädes mõistuse piiridesse. Siis peaks olema poodides arvestatud kindel kogus toitu, mis tähendaks ka seda, et nii suurtyes koghustes toitu ei aegu ja seda ei ole tarvis ära visata. Sealt edasi mõeldes, oleks poodidest üleliigne toit mida ära ei osteta, võimalus anda inimestele kellel pole resursse toidu ostmisele. Säärane olukorra lahendus võib aidata ka ülekaalulisuse vastu. Inimesed oleks sunnitud ostma rohkem naturaalset ja tervislikumat toitu ja kogused oleks piiratud. Muidugi oleks sellel lahendusel ka palju halbu külgi näiteks, kuidas saab korraldada pidusid või kuidas saab harjumused nii järsult ümber ehitada. Ma tõesti usun et sellele kõigele oleks võimalik leida lahendus.\nMuidugi erineb tarbimine ka väga suuresti elu korraldusest, pere suurusest, tööst, ajast jne. Kindlasti tuleks ka palju erandeid inimeste näol ja jääks ka küsimusi toidukohtade ja ametiasutuste toidlustamise üle. Tegelikult oleks ka võimalus lihtsalt poodides vähendada kaupade koguseid, võibolla tekitada olukordi, kus inimesed peavad käima jala poes ja suutma vedada oma ostetud asjad ise käeotsas koju, aga niivõrd laisas ühiskonnas mis meil praegu on oleks seda raske tekitada. Muidugi saaks ka müüa kaupu väiksemate kogustena ja piirata rohkem ebavajalike ja ebatervislike toiduainete müüki. Eks ta ole niivõrd moitme otsaga asi, aga kui olukord on või muutub veel halvemaks, siis kuskilt tuleb teha ohverdusi.\nKokkuvõtteks ütleksin mina, et kui inimesed soovivad meie planeeti aidata, hoida kokku energiat ja söösta tulevasi põlvkondi, siis selleks on palju erinevaid võimalusi. Tuleks olla lihtsalt avatud meelega ja kui miski ei sobi siis teha ettepanekuid ja aidata riigis olukorda muuta.');
