INSERT INTO core.text(id, content)
VALUES ('c5b1365f-eb64-4d47-a73f-8cce69f87a74',
        'Inimesed ei märka ise, kui palju nende igapäevased harjumised võivad olla tegelikult halvad. Näiteks plasttoodete kasutamine, toidu raiskamine ja halva kvaliteediga riiete liigne omamine. Miks inimesed on harjunud nendega?\nPoest on mugav osta tooteid, mis on plastikpakendis, sest  neid on lihtsam avada ja kasutada, kuid nad ei mõtle selle tagajärjele. Iga aastaga tekib prügimäele ja ookeanitesse suurtes kogustes prügi, milles suuremas kogustes on põhjustanud plastik. Loomad on hakanud neid sööma ja nendesse kinni jääma. Seetõttu on hakatud kasutama ökopakendeid. \nInimesed on harjunud toitu raiskama, sest neil on võimalus seda teha ja selle raiskamist ei saa vähendada nii kiiresti kui sooviks. Arvatakse, et toidu ära viskamine ei ole nii suur asi, kuid selletõttu raiskame me enda raha, maad, vett, energiat ja tööjõudu. \nTaaskasutuspoodidesse tuuakse liiga palju riideid sisse, mida ei suudeta maha müüa tänapäeva kiire moetrendide vahetamise tõttu.  Selle lahendamiseks on toonud moedisainer Eve Hanson idee hakata noortele tegema ekskursioone taaskasutuspoodide lattu. Paljud sisuloojad internetis on proovima hakanud teha videoid taaskasutuspoodides, et olla eeskujuks noortele ja aidata taaskasutust lahedaks ning trendikaks teha.\nInimetsel on väga palju tarbimisharjumusi, mis ei ole meie keskkonnale kõige paremad ja teevad meie keskkonnale päris palju kahju. Neid on võimalik muuta, aga mitte üleöö.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('c5b1365f-eb64-4d47-a73f-8cce69f87a74', 'title', 'Tarbimisharjumused meie ühiskonnas');
