INSERT INTO core.text(id, content)
VALUES ('672af3f9-8007-4526-beca-184b0c6b7b10',
        'Maailmas on hästi plaju toitu raisatud ning see pole ültsegi hea. Üle 60 kg inimese toidust on toidu jääde. Kas tõesti raisatakse nii palju toitu? \nMinu arust peaksid inimesed rohkem toitu hoidma, või viima enda söömata toidud toidupanka, et vaesemad inimesed saaksid ka süüa. Inimesed peaksid rohkem mõtlema kas naad ostavad liikselt toitu, et se vanaks läheks või söövad ikka kõik ära. Minu kodus näiteks on 50% tooted pealmised toidud mida me sööme kuna se on odavam ning aitab toidu raiskamis protsenti langetada.\nTegelikuses inimesed kasutavad toidu tootmisel hästi palju loodus resursse näiteks vett ning teravilju. Peale loodus resurside kasutamisele inimesed kasutavad hästi palju raha, et toitu osta. Paljudes peredes läheb hästi palju raha toitu peale ning palju sellest toidust lihtsalt visatakse minema. Enda näiteks võin õelda, et minu pere on paljugi raha säästnud odavamate toitude ostmises. Pealegi toidu ültse tootmiseks läheb hästi palju energiat kasutada ning metsi ma võtta et teha põllu maaks. Toidu tootmisel reostatakse maad ning hävitatakse loomade elupaikasi. \nVõin õelda, et inimesed kasutavad oma toitu eba säästlikult ning lohakalt. Toidu säästmiseks tuleks hoida kokku toitu ning annetama toitu toidupankadesse. Loodus keskonda peaks ka hoidma ning vähem reostama.');
