INSERT INTO core.text(id, content)
VALUES ('d192aec3-aa97-42d6-a3fe-8575c5fa996d',
        'Tänapäeviti läheb palju toitu raisku ja visatakse ära asju mida saaks keegi teine kasutada. Ostetakse asju mida elusees ei kasutata ja ostetakse riideid et ühe korra kanda ja siis kohe ära visata.\nPaljud inimesed lasevad toidul raisku minna või viskavad üldse selle ära. Toitu raisates sa ei raiska ainult toitu vaid ja vajalikku energijat, vett, toitaineid. Eesti inimesel on tavaliselt aastas 61 kg toidu jääkmeid millest moodustab 42% ehk 26 kg toidukadu. Selle asemel, et lasta toidul raisku minna või ära visata head toitu mis ei ole halvaks läinud mine ja anneta. Eestis on erinevaid kohti mis võtavad toidu annetusi vastu, selliseid kappe võid leida ka toidu poodidest kuhu saad panna kas saia pätsi või mingeid värskeid toit aineid mida sa ise ei kasuta nii, et need toit ained ei läheks raisku ja leiaksid köögi kus need ära kasutatakse.\nNoored võiks viia taaskasutus ladudesse, et nad näeksid kui mõtetu on asjade ostmine mida sa ei kasuta või sa ei kanna. Asjade ostmine mis sulle selga ei sobi või nahk ei kannata on mõttetu, sest sa viskad selle peaaegu koheliselt ära. Ära osta asju, sest ned näevad ägedad välja või sa arvad et sul läheb neid vaja. Ära osta asju ka kindlasti odavatest Hiina firmadest või poodidest nt Temu või Hansen, sest sealt tulevad odavalt tehtud praak asjad mille sa viskad suht koheliselt ära.\nKokkuvõtteks ära viska heas korras toitu ära ja ära osta odavaid asju mis on praht ja ka selliseid asju mille sa kohe ära viskad see on looduse reostamine ja  raha raiskamine.');
