INSERT INTO core.text(id, content)
VALUES ('1f9b55d6-3c69-4e34-8258-75b5c854fc74',
        'Praeguses maailmas on üldine toodete tarbimine muutunud üha suuremaks.Suurema tarbimisega kaasnevad ka suuremad kahjud.Tarbides üha rohkem toodeid tekib ümbrusesse ka rohkem prügi mida maha visatakse.Aga mida siis teha, et vähendada üldist toodete raiskamist, ja  toodete maha viskamist?\nOsa inimesi on harjunud toodete raiskamisega, või nende maha viskamisega, sest neid kas siis ei huvita looduse puhtus, või neil on rohkem raha ning tänu sellele neid ei huvita toodete raiskamine.Raiskamine ja toodete maha viskamine on üks suurimaid probleeme praegu maailmas ning selleks, et seda vähendada või üldse vältida võiks anda inimestele võimalus hoida loodust ja aidata abivajajaid.Üks võmalus oleks näiteks annetuskastid mis lisatakse igasse poodi ning kõik inimesed saaksid sinna oma toitu, riideid, või muid ülejäänud asju viia mida siis saaks annetada nendele kes neid asju väga vajavad, näiteks vaesed, või kodutud, neile saaks näiteks viia kellegi ülejäänud toitu, või kellelegi väikseks jäänud riideid.\nNeed ülejaanud asjad aitaksid väga palju neid inimesi kes vajavad hädasti abi ning kes ise ennast aidata ei saa, kas siis rahapuuduse pärast, või siis mingi muu põhjuse pärast.Viies oma asjad mida sa ei kasuta inimestele kes neid väga vajavad aitad sa teisi inimesi ja hoiad looduse puhtana ilma raiskamatta.\nEt vähendada raiskamist ja looduse reostamist tuleks inimestele anda võimalus teisi aidata, andes neile endale mittevaja minevad asjad, nii oleks loodus puhas, abivajajaid aidatud, ja mis veelgi parem iga aitaja saab selle eest endale selle hea tunde, et ta on kedagi aidanud.');
