INSERT INTO core.text(id, content)
VALUES ('f9d2ff20-ce0d-4c28-a14d-56acbb626013',
        'Taaskasutus. Miks on see tänapäeva maailmas nii oluline? Kuidas inimesed taaskasutavad? Taaskasutus tuleb sellest, et kulutatakse vähem materjali ja, et säästa meie kallid maavarasid. Aga miks riideid taaskasutatakse? Keegi ei taha ju teise inimesi vanu ja haisevaid riideid kanda. Üks põhjuseid miks riideid taaskasutatakse on selleks, et materjali raisk oleks väike, ja taaskasutusega saab taaskasutada vanu materjale, mille saab korda tehea.\nMiks just noortele raakida taaskasutamisest? Meie maailma noored on see järgmine põlvkond, kes võtab vanematelt juhtimise üle, ja kui nad ei tea isegi lihtsamaid asju nagu taaskasutamine, siis võib see maailm väga kiiresti hukata. Enamus tänapäeva noored käivad moodsate, trendikate ja ilusate riietega, aga kas nad teavad ikka millest on nende riided tehtud? Ja kas nad teavad, kuidas oma vanu riideid käsitleda?\nKui küsida tänapäeva noorelt, et kas ta viib oma vanad riided taaskasutusse, või hoopis viskab lihtsalt ära, siis üheksa korda kümnest viskavad noored oma vanad, korralikud riided ära. Aga miks viia oma vanad riided taaskasutusse? Kindlasti on selleks mitu põhjust, aga üks peamisi on selleks, et aidata neid kellel on riideid vaja. Või siis riided tagasi ringlusesse saata.\nTänapäeva noor on järgmise põlvkonna juht. Et nad saaksid elus ikka hakkama ja meie Maakera hirm kallid maavaru targalt kasutaksid, oleks vaja neile teha ekskursioone taaskasutuspoodidesse. Tänapäeval on ka teemas rohepööre, ja taaskasutus on üks osa sellest. Meie tänapäeva noored on võimelised meie maailma tegema veelgi paremaks ja selleks oleks neile vaja rääkida taaskasutamisest ja kuidas meie maailm puhtamaks teha. Ja see kõik algab taaskasutusega.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('f9d2ff20-ce0d-4c28-a14d-56acbb626013', 'title', 'Noortele taaskasutamisest.');
