INSERT INTO core.text(id, content)
VALUES ('274ff771-1718-42a2-815c-67b5f0c7f36e',
        'Toiduraiskamisel on mittmeid probleeme nagu inimesed raiskavad toituja viskavad selle minema. Eve Hansoni arvates peaksid koolilapsed minema taaskasutuspoodide lattu, et näha milline raiskamine tegelikult toimub. Iga inimene raiskab Eestis keskmiselt 61kg toidujäätmeid millest 26kg on toidukadu. toidu kadu on raisatud toitt või toiduaine. \nMinu arvates saaks toitu säästa niimodi, et inimesed kas hakkaksid enda ülejäänud toitu sõõma, voi nad ostavad endale mingi suguse talu looma nagu kanad või sead (saab anda ka kodu loomadele nagu koer). Enda kogemusest rääkides minu pere toitu ei raiska nii palju kui teised, kuna halvaks läinud toit või toit mida keegi ei taha enam viime kanadele sõõgiks. Sammuti saaks rikkamad inimesed annetada raha või toitu  vaesematele peredele kellel seda vaja läheb. Ja kui jääb toitu üle saaks selle sügav külma panna et millalgi seda edasi süüa . Kui meie ühiskond oskaks toitu säilitada oleks meil kõigil parem.  \nKooli lastele võiks hakkada tegema ekskursioone taaskasutus poodidesse. Inimene raiskab aastas 61kg toidujäätmeid millest 26kg on toidukadu. Inimesed saaksid säästa toitu kui ostetakse kanasid või sigu. Halvaks läinud toidu saaks anda loomadele. Toitu saaks ka sügav külma panna et hiljem ära süüa. rikkamad saaksid anda toitu vaesematele kellel seda tõesti vaja läheb.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('274ff771-1718-42a2-815c-67b5f0c7f36e', 'title', '„Toidu raiskamine“');
