INSERT INTO core.text(id, content)
VALUES ('bc4731b6-c160-4460-8835-83be5d9bdb1c',
        'Kahekümne esimesel sajandi inimestel on palju rohkem kui eelmistel sajanditel. Meil on rohkem juurdepääsu tarbimisele läbi interneti, kust me saame lihtsasti osta midagi ja päeva pärast kätte saada. See tekitab rohkelt laiskust inimestel, kus nad ei lõpeta mõtetu asjade ostmist, mida nad ei kasuta paari päeva pärast.                                                                        Köik see tekitab väga palju prügi läbi pakendite ja ära visanud jäätmetest. Ka toidujäätmed on halvad, kuna need on ka palju ära raisanud. Paljud inimesed viskavad ära toidu mis nad ära ei ole sõõnud, kuna nad arvavad, et see on lõpmatu. See on tõrjuv raiskamine, kuna toit, mis oli ära visanud, oleks saanud olla hommikuline eine või kellegi teise lõuna. See pole ainult teistele halb, vaid ka keskkonnale.                                                                                                                                              Enam meist on olnud ostnud midagi internetist, mõtlenud, et see on pisi asi. Varsti, on inimene ostnud tuhandeid asju ühest kohast, kus on odav. Üks kuulus moedisainer, nimega Eve Hanson, on õelnud, et köik peaks vaatama üle oma isiklikud tarbimisharjumused.                                                                                                                                On ka olemas taaskasutuspoed, kust ostatakse odavalt riideid või esemeid, mis oli varem teiste inimeste käes. Niimoodi saab hästi tarbimisharjumusi muuta ja mitte raisata oma raha ja aega kallite esemetega, mida kardad, et rikkud. Selliselt, saad odavalt asju mis on vaja või mitte aga odavalt ja säästvalt.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('bc4731b6-c160-4460-8835-83be5d9bdb1c', 'title', 'Inimesete tarbimisharjumused');
