INSERT INTO core.text(id, content)
VALUES ('5eff81b0-0f1f-4900-8040-a102a0a747cd',
        'Inimesed on harjunud toitu ja asju raiskama, sest nad teavad, et saavad endale toitu juurde osta. Inimesed võivad küll arvata seda, et midagi ju ei juhtu, kui visata väikese koguse toitu minema. See on tegelt puhas vale, sest on paljusi inimesi, kes annaksid kõik, et saada kasvõi ühe tüki leiba ja toidu minema viskamisega tekib koju ka väga palju toidujäätmeid. Me ei raiska ainult toitu vaid ka me raiskame oma raha, mille eest oleme kõik need ära visatud toidujäänused ostnud.\nInimesed võiksid õppida kuidas toitu säästlikumaks teha, sest siis me ei raiskaks väga palju toitu enam ja me ei peaks raha raiskamise peale mõtlema enam. Mõelda võiks ka sellele, kui palju keskkonna probleem võib tekitada suur toiduraiskamine.\nToidu viskamine võib olla sellepärast kahjulik, sest saagi suurendamiseks kasutatakse palju kemikaale ja mürgiseid aineid.\nToitu võiks rohkem säästa, sest kodumajapidamises tekib iga Eesti inimese kohta aastas keskmiselt 61kg toidujäätmeid. Näiteks kui me tahame säästa voi vähendada keskkonna probleeme, võime viia lagunevad toidujäätmes komposti. Säästmise võimaluseks võiks ka olla näteks see, et inimesed vaatavad üle oma säästmise või näidata inimestele, kui palju nad tegelikult tekitavad toidujäätmeid.\nMinu järelduseks on see, et inimestele võiks teha koolitus selle kohta, kuidas säästa rohkem ning kuidas vähendada keskonna probleeme.  Inimestele tuleb nii äkki mõistus pähe ja nad saavad aru sellest, kui palju nad tegelikult tekitavad toidujäätmeid. Isegei kui arvavatakse, et väikese koguse toidu minema viskamisega ei juhtu midagi. Aga kahjuks seda ei osata muuta kuna see on paljude inimeste harjumuseks juba.');
