INSERT INTO core.text(id, content)
VALUES ('8149a702-f3ce-4c3d-abca-d545302f1239',
        'Toidu ja toodete raiskamine on igapäevane probleem tänapäevases maailmas. Inimesed raiskavad toitu nii palju, et lõpuks läheb prügisse tohutus koguses juurvilju, puuvilja ja isegi liha, mida oleks võinud veel kasutada. Riiete ja jalanõudega on ka probleeme. Paljud tellivad endale hiinast riieid ja, kui neile ei meeldi see toode nad viskavad selle ära, selle asemel, et neid viia taaskasutusse. Miks siis inimesed raiskavad nii palju asju?\nEesti keskmise inimese kohta tekib aastas 61kg toidujäätmeid. Olgu need puuvilja koored, juurviljadest alles jäänud jäätmed või toit, mis on kaua külmikus seisnud. Koguaeg, kui neid jäätmeid tekib toodetakse toitu ja tooteid aina juurde ja see samal ajal rikub meie keskkonda. Meid ümbritsevates linnades tekib tänavale aina rohkem sodi ja tehastest tuleb aina rohkem süsihappegaasi õhku. Kuid inimesed teavad seda ja see ei lõpeta seda liigtarbimist. Üle tarbimine ei lõppe, sest me oleme ostmisest ja suurest valikust sõltuvuses. Iga kord, kui sa lähed poodi või tellid riideid, näed sa aina soodustusi ja kampaaniaid. Nähes neid kampaaniaid kuuled enda peas vaid seda, et sul on seda vaja. Ja nii hakkabki inimene aina ostma ja ostma.\nKeskkonda kahjustab kõige rohkem hiinast riiideid tellides. Seal on odavad rõivad ja neid on ka palju, kuid tegelikkuses need pole üldse nagu sulle tundub. Kõik need särgid, püksid, jalanõud, mütsid ja mis kõike muud seal müüakse on tehtud naftast. Kannad seda ühe korra ja tunned, kuidas need riideid ei tundu su seljas normaalsed. Ja väga paljud sellised rõivad on pärit just nendest suurtest Hiina vabrikutes. neid riideid tellides sa ei mõtle selle, kui palju jäätmeid jääb maha riidetehastest ja vabrikutest. Sa ainult ootad seda aega, kui need riided kätte saad.\nInimesed raiskavad igapäevaselt väga palju tooteid. See on tingitud sellest, et meil on kõik kättesaadav ja ka kiiresti. Eriti odavad on Hiinast tulnud tooted, mis rikuvad meie keskkonda ja kõike mis meid ümbritseb. Aga me ei mõtle sellele, kui palju see meie maailma kahjustab, vaid hoopis selle peale, et saame odavalt riided kätte. Just see suhtumine on see mis rikub meie maailma.');
