INSERT INTO core.text(id, content)
VALUES ('76f12178-a913-4b16-ae9f-64721897c252',
        'Tänapäeva maailmas on palju taaskasutust ja inimesed kasutavad seda palju. Aga miks on taaskasutus nii tähtis tänapäeval? Kas taaskasutuspoed on head tänapäeva maailmale? Taaskasutus on pakendite, paberi ja jäätmete ümbertöötamine toormaterjaliks ja seekaudu tegemine nende uus kasutussevõtt.\nTaaskasutus on tähtis tänapäevase maailmas mitmelpõhjusel. Tähtsus taaskasutusest tänapäeval on, et säästa materjali ja mitte palju raha kulutada. Aga vahel ei ole taaskasutusel kvaliteeti ja pole väga hea. Näiteks taaskasutuspoed. Taaskasutuspoodides on sageli väga odav ja inimesed ostavad sealt asju. Kuid kui nad vahel kätte saavad enda toote saavad teada, et toode pole sarnane mis kirjutatud oli internettis. Vahel on toode ka hea aga ei kesta kaua kuni see varsti katki läheb. Näiteks riided võivad kaunil reklaamfotol ilusad välja näha, aga kui klient toote kätte saab ei saa seda rohkem kanda kui üks kord, sest kehal on halb olla selles.');
INSERT INTO core.text_property(text_id, property_name, property_value)
VALUES ('76f12178-a913-4b16-ae9f-64721897c252', 'title', 'Taaskasutus.');
